window.VOCAB = [{"word":"abandon","pos":"v.","phonetic":"[əˈbændən]","meaning":"放棄；拋棄；遺棄","definition":"to leave a place, thing, or person permanently, especially when you are not allowed to be there or should not leave it","collocations":["abandon a plan","abandon ship","abandon hope","abandon a project"],"example":"The crew had to abandon the sinking ship.","exampleZh":"船員們不得不棄船逃生。","synonyms":["desert","give up","forsake"],"level":4,"theme":"動作與行為","examples":[{"en":"The crew had to abandon the sinking ship.","zh":"船員們不得不棄船逃生。"},{"en":"Because of the heavy rain, the team decided to abandon their weekend plan.","zh":"由於大雨，隊伍決定放棄他們的週末計畫。"},{"en":"The company was forced to abandon the project after running out of money.","zh":"資金用盡後，公司被迫放棄這個專案。"}]},{"word":"abbreviate","pos":"v.","phonetic":"[əˈbrivɪˌet]","meaning":"縮寫；使簡略","definition":"to shorten a word or phrase","collocations":["abbreviate a title","commonly abbreviated as"],"example":"The word \"doctor\" is often abbreviated as \"Dr.\"","exampleZh":"「doctor」這個字常縮寫為「Dr.」。","synonyms":["shorten","condense"],"level":4,"theme":"溝通與語言","examples":[{"en":"The word \"doctor\" is often abbreviated as \"Dr.\"","zh":"「doctor」這個字常縮寫為「Dr.」。"},{"en":"We usually abbreviate the word kilometer to km in reports.","zh":"我們在報告中通常把 kilometer 縮寫成 km。"},{"en":"The teacher asked us not to abbreviate words in formal essays.","zh":"老師要求我們在正式作文中不要使用縮寫。"}]},{"word":"abdomen","pos":"n.","phonetic":"[ˈæbdəmən]","meaning":"腹部","definition":"the front part of the body below the chest","collocations":["a pain in the abdomen","lower abdomen"],"example":"He felt a sharp pain in his abdomen.","exampleZh":"他感到腹部一陣劇痛。","synonyms":["belly","stomach"],"level":4,"theme":"身體與健康","examples":[{"en":"He felt a sharp pain in his abdomen.","zh":"他感到腹部一陣劇痛。"},{"en":"The nurse gently pressed on his lower abdomen to check for pain.","zh":"護士輕輕按壓他的下腹部以檢查是否疼痛。"},{"en":"Doing regular exercise can strengthen the muscles of your abdomen.","zh":"規律運動可以強化你腹部的肌肉。"}]},{"word":"abide","pos":"v.","phonetic":"[əˈbaɪd]","meaning":"遵守；忍受","definition":"to accept or act according to a rule; to tolerate","collocations":["abide by the rules","cannot abide"],"example":"All players must abide by the rules of the game.","exampleZh":"所有選手都必須遵守比賽規則。","synonyms":["comply","tolerate"],"level":5,"theme":"社會與文化","examples":[{"en":"All players must abide by the rules of the game.","zh":"所有選手都必須遵守比賽規則。"},{"en":"Every citizen must abide by the laws of the country.","zh":"每位公民都必須遵守國家的法律。"},{"en":"She cannot abide people who are rude to waiters.","zh":"她無法忍受對服務生無禮的人。"}]},{"word":"ability","pos":"n.","phonetic":"[əˈbɪlətɪ]","meaning":"能力；才能","definition":"the physical or mental power or skill needed to do something","collocations":["have the ability to","natural ability","leadership ability"],"example":"She has the ability to solve complex problems quickly.","exampleZh":"她有能力迅速解決複雜的問題。","synonyms":["skill","capability"],"level":3,"theme":"抽象概念","examples":[{"en":"She has the ability to solve complex problems quickly.","zh":"她有能力迅速解決複雜的問題。"},{"en":"His natural ability in mathematics impressed all of his teachers.","zh":"他在數學方面的天賦讓所有老師印象深刻。"},{"en":"Good managers need strong leadership ability to guide their teams.","zh":"好的經理需要強大的領導能力來帶領團隊。"}]},{"word":"able","pos":"adj.","phonetic":"[ˈebl̩]","meaning":"能夠的；有能力的","definition":"having the power, skill, or means to do something","collocations":["be able to","an able student","able-bodied"],"example":"He was able to finish the marathon in under four hours.","exampleZh":"他能夠在四小時內跑完馬拉松。","synonyms":["capable","competent"],"level":2,"theme":"性質與描述","examples":[{"en":"He was able to finish the marathon in under four hours.","zh":"他能夠在四小時內跑完馬拉松。"},{"en":"Thanks to the scholarship, she was able to attend university.","zh":"多虧了獎學金，她才得以上大學。"},{"en":"He is such an able student that he learns new concepts quickly.","zh":"他是個很有能力的學生，能很快學會新概念。"}]},{"word":"abnormal","pos":"adj.","phonetic":"[æbˈnɔrml̩]","meaning":"異常的；反常的","definition":"different from what is usual or expected","collocations":["abnormal behavior","abnormal weather"],"example":"The doctor noticed something abnormal in her heartbeat.","exampleZh":"醫生發現她的心跳有異常。","synonyms":["unusual","irregular"],"level":4,"theme":"性質與描述","examples":[{"en":"The doctor noticed something abnormal in her heartbeat.","zh":"醫生發現她的心跳有異常。"},{"en":"The recent abnormal weather has damaged many crops in the region.","zh":"最近的反常天氣損害了該地區許多農作物。"},{"en":"The teacher reported the student's abnormal behavior to the counselor.","zh":"老師向輔導員報告了那名學生的異常行為。"}]},{"word":"aboard","pos":"prep. / adv.","phonetic":"[əˈbord]","meaning":"在船（飛機、火車）上","definition":"on or into a ship, aircraft, or train","collocations":["go aboard","welcome aboard","aboard the ship"],"example":"All passengers must be aboard the plane by seven.","exampleZh":"所有乘客必須在七點前登機。","synonyms":["on board"],"level":3,"theme":"交通與旅行","examples":[{"en":"All passengers must be aboard the plane by seven.","zh":"所有乘客必須在七點前登機。"},{"en":"The captain welcomed everyone aboard the ship with a warm smile.","zh":"船長帶著溫暖的微笑歡迎大家登船。"},{"en":"Once everyone was aboard the train, it slowly left the station.","zh":"大家一上火車，列車便緩緩駛離車站。"}]},{"word":"abolish","pos":"v.","phonetic":"[əˈbɑlɪʃ]","meaning":"廢除；廢止","definition":"to officially end a law, system, or practice","collocations":["abolish slavery","abolish a law"],"example":"The government decided to abolish the old tax system.","exampleZh":"政府決定廢除舊的稅制。","synonyms":["eliminate","abandon"],"level":5,"theme":"政治與法律","examples":[{"en":"The government decided to abolish the old tax system.","zh":"政府決定廢除舊的稅制。"},{"en":"Many activists fought hard to abolish slavery in the past.","zh":"過去許多社運人士努力奮鬥以廢除奴隸制度。"},{"en":"The school decided to abolish the outdated dress code.","zh":"學校決定廢除過時的服裝規定。"}]},{"word":"about","pos":"prep. / adv.","phonetic":"[əˈbaʊt]","meaning":"關於；大約","definition":"on the subject of; approximately","collocations":["about time","about to","talk about"],"example":"The book is about the history of ancient Rome.","exampleZh":"這本書是關於古羅馬歷史的。","synonyms":["concerning","approximately"],"level":1,"theme":"溝通與語言","examples":[{"en":"The book is about the history of ancient Rome.","zh":"這本書是關於古羅馬歷史的。"},{"en":"We talked about our summer plans during the long car ride.","zh":"在漫長的車程中，我們談論著暑假的計畫。"},{"en":"It's about time you started reviewing for the final exam.","zh":"你也該開始複習期末考了。"}]},{"word":"above","pos":"prep. / adv.","phonetic":"[əˈbʌv]","meaning":"在...之上；高於","definition":"at a higher level or position than something else","collocations":["above average","above all","the sky above"],"example":"The plane flew above the clouds.","exampleZh":"飛機飛到了雲層之上。","synonyms":["over"],"level":1,"theme":"時間與空間","examples":[{"en":"The plane flew above the clouds.","zh":"飛機飛到了雲層之上。"},{"en":"Her test scores were well above average this semester.","zh":"她這學期的考試成績遠高於平均。"},{"en":"Above all, remember to stay calm during the interview.","zh":"最重要的是，面試時要記得保持冷靜。"}]},{"word":"abroad","pos":"adv.","phonetic":"[əˈbrɔd]","meaning":"在國外；到國外","definition":"in or to a foreign country","collocations":["study abroad","travel abroad","live abroad"],"example":"My sister is planning to study abroad next year.","exampleZh":"我姐姐計畫明年到國外留學。","synonyms":["overseas"],"level":3,"theme":"交通與旅行","examples":[{"en":"My sister is planning to study abroad next year.","zh":"我姐姐計畫明年到國外留學。"},{"en":"After graduation, he hopes to travel abroad for a whole year.","zh":"畢業後，他希望到國外旅行一整年。"},{"en":"Living abroad taught her to be more independent and confident.","zh":"在國外生活讓她變得更獨立、更有自信。"}]},{"word":"abrupt","pos":"adj.","phonetic":"[əˈbrʌpt]","meaning":"突然的；唐突的","definition":"sudden and unexpected","collocations":["an abrupt end","an abrupt change"],"example":"The meeting came to an abrupt end.","exampleZh":"這場會議突然結束了。","synonyms":["sudden","unexpected"],"level":5,"theme":"性質與描述","examples":[{"en":"The meeting came to an abrupt end.","zh":"這場會議突然結束了。"},{"en":"There was an abrupt change in the weather this afternoon.","zh":"今天下午天氣出現了突然的變化。"},{"en":"His abrupt reply made everyone at the table feel uncomfortable.","zh":"他唐突的回答讓桌上每個人都感到不自在。"}]},{"word":"absence","pos":"n.","phonetic":"[ˈæbsn̩s]","meaning":"缺席；不在","definition":"the state of being away from a place or not present","collocations":["absence from school","leave of absence","in the absence of"],"example":"His absence from the meeting was noticed by everyone.","exampleZh":"他缺席會議的事被大家注意到了。","synonyms":["nonattendance"],"level":4,"theme":"教育與學習","examples":[{"en":"His absence from the meeting was noticed by everyone.","zh":"他缺席會議的事被大家注意到了。"},{"en":"In the absence of the manager, her assistant made the decision.","zh":"在經理不在的情況下，她的助理做了決定。"},{"en":"His frequent absence from school worried his parents a lot.","zh":"他經常缺課，讓父母非常擔心。"}]},{"word":"absent","pos":"adj.","phonetic":"[ˈæbsn̩t]","meaning":"缺席的；不在的","definition":"not present at a place or event","collocations":["absent from class","absent-minded","mark someone absent"],"example":"Three students were absent from class today.","exampleZh":"今天有三名學生缺課。","synonyms":["away","missing"],"level":3,"theme":"教育與學習","examples":[{"en":"Three students were absent from class today.","zh":"今天有三名學生缺課。"},{"en":"She was absent from work because of a bad cold.","zh":"她因為重感冒而沒去上班。"},{"en":"My grandfather is a bit absent-minded and often loses his keys.","zh":"我爺爺有點心不在焉，常常弄丟鑰匙。"}]},{"word":"absolute","pos":"adj.","phonetic":"[ˈæbsəˌlut]","meaning":"絕對的；完全的","definition":"complete and total; not limited in any way","collocations":["absolute power","absolute zero","absolute silence"],"example":"The king had absolute power over his kingdom.","exampleZh":"國王對王國擁有絕對的權力。","synonyms":["complete","total"],"level":4,"theme":"性質與描述","examples":[{"en":"The king had absolute power over his kingdom.","zh":"國王對王國擁有絕對的權力。"},{"en":"The library requires absolute silence during examination periods.","zh":"圖書館在考試期間要求絕對安靜。"},{"en":"I have absolute trust in my best friend's honesty.","zh":"我對我最好朋友的誠實有絕對的信任。"}]},{"word":"absorb","pos":"v.","phonetic":"[əbˈsɔrb]","meaning":"吸收；吸引（注意力）","definition":"to take in a liquid, gas, or other substance gradually; to hold someone's attention completely","collocations":["absorb water","absorb information","absorbed in a book"],"example":"A sponge can absorb a lot of water.","exampleZh":"海綿可以吸收大量的水。","synonyms":["soak up","take in"],"level":4,"theme":"科學與數學","examples":[{"en":"A sponge can absorb a lot of water.","zh":"海綿可以吸收大量的水。"},{"en":"Young children can absorb new information remarkably fast.","zh":"幼兒能以驚人的速度吸收新資訊。"},{"en":"She was so absorbed in her novel that she missed the bus stop.","zh":"她太投入於小說中，以至於錯過了下車的站。"}]},{"word":"abstract","pos":"adj. / n.","phonetic":"[ˈæbstrækt]","meaning":"抽象的；摘要","definition":"existing as an idea rather than a physical thing; a brief summary","collocations":["abstract art","abstract idea","abstract concept"],"example":"Justice is an abstract concept that is hard to define.","exampleZh":"正義是一個難以定義的抽象概念。","synonyms":["theoretical","conceptual"],"level":5,"theme":"抽象概念","examples":[{"en":"Justice is an abstract concept that is hard to define.","zh":"正義是一個難以定義的抽象概念。"},{"en":"Many students find abstract art difficult to understand at first.","zh":"許多學生一開始覺得抽象藝術很難理解。"},{"en":"You should write a short abstract to summarize your research paper.","zh":"你應該寫一篇簡短的摘要來總結你的研究論文。"}]},{"word":"absurd","pos":"adj.","phonetic":"[əbˈsɝd]","meaning":"荒謬的；可笑的","definition":"completely unreasonable or ridiculous","collocations":["an absurd idea","sound absurd"],"example":"It seems absurd to work all night without any rest.","exampleZh":"整晚不休息地工作似乎很荒謬。","synonyms":["ridiculous","foolish"],"level":4,"theme":"性質與描述","examples":[{"en":"It seems absurd to work all night without any rest.","zh":"整晚不休息地工作似乎很荒謬。"},{"en":"It sounds absurd to blame the weather for your poor grades.","zh":"把成績差歸咎於天氣聽起來很荒謬。"},{"en":"Paying that much for a plain T-shirt is completely absurd.","zh":"花那麼多錢買一件素色 T 恤實在太荒謬了。"}]},{"word":"abundance","pos":"n.","phonetic":"[əˈbʌndəns]","meaning":"豐富；大量","definition":"a very large quantity of something","collocations":["an abundance of resources","in abundance"],"example":"The region has an abundance of natural resources.","exampleZh":"這個地區擁有豐富的天然資源。","synonyms":["plenty","wealth"],"level":5,"theme":"自然與環境","examples":[{"en":"The region has an abundance of natural resources.","zh":"這個地區擁有豐富的天然資源。"},{"en":"Fresh fruit is available in abundance at the summer market.","zh":"夏季市場裡有大量新鮮水果。"},{"en":"The garden had an abundance of colorful flowers in spring.","zh":"春天時花園裡有大量色彩繽紛的花朵。"}]},{"word":"abundant","pos":"adj.","phonetic":"[əˈbʌndənt]","meaning":"豐富的；充裕的","definition":"existing in large quantities; more than enough","collocations":["abundant resources","abundant rainfall","abundant supply"],"example":"The region has abundant natural resources.","exampleZh":"這個地區擁有豐富的天然資源。","synonyms":["plentiful","ample"],"level":5,"theme":"自然與環境","examples":[{"en":"The region has abundant natural resources.","zh":"這個地區擁有豐富的天然資源。"},{"en":"The tropical island receives abundant rainfall throughout the year.","zh":"這座熱帶島嶼全年有充沛的降雨。"},{"en":"There is an abundant supply of clean water in this village.","zh":"這個村莊有充足的乾淨水源供應。"}]},{"word":"abuse","pos":"n. / v.","phonetic":"[əˈbjus] (n.) / [əˈbjuz] (v.)","meaning":"濫用；虐待","definition":"to use something wrongly or harmfully; to treat someone cruelly","collocations":["drug abuse","child abuse","abuse power"],"example":"The company was accused of abusing its power.","exampleZh":"這家公司被指控濫用權力。","synonyms":["misuse","mistreat"],"level":4,"theme":"社會與文化","examples":[{"en":"The company was accused of abusing its power.","zh":"這家公司被指控濫用權力。"},{"en":"Drug abuse can seriously harm both your body and mind.","zh":"藥物濫用會嚴重傷害你的身心。"},{"en":"The officer was fired for abusing his authority over others.","zh":"那名警官因濫用職權而被解雇。"}]},{"word":"academic","pos":"adj.","phonetic":"[ˌækəˈdɛmɪk]","meaning":"學術的；學業的","definition":"relating to education and scholarship, especially in schools and universities","collocations":["academic year","academic performance","academic subject"],"example":"His academic performance improved a lot this semester.","exampleZh":"他這學期的學業表現進步很多。","synonyms":["scholarly","educational"],"level":4,"theme":"教育與學習","examples":[{"en":"His academic performance improved a lot this semester.","zh":"他這學期的學業表現進步很多。"},{"en":"The new academic year begins in early September for most schools.","zh":"對大多數學校而言，新學年在九月初開始。"},{"en":"Science is her favorite academic subject in high school.","zh":"自然科學是她高中最喜歡的學科。"}]},{"word":"accelerate","pos":"v.","phonetic":"[ækˈsɛləˌret]","meaning":"加速；促進","definition":"to increase in speed or make something happen faster","collocations":["accelerate growth","accelerate the process","the car accelerates"],"example":"The car accelerated quickly on the highway.","exampleZh":"這輛車在高速公路上迅速加速。","synonyms":["speed up"],"level":5,"theme":"科學與數學","examples":[{"en":"The car accelerated quickly on the highway.","zh":"這輛車在高速公路上迅速加速。"},{"en":"New technology has helped accelerate the growth of small businesses.","zh":"新科技幫助加速了小型企業的成長。"},{"en":"We can accelerate the process by working together as a team.","zh":"我們可以透過團隊合作來加快這個過程。"}]},{"word":"accent","pos":"n.","phonetic":"[ˈæksɛnt]","meaning":"口音；重音","definition":"a distinctive way of pronouncing words, typical of a region or country","collocations":["speak with an accent","strong accent","foreign accent"],"example":"She speaks English with a British accent.","exampleZh":"她說英語帶有英國口音。","synonyms":["pronunciation","dialect"],"level":3,"theme":"溝通與語言","examples":[{"en":"She speaks English with a British accent.","zh":"她說英語帶有英國口音。"},{"en":"The exchange student spoke Chinese with a slight foreign accent.","zh":"那位交換學生說中文帶著些微的外國口音。"},{"en":"In this word, the accent falls on the second syllable.","zh":"在這個字裡，重音落在第二個音節上。"}]},{"word":"accept","pos":"v.","phonetic":"[ækˈsɛpt]","meaning":"接受；承認","definition":"to agree to take or receive something offered","collocations":["accept an offer","accept responsibility","accept an invitation"],"example":"She happily accepted the job offer.","exampleZh":"她開心地接受了這份工作邀請。","synonyms":["receive","agree to"],"level":2,"theme":"動作與行為","examples":[{"en":"She happily accepted the job offer.","zh":"她開心地接受了這份工作邀請。"},{"en":"She gladly accepted the invitation to her friend's birthday party.","zh":"她欣然接受了朋友生日派對的邀請。"},{"en":"A good leader must accept responsibility for the team's mistakes.","zh":"好的領導者必須為團隊的錯誤承擔責任。"}]},{"word":"access","pos":"n. / v.","phonetic":"[ˈæksɛs]","meaning":"進入；使用權；存取","definition":"the means or opportunity to enter, use, or approach something","collocations":["access to information","gain access","internet access"],"example":"Students have free access to the library.","exampleZh":"學生可以免費使用圖書館。","synonyms":["entry","admission"],"level":3,"theme":"科技與媒體","examples":[{"en":"Students have free access to the library.","zh":"學生可以免費使用圖書館。"},{"en":"The internet gives us instant access to information from anywhere.","zh":"網路讓我們能隨時隨地即時取得資訊。"},{"en":"Only staff members can gain access to the restricted area.","zh":"只有員工才能進入這個管制區域。"}]},{"word":"accessible","pos":"adj.","phonetic":"[ækˈsɛsəbl̩]","meaning":"可到達的；易取得的","definition":"able to be reached, entered, or obtained easily","collocations":["easily accessible","accessible to the public"],"example":"The museum is easily accessible by bus.","exampleZh":"這座博物館搭公車就能輕鬆到達。","synonyms":["reachable","available"],"level":4,"theme":"交通與旅行","examples":[{"en":"The museum is easily accessible by bus.","zh":"這座博物館搭公車就能輕鬆到達。"},{"en":"The national park is easily accessible by train and bus.","zh":"這座國家公園搭火車和公車都很容易到達。"},{"en":"The library makes its online resources accessible to the public.","zh":"圖書館讓大眾都能取用其線上資源。"}]},{"word":"accessory","pos":"n.","phonetic":"[ækˈsɛsərɪ]","meaning":"配件；附屬品","definition":"an extra item added for decoration or usefulness","collocations":["fashion accessory","car accessories"],"example":"She bought a new bag as a fashion accessory.","exampleZh":"她買了一個新包包當作時尚配件。","synonyms":["addition","attachment"],"level":4,"theme":"服裝與外表","examples":[{"en":"She bought a new bag as a fashion accessory.","zh":"她買了一個新包包當作時尚配件。"},{"en":"A simple scarf can be a stylish accessory for any outfit.","zh":"一條簡單的圍巾可以成為任何服裝的時尚配件。"},{"en":"The store sells phone cases and other useful accessories.","zh":"這家店販售手機殼和其他實用的配件。"}]},{"word":"accident","pos":"n.","phonetic":"[ˈæksədənt]","meaning":"意外；事故","definition":"an unpleasant event that happens unexpectedly and causes damage or injury","collocations":["car accident","by accident","a serious accident"],"example":"He was injured in a car accident last week.","exampleZh":"他上週在一場車禍中受傷了。","synonyms":["mishap","crash"],"level":2,"theme":"身體與健康","examples":[{"en":"He was injured in a car accident last week.","zh":"他上週在一場車禍中受傷了。"},{"en":"I deleted the file by accident and had to redo everything.","zh":"我不小心刪除了檔案，只好重做所有東西。"},{"en":"A serious accident on the highway caused a long traffic jam.","zh":"高速公路上的一場嚴重事故造成了長時間的塞車。"}]},{"word":"acclaim","pos":"v. / n.","phonetic":"[əˈklem]","meaning":"讚揚；喝采","definition":"to praise enthusiastically, or such praise","collocations":["critical acclaim","widely acclaimed"],"example":"The film received great acclaim from critics.","exampleZh":"這部電影獲得影評人的高度讚揚。","synonyms":["praise","applaud"],"level":6,"theme":"藝術與音樂","examples":[{"en":"The film received great acclaim from critics.","zh":"這部電影獲得影評人的高度讚揚。"},{"en":"Her first novel won critical acclaim from readers around the world.","zh":"她的第一本小說贏得了世界各地讀者的高度讚揚。"},{"en":"The young pianist was widely acclaimed for his brilliant performance.","zh":"這位年輕鋼琴家因精彩的演出而廣受讚譽。"}]},{"word":"accommodate","pos":"v.","phonetic":"[əˈkɑməˌdet]","meaning":"容納；提供住宿","definition":"to provide lodging or sufficient space for someone","collocations":["accommodate guests","accommodate special needs"],"example":"The hotel can accommodate up to two hundred guests.","exampleZh":"這間飯店最多能容納兩百位房客。","synonyms":["house","hold"],"level":5,"theme":"居家與生活","examples":[{"en":"The hotel can accommodate up to two hundred guests.","zh":"這間飯店最多能容納兩百位房客。"},{"en":"The new stadium can accommodate over fifty thousand fans.","zh":"這座新體育場可容納超過五萬名球迷。"},{"en":"The school tries to accommodate students with special needs.","zh":"學校努力為有特殊需求的學生提供合適的安排。"}]},{"word":"accompany","pos":"v.","phonetic":"[əˈkʌmpənɪ]","meaning":"陪伴；伴隨","definition":"to go somewhere with someone, or to happen at the same time as something else","collocations":["accompany someone","accompanied by","accompany on the piano"],"example":"My mother accompanied me to the hospital.","exampleZh":"我媽媽陪我去醫院。","synonyms":["escort","go with"],"level":4,"theme":"人物與家庭","examples":[{"en":"My mother accompanied me to the hospital.","zh":"我媽媽陪我去醫院。"},{"en":"A pianist accompanied the singer during the school concert.","zh":"一位鋼琴家在校園音樂會上為歌手伴奏。"},{"en":"The thunder was accompanied by a sudden burst of heavy rain.","zh":"雷聲伴隨著突然而來的傾盆大雨。"}]},{"word":"accomplish","pos":"v.","phonetic":"[əˈkɑmplɪʃ]","meaning":"完成；達成","definition":"to succeed in doing or completing something","collocations":["accomplish a goal","accomplish a task","much accomplished"],"example":"She accomplished her goal of running a marathon.","exampleZh":"她達成了跑完一場馬拉松的目標。","synonyms":["achieve","complete"],"level":4,"theme":"抽象概念","examples":[{"en":"She accomplished her goal of running a marathon.","zh":"她達成了跑完一場馬拉松的目標。"},{"en":"With careful planning, the team accomplished the task ahead of schedule.","zh":"透過周密的計畫，團隊提前完成了任務。"},{"en":"You can accomplish a lot if you focus on one thing at a time.","zh":"如果你一次專注於一件事，就能完成很多事情。"}]},{"word":"accomplishment","pos":"n.","phonetic":"[əˈkɑmplɪʃmənt]","meaning":"成就；成果","definition":"something achieved successfully","collocations":["a great accomplishment","sense of accomplishment"],"example":"Winning the scholarship was a major accomplishment for her.","exampleZh":"獲得獎學金對她來說是一項重大成就。","synonyms":["achievement","success"],"level":4,"theme":"教育與學習","examples":[{"en":"Winning the scholarship was a major accomplishment for her.","zh":"獲得獎學金對她來說是一項重大成就。"},{"en":"Finishing the difficult project gave her a real sense of accomplishment.","zh":"完成這個困難的專案讓她有真正的成就感。"},{"en":"Learning to play the violin was a great accomplishment for him.","zh":"學會拉小提琴對他來說是一項了不起的成就。"}]},{"word":"according","pos":"adv.","phonetic":"[əˈkɔrdɪŋ]","meaning":"根據；依照","definition":"as stated by or in agreement with; used in the phrase 'according to'","collocations":["according to the report","according to plan","according to research"],"example":"According to the weather forecast, it will rain tomorrow.","exampleZh":"根據天氣預報，明天會下雨。","synonyms":["as reported by"],"level":3,"theme":"溝通與語言","examples":[{"en":"According to the weather forecast, it will rain tomorrow.","zh":"根據天氣預報，明天會下雨。"},{"en":"According to recent research, sleep greatly affects our memory.","zh":"根據最近的研究，睡眠對我們的記憶有很大的影響。"},{"en":"Everything went according to plan during the school trip.","zh":"校外教學期間一切都按照計畫進行。"}]},{"word":"account","pos":"n. / v.","phonetic":"[əˈkaʊnt]","meaning":"帳戶；描述；解釋","definition":"a record of money in a bank; a description of an event; to explain or give reasons for","collocations":["bank account","take into account","account for"],"example":"He opened a new bank account last month.","exampleZh":"他上個月開了一個新的銀行帳戶。","synonyms":["record","report"],"level":3,"theme":"商業與金錢","examples":[{"en":"He opened a new bank account last month.","zh":"他上個月開了一個新的銀行帳戶。"},{"en":"We should take the weather into account when planning the trip.","zh":"規劃旅行時，我們應該把天氣考慮進去。"},{"en":"She gave the police a detailed account of the accident.","zh":"她向警方詳細描述了這起事故的經過。"}]},{"word":"accumulate","pos":"v.","phonetic":"[əˈkjumjəˌlet]","meaning":"累積；積聚","definition":"to gather or gain an increasing number over time","collocations":["accumulate wealth","accumulate dust"],"example":"Dust had accumulated on the shelves over the years.","exampleZh":"多年來灰塵已在架子上堆積。","synonyms":["gather","collect"],"level":5,"theme":"抽象概念","examples":[{"en":"Dust had accumulated on the shelves over the years.","zh":"多年來灰塵已在架子上堆積。"},{"en":"Over the years, he managed to accumulate a small fortune.","zh":"多年來，他設法累積了一小筆財富。"},{"en":"Old newspapers began to accumulate in the corner of the room.","zh":"舊報紙開始堆積在房間的角落。"}]},{"word":"accurate","pos":"adj.","phonetic":"[ˈækjərɪt]","meaning":"準確的；精確的","definition":"correct and exact in every detail","collocations":["accurate information","accurate result","highly accurate"],"example":"The weather forecast was surprisingly accurate.","exampleZh":"這次的天氣預報出乎意料地準確。","synonyms":["precise","correct"],"level":4,"theme":"性質與描述","examples":[{"en":"The weather forecast was surprisingly accurate.","zh":"這次的天氣預報出乎意料地準確。"},{"en":"Please make sure the information on the form is accurate.","zh":"請確保表格上的資訊準確無誤。"},{"en":"The new device gives highly accurate temperature readings.","zh":"這台新裝置能提供高度精確的溫度讀數。"}]},{"word":"accusation","pos":"n.","phonetic":"[ˌækjəˈzeʃən]","meaning":"指控；控告","definition":"a claim that someone has done something wrong","collocations":["make an accusation","false accusation"],"example":"He denied the accusation of cheating on the test.","exampleZh":"他否認考試作弊的指控。","synonyms":["charge","allegation"],"level":5,"theme":"政治與法律","examples":[{"en":"He denied the accusation of cheating on the test.","zh":"他否認考試作弊的指控。"},{"en":"She was upset by the false accusation that she had lied.","zh":"她因為被誣指說謊而感到難過。"},{"en":"You should not make such a serious accusation without any proof.","zh":"你不該在毫無證據的情況下做出如此嚴重的指控。"}]},{"word":"accuse","pos":"v.","phonetic":"[əˈkjuz]","meaning":"指控；控告","definition":"to say that someone has done something wrong or illegal","collocations":["accuse someone of","falsely accused","accuse of stealing"],"example":"He was accused of stealing the money.","exampleZh":"他被指控偷了那筆錢。","synonyms":["blame","charge"],"level":4,"theme":"政治與法律","examples":[{"en":"He was accused of stealing the money.","zh":"他被指控偷了那筆錢。"},{"en":"The teacher accused him of copying answers during the test.","zh":"老師指控他在考試中抄襲答案。"},{"en":"It is unfair to accuse her without listening to her side.","zh":"不聽她的說法就指控她是不公平的。"}]},{"word":"accustomed","pos":"adj.","phonetic":"[əˈkʌstəmd]","meaning":"習慣的","definition":"used to something, familiar through habit","collocations":["become accustomed to","accustomed to the cold"],"example":"She soon became accustomed to the noisy city.","exampleZh":"她很快就習慣了這座喧鬧的城市。","synonyms":["used","familiar"],"level":4,"theme":"性質與描述","examples":[{"en":"She soon became accustomed to the noisy city.","zh":"她很快就習慣了這座喧鬧的城市。"},{"en":"Having lived in Canada, he is accustomed to the cold winters.","zh":"由於曾住在加拿大，他已習慣寒冷的冬天。"},{"en":"It took me a while to become accustomed to waking up early.","zh":"我花了一段時間才習慣早起。"}]},{"word":"ache","pos":"n. / v.","phonetic":"[ek]","meaning":"疼痛；隱痛","definition":"a continuous dull pain in a part of the body; to feel such a pain","collocations":["ache all over","a dull ache","my muscles ache"],"example":"My legs ache after the long hike.","exampleZh":"經過長途健行後，我的腿好痛。","synonyms":["pain","hurt"],"level":2,"theme":"身體與健康","examples":[{"en":"My legs ache after the long hike.","zh":"經過長途健行後，我的腿好痛。"},{"en":"After the long flight, my whole body ached all over.","zh":"長途飛行後，我全身都很痠痛。"},{"en":"There was a dull ache in her back after gardening all day.","zh":"整天在花園工作後，她的背部有隱隱的疼痛。"}]},{"word":"achieve","pos":"v.","phonetic":"[əˈtʃiv]","meaning":"達成；實現","definition":"to successfully complete something or reach a desired goal","collocations":["achieve a goal","achieve success","achieve a dream"],"example":"With hard work, she achieved her dream of becoming a doctor.","exampleZh":"經過努力，她實現了成為醫生的夢想。","synonyms":["accomplish","attain"],"level":3,"theme":"抽象概念","examples":[{"en":"With hard work, she achieved her dream of becoming a doctor.","zh":"經過努力，她實現了成為醫生的夢想。"},{"en":"You can achieve success through patience and constant effort.","zh":"透過耐心和持續的努力，你可以獲得成功。"},{"en":"The students worked together to achieve their common goal.","zh":"學生們齊心協力以達成他們共同的目標。"}]},{"word":"achievement","pos":"n.","phonetic":"[əˈtʃivmənt]","meaning":"成就；成績","definition":"something that has been done successfully, especially with effort or skill","collocations":["a great achievement","sense of achievement","academic achievement"],"example":"Winning the award was a great achievement for him.","exampleZh":"贏得這個獎項對他來說是一大成就。","synonyms":["accomplishment","success"],"level":3,"theme":"抽象概念","examples":[{"en":"Winning the award was a great achievement for him.","zh":"贏得這個獎項對他來說是一大成就。"},{"en":"Her academic achievement earned her a full scholarship abroad.","zh":"她的學業成就為她贏得了到國外留學的全額獎學金。"},{"en":"Reaching the mountain top gave the hikers a deep sense of achievement.","zh":"登上山頂讓登山者有深深的成就感。"}]},{"word":"acid","pos":"n. / adj.","phonetic":"[ˈæsɪd]","meaning":"酸；酸性的","definition":"a chemical substance that can dissolve metal and turn litmus paper red; having the properties of an acid","collocations":["acid rain","stomach acid","acid taste"],"example":"Acid rain can damage plants and buildings.","exampleZh":"酸雨會損害植物和建築物。","synonyms":[],"level":3,"theme":"科學與數學","examples":[{"en":"Acid rain can damage plants and buildings.","zh":"酸雨會損害植物和建築物。"},{"en":"Too much stomach acid can cause a burning feeling in your chest.","zh":"過多的胃酸會使你胸口有灼熱感。"},{"en":"This green apple has a sharp, acid taste that I love.","zh":"這顆青蘋果有我喜愛的強烈酸味。"}]},{"word":"acknowledge","pos":"v.","phonetic":"[əkˈnɑlɪdʒ]","meaning":"承認；感謝","definition":"to accept or admit that something is true; to show that you have noticed someone or something","collocations":["acknowledge a mistake","acknowledge receipt","acknowledge the truth"],"example":"He acknowledged his mistake and apologized.","exampleZh":"他承認了自己的錯誤並道歉。","synonyms":["admit","recognize"],"level":5,"theme":"溝通與語言","examples":[{"en":"He acknowledged his mistake and apologized.","zh":"他承認了自己的錯誤並道歉。"},{"en":"Please acknowledge receipt of this email as soon as possible.","zh":"請盡快確認收到這封電子郵件。"},{"en":"It takes courage to acknowledge a mistake in front of others.","zh":"在他人面前承認錯誤需要勇氣。"}]},{"word":"acquaintance","pos":"n.","phonetic":"[əˈkwentəns]","meaning":"相識的人；熟人","definition":"a person one knows slightly, not a close friend","collocations":["a business acquaintance","make his acquaintance"],"example":"He is just a casual acquaintance, not a close friend.","exampleZh":"他只是普通的熟人，不是親近的朋友。","synonyms":["contact","associate"],"level":5,"theme":"人物與家庭","examples":[{"en":"He is just a casual acquaintance, not a close friend.","zh":"他只是普通的熟人，不是親近的朋友。"},{"en":"I was glad to make her acquaintance at the school event.","zh":"我很高興在學校活動上認識她。"},{"en":"He met an old acquaintance while shopping downtown yesterday.","zh":"他昨天在市中心購物時遇到了一位老熟人。"}]},{"word":"acquire","pos":"v.","phonetic":"[əˈkwaɪr]","meaning":"獲得；取得","definition":"to gain possession of something or learn a skill through effort or experience","collocations":["acquire skills","acquire knowledge","acquire a company"],"example":"Children acquire language skills very quickly.","exampleZh":"孩童能非常快速地習得語言能力。","synonyms":["obtain","gain"],"level":4,"theme":"教育與學習","examples":[{"en":"Children acquire language skills very quickly.","zh":"孩童能非常快速地習得語言能力。"},{"en":"Reading widely helps students acquire knowledge about the world.","zh":"廣泛閱讀有助於學生獲得對世界的知識。"},{"en":"The large firm plans to acquire a smaller software company.","zh":"這家大公司計畫收購一家較小的軟體公司。"}]},{"word":"acronym","pos":"n.","phonetic":"[ˈækrəˌnɪm]","meaning":"首字母縮略詞","definition":"a word formed from the first letters of other words","collocations":["a common acronym","stand for an acronym"],"example":"NASA is an acronym for the National Aeronautics and Space Administration.","exampleZh":"NASA是「美國國家航空暨太空總署」的首字母縮略詞。","synonyms":["abbreviation"],"level":5,"theme":"溝通與語言","examples":[{"en":"NASA is an acronym for the National Aeronautics and Space Administration.","zh":"NASA是「美國國家航空暨太空總署」的首字母縮略詞。"},{"en":"The acronym DIY stands for do it yourself.","zh":"縮寫 DIY 代表 do it yourself（自己動手做）。"},{"en":"Many teenagers use the acronym LOL when chatting online.","zh":"許多青少年在網路聊天時使用縮寫 LOL。"}]},{"word":"across","pos":"prep. / adv.","phonetic":"[əˈkrɔs]","meaning":"橫越；穿過","definition":"from one side to the other of something","collocations":["across the street","across the world","walk across"],"example":"She walked across the bridge to reach the other side.","exampleZh":"她走過橋到達另一邊。","synonyms":["over"],"level":1,"theme":"時間與空間","examples":[{"en":"She walked across the bridge to reach the other side.","zh":"她走過橋到達另一邊。"},{"en":"There is a convenience store just across the street from us.","zh":"就在我們對街有一家便利商店。"},{"en":"News of the discovery spread quickly across the world.","zh":"這項發現的消息迅速傳遍全世界。"}]},{"word":"act","pos":"n. / v.","phonetic":"[ækt]","meaning":"行為；表演；行動","definition":"a thing that someone does; to perform in a play or film; to take action","collocations":["act quickly","an act of kindness","act in a movie"],"example":"He acted quickly to put out the fire.","exampleZh":"他迅速採取行動撲滅了大火。","synonyms":["deed","perform"],"level":1,"theme":"動作與行為","examples":[{"en":"He acted quickly to put out the fire.","zh":"他迅速採取行動撲滅了大火。"},{"en":"Helping the old man cross the road was a kind act.","zh":"幫助老人過馬路是個善良的舉動。"},{"en":"She has always dreamed of acting in a famous movie.","zh":"她一直夢想能在一部知名電影中演出。"}]},{"word":"action","pos":"n.","phonetic":"[ˈækʃən]","meaning":"行動；動作","definition":"the process of doing something to achieve a goal","collocations":["take action","action movie","put into action"],"example":"The government must take action to solve the problem.","exampleZh":"政府必須採取行動解決這個問題。","synonyms":["act","deed"],"level":1,"theme":"動作與行為","examples":[{"en":"The government must take action to solve the problem.","zh":"政府必須採取行動解決這個問題。"},{"en":"It is time to put our new ideas into action.","zh":"是時候把我們的新點子付諸行動了。"},{"en":"My little brother loves watching exciting action movies.","zh":"我弟弟很喜歡看刺激的動作片。"}]},{"word":"activate","pos":"v.","phonetic":"[ˈæktəˌvet]","meaning":"啟動；激發","definition":"to make something start working","collocations":["activate an alarm","activate a switch"],"example":"Press the button to activate the alarm system.","exampleZh":"按下按鈕以啟動警報系統。","synonyms":["trigger","start"],"level":3,"theme":"科技與媒體","examples":[{"en":"Press the button to activate the alarm system.","zh":"按下按鈕以啟動警報系統。"},{"en":"You need to activate your new card before using it.","zh":"你需要先啟用新卡才能使用它。"},{"en":"Opening the window at night can activate the security sensor.","zh":"夜間開窗可能會啟動安全感應器。"}]},{"word":"active","pos":"adj.","phonetic":"[ˈæktɪv]","meaning":"活躍的；積極的","definition":"engaging in physical activity or full of energy and ideas","collocations":["stay active","active lifestyle","active member"],"example":"He stays active by playing basketball every weekend.","exampleZh":"他每個週末打籃球以保持活力。","synonyms":["energetic","lively"],"level":2,"theme":"性質與描述","examples":[{"en":"He stays active by playing basketball every weekend.","zh":"他每個週末打籃球以保持活力。"},{"en":"She is an active member of the school volunteer club.","zh":"她是學校志工社的活躍成員。"},{"en":"Staying active in old age keeps both body and mind healthy.","zh":"年老時保持活躍能讓身心都健康。"}]},{"word":"activity","pos":"n.","phonetic":"[ækˈtɪvətɪ]","meaning":"活動","definition":"a thing that a person does for enjoyment, education, or exercise","collocations":["outdoor activity","school activity","physical activity"],"example":"Swimming is my favorite outdoor activity.","exampleZh":"游泳是我最喜歡的戶外活動。","synonyms":["pursuit"],"level":2,"theme":"運動與休閒","examples":[{"en":"Swimming is my favorite outdoor activity.","zh":"游泳是我最喜歡的戶外活動。"},{"en":"Doing regular physical activity is good for your heart.","zh":"規律的體能活動對你的心臟有益。"},{"en":"The school offers many after-class activities for students.","zh":"學校為學生提供許多課後活動。"}]},{"word":"actor","pos":"n.","phonetic":"[ˈæktɚ]","meaning":"演員（男）","definition":"a person who performs in plays, films, or television shows","collocations":["famous actor","leading actor","become an actor"],"example":"He is one of the most famous actors in Taiwan.","exampleZh":"他是台灣最有名的演員之一。","synonyms":["performer"],"level":1,"theme":"藝術與音樂","examples":[{"en":"He is one of the most famous actors in Taiwan.","zh":"他是台灣最有名的演員之一。"},{"en":"He has wanted to become an actor since he was a child.","zh":"他從小就想成為一名演員。"},{"en":"The leading actor gave a moving performance in the film.","zh":"男主角在這部電影中演出感人。"}]},{"word":"actress","pos":"n.","phonetic":"[ˈæktrɪs]","meaning":"女演員","definition":"a woman who performs in plays, films, or television shows","collocations":["leading actress","famous actress","award-winning actress"],"example":"The actress won an award for her performance.","exampleZh":"這位女演員因她的演出獲得了獎項。","synonyms":["performer"],"level":1,"theme":"藝術與音樂","examples":[{"en":"The actress won an award for her performance.","zh":"這位女演員因她的演出獲得了獎項。"},{"en":"The award-winning actress thanked her family in the speech.","zh":"這位得獎女演員在致詞中感謝了她的家人。"},{"en":"As a child, she dreamed of becoming a famous actress.","zh":"小時候，她夢想成為一名著名的女演員。"}]},{"word":"actual","pos":"adj.","phonetic":"[ˈæktʃʊəl]","meaning":"實際的；真實的","definition":"existing in fact; real","collocations":["actual cost","actual size","in actual fact"],"example":"The actual cost of the trip was higher than we expected.","exampleZh":"這趟旅行的實際花費比我們預期的還高。","synonyms":["real","true"],"level":3,"theme":"性質與描述","examples":[{"en":"The actual cost of the trip was higher than we expected.","zh":"這趟旅行的實際花費比我們預期的還高。"},{"en":"The photo makes the room look bigger than its actual size.","zh":"照片讓房間看起來比實際尺寸更大。"},{"en":"In actual fact, the test was easier than we had feared.","zh":"事實上，這次考試比我們擔心的還要簡單。"}]},{"word":"actually","pos":"adv.","phonetic":"[ˈæktʃʊəlɪ]","meaning":"事實上；實際上","definition":"used to emphasize that something is true or is the case, often contrary to expectation","collocations":["actually happened","what actually","actually think"],"example":"Actually, I don't like coffee at all.","exampleZh":"事實上，我一點都不喜歡咖啡。","synonyms":["in fact","really"],"level":2,"theme":"溝通與語言","examples":[{"en":"Actually, I don't like coffee at all.","zh":"事實上，我一點都不喜歡咖啡。"},{"en":"Nobody knows what actually happened on that rainy night.","zh":"沒有人知道那個雨夜實際上發生了什麼事。"},{"en":"I actually think this plan could work if we try hard.","zh":"我其實認為，只要我們努力，這個計畫是可行的。"}]},{"word":"adapt","pos":"v.","phonetic":"[əˈdæpt]","meaning":"適應；改編","definition":"to change your behavior to deal with a new situation, or to change something to fit a new use","collocations":["adapt to change","adapt a novel","adapt quickly"],"example":"It took time for him to adapt to the new environment.","exampleZh":"他花了一些時間才適應新環境。","synonyms":["adjust","modify"],"level":4,"theme":"動作與行為","examples":[{"en":"It took time for him to adapt to the new environment.","zh":"他花了一些時間才適應新環境。"},{"en":"Children usually adapt to a new school more quickly than adults.","zh":"孩子通常比大人更快適應新學校。"},{"en":"The director plans to adapt the popular novel into a film.","zh":"導演計畫把這部熱門小說改編成電影。"}]},{"word":"add","pos":"v.","phonetic":"[æd]","meaning":"增加；添加；相加","definition":"to put something together with something else, or to combine numbers","collocations":["add up","add sugar","add value"],"example":"Please add some salt to the soup.","exampleZh":"請在湯裡加一些鹽。","synonyms":["combine","include"],"level":1,"theme":"動作與行為","examples":[{"en":"Please add some salt to the soup.","zh":"請在湯裡加一些鹽。"},{"en":"If you add these numbers up, the total is one hundred.","zh":"如果你把這些數字相加，總和是一百。"},{"en":"A few fresh herbs can add flavor to a simple dish.","zh":"幾株新鮮香草就能為簡單的菜餚增添風味。"}]},{"word":"addict","pos":"n. / v.","phonetic":"[ˈædɪkt]","meaning":"上癮者；使上癮","definition":"a person who cannot stop doing or using something harmful","collocations":["drug addict","become addicted","internet addict"],"example":"He became addicted to online games.","exampleZh":"他對線上遊戲上癮了。","synonyms":["fanatic"],"level":5,"theme":"社會與文化","examples":[{"en":"He became addicted to online games.","zh":"他對線上遊戲上癮了。"},{"en":"My cousin has become a real internet addict this summer.","zh":"我表弟這個暑假變成了名副其實的網路成癮者。"},{"en":"Many people are addicted to sugary drinks without realizing it.","zh":"許多人在不知不覺中對含糖飲料上了癮。"}]},{"word":"addition","pos":"n.","phonetic":"[əˈdɪʃən]","meaning":"加法；增加物","definition":"the act of adding something, or the process of adding numbers together","collocations":["in addition to","addition to the family","simple addition"],"example":"In addition to English, she can speak French.","exampleZh":"除了英語之外，她還會說法語。","synonyms":["increase"],"level":3,"theme":"科學與數學","examples":[{"en":"In addition to English, she can speak French.","zh":"除了英語之外，她還會說法語。"},{"en":"The new baby is a lovely addition to their family.","zh":"新生兒是他們家庭中可愛的新成員。"},{"en":"In addition to studying, she works part-time at a café.","zh":"除了讀書之外，她還在咖啡廳打工。"}]},{"word":"additional","pos":"adj.","phonetic":"[əˈdɪʃənl̩]","meaning":"額外的；附加的","definition":"added to what already exists; extra","collocations":["additional cost","additional information","additional charge"],"example":"There is an additional charge for luggage.","exampleZh":"行李另外需要付額外的費用。","synonyms":["extra","further"],"level":4,"theme":"性質與描述","examples":[{"en":"There is an additional charge for luggage.","zh":"行李另外需要付額外的費用。"},{"en":"For additional information, please visit our official website.","zh":"若需更多資訊，請瀏覽我們的官方網站。"},{"en":"There will be an additional cost for express delivery.","zh":"快遞服務將會有額外的費用。"}]},{"word":"address","pos":"n. / v.","phonetic":"[əˈdrɛs]","meaning":"地址；演說；處理","definition":"the details of where a person lives or a message is sent; to deal with a problem","collocations":["home address","address the issue","email address"],"example":"Please write your address clearly on the form.","exampleZh":"請在表格上清楚寫下你的地址。","synonyms":["location","deal with"],"level":2,"theme":"居家與生活","examples":[{"en":"Please write your address clearly on the form.","zh":"請在表格上清楚寫下你的地址。"},{"en":"The principal gave an inspiring address at the graduation ceremony.","zh":"校長在畢業典禮上發表了一場激勵人心的演說。"},{"en":"The government must address the problem of air pollution soon.","zh":"政府必須盡快處理空氣污染的問題。"}]},{"word":"adequate","pos":"adj.","phonetic":"[ˈædəkwɪt]","meaning":"足夠的；適當的","definition":"enough or satisfactory for a particular purpose","collocations":["adequate supply","adequate time","adequate protection"],"example":"We need adequate time to prepare for the exam.","exampleZh":"我們需要足夠的時間準備考試。","synonyms":["sufficient","enough"],"level":5,"theme":"性質與描述","examples":[{"en":"We need adequate time to prepare for the exam.","zh":"我們需要足夠的時間準備考試。"},{"en":"Make sure you get adequate sleep before the big exam.","zh":"大考前務必要有足夠的睡眠。"},{"en":"A helmet provides adequate protection when riding a bike.","zh":"安全帽在騎腳踏車時能提供適當的保護。"}]},{"word":"adhere","pos":"v.","phonetic":"[ədˈhɪr]","meaning":"黏附；遵守","definition":"to stick firmly to something, or to follow a rule strictly","collocations":["adhere to a policy","adhere to the surface"],"example":"All employees must adhere to the company's safety rules.","exampleZh":"所有員工都必須遵守公司的安全規定。","synonyms":["stick","comply"],"level":5,"theme":"社會與文化","examples":[{"en":"All employees must adhere to the company's safety rules.","zh":"所有員工都必須遵守公司的安全規定。"},{"en":"The sticker will not adhere to a wet or dusty surface.","zh":"貼紙無法黏附在潮濕或有灰塵的表面上。"},{"en":"All members must adhere to the club's strict rules.","zh":"所有成員都必須遵守社團的嚴格規定。"}]},{"word":"adjacent","pos":"adj.","phonetic":"[əˈdʒesn̩t]","meaning":"鄰近的；毗連的","definition":"next to or near something","collocations":["adjacent room","adjacent to the park"],"example":"Our office is adjacent to a large shopping mall.","exampleZh":"我們的辦公室緊鄰一座大型購物中心。","synonyms":["nearby","neighboring"],"level":5,"theme":"時間與空間","examples":[{"en":"Our office is adjacent to a large shopping mall.","zh":"我們的辦公室緊鄰一座大型購物中心。"},{"en":"Their house is adjacent to a quiet public park.","zh":"他們的房子毗鄰一座安靜的公園。"},{"en":"The two friends were given adjacent seats on the plane.","zh":"這兩位朋友在飛機上被安排了相鄰的座位。"}]},{"word":"adjust","pos":"v.","phonetic":"[əˈdʒʌst]","meaning":"調整；適應","definition":"to change something slightly to make it more accurate or suitable; to get used to a new situation","collocations":["adjust to","adjust the settings","adjust quickly"],"example":"It took her a few weeks to adjust to the new school.","exampleZh":"她花了幾個星期才適應新學校。","synonyms":["adapt","modify"],"level":4,"theme":"動作與行為","examples":[{"en":"It took her a few weeks to adjust to the new school.","zh":"她花了幾個星期才適應新學校。"},{"en":"You can adjust the settings to make the screen brighter.","zh":"你可以調整設定讓螢幕變亮。"},{"en":"New employees usually adjust quickly to the friendly workplace.","zh":"新員工通常能很快適應這友善的職場。"}]},{"word":"adjustment","pos":"n.","phonetic":"[əˈdʒʌstmənt]","meaning":"調整；適應","definition":"a small change made to improve or correct something","collocations":["make an adjustment","adjustment period"],"example":"It took him a while to make an adjustment to the new schedule.","exampleZh":"他花了一段時間才適應新的時間表。","synonyms":["modification","change"],"level":4,"theme":"抽象概念","examples":[{"en":"It took him a while to make an adjustment to the new schedule.","zh":"他花了一段時間才適應新的時間表。"},{"en":"The mechanic made a small adjustment to the car's brakes.","zh":"技師對汽車的煞車做了小小的調整。"},{"en":"Moving to a big city required a long adjustment period.","zh":"搬到大城市需要一段長時間的適應期。"}]},{"word":"administration","pos":"n.","phonetic":"[ədˌmɪnəˈstreʃən]","meaning":"管理；行政；政府","definition":"the management of an organization or government","collocations":["school administration","government administration"],"example":"The school administration announced a new policy on attendance.","exampleZh":"校方行政單位公布了一項新的出席規定。","synonyms":["management","government"],"level":5,"theme":"政治與法律","examples":[{"en":"The school administration announced a new policy on attendance.","zh":"校方行政單位公布了一項新的出席規定。"},{"en":"The hospital administration hired more nurses to improve care.","zh":"醫院管理層聘請了更多護理師以改善照護。"},{"en":"She is studying business administration at a well-known university.","zh":"她正在一所知名大學攻讀企業管理。"}]},{"word":"admire","pos":"v.","phonetic":"[ədˈmaɪr]","meaning":"欽佩；讚賞","definition":"to respect or approve of someone or something greatly","collocations":["admire someone","admire the view","greatly admired"],"example":"I really admire her courage and determination.","exampleZh":"我非常欽佩她的勇氣和決心。","synonyms":["respect","adore"],"level":3,"theme":"情緒與感受","examples":[{"en":"I really admire her courage and determination.","zh":"我非常欽佩她的勇氣和決心。"},{"en":"We stood on the hilltop to admire the beautiful sunset.","zh":"我們站在山頂上欣賞美麗的日落。"},{"en":"She is greatly admired for her honesty and kindness.","zh":"她因誠實與善良而深受敬佩。"}]},{"word":"admission","pos":"n.","phonetic":"[ədˈmɪʃən]","meaning":"入場；入學；承認","definition":"permission to enter, or an acknowledgment of something","collocations":["admission fee","admission to college"],"example":"Admission to the museum is free on Sundays.","exampleZh":"星期日參觀博物館免費入場。","synonyms":["entry","acceptance"],"level":4,"theme":"教育與學習","examples":[{"en":"Admission to the museum is free on Sundays.","zh":"星期日參觀博物館免費入場。"},{"en":"The admission fee for the concert is quite reasonable.","zh":"這場音樂會的入場費相當合理。"},{"en":"His hard work finally earned him admission to a top college.","zh":"他的努力最終為他贏得了進入頂尖大學的資格。"}]},{"word":"admit","pos":"v.","phonetic":"[ədˈmɪt]","meaning":"承認；准許進入","definition":"to agree, often reluctantly, that something is true; to allow someone to enter","collocations":["admit a mistake","admit defeat","admitted to hospital"],"example":"He finally admitted that he was wrong.","exampleZh":"他終於承認自己錯了。","synonyms":["confess","acknowledge"],"level":3,"theme":"溝通與語言","examples":[{"en":"He finally admitted that he was wrong.","zh":"他終於承認自己錯了。"},{"en":"The players refused to admit defeat until the final whistle.","zh":"球員們直到終場哨聲前都不肯認輸。"},{"en":"She was admitted to the hospital after feeling dizzy.","zh":"她在感到頭暈後被送進了醫院。"}]},{"word":"adolescent","pos":"n. / adj.","phonetic":"[ˌædl̩ˈɛsn̩t]","meaning":"青少年（的）","definition":"a young person between childhood and adulthood","collocations":["adolescent behavior","adolescent years"],"example":"Adolescents often struggle to find their own identity.","exampleZh":"青少年常常在尋找自我認同上感到掙扎。","synonyms":["teenager","youth"],"level":5,"theme":"人物與家庭","examples":[{"en":"Adolescents often struggle to find their own identity.","zh":"青少年常常在尋找自我認同上感到掙扎。"},{"en":"During the adolescent years, teenagers experience many physical changes.","zh":"在青春期，青少年會經歷許多身體上的變化。"},{"en":"Many adolescents feel misunderstood by the adults around them.","zh":"許多青少年覺得自己被身邊的大人誤解。"}]},{"word":"adopt","pos":"v.","phonetic":"[əˈdɑpt]","meaning":"收養；採納","definition":"to legally take another person's child and raise it as your own; to choose to follow a course of action","collocations":["adopt a child","adopt a policy","adopt a new method"],"example":"They decided to adopt a child from overseas.","exampleZh":"他們決定收養一個海外的孩子。","synonyms":["take in"],"level":3,"theme":"人物與家庭","examples":[{"en":"They decided to adopt a child from overseas.","zh":"他們決定收養一個海外的孩子。"},{"en":"The school decided to adopt a new teaching method this year.","zh":"學校今年決定採用一種新的教學方法。"},{"en":"The kind couple chose to adopt a stray dog from the shelter.","zh":"這對善良的夫妻決定從收容所領養一隻流浪狗。"}]},{"word":"adore","pos":"v.","phonetic":"[əˈdɔr]","meaning":"喜愛；崇拜","definition":"to love or admire someone or something deeply","collocations":["adore her grandmother","simply adore"],"example":"The little girl adores her grandmother's stories.","exampleZh":"這個小女孩非常喜愛她祖母說的故事。","synonyms":["love","cherish"],"level":4,"theme":"情緒與感受","examples":[{"en":"The little girl adores her grandmother's stories.","zh":"這個小女孩非常喜愛她祖母說的故事。"},{"en":"The children simply adore their gentle new teacher.","zh":"孩子們非常喜愛他們溫柔的新老師。"},{"en":"She adores spending quiet weekends reading by the window.","zh":"她很喜愛在窗邊安靜地度過閱讀的週末。"}]},{"word":"adult","pos":"n. / adj.","phonetic":"[əˈdʌlt]","meaning":"成人；成年的","definition":"a person who is fully grown or of legal age","collocations":["young adult","adult life","become an adult"],"example":"Every adult in the family has a job.","exampleZh":"家中每位成人都有工作。","synonyms":["grown-up"],"level":2,"theme":"人物與家庭","examples":[{"en":"Every adult in the family has a job.","zh":"家中每位成人都有工作。"},{"en":"As a young adult, he is learning to manage his own money.","zh":"身為一個年輕的成年人，他正在學習管理自己的金錢。"},{"en":"The ticket price is different for children and adults.","zh":"兒童和成人的票價是不同的。"}]},{"word":"advance","pos":"n. / v.","phonetic":"[ædˈvæns]","meaning":"前進；進展；預付","definition":"to move forward or make progress; a movement forward","collocations":["in advance","advance notice","technological advance"],"example":"Please book your tickets in advance.","exampleZh":"請提前預訂你的票。","synonyms":["progress","proceed"],"level":4,"theme":"抽象概念","examples":[{"en":"Please book your tickets in advance.","zh":"請提前預訂你的票。"},{"en":"Recent technological advances have changed the way we communicate.","zh":"近來的科技進步改變了我們溝通的方式。"},{"en":"Please give the teacher advance notice if you cannot attend.","zh":"如果你無法出席，請事先通知老師。"}]},{"word":"advantage","pos":"n.","phonetic":"[ædˈvæntɪdʒ]","meaning":"優勢；好處","definition":"a condition or circumstance that puts one in a favorable position","collocations":["take advantage of","have an advantage","gain an advantage"],"example":"Speaking two languages gives her an advantage in job hunting.","exampleZh":"會說兩種語言讓她在求職上有優勢。","synonyms":["benefit"],"level":3,"theme":"抽象概念","examples":[{"en":"Speaking two languages gives her an advantage in job hunting.","zh":"會說兩種語言讓她在求職上有優勢。"},{"en":"You should take advantage of every chance to practice English.","zh":"你應該把握每個練習英語的機會。"},{"en":"Being tall gives him an advantage in playing basketball.","zh":"身材高大讓他在打籃球時佔有優勢。"}]},{"word":"adventure","pos":"n.","phonetic":"[ædˈvɛntʃɚ]","meaning":"冒險；奇遇","definition":"an exciting or dangerous experience","collocations":["go on an adventure","adventure story","sense of adventure"],"example":"Climbing the mountain was a great adventure for us.","exampleZh":"爬這座山對我們來說是一場很棒的冒險。","synonyms":["expedition"],"level":2,"theme":"交通與旅行","examples":[{"en":"Climbing the mountain was a great adventure for us.","zh":"爬這座山對我們來說是一場很棒的冒險。"},{"en":"The children love reading exciting adventure stories before bed.","zh":"孩子們喜歡在睡前閱讀刺激的冒險故事。"},{"en":"They set off on an adventure through the deep forest.","zh":"他們踏上了穿越森林深處的冒險旅程。"}]},{"word":"advertise","pos":"v.","phonetic":"[ˈædvɚˌtaɪz]","meaning":"廣告；宣傳","definition":"to tell the public about a product or service in order to encourage sales","collocations":["advertise a product","advertise online","widely advertised"],"example":"The company advertises its products on social media.","exampleZh":"這家公司在社群媒體上宣傳其產品。","synonyms":["promote"],"level":3,"theme":"商業與金錢","examples":[{"en":"The company advertises its products on social media.","zh":"這家公司在社群媒體上宣傳其產品。"},{"en":"Small shops often advertise online to reach more customers.","zh":"小商店常在網路上打廣告以觸及更多顧客。"},{"en":"The new movie was widely advertised on buses and billboards.","zh":"這部新電影在公車和廣告看板上被廣泛宣傳。"}]},{"word":"advertisement","pos":"n.","phonetic":"[ˌædvɚˈtaɪzmənt]","meaning":"廣告","definition":"a public notice promoting a product, service, or event","collocations":["a TV advertisement","place an advertisement","job advertisement"],"example":"I saw an advertisement for a new smartphone on TV.","exampleZh":"我在電視上看到一則新款智慧型手機的廣告。","synonyms":["ad","commercial"],"level":3,"theme":"商業與金錢","examples":[{"en":"I saw an advertisement for a new smartphone on TV.","zh":"我在電視上看到一則新款智慧型手機的廣告。"},{"en":"She found her current job through an advertisement in the newspaper.","zh":"她透過報紙上的一則廣告找到了現在的工作。"},{"en":"That catchy TV advertisement has been stuck in my head all day.","zh":"那則朗朗上口的電視廣告在我腦中盤旋了一整天。"}]},{"word":"advice","pos":"n.","phonetic":"[ædˈvaɪs]","meaning":"建議；忠告","definition":"suggestions about what someone should do","collocations":["give advice","take advice","piece of advice"],"example":"My teacher gave me some useful advice about studying.","exampleZh":"我的老師給了我一些關於讀書的實用建議。","synonyms":["suggestion","guidance"],"level":2,"theme":"溝通與語言","examples":[{"en":"My teacher gave me some useful advice about studying.","zh":"我的老師給了我一些關於讀書的實用建議。"},{"en":"Let me give you a useful piece of advice about interviews.","zh":"讓我給你一個關於面試的實用建議。"},{"en":"You should take your parents' advice more seriously.","zh":"你應該更認真地聽取父母的建議。"}]},{"word":"advise","pos":"v.","phonetic":"[ædˈvaɪz]","meaning":"建議；勸告","definition":"to recommend that someone do something","collocations":["advise someone to","strongly advise","advise against"],"example":"The doctor advised him to rest for a week.","exampleZh":"醫生建議他休息一個星期。","synonyms":["recommend","suggest"],"level":3,"theme":"溝通與語言","examples":[{"en":"The doctor advised him to rest for a week.","zh":"醫生建議他休息一個星期。"},{"en":"I would strongly advise you to save some money each month.","zh":"我強烈建議你每個月存一些錢。"},{"en":"The coach advised the players against training in the heat.","zh":"教練勸球員們不要在酷熱中訓練。"}]},{"word":"advocate","pos":"v. / n.","phonetic":"[ˈædvəˌket]","meaning":"提倡；擁護者","definition":"to publicly support an idea, or a person who does so","collocations":["advocate for change","a strong advocate"],"example":"She advocates for equal education opportunities for all children.","exampleZh":"她提倡讓所有孩子享有平等的教育機會。","synonyms":["support","champion"],"level":6,"theme":"社會與文化","examples":[{"en":"She advocates for equal education opportunities for all children.","zh":"她提倡讓所有孩子享有平等的教育機會。"},{"en":"He is a strong advocate of protecting the environment.","zh":"他是保護環境的堅定擁護者。"},{"en":"Many students advocate for longer breaks between classes.","zh":"許多學生提倡在課間有更長的休息時間。"}]},{"word":"aesthetic","pos":"adj. / n.","phonetic":"[ɛsˈθɛtɪk]","meaning":"美學的；審美觀","definition":"concerned with beauty or the appreciation of it","collocations":["aesthetic value","aesthetic appeal"],"example":"The building's design has great aesthetic appeal.","exampleZh":"這棟建築的設計極具美感。","synonyms":["artistic","visual"],"level":6,"theme":"藝術與音樂","examples":[{"en":"The building's design has great aesthetic appeal.","zh":"這棟建築的設計極具美感。"},{"en":"The old temple has great aesthetic value for many artists.","zh":"這座古老的寺廟對許多藝術家而言具有極高的美學價值。"},{"en":"Simple furniture can still have a strong aesthetic appeal.","zh":"簡約的家具依然可以有強烈的美感吸引力。"}]},{"word":"affair","pos":"n.","phonetic":"[əˈfɛr]","meaning":"事務；事情；外遇","definition":"an event or a series of events; matters of public interest or business","collocations":["foreign affairs","a love affair","current affairs"],"example":"The minister is responsible for foreign affairs.","exampleZh":"這位部長負責外交事務。","synonyms":["matter","business"],"level":4,"theme":"社會與文化","examples":[{"en":"The minister is responsible for foreign affairs.","zh":"這位部長負責外交事務。"},{"en":"Reading the news keeps me informed about current affairs.","zh":"閱讀新聞讓我了解時事。"},{"en":"How I spend my free time is my own private affair.","zh":"我如何運用空閒時間是我自己的私事。"}]},{"word":"affect","pos":"v.","phonetic":"[əˈfɛkt]","meaning":"影響","definition":"to have an effect or influence on someone or something","collocations":["affect health","directly affect","badly affected"],"example":"The bad weather affected our travel plans.","exampleZh":"惡劣的天氣影響了我們的旅行計畫。","synonyms":["influence","impact"],"level":3,"theme":"抽象概念","examples":[{"en":"The bad weather affected our travel plans.","zh":"惡劣的天氣影響了我們的旅行計畫。"},{"en":"Lack of sleep can seriously affect your health and mood.","zh":"睡眠不足會嚴重影響你的健康和情緒。"},{"en":"The heavy storm badly affected the farmers' rice harvest.","zh":"這場大風暴嚴重影響了農民的稻米收成。"}]},{"word":"affectionate","pos":"adj.","phonetic":"[əˈfɛkʃənɪt]","meaning":"親切的；深情的","definition":"showing warm and tender feelings","collocations":["an affectionate hug","affectionate towards"],"example":"He gave his daughter an affectionate hug before leaving.","exampleZh":"他離開前給了女兒一個深情的擁抱。","synonyms":["loving","tender"],"level":5,"theme":"情緒與感受","examples":[{"en":"He gave his daughter an affectionate hug before leaving.","zh":"他離開前給了女兒一個深情的擁抱。"},{"en":"The puppy is very affectionate towards everyone in the family.","zh":"這隻小狗對家裡每個人都很親暱。"},{"en":"She wrote an affectionate letter to her grandmother overseas.","zh":"她寫了一封充滿深情的信給海外的祖母。"}]},{"word":"affirm","pos":"v.","phonetic":"[əˈfɝm]","meaning":"肯定；斷言","definition":"to state something firmly as true","collocations":["affirm one's belief","affirm a decision"],"example":"The judge affirmed the earlier court decision.","exampleZh":"法官肯定了先前法院的判決。","synonyms":["confirm","assert"],"level":6,"theme":"溝通與語言","examples":[{"en":"The judge affirmed the earlier court decision.","zh":"法官肯定了先前法院的判決。"},{"en":"The scientist affirmed that the results were completely reliable.","zh":"這位科學家肯定地表示，這些結果完全可靠。"},{"en":"Her success affirmed her belief that hard work pays off.","zh":"她的成功肯定了她「努力終有回報」的信念。"}]},{"word":"afford","pos":"v.","phonetic":"[əˈfɔrd]","meaning":"負擔得起","definition":"to have enough money or time to be able to do or buy something","collocations":["can afford","afford to buy","afford the time"],"example":"We can't afford a new car this year.","exampleZh":"我們今年買不起新車。","synonyms":["manage"],"level":3,"theme":"商業與金錢","examples":[{"en":"We can't afford a new car this year.","zh":"我們今年買不起新車。"},{"en":"After saving for a year, they could finally afford a house.","zh":"存了一年錢後，他們終於買得起房子了。"},{"en":"I can't afford the time to watch television on weekdays.","zh":"我平日沒有多餘的時間看電視。"}]},{"word":"afraid","pos":"adj.","phonetic":"[əˈfred]","meaning":"害怕的；擔心的","definition":"feeling fear or worry about something","collocations":["afraid of","be afraid to","I'm afraid so"],"example":"She is afraid of spiders and snakes.","exampleZh":"她害怕蜘蛛和蛇。","synonyms":["scared","fearful"],"level":1,"theme":"情緒與感受","examples":[{"en":"She is afraid of spiders and snakes.","zh":"她害怕蜘蛛和蛇。"},{"en":"Don't be afraid to ask questions when you feel confused.","zh":"當你感到困惑時，不要害怕發問。"},{"en":"He was afraid of failing, so he practiced every single day.","zh":"他害怕失敗，所以每天都練習。"}]},{"word":"after","pos":"prep. / conj.","phonetic":"[ˈæftɚ]","meaning":"在...之後","definition":"following in time or place","collocations":["after school","after all","shortly after"],"example":"We went to the park after lunch.","exampleZh":"我們午餐後去了公園。","synonyms":["following"],"level":1,"theme":"時間與空間","examples":[{"en":"We went to the park after lunch.","zh":"我們午餐後去了公園。"},{"en":"We often play basketball together after school on Fridays.","zh":"我們週五放學後常一起打籃球。"},{"en":"Shortly after the movie began, the power suddenly went out.","zh":"電影開始不久後，突然停電了。"}]},{"word":"afternoon","pos":"n.","phonetic":"[ˌæftɚˈnun]","meaning":"下午","definition":"the time between noon and evening","collocations":["this afternoon","in the afternoon","good afternoon"],"example":"We usually take a walk in the afternoon.","exampleZh":"我們通常在下午散步。","synonyms":[],"level":1,"theme":"時間與空間","examples":[{"en":"We usually take a walk in the afternoon.","zh":"我們通常在下午散步。"},{"en":"Let's meet this afternoon to finish the group project.","zh":"我們今天下午碰面，把小組報告完成吧。"},{"en":"The library gets very crowded on weekend afternoons.","zh":"週末下午圖書館會變得非常擁擠。"}]},{"word":"again","pos":"adv.","phonetic":"[əˈɡɛn]","meaning":"再一次；又","definition":"one more time; once more","collocations":["once again","try again","never again"],"example":"Could you say that again, please?","exampleZh":"可以請你再說一次嗎？","synonyms":["once more"],"level":1,"theme":"時間與空間","examples":[{"en":"Could you say that again, please?","zh":"可以請你再說一次嗎？"},{"en":"If you fail the first time, just try again patiently.","zh":"如果第一次失敗，就耐心地再試一次。"},{"en":"The little boy asked to hear his favorite story again.","zh":"小男孩要求再聽一次他最喜歡的故事。"}]},{"word":"against","pos":"prep.","phonetic":"[əˈɡɛnst]","meaning":"反對；靠著","definition":"in opposition to; touching or leaning on","collocations":["vote against","lean against","against the law"],"example":"Many people voted against the new policy.","exampleZh":"許多人投票反對這項新政策。","synonyms":["opposed to"],"level":1,"theme":"抽象概念","examples":[{"en":"Many people voted against the new policy.","zh":"許多人投票反對這項新政策。"},{"en":"He leaned against the wall while waiting for the bus.","zh":"他等公車時靠著牆。"},{"en":"Driving without a license is against the law here.","zh":"在這裡無照駕駛是違法的。"}]},{"word":"age","pos":"n. / v.","phonetic":"[edʒ]","meaning":"年齡；時代；變老","definition":"the length of time a person has lived; a particular period of history","collocations":["at the age of","old age","the digital age"],"example":"She started learning the piano at the age of five.","exampleZh":"她五歲時開始學鋼琴。","synonyms":["era"],"level":1,"theme":"人物與家庭","examples":[{"en":"She started learning the piano at the age of five.","zh":"她五歲時開始學鋼琴。"},{"en":"In the digital age, almost everyone owns a smartphone.","zh":"在數位時代，幾乎每個人都擁有智慧型手機。"},{"en":"My grandfather is still active and healthy in his old age.","zh":"我爺爺年邁時依然活躍又健康。"}]},{"word":"agency","pos":"n.","phonetic":"[ˈedʒənsɪ]","meaning":"仲介機構；代理處","definition":"a business or organization that provides a particular service","collocations":["travel agency","advertising agency","government agency"],"example":"We booked our trip through a travel agency.","exampleZh":"我們透過旅行社訂了這趟旅程。","synonyms":["bureau"],"level":4,"theme":"工作與職業","examples":[{"en":"We booked our trip through a travel agency.","zh":"我們透過旅行社訂了這趟旅程。"},{"en":"She works at an advertising agency in the city center.","zh":"她在市中心的一家廣告公司工作。"},{"en":"A government agency is responsible for protecting public health.","zh":"一個政府機構負責保護公眾健康。"}]},{"word":"agent","pos":"n.","phonetic":"[ˈedʒənt]","meaning":"代理人；探員","definition":"a person who acts on behalf of another person or organization","collocations":["travel agent","secret agent","real estate agent"],"example":"Her agent negotiated a better contract for her.","exampleZh":"她的經紀人幫她談成了更好的合約。","synonyms":["representative"],"level":3,"theme":"工作與職業","examples":[{"en":"Her agent negotiated a better contract for her.","zh":"她的經紀人幫她談成了更好的合約。"},{"en":"The real estate agent showed us three apartments today.","zh":"房仲今天帶我們看了三間公寓。"},{"en":"A travel agent helped us plan the entire trip to Japan.","zh":"旅行社人員幫我們規劃了整趟日本行程。"}]},{"word":"aggressive","pos":"adj.","phonetic":"[əˈɡrɛsɪv]","meaning":"具攻擊性的；積極的","definition":"ready or likely to attack or confront; forceful in pursuing goals","collocations":["aggressive behavior","aggressive marketing","become aggressive"],"example":"The dog became aggressive when strangers approached.","exampleZh":"當陌生人靠近時，這隻狗變得有攻擊性。","synonyms":["hostile","forceful"],"level":4,"theme":"情緒與感受","examples":[{"en":"The dog became aggressive when strangers approached.","zh":"當陌生人靠近時，這隻狗變得有攻擊性。"},{"en":"The company used aggressive marketing to promote its new phone.","zh":"這家公司用積極的行銷手法來推廣新手機。"},{"en":"The referee warned the player for his aggressive behavior.","zh":"裁判警告那名球員的攻擊性行為。"}]},{"word":"ago","pos":"adv.","phonetic":"[əˈɡo]","meaning":"以前","definition":"before the present time; in the past","collocations":["years ago","a while ago","long ago"],"example":"They moved to this city three years ago.","exampleZh":"他們三年前搬到這座城市。","synonyms":["before"],"level":1,"theme":"時間與空間","examples":[{"en":"They moved to this city three years ago.","zh":"他們三年前搬到這座城市。"},{"en":"Long ago, people traveled mainly by horse and carriage.","zh":"很久以前，人們主要以馬車代步。"},{"en":"I finished my homework a while ago and went outside.","zh":"我不久前就寫完了功課，然後出去了。"}]},{"word":"agony","pos":"n.","phonetic":"[ˈæɡənɪ]","meaning":"極度痛苦；苦惱","definition":"extreme physical or mental pain or suffering","collocations":["in agony","cry in agony","agony of defeat"],"example":"He was in agony after twisting his ankle.","exampleZh":"他扭傷腳踝後痛苦不堪。","synonyms":["anguish","torment"],"level":5,"theme":"情緒與感受","examples":[{"en":"He was in agony after twisting his ankle.","zh":"他扭傷腳踝後痛苦不堪。"},{"en":"The injured runner lay on the track, crying in agony.","zh":"受傷的跑者躺在跑道上，痛苦地哭喊著。"},{"en":"Waiting for the exam results was pure agony for her.","zh":"等待考試結果對她來說是極大的煎熬。"}]},{"word":"agree","pos":"v.","phonetic":"[əˈɡri]","meaning":"同意；贊成","definition":"to have the same opinion as someone else, or to say yes to something","collocations":["agree with","agree to","totally agree"],"example":"I agree with your opinion on this matter.","exampleZh":"我同意你對這件事的看法。","synonyms":["consent"],"level":1,"theme":"溝通與語言","examples":[{"en":"I agree with your opinion on this matter.","zh":"我同意你對這件事的看法。"},{"en":"My classmates and I totally agree on the class trip destination.","zh":"我和同學們對班遊的目的地意見完全一致。"},{"en":"After some discussion, she agreed to help with the event.","zh":"經過一番討論後，她同意幫忙這場活動。"}]},{"word":"agreement","pos":"n.","phonetic":"[əˈɡrimənt]","meaning":"協議；同意","definition":"a formal decision or arrangement between two or more parties, or the state of agreeing","collocations":["reach an agreement","sign an agreement","come to an agreement"],"example":"The two countries signed a trade agreement.","exampleZh":"這兩個國家簽署了貿易協議。","synonyms":["contract","accord"],"level":3,"theme":"政治與法律","examples":[{"en":"The two countries signed a trade agreement.","zh":"這兩個國家簽署了貿易協議。"},{"en":"After hours of talks, both sides finally reached an agreement.","zh":"經過數小時的會談，雙方終於達成協議。"},{"en":"The two families came to an agreement about the shared garden.","zh":"兩家人就共用的花園達成了共識。"}]},{"word":"agricultural","pos":"adj.","phonetic":"[ˌæɡrɪˈkʌltʃərəl]","meaning":"農業的","definition":"relating to farming and the production of crops or livestock","collocations":["agricultural products","agricultural land","agricultural industry"],"example":"Taiwan exports many agricultural products.","exampleZh":"台灣出口許多農產品。","synonyms":["farming"],"level":4,"theme":"自然與環境","examples":[{"en":"Taiwan exports many agricultural products.","zh":"台灣出口許多農產品。"},{"en":"Much of the agricultural land here is used to grow rice.","zh":"這裡大部分的農地都用來種植稻米。"},{"en":"New machines have made the agricultural industry more efficient.","zh":"新機器使農業更有效率。"}]},{"word":"agriculture","pos":"n.","phonetic":"[ˈæɡrɪˌkʌltʃɚ]","meaning":"農業","definition":"the practice of farming, including growing crops and raising animals","collocations":["modern agriculture","agriculture department","sustainable agriculture"],"example":"Agriculture plays an important role in the country's economy.","exampleZh":"農業在這個國家的經濟中扮演重要角色。","synonyms":["farming"],"level":4,"theme":"自然與環境","examples":[{"en":"Agriculture plays an important role in the country's economy.","zh":"農業在這個國家的經濟中扮演重要角色。"},{"en":"Sustainable agriculture helps protect the soil for future generations.","zh":"永續農業有助於為後代保護土壤。"},{"en":"Modern agriculture relies heavily on advanced technology and machines.","zh":"現代農業高度仰賴先進的科技與機器。"}]},{"word":"ahead","pos":"adv.","phonetic":"[əˈhɛd]","meaning":"在前面；提前","definition":"further forward in space or time; in advance","collocations":["ahead of time","go ahead","plan ahead"],"example":"We need to plan ahead for the holidays.","exampleZh":"我們需要提前為假期做規劃。","synonyms":["in front","in advance"],"level":2,"theme":"時間與空間","examples":[{"en":"We need to plan ahead for the holidays.","zh":"我們需要提前為假期做規劃。"},{"en":"She finished the report two days ahead of time.","zh":"她提前兩天完成了報告。"},{"en":"You may go ahead and start eating without waiting for me.","zh":"你可以先開動，不用等我。"}]},{"word":"aid","pos":"n. / v.","phonetic":"[ed]","meaning":"援助；幫助","definition":"help or support, especially in a difficult situation","collocations":["financial aid","first aid","come to someone's aid"],"example":"The country received financial aid after the earthquake.","exampleZh":"這個國家在地震後獲得了財政援助。","synonyms":["help","assistance"],"level":3,"theme":"社會與文化","examples":[{"en":"The country received financial aid after the earthquake.","zh":"這個國家在地震後獲得了財政援助。"},{"en":"Several strangers came to his aid after he fell down.","zh":"他跌倒後，幾位陌生人前來幫助他。"},{"en":"Every teacher should know basic first aid for emergencies.","zh":"每位老師都應該懂得基本的急救以應付緊急狀況。"}]},{"word":"aim","pos":"n. / v.","phonetic":"[em]","meaning":"目標；瞄準","definition":"a purpose or intention; to point a weapon or object at a target","collocations":["aim for","achieve one's aim","aim at"],"example":"Her aim is to become a professional dancer.","exampleZh":"她的目標是成為職業舞者。","synonyms":["goal","purpose"],"level":3,"theme":"抽象概念","examples":[{"en":"Her aim is to become a professional dancer.","zh":"她的目標是成為職業舞者。"},{"en":"The archer carefully aimed at the center of the target.","zh":"弓箭手小心地瞄準靶心。"},{"en":"We should always aim for progress rather than perfection.","zh":"我們應該總是以進步為目標，而非追求完美。"}]},{"word":"air","pos":"n.","phonetic":"[ɛr]","meaning":"空氣；空中","definition":"the invisible mixture of gases that surrounds the earth","collocations":["fresh air","air pollution","in the air"],"example":"We opened the window to let in some fresh air.","exampleZh":"我們打開窗戶讓新鮮空氣進來。","synonyms":["atmosphere"],"level":1,"theme":"自然與環境","examples":[{"en":"We opened the window to let in some fresh air.","zh":"我們打開窗戶讓新鮮空氣進來。"},{"en":"Air pollution has become a serious problem in many big cities.","zh":"空氣污染在許多大城市已成為嚴重的問題。"},{"en":"A pleasant smell of flowers filled the air in spring.","zh":"春天時空氣中瀰漫著宜人的花香。"}]},{"word":"aircraft","pos":"n.","phonetic":"[ˈɛrˌkræft]","meaning":"飛機；航空器","definition":"a machine capable of flight, such as an airplane or helicopter","collocations":["military aircraft","aircraft carrier","fly an aircraft"],"example":"The aircraft landed safely despite the storm.","exampleZh":"儘管有暴風雨，這架飛機還是安全降落了。","synonyms":["airplane","plane"],"level":3,"theme":"交通與旅行","examples":[{"en":"The aircraft landed safely despite the storm.","zh":"儘管有暴風雨，這架飛機還是安全降落了。"},{"en":"Learning to fly an aircraft requires years of careful training.","zh":"學習駕駛飛機需要多年的謹慎訓練。"},{"en":"Several military aircraft flew over the city during the parade.","zh":"遊行期間有幾架軍機飛越城市上空。"}]},{"word":"airport","pos":"n.","phonetic":"[ˈɛrˌport]","meaning":"機場","definition":"a place where aircraft take off and land, with buildings for passengers","collocations":["international airport","airport security","drive to the airport"],"example":"My father will pick me up at the airport tomorrow.","exampleZh":"我爸爸明天會到機場接我。","synonyms":[],"level":1,"theme":"交通與旅行","examples":[{"en":"My father will pick me up at the airport tomorrow.","zh":"我爸爸明天會到機場接我。"},{"en":"We arrived early to get through airport security in time.","zh":"我們提早抵達，以便及時通過機場安檢。"},{"en":"The new international airport can handle millions of travelers.","zh":"這座新的國際機場能容納數百萬名旅客。"}]},{"word":"aisle","pos":"n.","phonetic":"[aɪl]","meaning":"走道；通道","definition":"a passage between rows of seats or shelves","collocations":["aisle seat","walk down the aisle","grocery aisle"],"example":"She chose an aisle seat so she could stretch her legs.","exampleZh":"她選了走道座位好伸展雙腿。","synonyms":["passage","walkway"],"level":3,"theme":"交通與旅行","examples":[{"en":"She chose an aisle seat so she could stretch her legs.","zh":"她選了走道座位好伸展雙腿。"},{"en":"You can find the snacks in the third grocery aisle.","zh":"你可以在第三條雜貨走道找到零食。"},{"en":"The flight attendant walked slowly down the narrow aisle.","zh":"空服員沿著狹窄的走道緩緩前行。"}]},{"word":"ajar","pos":"adj.","phonetic":"[əˈdʒɑr]","meaning":"（門）半開的","definition":"slightly open","collocations":["leave the door ajar","door was ajar"],"example":"He left the door ajar so the cat could come in.","exampleZh":"他讓門半開著好讓貓進來。","synonyms":["half-open"],"level":5,"theme":"居家與生活","examples":[{"en":"He left the door ajar so the cat could come in.","zh":"他讓門半開著好讓貓進來。"},{"en":"She left the window ajar to let in some fresh air.","zh":"她把窗戶留一條縫，好讓新鮮空氣進來。"},{"en":"When I got home, I noticed the front door was ajar.","zh":"我回到家時，注意到前門半開著。"}]},{"word":"alarm","pos":"n. / v.","phonetic":"[əˈlɑrm]","meaning":"警報；驚恐；使驚恐","definition":"a warning sound or signal; a feeling of fear or anxiety; to make someone anxious","collocations":["fire alarm","set an alarm","alarm clock"],"example":"The fire alarm went off during the meeting.","exampleZh":"開會時火災警報響了起來。","synonyms":["alert","warning"],"level":3,"theme":"居家與生活","examples":[{"en":"The fire alarm went off during the meeting.","zh":"開會時火災警報響了起來。"},{"en":"I set an alarm for six so I won't oversleep.","zh":"我把鬧鐘設在六點，這樣就不會睡過頭。"},{"en":"The loud noise from the kitchen filled her with alarm.","zh":"廚房傳來的巨大聲響讓她充滿驚恐。"}]},{"word":"album","pos":"n.","phonetic":"[ˈælbəm]","meaning":"專輯；相簿","definition":"a collection of songs released together, or a book for keeping photographs","collocations":["photo album","release an album","new album"],"example":"The band just released their new album.","exampleZh":"這個樂團剛發行了他們的新專輯。","synonyms":["record"],"level":2,"theme":"藝術與音樂","examples":[{"en":"The band just released their new album.","zh":"這個樂團剛發行了他們的新專輯。"},{"en":"We spent the evening looking through an old photo album.","zh":"我們花了一整晚翻看舊相簿。"},{"en":"Her favorite singer will release a new album next month.","zh":"她最喜歡的歌手下個月將發行新專輯。"}]},{"word":"alcohol","pos":"n.","phonetic":"[ˈælkəˌhɔl]","meaning":"酒精；含酒精飲料","definition":"a colorless liquid found in drinks like beer and wine that can make people drunk","collocations":["drink alcohol","alcohol abuse","alcohol-free"],"example":"He decided to give up alcohol for health reasons.","exampleZh":"他為了健康因素決定戒酒。","synonyms":["liquor"],"level":4,"theme":"食物與烹飪","examples":[{"en":"He decided to give up alcohol for health reasons.","zh":"他為了健康因素決定戒酒。"},{"en":"The party will serve only alcohol-free drinks for the students.","zh":"這場派對只會為學生提供無酒精飲料。"},{"en":"Doctors warn that too much alcohol can damage the liver.","zh":"醫生警告，過量的酒精會損害肝臟。"}]},{"word":"alert","pos":"adj. / v. / n.","phonetic":"[əˈlɝt]","meaning":"警覺的；警報；提醒","definition":"quick to notice danger or trouble; to warn someone of a danger","collocations":["stay alert","weather alert","alert someone to"],"example":"The guard remained alert throughout the night.","exampleZh":"這名警衛整晚保持警覺。","synonyms":["watchful","vigilant"],"level":4,"theme":"性質與描述","examples":[{"en":"The guard remained alert throughout the night.","zh":"這名警衛整晚保持警覺。"},{"en":"The weather alert warned people about the coming typhoon.","zh":"氣象警報提醒民眾即將來襲的颱風。"},{"en":"Drivers must stay alert when the roads are wet and slippery.","zh":"當路面潮濕溼滑時，駕駛必須保持警覺。"}]},{"word":"alien","pos":"n. / adj.","phonetic":"[ˈeljən]","meaning":"外星人；外國的","definition":"a creature from another planet; foreign or unfamiliar","collocations":["alien invasion","illegal alien","alien species"],"example":"The movie is about an alien from outer space.","exampleZh":"這部電影是關於一個來自外太空的外星人。","synonyms":["extraterrestrial","foreign"],"level":4,"theme":"科學與數學","examples":[{"en":"The movie is about an alien from outer space.","zh":"這部電影是關於一個來自外太空的外星人。"},{"en":"An alien species of fish is threatening the local river life.","zh":"一種外來魚類正威脅著當地河川的生態。"},{"en":"The customs of that country felt completely alien to him.","zh":"那個國家的習俗對他來說完全陌生。"}]},{"word":"alike","pos":"adj. / adv.","phonetic":"[əˈlaɪk]","meaning":"相似的；同樣地","definition":"similar in appearance or nature","collocations":["look alike","think alike","treat everyone alike"],"example":"The twins look so alike that people can't tell them apart.","exampleZh":"這對雙胞胎長得太像了，讓人分不清楚。","synonyms":["similar"],"level":3,"theme":"性質與描述","examples":[{"en":"The twins look so alike that people can't tell them apart.","zh":"這對雙胞胎長得太像了，讓人分不清楚。"},{"en":"A good teacher tries to treat all students alike.","zh":"好老師會試著平等地對待所有學生。"},{"en":"The two brothers think alike and often finish each other's sentences.","zh":"這對兄弟想法相似，常常接完彼此的話。"}]},{"word":"alive","pos":"adj.","phonetic":"[əˈlaɪv]","meaning":"活著的；有活力的","definition":"living, not dead; full of energy and activity","collocations":["stay alive","come alive","alive and well"],"example":"The rescue team found the missing hiker alive.","exampleZh":"救援隊發現失蹤的登山客還活著。","synonyms":["living"],"level":2,"theme":"性質與描述","examples":[{"en":"The rescue team found the missing hiker alive.","zh":"救援隊發現失蹤的登山客還活著。"},{"en":"The whole city comes alive with music during the festival.","zh":"節慶期間，整座城市因音樂而活躍起來。"},{"en":"We were relieved to hear that everyone was alive and well.","zh":"聽到大家都平安無事，我們鬆了一口氣。"}]},{"word":"allergic","pos":"adj.","phonetic":"[əˈlɝdʒɪk]","meaning":"過敏的","definition":"having an allergy to a particular substance","collocations":["allergic to","allergic reaction","allergic to peanuts"],"example":"She is allergic to peanuts and must avoid them.","exampleZh":"她對花生過敏，必須避免食用。","synonyms":[],"level":4,"theme":"身體與健康","examples":[{"en":"She is allergic to peanuts and must avoid them.","zh":"她對花生過敏，必須避免食用。"},{"en":"He had a mild allergic reaction after eating the seafood.","zh":"他吃了海鮮後出現了輕微的過敏反應。"},{"en":"Many people are allergic to pollen during the spring season.","zh":"許多人在春季會對花粉過敏。"}]},{"word":"allergy","pos":"n.","phonetic":"[ˈælɚdʒi]","meaning":"過敏","definition":"a medical condition causing a reaction to certain substances","collocations":["food allergy","allergy to pollen","allergy season"],"example":"She has an allergy to peanuts.","exampleZh":"她對花生過敏。","synonyms":["sensitivity"],"level":3,"theme":"身體與健康","examples":[{"en":"She has an allergy to peanuts.","zh":"她對花生過敏。"},{"en":"During allergy season, she sneezes almost every morning.","zh":"在過敏季節，她幾乎每天早上都打噴嚏。"},{"en":"Please tell the waiter if you have any food allergy.","zh":"如果你有任何食物過敏，請告訴服務生。"}]},{"word":"alley","pos":"n.","phonetic":"[ˈæli]","meaning":"巷子；小巷","definition":"a narrow street between or behind buildings","collocations":["back alley","blind alley","dark alley"],"example":"The cat disappeared into a narrow alley.","exampleZh":"那隻貓消失在一條狹窄的小巷裡。","synonyms":["lane"],"level":3,"theme":"居家與生活","examples":[{"en":"The cat disappeared into a narrow alley.","zh":"那隻貓消失在一條狹窄的小巷裡。"},{"en":"A small noodle shop is hidden in that narrow back alley.","zh":"一家小麵店藏在那條狹窄的後巷裡。"},{"en":"She felt nervous walking through the dark alley at night.","zh":"她夜裡走過那條昏暗的小巷時感到緊張。"}]},{"word":"alliance","pos":"n.","phonetic":"[əˈlaɪəns]","meaning":"聯盟；同盟","definition":"a union between groups formed for mutual benefit","collocations":["form an alliance","military alliance","strategic alliance"],"example":"The two countries formed a military alliance.","exampleZh":"這兩國組成了軍事同盟。","synonyms":["union","coalition"],"level":5,"theme":"政治與法律","examples":[{"en":"The two countries formed a military alliance.","zh":"這兩國組成了軍事同盟。"},{"en":"The two companies formed a strategic alliance to share technology.","zh":"這兩家公司組成策略聯盟以共享技術。"},{"en":"Several small nations built an alliance to protect their trade.","zh":"幾個小國建立聯盟以保護他們的貿易。"}]},{"word":"allocate","pos":"v.","phonetic":"[ˈæləˌket]","meaning":"分配；撥出","definition":"to give resources for a particular purpose","collocations":["allocate funds","allocate resources","allocate time"],"example":"The government allocated more funds to education.","exampleZh":"政府撥出更多經費給教育。","synonyms":["assign","distribute"],"level":6,"theme":"商業與金錢","examples":[{"en":"The government allocated more funds to education.","zh":"政府撥出更多經費給教育。"},{"en":"We should allocate enough time to review before the exam.","zh":"我們應該撥出足夠的時間在考前複習。"},{"en":"The city allocated more resources to repairing old roads.","zh":"市府撥出更多資源來修繕老舊道路。"}]},{"word":"allow","pos":"v.","phonetic":"[əˈlaʊ]","meaning":"允許；准許","definition":"to give permission for something to happen or someone to do something","collocations":["allow someone to","not allowed","allow time for"],"example":"My parents don't allow me to stay out late.","exampleZh":"我父母不允許我太晚回家。","synonyms":["permit"],"level":2,"theme":"動作與行為","examples":[{"en":"My parents don't allow me to stay out late.","zh":"我父母不允許我太晚回家。"},{"en":"Visitors are not allowed to touch the paintings in the gallery.","zh":"訪客不得觸摸畫廊裡的畫作。"},{"en":"Please allow enough time for the glue to dry completely.","zh":"請預留足夠的時間讓膠水完全乾透。"}]},{"word":"ally","pos":"n. / v.","phonetic":"[ˈælaɪ]","meaning":"盟友；同盟","definition":"a country, group, or person that cooperates with another for a common purpose","collocations":["close ally","military ally","ally with"],"example":"The two nations have been allies for decades.","exampleZh":"這兩個國家已經是盟友數十年了。","synonyms":["partner"],"level":5,"theme":"政治與法律","examples":[{"en":"The two nations have been allies for decades.","zh":"這兩個國家已經是盟友數十年了。"},{"en":"During the war, the small nation allied with its powerful neighbor.","zh":"戰爭期間，這個小國與其強大的鄰國結盟。"},{"en":"A close ally will support you even in difficult times.","zh":"親密的盟友即使在困難時期也會支持你。"}]},{"word":"almond","pos":"n.","phonetic":"[ˈɑmənd]","meaning":"杏仁","definition":"an edible nut with a hard shell","collocations":["almond milk","roasted almonds","almond tree"],"example":"She added sliced almonds to the salad.","exampleZh":"她在沙拉裡加了杏仁片。","synonyms":[],"level":3,"theme":"食物與烹飪","examples":[{"en":"She added sliced almonds to the salad.","zh":"她在沙拉裡加了杏仁片。"},{"en":"She prefers almond milk to regular milk in her coffee.","zh":"她喝咖啡時偏好用杏仁奶而非一般牛奶。"},{"en":"A handful of roasted almonds makes a healthy afternoon snack.","zh":"一把烤杏仁是健康的下午點心。"}]},{"word":"almost","pos":"adv.","phonetic":"[ˈɔlˌmost]","meaning":"幾乎；差不多","definition":"very nearly but not completely","collocations":["almost never","almost done","almost every"],"example":"I almost missed the bus this morning.","exampleZh":"我今天早上差點錯過公車。","synonyms":["nearly"],"level":1,"theme":"時間與空間","examples":[{"en":"I almost missed the bus this morning.","zh":"我今天早上差點錯過公車。"},{"en":"We are almost done with the project, so please be patient.","zh":"我們的專案快完成了，所以請耐心一點。"},{"en":"He almost never forgets to bring his umbrella on rainy days.","zh":"他在雨天幾乎從不忘記帶傘。"}]},{"word":"alone","pos":"adj. / adv.","phonetic":"[əˈlon]","meaning":"單獨的；獨自地","definition":"without other people present","collocations":["live alone","leave someone alone","all alone"],"example":"She prefers to travel alone.","exampleZh":"她比較喜歡獨自旅行。","synonyms":["solitary"],"level":2,"theme":"性質與描述","examples":[{"en":"She prefers to travel alone.","zh":"她比較喜歡獨自旅行。"},{"en":"After his roommate moved out, he had to live alone.","zh":"室友搬走後，他只好一個人住。"},{"en":"Please leave me alone; I need some time to think.","zh":"請讓我一個人靜一靜，我需要一些時間思考。"}]},{"word":"along","pos":"prep. / adv.","phonetic":"[əˈlɔŋ]","meaning":"沿著；一起","definition":"moving in a line beside something","collocations":["along the way","come along","walk along"],"example":"We walked along the beach at sunset.","exampleZh":"我們在日落時沿著海灘散步。","synonyms":[],"level":1,"theme":"時間與空間","examples":[{"en":"We walked along the beach at sunset.","zh":"我們在日落時沿著海灘散步。"},{"en":"Would you like to come along with us to the concert?","zh":"你想和我們一起去聽演唱會嗎？"},{"en":"We stopped at several small towns along the way home.","zh":"回家的路上，我們在幾個小鎮停留。"}]},{"word":"aloud","pos":"adv.","phonetic":"[əˈlaʊd]","meaning":"出聲地；大聲地","definition":"in a voice that can be heard","collocations":["read aloud","think aloud","laugh aloud"],"example":"The teacher asked him to read the poem aloud.","exampleZh":"老師要他把這首詩大聲朗讀出來。","synonyms":["audibly"],"level":3,"theme":"溝通與語言","examples":[{"en":"The teacher asked him to read the poem aloud.","zh":"老師要他把這首詩大聲朗讀出來。"},{"en":"She likes to read her English lines aloud to practice.","zh":"她喜歡把英文台詞大聲讀出來練習。"},{"en":"He was thinking aloud while trying to solve the puzzle.","zh":"他自言自語地思考，試著解開這道謎題。"}]},{"word":"alphabet","pos":"n.","phonetic":"[ˈælfəˌbɛt]","meaning":"字母；字母系統","definition":"the set of letters used in a language","collocations":["learn the alphabet","English alphabet","alphabet song"],"example":"Children learn the alphabet before they start reading.","exampleZh":"孩子們在開始閱讀之前先學習字母。","synonyms":[],"level":2,"theme":"教育與學習","examples":[{"en":"Children learn the alphabet before they start reading.","zh":"孩子們在開始閱讀之前先學習字母。"},{"en":"The English alphabet has twenty-six letters in total.","zh":"英文字母總共有二十六個字母。"},{"en":"The kindergarten teacher sang the alphabet song with the children.","zh":"幼稚園老師和孩子們一起唱字母歌。"}]},{"word":"already","pos":"adv.","phonetic":"[ɔlˈrɛdi]","meaning":"已經","definition":"before now or before a particular time","collocations":["already done","have already","already gone"],"example":"By the time I arrived, the meeting had already started.","exampleZh":"等我到的時候,會議已經開始了。","synonyms":[],"level":1,"theme":"時間與空間","examples":[{"en":"By the time I arrived, the meeting had already started.","zh":"等我到的時候,會議已經開始了。"},{"en":"By the time we arrived, the train had already gone.","zh":"我們抵達時，火車已經開走了。"},{"en":"You don't need to remind me; I have already finished it.","zh":"你不用提醒我，我已經完成了。"}]},{"word":"also","pos":"adv.","phonetic":"[ˈɔlso]","meaning":"也；還","definition":"in addition; too","collocations":["not only...but also","also known as"],"example":"She speaks French and also Spanish.","exampleZh":"她會說法語,也會說西班牙語。","synonyms":["too","as well"],"level":1,"theme":"抽象概念","examples":[{"en":"She speaks French and also Spanish.","zh":"她會說法語,也會說西班牙語。"},{"en":"The city is famous for its food and also its friendly people.","zh":"這座城市以美食聞名，也以友善的人們著稱。"},{"en":"The mountain, also known as the Sleeping Giant, attracts many hikers.","zh":"這座山又名沉睡的巨人，吸引許多登山客。"}]},{"word":"alter","pos":"v.","phonetic":"[ˈɔltɚ]","meaning":"改變；修改","definition":"to change something, often slightly","collocations":["alter plans","alter a dress","alter the course"],"example":"The tailor altered the suit to fit him perfectly.","exampleZh":"裁縫師修改了西裝讓它完全合身。","synonyms":["change","modify"],"level":4,"theme":"動作與行為","examples":[{"en":"The tailor altered the suit to fit him perfectly.","zh":"裁縫師修改了西裝讓它完全合身。"},{"en":"We had to alter our plans because of the sudden storm.","zh":"由於突如其來的暴風雨，我們不得不改變計畫。"},{"en":"One small decision can completely alter the course of your life.","zh":"一個小小的決定可能徹底改變你人生的走向。"}]},{"word":"alternative","pos":"n. / adj.","phonetic":"[ɔlˈtɝnətɪv]","meaning":"替代方案；另類的","definition":"a different option that can be chosen","collocations":["alternative energy","viable alternative","alternative route"],"example":"Solar power is a popular alternative to fossil fuels.","exampleZh":"太陽能是化石燃料的熱門替代方案。","synonyms":["substitute","option"],"level":5,"theme":"科學與數學","examples":[{"en":"Solar power is a popular alternative to fossil fuels.","zh":"太陽能是化石燃料的熱門替代方案。"},{"en":"We took an alternative route to avoid the traffic jam.","zh":"我們走了另一條路以避開塞車。"},{"en":"Wind power is a clean alternative energy source.","zh":"風力是一種乾淨的替代能源。"}]},{"word":"although","pos":"conj.","phonetic":"[ɔlˈðo]","meaning":"雖然；儘管","definition":"despite the fact that","collocations":["although it rained","although he tried"],"example":"Although it was raining, they still went hiking.","exampleZh":"儘管下著雨,他們還是去健行了。","synonyms":["though"],"level":2,"theme":"溝通與語言","examples":[{"en":"Although it was raining, they still went hiking.","zh":"儘管下著雨,他們還是去健行了。"},{"en":"Although he tried his best, he still missed the last question.","zh":"儘管他盡了全力，還是漏掉了最後一題。"},{"en":"Although the movie was long, none of us felt bored.","zh":"雖然這部電影很長，但我們都不覺得無聊。"}]},{"word":"altitude","pos":"n.","phonetic":"[ˈæltəˌtjud]","meaning":"海拔；高度","definition":"the height of something above sea level","collocations":["high altitude","gain altitude","altitude sickness"],"example":"The plane climbed to an altitude of 30,000 feet.","exampleZh":"飛機爬升到三萬英尺的高度。","synonyms":["height","elevation"],"level":5,"theme":"自然與環境","examples":[{"en":"The plane climbed to an altitude of 30,000 feet.","zh":"飛機爬升到三萬英尺的高度。"},{"en":"Some climbers suffer from altitude sickness on the high mountain.","zh":"有些登山者在高山上會出現高山症。"},{"en":"As the plane gained altitude, the houses below grew tiny.","zh":"隨著飛機爬升，下方的房屋變得渺小。"}]},{"word":"altogether","pos":"adv.","phonetic":"[ˌɔltəˈgɛðɚ]","meaning":"完全地；總共","definition":"completely; considering everything","collocations":["altogether different","stop altogether","altogether now"],"example":"The plan was altogether too risky.","exampleZh":"這個計畫完全太過冒險了。","synonyms":["entirely","completely"],"level":5,"theme":"抽象概念","examples":[{"en":"The plan was altogether too risky.","zh":"這個計畫完全太過冒險了。"},{"en":"The trip cost us five thousand dollars altogether.","zh":"這趟旅行總共花了我們五千元。"},{"en":"This year's plan is altogether different from last year's.","zh":"今年的計畫和去年的完全不同。"}]},{"word":"aluminum","pos":"n.","phonetic":"[əˈlumɪnəm]","meaning":"鋁","definition":"a lightweight silver-white metal","collocations":["aluminum foil","aluminum can","aluminum alloy"],"example":"She wrapped the sandwich in aluminum foil.","exampleZh":"她用鋁箔紙包三明治。","synonyms":[],"level":4,"theme":"科學與數學","examples":[{"en":"She wrapped the sandwich in aluminum foil.","zh":"她用鋁箔紙包三明治。"},{"en":"Please remember to recycle your empty aluminum cans.","zh":"請記得回收你的空鋁罐。"},{"en":"This bike frame is made of a light aluminum alloy.","zh":"這個自行車車架是用輕巧的鋁合金製成的。"}]},{"word":"always","pos":"adv.","phonetic":"[ˈɔlwez]","meaning":"總是；一直","definition":"at all times; on every occasion","collocations":["always late","will always remember"],"example":"He always arrives early for meetings.","exampleZh":"他開會總是提早到。","synonyms":["forever"],"level":1,"theme":"時間與空間","examples":[{"en":"He always arrives early for meetings.","zh":"他開會總是提早到。"},{"en":"I will always remember the kindness of my first teacher.","zh":"我會永遠記得我第一位老師的善良。"},{"en":"My friend is always late, no matter how early we meet.","zh":"我的朋友總是遲到，不管我們約多早。"}]},{"word":"amateur","pos":"n. / adj.","phonetic":"[ˈæməˌtʃʊr]","meaning":"業餘愛好者；業餘的","definition":"a person who does something for pleasure rather than as a job","collocations":["amateur photographer","amateur boxing"],"example":"He is a talented amateur photographer.","exampleZh":"他是一位有天分的業餘攝影師。","synonyms":["nonprofessional"],"level":5,"theme":"工作與職業","examples":[{"en":"He is a talented amateur photographer.","zh":"他是一位有天分的業餘攝影師。"},{"en":"As an amateur baker, she still makes wonderful birthday cakes.","zh":"身為一個業餘烘焙者，她仍能做出很棒的生日蛋糕。"},{"en":"The amateur football team practices every Sunday morning.","zh":"這支業餘足球隊每週日早上練習。"}]},{"word":"amaze","pos":"v.","phonetic":"[əˈmez]","meaning":"使驚訝","definition":"to surprise someone greatly","collocations":["amaze the audience","be amazed at"],"example":"The magician's tricks amazed the audience.","exampleZh":"魔術師的把戲讓觀眾感到驚訝。","synonyms":["astonish","surprise"],"level":3,"theme":"情緒與感受","examples":[{"en":"The magician's tricks amazed the audience.","zh":"魔術師的把戲讓觀眾感到驚訝。"},{"en":"The young dancer's talent amazed everyone in the theater.","zh":"這位年輕舞者的天賦讓劇場裡的每個人都驚嘆不已。"},{"en":"We were amazed at how quickly the puppy learned new tricks.","zh":"我們很驚訝這隻小狗學新把戲的速度有多快。"}]},{"word":"ambassador","pos":"n.","phonetic":"[æmˈbæsədɚ]","meaning":"大使","definition":"an official representative of a country abroad","collocations":["ambassador to","goodwill ambassador"],"example":"She was appointed as the ambassador to Japan.","exampleZh":"她被任命為駐日本大使。","synonyms":["envoy"],"level":5,"theme":"政治與法律","examples":[{"en":"She was appointed as the ambassador to Japan.","zh":"她被任命為駐日本大使。"},{"en":"The famous singer became a goodwill ambassador for children's rights.","zh":"這位知名歌手成為兒童權益的親善大使。"},{"en":"The ambassador gave a speech to promote peace between the nations.","zh":"大使發表演說以促進兩國之間的和平。"}]},{"word":"ambiguous","pos":"adj.","phonetic":"[æmˈbɪgjuəs]","meaning":"模稜兩可的；含糊的","definition":"having more than one possible meaning","collocations":["ambiguous statement","ambiguous answer"],"example":"His answer was too ambiguous to understand clearly.","exampleZh":"他的回答太模稜兩可,難以清楚理解。","synonyms":["vague","unclear"],"level":6,"theme":"溝通與語言","examples":[{"en":"His answer was too ambiguous to understand clearly.","zh":"他的回答太模稜兩可,難以清楚理解。"},{"en":"The instructions were so ambiguous that nobody knew what to do.","zh":"這些指示太含糊，沒有人知道該怎麼做。"},{"en":"She gave an ambiguous answer to avoid making a promise.","zh":"她給了個模稜兩可的答案，以避免做出承諾。"}]},{"word":"ambition","pos":"n.","phonetic":"[æmˈbɪʃən]","meaning":"野心；抱負","definition":"a strong desire to achieve something","collocations":["have ambition","career ambition","fulfill an ambition"],"example":"His ambition is to start his own company.","exampleZh":"他的抱負是創立自己的公司。","synonyms":["aspiration"],"level":4,"theme":"抽象概念","examples":[{"en":"His ambition is to start his own company.","zh":"他的抱負是創立自己的公司。"},{"en":"Her lifelong ambition is to become a famous scientist.","zh":"她一生的抱負是成為一位知名的科學家。"},{"en":"He finally fulfilled his ambition of opening a bookstore.","zh":"他終於實現了開一家書店的抱負。"}]},{"word":"ambulance","pos":"n.","phonetic":"[ˈæmbjələns]","meaning":"救護車","definition":"a vehicle for transporting sick or injured people","collocations":["call an ambulance","ambulance driver"],"example":"They called an ambulance after the accident.","exampleZh":"意外發生後他們叫了救護車。","synonyms":[],"level":2,"theme":"身體與健康","examples":[{"en":"They called an ambulance after the accident.","zh":"意外發生後他們叫了救護車。"},{"en":"When my grandfather fainted, we quickly called an ambulance for help.","zh":"當我祖父昏倒時，我們迅速叫了救護車求助。"},{"en":"The ambulance driver rushed the injured woman to the nearest hospital.","zh":"救護車司機把受傷的婦人緊急送到最近的醫院。"}]},{"word":"amend","pos":"v.","phonetic":"[əˈmɛnd]","meaning":"修改；修正","definition":"to change a document or law slightly","collocations":["amend the law","amend a proposal"],"example":"Congress voted to amend the constitution.","exampleZh":"國會投票修改憲法。","synonyms":["revise","modify"],"level":6,"theme":"政治與法律","examples":[{"en":"Congress voted to amend the constitution.","zh":"國會投票修改憲法。"},{"en":"The committee decided to amend the proposal after hearing new suggestions.","zh":"委員會聽取新建議後，決定修改這份提案。"},{"en":"Lawmakers promised to amend the outdated law next year.","zh":"立法者承諾明年修正這條過時的法律。"}]},{"word":"amid","pos":"prep.","phonetic":"[əˈmɪd]","meaning":"在...之中","definition":"in the middle of; surrounded by","collocations":["amid the chaos","amid criticism"],"example":"The president spoke amid growing tension.","exampleZh":"總統在日益緊張的局勢中發表談話。","synonyms":["among"],"level":5,"theme":"時間與空間","examples":[{"en":"The president spoke amid growing tension.","zh":"總統在日益緊張的局勢中發表談話。"},{"en":"She stayed calm amid the chaos of the crowded train station.","zh":"在擁擠火車站的一片混亂中，她仍保持冷靜。"},{"en":"The mayor resigned amid growing criticism from local residents.","zh":"在當地居民日益增加的批評聲中，市長辭職了。"}]},{"word":"among","pos":"prep.","phonetic":"[əˈmʌŋ]","meaning":"在...之中","definition":"surrounded by; in a group of","collocations":["among friends","among the crowd"],"example":"She felt comfortable among her close friends.","exampleZh":"她在親近的朋友中感到自在。","synonyms":["amid"],"level":2,"theme":"時間與空間","examples":[{"en":"She felt comfortable among her close friends.","zh":"她在親近的朋友中感到自在。"},{"en":"He quickly spotted his sister among the crowd at the airport.","zh":"他很快就在機場的人群中認出了他的妹妹。"},{"en":"The prize money was shared equally among the three winners.","zh":"獎金由三位得獎者平分。"}]},{"word":"amount","pos":"n. / v.","phonetic":"[əˈmaʊnt]","meaning":"數量；總計","definition":"a quantity of something","collocations":["a large amount","amount to","huge amount"],"example":"He spent a large amount of money on the trip.","exampleZh":"他在這趟旅行上花了大筆金錢。","synonyms":["quantity"],"level":2,"theme":"商業與金錢","examples":[{"en":"He spent a large amount of money on the trip.","zh":"他在這趟旅行上花了大筆金錢。"},{"en":"A huge amount of rain fell during the typhoon last night.","zh":"昨晚颱風期間下了大量的雨。"},{"en":"The repair costs amounted to more than ten thousand dollars.","zh":"修理費用總計超過一萬元。"}]},{"word":"ample","pos":"adj.","phonetic":"[ˈæmpl]","meaning":"充裕的；豐富的","definition":"more than enough; plentiful","collocations":["ample time","ample evidence","ample space"],"example":"We had ample time to finish the project.","exampleZh":"我們有充裕的時間完成這個專案。","synonyms":["plenty","abundant"],"level":5,"theme":"性質與描述","examples":[{"en":"We had ample time to finish the project.","zh":"我們有充裕的時間完成這個專案。"},{"en":"The new classroom offers ample space for group activities.","zh":"新教室提供充裕的空間進行小組活動。"},{"en":"There is ample evidence that regular exercise improves our health.","zh":"有充分的證據顯示規律運動能改善我們的健康。"}]},{"word":"amuse","pos":"v.","phonetic":"[əˈmjuz]","meaning":"使發笑；娛樂","definition":"to make someone laugh or smile","collocations":["amuse the children","amuse oneself"],"example":"The clown amused the children with funny tricks.","exampleZh":"小丑用滑稽的把戲逗孩子們開心。","synonyms":["entertain"],"level":4,"theme":"情緒與感受","examples":[{"en":"The clown amused the children with funny tricks.","zh":"小丑用滑稽的把戲逗孩子們開心。"},{"en":"The street performer amused everyone with his clever juggling tricks.","zh":"街頭藝人用他巧妙的雜耍逗樂了大家。"},{"en":"The children amused themselves by building sandcastles on the beach.","zh":"孩子們在海灘上堆沙堡自娛。"}]},{"word":"amusement","pos":"n.","phonetic":"[əˈmjuzmənt]","meaning":"娛樂；樂趣","definition":"enjoyment or entertainment","collocations":["amusement park","to my amusement"],"example":"They spent the day at the amusement park.","exampleZh":"他們在遊樂園度過了一天。","synonyms":["entertainment","fun"],"level":3,"theme":"運動與休閒","examples":[{"en":"They spent the day at the amusement park.","zh":"他們在遊樂園度過了一天。"},{"en":"To my amusement, the puppy chased its own tail for several minutes.","zh":"讓我覺得好笑的是，那隻小狗追著自己的尾巴好幾分鐘。"},{"en":"The city built a new amusement park near the river last year.","zh":"這座城市去年在河邊建了一座新的遊樂園。"}]},{"word":"analysis","pos":"n.","phonetic":"[əˈnæləsɪs]","meaning":"分析","definition":"a detailed examination of something","collocations":["data analysis","conduct an analysis"],"example":"The scientist published her analysis of the data.","exampleZh":"這位科學家發表了她對數據的分析。","synonyms":["examination"],"level":5,"theme":"科學與數學","examples":[{"en":"The scientist published her analysis of the data.","zh":"這位科學家發表了她對數據的分析。"},{"en":"The students conducted a careful analysis of the survey results.","zh":"學生們對問卷結果進行了仔細的分析。"},{"en":"Her analysis of the poem impressed the whole class.","zh":"她對這首詩的分析讓全班印象深刻。"}]},{"word":"analyze","pos":"v.","phonetic":"[ˈænəˌlaɪz]","meaning":"分析","definition":"to examine something in detail","collocations":["analyze data","analyze a problem"],"example":"Researchers analyzed the results carefully.","exampleZh":"研究人員仔細分析了結果。","synonyms":["examine","study"],"level":5,"theme":"科學與數學","examples":[{"en":"Researchers analyzed the results carefully.","zh":"研究人員仔細分析了結果。"},{"en":"Scientists analyze water samples to check for pollution.","zh":"科學家分析水樣本以檢測是否有污染。"},{"en":"We need to analyze the problem carefully before choosing a solution.","zh":"在選擇解決方案之前，我們需要仔細分析這個問題。"}]},{"word":"ancestor","pos":"n.","phonetic":"[ˈænˌsɛstɚ]","meaning":"祖先","definition":"a person from whom one is descended","collocations":["common ancestor","distant ancestor"],"example":"Her ancestors came from Ireland.","exampleZh":"她的祖先來自愛爾蘭。","synonyms":["forefather"],"level":4,"theme":"人物與家庭","examples":[{"en":"Her ancestors came from Ireland.","zh":"她的祖先來自愛爾蘭。"},{"en":"According to the legend, our ancestors once farmed this fertile valley.","zh":"根據傳說，我們的祖先曾在這個肥沃的山谷耕作。"},{"en":"Humans and apes are believed to share a common ancestor.","zh":"人類和猿類被認為擁有共同的祖先。"}]},{"word":"anchor","pos":"n. / v.","phonetic":"[ˈæŋkɚ]","meaning":"錨；主播；下錨","definition":"a heavy object used to hold a ship in place; a news presenter","collocations":["drop anchor","news anchor"],"example":"The ship dropped anchor near the shore.","exampleZh":"船在岸邊下錨。","synonyms":[],"level":4,"theme":"交通與旅行","examples":[{"en":"The ship dropped anchor near the shore.","zh":"船在岸邊下錨。"},{"en":"The sailors dropped anchor before the storm reached the quiet bay.","zh":"在暴風雨抵達寧靜的海灣之前，水手們拋下了錨。"},{"en":"The news anchor calmly reported the results of the election.","zh":"新聞主播冷靜地報導了選舉的結果。"}]},{"word":"ancient","pos":"adj.","phonetic":"[ˈenʃənt]","meaning":"古代的；古老的","definition":"very old; belonging to the distant past","collocations":["ancient civilization","ancient history"],"example":"They visited ancient ruins in Greece.","exampleZh":"他們參觀了希臘的古代遺跡。","synonyms":["old","antique"],"level":3,"theme":"社會與文化","examples":[{"en":"They visited ancient ruins in Greece.","zh":"他們參觀了希臘的古代遺跡。"},{"en":"Our teacher explained how an ancient civilization built these grand temples.","zh":"老師解釋了一個古代文明是如何建造這些宏偉的神廟的。"},{"en":"The museum displays many tools used in ancient times.","zh":"這座博物館展示許多古代使用的工具。"}]},{"word":"angel","pos":"n.","phonetic":"[ˈendʒəl]","meaning":"天使","definition":"a spiritual being often depicted with wings","collocations":["guardian angel","like an angel"],"example":"She sang like an angel at the concert.","exampleZh":"她在演唱會上唱得像天使一樣動聽。","synonyms":[],"level":2,"theme":"社會與文化","examples":[{"en":"She sang like an angel at the concert.","zh":"她在演唱會上唱得像天使一樣動聽。"},{"en":"My grandmother believes a guardian angel watches over our whole family.","zh":"我祖母相信有一位守護天使在看顧著我們全家。"},{"en":"In the painting, an angel with white wings floated above the clouds.","zh":"在那幅畫中，一位有著白色翅膀的天使漂浮在雲端之上。"}]},{"word":"anger","pos":"n. / v.","phonetic":"[ˈæŋgɚ]","meaning":"憤怒；使發怒","definition":"a strong feeling of annoyance or hostility","collocations":["fit of anger","anger management"],"example":"He tried to control his anger during the argument.","exampleZh":"他試著在爭吵中控制自己的怒氣。","synonyms":["rage","fury"],"level":2,"theme":"情緒與感受","examples":[{"en":"He tried to control his anger during the argument.","zh":"他試著在爭吵中控制自己的怒氣。"},{"en":"In a fit of anger, he slammed the door and left the room.","zh":"一怒之下，他甩上門，離開了房間。"},{"en":"Learning anger management helped her stay calm during heated arguments.","zh":"學習情緒管理幫助她在激烈的爭吵中保持冷靜。"}]},{"word":"angle","pos":"n.","phonetic":"[ˈæŋgl]","meaning":"角度","definition":"the space between two lines or surfaces that meet","collocations":["right angle","at an angle","from a different angle"],"example":"Measure the angle between the two walls.","exampleZh":"測量這兩面牆之間的角度。","synonyms":[],"level":3,"theme":"科學與數學","examples":[{"en":"Measure the angle between the two walls.","zh":"測量這兩面牆之間的角度。"},{"en":"Try looking at this difficult problem from a different angle.","zh":"試著從不同的角度看待這個困難的問題。"},{"en":"The two walls of the room meet at a perfect right angle.","zh":"房間的兩面牆以完美的直角相接。"}]},{"word":"angry","pos":"adj.","phonetic":"[ˈæŋgri]","meaning":"生氣的","definition":"feeling or showing anger","collocations":["get angry","angry at someone"],"example":"She got angry when he arrived late again.","exampleZh":"他又遲到讓她生氣了。","synonyms":["mad","furious"],"level":1,"theme":"情緒與感受","examples":[{"en":"She got angry when he arrived late again.","zh":"他又遲到讓她生氣了。"},{"en":"Dad got angry when he saw the broken window in the kitchen.","zh":"爸爸看到廚房那扇破掉的窗戶時生氣了。"},{"en":"She was angry at her brother for reading her private diary.","zh":"她因為哥哥偷看她私人的日記而生氣。"}]},{"word":"animal","pos":"n.","phonetic":"[ˈænəml]","meaning":"動物","definition":"a living creature other than a plant","collocations":["wild animal","animal shelter"],"example":"The zoo has many kinds of animals.","exampleZh":"動物園裡有很多種動物。","synonyms":["creature"],"level":1,"theme":"動物與植物","examples":[{"en":"The zoo has many kinds of animals.","zh":"動物園裡有很多種動物。"},{"en":"Volunteers care for injured pets at the local animal shelter.","zh":"志工在當地的動物收容所照顧受傷的寵物。"},{"en":"You should never feed wild animals inside the national park.","zh":"在國家公園裡絕對不該餵食野生動物。"}]},{"word":"ankle","pos":"n.","phonetic":"[ˈæŋkl]","meaning":"腳踝","definition":"the joint connecting the foot and leg","collocations":["sprain an ankle","twist one's ankle"],"example":"She sprained her ankle while jogging.","exampleZh":"她慢跑時扭傷了腳踝。","synonyms":[],"level":2,"theme":"身體與健康","examples":[{"en":"She sprained her ankle while jogging.","zh":"她慢跑時扭傷了腳踝。"},{"en":"He twisted his ankle badly during the basketball game yesterday.","zh":"他昨天在籃球比賽中嚴重扭傷了腳踝。"},{"en":"The doctor gently wrapped a bandage around her swollen ankle.","zh":"醫生輕輕地在她腫脹的腳踝上纏了繃帶。"}]},{"word":"anniversary","pos":"n.","phonetic":"[ˌænəˈvɝsəri]","meaning":"週年紀念日","definition":"a date marking a special event in a previous year","collocations":["wedding anniversary","celebrate an anniversary"],"example":"They celebrated their tenth wedding anniversary.","exampleZh":"他們慶祝結婚十週年紀念。","synonyms":[],"level":3,"theme":"人物與家庭","examples":[{"en":"They celebrated their tenth wedding anniversary.","zh":"他們慶祝結婚十週年紀念。"},{"en":"The school celebrated its fiftieth anniversary with a grand concert.","zh":"學校以一場盛大的音樂會慶祝五十週年紀念。"},{"en":"My parents went out for a fancy dinner on their wedding anniversary.","zh":"我父母在結婚週年紀念日出去吃了一頓豪華的晚餐。"}]},{"word":"announce","pos":"v.","phonetic":"[əˈnaʊns]","meaning":"宣布","definition":"to make something known publicly","collocations":["announce results","announce a decision"],"example":"The teacher announced the exam results.","exampleZh":"老師宣布了考試結果。","synonyms":["declare","proclaim"],"level":3,"theme":"溝通與語言","examples":[{"en":"The teacher announced the exam results.","zh":"老師宣布了考試結果。"},{"en":"The principal announced the winners of the writing contest this morning.","zh":"校長今天早上宣布了寫作比賽的得獎者。"},{"en":"The airline announced its decision to add several new flights.","zh":"航空公司宣布了增加幾個新航班的決定。"}]},{"word":"annoy","pos":"v.","phonetic":"[əˈnɔɪ]","meaning":"使惱怒","definition":"to make someone slightly angry","collocations":["annoy someone","get annoyed"],"example":"His constant complaining annoys everyone in the office.","exampleZh":"他不停的抱怨讓辦公室裡的每個人都感到厭煩。","synonyms":["irritate","bother"],"level":3,"theme":"情緒與感受","examples":[{"en":"His constant complaining annoys everyone in the office.","zh":"他不停的抱怨讓辦公室裡的每個人都感到厭煩。"},{"en":"The loud music from next door really annoys my neighbors.","zh":"隔壁傳來的吵鬧音樂真的讓我的鄰居很惱火。"},{"en":"She got annoyed when the website kept crashing during the test.","zh":"考試時網站一直當機，讓她感到惱怒。"}]},{"word":"annual","pos":"adj.","phonetic":"[ˈænjuəl]","meaning":"每年的；一年一度的","definition":"happening once every year","collocations":["annual report","annual meeting"],"example":"The company holds an annual meeting every March.","exampleZh":"這家公司每年三月舉行年度會議。","synonyms":["yearly"],"level":4,"theme":"時間與空間","examples":[{"en":"The company holds an annual meeting every March.","zh":"這家公司每年三月舉行年度會議。"},{"en":"Our family attends the annual flower festival every spring.","zh":"我們全家每年春天都會參加一年一度的花卉節。"},{"en":"The club published its annual report on the school website.","zh":"社團在學校網站上發布了年度報告。"}]},{"word":"another","pos":"adj. / pron.","phonetic":"[əˈnʌðɚ]","meaning":"另一個","definition":"one more; a different one","collocations":["another one","one after another"],"example":"Would you like another cup of coffee?","exampleZh":"你想再來一杯咖啡嗎?","synonyms":[],"level":1,"theme":"抽象概念","examples":[{"en":"Would you like another cup of coffee?","zh":"你想再來一杯咖啡嗎?"},{"en":"The cars passed slowly through the tunnel one after another.","zh":"車輛一輛接一輛地緩緩通過隧道。"},{"en":"If this pen doesn't work, please try another one.","zh":"如果這支筆不能用，請試試另一支。"}]},{"word":"answer","pos":"n. / v.","phonetic":"[ˈænsɚ]","meaning":"答案；回答","definition":"a reply to a question","collocations":["answer a question","correct answer","answer the phone"],"example":"She answered every question correctly.","exampleZh":"她把每個問題都答對了。","synonyms":["reply","respond"],"level":1,"theme":"教育與學習","examples":[{"en":"She answered every question correctly.","zh":"她把每個問題都答對了。"},{"en":"Could you answer the phone while I finish cooking dinner?","zh":"我做完晚飯之前，你能幫忙接電話嗎？"},{"en":"He checked the correct answer at the back of the book.","zh":"他在書本後面對了正確答案。"}]},{"word":"ant","pos":"n.","phonetic":"[ænt]","meaning":"螞蟻","definition":"a small insect that lives in organized colonies","collocations":["ant colony","ant hill"],"example":"A line of ants marched across the sidewalk.","exampleZh":"一排螞蟻在人行道上前進。","synonyms":[],"level":1,"theme":"動物與植物","examples":[{"en":"A line of ants marched across the sidewalk.","zh":"一排螞蟻在人行道上前進。"},{"en":"A busy ant colony lives beneath the old wooden fence.","zh":"一個忙碌的螞蟻群棲息在那道舊木籬笆底下。"},{"en":"The children watched an ant carry a crumb larger than itself.","zh":"孩子們看著一隻螞蟻搬運一塊比自己還大的碎屑。"}]},{"word":"anthem","pos":"n.","phonetic":"[ˈænθəm]","meaning":"頌歌；國歌","definition":"a song of praise or loyalty, especially for a country","collocations":["national anthem","sing the anthem"],"example":"Everyone stood to sing the national anthem.","exampleZh":"大家都起立唱國歌。","synonyms":[],"level":5,"theme":"社會與文化","examples":[{"en":"Everyone stood to sing the national anthem.","zh":"大家都起立唱國歌。"},{"en":"The players sang the national anthem before the match began.","zh":"球員們在比賽開始前唱國歌。"},{"en":"The crowd stood quietly as the anthem echoed through the stadium.","zh":"當國歌響徹體育場時，群眾靜靜地站著。"}]},{"word":"anticipate","pos":"v.","phonetic":"[ænˈtɪsəˌpet]","meaning":"預期；期待","definition":"to expect something before it happens","collocations":["anticipate a problem","eagerly anticipate"],"example":"Analysts anticipate a rise in prices next year.","exampleZh":"分析師預期明年物價會上漲。","synonyms":["expect","foresee"],"level":6,"theme":"抽象概念","examples":[{"en":"Analysts anticipate a rise in prices next year.","zh":"分析師預期明年物價會上漲。"},{"en":"A good teacher can anticipate the questions students are likely to ask.","zh":"一位好老師能預期學生可能會問的問題。"},{"en":"We eagerly anticipate the summer vacation every single year.","zh":"我們每一年都熱切地期待暑假。"}]},{"word":"antique","pos":"n. / adj.","phonetic":"[ænˈtik]","meaning":"古董；古老的","definition":"an object valued for its age","collocations":["antique shop","antique furniture"],"example":"She collects antique clocks from the 19th century.","exampleZh":"她收藏十九世紀的古董時鐘。","synonyms":[],"level":5,"theme":"藝術與音樂","examples":[{"en":"She collects antique clocks from the 19th century.","zh":"她收藏十九世紀的古董時鐘。"},{"en":"Her living room is filled with beautiful antique furniture.","zh":"她的客廳裡擺滿了漂亮的古董家具。"},{"en":"We found an old hand-drawn map in a small antique shop.","zh":"我們在一家小古董店裡找到了一張手繪的舊地圖。"}]},{"word":"anxiety","pos":"n.","phonetic":"[æŋˈzaɪəti]","meaning":"焦慮；不安","definition":"a feeling of worry or nervousness","collocations":["cause anxiety","anxiety disorder"],"example":"She felt a wave of anxiety before the interview.","exampleZh":"面試前她感到一陣焦慮。","synonyms":["worry","nervousness"],"level":5,"theme":"情緒與感受","examples":[{"en":"She felt a wave of anxiety before the interview.","zh":"面試前她感到一陣焦慮。"},{"en":"Waiting for the test results caused her a great deal of anxiety.","zh":"等待考試結果讓她非常焦慮。"},{"en":"Slow, deep breathing can help reduce anxiety before a speech.","zh":"緩慢的深呼吸有助於在演講前減輕焦慮。"}]},{"word":"anxious","pos":"adj.","phonetic":"[ˈæŋkʃəs]","meaning":"焦慮的；渴望的","definition":"worried or nervous about something","collocations":["anxious about","feel anxious"],"example":"He felt anxious about the upcoming exam.","exampleZh":"他對即將到來的考試感到焦慮。","synonyms":["nervous","worried"],"level":4,"theme":"情緒與感受","examples":[{"en":"He felt anxious about the upcoming exam.","zh":"他對即將到來的考試感到焦慮。"},{"en":"Many students feel anxious about speaking in front of the whole class.","zh":"許多學生對在全班面前說話感到焦慮。"},{"en":"She was anxious to hear whether she had passed the entrance exam.","zh":"她急切地想知道自己是否通過了入學考試。"}]},{"word":"any","pos":"adj. / pron. / adv.","phonetic":"[ˈɛni]","meaning":"任何的","definition":"one, some, or all of a group, used in questions or negatives","collocations":["any time","not any","any longer"],"example":"Do you have any questions?","exampleZh":"你有任何問題嗎?","synonyms":[],"level":1,"theme":"抽象概念","examples":[{"en":"Do you have any questions?","zh":"你有任何問題嗎?"},{"en":"You can call me at any time if you need some help.","zh":"如果你需要幫忙，隨時都可以打電話給我。"},{"en":"We don't have any milk left in the refrigerator.","zh":"冰箱裡一點牛奶也沒剩了。"}]},{"word":"anybody","pos":"pron.","phonetic":"[ˈɛniˌbɑdi]","meaning":"任何人","definition":"any person","collocations":["anybody home","hardly anybody"],"example":"Is anybody home?","exampleZh":"有人在家嗎?","synonyms":["anyone"],"level":1,"theme":"人物與家庭","examples":[{"en":"Is anybody home?","zh":"有人在家嗎?"},{"en":"Hardly anybody showed up for the early morning lecture.","zh":"幾乎沒有人來參加清晨的講座。"},{"en":"Can anybody explain how this old machine actually works?","zh":"有沒有人能解釋這台舊機器實際上是怎麼運作的？"}]},{"word":"anyhow","pos":"adv.","phonetic":"[ˈɛniˌhaʊ]","meaning":"無論如何；不管怎樣","definition":"in any case; regardless","collocations":["anyhow, let's go","do it anyhow"],"example":"It was raining, but we went hiking anyhow.","exampleZh":"儘管下雨,我們還是去健行了。","synonyms":["anyway","regardless"],"level":3,"theme":"抽象概念","examples":[{"en":"It was raining, but we went hiking anyhow.","zh":"儘管下雨,我們還是去健行了。"},{"en":"The road was flooded, but we drove home anyhow.","zh":"路淹水了，但我們還是照樣開車回家。"},{"en":"Anyhow, let's focus on finishing the report first.","zh":"無論如何，我們先專心把報告完成吧。"}]},{"word":"anymore","pos":"adv.","phonetic":"[ˌɛniˈmɔr]","meaning":"（不）再；再也（不）","definition":"any longer, used mainly in negative sentences","collocations":["not anymore","don't live here anymore"],"example":"She doesn't work here anymore.","exampleZh":"她不再在這裡工作了。","synonyms":[],"level":2,"theme":"時間與空間","examples":[{"en":"She doesn't work here anymore.","zh":"她不再在這裡工作了。"},{"en":"My old friend doesn't live in this neighborhood anymore.","zh":"我的老朋友已經不再住在這個社區了。"},{"en":"I couldn't stand the noise anymore, so I moved out.","zh":"我再也受不了那噪音，所以搬走了。"}]},{"word":"anyone","pos":"pron.","phonetic":"[ˈɛniˌwʌn]","meaning":"任何人","definition":"any person","collocations":["anyone else","if anyone"],"example":"Anyone can join the club.","exampleZh":"任何人都可以加入這個社團。","synonyms":["anybody"],"level":1,"theme":"人物與家庭","examples":[{"en":"Anyone can join the club.","zh":"任何人都可以加入這個社團。"},{"en":"If anyone has questions about the trip, please raise your hand.","zh":"如果有人對這趟旅行有問題，請舉手。"},{"en":"Does anyone else want to join us for lunch today?","zh":"今天還有其他人想跟我們一起吃午餐嗎？"}]},{"word":"anything","pos":"pron.","phonetic":"[ˈɛniˌθɪŋ]","meaning":"任何事物","definition":"any thing at all","collocations":["anything else","if anything"],"example":"I can't see anything in this fog.","exampleZh":"在這場霧中我什麼也看不見。","synonyms":[],"level":1,"theme":"抽象概念","examples":[{"en":"I can't see anything in this fog.","zh":"在這場霧中我什麼也看不見。"},{"en":"Is there anything else you would like to add to the list?","zh":"你還有什麼想加到清單上的嗎？"},{"en":"He was so hungry that he would eat almost anything.","zh":"他餓到幾乎什麼都吃得下。"}]},{"word":"anyway","pos":"adv.","phonetic":"[ˈɛniˌwe]","meaning":"無論如何；總之","definition":"regardless; in any case","collocations":["anyway","thanks anyway"],"example":"I was tired, but I went to the party anyway.","exampleZh":"我雖然很累,但還是去了派對。","synonyms":["anyhow"],"level":2,"theme":"抽象概念","examples":[{"en":"I was tired, but I went to the party anyway.","zh":"我雖然很累,但還是去了派對。"},{"en":"The store was closed, but thanks anyway for the suggestion.","zh":"那家店關門了，不過還是謝謝你的建議。"},{"en":"The math problem looked hard, but she decided to try anyway.","zh":"那道數學題看起來很難，但她還是決定試試看。"}]},{"word":"anywhere","pos":"adv.","phonetic":"[ˈɛniˌhwɛr]","meaning":"任何地方","definition":"in, at, or to any place","collocations":["anywhere else","go anywhere"],"example":"You can sit anywhere you like.","exampleZh":"你可以坐在任何你喜歡的地方。","synonyms":[],"level":1,"theme":"時間與空間","examples":[{"en":"You can sit anywhere you like.","zh":"你可以坐在任何你喜歡的地方。"},{"en":"I searched everywhere but couldn't find my keys anywhere at home.","zh":"我到處找，卻在家裡任何地方都找不到我的鑰匙。"},{"en":"With a bicycle, you can go almost anywhere in this town.","zh":"有了腳踏車，你幾乎可以去這個鎮上任何地方。"}]},{"word":"apart","pos":"adv.","phonetic":"[əˈpɑrt]","meaning":"分開地；相隔","definition":"separated by distance or time","collocations":["apart from","come apart","live apart"],"example":"The two towns are ten miles apart.","exampleZh":"這兩個城鎮相隔十英里。","synonyms":["separately"],"level":3,"theme":"時間與空間","examples":[{"en":"The two towns are ten miles apart.","zh":"這兩個城鎮相隔十英里。"},{"en":"Apart from a slight headache, I feel perfectly fine today.","zh":"除了有點頭痛之外，我今天覺得完全沒問題。"},{"en":"The cheap plastic toy came apart after only one day.","zh":"那個廉價的塑膠玩具才玩了一天就散開了。"}]},{"word":"apartment","pos":"n.","phonetic":"[əˈpɑrtmənt]","meaning":"公寓","definition":"a set of rooms for living in, usually on one floor of a building","collocations":["rent an apartment","apartment building"],"example":"They moved into a small apartment downtown.","exampleZh":"他們搬進市中心的一間小公寓。","synonyms":["flat"],"level":2,"theme":"居家與生活","examples":[{"en":"They moved into a small apartment downtown.","zh":"他們搬進市中心的一間小公寓。"},{"en":"They decided to rent an apartment closer to the school.","zh":"他們決定租一間離學校更近的公寓。"},{"en":"Our apartment building has a small shared garden on the roof.","zh":"我們的公寓大樓屋頂上有一座共用的小花園。"}]},{"word":"ape","pos":"n. / v.","phonetic":"[ep]","meaning":"猿；模仿","definition":"a large primate without a tail; to imitate someone","collocations":["great ape","ape someone's behavior"],"example":"Gorillas are the largest apes in the world.","exampleZh":"大猩猩是世界上最大的猿類。","synonyms":[],"level":3,"theme":"動物與植物","examples":[{"en":"Gorillas are the largest apes in the world.","zh":"大猩猩是世界上最大的猿類。"},{"en":"Scientists study how great apes use simple sticks as tools.","zh":"科學家研究大型猿類如何把簡單的樹枝當作工具使用。"},{"en":"The comedian aped the politician's voice to make everyone laugh.","zh":"那位喜劇演員模仿政治人物的聲音，逗得大家哈哈大笑。"}]},{"word":"apologize","pos":"v.","phonetic":"[əˈpɑləˌdʒaɪz]","meaning":"道歉","definition":"to say sorry for something one has done","collocations":["apologize for","apologize to someone"],"example":"He apologized for being late.","exampleZh":"他為遲到道歉。","synonyms":[],"level":3,"theme":"溝通與語言","examples":[{"en":"He apologized for being late.","zh":"他為遲到道歉。"},{"en":"You should apologize to your sister for breaking her favorite toy.","zh":"你應該為弄壞妹妹最喜歡的玩具而向她道歉。"},{"en":"He apologized sincerely for forgetting his best friend's birthday.","zh":"他為忘記最好朋友的生日而誠懇地道歉。"}]},{"word":"apology","pos":"n.","phonetic":"[əˈpɑlədʒi]","meaning":"道歉","definition":"a statement expressing regret for wrongdoing","collocations":["accept an apology","offer an apology"],"example":"She offered a sincere apology to her friend.","exampleZh":"她向朋友誠懇地道歉。","synonyms":[],"level":4,"theme":"溝通與語言","examples":[{"en":"She offered a sincere apology to her friend.","zh":"她向朋友誠懇地道歉。"},{"en":"She kindly accepted his apology and forgave him at once.","zh":"她親切地接受了他的道歉，並立刻原諒了他。"},{"en":"The student wrote a letter of apology to his class teacher.","zh":"那名學生寫了一封道歉信給他的級任老師。"}]},{"word":"apparent","pos":"adj.","phonetic":"[əˈpærənt]","meaning":"明顯的；顯然的","definition":"clearly seen or understood","collocations":["apparent reason","become apparent"],"example":"It became apparent that he had made a mistake.","exampleZh":"很明顯地他犯了一個錯誤。","synonyms":["obvious","clear"],"level":5,"theme":"性質與描述","examples":[{"en":"It became apparent that he had made a mistake.","zh":"很明顯地他犯了一個錯誤。"},{"en":"It soon became apparent that the original plan would not work.","zh":"很快就顯而易見，原本的計畫行不通。"},{"en":"She left the meeting early for no apparent reason.","zh":"她沒有明顯的理由就提早離開了會議。"}]},{"word":"appeal","pos":"n. / v.","phonetic":"[əˈpil]","meaning":"吸引力；懇求；上訴","definition":"attractiveness; to make an urgent or formal request","collocations":["appeal to","wide appeal","file an appeal"],"example":"The idea has great appeal to young people.","exampleZh":"這個點子對年輕人很有吸引力。","synonyms":["attraction","plea"],"level":5,"theme":"溝通與語言","examples":[{"en":"The idea has great appeal to young people.","zh":"這個點子對年輕人很有吸引力。"},{"en":"The new comic book has wide appeal among teenagers.","zh":"這本新漫畫對青少年有廣泛的吸引力。"},{"en":"The charity appealed to the public for donations after the flood.","zh":"洪水過後，這個慈善機構向大眾呼籲捐款。"}]},{"word":"appear","pos":"v.","phonetic":"[əˈpɪr]","meaning":"出現；似乎","definition":"to become visible; to seem to be a certain way","collocations":["appear suddenly","appear to be"],"example":"A rainbow appeared after the rain.","exampleZh":"雨後出現了一道彩虹。","synonyms":["seem","emerge"],"level":2,"theme":"動作與行為","examples":[{"en":"A rainbow appeared after the rain.","zh":"雨後出現了一道彩虹。"},{"en":"A stray cat appeared suddenly from behind the thick bushes.","zh":"一隻流浪貓突然從濃密的灌木叢後面出現。"},{"en":"She appears to be much happier since changing schools.","zh":"自從轉學後，她似乎快樂多了。"}]},{"word":"appearance","pos":"n.","phonetic":"[əˈpɪrəns]","meaning":"外觀；出現","definition":"the way someone or something looks","collocations":["physical appearance","make an appearance"],"example":"Her appearance had changed a lot since college.","exampleZh":"她自從大學以來外貌變化很大。","synonyms":["look"],"level":3,"theme":"服裝與外表","examples":[{"en":"Her appearance had changed a lot since college.","zh":"她自從大學以來外貌變化很大。"},{"en":"Don't judge other people only by their physical appearance.","zh":"不要只以外表來評斷別人。"},{"en":"The famous singer made a surprise appearance at our school fair.","zh":"那位知名歌手意外現身我們學校的園遊會。"}]},{"word":"appendix","pos":"n.","phonetic":"[əˈpɛndɪks]","meaning":"闌尾（盲腸）；附錄","definition":"a small organ in the body; extra material at the end of a book","collocations":["remove the appendix","appendix of a book"],"example":"The doctor removed his inflamed appendix.","exampleZh":"醫生切除了他發炎的闌尾。","synonyms":[],"level":5,"theme":"身體與健康","examples":[{"en":"The doctor removed his inflamed appendix.","zh":"醫生切除了他發炎的闌尾。"},{"en":"You can find the full word list in the appendix of this book.","zh":"你可以在這本書的附錄中找到完整的單字表。"},{"en":"He was rushed to the hospital when his appendix became infected.","zh":"當他的闌尾發炎時，他被緊急送往醫院。"}]},{"word":"appetite","pos":"n.","phonetic":"[ˈæpəˌtaɪt]","meaning":"食欲；胃口","definition":"a desire to eat food","collocations":["lose one's appetite","healthy appetite"],"example":"Exercise gave her a big appetite.","exampleZh":"運動讓她胃口大開。","synonyms":[],"level":4,"theme":"食物與烹飪","examples":[{"en":"Exercise gave her a big appetite.","zh":"運動讓她胃口大開。"},{"en":"The delicious smell from the kitchen gave me a huge appetite.","zh":"廚房傳來的美味香氣讓我食欲大增。"},{"en":"She completely lost her appetite when she caught a bad cold.","zh":"她重感冒時完全沒了胃口。"}]},{"word":"applaud","pos":"v.","phonetic":"[əˈplɔd]","meaning":"鼓掌；讚揚","definition":"to clap hands to show approval","collocations":["applaud loudly","applaud the effort"],"example":"The audience applauded the performers.","exampleZh":"觀眾為表演者鼓掌。","synonyms":["clap","praise"],"level":4,"theme":"藝術與音樂","examples":[{"en":"The audience applauded the performers.","zh":"觀眾為表演者鼓掌。"},{"en":"The whole audience applauded loudly when the play finally ended.","zh":"戲劇終於結束時，全場觀眾大聲鼓掌。"},{"en":"The judges applauded the young dancer's brave and honest effort.","zh":"評審們讚揚那位年輕舞者勇敢又真誠的努力。"}]},{"word":"apple","pos":"n.","phonetic":"[ˈæpl]","meaning":"蘋果","definition":"a round fruit with red, green, or yellow skin","collocations":["apple pie","an apple a day"],"example":"She packed an apple for lunch.","exampleZh":"她為午餐帶了一顆蘋果。","synonyms":[],"level":1,"theme":"食物與烹飪","examples":[{"en":"She packed an apple for lunch.","zh":"她為午餐帶了一顆蘋果。"},{"en":"Grandma baked a warm apple pie for our dessert tonight.","zh":"奶奶今晚烤了一個溫熱的蘋果派當我們的甜點。"},{"en":"People often say an apple a day keeps the doctor away.","zh":"人們常說一天一蘋果，醫生遠離我。"}]},{"word":"appliance","pos":"n.","phonetic":"[əˈplaɪəns]","meaning":"電器；用具","definition":"a device used for a specific task, especially at home","collocations":["kitchen appliance","household appliance"],"example":"They bought a new kitchen appliance for baking.","exampleZh":"他們買了一台新的廚房電器用來烘焙。","synonyms":["device"],"level":5,"theme":"居家與生活","examples":[{"en":"They bought a new kitchen appliance for baking.","zh":"他們買了一台新的廚房電器用來烘焙。"},{"en":"Remember to unplug every household appliance before the long trip.","zh":"出遠門前記得拔掉每一項家電的插頭。"},{"en":"The rice cooker is the most useful appliance in our kitchen.","zh":"電鍋是我們廚房裡最實用的電器。"}]},{"word":"applicant","pos":"n.","phonetic":"[ˈæpləkənt]","meaning":"申請人","definition":"a person who applies for something, such as a job","collocations":["job applicant","qualified applicant"],"example":"Hundreds of applicants applied for the position.","exampleZh":"數百名申請人應徵這個職位。","synonyms":["candidate"],"level":5,"theme":"工作與職業","examples":[{"en":"Hundreds of applicants applied for the position.","zh":"數百名申請人應徵這個職位。"},{"en":"Only the most qualified applicant will be offered the scholarship.","zh":"只有最符合資格的申請人才會獲得這份獎學金。"},{"en":"Each applicant must submit two letters of recommendation.","zh":"每位申請人都必須繳交兩封推薦信。"}]},{"word":"application","pos":"n.","phonetic":"[ˌæpləˈkeʃən]","meaning":"申請；應用程式","definition":"a formal request; a software program","collocations":["job application","mobile application"],"example":"He submitted his application before the deadline.","exampleZh":"他在截止日期前提交了申請。","synonyms":[],"level":4,"theme":"工作與職業","examples":[{"en":"He submitted his application before the deadline.","zh":"他在截止日期前提交了申請。"},{"en":"She downloaded a new application to help her learn English words.","zh":"她下載了一個新的應用程式來幫助她學英文單字。"},{"en":"Please complete the application form before this Friday.","zh":"請在這個星期五之前填完申請表。"}]},{"word":"apply","pos":"v.","phonetic":"[əˈplaɪ]","meaning":"申請；應用","definition":"to make a formal request; to put something into use","collocations":["apply for a job","apply a rule"],"example":"She applied for a scholarship to study abroad.","exampleZh":"她申請獎學金到國外留學。","synonyms":[],"level":3,"theme":"教育與學習","examples":[{"en":"She applied for a scholarship to study abroad.","zh":"她申請獎學金到國外留學。"},{"en":"He plans to apply to three different universities this year.","zh":"他打算今年申請三所不同的大學。"},{"en":"The same safety rules apply to everyone working in the lab.","zh":"相同的安全規則適用於在實驗室工作的每個人。"}]},{"word":"arch","pos":"n.","phonetic":"[ɑrtʃ]","meaning":"拱門；拱形結構","definition":"a curved structure that spans an opening","collocations":["stone arch","arch bridge","arch of a foot"],"example":"Tourists took photos under the ancient stone arch.","exampleZh":"遊客們在古老的石拱門下拍照。","synonyms":["arc"],"level":4,"theme":"其他","examples":[{"en":"Tourists took photos under the ancient stone arch.","zh":"遊客們在古老的石拱門下拍照。"},{"en":"We walked under a graceful stone arch at the park entrance.","zh":"我們從公園入口一座優雅的石拱門下走過。"},{"en":"The old railway crossed the deep valley on a tall arch bridge.","zh":"那條舊鐵路經由一座高聳的拱橋跨越深谷。"}]},{"word":"architect","pos":"n.","phonetic":"[ˈɑrkə͵tɛkt]","meaning":"建築師；設計師","definition":"a person who designs buildings","collocations":["hire an architect","famous architect","landscape architect"],"example":"The architect designed a modern museum downtown.","exampleZh":"這位建築師設計了市中心的一座現代博物館。","synonyms":["designer"],"level":4,"theme":"工作與職業","examples":[{"en":"The architect designed a modern museum downtown.","zh":"這位建築師設計了市中心的一座現代博物館。"},{"en":"A famous architect designed the curved roof of the new library.","zh":"一位知名的建築師設計了新圖書館彎曲的屋頂。"},{"en":"She dreams of becoming an architect and building eco-friendly houses.","zh":"她夢想成為建築師，蓋出環保的房子。"}]},{"word":"arctic","pos":"adj. / n.","phonetic":"[ˈɑrktɪk]","meaning":"北極的；極寒的","definition":"relating to the region around the North Pole, or extremely cold","collocations":["arctic weather","arctic circle","arctic wind"],"example":"Arctic winds swept through the northern towns.","exampleZh":"北極的寒風席捲了北方城鎮。","synonyms":["polar","freezing"],"level":5,"theme":"自然與環境","examples":[{"en":"Arctic winds swept through the northern towns.","zh":"北極的寒風席捲了北方城鎮。"},{"en":"A sudden arctic wind made our mountain trip freezing cold.","zh":"一陣突如其來的極地寒風讓我們的登山之旅冷得刺骨。"},{"en":"Polar bears are well suited to the harsh arctic weather.","zh":"北極熊很適應嚴酷的北極氣候。"}]},{"word":"area","pos":"n.","phonetic":"[ˈɛrɪə]","meaning":"地區；區域；範圍","definition":"a particular part of a place, or a subject of study","collocations":["local area","area of study","parking area"],"example":"This area is famous for its night markets.","exampleZh":"這個地區以夜市聞名。","synonyms":["region","zone"],"level":2,"theme":"時間與空間","examples":[{"en":"This area is famous for its night markets.","zh":"這個地區以夜市聞名。"},{"en":"Biology is the area of study that she enjoys the most.","zh":"生物學是她最喜歡的研究領域。"},{"en":"Please leave your bicycle only in the designated parking area.","zh":"請把你的腳踏車只停在指定的停車區。"}]},{"word":"argue","pos":"v.","phonetic":"[ˈɑrgju]","meaning":"爭論；主張；辯論","definition":"to give reasons for or against something, often in disagreement","collocations":["argue with someone","argue about money","argue that"],"example":"The two brothers argued about who should do the dishes.","exampleZh":"兩兄弟為了誰該洗碗而爭論。","synonyms":["quarrel","dispute"],"level":2,"theme":"溝通與語言","examples":[{"en":"The two brothers argued about who should do the dishes.","zh":"兩兄弟為了誰該洗碗而爭論。"},{"en":"The scientist argued that the new method saves much more energy.","zh":"那位科學家主張這個新方法能節省更多能源。"},{"en":"The neighbors often argue about where to park their cars.","zh":"鄰居們常為了停車的地方而爭論。"}]},{"word":"argument","pos":"n.","phonetic":"[ˈɑrgjəmənt]","meaning":"爭論；論點；理由","definition":"an exchange of differing views, often heated","collocations":["have an argument","strong argument","win an argument"],"example":"They had a heated argument over the phone bill.","exampleZh":"他們為了電話費起了激烈的爭論。","synonyms":["dispute","debate"],"level":3,"theme":"溝通與語言","examples":[{"en":"They had a heated argument over the phone bill.","zh":"他們為了電話費起了激烈的爭論。"},{"en":"She made a strong argument for recycling at the school meeting.","zh":"她在校務會議上為資源回收提出了有力的論點。"},{"en":"The two friends had a short argument but soon made up.","zh":"那兩個朋友起了短暫的爭執，但很快就和好了。"}]},{"word":"arithmetic","pos":"n.","phonetic":"[əˈrɪθmə͵tɪk]","meaning":"算術；計算","definition":"the branch of mathematics dealing with basic calculations","collocations":["mental arithmetic","arithmetic problem","basic arithmetic"],"example":"The students practiced arithmetic before the exam.","exampleZh":"學生們在考試前練習算術。","synonyms":["calculation"],"level":4,"theme":"科學與數學","examples":[{"en":"The students practiced arithmetic before the exam.","zh":"學生們在考試前練習算術。"},{"en":"He can solve difficult arithmetic problems without using a calculator.","zh":"他不用計算機就能解出困難的算術題。"},{"en":"Good mental arithmetic is very useful when shopping at the market.","zh":"良好的心算能力在市場購物時非常有用。"}]},{"word":"arm","pos":"n. / v.","phonetic":"[ɑrm]","meaning":"手臂；武裝","definition":"the upper limb of the body, or to equip with weapons","collocations":["break an arm","arm in arm","arm the soldiers"],"example":"She broke her arm while skiing last winter.","exampleZh":"她去年冬天滑雪時摔斷了手臂。","synonyms":["limb"],"level":1,"theme":"身體與健康","examples":[{"en":"She broke her arm while skiing last winter.","zh":"她去年冬天滑雪時摔斷了手臂。"},{"en":"The happy couple walked arm in arm along the quiet beach.","zh":"這對幸福的情侶手挽著手沿著寧靜的海灘散步。"},{"en":"The general refused to arm the young villagers with guns.","zh":"將軍拒絕用槍武裝年輕的村民。"}]},{"word":"army","pos":"n.","phonetic":"[ˈɑrmɪ]","meaning":"軍隊；陸軍","definition":"an organized military force for fighting on land","collocations":["join the army","army officer","army base"],"example":"His father served in the army for ten years.","exampleZh":"他父親在陸軍服役了十年。","synonyms":["troops"],"level":2,"theme":"政治與法律","examples":[{"en":"His father served in the army for ten years.","zh":"他父親在陸軍服役了十年。"},{"en":"After graduating, my cousin decided to join the army.","zh":"畢業後，我表哥決定從軍。"},{"en":"The army officer trained the new recruits every single morning.","zh":"那位陸軍軍官每天早上訓練新兵。"}]},{"word":"aroma","pos":"n.","phonetic":"[əˈromə]","meaning":"香味；香氣","definition":"a pleasant, distinctive smell","collocations":["the aroma of coffee","rich aroma","fill the air with aroma"],"example":"The aroma of fresh bread filled the kitchen.","exampleZh":"新鮮麵包的香氣瀰漫了整個廚房。","synonyms":["fragrance","scent"],"level":4,"theme":"食物與烹飪","examples":[{"en":"The aroma of fresh bread filled the kitchen.","zh":"新鮮麵包的香氣瀰漫了整個廚房。"},{"en":"The rich aroma of coffee greeted us as we entered the café.","zh":"我們走進咖啡館時，濃郁的咖啡香撲鼻而來。"},{"en":"The aroma of grilled fish drifted over from the night market.","zh":"烤魚的香味從夜市飄了過來。"}]},{"word":"around","pos":"prep. / adv.","phonetic":"[əˈraʊnd]","meaning":"環繞；大約；到處","definition":"in various directions or places, or approximately","collocations":["around the world","around noon","turn around"],"example":"They traveled around the world for a year.","exampleZh":"他們花了一年環遊世界。","synonyms":["about","approximately"],"level":1,"theme":"時間與空間","examples":[{"en":"They traveled around the world for a year.","zh":"他們花了一年環遊世界。"},{"en":"Let's meet around noon in front of the public library.","zh":"我們中午左右在公立圖書館前碰面吧。"},{"en":"She turned around quickly when someone suddenly called her name.","zh":"有人突然叫她的名字時，她迅速轉過身來。"}]},{"word":"arrange","pos":"v.","phonetic":"[əˈrendʒ]","meaning":"安排；排列；整理","definition":"to plan or organize something in advance","collocations":["arrange a meeting","arrange flowers","arrange for someone to do something"],"example":"She arranged a trip to Kenting for the weekend.","exampleZh":"她安排了一趟週末去墾丁的旅行。","synonyms":["organize","plan"],"level":2,"theme":"動作與行為","examples":[{"en":"She arranged a trip to Kenting for the weekend.","zh":"她安排了一趟週末去墾丁的旅行。"},{"en":"The florist arranged the fresh roses beautifully in a glass vase.","zh":"花商把新鮮的玫瑰漂亮地插進玻璃花瓶裡。"},{"en":"Our teacher arranged a meeting with all the worried parents.","zh":"我們老師安排了一場與所有憂心家長的會議。"}]},{"word":"arrangement","pos":"n.","phonetic":"[əˈrendʒmənt]","meaning":"安排；佈置；協議","definition":"a plan or preparation made in advance","collocations":["make arrangements","flower arrangement","reach an arrangement"],"example":"We made arrangements for the wedding ceremony.","exampleZh":"我們為婚禮做了各項安排。","synonyms":["plan","preparation"],"level":3,"theme":"抽象概念","examples":[{"en":"We made arrangements for the wedding ceremony.","zh":"我們為婚禮做了各項安排。"},{"en":"The two sides finally reached a fair arrangement about the noise.","zh":"雙方終於就噪音問題達成了公平的協議。"},{"en":"Her flower arrangement won first prize at the school fair.","zh":"她的插花作品在學校園遊會上得了第一名。"}]},{"word":"arrest","pos":"v. / n.","phonetic":"[əˈrɛst]","meaning":"逮捕；拘留","definition":"to take someone into custody by legal authority","collocations":["under arrest","arrest a suspect","make an arrest"],"example":"The police arrested the thief near the station.","exampleZh":"警方在車站附近逮捕了那名小偷。","synonyms":["detain","capture"],"level":4,"theme":"政治與法律","examples":[{"en":"The police arrested the thief near the station.","zh":"警方在車站附近逮捕了那名小偷。"},{"en":"The officer told the suspect that he was now under arrest.","zh":"警官告訴嫌犯他現在被逮捕了。"},{"en":"Police arrested two suspects following the late-night robbery.","zh":"警方在深夜搶案後逮捕了兩名嫌犯。"}]},{"word":"arrival","pos":"n.","phonetic":"[əˈraɪvl̩]","meaning":"到達；抵達；到來","definition":"the act of arriving somewhere","collocations":["arrival time","on arrival","new arrival"],"example":"The arrival of the flight was delayed by two hours.","exampleZh":"班機的抵達時間延誤了兩小時。","synonyms":["appearance"],"level":2,"theme":"交通與旅行","examples":[{"en":"The arrival of the flight was delayed by two hours.","zh":"班機的抵達時間延誤了兩小時。"},{"en":"The expected arrival time of the train is half past six.","zh":"火車預計的抵達時間是六點半。"},{"en":"On arrival, each guest received a warm welcome and a cool drink.","zh":"每位賓客一抵達就受到熱情的歡迎並拿到一杯冷飲。"}]},{"word":"arrive","pos":"v.","phonetic":"[əˈraɪv]","meaning":"到達；抵達","definition":"to reach a place after traveling","collocations":["arrive at","arrive in a city","arrive on time"],"example":"We arrived at the airport an hour early.","exampleZh":"我們提早一小時到達機場。","synonyms":["reach","get to"],"level":1,"theme":"交通與旅行","examples":[{"en":"We arrived at the airport an hour early.","zh":"我們提早一小時到達機場。"},{"en":"Please make sure that you arrive on time for the exam.","zh":"請務必準時到達參加考試。"},{"en":"They arrived in the city just as the sun was setting.","zh":"他們在太陽正要落下時抵達了這座城市。"}]},{"word":"arrogant","pos":"adj.","phonetic":"[ˈærəgənt]","meaning":"傲慢的；自大的","definition":"having an exaggerated sense of one's own importance","collocations":["arrogant attitude","sound arrogant","arrogant behavior"],"example":"His arrogant attitude made him unpopular with classmates.","exampleZh":"他傲慢的態度讓他在同學中不受歡迎。","synonyms":["haughty","conceited"],"level":5,"theme":"性質與描述","examples":[{"en":"His arrogant attitude made him unpopular with classmates.","zh":"他傲慢的態度讓他在同學中不受歡迎。"},{"en":"His arrogant behavior slowly drove all of his friends away.","zh":"他傲慢的行為漸漸把他所有的朋友都趕跑了。"},{"en":"I really didn't mean to sound arrogant when I answered.","zh":"我回答時真的無意顯得那麼自大。"}]},{"word":"arrow","pos":"n.","phonetic":"[ˈæro]","meaning":"箭；箭頭符號","definition":"a thin straight weapon shot from a bow, or a pointed symbol","collocations":["bow and arrow","follow the arrow","arrow key"],"example":"The archer shot an arrow straight into the target.","exampleZh":"弓箭手一箭射中了靶心。","synonyms":[],"level":2,"theme":"其他","examples":[{"en":"The archer shot an arrow straight into the target.","zh":"弓箭手一箭射中了靶心。"},{"en":"Just follow the arrow on the sign to reach the exit.","zh":"只要跟著標示上的箭頭走就能到出口。"},{"en":"Press the down arrow key to move to the next line.","zh":"按下向下的方向鍵就能移到下一行。"}]},{"word":"art","pos":"n.","phonetic":"[ɑrt]","meaning":"藝術；美術；技藝","definition":"the expression of human creativity through painting, drawing, or sculpture","collocations":["work of art","art gallery","modern art"],"example":"She studies art at a university in Taipei.","exampleZh":"她在台北的一所大學主修藝術。","synonyms":["craft"],"level":1,"theme":"藝術與音樂","examples":[{"en":"She studies art at a university in Taipei.","zh":"她在台北的一所大學主修藝術。"},{"en":"This old painting is considered a true work of art.","zh":"這幅古老的畫作被視為真正的藝術品。"},{"en":"We spent the whole afternoon exploring a modern art gallery.","zh":"我們花了整個下午逛現代美術館。"}]},{"word":"article","pos":"n.","phonetic":"[ˈɑrtɪkl̩]","meaning":"文章；報導；物品","definition":"a piece of writing in a newspaper or magazine, or an object","collocations":["news article","write an article","household articles"],"example":"He wrote an article about climate change.","exampleZh":"他寫了一篇關於氣候變遷的文章。","synonyms":["essay","piece"],"level":2,"theme":"教育與學習","examples":[{"en":"He wrote an article about climate change.","zh":"他寫了一篇關於氣候變遷的文章。"},{"en":"She read an interesting news article about ocean pollution.","zh":"她讀了一篇關於海洋污染的有趣新聞報導。"},{"en":"The store sells household articles such as towels and cups.","zh":"這家店販售毛巾和杯子之類的家用物品。"}]},{"word":"artificial","pos":"adj.","phonetic":"[͵ɑrtəˈfɪʃəl]","meaning":"人工的；人造的；虛假的","definition":"made by humans rather than occurring naturally","collocations":["artificial intelligence","artificial light","artificial flowers"],"example":"The company develops artificial intelligence software.","exampleZh":"這間公司開發人工智慧軟體。","synonyms":["man-made","synthetic"],"level":3,"theme":"科技與媒體","examples":[{"en":"The company develops artificial intelligence software.","zh":"這間公司開發人工智慧軟體。"},{"en":"These indoor plants can grow well under artificial light.","zh":"這些室內植物在人工燈光下也能長得好。"},{"en":"The vase was filled with colorful artificial flowers.","zh":"花瓶裡插滿了色彩繽紛的人造花。"}]},{"word":"artist","pos":"n.","phonetic":"[ˈɑrtɪst]","meaning":"藝術家；畫家","definition":"a person who creates art, especially paintings","collocations":["a famous artist","street artist","artist's studio"],"example":"The artist painted a beautiful sunset over the sea.","exampleZh":"這位藝術家畫了一幅美麗的海上夕陽。","synonyms":["painter"],"level":2,"theme":"藝術與音樂","examples":[{"en":"The artist painted a beautiful sunset over the sea.","zh":"這位藝術家畫了一幅美麗的海上夕陽。"},{"en":"A talented street artist drew our portraits in just ten minutes.","zh":"一位才華洋溢的街頭藝術家只花十分鐘就畫好了我們的肖像。"},{"en":"We visited the artist's studio, which was filled with unfinished paintings.","zh":"我們參觀了那位藝術家堆滿未完成畫作的工作室。"}]},{"word":"ash","pos":"n.","phonetic":"[æʃ]","meaning":"灰；灰燼","definition":"the powdery residue left after something burns","collocations":["volcanic ash","cigarette ash","ash tray"],"example":"Volcanic ash covered the entire village.","exampleZh":"火山灰覆蓋了整個村莊。","synonyms":["cinder"],"level":4,"theme":"自然與環境","examples":[{"en":"Volcanic ash covered the entire village.","zh":"火山灰覆蓋了整個村莊。"},{"en":"After the campfire finally died out, only gray ash remained.","zh":"營火終於熄滅後，只剩下灰色的灰燼。"},{"en":"Thick volcanic ash blocked the sunlight for several days.","zh":"厚厚的火山灰遮蔽了好幾天的陽光。"}]},{"word":"ashamed","pos":"adj.","phonetic":"[əˈʃemd]","meaning":"感到羞愧的；慚愧的","definition":"feeling embarrassed or guilty about something","collocations":["ashamed of oneself","feel ashamed","ashamed to admit"],"example":"He felt ashamed of lying to his parents.","exampleZh":"他對欺騙父母感到羞愧。","synonyms":["embarrassed","guilty"],"level":3,"theme":"情緒與感受","examples":[{"en":"He felt ashamed of lying to his parents.","zh":"他對欺騙父母感到羞愧。"},{"en":"I'm ashamed to admit that I completely forgot my promise.","zh":"我很慚愧地承認，我完全忘了我的承諾。"},{"en":"She felt deeply ashamed of shouting at her younger brother.","zh":"她為對弟弟大吼而感到深深羞愧。"}]},{"word":"aside","pos":"adv.","phonetic":"[əˈsaɪd]","meaning":"到旁邊；除外","definition":"to one side; away from the main point","collocations":["step aside","set aside money","joking aside"],"example":"She set aside some money for emergencies.","exampleZh":"她留了一些錢以備不時之需。","synonyms":[],"level":3,"theme":"時間與空間","examples":[{"en":"She set aside some money for emergencies.","zh":"她留了一些錢以備不時之需。"},{"en":"Please step aside so the nurses can pass with the stretcher.","zh":"請讓到一邊，好讓護士抬著擔架通過。"},{"en":"Joking aside, we really must finish this project tonight.","zh":"別開玩笑了，我們今晚真的必須完成這個專案。"}]},{"word":"ask","pos":"v.","phonetic":"[æsk]","meaning":"問；詢問；要求","definition":"to say something in order to obtain information or a favor","collocations":["ask a question","ask for help","ask about"],"example":"May I ask you a personal question?","exampleZh":"我可以問你一個私人問題嗎？","synonyms":["inquire","request"],"level":1,"theme":"溝通與語言","examples":[{"en":"May I ask you a personal question?","zh":"我可以問你一個私人問題嗎？"},{"en":"Don't be afraid to ask for help when you get lost.","zh":"迷路時別害怕開口求助。"},{"en":"A tourist stopped me to ask about the way to the station.","zh":"一位觀光客攔住我，問到車站的路怎麼走。"}]},{"word":"asleep","pos":"adj.","phonetic":"[əˈslip]","meaning":"睡著的","definition":"in a state of sleep","collocations":["fall asleep","fast asleep","sound asleep"],"example":"The baby finally fell asleep after crying.","exampleZh":"寶寶哭了一陣子後終於睡著了。","synonyms":["sleeping"],"level":1,"theme":"身體與健康","examples":[{"en":"The baby finally fell asleep after crying.","zh":"寶寶哭了一陣子後終於睡著了。"},{"en":"By the time the movie ended, my little brother was fast asleep.","zh":"電影結束時，我弟弟早已熟睡。"},{"en":"She fell asleep on the sofa while reading her favorite novel.","zh":"她看她最愛的小說時在沙發上睡著了。"}]},{"word":"aspect","pos":"n.","phonetic":"[ˈæspɛkt]","meaning":"方面；層面","definition":"a particular part or feature of a situation","collocations":["important aspect","every aspect of life","legal aspect"],"example":"We need to consider every aspect of the plan.","exampleZh":"我們需要考慮這項計畫的每個層面。","synonyms":["feature","facet"],"level":4,"theme":"抽象概念","examples":[{"en":"We need to consider every aspect of the plan.","zh":"我們需要考慮這項計畫的每個層面。"},{"en":"Teamwork is an important aspect of playing on a sports team.","zh":"團隊合作是參加運動隊伍的一個重要面向。"},{"en":"The internet now affects almost every aspect of our daily life.","zh":"網路如今幾乎影響我們日常生活的每個層面。"}]},{"word":"aspirin","pos":"n.","phonetic":"[ˈæspərɪn]","meaning":"阿斯匹靈；止痛藥","definition":"a common drug used to relieve pain and reduce fever","collocations":["take an aspirin","aspirin tablet","low-dose aspirin"],"example":"She took an aspirin to relieve her headache.","exampleZh":"她吃了一顆阿斯匹靈來緩解頭痛。","synonyms":["painkiller"],"level":3,"theme":"身體與健康","examples":[{"en":"She took an aspirin to relieve her headache.","zh":"她吃了一顆阿斯匹靈來緩解頭痛。"},{"en":"He swallowed an aspirin tablet with a glass of warm water.","zh":"他就著一杯溫水吞下了一顆阿斯匹靈藥片。"},{"en":"The nurse suggested a low-dose aspirin for his mild fever.","zh":"護士建議用低劑量的阿斯匹靈來緩解他輕微的發燒。"}]},{"word":"assemble","pos":"v.","phonetic":"[əˈsɛmbl̩]","meaning":"組裝；集合；聚集","definition":"to gather together or fit parts together","collocations":["assemble furniture","assemble a team","students assemble"],"example":"It took an hour to assemble the new bookshelf.","exampleZh":"組裝這個新書架花了一個小時。","synonyms":["gather","construct"],"level":4,"theme":"動作與行為","examples":[{"en":"It took an hour to assemble the new bookshelf.","zh":"組裝這個新書架花了一個小時。"},{"en":"The whole family helped assemble the new wooden bed.","zh":"全家人一起幫忙組裝那張新的木床。"},{"en":"The students assembled in the hall for the morning ceremony.","zh":"學生們在禮堂集合參加早晨的典禮。"}]},{"word":"assembly","pos":"n.","phonetic":"[əˈsɛmblɪ]","meaning":"集會；組裝；議會","definition":"a group of people gathered for a purpose, or the process of assembling parts","collocations":["school assembly","assembly line","general assembly"],"example":"All students gathered for the morning assembly.","exampleZh":"所有學生都聚集參加早上的集會。","synonyms":["gathering"],"level":4,"theme":"教育與學習","examples":[{"en":"All students gathered for the morning assembly.","zh":"所有學生都聚集參加早上的集會。"},{"en":"The principal gave an inspiring speech at the school assembly.","zh":"校長在學校集會上發表了一場激勵人心的演說。"},{"en":"Workers on the assembly line put together hundreds of toys daily.","zh":"生產線上的工人每天組裝數百個玩具。"}]},{"word":"assess","pos":"v.","phonetic":"[əˈsɛs]","meaning":"評估；評定","definition":"to evaluate the nature or value of something","collocations":["assess the damage","assess a situation","assess performance"],"example":"Teachers assess students' progress every semester.","exampleZh":"老師每學期評估學生的學習進度。","synonyms":["evaluate","judge"],"level":5,"theme":"教育與學習","examples":[{"en":"Teachers assess students' progress every semester.","zh":"老師每學期評估學生的學習進度。"},{"en":"Engineers arrived to assess the damage caused by the strong earthquake.","zh":"工程師抵達現場評估強震造成的損害。"},{"en":"The coach assessed each player's performance after the match.","zh":"教練在賽後評估每位球員的表現。"}]},{"word":"asset","pos":"n.","phonetic":"[ˈæsɛt]","meaning":"資產；有價值的人或物","definition":"a valuable resource or property owned by someone","collocations":["valuable asset","company assets","great asset to the team"],"example":"Her language skills are a great asset at work.","exampleZh":"她的語言能力是工作上寶貴的資產。","synonyms":["resource"],"level":5,"theme":"商業與金錢","examples":[{"en":"Her language skills are a great asset at work.","zh":"她的語言能力是工作上寶貴的資產。"},{"en":"Honesty is a valuable asset in any lasting friendship.","zh":"誠實是任何長久友誼中一項珍貴的資產。"},{"en":"His calm attitude makes him a great asset to our team.","zh":"他冷靜的態度使他成為我們團隊中的一大寶貴人才。"}]},{"word":"assign","pos":"v.","phonetic":"[əˈsaɪn]","meaning":"分派；指派；分配","definition":"to give a task or duty to someone","collocations":["assign homework","assign a task","assign a seat"],"example":"The teacher assigned homework for the weekend.","exampleZh":"老師指派了週末的作業。","synonyms":["allocate","designate"],"level":3,"theme":"工作與職業","examples":[{"en":"The teacher assigned homework for the weekend.","zh":"老師指派了週末的作業。"},{"en":"The teacher assigned each group a different topic to research.","zh":"老師分派給每一組不同的研究主題。"},{"en":"The flight attendant assigned us comfortable seats near the window.","zh":"空服員分配給我們靠窗的舒適座位。"}]},{"word":"assignment","pos":"n.","phonetic":"[əˈsaɪnmənt]","meaning":"作業；任務；指派","definition":"a task or piece of work assigned to someone","collocations":["homework assignment","complete an assignment","work assignment"],"example":"She finished her English assignment before dinner.","exampleZh":"她在晚餐前完成了英文作業。","synonyms":["task"],"level":3,"theme":"教育與學習","examples":[{"en":"She finished her English assignment before dinner.","zh":"她在晚餐前完成了英文作業。"},{"en":"I stayed up quite late to complete my history assignment.","zh":"我熬到很晚才完成我的歷史作業。"},{"en":"The group divided the assignment into three equal parts.","zh":"這一組把作業分成三個相等的部分。"}]},{"word":"assist","pos":"v.","phonetic":"[əˈsɪst]","meaning":"協助；幫助","definition":"to help someone by doing part of their work","collocations":["assist with","assist a customer","assist in research"],"example":"He assisted the elderly woman with her bags.","exampleZh":"他協助那位老太太提行李。","synonyms":["help","aid"],"level":3,"theme":"動作與行為","examples":[{"en":"He assisted the elderly woman with her bags.","zh":"他協助那位老太太提行李。"},{"en":"Older students often assist younger ones with their reading.","zh":"高年級學生常協助低年級學生閱讀。"},{"en":"She assisted her professor in an important science project.","zh":"她協助教授進行一項重要的科學計畫。"}]},{"word":"assistant","pos":"n. / adj.","phonetic":"[əˈsɪstənt]","meaning":"助理；助手；輔助的","definition":"a person who helps someone in their work","collocations":["personal assistant","assistant manager","shop assistant"],"example":"His assistant scheduled all his meetings.","exampleZh":"他的助理安排了他所有的會議。","synonyms":["helper","aide"],"level":2,"theme":"工作與職業","examples":[{"en":"His assistant scheduled all his meetings.","zh":"他的助理安排了他所有的會議。"},{"en":"The friendly shop assistant helped me find the right size.","zh":"親切的店員幫我找到了合適的尺寸。"},{"en":"As assistant manager, she trains all of the new workers.","zh":"身為副理，她負責訓練所有新進員工。"}]},{"word":"associate","pos":"v. / n.","phonetic":"[əˈsoʃɪ͵et]","meaning":"聯想；使有關聯；夥伴","definition":"to connect one thing with another in the mind, or a colleague","collocations":["associate with","business associate","closely associated"],"example":"People often associate winter with cold weather.","exampleZh":"人們常把冬天和寒冷的天氣聯想在一起。","synonyms":["connect","link"],"level":4,"theme":"抽象概念","examples":[{"en":"People often associate winter with cold weather.","zh":"人們常把冬天和寒冷的天氣聯想在一起。"},{"en":"Most people in Taiwan associate the color red with good luck.","zh":"在台灣，大多數人把紅色和好運聯想在一起。"},{"en":"My parents warned me not to associate with dishonest people.","zh":"我父母警告我不要跟不誠實的人來往。"}]},{"word":"association","pos":"n.","phonetic":"[ə͵soʃɪˈeʃən]","meaning":"協會；聯想；關聯","definition":"an organized group, or a connection between things or ideas","collocations":["trade association","in association with","strong association"],"example":"She joined the national teachers' association.","exampleZh":"她加入了全國教師協會。","synonyms":["organization","link"],"level":5,"theme":"社會與文化","examples":[{"en":"She joined the national teachers' association.","zh":"她加入了全國教師協會。"},{"en":"The concert was organized in association with a local charity.","zh":"這場音樂會是與一個當地慈善機構合作舉辦的。"},{"en":"There is a strong association between exercise and good sleep.","zh":"運動與良好睡眠之間有著密切的關聯。"}]},{"word":"assume","pos":"v.","phonetic":"[əˈsjum]","meaning":"假設；認為；承擔","definition":"to suppose something is true without proof","collocations":["assume responsibility","assume that","safe to assume"],"example":"I assumed you already knew the news.","exampleZh":"我以為你已經知道這個消息了。","synonyms":["suppose","presume"],"level":4,"theme":"抽象概念","examples":[{"en":"I assumed you already knew the news.","zh":"我以為你已經知道這個消息了。"},{"en":"Please don't assume that everyone agrees with your opinion.","zh":"請別假設每個人都同意你的意見。"},{"en":"As the eldest child, she had to assume responsibility for her siblings.","zh":"身為長女，她必須承擔起照顧弟妹的責任。"}]},{"word":"assumption","pos":"n.","phonetic":"[əˈsʌmpʃən]","meaning":"假設；假定","definition":"something believed to be true without proof","collocations":["make an assumption","false assumption","based on the assumption"],"example":"His plan was based on a wrong assumption.","exampleZh":"他的計畫是建立在一個錯誤的假設上。","synonyms":["premise"],"level":5,"theme":"抽象概念","examples":[{"en":"His plan was based on a wrong assumption.","zh":"他的計畫是建立在一個錯誤的假設上。"},{"en":"His whole argument rests on a false assumption about the weather.","zh":"他整個論點建立在一個關於天氣的錯誤假設上。"},{"en":"We planned the picnic on the assumption that it wouldn't rain.","zh":"我們在假設不會下雨的前提下計畫了這場野餐。"}]},{"word":"assure","pos":"v.","phonetic":"[əˈʃʊr]","meaning":"向...保證；使確信","definition":"to tell someone confidently that something is true","collocations":["assure someone that","I assure you","assure safety"],"example":"The manager assured us the product was safe.","exampleZh":"經理向我們保證這項產品是安全的。","synonyms":["guarantee","promise"],"level":4,"theme":"溝通與語言","examples":[{"en":"The manager assured us the product was safe.","zh":"經理向我們保證這項產品是安全的。"},{"en":"The guide assured us that the steep mountain path was completely safe.","zh":"嚮導向我們保證這條陡峭的山路完全安全。"},{"en":"I assure you that your package will arrive before Friday.","zh":"我向你保證你的包裹會在星期五前送達。"}]},{"word":"asthma","pos":"n.","phonetic":"[ˈæzmə]","meaning":"氣喘；哮喘","definition":"a chronic condition causing difficulty breathing","collocations":["asthma attack","suffer from asthma","asthma medication"],"example":"He carries an inhaler because he has asthma.","exampleZh":"他因為有氣喘所以隨身攜帶吸入器。","synonyms":[],"level":5,"theme":"身體與健康","examples":[{"en":"He carries an inhaler because he has asthma.","zh":"他因為有氣喘所以隨身攜帶吸入器。"},{"en":"Cold, dry air can sometimes trigger an asthma attack in children.","zh":"乾冷的空氣有時會引發孩童的氣喘發作。"},{"en":"He always keeps his asthma medication inside his backpack.","zh":"他總是把氣喘藥放在他的背包裡。"}]},{"word":"astonish","pos":"v.","phonetic":"[əˈstɑnɪʃ]","meaning":"使驚訝；使震驚","definition":"to surprise someone greatly","collocations":["astonish everyone","astonishing result","be astonished at"],"example":"The magician's trick astonished the audience.","exampleZh":"魔術師的把戲讓觀眾大為驚訝。","synonyms":["amaze","surprise"],"level":5,"theme":"情緒與感受","examples":[{"en":"The magician's trick astonished the audience.","zh":"魔術師的把戲讓觀眾大為驚訝。"},{"en":"The young pianist astonished everyone with her flawless performance.","zh":"這位年輕鋼琴家以她完美無瑕的演出讓所有人驚嘆。"},{"en":"We were astonished at how quickly the clever puppy learned tricks.","zh":"那隻聰明的小狗學會把戲的速度之快令我們驚訝。"}]},{"word":"astronaut","pos":"n.","phonetic":"[ˈæstrə͵nɔt]","meaning":"太空人；太空人員","definition":"a person trained to travel in a spacecraft","collocations":["become an astronaut","astronaut training","famous astronaut"],"example":"The astronaut spent six months on the space station.","exampleZh":"這位太空人在太空站待了六個月。","synonyms":[],"level":3,"theme":"工作與職業","examples":[{"en":"The astronaut spent six months on the space station.","zh":"這位太空人在太空站待了六個月。"},{"en":"As a child, she dreamed of becoming an astronaut one day.","zh":"小時候，她夢想有一天能成為一名太空人。"},{"en":"Astronaut training includes long hours practicing in a deep pool.","zh":"太空人訓練包括在深水池裡練習好幾個小時。"}]},{"word":"astronomy","pos":"n.","phonetic":"[əˈstrɑnəmɪ]","meaning":"天文學","definition":"the scientific study of stars, planets, and space","collocations":["study astronomy","astronomy class","modern astronomy"],"example":"She has loved astronomy since she was a child.","exampleZh":"她從小就熱愛天文學。","synonyms":[],"level":5,"theme":"科學與數學","examples":[{"en":"She has loved astronomy since she was a child.","zh":"她從小就熱愛天文學。"},{"en":"In astronomy class, we learned how stars are born and die.","zh":"在天文學課堂上，我們學到了恆星如何誕生與消亡。"},{"en":"He bought a telescope to explore his passion for astronomy.","zh":"他買了一台望遠鏡來探索他對天文學的熱情。"}]},{"word":"asylum","pos":"n.","phonetic":"[əˈsaɪləm]","meaning":"庇護；避難所","definition":"protection given by a country to refugees, or a place of shelter","collocations":["seek asylum","political asylum","grant asylum"],"example":"The refugees sought asylum in a neighboring country.","exampleZh":"難民在鄰國尋求庇護。","synonyms":["refuge","shelter"],"level":6,"theme":"政治與法律","examples":[{"en":"The refugees sought asylum in a neighboring country.","zh":"難民在鄰國尋求庇護。"},{"en":"The frightened family fled the war and sought asylum abroad.","zh":"這個受驚的家庭逃離戰爭，並到國外尋求庇護。"},{"en":"The government finally granted asylum to the young writer.","zh":"政府最終給予那位年輕作家庇護。"}]},{"word":"athlete","pos":"n.","phonetic":"[ˈæθlit]","meaning":"運動員；體育選手","definition":"a person who competes in sports requiring physical strength or speed","collocations":["professional athlete","Olympic athlete","talented athlete"],"example":"The athlete trained hard for the Olympics.","exampleZh":"這位運動員為了奧運努力訓練。","synonyms":["sportsperson"],"level":2,"theme":"運動與休閒","examples":[{"en":"The athlete trained hard for the Olympics.","zh":"這位運動員為了奧運努力訓練。"},{"en":"A professional athlete must follow a strict diet and daily schedule.","zh":"職業運動員必須遵守嚴格的飲食和每日作息。"},{"en":"The talented young athlete broke the school running record.","zh":"這位有天分的年輕運動員打破了校內的賽跑紀錄。"}]},{"word":"athletic","pos":"adj.","phonetic":"[æθˈlɛtɪk]","meaning":"運動的；體格健壯的","definition":"relating to athletes or physically strong and fit","collocations":["athletic ability","athletic build","athletic events"],"example":"He has an athletic build from years of training.","exampleZh":"多年的訓練讓他擁有健壯的體格。","synonyms":["fit","sporty"],"level":3,"theme":"運動與休閒","examples":[{"en":"He has an athletic build from years of training.","zh":"多年的訓練讓他擁有健壯的體格。"},{"en":"Her natural athletic ability made her the star of the team.","zh":"她天生的運動能力使她成為隊上的明星。"},{"en":"The school holds several athletic events every autumn.","zh":"學校每年秋天都會舉辦幾項體育競賽。"}]},{"word":"atmosphere","pos":"n.","phonetic":"[ˈætməs͵fɪr]","meaning":"大氣層；氣氛","definition":"the layer of gases around a planet, or the mood of a place","collocations":["earth's atmosphere","relaxed atmosphere","create an atmosphere"],"example":"The candles created a warm, romantic atmosphere.","exampleZh":"蠟燭營造出溫暖浪漫的氣氛。","synonyms":["mood","ambiance"],"level":3,"theme":"自然與環境","examples":[{"en":"The candles created a warm, romantic atmosphere.","zh":"蠟燭營造出溫暖浪漫的氣氛。"},{"en":"Soft music and warm lights created a relaxed atmosphere in the room.","zh":"輕柔的音樂和溫暖的燈光在房間裡營造出輕鬆的氣氛。"},{"en":"The earth's atmosphere protects us from the sun's harmful rays.","zh":"地球的大氣層保護我們免受太陽有害的射線。"}]},{"word":"atom","pos":"n.","phonetic":"[ˈætəm]","meaning":"原子","definition":"the smallest unit of a chemical element","collocations":["split an atom","atom structure","single atom"],"example":"Every atom contains protons, neutrons, and electrons.","exampleZh":"每個原子都包含質子、中子和電子。","synonyms":[],"level":5,"theme":"科學與數學","examples":[{"en":"Every atom contains protons, neutrons, and electrons.","zh":"每個原子都包含質子、中子和電子。"},{"en":"Scientists released huge energy by learning how to split an atom.","zh":"科學家透過學會如何分裂原子而釋放出巨大的能量。"},{"en":"A single atom is far too small to see with our eyes.","zh":"單一個原子小到我們的肉眼根本看不見。"}]},{"word":"atomic","pos":"adj.","phonetic":"[əˈtɑmɪk]","meaning":"原子的；原子能的","definition":"relating to atoms or atomic energy","collocations":["atomic bomb","atomic energy","atomic number"],"example":"The atomic bomb changed the course of history.","exampleZh":"原子彈改變了歷史的走向。","synonyms":[],"level":5,"theme":"科學與數學","examples":[{"en":"The atomic bomb changed the course of history.","zh":"原子彈改變了歷史的走向。"},{"en":"Many countries now use atomic energy to produce electricity.","zh":"許多國家現在利用原子能來發電。"},{"en":"In chemistry, every element has its own atomic number.","zh":"在化學中，每種元素都有自己的原子序。"}]},{"word":"attach","pos":"v.","phonetic":"[əˈtætʃ]","meaning":"附加；連接；依附","definition":"to fasten or join one thing to another","collocations":["attach a file","attach importance to","attach a label"],"example":"Please attach your resume to the email.","exampleZh":"請將你的履歷附加到電子郵件中。","synonyms":["fasten","connect"],"level":3,"theme":"科技與媒體","examples":[{"en":"Please attach your resume to the email.","zh":"請將你的履歷附加到電子郵件中。"},{"en":"Remember to attach a label with your name onto your bag.","zh":"記得在你的包包上貼一張寫著名字的標籤。"},{"en":"Our teacher attaches great importance to reading every single day.","zh":"我們老師非常重視每天閱讀。"}]},{"word":"attack","pos":"v. / n.","phonetic":"[əˈtæk]","meaning":"攻擊；抨擊","definition":"to use violence or force against someone or something","collocations":["attack the enemy","under attack","heart attack"],"example":"The soldiers were ready to attack at dawn.","exampleZh":"士兵們準備在黎明時發動攻擊。","synonyms":["assault","strike"],"level":2,"theme":"政治與法律","examples":[{"en":"The soldiers were ready to attack at dawn.","zh":"士兵們準備在黎明時發動攻擊。"},{"en":"The farmer's crops were under attack from swarms of hungry insects.","zh":"農夫的作物遭到成群飢餓昆蟲的侵襲。"},{"en":"Eating healthily can lower your risk of a heart attack.","zh":"健康飲食可以降低你心臟病發作的風險。"}]},{"word":"attain","pos":"v.","phonetic":"[əˈten]","meaning":"達成；獲得","definition":"to succeed in achieving something after effort","collocations":["attain a goal","attain success","attain knowledge"],"example":"She worked hard to attain her career goals.","exampleZh":"她努力工作以達成她的職涯目標。","synonyms":["achieve","reach"],"level":5,"theme":"抽象概念","examples":[{"en":"She worked hard to attain her career goals.","zh":"她努力工作以達成她的職涯目標。"},{"en":"With daily practice, you can gradually attain fluency in a language.","zh":"透過每天練習，你就能逐漸達到流利使用一種語言的程度。"},{"en":"He finally attained his goal of running a full marathon.","zh":"他終於達成了跑完全程馬拉松的目標。"}]},{"word":"attempt","pos":"v. / n.","phonetic":"[əˈtɛmpt]","meaning":"嘗試；企圖","definition":"to try to do something, especially something difficult","collocations":["attempt to escape","make an attempt","final attempt"],"example":"He attempted to fix the computer himself.","exampleZh":"他嘗試自己修理電腦。","synonyms":["try","effort"],"level":3,"theme":"動作與行為","examples":[{"en":"He attempted to fix the computer himself.","zh":"他嘗試自己修理電腦。"},{"en":"On her final attempt, she cleared the high jump easily.","zh":"在最後一次嘗試中，她輕鬆地跳過了跳高的橫竿。"},{"en":"The trapped bird made several attempts to fly out the open window.","zh":"那隻受困的鳥兒好幾次試著飛出敞開的窗戶。"}]},{"word":"attend","pos":"v.","phonetic":"[əˈtɛnd]","meaning":"參加；出席；照料","definition":"to be present at an event or place","collocations":["attend a meeting","attend school","attend a wedding"],"example":"All employees must attend the training session.","exampleZh":"所有員工都必須參加這場訓練課程。","synonyms":["participate","go to"],"level":2,"theme":"教育與學習","examples":[{"en":"All employees must attend the training session.","zh":"所有員工都必須參加這場訓練課程。"},{"en":"Children in Taiwan must attend school until the age of fifteen.","zh":"台灣的孩子必須就學到十五歲。"},{"en":"We were delighted to attend our cousin's wedding last weekend.","zh":"我們很高興上週末參加了表親的婚禮。"}]},{"word":"attendance","pos":"n.","phonetic":"[əˈtɛndəns]","meaning":"出席；出席人數","definition":"the act of being present at an event, or the number of people present","collocations":["attendance rate","take attendance","poor attendance"],"example":"The teacher checks attendance every morning.","exampleZh":"老師每天早上都會點名。","synonyms":["presence"],"level":4,"theme":"教育與學習","examples":[{"en":"The teacher checks attendance every morning.","zh":"老師每天早上都會點名。"},{"en":"The club's poor attendance forced the teacher to cancel it.","zh":"社團出席率太差，迫使老師取消了它。"},{"en":"Our class kept a perfect attendance rate all semester long.","zh":"我們班整個學期都保持全勤的出席率。"}]},{"word":"attention","pos":"n.","phonetic":"[əˈtɛnʃən]","meaning":"注意；專注；關注","definition":"the act of directing focus toward something","collocations":["pay attention","attract attention","need attention"],"example":"Please pay attention to the safety instructions.","exampleZh":"請注意安全指示。","synonyms":["focus","notice"],"level":2,"theme":"抽象概念","examples":[{"en":"Please pay attention to the safety instructions.","zh":"請注意安全指示。"},{"en":"The bright poster attracted the attention of every passerby.","zh":"那張鮮豔的海報吸引了每位路人的注意。"},{"en":"These young seedlings need daily attention to grow well.","zh":"這些幼苗需要每天照料才能長得好。"}]},{"word":"attic","pos":"n.","phonetic":"[ˈætɪk]","meaning":"閣樓","definition":"a room or space just below the roof of a house","collocations":["dusty attic","store in the attic","attic window"],"example":"They found old photographs in the attic.","exampleZh":"他們在閣樓裡發現了舊照片。","synonyms":["loft"],"level":3,"theme":"居家與生活","examples":[{"en":"They found old photographs in the attic.","zh":"他們在閣樓裡發現了舊照片。"},{"en":"We store all our winter clothes up in the dusty attic.","zh":"我們把所有冬天的衣物存放在滿是灰塵的閣樓裡。"},{"en":"A tiny attic window let a single beam of sunlight inside.","zh":"一扇小小的閣樓窗戶讓一道陽光透了進來。"}]},{"word":"attitude","pos":"n.","phonetic":"[ˈætə͵tjud]","meaning":"態度；看法","definition":"a settled way of thinking or feeling about something","collocations":["positive attitude","change one's attitude","attitude toward"],"example":"Her positive attitude helped the whole team.","exampleZh":"她積極的態度幫助了整個團隊。","synonyms":["outlook","mindset"],"level":3,"theme":"情緒與感受","examples":[{"en":"Her positive attitude helped the whole team.","zh":"她積極的態度幫助了整個團隊。"},{"en":"A positive attitude can help you overcome many difficulties in life.","zh":"正面的態度能幫助你克服人生中許多困難。"},{"en":"His attitude toward homework changed after his grades improved.","zh":"成績進步後，他對作業的態度改變了。"}]},{"word":"attorney","pos":"n.","phonetic":"[əˈtɝnɪ]","meaning":"律師","definition":"a person legally qualified to represent clients in court","collocations":["hire an attorney","attorney general","defense attorney"],"example":"She hired an attorney to handle the contract.","exampleZh":"她請了一位律師處理這份合約。","synonyms":["lawyer"],"level":5,"theme":"政治與法律","examples":[{"en":"She hired an attorney to handle the contract.","zh":"她請了一位律師處理這份合約。"},{"en":"The family hired an attorney to settle the property dispute.","zh":"這家人聘請了一位律師來解決財產糾紛。"},{"en":"The defense attorney argued that his client was completely innocent.","zh":"辯護律師主張他的當事人完全無辜。"}]},{"word":"attract","pos":"v.","phonetic":"[əˈtrækt]","meaning":"吸引","definition":"to cause someone or something to be drawn toward","collocations":["attract attention","attract tourists","attract customers"],"example":"The museum attracts thousands of visitors each year.","exampleZh":"這座博物館每年吸引數千名遊客。","synonyms":["draw","appeal to"],"level":3,"theme":"動作與行為","examples":[{"en":"The museum attracts thousands of visitors each year.","zh":"這座博物館每年吸引數千名遊客。"},{"en":"The colorful night market attracts tourists from all over the world.","zh":"這個色彩繽紛的夜市吸引了來自世界各地的觀光客。"},{"en":"Bright flowers attract bees and butterflies to the garden.","zh":"鮮豔的花朵把蜜蜂和蝴蝶吸引到花園裡。"}]},{"word":"attraction","pos":"n.","phonetic":"[əˈtrækʃən]","meaning":"吸引力；景點","definition":"the quality of being interesting or appealing, or a place people visit","collocations":["tourist attraction","main attraction","physical attraction"],"example":"The waterfall is the main attraction of the park.","exampleZh":"瀑布是這座公園的主要景點。","synonyms":["appeal"],"level":3,"theme":"交通與旅行","examples":[{"en":"The waterfall is the main attraction of the park.","zh":"瀑布是這座公園的主要景點。"},{"en":"The ancient temple is the town's most popular tourist attraction.","zh":"那座古老的廟宇是這個小鎮最受歡迎的觀光景點。"},{"en":"The main attraction of the fair was the giant Ferris wheel.","zh":"這場園遊會的主要焦點是那座巨大的摩天輪。"}]},{"word":"attractive","pos":"adj.","phonetic":"[əˈtræktɪv]","meaning":"有吸引力的；迷人的","definition":"pleasing or appealing, especially in appearance","collocations":["attractive offer","attractive appearance","financially attractive"],"example":"The company offered an attractive salary package.","exampleZh":"這間公司提供了有吸引力的薪資方案。","synonyms":["appealing","charming"],"level":2,"theme":"服裝與外表","examples":[{"en":"The company offered an attractive salary package.","zh":"這間公司提供了有吸引力的薪資方案。"},{"en":"The travel agency made us an attractive offer for the summer tour.","zh":"旅行社為暑假旅遊提供了我們一個很吸引人的優惠。"},{"en":"The garden looks especially attractive when the roses are in bloom.","zh":"當玫瑰盛開時，這座花園顯得格外迷人。"}]},{"word":"attribute","pos":"n. / v.","phonetic":"[ˈætrə͵bjut]","meaning":"特質；歸因於","definition":"a quality or feature of someone or something, or to regard as caused by","collocations":["key attribute","attribute success to","physical attribute"],"example":"Patience is an important attribute for a teacher.","exampleZh":"耐心是老師的重要特質。","synonyms":["quality","trait"],"level":5,"theme":"抽象概念","examples":[{"en":"Patience is an important attribute for a teacher.","zh":"耐心是老師的重要特質。"},{"en":"She attributes her success to her parents' constant support.","zh":"她把自己的成功歸功於父母不斷的支持。"},{"en":"Curiosity is a key attribute of every good scientist.","zh":"好奇心是每位優秀科學家的一項關鍵特質。"}]},{"word":"audience","pos":"n.","phonetic":"[ˈɔdɪəns]","meaning":"觀眾；聽眾","definition":"a group of people watching or listening to a performance","collocations":["large audience","audience reaction","target audience"],"example":"The audience clapped loudly after the concert.","exampleZh":"演唱會結束後觀眾熱烈鼓掌。","synonyms":["spectators","viewers"],"level":2,"theme":"藝術與音樂","examples":[{"en":"The audience clapped loudly after the concert.","zh":"演唱會結束後觀眾熱烈鼓掌。"},{"en":"A large audience gathered in the square to watch the outdoor movie.","zh":"一大群觀眾聚集在廣場上觀賞戶外電影。"},{"en":"The comedian carefully watched the audience reaction to each joke.","zh":"那位喜劇演員仔細觀察著觀眾對每個笑話的反應。"}]},{"word":"audio","pos":"adj. / n.","phonetic":"[ˈɔdɪ͵o]","meaning":"音訊的；聲音的","definition":"relating to sound, especially recorded sound","collocations":["audio equipment","audio file","audio quality"],"example":"The audio quality of the recording was excellent.","exampleZh":"這段錄音的音質非常好。","synonyms":["sound"],"level":3,"theme":"科技與媒體","examples":[{"en":"The audio quality of the recording was excellent.","zh":"這段錄音的音質非常好。"},{"en":"She sent me an audio file of the lecture she recorded.","zh":"她傳給我一個她錄下的演講音檔。"},{"en":"The club borrowed audio equipment for the school concert.","zh":"社團為學校音樂會借了音響設備。"}]},{"word":"audition","pos":"n. / v.","phonetic":"[ɔˈdɪʃən]","meaning":"試演；試鏡","definition":"a short performance to test the suitability of a performer","collocations":["go to an audition","audition for a role","successful audition"],"example":"She auditioned for the lead role in the play.","exampleZh":"她試鏡爭取這齣戲的主角。","synonyms":["tryout"],"level":4,"theme":"藝術與音樂","examples":[{"en":"She auditioned for the lead role in the play.","zh":"她試鏡爭取這齣戲的主角。"},{"en":"He felt nervous before his audition for the school choir.","zh":"參加學校合唱團的試唱前，他感到緊張。"},{"en":"After a successful audition, she won the main role in the play.","zh":"經過一場成功的試鏡後，她得到了戲劇的主角。"}]},{"word":"aunt","pos":"n.","phonetic":"[ænt]","meaning":"阿姨；姑姑；伯母；嬸嬸","definition":"the sister of one's parent, or the wife of one's uncle","collocations":["aunt and uncle","visit my aunt","favorite aunt"],"example":"My aunt often brings us fruit from her garden.","exampleZh":"我阿姨常常帶她花園種的水果給我們。","synonyms":[],"level":1,"theme":"人物與家庭","examples":[{"en":"My aunt often brings us fruit from her garden.","zh":"我阿姨常常帶她花園種的水果給我們。"},{"en":"During the holidays, we always visit my aunt in the countryside.","zh":"每逢假期，我們總會去鄉下探望我的阿姨。"},{"en":"My favorite aunt patiently taught me how to bake cookies.","zh":"我最喜歡的阿姨耐心地教我如何烤餅乾。"}]},{"word":"author","pos":"n.","phonetic":"[ˈɔθɚ]","meaning":"作者；作家","definition":"a person who writes a book or article","collocations":["best-selling author","the author of","famous author"],"example":"The author signed copies of her new novel.","exampleZh":"這位作者為她的新小說簽名。","synonyms":["writer"],"level":2,"theme":"藝術與音樂","examples":[{"en":"The author signed copies of her new novel.","zh":"這位作者為她的新小說簽名。"},{"en":"The best-selling author gave a talk at our school library.","zh":"那位暢銷作家在我們學校圖書館發表了一場演講。"},{"en":"She is the author of several popular children's books.","zh":"她是好幾本受歡迎童書的作者。"}]},{"word":"authority","pos":"n.","phonetic":"[əˈθɔrətɪ]","meaning":"權威；當局；權力","definition":"the power to give orders or make decisions, or a governing body","collocations":["local authority","in authority","have authority over"],"example":"The city authority approved the new construction plan.","exampleZh":"市政當局批准了這項新的建設計畫。","synonyms":["power","government"],"level":4,"theme":"政治與法律","examples":[{"en":"The city authority approved the new construction plan.","zh":"市政當局批准了這項新的建設計畫。"},{"en":"The local authority built a new bike path along the river.","zh":"地方當局沿著河邊興建了一條新的自行車道。"},{"en":"A teacher naturally has authority over the students in the classroom.","zh":"老師在教室裡對學生自然擁有管理權。"}]},{"word":"autobiography","pos":"n.","phonetic":"[͵ɔtəbaɪˈɑgrəfɪ]","meaning":"自傳","definition":"an account of a person's life written by that person","collocations":["write an autobiography","publish an autobiography","read an autobiography"],"example":"The singer published her autobiography last year.","exampleZh":"這位歌手去年出版了她的自傳。","synonyms":[],"level":5,"theme":"藝術與音樂","examples":[{"en":"The singer published her autobiography last year.","zh":"這位歌手去年出版了她的自傳。"},{"en":"In his autobiography, the coach describes his difficult childhood.","zh":"在他的自傳中，這位教練描述了他艱苦的童年。"},{"en":"Reading her autobiography inspired me to keep chasing my dreams.","zh":"讀她的自傳激勵我持續追逐我的夢想。"}]},{"word":"automatic","pos":"adj.","phonetic":"[͵ɔtəˈmætɪk]","meaning":"自動的；不假思索的","definition":"working by itself with little or no direct human control","collocations":["automatic door","automatic response","fully automatic"],"example":"The automatic door opened as we approached.","exampleZh":"我們一走近，自動門就開了。","synonyms":["mechanical"],"level":3,"theme":"科技與媒體","examples":[{"en":"The automatic door opened as we approached.","zh":"我們一走近，自動門就開了。"},{"en":"The library uses a fully automatic system for borrowing books.","zh":"這座圖書館使用一套全自動的借書系統。"},{"en":"Smiling became an automatic response whenever she saw the baby.","zh":"每當她看到那個寶寶，微笑就成了不假思索的反應。"}]},{"word":"automobile","pos":"n.","phonetic":"[ˈɔtəmə͵bil]","meaning":"汽車","definition":"a motor vehicle for carrying passengers","collocations":["automobile industry","automobile factory","electric automobile"],"example":"The automobile industry is developing electric cars.","exampleZh":"汽車產業正在發展電動車。","synonyms":["car","vehicle"],"level":3,"theme":"交通與旅行","examples":[{"en":"The automobile industry is developing electric cars.","zh":"汽車產業正在發展電動車。"},{"en":"Many workers in this town are employed at an automobile factory.","zh":"這個鎮上有許多工人在一家汽車工廠工作。"},{"en":"Electric automobiles are becoming more common on our city streets.","zh":"電動汽車在我們的城市街道上變得越來越常見。"}]},{"word":"autumn","pos":"n.","phonetic":"[ˈɔtəm]","meaning":"秋天","definition":"the season between summer and winter","collocations":["autumn leaves","in autumn","autumn breeze"],"example":"The leaves turn golden in autumn.","exampleZh":"秋天樹葉會變成金黃色。","synonyms":["fall"],"level":1,"theme":"天氣與季節","examples":[{"en":"The leaves turn golden in autumn.","zh":"秋天樹葉會變成金黃色。"},{"en":"A gentle autumn breeze scattered the fallen leaves everywhere.","zh":"一陣柔和的秋風把落葉吹得到處都是。"},{"en":"We really love hiking in the mountains in autumn.","zh":"我們非常喜歡在秋天到山裡健行。"}]},{"word":"available","pos":"adj.","phonetic":"[əˈveləbl̩]","meaning":"可用的；有空的","definition":"able to be obtained, used, or reached","collocations":["available online","available time","tickets available"],"example":"The manager is not available until three o'clock.","exampleZh":"經理三點前都沒空。","synonyms":["accessible","free"],"level":2,"theme":"抽象概念","examples":[{"en":"The manager is not available until three o'clock.","zh":"經理三點前都沒空。"},{"en":"There are still a few concert tickets available for Saturday night.","zh":"星期六晚上的音樂會還有幾張票可買。"},{"en":"The full report is now available online completely free.","zh":"完整的報告現在可以在網路上完全免費取得。"}]},{"word":"avenue","pos":"n.","phonetic":"[ˈævə͵nju]","meaning":"大道；途徑","definition":"a broad street, or a way of approaching a problem","collocations":["main avenue","new avenue for","tree-lined avenue"],"example":"They walked down the wide, tree-lined avenue.","exampleZh":"他們走在種滿樹的寬闊大道上。","synonyms":["street","route"],"level":4,"theme":"交通與旅行","examples":[{"en":"They walked down the wide, tree-lined avenue.","zh":"他們走在種滿樹的寬闊大道上。"},{"en":"Shops of every kind line the busy main avenue downtown.","zh":"各式各樣的商店排列在市中心繁忙的大道兩旁。"},{"en":"Learning to code opened a new avenue for her creativity.","zh":"學習寫程式為她的創造力開啟了一條新的途徑。"}]},{"word":"average","pos":"adj. / n.","phonetic":"[ˈævərɪdʒ]","meaning":"平均的；一般的；平均值","definition":"a standard or typical amount, or found by adding values and dividing","collocations":["on average","above average","calculate the average"],"example":"On average, students study three hours a day.","exampleZh":"平均而言，學生每天讀書三小時。","synonyms":["typical","mean"],"level":2,"theme":"科學與數學","examples":[{"en":"On average, students study three hours a day.","zh":"平均而言，學生每天讀書三小時。"},{"en":"Her test scores are well above average this semester.","zh":"她這學期的考試成績遠高於平均水準。"},{"en":"We calculated the average height of everyone in our class.","zh":"我們計算了全班每個人的平均身高。"}]},{"word":"aviation","pos":"n.","phonetic":"[͵evɪˈeʃən]","meaning":"航空；飛行","definition":"the operation of aircraft and the industry surrounding it","collocations":["civil aviation","aviation industry","aviation safety"],"example":"He works in the aviation industry as an engineer.","exampleZh":"他在航空業擔任工程師。","synonyms":["flying"],"level":5,"theme":"交通與旅行","examples":[{"en":"He works in the aviation industry as an engineer.","zh":"他在航空業擔任工程師。"},{"en":"Strict international rules are in place to ensure aviation safety.","zh":"有嚴格的國際規定用以確保航空安全。"},{"en":"He hopes to build a lasting career in the aviation industry.","zh":"他希望在航空業闖出一番長久的事業。"}]},{"word":"avoid","pos":"v.","phonetic":"[əˈvɔɪd]","meaning":"避免；躲避","definition":"to stay away from or prevent something from happening","collocations":["avoid danger","avoid eye contact","avoid mistakes"],"example":"Drivers should avoid using their phones while driving.","exampleZh":"駕駛人應避免在開車時使用手機。","synonyms":["evade","prevent"],"level":2,"theme":"動作與行為","examples":[{"en":"Drivers should avoid using their phones while driving.","zh":"駕駛人應避免在開車時使用手機。"},{"en":"Checking your work twice helps you avoid careless mistakes.","zh":"把作業檢查兩遍能幫助你避免粗心的錯誤。"},{"en":"The shy boy avoided eye contact throughout the whole interview.","zh":"那個害羞的男孩在整場面試中都避免眼神接觸。"}]},{"word":"await","pos":"v.","phonetic":"[əˈwet]","meaning":"等待","definition":"to wait for something or someone","collocations":["await a reply","eagerly await","await further instructions"],"example":"We eagerly await the results of the competition.","exampleZh":"我們殷切等待比賽的結果。","synonyms":["wait for"],"level":5,"theme":"動作與行為","examples":[{"en":"We eagerly await the results of the competition.","zh":"我們殷切等待比賽的結果。"},{"en":"Please stay in your seats and await further instructions.","zh":"請待在座位上，等候進一步的指示。"},{"en":"She anxiously awaits a reply to her college application.","zh":"她焦急地等待著大學申請的回覆。"}]},{"word":"awake","pos":"adj. / v.","phonetic":"[əˈwek]","meaning":"醒著的；喚醒","definition":"not asleep, or to stop sleeping","collocations":["stay awake","wide awake","awake early"],"example":"He stayed awake all night studying for the test.","exampleZh":"他為了考試整晚沒睡。","synonyms":["conscious"],"level":2,"theme":"身體與健康","examples":[{"en":"He stayed awake all night studying for the test.","zh":"他為了考試整晚沒睡。"},{"en":"The strong coffee kept her wide awake for the whole night.","zh":"那杯濃咖啡讓她整晚都非常清醒。"},{"en":"I usually awake early enough to watch the beautiful sunrise.","zh":"我通常醒得夠早，足以觀看美麗的日出。"}]},{"word":"award","pos":"n. / v.","phonetic":"[əˈwɔrd]","meaning":"獎項；獎勵；頒發","definition":"a prize given for achievement, or to give such a prize","collocations":["win an award","award ceremony","award a prize"],"example":"She received an award for her outstanding research.","exampleZh":"她因傑出的研究獲得一項獎項。","synonyms":["prize","honor"],"level":3,"theme":"教育與學習","examples":[{"en":"She received an award for her outstanding research.","zh":"她因傑出的研究獲得一項獎項。"},{"en":"The short film won an award at the international festival.","zh":"這部短片在國際影展上贏得了一座獎項。"},{"en":"The judges awarded first prize to the youngest contestant.","zh":"評審把首獎頒給了最年輕的參賽者。"}]},{"word":"aware","pos":"adj.","phonetic":"[əˈwɛr]","meaning":"察覺到的；意識到的","definition":"having knowledge or perception of a situation","collocations":["aware of","become aware","fully aware"],"example":"She was not aware of the change in schedule.","exampleZh":"她並不知道時間表有變動。","synonyms":["conscious","informed"],"level":3,"theme":"抽象概念","examples":[{"en":"She was not aware of the change in schedule.","zh":"她並不知道時間表有變動。"},{"en":"Drivers should be fully aware of children playing near the school.","zh":"駕駛人應充分留意在學校附近玩耍的孩童。"},{"en":"I wasn't aware that the museum closes on Mondays.","zh":"我不知道這間博物館星期一休館。"}]},{"word":"awareness","pos":"n.","phonetic":"[əˈwɛrnəs]","meaning":"意識；認知；覺察","definition":"knowledge or perception of a situation or fact","collocations":["raise awareness","public awareness","environmental awareness"],"example":"The campaign aims to raise awareness about recycling.","exampleZh":"這項活動旨在提高大眾對回收的意識。","synonyms":["consciousness"],"level":4,"theme":"抽象概念","examples":[{"en":"The campaign aims to raise awareness about recycling.","zh":"這項活動旨在提高大眾對回收的意識。"},{"en":"The students organized a fun event to raise environmental awareness.","zh":"學生們舉辦了一場有趣的活動來提升環保意識。"},{"en":"Public awareness of healthy eating has grown in recent years.","zh":"近年來大眾對健康飲食的認知已經提高。"}]},{"word":"away","pos":"adv.","phonetic":"[əˈwe]","meaning":"離開；遠離","definition":"to or at a distance from a place or person","collocations":["far away","go away","right away"],"example":"The beach is only a short walk away.","exampleZh":"海灘只要走一小段路就到了。","synonyms":["off"],"level":1,"theme":"時間與空間","examples":[{"en":"The beach is only a short walk away.","zh":"海灘只要走一小段路就到了。"},{"en":"The kind nurse promised to come and help right away.","zh":"那位親切的護士答應會馬上過來幫忙。"},{"en":"His quiet hometown is far away from the noisy city.","zh":"他寧靜的家鄉離喧鬧的城市很遠。"}]},{"word":"awful","pos":"adj.","phonetic":"[ˈɔfl̩]","meaning":"糟糕的；可怕的","definition":"very bad or unpleasant","collocations":["awful weather","feel awful","awful mistake"],"example":"The weather was awful during our trip.","exampleZh":"我們旅行期間天氣糟透了。","synonyms":["terrible","dreadful"],"level":2,"theme":"性質與描述","examples":[{"en":"The weather was awful during our trip.","zh":"我們旅行期間天氣糟透了。"},{"en":"I felt awful after eating far too much at the party.","zh":"在派對上吃太多後，我覺得很難受。"},{"en":"Losing his friend's borrowed book was an awful mistake.","zh":"弄丟朋友借他的書是個糟糕的錯誤。"}]},{"word":"awfully","pos":"adv.","phonetic":"[ˈɔflɪ]","meaning":"非常地；極糟地","definition":"very or extremely, often used informally","collocations":["awfully sorry","awfully cold","awfully nice"],"example":"I'm awfully sorry for being late again.","exampleZh":"對於又遲到了，我感到非常抱歉。","synonyms":["extremely","very"],"level":3,"theme":"性質與描述","examples":[{"en":"I'm awfully sorry for being late again.","zh":"對於又遲到了，我感到非常抱歉。"},{"en":"It was awfully cold outside, so we all stayed indoors.","zh":"外面冷得要命，所以我們全都待在室內。"},{"en":"The new neighbors have been awfully nice to our family.","zh":"新鄰居對我們一家非常友善。"}]},{"word":"awhile","pos":"adv.","phonetic":"[əˈhwaɪl]","meaning":"片刻；一會兒","definition":"for a short period of time","collocations":["rest awhile","stay awhile","wait awhile"],"example":"Let's sit here and rest awhile before continuing.","exampleZh":"讓我們坐在這裡休息一會兒再繼續走。","synonyms":["briefly"],"level":4,"theme":"時間與空間","examples":[{"en":"Let's sit here and rest awhile before continuing.","zh":"讓我們坐在這裡休息一會兒再繼續走。"},{"en":"Why don't you stay awhile and have some hot tea?","zh":"你何不多待一會兒，喝點熱茶呢？"},{"en":"We waited awhile at the bus stop before the rain finally stopped.","zh":"我們在公車站等了一會兒，雨才終於停。"}]},{"word":"awkward","pos":"adj.","phonetic":"[ˈɔkwɚd]","meaning":"尷尬的；笨拙的","definition":"causing embarrassment or difficult to handle","collocations":["awkward silence","awkward situation","feel awkward"],"example":"There was an awkward silence after her question.","exampleZh":"她問完問題後出現了一陣尷尬的沉默。","synonyms":["clumsy","uncomfortable"],"level":4,"theme":"情緒與感受","examples":[{"en":"There was an awkward silence after her question.","zh":"她問完問題後出現了一陣尷尬的沉默。"},{"en":"I felt awkward when I suddenly forgot my classmate's name.","zh":"我突然忘了同學的名字時覺得很尷尬。"},{"en":"Meeting his former teacher put him in an awkward situation.","zh":"遇見他以前的老師讓他陷入尷尬的處境。"}]},{"word":"axe","pos":"n. / v.","phonetic":"[æks]","meaning":"斧頭；削減","definition":"a tool with a blade for chopping wood, or to cut drastically","collocations":["chop with an axe","swing an axe","axe a project"],"example":"He used an axe to chop the firewood.","exampleZh":"他用斧頭劈柴。","synonyms":["hatchet"],"level":3,"theme":"其他","examples":[{"en":"He used an axe to chop the firewood.","zh":"他用斧頭劈柴。"},{"en":"After careful thought, the company decided to axe the expensive project.","zh":"經過審慎考慮後，公司決定砍掉這個昂貴的專案。"},{"en":"He swung the heavy axe and split the log in two.","zh":"他揮動沉重的斧頭，把木頭劈成兩半。"}]},{"word":"axis","pos":"n.","phonetic":"[ˈæksɪs]","meaning":"軸；軸線","definition":"an imaginary line around which something rotates, or a reference line in a graph","collocations":["earth's axis","x-axis","central axis"],"example":"The Earth rotates on its axis every twenty-four hours.","exampleZh":"地球每二十四小時繞其軸自轉一圈。","synonyms":[],"level":5,"theme":"科學與數學","examples":[{"en":"The Earth rotates on its axis every twenty-four hours.","zh":"地球每二十四小時繞其軸自轉一圈。"},{"en":"On this graph, time is shown along the horizontal x-axis.","zh":"在這張圖上，時間標示在水平的 x 軸上。"},{"en":"The spinning top wobbled slowly around its central axis.","zh":"那個旋轉的陀螺繞著它的中心軸緩緩搖晃。"}]},{"word":"baby","pos":"n.","phonetic":"[ˈbebɪ]","meaning":"嬰兒；寶寶","definition":"a very young child","collocations":["a newborn baby","baby food","have a baby"],"example":"The baby slept peacefully in her crib.","exampleZh":"嬰兒在嬰兒床裡安詳地睡著。","synonyms":["infant"],"level":1,"theme":"人物與家庭","examples":[{"en":"The baby slept peacefully in her crib.","zh":"嬰兒在嬰兒床裡安詳地睡著。"},{"en":"The gentle nurse carefully held the tiny newborn baby.","zh":"那位溫柔的護士小心地抱著那個小小的新生兒。"},{"en":"My neighbor is expecting to have a baby next month.","zh":"我的鄰居預計下個月生寶寶。"}]},{"word":"back","pos":"n. / adv. / v.","phonetic":"[bæk]","meaning":"背部；後面；支持","definition":"the rear part of the body or something, or to support someone","collocations":["back pain","go back","back someone up"],"example":"He hurt his back while lifting the box.","exampleZh":"他搬箱子時傷了背部。","synonyms":["support"],"level":1,"theme":"身體與健康","examples":[{"en":"He hurt his back while lifting the box.","zh":"他搬箱子時傷了背部。"},{"en":"She waved goodbye and walked back to her classroom.","zh":"她揮手道別，走回她的教室。"},{"en":"My grandfather often suffers from back pain after gardening.","zh":"我的祖父在做完園藝後常常為背痛所苦。"}]},{"word":"background","pos":"n.","phonetic":"[ˈbækˌgraʊnd]","meaning":"背景；出身","definition":"the details of a person's life or the setting behind something","collocations":["family background","background information","background music"],"example":"Her academic background helped her get the job.","exampleZh":"她的學術背景幫助她得到這份工作。","synonyms":["backdrop"],"level":3,"theme":"抽象概念","examples":[{"en":"Her academic background helped her get the job.","zh":"她的學術背景幫助她得到這份工作。"},{"en":"Soft background music helped the students relax during the exam.","zh":"輕柔的背景音樂幫助學生在考試時放鬆。"},{"en":"Please read the background information before joining the discussion.","zh":"請在加入討論之前先閱讀這些背景資訊。"}]},{"word":"bacteria","pos":"n.","phonetic":"[bækˈtɪrɪə]","meaning":"細菌","definition":"microscopic organisms that can cause disease","collocations":["harmful bacteria","kill bacteria","bacteria grow"],"example":"Washing your hands can remove harmful bacteria.","exampleZh":"洗手可以去除有害的細菌。","synonyms":["germs"],"level":4,"theme":"科學與數學","examples":[{"en":"Washing your hands can remove harmful bacteria.","zh":"洗手可以去除有害的細菌。"},{"en":"Harmful bacteria can grow quickly in warm, moist food.","zh":"有害的細菌會在溫熱潮濕的食物中迅速繁殖。"},{"en":"Boiling the water helps kill the bacteria inside it.","zh":"把水煮沸有助於殺死其中的細菌。"}]},{"word":"bad","pos":"adj.","phonetic":"[bæd]","meaning":"壞的；不好的","definition":"not good in quality or character","collocations":["bad weather","bad habit","feel bad"],"example":"The weather was too bad to go hiking.","exampleZh":"天氣太糟了，無法去健行。","synonyms":["poor","terrible"],"level":1,"theme":"性質與描述","examples":[{"en":"The weather was too bad to go hiking.","zh":"天氣太糟了，無法去健行。"},{"en":"Biting your nails is a really bad habit.","zh":"咬指甲是一個很不好的習慣。"},{"en":"I feel bad about forgetting my friend's birthday.","zh":"我對於忘記朋友的生日感到很過意不去。"}]},{"word":"badge","pos":"n.","phonetic":"[bædʒ]","meaning":"徽章；證章","definition":"a small sign worn to show identity or achievement","collocations":["wear a badge","name badge","earn a badge"],"example":"Every employee must wear a badge at work.","exampleZh":"每位員工上班時都必須配戴識別證。","synonyms":["emblem"],"level":3,"theme":"工作與職業","examples":[{"en":"Every employee must wear a badge at work.","zh":"每位員工上班時都必須配戴識別證。"},{"en":"Each visitor must wear a name badge inside the laboratory.","zh":"每位訪客在實驗室內都必須配戴名牌徽章。"},{"en":"The scout earned a badge for learning first aid.","zh":"那名童軍因為學會急救而獲得了一枚徽章。"}]},{"word":"badly","pos":"adv.","phonetic":"[ˈbædlɪ]","meaning":"糟糕地；嚴重地","definition":"in a poor or severe manner","collocations":["badly injured","behave badly","need badly"],"example":"He was badly injured in the accident.","exampleZh":"他在意外中受了重傷。","synonyms":["poorly","severely"],"level":2,"theme":"性質與描述","examples":[{"en":"He was badly injured in the accident.","zh":"他在意外中受了重傷。"},{"en":"The team played badly and lost the final match.","zh":"那支隊伍表現得很糟糕，輸掉了決賽。"},{"en":"After the earthquake, the village badly needed clean water.","zh":"地震過後，那座村莊迫切地需要乾淨的水。"}]},{"word":"bag","pos":"n.","phonetic":"[bæg]","meaning":"袋子；提包","definition":"a container made of flexible material for carrying things","collocations":["shopping bag","school bag","pack a bag"],"example":"She packed her bag before the trip.","exampleZh":"她在旅行前打包好行李袋。","synonyms":["sack"],"level":1,"theme":"居家與生活","examples":[{"en":"She packed her bag before the trip.","zh":"她在旅行前打包好行李袋。"},{"en":"He forgot his school bag on the train this morning.","zh":"他今天早上把書包忘在火車上了。"},{"en":"Remember to bring a reusable shopping bag to the store.","zh":"記得帶一個可重複使用的購物袋去商店。"}]},{"word":"baggage","pos":"n.","phonetic":"[ˈbægɪdʒ]","meaning":"行李","definition":"suitcases and bags used for traveling","collocations":["baggage claim","check baggage","carry baggage"],"example":"We waited an hour to collect our baggage.","exampleZh":"我們等了一小時才拿到行李。","synonyms":["luggage"],"level":3,"theme":"交通與旅行","examples":[{"en":"We waited an hour to collect our baggage.","zh":"我們等了一小時才拿到行李。"},{"en":"Passengers can check their baggage at the front counter.","zh":"旅客可以在前方櫃檯托運他們的行李。"},{"en":"Our heavy baggage made walking through the airport exhausting.","zh":"我們沉重的行李讓穿越機場變得非常累人。"}]},{"word":"bake","pos":"v.","phonetic":"[bek]","meaning":"烘烤","definition":"to cook food using dry heat in an oven","collocations":["bake bread","bake a cake","bake at 350 degrees"],"example":"My mother likes to bake cookies on weekends.","exampleZh":"我媽媽喜歡在週末烤餅乾。","synonyms":["roast"],"level":2,"theme":"食物與烹飪","examples":[{"en":"My mother likes to bake cookies on weekends.","zh":"我媽媽喜歡在週末烤餅乾。"},{"en":"We plan to bake bread together this Sunday afternoon.","zh":"我們打算這個星期天下午一起烤麵包。"},{"en":"Bake the cake at 350 degrees for thirty minutes.","zh":"把蛋糕以三百五十度烤三十分鐘。"}]},{"word":"bakery","pos":"n.","phonetic":"[ˈbekərɪ]","meaning":"麵包店","definition":"a shop that makes and sells bread and cakes","collocations":["local bakery","bakery shop","fresh from the bakery"],"example":"There is a small bakery near my house.","exampleZh":"我家附近有一家小麵包店。","synonyms":[],"level":2,"theme":"食物與烹飪","examples":[{"en":"There is a small bakery near my house.","zh":"我家附近有一家小麵包店。"},{"en":"The local bakery sells fresh croissants every morning.","zh":"那家在地的麵包店每天早上都販售新鮮的可頌。"},{"en":"The whole street smelled of bread from the bakery.","zh":"整條街都飄著從麵包店傳來的麵包香。"}]},{"word":"balance","pos":"n. / v.","phonetic":"[ˈbæləns]","meaning":"平衡；餘額","definition":"a state of steadiness or an even distribution of weight","collocations":["lose balance","balance a budget","keep your balance"],"example":"She lost her balance and almost fell.","exampleZh":"她失去平衡，差點跌倒。","synonyms":["equilibrium"],"level":3,"theme":"性質與描述","examples":[{"en":"She lost her balance and almost fell.","zh":"她失去平衡，差點跌倒。"},{"en":"A good diet helps you keep a healthy balance.","zh":"良好的飲食有助於你維持健康的平衡。"},{"en":"The government struggled to balance the national budget this year.","zh":"政府今年費盡力氣要讓國家預算收支平衡。"}]},{"word":"balcony","pos":"n.","phonetic":"[ˈbælkənɪ]","meaning":"陽台","definition":"a platform on the outside of a building with a rail","collocations":["sit on the balcony","balcony view","step onto the balcony"],"example":"We had coffee on the balcony every morning.","exampleZh":"我們每天早上都在陽台喝咖啡。","synonyms":["terrace"],"level":3,"theme":"居家與生活","examples":[{"en":"We had coffee on the balcony every morning.","zh":"我們每天早上都在陽台喝咖啡。"},{"en":"She grows small pots of herbs on her balcony.","zh":"她在陽台上種了幾小盆香草。"},{"en":"From the balcony we could see the entire harbor.","zh":"從陽台上我們可以看見整個港口。"}]},{"word":"bald","pos":"adj.","phonetic":"[bɔld]","meaning":"禿頭的","definition":"having no hair on the head","collocations":["go bald","bald head","bald spot"],"example":"His father went bald in his thirties.","exampleZh":"他父親三十幾歲就禿頭了。","synonyms":[],"level":3,"theme":"服裝與外表","examples":[{"en":"His father went bald in his thirties.","zh":"他父親三十幾歲就禿頭了。"},{"en":"The old man had a shiny bald head.","zh":"那位老人有一顆光亮的禿頭。"},{"en":"Stress may cause some people to go bald early.","zh":"壓力可能使某些人提早禿頭。"}]},{"word":"ball","pos":"n.","phonetic":"[bɔl]","meaning":"球；舞會","definition":"a round object used in games","collocations":["throw a ball","play ball","kick the ball"],"example":"The children were playing ball in the park.","exampleZh":"孩子們在公園裡玩球。","synonyms":[],"level":1,"theme":"運動與休閒","examples":[{"en":"The children were playing ball in the park.","zh":"孩子們在公園裡玩球。"},{"en":"He threw the ball across the yard to his dog.","zh":"他把球扔過院子丟給他的狗。"},{"en":"The players kicked the ball toward the goal.","zh":"球員們把球踢向球門。"}]},{"word":"balloon","pos":"n.","phonetic":"[bəˈlun]","meaning":"氣球","definition":"a colored rubber bag filled with air or gas","collocations":["blow up a balloon","hot air balloon","pop a balloon"],"example":"The children released colorful balloons into the sky.","exampleZh":"孩子們把五顏六色的氣球放到天空中。","synonyms":[],"level":2,"theme":"其他","examples":[{"en":"The children released colorful balloons into the sky.","zh":"孩子們把五顏六色的氣球放到天空中。"},{"en":"The clown blew up a red balloon for the child.","zh":"小丑為那個孩子吹起一顆紅色的氣球。"},{"en":"We watched a hot air balloon rise into the sky.","zh":"我們看著一個熱氣球升上天空。"}]},{"word":"ban","pos":"v. / n.","phonetic":"[bæn]","meaning":"禁止；禁令","definition":"to officially forbid something","collocations":["ban smoking","impose a ban","lift a ban"],"example":"The city plans to ban smoking in public parks.","exampleZh":"該市計畫禁止在公園吸菸。","synonyms":["prohibit","forbid"],"level":4,"theme":"政治與法律","examples":[{"en":"The city plans to ban smoking in public parks.","zh":"該市計畫禁止在公園吸菸。"},{"en":"The school decided to ban mobile phones during class.","zh":"學校決定禁止在上課時使用手機。"},{"en":"Many citizens hope the government will lift the ban soon.","zh":"許多市民希望政府很快就會解除這項禁令。"}]},{"word":"banana","pos":"n.","phonetic":"[bəˈnænə]","meaning":"香蕉","definition":"a long curved yellow tropical fruit","collocations":["peel a banana","banana bread","ripe banana"],"example":"She ate a banana for breakfast.","exampleZh":"她早餐吃了一根香蕉。","synonyms":[],"level":1,"theme":"食物與烹飪","examples":[{"en":"She ate a banana for breakfast.","zh":"她早餐吃了一根香蕉。"},{"en":"He peeled a ripe banana and shared half with me.","zh":"他剝了一根熟香蕉，並分了一半給我。"},{"en":"My mother baked delicious banana bread this afternoon.","zh":"我媽媽今天下午烤了美味的香蕉麵包。"}]},{"word":"band","pos":"n.","phonetic":"[bænd]","meaning":"樂團；帶子；群體","definition":"a group of musicians, or a thin strip of material","collocations":["rock band","rubber band","join a band"],"example":"He plays guitar in a rock band.","exampleZh":"他在一個搖滾樂團裡彈吉他。","synonyms":["group"],"level":2,"theme":"藝術與音樂","examples":[{"en":"He plays guitar in a rock band.","zh":"他在一個搖滾樂團裡彈吉他。"},{"en":"Their rock band will perform at the school festival.","zh":"他們的搖滾樂團將在校慶上表演。"},{"en":"She tied her hair back with a rubber band.","zh":"她用一條橡皮筋把頭髮往後綁起來。"}]},{"word":"bandage","pos":"n. / v.","phonetic":"[ˈbændɪdʒ]","meaning":"繃帶；包紮","definition":"a strip of material used to wrap a wound","collocations":["wrap a bandage","apply a bandage","remove the bandage"],"example":"The nurse put a bandage on his cut.","exampleZh":"護理師在他的傷口上包了繃帶。","synonyms":[],"level":3,"theme":"身體與健康","examples":[{"en":"The nurse put a bandage on his cut.","zh":"護理師在他的傷口上包了繃帶。"},{"en":"The coach wrapped a bandage around the runner's ankle.","zh":"教練用繃帶把那名跑者的腳踝包紮起來。"},{"en":"You can remove the bandage once the wound heals.","zh":"傷口癒合後你就可以拆掉繃帶了。"}]},{"word":"bang","pos":"v. / n.","phonetic":"[bæŋ]","meaning":"猛擊；砰的一聲","definition":"to hit something hard making a loud noise","collocations":["bang the door","with a bang","bang on the table"],"example":"He banged on the door until someone answered.","exampleZh":"他猛敲門直到有人應門。","synonyms":["slam"],"level":3,"theme":"動作與行為","examples":[{"en":"He banged on the door until someone answered.","zh":"他猛敲門直到有人應門。"},{"en":"The door shut with a loud bang in the wind.","zh":"門在風中砰的一聲用力關上。"},{"en":"He banged on the table to get everyone's attention.","zh":"他猛敲桌子以引起大家的注意。"}]},{"word":"bank","pos":"n.","phonetic":"[bæŋk]","meaning":"銀行；河岸","definition":"a financial institution, or the land beside a river","collocations":["bank account","river bank","go to the bank"],"example":"She deposited the money at the bank.","exampleZh":"她把錢存進銀行。","synonyms":[],"level":1,"theme":"商業與金錢","examples":[{"en":"She deposited the money at the bank.","zh":"她把錢存進銀行。"},{"en":"I opened a new bank account for my savings.","zh":"我開了一個新的銀行帳戶來存我的積蓄。"},{"en":"We sat on the river bank and watched the ducks.","zh":"我們坐在河岸上看著鴨子。"}]},{"word":"bar","pos":"n.","phonetic":"[bɑr]","meaning":"酒吧；棒；橫木","definition":"a place serving drinks, or a long piece of solid material","collocations":["chocolate bar","go to a bar","behind bars"],"example":"They met at a bar after work.","exampleZh":"他們下班後在酒吧碰面。","synonyms":[],"level":2,"theme":"居家與生活","examples":[{"en":"They met at a bar after work.","zh":"他們下班後在酒吧碰面。"},{"en":"He bought a chocolate bar from the vending machine.","zh":"他從販賣機買了一條巧克力棒。"},{"en":"They met at a quiet bar to catch up.","zh":"他們在一間安靜的酒吧碰面敘舊。"}]},{"word":"barbecue","pos":"n. / v.","phonetic":"[ˈbɑrbɪˌkju]","meaning":"烤肉；燒烤","definition":"a meal cooked outdoors over an open fire","collocations":["have a barbecue","barbecue sauce","barbecue chicken"],"example":"We had a barbecue in the backyard last weekend.","exampleZh":"我們上週末在後院烤肉。","synonyms":[],"level":3,"theme":"食物與烹飪","examples":[{"en":"We had a barbecue in the backyard last weekend.","zh":"我們上週末在後院烤肉。"},{"en":"Let's have a barbecue by the lake this weekend.","zh":"這個週末我們去湖邊烤肉吧。"},{"en":"He brushed barbecue sauce onto the grilled chicken.","zh":"他把烤肉醬刷在烤雞上。"}]},{"word":"barber","pos":"n.","phonetic":"[ˈbɑrbɚ]","meaning":"理髮師","definition":"a person whose job is cutting men's hair","collocations":["go to the barber","barber shop","visit a barber"],"example":"My father goes to the barber every month.","exampleZh":"我父親每個月都去理髮店剪頭髮。","synonyms":[],"level":2,"theme":"工作與職業","examples":[{"en":"My father goes to the barber every month.","zh":"我父親每個月都去理髮店剪頭髮。"},{"en":"The barber trimmed his hair neatly before the interview.","zh":"理髮師在面試前把他的頭髮修剪得很整齊。"},{"en":"There is a small barber shop next to the market.","zh":"市場旁邊有一間小小的理髮店。"}]},{"word":"bare","pos":"adj.","phonetic":"[bɛr]","meaning":"赤裸的；光禿的","definition":"not covered by clothing or vegetation","collocations":["bare feet","bare hands","bare walls"],"example":"He walked on the beach with bare feet.","exampleZh":"他赤腳走在沙灘上。","synonyms":["naked"],"level":3,"theme":"服裝與外表","examples":[{"en":"He walked on the beach with bare feet.","zh":"他赤腳走在沙灘上。"},{"en":"The children ran across the grass with bare feet.","zh":"孩子們赤著腳跑過草地。"},{"en":"The new apartment had bare walls and no furniture.","zh":"那間新公寓牆壁光禿禿的，也沒有家具。"}]},{"word":"barely","pos":"adv.","phonetic":"[ˈbɛrlɪ]","meaning":"幾乎不；勉強","definition":"only just; almost not","collocations":["barely enough","barely survive","barely see"],"example":"He barely passed the exam.","exampleZh":"他勉強通過了考試。","synonyms":["hardly","scarcely"],"level":4,"theme":"性質與描述","examples":[{"en":"He barely passed the exam.","zh":"他勉強通過了考試。"},{"en":"There was barely enough time to finish the test.","zh":"時間幾乎不夠完成這場考試。"},{"en":"The room was so dark I could barely see.","zh":"房間太暗了，我幾乎看不見。"}]},{"word":"bargain","pos":"n. / v.","phonetic":"[ˈbɑrgɪn]","meaning":"划算的交易；討價還價","definition":"an agreement or a good deal, or to negotiate a price","collocations":["a great bargain","bargain for","strike a bargain"],"example":"She found a real bargain at the flea market.","exampleZh":"她在跳蚤市場找到很划算的商品。","synonyms":["deal"],"level":4,"theme":"商業與金錢","examples":[{"en":"She found a real bargain at the flea market.","zh":"她在跳蚤市場找到很划算的商品。"},{"en":"This jacket was a great bargain at half price.","zh":"這件外套半價出售，真是超划算的好貨。"},{"en":"She likes to bargain for a lower price at markets.","zh":"她喜歡在市場上討價還價爭取更低的價格。"}]},{"word":"bark","pos":"v. / n.","phonetic":"[bɑrk]","meaning":"吠叫；樹皮","definition":"the sharp sound a dog makes, or the outer layer of a tree","collocations":["dog barks","bark at strangers","tree bark"],"example":"The dog barked loudly at the mailman.","exampleZh":"那隻狗對著郵差大聲吠叫。","synonyms":[],"level":2,"theme":"動物與植物","examples":[{"en":"The dog barked loudly at the mailman.","zh":"那隻狗對著郵差大聲吠叫。"},{"en":"The puppy tends to bark at strangers near the gate.","zh":"這隻小狗容易對門口附近的陌生人吠叫。"},{"en":"We peeled the rough bark off the fallen branch.","zh":"我們把掉落枝條上粗糙的樹皮剝掉。"}]},{"word":"barrel","pos":"n.","phonetic":"[ˈbærəl]","meaning":"桶；圓筒","definition":"a large round container for liquids","collocations":["oil barrel","a barrel of wine","barrel of beer"],"example":"The wine was stored in wooden barrels.","exampleZh":"這些酒被存放在木桶裡。","synonyms":["cask"],"level":4,"theme":"居家與生活","examples":[{"en":"The wine was stored in wooden barrels.","zh":"這些酒被存放在木桶裡。"},{"en":"The farmer stored rainwater in a large wooden barrel.","zh":"農夫把雨水儲存在一個大木桶裡。"},{"en":"The price of one barrel of oil rose sharply.","zh":"一桶石油的價格急遽上漲。"}]},{"word":"barrier","pos":"n.","phonetic":"[ˈbærɪɚ]","meaning":"障礙；屏障","definition":"an obstacle that prevents movement or progress","collocations":["language barrier","break down barriers","overcome a barrier"],"example":"Language can be a barrier to communication.","exampleZh":"語言可能是溝通的障礙。","synonyms":["obstacle"],"level":4,"theme":"抽象概念","examples":[{"en":"Language can be a barrier to communication.","zh":"語言可能是溝通的障礙。"},{"en":"Shyness can be a barrier to making new friends.","zh":"害羞可能是結交新朋友的障礙。"},{"en":"Working together, they broke down the barriers between classes.","zh":"透過合作，他們打破了班級之間的隔閡。"}]},{"word":"base","pos":"n. / v.","phonetic":"[bes]","meaning":"基礎；根據地","definition":"the lowest part of something, or a foundation","collocations":["base camp","based on","home base"],"example":"The company's base is in Taipei.","exampleZh":"這家公司的總部設在台北。","synonyms":["foundation"],"level":3,"theme":"抽象概念","examples":[{"en":"The company's base is in Taipei.","zh":"這家公司的總部設在台北。"},{"en":"The story is based on a real historical event.","zh":"這個故事是根據一個真實的歷史事件改編的。"},{"en":"The climbers rested at the base of the mountain.","zh":"登山者在山腳下休息。"}]},{"word":"baseball","pos":"n.","phonetic":"[ˈbesˌbɔl]","meaning":"棒球","definition":"a team sport played with a bat and ball","collocations":["play baseball","baseball game","baseball team"],"example":"They watched a baseball game on Saturday.","exampleZh":"他們星期六去看了一場棒球賽。","synonyms":[],"level":1,"theme":"運動與休閒","examples":[{"en":"They watched a baseball game on Saturday.","zh":"他們星期六去看了一場棒球賽。"},{"en":"Our school baseball team won the regional championship.","zh":"我們學校的棒球隊贏得了區域冠軍。"},{"en":"He dreams of becoming a professional baseball player someday.","zh":"他夢想著有一天能成為職業棒球選手。"}]},{"word":"basement","pos":"n.","phonetic":"[ˈbesmənt]","meaning":"地下室","definition":"a room or level below ground in a building","collocations":["in the basement","basement storage","basement apartment"],"example":"We store old furniture in the basement.","exampleZh":"我們把舊家具存放在地下室。","synonyms":["cellar"],"level":3,"theme":"居家與生活","examples":[{"en":"We store old furniture in the basement.","zh":"我們把舊家具存放在地下室。"},{"en":"They turned the basement into a small music room.","zh":"他們把地下室改造成一間小型的音樂室。"},{"en":"The basement flooded after the heavy rain last night.","zh":"昨晚的大雨過後，地下室淹水了。"}]},{"word":"basic","pos":"adj.","phonetic":"[ˈbesɪk]","meaning":"基本的；基礎的","definition":"forming an essential foundation","collocations":["basic needs","basic skills","basic information"],"example":"Reading is a basic skill everyone needs.","exampleZh":"閱讀是每個人都需要的基本技能。","synonyms":["fundamental"],"level":2,"theme":"性質與描述","examples":[{"en":"Reading is a basic skill everyone needs.","zh":"閱讀是每個人都需要的基本技能。"},{"en":"Students must master the basic skills before advanced ones.","zh":"學生必須先掌握基本技能，才能學習進階的技能。"},{"en":"Clean water is one of our most basic needs.","zh":"乾淨的水是我們最基本的需求之一。"}]},{"word":"basin","pos":"n.","phonetic":"[ˈbesn̩]","meaning":"盆地；臉盆","definition":"a wide bowl-shaped container or a low area of land","collocations":["wash basin","river basin","kitchen basin"],"example":"She washed her hands in the basin.","exampleZh":"她在臉盆裡洗手。","synonyms":["bowl"],"level":4,"theme":"居家與生活","examples":[{"en":"She washed her hands in the basin.","zh":"她在臉盆裡洗手。"},{"en":"He filled the basin with warm water to wash up.","zh":"他在臉盆裡裝滿溫水來梳洗。"},{"en":"Many crops grow well in the fertile river basin.","zh":"許多作物在肥沃的河谷盆地裡生長良好。"}]},{"word":"basis","pos":"n.","phonetic":"[ˈbesɪs]","meaning":"基礎；依據","definition":"the foundation or reason for something","collocations":["on a regular basis","basis for","legal basis"],"example":"Trust is the basis of any friendship.","exampleZh":"信任是任何友誼的基礎。","synonyms":["foundation"],"level":3,"theme":"抽象概念","examples":[{"en":"Trust is the basis of any friendship.","zh":"信任是任何友誼的基礎。"},{"en":"We hold team meetings on a regular basis.","zh":"我們定期舉行團隊會議。"},{"en":"Mutual respect is the basis for a good friendship.","zh":"相互尊重是良好友誼的基礎。"}]},{"word":"basket","pos":"n.","phonetic":"[ˈbæskɪt]","meaning":"籃子","definition":"a container made of woven material","collocations":["shopping basket","basket of fruit","fruit basket"],"example":"She carried a basket of apples to the market.","exampleZh":"她提著一籃蘋果去市場。","synonyms":[],"level":1,"theme":"居家與生活","examples":[{"en":"She carried a basket of apples to the market.","zh":"她提著一籃蘋果去市場。"},{"en":"She placed the fresh vegetables into a woven basket.","zh":"她把新鮮的蔬菜放進一個編織的籃子裡。"},{"en":"He put the dirty clothes in the laundry basket.","zh":"他把髒衣服放進洗衣籃裡。"}]},{"word":"basketball","pos":"n.","phonetic":"[ˈbæskɪtˌbɔl]","meaning":"籃球","definition":"a team sport played by shooting a ball through a hoop","collocations":["play basketball","basketball court","basketball team"],"example":"He practices basketball every afternoon.","exampleZh":"他每天下午都練習打籃球。","synonyms":[],"level":1,"theme":"運動與休閒","examples":[{"en":"He practices basketball every afternoon.","zh":"他每天下午都練習打籃球。"},{"en":"They played basketball on the outdoor court after school.","zh":"放學後他們在戶外球場上打籃球。"},{"en":"Our basketball team practices every day after class.","zh":"我們的籃球隊每天下課後都會練習。"}]},{"word":"bat","pos":"n.","phonetic":"[bæt]","meaning":"球棒；蝙蝠","definition":"a piece of equipment used to hit a ball, or a flying mammal","collocations":["baseball bat","swing a bat","bats fly"],"example":"He hit the ball hard with his bat.","exampleZh":"他用球棒把球打得很遠。","synonyms":[],"level":2,"theme":"動物與植物","examples":[{"en":"He hit the ball hard with his bat.","zh":"他用球棒把球打得很遠。"},{"en":"The player swung the bat and hit a home run.","zh":"那名球員揮動球棒擊出了一支全壘打。"},{"en":"At dusk, several bats flew out of the dark cave.","zh":"黃昏時，幾隻蝙蝠從黑暗的洞穴中飛了出來。"}]},{"word":"batch","pos":"n.","phonetic":"[bætʃ]","meaning":"一批；一批份量","definition":"a quantity of something produced at one time","collocations":["a batch of cookies","batch of students","in batches"],"example":"She baked a fresh batch of cookies.","exampleZh":"她烤了一批新鮮的餅乾。","synonyms":["group"],"level":4,"theme":"其他","examples":[{"en":"She baked a fresh batch of cookies.","zh":"她烤了一批新鮮的餅乾。"},{"en":"The baker prepared a fresh batch of bread each morning.","zh":"麵包師傅每天早上都準備一批新鮮的麵包。"},{"en":"A new batch of students joined the club this term.","zh":"這學期有一批新生加入了社團。"}]},{"word":"bath","pos":"n.","phonetic":"[bæθ]","meaning":"沐浴；浴缸","definition":"an act of washing the body in water, or the tub used for it","collocations":["take a bath","hot bath","run a bath"],"example":"She took a hot bath after work.","exampleZh":"她下班後洗了個熱水澡。","synonyms":[],"level":1,"theme":"居家與生活","examples":[{"en":"She took a hot bath after work.","zh":"她下班後洗了個熱水澡。"},{"en":"After the long hike, a hot bath felt wonderful.","zh":"在長途健行之後，泡個熱水澡感覺真棒。"},{"en":"She likes to run a warm bath before bedtime.","zh":"她喜歡在睡前放一缸溫水泡澡。"}]},{"word":"bathe","pos":"v.","phonetic":"[beð]","meaning":"洗澡；沐浴","definition":"to wash oneself or someone else in water","collocations":["bathe a baby","bathe in the sea","bathe daily"],"example":"She bathes her baby every evening.","exampleZh":"她每天晚上幫寶寶洗澡。","synonyms":["wash"],"level":3,"theme":"身體與健康","examples":[{"en":"She bathes her baby every evening.","zh":"她每天晚上幫寶寶洗澡。"},{"en":"On hot summer days, we love to bathe in the sea.","zh":"在炎熱的夏天，我們喜歡到海裡戲水。"},{"en":"The nurse taught new parents how to bathe their baby.","zh":"護理師教新手父母如何幫寶寶洗澡。"}]},{"word":"bathroom","pos":"n.","phonetic":"[ˈbæθˌrum]","meaning":"浴室；廁所","definition":"a room with a bath, sink, and often a toilet","collocations":["clean the bathroom","bathroom sink","go to the bathroom"],"example":"He is cleaning the bathroom right now.","exampleZh":"他現在正在打掃浴室。","synonyms":[],"level":1,"theme":"居家與生活","examples":[{"en":"He is cleaning the bathroom right now.","zh":"他現在正在打掃浴室。"},{"en":"Could you tell me where the bathroom is, please?","zh":"請問你可以告訴我廁所在哪裡嗎？"},{"en":"She scrubbed the bathroom sink until it shone.","zh":"她把浴室的洗手台刷到閃閃發亮。"}]},{"word":"battery","pos":"n.","phonetic":"[ˈbætərɪ]","meaning":"電池","definition":"a device that stores and provides electrical power","collocations":["battery life","charge the battery","dead battery"],"example":"The battery in my phone died quickly.","exampleZh":"我手機的電池很快就沒電了。","synonyms":[],"level":2,"theme":"科技與媒體","examples":[{"en":"The battery in my phone died quickly.","zh":"我手機的電池很快就沒電了。"},{"en":"Remember to charge the battery before the long trip.","zh":"記得在長途旅行前把電池充飽電。"},{"en":"This laptop has a battery life of ten hours.","zh":"這台筆記型電腦的電池續航力有十個小時。"}]},{"word":"battle","pos":"n. / v.","phonetic":"[ˈbætl̩]","meaning":"戰役；奮戰","definition":"a fight between armed forces, or a struggle","collocations":["fight a battle","battle against","win a battle"],"example":"The soldiers fought a fierce battle.","exampleZh":"士兵們打了一場激烈的戰役。","synonyms":["fight","combat"],"level":3,"theme":"政治與法律","examples":[{"en":"The soldiers fought a fierce battle.","zh":"士兵們打了一場激烈的戰役。"},{"en":"She won her long battle against a serious illness.","zh":"她贏得了對抗重病的漫長奮戰。"},{"en":"History books describe the famous battle in great detail.","zh":"歷史課本非常詳細地描述了那場著名的戰役。"}]},{"word":"bay","pos":"n.","phonetic":"[be]","meaning":"海灣","definition":"an area of coast where the land curves inward","collocations":["a sheltered bay","sandy bay","across the bay"],"example":"The fishing boats returned to the bay at sunset.","exampleZh":"漁船在日落時分回到海灣。","synonyms":[],"level":4,"theme":"自然與環境","examples":[{"en":"The fishing boats returned to the bay at sunset.","zh":"漁船在日落時分回到海灣。"},{"en":"Small boats rested quietly in the sheltered bay.","zh":"小船靜靜地停泊在避風的海灣裡。"},{"en":"We swam in the calm water of the sandy bay.","zh":"我們在沙質海灣平靜的水中游泳。"}]},{"word":"beach","pos":"n.","phonetic":"[bitʃ]","meaning":"海灘","definition":"an area of sand or stones beside the sea","collocations":["go to the beach","beach ball","sandy beach"],"example":"We spent the whole day at the beach.","exampleZh":"我們整天都待在海灘上。","synonyms":["shore"],"level":1,"theme":"自然與環境","examples":[{"en":"We spent the whole day at the beach.","zh":"我們整天都待在海灘上。"},{"en":"The children built a sandcastle on the sandy beach.","zh":"孩子們在沙灘上堆了一座沙堡。"},{"en":"Let's go to the beach and watch the sunrise.","zh":"我們去海灘看日出吧。"}]},{"word":"bead","pos":"n.","phonetic":"[bid]","meaning":"珠子","definition":"a small piece of material with a hole for threading","collocations":["string of beads","glass bead","bead necklace"],"example":"She made a necklace from colorful beads.","exampleZh":"她用彩色珠子做了一條項鍊。","synonyms":[],"level":4,"theme":"服裝與外表","examples":[{"en":"She made a necklace from colorful beads.","zh":"她用彩色珠子做了一條項鍊。"},{"en":"A single glass bead had fallen off her bracelet.","zh":"一顆玻璃珠子從她的手鍊上掉了下來。"},{"en":"Beads of sweat formed on his forehead during the race.","zh":"比賽時，他的額頭上冒出了一顆顆汗珠。"}]},{"word":"beam","pos":"n. / v.","phonetic":"[bim]","meaning":"樑；光束；微笑","definition":"a long piece of wood or metal, or a ray of light","collocations":["laser beam","wooden beam","beam of light"],"example":"A beam of sunlight came through the window.","exampleZh":"一道陽光穿過窗戶照了進來。","synonyms":["ray"],"level":4,"theme":"科學與數學","examples":[{"en":"A beam of sunlight came through the window.","zh":"一道陽光穿過窗戶照了進來。"},{"en":"A warm beam of sunlight lit up the classroom.","zh":"一道溫暖的陽光照亮了教室。"},{"en":"Thick wooden beams supported the roof of the old barn.","zh":"粗壯的木樑支撐著這座老穀倉的屋頂。"}]},{"word":"bean","pos":"n.","phonetic":"[bin]","meaning":"豆子","definition":"the edible seed of certain plants","collocations":["green beans","coffee bean","bean soup"],"example":"She added beans to the soup.","exampleZh":"她在湯裡加了豆子。","synonyms":[],"level":2,"theme":"食物與烹飪","examples":[{"en":"She added beans to the soup.","zh":"她在湯裡加了豆子。"},{"en":"She boiled green beans as a side dish for dinner.","zh":"她煮了四季豆作為晚餐的配菜。"},{"en":"Fresh coffee beans give the drink a rich aroma.","zh":"新鮮的咖啡豆讓這杯飲料散發濃郁的香氣。"}]},{"word":"bear","pos":"v. / n.","phonetic":"[bɛr]","meaning":"忍受；熊","definition":"to tolerate something, or a large wild animal","collocations":["bear the pain","polar bear","can't bear it"],"example":"I can't bear this heat anymore.","exampleZh":"我再也無法忍受這種炎熱了。","synonyms":["tolerate","endure"],"level":3,"theme":"動作與行為","examples":[{"en":"I can't bear this heat anymore.","zh":"我再也無法忍受這種炎熱了。"},{"en":"I can hardly bear the pain in my knee.","zh":"我幾乎無法忍受膝蓋的疼痛。"},{"en":"A large brown bear wandered near the campsite.","zh":"一隻大棕熊在營地附近徘徊。"}]},{"word":"beard","pos":"n.","phonetic":"[bɪrd]","meaning":"鬍子","definition":"hair growing on a man's chin and cheeks","collocations":["grow a beard","thick beard","shave a beard"],"example":"He decided to grow a beard this winter.","exampleZh":"他決定今年冬天留鬍子。","synonyms":[],"level":3,"theme":"服裝與外表","examples":[{"en":"He decided to grow a beard this winter.","zh":"他決定今年冬天留鬍子。"},{"en":"He decided to shave his beard before the wedding.","zh":"他決定在婚禮前刮掉鬍子。"},{"en":"The old fisherman had a thick gray beard.","zh":"那位老漁夫留著濃密的灰白鬍子。"}]},{"word":"beast","pos":"n.","phonetic":"[bist]","meaning":"野獸","definition":"a large or dangerous animal","collocations":["wild beast","beast of burden","fierce beast"],"example":"The story tells of a beauty and a beast.","exampleZh":"這個故事講述美女與野獸。","synonyms":["animal"],"level":4,"theme":"動物與植物","examples":[{"en":"The story tells of a beauty and a beast.","zh":"這個故事講述美女與野獸。"},{"en":"The legend describes a fierce beast living in the forest.","zh":"那則傳說描述了一頭住在森林裡的兇猛野獸。"},{"en":"In ancient times, oxen were valued as beasts of burden.","zh":"在古代，牛因為是役用牲畜而備受重視。"}]},{"word":"beat","pos":"v. / n.","phonetic":"[bit]","meaning":"打敗；跳動；節拍","definition":"to defeat someone, or the rhythm of music","collocations":["beat the drum","heart beat","beat a rival"],"example":"Our team beat the rival school in the final.","exampleZh":"我們隊在決賽中打敗了對手學校。","synonyms":["defeat"],"level":2,"theme":"運動與休閒","examples":[{"en":"Our team beat the rival school in the final.","zh":"我們隊在決賽中打敗了對手學校。"},{"en":"Our team beat the champions in an exciting game.","zh":"我們的隊伍在一場精彩的比賽中打敗了衛冕者。"},{"en":"I could feel my heart beat faster before the speech.","zh":"演講前我能感覺到自己的心跳加快。"}]},{"word":"beautiful","pos":"adj.","phonetic":"[ˈbjutəfəl]","meaning":"美麗的","definition":"very pleasing to look at","collocations":["beautiful scenery","beautiful woman","beautiful day"],"example":"The sunset over the ocean was beautiful.","exampleZh":"海上的日落景色非常美麗。","synonyms":["pretty","gorgeous"],"level":1,"theme":"服裝與外表","examples":[{"en":"The sunset over the ocean was beautiful.","zh":"海上的日落景色非常美麗。"},{"en":"We admired the beautiful scenery from the mountaintop.","zh":"我們從山頂欣賞著美麗的風景。"},{"en":"What a beautiful day for a picnic in the park!","zh":"這真是個到公園野餐的好天氣！"}]},{"word":"beauty","pos":"n.","phonetic":"[ˈbjutɪ]","meaning":"美麗；美人","definition":"the quality of being pleasing to look at","collocations":["natural beauty","beauty salon","great beauty"],"example":"The beauty of the mountains amazed us.","exampleZh":"山的美景令我們驚嘆。","synonyms":[],"level":2,"theme":"性質與描述","examples":[{"en":"The beauty of the mountains amazed us.","zh":"山的美景令我們驚嘆。"},{"en":"The natural beauty of the valley left us speechless.","zh":"這座山谷的自然之美讓我們啞口無言。"},{"en":"She booked an appointment at the beauty salon downtown.","zh":"她在市區的美容沙龍預約了時段。"}]},{"word":"because","pos":"conj.","phonetic":"[bɪˈkɔz]","meaning":"因為","definition":"for the reason that","collocations":["because of","just because","because I said so"],"example":"She stayed home because she was sick.","exampleZh":"她因為生病而待在家裡。","synonyms":["since","as"],"level":1,"theme":"溝通與語言","examples":[{"en":"She stayed home because she was sick.","zh":"她因為生病而待在家裡。"},{"en":"We canceled the trip because of the heavy storm.","zh":"因為那場強烈的暴風雨，我們取消了旅行。"},{"en":"He was tired because he had studied all night.","zh":"他很累，因為他讀了一整晚的書。"}]},{"word":"become","pos":"v.","phonetic":"[bɪˈkʌm]","meaning":"變成；成為","definition":"to begin to be something","collocations":["become famous","become a doctor","become aware"],"example":"She worked hard to become a doctor.","exampleZh":"她努力工作以成為一名醫生。","synonyms":["turn into"],"level":1,"theme":"抽象概念","examples":[{"en":"She worked hard to become a doctor.","zh":"她努力工作以成為一名醫生。"},{"en":"With practice, she became aware of her own mistakes.","zh":"透過練習，她漸漸察覺到自己的錯誤。"},{"en":"The young singer quickly became famous around the country.","zh":"這位年輕歌手很快就在全國各地成名了。"}]},{"word":"bed","pos":"n.","phonetic":"[bɛd]","meaning":"床","definition":"a piece of furniture for sleeping on","collocations":["go to bed","make the bed","bed sheet"],"example":"He went to bed early last night.","exampleZh":"他昨晚很早就上床睡覺了。","synonyms":[],"level":1,"theme":"居家與生活","examples":[{"en":"He went to bed early last night.","zh":"他昨晚很早就上床睡覺了。"},{"en":"Please make your bed before you leave the room.","zh":"離開房間前請先鋪好你的床。"},{"en":"The tired children went to bed right after dinner.","zh":"疲累的孩子們晚餐後就馬上上床睡覺了。"}]},{"word":"bee","pos":"n.","phonetic":"[bi]","meaning":"蜜蜂","definition":"a flying insect that makes honey","collocations":["busy bee","bee sting","bee hive"],"example":"A bee stung him on the arm.","exampleZh":"一隻蜜蜂螫了他的手臂。","synonyms":[],"level":1,"theme":"動物與植物","examples":[{"en":"A bee stung him on the arm.","zh":"一隻蜜蜂螫了他的手臂。"},{"en":"A busy bee moved from flower to flower in the garden.","zh":"一隻忙碌的蜜蜂在花園裡從一朵花飛到另一朵花。"},{"en":"The gardener was careful to avoid a bee sting.","zh":"園丁小心翼翼地避免被蜜蜂螫到。"}]},{"word":"beef","pos":"n.","phonetic":"[bif]","meaning":"牛肉","definition":"the meat from a cow","collocations":["beef noodles","ground beef","roast beef"],"example":"He ordered beef noodles for lunch.","exampleZh":"他午餐點了牛肉麵。","synonyms":[],"level":1,"theme":"食物與烹飪","examples":[{"en":"He ordered beef noodles for lunch.","zh":"他午餐點了牛肉麵。"},{"en":"My father cooked a pot of beef noodles for us.","zh":"我父親為我們煮了一鍋牛肉麵。"},{"en":"She used ground beef to make the spaghetti sauce.","zh":"她用絞牛肉來做義大利麵醬。"}]},{"word":"beer","pos":"n.","phonetic":"[bɪr]","meaning":"啤酒","definition":"an alcoholic drink made from grain","collocations":["cold beer","a glass of beer","beer bottle"],"example":"They drank cold beer at the party.","exampleZh":"他們在派對上喝冰啤酒。","synonyms":[],"level":2,"theme":"食物與烹飪","examples":[{"en":"They drank cold beer at the party.","zh":"他們在派對上喝冰啤酒。"},{"en":"He ordered a cold beer to go with his meal.","zh":"他點了一杯冰啤酒配他的餐點。"},{"en":"The empty beer bottles were left on the table.","zh":"空的啤酒瓶被留在桌子上。"}]},{"word":"beg","pos":"v.","phonetic":"[bɛg]","meaning":"懇求；乞討","definition":"to ask for something urgently or humbly","collocations":["beg for forgiveness","beg someone to","beg for money"],"example":"He begged his parents for forgiveness.","exampleZh":"他懇求父母原諒他。","synonyms":["plead"],"level":3,"theme":"溝通與語言","examples":[{"en":"He begged his parents for forgiveness.","zh":"他懇求父母原諒他。"},{"en":"The little boy begged his mother for another cookie.","zh":"那個小男孩懇求媽媽再給他一塊餅乾。"},{"en":"A homeless man had to beg for money on the street.","zh":"一名無家可歸的男子不得不在街上乞討。"}]},{"word":"begin","pos":"v.","phonetic":"[bɪˈgɪn]","meaning":"開始","definition":"to start doing or happening","collocations":["begin with","begin a journey","begin to rain"],"example":"The meeting will begin at nine o'clock.","exampleZh":"會議將於九點開始。","synonyms":["start"],"level":1,"theme":"時間與空間","examples":[{"en":"The meeting will begin at nine o'clock.","zh":"會議將於九點開始。"},{"en":"The concert will begin at seven this evening.","zh":"音樂會將於今晚七點開始。"},{"en":"Dark clouds gathered, and it began to rain heavily.","zh":"烏雲聚集，天空開始下起大雨。"}]},{"word":"beginning","pos":"n.","phonetic":"[bɪˈgɪnɪŋ]","meaning":"開始；開端","definition":"the point where something starts","collocations":["from the beginning","beginning of the year","new beginning"],"example":"This is just the beginning of the story.","exampleZh":"這只是故事的開端。","synonyms":["start"],"level":1,"theme":"時間與空間","examples":[{"en":"This is just the beginning of the story.","zh":"這只是故事的開端。"},{"en":"From the beginning, he knew the task would be hard.","zh":"從一開始，他就知道這項任務會很艱難。"},{"en":"The beginning of the new year brings fresh hope.","zh":"新年的開端帶來嶄新的希望。"}]},{"word":"behave","pos":"v.","phonetic":"[bɪˈhev]","meaning":"表現；行為舉止","definition":"to act in a particular way","collocations":["behave well","behave badly","behave yourself"],"example":"The children behaved well at the museum.","exampleZh":"孩子們在博物館裡表現得很好。","synonyms":["act"],"level":3,"theme":"動作與行為","examples":[{"en":"The children behaved well at the museum.","zh":"孩子們在博物館裡表現得很好。"},{"en":"The teacher asked the students to behave during the trip.","zh":"老師要求學生們在旅途中要守規矩。"},{"en":"He behaved badly and had to apologize to everyone.","zh":"他表現得很差，必須向大家道歉。"}]},{"word":"behavior","pos":"n.","phonetic":"[bɪˈhevjɚ]","meaning":"行為；舉止","definition":"the way a person or animal acts","collocations":["good behavior","strange behavior","behavior problem"],"example":"His behavior surprised everyone at the party.","exampleZh":"他的行為讓派對上的每個人都很驚訝。","synonyms":["conduct"],"level":3,"theme":"抽象概念","examples":[{"en":"His behavior surprised everyone at the party.","zh":"他的行為讓派對上的每個人都很驚訝。"},{"en":"Her kind behavior made the new student feel welcome.","zh":"她親切的舉止讓那位新同學感到受歡迎。"},{"en":"Scientists study the strange behavior of these ocean fish.","zh":"科學家研究這些海洋魚類奇特的行為。"}]},{"word":"behind","pos":"prep. / adv.","phonetic":"[bɪˈhaɪnd]","meaning":"在...後面；落後","definition":"at or to the back of something","collocations":["behind schedule","fall behind","hide behind"],"example":"The cat hid behind the sofa.","exampleZh":"貓咪躲在沙發後面。","synonyms":[],"level":1,"theme":"時間與空間","examples":[{"en":"The cat hid behind the sofa.","zh":"貓咪躲在沙發後面。"},{"en":"The project fell behind schedule due to the delay.","zh":"由於延誤，這個專案進度落後了。"},{"en":"A little boy was hiding behind the curtain.","zh":"一個小男孩躲在窗簾後面。"}]},{"word":"belief","pos":"n.","phonetic":"[bɪˈlif]","meaning":"信念；信仰","definition":"a strong feeling that something is true","collocations":["religious belief","strong belief","belief in oneself"],"example":"Her belief in herself never wavered.","exampleZh":"她對自己的信念從未動搖。","synonyms":["faith"],"level":3,"theme":"抽象概念","examples":[{"en":"Her belief in herself never wavered.","zh":"她對自己的信念從未動搖。"},{"en":"Her firm belief in kindness guides all her actions.","zh":"她對善良的堅定信念指引著她所有的行為。"},{"en":"People from different cultures hold different religious beliefs.","zh":"來自不同文化的人們抱持著不同的宗教信仰。"}]},{"word":"believe","pos":"v.","phonetic":"[bɪˈliv]","meaning":"相信","definition":"to accept something as true","collocations":["believe in","hard to believe","believe someone"],"example":"I believe you are telling the truth.","exampleZh":"我相信你說的是實話。","synonyms":["trust"],"level":1,"theme":"抽象概念","examples":[{"en":"I believe you are telling the truth.","zh":"我相信你說的是實話。"},{"en":"I firmly believe that hard work leads to success.","zh":"我堅信努力會帶來成功。"},{"en":"It was hard to believe the good news at first.","zh":"起初，這個好消息令人難以置信。"}]},{"word":"bell","pos":"n.","phonetic":"[bɛl]","meaning":"鈴；鐘","definition":"a hollow metal object that makes a ringing sound","collocations":["ring a bell","school bell","doorbell"],"example":"The school bell rang loudly.","exampleZh":"學校的鐘聲響亮地響起。","synonyms":[],"level":1,"theme":"教育與學習","examples":[{"en":"The school bell rang loudly.","zh":"學校的鐘聲響亮地響起。"},{"en":"The school bell rang, and everyone rushed outside.","zh":"上課鐘響了，大家都衝到外面去。"},{"en":"She pressed the doorbell twice, but no one answered.","zh":"她按了兩次門鈴，但沒有人應門。"}]},{"word":"belong","pos":"v.","phonetic":"[bɪˈlɔŋ]","meaning":"屬於","definition":"to be the property of someone or a member of a group","collocations":["belong to","belong together","belong here"],"example":"This book belongs to my sister.","exampleZh":"這本書是我妹妹的。","synonyms":[],"level":2,"theme":"抽象概念","examples":[{"en":"This book belongs to my sister.","zh":"這本書是我妹妹的。"},{"en":"This umbrella belongs to the girl by the door.","zh":"這把雨傘是門邊那個女孩的。"},{"en":"After joining the club, she finally felt she belonged.","zh":"加入社團之後，她終於覺得自己有了歸屬。"}]},{"word":"below","pos":"prep. / adv.","phonetic":"[bɪˈlo]","meaning":"在...之下","definition":"at a lower level or position than something","collocations":["below average","below zero","below the surface"],"example":"The temperature dropped below zero last night.","exampleZh":"昨晚氣溫降到零度以下。","synonyms":["under"],"level":1,"theme":"時間與空間","examples":[{"en":"The temperature dropped below zero last night.","zh":"昨晚氣溫降到零度以下。"},{"en":"His test score was slightly below the class average.","zh":"他的考試成績略低於班級的平均。"},{"en":"From the plane, the city looked tiny far below.","zh":"從飛機上看，遠在下方的城市顯得非常渺小。"}]},{"word":"belt","pos":"n.","phonetic":"[bɛlt]","meaning":"皮帶；腰帶","definition":"a strip of material worn around the waist","collocations":["seat belt","leather belt","wear a belt"],"example":"Please fasten your seat belt before we take off.","exampleZh":"起飛前請繫好安全帶。","synonyms":[],"level":2,"theme":"服裝與外表","examples":[{"en":"Please fasten your seat belt before we take off.","zh":"起飛前請繫好安全帶。"},{"en":"He tightened his leather belt after losing some weight.","zh":"減重之後，他把皮帶束得更緊了。"},{"en":"Always fasten your seat belt before the car moves.","zh":"車子開動前一定要繫好安全帶。"}]},{"word":"bench","pos":"n.","phonetic":"[bɛntʃ]","meaning":"長椅","definition":"a long seat for several people","collocations":["park bench","sit on a bench","wooden bench"],"example":"They sat on a bench in the park.","exampleZh":"他們坐在公園的長椅上。","synonyms":[],"level":2,"theme":"居家與生活","examples":[{"en":"They sat on a bench in the park.","zh":"他們坐在公園的長椅上。"},{"en":"An old couple rested on a wooden bench nearby.","zh":"一對老夫婦在附近的木長椅上休息。"},{"en":"We sat on a park bench and fed the pigeons.","zh":"我們坐在公園的長椅上餵鴿子。"}]},{"word":"bend","pos":"v. / n.","phonetic":"[bɛnd]","meaning":"彎曲；轉彎","definition":"to move or shape something into a curve","collocations":["bend down","bend the rules","sharp bend"],"example":"She bent down to pick up the pen.","exampleZh":"她彎下腰撿起筆。","synonyms":["curve"],"level":3,"theme":"動作與行為","examples":[{"en":"She bent down to pick up the pen.","zh":"她彎下腰撿起筆。"},{"en":"She had to bend down to tie her shoelaces.","zh":"她必須彎下腰去綁鞋帶。"},{"en":"Please slow down before the sharp bend in the road.","zh":"在道路的急轉彎前請減速。"}]},{"word":"beneath","pos":"prep.","phonetic":"[bɪˈniθ]","meaning":"在...之下","definition":"in or to a lower position than something","collocations":["beneath the surface","beneath the tree","far beneath"],"example":"Treasure was buried beneath the old oak tree.","exampleZh":"寶藏埋在那棵老橡樹下面。","synonyms":["below","under"],"level":4,"theme":"時間與空間","examples":[{"en":"Treasure was buried beneath the old oak tree.","zh":"寶藏埋在那棵老橡樹下面。"},{"en":"A small stream flowed beneath the old stone bridge.","zh":"一條小溪流淌在古老的石橋下方。"},{"en":"The cat curled up beneath the warm blanket.","zh":"貓咪蜷縮在溫暖的毯子底下。"}]},{"word":"benefit","pos":"n. / v.","phonetic":"[ˈbɛnəfɪt]","meaning":"利益；好處","definition":"an advantage gained from something","collocations":["health benefits","benefit from","for the benefit of"],"example":"Regular exercise has many health benefits.","exampleZh":"規律運動有許多健康益處。","synonyms":["advantage"],"level":3,"theme":"抽象概念","examples":[{"en":"Regular exercise has many health benefits.","zh":"規律運動有許多健康益處。"},{"en":"Students can benefit greatly from reading every day.","zh":"學生能從每天閱讀中獲益良多。"},{"en":"The charity concert was held for the benefit of orphans.","zh":"這場慈善音樂會是為了孤兒的福祉而舉辦的。"}]},{"word":"besides","pos":"adv. / prep.","phonetic":"[bɪˈsaɪdz]","meaning":"此外；除了...之外","definition":"in addition to something","collocations":["besides that","besides which","besides me"],"example":"Besides English, she also speaks French.","exampleZh":"除了英文，她還會說法文。","synonyms":["also"],"level":3,"theme":"溝通與語言","examples":[{"en":"Besides English, she also speaks French.","zh":"除了英文，她還會說法文。"},{"en":"Besides math, he is also very good at science.","zh":"除了數學之外，他的自然科學也很好。"},{"en":"I don't want to go out; besides, it's raining.","zh":"我不想出門，何況現在正在下雨。"}]},{"word":"best","pos":"adj. / adv.","phonetic":"[bɛst]","meaning":"最好的；最好地","definition":"of the highest quality or greatest degree","collocations":["do your best","best friend","best of luck"],"example":"He is my best friend since childhood.","exampleZh":"他是我從小到大最好的朋友。","synonyms":[],"level":1,"theme":"性質與描述","examples":[{"en":"He is my best friend since childhood.","zh":"他是我從小到大最好的朋友。"},{"en":"Just do your best, and don't worry about the result.","zh":"盡你最大的努力就好，不必擔心結果。"},{"en":"This is the best restaurant I have ever tried.","zh":"這是我試過最棒的餐廳。"}]},{"word":"bet","pos":"v. / n.","phonetic":"[bɛt]","meaning":"打賭","definition":"to risk money on the result of something uncertain","collocations":["bet on","place a bet","I bet"],"example":"I bet you can't finish the race first.","exampleZh":"我跟你打賭你不能第一個跑完比賽。","synonyms":["wager"],"level":3,"theme":"抽象概念","examples":[{"en":"I bet you can't finish the race first.","zh":"我跟你打賭你不能第一個跑完比賽。"},{"en":"I bet our team will win the championship this year.","zh":"我敢打賭我們的隊伍今年會贏得冠軍。"},{"en":"He placed a small bet on the horse race.","zh":"他在賽馬上下了一個小小的賭注。"}]},{"word":"betray","pos":"v.","phonetic":"[bɪˈtre]","meaning":"背叛","definition":"to be disloyal to someone who trusts you","collocations":["betray trust","betray a friend","feel betrayed"],"example":"He felt betrayed when his friend told the secret.","exampleZh":"當朋友洩露秘密時，他感到被背叛了。","synonyms":["deceive"],"level":5,"theme":"情緒與感受","examples":[{"en":"He felt betrayed when his friend told the secret.","zh":"當朋友洩露秘密時，他感到被背叛了。"},{"en":"A true friend would never betray your trust.","zh":"真正的朋友絕不會背叛你的信任。"},{"en":"She felt betrayed when her secret was shared online.","zh":"當她的秘密被公開在網路上時，她感到被背叛了。"}]},{"word":"better","pos":"adj. / adv.","phonetic":"[ˈbɛtɚ]","meaning":"更好的；更好地","definition":"of a higher standard or more suitable","collocations":["feel better","better than","get better"],"example":"She feels much better after taking the medicine.","exampleZh":"她吃藥後感覺好多了。","synonyms":[],"level":1,"theme":"性質與描述","examples":[{"en":"She feels much better after taking the medicine.","zh":"她吃藥後感覺好多了。"},{"en":"After a good rest, he felt much better today.","zh":"好好休息之後，他今天覺得好多了。"},{"en":"Practicing daily is a better way to improve your English.","zh":"每天練習是精進英文更好的方法。"}]},{"word":"between","pos":"prep.","phonetic":"[bɪˈtwin]","meaning":"在...之間","definition":"in the space separating two things","collocations":["between us","between classes","choose between"],"example":"The park is located between the school and the library.","exampleZh":"公園位於學校和圖書館之間。","synonyms":[],"level":1,"theme":"時間與空間","examples":[{"en":"The park is located between the school and the library.","zh":"公園位於學校和圖書館之間。"},{"en":"The bookstore stands between a café and a bank.","zh":"那家書店位於一間咖啡館和一間銀行之間。"},{"en":"It was hard to choose between the two universities.","zh":"要在這兩所大學之間做選擇很困難。"}]},{"word":"beverage","pos":"n.","phonetic":"[ˈbɛvərɪdʒ]","meaning":"飲料","definition":"a drink of any kind other than water","collocations":["hot beverage","alcoholic beverage","serve beverages"],"example":"The menu offers a variety of beverages.","exampleZh":"菜單提供多種飲料選擇。","synonyms":["drink"],"level":5,"theme":"食物與烹飪","examples":[{"en":"The menu offers a variety of beverages.","zh":"菜單提供多種飲料選擇。"},{"en":"Would you like a hot beverage on this cold day?","zh":"在這麼冷的天，你想來杯熱飲嗎？"},{"en":"The café serves a wide range of cold beverages.","zh":"這間咖啡館供應各式各樣的冷飲。"}]},{"word":"beware","pos":"v.","phonetic":"[bɪˈwɛr]","meaning":"當心；小心","definition":"to be cautious about danger","collocations":["beware of dogs","beware of scams","please beware"],"example":"Beware of the dog when you enter the yard.","exampleZh":"進入院子時要小心那隻狗。","synonyms":["watch out"],"level":4,"theme":"性質與描述","examples":[{"en":"Beware of the dog when you enter the yard.","zh":"進入院子時要小心那隻狗。"},{"en":"Beware of scams that ask for your bank details.","zh":"要當心那些索取你銀行資料的詐騙。"},{"en":"A sign warned us to beware of the slippery floor.","zh":"一個告示牌警告我們要小心濕滑的地板。"}]},{"word":"beyond","pos":"prep.","phonetic":"[bɪˈjɑnd]","meaning":"超出；在...之外","definition":"further away or later than something","collocations":["beyond doubt","beyond belief","beyond expectations"],"example":"His talent goes beyond what we expected.","exampleZh":"他的才能超出我們的預期。","synonyms":["past"],"level":4,"theme":"時間與空間","examples":[{"en":"His talent goes beyond what we expected.","zh":"他的才能超出我們的預期。"},{"en":"The final exam was beyond what most students expected.","zh":"這次期末考超出了大多數學生的預期。"},{"en":"Beyond the hills lay a quiet little village.","zh":"群山之外坐落著一座寧靜的小村莊。"}]},{"word":"bicycle","pos":"n.","phonetic":"[ˈbaɪˌsɪkl̩]","meaning":"腳踏車","definition":"a two-wheeled vehicle powered by pedaling","collocations":["ride a bicycle","bicycle lane","fix a bicycle"],"example":"He rides his bicycle to school every day.","exampleZh":"他每天騎腳踏車上學。","synonyms":["bike"],"level":1,"theme":"交通與旅行","examples":[{"en":"He rides his bicycle to school every day.","zh":"他每天騎腳踏車上學。"},{"en":"She rides her bicycle along the river every morning.","zh":"她每天早上沿著河邊騎腳踏車。"},{"en":"The city built a new bicycle lane downtown.","zh":"這座城市在市中心建了一條新的自行車道。"}]},{"word":"bid","pos":"v. / n.","phonetic":"[bɪd]","meaning":"出價；投標","definition":"to offer a price for something","collocations":["bid on","place a bid","winning bid"],"example":"She made a high bid for the painting.","exampleZh":"她為那幅畫出了高價。","synonyms":["offer"],"level":5,"theme":"商業與金錢","examples":[{"en":"She made a high bid for the painting.","zh":"她為那幅畫出了高價。"},{"en":"He placed the winning bid on the antique clock.","zh":"他以最高價標得了那座古董時鐘。"},{"en":"Several companies plan to bid for the construction project.","zh":"好幾家公司打算競標這個建設工程。"}]},{"word":"big","pos":"adj.","phonetic":"[bɪg]","meaning":"大的","definition":"of great size or extent","collocations":["big house","big deal","big city"],"example":"They moved into a big house last year.","exampleZh":"他們去年搬進了一棟大房子。","synonyms":["large"],"level":1,"theme":"性質與描述","examples":[{"en":"They moved into a big house last year.","zh":"他們去年搬進了一棟大房子。"},{"en":"Winning the contest was a big deal for her.","zh":"贏得這場比賽對她來說是件大事。"},{"en":"They moved from a small town to a big city.","zh":"他們從一個小鎮搬到了一座大城市。"}]},{"word":"bike","pos":"n.","phonetic":"[baɪk]","meaning":"腳踏車；機車","definition":"a bicycle or motorcycle","collocations":["ride a bike","mountain bike","bike path"],"example":"We rented bikes to explore the island.","exampleZh":"我們租了腳踏車去探索這座島。","synonyms":["bicycle"],"level":1,"theme":"交通與旅行","examples":[{"en":"We rented bikes to explore the island.","zh":"我們租了腳踏車去探索這座島。"},{"en":"We followed the bike path all the way to the beach.","zh":"我們沿著自行車道一路騎到海邊。"},{"en":"He bought a mountain bike for the weekend trip.","zh":"他為了週末的旅行買了一輛登山車。"}]},{"word":"bill","pos":"n.","phonetic":"[bɪl]","meaning":"帳單；法案","definition":"a written statement of money owed, or a proposed law","collocations":["pay the bill","electricity bill","pass a bill"],"example":"He forgot to pay the electricity bill.","exampleZh":"他忘了繳電費帳單。","synonyms":["invoice"],"level":2,"theme":"商業與金錢","examples":[{"en":"He forgot to pay the electricity bill.","zh":"他忘了繳電費帳單。"},{"en":"Please remember to pay the water bill by Friday.","zh":"請記得在星期五前繳交水費帳單。"},{"en":"Lawmakers voted to pass the new environmental bill.","zh":"立法者投票通過了那項新的環保法案。"}]},{"word":"billion","pos":"n.","phonetic":"[ˈbɪljən]","meaning":"十億","definition":"the number 1,000,000,000","collocations":["a billion dollars","billions of people","one billion"],"example":"The company is worth over a billion dollars.","exampleZh":"這家公司的價值超過十億美元。","synonyms":[],"level":3,"theme":"科學與數學","examples":[{"en":"The company is worth over a billion dollars.","zh":"這家公司的價值超過十億美元。"},{"en":"There are billions of stars in our galaxy.","zh":"我們的銀河系裡有數十億顆星星。"},{"en":"The bridge project cost nearly one billion dollars.","zh":"這座橋樑工程耗資將近十億美元。"}]},{"word":"bind","pos":"v.","phonetic":"[baɪnd]","meaning":"綁；捆綁；約束","definition":"to tie or fasten tightly together","collocations":["bind together","bind a wound","legally bind"],"example":"The ropes were used to bind the boxes together.","exampleZh":"繩子被用來把箱子綁在一起。","synonyms":["tie","fasten"],"level":4,"theme":"動作與行為","examples":[{"en":"The ropes were used to bind the boxes together.","zh":"繩子被用來把箱子綁在一起。"},{"en":"He used strong string to bind the newspapers together.","zh":"他用結實的繩子把報紙捆綁在一起。"},{"en":"A shared goal can bind a team closely together.","zh":"共同的目標能把一個團隊緊密地連結起來。"}]},{"word":"biology","pos":"n.","phonetic":"[baɪˈɑlədʒɪ]","meaning":"生物學","definition":"the scientific study of living organisms","collocations":["biology class","study biology","marine biology"],"example":"She is majoring in biology at university.","exampleZh":"她在大學主修生物學。","synonyms":[],"level":2,"theme":"科學與數學","examples":[{"en":"She is majoring in biology at university.","zh":"她在大學主修生物學。"},{"en":"Our biology class visited the lab to study cells.","zh":"我們的生物課去實驗室研究細胞。"},{"en":"She hopes to study marine biology at university.","zh":"她希望在大學研讀海洋生物學。"}]},{"word":"bird","pos":"n.","phonetic":"[bɝd]","meaning":"鳥","definition":"a warm-blooded animal with feathers and wings","collocations":["a flock of birds","bird watching","bird cage"],"example":"Birds were singing in the trees this morning.","exampleZh":"今天早上鳥兒在樹上歌唱。","synonyms":[],"level":1,"theme":"動物與植物","examples":[{"en":"Birds were singing in the trees this morning.","zh":"今天早上鳥兒在樹上歌唱。"},{"en":"A flock of birds flew south for the winter.","zh":"一群鳥為了過冬而向南飛去。"},{"en":"My grandfather enjoys bird watching in the countryside.","zh":"我祖父喜歡在鄉間賞鳥。"}]},{"word":"birth","pos":"n.","phonetic":"[bɝθ]","meaning":"出生；誕生","definition":"the process of being born","collocations":["give birth","date of birth","birth rate"],"example":"She gave birth to a healthy baby girl.","exampleZh":"她生下了一個健康的女嬰。","synonyms":[],"level":2,"theme":"人物與家庭","examples":[{"en":"She gave birth to a healthy baby girl.","zh":"她生下了一個健康的女嬰。"},{"en":"Please write your date of birth on the form.","zh":"請在表格上寫下你的出生日期。"},{"en":"The whole family celebrated the birth of the baby.","zh":"全家人一起慶祝寶寶的誕生。"}]},{"word":"birthday","pos":"n.","phonetic":"[ˈbɝθˌde]","meaning":"生日","definition":"the anniversary of the day someone was born","collocations":["happy birthday","birthday party","birthday cake"],"example":"We threw a surprise party for her birthday.","exampleZh":"我們為她的生日辦了一個驚喜派對。","synonyms":[],"level":1,"theme":"人物與家庭","examples":[{"en":"We threw a surprise party for her birthday.","zh":"我們為她的生日辦了一個驚喜派對。"},{"en":"She blew out the candles on her birthday cake.","zh":"她吹熄了生日蛋糕上的蠟燭。"},{"en":"We are planning a birthday party for my brother.","zh":"我們正在為我弟弟籌辦一場生日派對。"}]},{"word":"biscuit","pos":"n.","phonetic":"[ˈbɪskɪt]","meaning":"餅乾","definition":"a small flat baked snack","collocations":["chocolate biscuit","packet of biscuits","crispy biscuit"],"example":"He enjoyed a cup of tea with a biscuit.","exampleZh":"他享用了一杯茶配餅乾。","synonyms":["cookie"],"level":3,"theme":"食物與烹飪","examples":[{"en":"He enjoyed a cup of tea with a biscuit.","zh":"他享用了一杯茶配餅乾。"},{"en":"He dipped a crispy biscuit into his warm tea.","zh":"他把一塊酥脆的餅乾浸入溫熱的茶中。"},{"en":"She opened a packet of chocolate biscuits for the guests.","zh":"她為客人拆開了一包巧克力餅乾。"}]},{"word":"bit","pos":"n.","phonetic":"[bɪt]","meaning":"一點；少量","definition":"a small amount or piece of something","collocations":["a bit of","little bit","bit by bit"],"example":"Could you give me a bit more time?","exampleZh":"你可以再多給我一點時間嗎？","synonyms":["piece"],"level":1,"theme":"抽象概念","examples":[{"en":"Could you give me a bit more time?","zh":"你可以再多給我一點時間嗎？"},{"en":"Could you speak a bit more slowly, please?","zh":"可以請你說得再慢一點嗎？"},{"en":"Bit by bit, he saved enough money for a bicycle.","zh":"一點一滴地，他存夠了買一輛腳踏車的錢。"}]},{"word":"bite","pos":"v. / n.","phonetic":"[baɪt]","meaning":"咬；咬傷","definition":"to use teeth to cut into something","collocations":["bite into","dog bite","take a bite"],"example":"The dog bit the mailman on the leg.","exampleZh":"那隻狗咬了郵差的腿。","synonyms":["chew"],"level":2,"theme":"動作與行為","examples":[{"en":"The dog bit the mailman on the leg.","zh":"那隻狗咬了郵差的腿。"},{"en":"She took a big bite of the juicy apple.","zh":"她大大地咬了一口多汁的蘋果。"},{"en":"Be careful not to get a mosquito bite outside.","zh":"在外面要小心別被蚊子咬。"}]},{"word":"bitter","pos":"adj.","phonetic":"[ˈbɪtɚ]","meaning":"苦的；痛苦的","definition":"having a sharp unpleasant taste, or feeling resentful","collocations":["bitter taste","bitter cold","bitter experience"],"example":"The medicine had a very bitter taste.","exampleZh":"這藥的味道非常苦。","synonyms":["sour"],"level":4,"theme":"情緒與感受","examples":[{"en":"The medicine had a very bitter taste.","zh":"這藥的味道非常苦。"},{"en":"The black coffee tasted too bitter for my liking.","zh":"這杯黑咖啡對我來說太苦了。"},{"en":"Losing the final was a bitter experience for the team.","zh":"輸掉決賽對這支隊伍來說是個痛苦的經驗。"}]},{"word":"blame","pos":"v. / n.","phonetic":"[blem]","meaning":"責怪；歸咎","definition":"to hold someone responsible for a fault","collocations":["blame someone for","take the blame","put blame on"],"example":"Don't blame yourself for the mistake.","exampleZh":"不要為這個錯誤責怪自己。","synonyms":["accuse"],"level":3,"theme":"情緒與感受","examples":[{"en":"Don't blame yourself for the mistake.","zh":"不要為這個錯誤責怪自己。"},{"en":"Please don't blame the whole team for one mistake.","zh":"請不要因為一個錯誤就責怪整個團隊。"},{"en":"He bravely took the blame for the broken window.","zh":"他勇敢地為打破的窗戶承擔了責任。"}]},{"word":"blank","pos":"adj. / n.","phonetic":"[blæŋk]","meaning":"空白的；空格","definition":"having nothing written or printed on it","collocations":["blank page","fill in the blank","blank expression"],"example":"Please fill in the blank with the correct word.","exampleZh":"請在空格處填入正確的單字。","synonyms":["empty"],"level":3,"theme":"教育與學習","examples":[{"en":"Please fill in the blank with the correct word.","zh":"請在空格處填入正確的單字。"},{"en":"Fill in each blank with the correct verb form.","zh":"在每個空格中填入正確的動詞形式。"},{"en":"She stared at the blank page, unsure how to start.","zh":"她盯著空白的頁面，不知道該如何下筆。"}]},{"word":"blanket","pos":"n.","phonetic":"[ˈblæŋkɪt]","meaning":"毯子","definition":"a large piece of soft material used for warmth","collocations":["warm blanket","wrap in a blanket","picnic blanket"],"example":"She wrapped the baby in a warm blanket.","exampleZh":"她用溫暖的毯子把寶寶包起來。","synonyms":[],"level":2,"theme":"居家與生活","examples":[{"en":"She wrapped the baby in a warm blanket.","zh":"她用溫暖的毯子把寶寶包起來。"},{"en":"We spread a picnic blanket under the shady tree.","zh":"我們在樹蔭下鋪了一張野餐墊。"},{"en":"On cold nights, she pulls a thick blanket over herself.","zh":"寒冷的夜裡，她會拉一條厚毯子蓋在身上。"}]},{"word":"bleed","pos":"v.","phonetic":"[blid]","meaning":"流血","definition":"to lose blood from a wound","collocations":["bleed heavily","bleed from a cut","start to bleed"],"example":"His knee started to bleed after the fall.","exampleZh":"他跌倒後膝蓋開始流血。","synonyms":[],"level":4,"theme":"身體與健康","examples":[{"en":"His knee started to bleed after the fall.","zh":"他跌倒後膝蓋開始流血。"},{"en":"His nose began to bleed after the hard fall.","zh":"重重摔倒之後，他的鼻子開始流血。"},{"en":"Press firmly on the cut so it stops bleeding.","zh":"用力壓住傷口，讓它停止流血。"}]},{"word":"blend","pos":"v. / n.","phonetic":"[blɛnd]","meaning":"混合；混合物","definition":"to mix different things together smoothly","collocations":["blend in","blend ingredients","perfect blend"],"example":"She blended the fruits to make a smoothie.","exampleZh":"她把水果打成果昔。","synonyms":["mix"],"level":4,"theme":"食物與烹飪","examples":[{"en":"She blended the fruits to make a smoothie.","zh":"她把水果打成果昔。"},{"en":"Blend the milk and banana to make a smoothie.","zh":"把牛奶和香蕉打在一起做成一杯果昔。"},{"en":"The new building blends in well with the old street.","zh":"這棟新建築與這條老街融合得很好。"}]},{"word":"bless","pos":"v.","phonetic":"[blɛs]","meaning":"祝福","definition":"to ask for divine favor for someone","collocations":["bless you","God bless","blessed with"],"example":"The priest blessed the newly married couple.","exampleZh":"神父為這對新婚夫婦祝福。","synonyms":[],"level":4,"theme":"社會與文化","examples":[{"en":"The priest blessed the newly married couple.","zh":"神父為這對新婚夫婦祝福。"},{"en":"Her grandmother would always bless her before a journey.","zh":"她的祖母總會在她出遠門前為她祝福。"},{"en":"We feel blessed with such kind and caring neighbors.","zh":"我們很幸運能有如此善良又體貼的鄰居。"}]},{"word":"blind","pos":"adj.","phonetic":"[blaɪnd]","meaning":"失明的；盲目的","definition":"unable to see","collocations":["blind person","go blind","blind faith"],"example":"He has been blind since birth.","exampleZh":"他自出生以來就失明了。","synonyms":[],"level":3,"theme":"身體與健康","examples":[{"en":"He has been blind since birth.","zh":"他自出生以來就失明了。"},{"en":"A guide dog helps the blind man cross the street.","zh":"一隻導盲犬幫助那位盲人過馬路。"},{"en":"We should not follow anyone with blind faith.","zh":"我們不該盲目地信從任何人。"}]},{"word":"blink","pos":"v.","phonetic":"[blɪŋk]","meaning":"眨眼","definition":"to close and open the eyes quickly","collocations":["blink twice","without blinking","blink an eye"],"example":"She blinked in surprise at the news.","exampleZh":"她聽到這個消息驚訝地眨了眨眼。","synonyms":[],"level":4,"theme":"身體與健康","examples":[{"en":"She blinked in surprise at the news.","zh":"她聽到這個消息驚訝地眨了眨眼。"},{"en":"The bright light made her blink several times.","zh":"刺眼的光讓她眨了好幾次眼睛。"},{"en":"He agreed to help without blinking an eye.","zh":"他毫不猶豫地就答應幫忙。"}]},{"word":"block","pos":"n. / v.","phonetic":"[blɑk]","meaning":"街區；阻擋","definition":"a large solid piece of material, or to obstruct something","collocations":["block the road","city block","block a view"],"example":"A fallen tree blocked the road.","exampleZh":"一棵倒下的樹擋住了道路。","synonyms":["obstruct"],"level":2,"theme":"交通與旅行","examples":[{"en":"A fallen tree blocked the road.","zh":"一棵倒下的樹擋住了道路。"},{"en":"A large truck was blocking the narrow road.","zh":"一輛大卡車擋住了那條狹窄的道路。"},{"en":"The library is just two blocks from our school.","zh":"圖書館離我們學校只有兩個街區。"}]},{"word":"blood","pos":"n.","phonetic":"[blʌd]","meaning":"血液","definition":"the red liquid that flows through the body","collocations":["blood pressure","blood donation","lose blood"],"example":"The doctor checked his blood pressure.","exampleZh":"醫生檢查了他的血壓。","synonyms":[],"level":2,"theme":"身體與健康","examples":[{"en":"The doctor checked his blood pressure.","zh":"醫生檢查了他的血壓。"},{"en":"The doctor took a small sample of my blood.","zh":"醫生抽了我一小管血液樣本。"},{"en":"Many people came to give blood at the hospital.","zh":"許多人來到醫院捐血。"}]},{"word":"bloom","pos":"v. / n.","phonetic":"[blum]","meaning":"開花","definition":"to produce flowers, or the flowering state of a plant","collocations":["in full bloom","flowers bloom","bloom in spring"],"example":"The cherry blossoms bloom in early spring.","exampleZh":"櫻花在早春時節綻放。","synonyms":["blossom"],"level":4,"theme":"動物與植物","examples":[{"en":"The cherry blossoms bloom in early spring.","zh":"櫻花在早春時節綻放。"},{"en":"The roses in our garden are in full bloom now.","zh":"我們花園裡的玫瑰現在正盛開著。"},{"en":"These wildflowers usually bloom after the spring rain.","zh":"這些野花通常在春雨過後綻放。"}]},{"word":"blossom","pos":"n. / v.","phonetic":"[ˈblɑsəm]","meaning":"花朵；開花","definition":"a flower, especially of a fruit tree, or to flower","collocations":["cherry blossom","blossom into","apple blossom"],"example":"The cherry blossom festival attracts many tourists.","exampleZh":"櫻花節吸引了許多遊客。","synonyms":["bloom","flower"],"level":4,"theme":"動物與植物","examples":[{"en":"The cherry blossom festival attracts many tourists.","zh":"櫻花節吸引了許多遊客。"},{"en":"The apple blossom covered the trees in soft pink.","zh":"蘋果花把樹木覆蓋上一層柔和的粉紅。"},{"en":"With encouragement, the shy child blossomed into a leader.","zh":"在鼓勵之下，那個害羞的孩子成長為一位領導者。"}]},{"word":"boast","pos":"v.","phonetic":"[bost]","meaning":"誇耀；自誇","definition":"to speak with excessive pride about oneself","collocations":["boast about","boast that","boast of one's skill"],"example":"He likes to boast about his achievements.","exampleZh":"他喜歡誇耀自己的成就。","synonyms":["brag"],"level":4,"theme":"動作與行為","examples":[{"en":"He likes to boast about his achievements.","zh":"他喜歡誇耀自己的成就。"},{"en":"He loves to boast about his high test scores.","zh":"他很愛炫耀自己的高分。"},{"en":"She never boasts, even though she is very talented.","zh":"儘管她很有才華，卻從不自誇。"}]},{"word":"boat","pos":"n.","phonetic":"[bot]","meaning":"船；小船","definition":"a small vessel for traveling on water","collocations":["row a boat","get on a boat","fishing boat"],"example":"We took a boat across the lake.","exampleZh":"我們乘船橫渡湖泊。","synonyms":["ship","vessel"],"level":1,"theme":"交通與旅行","examples":[{"en":"We took a boat across the lake.","zh":"我們乘船橫渡湖泊。"},{"en":"They rowed the small boat across the calm lake.","zh":"他們划著小船橫渡平靜的湖面。"},{"en":"A fishing boat returned to the harbor at dawn.","zh":"一艘漁船在黎明時分返回港口。"}]},{"word":"body","pos":"n.","phonetic":"[ˈbɑdɪ]","meaning":"身體；屍體；主體","definition":"the physical structure of a person or animal","collocations":["human body","body language","body of the report"],"example":"Exercise keeps your body healthy.","exampleZh":"運動能讓你的身體保持健康。","synonyms":[],"level":1,"theme":"身體與健康","examples":[{"en":"Exercise keeps your body healthy.","zh":"運動能讓你的身體保持健康。"},{"en":"Regular exercise keeps your body strong and healthy.","zh":"規律的運動讓你的身體強壯又健康。"},{"en":"The main body of the report explains the results clearly.","zh":"這份報告的主體部分清楚地說明了結果。"}]},{"word":"boil","pos":"v.","phonetic":"[bɔɪl]","meaning":"煮沸；沸騰","definition":"to heat a liquid until it bubbles and turns to steam","collocations":["boil water","boil an egg","bring to a boil"],"example":"Boil the water before adding the pasta.","exampleZh":"加入義大利麵前先把水煮沸。","synonyms":[],"level":2,"theme":"食物與烹飪","examples":[{"en":"Boil the water before adding the pasta.","zh":"加入義大利麵前先把水煮沸。"},{"en":"Wait for the water to boil before adding the noodles.","zh":"等水沸騰之後再放入麵條。"},{"en":"She likes to boil an egg for breakfast every day.","zh":"她喜歡每天早餐水煮一顆蛋。"}]},{"word":"bold","pos":"adj.","phonetic":"[bold]","meaning":"大膽的；醒目的","definition":"showing courage or confidence; strong and noticeable","collocations":["bold move","bold colors","bold decision"],"example":"She made a bold decision to start her own business.","exampleZh":"她做出大膽的決定,自行創業。","synonyms":["brave","daring"],"level":4,"theme":"性質與描述","examples":[{"en":"She made a bold decision to start her own business.","zh":"她做出大膽的決定,自行創業。"},{"en":"It was a bold move to change careers at forty.","zh":"在四十歲轉換職涯是個大膽的舉動。"},{"en":"The poster uses bold colors to attract attention.","zh":"這張海報使用醒目的顏色來吸引注意。"}]},{"word":"bolt","pos":"n. / v.","phonetic":"[bolt]","meaning":"螺栓；閃電；逃跑；閂住","definition":"a metal pin used to fasten things, or to run away suddenly","collocations":["nuts and bolts","bolt the door","bolt out of the room"],"example":"He bolted the door before going to bed.","exampleZh":"他睡前把門閂上。","synonyms":[],"level":5,"theme":"居家與生活","examples":[{"en":"He bolted the door before going to bed.","zh":"他睡前把門閂上。"},{"en":"He tightened every bolt on the wobbly chair.","zh":"他把那張搖晃的椅子上每一顆螺栓都鎖緊。"},{"en":"The frightened cat bolted out of the room instantly.","zh":"受驚的貓瞬間衝出了房間。"}]},{"word":"bomb","pos":"n. / v.","phonetic":"[bɑm]","meaning":"炸彈；轟炸","definition":"an explosive device designed to cause damage","collocations":["drop a bomb","bomb attack","defuse a bomb"],"example":"The building was destroyed by a bomb.","exampleZh":"這棟建築物被炸彈摧毀了。","synonyms":["explosive"],"level":3,"theme":"政治與法律","examples":[{"en":"The building was destroyed by a bomb.","zh":"這棟建築物被炸彈摧毀了。"},{"en":"Soldiers worked carefully to defuse the dangerous bomb.","zh":"士兵們小心翼翼地拆解那顆危險的炸彈。"},{"en":"The old factory was destroyed by a bomb during the war.","zh":"那間老工廠在戰爭中被炸彈摧毀了。"}]},{"word":"bond","pos":"n. / v.","phonetic":"[bɑnd]","meaning":"結合；債券；緊密連結","definition":"a close connection between people, or a financial certificate","collocations":["form a bond","government bond","bond with someone"],"example":"The two friends share a strong bond.","exampleZh":"這兩位朋友之間有很深厚的情誼。","synonyms":["tie","link"],"level":5,"theme":"商業與金錢","examples":[{"en":"The two friends share a strong bond.","zh":"這兩位朋友之間有很深厚的情誼。"},{"en":"Years of friendship formed a strong bond between them.","zh":"多年的友誼在他們之間建立了深厚的情感連結。"},{"en":"Her parents invested their savings in government bonds.","zh":"她的父母把積蓄投資在政府債券上。"}]},{"word":"bone","pos":"n.","phonetic":"[bon]","meaning":"骨頭","definition":"one of the hard parts that form the skeleton","collocations":["broken bone","bone structure","dog bone"],"example":"She broke a bone in her arm.","exampleZh":"她手臂骨折了。","synonyms":[],"level":2,"theme":"身體與健康","examples":[{"en":"She broke a bone in her arm.","zh":"她手臂骨折了。"},{"en":"He broke a bone in his leg while skiing.","zh":"他滑雪時腿部斷了一根骨頭。"},{"en":"Drinking milk every day helps children build strong bones.","zh":"每天喝牛奶能幫助孩子建立強壯的骨骼。"}]},{"word":"bonus","pos":"n.","phonetic":"[ˈbonəs]","meaning":"獎金；額外好處","definition":"an extra payment or benefit given in addition to what is usual","collocations":["year-end bonus","bonus point","earn a bonus"],"example":"Employees received a bonus at the end of the year.","exampleZh":"員工在年底領到獎金。","synonyms":["reward"],"level":4,"theme":"工作與職業","examples":[{"en":"Employees received a bonus at the end of the year.","zh":"員工在年底領到獎金。"},{"en":"Every worker in the office received a generous year-end bonus.","zh":"辦公室裡的每位員工都領到了一筆優渥的年終獎金。"},{"en":"Free delivery is a nice bonus with this order.","zh":"免費運送是這筆訂單附帶的一個好處。"}]},{"word":"book","pos":"n. / v.","phonetic":"[bʊk]","meaning":"書；預訂","definition":"a set of printed pages bound together, or to reserve something","collocations":["book a ticket","read a book","book a table"],"example":"I booked a table for dinner.","exampleZh":"我預訂了晚餐的位子。","synonyms":["reserve"],"level":1,"theme":"教育與學習","examples":[{"en":"I booked a table for dinner.","zh":"我預訂了晚餐的位子。"},{"en":"I need to book a table for four this evening.","zh":"我需要為今晚預訂一張四人桌。"},{"en":"She borrowed an interesting book from the library.","zh":"她從圖書館借了一本有趣的書。"}]},{"word":"boom","pos":"n. / v.","phonetic":"[bum]","meaning":"繁榮；轟隆聲","definition":"a period of rapid economic growth, or a loud deep sound","collocations":["economic boom","baby boom","boom in sales"],"example":"The economy experienced a boom in the 1990s.","exampleZh":"經濟在1990年代蓬勃發展。","synonyms":["growth"],"level":5,"theme":"商業與金錢","examples":[{"en":"The economy experienced a boom in the 1990s.","zh":"經濟在1990年代蓬勃發展。"},{"en":"The tourism boom brought many jobs to the town.","zh":"觀光業的蓬勃發展為這個小鎮帶來許多工作機會。"},{"en":"We heard a loud boom of thunder in the distance.","zh":"我們聽見遠處傳來一聲響亮的雷鳴。"}]},{"word":"boost","pos":"v. / n.","phonetic":"[bust]","meaning":"提升；促進","definition":"to increase or improve something","collocations":["boost morale","boost sales","give a boost"],"example":"The new policy helped boost sales.","exampleZh":"新政策有助於提升銷售額。","synonyms":["increase","enhance"],"level":4,"theme":"商業與金錢","examples":[{"en":"The new policy helped boost sales.","zh":"新政策有助於提升銷售額。"},{"en":"A few kind words can boost a student's confidence.","zh":"幾句親切的話就能提升學生的信心。"},{"en":"The new advertisement gave the company's sales a boost.","zh":"這則新廣告為公司的銷售帶來了提升。"}]},{"word":"boot","pos":"n.","phonetic":"[but]","meaning":"靴子","definition":"a strong shoe that covers the foot and ankle","collocations":["pair of boots","hiking boots","rain boots"],"example":"He wore boots to walk in the snow.","exampleZh":"他穿著靴子在雪地裡走路。","synonyms":[],"level":2,"theme":"服裝與外表","examples":[{"en":"He wore boots to walk in the snow.","zh":"他穿著靴子在雪地裡走路。"},{"en":"She laced up her hiking boots before the trail.","zh":"出發走步道前，她繫好了登山靴的鞋帶。"},{"en":"Rain boots keep your feet dry on wet days.","zh":"雨鞋能在下雨天讓你的腳保持乾燥。"}]},{"word":"border","pos":"n. / v.","phonetic":"[ˈbɔrdɚ]","meaning":"邊界；邊境","definition":"a line separating two countries or areas","collocations":["cross the border","border area","border on"],"example":"The river forms the border between the two countries.","exampleZh":"這條河形成了兩國之間的邊界。","synonyms":["boundary"],"level":3,"theme":"政治與法律","examples":[{"en":"The river forms the border between the two countries.","zh":"這條河形成了兩國之間的邊界。"},{"en":"They showed their passports before crossing the border.","zh":"他們在跨越邊境前出示了護照。"},{"en":"A long fence runs along the country's northern border.","zh":"一道長長的圍籬沿著這個國家的北部邊界延伸。"}]},{"word":"bore","pos":"v.","phonetic":"[bor]","meaning":"使厭煩；鑽孔","definition":"to make someone feel uninterested or tired","collocations":["bore someone","bored to death","bore a hole"],"example":"The long lecture bored the students.","exampleZh":"這場冗長的演講讓學生覺得無聊。","synonyms":["tire"],"level":3,"theme":"情緒與感受","examples":[{"en":"The long lecture bored the students.","zh":"這場冗長的演講讓學生覺得無聊。"},{"en":"The slow documentary bored the whole class to sleep.","zh":"那部節奏緩慢的紀錄片讓全班無聊到想睡覺。"},{"en":"Workers used a machine to bore a hole in the wall.","zh":"工人用一台機器在牆上鑽了一個洞。"}]},{"word":"boring","pos":"adj.","phonetic":"[ˈborɪŋ]","meaning":"無聊的","definition":"not interesting or exciting","collocations":["boring class","boring movie","find it boring"],"example":"The movie was so boring that I fell asleep.","exampleZh":"這部電影太無聊了,我睡著了。","synonyms":["dull","tedious"],"level":2,"theme":"情緒與感受","examples":[{"en":"The movie was so boring that I fell asleep.","zh":"這部電影太無聊了,我睡著了。"},{"en":"The lecture was so boring that many students yawned.","zh":"這場演講太無聊了，許多學生都打起哈欠。"},{"en":"I find copying notes by hand quite boring.","zh":"我覺得用手抄筆記相當無聊。"}]},{"word":"born","pos":"v. / adj.","phonetic":"[bɔrn]","meaning":"出生的","definition":"having begun life; brought into existence","collocations":["be born","born in","newly born"],"example":"She was born in Taipei.","exampleZh":"她出生在台北。","synonyms":[],"level":1,"theme":"人物與家庭","examples":[{"en":"She was born in Taipei.","zh":"她出生在台北。"},{"en":"My little sister was born on a snowy morning.","zh":"我妹妹在一個下雪的早晨出生。"},{"en":"Some people seem to be born with musical talent.","zh":"有些人似乎天生就具有音樂天分。"}]},{"word":"borrow","pos":"v.","phonetic":"[ˈbɑro]","meaning":"借（入）","definition":"to take and use something with the intention of returning it","collocations":["borrow money","borrow a book","borrow from"],"example":"Can I borrow your pen for a minute?","exampleZh":"我可以借用你的筆一下嗎？","synonyms":[],"level":2,"theme":"動作與行為","examples":[{"en":"Can I borrow your pen for a minute?","zh":"我可以借用你的筆一下嗎？"},{"en":"May I borrow your umbrella until the rain stops?","zh":"我可以借用你的雨傘直到雨停嗎？"},{"en":"He had to borrow money from his brother for the trip.","zh":"他為了這趟旅行不得不向哥哥借錢。"}]},{"word":"boss","pos":"n. / v.","phonetic":"[bɔs]","meaning":"老闆；上司","definition":"a person who is in charge of workers","collocations":["work for a boss","boss around","strict boss"],"example":"My boss praised my report.","exampleZh":"我的老闆稱讚了我的報告。","synonyms":["employer"],"level":2,"theme":"工作與職業","examples":[{"en":"My boss praised my report.","zh":"我的老闆稱讚了我的報告。"},{"en":"Her boss praised her for finishing the report early.","zh":"她的老闆稱讚她提早完成了報告。"},{"en":"He doesn't like it when people boss him around.","zh":"他不喜歡別人對他頤指氣使。"}]},{"word":"both","pos":"pron. / adj.","phonetic":"[boθ]","meaning":"兩者都","definition":"used to refer to two people or things together","collocations":["both of them","both sides","both...and"],"example":"Both of my parents are teachers.","exampleZh":"我父母兩人都是老師。","synonyms":[],"level":1,"theme":"抽象概念","examples":[{"en":"Both of my parents are teachers.","zh":"我父母兩人都是老師。"},{"en":"Both of my grandparents enjoy gardening in the morning.","zh":"我的祖父母兩人都喜歡在早上做園藝。"},{"en":"She is both clever and hardworking at school.","zh":"她在學校裡既聰明又用功。"}]},{"word":"bother","pos":"v.","phonetic":"[ˈbɑðɚ]","meaning":"打擾；煩惱","definition":"to annoy, worry, or trouble someone","collocations":["bother someone","don't bother","be bothered by"],"example":"Sorry to bother you, but I have a question.","exampleZh":"抱歉打擾你,但我有個問題。","synonyms":["disturb","annoy"],"level":3,"theme":"情緒與感受","examples":[{"en":"Sorry to bother you, but I have a question.","zh":"抱歉打擾你,但我有個問題。"},{"en":"Sorry to bother you, but could you help me?","zh":"抱歉打擾你，不過你可以幫我一下嗎？"},{"en":"Don't bother waiting for me; I'll be very late.","zh":"別費心等我了，我會很晚才到。"}]},{"word":"bottle","pos":"n.","phonetic":"[ˈbɑtl̩]","meaning":"瓶子","definition":"a container with a narrow neck used for liquids","collocations":["water bottle","bottle opener","empty bottle"],"example":"She filled the bottle with water.","exampleZh":"她把瓶子裝滿了水。","synonyms":[],"level":1,"theme":"居家與生活","examples":[{"en":"She filled the bottle with water.","zh":"她把瓶子裝滿了水。"},{"en":"He always carries a water bottle to school.","zh":"他總是帶著一個水瓶去上學。"},{"en":"Please recycle the empty plastic bottles in the green bin.","zh":"請把空的塑膠瓶回收到綠色的垃圾桶裡。"}]},{"word":"bottleneck","pos":"n.","phonetic":"[ˈbɑtl̩ˌnɛk]","meaning":"瓶頸；障礙","definition":"a point of congestion that slows down progress","collocations":["traffic bottleneck","production bottleneck","remove a bottleneck"],"example":"The lack of funding is a major bottleneck for the project.","exampleZh":"資金不足是這個計畫的主要瓶頸。","synonyms":["obstacle"],"level":6,"theme":"商業與金錢","examples":[{"en":"The lack of funding is a major bottleneck for the project.","zh":"資金不足是這個計畫的主要瓶頸。"},{"en":"The single printer became a bottleneck during the busy exam week.","zh":"在忙碌的考試週，唯一的一台印表機成了瓶頸。"},{"en":"The team worked to remove the bottleneck in production.","zh":"團隊努力排除生產上的瓶頸。"}]},{"word":"bottom","pos":"n. / adj.","phonetic":"[ˈbɑtəm]","meaning":"底部","definition":"the lowest part of something","collocations":["bottom of the sea","bottom line","hit bottom"],"example":"The keys were at the bottom of the bag.","exampleZh":"鑰匙在袋子的底部。","synonyms":["base"],"level":2,"theme":"時間與空間","examples":[{"en":"The keys were at the bottom of the bag.","zh":"鑰匙在袋子的底部。"},{"en":"His keys had sunk to the bottom of the pool.","zh":"他的鑰匙沉到了游泳池的底部。"},{"en":"Read the note at the bottom of the page carefully.","zh":"仔細閱讀頁面底部的那則註記。"}]},{"word":"bounce","pos":"v. / n.","phonetic":"[baʊns]","meaning":"彈跳","definition":"to move up and down after hitting a hard surface","collocations":["bounce a ball","bounce back","bounce off"],"example":"The ball bounced off the wall.","exampleZh":"球從牆上彈了回來。","synonyms":[],"level":3,"theme":"運動與休閒","examples":[{"en":"The ball bounced off the wall.","zh":"球從牆上彈了回來。"},{"en":"The basketball bounced twice before he caught it.","zh":"籃球彈了兩下他才接住。"},{"en":"After the loss, the team managed to bounce back quickly.","zh":"輸球之後，這支隊伍很快就重新振作起來。"}]},{"word":"bound","pos":"adj. / v.","phonetic":"[baʊnd]","meaning":"受約束的；即將前往的","definition":"tied, obliged, or heading toward a destination","collocations":["bound for","bound to happen","legally bound"],"example":"The train is bound for Kaohsiung.","exampleZh":"這班火車開往高雄。","synonyms":[],"level":5,"theme":"交通與旅行","examples":[{"en":"The train is bound for Kaohsiung.","zh":"這班火車開往高雄。"},{"en":"This bus is bound for the city center.","zh":"這班公車是開往市中心的。"},{"en":"If you keep practicing, you are bound to improve.","zh":"如果你持續練習，就一定會進步。"}]},{"word":"boundary","pos":"n.","phonetic":"[ˈbaʊndərɪ]","meaning":"界線；範圍","definition":"a line that marks the limits of an area","collocations":["set a boundary","national boundary","cross a boundary"],"example":"The fence marks the boundary of the property.","exampleZh":"這道籬笆標示出這塊地產的界線。","synonyms":["border","limit"],"level":5,"theme":"政治與法律","examples":[{"en":"The fence marks the boundary of the property.","zh":"這道籬笆標示出這塊地產的界線。"},{"en":"A row of trees marks the boundary of the school.","zh":"一排樹木標示著學校的界線。"},{"en":"Good friends know how to respect each other's boundaries.","zh":"好朋友懂得尊重彼此的界線。"}]},{"word":"bouquet","pos":"n.","phonetic":"[buˈke]","meaning":"花束","definition":"a bunch of flowers arranged attractively","collocations":["bouquet of flowers","wedding bouquet","hand a bouquet"],"example":"He gave her a bouquet of roses.","exampleZh":"他送她一束玫瑰花。","synonyms":[],"level":5,"theme":"居家與生活","examples":[{"en":"He gave her a bouquet of roses.","zh":"他送她一束玫瑰花。"},{"en":"She received a beautiful bouquet of flowers on her birthday.","zh":"她在生日時收到了一束美麗的花。"},{"en":"The bride tossed her bouquet toward the excited guests.","zh":"新娘把她的捧花拋向興奮的賓客。"}]},{"word":"bow","pos":"n. / v.","phonetic":"[baʊ]","meaning":"鞠躬；弓","definition":"to bend the body forward to show respect, or a weapon for shooting arrows","collocations":["take a bow","bow and arrow","bow to someone"],"example":"The actors bowed to the audience.","exampleZh":"演員們向觀眾鞠躬。","synonyms":[],"level":3,"theme":"社會與文化","examples":[{"en":"The actors bowed to the audience.","zh":"演員們向觀眾鞠躬。"},{"en":"The pianist stood up to take a bow after the show.","zh":"演出結束後，鋼琴家起身鞠躬致意。"},{"en":"The children learned to shoot with a bow and arrow.","zh":"孩子們學會了用弓箭射擊。"}]},{"word":"bowl","pos":"n.","phonetic":"[bol]","meaning":"碗","definition":"a round, deep dish used for food or liquid","collocations":["rice bowl","bowl of soup","mixing bowl"],"example":"She served the soup in a bowl.","exampleZh":"她把湯盛在碗裡。","synonyms":[],"level":1,"theme":"食物與烹飪","examples":[{"en":"She served the soup in a bowl.","zh":"她把湯盛在碗裡。"},{"en":"She poured hot soup into a large ceramic bowl.","zh":"她把熱湯倒進一個大陶碗裡。"},{"en":"He mixed the flour and eggs in a big bowl.","zh":"他在一個大碗裡把麵粉和蛋混合在一起。"}]},{"word":"box","pos":"n. / v.","phonetic":"[bɑks]","meaning":"盒子；拳擊","definition":"a container with straight sides, or to fight with fists","collocations":["cardboard box","box office","box up"],"example":"He packed his books into a box.","exampleZh":"他把書打包裝進盒子裡。","synonyms":[],"level":1,"theme":"居家與生活","examples":[{"en":"He packed his books into a box.","zh":"他把書打包裝進盒子裡。"},{"en":"He packed all his old toys into a cardboard box.","zh":"他把所有的舊玩具都裝進一個紙箱裡。"},{"en":"The new movie did very well at the box office.","zh":"這部新電影的票房非常好。"}]},{"word":"boxer","pos":"n.","phonetic":"[ˈbɑksɚ]","meaning":"拳擊手","definition":"a person who fights as a sport using fists","collocations":["professional boxer","boxer's punch","champion boxer"],"example":"The boxer trained hard for the championship.","exampleZh":"這位拳擊手為了冠軍賽努力訓練。","synonyms":[],"level":4,"theme":"運動與休閒","examples":[{"en":"The boxer trained hard for the championship.","zh":"這位拳擊手為了冠軍賽努力訓練。"},{"en":"The young boxer practiced his punches every single morning.","zh":"這位年輕的拳擊手每天早上都練習出拳。"},{"en":"A famous boxer visited our school to give a talk.","zh":"一位知名的拳擊手來我們學校演講。"}]},{"word":"boxing","pos":"n.","phonetic":"[ˈbɑksɪŋ]","meaning":"拳擊","definition":"the sport of fighting with fists","collocations":["boxing match","boxing gloves","take up boxing"],"example":"Boxing requires speed and strength.","exampleZh":"拳擊需要速度與力量。","synonyms":[],"level":4,"theme":"運動與休閒","examples":[{"en":"Boxing requires speed and strength.","zh":"拳擊需要速度與力量。"},{"en":"He took up boxing to stay fit and strong.","zh":"他開始練拳擊以保持健康強壯。"},{"en":"Thousands of fans watched the exciting boxing match.","zh":"數千名粉絲觀看了那場精彩的拳擊比賽。"}]},{"word":"boy","pos":"n.","phonetic":"[bɔɪ]","meaning":"男孩","definition":"a male child or young man","collocations":["little boy","boy scout","boy band"],"example":"The boy played happily in the park.","exampleZh":"那個男孩在公園裡開心地玩耍。","synonyms":[],"level":1,"theme":"人物與家庭","examples":[{"en":"The boy played happily in the park.","zh":"那個男孩在公園裡開心地玩耍。"},{"en":"The little boy laughed as he chased the bubbles.","zh":"那個小男孩追著泡泡開心地笑著。"},{"en":"A boy scout helped the old lady cross the road.","zh":"一名童子軍幫助那位老太太過馬路。"}]},{"word":"boycott","pos":"v. / n.","phonetic":"[ˈbɔɪkɑt]","meaning":"抵制","definition":"to refuse to buy, use, or take part in something as a protest","collocations":["boycott a product","call for a boycott","boycott an election"],"example":"Consumers decided to boycott the company's products.","exampleZh":"消費者決定抵制這家公司的產品。","synonyms":[],"level":6,"theme":"社會與文化","examples":[{"en":"Consumers decided to boycott the company's products.","zh":"消費者決定抵制這家公司的產品。"},{"en":"Shoppers threatened to boycott the store over unfair prices.","zh":"消費者威脅要因為不公平的價格而抵制那家商店。"},{"en":"Several groups called for a boycott of the wasteful product.","zh":"好幾個團體呼籲抵制那項浪費的產品。"}]},{"word":"boyfriend","pos":"n.","phonetic":"[ˈbɔɪˌfrɛnd]","meaning":"男朋友","definition":"a male romantic partner","collocations":["have a boyfriend","ex-boyfriend","meet her boyfriend"],"example":"She introduced her boyfriend to her parents.","exampleZh":"她向父母介紹了她的男朋友。","synonyms":[],"level":2,"theme":"人物與家庭","examples":[{"en":"She introduced her boyfriend to her parents.","zh":"她向父母介紹了她的男朋友。"},{"en":"My sister broke up with her boyfriend after two years together.","zh":"我姐姐和男朋友交往兩年後分手了。"},{"en":"She was nervous about letting her parents meet her boyfriend.","zh":"她很緊張要讓父母見她的男朋友。"}]},{"word":"bracelet","pos":"n.","phonetic":"[ˈbreslɪt]","meaning":"手鐲；手鍊","definition":"a piece of jewelry worn around the wrist","collocations":["gold bracelet","wear a bracelet","charm bracelet"],"example":"She wore a silver bracelet on her wrist.","exampleZh":"她手腕上戴著一條銀手鍊。","synonyms":[],"level":3,"theme":"服裝與外表","examples":[{"en":"She wore a silver bracelet on her wrist.","zh":"她手腕上戴著一條銀手鍊。"},{"en":"My grandmother gave me a gold bracelet for my birthday.","zh":"我奶奶送了我一條金手鍊當生日禮物。"},{"en":"Each charm on her bracelet represents a special memory.","zh":"她手鍊上的每個吊飾都代表一段特別的回憶。"}]},{"word":"bracket","pos":"n.","phonetic":"[ˈbrækɪt]","meaning":"括號；等級","definition":"a mark used to enclose text, or a category or range","collocations":["square brackets","tax bracket","age bracket"],"example":"Put the extra information in brackets.","exampleZh":"把額外的資訊放在括號裡。","synonyms":[],"level":5,"theme":"溝通與語言","examples":[{"en":"Put the extra information in brackets.","zh":"把額外的資訊放在括號裡。"},{"en":"The teacher told us to put examples inside square brackets.","zh":"老師要我們把例子放進方括號裡。"},{"en":"Families in a higher tax bracket pay more each year.","zh":"所得級距較高的家庭每年要繳更多稅。"}]},{"word":"brain","pos":"n.","phonetic":"[bren]","meaning":"大腦","definition":"the organ inside the head that controls thought and feeling","collocations":["brain damage","use your brain","brain cell"],"example":"The human brain is incredibly complex.","exampleZh":"人類的大腦極其複雜。","synonyms":[],"level":2,"theme":"身體與健康","examples":[{"en":"The human brain is incredibly complex.","zh":"人類的大腦極其複雜。"},{"en":"You need to use your brain to solve this tricky puzzle.","zh":"你得動動腦筋才能解開這道棘手的謎題。"},{"en":"Scientists study how the brain stores and recalls memories.","zh":"科學家研究大腦如何儲存和喚起記憶。"}]},{"word":"brake","pos":"n. / v.","phonetic":"[brek]","meaning":"煞車","definition":"a device used to slow or stop a vehicle","collocations":["step on the brake","brake pedal","slam the brakes"],"example":"She hit the brake to avoid the dog.","exampleZh":"她踩煞車以避開那隻狗。","synonyms":[],"level":3,"theme":"交通與旅行","examples":[{"en":"She hit the brake to avoid the dog.","zh":"她踩煞車以避開那隻狗。"},{"en":"The driver slammed the brakes when a child ran across.","zh":"當一個小孩跑過馬路時，駕駛猛踩煞車。"},{"en":"My bike's brake stopped working, so I nearly crashed.","zh":"我腳踏車的煞車失靈，害我差點撞上去。"}]},{"word":"branch","pos":"n. / v.","phonetic":"[bræntʃ]","meaning":"樹枝；分行","definition":"a part of a tree that grows from the trunk, or a division of an organization","collocations":["tree branch","bank branch","branch out"],"example":"The bird sat on a branch of the tree.","exampleZh":"那隻鳥停在樹枝上。","synonyms":[],"level":3,"theme":"自然與環境","examples":[{"en":"The bird sat on a branch of the tree.","zh":"那隻鳥停在樹枝上。"},{"en":"The company opened a new branch in the city center.","zh":"這家公司在市中心開了一家新分行。"},{"en":"After years of painting, she decided to branch out into sculpture.","zh":"畫了多年後，她決定跨足雕塑領域。"}]},{"word":"brand","pos":"n. / v.","phonetic":"[brænd]","meaning":"品牌","definition":"a type of product made by a particular company","collocations":["brand name","popular brand","brand new"],"example":"This brand is known for its quality.","exampleZh":"這個品牌以品質聞名。","synonyms":[],"level":3,"theme":"商業與金錢","examples":[{"en":"This brand is known for its quality.","zh":"這個品牌以品質聞名。"},{"en":"Many teenagers only buy shoes from a famous brand name.","zh":"許多青少年只買有名品牌的鞋子。"},{"en":"He was proud to drive his brand new car to school.","zh":"他很自豪能開著全新的車去上學。"}]},{"word":"brass","pos":"n.","phonetic":"[bræs]","meaning":"黃銅；銅管樂器","definition":"a yellow metal alloy of copper and zinc, or wind instruments made of it","collocations":["brass band","brass instrument","polished brass"],"example":"The brass instruments played loudly in the parade.","exampleZh":"銅管樂器在遊行中大聲演奏。","synonyms":[],"level":5,"theme":"藝術與音樂","examples":[{"en":"The brass instruments played loudly in the parade.","zh":"銅管樂器在遊行中大聲演奏。"},{"en":"The school brass band practiced hard for the summer concert.","zh":"學校的銅管樂隊為了暑期音樂會努力練習。"},{"en":"The old door handle was made of polished brass.","zh":"那個舊門把是用擦亮的黃銅製成的。"}]},{"word":"brave","pos":"adj.","phonetic":"[brev]","meaning":"勇敢的","definition":"showing courage in the face of danger or pain","collocations":["brave soldier","brave decision","stay brave"],"example":"The firefighter was brave enough to enter the burning building.","exampleZh":"那位消防員勇敢地進入了燃燒的建築物。","synonyms":["courageous","bold"],"level":2,"theme":"性質與描述","examples":[{"en":"The firefighter was brave enough to enter the burning building.","zh":"那位消防員勇敢地進入了燃燒的建築物。"},{"en":"It was a brave decision to quit her job and travel alone.","zh":"辭掉工作獨自旅行是個勇敢的決定。"},{"en":"The little boy stayed brave while the doctor treated his wound.","zh":"醫生處理傷口時，那個小男孩保持勇敢。"}]},{"word":"bravery","pos":"n.","phonetic":"[ˈbrevərɪ]","meaning":"勇氣","definition":"courageous behavior or character","collocations":["act of bravery","show bravery","medal for bravery"],"example":"He was awarded a medal for his bravery.","exampleZh":"他因勇敢的行為獲頒獎章。","synonyms":["courage"],"level":4,"theme":"性質與描述","examples":[{"en":"He was awarded a medal for his bravery.","zh":"他因勇敢的行為獲頒獎章。"},{"en":"The rescuers showed great bravery during the flood.","zh":"救難人員在洪水中展現了極大的勇氣。"},{"en":"Her act of bravery saved several children from the fire.","zh":"她勇敢的舉動從火場中救出了好幾個孩子。"}]},{"word":"bread","pos":"n.","phonetic":"[brɛd]","meaning":"麵包","definition":"a food made by baking a mixture of flour and water","collocations":["loaf of bread","bread and butter","slice of bread"],"example":"She spread butter on the bread.","exampleZh":"她在麵包上塗奶油。","synonyms":[],"level":1,"theme":"食物與烹飪","examples":[{"en":"She spread butter on the bread.","zh":"她在麵包上塗奶油。"},{"en":"He bought a fresh loaf of bread from the bakery.","zh":"他從麵包店買了一條新鮮的麵包。"},{"en":"For breakfast I usually eat two slices of bread with jam.","zh":"早餐我通常吃兩片塗果醬的麵包。"}]},{"word":"break","pos":"v. / n.","phonetic":"[brek]","meaning":"打破；休息","definition":"to separate into pieces suddenly, or a period of rest","collocations":["take a break","break a rule","break down"],"example":"Let's take a short break before continuing.","exampleZh":"我們在繼續之前先休息一下。","synonyms":[],"level":1,"theme":"動作與行為","examples":[{"en":"Let's take a short break before continuing.","zh":"我們在繼續之前先休息一下。"},{"en":"Students who break the rules will be sent to the office.","zh":"違反規定的學生會被送到辦公室。"},{"en":"Be careful not to break the glass while washing it.","zh":"洗玻璃杯時小心別打破它。"}]},{"word":"breakdown","pos":"n.","phonetic":"[ˈbrekˌdaʊn]","meaning":"故障；崩潰","definition":"a failure of a machine, system, or relationship","collocations":["nervous breakdown","mechanical breakdown","complete breakdown"],"example":"The car had a breakdown on the highway.","exampleZh":"那輛車在高速公路上拋錨了。","synonyms":[],"level":5,"theme":"其他","examples":[{"en":"The car had a breakdown on the highway.","zh":"那輛車在高速公路上拋錨了。"},{"en":"Working too many hours led him to a nervous breakdown.","zh":"工時過長導致他精神崩潰。"},{"en":"A mechanical breakdown forced the train to stop for an hour.","zh":"機械故障迫使火車停了一個小時。"}]},{"word":"breakfast","pos":"n.","phonetic":"[ˈbrɛkfəst]","meaning":"早餐","definition":"the first meal of the day","collocations":["eat breakfast","breakfast table","skip breakfast"],"example":"We had toast and eggs for breakfast.","exampleZh":"我們早餐吃了吐司和蛋。","synonyms":[],"level":1,"theme":"食物與烹飪","examples":[{"en":"We had toast and eggs for breakfast.","zh":"我們早餐吃了吐司和蛋。"},{"en":"Doctors warn that students should never skip breakfast before exams.","zh":"醫生警告學生考試前絕不該不吃早餐。"},{"en":"The whole family gathered around the breakfast table on Sunday.","zh":"星期天全家人圍坐在早餐桌旁。"}]},{"word":"breakthrough","pos":"n.","phonetic":"[ˈbrekˌθru]","meaning":"突破","definition":"a sudden important discovery or development","collocations":["scientific breakthrough","major breakthrough","make a breakthrough"],"example":"Scientists made a breakthrough in cancer research.","exampleZh":"科學家在癌症研究上有了重大突破。","synonyms":[],"level":6,"theme":"科學與數學","examples":[{"en":"Scientists made a breakthrough in cancer research.","zh":"科學家在癌症研究上有了重大突破。"},{"en":"The team finally made a breakthrough after months of research.","zh":"經過數月的研究，團隊終於有了突破。"},{"en":"This major breakthrough could change how we treat the disease.","zh":"這項重大突破可能改變我們治療這種疾病的方式。"}]},{"word":"breast","pos":"n.","phonetic":"[brɛst]","meaning":"胸部","definition":"the front part of the chest","collocations":["chicken breast","breast cancer","breast feeding"],"example":"The recipe calls for chicken breast.","exampleZh":"這道食譜需要用到雞胸肉。","synonyms":[],"level":3,"theme":"身體與健康","examples":[{"en":"The recipe calls for chicken breast.","zh":"這道食譜需要用到雞胸肉。"},{"en":"She grilled a chicken breast and served it with salad.","zh":"她烤了一塊雞胸肉，並搭配沙拉一起上桌。"},{"en":"Regular checkups can help detect breast cancer early.","zh":"定期檢查有助於及早發現乳癌。"}]},{"word":"breath","pos":"n.","phonetic":"[brɛθ]","meaning":"呼吸","definition":"the air taken into and let out of the lungs","collocations":["take a breath","hold your breath","out of breath"],"example":"She took a deep breath before speaking.","exampleZh":"她說話前深吸了一口氣。","synonyms":[],"level":2,"theme":"身體與健康","examples":[{"en":"She took a deep breath before speaking.","zh":"她說話前深吸了一口氣。"},{"en":"After running upstairs, he was completely out of breath.","zh":"跑上樓後，他喘得上氣不接下氣。"},{"en":"Hold your breath for a moment while I take the photo.","zh":"我拍照時你先屏住呼吸一下。"}]},{"word":"breathe","pos":"v.","phonetic":"[brið]","meaning":"呼吸","definition":"to take air into the lungs and let it out","collocations":["breathe deeply","breathe fresh air","breathe in"],"example":"It's hard to breathe in such polluted air.","exampleZh":"在這麼污染的空氣中很難呼吸。","synonyms":[],"level":2,"theme":"身體與健康","examples":[{"en":"It's hard to breathe in such polluted air.","zh":"在這麼污染的空氣中很難呼吸。"},{"en":"The doctor asked me to breathe deeply and relax.","zh":"醫生要我深呼吸並放輕鬆。"},{"en":"It feels wonderful to breathe fresh air in the mountains.","zh":"在山上呼吸新鮮空氣的感覺真棒。"}]},{"word":"breed","pos":"v. / n.","phonetic":"[brid]","meaning":"繁殖；品種","definition":"to produce offspring, or a particular type of animal","collocations":["breed dogs","rare breed","breed cattle"],"example":"Farmers breed cattle for milk and meat.","exampleZh":"農夫養牛以生產牛奶和肉類。","synonyms":[],"level":4,"theme":"動物與植物","examples":[{"en":"Farmers breed cattle for milk and meat.","zh":"農夫養牛以生產牛奶和肉類。"},{"en":"This is a rare breed of dog seldom seen in Taiwan.","zh":"這是一種在台灣很少見的稀有犬種。"},{"en":"Salmon swim upstream to breed in the rivers where they were born.","zh":"鮭魚逆流而上，回到出生的河流繁殖。"}]},{"word":"breeze","pos":"n.","phonetic":"[briz]","meaning":"微風","definition":"a gentle wind","collocations":["cool breeze","ocean breeze","light breeze"],"example":"A gentle breeze blew through the window.","exampleZh":"一陣微風從窗戶吹進來。","synonyms":["wind"],"level":3,"theme":"天氣與季節","examples":[{"en":"A gentle breeze blew through the window.","zh":"一陣微風從窗戶吹進來。"},{"en":"A cool breeze made the hot afternoon much more pleasant.","zh":"一陣涼爽的微風讓炎熱的午後舒服多了。"},{"en":"We sat on the beach enjoying the gentle ocean breeze.","zh":"我們坐在沙灘上，享受輕柔的海風。"}]},{"word":"brick","pos":"n.","phonetic":"[brɪk]","meaning":"磚頭","definition":"a rectangular block of baked clay used for building","collocations":["brick wall","red brick","lay bricks"],"example":"The house is made of red brick.","exampleZh":"這棟房子是用紅磚蓋的。","synonyms":[],"level":2,"theme":"居家與生活","examples":[{"en":"The house is made of red brick.","zh":"這棟房子是用紅磚蓋的。"},{"en":"The workers spent all day laying bricks for the new wall.","zh":"工人們花了一整天砌磚建新牆。"},{"en":"The children accidentally kicked their ball over the brick wall.","zh":"孩子們不小心把球踢過了磚牆。"}]},{"word":"bride","pos":"n.","phonetic":"[braɪd]","meaning":"新娘","definition":"a woman on her wedding day","collocations":["beautiful bride","bride and groom","give away the bride"],"example":"The bride wore a white dress.","exampleZh":"新娘穿著白色的婚紗。","synonyms":[],"level":3,"theme":"人物與家庭","examples":[{"en":"The bride wore a white dress.","zh":"新娘穿著白色的婚紗。"},{"en":"The bride and groom exchanged rings in front of their guests.","zh":"新娘和新郎在賓客面前交換戒指。"},{"en":"Her father proudly walked in to give away the bride.","zh":"她的父親自豪地走進來，把新娘交給新郎。"}]},{"word":"bridge","pos":"n. / v.","phonetic":"[brɪdʒ]","meaning":"橋樑","definition":"a structure built to allow crossing over a river or road","collocations":["cross a bridge","build a bridge","bridge the gap"],"example":"The bridge connects the two cities.","exampleZh":"這座橋連接了這兩座城市。","synonyms":[],"level":2,"theme":"交通與旅行","examples":[{"en":"The bridge connects the two cities.","zh":"這座橋連接了這兩座城市。"},{"en":"We had to cross a long bridge to reach the island.","zh":"我們得越過一座長橋才能抵達那座島。"},{"en":"Learning each other's language can bridge the gap between cultures.","zh":"學習彼此的語言能縮小文化之間的隔閡。"}]},{"word":"brief","pos":"adj. / n.","phonetic":"[brif]","meaning":"簡短的","definition":"short in duration or length","collocations":["brief summary","in brief","brief moment"],"example":"He gave a brief explanation of the plan.","exampleZh":"他對計畫做了簡短的說明。","synonyms":["short"],"level":3,"theme":"溝通與語言","examples":[{"en":"He gave a brief explanation of the plan.","zh":"他對計畫做了簡短的說明。"},{"en":"Please write a brief summary of the article in three sentences.","zh":"請用三句話寫出這篇文章的簡短摘要。"},{"en":"For a brief moment, the whole room fell completely silent.","zh":"有那麼一瞬間，整個房間變得鴉雀無聲。"}]},{"word":"bright","pos":"adj.","phonetic":"[braɪt]","meaning":"明亮的；聰明的","definition":"full of light, or intelligent and quick to learn","collocations":["bright light","bright student","bright future"],"example":"The bright sun woke her up early.","exampleZh":"明亮的陽光讓她一早就醒來。","synonyms":["shining","clever"],"level":1,"theme":"性質與描述","examples":[{"en":"The bright sun woke her up early.","zh":"明亮的陽光讓她一早就醒來。"},{"en":"She is a bright student who always asks thoughtful questions.","zh":"她是個聰明的學生，總是提出有深度的問題。"},{"en":"With hard work, you can build a bright future for yourself.","zh":"透過努力，你能為自己打造光明的未來。"}]},{"word":"brilliant","pos":"adj.","phonetic":"[ˈbrɪljənt]","meaning":"傑出的；燦爛的","definition":"exceptionally clever, talented, or impressive","collocations":["brilliant idea","brilliant student","brilliant performance"],"example":"She came up with a brilliant solution.","exampleZh":"她想出了一個絕妙的解決方案。","synonyms":["excellent","outstanding"],"level":4,"theme":"性質與描述","examples":[{"en":"She came up with a brilliant solution.","zh":"她想出了一個絕妙的解決方案。"},{"en":"Her brilliant performance earned a standing ovation from the audience.","zh":"她精彩的表演贏得觀眾起立鼓掌。"},{"en":"What a brilliant idea to recycle old bottles into lamps!","zh":"把舊瓶子回收做成燈，真是個絕妙的點子！"}]},{"word":"bring","pos":"v.","phonetic":"[brɪŋ]","meaning":"帶來","definition":"to take or carry something to a place","collocations":["bring a gift","bring about","bring up"],"example":"Please bring your book to class tomorrow.","exampleZh":"請明天把書帶來上課。","synonyms":[],"level":1,"theme":"動作與行為","examples":[{"en":"Please bring your book to class tomorrow.","zh":"請明天把書帶來上課。"},{"en":"Remember to bring an umbrella because it might rain later.","zh":"記得帶把傘，因為待會兒可能會下雨。"},{"en":"New technology has brought about huge changes in education.","zh":"新科技為教育帶來了巨大的改變。"}]},{"word":"broad","pos":"adj.","phonetic":"[brɔd]","meaning":"寬闊的","definition":"wide in extent or scope","collocations":["broad shoulders","broad range","broad daylight"],"example":"The river has a broad, calm surface.","exampleZh":"這條河的水面寬闊而平靜。","synonyms":["wide"],"level":3,"theme":"性質與描述","examples":[{"en":"The river has a broad, calm surface.","zh":"這條河的水面寬闊而平靜。"},{"en":"The store offers a broad range of products at low prices.","zh":"這家店以低價提供種類廣泛的商品。"},{"en":"The thief stole the bike in broad daylight.","zh":"小偷在光天化日之下偷走了那輛腳踏車。"}]},{"word":"broadcast","pos":"v. / n.","phonetic":"[ˈbrɔdˌkæst]","meaning":"廣播；播送","definition":"to send out a program on television or radio","collocations":["live broadcast","broadcast news","broadcast live"],"example":"The game was broadcast live around the world.","exampleZh":"這場比賽在全球現場直播。","synonyms":[],"level":4,"theme":"科技與媒體","examples":[{"en":"The game was broadcast live around the world.","zh":"這場比賽在全球現場直播。"},{"en":"The station will broadcast the concert live tomorrow evening.","zh":"電視台明晚將現場直播這場音樂會。"},{"en":"Millions of viewers watched the live broadcast of the ceremony.","zh":"數百萬觀眾收看了這場典禮的現場直播。"}]},{"word":"broken","pos":"adj.","phonetic":"[ˈbrokən]","meaning":"破碎的","definition":"damaged, shattered, or no longer working","collocations":["broken window","broken heart","broken promise"],"example":"The broken window let cold air in.","exampleZh":"破掉的窗戶讓冷空氣進來。","synonyms":[],"level":1,"theme":"性質與描述","examples":[{"en":"The broken window let cold air in.","zh":"破掉的窗戶讓冷空氣進來。"},{"en":"A broken promise can easily destroy someone's trust in you.","zh":"一個未實現的承諾很容易摧毀別人對你的信任。"},{"en":"He felt a broken heart after his best friend moved away.","zh":"最好的朋友搬走後，他傷心欲絕。"}]},{"word":"brook","pos":"n.","phonetic":"[brʊk]","meaning":"小溪","definition":"a small natural stream of water","collocations":["babbling brook","cross a brook","fish in a brook"],"example":"We fished in the brook near our house.","exampleZh":"我們在家附近的小溪釣魚。","synonyms":["stream"],"level":5,"theme":"自然與環境","examples":[{"en":"We fished in the brook near our house.","zh":"我們在家附近的小溪釣魚。"},{"en":"A clear brook runs through the quiet little village.","zh":"一條清澈的小溪流經這個寧靜的小村莊。"},{"en":"We stepped on the rocks to cross the shallow brook.","zh":"我們踩著石頭越過那條淺淺的小溪。"}]},{"word":"broom","pos":"n.","phonetic":"[brum]","meaning":"掃帚","definition":"a brush with a long handle used for sweeping floors","collocations":["sweep with a broom","broom closet","new broom"],"example":"She swept the floor with a broom.","exampleZh":"她用掃帚掃地。","synonyms":[],"level":2,"theme":"居家與生活","examples":[{"en":"She swept the floor with a broom.","zh":"她用掃帚掃地。"},{"en":"He grabbed a broom to sweep the fallen leaves off the porch.","zh":"他拿起掃帚，把門廊上的落葉掃乾淨。"},{"en":"The old broom is kept in the closet near the kitchen.","zh":"那把舊掃帚放在廚房旁的儲物間裡。"}]},{"word":"brother","pos":"n.","phonetic":"[ˈbrʌðɚ]","meaning":"兄弟","definition":"a male sibling","collocations":["older brother","younger brother","brother-in-law"],"example":"My brother and I share a room.","exampleZh":"我和我哥哥共用一間房間。","synonyms":[],"level":1,"theme":"人物與家庭","examples":[{"en":"My brother and I share a room.","zh":"我和我哥哥共用一間房間。"},{"en":"My older brother taught me how to ride a bicycle.","zh":"我哥哥教我怎麼騎腳踏車。"},{"en":"Her younger brother is always borrowing her headphones without asking.","zh":"她弟弟總是不問一聲就借走她的耳機。"}]},{"word":"brow","pos":"n.","phonetic":"[braʊ]","meaning":"眉毛；額頭","definition":"the forehead, or the hair above the eye","collocations":["raise an eyebrow","furrowed brow","wipe one's brow"],"example":"He wiped the sweat from his brow.","exampleZh":"他擦去額頭上的汗水。","synonyms":["forehead"],"level":5,"theme":"身體與健康","examples":[{"en":"He wiped the sweat from his brow.","zh":"他擦去額頭上的汗水。"},{"en":"She raised an eyebrow when she heard his strange excuse.","zh":"聽到他奇怪的藉口時，她挑了挑眉。"},{"en":"With a furrowed brow, he tried to solve the hard math problem.","zh":"他皺著眉頭，努力解那道困難的數學題。"}]},{"word":"brown","pos":"adj. / n.","phonetic":"[braʊn]","meaning":"棕色的","definition":"having the color of soil, wood, or coffee","collocations":["brown hair","brown bread","dark brown"],"example":"She has brown eyes and brown hair.","exampleZh":"她有棕色的眼睛和棕色的頭髮。","synonyms":[],"level":1,"theme":"服裝與外表","examples":[{"en":"She has brown eyes and brown hair.","zh":"她有棕色的眼睛和棕色的頭髮。"},{"en":"She prefers brown bread because it is healthier than white.","zh":"她偏愛全麥麵包，因為它比白麵包健康。"},{"en":"The autumn leaves slowly turned a deep, dark brown.","zh":"秋天的葉子慢慢轉為深棕色。"}]},{"word":"browse","pos":"v.","phonetic":"[braʊz]","meaning":"瀏覽","definition":"to look through something in a casual way","collocations":["browse the internet","browse a store","browse through"],"example":"I like to browse the shelves in bookstores.","exampleZh":"我喜歡在書店裡瀏覽書架。","synonyms":[],"level":4,"theme":"科技與媒體","examples":[{"en":"I like to browse the shelves in bookstores.","zh":"我喜歡在書店裡瀏覽書架。"},{"en":"She likes to browse the internet for new recipes.","zh":"她喜歡上網瀏覽新食譜。"},{"en":"We spent an hour browsing through the old bookshop.","zh":"我們花了一個小時在那家舊書店裡隨意翻看。"}]},{"word":"browser","pos":"n.","phonetic":"[ˈbraʊzɚ]","meaning":"瀏覽器","definition":"software used to access and view information on the internet","collocations":["web browser","browser history","open a browser"],"example":"He opened his browser to search for information.","exampleZh":"他打開瀏覽器搜尋資訊。","synonyms":[],"level":4,"theme":"科技與媒體","examples":[{"en":"He opened his browser to search for information.","zh":"他打開瀏覽器搜尋資訊。"},{"en":"You should clear your browser history to protect your privacy.","zh":"你應該清除瀏覽器的紀錄以保護隱私。"},{"en":"This web browser loads pages faster than the older one.","zh":"這個網頁瀏覽器載入頁面比舊的快。"}]},{"word":"bruise","pos":"n. / v.","phonetic":"[bruz]","meaning":"瘀傷","definition":"a discolored mark left on the skin after an injury","collocations":["get a bruise","bruise easily","nasty bruise"],"example":"She had a bruise on her knee after falling.","exampleZh":"她跌倒後膝蓋上有一塊瘀傷。","synonyms":[],"level":5,"theme":"身體與健康","examples":[{"en":"She had a bruise on her knee after falling.","zh":"她跌倒後膝蓋上有一塊瘀傷。"},{"en":"He got a nasty bruise after falling off his skateboard.","zh":"他從滑板上摔下來後，留下一塊嚴重的瘀傷。"},{"en":"Some people bruise easily even after a light bump.","zh":"有些人即使輕輕碰一下也很容易瘀青。"}]},{"word":"brush","pos":"n. / v.","phonetic":"[brʌʃ]","meaning":"刷子；刷","definition":"a tool with bristles used for cleaning, painting, or grooming","collocations":["toothbrush","brush your hair","brush aside"],"example":"She brushes her teeth twice a day.","exampleZh":"她一天刷兩次牙。","synonyms":[],"level":2,"theme":"居家與生活","examples":[{"en":"She brushes her teeth twice a day.","zh":"她一天刷兩次牙。"},{"en":"Don't forget to brush your hair before the interview.","zh":"面試前別忘了梳頭髮。"},{"en":"The painter used a fine brush to add tiny details.","zh":"畫家用一支細刷子添上細微的細節。"}]},{"word":"brutal","pos":"adj.","phonetic":"[ˈbrutl̩]","meaning":"殘忍的","definition":"savagely violent or cruel","collocations":["brutal attack","brutal honesty","brutal weather"],"example":"The war led to brutal violence.","exampleZh":"這場戰爭導致了殘忍的暴力事件。","synonyms":["cruel","violent"],"level":5,"theme":"性質與描述","examples":[{"en":"The war led to brutal violence.","zh":"這場戰爭導致了殘忍的暴力事件。"},{"en":"The hikers struggled through the brutal weather on the mountain.","zh":"登山者在山上艱難地與惡劣天氣搏鬥。"},{"en":"I appreciate his brutal honesty, even when it hurts.","zh":"我欣賞他毫不留情的坦率，即使那很傷人。"}]},{"word":"bubble","pos":"n. / v.","phonetic":"[ˈbʌbl̩]","meaning":"泡泡","definition":"a small ball of air or gas surrounded by liquid","collocations":["soap bubble","bubble tea","bubble up"],"example":"The children blew bubbles in the garden.","exampleZh":"孩子們在花園裡吹泡泡。","synonyms":[],"level":2,"theme":"居家與生活","examples":[{"en":"The children blew bubbles in the garden.","zh":"孩子們在花園裡吹泡泡。"},{"en":"After class, my friends and I went out for bubble tea.","zh":"下課後，我和朋友出去喝珍珠奶茶。"},{"en":"The children laughed as soap bubbles floated across the yard.","zh":"肥皂泡飄過院子時，孩子們笑了起來。"}]},{"word":"bucket","pos":"n.","phonetic":"[ˈbʌkɪt]","meaning":"水桶","definition":"a round open container with a handle, used to carry liquids","collocations":["bucket of water","kick the bucket","mop and bucket"],"example":"He filled the bucket with water.","exampleZh":"他把水桶裝滿水。","synonyms":["pail"],"level":2,"theme":"居家與生活","examples":[{"en":"He filled the bucket with water.","zh":"他把水桶裝滿水。"},{"en":"She carried a heavy bucket of water to the garden.","zh":"她提著一桶沉重的水到花園去。"},{"en":"Grab a mop and bucket to clean up the spilled juice.","zh":"拿拖把和水桶來清理灑出的果汁。"}]},{"word":"buckle","pos":"n. / v.","phonetic":"[ˈbʌkl̩]","meaning":"扣環；扣緊","definition":"a fastening device on a belt or strap, or to fasten with one","collocations":["seat belt buckle","buckle up","buckle a belt"],"example":"Please buckle your seat belt before we drive.","exampleZh":"開車前請繫好安全帶。","synonyms":[],"level":4,"theme":"服裝與外表","examples":[{"en":"Please buckle your seat belt before we drive.","zh":"開車前請繫好安全帶。"},{"en":"Always buckle up before the car starts moving.","zh":"車子開動前一定要繫好安全帶。"},{"en":"The metal buckle on his backpack finally broke.","zh":"他背包上的金屬扣環終於壞了。"}]},{"word":"budget","pos":"n. / v.","phonetic":"[ˈbʌdʒɪt]","meaning":"預算","definition":"a plan for how money will be spent","collocations":["tight budget","family budget","budget for"],"example":"We need to stick to our budget this month.","exampleZh":"我們這個月必須遵守預算。","synonyms":[],"level":3,"theme":"商業與金錢","examples":[{"en":"We need to stick to our budget this month.","zh":"我們這個月必須遵守預算。"},{"en":"On a tight budget, they cooked at home instead of eating out.","zh":"在預算吃緊的情況下，他們在家做飯而不外食。"},{"en":"We must budget for unexpected repairs on the old house.","zh":"我們必須為這棟老房子的意外維修編列預算。"}]},{"word":"buffet","pos":"n.","phonetic":"[bəˈfe]","meaning":"自助餐","definition":"a meal at which guests serve themselves from a range of dishes","collocations":["buffet dinner","all-you-can-eat buffet","buffet table"],"example":"We had lunch at a buffet restaurant.","exampleZh":"我們在自助餐廳吃了午餐。","synonyms":[],"level":4,"theme":"食物與烹飪","examples":[{"en":"We had lunch at a buffet restaurant.","zh":"我們在自助餐廳吃了午餐。"},{"en":"The hotel offers an all-you-can-eat buffet every weekend.","zh":"這家飯店每個週末都提供吃到飽的自助餐。"},{"en":"The buffet table was covered with dishes from around the world.","zh":"自助餐桌上擺滿了來自世界各地的菜餚。"}]},{"word":"bug","pos":"n. / v.","phonetic":"[bʌg]","meaning":"蟲子；程式錯誤；使煩惱","definition":"a small insect, or a defect in a computer program","collocations":["computer bug","bug someone","fix a bug"],"example":"There is a bug in the new software.","exampleZh":"這個新軟體有一個程式錯誤。","synonyms":["insect"],"level":2,"theme":"科技與媒體","examples":[{"en":"There is a bug in the new software.","zh":"這個新軟體有一個程式錯誤。"},{"en":"The programmer worked late to fix a bug in the app.","zh":"程式設計師工作到很晚，就為了修正應用程式裡的一個錯誤。"},{"en":"Stop bugging me while I'm trying to finish my homework.","zh":"我在寫作業的時候別煩我。"}]},{"word":"build","pos":"v.","phonetic":"[bɪld]","meaning":"建造","definition":"to construct something by putting parts together","collocations":["build a house","build a relationship","build up"],"example":"They plan to build a new bridge next year.","exampleZh":"他們計畫明年建造一座新橋。","synonyms":["construct"],"level":1,"theme":"動作與行為","examples":[{"en":"They plan to build a new bridge next year.","zh":"他們計畫明年建造一座新橋。"},{"en":"It takes time and honesty to build a strong relationship.","zh":"建立穩固的關係需要時間和誠實。"},{"en":"The workers will build a new library beside the school.","zh":"工人們將在學校旁邊蓋一座新圖書館。"}]},{"word":"builder","pos":"n.","phonetic":"[ˈbɪldɚ]","meaning":"建造者；建築工人","definition":"a person or company that constructs buildings","collocations":["home builder","skilled builder","hire a builder"],"example":"The builder finished the house on schedule.","exampleZh":"這位建築工人如期完成了房子。","synonyms":[],"level":3,"theme":"工作與職業","examples":[{"en":"The builder finished the house on schedule.","zh":"這位建築工人如期完成了房子。"},{"en":"They hired a skilled builder to renovate their kitchen.","zh":"他們雇了一位技術純熟的建築工人來翻修廚房。"},{"en":"The builder promised to finish the roof before the rainy season.","zh":"建築工人承諾在雨季前完成屋頂。"}]},{"word":"building","pos":"n.","phonetic":"[ˈbɪldɪŋ]","meaning":"建築物","definition":"a structure with a roof and walls used for living or working","collocations":["tall building","office building","building material"],"example":"The office building has twenty floors.","exampleZh":"這棟辦公大樓有二十層樓。","synonyms":[],"level":1,"theme":"居家與生活","examples":[{"en":"The office building has twenty floors.","zh":"這棟辦公大樓有二十層樓。"},{"en":"The tallest building in the city has over eighty floors.","zh":"這座城市最高的建築物有超過八十層樓。"},{"en":"Concrete and steel are common building materials today.","zh":"混凝土和鋼鐵是今日常見的建築材料。"}]},{"word":"bulb","pos":"n.","phonetic":"[bʌlb]","meaning":"燈泡；球根","definition":"a glass object that produces light, or a rounded root of a plant","collocations":["light bulb","flower bulb","change a bulb"],"example":"The light bulb burned out last night.","exampleZh":"燈泡昨晚燒壞了。","synonyms":[],"level":3,"theme":"科技與媒體","examples":[{"en":"The light bulb burned out last night.","zh":"燈泡昨晚燒壞了。"},{"en":"Please change the bulb in the hallway; it keeps flickering.","zh":"請換掉走廊上的燈泡，它一直閃爍。"},{"en":"In autumn we plant tulip bulbs so they bloom in spring.","zh":"秋天我們種下鬱金香球根，好讓它們在春天開花。"}]},{"word":"bulk","pos":"n.","phonetic":"[bʌlk]","meaning":"大量；體積","definition":"the large size, mass, or quantity of something","collocations":["in bulk","bulk of the work","bulk buying"],"example":"We buy rice in bulk to save money.","exampleZh":"我們大量購買米以節省開銷。","synonyms":[],"level":5,"theme":"商業與金錢","examples":[{"en":"We buy rice in bulk to save money.","zh":"我們大量購買米以節省開銷。"},{"en":"Buying rice in bulk is cheaper for a large family.","zh":"對一個大家庭來說，大量購買米比較便宜。"},{"en":"A few volunteers did the bulk of the work at the event.","zh":"少數幾位志工完成了活動大部分的工作。"}]},{"word":"bull","pos":"n.","phonetic":"[bʊl]","meaning":"公牛","definition":"an adult male of the cattle family","collocations":["bull market","charging bull","bull fight"],"example":"The bull ran across the field.","exampleZh":"那頭公牛跑過田野。","synonyms":[],"level":3,"theme":"動物與植物","examples":[{"en":"The bull ran across the field.","zh":"那頭公牛跑過田野。"},{"en":"The angry bull charged straight toward the red flag.","zh":"憤怒的公牛直直朝紅旗衝了過去。"},{"en":"During a bull market, many people rush to buy stocks.","zh":"在牛市期間，許多人搶著買股票。"}]},{"word":"bullet","pos":"n.","phonetic":"[ˈbʊlɪt]","meaning":"子彈","definition":"a small metal projectile fired from a gun","collocations":["bullet wound","fire a bullet","bullet train"],"example":"The bullet missed its target.","exampleZh":"那顆子彈沒有擊中目標。","synonyms":[],"level":4,"theme":"政治與法律","examples":[{"en":"The bullet missed its target.","zh":"那顆子彈沒有擊中目標。"},{"en":"We took the bullet train from Taipei to Kaohsiung.","zh":"我們搭高鐵從台北到高雄。"},{"en":"The soldier was lucky that the bullet only grazed his arm.","zh":"那名士兵很幸運，子彈只擦過他的手臂。"}]},{"word":"bully","pos":"n. / v.","phonetic":"[ˈbʊlɪ]","meaning":"惡霸；欺負","definition":"a person who hurts or frightens weaker people, or to act this way","collocations":["school bully","bully someone","stand up to a bully"],"example":"The teacher stopped the bully from hurting the boy.","exampleZh":"老師阻止了那個惡霸傷害那個男孩。","synonyms":[],"level":4,"theme":"社會與文化","examples":[{"en":"The teacher stopped the bully from hurting the boy.","zh":"老師阻止了那個惡霸傷害那個男孩。"},{"en":"The teacher encouraged students to stand up to a bully.","zh":"老師鼓勵學生勇敢對抗霸凌者。"},{"en":"It is wrong to bully classmates who are smaller than you.","zh":"欺負比你弱小的同學是不對的。"}]},{"word":"bump","pos":"v. / n.","phonetic":"[bʌmp]","meaning":"碰撞","definition":"to hit against something accidentally","collocations":["bump into","bump one's head","bump up"],"example":"I bumped into an old friend at the mall.","exampleZh":"我在購物中心巧遇一位老朋友。","synonyms":[],"level":3,"theme":"動作與行為","examples":[{"en":"I bumped into an old friend at the mall.","zh":"我在購物中心巧遇一位老朋友。"},{"en":"Be careful not to bump your head on the low doorway.","zh":"小心別在低矮的門口撞到頭。"},{"en":"I bumped into my old teacher at the train station yesterday.","zh":"昨天我在火車站巧遇以前的老師。"}]},{"word":"bunch","pos":"n.","phonetic":"[bʌntʃ]","meaning":"一束；一群","definition":"a group of things growing or fastened together","collocations":["bunch of flowers","bunch of grapes","a whole bunch"],"example":"She bought a bunch of bananas.","exampleZh":"她買了一串香蕉。","synonyms":["cluster"],"level":3,"theme":"食物與烹飪","examples":[{"en":"She bought a bunch of bananas.","zh":"她買了一串香蕉。"},{"en":"He gave his mother a bunch of flowers on Mother's Day.","zh":"母親節時他送給媽媽一束花。"},{"en":"A whole bunch of students signed up for the science club.","zh":"一大群學生報名參加了科學社。"}]},{"word":"bundle","pos":"n. / v.","phonetic":"[ˈbʌndl̩]","meaning":"捆；包裹","definition":"a collection of things tied or wrapped together","collocations":["bundle of clothes","bundle up","bundle of joy"],"example":"He carried a bundle of newspapers.","exampleZh":"他抱著一捆報紙。","synonyms":[],"level":5,"theme":"居家與生活","examples":[{"en":"He carried a bundle of newspapers.","zh":"他抱著一捆報紙。"},{"en":"She tied the old letters into a neat bundle.","zh":"她把舊信件綁成整齊的一捆。"},{"en":"Bundle up warmly before you go out into the snow.","zh":"出門到雪地裡之前，把自己包得暖暖的。"}]},{"word":"burden","pos":"n. / v.","phonetic":"[ˈbɝdn̩]","meaning":"負擔","definition":"a heavy load or a difficult responsibility","collocations":["financial burden","carry a burden","burden someone with"],"example":"The debt became a heavy burden on the family.","exampleZh":"這筆債務成為這個家庭沉重的負擔。","synonyms":["load"],"level":5,"theme":"抽象概念","examples":[{"en":"The debt became a heavy burden on the family.","zh":"這筆債務成為這個家庭沉重的負擔。"},{"en":"Paying for college can be a heavy financial burden for parents.","zh":"支付大學學費對父母來說可能是沉重的經濟負擔。"},{"en":"She didn't want to burden her friends with her worries.","zh":"她不想把自己的煩惱加諸在朋友身上。"}]},{"word":"burger","pos":"n.","phonetic":"[ˈbɝgɚ]","meaning":"漢堡","definition":"a sandwich made of ground meat served in a bun","collocations":["cheeseburger","order a burger","veggie burger"],"example":"We stopped at a diner for a burger.","exampleZh":"我們在小餐館停下來吃漢堡。","synonyms":[],"level":2,"theme":"食物與烹飪","examples":[{"en":"We stopped at a diner for a burger.","zh":"我們在小餐館停下來吃漢堡。"},{"en":"He ordered a cheeseburger and a large soda for lunch.","zh":"他午餐點了一個起司漢堡和一杯大杯汽水。"},{"en":"The new restaurant serves a delicious veggie burger.","zh":"這家新餐廳供應美味的素食漢堡。"}]},{"word":"burglar","pos":"n.","phonetic":"[ˈbɝglɚ]","meaning":"竊賊","definition":"a person who breaks into a building to steal","collocations":["catch a burglar","burglar alarm","arrest a burglar"],"example":"The burglar broke into the house at midnight.","exampleZh":"竊賊在午夜闖入了那間房子。","synonyms":["thief"],"level":4,"theme":"政治與法律","examples":[{"en":"The burglar broke into the house at midnight.","zh":"竊賊在午夜闖入了那間房子。"},{"en":"The loud burglar alarm scared the thief away.","zh":"響亮的防盜警報器把小偷嚇跑了。"},{"en":"Police finally caught the burglar who robbed several homes.","zh":"警方終於抓到那個闖入好幾戶人家的竊賊。"}]},{"word":"burn","pos":"v. / n.","phonetic":"[bɝn]","meaning":"燃燒；燒傷","definition":"to be destroyed by fire, or an injury caused by fire or heat","collocations":["burn calories","get burned","burn down"],"example":"The candle burned all night.","exampleZh":"蠟燭燒了一整夜。","synonyms":[],"level":2,"theme":"動作與行為","examples":[{"en":"The candle burned all night.","zh":"蠟燭燒了一整夜。"},{"en":"Running every morning helps you burn calories quickly.","zh":"每天早上跑步能幫你迅速燃燒卡路里。"},{"en":"Be careful not to get burned by the hot pan.","zh":"小心別被熱鍋燙傷。"}]},{"word":"burst","pos":"v. / n.","phonetic":"[bɝst]","meaning":"爆裂；突然發生","definition":"to break open suddenly and violently","collocations":["burst into tears","burst out laughing","burst into flames"],"example":"The balloon burst with a loud bang.","exampleZh":"氣球砰的一聲爆裂了。","synonyms":["explode"],"level":4,"theme":"動作與行為","examples":[{"en":"The balloon burst with a loud bang.","zh":"氣球砰的一聲爆裂了。"},{"en":"She burst into tears when she heard the sad news.","zh":"聽到那個悲傷的消息時，她突然放聲大哭。"},{"en":"The whole class burst out laughing at his silly joke.","zh":"全班同學被他的傻笑話逗得哄堂大笑。"}]},{"word":"bury","pos":"v.","phonetic":"[ˈbɛrɪ]","meaning":"埋葬","definition":"to put a dead body or object into the ground and cover it","collocations":["bury treasure","bury the dead","bury one's face"],"example":"The dog buried a bone in the yard.","exampleZh":"那隻狗把一根骨頭埋在院子裡。","synonyms":[],"level":3,"theme":"動作與行為","examples":[{"en":"The dog buried a bone in the yard.","zh":"那隻狗把一根骨頭埋在院子裡。"},{"en":"The pirates were said to bury treasure on the island.","zh":"據說海盜把寶藏埋在那座島上。"},{"en":"Embarrassed, he buried his face in his hands.","zh":"他很尷尬，把臉埋進雙手裡。"}]},{"word":"bus","pos":"n.","phonetic":"[bʌs]","meaning":"公車","definition":"a large road vehicle used to carry passengers","collocations":["take a bus","bus stop","miss the bus"],"example":"She takes the bus to school every day.","exampleZh":"她每天搭公車上學。","synonyms":[],"level":1,"theme":"交通與旅行","examples":[{"en":"She takes the bus to school every day.","zh":"她每天搭公車上學。"},{"en":"If we don't hurry, we will miss the last bus home.","zh":"如果不快點，我們就會錯過回家的末班公車。"},{"en":"A crowd of people waited at the bus stop in the rain.","zh":"一群人在雨中等在公車站牌旁。"}]},{"word":"bush","pos":"n.","phonetic":"[bʊʃ]","meaning":"灌木","definition":"a low, woody plant with many branches","collocations":["rose bush","hide in the bush","trim a bush"],"example":"The cat hid behind the bush.","exampleZh":"那隻貓躲在灌木叢後面。","synonyms":["shrub"],"level":2,"theme":"自然與環境","examples":[{"en":"The cat hid behind the bush.","zh":"那隻貓躲在灌木叢後面。"},{"en":"My grandfather carefully trimmed the rose bush in the garden.","zh":"我爺爺仔細地修剪花園裡的玫瑰花叢。"},{"en":"A small rabbit suddenly jumped out from behind the bush.","zh":"一隻小兔子突然從灌木叢後跳了出來。"}]},{"word":"business","pos":"n.","phonetic":"[ˈbɪznɪs]","meaning":"生意；企業","definition":"trade and commercial activity, or a company","collocations":["run a business","business trip","start a business"],"example":"He started his own business last year.","exampleZh":"他去年開始經營自己的事業。","synonyms":[],"level":2,"theme":"商業與金錢","examples":[{"en":"He started his own business last year.","zh":"他去年開始經營自己的事業。"},{"en":"My uncle runs a small business selling handmade furniture.","zh":"我叔叔經營一家販售手工家具的小生意。"},{"en":"My father is away on a business trip until next week.","zh":"我爸爸出差去了，要到下週才回來。"}]},{"word":"businessman","pos":"n.","phonetic":"[ˈbɪznɪsˌmæn]","meaning":"商人","definition":"a man who works in trade or commerce","collocations":["successful businessman","local businessman","shrewd businessman"],"example":"The businessman signed a new contract.","exampleZh":"那位商人簽署了一份新合約。","synonyms":[],"level":2,"theme":"工作與職業","examples":[{"en":"The businessman signed a new contract.","zh":"那位商人簽署了一份新合約。"},{"en":"The successful businessman donated money to build a school.","zh":"那位成功的商人捐錢蓋了一所學校。"},{"en":"A local businessman sponsored the town's summer festival.","zh":"一位當地商人贊助了小鎮的夏日慶典。"}]},{"word":"busy","pos":"adj.","phonetic":"[ˈbɪzɪ]","meaning":"忙碌的","definition":"having a great deal to do","collocations":["busy schedule","busy street","stay busy"],"example":"She has been busy preparing for the exam.","exampleZh":"她一直忙著準備考試。","synonyms":[],"level":1,"theme":"性質與描述","examples":[{"en":"She has been busy preparing for the exam.","zh":"她一直忙著準備考試。"},{"en":"Her busy schedule leaves little time for hobbies.","zh":"她忙碌的行程幾乎沒有時間留給嗜好。"},{"en":"We crossed the busy street carefully at the traffic light.","zh":"我們在紅綠燈前小心地穿越繁忙的街道。"}]},{"word":"but","pos":"conj. / prep.","phonetic":"[bʌt]","meaning":"但是；除了","definition":"used to introduce a contrast, or meaning except","collocations":["but also","nothing but","not only...but"],"example":"I wanted to go, but I was too tired.","exampleZh":"我想去,但我太累了。","synonyms":["however"],"level":1,"theme":"溝通與語言","examples":[{"en":"I wanted to go, but I was too tired.","zh":"我想去,但我太累了。"},{"en":"The movie was long, but I enjoyed every minute of it.","zh":"那部電影很長，但我很享受其中的每一分鐘。"},{"en":"She wanted nothing but a quiet weekend at home.","zh":"她只想要一個在家安靜度過的週末。"}]},{"word":"butcher","pos":"n.","phonetic":"[ˈbʊtʃɚ]","meaning":"屠夫；肉販","definition":"a person whose job is to sell meat","collocations":["local butcher","butcher shop","go to the butcher"],"example":"She bought some pork from the butcher.","exampleZh":"她向肉販買了一些豬肉。","synonyms":[],"level":4,"theme":"工作與職業","examples":[{"en":"She bought some pork from the butcher.","zh":"她向肉販買了一些豬肉。"},{"en":"My mother asked the butcher for a fresh cut of beef.","zh":"我媽媽向肉販要了一塊新鮮的牛肉。"},{"en":"The butcher shop on the corner sells excellent sausages.","zh":"轉角的肉舖賣的香腸非常好吃。"}]},{"word":"butter","pos":"n.","phonetic":"[ˈbʌtɚ]","meaning":"奶油","definition":"a fatty food made by churning cream, spread on bread","collocations":["peanut butter","bread and butter","melt butter"],"example":"She spread butter on the toast.","exampleZh":"她在吐司上塗奶油。","synonyms":[],"level":1,"theme":"食物與烹飪","examples":[{"en":"She spread butter on the toast.","zh":"她在吐司上塗奶油。"},{"en":"I love a warm sandwich made with peanut butter and banana.","zh":"我很愛用花生醬和香蕉做的溫熱三明治。"},{"en":"Melt the butter in the pan before adding the eggs.","zh":"在加入蛋之前，先把奶油在鍋裡融化。"}]},{"word":"butterfly","pos":"n.","phonetic":"[ˈbʌtɚˌflaɪ]","meaning":"蝴蝶","definition":"an insect with large, often colorful wings","collocations":["catch a butterfly","butterfly effect","butterfly stroke"],"example":"A colorful butterfly landed on the flower.","exampleZh":"一隻色彩繽紛的蝴蝶停在花上。","synonyms":[],"level":1,"theme":"動物與植物","examples":[{"en":"A colorful butterfly landed on the flower.","zh":"一隻色彩繽紛的蝴蝶停在花上。"},{"en":"The children tried to catch a butterfly in the meadow.","zh":"孩子們試著在草地上抓蝴蝶。"},{"en":"She swims the butterfly stroke faster than anyone on the team.","zh":"她游蝶式比隊上任何人都快。"}]},{"word":"button","pos":"n. / v.","phonetic":"[ˈbʌtn̩]","meaning":"鈕扣；按鈕","definition":"a small disc used to fasten clothing, or a device to press","collocations":["press a button","button up","sew on a button"],"example":"He pressed the button to start the machine.","exampleZh":"他按下按鈕啟動機器。","synonyms":[],"level":1,"theme":"服裝與外表","examples":[{"en":"He pressed the button to start the machine.","zh":"他按下按鈕啟動機器。"},{"en":"A button fell off his shirt, so his mother sewed it back on.","zh":"他襯衫上的一顆鈕扣掉了，媽媽幫他縫了回去。"},{"en":"Just press the green button to turn the machine on.","zh":"只要按下綠色按鈕就能開啟機器。"}]},{"word":"buy","pos":"v.","phonetic":"[baɪ]","meaning":"購買","definition":"to obtain something by paying money for it","collocations":["buy a gift","buy time","buy in bulk"],"example":"I want to buy a new phone.","exampleZh":"我想買一支新手機。","synonyms":["purchase"],"level":1,"theme":"商業與金錢","examples":[{"en":"I want to buy a new phone.","zh":"我想買一支新手機。"},{"en":"She saved for months to buy a gift for her mother.","zh":"她存了好幾個月的錢，就為了買禮物給媽媽。"},{"en":"He told a long story just to buy time before the deadline.","zh":"他說了一個長長的故事，只是為了在截止期限前拖延時間。"}]},{"word":"buyer","pos":"n.","phonetic":"[ˈbaɪɚ]","meaning":"買家","definition":"a person who buys something, especially in a business deal","collocations":["potential buyer","home buyer","buyer beware"],"example":"The buyer agreed to the seller's price.","exampleZh":"買家同意了賣方的價格。","synonyms":[],"level":3,"theme":"商業與金錢","examples":[{"en":"The buyer agreed to the seller's price.","zh":"買家同意了賣方的價格。"},{"en":"Several potential buyers came to look at the old house.","zh":"好幾位潛在買家來看那棟老房子。"},{"en":"First-time home buyers often need advice about loans.","zh":"首次購屋的買家常常需要有關貸款的建議。"}]},{"word":"buzz","pos":"n. / v.","phonetic":"[bʌz]","meaning":"嗡嗡聲；發出嗡嗡聲","definition":"a low humming sound, or to make such a sound","collocations":["buzz around","create a buzz","buzz with excitement"],"example":"The bee buzzed around the flowers.","exampleZh":"那隻蜜蜂在花叢間嗡嗡作響。","synonyms":[],"level":4,"theme":"動物與植物","examples":[{"en":"The bee buzzed around the flowers.","zh":"那隻蜜蜂在花叢間嗡嗡作響。"},{"en":"The new phone created a huge buzz among students.","zh":"這款新手機在學生之間引起了熱烈的討論。"},{"en":"The classroom buzzed with excitement before the school trip.","zh":"校外教學前，教室裡充滿了興奮的騷動。"}]},{"word":"bypass","pos":"v. / n.","phonetic":"[ˈbaɪˌpæs]","meaning":"繞道；忽略","definition":"to go around something instead of through it","collocations":["bypass a rule","heart bypass","bypass the city"],"example":"The new highway bypasses the city center.","exampleZh":"這條新公路繞過了市中心。","synonyms":["avoid"],"level":5,"theme":"交通與旅行","examples":[{"en":"The new highway bypasses the city center.","zh":"這條新公路繞過了市中心。"},{"en":"We took the new road to bypass the crowded city center.","zh":"我們走新的道路繞過擁擠的市中心。"},{"en":"You should not bypass the safety rules just to save time.","zh":"你不該為了省時間就忽略安全規定。"}]},{"word":"bystander","pos":"n.","phonetic":"[ˈbaɪˌstændɚ]","meaning":"旁觀者","definition":"a person who watches an event without taking part in it","collocations":["innocent bystander","curious bystander","mere bystander"],"example":"Several bystanders witnessed the accident.","exampleZh":"幾名旁觀者目擊了這起事故。","synonyms":["onlooker"],"level":6,"theme":"社會與文化","examples":[{"en":"Several bystanders witnessed the accident.","zh":"幾名旁觀者目擊了這起事故。"},{"en":"A brave bystander helped the injured cyclist off the road.","zh":"一位勇敢的旁觀者把受傷的單車騎士扶離馬路。"},{"en":"During the argument, he chose to remain a mere bystander.","zh":"在那場爭吵中，他選擇當個純粹的旁觀者。"}]},{"word":"byte","pos":"n.","phonetic":"[baɪt]","meaning":"位元組","definition":"a unit of digital information, usually consisting of eight bits","collocations":["kilobyte","megabyte","byte size"],"example":"A byte consists of eight bits.","exampleZh":"一個位元組由八個位元(bit)所組成。","synonyms":[],"level":5,"theme":"科技與媒體","examples":[{"en":"A byte consists of eight bits.","zh":"一個位元組由八個位元(bit)所組成。"},{"en":"This photo file is several megabytes in size.","zh":"這個照片檔案有好幾百萬位元組大。"},{"en":"Each character you type is stored as one byte of data.","zh":"你輸入的每個字元都以一個位元組的資料儲存。"}]},{"word":"cabbage","pos":"n.","phonetic":"[ˈkæbɪdʒ]","meaning":"高麗菜；甘藍菜","definition":"a leafy green or purple vegetable with tightly packed leaves","collocations":["a head of cabbage","cabbage soup","shred cabbage"],"example":"My mother cooked cabbage soup for dinner.","exampleZh":"我媽媽晚餐煮了高麗菜湯。","synonyms":[],"level":2,"theme":"食物與烹飪","examples":[{"en":"My mother cooked cabbage soup for dinner.","zh":"我媽媽晚餐煮了高麗菜湯。"},{"en":"She bought a fresh head of cabbage at the market.","zh":"她在市場買了一顆新鮮的高麗菜。"},{"en":"We shred the cabbage finely to make a crunchy salad.","zh":"我們把高麗菜切成細絲，做成爽脆的沙拉。"}]},{"word":"cabin","pos":"n.","phonetic":"[ˈkæbɪn]","meaning":"小木屋；船艙","definition":"a small wooden house, or a room on a ship or plane","collocations":["log cabin","cabin crew","mountain cabin"],"example":"We spent the weekend in a cabin by the lake.","exampleZh":"我們在湖邊的小木屋度過週末。","synonyms":["hut","cottage"],"level":3,"theme":"居家與生活","examples":[{"en":"We spent the weekend in a cabin by the lake.","zh":"我們在湖邊的小木屋度過週末。"},{"en":"They rented a cozy log cabin deep in the forest.","zh":"他們在森林深處租了一間舒適的小木屋。"},{"en":"The cabin crew asked passengers to fasten their seat belts.","zh":"機組人員請乘客繫好安全帶。"}]},{"word":"cable","pos":"n.","phonetic":"[ˈkebl̩]","meaning":"電纜；纜線；有線電視","definition":"a thick wire or set of wires used to carry electricity or signals","collocations":["cable TV","power cable","fiber-optic cable"],"example":"Please connect the cable to the TV.","exampleZh":"請把電纜接到電視上。","synonyms":["wire","cord"],"level":3,"theme":"科技與媒體","examples":[{"en":"Please connect the cable to the TV.","zh":"請把電纜接到電視上。"},{"en":"The storm damaged a power cable and cut off electricity.","zh":"暴風雨損壞了一條電纜，導致停電。"},{"en":"We subscribed to cable TV to watch the sports channels.","zh":"我們訂了有線電視來看體育頻道。"}]},{"word":"cafe","pos":"n.","phonetic":"[kæˈfe]","meaning":"咖啡館；小餐館","definition":"a small restaurant that sells drinks and light meals","collocations":["internet cafe","cafe owner","sit in a cafe"],"example":"We chatted for hours at a cozy cafe.","exampleZh":"我們在一間舒適的咖啡館聊了好幾個小時。","synonyms":[],"level":1,"theme":"食物與烹飪","examples":[{"en":"We chatted for hours at a cozy cafe.","zh":"我們在一間舒適的咖啡館聊了好幾個小時。"},{"en":"We often sit in a quiet cafe to study on weekends.","zh":"週末我們常坐在一家安靜的咖啡館裡讀書。"},{"en":"The cafe owner greets every regular customer by name.","zh":"咖啡館老闆用名字問候每位常客。"}]},{"word":"cafeteria","pos":"n.","phonetic":"[ˌkæfəˈtɪrɪə]","meaning":"自助餐廳；學生餐廳","definition":"a self-service restaurant, especially in a school or workplace","collocations":["school cafeteria","cafeteria food","eat in the cafeteria"],"example":"Students line up for lunch in the cafeteria.","exampleZh":"學生們在自助餐廳排隊吃午餐。","synonyms":[],"level":2,"theme":"教育與學習","examples":[{"en":"Students line up for lunch in the cafeteria.","zh":"學生們在自助餐廳排隊吃午餐。"},{"en":"The cafeteria food has improved a lot since last year.","zh":"自去年以來，學生餐廳的伙食改善了不少。"},{"en":"We usually eat in the cafeteria before afternoon classes.","zh":"下午上課前，我們通常在學生餐廳吃飯。"}]},{"word":"cage","pos":"n.","phonetic":"[kedʒ]","meaning":"籠子","definition":"a structure of bars or wire used to keep animals or birds","collocations":["bird cage","lock in a cage","cage door"],"example":"The parrot was kept in a large cage.","exampleZh":"那隻鸚鵡被關在一個大籠子裡。","synonyms":[],"level":2,"theme":"動物與植物","examples":[{"en":"The parrot was kept in a large cage.","zh":"那隻鸚鵡被關在一個大籠子裡。"},{"en":"He forgot to close the cage door, and the hamster escaped.","zh":"他忘了關籠子的門，倉鼠就跑掉了。"},{"en":"Many people believe wild animals should not be kept in a cage.","zh":"許多人認為野生動物不該被關在籠子裡。"}]},{"word":"cake","pos":"n.","phonetic":"[kek]","meaning":"蛋糕","definition":"a sweet baked food made from flour, eggs, and sugar","collocations":["birthday cake","bake a cake","piece of cake"],"example":"She baked a chocolate cake for the party.","exampleZh":"她為派對烤了一個巧克力蛋糕。","synonyms":[],"level":1,"theme":"食物與烹飪","examples":[{"en":"She baked a chocolate cake for the party.","zh":"她為派對烤了一個巧克力蛋糕。"},{"en":"She spent the afternoon baking a cake for the party.","zh":"她花了一整個下午為派對烤蛋糕。"},{"en":"Everyone got a large piece of cake after dinner.","zh":"晚餐後每個人都分到一大塊蛋糕。"}]},{"word":"calculate","pos":"v.","phonetic":"[ˈkælkjəˌlet]","meaning":"計算；估計","definition":"to find a number or amount using mathematics","collocations":["calculate the cost","calculate carefully","calculate a result"],"example":"Please calculate the total cost of the trip.","exampleZh":"請計算這趟旅行的總花費。","synonyms":["compute","figure out"],"level":3,"theme":"科學與數學","examples":[{"en":"Please calculate the total cost of the trip.","zh":"請計算這趟旅行的總花費。"},{"en":"We need to calculate the cost before booking the trip.","zh":"在預訂這趟旅行前，我們得先計算費用。"},{"en":"The scientist calculated the result twice to avoid mistakes.","zh":"為了避免錯誤，那位科學家把結果算了兩遍。"}]},{"word":"calculator","pos":"n.","phonetic":"[ˈkælkjəˌletɚ]","meaning":"計算機","definition":"a small electronic device used to do math","collocations":["scientific calculator","use a calculator"],"example":"He used a calculator to check his answer.","exampleZh":"他用計算機檢查他的答案。","synonyms":[],"level":2,"theme":"科學與數學","examples":[{"en":"He used a calculator to check his answer.","zh":"他用計算機檢查他的答案。"},{"en":"You may use a scientific calculator during the math exam.","zh":"數學考試時你可以使用工程計算機。"},{"en":"Without a calculator, she added the long list by hand.","zh":"沒有計算機，她只好用手算那一長串數字。"}]},{"word":"calendar","pos":"n.","phonetic":"[ˈkæləndɚ]","meaning":"日曆；月曆","definition":"a chart showing the days, weeks, and months of a year","collocations":["hang a calendar","check the calendar","calendar year"],"example":"I marked the date on the calendar.","exampleZh":"我在日曆上標記了那個日期。","synonyms":[],"level":2,"theme":"時間與空間","examples":[{"en":"I marked the date on the calendar.","zh":"我在日曆上標記了那個日期。"},{"en":"I marked all the exam dates on my wall calendar.","zh":"我把所有考試日期都標在牆上的月曆上。"},{"en":"Let me check the calendar before we plan the meeting.","zh":"在安排會議前，讓我先看看行事曆。"}]},{"word":"calm","pos":"adj. / v.","phonetic":"[kɑm]","meaning":"冷靜的；平靜的；使平靜","definition":"free from excitement, disturbance, or strong emotion","collocations":["stay calm","calm down","calm sea"],"example":"Try to stay calm during the exam.","exampleZh":"考試時盡量保持冷靜。","synonyms":["peaceful","quiet"],"level":2,"theme":"情緒與感受","examples":[{"en":"Try to stay calm during the exam.","zh":"考試時盡量保持冷靜。"},{"en":"The captain stayed calm as the storm grew stronger.","zh":"當暴風雨越來越猛烈時，船長保持冷靜。"},{"en":"She spoke gently to calm the frightened child.","zh":"她溫柔地說話，安撫那個受驚的孩子。"}]},{"word":"camel","pos":"n.","phonetic":"[ˈkæml̩]","meaning":"駱駝","definition":"a large desert animal with one or two humps on its back","collocations":["ride a camel","camel's hump"],"example":"Tourists rode camels across the desert.","exampleZh":"遊客們騎著駱駝穿越沙漠。","synonyms":[],"level":2,"theme":"動物與植物","examples":[{"en":"Tourists rode camels across the desert.","zh":"遊客們騎著駱駝穿越沙漠。"},{"en":"A camel can travel for days without drinking water.","zh":"駱駝可以好幾天不喝水也能行走。"},{"en":"On our trip we rode a camel across the golden dunes.","zh":"旅途中我們騎著駱駝越過金黃色的沙丘。"}]},{"word":"camera","pos":"n.","phonetic":"[ˈkæmərə]","meaning":"相機；攝影機","definition":"a device used for taking photographs or video","collocations":["digital camera","security camera","take a camera"],"example":"She bought a new camera for the trip.","exampleZh":"她為這趟旅行買了一台新相機。","synonyms":[],"level":1,"theme":"科技與媒體","examples":[{"en":"She bought a new camera for the trip.","zh":"她為這趟旅行買了一台新相機。"},{"en":"A security camera at the entrance recorded the whole event.","zh":"入口處的監視器錄下了整起事件。"},{"en":"She always takes her camera along on family trips.","zh":"家庭旅行時她總是帶著相機。"}]},{"word":"camp","pos":"n. / v.","phonetic":"[kæmp]","meaning":"露營；營地；紮營","definition":"a place with tents or cabins for a temporary stay outdoors","collocations":["summer camp","go camping","set up camp"],"example":"The scouts went camping in the mountains.","exampleZh":"童子軍去山上露營。","synonyms":[],"level":2,"theme":"交通與旅行","examples":[{"en":"The scouts went camping in the mountains.","zh":"童子軍去山上露營。"},{"en":"The hikers set up camp near a clear mountain stream.","zh":"登山者在一條清澈的山溪旁紮營。"},{"en":"My little sister will attend a summer camp next month.","zh":"我妹妹下個月要參加夏令營。"}]},{"word":"campaign","pos":"n.","phonetic":"[kæmˈpen]","meaning":"活動；競選；運動","definition":"a planned series of actions to achieve a particular goal","collocations":["election campaign","launch a campaign","advertising campaign"],"example":"The company launched a new marketing campaign.","exampleZh":"這家公司推出了一項新的行銷活動。","synonyms":[],"level":4,"theme":"政治與法律","examples":[{"en":"The company launched a new marketing campaign.","zh":"這家公司推出了一項新的行銷活動。"},{"en":"The school launched a campaign to reduce plastic waste.","zh":"學校發起了一項減少塑膠垃圾的活動。"},{"en":"Volunteers worked hard during the mayor's election campaign.","zh":"在市長的競選活動期間，志工們努力工作。"}]},{"word":"campus","pos":"n.","phonetic":"[ˈkæmpəs]","meaning":"校園","definition":"the grounds and buildings of a university or school","collocations":["college campus","on campus","campus life"],"example":"The university campus is beautiful in spring.","exampleZh":"這所大學的校園在春天很美。","synonyms":[],"level":3,"theme":"教育與學習","examples":[{"en":"The university campus is beautiful in spring.","zh":"這所大學的校園在春天很美。"},{"en":"Many students live in dormitories on campus.","zh":"許多學生住在校園裡的宿舍。"},{"en":"The college campus is full of cherry blossoms in spring.","zh":"春天時大學校園裡開滿了櫻花。"}]},{"word":"canal","pos":"n.","phonetic":"[kəˈnæl]","meaning":"運河；水道","definition":"a man-made waterway for boats or irrigation","collocations":["dig a canal","narrow canal","canal boat"],"example":"Boats travel through the canal every day.","exampleZh":"船隻每天都會經過這條運河。","synonyms":[],"level":4,"theme":"自然與環境","examples":[{"en":"Boats travel through the canal every day.","zh":"船隻每天都會經過這條運河。"},{"en":"Workers dug a canal to bring water to the dry fields.","zh":"工人們挖了一條運河，把水引到乾旱的田地。"},{"en":"We took a slow boat ride along the narrow canal.","zh":"我們沿著狹窄的運河搭船慢慢遊覽。"}]},{"word":"cancel","pos":"v.","phonetic":"[ˈkænsl̩]","meaning":"取消","definition":"to decide that a planned event will not happen","collocations":["cancel a meeting","cancel an order","cancel a flight"],"example":"The flight was canceled due to bad weather.","exampleZh":"由於天氣不好，班機被取消了。","synonyms":["call off"],"level":3,"theme":"動作與行為","examples":[{"en":"The flight was canceled due to bad weather.","zh":"由於天氣不好，班機被取消了。"},{"en":"The manager had to cancel the meeting because of the storm.","zh":"由於暴風雨，經理不得不取消會議。"},{"en":"She called the store to cancel her online order.","zh":"她打電話到商店取消她的網路訂單。"}]},{"word":"cancer","pos":"n.","phonetic":"[ˈkænsɚ]","meaning":"癌症","definition":"a serious disease caused by abnormal growth of cells","collocations":["lung cancer","fight cancer","cancer patient"],"example":"Doctors are researching new treatments for cancer.","exampleZh":"醫生正在研究癌症的新療法。","synonyms":[],"level":4,"theme":"身體與健康","examples":[{"en":"Doctors are researching new treatments for cancer.","zh":"醫生正在研究癌症的新療法。"},{"en":"Smoking greatly increases the risk of lung cancer.","zh":"抽菸大大增加罹患肺癌的風險。"},{"en":"The charity raises money to help cancer patients.","zh":"這個慈善機構募款幫助癌症病患。"}]},{"word":"candidate","pos":"n.","phonetic":"[ˈkændəˌdet]","meaning":"候選人；應徵者","definition":"a person who applies for a job or competes in an election","collocations":["presidential candidate","job candidate","qualified candidate"],"example":"Three candidates are running for mayor.","exampleZh":"有三位候選人在競選市長。","synonyms":[],"level":4,"theme":"政治與法律","examples":[{"en":"Three candidates are running for mayor.","zh":"有三位候選人在競選市長。"},{"en":"She was the most qualified candidate for the teaching job.","zh":"她是這個教職最合適的應徵者。"},{"en":"Each candidate gave a short speech before the election.","zh":"選舉前每位候選人都發表了簡短的演說。"}]},{"word":"candle","pos":"n.","phonetic":"[ˈkændl̩]","meaning":"蠟燭","definition":"a stick of wax with a wick that is burned to give light","collocations":["light a candle","blow out a candle","candlelight"],"example":"She lit a candle on the birthday cake.","exampleZh":"她在生日蛋糕上點了一根蠟燭。","synonyms":[],"level":2,"theme":"居家與生活","examples":[{"en":"She lit a candle on the birthday cake.","zh":"她在生日蛋糕上點了一根蠟燭。"},{"en":"When the power went out, we lit a candle for light.","zh":"停電時，我們點了一支蠟燭照明。"},{"en":"She made a wish and blew out the candles on her cake.","zh":"她許了願，然後吹熄蛋糕上的蠟燭。"}]},{"word":"candy","pos":"n.","phonetic":"[ˈkændɪ]","meaning":"糖果","definition":"sweet food made mainly with sugar","collocations":["candy bar","piece of candy","candy store"],"example":"Children love to eat candy on Halloween.","exampleZh":"孩子們在萬聖節喜歡吃糖果。","synonyms":["sweets"],"level":1,"theme":"食物與烹飪","examples":[{"en":"Children love to eat candy on Halloween.","zh":"孩子們在萬聖節喜歡吃糖果。"},{"en":"The children's eyes lit up inside the colorful candy store.","zh":"在色彩繽紛的糖果店裡，孩子們的眼睛都亮了起來。"},{"en":"Eating too much candy is bad for your teeth.","zh":"吃太多糖果對牙齒有害。"}]},{"word":"canoe","pos":"n.","phonetic":"[kəˈnu]","meaning":"獨木舟","definition":"a light narrow boat moved forward with paddles","collocations":["paddle a canoe","canoe trip"],"example":"They paddled a canoe down the river.","exampleZh":"他們划著獨木舟順流而下。","synonyms":[],"level":3,"theme":"交通與旅行","examples":[{"en":"They paddled a canoe down the river.","zh":"他們划著獨木舟順流而下。"},{"en":"We learned how to paddle a canoe at summer camp.","zh":"我們在夏令營學會了如何划獨木舟。"},{"en":"Their canoe trip down the river lasted three peaceful days.","zh":"他們順流而下的獨木舟之旅，度過了平靜的三天。"}]},{"word":"canteen","pos":"n.","phonetic":"[kænˈtin]","meaning":"餐廳；福利社","definition":"a place in a school or factory where food is sold","collocations":["school canteen","canteen lunch"],"example":"We usually eat lunch in the canteen.","exampleZh":"我們通常在餐廳吃午餐。","synonyms":[],"level":3,"theme":"教育與學習","examples":[{"en":"We usually eat lunch in the canteen.","zh":"我們通常在餐廳吃午餐。"},{"en":"The school canteen sells cheap and tasty noodles.","zh":"學校福利社賣的麵又便宜又好吃。"},{"en":"Workers grab a quick canteen lunch during their short break.","zh":"工人們在短暫的休息時間到員工餐廳快速吃個午餐。"}]},{"word":"canvas","pos":"n.","phonetic":"[ˈkænvəs]","meaning":"帆布；畫布","definition":"a strong heavy cloth used for painting on or making bags","collocations":["paint on canvas","canvas bag"],"example":"The artist painted a landscape on canvas.","exampleZh":"這位畫家在畫布上畫了一幅風景畫。","synonyms":[],"level":4,"theme":"藝術與音樂","examples":[{"en":"The artist painted a landscape on canvas.","zh":"這位畫家在畫布上畫了一幅風景畫。"},{"en":"She carries her books in a sturdy canvas bag.","zh":"她用一個堅固的帆布袋裝書。"},{"en":"The artist stretched a fresh canvas before starting to paint.","zh":"畫家在開始作畫前，先繃好一塊新的畫布。"}]},{"word":"canyon","pos":"n.","phonetic":"[ˈkænjən]","meaning":"峽谷","definition":"a deep valley with steep rocky sides","collocations":["deep canyon","canyon walls"],"example":"The deep canyon attracts millions of visitors.","exampleZh":"這座深邃的峽谷吸引了數百萬遊客。","synonyms":[],"level":4,"theme":"自然與環境","examples":[{"en":"The deep canyon attracts millions of visitors.","zh":"這座深邃的峽谷吸引了數百萬遊客。"},{"en":"The river slowly carved a deep canyon over millions of years.","zh":"這條河歷經數百萬年慢慢刻鑿出一道深峽谷。"},{"en":"Our voices echoed loudly between the steep canyon walls.","zh":"我們的聲音在陡峭的峽谷壁之間大聲迴盪。"}]},{"word":"capable","pos":"adj.","phonetic":"[ˈkepəbl̩]","meaning":"有能力的","definition":"having the ability or skill to do something","collocations":["capable of","a capable leader"],"example":"She is capable of solving difficult problems.","exampleZh":"她有能力解決困難的問題。","synonyms":["able","competent"],"level":4,"theme":"性質與描述","examples":[{"en":"She is capable of solving difficult problems.","zh":"她有能力解決困難的問題。"},{"en":"She proved to be a capable leader during the crisis.","zh":"在危機中她證明自己是個能幹的領導者。"},{"en":"This computer is capable of storing thousands of songs.","zh":"這台電腦能夠儲存數千首歌曲。"}]},{"word":"capacity","pos":"n.","phonetic":"[kəˈpæsətɪ]","meaning":"容量；能力","definition":"the maximum amount that something can hold or produce","collocations":["seating capacity","full capacity","learning capacity"],"example":"The stadium has a capacity of fifty thousand seats.","exampleZh":"這座體育場的容量是五萬個座位。","synonyms":[],"level":5,"theme":"性質與描述","examples":[{"en":"The stadium has a capacity of fifty thousand seats.","zh":"這座體育場的容量是五萬個座位。"},{"en":"The concert hall was filled to full capacity that night.","zh":"那天晚上音樂廳座無虛席。"},{"en":"Young children have a remarkable capacity for learning languages.","zh":"幼童擁有驚人的語言學習能力。"}]},{"word":"capital","pos":"n. / adj.","phonetic":"[ˈkæpətl̩]","meaning":"首都；資本；大寫的","definition":"the main city of a country, or money used to start a business","collocations":["capital city","capital letter","raise capital"],"example":"Taipei is the capital of Taiwan.","exampleZh":"台北是台灣的首都。","synonyms":[],"level":3,"theme":"商業與金錢","examples":[{"en":"Taipei is the capital of Taiwan.","zh":"台北是台灣的首都。"},{"en":"Please begin every sentence with a capital letter.","zh":"請用大寫字母開始每個句子。"},{"en":"The startup needs to raise capital to expand its business.","zh":"這家新創公司需要籌措資金來擴展業務。"}]},{"word":"captain","pos":"n.","phonetic":"[ˈkæptɪn]","meaning":"船長；隊長；機長","definition":"the leader of a ship, plane, or sports team","collocations":["team captain","ship's captain","flight captain"],"example":"The captain welcomed passengers aboard the plane.","exampleZh":"機長歡迎乘客登機。","synonyms":[],"level":2,"theme":"工作與職業","examples":[{"en":"The captain welcomed passengers aboard the plane.","zh":"機長歡迎乘客登機。"},{"en":"As team captain, she encouraged everyone before the big game.","zh":"身為隊長，她在大賽前鼓勵每一位隊員。"},{"en":"The ship's captain guided the vessel safely into the harbor.","zh":"船長引導船隻安全地駛進港口。"}]},{"word":"capture","pos":"v. / n.","phonetic":"[ˈkæptʃɚ]","meaning":"捕獲；俘虜；擷取","definition":"to catch a person, animal, or thing, or to record something well","collocations":["capture an image","capture a criminal","capture attention"],"example":"The photo captured the beauty of the sunset.","exampleZh":"這張照片捕捉到了日落的美景。","synonyms":["catch","seize"],"level":4,"theme":"動作與行為","examples":[{"en":"The photo captured the beauty of the sunset.","zh":"這張照片捕捉到了日落的美景。"},{"en":"The photographer managed to capture an image of the rare bird.","zh":"攝影師成功拍下了那隻稀有鳥類的影像。"},{"en":"The colorful poster quickly captured everyone's attention.","zh":"那張色彩鮮豔的海報很快吸引了大家的注意。"}]},{"word":"card","pos":"n.","phonetic":"[kɑrd]","meaning":"卡片；紙牌","definition":"a piece of stiff paper with writing, numbers, or pictures on it","collocations":["birthday card","credit card","play cards"],"example":"She sent a birthday card to her grandmother.","exampleZh":"她寄了一張生日卡片給祖母。","synonyms":[],"level":1,"theme":"溝通與語言","examples":[{"en":"She sent a birthday card to her grandmother.","zh":"她寄了一張生日卡片給祖母。"},{"en":"We stayed up late playing cards during the holiday.","zh":"假期時我們熬夜打牌。"},{"en":"He paid for the groceries with his credit card.","zh":"他用信用卡付了雜貨的錢。"}]},{"word":"care","pos":"n. / v.","phonetic":"[kɛr]","meaning":"照顧；關心；小心","definition":"the process of protecting someone, or a feeling of concern","collocations":["take care of","health care","care about"],"example":"She takes good care of her little brother.","exampleZh":"她很細心地照顧她的弟弟。","synonyms":["concern","attention"],"level":1,"theme":"情緒與感受","examples":[{"en":"She takes good care of her little brother.","zh":"她很細心地照顧她的弟弟。"},{"en":"Good health care is important for people of every age.","zh":"良好的醫療照護對每個年齡層的人都很重要。"},{"en":"She really cares about protecting the environment.","zh":"她非常關心環境保護。"}]},{"word":"career","pos":"n.","phonetic":"[kəˈrɪr]","meaning":"職業；生涯","definition":"a person's job or profession over a long period of time","collocations":["career path","build a career","career goals"],"example":"He decided to pursue a career in medicine.","exampleZh":"他決定從事醫學方面的職業。","synonyms":[],"level":4,"theme":"工作與職業","examples":[{"en":"He decided to pursue a career in medicine.","zh":"他決定從事醫學方面的職業。"},{"en":"He is thinking carefully about his future career path.","zh":"他正仔細思考自己未來的職業道路。"},{"en":"She worked hard to build a career in journalism.","zh":"她努力工作，在新聞界闖出一番事業。"}]},{"word":"careful","pos":"adj.","phonetic":"[ˈkɛrfəl]","meaning":"小心的；仔細的","definition":"taking care to avoid danger or mistakes","collocations":["be careful","careful planning","careful driver"],"example":"Be careful when crossing the street.","exampleZh":"過馬路時要小心。","synonyms":["cautious"],"level":1,"theme":"性質與描述","examples":[{"en":"Be careful when crossing the street.","zh":"過馬路時要小心。"},{"en":"The trip succeeded thanks to months of careful planning.","zh":"這趟旅程的成功歸功於數個月的仔細規劃。"},{"en":"Please be careful with the hot soup on the tray.","zh":"請小心托盤上的熱湯。"}]},{"word":"careless","pos":"adj.","phonetic":"[ˈkɛrlɪs]","meaning":"粗心的；疏忽的","definition":"not paying enough attention to what one is doing","collocations":["careless mistake","careless driver"],"example":"He made a careless mistake on the test.","exampleZh":"他在考試中犯了一個粗心的錯誤。","synonyms":["sloppy"],"level":2,"theme":"性質與描述","examples":[{"en":"He made a careless mistake on the test.","zh":"他在考試中犯了一個粗心的錯誤。"},{"en":"One careless mistake cost the team the championship.","zh":"一個粗心的錯誤讓球隊輸掉了冠軍。"},{"en":"A careless driver ran the red light and caused an accident.","zh":"一名粗心的駕駛闖紅燈，造成了一場車禍。"}]},{"word":"cargo","pos":"n.","phonetic":"[ˈkɑrgo]","meaning":"貨物","definition":"goods carried by a ship, plane, or truck","collocations":["cargo ship","carry cargo"],"example":"The ship was loaded with cargo from overseas.","exampleZh":"這艘船裝載了來自海外的貨物。","synonyms":["freight"],"level":4,"theme":"交通與旅行","examples":[{"en":"The ship was loaded with cargo from overseas.","zh":"這艘船裝載了來自海外的貨物。"},{"en":"The huge cargo ship carried thousands of containers overseas.","zh":"這艘巨大的貨輪把數千個貨櫃運往海外。"},{"en":"The plane had to leave some cargo behind because of the weight.","zh":"由於重量問題，飛機不得不留下部分貨物。"}]},{"word":"carpenter","pos":"n.","phonetic":"[ˈkɑrpəntɚ]","meaning":"木匠","definition":"a person whose job is to make things from wood","collocations":["skilled carpenter","carpenter's tools"],"example":"The carpenter built a wooden table for us.","exampleZh":"這位木匠為我們做了一張木桌。","synonyms":[],"level":3,"theme":"工作與職業","examples":[{"en":"The carpenter built a wooden table for us.","zh":"這位木匠為我們做了一張木桌。"},{"en":"The skilled carpenter carved beautiful patterns into the door.","zh":"技術高超的木匠在門上雕刻了美麗的圖案。"},{"en":"He borrowed the carpenter's tools to fix the broken chair.","zh":"他借了木匠的工具來修理壞掉的椅子。"}]},{"word":"carpet","pos":"n.","phonetic":"[ˈkɑrpɪt]","meaning":"地毯","definition":"a thick fabric covering for a floor","collocations":["roll out the carpet","vacuum the carpet"],"example":"They laid a new carpet in the living room.","exampleZh":"他們在客廳鋪了新地毯。","synonyms":["rug"],"level":2,"theme":"居家與生活","examples":[{"en":"They laid a new carpet in the living room.","zh":"他們在客廳鋪了新地毯。"},{"en":"She vacuumed the carpet before the guests arrived.","zh":"客人到來前，她用吸塵器把地毯清理乾淨。"},{"en":"The soft carpet felt warm under our bare feet.","zh":"柔軟的地毯讓我們的赤腳感到溫暖。"}]},{"word":"carrot","pos":"n.","phonetic":"[ˈkærət]","meaning":"紅蘿蔔","definition":"a long orange root vegetable","collocations":["carrot cake","chop carrots"],"example":"Rabbits love to eat carrots.","exampleZh":"兔子喜歡吃紅蘿蔔。","synonyms":[],"level":1,"theme":"食物與烹飪","examples":[{"en":"Rabbits love to eat carrots.","zh":"兔子喜歡吃紅蘿蔔。"},{"en":"Please chop the carrots into small pieces for the soup.","zh":"請把紅蘿蔔切成小塊放進湯裡。"},{"en":"My grandmother bakes a delicious carrot cake every winter.","zh":"我奶奶每年冬天都會烤美味的紅蘿蔔蛋糕。"}]},{"word":"carry","pos":"v.","phonetic":"[ˈkærɪ]","meaning":"攜帶；搬運","definition":"to hold and move something from one place to another","collocations":["carry a bag","carry on","carry out"],"example":"Can you help me carry this box upstairs?","exampleZh":"你可以幫我把這個箱子搬到樓上嗎？","synonyms":["transport"],"level":1,"theme":"動作與行為","examples":[{"en":"Can you help me carry this box upstairs?","zh":"你可以幫我把這個箱子搬到樓上嗎？"},{"en":"The scientists will carry out the experiment next week.","zh":"科學家們下週將進行這項實驗。"},{"en":"She carried a heavy bag of books all the way home.","zh":"她提著一袋沉重的書一路走回家。"}]},{"word":"cartoon","pos":"n.","phonetic":"[kɑrˈtun]","meaning":"卡通；漫畫","definition":"a funny drawing or an animated film","collocations":["watch cartoons","cartoon character"],"example":"Kids love watching cartoons on Saturday morning.","exampleZh":"孩子們喜歡在星期六早上看卡通。","synonyms":[],"level":1,"theme":"藝術與音樂","examples":[{"en":"Kids love watching cartoons on Saturday morning.","zh":"孩子們喜歡在星期六早上看卡通。"},{"en":"My little brother dressed up as his favorite cartoon character.","zh":"我弟弟打扮成他最喜歡的卡通人物。"},{"en":"On rainy days the kids stay inside and watch cartoons.","zh":"下雨天孩子們就待在室內看卡通。"}]},{"word":"carve","pos":"v.","phonetic":"[kɑrv]","meaning":"雕刻；切割","definition":"to cut wood, stone, or meat into a particular shape","collocations":["carve a statue","carve meat","carve wood"],"example":"The artist carved a beautiful statue from marble.","exampleZh":"這位藝術家用大理石雕刻了一座美麗的雕像。","synonyms":["sculpt"],"level":4,"theme":"藝術與音樂","examples":[{"en":"The artist carved a beautiful statue from marble.","zh":"這位藝術家用大理石雕刻了一座美麗的雕像。"},{"en":"Father taught me how to carve a spoon out of wood.","zh":"爸爸教我如何用木頭雕一支湯匙。"},{"en":"At dinner, Grandpa carefully carved the roast meat.","zh":"晚餐時，爺爺仔細地切開烤肉。"}]},{"word":"case","pos":"n.","phonetic":"[kes]","meaning":"情況；案件；箱子","definition":"a particular situation, a legal matter, or a container","collocations":["in case","court case","suitcase"],"example":"In case of fire, use the stairs, not the elevator.","exampleZh":"萬一發生火災，請走樓梯，不要搭電梯。","synonyms":[],"level":2,"theme":"抽象概念","examples":[{"en":"In case of fire, use the stairs, not the elevator.","zh":"萬一發生火災，請走樓梯，不要搭電梯。"},{"en":"Take an umbrella in case it rains this afternoon.","zh":"帶把傘，以防今天下午下雨。"},{"en":"The lawyer prepared carefully for the difficult court case.","zh":"律師為這樁棘手的官司做了充分的準備。"}]},{"word":"cash","pos":"n. / v.","phonetic":"[kæʃ]","meaning":"現金；兌現","definition":"money in the form of coins and notes","collocations":["pay in cash","cash a check","cash machine"],"example":"I don't have enough cash to pay the bill.","exampleZh":"我沒有足夠的現金付帳單。","synonyms":[],"level":2,"theme":"商業與金錢","examples":[{"en":"I don't have enough cash to pay the bill.","zh":"我沒有足夠的現金付帳單。"},{"en":"The small shop only accepts payment in cash.","zh":"這家小店只收現金付款。"},{"en":"He went to the bank to cash a check this morning.","zh":"他今天早上去銀行兌現一張支票。"}]},{"word":"cashier","pos":"n.","phonetic":"[kæˈʃɪr]","meaning":"收銀員","definition":"a person who handles payments in a store or bank","collocations":["cashier's counter","work as a cashier"],"example":"The cashier gave me my change and receipt.","exampleZh":"收銀員給了我找零和收據。","synonyms":[],"level":2,"theme":"工作與職業","examples":[{"en":"The cashier gave me my change and receipt.","zh":"收銀員給了我找零和收據。"},{"en":"She works as a cashier at the supermarket after school.","zh":"放學後她在超市當收銀員。"},{"en":"Please pay for your items at the cashier's counter.","zh":"請到收銀台結帳。"}]},{"word":"cast","pos":"v. / n.","phonetic":"[kæst]","meaning":"投擲；選派演員；演員陣容","definition":"to throw something, or the group of actors in a play or film","collocations":["cast a vote","cast a shadow","movie cast"],"example":"Every citizen has the right to cast a vote.","exampleZh":"每位公民都有投票的權利。","synonyms":[],"level":4,"theme":"藝術與音樂","examples":[{"en":"Every citizen has the right to cast a vote.","zh":"每位公民都有投票的權利。"},{"en":"Tall trees cast long shadows across the quiet park.","zh":"高大的樹木在寧靜的公園裡投下長長的影子。"},{"en":"The entire movie cast appeared at the premiere.","zh":"整個電影演員陣容都出席了首映會。"}]},{"word":"castle","pos":"n.","phonetic":"[ˈkæsl̩]","meaning":"城堡","definition":"a large building built in the past to defend against attack","collocations":["medieval castle","sand castle"],"example":"Tourists visit the old castle every summer.","exampleZh":"遊客們每年夏天都會參觀這座古老的城堡。","synonyms":[],"level":2,"theme":"居家與生活","examples":[{"en":"Tourists visit the old castle every summer.","zh":"遊客們每年夏天都會參觀這座古老的城堡。"},{"en":"The children built a huge sand castle on the beach.","zh":"孩子們在海灘上堆了一座巨大的沙堡。"},{"en":"We explored an old medieval castle during our holiday.","zh":"假期時我們探訪了一座古老的中世紀城堡。"}]},{"word":"casual","pos":"adj.","phonetic":"[ˈkæʒʊəl]","meaning":"隨意的；非正式的","definition":"relaxed and informal in style or manner","collocations":["casual clothes","casual conversation","dress casually"],"example":"You can wear casual clothes to the party.","exampleZh":"你可以穿便服去參加派對。","synonyms":["informal"],"level":4,"theme":"服裝與外表","examples":[{"en":"You can wear casual clothes to the party.","zh":"你可以穿便服去參加派對。"},{"en":"On Fridays, employees are allowed to dress casually.","zh":"星期五時，員工可以穿著休閒服裝。"},{"en":"They had a casual conversation over coffee about their travels.","zh":"他們喝著咖啡，隨意聊著各自的旅行。"}]},{"word":"catch","pos":"v.","phonetic":"[kætʃ]","meaning":"抓住；趕上；感染","definition":"to take hold of something moving, or to be in time for something","collocations":["catch a ball","catch a cold","catch a bus"],"example":"He ran fast to catch the last bus.","exampleZh":"他跑得很快才趕上了最後一班公車。","synonyms":["grab"],"level":1,"theme":"動作與行為","examples":[{"en":"He ran fast to catch the last bus.","zh":"他跑得很快才趕上了最後一班公車。"},{"en":"Wear a coat, or you might catch a cold in this wind.","zh":"穿上外套，不然這種風會讓你感冒。"},{"en":"He jumped high to catch the ball with one hand.","zh":"他高高躍起，用一隻手接住了球。"}]},{"word":"category","pos":"n.","phonetic":"[ˈkætəˌgorɪ]","meaning":"類別；種類","definition":"a group of things that share particular characteristics","collocations":["different categories","fall into a category"],"example":"Books in the library are organized by category.","exampleZh":"圖書館的書是按類別分類的。","synonyms":["type","class"],"level":4,"theme":"抽象概念","examples":[{"en":"Books in the library are organized by category.","zh":"圖書館的書是按類別分類的。"},{"en":"The museum sorts its paintings into several different categories.","zh":"博物館把館藏畫作分成好幾個不同的類別。"},{"en":"This new film does not fall into any usual category.","zh":"這部新電影不屬於任何常見的類別。"}]},{"word":"caterpillar","pos":"n.","phonetic":"[ˈkætəˌpɪlɚ]","meaning":"毛毛蟲","definition":"the wormlike larva of a butterfly or moth","collocations":["hungry caterpillar","caterpillar crawls"],"example":"The caterpillar turned into a beautiful butterfly.","exampleZh":"這隻毛毛蟲變成了一隻美麗的蝴蝶。","synonyms":[],"level":2,"theme":"動物與植物","examples":[{"en":"The caterpillar turned into a beautiful butterfly.","zh":"這隻毛毛蟲變成了一隻美麗的蝴蝶。"},{"en":"A fat green caterpillar slowly crawled along the leaf.","zh":"一隻肥胖的綠色毛毛蟲沿著葉子慢慢爬行。"},{"en":"The hungry caterpillar ate through several leaves in a day.","zh":"那隻飢餓的毛毛蟲一天內就把好幾片葉子吃光了。"}]},{"word":"cattle","pos":"n.","phonetic":"[ˈkætl̩]","meaning":"牛群","definition":"cows and bulls raised for meat or milk","collocations":["raise cattle","herd of cattle"],"example":"The farmer raises cattle on his ranch.","exampleZh":"這位農夫在他的牧場上養牛。","synonyms":[],"level":3,"theme":"動物與植物","examples":[{"en":"The farmer raises cattle on his ranch.","zh":"這位農夫在他的牧場上養牛。"},{"en":"A large herd of cattle grazed peacefully in the field.","zh":"一大群牛在田野裡平靜地吃草。"},{"en":"The family has raised cattle on this land for generations.","zh":"這家人在這片土地上養牛已經好幾代了。"}]},{"word":"cause","pos":"n. / v.","phonetic":"[kɔz]","meaning":"原因；導致","definition":"something that makes something else happen","collocations":["cause damage","root cause","cause and effect"],"example":"Heavy rain caused the flood in the city.","exampleZh":"大雨導致了這座城市的洪水。","synonyms":["reason"],"level":2,"theme":"抽象概念","examples":[{"en":"Heavy rain caused the flood in the city.","zh":"大雨導致了這座城市的洪水。"},{"en":"The strong typhoon caused serious damage to the coastal town.","zh":"強烈的颱風對沿海城鎮造成了嚴重的損害。"},{"en":"Doctors are still searching for the root cause of the illness.","zh":"醫生們仍在尋找這種疾病的根本原因。"}]},{"word":"caution","pos":"n.","phonetic":"[ˈkɔʃən]","meaning":"小心；謹慎；警告","definition":"great care taken to avoid danger or mistakes","collocations":["with caution","proceed with caution","word of caution"],"example":"Drivers should proceed with caution in the fog.","exampleZh":"在霧中開車，駕駛應該要小心謹慎。","synonyms":["care"],"level":5,"theme":"性質與描述","examples":[{"en":"Drivers should proceed with caution in the fog.","zh":"在霧中開車，駕駛應該要小心謹慎。"},{"en":"The wet floor sign warns people to walk with caution.","zh":"濕滑地板的告示牌提醒人們小心行走。"},{"en":"A word of caution: never share your password with strangers.","zh":"提醒一句：絕不要把你的密碼告訴陌生人。"}]},{"word":"cautious","pos":"adj.","phonetic":"[ˈkɔʃəs]","meaning":"謹慎的；小心的","definition":"careful to avoid danger, risk, or mistakes","collocations":["cautious approach","remain cautious"],"example":"Investors are cautious about the stock market.","exampleZh":"投資人對股市抱持謹慎的態度。","synonyms":["careful","wary"],"level":5,"theme":"性質與描述","examples":[{"en":"Investors are cautious about the stock market.","zh":"投資人對股市抱持謹慎的態度。"},{"en":"She took a cautious approach when investing her savings.","zh":"她在投資存款時採取謹慎的做法。"},{"en":"Drivers should remain cautious on icy winter roads.","zh":"在結冰的冬季道路上，駕駛應保持謹慎。"}]},{"word":"cave","pos":"n.","phonetic":"[kev]","meaning":"洞穴","definition":"a large hollow place in the side of a hill or underground","collocations":["explore a cave","cave dwelling"],"example":"The children were scared to enter the dark cave.","exampleZh":"孩子們害怕進入那個黑暗的洞穴。","synonyms":[],"level":2,"theme":"自然與環境","examples":[{"en":"The children were scared to enter the dark cave.","zh":"孩子們害怕進入那個黑暗的洞穴。"},{"en":"The explorers used flashlights to explore the dark cave.","zh":"探險者用手電筒探索那個漆黑的洞穴。"},{"en":"Ancient people once used this cave as a shelter.","zh":"古代人曾用這個洞穴當作避難所。"}]},{"word":"ceiling","pos":"n.","phonetic":"[ˈsilɪŋ]","meaning":"天花板；上限","definition":"the surface at the top of the inside of a room","collocations":["high ceiling","hit the ceiling","price ceiling"],"example":"The old house has a very high ceiling.","exampleZh":"這棟老房子的天花板非常高。","synonyms":[],"level":3,"theme":"居家與生活","examples":[{"en":"The old house has a very high ceiling.","zh":"這棟老房子的天花板非常高。"},{"en":"The hall's high ceiling made the room feel very grand.","zh":"大廳挑高的天花板讓整個空間顯得格外氣派。"},{"en":"The government set a price ceiling to protect poor families.","zh":"政府設定了價格上限以保護貧困家庭。"}]},{"word":"celebrate","pos":"v.","phonetic":"[ˈsɛləˌbret]","meaning":"慶祝","definition":"to do something enjoyable for a special occasion","collocations":["celebrate a birthday","celebrate victory"],"example":"We celebrated her graduation with a big dinner.","exampleZh":"我們用一頓豐盛的晚餐慶祝她畢業。","synonyms":[],"level":2,"theme":"社會與文化","examples":[{"en":"We celebrated her graduation with a big dinner.","zh":"我們用一頓豐盛的晚餐慶祝她畢業。"},{"en":"The team went out to celebrate their hard-won victory.","zh":"球隊出去慶祝這場得來不易的勝利。"},{"en":"We celebrate the New Year with fireworks and family dinners.","zh":"我們用煙火和家庭晚宴來慶祝新年。"}]},{"word":"celebration","pos":"n.","phonetic":"[ˌsɛləˈbreʃən]","meaning":"慶祝活動","definition":"an event or party held to celebrate something","collocations":["wedding celebration","in celebration of"],"example":"The festival is a celebration of the harvest.","exampleZh":"這個節慶是為了慶祝豐收。","synonyms":[],"level":3,"theme":"社會與文化","examples":[{"en":"The festival is a celebration of the harvest.","zh":"這個節慶是為了慶祝豐收。"},{"en":"The whole village gathered for the harvest celebration.","zh":"全村的人都聚在一起參加豐收慶典。"},{"en":"They held a big celebration in honor of her graduation.","zh":"他們舉辦了一場盛大的慶祝活動來祝賀她畢業。"}]},{"word":"celebrity","pos":"n.","phonetic":"[səˈlɛbrətɪ]","meaning":"名人","definition":"a person who is famous, especially in entertainment","collocations":["movie celebrity","celebrity gossip"],"example":"Many fans waited outside to see the celebrity.","exampleZh":"許多粉絲在外面等著見那位名人。","synonyms":["star"],"level":4,"theme":"社會與文化","examples":[{"en":"Many fans waited outside to see the celebrity.","zh":"許多粉絲在外面等著見那位名人。"},{"en":"Reporters followed the celebrity everywhere she went.","zh":"記者跟著那位名人到她去的每個地方。"},{"en":"Many magazines are full of celebrity gossip.","zh":"許多雜誌充滿了名人的八卦。"}]},{"word":"cell","pos":"n.","phonetic":"[sɛl]","meaning":"細胞；牢房；電池","definition":"the smallest structural unit of a living thing, or a small prison room","collocations":["blood cell","prison cell","cell phone"],"example":"The human body is made up of trillions of cells.","exampleZh":"人體是由數兆個細胞組成的。","synonyms":[],"level":3,"theme":"科學與數學","examples":[{"en":"The human body is made up of trillions of cells.","zh":"人體是由數兆個細胞組成的。"},{"en":"The prisoner spent long hours alone in his small cell.","zh":"囚犯獨自在他狹小的牢房裡待了很長的時間。"},{"en":"Red blood cells carry oxygen throughout the body.","zh":"紅血球把氧氣輸送到全身。"}]},{"word":"cellar","pos":"n.","phonetic":"[ˈsɛlɚ]","meaning":"地窖；地下室","definition":"an underground room used for storage","collocations":["wine cellar","dark cellar"],"example":"They keep old wine in the cellar.","exampleZh":"他們把舊酒存放在地窖裡。","synonyms":["basement"],"level":4,"theme":"居家與生活","examples":[{"en":"They keep old wine in the cellar.","zh":"他們把舊酒存放在地窖裡。"},{"en":"They store hundreds of bottles in the cool wine cellar.","zh":"他們在涼爽的酒窖裡存放了數百瓶酒。"},{"en":"During the storm, the family hid in the dark cellar.","zh":"暴風雨期間，一家人躲進黑暗的地窖裡。"}]},{"word":"cement","pos":"n.","phonetic":"[sɪˈmɛnt]","meaning":"水泥","definition":"a gray powder mixed with water and sand to make concrete","collocations":["cement mixer","pour cement"],"example":"Workers poured cement to build the foundation.","exampleZh":"工人們澆灌水泥來建造地基。","synonyms":[],"level":4,"theme":"居家與生活","examples":[{"en":"Workers poured cement to build the foundation.","zh":"工人們澆灌水泥來建造地基。"},{"en":"The workers poured cement to build the new sidewalk.","zh":"工人們灌漿建造新的人行道。"},{"en":"A cement mixer slowly turned outside the construction site.","zh":"一輛水泥攪拌車在工地外緩緩轉動。"}]},{"word":"cent","pos":"n.","phonetic":"[sɛnt]","meaning":"分（貨幣單位）","definition":"a small unit of money equal to one hundredth of a dollar","collocations":["fifty cents","not a cent"],"example":"The candy costs only fifty cents.","exampleZh":"這顆糖果只要五十美分。","synonyms":[],"level":1,"theme":"商業與金錢","examples":[{"en":"The candy costs only fifty cents.","zh":"這顆糖果只要五十美分。"},{"en":"The old newspaper cost only a few cents years ago.","zh":"多年前這份舊報紙只賣幾分錢。"},{"en":"After the trip, he didn't have a single cent left.","zh":"旅行結束後，他一分錢也不剩。"}]},{"word":"center","pos":"n.","phonetic":"[ˈsɛntɚ]","meaning":"中心；中央","definition":"the middle point of something","collocations":["shopping center","center of attention","city center"],"example":"The new mall is located in the city center.","exampleZh":"這間新的購物中心位於市中心。","synonyms":["middle"],"level":1,"theme":"時間與空間","examples":[{"en":"The new mall is located in the city center.","zh":"這間新的購物中心位於市中心。"},{"en":"The new shopping center attracts crowds every weekend.","zh":"這座新的購物中心每個週末都吸引大批人潮。"},{"en":"The birthday boy became the center of attention at the party.","zh":"壽星成了派對上眾人注目的焦點。"}]},{"word":"central","pos":"adj.","phonetic":"[ˈsɛntrəl]","meaning":"中央的；核心的","definition":"in or near the center, or most important","collocations":["central idea","central government","central location"],"example":"The library is in a central location on campus.","exampleZh":"圖書館位於校園的中心位置。","synonyms":[],"level":3,"theme":"時間與空間","examples":[{"en":"The library is in a central location on campus.","zh":"圖書館位於校園的中心位置。"},{"en":"The hotel's central location makes sightseeing very convenient.","zh":"飯店位置適中，讓觀光非常方便。"},{"en":"Try to summarize the central idea of the whole passage.","zh":"試著總結整段文章的核心概念。"}]},{"word":"century","pos":"n.","phonetic":"[ˈsɛntʃərɪ]","meaning":"世紀；一百年","definition":"a period of one hundred years","collocations":["the 21st century","for a century"],"example":"This temple was built in the 18th century.","exampleZh":"這座廟宇建於十八世紀。","synonyms":[],"level":2,"theme":"時間與空間","examples":[{"en":"This temple was built in the 18th century.","zh":"這座廟宇建於十八世紀。"},{"en":"Many amazing inventions appeared during the twentieth century.","zh":"許多驚人的發明出現在二十世紀。"},{"en":"This family recipe has been passed down for over a century.","zh":"這道家傳食譜已經流傳超過一個世紀了。"}]},{"word":"cereal","pos":"n.","phonetic":"[ˈsɪrɪəl]","meaning":"穀類食品；穀物","definition":"a grain-based food often eaten for breakfast","collocations":["bowl of cereal","cereal box"],"example":"She eats cereal with milk every morning.","exampleZh":"她每天早上都吃穀片配牛奶。","synonyms":[],"level":2,"theme":"食物與烹飪","examples":[{"en":"She eats cereal with milk every morning.","zh":"她每天早上都吃穀片配牛奶。"},{"en":"He poured milk over a big bowl of cereal.","zh":"他把牛奶倒在一大碗穀片上。"},{"en":"The colorful cereal box attracted the young children immediately.","zh":"色彩繽紛的穀片盒立刻吸引了小孩子。"}]},{"word":"ceremony","pos":"n.","phonetic":"[ˈsɛrəˌmonɪ]","meaning":"典禮；儀式","definition":"a formal event held to mark a special occasion","collocations":["graduation ceremony","wedding ceremony"],"example":"The graduation ceremony was held in the gym.","exampleZh":"畢業典禮在體育館舉行。","synonyms":[],"level":4,"theme":"社會與文化","examples":[{"en":"The graduation ceremony was held in the gym.","zh":"畢業典禮在體育館舉行。"},{"en":"Parents were invited to attend the graduation ceremony.","zh":"家長受邀出席畢業典禮。"},{"en":"The wedding ceremony took place in a beautiful old church.","zh":"婚禮在一座美麗的古老教堂裡舉行。"}]},{"word":"certain","pos":"adj.","phonetic":"[ˈsɝtn̩]","meaning":"確定的；某些","definition":"sure about something, or particular but not named","collocations":["make certain","a certain amount","certain to happen"],"example":"I am certain that she will succeed.","exampleZh":"我確信她會成功。","synonyms":["sure"],"level":2,"theme":"抽象概念","examples":[{"en":"I am certain that she will succeed.","zh":"我確信她會成功。"},{"en":"Please make certain that all the doors are locked at night.","zh":"請確認晚上所有的門都上鎖了。"},{"en":"Only certain students were chosen for the special program.","zh":"只有某些學生被選入這個特別的課程。"}]},{"word":"certainly","pos":"adv.","phonetic":"[ˈsɝtn̩lɪ]","meaning":"當然；確實","definition":"without doubt; definitely","collocations":["certainly not","will certainly help"],"example":"I will certainly attend the meeting tomorrow.","exampleZh":"我明天一定會出席會議。","synonyms":["definitely"],"level":2,"theme":"溝通與語言","examples":[{"en":"I will certainly attend the meeting tomorrow.","zh":"我明天一定會出席會議。"},{"en":"I will certainly help you finish this project on time.","zh":"我一定會幫你準時完成這個專案。"},{"en":"Would I ever lie to you? Certainly not, I promise.","zh":"我會對你說謊嗎？當然不會，我保證。"}]},{"word":"certificate","pos":"n.","phonetic":"[sɚˈtɪfəkɪt]","meaning":"證書；證明書","definition":"an official document stating that a fact is true","collocations":["birth certificate","certificate of completion"],"example":"She received a certificate for finishing the course.","exampleZh":"她完成這門課程後收到了一張證書。","synonyms":[],"level":4,"theme":"教育與學習","examples":[{"en":"She received a certificate for finishing the course.","zh":"她完成這門課程後收到了一張證書。"},{"en":"You need your birth certificate to apply for a passport.","zh":"你需要出生證明才能申請護照。"},{"en":"After the training, each student earned a certificate of completion.","zh":"訓練結束後，每位學生都獲得了結業證書。"}]},{"word":"chain","pos":"n. / v.","phonetic":"[tʃen]","meaning":"鏈子；連鎖；用鏈鎖住","definition":"a series of connected metal rings","collocations":["chain reaction","fast-food chain","gold chain"],"example":"The dog was tied to a chain in the yard.","exampleZh":"那隻狗被鏈子拴在院子裡。","synonyms":[],"level":3,"theme":"居家與生活","examples":[{"en":"The dog was tied to a chain in the yard.","zh":"那隻狗被鏈子拴在院子裡。"},{"en":"A single small mistake caused a chain reaction of problems.","zh":"一個小失誤引發了一連串問題的連鎖反應。"},{"en":"She wore a beautiful gold chain around her neck yesterday.","zh":"她昨天在脖子上戴著一條漂亮的金鏈子。"}]},{"word":"chair","pos":"n.","phonetic":"[tʃɛr]","meaning":"椅子；主持","definition":"a piece of furniture for one person to sit on","collocations":["sit on a chair","chair a meeting"],"example":"Please pull up a chair and join us.","exampleZh":"請拉張椅子過來加入我們吧。","synonyms":[],"level":1,"theme":"居家與生活","examples":[{"en":"Please pull up a chair and join us.","zh":"請拉張椅子過來加入我們吧。"},{"en":"Our teacher will chair the meeting about the school trip.","zh":"我們老師將主持這場關於校外教學的會議。"},{"en":"He pulled his chair closer to the desk to study.","zh":"他把椅子拉近書桌，好專心讀書。"}]},{"word":"chairman","pos":"n.","phonetic":"[ˈtʃɛrmən]","meaning":"主席；董事長","definition":"the person who leads a meeting, committee, or organization","collocations":["board chairman","chairman of the committee"],"example":"The chairman opened the meeting with a short speech.","exampleZh":"主席用一段簡短的致詞開始了會議。","synonyms":[],"level":4,"theme":"工作與職業","examples":[{"en":"The chairman opened the meeting with a short speech.","zh":"主席用一段簡短的致詞開始了會議。"},{"en":"The chairman of the committee announced the final decision clearly.","zh":"委員會主席清楚地宣布了最終的決定。"},{"en":"She was elected as the new board chairman last week.","zh":"她上週被選為新任董事長。"}]},{"word":"chalk","pos":"n.","phonetic":"[tʃɔk]","meaning":"粉筆","definition":"a soft white or colored stick used for writing on a blackboard","collocations":["piece of chalk","chalk dust"],"example":"The teacher wrote the answer on the board with chalk.","exampleZh":"老師用粉筆把答案寫在黑板上。","synonyms":[],"level":1,"theme":"教育與學習","examples":[{"en":"The teacher wrote the answer on the board with chalk.","zh":"老師用粉筆把答案寫在黑板上。"},{"en":"He picked up a piece of chalk and drew a map.","zh":"他拿起一支粉筆，畫了一張地圖。"},{"en":"Chalk dust covered the teacher's hands after the long class.","zh":"上完那堂長課後，老師的手上沾滿了粉筆灰。"}]},{"word":"challenge","pos":"n. / v.","phonetic":"[ˈtʃælɪndʒ]","meaning":"挑戰；質疑","definition":"a difficult task that tests one's ability, or to question something","collocations":["face a challenge","accept a challenge","challenge an idea"],"example":"Learning a new language can be a real challenge.","exampleZh":"學習一種新語言可能是個真正的挑戰。","synonyms":["difficulty"],"level":3,"theme":"抽象概念","examples":[{"en":"Learning a new language can be a real challenge.","zh":"學習一種新語言可能是個真正的挑戰。"},{"en":"Moving to a new school was a big challenge for her.","zh":"轉到新學校對她來說是一大挑戰。"},{"en":"The students challenged the teacher's idea with very good reasons.","zh":"學生們用充分的理由質疑了老師的想法。"}]},{"word":"chamber","pos":"n.","phonetic":"[ˈtʃembɚ]","meaning":"房間；議院；室","definition":"a room, especially one used for a special or formal purpose","collocations":["chamber of commerce","gas chamber"],"example":"The senators gathered in the chamber to vote.","exampleZh":"參議員們聚集在議事廳投票。","synonyms":[],"level":5,"theme":"政治與法律","examples":[{"en":"The senators gathered in the chamber to vote.","zh":"參議員們聚集在議事廳投票。"},{"en":"The local chamber of commerce supports small businesses in town.","zh":"當地的商會支持鎮上的小型企業。"},{"en":"The ancient tomb had a hidden chamber full of treasures.","zh":"這座古墓有一個藏滿寶藏的密室。"}]},{"word":"champion","pos":"n.","phonetic":"[ˈtʃæmpɪən]","meaning":"冠軍；優勝者","definition":"the winner of a competition or contest","collocations":["world champion","defending champion"],"example":"She became the world champion in swimming.","exampleZh":"她成為了游泳世界冠軍。","synonyms":["winner"],"level":3,"theme":"運動與休閒","examples":[{"en":"She became the world champion in swimming.","zh":"她成為了游泳世界冠軍。"},{"en":"The defending champion trained hard to keep his title.","zh":"衛冕冠軍努力訓練，想保住他的頭銜。"},{"en":"After years of practice, she finally became a world champion.","zh":"經過多年練習，她終於成為世界冠軍。"}]},{"word":"championship","pos":"n.","phonetic":"[ˈtʃæmpɪənˌʃɪp]","meaning":"錦標賽；冠軍賽","definition":"a competition held to find the best player or team","collocations":["win the championship","world championship"],"example":"The team won the national championship last year.","exampleZh":"這支隊伍去年贏得了全國錦標賽。","synonyms":[],"level":4,"theme":"運動與休閒","examples":[{"en":"The team won the national championship last year.","zh":"這支隊伍去年贏得了全國錦標賽。"},{"en":"Our basketball team hopes to win the championship this year.","zh":"我們的籃球隊希望今年能贏得冠軍賽。"},{"en":"The world championship will be held in our city next summer.","zh":"世界錦標賽明年夏天將在我們的城市舉辦。"}]},{"word":"chance","pos":"n.","phonetic":"[tʃæns]","meaning":"機會；可能性","definition":"an opportunity, or the possibility of something happening","collocations":["take a chance","by chance","a good chance"],"example":"This is your last chance to change your answer.","exampleZh":"這是你修改答案的最後機會。","synonyms":["opportunity"],"level":1,"theme":"抽象概念","examples":[{"en":"This is your last chance to change your answer.","zh":"這是你修改答案的最後機會。"},{"en":"You should take a chance and try out for the team.","zh":"你應該把握機會，去參加球隊的選拔。"},{"en":"We met by chance at the bookstore yesterday afternoon.","zh":"我們昨天下午在書店裡偶然相遇。"}]},{"word":"change","pos":"v. / n.","phonetic":"[tʃendʒ]","meaning":"改變；零錢","definition":"to make or become different, or the money returned after a payment","collocations":["change one's mind","climate change","small change"],"example":"She decided to change her career path.","exampleZh":"她決定改變她的職涯方向。","synonyms":["alter"],"level":1,"theme":"動作與行為","examples":[{"en":"She decided to change her career path.","zh":"她決定改變她的職涯方向。"},{"en":"She changed her mind and decided to study abroad instead.","zh":"她改變了主意，決定改為出國留學。"},{"en":"The clerk gave me some small change after I paid.","zh":"我付完錢後，店員找給我一些零錢。"}]},{"word":"channel","pos":"n.","phonetic":"[ˈtʃænl̩]","meaning":"頻道；海峽；管道","definition":"a television station, or a passage of water connecting two seas","collocations":["TV channel","the English Channel","channel of communication"],"example":"He switched the channel to watch the news.","exampleZh":"他轉台去看新聞。","synonyms":[],"level":3,"theme":"科技與媒體","examples":[{"en":"He switched the channel to watch the news.","zh":"他轉台去看新聞。"},{"en":"My little brother keeps switching the TV channel during dinner.","zh":"我弟弟在吃晚餐時一直轉電視頻道。"},{"en":"Email is an important channel of communication between teachers and parents.","zh":"電子郵件是老師和家長之間重要的溝通管道。"}]},{"word":"chaos","pos":"n.","phonetic":"[ˈkeɑs]","meaning":"混亂；紊亂","definition":"a state of complete disorder and confusion","collocations":["total chaos","descend into chaos"],"example":"The blackout caused chaos in the city center.","exampleZh":"停電讓市中心陷入一片混亂。","synonyms":["disorder"],"level":5,"theme":"抽象概念","examples":[{"en":"The blackout caused chaos in the city center.","zh":"停電讓市中心陷入一片混亂。"},{"en":"The classroom fell into total chaos when the lights went out.","zh":"燈一熄滅，教室就陷入了一片混亂。"},{"en":"Without clear rules, the game quickly descended into chaos.","zh":"沒有明確的規則，這場遊戲很快就變得一團混亂。"}]},{"word":"chapter","pos":"n.","phonetic":"[ˈtʃæptɚ]","meaning":"章節","definition":"a main division of a book","collocations":["final chapter","read a chapter"],"example":"Please finish reading chapter three by tomorrow.","exampleZh":"請在明天前讀完第三章。","synonyms":[],"level":2,"theme":"教育與學習","examples":[{"en":"Please finish reading chapter three by tomorrow.","zh":"請在明天前讀完第三章。"},{"en":"I read one chapter of my novel every night before sleeping.","zh":"我每天睡前都會讀一章小說。"},{"en":"The final chapter of the story surprised all the readers.","zh":"故事的最後一章讓所有讀者都感到驚訝。"}]},{"word":"character","pos":"n.","phonetic":"[ˈkærɪktɚ]","meaning":"角色；性格；文字","definition":"a person in a story, or a person's nature and personality","collocations":["main character","strong character","Chinese character"],"example":"The main character in the novel is very brave.","exampleZh":"這部小說的主角非常勇敢。","synonyms":["personality"],"level":3,"theme":"藝術與音樂","examples":[{"en":"The main character in the novel is very brave.","zh":"這部小說的主角非常勇敢。"},{"en":"The main character in the movie learns to be brave.","zh":"電影裡的主角學會了勇敢。"},{"en":"Learning to write each Chinese character takes a lot of practice.","zh":"學會書寫每個中文字都需要大量的練習。"}]},{"word":"characteristic","pos":"n. / adj.","phonetic":"[ˌkærɪktəˈrɪstɪk]","meaning":"特徵；特有的","definition":"a typical feature or quality of someone or something","collocations":["key characteristic","characteristic feature"],"example":"Curiosity is a characteristic of young children.","exampleZh":"好奇心是幼童的一項特徵。","synonyms":["feature","trait"],"level":5,"theme":"性質與描述","examples":[{"en":"Curiosity is a characteristic of young children.","zh":"好奇心是幼童的一項特徵。"},{"en":"Honesty is the most important characteristic of a good friend.","zh":"誠實是一個好朋友最重要的特質。"},{"en":"Bright colors are a characteristic feature of this artist's paintings.","zh":"鮮豔的色彩是這位藝術家畫作的特徵。"}]},{"word":"charge","pos":"v. / n.","phonetic":"[tʃɑrdʒ]","meaning":"收費；充電；指控；負責","definition":"to ask for money for something, to fill with electricity, or to accuse someone","collocations":["charge a fee","in charge of","charge a battery"],"example":"The hotel charges extra for breakfast.","exampleZh":"這間飯店早餐要額外收費。","synonyms":[],"level":3,"theme":"商業與金錢","examples":[{"en":"The hotel charges extra for breakfast.","zh":"這間飯店早餐要額外收費。"},{"en":"Remember to charge your phone battery before the long trip.","zh":"記得在長途旅行前把手機電池充飽電。"},{"en":"My sister is in charge of decorating the classroom this week.","zh":"這週由我姐姐負責布置教室。"}]},{"word":"charity","pos":"n.","phonetic":"[ˈtʃærətɪ]","meaning":"慈善；慈善機構","definition":"the giving of money or help to those in need","collocations":["charity organization","give to charity"],"example":"The company donated money to a local charity.","exampleZh":"這家公司捐款給當地一家慈善機構。","synonyms":[],"level":4,"theme":"社會與文化","examples":[{"en":"The company donated money to a local charity.","zh":"這家公司捐款給當地一家慈善機構。"},{"en":"They gave most of their old clothes to charity.","zh":"他們把大部分的舊衣服都捐給了慈善機構。"},{"en":"The students raised money for a charity that helps sick children.","zh":"學生們為一個幫助生病孩童的慈善機構募款。"}]},{"word":"charm","pos":"n. / v.","phonetic":"[tʃɑrm]","meaning":"魅力；迷人之處；使著迷","definition":"an attractive quality, or to please and delight someone","collocations":["natural charm","charm the audience"],"example":"Her smile has a certain charm that everyone loves.","exampleZh":"她的微笑有一種大家都喜愛的魅力。","synonyms":["appeal"],"level":4,"theme":"性質與描述","examples":[{"en":"Her smile has a certain charm that everyone loves.","zh":"她的微笑有一種大家都喜愛的魅力。"},{"en":"The young singer charmed the audience with her gentle voice.","zh":"這位年輕歌手用溫柔的嗓音迷住了觀眾。"},{"en":"His natural charm makes it easy for him to make friends.","zh":"他天生的魅力讓他很容易交到朋友。"}]},{"word":"charming","pos":"adj.","phonetic":"[ˈtʃɑrmɪŋ]","meaning":"迷人的","definition":"pleasant and attractive","collocations":["charming smile","charming village"],"example":"They stayed in a charming little village.","exampleZh":"他們住在一個迷人的小村莊裡。","synonyms":["attractive"],"level":4,"theme":"性質與描述","examples":[{"en":"They stayed in a charming little village.","zh":"他們住在一個迷人的小村莊裡。"},{"en":"We spent the weekend in a charming village by the sea.","zh":"我們在一個海邊迷人的小村莊度過了週末。"},{"en":"The new student won everyone over with his charming smile.","zh":"這位新同學用迷人的微笑贏得了大家的好感。"}]},{"word":"chart","pos":"n.","phonetic":"[tʃɑrt]","meaning":"圖表","definition":"a diagram or drawing that shows information clearly","collocations":["bar chart","weather chart","top of the charts"],"example":"The chart shows the sales figures for each month.","exampleZh":"這張圖表顯示了每個月的銷售數字。","synonyms":["graph"],"level":3,"theme":"科學與數學","examples":[{"en":"The chart shows the sales figures for each month.","zh":"這張圖表顯示了每個月的銷售數字。"},{"en":"The bar chart clearly shows how much water we use daily.","zh":"這張長條圖清楚顯示我們每天用了多少水。"},{"en":"Her new song quickly reached the top of the charts.","zh":"她的新歌很快就登上了排行榜的冠軍。"}]},{"word":"chase","pos":"v. / n.","phonetic":"[tʃes]","meaning":"追逐；追趕","definition":"to run after someone or something in order to catch it","collocations":["chase a thief","car chase"],"example":"The dog chased the cat across the yard.","exampleZh":"那隻狗追著貓跑過院子。","synonyms":["pursue"],"level":2,"theme":"動作與行為","examples":[{"en":"The dog chased the cat across the yard.","zh":"那隻狗追著貓跑過院子。"},{"en":"The police officer chased the thief down the busy street.","zh":"警察沿著繁忙的街道追趕小偷。"},{"en":"The movie ended with an exciting car chase through the city.","zh":"這部電影以一場穿越城市的刺激飛車追逐作結。"}]},{"word":"chat","pos":"v. / n.","phonetic":"[tʃæt]","meaning":"聊天","definition":"to talk in a friendly, informal way","collocations":["have a chat","chat online","a friendly chat"],"example":"We chatted about school over coffee.","exampleZh":"我們邊喝咖啡邊聊學校的事。","synonyms":["talk"],"level":1,"theme":"溝通與語言","examples":[{"en":"We chatted about school over coffee.","zh":"我們邊喝咖啡邊聊學校的事。"},{"en":"We often chat online after finishing our homework at night.","zh":"我們晚上寫完功課後常常在網路上聊天。"},{"en":"I had a friendly chat with my neighbor this morning.","zh":"今天早上我和鄰居愉快地聊了一下。"}]},{"word":"cheap","pos":"adj.","phonetic":"[tʃip]","meaning":"便宜的；廉價的","definition":"low in price; not expensive","collocations":["cheap price","cheap flight","dirt cheap"],"example":"This restaurant serves cheap but delicious food.","exampleZh":"這家餐廳的食物便宜又好吃。","synonyms":["inexpensive"],"level":1,"theme":"商業與金錢","examples":[{"en":"This restaurant serves cheap but delicious food.","zh":"這家餐廳的食物便宜又好吃。"},{"en":"We booked a cheap flight to save money for our trip.","zh":"我們訂了便宜的機票，好為旅行省錢。"},{"en":"The vegetables at the morning market are usually dirt cheap.","zh":"早市裡的蔬菜通常非常便宜。"}]},{"word":"cheat","pos":"v. / n.","phonetic":"[tʃit]","meaning":"欺騙；作弊","definition":"to act dishonestly in order to gain an advantage","collocations":["cheat on a test","cheat someone"],"example":"He was caught cheating on the final exam.","exampleZh":"他被抓到在期末考作弊。","synonyms":["deceive"],"level":2,"theme":"動作與行為","examples":[{"en":"He was caught cheating on the final exam.","zh":"他被抓到在期末考作弊。"},{"en":"The teacher warned us never to cheat on a test.","zh":"老師警告我們考試時絕對不可以作弊。"},{"en":"He felt guilty for cheating his friend out of money.","zh":"他因為騙走朋友的錢而感到內疚。"}]},{"word":"check","pos":"v. / n.","phonetic":"[tʃɛk]","meaning":"檢查；核對；支票","definition":"to examine something to make sure it is correct or safe","collocations":["check the answer","check in","write a check"],"example":"Please check your homework before you submit it.","exampleZh":"請在交作業前檢查一下。","synonyms":["examine"],"level":1,"theme":"動作與行為","examples":[{"en":"Please check your homework before you submit it.","zh":"請在交作業前檢查一下。"},{"en":"We arrived early to check in at the hotel.","zh":"我們提早抵達旅館辦理入住手續。"},{"en":"Always check your answers carefully before handing in the exam.","zh":"交考卷前一定要仔細檢查你的答案。"}]},{"word":"cheek","pos":"n.","phonetic":"[tʃik]","meaning":"臉頰","definition":"the soft part of the face below the eye on either side","collocations":["rosy cheeks","kiss on the cheek"],"example":"The baby's cheeks were round and rosy.","exampleZh":"這個嬰兒的臉頰圓潤紅潤。","synonyms":[],"level":2,"theme":"身體與健康","examples":[{"en":"The baby's cheeks were round and rosy.","zh":"這個嬰兒的臉頰圓潤紅潤。"},{"en":"Her cheeks turned red when the teacher praised her work.","zh":"當老師稱讚她的作品時，她的臉頰紅了起來。"},{"en":"The grandmother gave the child a gentle kiss on the cheek.","zh":"奶奶在孩子的臉頰上輕輕地親了一下。"}]},{"word":"cheer","pos":"v. / n.","phonetic":"[tʃɪr]","meaning":"歡呼；使高興","definition":"to shout in support of someone, or to make someone feel happier","collocations":["cheer for a team","cheer up","loud cheers"],"example":"The fans cheered loudly for their team.","exampleZh":"球迷們為他們的隊伍大聲歡呼。","synonyms":["applaud"],"level":2,"theme":"情緒與感受","examples":[{"en":"The fans cheered loudly for their team.","zh":"球迷們為他們的隊伍大聲歡呼。"},{"en":"We cheered for our team until the very last minute.","zh":"我們為自己的隊伍加油到最後一刻。"},{"en":"I tried to cheer up my friend after she failed the test.","zh":"朋友考試不及格後，我試著讓她開心起來。"}]},{"word":"cheerful","pos":"adj.","phonetic":"[ˈtʃɪrfəl]","meaning":"快樂的；愉快的","definition":"happy, positive, and full of good spirits","collocations":["cheerful mood","cheerful smile"],"example":"She always has a cheerful smile on her face.","exampleZh":"她臉上總是掛著愉快的笑容。","synonyms":["happy"],"level":3,"theme":"情緒與感受","examples":[{"en":"She always has a cheerful smile on her face.","zh":"她臉上總是掛著愉快的笑容。"},{"en":"The nurse was in a cheerful mood despite the busy day.","zh":"儘管一整天都很忙，那位護士仍心情愉快。"},{"en":"Bright yellow walls make the whole room feel warm and cheerful.","zh":"明亮的黃色牆壁讓整個房間感覺溫暖又愉快。"}]},{"word":"cheese","pos":"n.","phonetic":"[tʃiz]","meaning":"起司；乳酪","definition":"a solid food made from milk","collocations":["slice of cheese","melted cheese"],"example":"He added some cheese to his sandwich.","exampleZh":"他在三明治裡加了一些起司。","synonyms":[],"level":1,"theme":"食物與烹飪","examples":[{"en":"He added some cheese to his sandwich.","zh":"他在三明治裡加了一些起司。"},{"en":"She put a thick slice of cheese on top of the burger.","zh":"她在漢堡上放了一片厚厚的起司。"},{"en":"The freshly baked pizza was covered with delicious melted cheese.","zh":"剛烤好的披薩上鋪滿了美味的融化起司。"}]},{"word":"chef","pos":"n.","phonetic":"[ʃɛf]","meaning":"主廚；廚師","definition":"a professional cook, especially the head cook in a restaurant","collocations":["head chef","famous chef"],"example":"The chef prepared a special dish for the guests.","exampleZh":"主廚為客人們準備了一道特別的菜。","synonyms":["cook"],"level":3,"theme":"工作與職業","examples":[{"en":"The chef prepared a special dish for the guests.","zh":"主廚為客人們準備了一道特別的菜。"},{"en":"The head chef taught us how to make fresh noodles.","zh":"主廚教我們如何製作新鮮的麵條。"},{"en":"A famous chef opened a new restaurant near our school.","zh":"一位知名主廚在我們學校附近開了一家新餐廳。"}]},{"word":"chemical","pos":"n. / adj.","phonetic":"[ˈkɛmɪkl̩]","meaning":"化學物質；化學的","definition":"a substance used in or produced by a chemical process","collocations":["chemical reaction","harmful chemicals"],"example":"Some cleaning products contain harmful chemicals.","exampleZh":"有些清潔用品含有有害的化學物質。","synonyms":[],"level":4,"theme":"科學與數學","examples":[{"en":"Some cleaning products contain harmful chemicals.","zh":"有些清潔用品含有有害的化學物質。"},{"en":"Mixing the two liquids caused an interesting chemical reaction.","zh":"把這兩種液體混合會產生有趣的化學反應。"},{"en":"Farmers should avoid using too many harmful chemicals on crops.","zh":"農夫應該避免在作物上使用過多有害的化學物質。"}]},{"word":"chemist","pos":"n.","phonetic":"[ˈkɛmɪst]","meaning":"化學家；藥劑師","definition":"a scientist who studies or works with chemistry","collocations":["research chemist","skilled chemist"],"example":"The chemist mixed the two liquids carefully.","exampleZh":"這位化學家小心地混合這兩種液體。","synonyms":[],"level":4,"theme":"科學與數學","examples":[{"en":"The chemist mixed the two liquids carefully.","zh":"這位化學家小心地混合這兩種液體。"},{"en":"The research chemist spent years developing a safer medicine.","zh":"這位研究化學家花了多年時間研發更安全的藥物。"},{"en":"A skilled chemist must follow safety rules inside the lab.","zh":"一位熟練的化學家在實驗室裡必須遵守安全規則。"}]},{"word":"chemistry","pos":"n.","phonetic":"[ˈkɛmɪstrɪ]","meaning":"化學","definition":"the science that deals with substances and their reactions","collocations":["study chemistry","chemistry class"],"example":"She got the highest score in the chemistry exam.","exampleZh":"她在化學考試中拿到最高分。","synonyms":[],"level":3,"theme":"科學與數學","examples":[{"en":"She got the highest score in the chemistry exam.","zh":"她在化學考試中拿到最高分。"},{"en":"I find chemistry class much more interesting than history.","zh":"我覺得化學課比歷史課有趣多了。"},{"en":"She wants to study chemistry at university next year.","zh":"她想在明年上大學時主修化學。"}]},{"word":"cherish","pos":"v.","phonetic":"[ˈtʃɛrɪʃ]","meaning":"珍惜；珍愛","definition":"to love, protect, and care for something or someone deeply","collocations":["cherish memories","cherish a friendship"],"example":"I will always cherish the time we spent together.","exampleZh":"我會永遠珍惜我們相處的時光。","synonyms":["treasure"],"level":5,"theme":"情緒與感受","examples":[{"en":"I will always cherish the time we spent together.","zh":"我會永遠珍惜我們相處的時光。"},{"en":"I will always cherish the happy memories of my childhood.","zh":"我會永遠珍惜童年那些快樂的回憶。"},{"en":"They cherish their friendship even though they live far apart.","zh":"即使住得很遠，他們仍珍惜彼此的友誼。"}]},{"word":"cherry","pos":"n.","phonetic":"[ˈtʃɛrɪ]","meaning":"櫻桃","definition":"a small round red or black fruit with a hard stone","collocations":["cherry blossom","cherry pie"],"example":"Cherry blossoms bloom beautifully in spring.","exampleZh":"櫻花在春天盛開得很美。","synonyms":[],"level":1,"theme":"食物與烹飪","examples":[{"en":"Cherry blossoms bloom beautifully in spring.","zh":"櫻花在春天盛開得很美。"},{"en":"My grandmother baked a sweet cherry pie for the party.","zh":"我奶奶為派對烤了一個甜甜的櫻桃派。"},{"en":"Crowds gather in the park to see the cherry blossoms.","zh":"人群聚集在公園裡欣賞櫻花。"}]},{"word":"chess","pos":"n.","phonetic":"[tʃɛs]","meaning":"西洋棋","definition":"a board game for two players using pieces of different powers","collocations":["play chess","chess champion"],"example":"My father taught me how to play chess.","exampleZh":"我爸爸教我怎麼下西洋棋。","synonyms":[],"level":2,"theme":"運動與休閒","examples":[{"en":"My father taught me how to play chess.","zh":"我爸爸教我怎麼下西洋棋。"},{"en":"We often play chess together during the long lunch break.","zh":"我們常在漫長的午休時間一起下西洋棋。"},{"en":"He became the school's chess champion at just twelve years old.","zh":"他年僅十二歲就成為學校的西洋棋冠軍。"}]},{"word":"chest","pos":"n.","phonetic":"[tʃɛst]","meaning":"胸部；箱子","definition":"the front part of the body between the neck and stomach, or a large strong box","collocations":["chest pain","treasure chest"],"example":"He felt a sharp pain in his chest.","exampleZh":"他感到胸口一陣劇痛。","synonyms":[],"level":3,"theme":"身體與健康","examples":[{"en":"He felt a sharp pain in his chest.","zh":"他感到胸口一陣劇痛。"},{"en":"The old pirate map led them to a hidden treasure chest.","zh":"那張古老的海盜地圖帶領他們找到一個藏起來的寶箱。"},{"en":"He should see a doctor about his sudden chest pain.","zh":"他突然胸痛，應該去看醫生。"}]},{"word":"chew","pos":"v.","phonetic":"[tʃu]","meaning":"咀嚼","definition":"to crush and grind food with the teeth","collocations":["chew gum","chew food slowly"],"example":"You should chew your food slowly and carefully.","exampleZh":"你應該慢慢地仔細咀嚼食物。","synonyms":[],"level":2,"theme":"動作與行為","examples":[{"en":"You should chew your food slowly and carefully.","zh":"你應該慢慢地仔細咀嚼食物。"},{"en":"The teacher told us not to chew gum in class.","zh":"老師叫我們上課時不要嚼口香糖。"},{"en":"If you chew your food slowly, digestion becomes much easier.","zh":"如果你細嚼慢嚥，消化就會容易許多。"}]},{"word":"chick","pos":"n.","phonetic":"[tʃɪk]","meaning":"小雞","definition":"a baby chicken","collocations":["baby chick","hatch a chick"],"example":"The hen protected her chicks from the rain.","exampleZh":"母雞保護牠的小雞不被雨淋濕。","synonyms":[],"level":1,"theme":"動物與植物","examples":[{"en":"The hen protected her chicks from the rain.","zh":"母雞保護牠的小雞不被雨淋濕。"},{"en":"The children watched a baby chick hatch from its egg.","zh":"孩子們看著一隻小雞從蛋裡孵出來。"},{"en":"Several yellow chicks followed the hen around the farm.","zh":"幾隻黃色的小雞跟著母雞在農場裡到處走。"}]},{"word":"chicken","pos":"n.","phonetic":"[ˈtʃɪkɪn]","meaning":"雞；雞肉","definition":"a common farm bird raised for its eggs and meat","collocations":["fried chicken","raise chickens"],"example":"We had roast chicken for dinner last night.","exampleZh":"我們昨晚吃了烤雞當晚餐。","synonyms":[],"level":1,"theme":"食物與烹飪","examples":[{"en":"We had roast chicken for dinner last night.","zh":"我們昨晚吃了烤雞當晚餐。"},{"en":"My uncle raises chickens on his small farm in the countryside.","zh":"我叔叔在鄉下的小農場裡養雞。"},{"en":"We ordered a big bucket of fried chicken for the picnic.","zh":"我們點了一大桶炸雞帶去野餐。"}]},{"word":"cigarette","pos":"n.","phonetic":"[ˈsɪgəˌrɛt]","meaning":"香菸","definition":"a thin tube of shredded tobacco rolled in paper for smoking","collocations":["light a cigarette","smoke a cigarette","cigarette smoke"],"example":"He tried hard to quit smoking cigarettes.","exampleZh":"他很努力想戒菸。","synonyms":[],"level":2,"theme":"身體與健康","examples":[{"en":"He tried hard to quit smoking cigarettes.","zh":"他很努力想戒菸。"},{"en":"Smoking cigarettes can seriously harm your lungs and heart.","zh":"抽菸會嚴重傷害你的肺和心臟。"},{"en":"The smell of cigarette smoke filled the small waiting room.","zh":"香菸的煙味瀰漫了那間狹小的候診室。"}]},{"word":"cinema","pos":"n.","phonetic":"[ˈsɪnəmə]","meaning":"電影院；電影","definition":"a theater where films are shown, or the film industry","collocations":["go to the cinema","cinema ticket","local cinema"],"example":"We watched a new movie at the cinema last night.","exampleZh":"我們昨晚在電影院看了一部新電影。","synonyms":["theater","movies"],"level":2,"theme":"藝術與音樂","examples":[{"en":"We watched a new movie at the cinema last night.","zh":"我們昨晚在電影院看了一部新電影。"},{"en":"Let's go to the cinema to watch that new adventure film.","zh":"我們去電影院看那部新的冒險片吧。"},{"en":"The local cinema offers cheaper tickets on Wednesday evenings.","zh":"當地的電影院在週三晚上提供較便宜的票。"}]},{"word":"circle","pos":"n. / v.","phonetic":"[ˈsɝkl̩]","meaning":"圓圈；圈子；環繞","definition":"a round shape or a group of people with shared interests, or to move in a circle","collocations":["draw a circle","a circle of friends","circle the date"],"example":"She drew a circle on the whiteboard.","exampleZh":"她在白板上畫了一個圓圈。","synonyms":["ring","loop"],"level":1,"theme":"性質與描述","examples":[{"en":"She drew a circle on the whiteboard.","zh":"她在白板上畫了一個圓圈。"},{"en":"She has a small circle of friends she trusts completely.","zh":"她有一小群她完全信任的朋友。"},{"en":"Please circle the correct answer with your red pen.","zh":"請用你的紅筆把正確答案圈起來。"}]},{"word":"circulate","pos":"v.","phonetic":"[ˈsɝkjəˌlet]","meaning":"循環；流通；傳播","definition":"to move continuously through a system, or to spread among people","collocations":["circulate blood","circulate a rumor","circulate information"],"example":"Blood circulates through the body carrying oxygen.","exampleZh":"血液在體內循環,輸送氧氣。","synonyms":["spread","distribute"],"level":4,"theme":"科學與數學","examples":[{"en":"Blood circulates through the body carrying oxygen.","zh":"血液在體內循環,輸送氧氣。"},{"en":"The teacher circulated the handouts among all the students.","zh":"老師把講義發給所有學生傳閱。"},{"en":"A strange rumor began to circulate around the whole school.","zh":"一則奇怪的謠言開始在整個學校流傳。"}]},{"word":"circumstance","pos":"n.","phonetic":"[ˈsɝkəmˌstæns]","meaning":"情況；環境；狀況","definition":"a fact or condition connected with an event or situation","collocations":["under no circumstances","difficult circumstances","given the circumstances"],"example":"Under no circumstances should you open that door.","exampleZh":"無論如何你都不該打開那扇門。","synonyms":["situation","condition"],"level":4,"theme":"抽象概念","examples":[{"en":"Under no circumstances should you open that door.","zh":"無論如何你都不該打開那扇門。"},{"en":"Given the current circumstances, we decided to postpone the trip.","zh":"考量到當時的情況，我們決定延後這趟旅行。"},{"en":"She stayed calm and hopeful under very difficult circumstances.","zh":"在非常艱難的處境下，她仍保持冷靜與樂觀。"}]},{"word":"circus","pos":"n.","phonetic":"[ˈsɝkəs]","meaning":"馬戲團","definition":"a traveling company of performers and animals that puts on shows","collocations":["go to the circus","circus performer","circus tent"],"example":"The children were excited to visit the circus.","exampleZh":"孩子們很興奮要去看馬戲團表演。","synonyms":[],"level":1,"theme":"藝術與音樂","examples":[{"en":"The children were excited to visit the circus.","zh":"孩子們很興奮要去看馬戲團表演。"},{"en":"A talented circus performer balanced carefully on a thin rope.","zh":"一位才華洋溢的馬戲團表演者小心地在細繩上保持平衡。"},{"en":"The huge circus tent was set up in the field overnight.","zh":"巨大的馬戲團帳篷一夜之間就在田野裡搭好了。"}]},{"word":"citizen","pos":"n.","phonetic":"[ˈsɪtəzn̩]","meaning":"公民；市民","definition":"a legally recognized member of a country or state","collocations":["senior citizen","law-abiding citizen","become a citizen"],"example":"Every citizen has the right to vote.","exampleZh":"每位公民都有投票的權利。","synonyms":["national","resident"],"level":2,"theme":"社會與文化","examples":[{"en":"Every citizen has the right to vote.","zh":"每位公民都有投票的權利。"},{"en":"Buses offer free rides for senior citizens in our city.","zh":"在我們的城市，公車提供銀髮族免費搭乘。"},{"en":"A good citizen obeys the law and helps the community.","zh":"一個好公民會遵守法律並幫助社區。"}]},{"word":"city","pos":"n.","phonetic":"[ˈsɪtɪ]","meaning":"城市","definition":"a large town","collocations":["big city","city center","city life"],"example":"Taipei is a busy and modern city.","exampleZh":"台北是一座忙碌又現代的城市。","synonyms":["town","metropolis"],"level":1,"theme":"社會與文化","examples":[{"en":"Taipei is a busy and modern city.","zh":"台北是一座忙碌又現代的城市。"},{"en":"Many young people move to the big city to find work.","zh":"許多年輕人搬到大城市尋找工作。"},{"en":"Traffic in the city center is always heavy on weekdays.","zh":"市中心的交通在平日總是很擁擠。"}]},{"word":"civil","pos":"adj.","phonetic":"[ˈsɪvl̩]","meaning":"公民的；文明的；民間的","definition":"relating to ordinary citizens, or polite and courteous","collocations":["civil rights","civil war","civil servant"],"example":"The country suffered a long civil war.","exampleZh":"這個國家經歷了一場漫長的內戰。","synonyms":["polite","public"],"level":3,"theme":"政治與法律","examples":[{"en":"The country suffered a long civil war.","zh":"這個國家經歷了一場漫長的內戰。"},{"en":"My aunt works as a civil servant in the city government.","zh":"我阿姨在市政府擔任公務員。"},{"en":"Many people fought bravely for their basic civil rights.","zh":"許多人勇敢地為他們的基本公民權利奮鬥。"}]},{"word":"civilization","pos":"n.","phonetic":"[ˌsɪvləˈzeʃən]","meaning":"文明","definition":"the stage of human social development that is considered advanced","collocations":["ancient civilization","modern civilization","the rise of civilization"],"example":"Egypt is famous for its ancient civilization.","exampleZh":"埃及以其古老文明聞名。","synonyms":["culture","society"],"level":4,"theme":"社會與文化","examples":[{"en":"Egypt is famous for its ancient civilization.","zh":"埃及以其古老文明聞名。"},{"en":"Students learned about an ancient civilization in history class.","zh":"學生們在歷史課上學到了一個古老的文明。"},{"en":"Rivers played a key role in the rise of civilization.","zh":"河流在文明的興起中扮演了關鍵角色。"}]},{"word":"clap","pos":"v. / n.","phonetic":"[klæp]","meaning":"鼓掌；拍手","definition":"to strike the hands together repeatedly to show approval","collocations":["clap your hands","clap for someone","clap loudly"],"example":"The audience clapped loudly after the performance.","exampleZh":"表演結束後觀眾熱烈鼓掌。","synonyms":["applaud"],"level":1,"theme":"動作與行為","examples":[{"en":"The audience clapped loudly after the performance.","zh":"表演結束後觀眾熱烈鼓掌。"},{"en":"Everyone clapped loudly when the young pianist finished playing.","zh":"當這位年輕鋼琴家演奏完畢時，大家都大聲鼓掌。"},{"en":"Clap your hands if you already know the correct answer.","zh":"如果你已經知道正確答案就拍拍手。"}]},{"word":"clarify","pos":"v.","phonetic":"[ˈklærəˌfaɪ]","meaning":"澄清；闡明","definition":"to make a statement or situation clearer or easier to understand","collocations":["clarify a point","clarify the situation","please clarify"],"example":"Could you clarify what you mean by that?","exampleZh":"你可以澄清一下那句話的意思嗎？","synonyms":["explain","clear up"],"level":4,"theme":"溝通與語言","examples":[{"en":"Could you clarify what you mean by that?","zh":"你可以澄清一下那句話的意思嗎？"},{"en":"Could you clarify this point? I don't quite understand it.","zh":"你可以澄清這一點嗎？我不太明白。"},{"en":"The principal spoke to clarify the situation for worried parents.","zh":"校長出面向擔心的家長們說明澄清情況。"}]},{"word":"clash","pos":"v. / n.","phonetic":"[klæʃ]","meaning":"衝突；碰撞；不協調","definition":"to fight or disagree strongly, or a serious disagreement","collocations":["clash with police","clash of opinions","personality clash"],"example":"Protesters clashed with police outside the building.","exampleZh":"抗議者在大樓外與警方發生衝突。","synonyms":["conflict","fight"],"level":4,"theme":"政治與法律","examples":[{"en":"Protesters clashed with police outside the building.","zh":"抗議者在大樓外與警方發生衝突。"},{"en":"A clash of opinions made the class discussion very lively.","zh":"意見的衝突讓課堂討論變得非常熱烈。"},{"en":"Their different personalities often clash during group projects.","zh":"他們不同的個性在分組報告時常常起衝突。"}]},{"word":"class","pos":"n.","phonetic":"[klæs]","meaning":"班級；課程；階級","definition":"a group of students taught together, or a social division","collocations":["take a class","social class","class schedule"],"example":"Our English class starts at nine o'clock.","exampleZh":"我們的英文課九點開始。","synonyms":["course","lesson"],"level":1,"theme":"教育與學習","examples":[{"en":"Our English class starts at nine o'clock.","zh":"我們的英文課九點開始。"},{"en":"I decided to take a cooking class over the summer.","zh":"我決定暑假去上一堂烹飪課。"},{"en":"Please check the class schedule before choosing your courses.","zh":"選課前請先查看課程時間表。"}]},{"word":"classic","pos":"adj. / n.","phonetic":"[ˈklæsɪk]","meaning":"經典的；經典作品","definition":"judged over time to be of the highest quality, or a work of art of that kind","collocations":["a classic novel","classic style","modern classic"],"example":"This novel has become a classic of modern literature.","exampleZh":"這部小說已成為現代文學的經典之作。","synonyms":["timeless","masterpiece"],"level":3,"theme":"藝術與音樂","examples":[{"en":"This novel has become a classic of modern literature.","zh":"這部小說已成為現代文學的經典之作。"},{"en":"This classic novel is still popular among young readers today.","zh":"這部經典小說至今仍受年輕讀者歡迎。"},{"en":"She prefers a classic style that never goes out of fashion.","zh":"她偏愛永不退流行的經典風格。"}]},{"word":"classify","pos":"v.","phonetic":"[ˈklæsəˌfaɪ]","meaning":"分類；歸類","definition":"to arrange things into groups according to shared qualities","collocations":["classify data","classify animals","classify information"],"example":"Scientists classify animals into different groups.","exampleZh":"科學家將動物分成不同的類別。","synonyms":["categorize","sort"],"level":3,"theme":"科學與數學","examples":[{"en":"Scientists classify animals into different groups.","zh":"科學家將動物分成不同的類別。"},{"en":"Librarians classify books by subject to help readers find them.","zh":"圖書館員依主題將書籍分類，好幫助讀者找書。"},{"en":"We learned how scientists classify animals into different groups.","zh":"我們學到科學家如何將動物分成不同的類別。"}]},{"word":"classroom","pos":"n.","phonetic":"[ˈklæsˌrum]","meaning":"教室","definition":"a room in a school where lessons take place","collocations":["classroom rules","in the classroom","classroom activity"],"example":"The teacher decorated the classroom for the holidays.","exampleZh":"老師為了節日裝飾了教室。","synonyms":[],"level":1,"theme":"教育與學習","examples":[{"en":"The teacher decorated the classroom for the holidays.","zh":"老師為了節日裝飾了教室。"},{"en":"Everyone must follow the classroom rules to keep good order.","zh":"每個人都必須遵守教室規則以維持良好的秩序。"},{"en":"Today's classroom activity was a fun group science experiment.","zh":"今天的課堂活動是一個有趣的小組科學實驗。"}]},{"word":"clay","pos":"n.","phonetic":"[kle]","meaning":"黏土；陶土","definition":"a stiff, sticky earth material used for making pottery and bricks","collocations":["clay pot","mold clay","clay figure"],"example":"The children made small animals out of clay.","exampleZh":"孩子們用黏土做了一些小動物。","synonyms":[],"level":2,"theme":"藝術與音樂","examples":[{"en":"The children made small animals out of clay.","zh":"孩子們用黏土做了一些小動物。"},{"en":"The artist molded the soft clay into a lovely bowl.","zh":"藝術家將柔軟的黏土捏成一個可愛的碗。"},{"en":"We planted the small herbs in a little clay pot.","zh":"我們把小香草種在一個小陶盆裡。"}]},{"word":"clean","pos":"adj. / v.","phonetic":"[klin]","meaning":"乾淨的；清潔","definition":"free from dirt, or to make something free from dirt","collocations":["clean the house","clean water","keep clean"],"example":"Please clean your room before dinner.","exampleZh":"晚餐前請把你的房間打掃乾淨。","synonyms":["tidy","spotless"],"level":1,"theme":"居家與生活","examples":[{"en":"Please clean your room before dinner.","zh":"晚餐前請把你的房間打掃乾淨。"},{"en":"Many people around the world still lack clean drinking water.","zh":"世界上仍有許多人缺乏乾淨的飲用水。"},{"en":"We spent the whole morning cleaning the house together.","zh":"我們一起花了一整個早上打掃房子。"}]},{"word":"clear","pos":"adj. / v.","phonetic":"[klɪr]","meaning":"清楚的；晴朗的；清除","definition":"easy to see, hear, or understand, or to remove obstacles","collocations":["clear sky","make it clear","clear the table"],"example":"The instructions were very clear and easy to follow.","exampleZh":"這些說明非常清楚且容易遵循。","synonyms":["obvious","plain"],"level":1,"theme":"性質與描述","examples":[{"en":"The instructions were very clear and easy to follow.","zh":"這些說明非常清楚且容易遵循。"},{"en":"After dinner, the children helped clear the table quickly.","zh":"晚餐後，孩子們幫忙很快地收拾了餐桌。"},{"en":"We enjoyed the clear sky and bright stars while camping.","zh":"露營時我們享受著晴朗的天空和明亮的星星。"}]},{"word":"clerk","pos":"n.","phonetic":"[klɝk]","meaning":"職員；辦事員；店員","definition":"a person who works in an office or shop keeping records or serving customers","collocations":["office clerk","sales clerk","bank clerk"],"example":"The clerk helped me find the right form.","exampleZh":"那位職員幫我找到了正確的表格。","synonyms":["assistant","cashier"],"level":2,"theme":"工作與職業","examples":[{"en":"The clerk helped me find the right form.","zh":"那位職員幫我找到了正確的表格。"},{"en":"The sales clerk kindly showed me where the shoes were.","zh":"店員親切地告訴我鞋子放在哪裡。"},{"en":"The bank clerk helped my grandfather open a new account.","zh":"銀行行員幫我爺爺開了一個新帳戶。"}]},{"word":"clever","pos":"adj.","phonetic":"[ˈklɛvɚ]","meaning":"聰明的；機靈的","definition":"quick to understand, learn, and devise or apply ideas","collocations":["clever idea","clever student","clever trick"],"example":"That was a clever solution to a difficult problem.","exampleZh":"那是解決難題的聰明方法。","synonyms":["smart","intelligent"],"level":1,"theme":"性質與描述","examples":[{"en":"That was a clever solution to a difficult problem.","zh":"那是解決難題的聰明方法。"},{"en":"She came up with a clever idea to save the club money.","zh":"她想出了一個能為社團省錢的聰明點子。"},{"en":"The magician amazed us all with a clever card trick.","zh":"魔術師用一個巧妙的紙牌把戲讓我們大為驚嘆。"}]},{"word":"click","pos":"v. / n.","phonetic":"[klɪk]","meaning":"點擊；喀嗒聲","definition":"to press a button on a mouse or make a short sharp sound","collocations":["click the mouse","click a link","hear a click"],"example":"Click the icon to open the file.","exampleZh":"點擊圖示以開啟檔案。","synonyms":[],"level":2,"theme":"科技與媒體","examples":[{"en":"Click the icon to open the file.","zh":"點擊圖示以開啟檔案。"},{"en":"Click the link below to sign up for the workshop.","zh":"點擊下方的連結來報名這場工作坊。"},{"en":"I heard a soft click as the door locked behind me.","zh":"當門在我身後鎖上時，我聽到輕輕的一聲喀嗒。"}]},{"word":"client","pos":"n.","phonetic":"[ˈklaɪənt]","meaning":"客戶；委託人","definition":"a person or organization using the services of a professional","collocations":["important client","client meeting","serve a client"],"example":"The lawyer met with a new client this morning.","exampleZh":"律師今天早上和一位新客戶會面。","synonyms":["customer"],"level":3,"theme":"商業與金錢","examples":[{"en":"The lawyer met with a new client this morning.","zh":"律師今天早上和一位新客戶會面。"},{"en":"The designer listened carefully to what the client really wanted.","zh":"設計師仔細聆聽客戶真正想要的東西。"},{"en":"My mother has a meeting with an important client tomorrow.","zh":"我媽媽明天要和一位重要的客戶開會。"}]},{"word":"cliff","pos":"n.","phonetic":"[klɪf]","meaning":"懸崖；峭壁","definition":"a steep rock face, especially at the edge of the sea","collocations":["steep cliff","cliff edge","fall off a cliff"],"example":"They watched the sunset from the top of the cliff.","exampleZh":"他們在懸崖頂上欣賞日落。","synonyms":["bluff","precipice"],"level":2,"theme":"自然與環境","examples":[{"en":"They watched the sunset from the top of the cliff.","zh":"他們在懸崖頂上欣賞日落。"},{"en":"Please stay away from the steep cliff near the path.","zh":"請遠離步道旁那道陡峭的懸崖。"},{"en":"Seabirds built their nests along the rocky cliff edge.","zh":"海鳥沿著岩石懸崖的邊緣築巢。"}]},{"word":"climate","pos":"n.","phonetic":"[ˈklaɪmɪt]","meaning":"氣候；風氣","definition":"the weather conditions of an area over a long period, or a general atmosphere","collocations":["climate change","tropical climate","political climate"],"example":"Climate change is affecting weather patterns worldwide.","exampleZh":"氣候變遷正影響著全球的天氣模式。","synonyms":["weather"],"level":3,"theme":"自然與環境","examples":[{"en":"Climate change is affecting weather patterns worldwide.","zh":"氣候變遷正影響著全球的天氣模式。"},{"en":"Taiwan's warm, tropical climate is perfect for growing fruit.","zh":"台灣溫暖的熱帶氣候很適合種植水果。"},{"en":"Scientists warn that climate change threatens many animal species.","zh":"科學家警告，氣候變遷威脅著許多動物物種。"}]},{"word":"climb","pos":"v.","phonetic":"[klaɪm]","meaning":"攀爬；上升","definition":"to go up using hands and feet, or to rise","collocations":["climb a mountain","climb the stairs","climb a tree"],"example":"They climbed the mountain before sunrise.","exampleZh":"他們在日出前爬上了那座山。","synonyms":["ascend","scale"],"level":1,"theme":"運動與休閒","examples":[{"en":"They climbed the mountain before sunrise.","zh":"他們在日出前爬上了那座山。"},{"en":"The boys climbed the tree to get a better view.","zh":"男孩們爬上樹以看得更清楚。"},{"en":"We climbed the stairs to the rooftop to watch the fireworks.","zh":"我們爬樓梯到屋頂上觀賞煙火。"}]},{"word":"cling","pos":"v.","phonetic":"[klɪŋ]","meaning":"緊抓；依附","definition":"to hold on tightly to something or someone","collocations":["cling to hope","cling to a rope","cling together"],"example":"The child clung to her mother's hand.","exampleZh":"小孩緊緊抓住媽媽的手。","synonyms":["hold on","grip"],"level":4,"theme":"動作與行為","examples":[{"en":"The child clung to her mother's hand.","zh":"小孩緊緊抓住媽媽的手。"},{"en":"The frightened kitten clung to the branch during the storm.","zh":"受驚的小貓在暴風雨中緊緊抓著樹枝。"},{"en":"Even in hard times, she clung to hope for the future.","zh":"即使在艱難的時刻，她仍緊抓著對未來的希望。"}]},{"word":"clinic","pos":"n.","phonetic":"[ˈklɪnɪk]","meaning":"診所","definition":"a place where people get medical treatment or advice","collocations":["dental clinic","visit a clinic","clinic hours"],"example":"She went to the clinic to get her flu shot.","exampleZh":"她去診所打流感疫苗。","synonyms":["surgery"],"level":2,"theme":"身體與健康","examples":[{"en":"She went to the clinic to get her flu shot.","zh":"她去診所打流感疫苗。"},{"en":"I have an appointment at the dental clinic this afternoon.","zh":"我今天下午在牙科診所有預約。"},{"en":"The clinic hours are printed clearly on the front door.","zh":"診所的看診時間清楚地印在前門上。"}]},{"word":"clip","pos":"v. / n.","phonetic":"[klɪp]","meaning":"夾住；剪輯片段","definition":"to attach with a small fastener, or a short extract from a film","collocations":["paper clip","clip your nails","video clip"],"example":"He clipped the pages together with a paper clip.","exampleZh":"他用迴紋針把幾頁紙夾在一起。","synonyms":["fasten","trim"],"level":2,"theme":"科技與媒體","examples":[{"en":"He clipped the pages together with a paper clip.","zh":"他用迴紋針把幾頁紙夾在一起。"},{"en":"She shared a funny video clip with her classmates online.","zh":"她在網路上和同學分享了一段有趣的影片片段。"},{"en":"Remember to clip your nails before the cooking class.","zh":"記得在烹飪課前把指甲剪好。"}]},{"word":"clock","pos":"n.","phonetic":"[klɑk]","meaning":"時鐘","definition":"a device that shows the time","collocations":["alarm clock","around the clock","clock tower"],"example":"The clock on the wall shows three o'clock.","exampleZh":"牆上的時鐘顯示三點鐘。","synonyms":["timepiece"],"level":1,"theme":"時間與空間","examples":[{"en":"The clock on the wall shows three o'clock.","zh":"牆上的時鐘顯示三點鐘。"},{"en":"My alarm clock rings at six every school morning.","zh":"上學日每天早上六點我的鬧鐘就會響。"},{"en":"The old clock tower stands proudly in the town square.","zh":"那座古老的鐘塔驕傲地矗立在市鎮廣場上。"}]},{"word":"clone","pos":"n. / v.","phonetic":"[klon]","meaning":"複製；複製品","definition":"an organism produced from another that is genetically identical, or to produce one","collocations":["clone a sheep","genetic clone","clone technology"],"example":"Scientists successfully cloned a sheep named Dolly.","exampleZh":"科學家成功複製出一隻名叫桃莉的羊。","synonyms":["copy","duplicate"],"level":5,"theme":"科學與數學","examples":[{"en":"Scientists successfully cloned a sheep named Dolly.","zh":"科學家成功複製出一隻名叫桃莉的羊。"},{"en":"Some scientists worry about the risks of clone technology.","zh":"有些科學家擔心複製技術帶來的風險。"},{"en":"A cloned animal is simply a genetic copy of the original.","zh":"被複製的動物只是原始動物的基因複製品。"}]},{"word":"close","pos":"adj. / v.","phonetic":"[kloz]","meaning":"接近的；親密的；關閉","definition":"near in space or relationship, or to shut something","collocations":["close friend","close the door","close call"],"example":"We are very close friends since childhood.","exampleZh":"我們從小就是非常親密的朋友。","synonyms":["near","shut"],"level":1,"theme":"人物與家庭","examples":[{"en":"We are very close friends since childhood.","zh":"我們從小就是非常親密的朋友。"},{"en":"Please close the window; the wind outside is too strong.","zh":"請把窗戶關上，外面的風太大了。"},{"en":"That was a close call; the ball almost hit me.","zh":"好險，那顆球差點打到我。"}]},{"word":"closet","pos":"n.","phonetic":"[ˈklɑzɪt]","meaning":"衣櫥；壁櫥","definition":"a small enclosed space used for storing things, especially clothes","collocations":["walk-in closet","clean the closet","closet door"],"example":"She hung her coat in the closet.","exampleZh":"她把外套掛在衣櫥裡。","synonyms":["wardrobe","cupboard"],"level":2,"theme":"居家與生活","examples":[{"en":"She hung her coat in the closet.","zh":"她把外套掛在衣櫥裡。"},{"en":"We spent the whole afternoon cleaning out the messy closet.","zh":"我們花了一整個下午整理那個凌亂的衣櫥。"},{"en":"Her bright new bedroom even has a large walk-in closet.","zh":"她明亮的新臥室甚至有一個大型的更衣間。"}]},{"word":"cloth","pos":"n.","phonetic":"[klɔθ]","meaning":"布；布料","definition":"woven or felted fabric","collocations":["a piece of cloth","cotton cloth","wipe with a cloth"],"example":"She wiped the table with a clean cloth.","exampleZh":"她用一塊乾淨的布擦拭桌子。","synonyms":["fabric","material"],"level":2,"theme":"服裝與外表","examples":[{"en":"She wiped the table with a clean cloth.","zh":"她用一塊乾淨的布擦拭桌子。"},{"en":"She used a soft cotton cloth to polish the mirror.","zh":"她用一塊柔軟的棉布把鏡子擦亮。"},{"en":"Wipe the spilled juice with a damp cloth right away.","zh":"馬上用濕布把灑出來的果汁擦掉。"}]},{"word":"clothes","pos":"n.","phonetic":"[kloz]","meaning":"衣服","definition":"items worn to cover the body","collocations":["wash clothes","new clothes","change clothes"],"example":"He needs to buy some new clothes for winter.","exampleZh":"他需要買一些新衣服過冬。","synonyms":["clothing","garments"],"level":1,"theme":"服裝與外表","examples":[{"en":"He needs to buy some new clothes for winter.","zh":"他需要買一些新衣服過冬。"},{"en":"You should change your wet clothes before you catch cold.","zh":"你應該在感冒前換掉濕衣服。"},{"en":"My mother washes all our clothes every Saturday morning.","zh":"我媽媽每週六早上洗我們所有的衣服。"}]},{"word":"clothing","pos":"n.","phonetic":"[ˈkloðɪŋ]","meaning":"衣物；服裝","definition":"clothes considered collectively","collocations":["warm clothing","clothing store","protective clothing"],"example":"The store sells clothing for the whole family.","exampleZh":"這家店販賣全家人的服飾。","synonyms":["clothes","garments"],"level":2,"theme":"服裝與外表","examples":[{"en":"The store sells clothing for the whole family.","zh":"這家店販賣全家人的服飾。"},{"en":"Bring warm clothing because the mountain gets cold at night.","zh":"帶些保暖的衣物，因為山上晚上會變冷。"},{"en":"Workers must wear protective clothing inside the busy factory.","zh":"工人在繁忙的工廠裡必須穿著防護衣物。"}]},{"word":"cloud","pos":"n.","phonetic":"[klaʊd]","meaning":"雲；雲朵","definition":"a visible mass of condensed water vapor floating in the sky","collocations":["dark cloud","cloud cover","rain cloud"],"example":"Dark clouds gathered before the storm.","exampleZh":"暴風雨來臨前烏雲密布。","synonyms":[],"level":1,"theme":"天氣與季節","examples":[{"en":"Dark clouds gathered before the storm.","zh":"暴風雨來臨前烏雲密布。"},{"en":"Heavy rain clouds rolled in just before the game started.","zh":"厚重的雨雲在比賽開始前湧了進來。"},{"en":"The thick cloud cover hid the moon all night long.","zh":"厚厚的雲層整晚遮住了月亮。"}]},{"word":"clown","pos":"n.","phonetic":"[klaʊn]","meaning":"小丑","definition":"a performer who wears funny clothes and makeup to make people laugh","collocations":["circus clown","act like a clown","clown around"],"example":"The clown made all the children laugh at the party.","exampleZh":"那位小丑逗得派對上所有孩子都笑了。","synonyms":["jester"],"level":2,"theme":"藝術與音樂","examples":[{"en":"The clown made all the children laugh at the party.","zh":"那位小丑逗得派對上所有孩子都笑了。"},{"en":"The circus clown juggled balls while riding a tiny bike.","zh":"馬戲團的小丑一邊騎著小腳踏車一邊拋接球。"},{"en":"Stop clowning around and finish your homework right now.","zh":"別再嬉鬧了，現在馬上把功課寫完。"}]},{"word":"club","pos":"n.","phonetic":"[klʌb]","meaning":"社團；俱樂部；棍棒","definition":"a group of people with a shared interest, or a heavy stick","collocations":["join a club","book club","golf club"],"example":"She joined the school's photography club.","exampleZh":"她加入了學校的攝影社團。","synonyms":["society","association"],"level":1,"theme":"社會與文化","examples":[{"en":"She joined the school's photography club.","zh":"她加入了學校的攝影社團。"},{"en":"Every month our book club meets to discuss a new story.","zh":"我們的讀書會每個月聚會討論一個新的故事。"},{"en":"He decided to join the school's basketball club this term.","zh":"這學期他決定加入學校的籃球社。"}]},{"word":"clue","pos":"n.","phonetic":"[klu]","meaning":"線索","definition":"a piece of information that helps solve a problem or mystery","collocations":["give a clue","find a clue","no clue"],"example":"The detective found an important clue at the scene.","exampleZh":"偵探在現場找到一個重要線索。","synonyms":["hint","lead"],"level":2,"theme":"抽象概念","examples":[{"en":"The detective found an important clue at the scene.","zh":"偵探在現場找到一個重要線索。"},{"en":"The teacher gave us a small clue to solve the puzzle.","zh":"老師給了我們一個小線索來解開這個謎題。"},{"en":"Honestly, I have no clue where I left my keys.","zh":"老實說，我完全不知道我把鑰匙放在哪裡。"}]},{"word":"clumsy","pos":"adj.","phonetic":"[ˈklʌmzɪ]","meaning":"笨拙的；不靈巧的","definition":"awkward in movement or in handling things","collocations":["clumsy movement","clumsy attempt","feel clumsy"],"example":"He is so clumsy that he keeps dropping things.","exampleZh":"他非常笨拙,總是把東西掉在地上。","synonyms":["awkward","careless"],"level":3,"theme":"性質與描述","examples":[{"en":"He is so clumsy that he keeps dropping things.","zh":"他非常笨拙,總是把東西掉在地上。"},{"en":"After breaking two cups, he felt clumsy and quite embarrassed.","zh":"打破兩個杯子後，他覺得自己笨手笨腳又相當尷尬。"},{"en":"Her first clumsy attempt at baking ended in a real mess.","zh":"她第一次笨拙的烘焙嘗試以一團混亂收場。"}]},{"word":"cluster","pos":"n. / v.","phonetic":"[ˈklʌstɚ]","meaning":"群；串；聚集","definition":"a group of similar things or people close together","collocations":["cluster of stars","cluster together","a cluster of houses"],"example":"A cluster of stars shone brightly in the night sky.","exampleZh":"一群星星在夜空中閃耀。","synonyms":["group","bunch"],"level":4,"theme":"自然與環境","examples":[{"en":"A cluster of stars shone brightly in the night sky.","zh":"一群星星在夜空中閃耀。"},{"en":"A small cluster of houses sat quietly beside the river.","zh":"一小群房屋靜靜地坐落在河邊。"},{"en":"The nervous students clustered together near the exam room.","zh":"緊張的學生們聚集在考場附近。"}]},{"word":"clutch","pos":"v.","phonetic":"[klʌtʃ]","meaning":"緊握；抓住","definition":"to grasp something tightly","collocations":["clutch a bag","clutch at straws","clutch someone's hand"],"example":"She clutched her bag tightly as she walked home.","exampleZh":"她走回家時緊緊抓著她的包包。","synonyms":["grip","grasp"],"level":4,"theme":"動作與行為","examples":[{"en":"She clutched her bag tightly as she walked home.","zh":"她走回家時緊緊抓著她的包包。"},{"en":"The little girl clutched her mother's hand in the crowd.","zh":"小女孩在人群中緊緊抓著媽媽的手。"},{"en":"He clutched the letter tightly, too afraid to open it.","zh":"他緊緊抓著那封信，害怕得不敢打開。"}]},{"word":"coach","pos":"n. / v.","phonetic":"[kotʃ]","meaning":"教練；長途巴士；指導","definition":"a person who trains athletes or a team, or to train someone","collocations":["basketball coach","coach a team","take a coach"],"example":"The coach trained the team hard for the finals.","exampleZh":"教練為了決賽嚴格訓練球隊。","synonyms":["trainer","instructor"],"level":2,"theme":"運動與休閒","examples":[{"en":"The coach trained the team hard for the finals.","zh":"教練為了決賽嚴格訓練球隊。"},{"en":"Our basketball coach teaches us teamwork as well as skills.","zh":"我們的籃球教練除了技巧，也教我們團隊合作。"},{"en":"We took a coach to the coast for our field trip.","zh":"我們搭乘長途巴士到海邊校外教學。"}]},{"word":"coal","pos":"n.","phonetic":"[kol]","meaning":"煤炭","definition":"a hard black mineral used as fuel","collocations":["coal mine","burn coal","coal power plant"],"example":"The factory used to run on coal.","exampleZh":"這家工廠以前是用煤炭運轉的。","synonyms":[],"level":2,"theme":"自然與環境","examples":[{"en":"The factory used to run on coal.","zh":"這家工廠以前是用煤炭運轉的。"},{"en":"Many years ago, most trains ran by burning coal.","zh":"許多年前，大多數火車都是靠燃燒煤炭運行的。"},{"en":"Workers in the coal mine faced many serious dangers daily.","zh":"煤礦裡的工人每天面臨許多嚴重的危險。"}]},{"word":"coast","pos":"n.","phonetic":"[kost]","meaning":"海岸","definition":"the land next to or close to the sea","collocations":["west coast","along the coast","coast guard"],"example":"They spent the summer on the east coast.","exampleZh":"他們在東岸度過了整個夏天。","synonyms":["shore","seaside"],"level":2,"theme":"自然與環境","examples":[{"en":"They spent the summer on the east coast.","zh":"他們在東岸度過了整個夏天。"},{"en":"We drove slowly along the coast to enjoy the ocean view.","zh":"我們沿著海岸慢慢地開車，欣賞海景。"},{"en":"The coast guard rescued the fishermen during the fierce storm.","zh":"海岸巡防隊在猛烈的暴風雨中救起了那些漁民。"}]},{"word":"coat","pos":"n.","phonetic":"[kot]","meaning":"外套；大衣","definition":"an outer garment worn for warmth or protection","collocations":["wear a coat","winter coat","coat of paint"],"example":"Put on your coat, it's cold outside.","exampleZh":"穿上外套,外面很冷。","synonyms":["jacket"],"level":1,"theme":"服裝與外表","examples":[{"en":"Put on your coat, it's cold outside.","zh":"穿上外套,外面很冷。"},{"en":"She bought a warm winter coat before the cold season.","zh":"她在寒冷季節來臨前買了一件溫暖的冬季大衣。"},{"en":"The old wooden fence needs a fresh coat of paint.","zh":"那道舊的木頭圍籬需要重新上一層油漆。"}]},{"word":"cocoa","pos":"n.","phonetic":"[ˈkoko]","meaning":"可可粉；可可飲料","definition":"a powder made from crushed cacao seeds, or a hot drink made from it","collocations":["hot cocoa","cocoa powder","cup of cocoa"],"example":"She made a cup of hot cocoa on a cold night.","exampleZh":"她在寒冷的夜晚泡了一杯熱可可。","synonyms":[],"level":2,"theme":"食物與烹飪","examples":[{"en":"She made a cup of hot cocoa on a cold night.","zh":"她在寒冷的夜晚泡了一杯熱可可。"},{"en":"We warmed up with a cup of hot cocoa after skiing.","zh":"滑雪後我們喝了一杯熱可可暖暖身子。"},{"en":"Add two spoons of cocoa powder to make the cake richer.","zh":"加兩匙可可粉能讓蛋糕更香濃。"}]},{"word":"code","pos":"n.","phonetic":"[kod]","meaning":"代碼；密碼；規範","definition":"a system of words, letters, or symbols used to represent others, or a set of rules","collocations":["dress code","secret code","write code"],"example":"The programmer wrote the code for a new app.","exampleZh":"這位程式設計師撰寫了一款新應用程式的程式碼。","synonyms":["cipher","rules"],"level":3,"theme":"科技與媒體","examples":[{"en":"The programmer wrote the code for a new app.","zh":"這位程式設計師撰寫了一款新應用程式的程式碼。"},{"en":"Our school has a strict dress code for formal events.","zh":"我們學校在正式活動有嚴格的服裝規定。"},{"en":"The two friends invented a secret code to pass notes.","zh":"這兩個朋友發明了一套暗號來傳紙條。"}]},{"word":"coffee","pos":"n.","phonetic":"[ˈkɔfɪ]","meaning":"咖啡","definition":"a hot drink made from roasted coffee beans","collocations":["a cup of coffee","black coffee","coffee shop"],"example":"He drinks a cup of coffee every morning.","exampleZh":"他每天早上都喝一杯咖啡。","synonyms":[],"level":1,"theme":"食物與烹飪","examples":[{"en":"He drinks a cup of coffee every morning.","zh":"他每天早上都喝一杯咖啡。"},{"en":"We often meet at the coffee shop to study together.","zh":"我們常在咖啡店碰面一起讀書。"},{"en":"My father enjoys a cup of black coffee after lunch.","zh":"我爸爸喜歡在午餐後喝一杯黑咖啡。"}]},{"word":"coin","pos":"n.","phonetic":"[kɔɪn]","meaning":"硬幣","definition":"a flat, round piece of metal used as money","collocations":["flip a coin","gold coin","coin collection"],"example":"He found an old coin buried in the garden.","exampleZh":"他在花園裡發現一枚古老的硬幣。","synonyms":[],"level":1,"theme":"商業與金錢","examples":[{"en":"He found an old coin buried in the garden.","zh":"他在花園裡發現一枚古老的硬幣。"},{"en":"Let's flip a coin to decide who goes first.","zh":"我們擲硬幣來決定誰先開始吧。"},{"en":"He proudly showed me his growing collection of old coins.","zh":"他驕傲地向我展示他日益增多的舊硬幣收藏。"}]},{"word":"coincidence","pos":"n.","phonetic":"[koˈɪnsədəns]","meaning":"巧合","definition":"a remarkable occurrence of events happening at the same time by chance","collocations":["by coincidence","pure coincidence","strange coincidence"],"example":"Meeting you here is quite a coincidence.","exampleZh":"在這裡遇見你真是巧合。","synonyms":["chance"],"level":5,"theme":"抽象概念","examples":[{"en":"Meeting you here is quite a coincidence.","zh":"在這裡遇見你真是巧合。"},{"en":"By an odd coincidence, we wore the exact same shirt.","zh":"很巧的是，我們穿了一模一樣的襯衫。"},{"en":"It was pure coincidence that we sat next to each other.","zh":"我們坐在彼此旁邊純粹是巧合。"}]},{"word":"cold","pos":"adj. / n.","phonetic":"[kold]","meaning":"寒冷的；感冒","definition":"having a low temperature, or an illness affecting the nose and throat","collocations":["catch a cold","cold weather","cold water"],"example":"She caught a cold after standing in the rain.","exampleZh":"她淋雨後感冒了。","synonyms":["chilly","frigid"],"level":1,"theme":"天氣與季節","examples":[{"en":"She caught a cold after standing in the rain.","zh":"她淋雨後感冒了。"},{"en":"Wear a scarf so you don't catch a cold outside.","zh":"圍上圍巾，這樣在外面才不會感冒。"},{"en":"After the long run, she drank a glass of cold water.","zh":"跑完長跑後，她喝了一杯冰水。"}]},{"word":"collapse","pos":"v. / n.","phonetic":"[kəˈlæps]","meaning":"倒塌；崩潰","definition":"to fall down or break apart suddenly, or such an event","collocations":["building collapse","economic collapse","collapse from exhaustion"],"example":"The old bridge collapsed during the storm.","exampleZh":"那座老橋在暴風雨中倒塌了。","synonyms":["fall down","break down"],"level":4,"theme":"動作與行為","examples":[{"en":"The old bridge collapsed during the storm.","zh":"那座老橋在暴風雨中倒塌了。"},{"en":"The tired runner nearly collapsed from exhaustion after the race.","zh":"疲憊的跑者在比賽後幾乎因精疲力竭而昏倒。"},{"en":"The heavy snow finally caused the old roof to collapse.","zh":"厚重的積雪最終使那個舊屋頂倒塌了。"}]},{"word":"collar","pos":"n.","phonetic":"[ˈkɑlɚ]","meaning":"衣領；項圈","definition":"the part of a shirt or coat around the neck, or a band for an animal's neck","collocations":["shirt collar","dog collar","turn up the collar"],"example":"He fixed his collar before the interview.","exampleZh":"他在面試前整理了一下衣領。","synonyms":[],"level":2,"theme":"服裝與外表","examples":[{"en":"He fixed his collar before the interview.","zh":"他在面試前整理了一下衣領。"},{"en":"He turned up his collar to block the cold wind.","zh":"他豎起衣領來擋住冷風。"},{"en":"We put a new collar with a bell on our dog.","zh":"我們給我們的狗戴上一個附有鈴鐺的新項圈。"}]},{"word":"colleague","pos":"n.","phonetic":"[ˈkɑlig]","meaning":"同事","definition":"a person one works with, especially in a profession","collocations":["close colleague","work colleague","former colleague"],"example":"She went to lunch with her colleagues.","exampleZh":"她和同事一起去吃午餐。","synonyms":["coworker"],"level":3,"theme":"工作與職業","examples":[{"en":"She went to lunch with her colleagues.","zh":"她和同事一起去吃午餐。"},{"en":"My mother often invites her colleagues home for dinner.","zh":"我媽媽常邀請她的同事到家裡吃晚餐。"},{"en":"He met a former colleague by chance at the airport.","zh":"他在機場偶然遇見了一位以前的同事。"}]},{"word":"collect","pos":"v.","phonetic":"[kəˈlɛkt]","meaning":"收集；收取","definition":"to gather things together, or to receive money owed","collocations":["collect stamps","collect data","collect money"],"example":"He collects stamps from different countries.","exampleZh":"他收集來自不同國家的郵票。","synonyms":["gather","accumulate"],"level":2,"theme":"動作與行為","examples":[{"en":"He collects stamps from different countries.","zh":"他收集來自不同國家的郵票。"},{"en":"The scientists collected data from the river for their study.","zh":"科學家們從河裡收集資料以進行研究。"},{"en":"Our class collected money to help the flood victims.","zh":"我們班募集了款項來幫助水災的受災戶。"}]},{"word":"collection","pos":"n.","phonetic":"[kəˈlɛkʃən]","meaning":"收藏品；收集","definition":"a group of objects gathered together, or the act of collecting","collocations":["art collection","garbage collection","a collection of poems"],"example":"The museum has a huge collection of ancient coins.","exampleZh":"這間博物館有大量的古代錢幣收藏。","synonyms":["accumulation"],"level":3,"theme":"藝術與音樂","examples":[{"en":"The museum has a huge collection of ancient coins.","zh":"這間博物館有大量的古代錢幣收藏。"},{"en":"She published a beautiful collection of poems last spring.","zh":"去年春天她出版了一本優美的詩集。"},{"en":"Garbage collection in our neighborhood happens every Tuesday and Friday.","zh":"我們社區的垃圾收集在每週二和週五進行。"}]},{"word":"college","pos":"n.","phonetic":"[ˈkɑlɪdʒ]","meaning":"學院；大學","definition":"an institution of higher education","collocations":["go to college","community college","college student"],"example":"She is studying business at college.","exampleZh":"她正在大學裡念商業。","synonyms":["university"],"level":2,"theme":"教育與學習","examples":[{"en":"She is studying business at college.","zh":"她正在大學裡念商業。"},{"en":"My older sister will go to college in the fall.","zh":"我姐姐今年秋天要上大學。"},{"en":"Many college students work part-time to pay for their studies.","zh":"許多大學生打工來支付他們的學費。"}]},{"word":"collide","pos":"v.","phonetic":"[kəˈlaɪd]","meaning":"碰撞；相撞","definition":"to hit something violently while moving","collocations":["collide with a car","planets collide","collide head-on"],"example":"The two cars collided at the intersection.","exampleZh":"這兩輛車在十字路口相撞。","synonyms":["crash","hit"],"level":4,"theme":"交通與旅行","examples":[{"en":"The two cars collided at the intersection.","zh":"這兩輛車在十字路口相撞。"},{"en":"The cyclist almost collided with a car at the corner.","zh":"那名騎腳踏車的人在轉角處差點撞上一輛車。"},{"en":"Two players collided head-on while chasing the same ball.","zh":"兩名球員在追同一顆球時迎面相撞。"}]},{"word":"colony","pos":"n.","phonetic":"[ˈkɑlənɪ]","meaning":"殖民地；群落","definition":"a country or area controlled by another country, or a group of the same organism living together","collocations":["former colony","ant colony","establish a colony"],"example":"Taiwan was once a Japanese colony.","exampleZh":"台灣曾經是日本的殖民地。","synonyms":["settlement"],"level":4,"theme":"政治與法律","examples":[{"en":"Taiwan was once a Japanese colony.","zh":"台灣曾經是日本的殖民地。"},{"en":"We watched a busy ant colony carry food underground.","zh":"我們看著忙碌的蟻群把食物搬到地底下。"},{"en":"The country was once a former colony of a European power.","zh":"這個國家曾經是某個歐洲強權的殖民地。"}]},{"word":"color","pos":"n.","phonetic":"[ˈkʌlɚ]","meaning":"顏色","definition":"the property of an object producing different sensations by reflecting light","collocations":["bright color","favorite color","color scheme"],"example":"What color do you want to paint the wall?","exampleZh":"你想把牆漆成什麼顏色？","synonyms":["hue"],"level":1,"theme":"性質與描述","examples":[{"en":"What color do you want to paint the wall?","zh":"你想把牆漆成什麼顏色？"},{"en":"Blue has always been my favorite color since childhood.","zh":"藍色從小就一直是我最喜歡的顏色。"},{"en":"The artist used bright colors to paint the summer garden.","zh":"藝術家用鮮豔的色彩畫出夏日花園。"}]},{"word":"column","pos":"n.","phonetic":"[ˈkɑləm]","meaning":"專欄；圓柱；欄","definition":"a vertical division of a page, a supporting pillar, or a regular newspaper feature","collocations":["newspaper column","stone column","write a column"],"example":"She writes a weekly column for the newspaper.","exampleZh":"她每週為報紙撰寫一個專欄。","synonyms":["pillar"],"level":4,"theme":"科技與媒體","examples":[{"en":"She writes a weekly column for the newspaper.","zh":"她每週為報紙撰寫一個專欄。"},{"en":"Tall stone columns supported the roof of the ancient temple.","zh":"高大的石柱支撐著這座古老神廟的屋頂。"},{"en":"He writes a weekly column about healthy eating habits.","zh":"他每週寫一個關於健康飲食習慣的專欄。"}]},{"word":"comb","pos":"n. / v.","phonetic":"[kom]","meaning":"梳子；梳理","definition":"a toothed device for arranging hair, or to use it","collocations":["comb your hair","fine-tooth comb","comb through"],"example":"She combed her hair before school.","exampleZh":"她上學前梳了頭髮。","synonyms":[],"level":2,"theme":"服裝與外表","examples":[{"en":"She combed her hair before school.","zh":"她上學前梳了頭髮。"},{"en":"Please comb your hair neatly before the class photo.","zh":"拍班級照前，請把頭髮梳整齊。"},{"en":"The detectives combed through every room looking for clues.","zh":"偵探們仔細搜查每個房間尋找線索。"}]},{"word":"combine","pos":"v.","phonetic":"[kəmˈbaɪn]","meaning":"結合；混合","definition":"to join or merge two or more things together","collocations":["combine ingredients","combine forces","combine work and study"],"example":"Combine the flour and sugar in a bowl.","exampleZh":"把麵粉和糖放在碗裡混合。","synonyms":["merge","mix"],"level":3,"theme":"動作與行為","examples":[{"en":"Combine the flour and sugar in a bowl.","zh":"把麵粉和糖放在碗裡混合。"},{"en":"Combine the eggs and flour before slowly adding the milk.","zh":"在慢慢加入牛奶之前，先把蛋和麵粉混合。"},{"en":"She learned to combine work and study without much stress.","zh":"她學會了在沒有太大壓力下兼顧工作與學業。"}]},{"word":"comedy","pos":"n.","phonetic":"[ˈkɑmədɪ]","meaning":"喜劇","definition":"a movie, play, or program intended to be humorous","collocations":["romantic comedy","stand-up comedy","comedy show"],"example":"We watched a comedy last weekend and laughed a lot.","exampleZh":"我們上週末看了一部喜劇,笑得很開心。","synonyms":[],"level":2,"theme":"藝術與音樂","examples":[{"en":"We watched a comedy last weekend and laughed a lot.","zh":"我們上週末看了一部喜劇,笑得很開心。"},{"en":"We laughed all night at the funny stand-up comedy show.","zh":"在那場好笑的單口喜劇秀上，我們笑了一整晚。"},{"en":"She prefers a light romantic comedy to a scary film.","zh":"比起恐怖片，她更喜歡輕鬆的浪漫喜劇。"}]},{"word":"comfort","pos":"n. / v.","phonetic":"[ˈkʌmfɚt]","meaning":"舒適；安慰","definition":"a state of physical ease, or to ease someone's grief","collocations":["comfort food","offer comfort","comfort a friend"],"example":"She comforted her friend after the bad news.","exampleZh":"聽到壞消息後,她安慰了朋友。","synonyms":["console","ease"],"level":2,"theme":"情緒與感受","examples":[{"en":"She comforted her friend after the bad news.","zh":"聽到壞消息後,她安慰了朋友。"},{"en":"A warm bowl of soup is my favorite comfort food.","zh":"一碗溫熱的湯是我最喜歡的療癒食物。"},{"en":"She gently comforted her little brother after the bad nightmare.","zh":"弟弟做完可怕的惡夢後，她溫柔地安慰他。"}]},{"word":"comfortable","pos":"adj.","phonetic":"[ˈkʌmfɚtəbl̩]","meaning":"舒適的；自在的","definition":"providing physical ease, or feeling relaxed and at ease","collocations":["comfortable chair","feel comfortable","comfortable life"],"example":"This sofa is very comfortable to sit on.","exampleZh":"這張沙發坐起來很舒適。","synonyms":["cozy","relaxed"],"level":2,"theme":"情緒與感受","examples":[{"en":"This sofa is very comfortable to sit on.","zh":"這張沙發坐起來很舒適。"},{"en":"I finally feel comfortable speaking English in front of others.","zh":"我終於能自在地在別人面前說英語了。"},{"en":"These new shoes are comfortable enough for a long walk.","zh":"這雙新鞋舒適到足以走一段長路。"}]},{"word":"comic","pos":"adj. / n.","phonetic":"[ˈkɑmɪk]","meaning":"喜劇的；漫畫","definition":"causing laughter, or a magazine of comic strips","collocations":["comic book","comic strip","comic relief"],"example":"He loves reading comic books on weekends.","exampleZh":"他喜歡在週末看漫畫書。","synonyms":["funny","humorous"],"level":2,"theme":"藝術與音樂","examples":[{"en":"He loves reading comic books on weekends.","zh":"他喜歡在週末看漫畫書。"},{"en":"He draws a funny comic strip for the school newspaper.","zh":"他為學校報紙畫了一則好笑的連環漫畫。"},{"en":"The clumsy sidekick provided some comic relief in the play.","zh":"那個笨拙的配角在戲裡帶來一些輕鬆的笑料。"}]},{"word":"comma","pos":"n.","phonetic":"[ˈkɑmə]","meaning":"逗號","definition":"a punctuation mark used to indicate a pause","collocations":["put a comma","comma splice","use a comma"],"example":"You need a comma after the introductory phrase.","exampleZh":"介紹性片語後面需要加逗號。","synonyms":[],"level":2,"theme":"溝通與語言","examples":[{"en":"You need a comma after the introductory phrase.","zh":"介紹性片語後面需要加逗號。"},{"en":"Don't forget to put a comma between the two clauses.","zh":"別忘了在兩個子句之間加上逗號。"},{"en":"Using a comma correctly can change a whole sentence's meaning.","zh":"正確地使用逗號能改變整個句子的意思。"}]},{"word":"command","pos":"v. / n.","phonetic":"[kəˈmænd]","meaning":"命令;指揮","definition":"to give an authoritative order, or such an order","collocations":["give a command","command respect","under command"],"example":"The general commanded the troops to advance.","exampleZh":"將軍命令部隊前進。","synonyms":["order","instruct"],"level":3,"theme":"政治與法律","examples":[{"en":"The general commanded the troops to advance.","zh":"將軍命令部隊前進。"},{"en":"The captain gave a clear command to lower the sails.","zh":"船長下達了明確的命令要降下船帆。"},{"en":"Her honesty and hard work command everyone's deep respect.","zh":"她的誠實與努力贏得了大家深深的尊敬。"}]},{"word":"comment","pos":"n. / v.","phonetic":"[ˈkɑmɛnt]","meaning":"評論；意見","definition":"a remark expressing an opinion, or to make such a remark","collocations":["leave a comment","no comment","comment on"],"example":"She left a positive comment on my post.","exampleZh":"她在我的貼文下留了正面的評論。","synonyms":["remark"],"level":3,"theme":"溝通與語言","examples":[{"en":"She left a positive comment on my post.","zh":"她在我的貼文下留了正面的評論。"},{"en":"Feel free to leave a friendly comment below the article.","zh":"歡迎在文章下方留下友善的評論。"},{"en":"The teacher commented positively on my writing progress.","zh":"老師對我寫作的進步給予了正面的評論。"}]},{"word":"commerce","pos":"n.","phonetic":"[ˈkɑmɝs]","meaning":"商業；貿易","definition":"the activity of buying and selling goods and services","collocations":["electronic commerce","international commerce","chamber of commerce"],"example":"Online commerce has grown rapidly in recent years.","exampleZh":"近年來線上商業快速成長。","synonyms":["trade","business"],"level":4,"theme":"商業與金錢","examples":[{"en":"Online commerce has grown rapidly in recent years.","zh":"近年來線上商業快速成長。"},{"en":"Electronic commerce allows people to shop from their own homes.","zh":"電子商務讓人們能在自己家裡購物。"},{"en":"International commerce connects businesses across many different countries.","zh":"國際貿易連結了許多不同國家的企業。"}]},{"word":"commercial","pos":"adj. / n.","phonetic":"[kəˈmɝʃəl]","meaning":"商業的；廣告","definition":"related to commerce, or a television advertisement","collocations":["commercial success","TV commercial","commercial building"],"example":"The film was a huge commercial success.","exampleZh":"這部電影在商業上大獲成功。","synonyms":["business"],"level":3,"theme":"商業與金錢","examples":[{"en":"The film was a huge commercial success.","zh":"這部電影在商業上大獲成功。"},{"en":"That catchy TV commercial made me want the new drink.","zh":"那支洗腦的電視廣告讓我想買那款新飲料。"},{"en":"Her first novel was both a critical and commercial success.","zh":"她的第一本小說在評價和商業上都很成功。"}]},{"word":"commit","pos":"v.","phonetic":"[kəˈmɪt]","meaning":"犯（罪）；承諾；致力於","definition":"to carry out a wrong act, or to bind oneself to a course of action","collocations":["commit a crime","commit to a plan","commit oneself"],"example":"He was arrested for committing a crime.","exampleZh":"他因犯罪而被逮捕。","synonyms":["carry out","pledge"],"level":4,"theme":"政治與法律","examples":[{"en":"He was arrested for committing a crime.","zh":"他因犯罪而被逮捕。"},{"en":"She committed herself to studying two full hours every evening.","zh":"她致力於每晚讀書整整兩個小時。"},{"en":"Once we commit to the plan, we must not give up.","zh":"一旦我們對計畫做出承諾，就絕不能放棄。"}]},{"word":"committee","pos":"n.","phonetic":"[kəˈmɪtɪ]","meaning":"委員會","definition":"a group of people appointed for a specific function","collocations":["form a committee","committee meeting","join a committee"],"example":"The committee will decide on the new policy.","exampleZh":"委員會將決定新的政策。","synonyms":["board","panel"],"level":4,"theme":"社會與文化","examples":[{"en":"The committee will decide on the new policy.","zh":"委員會將決定新的政策。"},{"en":"The school formed a committee to plan the graduation ceremony.","zh":"學校成立了一個委員會來籌辦畢業典禮。"},{"en":"She proudly joined the committee that organizes charity events.","zh":"她驕傲地加入了負責籌辦慈善活動的委員會。"}]},{"word":"common","pos":"adj.","phonetic":"[ˈkɑmən]","meaning":"常見的；共同的","definition":"occurring often, or shared by two or more people","collocations":["common sense","common ground","in common"],"example":"It's common for students to feel nervous before exams.","exampleZh":"學生在考試前感到緊張是很常見的。","synonyms":["usual","shared"],"level":1,"theme":"性質與描述","examples":[{"en":"It's common for students to feel nervous before exams.","zh":"學生在考試前感到緊張是很常見的。"},{"en":"The two teams finally found some common ground during talks.","zh":"兩隊在會談中終於找到了一些共識。"},{"en":"My best friend and I have a lot in common.","zh":"我和我最好的朋友有很多共同點。"}]},{"word":"communicate","pos":"v.","phonetic":"[kəˈmjunəˌket]","meaning":"溝通；傳達","definition":"to share or exchange information, news, or ideas","collocations":["communicate effectively","communicate with","communicate ideas"],"example":"It's important to communicate clearly with your team.","exampleZh":"與你的團隊清楚溝通很重要。","synonyms":["convey","express"],"level":3,"theme":"溝通與語言","examples":[{"en":"It's important to communicate clearly with your team.","zh":"與你的團隊清楚溝通很重要。"},{"en":"Good leaders know how to communicate their ideas very clearly.","zh":"優秀的領導者懂得如何非常清楚地傳達他們的想法。"},{"en":"We use pictures to communicate with visitors who speak other languages.","zh":"我們用圖片和說其他語言的訪客溝通。"}]},{"word":"communication","pos":"n.","phonetic":"[kəˌmjunəˈkeʃən]","meaning":"溝通；通訊","definition":"the sharing of information between people","collocations":["good communication","communication skills","means of communication"],"example":"Good communication is key to a healthy relationship.","exampleZh":"良好的溝通是健康關係的關鍵。","synonyms":[],"level":3,"theme":"溝通與語言","examples":[{"en":"Good communication is key to a healthy relationship.","zh":"良好的溝通是健康關係的關鍵。"},{"en":"Strong communication skills will help you in almost any job.","zh":"良好的溝通技巧幾乎在任何工作上都能幫助你。"},{"en":"The internet has become our main means of communication.","zh":"網路已經成為我們主要的通訊方式。"}]},{"word":"community","pos":"n.","phonetic":"[kəˈmjunətɪ]","meaning":"社區；社群","definition":"a group of people living in the same place or sharing an interest","collocations":["local community","community service","online community"],"example":"The whole community came together to clean the park.","exampleZh":"整個社區的人一起清理公園。","synonyms":["society"],"level":2,"theme":"社會與文化","examples":[{"en":"The whole community came together to clean the park.","zh":"整個社區的人一起清理公園。"},{"en":"Students often do community service to help those in need.","zh":"學生們常做社區服務來幫助有需要的人。"},{"en":"She found supportive friends in an online community for artists.","zh":"她在一個藝術家的網路社群裡找到了支持她的朋友。"}]},{"word":"commute","pos":"v.","phonetic":"[kəˈmjut]","meaning":"通勤","definition":"to travel regularly between home and work","collocations":["commute to work","daily commute","long commute"],"example":"He commutes to the city by train every day.","exampleZh":"他每天搭火車通勤到市區。","synonyms":["travel"],"level":4,"theme":"交通與旅行","examples":[{"en":"He commutes to the city by train every day.","zh":"他每天搭火車通勤到市區。"},{"en":"My father commutes to work by bicycle every single morning.","zh":"我爸爸每天早上都騎腳踏車通勤上班。"},{"en":"A long daily commute leaves her feeling tired and stressed.","zh":"每天漫長的通勤讓她感到疲累又有壓力。"}]},{"word":"companion","pos":"n.","phonetic":"[kəmˈpænjən]","meaning":"同伴；夥伴","definition":"a person who accompanies or spends time with another","collocations":["travel companion","close companion","faithful companion"],"example":"The dog became her constant companion.","exampleZh":"那隻狗成了她長期的夥伴。","synonyms":["partner","friend"],"level":4,"theme":"人物與家庭","examples":[{"en":"The dog became her constant companion.","zh":"那隻狗成了她長期的夥伴。"},{"en":"Her loyal dog has been a faithful companion for many years.","zh":"她忠心的狗多年來一直是她忠實的夥伴。"},{"en":"A good travel companion makes any journey more enjoyable.","zh":"一個好的旅伴會讓任何旅程都更愉快。"}]},{"word":"company","pos":"n.","phonetic":"[ˈkʌmpənɪ]","meaning":"公司；陪伴","definition":"a business organization, or the state of being with someone","collocations":["run a company","keep company","insurance company"],"example":"She works for a large technology company.","exampleZh":"她在一家大型科技公司工作。","synonyms":["firm","business"],"level":2,"theme":"商業與金錢","examples":[{"en":"She works for a large technology company.","zh":"她在一家大型科技公司工作。"},{"en":"My aunt runs a small company that designs greeting cards.","zh":"我阿姨經營一家設計賀卡的小公司。"},{"en":"The old man's gentle cat keeps him company every evening.","zh":"那隻溫馴的貓每天晚上都陪伴著這位老先生。"}]},{"word":"compare","pos":"v.","phonetic":"[kəmˈpɛr]","meaning":"比較","definition":"to examine two or more things to note similarities and differences","collocations":["compare prices","compare notes","compare to"],"example":"Let's compare the two products before buying.","exampleZh":"在購買之前,我們先比較這兩件產品。","synonyms":["contrast"],"level":2,"theme":"抽象概念","examples":[{"en":"Let's compare the two products before buying.","zh":"在購買之前,我們先比較這兩件產品。"},{"en":"We compared prices at three stores before buying the bike.","zh":"買腳踏車前，我們比較了三家店的價格。"},{"en":"After the exam, students compared notes about the hard questions.","zh":"考試後，學生們交換對難題的看法。"}]},{"word":"comparison","pos":"n.","phonetic":"[kəmˈpærəsn̩]","meaning":"比較","definition":"the act of comparing two or more things","collocations":["by comparison","make a comparison","in comparison with"],"example":"In comparison with last year, sales have increased.","exampleZh":"與去年相比,銷售額增加了。","synonyms":["contrast"],"level":3,"theme":"抽象概念","examples":[{"en":"In comparison with last year, sales have increased.","zh":"與去年相比,銷售額增加了。"},{"en":"The teacher made a clear comparison between the two poems.","zh":"老師清楚地比較了這兩首詩。"},{"en":"In comparison with last year, this winter feels much colder.","zh":"和去年相比，今年冬天感覺冷多了。"}]},{"word":"compass","pos":"n.","phonetic":"[ˈkʌmpəs]","meaning":"羅盤；指南針","definition":"an instrument for finding directions","collocations":["moral compass","use a compass","compass needle"],"example":"The hikers used a compass to find their way.","exampleZh":"登山客用指南針找路。","synonyms":[],"level":3,"theme":"科學與數學","examples":[{"en":"The hikers used a compass to find their way.","zh":"登山客用指南針找路。"},{"en":"The scouts learned to use a compass during the camping trip.","zh":"童軍們在露營時學會了使用指南針。"},{"en":"The compass needle always points steadily toward the north.","zh":"指南針的指針總是穩定地指向北方。"}]},{"word":"compassion","pos":"n.","phonetic":"[kəmˈpæʃən]","meaning":"同情心；憐憫","definition":"a strong feeling of sympathy for someone suffering","collocations":["show compassion","act with compassion","compassion for others"],"example":"She showed great compassion for the homeless.","exampleZh":"她對無家可歸的人展現了極大的同情心。","synonyms":["sympathy","mercy"],"level":5,"theme":"情緒與感受","examples":[{"en":"She showed great compassion for the homeless.","zh":"她對無家可歸的人展現了極大的同情心。"},{"en":"The kind nurse treated every patient with warmth and compassion.","zh":"那位親切的護士以溫暖和同情心對待每一位病人。"},{"en":"Teaching children compassion for others is truly very important.","zh":"教導孩子對他人的同情心是非常重要的。"}]},{"word":"compatible","pos":"adj.","phonetic":"[kəmˈpætəbl̩]","meaning":"相容的；合得來的","definition":"able to exist or work together without conflict","collocations":["compatible with","compatible software","compatible personalities"],"example":"This software is compatible with most computers.","exampleZh":"這個軟體與大多數電腦相容。","synonyms":["consistent"],"level":5,"theme":"科技與媒體","examples":[{"en":"This software is compatible with most computers.","zh":"這個軟體與大多數電腦相容。"},{"en":"Make sure the new app is compatible with your phone.","zh":"確認這個新的應用程式與你的手機相容。"},{"en":"Their compatible personalities made them perfect partners for the project.","zh":"他們合得來的個性讓他們成為這項專案的最佳搭檔。"}]},{"word":"compensate","pos":"v.","phonetic":"[ˈkɑmpənˌset]","meaning":"補償；賠償","definition":"to give something to make up for loss or damage","collocations":["compensate for","compensate victims","fully compensate"],"example":"The company compensated workers for the accident.","exampleZh":"公司對事故中的員工做出了賠償。","synonyms":["reimburse","make up for"],"level":5,"theme":"商業與金錢","examples":[{"en":"The company compensated workers for the accident.","zh":"公司對事故中的員工做出了賠償。"},{"en":"Hard work can often compensate for a lack of talent.","zh":"努力往往能彌補天賦的不足。"},{"en":"The airline promised to fully compensate passengers for the long delay.","zh":"航空公司承諾會為漫長的誤點充分補償乘客。"}]},{"word":"compete","pos":"v.","phonetic":"[kəmˈpit]","meaning":"競爭；比賽","definition":"to strive against others for a prize or advantage","collocations":["compete for","compete against","compete fairly"],"example":"Athletes from many countries compete in the Olympics.","exampleZh":"來自許多國家的運動員在奧運中競賽。","synonyms":["contend","rival"],"level":3,"theme":"運動與休閒","examples":[{"en":"Athletes from many countries compete in the Olympics.","zh":"來自許多國家的運動員在奧運中競賽。"},{"en":"Several schools will compete for the science prize this year.","zh":"今年將有好幾所學校競逐這項科學獎。"},{"en":"The coach reminded us to always compete fairly and honestly.","zh":"教練提醒我們永遠要公平且誠實地競爭。"}]},{"word":"competent","pos":"adj.","phonetic":"[ˈkɑmpətənt]","meaning":"有能力的；勝任的","definition":"having the necessary ability or skill to do something successfully","collocations":["competent worker","competent in","fully competent"],"example":"She is a competent and reliable manager.","exampleZh":"她是位能力強又可靠的經理。","synonyms":["capable","skilled"],"level":5,"theme":"工作與職業","examples":[{"en":"She is a competent and reliable manager.","zh":"她是位能力強又可靠的經理。"},{"en":"She is fully competent to handle the project on her own.","zh":"她完全有能力獨自處理這個專案。"},{"en":"A competent worker finishes every task carefully and on time.","zh":"一個能幹的員工會仔細且準時地完成每項工作。"}]},{"word":"competition","pos":"n.","phonetic":"[ˌkɑmpəˈtɪʃən]","meaning":"競爭；比賽","definition":"the activity of competing, or an event in which people compete","collocations":["win a competition","fierce competition","enter a competition"],"example":"She won first place in the singing competition.","exampleZh":"她在歌唱比賽中獲得第一名。","synonyms":["contest","rivalry"],"level":3,"theme":"運動與休閒","examples":[{"en":"She won first place in the singing competition.","zh":"她在歌唱比賽中獲得第一名。"},{"en":"He decided to enter the school's writing competition this term.","zh":"這學期他決定參加學校的寫作比賽。"},{"en":"There was fierce competition for the last spot on the team.","zh":"大家為了隊上最後一個名額展開激烈的競爭。"}]},{"word":"competitive","pos":"adj.","phonetic":"[kəmˈpɛtətɪv]","meaning":"競爭激烈的；有競爭力的","definition":"relating to competition, or eager to win or be more successful","collocations":["competitive market","competitive price","competitive spirit"],"example":"The job market has become very competitive.","exampleZh":"就業市場已變得非常競爭。","synonyms":["cutthroat"],"level":4,"theme":"商業與金錢","examples":[{"en":"The job market has become very competitive.","zh":"就業市場已變得非常競爭。"},{"en":"The shop offers competitive prices to attract more new customers.","zh":"這家店提供有競爭力的價格來吸引更多新顧客。"},{"en":"Her strong competitive spirit pushes her to improve every day.","zh":"她強烈的競爭精神驅使她每天進步。"}]},{"word":"competitor","pos":"n.","phonetic":"[kəmˈpɛtətɚ]","meaning":"競爭對手","definition":"a person or company competing with others","collocations":["main competitor","business competitor","beat a competitor"],"example":"The company keeps a close eye on its competitors.","exampleZh":"這家公司密切關注其競爭對手。","synonyms":["rival"],"level":4,"theme":"商業與金錢","examples":[{"en":"The company keeps a close eye on its competitors.","zh":"這家公司密切關注其競爭對手。"},{"en":"She trained hard to beat her toughest competitor in the race.","zh":"她努力訓練，想在比賽中擊敗她最強勁的對手。"},{"en":"The bakery's main competitor just opened across the street.","zh":"這家麵包店的主要競爭對手剛在對街開幕。"}]},{"word":"complain","pos":"v.","phonetic":"[kəmˈplen]","meaning":"抱怨；投訴","definition":"to express dissatisfaction about something","collocations":["complain about","complain to the manager","complain loudly"],"example":"Customers complained about the poor service.","exampleZh":"顧客抱怨服務不佳。","synonyms":["grumble","protest"],"level":2,"theme":"溝通與語言","examples":[{"en":"Customers complained about the poor service.","zh":"顧客抱怨服務不佳。"},{"en":"Students complained about the difficult homework to their teacher.","zh":"學生們向老師抱怨作業太難。"},{"en":"He complained to the manager about the cold, tasteless soup.","zh":"他向經理抱怨湯又冷又沒味道。"}]},{"word":"complaint","pos":"n.","phonetic":"[kəmˈplent]","meaning":"抱怨；投訴","definition":"a statement expressing dissatisfaction","collocations":["file a complaint","common complaint","lodge a complaint"],"example":"The manager received several complaints about the noise.","exampleZh":"經理收到幾起關於噪音的投訴。","synonyms":["grievance"],"level":3,"theme":"溝通與語言","examples":[{"en":"The manager received several complaints about the noise.","zh":"經理收到幾起關於噪音的投訴。"},{"en":"A common complaint among students is that lunch breaks are short.","zh":"學生們常見的抱怨是午休時間太短。"},{"en":"She filed a complaint about the broken elevator in the building.","zh":"她針對大樓裡故障的電梯提出了投訴。"}]},{"word":"complete","pos":"adj. / v.","phonetic":"[kəmˈplit]","meaning":"完整的；完成","definition":"having all necessary parts, or to finish something","collocations":["complete a task","complete set","complete silence"],"example":"She completed her homework before dinner.","exampleZh":"她在晚餐前完成了作業。","synonyms":["finish","whole"],"level":1,"theme":"動作與行為","examples":[{"en":"She completed her homework before dinner.","zh":"她在晚餐前完成了作業。"},{"en":"The room fell into complete silence during the important test.","zh":"重要考試時，整個房間陷入一片完全的寂靜。"},{"en":"He finally collected a complete set of the comic series.","zh":"他終於收集齊了那套完整的漫畫系列。"}]},{"word":"complex","pos":"adj.","phonetic":"[kəmˈplɛks]","meaning":"複雜的","definition":"consisting of many interconnected parts; not simple","collocations":["complex problem","complex system","complex relationship"],"example":"The instructions were too complex for beginners.","exampleZh":"這些說明對初學者來說太複雜了。","synonyms":["complicated","intricate"],"level":3,"theme":"性質與描述","examples":[{"en":"The instructions were too complex for beginners.","zh":"這些說明對初學者來說太複雜了。"},{"en":"The human brain is an incredibly complex and delicate system.","zh":"人類的大腦是一個極其複雜又精密的系統。"},{"en":"Solving this complex problem requires patience and careful thinking.","zh":"解決這個複雜的問題需要耐心和仔細的思考。"}]},{"word":"complicate","pos":"v.","phonetic":"[ˈkɑmpləˌket]","meaning":"使複雜化","definition":"to make something more difficult to understand or deal with","collocations":["complicate matters","complicate things further","complicate a plan"],"example":"His constant interruptions only complicated the discussion.","exampleZh":"他不斷打斷討論只讓事情更複雜。","synonyms":["confuse"],"level":4,"theme":"性質與描述","examples":[{"en":"His constant interruptions only complicated the discussion.","zh":"他不斷打斷討論只讓事情更複雜。"},{"en":"Adding too many rules will only complicate the simple game.","zh":"加入太多規則只會讓這個簡單的遊戲變得更複雜。"},{"en":"Please don't complicate matters by changing the plan again.","zh":"請別再更改計畫，把事情弄得更複雜了。"}]},{"word":"compliment","pos":"n. / v.","phonetic":"[ˈkɑmpləmənt]","meaning":"稱讚；恭維","definition":"a polite expression of praise, or to give such praise","collocations":["pay a compliment","take a compliment","compliment someone on"],"example":"She complimented me on my new haircut.","exampleZh":"她稱讚了我的新髮型。","synonyms":["praise"],"level":4,"theme":"溝通與語言","examples":[{"en":"She complimented me on my new haircut.","zh":"她稱讚了我的新髮型。"},{"en":"The judge complimented her on her wonderfully creative painting.","zh":"評審稱讚她那幅極富創意的畫作。"},{"en":"He blushed and didn't know how to take the compliment.","zh":"他臉紅了，不知道該如何接受這個稱讚。"}]},{"word":"component","pos":"n.","phonetic":"[kəmˈponənt]","meaning":"組成部分；零件","definition":"a part or element of a larger whole","collocations":["key component","electronic component","main component"],"example":"Trust is a key component of any relationship.","exampleZh":"信任是任何關係中的關鍵組成部分。","synonyms":["part","element"],"level":5,"theme":"抽象概念","examples":[{"en":"Trust is a key component of any relationship.","zh":"信任是任何關係中的關鍵組成部分。"},{"en":"Fresh vegetables are a key component of a healthy diet.","zh":"新鮮蔬菜是健康飲食的關鍵組成部分。"},{"en":"The technician replaced a tiny electronic component inside the radio.","zh":"技師更換了收音機裡一個微小的電子零件。"}]},{"word":"compose","pos":"v.","phonetic":"[kəmˈpoz]","meaning":"組成；創作；作曲","definition":"to make up or form something, or to write music","collocations":["compose music","compose a letter","composed of"],"example":"Beethoven composed many famous symphonies.","exampleZh":"貝多芬創作了許多著名的交響曲。","synonyms":["create","write"],"level":4,"theme":"藝術與音樂","examples":[{"en":"Beethoven composed many famous symphonies.","zh":"貝多芬創作了許多著名的交響曲。"},{"en":"Ordinary water is composed of hydrogen and oxygen atoms.","zh":"普通的水是由氫原子和氧原子組成的。"},{"en":"The talented student composed a lovely song for the concert.","zh":"這位才華洋溢的學生為音樂會創作了一首動聽的歌曲。"}]},{"word":"composition","pos":"n.","phonetic":"[ˌkɑmpəˈzɪʃən]","meaning":"作文；作曲；組成","definition":"a piece of writing or music, or the way something is put together","collocations":["write a composition","musical composition","chemical composition"],"example":"Our teacher assigned a composition about our summer vacation.","exampleZh":"老師出了一篇關於暑假的作文作業。","synonyms":["essay","structure"],"level":4,"theme":"教育與學習","examples":[{"en":"Our teacher assigned a composition about our summer vacation.","zh":"老師出了一篇關於暑假的作文作業。"},{"en":"For homework, we must write a composition about our dreams.","zh":"作業是我們必須寫一篇關於夢想的作文。"},{"en":"Scientists carefully studied the chemical composition of the strange rock.","zh":"科學家仔細研究了那塊奇怪岩石的化學成分。"}]},{"word":"compound","pos":"n. / adj.","phonetic":"[ˈkɑmpaʊnd]","meaning":"化合物；複合的","definition":"a thing composed of two or more parts, especially a chemical substance","collocations":["chemical compound","compound word","compound interest"],"example":"Water is a compound made of hydrogen and oxygen.","exampleZh":"水是由氫和氧組成的化合物。","synonyms":["mixture"],"level":5,"theme":"科學與數學","examples":[{"en":"Water is a compound made of hydrogen and oxygen.","zh":"水是由氫和氧組成的化合物。"},{"en":"The word 'notebook' is a compound word made of two parts.","zh":"「notebook」這個字是由兩個部分組成的複合字。"},{"en":"Salt is a common chemical compound found in our kitchens.","zh":"鹽是一種在我們廚房裡常見的化合物。"}]},{"word":"comprehend","pos":"v.","phonetic":"[ˌkɑmprɪˈhɛnd]","meaning":"理解；領會","definition":"to fully grasp the meaning or nature of something","collocations":["fail to comprehend","hard to comprehend","comprehend the situation"],"example":"It was hard for him to comprehend the tragedy.","exampleZh":"對他來說,很難理解這場悲劇。","synonyms":["understand","grasp"],"level":5,"theme":"教育與學習","examples":[{"en":"It was hard for him to comprehend the tragedy.","zh":"對他來說,很難理解這場悲劇。"},{"en":"The young child could not comprehend why the sky turns dark.","zh":"這個小孩無法理解天空為什麼會變黑。"},{"en":"The sheer size of the universe is truly hard to comprehend.","zh":"宇宙的龐大真的很難理解。"}]},{"word":"comprehensive","pos":"adj.","phonetic":"[ˌkɑmprɪˈhɛnsɪv]","meaning":"全面的；廣泛的","definition":"complete and including everything necessary","collocations":["comprehensive plan","comprehensive review","comprehensive coverage"],"example":"The report gives a comprehensive overview of the problem.","exampleZh":"這份報告對問題提供了全面的概述。","synonyms":["thorough","complete"],"level":5,"theme":"抽象概念","examples":[{"en":"The report gives a comprehensive overview of the problem.","zh":"這份報告對問題提供了全面的概述。"},{"en":"The teacher gave a comprehensive review before the final exam.","zh":"老師在期末考前做了全面的複習。"},{"en":"They created a comprehensive plan to protect the local forest.","zh":"他們擬定了一個全面的計畫來保護當地的森林。"}]},{"word":"compress","pos":"v.","phonetic":"[kəmˈprɛs]","meaning":"壓縮","definition":"to press or squeeze something to make it smaller or denser","collocations":["compress a file","compress air","compressed into"],"example":"You can compress the file to save space.","exampleZh":"你可以壓縮檔案以節省空間。","synonyms":["squeeze","condense"],"level":5,"theme":"科技與媒體","examples":[{"en":"You can compress the file to save space.","zh":"你可以壓縮檔案以節省空間。"},{"en":"You should compress the large file before emailing it.","zh":"在用電子郵件寄出前，你應該把這個大檔案壓縮。"},{"en":"The pump compresses air to fill the flat bicycle tire.","zh":"這個打氣筒壓縮空氣來把沒氣的腳踏車輪胎打滿。"}]},{"word":"compromise","pos":"n. / v.","phonetic":"[ˈkɑmprəˌmaɪz]","meaning":"妥協；折衷","definition":"an agreement reached by each side making concessions, or to make such an agreement","collocations":["reach a compromise","compromise on","willing to compromise"],"example":"The two sides finally reached a compromise.","exampleZh":"雙方最終達成了妥協。","synonyms":["settlement"],"level":4,"theme":"政治與法律","examples":[{"en":"The two sides finally reached a compromise.","zh":"雙方最終達成了妥協。"},{"en":"After a long argument, both students were willing to compromise on the plan.","zh":"經過長時間的爭論後，兩位學生都願意在計畫上妥協。"},{"en":"Good friends often reach a compromise instead of insisting on being right.","zh":"好朋友常會達成折衷，而不是堅持自己是對的。"}]},{"word":"compulsory","pos":"adj.","phonetic":"[kəmˈpʌlsərɪ]","meaning":"必修的；強制的","definition":"required by law or a rule; obligatory","collocations":["compulsory education","compulsory subject","compulsory military service"],"example":"English is a compulsory subject in most schools.","exampleZh":"英文是大多數學校的必修科目。","synonyms":["mandatory","required"],"level":5,"theme":"教育與學習","examples":[{"en":"English is a compulsory subject in most schools.","zh":"英文是大多數學校的必修科目。"},{"en":"In Taiwan, nine years of compulsory education are provided for every child.","zh":"在台灣，每個孩子都能享有九年的義務教育。"},{"en":"Math is a compulsory subject that all high-school students must study.","zh":"數學是所有高中生都必須學習的必修科目。"}]},{"word":"compute","pos":"v.","phonetic":"[kəmˈpjut]","meaning":"計算","definition":"to calculate a figure or amount","collocations":["compute the cost","compute a result","compute data"],"example":"The software can compute the results in seconds.","exampleZh":"這套軟體能在幾秒內計算出結果。","synonyms":["calculate"],"level":4,"theme":"科學與數學","examples":[{"en":"The software can compute the results in seconds.","zh":"這套軟體能在幾秒內計算出結果。"},{"en":"The teacher showed us how to compute the average of the test scores.","zh":"老師教我們如何計算考試分數的平均值。"},{"en":"It took him a few minutes to compute the total cost of the trip.","zh":"他花了幾分鐘才計算出這趟旅行的總花費。"}]},{"word":"computer","pos":"n.","phonetic":"[kəmˈpjutɚ]","meaning":"電腦","definition":"an electronic device for processing data","collocations":["use a computer","computer science","laptop computer"],"example":"She bought a new computer for her studies.","exampleZh":"她為了學業買了一台新電腦。","synonyms":[],"level":1,"theme":"科技與媒體","examples":[{"en":"She bought a new computer for her studies.","zh":"她為了學業買了一台新電腦。"},{"en":"My brother is studying computer science at a university in Taipei.","zh":"我哥哥在台北的一所大學攻讀資訊科學。"},{"en":"She carries a light laptop computer to school every day.","zh":"她每天帶著一台輕便的筆記型電腦去上學。"}]},{"word":"conceal","pos":"v.","phonetic":"[kənˈsil]","meaning":"隱藏；隱瞞","definition":"to keep something from being seen or known","collocations":["conceal the truth","conceal one's feelings","carefully concealed"],"example":"She tried to conceal her disappointment.","exampleZh":"她試圖隱藏自己的失望。","synonyms":["hide","cover up"],"level":5,"theme":"抽象概念","examples":[{"en":"She tried to conceal her disappointment.","zh":"她試圖隱藏自己的失望。"},{"en":"He could not conceal his excitement when he saw the concert tickets.","zh":"當他看到演唱會門票時，無法掩飾自己的興奮。"},{"en":"The thief carefully concealed the stolen jewelry under the floor.","zh":"小偷小心地把偷來的珠寶藏在地板下。"}]},{"word":"concentrate","pos":"v.","phonetic":"[ˋkɑnsn̩͵tret]","meaning":"專心；集中","definition":"to focus all one's attention or effort on something","collocations":["concentrate on studying","concentrate one's efforts","hard to concentrate"],"example":"Please turn off the TV so I can concentrate on my homework.","exampleZh":"請把電視關掉，這樣我才能專心寫功課。","synonyms":["focus"],"level":3,"theme":"教育與學習","examples":[{"en":"Please turn off the TV so I can concentrate on my homework.","zh":"請把電視關掉，這樣我才能專心寫功課。"},{"en":"It is hard to concentrate on studying when your phone keeps buzzing.","zh":"當你的手機一直震動時，很難專心讀書。"},{"en":"The coach told the players to concentrate their efforts on defense.","zh":"教練要球員把心力集中在防守上。"}]},{"word":"concept","pos":"n.","phonetic":"[ˋkɑnsɛpt]","meaning":"概念；觀念","definition":"an abstract idea or general notion","collocations":["a basic concept","the concept of freedom","grasp a concept"],"example":"Students found the concept of gravity difficult at first.","exampleZh":"學生一開始覺得重力的概念很難懂。","synonyms":["idea","notion"],"level":4,"theme":"抽象概念","examples":[{"en":"Students found the concept of gravity difficult at first.","zh":"學生一開始覺得重力的概念很難懂。"},{"en":"It took her a while to grasp the concept of negative numbers.","zh":"她花了一段時間才理解負數的概念。"},{"en":"The lecture explored the concept of freedom in modern society.","zh":"那場演講探討了現代社會中自由的概念。"}]},{"word":"concern","pos":"n. / v.","phonetic":"[kənˋsɜn]","meaning":"擔憂；關切的事；使擔心","definition":"a feeling of worry, or something that worries someone","collocations":["a growing concern","express concern","concern about safety"],"example":"Pollution is a major concern for the whole city.","exampleZh":"污染是全市共同關切的重大問題。","synonyms":["worry","anxiety"],"level":3,"theme":"情緒與感受","examples":[{"en":"Pollution is a major concern for the whole city.","zh":"污染是全市共同關切的重大問題。"},{"en":"Many parents expressed concern about the safety of the old playground.","zh":"許多家長對那座老舊遊樂場的安全表達了關切。"},{"en":"Rising sea levels are a growing concern for coastal towns.","zh":"海平面上升是沿海城鎮日益嚴重的憂慮。"}]},{"word":"conclude","pos":"v.","phonetic":"[kənˋklud]","meaning":"下結論；結束","definition":"to decide something after considering the facts, or to end","collocations":["conclude that","conclude a meeting","conclude with a summary"],"example":"The researchers concluded that the drug was safe.","exampleZh":"研究人員的結論是這種藥是安全的。","synonyms":["decide","finish"],"level":4,"theme":"教育與學習","examples":[{"en":"The researchers concluded that the drug was safe.","zh":"研究人員的結論是這種藥是安全的。"},{"en":"From the results, we can conclude that the plants need more sunlight.","zh":"從結果來看，我們可以斷定這些植物需要更多陽光。"},{"en":"The principal concluded the assembly with a short summary.","zh":"校長以簡短的總結結束了這場集會。"}]},{"word":"condition","pos":"n.","phonetic":"[kənˋdɪʃən]","meaning":"狀況；條件","definition":"the state that something or someone is in, or a requirement","collocations":["in good condition","weather conditions","on one condition"],"example":"The used car is still in excellent condition.","exampleZh":"這輛二手車的狀況仍然很好。","synonyms":["state","situation"],"level":3,"theme":"性質與描述","examples":[{"en":"The used car is still in excellent condition.","zh":"這輛二手車的狀況仍然很好。"},{"en":"My mother agreed to buy the bike on one condition: I keep my grades up.","zh":"我媽媽答應買腳踏車給我，但有一個條件：我要維持好成績。"},{"en":"The hikers turned back because the weather conditions grew dangerous.","zh":"由於天氣狀況變得危險，登山客們折返了。"}]},{"word":"conduct","pos":"v. / n.","phonetic":"[kənˋdʌkt]","meaning":"進行；實施；行為","definition":"to organize and carry out an activity, or one's behavior","collocations":["conduct a survey","conduct an experiment","professional conduct"],"example":"The team conducted an experiment to test the theory.","exampleZh":"這個團隊進行了一項實驗來驗證這個理論。","synonyms":["carry out","behavior"],"level":5,"theme":"工作與職業","examples":[{"en":"The team conducted an experiment to test the theory.","zh":"這個團隊進行了一項實驗來驗證這個理論。"},{"en":"Our class conducted a survey about students' favorite sports.","zh":"我們班進行了一項關於學生最喜歡運動的問卷調查。"},{"en":"Good conduct in the library means keeping quiet and respecting others.","zh":"在圖書館裡良好的行為就是保持安靜並尊重他人。"}]},{"word":"confess","pos":"v.","phonetic":"[kənˋfɛs]","meaning":"坦白；承認","definition":"to admit that one has done something wrong","collocations":["confess to a crime","confess one's mistake","confess the truth"],"example":"He finally confessed that he had broken the window.","exampleZh":"他終於坦承是他打破了窗戶。","synonyms":["admit"],"level":4,"theme":"溝通與語言","examples":[{"en":"He finally confessed that he had broken the window.","zh":"他終於坦承是他打破了窗戶。"},{"en":"She finally confessed that she had eaten the last slice of cake.","zh":"她終於承認自己吃掉了最後一塊蛋糕。"},{"en":"The boy was brave enough to confess his mistake to the teacher.","zh":"那個男孩勇敢地向老師坦承自己的錯誤。"}]},{"word":"confident","pos":"adj.","phonetic":"[ˋkɑnfədənt]","meaning":"有信心的；確信的","definition":"feeling sure about one's abilities or a future outcome","collocations":["feel confident","confident about the future","a confident speaker"],"example":"She felt confident about passing the exam.","exampleZh":"她對通過這次考試很有信心。","synonyms":["assured","certain"],"level":3,"theme":"情緒與感受","examples":[{"en":"She felt confident about passing the exam.","zh":"她對通過這次考試很有信心。"},{"en":"After weeks of practice, she became a confident speaker on stage.","zh":"經過幾週的練習，她成為一位在台上充滿自信的演講者。"},{"en":"The students feel confident about the future after visiting the college.","zh":"參觀那所大學後，學生們對未來充滿信心。"}]},{"word":"confirm","pos":"v.","phonetic":"[kənˋfɝm]","meaning":"確認；證實","definition":"to state or show that something is true or correct","collocations":["confirm a reservation","confirm the news","confirm one's identity"],"example":"Could you please confirm your flight time by phone?","exampleZh":"可以請你打電話確認一下班機時間嗎？","synonyms":["verify"],"level":3,"theme":"溝通與語言","examples":[{"en":"Could you please confirm your flight time by phone?","zh":"可以請你打電話確認一下班機時間嗎？"},{"en":"The hotel sent an email to confirm our reservation for two nights.","zh":"飯店寄了一封電子郵件確認我們兩晚的訂房。"},{"en":"Scientists ran more tests to confirm the surprising news.","zh":"科學家做了更多測試來證實這個令人驚訝的消息。"}]},{"word":"conflict","pos":"n. / v.","phonetic":"[ˋkɑnflɪkt]","meaning":"衝突；矛盾","definition":"a serious disagreement or a state of being incompatible","collocations":["a conflict of interest","armed conflict","conflict with each other"],"example":"The two countries have been in conflict for years.","exampleZh":"這兩個國家已經衝突多年了。","synonyms":["dispute","clash"],"level":4,"theme":"政治與法律","examples":[{"en":"The two countries have been in conflict for years.","zh":"這兩個國家已經衝突多年了。"},{"en":"Their opinions often conflict with each other during group discussions.","zh":"在小組討論中，他們的意見常常互相衝突。"},{"en":"The teacher helped the two friends solve their conflict peacefully.","zh":"老師幫助這兩位朋友和平地解決了他們的衝突。"}]},{"word":"confuse","pos":"v.","phonetic":"[kənˋfjuz]","meaning":"使困惑；混淆","definition":"to make someone unable to think clearly, or mix things up","collocations":["confuse two words","get confused","confuse the issue"],"example":"The complicated instructions confused all the new workers.","exampleZh":"複雜的說明讓所有新員工都感到困惑。","synonyms":["puzzle","mix up"],"level":3,"theme":"教育與學習","examples":[{"en":"The complicated instructions confused all the new workers.","zh":"複雜的說明讓所有新員工都感到困惑。"},{"en":"Beginners often confuse the two words because they sound alike.","zh":"初學者常把這兩個字搞混，因為它們發音相似。"},{"en":"The unclear map made the tourists get confused at the station.","zh":"那張不清楚的地圖讓遊客們在車站裡感到困惑。"}]},{"word":"congratulate","pos":"v.","phonetic":"[kənˋɡrætʃə͵let]","meaning":"祝賀；恭喜","definition":"to praise someone for an achievement or happy event","collocations":["congratulate someone on","congratulate the winner"],"example":"We all congratulated Amy on her graduation.","exampleZh":"我們都恭喜艾咪畢業了。","synonyms":["praise"],"level":3,"theme":"人物與家庭","examples":[{"en":"We all congratulated Amy on her graduation.","zh":"我們都恭喜艾咪畢業了。"},{"en":"The whole class congratulated her on winning the science award.","zh":"全班同學恭喜她贏得科學獎。"},{"en":"The coach was the first to congratulate the winner of the race.","zh":"教練是第一個向賽跑冠軍道賀的人。"}]},{"word":"connect","pos":"v.","phonetic":"[kəˋnɛkt]","meaning":"連接；連結","definition":"to join or link two or more things together","collocations":["connect to the internet","connect two cities","connect with people"],"example":"This bridge connects the two islands.","exampleZh":"這座橋連接了這兩座島嶼。","synonyms":["link","join"],"level":2,"theme":"科技與媒體","examples":[{"en":"This bridge connects the two islands.","zh":"這座橋連接了這兩座島嶼。"},{"en":"You can connect to the internet by entering the library's password.","zh":"你輸入圖書館的密碼就可以連上網路。"},{"en":"A new highway will connect the two cities in about an hour.","zh":"一條新的高速公路將使這兩座城市約一小時就能相通。"}]},{"word":"conquer","pos":"v.","phonetic":"[ˋkɑŋkɚ]","meaning":"征服；克服","definition":"to defeat and take control of a place or overcome a difficulty","collocations":["conquer a country","conquer one's fear","conquer the market"],"example":"The ancient empire conquered many neighboring lands.","exampleZh":"這個古代帝國征服了許多鄰近的土地。","synonyms":["defeat","overcome"],"level":4,"theme":"政治與法律","examples":[{"en":"The ancient empire conquered many neighboring lands.","zh":"這個古代帝國征服了許多鄰近的土地。"},{"en":"She worked hard to conquer her fear of speaking in public.","zh":"她努力克服自己在公開場合說話的恐懼。"},{"en":"The climbers finally conquered the highest peak in the region.","zh":"登山者終於征服了該地區最高的山峰。"}]},{"word":"conscious","pos":"adj.","phonetic":"[ˋkɑnʃəs]","meaning":"意識到的；有知覺的","definition":"aware of something, or awake and able to think","collocations":["become conscious of","a conscious effort","remain conscious"],"example":"After the accident, he remained conscious the whole time.","exampleZh":"意外發生後，他一直保持清醒的意識。","synonyms":["aware"],"level":5,"theme":"身體與健康","examples":[{"en":"After the accident, he remained conscious the whole time.","zh":"意外發生後，他一直保持清醒的意識。"},{"en":"She made a conscious effort to speak more slowly during the speech.","zh":"她刻意在演講時放慢說話速度。"},{"en":"He suddenly became conscious of how quiet the classroom was.","zh":"他突然意識到教室有多麼安靜。"}]},{"word":"consent","pos":"n. / v.","phonetic":"[kənˋsɛnt]","meaning":"同意；許可","definition":"permission for something to happen, or to give such permission","collocations":["give consent","parental consent","consent to the plan"],"example":"The doctor could not operate without the patient's consent.","exampleZh":"沒有病患的同意，醫生不能動手術。","synonyms":["permission","agree"],"level":5,"theme":"社會與文化","examples":[{"en":"The doctor could not operate without the patient's consent.","zh":"沒有病患的同意，醫生不能動手術。"},{"en":"Students under eighteen need parental consent to join the trip.","zh":"未滿十八歲的學生需要家長同意才能參加這趟旅行。"},{"en":"The neighbors would not consent to the noisy building plan.","zh":"鄰居們不同意這項吵雜的建案計畫。"}]},{"word":"consequence","pos":"n.","phonetic":"[ˋkɑnsə͵kwɛns]","meaning":"後果；結果","definition":"a result or effect of an action or condition","collocations":["face the consequences","as a consequence","serious consequences"],"example":"He didn't think about the consequences of skipping school.","exampleZh":"他沒想過翹課會有什麼後果。","synonyms":["result","outcome"],"level":5,"theme":"抽象概念","examples":[{"en":"He didn't think about the consequences of skipping school.","zh":"他沒想過翹課會有什麼後果。"},{"en":"If you cheat on the test, you must face the consequences.","zh":"如果你考試作弊，就必須承擔後果。"},{"en":"Cutting down too many trees can have serious consequences for wildlife.","zh":"砍伐太多樹木可能對野生動物造成嚴重的後果。"}]},{"word":"conserve","pos":"v.","phonetic":"[kənˋsɝv]","meaning":"節約；保育","definition":"to protect something from being wasted or destroyed","collocations":["conserve energy","conserve water","conserve wildlife"],"example":"We should all try to conserve water during the drought.","exampleZh":"乾旱期間我們都應該試著節約用水。","synonyms":["preserve","save"],"level":5,"theme":"自然與環境","examples":[{"en":"We should all try to conserve water during the drought.","zh":"乾旱期間我們都應該試著節約用水。"},{"en":"Turning off the lights is a simple way to conserve energy.","zh":"關燈是節約能源的一個簡單方法。"},{"en":"The national park was created to conserve rare wildlife.","zh":"這座國家公園是為了保育稀有的野生動物而設立的。"}]},{"word":"consider","pos":"v.","phonetic":"[kənˋsɪdɚ]","meaning":"考慮；認為","definition":"to think carefully about something before making a decision","collocations":["consider carefully","consider an option","consider it important"],"example":"She is considering studying abroad next year.","exampleZh":"她正在考慮明年出國留學。","synonyms":["think about"],"level":3,"theme":"教育與學習","examples":[{"en":"She is considering studying abroad next year.","zh":"她正在考慮明年出國留學。"},{"en":"Please consider carefully before you choose your future career.","zh":"在選擇未來的職業之前，請仔細考慮。"},{"en":"Many teachers consider reading an important daily habit.","zh":"許多老師認為閱讀是重要的每日習慣。"}]},{"word":"consist","pos":"v.","phonetic":"[kənˋsɪst]","meaning":"由...組成","definition":"to be made up of particular parts or things","collocations":["consist of","the team consists of"],"example":"The committee consists of ten members.","exampleZh":"這個委員會由十名成員組成。","synonyms":["comprise"],"level":4,"theme":"抽象概念","examples":[{"en":"The committee consists of ten members.","zh":"這個委員會由十名成員組成。"},{"en":"A balanced meal should consist of vegetables, grains, and protein.","zh":"均衡的一餐應該由蔬菜、穀類和蛋白質組成。"},{"en":"Our debate team consists of five hardworking students.","zh":"我們的辯論隊由五位認真的學生組成。"}]},{"word":"constant","pos":"adj.","phonetic":"[ˋkɑnstənt]","meaning":"不斷的；持續的","definition":"happening all the time or not changing","collocations":["constant noise","under constant pressure","a constant speed"],"example":"The factory produces a constant level of noise all day.","exampleZh":"這間工廠整天都發出不斷的噪音。","synonyms":["continuous","steady"],"level":4,"theme":"性質與描述","examples":[{"en":"The factory produces a constant level of noise all day.","zh":"這間工廠整天都發出不斷的噪音。"},{"en":"The constant noise from the street kept her awake all night.","zh":"街上不斷的噪音讓她整夜無法入睡。"},{"en":"Students feel under constant pressure during the exam season.","zh":"學生在考試季節裡感到持續的壓力。"}]},{"word":"construct","pos":"v.","phonetic":"[kənˋstrʌkt]","meaning":"建造；構築","definition":"to build something, especially a structure or system","collocations":["construct a building","construct a theory","under construction"],"example":"Workers are constructing a new bridge across the river.","exampleZh":"工人正在河上建造一座新橋。","synonyms":["build"],"level":4,"theme":"居家與生活","examples":[{"en":"Workers are constructing a new bridge across the river.","zh":"工人正在河上建造一座新橋。"},{"en":"Engineers plan to construct a new library next to the school.","zh":"工程師計畫在學校旁邊建造一座新圖書館。"},{"en":"Scientists slowly constructed a theory to explain the strange results.","zh":"科學家慢慢建立起一套理論來解釋這些奇怪的結果。"}]},{"word":"consult","pos":"v.","phonetic":"[kənˋsʌlt]","meaning":"諮詢；請教","definition":"to seek advice or information from someone or something","collocations":["consult a doctor","consult a dictionary","consult with experts"],"example":"You should consult a doctor if the pain continues.","exampleZh":"如果疼痛持續，你應該去看醫生諮詢。","synonyms":["ask advice"],"level":5,"theme":"工作與職業","examples":[{"en":"You should consult a doctor if the pain continues.","zh":"如果疼痛持續，你應該去看醫生諮詢。"},{"en":"If you don't know the meaning, consult a dictionary first.","zh":"如果你不知道意思，先查閱字典。"},{"en":"The students consulted their teacher about the difficult project.","zh":"學生們就這個困難的專題向老師請教。"}]},{"word":"consume","pos":"v.","phonetic":"[kənˋsjum]","meaning":"消耗；食用","definition":"to eat, drink, or use up a resource","collocations":["consume energy","consume food","consume resources"],"example":"Large cars consume a lot of fuel.","exampleZh":"大型汽車消耗很多燃料。","synonyms":["use up","eat"],"level":5,"theme":"商業與金錢","examples":[{"en":"Large cars consume a lot of fuel.","zh":"大型汽車消耗很多燃料。"},{"en":"Air conditioners consume a lot of energy during the hot summer.","zh":"冷氣在炎熱的夏天會消耗大量能源。"},{"en":"Teenagers should not consume too many sugary drinks.","zh":"青少年不應該喝太多含糖飲料。"}]},{"word":"contact","pos":"n. / v.","phonetic":"[ˋkɑntækt]","meaning":"接觸；聯絡","definition":"communication with someone, or to communicate with someone","collocations":["contact information","stay in contact","contact the office"],"example":"Please contact us if you have any questions.","exampleZh":"如果有任何問題，請聯絡我們。","synonyms":["reach","touch"],"level":3,"theme":"溝通與語言","examples":[{"en":"Please contact us if you have any questions.","zh":"如果有任何問題，請聯絡我們。"},{"en":"Please leave your contact information so we can reach you later.","zh":"請留下你的聯絡資訊，以便我們稍後能聯繫你。"},{"en":"The two old friends still stay in contact through letters.","zh":"這兩位老朋友仍透過書信保持聯絡。"}]},{"word":"contain","pos":"v.","phonetic":"[kənˋten]","meaning":"包含；容納","definition":"to hold or include something within itself","collocations":["contain information","the box contains","contain emotions"],"example":"This drink contains a lot of sugar.","exampleZh":"這種飲料含有很多糖分。","synonyms":["include","hold"],"level":3,"theme":"性質與描述","examples":[{"en":"This drink contains a lot of sugar.","zh":"這種飲料含有很多糖分。"},{"en":"This booklet contains all the information you need for the trip.","zh":"這本小冊子包含你這趟旅行所需的所有資訊。"},{"en":"The old box contains photographs from my grandmother's childhood.","zh":"這個舊盒子裝著我奶奶童年時的照片。"}]},{"word":"container","pos":"n.","phonetic":"[kənˋtenɚ]","meaning":"容器；貨櫃","definition":"an object used for holding or transporting things","collocations":["a plastic container","a shipping container","food container"],"example":"She stored the leftovers in a plastic container.","exampleZh":"她把剩菜裝進塑膠容器裡。","synonyms":["box"],"level":3,"theme":"居家與生活","examples":[{"en":"She stored the leftovers in a plastic container.","zh":"她把剩菜裝進塑膠容器裡。"},{"en":"She kept the fresh cookies in an airtight plastic container.","zh":"她把新鮮的餅乾放在密封的塑膠容器裡。"},{"en":"Huge shipping containers were stacked neatly at the busy port.","zh":"巨大的貨櫃在繁忙的港口整齊地堆疊著。"}]},{"word":"contemporary","pos":"adj.","phonetic":"[kənˋtɛmpə͵rɛrɪ]","meaning":"當代的；同時代的","definition":"belonging to the present time, or existing at the same period","collocations":["contemporary art","contemporary society","a contemporary of"],"example":"The museum displays works of contemporary art.","exampleZh":"這間博物館展出當代藝術作品。","synonyms":["modern"],"level":6,"theme":"藝術與音樂","examples":[{"en":"The museum displays works of contemporary art.","zh":"這間博物館展出當代藝術作品。"},{"en":"The gallery is famous for its bold pieces of contemporary art.","zh":"這間畫廊以其大膽的當代藝術作品而聞名。"},{"en":"Technology plays a huge role in contemporary society.","zh":"科技在當代社會中扮演著重要的角色。"}]},{"word":"content","pos":"n. / adj.","phonetic":"[ˋkɑntɛnt]","meaning":"內容；滿足的","definition":"the material contained in something, or feeling satisfied","collocations":["table of contents","content with life","online content"],"example":"He seems content with his simple lifestyle.","exampleZh":"他似乎對自己簡樸的生活方式感到滿足。","synonyms":["satisfied"],"level":4,"theme":"情緒與感受","examples":[{"en":"He seems content with his simple lifestyle.","zh":"他似乎對自己簡樸的生活方式感到滿足。"},{"en":"Check the table of contents to find the chapter you need.","zh":"查看目錄就能找到你需要的章節。"},{"en":"My grandfather feels content with his quiet life in the countryside.","zh":"我爺爺對他在鄉下的寧靜生活感到滿足。"}]},{"word":"contest","pos":"n.","phonetic":"[ˋkɑntɛst]","meaning":"競賽；比賽","definition":"a competition in which people try to win a prize","collocations":["a singing contest","enter a contest","win a contest"],"example":"She won first prize in the speech contest.","exampleZh":"她在演講比賽中贏得第一名。","synonyms":["competition"],"level":3,"theme":"運動與休閒","examples":[{"en":"She won first prize in the speech contest.","zh":"她在演講比賽中贏得第一名。"},{"en":"She practiced every day to enter the national singing contest.","zh":"她每天練習，為了參加全國歌唱比賽。"},{"en":"The two teams competed fiercely to win the science contest.","zh":"兩支隊伍激烈競爭，想贏得這場科學競賽。"}]},{"word":"context","pos":"n.","phonetic":"[ˋkɑntɛkst]","meaning":"背景；上下文","definition":"the circumstances or setting in which something occurs","collocations":["historical context","out of context","in this context"],"example":"You need to read the whole context to understand the joke.","exampleZh":"你需要讀完整段上下文才能理解這個笑話。","synonyms":["background"],"level":5,"theme":"溝通與語言","examples":[{"en":"You need to read the whole context to understand the joke.","zh":"你需要讀完整段上下文才能理解這個笑話。"},{"en":"You can often guess a word's meaning from its context.","zh":"你常常可以從上下文猜出一個字的意思。"},{"en":"Understanding the historical context makes the novel easier to enjoy.","zh":"了解歷史背景會讓這本小說更容易欣賞。"}]},{"word":"continent","pos":"n.","phonetic":"[ˋkɑntənənt]","meaning":"大陸；洲","definition":"one of the world's main large landmasses","collocations":["the African continent","across the continent"],"example":"Africa is the second largest continent in the world.","exampleZh":"非洲是世界上第二大的洲。","synonyms":[],"level":3,"theme":"自然與環境","examples":[{"en":"Africa is the second largest continent in the world.","zh":"非洲是世界上第二大的洲。"},{"en":"Antarctica is the coldest continent on Earth.","zh":"南極洲是地球上最寒冷的大陸。"},{"en":"The explorers traveled across the entire continent by train.","zh":"探險家們搭火車橫越了整個大陸。"}]},{"word":"continue","pos":"v.","phonetic":"[kənˋtɪnju]","meaning":"繼續","definition":"to keep doing something or keep happening without stopping","collocations":["continue to grow","continue reading","continue a tradition"],"example":"They continued walking despite the heavy rain.","exampleZh":"儘管下著大雨，他們仍繼續走路。","synonyms":["carry on"],"level":2,"theme":"動作與行為","examples":[{"en":"They continued walking despite the heavy rain.","zh":"儘管下著大雨，他們仍繼續走路。"},{"en":"The city's population will continue to grow over the next decade.","zh":"這座城市的人口在未來十年將持續成長。"},{"en":"Our family continues the tradition of making dumplings every New Year.","zh":"我們家延續著每年過年包餃子的傳統。"}]},{"word":"contract","pos":"n.","phonetic":"[ˋkɑntrækt]","meaning":"合約；契約","definition":"a written legal agreement between two or more parties","collocations":["sign a contract","break a contract","a work contract"],"example":"Both companies signed a contract yesterday.","exampleZh":"兩家公司昨天簽了合約。","synonyms":["agreement"],"level":5,"theme":"商業與金錢","examples":[{"en":"Both companies signed a contract yesterday.","zh":"兩家公司昨天簽了合約。"},{"en":"The singer signed a contract to record three new albums.","zh":"那位歌手簽了一份合約，要錄製三張新專輯。"},{"en":"Breaking a contract can lead to serious legal trouble.","zh":"違反合約可能會導致嚴重的法律問題。"}]},{"word":"contribute","pos":"v.","phonetic":"[kənˋtrɪbjut]","meaning":"貢獻；捐助","definition":"to give something, such as money, time, or ideas, to help achieve something","collocations":["contribute to society","contribute money","contribute an idea"],"example":"Everyone in the group contributed ideas for the project.","exampleZh":"小組裡的每個人都為這個專案貢獻了想法。","synonyms":["donate"],"level":5,"theme":"社會與文化","examples":[{"en":"Everyone in the group contributed ideas for the project.","zh":"小組裡的每個人都為這個專案貢獻了想法。"},{"en":"Volunteers contribute their time to help the elderly in the community.","zh":"志工們付出時間幫助社區裡的長者。"},{"en":"Every student was asked to contribute an idea for the school festival.","zh":"每位學生都被要求為校慶提供一個點子。"}]},{"word":"crab","pos":"n.","phonetic":"[kræb]","meaning":"螃蟹","definition":"a sea creature with a hard shell and ten legs, the front two with claws","collocations":["catch crabs","crab meat","hermit crab"],"example":"We caught several crabs on the beach.","exampleZh":"我們在海灘上抓到了幾隻螃蟹。","synonyms":[],"level":2,"theme":"動物與植物","examples":[{"en":"We caught several crabs on the beach.","zh":"我們在海灘上抓到了幾隻螃蟹。"},{"en":"We watched a tiny hermit crab crawl across the wet sand.","zh":"我們看著一隻小寄居蟹爬過濕濕的沙灘。"},{"en":"The soup was full of sweet, fresh crab meat.","zh":"這碗湯裡滿是鮮甜的蟹肉。"}]},{"word":"crack","pos":"v. / n.","phonetic":"[kræk]","meaning":"裂開；破裂；裂縫","definition":"to break without separating into parts, or a line on a surface where it has broken","collocations":["crack a joke","crack an egg","a crack in the wall"],"example":"There is a crack in the window glass.","exampleZh":"窗戶玻璃上有一道裂縫。","synonyms":["split","break"],"level":2,"theme":"性質與描述","examples":[{"en":"There is a crack in the window glass.","zh":"窗戶玻璃上有一道裂縫。"},{"en":"There is a thin crack in the wall after the earthquake.","zh":"地震後牆上出現了一道細細的裂縫。"},{"en":"He cracked two eggs into the bowl and began to stir.","zh":"他把兩顆蛋打進碗裡，開始攪拌。"}]},{"word":"cracker","pos":"n.","phonetic":"[ˈkrækɚ]","meaning":"薄脆餅乾","definition":"a thin, crisp biscuit, often eaten with cheese","collocations":["cheese and crackers","a box of crackers"],"example":"She spread cheese on a cracker.","exampleZh":"她在餅乾上塗了乳酪。","synonyms":["biscuit"],"level":2,"theme":"食物與烹飪","examples":[{"en":"She spread cheese on a cracker.","zh":"她在餅乾上塗了乳酪。"},{"en":"We served cheese and crackers to the guests before dinner.","zh":"我們在晚餐前招待客人吃起司和薄脆餅乾。"},{"en":"She opened a fresh box of crackers for the afternoon snack.","zh":"她打開一盒新的薄脆餅乾當作下午的點心。"}]},{"word":"cradle","pos":"n. / v.","phonetic":"[ˈkredl̩]","meaning":"搖籃；發源地；輕輕抱住","definition":"a small bed for a baby that can be rocked from side to side","collocations":["rock the cradle","cradle of civilization","cradle a baby"],"example":"The mother gently rocked the cradle.","exampleZh":"媽媽輕輕地搖著搖籃。","synonyms":["crib"],"level":3,"theme":"居家與生活","examples":[{"en":"The mother gently rocked the cradle.","zh":"媽媽輕輕地搖著搖籃。"},{"en":"The nurse gently cradled the newborn baby in her arms.","zh":"護士輕輕地把新生兒抱在懷裡。"},{"en":"Egypt is often called a cradle of ancient civilization.","zh":"埃及常被稱為古代文明的搖籃。"}]},{"word":"craft","pos":"n. / v.","phonetic":"[kræft]","meaning":"工藝；技藝；精心製作","definition":"an activity involving skill in making things by hand","collocations":["arts and crafts","craft a plan","traditional craft"],"example":"She learned the craft of pottery from her grandmother.","exampleZh":"她向祖母學習製陶的技藝。","synonyms":["skill","art"],"level":3,"theme":"藝術與音樂","examples":[{"en":"She learned the craft of pottery from her grandmother.","zh":"她向祖母學習製陶的技藝。"},{"en":"The students enjoyed the arts and crafts class on Friday afternoon.","zh":"學生們很享受週五下午的手工藝課。"},{"en":"Making paper by hand is a traditional craft in this village.","zh":"手工造紙是這個村莊的傳統工藝。"}]},{"word":"craftsman","pos":"n.","phonetic":"[ˈkræftsmən]","meaning":"工匠；手藝人","definition":"a skilled worker who makes things by hand","collocations":["skilled craftsman","master craftsman"],"example":"The old craftsman carved the wooden statue by hand.","exampleZh":"這位老工匠親手雕刻了這座木像。","synonyms":["artisan"],"level":4,"theme":"工作與職業","examples":[{"en":"The old craftsman carved the wooden statue by hand.","zh":"這位老工匠親手雕刻了這座木像。"},{"en":"A skilled craftsman spent months building the wooden bridge.","zh":"一位技術純熟的工匠花了好幾個月建造這座木橋。"},{"en":"The master craftsman taught his students how to shape metal.","zh":"那位工藝大師教學生如何塑造金屬。"}]},{"word":"cram","pos":"v.","phonetic":"[kræm]","meaning":"填塞；死記硬背；擠進","definition":"to force too many things into a small space, or to study intensively before a test","collocations":["cram for an exam","cram into a bag","cram school"],"example":"He crammed all night before the final exam.","exampleZh":"他考前熬夜死記硬背。","synonyms":["stuff","squeeze"],"level":4,"theme":"教育與學習","examples":[{"en":"He crammed all night before the final exam.","zh":"他考前熬夜死記硬背。"},{"en":"Many students go to cram school after their regular classes end.","zh":"許多學生在正規課程結束後去補習班。"},{"en":"She tried to cram all her clothes into one small suitcase.","zh":"她試圖把所有衣服都塞進一個小行李箱。"}]},{"word":"cramp","pos":"n. / v.","phonetic":"[kræmp]","meaning":"抽筋；痙攣；妨礙","definition":"a sudden painful tightening of a muscle","collocations":["stomach cramp","muscle cramp","cramp one's style"],"example":"She got a leg cramp while swimming.","exampleZh":"她游泳時腿抽筋了。","synonyms":["spasm"],"level":4,"theme":"身體與健康","examples":[{"en":"She got a leg cramp while swimming.","zh":"她游泳時腿抽筋了。"},{"en":"The runner stopped suddenly because of a painful muscle cramp.","zh":"那名跑者因為肌肉抽筋而突然停了下來。"},{"en":"Eating too fast gave him a stomach cramp during the trip.","zh":"吃得太快讓他在旅途中胃部痙攣。"}]},{"word":"crane","pos":"n.","phonetic":"[kren]","meaning":"起重機；鶴","definition":"a large machine used for lifting heavy objects, or a large water bird","collocations":["construction crane","paper crane","a flock of cranes"],"example":"The crane lifted the steel beam onto the building.","exampleZh":"起重機將鋼樑吊上了建築物。","synonyms":[],"level":3,"theme":"其他","examples":[{"en":"The crane lifted the steel beam onto the building.","zh":"起重機將鋼樑吊上了建築物。"},{"en":"She folded a hundred paper cranes to wish her friend good luck.","zh":"她摺了一百隻紙鶴，祝她的朋友好運。"},{"en":"A tall construction crane towered over the unfinished building.","zh":"一台高聳的建築起重機矗立在未完工的大樓上方。"}]},{"word":"cranky","pos":"adj.","phonetic":"[ˈkræŋkɪ]","meaning":"易怒的；脾氣壞的","definition":"easily annoyed or irritable, especially when tired","collocations":["feel cranky","cranky child"],"example":"The tired baby was cranky all afternoon.","exampleZh":"疲累的寶寶整個下午都很煩躁。","synonyms":["irritable","grumpy"],"level":4,"theme":"情緒與感受","examples":[{"en":"The tired baby was cranky all afternoon.","zh":"疲累的寶寶整個下午都很煩躁。"},{"en":"The child became cranky because he had missed his afternoon nap.","zh":"那個孩子因為沒睡午覺而變得脾氣暴躁。"},{"en":"I always feel cranky when I don't get enough sleep.","zh":"我睡眠不足時總是很容易發脾氣。"}]},{"word":"crash","pos":"v. / n.","phonetic":"[kræʃ]","meaning":"墜毀；撞毀；崩潰","definition":"to hit something violently, or a sudden violent collision","collocations":["car crash","crash into","stock market crash"],"example":"The car crashed into a tree.","exampleZh":"那輛車撞上了一棵樹。","synonyms":["collide","wreck"],"level":2,"theme":"交通與旅行","examples":[{"en":"The car crashed into a tree.","zh":"那輛車撞上了一棵樹。"},{"en":"The bus nearly crashed into a wall on the icy road.","zh":"公車在結冰的路上差點撞上一堵牆。"},{"en":"My computer suddenly crashed and I lost all my homework.","zh":"我的電腦突然當機，我所有的作業都不見了。"}]},{"word":"crater","pos":"n.","phonetic":"[ˈkretɚ]","meaning":"火山口；隕石坑","definition":"a large bowl-shaped hollow at the top of a volcano or made by an impact","collocations":["volcanic crater","impact crater"],"example":"The astronauts studied craters on the moon's surface.","exampleZh":"太空人研究了月球表面的隕石坑。","synonyms":[],"level":4,"theme":"自然與環境","examples":[{"en":"The astronauts studied craters on the moon's surface.","zh":"太空人研究了月球表面的隕石坑。"},{"en":"Hikers peered into the deep volcanic crater at the summit.","zh":"登山客們俯視著山頂那個深深的火山口。"},{"en":"The meteor left a huge impact crater in the desert.","zh":"那顆隕石在沙漠中留下了一個巨大的撞擊坑。"}]},{"word":"crawl","pos":"v. / n.","phonetic":"[krɔl]","meaning":"爬行；緩慢行進","definition":"to move slowly on hands and knees or with the body close to the ground","collocations":["crawl on all fours","crawl along","traffic crawl"],"example":"The baby crawled across the floor.","exampleZh":"嬰兒在地板上爬行。","synonyms":["creep"],"level":2,"theme":"動作與行為","examples":[{"en":"The baby crawled across the floor.","zh":"嬰兒在地板上爬行。"},{"en":"Traffic crawled slowly along the highway during the holiday.","zh":"假期間車流在高速公路上緩慢地爬行。"},{"en":"The soldier had to crawl on all fours under the low fence.","zh":"那名士兵必須用四肢爬過低矮的圍籬。"}]},{"word":"crayon","pos":"n.","phonetic":"[ˈkreən]","meaning":"蠟筆","definition":"a stick of colored wax used for drawing","collocations":["a box of crayons","color with crayons"],"example":"The child drew a sun with a yellow crayon.","exampleZh":"小孩用黃色蠟筆畫了一個太陽。","synonyms":[],"level":1,"theme":"教育與學習","examples":[{"en":"The child drew a sun with a yellow crayon.","zh":"小孩用黃色蠟筆畫了一個太陽。"},{"en":"The little boy colored the sky with a blue crayon.","zh":"那個小男孩用藍色蠟筆把天空塗上顏色。"},{"en":"She gave each child a new box of crayons for the drawing class.","zh":"她給每個孩子一盒新蠟筆上繪畫課。"}]},{"word":"crazy","pos":"adj.","phonetic":"[ˈkrezɪ]","meaning":"瘋狂的；著迷的","definition":"very foolish or strange; extremely enthusiastic about something","collocations":["crazy about","go crazy","a crazy idea"],"example":"He is crazy about basketball.","exampleZh":"他對籃球非常著迷。","synonyms":["insane","mad"],"level":1,"theme":"情緒與感受","examples":[{"en":"He is crazy about basketball.","zh":"他對籃球非常著迷。"},{"en":"My little sister is crazy about collecting stickers.","zh":"我妹妹瘋狂地迷戀收集貼紙。"},{"en":"At first it sounded like a crazy idea, but it actually worked.","zh":"一開始這聽起來像個瘋狂的點子，但它竟然成功了。"}]},{"word":"cream","pos":"n. / adj.","phonetic":"[krim]","meaning":"奶油；乳霜；乳白色的","definition":"the thick fatty part of milk, or a thick smooth substance for the skin","collocations":["whipped cream","ice cream","face cream"],"example":"She put cream in her coffee.","exampleZh":"她在咖啡裡加了奶油。","synonyms":[],"level":1,"theme":"食物與烹飪","examples":[{"en":"She put cream in her coffee.","zh":"她在咖啡裡加了奶油。"},{"en":"She topped the hot chocolate with a swirl of whipped cream.","zh":"她在熱巧克力上擠了一圈鮮奶油。"},{"en":"He painted his bedroom walls a soft cream color.","zh":"他把臥室的牆漆成柔和的乳白色。"}]},{"word":"crease","pos":"n. / v.","phonetic":"[kris]","meaning":"摺痕；皺褶；弄皺","definition":"a line made on paper or cloth by folding or pressing it","collocations":["crease in trousers","crease easily","iron out a crease"],"example":"His shirt was full of creases after the trip.","exampleZh":"旅行後他的襯衫全是皺褶。","synonyms":["wrinkle","fold"],"level":4,"theme":"服裝與外表","examples":[{"en":"His shirt was full of creases after the trip.","zh":"旅行後他的襯衫全是皺褶。"},{"en":"She ironed the shirt to remove every crease before the interview.","zh":"面試前她把襯衫熨平，去除每一道皺褶。"},{"en":"This soft fabric creases easily if you fold it tightly.","zh":"這種柔軟的布料如果摺得太緊很容易起皺。"}]},{"word":"create","pos":"v.","phonetic":"[krɪˈet]","meaning":"創造；創作；引起","definition":"to make something new to exist","collocations":["create a problem","create jobs","create art"],"example":"The artist created a beautiful painting.","exampleZh":"這位藝術家創作了一幅美麗的畫。","synonyms":["make","produce"],"level":2,"theme":"藝術與音樂","examples":[{"en":"The artist created a beautiful painting.","zh":"這位藝術家創作了一幅美麗的畫。"},{"en":"The new factory will create hundreds of jobs for the town.","zh":"這座新工廠將為小鎮創造數百個工作機會。"},{"en":"Careless words can create a big problem between friends.","zh":"不經意的話語可能會在朋友之間製造大問題。"}]},{"word":"creation","pos":"n.","phonetic":"[krɪˈeʃən]","meaning":"創造；創作物","definition":"the act of making something new, or something that has been made","collocations":["job creation","a work of creation"],"example":"The novel was his greatest creation.","exampleZh":"這部小說是他最偉大的創作。","synonyms":["invention"],"level":3,"theme":"藝術與音樂","examples":[{"en":"The novel was his greatest creation.","zh":"這部小說是他最偉大的創作。"},{"en":"The government focused on job creation to help young people.","zh":"政府著重於創造就業機會來幫助年輕人。"},{"en":"The chef proudly showed us his latest dessert creation.","zh":"那位廚師驕傲地向我們展示他最新的甜點創作。"}]},{"word":"creative","pos":"adj.","phonetic":"[krɪˈetɪv]","meaning":"有創意的；創造性的","definition":"having or showing an ability to make new things or think of new ideas","collocations":["creative writing","creative thinking","a creative solution"],"example":"She is very creative when it comes to solving problems.","exampleZh":"在解決問題方面她非常有創意。","synonyms":["imaginative","inventive"],"level":3,"theme":"性質與描述","examples":[{"en":"She is very creative when it comes to solving problems.","zh":"在解決問題方面她非常有創意。"},{"en":"Our teacher encourages creative thinking during every lesson.","zh":"我們的老師在每堂課都鼓勵創意思考。"},{"en":"The team found a creative solution to the recycling problem.","zh":"這個團隊為回收問題找到了一個有創意的解決方法。"}]},{"word":"creativity","pos":"n.","phonetic":"[ˌkrieˈtɪvətɪ]","meaning":"創造力；創意","definition":"the ability to produce original and unusual ideas","collocations":["encourage creativity","artistic creativity"],"example":"The teacher encouraged creativity in the classroom.","exampleZh":"老師鼓勵學生在課堂上發揮創造力。","synonyms":["inventiveness"],"level":4,"theme":"抽象概念","examples":[{"en":"The teacher encouraged creativity in the classroom.","zh":"老師鼓勵學生在課堂上發揮創造力。"},{"en":"Painting freely can help children develop their creativity.","zh":"自由作畫可以幫助孩子培養創造力。"},{"en":"The art contest is a great way to show your creativity.","zh":"這場美術比賽是展現創造力的好機會。"}]},{"word":"creator","pos":"n.","phonetic":"[kriˈetɚ]","meaning":"創造者；創作者","definition":"a person who makes or invents something","collocations":["the creator of","content creator"],"example":"He is the creator of this popular app.","exampleZh":"他是這款熱門應用程式的創作者。","synonyms":["inventor","maker"],"level":4,"theme":"工作與職業","examples":[{"en":"He is the creator of this popular app.","zh":"他是這款熱門應用程式的創作者。"},{"en":"She dreams of becoming a famous content creator online.","zh":"她夢想成為網路上有名的內容創作者。"},{"en":"Everyone praised the creator of this clever board game.","zh":"大家都稱讚這款巧妙桌遊的創作者。"}]},{"word":"creature","pos":"n.","phonetic":"[ˈkritʃɚ]","meaning":"生物；動物","definition":"a living being, especially an animal","collocations":["living creature","sea creature","strange creature"],"example":"Whales are amazing creatures of the sea.","exampleZh":"鯨魚是海洋中令人驚嘆的生物。","synonyms":["animal","being"],"level":3,"theme":"動物與植物","examples":[{"en":"Whales are amazing creatures of the sea.","zh":"鯨魚是海洋中令人驚嘆的生物。"},{"en":"Every living creature needs clean water to survive.","zh":"每一種生物都需要乾淨的水才能生存。"},{"en":"Divers discovered a strange sea creature deep in the ocean.","zh":"潛水員在深海中發現了一種奇特的海洋生物。"}]},{"word":"credible","pos":"adj.","phonetic":"[ˈkrɛdəbl̩]","meaning":"可信的；可靠的","definition":"able to be believed or trusted","collocations":["credible source","credible evidence"],"example":"The reporter found a credible witness.","exampleZh":"記者找到了一位可信的目擊者。","synonyms":["believable","reliable"],"level":5,"theme":"抽象概念","examples":[{"en":"The reporter found a credible witness.","zh":"記者找到了一位可信的目擊者。"},{"en":"Always check that the news comes from a credible source.","zh":"一定要確認新聞來自可信的來源。"},{"en":"The lawyer needed credible evidence to prove her case.","zh":"律師需要可信的證據來證明她的論點。"}]},{"word":"credit","pos":"n. / v.","phonetic":"[ˈkrɛdɪt]","meaning":"信用；學分；歸功於","definition":"the ability to buy something now and pay later; recognition for an achievement","collocations":["credit card","take credit for","school credit"],"example":"He paid for the trip with a credit card.","exampleZh":"他用信用卡支付了這趟旅行的費用。","synonyms":[],"level":3,"theme":"商業與金錢","examples":[{"en":"He paid for the trip with a credit card.","zh":"他用信用卡支付了這趟旅行的費用。"},{"en":"You can earn extra school credit by joining the science club.","zh":"參加科學社可以獲得額外的學分。"},{"en":"He always takes credit for work that others have done.","zh":"他總是把別人做的工作歸功於自己。"}]},{"word":"creek","pos":"n.","phonetic":"[krik]","meaning":"小溪；小河","definition":"a small stream or narrow river","collocations":["a babbling creek","cross a creek"],"example":"The children played by the creek all afternoon.","exampleZh":"孩子們整個下午都在小溪邊玩耍。","synonyms":["stream","brook"],"level":3,"theme":"自然與環境","examples":[{"en":"The children played by the creek all afternoon.","zh":"孩子們整個下午都在小溪邊玩耍。"},{"en":"We crossed a shallow creek on our way to the campsite.","zh":"我們在前往營地的路上涉過一條淺淺的小溪。"},{"en":"The babbling creek made a gentle sound through the forest.","zh":"潺潺的小溪在森林中發出輕柔的聲音。"}]},{"word":"creep","pos":"v.","phonetic":"[krip]","meaning":"悄悄地移動；蔓延","definition":"to move slowly and carefully to avoid being seen or heard","collocations":["creep up on","creep along","fear creeps in"],"example":"The cat crept silently toward the bird.","exampleZh":"貓悄悄地朝鳥爬過去。","synonyms":["crawl","sneak"],"level":4,"theme":"動作與行為","examples":[{"en":"The cat crept silently toward the bird.","zh":"貓悄悄地朝鳥爬過去。"},{"en":"The thief tried to creep up on the sleeping guard.","zh":"小偷試圖悄悄地靠近熟睡的警衛。"},{"en":"A feeling of fear slowly crept into her heart in the dark.","zh":"在黑暗中，一股恐懼慢慢爬進她的心裡。"}]},{"word":"crescent","pos":"n. / adj.","phonetic":"[ˈkrɛsn̩t]","meaning":"新月；新月形的","definition":"a curved shape like the moon in its first or last quarter","collocations":["crescent moon","crescent shape"],"example":"A thin crescent moon hung in the night sky.","exampleZh":"一輪細細的新月掛在夜空中。","synonyms":[],"level":5,"theme":"自然與環境","examples":[{"en":"A thin crescent moon hung in the night sky.","zh":"一輪細細的新月掛在夜空中。"},{"en":"A silver crescent moon appeared above the quiet hills.","zh":"一彎銀色的新月出現在寧靜的山丘上方。"},{"en":"The baker shaped the dough into a crescent before baking.","zh":"烘焙師在烘烤前把麵團塑成新月形。"}]},{"word":"crevice","pos":"n.","phonetic":"[ˈkrɛvɪs]","meaning":"裂縫；縫隙","definition":"a narrow crack or gap, especially in rock","collocations":["a deep crevice","hide in a crevice"],"example":"A small plant grew from a crevice in the rock.","exampleZh":"一株小植物從岩石的裂縫中長出來。","synonyms":["crack","gap"],"level":6,"theme":"自然與環境","examples":[{"en":"A small plant grew from a crevice in the rock.","zh":"一株小植物從岩石的裂縫中長出來。"},{"en":"A tiny lizard quickly hid in a crevice between the rocks.","zh":"一隻小蜥蜴迅速躲進岩石間的縫隙裡。"},{"en":"Water seeped into a deep crevice on the mountain wall.","zh":"水滲入了山壁上一道深深的裂縫。"}]},{"word":"crew","pos":"n.","phonetic":"[kru]","meaning":"全體船員；工作團隊","definition":"a group of people who work together, especially on a ship, plane, or film","collocations":["ship's crew","film crew","flight crew"],"example":"The plane's crew welcomed the passengers on board.","exampleZh":"飛機的機組人員歡迎乘客登機。","synonyms":["team","staff"],"level":3,"theme":"工作與職業","examples":[{"en":"The plane's crew welcomed the passengers on board.","zh":"飛機的機組人員歡迎乘客登機。"},{"en":"The film crew worked late into the night to finish the scene.","zh":"攝製團隊工作到深夜才拍完這一幕。"},{"en":"The ship's crew prepared the boat before it left the harbor.","zh":"船員們在船離港前做好了準備。"}]},{"word":"crib","pos":"n.","phonetic":"[krɪb]","meaning":"嬰兒床","definition":"a small bed with high sides for a baby","collocations":["baby crib","put the baby in the crib"],"example":"The baby fell asleep in her crib.","exampleZh":"寶寶在嬰兒床裡睡著了。","synonyms":["cradle"],"level":3,"theme":"居家與生活","examples":[{"en":"The baby fell asleep in her crib.","zh":"寶寶在嬰兒床裡睡著了。"},{"en":"She gently put the sleeping baby into the crib.","zh":"她輕輕地把熟睡的寶寶放進嬰兒床。"},{"en":"They painted the new crib a soft shade of yellow.","zh":"他們把新的嬰兒床漆成柔和的黃色。"}]},{"word":"cricket","pos":"n.","phonetic":"[ˈkrɪkɪt]","meaning":"蟋蟀；板球運動","definition":"a small jumping insect that makes a chirping sound, or a bat-and-ball sport","collocations":["play cricket","cricket match","chirping crickets"],"example":"We could hear crickets chirping outside at night.","exampleZh":"晚上我們可以聽到外面蟋蟀的鳴叫聲。","synonyms":[],"level":3,"theme":"動物與植物","examples":[{"en":"We could hear crickets chirping outside at night.","zh":"晚上我們可以聽到外面蟋蟀的鳴叫聲。"},{"en":"On summer nights, the chirping crickets fill the garden with sound.","zh":"在夏夜裡，鳴叫的蟋蟀讓花園充滿聲音。"},{"en":"The boys spent the whole afternoon playing cricket in the park.","zh":"男孩們整個下午都在公園裡打板球。"}]},{"word":"crime","pos":"n.","phonetic":"[kraɪm]","meaning":"罪行；犯罪","definition":"an action that is against the law","collocations":["commit a crime","crime rate","organized crime"],"example":"The police are investigating a serious crime.","exampleZh":"警方正在調查一起嚴重的犯罪案件。","synonyms":["offense"],"level":3,"theme":"政治與法律","examples":[{"en":"The police are investigating a serious crime.","zh":"警方正在調查一起嚴重的犯罪案件。"},{"en":"The crime rate in this quiet town is very low.","zh":"這個寧靜小鎮的犯罪率非常低。"},{"en":"Stealing from others is a serious crime.","zh":"偷竊他人財物是嚴重的罪行。"}]},{"word":"criminal","pos":"n. / adj.","phonetic":"[ˈkrɪmənl̩]","meaning":"罪犯；犯罪的","definition":"a person who commits a crime, or relating to crime","collocations":["criminal record","criminal case","catch a criminal"],"example":"The criminal was arrested by the police.","exampleZh":"這名罪犯被警方逮捕了。","synonyms":["offender"],"level":4,"theme":"政治與法律","examples":[{"en":"The criminal was arrested by the police.","zh":"這名罪犯被警方逮捕了。"},{"en":"The police worked hard to catch the dangerous criminal.","zh":"警方努力追捕這名危險的罪犯。"},{"en":"A person with a criminal record may find it hard to get a job.","zh":"有犯罪紀錄的人可能很難找到工作。"}]},{"word":"cripple","pos":"v.","phonetic":"[ˈkrɪpl̩]","meaning":"使殘廢；嚴重損害","definition":"to severely damage or weaken something, or to disable a person physically","collocations":["cripple the economy","crippled by injury"],"example":"The strike crippled the country's transportation system.","exampleZh":"這場罷工嚴重癱瘓了該國的交通系統。","synonyms":["disable","weaken"],"level":6,"theme":"抽象概念","examples":[{"en":"The strike crippled the country's transportation system.","zh":"這場罷工嚴重癱瘓了該國的交通系統。"},{"en":"The sudden flood crippled the town's water supply for days.","zh":"這場突如其來的洪水使小鎮的供水系統癱瘓了好幾天。"},{"en":"The athlete was crippled by a serious knee injury last year.","zh":"那名運動員去年因嚴重的膝傷而無法再運動。"}]},{"word":"crisis","pos":"n.","phonetic":"[ˈkraɪsɪs]","meaning":"危機；緊要關頭","definition":"a time of great danger, difficulty, or confusion","collocations":["financial crisis","crisis management","face a crisis"],"example":"The company faced a serious financial crisis.","exampleZh":"這家公司面臨了嚴重的財務危機。","synonyms":["emergency"],"level":4,"theme":"抽象概念","examples":[{"en":"The company faced a serious financial crisis.","zh":"這家公司面臨了嚴重的財務危機。"},{"en":"During the water crisis, everyone was asked to save every drop.","zh":"在缺水危機期間，每個人都被要求節省每一滴水。"},{"en":"The country slowly recovered from the financial crisis.","zh":"這個國家慢慢從金融危機中復甦。"}]},{"word":"crisp","pos":"adj.","phonetic":"[krɪsp]","meaning":"脆的；清新的；乾脆的","definition":"firm, dry, and easily broken; pleasantly fresh and cool","collocations":["crisp apple","crisp morning air","crisp bacon"],"example":"The autumn air was cool and crisp.","exampleZh":"秋天的空氣涼爽而清新。","synonyms":["crunchy"],"level":4,"theme":"性質與描述","examples":[{"en":"The autumn air was cool and crisp.","zh":"秋天的空氣涼爽而清新。"},{"en":"She bit into a fresh, crisp apple from the orchard.","zh":"她咬了一口果園裡新鮮又爽脆的蘋果。"},{"en":"We went for a walk to enjoy the crisp morning air.","zh":"我們去散步，享受清新的晨間空氣。"}]},{"word":"crisscross","pos":"v. / adj.","phonetic":"[ˈkrɪsˌkrɔs]","meaning":"交叉；縱橫交錯的","definition":"to move or lie across something in different directions, forming a pattern of crossed lines","collocations":["crisscross pattern","roads crisscross the city"],"example":"Paths crisscross through the park.","exampleZh":"小徑在公園裡交錯縱橫。","synonyms":[],"level":5,"theme":"性質與描述","examples":[{"en":"Paths crisscross through the park.","zh":"小徑在公園裡交錯縱橫。"},{"en":"Narrow canals crisscross the old part of the town.","zh":"狹窄的運河縱橫交錯於這座城鎮的古老區域。"},{"en":"She wove the ribbons into a colorful crisscross pattern.","zh":"她把緞帶編織成色彩繽紛的交叉圖案。"}]},{"word":"critic","pos":"n.","phonetic":"[ˈkrɪtɪk]","meaning":"評論家；批評者","definition":"a person who gives opinions about the good and bad qualities of something","collocations":["film critic","harsh critic","art critic"],"example":"The food critic praised the new restaurant.","exampleZh":"這位美食評論家稱讚了這家新餐廳。","synonyms":["reviewer"],"level":4,"theme":"藝術與音樂","examples":[{"en":"The food critic praised the new restaurant.","zh":"這位美食評論家稱讚了這家新餐廳。"},{"en":"A famous film critic wrote a glowing review of the movie.","zh":"一位知名的影評家為這部電影寫了一篇讚不絕口的評論。"},{"en":"She is her own harshest critic when it comes to painting.","zh":"談到繪畫，她是自己最嚴厲的批評者。"}]},{"word":"critical","pos":"adj.","phonetic":"[ˈkrɪtɪkl̩]","meaning":"批評的；關鍵的；危急的","definition":"expressing disapproval, or extremely important, or very serious","collocations":["critical thinking","critical condition","a critical moment"],"example":"The patient is in critical condition.","exampleZh":"這位病人情況危急。","synonyms":["crucial","vital"],"level":4,"theme":"性質與描述","examples":[{"en":"The patient is in critical condition.","zh":"這位病人情況危急。"},{"en":"Critical thinking helps students judge information more wisely.","zh":"批判性思考幫助學生更明智地判斷資訊。"},{"en":"The final penalty came at a critical moment in the match.","zh":"那記關鍵的罰球出現在比賽的緊要關頭。"}]},{"word":"criticism","pos":"n.","phonetic":"[ˈkrɪtəˌsɪzəm]","meaning":"批評;評論","definition":"the act of expressing disapproval or pointing out faults","collocations":["harsh criticism","constructive criticism","face criticism"],"example":"He accepted the criticism calmly.","exampleZh":"他冷靜地接受了批評。","synonyms":["disapproval"],"level":4,"theme":"溝通與語言","examples":[{"en":"He accepted the criticism calmly.","zh":"他冷靜地接受了批評。"},{"en":"Constructive criticism can help you improve your writing.","zh":"建設性的批評能幫助你改進你的寫作。"},{"en":"The young author faced harsh criticism for her first novel.","zh":"這位年輕作家的第一部小說受到嚴厲的批評。"}]},{"word":"criticize","pos":"v.","phonetic":"[ˈkrɪtəˌsaɪz]","meaning":"批評；指責","definition":"to express disapproval of someone or something","collocations":["criticize harshly","criticize a decision"],"example":"The teacher criticized his careless mistakes.","exampleZh":"老師批評了他的粗心錯誤。","synonyms":["condemn","blame"],"level":4,"theme":"溝通與語言","examples":[{"en":"The teacher criticized his careless mistakes.","zh":"老師批評了他的粗心錯誤。"},{"en":"It is easy to criticize others, but harder to praise them.","zh":"批評別人很容易，稱讚別人卻比較難。"},{"en":"Many people criticized the decision to close the old library.","zh":"許多人批評關閉那座舊圖書館的決定。"}]},{"word":"crocodile","pos":"n.","phonetic":"[ˈkrɑkəˌdaɪl]","meaning":"鱷魚","definition":"a large reptile with a long body and strong jaws that lives in rivers and lakes","collocations":["crocodile tears","crocodile skin"],"example":"A crocodile was resting by the riverbank.","exampleZh":"一隻鱷魚正在河岸邊休息。","synonyms":[],"level":2,"theme":"動物與植物","examples":[{"en":"A crocodile was resting by the riverbank.","zh":"一隻鱷魚正在河岸邊休息。"},{"en":"A huge crocodile lay silently at the edge of the muddy river.","zh":"一隻巨大的鱷魚靜靜地趴在泥濘的河邊。"},{"en":"She cried crocodile tears to avoid getting into trouble.","zh":"她假惺惺地流下鱷魚的眼淚，以免惹上麻煩。"}]},{"word":"crop","pos":"n. / v.","phonetic":"[krɑp]","meaning":"農作物；收成；剪裁","definition":"a plant grown in large amounts, especially for food","collocations":["harvest a crop","crop rotation","crop failure"],"example":"Farmers harvested the rice crop in autumn.","exampleZh":"農夫在秋天收割了稻米。","synonyms":["harvest"],"level":3,"theme":"自然與環境","examples":[{"en":"Farmers harvested the rice crop in autumn.","zh":"農夫在秋天收割了稻米。"},{"en":"Heavy rain destroyed most of the farmers' rice crop this year.","zh":"今年的大雨毀掉了農民大部分的稻作。"},{"en":"Farmers use crop rotation to keep the soil healthy.","zh":"農民利用輪作來保持土壤健康。"}]},{"word":"cross","pos":"v. / adj. / n.","phonetic":"[krɔs]","meaning":"穿越；生氣的；十字架","definition":"to go from one side to the other, or angry, or a mark shaped like a plus sign","collocations":["cross the street","cross one's arms","get cross with"],"example":"Look both ways before you cross the street.","exampleZh":"過馬路前要看清左右來車。","synonyms":["angry"],"level":1,"theme":"交通與旅行","examples":[{"en":"Look both ways before you cross the street.","zh":"過馬路前要看清左右來車。"},{"en":"The teacher looked quite cross when nobody had finished the homework.","zh":"當沒有人完成作業時，老師看起來相當生氣。"},{"en":"Always wait for the green light before you cross a wide road.","zh":"過寬闊的馬路前一定要等綠燈。"}]},{"word":"crossroad","pos":"n.","phonetic":"[ˈkrɔsˌrod]","meaning":"十字路口；抉擇點","definition":"a place where two roads meet, or a moment of important decision","collocations":["at a crossroad","reach a crossroad"],"example":"She stood at a crossroad in her career.","exampleZh":"她正處於職涯的抉擇點。","synonyms":["intersection"],"level":4,"theme":"時間與空間","examples":[{"en":"She stood at a crossroad in her career.","zh":"她正處於職涯的抉擇點。"},{"en":"After graduation, many students stand at a crossroad in life.","zh":"畢業後，許多學生站在人生的抉擇點上。"},{"en":"We reached a crossroad and were not sure which way to turn.","zh":"我們來到一個十字路口，不確定該往哪個方向走。"}]},{"word":"crossword","pos":"n.","phonetic":"[ˈkrɔsˌwɝd]","meaning":"填字遊戲","definition":"a puzzle in which words are guessed and written into a grid of squares","collocations":["solve a crossword","crossword puzzle"],"example":"He does a crossword puzzle every morning.","exampleZh":"他每天早上都會做填字遊戲。","synonyms":[],"level":3,"theme":"運動與休閒","examples":[{"en":"He does a crossword puzzle every morning.","zh":"他每天早上都會做填字遊戲。"},{"en":"My grandmother loves to solve a crossword with her morning tea.","zh":"我奶奶喜歡一邊喝早茶一邊玩填字遊戲。"},{"en":"This crossword puzzle is too difficult for me to finish alone.","zh":"這個填字遊戲太難了，我一個人無法完成。"}]},{"word":"crouch","pos":"v.","phonetic":"[kraʊtʃ]","meaning":"蹲伏；蹲下","definition":"to lower the body close to the ground by bending the knees","collocations":["crouch down","crouch behind"],"example":"He crouched behind the wall to hide.","exampleZh":"他蹲在牆後躲藏。","synonyms":["squat"],"level":5,"theme":"動作與行為","examples":[{"en":"He crouched behind the wall to hide.","zh":"他蹲在牆後躲藏。"},{"en":"The photographer crouched down to take a picture of the flower.","zh":"攝影師蹲下來為那朵花拍照。"},{"en":"The children crouched behind the sofa during the game of hide-and-seek.","zh":"孩子們在捉迷藏時蹲在沙發後面。"}]},{"word":"crow","pos":"n. / v.","phonetic":"[kro]","meaning":"烏鴉；(公雞)啼叫","definition":"a large black bird with a loud harsh call","collocations":["a flock of crows","crow's nest","the rooster crows"],"example":"A crow perched on the tree branch.","exampleZh":"一隻烏鴉停在樹枝上。","synonyms":[],"level":3,"theme":"動物與植物","examples":[{"en":"A crow perched on the tree branch.","zh":"一隻烏鴉停在樹枝上。"},{"en":"A flock of crows flew noisily over the empty field.","zh":"一群烏鴉吵鬧地飛過空曠的田野。"},{"en":"The rooster crows loudly every morning at sunrise.","zh":"公雞每天早上日出時大聲啼叫。"}]},{"word":"crowd","pos":"n. / v.","phonetic":"[kraʊd]","meaning":"人群；擠滿","definition":"a large group of people gathered together","collocations":["a large crowd","crowd around","avoid crowds"],"example":"A huge crowd gathered to watch the concert.","exampleZh":"大批人群聚集觀看演唱會。","synonyms":["mob"],"level":2,"theme":"社會與文化","examples":[{"en":"A huge crowd gathered to watch the concert.","zh":"大批人群聚集觀看演唱會。"},{"en":"Fans began to crowd around the singer after the show.","zh":"表演結束後，粉絲開始圍在歌手身邊。"},{"en":"She prefers to shop early to avoid the weekend crowds.","zh":"她喜歡提早購物，以避開週末的人潮。"}]},{"word":"crowded","pos":"adj.","phonetic":"[ˈkraʊdɪd]","meaning":"擁擠的","definition":"completely filled with people or things","collocations":["crowded street","crowded bus"],"example":"The train was too crowded to find a seat.","exampleZh":"火車太擁擠了，找不到座位。","synonyms":["packed"],"level":2,"theme":"性質與描述","examples":[{"en":"The train was too crowded to find a seat.","zh":"火車太擁擠了，找不到座位。"},{"en":"The night market was so crowded that we could hardly walk.","zh":"夜市太擁擠了，我們幾乎走不動。"},{"en":"She missed her stop on the crowded bus this morning.","zh":"今天早上她在擁擠的公車上坐過了站。"}]},{"word":"crown","pos":"n. / v.","phonetic":"[kraʊn]","meaning":"王冠；加冕","definition":"a circular ornament worn on the head by a king or queen","collocations":["wear a crown","crown a king"],"example":"The king wore a golden crown.","exampleZh":"國王戴著一頂金色的王冠。","synonyms":[],"level":3,"theme":"社會與文化","examples":[{"en":"The king wore a golden crown.","zh":"國王戴著一頂金色的王冠。"},{"en":"The young prince will be crowned king next spring.","zh":"這位年輕的王子將於明年春天加冕為國王。"},{"en":"In the school play, she wore a shiny paper crown.","zh":"在學校話劇中，她戴著一頂閃亮的紙王冠。"}]},{"word":"crucial","pos":"adj.","phonetic":"[ˈkruʃəl]","meaning":"關鍵的；決定性的","definition":"extremely important because it will affect other things","collocations":["crucial role","crucial decision","crucial moment"],"example":"Teamwork played a crucial role in our success.","exampleZh":"團隊合作在我們的成功中扮演了關鍵角色。","synonyms":["critical","vital"],"level":5,"theme":"抽象概念","examples":[{"en":"Teamwork played a crucial role in our success.","zh":"團隊合作在我們的成功中扮演了關鍵角色。"},{"en":"Getting enough sleep plays a crucial role in staying healthy.","zh":"充足的睡眠在保持健康方面扮演著關鍵的角色。"},{"en":"Choosing the right university is a crucial decision for many teenagers.","zh":"選擇合適的大學對許多青少年來說是個關鍵的決定。"}]},{"word":"crude","pos":"adj.","phonetic":"[krud]","meaning":"粗糙的；未加工的；粗魯的","definition":"in a natural or raw state; rough and lacking taste","collocations":["crude oil","crude manner","crude joke"],"example":"The country exports crude oil to many nations.","exampleZh":"這個國家向許多國家出口原油。","synonyms":["raw","rough"],"level":5,"theme":"性質與描述","examples":[{"en":"The country exports crude oil to many nations.","zh":"這個國家向許多國家出口原油。"},{"en":"The factory turns crude oil into fuel for cars.","zh":"這座工廠把原油加工成汽車用的燃料。"},{"en":"He built a crude shelter out of branches and leaves.","zh":"他用樹枝和樹葉搭了一個簡陋的遮蔽處。"}]},{"word":"cruel","pos":"adj.","phonetic":"[ˈkruəl]","meaning":"殘忍的；殘酷的","definition":"causing pain or suffering to others deliberately","collocations":["cruel treatment","cruel to animals"],"example":"It is cruel to leave a dog outside in the cold.","exampleZh":"在寒冷天氣把狗留在外面是殘忍的。","synonyms":["brutal","harsh"],"level":3,"theme":"情緒與感受","examples":[{"en":"It is cruel to leave a dog outside in the cold.","zh":"在寒冷天氣把狗留在外面是殘忍的。"},{"en":"It is cruel to keep a wild bird in such a tiny cage.","zh":"把野鳥關在這麼小的籠子裡是很殘忍的。"},{"en":"The story describes the cruel treatment of the poor workers.","zh":"這個故事描述了那些貧窮工人所受到的殘酷對待。"}]},{"word":"cruelty","pos":"n.","phonetic":"[ˈkruəltɪ]","meaning":"殘忍；殘酷行為","definition":"cruel behavior or treatment","collocations":["animal cruelty","act of cruelty"],"example":"The organization fights against animal cruelty.","exampleZh":"這個組織致力於對抗虐待動物的行為。","synonyms":["brutality"],"level":4,"theme":"抽象概念","examples":[{"en":"The organization fights against animal cruelty.","zh":"這個組織致力於對抗虐待動物的行為。"},{"en":"Many people protested against cruelty toward stray dogs.","zh":"許多人抗議對流浪狗的殘忍行為。"},{"en":"The new law aims to prevent cruelty to farm animals.","zh":"這項新法律旨在防止對農場動物的殘酷對待。"}]},{"word":"cruise","pos":"n. / v.","phonetic":"[kruz]","meaning":"郵輪旅行；巡航","definition":"a voyage on a ship taken for pleasure, or to travel at a steady speed","collocations":["go on a cruise","cruise ship","cruise around"],"example":"They took a cruise around the Caribbean islands.","exampleZh":"他們搭乘郵輪遊覽加勒比海群島。","synonyms":["voyage"],"level":3,"theme":"交通與旅行","examples":[{"en":"They took a cruise around the Caribbean islands.","zh":"他們搭乘郵輪遊覽加勒比海群島。"},{"en":"My grandparents plan to go on a cruise for their anniversary.","zh":"我的祖父母打算搭郵輪旅行來慶祝他們的結婚紀念日。"},{"en":"The huge cruise ship carried thousands of happy passengers.","zh":"那艘巨大的郵輪載著數千名快樂的乘客。"}]},{"word":"crumb","pos":"n.","phonetic":"[krʌm]","meaning":"碎屑；麵包屑","definition":"a very small piece of bread, cake, or biscuit","collocations":["bread crumbs","cake crumbs"],"example":"There were crumbs all over the table.","exampleZh":"桌上到處都是麵包屑。","synonyms":["fragment"],"level":3,"theme":"食物與烹飪","examples":[{"en":"There were crumbs all over the table.","zh":"桌上到處都是麵包屑。"},{"en":"The little bird pecked at the bread crumbs on the ground.","zh":"小鳥啄食著地上的麵包屑。"},{"en":"She wiped the cake crumbs off the table after the party.","zh":"派對後她把桌上的蛋糕屑擦乾淨。"}]},{"word":"crumble","pos":"v.","phonetic":"[ˈkrʌmbl̩]","meaning":"崩潰；碎裂；瓦解","definition":"to break into small pieces, or to gradually fall apart","collocations":["crumble away","crumble under pressure"],"example":"The old wall began to crumble after the earthquake.","exampleZh":"地震後那面老牆開始崩塌。","synonyms":["collapse"],"level":5,"theme":"性質與描述","examples":[{"en":"The old wall began to crumble after the earthquake.","zh":"地震後那面老牆開始崩塌。"},{"en":"The old cookie began to crumble as soon as I picked it up.","zh":"這塊舊餅乾一被我拿起來就開始碎裂。"},{"en":"Some students crumble under pressure during important exams.","zh":"有些學生在重要考試的壓力下會崩潰。"}]},{"word":"crunch","pos":"v. / n.","phonetic":"[krʌntʃ]","meaning":"嘎吱作響地咬碎；緊要關頭","definition":"to crush something noisily with the teeth, or a critical situation","collocations":["crunch numbers","budget crunch","crunch on chips"],"example":"He crunched loudly on a bag of chips.","exampleZh":"他大聲地嚼著一包洋芋片。","synonyms":["chomp"],"level":4,"theme":"食物與烹飪","examples":[{"en":"He crunched loudly on a bag of chips.","zh":"他大聲地嚼著一包洋芋片。"},{"en":"The children crunched happily on their crispy potato chips.","zh":"孩子們開心地嘎吱嘎吱地嚼著酥脆的洋芋片。"},{"en":"The fresh snow crunched under our boots as we walked.","zh":"走路時，新雪在我們的靴子下嘎吱作響。"}]},{"word":"crusade","pos":"n. / v.","phonetic":"[kruˈsed]","meaning":"運動；聖戰；奮鬥","definition":"a vigorous campaign for a cause, or a religious war in the Middle Ages","collocations":["crusade against poverty","launch a crusade"],"example":"She led a crusade against plastic pollution.","exampleZh":"她發起了一場反對塑膠污染的運動。","synonyms":["campaign"],"level":6,"theme":"社會與文化","examples":[{"en":"She led a crusade against plastic pollution.","zh":"她發起了一場反對塑膠污染的運動。"},{"en":"The doctor began a crusade against smoking in his hometown.","zh":"這位醫生在他的家鄉發起了一場反吸菸運動。"},{"en":"The students launched a crusade against food waste at school.","zh":"學生們在學校發起了一場對抗食物浪費的運動。"}]},{"word":"crush","pos":"v. / n.","phonetic":"[krʌʃ]","meaning":"壓碎；擠壓；迷戀","definition":"to press something hard so it breaks or is badly damaged","collocations":["crush a can","have a crush on","crush grapes"],"example":"He crushed the empty can with his foot.","exampleZh":"他用腳把空罐壓扁了。","synonyms":["squash"],"level":3,"theme":"動作與行為","examples":[{"en":"He crushed the empty can with his foot.","zh":"他用腳把空罐壓扁了。"},{"en":"Workers crush the grapes to make juice and wine.","zh":"工人們壓碎葡萄來製作果汁和葡萄酒。"},{"en":"She had a secret crush on the boy who sat beside her.","zh":"她偷偷喜歡上坐在她旁邊的那個男孩。"}]},{"word":"crust","pos":"n.","phonetic":"[krʌst]","meaning":"外殼；表皮；(麵包)硬皮","definition":"the hard outer layer of bread or pastry, or the earth's outer layer","collocations":["pie crust","earth's crust","bread crust"],"example":"She cut off the crust of the bread.","exampleZh":"她把麵包的外皮切掉了。","synonyms":["shell"],"level":4,"theme":"食物與烹飪","examples":[{"en":"She cut off the crust of the bread.","zh":"她把麵包的外皮切掉了。"},{"en":"The apple pie had a golden, crispy crust on top.","zh":"這個蘋果派上面有一層金黃酥脆的外皮。"},{"en":"Earthquakes happen when the earth's crust suddenly moves.","zh":"當地殼突然移動時就會發生地震。"}]},{"word":"crutch","pos":"n.","phonetic":"[krʌtʃ]","meaning":"拐杖","definition":"a support used under the arm to help an injured person walk","collocations":["walk on crutches","use a crutch"],"example":"He had to walk with crutches after breaking his leg.","exampleZh":"他摔斷腿後必須拄著拐杖走路。","synonyms":[],"level":4,"theme":"身體與健康","examples":[{"en":"He had to walk with crutches after breaking his leg.","zh":"他摔斷腿後必須拄著拐杖走路。"},{"en":"After the surgery, she had to walk on crutches for a month.","zh":"手術後，她必須拄著拐杖走一個月的路。"},{"en":"He leaned on a crutch while his broken ankle healed.","zh":"在腳踝骨折復原期間，他靠著拐杖行走。"}]},{"word":"cry","pos":"v. / n.","phonetic":"[kraɪ]","meaning":"哭泣；喊叫；哭聲","definition":"to shed tears because of pain or emotion, or a loud shout","collocations":["cry out loud","burst into tears","a cry for help"],"example":"The baby began to cry loudly.","exampleZh":"嬰兒開始大聲哭泣。","synonyms":["weep","shout"],"level":1,"theme":"情緒與感受","examples":[{"en":"The baby began to cry loudly.","zh":"嬰兒開始大聲哭泣。"},{"en":"She burst into tears when she heard the happy news.","zh":"聽到這個好消息時，她激動得哭了出來。"},{"en":"We heard a cry for help coming from the river.","zh":"我們聽到從河邊傳來的求救呼喊。"}]},{"word":"crystal","pos":"n. / adj.","phonetic":"[ˈkrɪstl̩]","meaning":"水晶；結晶；透明的","definition":"a clear, transparent mineral or glass, or very clear","collocations":["crystal clear","crystal ball","salt crystal"],"example":"The lake water was crystal clear.","exampleZh":"湖水清澈如水晶般透明。","synonyms":[],"level":3,"theme":"自然與環境","examples":[{"en":"The lake water was crystal clear.","zh":"湖水清澈如水晶般透明。"},{"en":"Her explanation made the difficult idea crystal clear.","zh":"她的解釋把這個困難的概念說得一清二楚。"},{"en":"Tiny salt crystals sparkled on the surface of the rocks.","zh":"細小的鹽結晶在岩石表面閃閃發光。"}]},{"word":"cub","pos":"n.","phonetic":"[kʌb]","meaning":"幼獸","definition":"the young of certain animals, such as lions, bears, or foxes","collocations":["lion cub","bear cub"],"example":"The lioness watched over her cubs carefully.","exampleZh":"母獅小心地看顧著她的幼獅。","synonyms":[],"level":3,"theme":"動物與植物","examples":[{"en":"The lioness watched over her cubs carefully.","zh":"母獅小心地看顧著她的幼獅。"},{"en":"The playful bear cub rolled down the grassy hill.","zh":"頑皮的小熊從長滿草的山坡上滾了下來。"},{"en":"The lion cub stayed close to its mother in the tall grass.","zh":"小獅子在長草中緊緊跟著牠的媽媽。"}]},{"word":"cube","pos":"n.","phonetic":"[kjub]","meaning":"立方體；立方","definition":"a solid object with six equal square sides","collocations":["ice cube","sugar cube","cube root"],"example":"She dropped an ice cube into her drink.","exampleZh":"她把一顆冰塊放進飲料裡。","synonyms":[],"level":3,"theme":"科學與數學","examples":[{"en":"She dropped an ice cube into her drink.","zh":"她把一顆冰塊放進飲料裡。"},{"en":"He added two sugar cubes to his cup of black tea.","zh":"他在他的紅茶裡加了兩塊方糖。"},{"en":"The teacher asked us to find the cube root of the number.","zh":"老師要我們求出這個數字的立方根。"}]},{"word":"cubic","pos":"adj.","phonetic":"[ˈkjubɪk]","meaning":"立方的","definition":"having the shape of a cube, or relating to volume measured in cubes","collocations":["cubic meter","cubic shape"],"example":"The tank holds ten cubic meters of water.","exampleZh":"這個水槽可容納十立方公尺的水。","synonyms":[],"level":5,"theme":"科學與數學","examples":[{"en":"The tank holds ten cubic meters of water.","zh":"這個水槽可容納十立方公尺的水。"},{"en":"The swimming pool holds about fifty cubic meters of water.","zh":"這座游泳池大約可容納五十立方公尺的水。"},{"en":"The children stacked cubic wooden blocks into a tall tower.","zh":"孩子們把立方體的木塊堆成一座高塔。"}]},{"word":"cucumber","pos":"n.","phonetic":"[ˈkjukʌmbɚ]","meaning":"黃瓜；小黃瓜","definition":"a long green vegetable eaten raw in salads","collocations":["cucumber salad","slice a cucumber"],"example":"She added sliced cucumber to the salad.","exampleZh":"她在沙拉裡加了切片黃瓜。","synonyms":[],"level":2,"theme":"食物與烹飪","examples":[{"en":"She added sliced cucumber to the salad.","zh":"她在沙拉裡加了切片黃瓜。"},{"en":"On hot days, a cool cucumber salad is very refreshing.","zh":"在炎熱的日子裡，一份清涼的黃瓜沙拉非常爽口。"},{"en":"She sliced a fresh cucumber to put in the sandwiches.","zh":"她切了一根新鮮的小黃瓜放進三明治裡。"}]},{"word":"cuddle","pos":"v. / n.","phonetic":"[ˈkʌdl̩]","meaning":"擁抱；依偎","definition":"to hold someone closely and lovingly in one's arms","collocations":["cuddle up","give a cuddle"],"example":"The little girl cuddled her teddy bear.","exampleZh":"小女孩緊緊抱著她的泰迪熊。","synonyms":["hug","embrace"],"level":4,"theme":"情緒與感受","examples":[{"en":"The little girl cuddled her teddy bear.","zh":"小女孩緊緊抱著她的泰迪熊。"},{"en":"On cold nights, the kitten likes to cuddle up beside me.","zh":"在寒冷的夜晚，小貓喜歡依偎在我身邊。"},{"en":"The mother gave her sleepy child a warm cuddle.","zh":"媽媽給了她想睡的孩子一個溫暖的擁抱。"}]},{"word":"cue","pos":"n. / v.","phonetic":"[kju]","meaning":"提示；暗示；給予提示","definition":"a signal for someone to do something, especially in a performance","collocations":["take a cue","cue card","on cue"],"example":"The actor waited for his cue to enter the stage.","exampleZh":"演員等待提示上台。","synonyms":["signal","hint"],"level":4,"theme":"溝通與語言","examples":[{"en":"The actor waited for his cue to enter the stage.","zh":"演員等待提示上台。"},{"en":"The singer watched the cue cards to remember the lyrics.","zh":"歌手看著提示卡來記住歌詞。"},{"en":"Right on cue, the audience began to clap loudly.","zh":"就在暗示響起的那一刻，觀眾開始大聲鼓掌。"}]},{"word":"cuisine","pos":"n.","phonetic":"[kwɪˈzin]","meaning":"烹飪；菜系","definition":"a style or method of cooking, especially of a particular country","collocations":["French cuisine","local cuisine","fine cuisine"],"example":"The restaurant serves authentic Italian cuisine.","exampleZh":"這家餐廳提供道地的義大利菜。","synonyms":["cooking"],"level":5,"theme":"食物與烹飪","examples":[{"en":"The restaurant serves authentic Italian cuisine.","zh":"這家餐廳提供道地的義大利菜。"},{"en":"We traveled to the south to taste the famous local cuisine.","zh":"我們到南部去品嚐著名的地方美食。"},{"en":"The chef trained for years to master French cuisine.","zh":"這位主廚訓練了多年才精通法式料理。"}]},{"word":"culinary","pos":"adj.","phonetic":"[ˈkjulɪˌnɛrɪ]","meaning":"烹飪的；廚藝的","definition":"relating to cooking or the kitchen","collocations":["culinary skills","culinary school","culinary arts"],"example":"She studied culinary arts in Paris.","exampleZh":"她在巴黎學習烹飪藝術。","synonyms":[],"level":6,"theme":"食物與烹飪","examples":[{"en":"She studied culinary arts in Paris.","zh":"她在巴黎學習烹飪藝術。"},{"en":"He improved his culinary skills by cooking dinner every night.","zh":"他每晚做晚餐，藉此提升自己的廚藝。"},{"en":"After high school, she hopes to enter a famous culinary school.","zh":"高中畢業後，她希望進入一所知名的廚藝學校。"}]},{"word":"culminate","pos":"v.","phonetic":"[ˈkʌlməˌnet]","meaning":"達到高潮；以...告終","definition":"to reach a final or climactic point","collocations":["culminate in","culminate with a ceremony"],"example":"The festival culminated in a spectacular fireworks show.","exampleZh":"這場節慶最終以精彩的煙火表演作結。","synonyms":["climax","end"],"level":6,"theme":"抽象概念","examples":[{"en":"The festival culminated in a spectacular fireworks show.","zh":"這場節慶最終以精彩的煙火表演作結。"},{"en":"Months of hard practice culminated in a wonderful final concert.","zh":"數月的辛苦練習以一場精彩的期末音樂會告終。"},{"en":"The school year culminated in a lively graduation ceremony.","zh":"這個學年以一場熱鬧的畢業典禮達到高潮。"}]},{"word":"culprit","pos":"n.","phonetic":"[ˈkʌlprɪt]","meaning":"罪魁禍首；犯人","definition":"a person who is guilty of a crime or wrongdoing","collocations":["find the culprit","the real culprit"],"example":"The police finally caught the culprit.","exampleZh":"警方終於抓到了犯人。","synonyms":["offender"],"level":5,"theme":"政治與法律","examples":[{"en":"The police finally caught the culprit.","zh":"警方終於抓到了犯人。"},{"en":"After some searching, we found the culprit who broke the vase.","zh":"找了一陣子後，我們找到了打破花瓶的罪魁禍首。"},{"en":"Too much sugar is often the real culprit behind tooth decay.","zh":"過多的糖分往往是蛀牙背後真正的元凶。"}]},{"word":"cultivate","pos":"v.","phonetic":"[ˈkʌltəˌvet]","meaning":"耕種；培養","definition":"to prepare land and grow crops, or to develop a skill or relationship","collocations":["cultivate land","cultivate a habit","cultivate friendship"],"example":"Farmers cultivate rice in this region.","exampleZh":"農夫在這地區種植稻米。","synonyms":["grow","develop"],"level":5,"theme":"自然與環境","examples":[{"en":"Farmers cultivate rice in this region.","zh":"農夫在這地區種植稻米。"},{"en":"Reading every day helps you cultivate a good study habit.","zh":"每天閱讀有助於你培養良好的讀書習慣。"},{"en":"The villagers cultivate tea on the gentle mountain slopes.","zh":"村民們在平緩的山坡上種植茶葉。"}]},{"word":"cultural","pos":"adj.","phonetic":"[ˈkʌltʃərəl]","meaning":"文化的","definition":"relating to the customs and beliefs of a society","collocations":["cultural heritage","cultural difference","cultural exchange"],"example":"The festival celebrates the region's cultural heritage.","exampleZh":"這個節慶慶祝該地區的文化遺產。","synonyms":[],"level":3,"theme":"社會與文化","examples":[{"en":"The festival celebrates the region's cultural heritage.","zh":"這個節慶慶祝該地區的文化遺產。"},{"en":"The exchange program helps students understand cultural differences.","zh":"這個交換計畫幫助學生了解文化差異。"},{"en":"The old temple is an important part of our cultural heritage.","zh":"這座古老的廟宇是我們文化遺產的重要一部分。"}]},{"word":"culture","pos":"n.","phonetic":"[ˈkʌltʃɚ]","meaning":"文化","definition":"the customs, arts, and beliefs of a particular society","collocations":["pop culture","culture shock","traditional culture"],"example":"Taiwan has a rich and diverse culture.","exampleZh":"台灣擁有豐富多元的文化。","synonyms":[],"level":2,"theme":"社會與文化","examples":[{"en":"Taiwan has a rich and diverse culture.","zh":"台灣擁有豐富多元的文化。"},{"en":"Many students experience culture shock when studying abroad.","zh":"許多學生在國外求學時會經歷文化衝擊。"},{"en":"Pop culture has a strong influence on young people's clothes.","zh":"流行文化對年輕人的穿著有很大的影響。"}]},{"word":"cumulative","pos":"adj.","phonetic":"[ˈkjumjəˌletɪv]","meaning":"累積的","definition":"increasing steadily by successive additions","collocations":["cumulative effect","cumulative total"],"example":"The cumulative effect of pollution harms the environment.","exampleZh":"污染的累積效應對環境造成傷害。","synonyms":["accumulated"],"level":6,"theme":"科學與數學","examples":[{"en":"The cumulative effect of pollution harms the environment.","zh":"污染的累積效應對環境造成傷害。"},{"en":"The cumulative effect of daily exercise keeps your body strong.","zh":"每日運動的累積效果能讓你的身體保持強壯。"},{"en":"Your final grade is the cumulative total of every quiz this term.","zh":"你的期末成績是這學期每次小考的累積總分。"}]},{"word":"cunning","pos":"adj.","phonetic":"[ˈkʌnɪŋ]","meaning":"狡猾的；精明的","definition":"clever at achieving one's aims by deceit or trickery","collocations":["cunning plan","a cunning fox"],"example":"The fox is known for being a cunning animal.","exampleZh":"狐狸以狡猾聞名。","synonyms":["sly","crafty"],"level":5,"theme":"性質與描述","examples":[{"en":"The fox is known for being a cunning animal.","zh":"狐狸以狡猾聞名。"},{"en":"The cunning thief tricked the guard and escaped easily.","zh":"那個狡猾的小偷騙過了警衛，輕鬆地逃走了。"},{"en":"She came up with a cunning plan to surprise her parents.","zh":"她想出了一個精明的計畫來給她的父母一個驚喜。"}]},{"word":"cup","pos":"n.","phonetic":"[kʌp]","meaning":"杯子；獎盃","definition":"a small container used for drinking, or a trophy","collocations":["a cup of tea","World Cup","paper cup"],"example":"She poured a cup of coffee.","exampleZh":"她倒了一杯咖啡。","synonyms":[],"level":1,"theme":"居家與生活","examples":[{"en":"She poured a cup of coffee.","zh":"她倒了一杯咖啡。"},{"en":"He drinks a cup of warm tea before going to bed.","zh":"他睡前會喝一杯溫茶。"},{"en":"The team lifted the shiny cup after winning the final.","zh":"這支隊伍在贏得決賽後高舉閃亮的獎盃。"}]},{"word":"cupboard","pos":"n.","phonetic":"[ˈkʌbɚd]","meaning":"櫥櫃；碗櫥","definition":"a piece of furniture with doors and shelves for storing things","collocations":["kitchen cupboard","open the cupboard"],"example":"She put the dishes back in the cupboard.","exampleZh":"她把碗盤放回櫥櫃裡。","synonyms":["cabinet"],"level":3,"theme":"居家與生活","examples":[{"en":"She put the dishes back in the cupboard.","zh":"她把碗盤放回櫥櫃裡。"},{"en":"She reached into the kitchen cupboard to find a clean bowl.","zh":"她伸手到廚房的櫥櫃裡找一個乾淨的碗。"},{"en":"All the cups are neatly stacked inside the wooden cupboard.","zh":"所有的杯子都整齊地疊放在木櫥櫃裡。"}]},{"word":"cupcake","pos":"n.","phonetic":"[ˈkʌpˌkek]","meaning":"杯子蛋糕","definition":"a small cake baked in a cup-shaped paper or foil case","collocations":["bake cupcakes","decorate a cupcake"],"example":"She baked chocolate cupcakes for the party.","exampleZh":"她為派對烤了巧克力杯子蛋糕。","synonyms":[],"level":2,"theme":"食物與烹飪","examples":[{"en":"She baked chocolate cupcakes for the party.","zh":"她為派對烤了巧克力杯子蛋糕。"},{"en":"The children decorated each cupcake with colorful sugar stars.","zh":"孩子們用彩色的糖星星裝飾每一個杯子蛋糕。"},{"en":"She baked a dozen cupcakes for her classmate's birthday.","zh":"她為同學的生日烤了一打杯子蛋糕。"}]},{"word":"curb","pos":"n. / v.","phonetic":"[kɝb]","meaning":"路緣；抑制","definition":"the edge of a sidewalk, or to control or limit something","collocations":["curb one's appetite","park by the curb","curb inflation"],"example":"The government tried to curb rising prices.","exampleZh":"政府試圖抑制物價上漲。","synonyms":["control","limit"],"level":5,"theme":"抽象概念","examples":[{"en":"The government tried to curb rising prices.","zh":"政府試圖抑制物價上漲。"},{"en":"Drinking water before meals can help curb your appetite.","zh":"飯前喝水有助於抑制你的食慾。"},{"en":"He parked the car neatly by the curb outside the shop.","zh":"他把車整齊地停在商店外的路緣旁。"}]},{"word":"cure","pos":"v. / n.","phonetic":"[kjʊr]","meaning":"治癒；治療方法","definition":"to make an ill person healthy again, or a medicine that does this","collocations":["cure a disease","find a cure","cure for cancer"],"example":"Scientists are working to find a cure for the disease.","exampleZh":"科學家正努力尋找這種疾病的治療方法。","synonyms":["heal","remedy"],"level":3,"theme":"身體與健康","examples":[{"en":"Scientists are working to find a cure for the disease.","zh":"科學家正努力尋找這種疾病的治療方法。"},{"en":"Doctors hope to find a cure for the rare illness soon.","zh":"醫生們希望能盡快找到這種罕見疾病的療法。"},{"en":"Rest and warm soup helped cure her bad cold.","zh":"休息和熱湯幫助她治好了重感冒。"}]},{"word":"curfew","pos":"n.","phonetic":"[ˈkɝfju]","meaning":"宵禁；門禁時間","definition":"a rule requiring people to be indoors after a certain time","collocations":["set a curfew","break curfew"],"example":"My parents set a curfew of ten o'clock on weekdays.","exampleZh":"我父母規定平日的門禁時間是十點。","synonyms":[],"level":5,"theme":"社會與文化","examples":[{"en":"My parents set a curfew of ten o'clock on weekdays.","zh":"我父母規定平日的門禁時間是十點。"},{"en":"The students in the dormitory must return before the evening curfew.","zh":"宿舍的學生必須在晚間門禁時間前回來。"},{"en":"He broke the curfew and got into trouble with his parents.","zh":"他違反了門禁時間，因而惹上了父母的麻煩。"}]},{"word":"curiosity","pos":"n.","phonetic":"[ˌkjʊrɪˈɑsətɪ]","meaning":"好奇心","definition":"a strong desire to know or learn something","collocations":["out of curiosity","satisfy one's curiosity"],"example":"Her curiosity led her to explore the old house.","exampleZh":"她的好奇心驅使她去探索那棟老房子。","synonyms":["inquisitiveness"],"level":4,"theme":"情緒與感受","examples":[{"en":"Her curiosity led her to explore the old house.","zh":"她的好奇心驅使她去探索那棟老房子。"},{"en":"Out of curiosity, she opened the mysterious old letter.","zh":"出於好奇，她打開了那封神祕的舊信。"},{"en":"The science museum is a great place to satisfy a child's curiosity.","zh":"科學博物館是滿足孩子好奇心的好地方。"}]},{"word":"curious","pos":"adj.","phonetic":"[ˈkjʊrɪəs]","meaning":"好奇的","definition":"eager to know or learn something","collocations":["curious about","curious child"],"example":"The children were curious about the strange noise.","exampleZh":"孩子們對那奇怪的聲音感到好奇。","synonyms":["inquisitive"],"level":3,"theme":"情緒與感受","examples":[{"en":"The children were curious about the strange noise.","zh":"孩子們對那奇怪的聲音感到好奇。"},{"en":"The curious child asked endless questions about the stars.","zh":"那個好奇的孩子問了無數關於星星的問題。"},{"en":"I am curious about how bees make honey.","zh":"我很好奇蜜蜂是如何製造蜂蜜的。"}]},{"word":"curl","pos":"v. / n.","phonetic":"[kɝl]","meaning":"捲曲；捲髮","definition":"to twist into a curved or spiral shape","collocations":["curl one's hair","curl up on the sofa"],"example":"She curled up on the sofa with a blanket.","exampleZh":"她裹著毯子蜷縮在沙發上。","synonyms":["twist"],"level":3,"theme":"服裝與外表","examples":[{"en":"She curled up on the sofa with a blanket.","zh":"她裹著毯子蜷縮在沙發上。"},{"en":"The cat curled up into a warm ball near the heater.","zh":"貓咪蜷縮成一團溫暖的球，靠在暖爐旁。"},{"en":"She used a machine to curl her hair before the party.","zh":"派對前她用機器把頭髮捲了起來。"}]},{"word":"curly","pos":"adj.","phonetic":"[ˈkɝlɪ]","meaning":"捲曲的","definition":"having curls or a curved shape, especially hair","collocations":["curly hair","curly fries"],"example":"She has beautiful curly hair.","exampleZh":"她有一頭美麗的捲髮。","synonyms":["wavy"],"level":2,"theme":"服裝與外表","examples":[{"en":"She has beautiful curly hair.","zh":"她有一頭美麗的捲髮。"},{"en":"The little girl tied ribbons in her curly brown hair.","zh":"小女孩在她捲曲的棕色頭髮上綁了緞帶。"},{"en":"We ordered a plate of crispy curly fries to share.","zh":"我們點了一盤酥脆的捲曲薯條一起分享。"}]},{"word":"currency","pos":"n.","phonetic":"[ˈkɝənsɪ]","meaning":"貨幣；通貨","definition":"the money used in a particular country","collocations":["foreign currency","exchange currency","local currency"],"example":"You need to exchange your currency before traveling.","exampleZh":"旅行前你需要兌換貨幣。","synonyms":["money"],"level":4,"theme":"商業與金錢","examples":[{"en":"You need to exchange your currency before traveling.","zh":"旅行前你需要兌換貨幣。"},{"en":"Before the trip, we exchanged some money into foreign currency.","zh":"出發旅行前，我們把一些錢換成了外幣。"},{"en":"The local currency is accepted at every shop in the town.","zh":"當地貨幣在鎮上的每家商店都能使用。"}]},{"word":"current","pos":"adj. / n.","phonetic":"[ˈkɝənt]","meaning":"目前的；水流；電流","definition":"belonging to the present time, or a flow of water, air, or electricity","collocations":["current situation","ocean current","electric current"],"example":"The current situation requires immediate action.","exampleZh":"目前的情況需要立即採取行動。","synonyms":["present"],"level":3,"theme":"時間與空間","examples":[{"en":"The current situation requires immediate action.","zh":"目前的情況需要立即採取行動。"},{"en":"Strong ocean currents can be dangerous for young swimmers.","zh":"強勁的洋流對年輕的游泳者來說可能很危險。"},{"en":"The teacher asked us about the current situation in our town.","zh":"老師問我們關於我們鎮上目前的情況。"}]},{"word":"curriculum","pos":"n.","phonetic":"[kəˈrɪkjələm]","meaning":"課程；課程表","definition":"the subjects that are studied or taught in a school or course","collocations":["school curriculum","curriculum design"],"example":"The school revised its curriculum this year.","exampleZh":"這所學校今年修訂了課程。","synonyms":[],"level":5,"theme":"教育與學習","examples":[{"en":"The school revised its curriculum this year.","zh":"這所學校今年修訂了課程。"},{"en":"The new curriculum includes more classes about the environment.","zh":"新課程包含了更多關於環境的課。"},{"en":"Art and music are important parts of the school curriculum.","zh":"美術和音樂是學校課程的重要部分。"}]},{"word":"curse","pos":"n. / v.","phonetic":"[kɝs]","meaning":"詛咒；咒罵","definition":"a wish that something bad will happen to someone, or to swear","collocations":["put a curse on","curse under one's breath"],"example":"The witch put a curse on the village.","exampleZh":"女巫對這個村莊下了詛咒。","synonyms":["swear"],"level":4,"theme":"抽象概念","examples":[{"en":"The witch put a curse on the village.","zh":"女巫對這個村莊下了詛咒。"},{"en":"In the fairy tale, a witch put a curse on the young prince.","zh":"在童話故事中，一個女巫對年輕的王子下了詛咒。"},{"en":"He cursed under his breath when he dropped his ice cream.","zh":"他掉了冰淇淋時，低聲咒罵了幾句。"}]},{"word":"cursor","pos":"n.","phonetic":"[ˈkɝsɚ]","meaning":"游標；指標","definition":"a movable indicator on a computer screen showing where text will appear","collocations":["move the cursor","blinking cursor"],"example":"Move the cursor to the top of the page.","exampleZh":"把游標移到頁面頂端。","synonyms":[],"level":4,"theme":"科技與媒體","examples":[{"en":"Move the cursor to the top of the page.","zh":"把游標移到頁面頂端。"},{"en":"Move the cursor to the button and click it once.","zh":"把游標移到按鈕上，然後點一下。"},{"en":"The blinking cursor waited for her to start typing the essay.","zh":"閃爍的游標等著她開始打這篇作文。"}]},{"word":"curtain","pos":"n.","phonetic":"[ˈkɝtn̩]","meaning":"窗簾；布幕","definition":"a piece of cloth hung to cover a window or stage","collocations":["draw the curtains","shower curtain","stage curtain"],"example":"She closed the curtains before going to bed.","exampleZh":"她睡前拉上了窗簾。","synonyms":[],"level":2,"theme":"居家與生活","examples":[{"en":"She closed the curtains before going to bed.","zh":"她睡前拉上了窗簾。"},{"en":"She drew the curtains to keep out the bright morning sun.","zh":"她拉上窗簾，擋住明亮的晨光。"},{"en":"The audience clapped as the stage curtain slowly rose.","zh":"舞台布幕緩緩升起時，觀眾鼓起掌來。"}]},{"word":"curve","pos":"n. / v.","phonetic":"[kɝv]","meaning":"曲線；彎道；彎曲","definition":"a line that bends smoothly, without any straight parts","collocations":["a sharp curve","curve to the left","learning curve"],"example":"The road curves sharply near the mountain.","exampleZh":"這條路在山附近有個急彎。","synonyms":["bend"],"level":3,"theme":"性質與描述","examples":[{"en":"The road curves sharply near the mountain.","zh":"這條路在山附近有個急彎。"},{"en":"The driver slowed down before the sharp curve in the road.","zh":"駕駛在路上的急彎前放慢了速度。"},{"en":"Learning a new language has a steep learning curve at first.","zh":"學習一門新語言一開始有陡峭的學習曲線。"}]},{"word":"cushion","pos":"n. / v.","phonetic":"[ˈkʊʃən]","meaning":"靠墊；坐墊；緩和","definition":"a soft pillow-like object used for sitting or resting on, or to soften an impact","collocations":["sofa cushion","cushion the blow","seat cushion"],"example":"She placed a cushion on the chair.","exampleZh":"她在椅子上放了一個靠墊。","synonyms":["pillow"],"level":4,"theme":"居家與生活","examples":[{"en":"She placed a cushion on the chair.","zh":"她在椅子上放了一個靠墊。"},{"en":"The thick grass helped cushion her fall from the bike.","zh":"厚厚的草地緩和了她從腳踏車上摔下的衝擊。"},{"en":"He fluffed up the sofa cushions before the guests arrived.","zh":"客人來之前，他把沙發靠墊拍鬆。"}]},{"word":"custody","pos":"n.","phonetic":"[ˈkʌstədɪ]","meaning":"監護權；拘留","definition":"the legal right to take care of someone, especially a child; imprisonment","collocations":["child custody","take into custody"],"example":"The parents share custody of their daughter.","exampleZh":"父母共同擁有女兒的監護權。","synonyms":[],"level":5,"theme":"政治與法律","examples":[{"en":"The parents share custody of their daughter.","zh":"父母共同擁有女兒的監護權。"},{"en":"After the divorce, the mother was given custody of the children.","zh":"離婚後，母親獲得了孩子的監護權。"},{"en":"The police took the suspect into custody for questioning.","zh":"警方將嫌疑犯拘留起來偵訊。"}]},{"word":"custom","pos":"n. / adj.","phonetic":"[ˈkʌstəm]","meaning":"習俗；慣例；訂製的","definition":"a traditional way of behaving in a society, or made specially to order","collocations":["local custom","custom-made","follow a custom"],"example":"It is a local custom to remove shoes before entering.","exampleZh":"進門前脫鞋是當地的習俗。","synonyms":["tradition"],"level":3,"theme":"社會與文化","examples":[{"en":"It is a local custom to remove shoes before entering.","zh":"進門前脫鞋是當地的習俗。"},{"en":"Giving red envelopes is a common custom during the New Year.","zh":"發紅包是過年期間常見的習俗。"},{"en":"He wore a custom-made suit to his sister's wedding.","zh":"他穿著一套訂做的西裝參加姊姊的婚禮。"}]},{"word":"customer","pos":"n.","phonetic":"[ˈkʌstəmɚ]","meaning":"顧客","definition":"a person who buys goods or services from a business","collocations":["customer service","satisfied customer","regular customer"],"example":"The shop offers great customer service.","exampleZh":"這家店提供優質的顧客服務。","synonyms":["client"],"level":2,"theme":"商業與金錢","examples":[{"en":"The shop offers great customer service.","zh":"這家店提供優質的顧客服務。"},{"en":"A satisfied customer often returns to buy more products.","zh":"滿意的顧客通常會再回來購買更多商品。"},{"en":"She is a regular customer at the small bakery on the corner.","zh":"她是街角那間小麵包店的常客。"}]},{"word":"customize","pos":"v.","phonetic":"[ˈkʌstəˌmaɪz]","meaning":"客製化；訂做","definition":"to modify something according to a person's individual requirements","collocations":["customize a phone","customize settings"],"example":"You can customize the settings on your phone.","exampleZh":"你可以在手機上客製化設定。","synonyms":["personalize"],"level":5,"theme":"科技與媒體","examples":[{"en":"You can customize the settings on your phone.","zh":"你可以在手機上客製化設定。"},{"en":"You can customize the app to show only the news you like.","zh":"你可以客製化這個應用程式，讓它只顯示你喜歡的新聞。"},{"en":"The workshop lets you customize your own leather wallet.","zh":"這個工作坊讓你訂做屬於自己的皮革錢包。"}]},{"word":"customs","pos":"n.","phonetic":"[ˈkʌstəmz]","meaning":"海關","definition":"the place at a border where officials check goods entering a country","collocations":["pass through customs","customs officer","customs declaration"],"example":"We had to wait in line at customs.","exampleZh":"我們得在海關排隊等候。","synonyms":[],"level":4,"theme":"交通與旅行","examples":[{"en":"We had to wait in line at customs.","zh":"我們得在海關排隊等候。"},{"en":"The customs officer checked our bags at the airport.","zh":"海關人員在機場檢查了我們的行李。"},{"en":"It took an hour to pass through customs after the long flight.","zh":"漫長的飛行後，通過海關花了一個小時。"}]},{"word":"cut","pos":"v. / n.","phonetic":"[kʌt]","meaning":"切；剪；傷口","definition":"to use a sharp tool to divide or remove something","collocations":["cut down","cut in line","a paper cut"],"example":"She cut the cake into eight pieces.","exampleZh":"她把蛋糕切成八塊。","synonyms":["slice"],"level":1,"theme":"動作與行為","examples":[{"en":"She cut the cake into eight pieces.","zh":"她把蛋糕切成八塊。"},{"en":"Please don't cut in line; everyone has been waiting patiently.","zh":"請不要插隊，大家都耐心地等候很久了。"},{"en":"He got a small paper cut while wrapping the gift.","zh":"他包禮物時被紙割了一個小傷口。"}]},{"word":"cute","pos":"adj.","phonetic":"[kjut]","meaning":"可愛的","definition":"attractive in a pleasant and often small or dainty way","collocations":["a cute puppy","look cute"],"example":"The puppy in the window is so cute.","exampleZh":"櫥窗裡的小狗好可愛。","synonyms":["adorable"],"level":1,"theme":"性質與描述","examples":[{"en":"The puppy in the window is so cute.","zh":"櫥窗裡的小狗好可愛。"},{"en":"The baby looked so cute in his tiny striped hat.","zh":"寶寶戴著小小的條紋帽子，看起來好可愛。"},{"en":"She drew a cute cartoon rabbit on the corner of her notebook.","zh":"她在筆記本的角落畫了一隻可愛的卡通兔子。"}]},{"word":"cutlery","pos":"n.","phonetic":"[ˈkʌtlərɪ]","meaning":"餐具（刀叉匙）","definition":"knives, forks, and spoons used for eating","collocations":["set of cutlery","plastic cutlery"],"example":"Please place the cutlery beside each plate.","exampleZh":"請把餐具放在每個盤子旁邊。","synonyms":["silverware"],"level":4,"theme":"居家與生活","examples":[{"en":"Please place the cutlery beside each plate.","zh":"請把餐具放在每個盤子旁邊。"},{"en":"They brought plastic cutlery for the picnic in the park.","zh":"他們帶了塑膠餐具去公園野餐。"},{"en":"Please set out the cutlery neatly before dinner begins.","zh":"請在晚餐開始前把餐具整齊地擺好。"}]},{"word":"cyberspace","pos":"n.","phonetic":"[ˈsaɪbɚˌspes]","meaning":"網路空間；虛擬空間","definition":"the online world of computer networks and the internet","collocations":["explore cyberspace","in cyberspace"],"example":"Young people spend hours in cyberspace every day.","exampleZh":"年輕人每天花好幾個小時在網路空間裡。","synonyms":[],"level":6,"theme":"科技與媒體","examples":[{"en":"Young people spend hours in cyberspace every day.","zh":"年輕人每天花好幾個小時在網路空間裡。"},{"en":"In cyberspace, people from around the world can share ideas instantly.","zh":"在網路空間裡，世界各地的人可以即時分享想法。"},{"en":"Teachers remind students to stay safe while exploring cyberspace.","zh":"老師提醒學生在探索網路空間時要注意安全。"}]},{"word":"cycle","pos":"n. / v.","phonetic":"[ˈsaɪkl̩]","meaning":"週期；循環；騎自行車","definition":"a series of events that happen repeatedly in the same order","collocations":["life cycle","cycle to work","water cycle"],"example":"The water cycle involves evaporation and rain.","exampleZh":"水循環包含蒸發和降雨的過程。","synonyms":["loop","circle"],"level":3,"theme":"科學與數學","examples":[{"en":"The water cycle involves evaporation and rain.","zh":"水循環包含蒸發和降雨的過程。"},{"en":"We studied the life cycle of a butterfly in biology class.","zh":"我們在生物課上研究了蝴蝶的生命週期。"},{"en":"My father likes to cycle to work when the weather is nice.","zh":"天氣好的時候，我爸爸喜歡騎腳踏車去上班。"}]},{"word":"cyclist","pos":"n.","phonetic":"[ˈsaɪklɪst]","meaning":"騎自行車的人","definition":"a person who rides a bicycle","collocations":["professional cyclist","keen cyclist"],"example":"The cyclist rode quickly along the path.","exampleZh":"那位自行車騎士沿著小徑快速前進。","synonyms":[],"level":3,"theme":"運動與休閒","examples":[{"en":"The cyclist rode quickly along the path.","zh":"那位自行車騎士沿著小徑快速前進。"},{"en":"The cyclist wore a helmet to stay safe on the busy road.","zh":"這位騎自行車的人戴著安全帽，以在繁忙的道路上保持安全。"},{"en":"A group of cyclists raced along the coastal road at dawn.","zh":"一群自行車手在黎明時沿著海岸公路競速。"}]},{"word":"cylinder","pos":"n.","phonetic":"[ˈsɪləndɚ]","meaning":"圓柱體；汽缸","definition":"a solid or hollow shape with straight sides and circular ends","collocations":["gas cylinder","engine cylinder"],"example":"The engine has four cylinders.","exampleZh":"這台引擎有四個汽缸。","synonyms":[],"level":5,"theme":"科學與數學","examples":[{"en":"The engine has four cylinders.","zh":"這台引擎有四個汽缸。"},{"en":"We measured the volume of the metal cylinder in science class.","zh":"我們在科學課上測量了那個金屬圓柱體的體積。"},{"en":"The workers stored the gas cylinder safely in the corner.","zh":"工人們把那個瓦斯鋼瓶安全地放在角落。"}]},{"word":"cynical","pos":"adj.","phonetic":"[ˈsɪnɪkl̩]","meaning":"憤世嫉俗的；懷疑的","definition":"believing that people are motivated only by self-interest; distrustful","collocations":["cynical attitude","become cynical"],"example":"He has a cynical view of politicians.","exampleZh":"他對政治人物抱持憤世嫉俗的看法。","synonyms":["skeptical"],"level":6,"theme":"情緒與感受","examples":[{"en":"He has a cynical view of politicians.","zh":"他對政治人物抱持憤世嫉俗的看法。"},{"en":"After years of failure, he became cynical about his chances of success.","zh":"經歷多年的失敗後，他對自己成功的機會變得憤世嫉俗。"},{"en":"Her cynical attitude made it hard for others to trust her.","zh":"她憤世嫉俗的態度讓別人很難信任她。"}]},{"word":"cypress","pos":"n.","phonetic":"[ˈsaɪprəs]","meaning":"柏樹","definition":"a tall evergreen tree with dark green leaves","collocations":["cypress tree","cypress forest"],"example":"Rows of cypress trees lined the driveway.","exampleZh":"車道兩旁種滿了成排的柏樹。","synonyms":[],"level":5,"theme":"動物與植物","examples":[{"en":"Rows of cypress trees lined the driveway.","zh":"車道兩旁種滿了成排的柏樹。"},{"en":"A tall cypress tree stood quietly beside the old temple.","zh":"一棵高大的柏樹靜靜地佇立在古老的寺廟旁。"},{"en":"We walked through a peaceful cypress forest during our hike.","zh":"健行時我們穿過了一片寧靜的柏樹林。"}]},{"word":"dad","pos":"n.","phonetic":"[dæd]","meaning":"爸爸","definition":"a person's father, used informally","collocations":["my dad","dad's car","call dad"],"example":"My dad picks me up from school every day.","exampleZh":"我爸爸每天都來學校接我。","synonyms":["father","daddy"],"level":1,"theme":"人物與家庭","examples":[{"en":"My dad picks me up from school every day.","zh":"我爸爸每天都來學校接我。"},{"en":"My dad taught me how to ride a bicycle when I was six.","zh":"我六歲時，爸爸教我如何騎腳踏車。"},{"en":"Every weekend I wash dad's car to earn some pocket money.","zh":"每個週末我都會洗爸爸的車來賺點零用錢。"}]},{"word":"daily","pos":"adj. / adv.","phonetic":"[ˈdelɪ]","meaning":"每日的；每天","definition":"happening or done every day","collocations":["daily life","daily routine","daily newspaper"],"example":"She goes jogging on a daily basis.","exampleZh":"她每天都去慢跑。","synonyms":["everyday"],"level":2,"theme":"時間與空間","examples":[{"en":"She goes jogging on a daily basis.","zh":"她每天都去慢跑。"},{"en":"Reading English news is part of my daily routine.","zh":"閱讀英文新聞是我每日例行公事的一部分。"},{"en":"The old man buys a daily newspaper from the corner store.","zh":"那位老先生每天都在轉角商店買一份日報。"}]},{"word":"damage","pos":"n. / v.","phonetic":"[ˈdæmɪdʒ]","meaning":"損害；損傷","definition":"harm that reduces value or usefulness","collocations":["cause damage","serious damage","damage property"],"example":"The storm caused severe damage to the roof.","exampleZh":"這場暴風雨對屋頂造成嚴重損害。","synonyms":["harm","destruction"],"level":3,"theme":"性質與描述","examples":[{"en":"The storm caused severe damage to the roof.","zh":"這場暴風雨對屋頂造成嚴重損害。"},{"en":"Smoking can cause serious damage to your lungs over time.","zh":"長期抽菸會對你的肺部造成嚴重的損害。"},{"en":"The flood damaged many crops in the farming village.","zh":"洪水損害了農村裡許多農作物。"}]},{"word":"damp","pos":"adj.","phonetic":"[dæmp]","meaning":"潮濕的","definition":"slightly wet","collocations":["damp weather","damp cloth","damp air"],"example":"The basement felt cold and damp.","exampleZh":"地下室感覺又冷又潮濕。","synonyms":["moist","humid"],"level":3,"theme":"天氣與季節","examples":[{"en":"The basement felt cold and damp.","zh":"地下室感覺又冷又潮濕。"},{"en":"She wiped the table with a damp cloth after dinner.","zh":"晚餐後她用一塊濕布擦拭桌子。"},{"en":"The damp weather made all our clothes smell musty.","zh":"潮濕的天氣使我們所有的衣服都有霉味。"}]},{"word":"dance","pos":"n. / v.","phonetic":"[dæns]","meaning":"舞蹈；跳舞","definition":"to move rhythmically to music","collocations":["dance class","dance to the music","folk dance"],"example":"They danced together at the wedding.","exampleZh":"他們在婚禮上一起跳舞。","synonyms":[],"level":1,"theme":"運動與休閒","examples":[{"en":"They danced together at the wedding.","zh":"他們在婚禮上一起跳舞。"},{"en":"She signed up for a dance class to stay active.","zh":"她報名了一堂舞蹈課來保持活力。"},{"en":"The children love to dance to the music at parties.","zh":"孩子們喜歡在派對上隨著音樂跳舞。"}]},{"word":"danger","pos":"n.","phonetic":"[ˈdendʒɚ]","meaning":"危險","definition":"the possibility of harm or death","collocations":["in danger","face danger","danger zone"],"example":"Firefighters risk their lives to save people in danger.","exampleZh":"消防員冒著生命危險拯救身處危險中的人。","synonyms":["risk","peril"],"level":2,"theme":"抽象概念","examples":[{"en":"Firefighters risk their lives to save people in danger.","zh":"消防員冒著生命危險拯救身處危險中的人。"},{"en":"The hikers were unaware of the danger ahead on the icy trail.","zh":"健行者沒有察覺到結冰步道前方的危險。"},{"en":"Wild animals in that area put campers in danger.","zh":"那個地區的野生動物使露營者陷入危險。"}]},{"word":"dangerous","pos":"adj.","phonetic":"[ˈdendʒərəs]","meaning":"危險的","definition":"likely to cause harm","collocations":["dangerous sport","dangerous road","extremely dangerous"],"example":"Riding a motorcycle without a helmet is dangerous.","exampleZh":"騎機車不戴安全帽是很危險的。","synonyms":["risky","hazardous"],"level":2,"theme":"性質與描述","examples":[{"en":"Riding a motorcycle without a helmet is dangerous.","zh":"騎機車不戴安全帽是很危險的。"},{"en":"Swimming in that river is extremely dangerous after heavy rain.","zh":"大雨過後在那條河游泳極為危險。"},{"en":"The mountain road becomes dangerous when it is covered with fog.","zh":"那條山路被霧籠罩時會變得很危險。"}]},{"word":"dare","pos":"v.","phonetic":"[dɛr]","meaning":"敢；膽敢","definition":"to have the courage to do something","collocations":["dare to speak","don't you dare","dare someone"],"example":"He didn't dare to tell his mother the truth.","exampleZh":"他不敢告訴媽媽真相。","synonyms":["venture"],"level":3,"theme":"動作與行為","examples":[{"en":"He didn't dare to tell his mother the truth.","zh":"他不敢告訴媽媽真相。"},{"en":"She didn't dare to speak up during the important meeting.","zh":"在那場重要的會議中，她不敢開口發言。"},{"en":"Don't you dare touch my things without asking first.","zh":"沒先問過就別想碰我的東西。"}]},{"word":"dark","pos":"adj.","phonetic":"[dɑrk]","meaning":"黑暗的；深色的","definition":"having little or no light","collocations":["dark room","dark night","dark color"],"example":"It was too dark to see the road ahead.","exampleZh":"天太黑了看不清前方的路。","synonyms":["dim","gloomy"],"level":1,"theme":"性質與描述","examples":[{"en":"It was too dark to see the road ahead.","zh":"天太黑了看不清前方的路。"},{"en":"The room was so dark that I could not find the switch.","zh":"房間太暗了，我找不到開關。"},{"en":"She prefers wearing dark colors like black and navy blue.","zh":"她偏好穿黑色和深藍色等深色的衣服。"}]},{"word":"darkness","pos":"n.","phonetic":"[ˈdɑrknɪs]","meaning":"黑暗","definition":"the state of being dark","collocations":["in darkness","total darkness","fear of darkness"],"example":"The whole city was in darkness after the blackout.","exampleZh":"停電後整座城市陷入黑暗。","synonyms":["dark","gloom"],"level":3,"theme":"性質與描述","examples":[{"en":"The whole city was in darkness after the blackout.","zh":"停電後整座城市陷入黑暗。"},{"en":"The candle gave us a little light in the total darkness.","zh":"在一片漆黑中，那根蠟燭給了我們一點光亮。"},{"en":"Many children have a fear of darkness when they sleep alone.","zh":"許多孩子在獨自睡覺時會害怕黑暗。"}]},{"word":"data","pos":"n.","phonetic":"[ˈdetə]","meaning":"資料；數據","definition":"facts and information used for analysis","collocations":["collect data","data analysis","personal data"],"example":"Researchers analyzed the data from the survey.","exampleZh":"研究人員分析了這項調查的數據。","synonyms":["information"],"level":4,"theme":"科技與媒體","examples":[{"en":"Researchers analyzed the data from the survey.","zh":"研究人員分析了這項調查的數據。"},{"en":"The scientists spent weeks collecting data for their experiment.","zh":"科學家們花了好幾週為他們的實驗收集數據。"},{"en":"Companies must protect their customers' personal data carefully.","zh":"公司必須謹慎地保護顧客的個人資料。"}]},{"word":"database","pos":"n.","phonetic":"[ˈdetəˌbes]","meaning":"資料庫","definition":"an organized collection of data stored electronically","collocations":["build a database","search a database","update the database"],"example":"The company stores customer information in a database.","exampleZh":"這家公司把客戶資訊儲存在資料庫中。","synonyms":[],"level":4,"theme":"科技與媒體","examples":[{"en":"The company stores customer information in a database.","zh":"這家公司把客戶資訊儲存在資料庫中。"},{"en":"The librarian showed us how to search the database for articles.","zh":"圖書館員教我們如何在資料庫中搜尋文章。"},{"en":"They update the database every night with new records.","zh":"他們每晚都用新的紀錄更新資料庫。"}]},{"word":"date","pos":"n. / v.","phonetic":"[det]","meaning":"日期；約會","definition":"a specific day, or a romantic meeting","collocations":["due date","go on a date","set a date"],"example":"They went on their first date to the movies.","exampleZh":"他們第一次約會去看電影。","synonyms":["appointment"],"level":2,"theme":"時間與空間","examples":[{"en":"They went on their first date to the movies.","zh":"他們第一次約會去看電影。"},{"en":"Please write your name and the date at the top of the paper.","zh":"請在紙的最上方寫下你的名字和日期。"},{"en":"He was nervous before going on a date with his classmate.","zh":"和同學約會前，他感到很緊張。"}]},{"word":"daughter","pos":"n.","phonetic":"[ˈdɔtɚ]","meaning":"女兒","definition":"a person's female child","collocations":["only daughter","daughter's wedding","raise a daughter"],"example":"Their daughter just graduated from college.","exampleZh":"他們的女兒剛從大學畢業。","synonyms":[],"level":1,"theme":"人物與家庭","examples":[{"en":"Their daughter just graduated from college.","zh":"他們的女兒剛從大學畢業。"},{"en":"Their only daughter is studying medicine at a famous university.","zh":"他們唯一的女兒正在一所著名的大學讀醫學。"},{"en":"The couple worked hard to raise their daughter well.","zh":"這對夫妻努力把女兒養育得很好。"}]},{"word":"dawn","pos":"n.","phonetic":"[dɔn]","meaning":"黎明；破曉","definition":"the time when light first appears in the morning","collocations":["at dawn","from dawn to dusk","dawn breaks"],"example":"We got up before dawn to watch the sunrise.","exampleZh":"我們天還沒亮就起床看日出。","synonyms":["daybreak"],"level":3,"theme":"時間與空間","examples":[{"en":"We got up before dawn to watch the sunrise.","zh":"我們天還沒亮就起床看日出。"},{"en":"The farmers work from dawn to dusk during the harvest season.","zh":"收穫季節時，農夫們從黎明工作到黃昏。"},{"en":"The birds began to sing just as dawn broke over the hills.","zh":"就在黎明破曉照亮山丘時，鳥兒開始歌唱。"}]},{"word":"day","pos":"n.","phonetic":"[de]","meaning":"天；日子","definition":"a period of twenty-four hours","collocations":["all day","one day","school day"],"example":"I had a very busy day at work.","exampleZh":"我今天工作非常忙碌。","synonyms":[],"level":1,"theme":"時間與空間","examples":[{"en":"I had a very busy day at work.","zh":"我今天工作非常忙碌。"},{"en":"We spent the whole day exploring the old part of the city.","zh":"我們花了一整天探索這座城市的舊城區。"},{"en":"One day I hope to travel across Europe by train.","zh":"總有一天我希望能搭火車橫越歐洲。"}]},{"word":"daydream","pos":"n. / v.","phonetic":"[ˈdeˌdrim]","meaning":"白日夢；做白日夢","definition":"pleasant thoughts that distract from the present","collocations":["daydream about","have a daydream","daydream in class"],"example":"He often daydreams about traveling around the world.","exampleZh":"他常常做白日夢想環遊世界。","synonyms":["fantasy"],"level":3,"theme":"抽象概念","examples":[{"en":"He often daydreams about traveling around the world.","zh":"他常常做白日夢想環遊世界。"},{"en":"The teacher noticed that he was daydreaming in class again.","zh":"老師注意到他又在課堂上做白日夢了。"},{"en":"She often has a daydream about becoming a famous singer.","zh":"她常常幻想自己成為一位著名的歌手。"}]},{"word":"dazzle","pos":"v.","phonetic":"[ˈdæzl]","meaning":"使目眩；使驚豔","definition":"to impress someone greatly or temporarily blind with bright light","collocations":["dazzle the audience","dazzling smile","dazzled by the lights"],"example":"The dancer's performance dazzled the entire audience.","exampleZh":"那位舞者的表演讓全場觀眾為之驚豔。","synonyms":["amaze","impress"],"level":4,"theme":"藝術與音樂","examples":[{"en":"The dancer's performance dazzled the entire audience.","zh":"那位舞者的表演讓全場觀眾為之驚豔。"},{"en":"The bright headlights dazzled the driver for a moment.","zh":"刺眼的車頭燈讓駕駛一時目眩。"},{"en":"Her dazzling smile impressed everyone at the party.","zh":"她燦爛耀眼的笑容讓派對上的每個人都印象深刻。"}]},{"word":"dead","pos":"adj.","phonetic":"[dɛd]","meaning":"死的；不再運作的","definition":"no longer alive or functioning","collocations":["dead battery","dead end","drop dead"],"example":"The phone battery is dead.","exampleZh":"手機電池沒電了。","synonyms":["lifeless"],"level":2,"theme":"身體與健康","examples":[{"en":"The phone battery is dead.","zh":"手機電池沒電了。"},{"en":"We found a dead battery in the old flashlight.","zh":"我們在那支舊手電筒裡發現了一顆沒電的電池。"},{"en":"The street was a dead end, so we had to turn back.","zh":"那條街是死巷，所以我們只好折返。"}]},{"word":"deadline","pos":"n.","phonetic":"[ˈdɛdˌlaɪn]","meaning":"截止日期","definition":"a time by which something must be finished","collocations":["meet a deadline","miss a deadline","tight deadline"],"example":"We have to submit the report before the deadline.","exampleZh":"我們必須在截止日期前繳交報告。","synonyms":["due date"],"level":4,"theme":"工作與職業","examples":[{"en":"We have to submit the report before the deadline.","zh":"我們必須在截止日期前繳交報告。"},{"en":"The reporter worked all night to meet the deadline.","zh":"那位記者熬夜趕工以趕上截止期限。"},{"en":"If you miss the deadline, your application will not be accepted.","zh":"如果你錯過截止日期，你的申請將不被接受。"}]},{"word":"deaf","pos":"adj.","phonetic":"[dɛf]","meaning":"聾的","definition":"unable to hear","collocations":["deaf ear","deaf and mute","go deaf"],"example":"She has been deaf since birth.","exampleZh":"她出生以來就是聾的。","synonyms":[],"level":3,"theme":"身體與健康","examples":[{"en":"She has been deaf since birth.","zh":"她出生以來就是聾的。"},{"en":"He turned a deaf ear to all their complaints.","zh":"他對他們所有的抱怨充耳不聞。"},{"en":"The old man went deaf in one ear after the illness.","zh":"那位老人生病後有一隻耳朵聾了。"}]},{"word":"deal","pos":"n. / v.","phonetic":"[dil]","meaning":"交易；處理","definition":"an agreement, or to handle a situation","collocations":["make a deal","deal with","a good deal"],"example":"We need to deal with this problem quickly.","exampleZh":"我們需要盡快處理這個問題。","synonyms":["handle","agreement"],"level":2,"theme":"商業與金錢","examples":[{"en":"We need to deal with this problem quickly.","zh":"我們需要盡快處理這個問題。"},{"en":"The two companies finally made a deal after long talks.","zh":"經過長時間的談判，兩家公司終於達成了交易。"},{"en":"Teachers must learn to deal with difficult students patiently.","zh":"老師必須學會耐心地處理難搞的學生。"}]},{"word":"dear","pos":"adj.","phonetic":"[dɪr]","meaning":"親愛的；昂貴的","definition":"loved or valued highly; costly","collocations":["dear friend","hold dear","dear to my heart"],"example":"She is a very dear friend of mine.","exampleZh":"她是我非常親愛的朋友。","synonyms":["beloved"],"level":2,"theme":"情緒與感受","examples":[{"en":"She is a very dear friend of mine.","zh":"她是我非常親愛的朋友。"},{"en":"These old photographs are very dear to my heart.","zh":"這些舊照片對我來說彌足珍貴。"},{"en":"She wrote a long letter to her dear friend abroad.","zh":"她寫了一封長信給她在國外的摯友。"}]},{"word":"death","pos":"n.","phonetic":"[dɛθ]","meaning":"死亡","definition":"the end of life","collocations":["cause of death","fear of death","death rate"],"example":"His grandfather's death was a great shock to the family.","exampleZh":"他祖父的過世令全家人非常震驚。","synonyms":["passing"],"level":2,"theme":"身體與健康","examples":[{"en":"His grandfather's death was a great shock to the family.","zh":"他祖父的過世令全家人非常震驚。"},{"en":"The sudden death of the singer shocked millions of fans.","zh":"這位歌手的猝逝震驚了數百萬名歌迷。"},{"en":"Doctors are still trying to find the cause of death.","zh":"醫生們仍在試圖找出死亡的原因。"}]},{"word":"debate","pos":"n. / v.","phonetic":"[dɪˈbet]","meaning":"辯論","definition":"a formal discussion of opposing views","collocations":["hold a debate","debate over","join a debate"],"example":"The students had a heated debate about the new policy.","exampleZh":"學生們針對新政策展開激烈辯論。","synonyms":["argument","discussion"],"level":4,"theme":"溝通與語言","examples":[{"en":"The students had a heated debate about the new policy.","zh":"學生們針對新政策展開激烈辯論。"},{"en":"The two teams will hold a debate about environmental issues.","zh":"兩支隊伍將針對環境議題舉行一場辯論。"},{"en":"Many people joined the debate over the new traffic rules.","zh":"許多人加入了關於新交通規則的辯論。"}]},{"word":"debt","pos":"n.","phonetic":"[dɛt]","meaning":"債務","definition":"money owed to someone","collocations":["pay off debt","in debt","national debt"],"example":"He worked hard to pay off his debt.","exampleZh":"他努力工作來還清債務。","synonyms":["liability"],"level":4,"theme":"商業與金錢","examples":[{"en":"He worked hard to pay off his debt.","zh":"他努力工作來還清債務。"},{"en":"It took him five years to pay off his debt.","zh":"他花了五年才還清債務。"},{"en":"The young couple is deeply in debt after buying a house.","zh":"這對年輕夫妻買房後負債累累。"}]},{"word":"decade","pos":"n.","phonetic":"[ˈdɛked]","meaning":"十年","definition":"a period of ten years","collocations":["over the past decade","last decade","for decades"],"example":"The city has changed a lot over the past decade.","exampleZh":"這座城市在過去十年間變化很大。","synonyms":[],"level":3,"theme":"時間與空間","examples":[{"en":"The city has changed a lot over the past decade.","zh":"這座城市在過去十年間變化很大。"},{"en":"Technology has advanced rapidly over the past decade.","zh":"在過去的十年間，科技進步得非常迅速。"},{"en":"The famous author has written novels for more than three decades.","zh":"這位著名作家寫小說已超過三十年。"}]},{"word":"deceive","pos":"v.","phonetic":"[dɪˈsiv]","meaning":"欺騙；矇騙","definition":"to make someone believe something that is not true","collocations":["deceive someone into doing","deceive the public"],"example":"He deceived his friends about his real intentions.","exampleZh":"他在真正的意圖上欺騙了朋友。","synonyms":["trick","mislead"],"level":5,"theme":"抽象概念","examples":[{"en":"He deceived his friends about his real intentions.","zh":"他在真正的意圖上欺騙了朋友。"},{"en":"He tried to deceive the public with false advertisements.","zh":"他試圖用不實的廣告欺騙大眾。"},{"en":"She was deceived into signing the unfair contract.","zh":"她受騙簽下了那份不公平的合約。"}]},{"word":"decent","pos":"adj.","phonetic":"[ˈdisnt]","meaning":"像樣的；正派的","definition":"of an acceptable standard; morally correct","collocations":["a decent job","decent people","decent salary"],"example":"She finally found a decent job after months of searching.","exampleZh":"她找工作找了好幾個月，終於找到一份像樣的工作。","synonyms":["respectable","adequate"],"level":4,"theme":"性質與描述","examples":[{"en":"She finally found a decent job after months of searching.","zh":"她找工作找了好幾個月，終於找到一份像樣的工作。"},{"en":"After graduation, he hoped to find a decent job quickly.","zh":"畢業後，他希望能快點找到一份像樣的工作。"},{"en":"They are decent people who always help their neighbors.","zh":"他們是正派的人，總是幫助鄰居。"}]},{"word":"decide","pos":"v.","phonetic":"[dɪˈsaɪd]","meaning":"決定","definition":"to make a choice after consideration","collocations":["decide to do","decide on","decide against"],"example":"She decided to study abroad next year.","exampleZh":"她決定明年出國留學。","synonyms":["determine","choose"],"level":2,"theme":"抽象概念","examples":[{"en":"She decided to study abroad next year.","zh":"她決定明年出國留學。"},{"en":"After much thought, she decided to accept the scholarship.","zh":"經過深思熟慮後，她決定接受這份獎學金。"},{"en":"We still haven't decided on a place for our holiday.","zh":"我們還沒決定好度假的地點。"}]},{"word":"decision","pos":"n.","phonetic":"[dɪˈsɪʒən]","meaning":"決定","definition":"a choice made after consideration","collocations":["make a decision","final decision","difficult decision"],"example":"Moving to a new city was a hard decision.","exampleZh":"搬到新城市是一個困難的決定。","synonyms":["choice"],"level":2,"theme":"抽象概念","examples":[{"en":"Moving to a new city was a hard decision.","zh":"搬到新城市是一個困難的決定。"},{"en":"Choosing a career is one of the most difficult decisions in life.","zh":"選擇職業是人生中最艱難的決定之一。"},{"en":"The judges will make a final decision tomorrow morning.","zh":"評審們將在明天早上做出最終決定。"}]},{"word":"decisive","pos":"adj.","phonetic":"[dɪˈsaɪsɪv]","meaning":"果斷的；決定性的","definition":"able to make decisions quickly and confidently","collocations":["decisive action","a decisive victory","decisive leader"],"example":"The coach made a decisive move that won the game.","exampleZh":"教練做出了一個決定性的舉動，贏得了比賽。","synonyms":["resolute","firm"],"level":5,"theme":"性質與描述","examples":[{"en":"The coach made a decisive move that won the game.","zh":"教練做出了一個決定性的舉動，贏得了比賽。"},{"en":"A good leader must be decisive in times of crisis.","zh":"一位好的領導者在危機時刻必須果斷。"},{"en":"Her last goal was decisive and won the championship.","zh":"她最後的一球具有決定性，贏得了冠軍。"}]},{"word":"declare","pos":"v.","phonetic":"[dɪˈklɛr]","meaning":"宣布；聲明","definition":"to state something officially or firmly","collocations":["declare war","declare independence","declare openly"],"example":"The government declared a state of emergency.","exampleZh":"政府宣布進入緊急狀態。","synonyms":["announce","proclaim"],"level":5,"theme":"政治與法律","examples":[{"en":"The government declared a state of emergency.","zh":"政府宣布進入緊急狀態。"},{"en":"The president declared that a new law would take effect soon.","zh":"總統宣布一項新法律即將生效。"},{"en":"Travelers must declare any valuable items at customs.","zh":"旅客必須向海關申報任何貴重物品。"}]},{"word":"decline","pos":"v. / n.","phonetic":"[dɪˈklaɪn]","meaning":"下降；婉拒","definition":"to become smaller or worse, or to refuse politely","collocations":["decline an offer","decline in sales","sharp decline"],"example":"Sales have declined sharply this quarter.","exampleZh":"本季銷售大幅下滑。","synonyms":["refuse","decrease"],"level":5,"theme":"商業與金錢","examples":[{"en":"Sales have declined sharply this quarter.","zh":"本季銷售大幅下滑。"},{"en":"He politely declined the invitation to the dinner party.","zh":"他婉拒了那場晚宴的邀請。"},{"en":"The number of visitors has declined sharply this winter.","zh":"今年冬天遊客的人數大幅下降。"}]},{"word":"decrease","pos":"v. / n.","phonetic":"[dɪˈkris]","meaning":"減少","definition":"to become or make smaller in size or amount","collocations":["decrease in number","sharp decrease","gradually decrease"],"example":"The population of the village has decreased over the years.","exampleZh":"這個村莊的人口這些年來逐漸減少。","synonyms":["reduce","decline"],"level":4,"theme":"抽象概念","examples":[{"en":"The population of the village has decreased over the years.","zh":"這個村莊的人口這些年來逐漸減少。"},{"en":"Regular exercise can decrease the risk of heart disease.","zh":"規律運動可以降低罹患心臟病的風險。"},{"en":"There has been a sharp decrease in the birth rate.","zh":"出生率出現了急遽的下降。"}]},{"word":"dedicate","pos":"v.","phonetic":"[ˈdɛdɪˌket]","meaning":"奉獻；致力於","definition":"to devote time or effort to a particular purpose","collocations":["dedicate one's life to","dedicate a book to"],"example":"She dedicated her life to helping the poor.","exampleZh":"她將一生奉獻於幫助窮人。","synonyms":["devote","commit"],"level":5,"theme":"抽象概念","examples":[{"en":"She dedicated her life to helping the poor.","zh":"她將一生奉獻於幫助窮人。"},{"en":"The young doctor dedicated himself to helping poor villagers.","zh":"這位年輕醫生致力於幫助貧窮的村民。"},{"en":"The author dedicated the book to her supportive parents.","zh":"作者把這本書獻給支持她的父母。"}]},{"word":"deep","pos":"adj.","phonetic":"[dip]","meaning":"深的","definition":"extending far down or in","collocations":["deep water","deep breath","deep sleep"],"example":"He took a deep breath before the interview.","exampleZh":"他在面試前深深吸了一口氣。","synonyms":["profound"],"level":1,"theme":"性質與描述","examples":[{"en":"He took a deep breath before the interview.","zh":"他在面試前深深吸了一口氣。"},{"en":"The lake is so deep that no one has reached the bottom.","zh":"這座湖非常深，沒有人曾抵達湖底。"},{"en":"She fell into a deep sleep as soon as she lay down.","zh":"她一躺下就陷入了深沉的睡眠。"}]},{"word":"deer","pos":"n.","phonetic":"[dɪr]","meaning":"鹿","definition":"a hoofed grazing animal with antlers","collocations":["a herd of deer","wild deer","deer hunting"],"example":"A deer ran across the road in front of our car.","exampleZh":"一隻鹿跑過我們車子前方的馬路。","synonyms":[],"level":1,"theme":"動物與植物","examples":[{"en":"A deer ran across the road in front of our car.","zh":"一隻鹿跑過我們車子前方的馬路。"},{"en":"A herd of deer grazed peacefully in the open field.","zh":"一群鹿在開闊的原野上安詳地吃著草。"},{"en":"We spotted a wild deer drinking from the mountain stream.","zh":"我們看見一隻野鹿在山間溪流邊喝水。"}]},{"word":"defeat","pos":"v. / n.","phonetic":"[dɪˈfit]","meaning":"擊敗；失敗","definition":"to win against someone in a battle or contest","collocations":["defeat the enemy","admit defeat","suffer defeat"],"example":"Our team defeated the rivals in the final game.","exampleZh":"我們隊在決賽中擊敗了對手。","synonyms":["beat","overcome"],"level":4,"theme":"運動與休閒","examples":[{"en":"Our team defeated the rivals in the final game.","zh":"我們隊在決賽中擊敗了對手。"},{"en":"The soldiers fought bravely to defeat the enemy.","zh":"士兵們英勇奮戰以擊敗敵人。"},{"en":"After a long struggle, the champion refused to admit defeat.","zh":"經過長時間的奮鬥，冠軍拒絕認輸。"}]},{"word":"defend","pos":"v.","phonetic":"[dɪˈfɛnd]","meaning":"防禦；辯護","definition":"to protect from attack or criticism","collocations":["defend against","defend a decision","defend one's rights"],"example":"Soldiers were sent to defend the border.","exampleZh":"士兵被派去防守邊境。","synonyms":["protect","guard"],"level":3,"theme":"政治與法律","examples":[{"en":"Soldiers were sent to defend the border.","zh":"士兵被派去防守邊境。"},{"en":"The lawyer worked hard to defend his innocent client.","zh":"那位律師努力為他無辜的委託人辯護。"},{"en":"The castle walls were built to defend against invaders.","zh":"這座城堡的城牆是為了抵禦入侵者而建造的。"}]},{"word":"defiant","pos":"adj.","phonetic":"[dɪˈfaɪənt]","meaning":"反抗的；挑釁的","definition":"showing open resistance or bold disobedience","collocations":["a defiant attitude","remain defiant"],"example":"The teenager gave a defiant look and refused to apologize.","exampleZh":"那位青少年露出反抗的神情，拒絕道歉。","synonyms":["rebellious","disobedient"],"level":6,"theme":"情緒與感受","examples":[{"en":"The teenager gave a defiant look and refused to apologize.","zh":"那位青少年露出反抗的神情，拒絕道歉。"},{"en":"The workers remained defiant despite the manager's warnings.","zh":"儘管經理提出警告，工人們仍然堅持反抗。"},{"en":"She gave a defiant answer and refused to follow the order.","zh":"她給了一個挑釁的回答，並拒絕服從命令。"}]},{"word":"deficient","pos":"adj.","phonetic":"[dɪˈfɪʃənt]","meaning":"不足的；缺乏的","definition":"lacking something necessary or complete","collocations":["deficient in vitamins","nutritionally deficient"],"example":"A diet deficient in iron can cause fatigue.","exampleZh":"缺鐵的飲食會導致疲勞。","synonyms":["lacking","insufficient"],"level":6,"theme":"身體與健康","examples":[{"en":"A diet deficient in iron can cause fatigue.","zh":"缺鐵的飲食會導致疲勞。"},{"en":"Many children in poor areas are deficient in basic nutrients.","zh":"許多貧困地區的孩童缺乏基本的營養素。"},{"en":"A diet deficient in vitamins can weaken the immune system.","zh":"缺乏維生素的飲食會削弱免疫系統。"}]},{"word":"define","pos":"v.","phonetic":"[dɪˈfaɪn]","meaning":"下定義；界定","definition":"to state the exact meaning of something","collocations":["define a term","clearly defined","define success"],"example":"The dictionary defines the word clearly.","exampleZh":"這本字典清楚地為這個字下定義。","synonyms":["explain","specify"],"level":4,"theme":"教育與學習","examples":[{"en":"The dictionary defines the word clearly.","zh":"這本字典清楚地為這個字下定義。"},{"en":"It is difficult to define happiness in a single sentence.","zh":"很難用一句話來定義快樂。"},{"en":"The rules clearly define what students are allowed to do.","zh":"這些規則清楚地界定了學生被允許做的事。"}]},{"word":"definite","pos":"adj.","phonetic":"[ˈdɛfənɪt]","meaning":"明確的；確定的","definition":"clear and certain","collocations":["definite answer","definite plan","fairly definite"],"example":"We need a definite answer by tomorrow.","exampleZh":"我們需要在明天前得到一個明確的答案。","synonyms":["certain","clear"],"level":4,"theme":"性質與描述","examples":[{"en":"We need a definite answer by tomorrow.","zh":"我們需要在明天前得到一個明確的答案。"},{"en":"The manager gave us a definite answer about the schedule.","zh":"經理給了我們關於時程的明確答覆。"},{"en":"We don't have a definite plan for the summer vacation yet.","zh":"我們還沒有暑假的確定計畫。"}]},{"word":"definitely","pos":"adv.","phonetic":"[ˈdɛfənɪtlɪ]","meaning":"確實地；肯定地","definition":"without doubt; certainly","collocations":["definitely true","will definitely come","definitely not"],"example":"I will definitely attend your birthday party.","exampleZh":"我一定會參加你的生日派對。","synonyms":["certainly"],"level":3,"theme":"溝通與語言","examples":[{"en":"I will definitely attend your birthday party.","zh":"我一定會參加你的生日派對。"},{"en":"I will definitely finish the project before the weekend.","zh":"我一定會在週末前完成這個專案。"},{"en":"That is definitely not the answer the teacher expected.","zh":"那絕對不是老師所期待的答案。"}]},{"word":"degree","pos":"n.","phonetic":"[dɪˈgri]","meaning":"程度；學位；度數","definition":"a unit of measurement, or an academic qualification","collocations":["bachelor's degree","to some degree","30 degrees"],"example":"She earned a degree in economics.","exampleZh":"她獲得經濟學學位。","synonyms":["extent"],"level":3,"theme":"教育與學習","examples":[{"en":"She earned a degree in economics.","zh":"她獲得經濟學學位。"},{"en":"The temperature dropped to five degrees during the cold night.","zh":"在那個寒冷的夜晚，氣溫降到了五度。"},{"en":"She earned a bachelor's degree in engineering last year.","zh":"她去年取得了工程學的學士學位。"}]},{"word":"delay","pos":"v. / n.","phonetic":"[dɪˈle]","meaning":"延遲；耽擱","definition":"to make something happen later than planned","collocations":["delay a flight","without delay","delay the meeting"],"example":"The flight was delayed due to bad weather.","exampleZh":"班機因天候不佳而延誤。","synonyms":["postpone"],"level":3,"theme":"交通與旅行","examples":[{"en":"The flight was delayed due to bad weather.","zh":"班機因天候不佳而延誤。"},{"en":"Heavy snow delayed all the flights at the airport.","zh":"大雪使機場所有的班機都延誤了。"},{"en":"Please reply to this message without delay.","zh":"請立即回覆這則訊息，不要拖延。"}]},{"word":"delegate","pos":"n. / v.","phonetic":"[ˈdɛlɪˌɡet]","meaning":"代表；代表團成員；委派","definition":"a person sent to represent others; to assign responsibility to someone else","collocations":["delegate a task","conference delegate","delegate authority"],"example":"The manager decided to delegate some tasks to her team.","exampleZh":"經理決定將一些任務委派給她的團隊。","synonyms":["representative","assign"],"level":6,"theme":"工作與職業","examples":[{"en":"The manager decided to delegate some tasks to her team.","zh":"經理決定將一些任務委派給她的團隊。"},{"en":"A good manager knows how to delegate tasks to her team.","zh":"一位好的經理懂得如何把任務委派給她的團隊。"},{"en":"Each country sent a delegate to attend the youth conference.","zh":"每個國家都派了一位代表出席這場青年會議。"}]},{"word":"deliberate","pos":"adj. / v.","phonetic":"[dɪˈlɪbərɪt]","meaning":"故意的；深思熟慮的；仔細考慮","definition":"done on purpose; to think carefully about something","collocations":["a deliberate choice","deliberate on a decision"],"example":"It was a deliberate decision to move to a smaller city.","exampleZh":"搬到較小的城市是一個經過深思熟慮的決定。","synonyms":["intentional","calculated"],"level":5,"theme":"抽象概念","examples":[{"en":"It was a deliberate decision to move to a smaller city.","zh":"搬到較小的城市是一個經過深思熟慮的決定。"},{"en":"The committee will deliberate on the proposal for several days.","zh":"委員會將針對這項提案審慎討論好幾天。"},{"en":"Ignoring the warning sign was a deliberate act of carelessness.","zh":"無視警告標誌是一種故意的疏忽行為。"}]},{"word":"delicate","pos":"adj.","phonetic":"[ˈdɛlɪkɪt]","meaning":"精緻的；脆弱的；細膩的","definition":"easily damaged or requiring careful handling; fine in texture","collocations":["a delicate situation","delicate skin","handle with delicate care"],"example":"The vase is very delicate, so please handle it carefully.","exampleZh":"這個花瓶非常脆弱，請小心搬運。","synonyms":["fragile","fine"],"level":5,"theme":"性質與描述","examples":[{"en":"The vase is very delicate, so please handle it carefully.","zh":"這個花瓶非常脆弱，請小心搬運。"},{"en":"The artist painted the delicate petals of the rose with great care.","zh":"這位藝術家非常細心地畫出玫瑰精緻的花瓣。"},{"en":"Negotiating peace between the two sides is a delicate situation.","zh":"在雙方之間協調和平是一個微妙棘手的情況。"}]},{"word":"delicious","pos":"adj.","phonetic":"[dɪˈlɪʃəs]","meaning":"美味的","definition":"having a very pleasant taste","collocations":["delicious meal","smell delicious","absolutely delicious"],"example":"The cake she baked was absolutely delicious.","exampleZh":"她烤的蛋糕非常美味。","synonyms":["tasty","yummy"],"level":2,"theme":"食物與烹飪","examples":[{"en":"The cake she baked was absolutely delicious.","zh":"她烤的蛋糕非常美味。"},{"en":"The soup smelled so delicious that everyone wanted a bowl.","zh":"這湯聞起來太美味了，每個人都想來一碗。"},{"en":"We enjoyed a delicious meal at the small family restaurant.","zh":"我們在那家小小的家庭餐廳享用了一頓美味的餐點。"}]},{"word":"delightful","pos":"adj.","phonetic":"[dɪˈlaɪtfəl]","meaning":"令人愉快的；討人喜歡的","definition":"causing delight; charming and pleasant","collocations":["a delightful surprise","delightful weather"],"example":"We had a delightful evening at the beach.","exampleZh":"我們在海灘度過了一個愉快的夜晚。","synonyms":["pleasant","charming"],"level":3,"theme":"情緒與感受","examples":[{"en":"We had a delightful evening at the beach.","zh":"我們在海灘度過了一個愉快的夜晚。"},{"en":"The garden was full of delightful colors in early spring.","zh":"初春時，花園裡充滿了令人愉悅的色彩。"},{"en":"Meeting such a delightful child brightened everyone's day.","zh":"遇見這麼討人喜歡的孩子讓每個人的一天都變得明亮。"}]},{"word":"deliver","pos":"v.","phonetic":"[dɪˈlɪvɚ]","meaning":"遞送；發表","definition":"to bring goods or a message to a place, or give a speech","collocations":["deliver a package","deliver a speech","deliver on time"],"example":"The mailman delivers letters every morning.","exampleZh":"郵差每天早上送信。","synonyms":["bring","carry"],"level":3,"theme":"工作與職業","examples":[{"en":"The mailman delivers letters every morning.","zh":"郵差每天早上送信。"},{"en":"The company promises to deliver every package on time.","zh":"這家公司承諾準時遞送每一件包裹。"},{"en":"The principal will deliver a speech at the graduation ceremony.","zh":"校長將在畢業典禮上發表演說。"}]},{"word":"demand","pos":"n. / v.","phonetic":"[dɪˈmænd]","meaning":"需求；要求","definition":"an insistent request, or the desire for goods or services","collocations":["in high demand","demand payment","meet demand"],"example":"There is a high demand for skilled workers.","exampleZh":"目前對熟練工人的需求很高。","synonyms":["request","require"],"level":4,"theme":"商業與金錢","examples":[{"en":"There is a high demand for skilled workers.","zh":"目前對熟練工人的需求很高。"},{"en":"There is a high demand for electric cars in the city.","zh":"這座城市對電動車有很高的需求。"},{"en":"The angry customers demanded a full refund immediately.","zh":"憤怒的顧客要求立即全額退款。"}]},{"word":"demonstrate","pos":"v.","phonetic":"[ˈdɛmənˌstret]","meaning":"示範；證明；展示","definition":"to show clearly by giving proof or evidence","collocations":["demonstrate a skill","demonstrate how to","demonstrate against"],"example":"The teacher demonstrated how to solve the equation.","exampleZh":"老師示範了如何解這道方程式。","synonyms":["show","prove"],"level":4,"theme":"教育與學習","examples":[{"en":"The teacher demonstrated how to solve the equation.","zh":"老師示範了如何解這道方程式。"},{"en":"The coach demonstrated the correct way to throw the ball.","zh":"教練示範了投球的正確方法。"},{"en":"The results clearly demonstrate the benefits of regular exercise.","zh":"這些結果清楚地證明了規律運動的好處。"}]},{"word":"dense","pos":"adj.","phonetic":"[dɛns]","meaning":"密集的；濃厚的","definition":"closely packed together","collocations":["dense forest","dense population","dense fog"],"example":"The city has a dense population.","exampleZh":"這座城市人口密度很高。","synonyms":["thick","compact"],"level":5,"theme":"性質與描述","examples":[{"en":"The city has a dense population.","zh":"這座城市人口密度很高。"},{"en":"The explorers slowly made their way through the dense forest.","zh":"探險家們緩慢地穿過那片茂密的森林。"},{"en":"A dense fog covered the harbor early this morning.","zh":"今天清晨，濃霧籠罩了港口。"}]},{"word":"dentist","pos":"n.","phonetic":"[ˈdɛntɪst]","meaning":"牙醫","definition":"a doctor who treats teeth","collocations":["visit the dentist","see a dentist","dentist appointment"],"example":"I have an appointment with the dentist tomorrow.","exampleZh":"我明天跟牙醫有約。","synonyms":[],"level":2,"theme":"身體與健康","examples":[{"en":"I have an appointment with the dentist tomorrow.","zh":"我明天跟牙醫有約。"},{"en":"The dentist advised me to brush my teeth twice a day.","zh":"牙醫建議我每天刷兩次牙。"},{"en":"She was nervous before her dentist appointment this afternoon.","zh":"今天下午看牙醫前，她感到很緊張。"}]},{"word":"deny","pos":"v.","phonetic":"[dɪˈnaɪ]","meaning":"否認","definition":"to state that something is not true","collocations":["deny the charge","deny doing something","flatly deny"],"example":"He denied stealing the money.","exampleZh":"他否認偷了那筆錢。","synonyms":["refute"],"level":4,"theme":"溝通與語言","examples":[{"en":"He denied stealing the money.","zh":"他否認偷了那筆錢。"},{"en":"The suspect continued to deny any involvement in the crime.","zh":"嫌疑人持續否認與這起犯罪有任何關聯。"},{"en":"He flatly denied breaking the classroom window.","zh":"他斷然否認打破了教室的窗戶。"}]},{"word":"depart","pos":"v.","phonetic":"[dɪˈpɑrt]","meaning":"出發；離開","definition":"to leave, especially to start a journey","collocations":["depart from","flight departs","depart for"],"example":"The train departs from platform three.","exampleZh":"火車從第三月台出發。","synonyms":["leave"],"level":4,"theme":"交通與旅行","examples":[{"en":"The train departs from platform three.","zh":"火車從第三月台出發。"},{"en":"The bus will depart for the mountains at seven o'clock.","zh":"巴士將在七點出發前往山區。"},{"en":"Passengers should arrive early before the ferry departs.","zh":"在渡輪出發前，乘客應提早抵達。"}]},{"word":"department","pos":"n.","phonetic":"[dɪˈpɑrtmənt]","meaning":"部門；系","definition":"a division within an organization or institution","collocations":["sales department","department store","history department"],"example":"She works in the marketing department.","exampleZh":"她在行銷部門工作。","synonyms":["division"],"level":2,"theme":"工作與職業","examples":[{"en":"She works in the marketing department.","zh":"她在行銷部門工作。"},{"en":"She was promoted to lead the sales department last month.","zh":"上個月她獲升遷，領導業務部門。"},{"en":"The history department offers many interesting courses this year.","zh":"歷史系今年開設了許多有趣的課程。"}]},{"word":"depend","pos":"v.","phonetic":"[dɪˈpɛnd]","meaning":"依賴；視情況而定","definition":"to rely on someone or something","collocations":["depend on","it depends","depend heavily"],"example":"Children depend on their parents for support.","exampleZh":"孩子依賴父母的支持。","synonyms":["rely"],"level":2,"theme":"抽象概念","examples":[{"en":"Children depend on their parents for support.","zh":"孩子依賴父母的支持。"},{"en":"Young birds depend on their parents for food and safety.","zh":"幼鳥依賴牠們的父母提供食物和安全。"},{"en":"Whether we go hiking depends entirely on the weather.","zh":"我們是否去健行完全取決於天氣。"}]},{"word":"depict","pos":"v.","phonetic":"[dɪˈpɪkt]","meaning":"描繪；描寫","definition":"to represent or portray something in a picture or words","collocations":["depict a scene","depicted in the novel"],"example":"The painting depicts a peaceful countryside village.","exampleZh":"這幅畫描繪了一個寧靜的鄉村。","synonyms":["portray","illustrate"],"level":5,"theme":"藝術與音樂","examples":[{"en":"The painting depicts a peaceful countryside village.","zh":"這幅畫描繪了一個寧靜的鄉村。"},{"en":"The mural depicts the daily life of ancient farmers.","zh":"這幅壁畫描繪了古代農民的日常生活。"},{"en":"The novel vividly depicts life in a small fishing town.","zh":"這本小說生動地描寫了一座小漁鎮的生活。"}]},{"word":"deposit","pos":"n. / v.","phonetic":"[dɪˈpɑzɪt]","meaning":"存款；訂金；存放","definition":"a sum of money placed in a bank or as a partial payment; to place something somewhere","collocations":["make a deposit","pay a deposit","deposit money"],"example":"You need to pay a deposit before renting the apartment.","exampleZh":"租這間公寓之前你需要先付訂金。","synonyms":["down payment"],"level":4,"theme":"商業與金錢","examples":[{"en":"You need to pay a deposit before renting the apartment.","zh":"租這間公寓之前你需要先付訂金。"},{"en":"She went to the bank to deposit her monthly salary.","zh":"她去銀行存入她的月薪。"},{"en":"We paid a deposit to reserve the seaside cabin.","zh":"我們付了訂金以預訂那間海邊小屋。"}]},{"word":"depression","pos":"n.","phonetic":"[dɪˈprɛʃən]","meaning":"憂鬱症；蕭條","definition":"a state of severe sadness, or an economic downturn","collocations":["suffer from depression","economic depression","fight depression"],"example":"He was diagnosed with depression last year.","exampleZh":"他去年被診斷出患有憂鬱症。","synonyms":["sadness"],"level":6,"theme":"情緒與感受","examples":[{"en":"He was diagnosed with depression last year.","zh":"他去年被診斷出患有憂鬱症。"},{"en":"Regular exercise can help people cope with depression.","zh":"規律運動可以幫助人們對抗憂鬱症。"},{"en":"Many factories closed down during the economic depression.","zh":"在經濟蕭條期間，許多工廠倒閉了。"}]},{"word":"deputy","pos":"n.","phonetic":"[ˈdɛpjəti]","meaning":"副手；代理人","definition":"a person appointed to act on behalf of another","collocations":["deputy mayor","deputy manager"],"example":"The deputy manager ran the meeting in the boss's absence.","exampleZh":"老闆不在時，副理主持了這場會議。","synonyms":["assistant","substitute"],"level":5,"theme":"工作與職業","examples":[{"en":"The deputy manager ran the meeting in the boss's absence.","zh":"老闆不在時，副理主持了這場會議。"},{"en":"The deputy mayor attended the ceremony on behalf of the city.","zh":"副市長代表本市出席了這場典禮。"},{"en":"When the director is away, his deputy makes the decisions.","zh":"主管不在時，由他的副手做決定。"}]},{"word":"derive","pos":"v.","phonetic":"[dɪˈraɪv]","meaning":"源自；獲得","definition":"to obtain something from a particular source","collocations":["derive from","derive satisfaction from","derive a conclusion"],"example":"The word 'biology' derives from Greek roots.","exampleZh":"「biology」這個字源自希臘字根。","synonyms":["originate","stem"],"level":5,"theme":"溝通與語言","examples":[{"en":"The word 'biology' derives from Greek roots.","zh":"「biology」這個字源自希臘字根。"},{"en":"Many English words derive from Latin and Greek.","zh":"許多英文單字源自拉丁文和希臘文。"},{"en":"She derives great satisfaction from teaching young children.","zh":"她從教導幼童中獲得極大的滿足感。"}]},{"word":"descend","pos":"v.","phonetic":"[dɪˈsɛnd]","meaning":"下降；下來","definition":"to move downward from a higher place","collocations":["descend the stairs","descend into chaos"],"example":"The plane began to descend as it approached the airport.","exampleZh":"飛機在接近機場時開始下降。","synonyms":["descend","go down"],"level":4,"theme":"動作與行為","examples":[{"en":"The plane began to descend as it approached the airport.","zh":"飛機在接近機場時開始下降。"},{"en":"The climbers began to descend the mountain before sunset.","zh":"登山者在日落前開始下山。"},{"en":"Please hold the handrail as you descend the steep stairs.","zh":"下這道陡峭的樓梯時，請扶著扶手。"}]},{"word":"describe","pos":"v.","phonetic":"[dɪˈskraɪb]","meaning":"描述","definition":"to give a detailed account of something","collocations":["describe in detail","describe as","hard to describe"],"example":"Can you describe what happened last night?","exampleZh":"你能描述一下昨晚發生了什麼事嗎？","synonyms":["depict"],"level":2,"theme":"溝通與語言","examples":[{"en":"Can you describe what happened last night?","zh":"你能描述一下昨晚發生了什麼事嗎？"},{"en":"The witness tried to describe the man she had seen.","zh":"目擊者試圖描述她所看到的那名男子。"},{"en":"It is hard to describe the beauty of the sunset in words.","zh":"很難用言語描述那日落之美。"}]},{"word":"desert","pos":"n.","phonetic":"[ˈdɛzɚt]","meaning":"沙漠","definition":"a large area of dry, sandy land","collocations":["desert climate","cross the desert","desert island"],"example":"Very little rain falls in the desert.","exampleZh":"沙漠裡降雨量非常少。","synonyms":[],"level":3,"theme":"自然與環境","examples":[{"en":"Very little rain falls in the desert.","zh":"沙漠裡降雨量非常少。"},{"en":"Camels can survive for days while crossing the desert.","zh":"駱駝在穿越沙漠時可以好幾天不進食也能存活。"},{"en":"The story is about a man stranded on a desert island.","zh":"這個故事是關於一個被困在荒島上的男子。"}]},{"word":"deserve","pos":"v.","phonetic":"[dɪˈzɝv]","meaning":"應得；值得","definition":"to have earned or be worthy of something","collocations":["deserve credit","deserve a break","richly deserve"],"example":"You deserve a reward for your hard work.","exampleZh":"你的努力值得獲得獎勵。","synonyms":["merit"],"level":4,"theme":"抽象概念","examples":[{"en":"You deserve a reward for your hard work.","zh":"你的努力值得獲得獎勵。"},{"en":"After all her hard work, she deserves a long vacation.","zh":"在她所有的努力之後，她應該享有一個長假。"},{"en":"The brave firefighters deserve credit for saving the family.","zh":"這些勇敢的消防員因拯救了那家人而值得讚許。"}]},{"word":"design","pos":"n. / v.","phonetic":"[dɪˈzaɪn]","meaning":"設計","definition":"a plan or drawing showing how something will look or work","collocations":["design a building","fashion design","graphic design"],"example":"She designed the poster for the school festival.","exampleZh":"她為校慶設計了海報。","synonyms":["plan","create"],"level":3,"theme":"藝術與音樂","examples":[{"en":"She designed the poster for the school festival.","zh":"她為校慶設計了海報。"},{"en":"The students were asked to design a poster for the fair.","zh":"學生們被要求為園遊會設計一張海報。"},{"en":"The new phone has a sleek and modern design.","zh":"這支新手機擁有時尚而現代的設計。"}]},{"word":"desire","pos":"n. / v.","phonetic":"[dɪˈzaɪr]","meaning":"渴望；欲望","definition":"a strong wish for something","collocations":["desire to succeed","strong desire","fulfill a desire"],"example":"She has a strong desire to travel the world.","exampleZh":"她非常渴望環遊世界。","synonyms":["wish","longing"],"level":4,"theme":"情緒與感受","examples":[{"en":"She has a strong desire to travel the world.","zh":"她非常渴望環遊世界。"},{"en":"He has a strong desire to become a professional musician.","zh":"他強烈渴望成為一名職業音樂家。"},{"en":"Nothing could stop her desire to help others in need.","zh":"沒有什麼能阻止她幫助需要幫助之人的渴望。"}]},{"word":"desk","pos":"n.","phonetic":"[dɛsk]","meaning":"書桌；辦公桌","definition":"a piece of furniture with a flat top for writing or working","collocations":["office desk","clean up the desk","front desk"],"example":"He keeps his desk very tidy.","exampleZh":"他把書桌整理得很整齊。","synonyms":[],"level":1,"theme":"居家與生活","examples":[{"en":"He keeps his desk very tidy.","zh":"他把書桌整理得很整齊。"},{"en":"She organized all her books neatly on the desk.","zh":"她把所有的書整齊地擺放在書桌上。"},{"en":"Please leave your key at the front desk when you check out.","zh":"退房時，請將鑰匙留在櫃台。"}]},{"word":"despite","pos":"prep.","phonetic":"[dɪˈspaɪt]","meaning":"儘管","definition":"without being affected by; in spite of","collocations":["despite the rain","despite his efforts","despite all odds"],"example":"Despite the heavy rain, the game continued.","exampleZh":"儘管下著大雨，比賽仍繼續進行。","synonyms":["in spite of"],"level":4,"theme":"抽象概念","examples":[{"en":"Despite the heavy rain, the game continued.","zh":"儘管下著大雨，比賽仍繼續進行。"},{"en":"Despite his injury, the athlete finished the entire race.","zh":"儘管受了傷，這位運動員還是跑完了整場比賽。"},{"en":"She stayed calm despite all the noise around her.","zh":"儘管周圍一片吵雜，她仍保持冷靜。"}]},{"word":"dessert","pos":"n.","phonetic":"[dɪˈzɝt]","meaning":"甜點","definition":"a sweet course eaten at the end of a meal","collocations":["order dessert","favorite dessert","dessert menu"],"example":"We ordered chocolate cake for dessert.","exampleZh":"我們點了巧克力蛋糕當甜點。","synonyms":["sweet"],"level":2,"theme":"食物與烹飪","examples":[{"en":"We ordered chocolate cake for dessert.","zh":"我們點了巧克力蛋糕當甜點。"},{"en":"The waiter handed us the dessert menu after the main course.","zh":"主餐後，服務生把甜點菜單遞給我們。"},{"en":"My favorite dessert is a slice of warm apple pie.","zh":"我最愛的甜點是一片溫熱的蘋果派。"}]},{"word":"destroy","pos":"v.","phonetic":"[dɪˈstrɔɪ]","meaning":"摧毀","definition":"to damage something so badly it no longer exists or works","collocations":["destroy evidence","completely destroy","destroy a building"],"example":"The earthquake destroyed hundreds of houses.","exampleZh":"這場地震摧毀了數百棟房屋。","synonyms":["demolish","ruin"],"level":3,"theme":"自然與環境","examples":[{"en":"The earthquake destroyed hundreds of houses.","zh":"這場地震摧毀了數百棟房屋。"},{"en":"The huge fire destroyed the entire factory within hours.","zh":"這場大火在幾小時內就摧毀了整座工廠。"},{"en":"Careless tourists can destroy fragile natural environments.","zh":"粗心的遊客可能會破壞脆弱的自然環境。"}]},{"word":"detail","pos":"n.","phonetic":"[ˈditel]","meaning":"細節","definition":"a small individual feature or fact","collocations":["in detail","pay attention to detail","every detail"],"example":"Please explain the plan in detail.","exampleZh":"請詳細說明這個計畫。","synonyms":["particular"],"level":3,"theme":"抽象概念","examples":[{"en":"Please explain the plan in detail.","zh":"請詳細說明這個計畫。"},{"en":"The guide explained the tour schedule in great detail.","zh":"導遊非常詳細地說明了行程安排。"},{"en":"A good designer pays close attention to every detail.","zh":"一位優秀的設計師會非常注重每一個細節。"}]},{"word":"detect","pos":"v.","phonetic":"[dɪˈtɛkt]","meaning":"偵測；察覺","definition":"to discover or identify the presence of something","collocations":["detect a problem","hard to detect","detect a signal"],"example":"The device can detect smoke early.","exampleZh":"這個裝置能及早偵測到煙霧。","synonyms":["discover","notice"],"level":5,"theme":"科學與數學","examples":[{"en":"The device can detect smoke early.","zh":"這個裝置能及早偵測到煙霧。"},{"en":"The new alarm can detect smoke within seconds.","zh":"這個新警報器可以在幾秒內偵測到煙霧。"},{"en":"The teacher was quick to detect the change in his mood.","zh":"老師很快就察覺到他情緒的變化。"}]},{"word":"deteriorate","pos":"v.","phonetic":"[dɪˈtɪriəˌret]","meaning":"惡化；變壞","definition":"to become progressively worse","collocations":["health deteriorates","relations deteriorate"],"example":"Her health began to deteriorate after the accident.","exampleZh":"意外發生後，她的健康狀況開始惡化。","synonyms":["worsen","decline"],"level":6,"theme":"身體與健康","examples":[{"en":"Her health began to deteriorate after the accident.","zh":"意外發生後，她的健康狀況開始惡化。"},{"en":"Without proper care, the patient's condition may deteriorate.","zh":"若沒有適當的照護，病人的狀況可能會惡化。"},{"en":"Relations between the two neighbors slowly deteriorated.","zh":"這兩位鄰居之間的關係逐漸惡化。"}]},{"word":"determine","pos":"v.","phonetic":"[dɪˈtɝmɪn]","meaning":"決定；確定","definition":"to establish something precisely; to decide firmly","collocations":["determine the cause","determine to succeed","yet to be determined"],"example":"Scientists tried to determine the cause of the disease.","exampleZh":"科學家試圖確定這種疾病的成因。","synonyms":["decide","resolve"],"level":5,"theme":"科學與數學","examples":[{"en":"Scientists tried to determine the cause of the disease.","zh":"科學家試圖確定這種疾病的成因。"},{"en":"The referee will determine whether the goal was valid.","zh":"裁判將判定這個進球是否有效。"},{"en":"Hard work and attitude often determine a person's success.","zh":"努力和態度往往決定一個人的成功。"}]},{"word":"devastate","pos":"v.","phonetic":"[ˈdɛvəˌstet]","meaning":"摧毀；使震驚悲痛","definition":"to destroy completely or cause severe emotional shock","collocations":["devastate a region","devastated by the news"],"example":"The earthquake devastated the entire coastal town.","exampleZh":"這場地震摧毀了整個沿海小鎮。","synonyms":["destroy","ravage"],"level":6,"theme":"自然與環境","examples":[{"en":"The earthquake devastated the entire coastal town.","zh":"這場地震摧毀了整個沿海小鎮。"},{"en":"A powerful typhoon devastated the small island overnight.","zh":"一場強烈的颱風在一夜之間摧毀了這座小島。"},{"en":"She was devastated by the news of her friend's illness.","zh":"朋友生病的消息讓她悲痛欲絕。"}]},{"word":"develop","pos":"v.","phonetic":"[dɪˈvɛləp]","meaning":"發展；開發","definition":"to grow or cause to grow and become more advanced","collocations":["develop a skill","develop a country","develop software"],"example":"The country has developed rapidly in recent years.","exampleZh":"這個國家近年來發展迅速。","synonyms":["grow","evolve"],"level":3,"theme":"抽象概念","examples":[{"en":"The country has developed rapidly in recent years.","zh":"這個國家近年來發展迅速。"},{"en":"Reading widely helps children develop their imagination.","zh":"廣泛閱讀有助於孩子發展想像力。"},{"en":"The team spent two years developing a new mobile app.","zh":"這個團隊花了兩年開發一款新的手機應用程式。"}]},{"word":"development","pos":"n.","phonetic":"[dɪˈvɛləpmənt]","meaning":"發展；開發","definition":"the process of growing or being improved","collocations":["economic development","rapid development","child development"],"example":"Economic development has improved people's lives.","exampleZh":"經濟發展改善了人們的生活。","synonyms":["growth","progress"],"level":4,"theme":"社會與文化","examples":[{"en":"Economic development has improved people's lives.","zh":"經濟發展改善了人們的生活。"},{"en":"The rapid development of the city created many new jobs.","zh":"這座城市的快速發展創造了許多新的工作機會。"},{"en":"Good nutrition is essential for a child's development.","zh":"良好的營養對孩子的發育至關重要。"}]},{"word":"device","pos":"n.","phonetic":"[dɪˈvaɪs]","meaning":"裝置；設備","definition":"a tool or piece of equipment made for a specific purpose","collocations":["electronic device","mobile device","safety device"],"example":"This device measures blood pressure accurately.","exampleZh":"這個裝置能準確測量血壓。","synonyms":["gadget","tool"],"level":4,"theme":"科技與媒體","examples":[{"en":"This device measures blood pressure accurately.","zh":"這個裝置能準確測量血壓。"},{"en":"This small device can measure the air quality in a room.","zh":"這個小裝置可以測量房間裡的空氣品質。"},{"en":"Many students bring a mobile device to school every day.","zh":"許多學生每天都帶著行動裝置到學校。"}]},{"word":"devote","pos":"v.","phonetic":"[dɪˈvot]","meaning":"奉獻；投入","definition":"to give a large amount of time or effort to something","collocations":["devote time to","devote oneself to","devote energy"],"example":"She devotes most of her time to charity work.","exampleZh":"她把大部分時間都奉獻給慈善工作。","synonyms":["dedicate"],"level":5,"theme":"抽象概念","examples":[{"en":"She devotes most of her time to charity work.","zh":"她把大部分時間都奉獻給慈善工作。"},{"en":"He decided to devote his weekends to volunteer work.","zh":"他決定把週末的時間投入志工服務。"},{"en":"She devoted years of effort to protecting endangered animals.","zh":"她投入了多年的心力保護瀕臨絕種的動物。"}]},{"word":"dew","pos":"n.","phonetic":"[dju]","meaning":"露水","definition":"small drops of water that form on cool surfaces at night","collocations":["morning dew","dew on the grass","heavy dew"],"example":"The grass was covered with morning dew.","exampleZh":"草地上覆蓋著清晨的露水。","synonyms":[],"level":4,"theme":"自然與環境","examples":[{"en":"The grass was covered with morning dew.","zh":"草地上覆蓋著清晨的露水。"},{"en":"Tiny drops of dew sparkled on the leaves at sunrise.","zh":"日出時，細小的露珠在葉子上閃閃發光。"},{"en":"The morning dew made the whole meadow glisten.","zh":"清晨的露水使整片草地閃閃發亮。"}]},{"word":"diagnose","pos":"v.","phonetic":"[ˈdaɪəɡˌnoz]","meaning":"診斷","definition":"to identify the nature of an illness or problem","collocations":["diagnose a disease","diagnosed with cancer"],"example":"The doctor diagnosed him with a rare condition.","exampleZh":"醫生診斷出他患有一種罕見疾病。","synonyms":["identify","detect"],"level":5,"theme":"身體與健康","examples":[{"en":"The doctor diagnosed him with a rare condition.","zh":"醫生診斷出他患有一種罕見疾病。"},{"en":"It took several tests to diagnose the strange illness.","zh":"經過多次檢查才診斷出這種奇怪的疾病。"},{"en":"She was diagnosed with a mild allergy to peanuts.","zh":"她被診斷出對花生有輕微過敏。"}]},{"word":"diagram","pos":"n.","phonetic":"[ˈdaɪəˌgræm]","meaning":"圖表；示意圖","definition":"a simplified drawing showing the parts of something","collocations":["draw a diagram","flow diagram","label a diagram"],"example":"The teacher drew a diagram to explain the water cycle.","exampleZh":"老師畫了一張圖表來說明水循環。","synonyms":["chart"],"level":4,"theme":"科學與數學","examples":[{"en":"The teacher drew a diagram to explain the water cycle.","zh":"老師畫了一張圖表來說明水循環。"},{"en":"The engineer drew a diagram to show how the machine works.","zh":"工程師畫了一張示意圖來說明這台機器如何運作。"},{"en":"Students had to label each part of the diagram correctly.","zh":"學生們必須正確地標示出圖表的每個部分。"}]},{"word":"dial","pos":"v. / n.","phonetic":"[ˈdaɪəl]","meaning":"撥號；轉盤","definition":"to press buttons on a phone to call a number","collocations":["dial a number","dial the wrong number","phone dial"],"example":"She dialed the emergency number immediately.","exampleZh":"她立刻撥打了緊急電話號碼。","synonyms":["call"],"level":3,"theme":"科技與媒體","examples":[{"en":"She dialed the emergency number immediately.","zh":"她立刻撥打了緊急電話號碼。"},{"en":"In an emergency, dial the number for the fire department.","zh":"遇到緊急情況時，請撥打消防隊的電話號碼。"},{"en":"He accidentally dialed the wrong number twice.","zh":"他不小心撥錯號碼兩次。"}]},{"word":"dialect","pos":"n.","phonetic":"[ˈdaɪəˌlɛkt]","meaning":"方言","definition":"a regional variety of a language","collocations":["speak a dialect","local dialect"],"example":"People in that region speak a distinct dialect.","exampleZh":"那個地區的人講一種獨特的方言。","synonyms":["vernacular"],"level":5,"theme":"溝通與語言","examples":[{"en":"People in that region speak a distinct dialect.","zh":"那個地區的人講一種獨特的方言。"},{"en":"The old fisherman spoke a dialect I could barely understand.","zh":"那位老漁夫說著一種我幾乎聽不懂的方言。"},{"en":"Each village in the valley has its own local dialect.","zh":"山谷裡的每個村莊都有自己的地方方言。"}]},{"word":"dialogue","pos":"n.","phonetic":"[ˈdaɪəˌlɔg]","meaning":"對話","definition":"a conversation between two or more people","collocations":["open dialogue","dialogue between","in dialogue"],"example":"The two countries agreed to open a dialogue.","exampleZh":"這兩個國家同意展開對話。","synonyms":["conversation"],"level":4,"theme":"溝通與語言","examples":[{"en":"The two countries agreed to open a dialogue.","zh":"這兩個國家同意展開對話。"},{"en":"The film's dialogue felt natural and easy to follow.","zh":"這部電影的對話感覺自然且容易理解。"},{"en":"Honest dialogue between parents and teenagers is important.","zh":"父母與青少年之間坦誠的對話很重要。"}]},{"word":"diamond","pos":"n.","phonetic":"[ˈdaɪəmənd]","meaning":"鑽石","definition":"a precious, extremely hard clear stone","collocations":["diamond ring","cut diamond","diamond necklace"],"example":"He gave her a diamond ring on their anniversary.","exampleZh":"他在結婚週年送她一枚鑽戒。","synonyms":[],"level":3,"theme":"商業與金錢","examples":[{"en":"He gave her a diamond ring on their anniversary.","zh":"他在結婚週年送她一枚鑽戒。"},{"en":"The tiny diamond on the ring sparkled under the lights.","zh":"戒指上那顆小小的鑽石在燈光下閃閃發光。"},{"en":"Diamonds are among the hardest natural materials on Earth.","zh":"鑽石是地球上最堅硬的天然材料之一。"}]},{"word":"diary","pos":"n.","phonetic":"[ˈdaɪərɪ]","meaning":"日記","definition":"a book in which one records daily events or thoughts","collocations":["keep a diary","write in a diary","personal diary"],"example":"She writes in her diary every night.","exampleZh":"她每晚都會寫日記。","synonyms":["journal"],"level":2,"theme":"教育與學習","examples":[{"en":"She writes in her diary every night.","zh":"她每晚都會寫日記。"},{"en":"She keeps a diary to record her thoughts and feelings.","zh":"她寫日記來記錄自己的想法和感受。"},{"en":"He wrote about his exciting trip in his diary.","zh":"他在日記裡寫下了那趟令人興奮的旅程。"}]},{"word":"dictionary","pos":"n.","phonetic":"[ˈdɪkʃəˌnɛrɪ]","meaning":"字典","definition":"a book that lists words and their meanings","collocations":["look up in a dictionary","English dictionary","online dictionary"],"example":"You can look up new words in a dictionary.","exampleZh":"你可以在字典裡查詢新單字。","synonyms":[],"level":1,"theme":"教育與學習","examples":[{"en":"You can look up new words in a dictionary.","zh":"你可以在字典裡查詢新單字。"},{"en":"Whenever I meet a new word, I look it up in a dictionary.","zh":"每當我遇到生字時，我就會查字典。"},{"en":"An online dictionary can also teach you correct pronunciation.","zh":"線上字典也能教你正確的發音。"}]},{"word":"die","pos":"v.","phonetic":"[daɪ]","meaning":"死亡","definition":"to stop living","collocations":["die of","die young","die out"],"example":"Many plants die without enough sunlight.","exampleZh":"許多植物如果沒有足夠陽光就會死亡。","synonyms":["pass away"],"level":1,"theme":"身體與健康","examples":[{"en":"Many plants die without enough sunlight.","zh":"許多植物如果沒有足夠陽光就會死亡。"},{"en":"The flowers will die quickly without enough water.","zh":"沒有足夠的水，這些花很快就會枯死。"},{"en":"Sadly, many rare animals may die out in the near future.","zh":"遺憾的是，許多稀有動物在不久的將來可能會滅絕。"}]},{"word":"diet","pos":"n.","phonetic":"[ˈdaɪət]","meaning":"飲食；節食","definition":"the food regularly eaten by a person; a restricted eating plan","collocations":["healthy diet","go on a diet","balanced diet"],"example":"A balanced diet is important for good health.","exampleZh":"均衡飲食對健康很重要。","synonyms":["nutrition"],"level":3,"theme":"身體與健康","examples":[{"en":"A balanced diet is important for good health.","zh":"均衡飲食對健康很重要。"},{"en":"Doctors recommend a healthy diet full of fruits and vegetables.","zh":"醫生建議採取富含蔬果的健康飲食。"},{"en":"She went on a strict diet before the summer holiday.","zh":"暑假前，她開始了嚴格的節食。"}]},{"word":"differ","pos":"v.","phonetic":"[ˈdɪfɚ]","meaning":"不同；相異","definition":"to be unlike or disagree with something","collocations":["differ from","differ in opinion","widely differ"],"example":"Opinions on this issue differ greatly.","exampleZh":"對這件事的看法差異很大。","synonyms":["vary"],"level":4,"theme":"抽象概念","examples":[{"en":"Opinions on this issue differ greatly.","zh":"對這件事的看法差異很大。"},{"en":"My taste in music differs greatly from my brother's.","zh":"我對音樂的喜好和我哥哥的大不相同。"},{"en":"The two witnesses differ in their account of the accident.","zh":"這兩名目擊者對這起意外的說法各不相同。"}]},{"word":"difference","pos":"n.","phonetic":"[ˈdɪfərəns]","meaning":"差異；不同","definition":"a way in which people or things are not the same","collocations":["make a difference","tell the difference","big difference"],"example":"There is a big difference between the two designs.","exampleZh":"這兩個設計之間有很大的差異。","synonyms":["distinction"],"level":2,"theme":"抽象概念","examples":[{"en":"There is a big difference between the two designs.","zh":"這兩個設計之間有很大的差異。"},{"en":"Even a small act of kindness can make a big difference.","zh":"即使是小小的善舉也能帶來很大的改變。"},{"en":"Can you tell the difference between these two colors?","zh":"你能分辨出這兩種顏色的差異嗎？"}]},{"word":"different","pos":"adj.","phonetic":"[ˈdɪfərənt]","meaning":"不同的","definition":"not the same as another","collocations":["different from","completely different","different types"],"example":"Each student has a different opinion on the topic.","exampleZh":"每個學生對這個主題都有不同的看法。","synonyms":["distinct","varied"],"level":1,"theme":"性質與描述","examples":[{"en":"Each student has a different opinion on the topic.","zh":"每個學生對這個主題都有不同的看法。"},{"en":"People from different cultures celebrate the new year in various ways.","zh":"來自不同文化的人以各種方式慶祝新年。"},{"en":"Her second novel is completely different from her first.","zh":"她的第二本小說和第一本完全不同。"}]},{"word":"difficult","pos":"adj.","phonetic":"[ˈdɪfɪkəlt]","meaning":"困難的","definition":"needing much effort or skill to do or understand","collocations":["difficult task","difficult decision","find it difficult"],"example":"Learning a new language can be difficult at first.","exampleZh":"學習新語言一開始可能很困難。","synonyms":["hard","tough"],"level":1,"theme":"性質與描述","examples":[{"en":"Learning a new language can be difficult at first.","zh":"學習新語言一開始可能很困難。"},{"en":"It was a difficult task, but the team never gave up.","zh":"這是一項艱難的任務，但團隊從未放棄。"},{"en":"Many students find advanced math quite difficult.","zh":"許多學生覺得高等數學相當困難。"}]},{"word":"difficulty","pos":"n.","phonetic":"[ˈdɪfɪˌkʌltɪ]","meaning":"困難","definition":"a problem or something that causes trouble","collocations":["face difficulty","without difficulty","financial difficulty"],"example":"He had great difficulty finding a job.","exampleZh":"他找工作遇到很大的困難。","synonyms":["hardship"],"level":2,"theme":"抽象概念","examples":[{"en":"He had great difficulty finding a job.","zh":"他找工作遇到很大的困難。"},{"en":"She overcame many difficulties to achieve her dream.","zh":"她克服了許多困難來實現她的夢想。"},{"en":"The old man had difficulty climbing the steep hill.","zh":"那位老人爬那座陡峭的山坡有困難。"}]},{"word":"dig","pos":"v.","phonetic":"[dɪg]","meaning":"挖掘","definition":"to break up and remove earth using a tool or hands","collocations":["dig a hole","dig up","dig into"],"example":"The dog dug a hole in the backyard.","exampleZh":"那隻狗在後院挖了一個洞。","synonyms":["excavate"],"level":2,"theme":"動作與行為","examples":[{"en":"The dog dug a hole in the backyard.","zh":"那隻狗在後院挖了一個洞。"},{"en":"The workers began to dig a deep hole for the new pool.","zh":"工人們開始為新的游泳池挖一個深洞。"},{"en":"Archaeologists dig carefully to avoid damaging ancient objects.","zh":"考古學家小心翼翼地挖掘，以免損壞古物。"}]},{"word":"digest","pos":"v.","phonetic":"[daɪˈdʒɛst]","meaning":"消化","definition":"to break down food in the body for absorption","collocations":["digest food","easy to digest","hard to digest"],"example":"It takes time for the body to digest a big meal.","exampleZh":"身體需要時間消化一頓大餐。","synonyms":["absorb"],"level":4,"theme":"身體與健康","examples":[{"en":"It takes time for the body to digest a big meal.","zh":"身體需要時間消化一頓大餐。"},{"en":"It is easier to digest food after a short walk.","zh":"散步一小段路後比較容易消化食物。"},{"en":"Fatty meals can be hard to digest late at night.","zh":"油膩的餐點在深夜可能難以消化。"}]},{"word":"digital","pos":"adj.","phonetic":"[ˈdɪdʒɪtəl]","meaning":"數位的","definition":"using electronic technology to store and process information","collocations":["digital camera","digital world","go digital"],"example":"Most photos today are taken with a digital camera.","exampleZh":"現在大部分照片都是用數位相機拍攝的。","synonyms":[],"level":3,"theme":"科技與媒體","examples":[{"en":"Most photos today are taken with a digital camera.","zh":"現在大部分照片都是用數位相機拍攝的。"},{"en":"The museum uses digital screens to explain each painting.","zh":"博物館使用數位螢幕來解說每一幅畫作。"},{"en":"We now live in a fast-changing digital world.","zh":"我們如今生活在一個快速變遷的數位世界。"}]},{"word":"dignity","pos":"n.","phonetic":"[ˈdɪɡnəti]","meaning":"尊嚴；莊重","definition":"the state of being worthy of honor or respect","collocations":["human dignity","with dignity","lose one's dignity"],"example":"She faced the difficult situation with dignity.","exampleZh":"她以尊嚴面對這個艱難的處境。","synonyms":["honor","self-respect"],"level":5,"theme":"抽象概念","examples":[{"en":"She faced the difficult situation with dignity.","zh":"她以尊嚴面對這個艱難的處境。"},{"en":"Everyone deserves to be treated with dignity and respect.","zh":"每個人都應該受到有尊嚴且尊重的對待。"},{"en":"She accepted the criticism with quiet dignity.","zh":"她以沉靜的莊重接受了批評。"}]},{"word":"dilemma","pos":"n.","phonetic":"[dɪˈlɛmə]","meaning":"兩難困境","definition":"a situation requiring a choice between equally difficult options","collocations":["face a dilemma","moral dilemma","ethical dilemma"],"example":"She faced a dilemma about whether to accept the job offer.","exampleZh":"她面臨一個兩難困境，不知該不該接受這份工作邀約。","synonyms":["predicament"],"level":6,"theme":"抽象概念","examples":[{"en":"She faced a dilemma about whether to accept the job offer.","zh":"她面臨一個兩難困境，不知該不該接受這份工作邀約。"},{"en":"He faced a dilemma between helping his friend and telling the truth.","zh":"他面臨幫助朋友和說出真相之間的兩難困境。"},{"en":"Choosing between two good universities was a real dilemma for her.","zh":"在兩所好大學之間做選擇對她來說是個真正的兩難。"}]},{"word":"diligent","pos":"adj.","phonetic":"[ˈdɪlədʒənt]","meaning":"勤勉的；勤奮的","definition":"showing careful and persistent effort in work or duties","collocations":["a diligent student","diligent worker"],"example":"He is a diligent student who studies every day.","exampleZh":"他是個勤奮的學生，每天都在讀書。","synonyms":["hardworking","industrious"],"level":4,"theme":"教育與學習","examples":[{"en":"He is a diligent student who studies every day.","zh":"他是個勤奮的學生，每天都在讀書。"},{"en":"The diligent worker was praised for finishing early.","zh":"這位勤奮的員工因提早完成工作而受到稱讚。"},{"en":"Being diligent in your studies will pay off in the future.","zh":"在學業上勤奮努力將來會有回報。"}]},{"word":"dim","pos":"adj.","phonetic":"[dɪm]","meaning":"昏暗的","definition":"not bright; giving little light","collocations":["dim light","dim room","grow dim"],"example":"The restaurant had a dim, cozy atmosphere.","exampleZh":"這家餐廳燈光昏暗，氣氛溫馨。","synonyms":["dark","faint"],"level":5,"theme":"性質與描述","examples":[{"en":"The restaurant had a dim, cozy atmosphere.","zh":"這家餐廳燈光昏暗，氣氛溫馨。"},{"en":"The lights grew dim as the movie was about to start.","zh":"電影即將開始時，燈光漸漸變暗。"},{"en":"It was hard to read in the dim light of the old lamp.","zh":"在那盞舊燈昏暗的光線下很難閱讀。"}]},{"word":"dime","pos":"n.","phonetic":"[daɪm]","meaning":"一角硬幣（美分）","definition":"a US or Canadian coin worth ten cents","collocations":["a dime a dozen","drop a dime","not worth a dime"],"example":"He found a dime on the sidewalk.","exampleZh":"他在人行道上撿到一枚一角硬幣。","synonyms":[],"level":3,"theme":"商業與金錢","examples":[{"en":"He found a dime on the sidewalk.","zh":"他在人行道上撿到一枚一角硬幣。"},{"en":"He dropped a dime into the charity box on the counter.","zh":"他把一枚一角硬幣投進櫃台上的慈善箱。"},{"en":"Such cheap toys are a dime a dozen at the market.","zh":"這種便宜的玩具在市場上多得不值錢。"}]},{"word":"dimension","pos":"n.","phonetic":"[dɪˈmɛnʃən]","meaning":"維度；尺寸；層面","definition":"a measurable extent, or an aspect of a situation","collocations":["new dimension","room dimensions","third dimension"],"example":"The problem has a political dimension as well.","exampleZh":"這個問題也有政治層面的考量。","synonyms":["aspect","size"],"level":5,"theme":"科學與數學","examples":[{"en":"The problem has a political dimension as well.","zh":"這個問題也有政治層面的考量。"},{"en":"The carpenter measured the exact dimensions of the table.","zh":"木匠測量了桌子的精確尺寸。"},{"en":"Music adds an emotional dimension to the whole film.","zh":"音樂為整部電影增添了情感的層面。"}]},{"word":"diminish","pos":"v.","phonetic":"[dɪˈmɪnɪʃ]","meaning":"減少；減弱","definition":"to make or become smaller or less important","collocations":["diminish in value","diminish the risk"],"example":"Her enthusiasm did not diminish despite the setbacks.","exampleZh":"儘管遭遇挫折，她的熱忱並未減弱。","synonyms":["decrease","reduce"],"level":5,"theme":"抽象概念","examples":[{"en":"Her enthusiasm did not diminish despite the setbacks.","zh":"儘管遭遇挫折，她的熱忱並未減弱。"},{"en":"The medicine helped to diminish the patient's pain.","zh":"這種藥物有助於減輕病人的疼痛。"},{"en":"His interest in the game did not diminish over time.","zh":"隨著時間過去，他對這款遊戲的興趣並未減退。"}]},{"word":"dine","pos":"v.","phonetic":"[daɪn]","meaning":"用餐","definition":"to eat dinner, especially formally","collocations":["dine out","dine with","fine dining"],"example":"They decided to dine at a fancy restaurant.","exampleZh":"他們決定到一家高級餐廳用餐。","synonyms":["eat"],"level":4,"theme":"食物與烹飪","examples":[{"en":"They decided to dine at a fancy restaurant.","zh":"他們決定到一家高級餐廳用餐。"},{"en":"On special occasions, they like to dine at a fine restaurant.","zh":"在特殊場合，他們喜歡在高級餐廳用餐。"},{"en":"We were invited to dine with our teacher last night.","zh":"昨晚我們受邀與老師共進晚餐。"}]},{"word":"dinner","pos":"n.","phonetic":"[ˈdɪnɚ]","meaning":"晚餐","definition":"the main meal of the day, usually in the evening","collocations":["cook dinner","have dinner","dinner party"],"example":"We usually have dinner together as a family.","exampleZh":"我們一家人通常一起吃晚餐。","synonyms":[],"level":1,"theme":"食物與烹飪","examples":[{"en":"We usually have dinner together as a family.","zh":"我們一家人通常一起吃晚餐。"},{"en":"My mother is cooking dinner for the whole family tonight.","zh":"今晚我媽媽正在為全家人做晚餐。"},{"en":"They held a dinner party to celebrate the good news.","zh":"他們舉辦了一場晚宴來慶祝這個好消息。"}]},{"word":"dinosaur","pos":"n.","phonetic":"[ˈdaɪnəˌsɔr]","meaning":"恐龍","definition":"a large extinct reptile that lived millions of years ago","collocations":["dinosaur bones","dinosaur fossil","dinosaur museum"],"example":"Kids love to learn about dinosaurs.","exampleZh":"孩子們喜歡認識恐龍。","synonyms":[],"level":1,"theme":"動物與植物","examples":[{"en":"Kids love to learn about dinosaurs.","zh":"孩子們喜歡認識恐龍。"},{"en":"The museum displays a huge dinosaur skeleton in the main hall.","zh":"博物館在大廳展示了一具巨大的恐龍骨骼。"},{"en":"Scientists study dinosaur fossils to learn about the past.","zh":"科學家研究恐龍化石以了解過去。"}]},{"word":"dip","pos":"v. / n.","phonetic":"[dɪp]","meaning":"浸；沾","definition":"to put something briefly into a liquid","collocations":["dip into","dip a cookie","take a dip"],"example":"She dipped the bread into the soup.","exampleZh":"她把麵包沾進湯裡。","synonyms":["immerse"],"level":3,"theme":"食物與烹飪","examples":[{"en":"She dipped the bread into the soup.","zh":"她把麵包沾進湯裡。"},{"en":"She likes to dip her fries in ketchup.","zh":"她喜歡把薯條沾番茄醬。"},{"en":"On hot days, we take a quick dip in the river.","zh":"在炎熱的日子，我們會到河裡泡一下水。"}]},{"word":"diploma","pos":"n.","phonetic":"[dɪˈplomə]","meaning":"畢業證書；文憑","definition":"a certificate awarded for completing a course of study","collocations":["earn a diploma","high school diploma","diploma ceremony"],"example":"She proudly received her high school diploma.","exampleZh":"她驕傲地拿到高中畢業證書。","synonyms":["certificate"],"level":4,"theme":"教育與學習","examples":[{"en":"She proudly received her high school diploma.","zh":"她驕傲地拿到高中畢業證書。"},{"en":"He framed his high school diploma and hung it on the wall.","zh":"他把高中畢業證書裱框並掛在牆上。"},{"en":"You need a diploma to apply for that training program.","zh":"你需要一張文憑才能申請那個訓練課程。"}]},{"word":"direct","pos":"v. / adj.","phonetic":"[dəˈrɛkt]","meaning":"直接的；指導；導演","definition":"going straight to a place; to guide or manage","collocations":["direct a film","direct flight","direct approach"],"example":"He directed the traffic at the busy intersection.","exampleZh":"他在繁忙的十字路口指揮交通。","synonyms":["guide","straight"],"level":3,"theme":"藝術與音樂","examples":[{"en":"He directed the traffic at the busy intersection.","zh":"他在繁忙的十字路口指揮交通。"},{"en":"The tourists took a direct flight to the island.","zh":"遊客們搭乘直飛班機前往那座島嶼。"},{"en":"A famous filmmaker was invited to direct the new movie.","zh":"一位著名的電影人受邀執導這部新電影。"}]},{"word":"direction","pos":"n.","phonetic":"[dəˈrɛkʃən]","meaning":"方向；指示","definition":"the course along which something moves; instructions","collocations":["wrong direction","give directions","new direction"],"example":"Could you give me directions to the station?","exampleZh":"你可以告訴我到車站的路怎麼走嗎？","synonyms":["way","guidance"],"level":2,"theme":"時間與空間","examples":[{"en":"Could you give me directions to the station?","zh":"你可以告訴我到車站的路怎麼走嗎？"},{"en":"We must be heading in the wrong direction again.","zh":"我們一定又走錯方向了。"},{"en":"The kind stranger gave us clear directions to the museum.","zh":"那位親切的陌生人給了我們前往博物館的清楚指示。"}]},{"word":"director","pos":"n.","phonetic":"[dəˈrɛktɚ]","meaning":"導演；主管","definition":"a person who supervises or oversees a film, project, or organization","collocations":["film director","managing director","assistant director"],"example":"The director praised the actors' performances.","exampleZh":"導演稱讚了演員們的表現。","synonyms":["manager"],"level":3,"theme":"工作與職業","examples":[{"en":"The director praised the actors' performances.","zh":"導演稱讚了演員們的表現。"},{"en":"The film's director thanked the whole crew for their effort.","zh":"這部電影的導演感謝全體工作人員的付出。"},{"en":"As managing director, she oversees the entire company.","zh":"身為總經理，她掌管整間公司。"}]},{"word":"dirt","pos":"n.","phonetic":"[dɝt]","meaning":"泥土；污垢","definition":"soil or a substance that makes something unclean","collocations":["dirt road","covered in dirt","pile of dirt"],"example":"The children came home covered in dirt.","exampleZh":"孩子們回家時渾身都是泥土。","synonyms":["soil","mud"],"level":2,"theme":"自然與環境","examples":[{"en":"The children came home covered in dirt.","zh":"孩子們回家時渾身都是泥土。"},{"en":"The car bounced along the narrow dirt road.","zh":"車子沿著狹窄的泥土路顛簸前行。"},{"en":"He wiped the dirt off his hands after gardening.","zh":"園藝過後，他把手上的污垢擦掉。"}]},{"word":"dirty","pos":"adj.","phonetic":"[ˈdɝtɪ]","meaning":"髒的","definition":"covered with dirt; not clean","collocations":["dirty clothes","get dirty","dirty dishes"],"example":"His shoes got dirty after the hike.","exampleZh":"健行後他的鞋子變髒了。","synonyms":["filthy","unclean"],"level":1,"theme":"性質與描述","examples":[{"en":"His shoes got dirty after the hike.","zh":"健行後他的鞋子變髒了。"},{"en":"Please put your dirty clothes in the laundry basket.","zh":"請把你的髒衣服放進洗衣籃。"},{"en":"The kids got dirty while playing in the mud.","zh":"孩子們在泥巴裡玩耍時弄髒了自己。"}]},{"word":"disability","pos":"n.","phonetic":"[ˌdɪsəˈbɪlətɪ]","meaning":"殘疾；障礙","definition":"a physical or mental condition that limits activities","collocations":["learning disability","people with disabilities","physical disability"],"example":"The building is designed for people with disabilities.","exampleZh":"這棟建築的設計是為了方便身心障礙者。","synonyms":["impairment"],"level":5,"theme":"身體與健康","examples":[{"en":"The building is designed for people with disabilities.","zh":"這棟建築的設計是為了方便身心障礙者。"},{"en":"The new law protects the rights of people with disabilities.","zh":"這項新法律保障身心障礙者的權利。"},{"en":"He overcame his physical disability to become an athlete.","zh":"他克服了身體上的殘疾，成為一名運動員。"}]},{"word":"disagree","pos":"v.","phonetic":"[ˌdɪsəˈgri]","meaning":"不同意","definition":"to have a different opinion","collocations":["disagree with","strongly disagree","agree to disagree"],"example":"I disagree with your opinion on this matter.","exampleZh":"我不同意你對這件事的看法。","synonyms":["differ"],"level":3,"theme":"溝通與語言","examples":[{"en":"I disagree with your opinion on this matter.","zh":"我不同意你對這件事的看法。"},{"en":"I completely disagree with the way they solved the problem.","zh":"我完全不同意他們解決這個問題的方式。"},{"en":"The two experts strongly disagree about the causes of the change.","zh":"這兩位專家對於這項改變的原因意見嚴重分歧。"}]},{"word":"disappear","pos":"v.","phonetic":"[ˌdɪsəˈpɪr]","meaning":"消失","definition":"to cease to be visible","collocations":["disappear from sight","suddenly disappear","disappear into"],"example":"The magician made the coin disappear.","exampleZh":"魔術師讓硬幣消失了。","synonyms":["vanish"],"level":3,"theme":"動作與行為","examples":[{"en":"The magician made the coin disappear.","zh":"魔術師讓硬幣消失了。"},{"en":"The ship slowly disappeared from sight over the horizon.","zh":"那艘船在地平線上慢慢消失在視線中。"},{"en":"My keys seem to have disappeared into thin air.","zh":"我的鑰匙似乎憑空消失了。"}]},{"word":"disappoint","pos":"v.","phonetic":"[ˌdɪsəˈpɔɪnt]","meaning":"使失望","definition":"to fail to meet the expectations of someone","collocations":["disappoint fans","feel disappointed","don't want to disappoint"],"example":"The team's poor performance disappointed the fans.","exampleZh":"球隊表現不佳讓球迷們失望。","synonyms":["let down"],"level":4,"theme":"情緒與感受","examples":[{"en":"The team's poor performance disappointed the fans.","zh":"球隊表現不佳讓球迷們失望。"},{"en":"He didn't want to disappoint his parents by failing the exam.","zh":"他不想因為考試不及格而讓父母失望。"},{"en":"The ending of the movie really disappointed the audience.","zh":"這部電影的結局真的讓觀眾很失望。"}]},{"word":"disaster","pos":"n.","phonetic":"[dɪˈzæstɚ]","meaning":"災難","definition":"a sudden event causing great damage or suffering","collocations":["natural disaster","disaster relief","complete disaster"],"example":"The earthquake was one of the worst natural disasters in history.","exampleZh":"這場地震是歷史上最嚴重的天然災害之一。","synonyms":["catastrophe"],"level":4,"theme":"自然與環境","examples":[{"en":"The earthquake was one of the worst natural disasters in history.","zh":"這場地震是歷史上最嚴重的天然災害之一。"},{"en":"The town is still recovering from last year's natural disaster.","zh":"這座小鎮仍在從去年的天災中復原。"},{"en":"Without a plan, the trip turned into a complete disaster.","zh":"由於沒有計畫，這趟旅行變成了一場徹底的災難。"}]},{"word":"discipline","pos":"n.","phonetic":"[ˈdɪsəplɪn]","meaning":"紀律；訓練","definition":"the practice of training people to obey rules","collocations":["self-discipline","strict discipline","maintain discipline"],"example":"Success in sports requires discipline and practice.","exampleZh":"在運動上成功需要紀律與練習。","synonyms":["order","training"],"level":5,"theme":"教育與學習","examples":[{"en":"Success in sports requires discipline and practice.","zh":"在運動上成功需要紀律與練習。"},{"en":"Learning a musical instrument requires patience and discipline.","zh":"學習樂器需要耐心和紀律。"},{"en":"Self-discipline helped him wake up early to study every day.","zh":"自律幫助他每天早起讀書。"}]},{"word":"discount","pos":"n.","phonetic":"[ˈdɪskaʊnt]","meaning":"折扣","definition":"a reduction in the usual price","collocations":["give a discount","student discount","big discount"],"example":"Students can get a discount with their ID cards.","exampleZh":"學生憑學生證可以享有折扣。","synonyms":["reduction"],"level":3,"theme":"商業與金錢","examples":[{"en":"Students can get a discount with their ID cards.","zh":"學生憑學生證可以享有折扣。"},{"en":"The store is offering a big discount on winter coats.","zh":"這家店的冬季外套正在打大折扣。"},{"en":"You can get a student discount if you show your ID.","zh":"出示證件的話，你可以享有學生折扣。"}]},{"word":"discover","pos":"v.","phonetic":"[dɪˈskʌvɚ]","meaning":"發現","definition":"to find something for the first time","collocations":["discover a new species","accidentally discover","discover the truth"],"example":"Scientists discovered a new species of frog in the rainforest.","exampleZh":"科學家在雨林中發現了一種新的青蛙物種。","synonyms":["find","uncover"],"level":2,"theme":"科學與數學","examples":[{"en":"Scientists discovered a new species of frog in the rainforest.","zh":"科學家在雨林中發現了一種新的青蛙物種。"},{"en":"The children were excited to discover a bird's nest in the tree.","zh":"孩子們興奮地在樹上發現了一個鳥巢。"},{"en":"She discovered the truth only after reading the old letters.","zh":"她讀了那些舊信之後才發現真相。"}]},{"word":"discuss","pos":"v.","phonetic":"[dɪˈskʌs]","meaning":"討論","definition":"to talk about something with others","collocations":["discuss a topic","discuss with","discuss further"],"example":"Let's discuss the plan for the trip.","exampleZh":"讓我們討論一下這次旅行的計畫。","synonyms":["talk about"],"level":2,"theme":"溝通與語言","examples":[{"en":"Let's discuss the plan for the trip.","zh":"讓我們討論一下這次旅行的計畫。"},{"en":"The class gathered to discuss ways to save energy.","zh":"全班聚在一起討論節約能源的方法。"},{"en":"We should discuss this matter further before deciding.","zh":"在決定之前，我們應該進一步討論這件事。"}]},{"word":"disease","pos":"n.","phonetic":"[dɪˈziz]","meaning":"疾病","definition":"an illness affecting a person, animal, or plant","collocations":["heart disease","spread disease","cure a disease"],"example":"The doctor explained the symptoms of the disease.","exampleZh":"醫生解釋了這種疾病的症狀。","synonyms":["illness"],"level":3,"theme":"身體與健康","examples":[{"en":"The doctor explained the symptoms of the disease.","zh":"醫生解釋了這種疾病的症狀。"},{"en":"Washing your hands often can help prevent the spread of disease.","zh":"經常洗手有助於防止疾病傳播。"},{"en":"Doctors are working hard to find a cure for the rare disease.","zh":"醫生們正努力尋找治療這種罕見疾病的方法。"}]},{"word":"dish","pos":"n.","phonetic":"[dɪʃ]","meaning":"盤子；菜餚","definition":"a plate used for serving food, or a particular food item","collocations":["wash the dishes","main dish","favorite dish"],"example":"This restaurant is famous for its seafood dish.","exampleZh":"這家餐廳以海鮮菜餚聞名。","synonyms":["plate"],"level":1,"theme":"食物與烹飪","examples":[{"en":"This restaurant is famous for its seafood dish.","zh":"這家餐廳以海鮮菜餚聞名。"},{"en":"It's my turn to wash the dishes after dinner tonight.","zh":"今晚晚餐後輪到我洗碗。"},{"en":"The chef's signature dish is a spicy seafood stew.","zh":"這位主廚的招牌菜是辣味海鮮燉湯。"}]},{"word":"dismiss","pos":"v.","phonetic":"[dɪsˈmɪs]","meaning":"解散；解僱；不予考慮","definition":"to send away, remove from a job, or refuse to consider seriously","collocations":["dismiss a claim","dismiss an employee","class dismissed"],"example":"The teacher dismissed the class early.","exampleZh":"老師提早讓學生下課。","synonyms":["fire","reject"],"level":5,"theme":"工作與職業","examples":[{"en":"The teacher dismissed the class early.","zh":"老師提早讓學生下課。"},{"en":"The manager dismissed the idea without even considering it.","zh":"經理連考慮都沒考慮就否決了這個想法。"},{"en":"The teacher dismissed the students once the bell rang.","zh":"鐘聲一響，老師就讓學生們解散。"}]},{"word":"display","pos":"n. / v.","phonetic":"[dɪˈsple]","meaning":"展示；陳列","definition":"to show or exhibit something publicly","collocations":["on display","display a product","fireworks display"],"example":"The museum displays ancient artifacts from the region.","exampleZh":"這座博物館展示了該地區的古代文物。","synonyms":["exhibit","show"],"level":3,"theme":"藝術與音樂","examples":[{"en":"The museum displays ancient artifacts from the region.","zh":"這座博物館展示了該地區的古代文物。"},{"en":"Beautiful paintings were on display throughout the gallery.","zh":"美麗的畫作陳列在整個畫廊裡。"},{"en":"The store displayed its newest products in the front window.","zh":"這家店把最新的產品陳列在櫥窗前。"}]},{"word":"dock","pos":"n. / v.","phonetic":"[dɑk]","meaning":"碼頭；船塢","definition":"a place where ships load and unload","collocations":["fishing dock","dock a ship","loading dock"],"example":"The ship stopped at the dock to unload cargo.","exampleZh":"這艘船停靠在碼頭卸貨。","synonyms":["pier","wharf"],"level":4,"theme":"交通與旅行","examples":[{"en":"The ship stopped at the dock to unload cargo.","zh":"這艘船停靠在碼頭卸貨。"},{"en":"The fishermen tied their boats to the wooden dock.","zh":"漁夫們把他們的船繫在木造碼頭上。"},{"en":"Trucks lined up at the loading dock to collect goods.","zh":"卡車在裝卸碼頭排隊等著載貨。"}]},{"word":"doctor","pos":"n.","phonetic":"[ˈdɑktɚ]","meaning":"醫生；博士","definition":"a person qualified to treat illness","collocations":["see a doctor","family doctor","doctor's appointment"],"example":"I need to see a doctor about my cough.","exampleZh":"我需要去看醫生治療我的咳嗽。","synonyms":["physician"],"level":1,"theme":"身體與健康","examples":[{"en":"I need to see a doctor about my cough.","zh":"我需要去看醫生治療我的咳嗽。"},{"en":"You should see a doctor if the fever does not go away.","zh":"如果發燒沒有退，你應該去看醫生。"},{"en":"Our family doctor has known me since I was a baby.","zh":"我們的家庭醫生從我還是嬰兒時就認識我了。"}]},{"word":"document","pos":"n. / v.","phonetic":"[ˈdɑkjəmənt]","meaning":"文件；記錄","definition":"a piece of written material providing information","collocations":["legal document","sign a document","document a process"],"example":"Please sign this document before you leave.","exampleZh":"離開前請簽署這份文件。","synonyms":["file","record"],"level":3,"theme":"教育與學習","examples":[{"en":"Please sign this document before you leave.","zh":"離開前請簽署這份文件。"},{"en":"Remember to bring all the important documents to the interview.","zh":"記得帶所有重要的文件去面試。"},{"en":"The researchers carefully documented every step of the experiment.","zh":"研究人員仔細記錄了實驗的每一個步驟。"}]},{"word":"dodge","pos":"v.","phonetic":"[dɑdʒ]","meaning":"躲避；閃避","definition":"to avoid by moving quickly","collocations":["dodge a question","dodge traffic","dodge a ball"],"example":"He dodged the ball just in time.","exampleZh":"他及時躲開了那顆球。","synonyms":["avoid","evade"],"level":4,"theme":"動作與行為","examples":[{"en":"He dodged the ball just in time.","zh":"他及時躲開了那顆球。"},{"en":"The politician tried to dodge the reporter's tough question.","zh":"那位政治人物試圖迴避記者尖銳的問題。"},{"en":"The cat quickly dodged the falling box.","zh":"那隻貓迅速閃避了掉落的箱子。"}]},{"word":"dog","pos":"n.","phonetic":"[dɔg]","meaning":"狗","definition":"a domesticated animal often kept as a pet","collocations":["walk the dog","pet dog","guard dog"],"example":"My dog loves to play in the park.","exampleZh":"我的狗喜歡在公園裡玩耍。","synonyms":[],"level":1,"theme":"動物與植物","examples":[{"en":"My dog loves to play in the park.","zh":"我的狗喜歡在公園裡玩耍。"},{"en":"Every evening my grandfather walks the dog around the block.","zh":"每天傍晚，我爺爺都會帶狗繞街區散步。"},{"en":"The farmer keeps a guard dog to protect the sheep.","zh":"農夫養了一隻看門狗來保護羊群。"}]},{"word":"doll","pos":"n.","phonetic":"[dɑl]","meaning":"洋娃娃","definition":"a toy in the form of a human figure","collocations":["play with dolls","doll house","baby doll"],"example":"The little girl carried her favorite doll everywhere.","exampleZh":"小女孩到哪都帶著她最喜歡的洋娃娃。","synonyms":[],"level":1,"theme":"居家與生活","examples":[{"en":"The little girl carried her favorite doll everywhere.","zh":"小女孩到哪都帶著她最喜歡的洋娃娃。"},{"en":"Her grandmother sewed a lovely doll for her birthday.","zh":"她的奶奶為她的生日縫製了一個可愛的洋娃娃。"},{"en":"The children spent the afternoon playing in the doll house.","zh":"孩子們整個下午都在玩娃娃屋。"}]},{"word":"dollar","pos":"n.","phonetic":"[ˈdɑlɚ]","meaning":"美元","definition":"the basic unit of money in the United States","collocations":["US dollar","dollar bill","spend a dollar"],"example":"The toy costs about five dollars.","exampleZh":"這個玩具大約要五美元。","synonyms":[],"level":1,"theme":"商業與金錢","examples":[{"en":"The toy costs about five dollars.","zh":"這個玩具大約要五美元。"},{"en":"The notebook only cost me two dollars at the sale.","zh":"特價時這本筆記本只花了我兩美元。"},{"en":"He saved every dollar to buy a new bicycle.","zh":"他省下每一塊錢來買一輛新腳踏車。"}]},{"word":"dolphin","pos":"n.","phonetic":"[ˈdɑlfɪn]","meaning":"海豚","definition":"an intelligent sea mammal","collocations":["dolphin show","swim with dolphins"],"example":"We watched the dolphins jump at the aquarium show.","exampleZh":"我們在水族館表演中看海豚跳躍。","synonyms":[],"level":2,"theme":"動物與植物","examples":[{"en":"We watched the dolphins jump at the aquarium show.","zh":"我們在水族館表演中看海豚跳躍。"},{"en":"A group of dolphins followed the boat across the bay.","zh":"一群海豚跟著船橫越海灣。"},{"en":"Visitors were amazed to swim with dolphins in the clear water.","zh":"遊客們對能在清澈的水中與海豚共游感到驚奇。"}]},{"word":"dome","pos":"n.","phonetic":"[dom]","meaning":"圓頂","definition":"a rounded roof or ceiling","collocations":["glass dome","dome-shaped","stadium dome"],"example":"The building has a beautiful glass dome on top.","exampleZh":"這棟建築頂部有一個美麗的玻璃圓頂。","synonyms":[],"level":4,"theme":"居家與生活","examples":[{"en":"The building has a beautiful glass dome on top.","zh":"這棟建築頂部有一個美麗的玻璃圓頂。"},{"en":"The ancient church is famous for its enormous golden dome.","zh":"這座古老的教堂以其巨大的金色圓頂而聞名。"},{"en":"Sunlight poured through the glass dome of the station.","zh":"陽光透過車站的玻璃圓頂灑落下來。"}]},{"word":"domestic","pos":"adj.","phonetic":"[dəˈmɛstɪk]","meaning":"家庭的；國內的","definition":"relating to the home, or not foreign","collocations":["domestic flight","domestic animal","domestic affairs"],"example":"The airline offers many domestic flights every day.","exampleZh":"這家航空公司每天提供許多國內航班。","synonyms":["household","national"],"level":5,"theme":"政治與法律","examples":[{"en":"The airline offers many domestic flights every day.","zh":"這家航空公司每天提供許多國內航班。"},{"en":"The airline added several new domestic flights this year.","zh":"這家航空公司今年增加了幾條新的國內航線。"},{"en":"Cats and dogs are common domestic animals in many homes.","zh":"貓和狗是許多家庭常見的家養動物。"}]},{"word":"dominate","pos":"v.","phonetic":"[ˈdɑməˌnet]","meaning":"支配；主宰","definition":"to have power and influence over","collocations":["dominate the market","dominate a discussion","dominate the game"],"example":"The team dominated the game from start to finish.","exampleZh":"這支隊伍從頭到尾都主導了這場比賽。","synonyms":["control","rule"],"level":5,"theme":"動作與行為","examples":[{"en":"The team dominated the game from start to finish.","zh":"這支隊伍從頭到尾都主導了這場比賽。"},{"en":"One large company continues to dominate the smartphone market.","zh":"一家大公司持續主宰著智慧型手機市場。"},{"en":"The tall player dominated the basketball court all night.","zh":"那位高大的球員整晚都主宰著籃球場。"}]},{"word":"donate","pos":"v.","phonetic":"[ˈdonet]","meaning":"捐贈","definition":"to give something as a gift to charity","collocations":["donate money","donate blood","donate to charity"],"example":"They donated a large sum of money to the school.","exampleZh":"他們捐了一大筆錢給學校。","synonyms":["contribute","give"],"level":4,"theme":"商業與金錢","examples":[{"en":"They donated a large sum of money to the school.","zh":"他們捐了一大筆錢給學校。"},{"en":"Many kind people donate blood to help save lives.","zh":"許多善心人士捐血以幫助拯救生命。"},{"en":"The company donated hundreds of books to the local library.","zh":"這家公司捐贈了數百本書給當地圖書館。"}]},{"word":"donkey","pos":"n.","phonetic":"[ˈdɑŋki]","meaning":"驢子","definition":"a domesticated animal related to the horse","collocations":["ride a donkey","stubborn as a donkey"],"example":"The farmer used a donkey to carry the goods.","exampleZh":"農夫用驢子搬運貨物。","synonyms":[],"level":2,"theme":"動物與植物","examples":[{"en":"The farmer used a donkey to carry the goods.","zh":"農夫用驢子搬運貨物。"},{"en":"The tired donkey slowly carried the heavy load up the hill.","zh":"疲憊的驢子緩慢地馱著沉重的貨物上山。"},{"en":"Children lined up to ride the friendly donkey at the fair.","zh":"孩子們排隊在園遊會上騎那隻溫馴的驢子。"}]},{"word":"donor","pos":"n.","phonetic":"[ˈdonɚ]","meaning":"捐贈者；捐獻者","definition":"a person who gives something, especially blood or an organ","collocations":["blood donor","organ donor","generous donor"],"example":"He became a blood donor after college.","exampleZh":"他大學畢業後成為一名捐血者。","synonyms":["contributor","giver"],"level":5,"theme":"身體與健康","examples":[{"en":"He became a blood donor after college.","zh":"他大學畢業後成為一名捐血者。"},{"en":"A generous donor gave a large sum of money to the hospital.","zh":"一位慷慨的捐贈者捐了一大筆錢給那家醫院。"},{"en":"My uncle registered as an organ donor to help others live.","zh":"我叔叔登記成為器官捐贈者，以幫助他人活下去。"}]},{"word":"doom","pos":"n. / v.","phonetic":"[dum]","meaning":"厄運；毀滅","definition":"death, destruction, or a terrible fate","collocations":["doom and gloom","sense of doom","doomed to fail"],"example":"The old prophecy predicted the city's doom.","exampleZh":"那個古老的預言預示了這座城市的毀滅。","synonyms":["fate","destruction"],"level":5,"theme":"抽象概念","examples":[{"en":"The old prophecy predicted the city's doom.","zh":"那個古老的預言預示了這座城市的毀滅。"},{"en":"Without careful planning, the project seemed doomed to fail from the start.","zh":"由於缺乏周詳的計畫，這個專案從一開始似乎就註定會失敗。"},{"en":"A strange sense of doom filled her heart before the storm arrived.","zh":"暴風雨來臨前，一種奇怪的厄運感充滿了她的心。"}]},{"word":"door","pos":"n.","phonetic":"[dor]","meaning":"門","definition":"a hinged barrier used to open and close an entrance","collocations":["open the door","front door","knock on the door"],"example":"Please close the door when you leave.","exampleZh":"你離開時請把門關上。","synonyms":[],"level":1,"theme":"居家與生活","examples":[{"en":"Please close the door when you leave.","zh":"你離開時請把門關上。"},{"en":"Someone is knocking on the door; could you please answer it?","zh":"有人在敲門，你可以去應門嗎？"},{"en":"He opened the front door and welcomed his guests inside.","zh":"他打開前門，歡迎客人進來。"}]},{"word":"doorway","pos":"n.","phonetic":"[ˈdorˌwe]","meaning":"門口","definition":"the entrance to a room or building","collocations":["stand in the doorway","narrow doorway"],"example":"She stood in the doorway, waiting for him.","exampleZh":"她站在門口等他。","synonyms":["entrance"],"level":3,"theme":"居家與生活","examples":[{"en":"She stood in the doorway, waiting for him.","zh":"她站在門口等他。"},{"en":"The narrow doorway made it hard to carry the sofa inside.","zh":"狹窄的門口讓沙發很難搬進屋內。"},{"en":"A little cat appeared in the doorway and stared at us.","zh":"一隻小貓出現在門口，盯著我們看。"}]},{"word":"dormitory","pos":"n.","phonetic":"[ˈdɔrməˌtɔri]","meaning":"宿舍","definition":"a large building with rooms for many people to sleep in","collocations":["school dormitory","live in a dormitory"],"example":"Most freshmen live in the school dormitory.","exampleZh":"大多數大一新生住在學校宿舍。","synonyms":["dorm"],"level":4,"theme":"教育與學習","examples":[{"en":"Most freshmen live in the school dormitory.","zh":"大多數大一新生住在學校宿舍。"},{"en":"Living in a dormitory helped her make many new friends quickly.","zh":"住在宿舍讓她很快就交到許多新朋友。"},{"en":"The school dormitory has strict rules about quiet hours at night.","zh":"學校宿舍對於晚上的安靜時段有嚴格的規定。"}]},{"word":"dose","pos":"n. / v.","phonetic":"[dos]","meaning":"劑量","definition":"a measured quantity of medicine","collocations":["daily dose","dose of medicine","overdose"],"example":"Take one dose of this medicine every morning.","exampleZh":"每天早上服用一劑這種藥。","synonyms":["dosage"],"level":4,"theme":"身體與健康","examples":[{"en":"Take one dose of this medicine every morning.","zh":"每天早上服用一劑這種藥。"},{"en":"The doctor increased his daily dose to control the pain.","zh":"醫生增加了他的每日劑量以控制疼痛。"},{"en":"Taking too large a dose of this drug can be dangerous.","zh":"服用過大劑量的這種藥物可能會很危險。"}]},{"word":"dot","pos":"n. / v.","phonetic":"[dɑt]","meaning":"點；圓點","definition":"a small round mark","collocations":["polka dot","dot the i's","connect the dots"],"example":"She drew a red dot on the map.","exampleZh":"她在地圖上畫了一個紅點。","synonyms":["point","spot"],"level":2,"theme":"藝術與音樂","examples":[{"en":"She drew a red dot on the map.","zh":"她在地圖上畫了一個紅點。"},{"en":"She wore a white dress covered with tiny polka dots.","zh":"她穿了一件佈滿小圓點的白色洋裝。"},{"en":"If you connect the dots, the puzzle forms a star.","zh":"如果你把這些點連起來，這個謎題會形成一顆星星。"}]},{"word":"double","pos":"adj. / v. / n.","phonetic":"[ˈdʌbl̩]","meaning":"雙倍的；使加倍","definition":"twice as much or as many","collocations":["double the amount","double room","double-check"],"example":"The price of the ticket has doubled since last year.","exampleZh":"這張票的價格自去年以來已經翻倍了。","synonyms":["twofold"],"level":2,"theme":"科學與數學","examples":[{"en":"The price of the ticket has doubled since last year.","zh":"這張票的價格自去年以來已經翻倍了。"},{"en":"Please double-check your answers before you hand in the test.","zh":"交考卷之前，請再次仔細檢查你的答案。"},{"en":"They booked a double room for their weekend trip to the coast.","zh":"他們為週末的海岸之旅訂了一間雙人房。"}]},{"word":"doubt","pos":"n. / v.","phonetic":"[daʊt]","meaning":"懷疑","definition":"a feeling of uncertainty","collocations":["have doubts","without a doubt","doubt someone's word"],"example":"I have no doubt that she will succeed.","exampleZh":"我毫不懷疑她會成功。","synonyms":["uncertainty","suspicion"],"level":2,"theme":"情緒與感受","examples":[{"en":"I have no doubt that she will succeed.","zh":"我毫不懷疑她會成功。"},{"en":"Without a doubt, she is the most talented singer in our class.","zh":"毫無疑問，她是我們班上最有天分的歌手。"},{"en":"I began to doubt his word after he broke his promise again.","zh":"他再次違背承諾後，我開始懷疑他的話。"}]},{"word":"dough","pos":"n.","phonetic":"[do]","meaning":"麵團","definition":"a thick mixture of flour and liquid used for baking","collocations":["knead dough","bread dough","pizza dough"],"example":"She kneaded the dough before baking the bread.","exampleZh":"她在烤麵包前先揉了麵團。","synonyms":[],"level":3,"theme":"食物與烹飪","examples":[{"en":"She kneaded the dough before baking the bread.","zh":"她在烤麵包前先揉了麵團。"},{"en":"We rolled out the pizza dough and added cheese and tomatoes.","zh":"我們把披薩麵團擀開，加上起司和番茄。"},{"en":"The bread dough needs to rise for about an hour.","zh":"麵包麵團需要發酵大約一個小時。"}]},{"word":"doughnut","pos":"n.","phonetic":"[ˈdoˌnʌt]","meaning":"甜甜圈","definition":"a small fried cake of sweetened dough","collocations":["chocolate doughnut","box of doughnuts"],"example":"He bought a dozen doughnuts for the office.","exampleZh":"他買了一打甜甜圈給辦公室的人。","synonyms":["donut"],"level":2,"theme":"食物與烹飪","examples":[{"en":"He bought a dozen doughnuts for the office.","zh":"他買了一打甜甜圈給辦公室的人。"},{"en":"She chose a chocolate doughnut with colorful sprinkles on top.","zh":"她選了一個上面撒著彩色糖粒的巧克力甜甜圈。"},{"en":"My mother brought a box of doughnuts home for dessert.","zh":"我媽媽帶了一盒甜甜圈回家當甜點。"}]},{"word":"dove","pos":"n.","phonetic":"[dʌv]","meaning":"鴿子","definition":"a bird often associated with peace","collocations":["white dove","peace dove","release doves"],"example":"A white dove is often used as a symbol of peace.","exampleZh":"白鴿常被用來作為和平的象徵。","synonyms":["pigeon"],"level":3,"theme":"動物與植物","examples":[{"en":"A white dove is often used as a symbol of peace.","zh":"白鴿常被用來作為和平的象徵。"},{"en":"At the ceremony, they released white doves into the clear sky.","zh":"在典禮上，他們把白鴿放飛到晴朗的天空中。"},{"en":"A gentle dove landed on the windowsill and cooed softly.","zh":"一隻溫馴的鴿子停在窗台上，輕輕地咕咕叫著。"}]},{"word":"down","pos":"adv. / prep. / adj.","phonetic":"[daʊn]","meaning":"向下；沮喪的","definition":"toward a lower place","collocations":["sit down","feel down","down the street"],"example":"He walked down the street toward the station.","exampleZh":"他沿著街道走向車站。","synonyms":["downward"],"level":1,"theme":"時間與空間","examples":[{"en":"He walked down the street toward the station.","zh":"他沿著街道走向車站。"},{"en":"Please sit down and make yourself comfortable while I make tea.","zh":"請坐下，別客氣，我來泡茶。"},{"en":"She has been feeling down since her best friend moved away.","zh":"自從她最好的朋友搬走後，她一直覺得很沮喪。"}]},{"word":"download","pos":"v. / n.","phonetic":"[ˈdaʊnˌlod]","meaning":"下載","definition":"to copy data from the internet to a device","collocations":["download a file","download speed","free download"],"example":"You can download the app for free.","exampleZh":"你可以免費下載這個應用程式。","synonyms":[],"level":3,"theme":"科技與媒體","examples":[{"en":"You can download the app for free.","zh":"你可以免費下載這個應用程式。"},{"en":"The download speed here is too slow to watch videos smoothly.","zh":"這裡的下載速度太慢，無法順暢地觀看影片。"},{"en":"I downloaded a useful file to help me study for the exam.","zh":"我下載了一個實用的檔案來幫助我準備考試。"}]},{"word":"downstairs","pos":"adv. / adj.","phonetic":"[ˈdaʊnˈstɛrz]","meaning":"樓下","definition":"on or to a lower floor","collocations":["go downstairs","downstairs neighbor"],"example":"The kitchen is downstairs, next to the living room.","exampleZh":"廚房在樓下，就在客廳旁邊。","synonyms":[],"level":2,"theme":"居家與生活","examples":[{"en":"The kitchen is downstairs, next to the living room.","zh":"廚房在樓下，就在客廳旁邊。"},{"en":"Our downstairs neighbor complained about the noise late last night.","zh":"我們樓下的鄰居抱怨昨天深夜的噪音。"},{"en":"She hurried downstairs when she heard the doorbell ring.","zh":"聽到門鈴響時，她匆匆走下樓。"}]},{"word":"downtown","pos":"n. / adv.","phonetic":"[ˈdaʊnˈtaʊn]","meaning":"市中心","definition":"the central business part of a city","collocations":["go downtown","downtown area","downtown traffic"],"example":"We went downtown to watch a movie.","exampleZh":"我們去市中心看電影。","synonyms":["city center"],"level":3,"theme":"交通與旅行","examples":[{"en":"We went downtown to watch a movie.","zh":"我們去市中心看電影。"},{"en":"The downtown traffic is always heavy during the evening rush hour.","zh":"市中心的交通在傍晚尖峰時段總是很擁擠。"},{"en":"Many trendy shops and cafés are found in the downtown area.","zh":"市中心地區有許多時髦的商店和咖啡館。"}]},{"word":"downward","pos":"adv. / adj.","phonetic":"[ˈdaʊnwɚd]","meaning":"向下的","definition":"moving or pointing toward a lower place","collocations":["downward trend","downward slope","move downward"],"example":"Sales showed a downward trend this quarter.","exampleZh":"這一季的銷售呈現下降趨勢。","synonyms":["descending"],"level":4,"theme":"時間與空間","examples":[{"en":"Sales showed a downward trend this quarter.","zh":"這一季的銷售呈現下降趨勢。"},{"en":"The temperature continued its downward trend throughout the cold week.","zh":"在寒冷的那一週裡，氣溫持續呈現下降的趨勢。"},{"en":"The path followed a gentle downward slope toward the river.","zh":"這條小徑沿著平緩的下坡通向河邊。"}]},{"word":"doze","pos":"v. / n.","phonetic":"[doz]","meaning":"打盹","definition":"to sleep lightly for a short time","collocations":["doze off","have a doze"],"example":"He dozed off during the boring lecture.","exampleZh":"他在無聊的課堂上打起了瞌睡。","synonyms":["nap","snooze"],"level":5,"theme":"身體與健康","examples":[{"en":"He dozed off during the boring lecture.","zh":"他在無聊的課堂上打起了瞌睡。"},{"en":"Grandpa likes to have a short doze after eating lunch.","zh":"爺爺喜歡在吃完午餐後小睡一下。"},{"en":"The warm sunshine made me doze off on the sofa.","zh":"溫暖的陽光讓我在沙發上打起盹來。"}]},{"word":"dozen","pos":"n.","phonetic":"[ˈdʌzn̩]","meaning":"一打；十二個","definition":"a group of twelve","collocations":["a dozen eggs","dozens of times","half a dozen"],"example":"She bought a dozen eggs at the market.","exampleZh":"她在市場買了一打雞蛋。","synonyms":[],"level":2,"theme":"科學與數學","examples":[{"en":"She bought a dozen eggs at the market.","zh":"她在市場買了一打雞蛋。"},{"en":"I have told you dozens of times not to be late.","zh":"我已經跟你說過幾十次不要遲到了。"},{"en":"She bought half a dozen apples for the fruit salad.","zh":"她買了半打蘋果來做水果沙拉。"}]},{"word":"drab","pos":"adj.","phonetic":"[dræb]","meaning":"單調的；灰暗的","definition":"lacking brightness or color; dull","collocations":["drab colors","drab clothing","drab surroundings"],"example":"The office walls were painted a drab gray.","exampleZh":"辦公室的牆壁被漆成單調的灰色。","synonyms":["dull","dreary"],"level":6,"theme":"性質與描述","examples":[{"en":"The office walls were painted a drab gray.","zh":"辦公室的牆壁被漆成單調的灰色。"},{"en":"He brightened up the drab room with a few colorful paintings.","zh":"他用幾幅色彩鮮豔的畫作點亮了那間單調的房間。"},{"en":"She was tired of wearing such drab, gray clothing every day.","zh":"她厭倦了每天穿著如此單調灰暗的衣服。"}]},{"word":"draft","pos":"n. / v.","phonetic":"[dræft]","meaning":"草稿；徵兵；匯票","definition":"a preliminary version of a piece of writing, or to write such a version","collocations":["draft a letter","rough draft","draft a proposal"],"example":"She wrote a draft of her essay before the final version.","exampleZh":"她在寫最終版本之前先寫了一份草稿。","synonyms":["outline","sketch"],"level":4,"theme":"教育與學習","examples":[{"en":"She wrote a draft of her essay before the final version.","zh":"她在寫最終版本之前先寫了一份草稿。"},{"en":"The committee asked me to draft a proposal for the new library.","zh":"委員會要求我為新圖書館草擬一份提案。"},{"en":"This is only a rough draft, so the wording may still change.","zh":"這只是初稿，所以用字遣詞可能還會更動。"}]},{"word":"drag","pos":"v. / n.","phonetic":"[dræg]","meaning":"拖；拖曳；累贅","definition":"to pull something along the ground with effort","collocations":["drag a chair","drag and drop","drag on"],"example":"He dragged the heavy box across the floor.","exampleZh":"他把沉重的箱子拖過地板。","synonyms":["pull","haul"],"level":3,"theme":"動作與行為","examples":[{"en":"He dragged the heavy box across the floor.","zh":"他把沉重的箱子拖過地板。"},{"en":"The boring meeting seemed to drag on for hours.","zh":"那場無聊的會議似乎拖了好幾個小時。"},{"en":"You can simply drag and drop the photos into this folder.","zh":"你只要把照片拖放到這個資料夾裡就好。"}]},{"word":"dragon","pos":"n.","phonetic":"[ˈdrægən]","meaning":"龍","definition":"a mythical creature usually depicted as a giant fire-breathing lizard","collocations":["dragon boat","fire-breathing dragon","dragon legend"],"example":"In Chinese culture, the dragon symbolizes power and good fortune.","exampleZh":"在中華文化中，龍象徵著權力與好運。","synonyms":[],"level":2,"theme":"社會與文化","examples":[{"en":"In Chinese culture, the dragon symbolizes power and good fortune.","zh":"在中華文化中，龍象徵著權力與好運。"},{"en":"Every year our town holds an exciting dragon boat race.","zh":"每年我們鎮上都會舉辦刺激的龍舟比賽。"},{"en":"In the story, a brave knight fought a fire-breathing dragon.","zh":"在這個故事裡，一位勇敢的騎士對抗一條會噴火的龍。"}]},{"word":"drain","pos":"v. / n.","phonetic":"[dren]","meaning":"排水；耗盡；排水管","definition":"to remove liquid gradually, or a pipe carrying away waste water","collocations":["drain water","drain resources","blocked drain"],"example":"The heavy rain caused the drain to overflow.","exampleZh":"大雨導致排水管溢出。","synonyms":["exhaust","empty"],"level":4,"theme":"居家與生活","examples":[{"en":"The heavy rain caused the drain to overflow.","zh":"大雨導致排水管溢出。"},{"en":"The long war began to drain the country's resources.","zh":"這場漫長的戰爭開始耗盡這個國家的資源。"},{"en":"A blocked drain caused water to spread across the kitchen floor.","zh":"堵塞的排水管導致水漫延到廚房地板上。"}]},{"word":"drainage","pos":"n.","phonetic":"[ˈdrenɪdʒ]","meaning":"排水；排水系統","definition":"the removal of water from an area","collocations":["drainage system","poor drainage","drainage pipe"],"example":"The city improved its drainage system after the flood.","exampleZh":"這座城市在洪水後改善了排水系統。","synonyms":[],"level":5,"theme":"居家與生活","examples":[{"en":"The city improved its drainage system after the flood.","zh":"這座城市在洪水後改善了排水系統。"},{"en":"Poor drainage in the field caused the crops to rot.","zh":"田裡不良的排水導致農作物腐爛。"},{"en":"Workers repaired the broken drainage pipe under the road.","zh":"工人修理了路面下損壞的排水管。"}]},{"word":"drama","pos":"n.","phonetic":"[ˈdrɑmə]","meaning":"戲劇；戲劇性事件","definition":"a play for theatre, radio, or television","collocations":["watch a drama","school drama club","real-life drama"],"example":"She joined the drama club at school.","exampleZh":"她加入了學校的戲劇社。","synonyms":["play","theater"],"level":2,"theme":"藝術與音樂","examples":[{"en":"She joined the drama club at school.","zh":"她加入了學校的戲劇社。"},{"en":"We watched a moving drama about a family reunited after years.","zh":"我們看了一部關於一家人多年後團聚的感人戲劇。"},{"en":"The reality show is full of real-life drama and arguments.","zh":"那個實境節目充滿了真實生活的戲劇性事件和爭吵。"}]},{"word":"dramatic","pos":"adj.","phonetic":"[drəˈmætɪk]","meaning":"戲劇性的；引人注目的","definition":"striking in appearance or effect","collocations":["dramatic change","dramatic increase","dramatic effect"],"example":"There was a dramatic increase in sales last month.","exampleZh":"上個月銷售額有戲劇性的成長。","synonyms":["striking","sudden"],"level":4,"theme":"性質與描述","examples":[{"en":"There was a dramatic increase in sales last month.","zh":"上個月銷售額有戲劇性的成長。"},{"en":"There has been a dramatic change in her attitude toward study.","zh":"她對讀書的態度有了戲劇性的轉變。"},{"en":"The new lighting created a dramatic effect on the stage.","zh":"新的燈光在舞台上營造出引人注目的效果。"}]},{"word":"drastic","pos":"adj.","phonetic":"[ˈdræstɪk]","meaning":"激烈的；嚴厲的","definition":"likely to have a strong or far-reaching effect","collocations":["drastic measures","drastic change","drastic action"],"example":"The government took drastic measures to control the disease.","exampleZh":"政府採取激烈措施以控制疾病。","synonyms":["severe","extreme"],"level":5,"theme":"性質與描述","examples":[{"en":"The government took drastic measures to control the disease.","zh":"政府採取激烈措施以控制疾病。"},{"en":"The company took drastic action to cut its rising costs.","zh":"公司採取了激烈的行動來削減不斷上升的成本。"},{"en":"Losing weight safely does not require such a drastic diet.","zh":"安全地減重並不需要如此激烈的飲食方式。"}]},{"word":"draw","pos":"v. / n.","phonetic":"[drɔ]","meaning":"畫；拉；抽籤；平局","definition":"to produce a picture by making lines","collocations":["draw a picture","draw conclusions","draw attention"],"example":"The little girl loves to draw pictures of animals.","exampleZh":"小女孩喜歡畫動物的圖畫。","synonyms":["sketch","pull"],"level":2,"theme":"藝術與音樂","examples":[{"en":"The little girl loves to draw pictures of animals.","zh":"小女孩喜歡畫動物的圖畫。"},{"en":"The colorful poster was designed to draw attention to the event.","zh":"那張色彩繽紛的海報是設計來吸引大家注意這個活動的。"},{"en":"We should not draw conclusions before we have all the facts.","zh":"在掌握所有事實之前，我們不該妄下結論。"}]},{"word":"drawback","pos":"n.","phonetic":"[ˈdrɔˌbæk]","meaning":"缺點；不利之處","definition":"a disadvantage or problem","collocations":["main drawback","serious drawback","drawback of a plan"],"example":"The main drawback of the job is the low salary.","exampleZh":"這份工作的主要缺點是薪水低。","synonyms":["disadvantage","downside"],"level":5,"theme":"抽象概念","examples":[{"en":"The main drawback of the job is the low salary.","zh":"這份工作的主要缺點是薪水低。"},{"en":"One serious drawback of the plan is its very high cost.","zh":"這個計畫的一個嚴重缺點就是它極高的成本。"},{"en":"The only drawback of this laptop is its short battery life.","zh":"這台筆電唯一的缺點就是電池續航力太短。"}]},{"word":"drawer","pos":"n.","phonetic":"[drɔr]","meaning":"抽屜","definition":"a box-shaped storage compartment","collocations":["open a drawer","top drawer","desk drawer"],"example":"She keeps her socks in the top drawer.","exampleZh":"她把襪子放在最上層的抽屜裡。","synonyms":[],"level":2,"theme":"居家與生活","examples":[{"en":"She keeps her socks in the top drawer.","zh":"她把襪子放在最上層的抽屜裡。"},{"en":"He searched every desk drawer but could not find his keys.","zh":"他翻遍了書桌的每個抽屜，卻找不到他的鑰匙。"},{"en":"Please put the clean spoons in the top drawer.","zh":"請把乾淨的湯匙放進最上層的抽屜。"}]},{"word":"drawing","pos":"n.","phonetic":"[ˈdrɔɪŋ]","meaning":"素描；繪畫","definition":"a picture made with a pencil or pen","collocations":["pencil drawing","drawing class","make a drawing"],"example":"He made a detailed drawing of the building.","exampleZh":"他畫了一張這棟建築的詳細素描。","synonyms":["sketch","illustration"],"level":2,"theme":"藝術與音樂","examples":[{"en":"He made a detailed drawing of the building.","zh":"他畫了一張這棟建築的詳細素描。"},{"en":"She signed up for a drawing class at the community center.","zh":"她在社區中心報名了一堂繪畫課。"},{"en":"His pencil drawing of the old bridge won first prize.","zh":"他那幅舊橋的鉛筆素描贏得了第一名。"}]},{"word":"dread","pos":"v. / n.","phonetic":"[drɛd]","meaning":"害怕；恐懼","definition":"to anticipate with great apprehension","collocations":["dread the exam","live in dread","dread doing something"],"example":"I dread going to the dentist.","exampleZh":"我很害怕去看牙醫。","synonyms":["fear","terror"],"level":5,"theme":"情緒與感受","examples":[{"en":"I dread going to the dentist.","zh":"我很害怕去看牙醫。"},{"en":"Many students dread the final exam at the end of the term.","zh":"許多學生害怕學期末的期末考。"},{"en":"She lived in dread of forgetting her lines on stage.","zh":"她一直很害怕在舞台上忘詞。"}]},{"word":"dreadful","pos":"adj.","phonetic":"[ˈdrɛdfəl]","meaning":"可怕的；糟糕透頂的","definition":"causing or involving great suffering; very bad","collocations":["dreadful weather","dreadful mistake","feel dreadful"],"example":"The weather was dreadful during our trip.","exampleZh":"我們旅行時天氣糟透了。","synonyms":["terrible","awful"],"level":4,"theme":"性質與描述","examples":[{"en":"The weather was dreadful during our trip.","zh":"我們旅行時天氣糟透了。"},{"en":"I made a dreadful mistake and sent the letter to the wrong person.","zh":"我犯了一個糟糕透頂的錯誤，把信寄給了錯的人。"},{"en":"She felt dreadful after eating the spoiled seafood.","zh":"吃了不新鮮的海鮮後，她覺得非常難受。"}]},{"word":"dream","pos":"n. / v.","phonetic":"[drim]","meaning":"夢；夢想","definition":"a series of thoughts during sleep, or to imagine something desired","collocations":["have a dream","dream job","dream of"],"example":"She dreams of becoming a famous singer.","exampleZh":"她夢想成為一位有名的歌手。","synonyms":["fantasy","vision"],"level":1,"theme":"抽象概念","examples":[{"en":"She dreams of becoming a famous singer.","zh":"她夢想成為一位有名的歌手。"},{"en":"Becoming a pilot has always been his dream job.","zh":"當一名飛行員一直是他夢寐以求的工作。"},{"en":"Last night I had a strange dream about flying over mountains.","zh":"昨晚我做了一個關於飛越群山的奇怪的夢。"}]},{"word":"dreamer","pos":"n.","phonetic":"[ˈdrimɚ]","meaning":"空想家；夢想者","definition":"a person who has unrealistic or impractical ideas","collocations":["hopeless dreamer","born dreamer"],"example":"He is a dreamer who always talks about future plans.","exampleZh":"他是個總是談論未來計畫的夢想家。","synonyms":["idealist"],"level":4,"theme":"人物與家庭","examples":[{"en":"He is a dreamer who always talks about future plans.","zh":"他是個總是談論未來計畫的夢想家。"},{"en":"People called him a hopeless dreamer, but his idea finally worked.","zh":"人們稱他為無可救藥的空想家，但他的點子最終成功了。"},{"en":"As a born dreamer, she always imagines a better future.","zh":"身為一個天生的夢想家，她總是想像著更美好的未來。"}]},{"word":"dreamy","pos":"adj.","phonetic":"[ˈdrimi]","meaning":"夢幻的；心不在焉的","definition":"dreamlike, vague, or impractical","collocations":["dreamy expression","dreamy look","dreamy music"],"example":"She had a dreamy look on her face.","exampleZh":"她臉上帶著夢幻般的表情。","synonyms":["vague","absent-minded"],"level":5,"theme":"情緒與感受","examples":[{"en":"She had a dreamy look on her face.","zh":"她臉上帶著夢幻般的表情。"},{"en":"The soft, dreamy music slowly made everyone feel relaxed.","zh":"那輕柔夢幻的音樂慢慢讓每個人都感到放鬆。"},{"en":"He stared out of the window with a dreamy expression.","zh":"他帶著心不在焉的表情望向窗外。"}]},{"word":"dress","pos":"n. / v.","phonetic":"[drɛs]","meaning":"洋裝；穿衣","definition":"a one-piece garment for women, or to put on clothes","collocations":["wear a dress","dress up","get dressed"],"example":"She wore a beautiful red dress to the party.","exampleZh":"她穿了一件漂亮的紅色洋裝去參加派對。","synonyms":["gown","attire"],"level":1,"theme":"服裝與外表","examples":[{"en":"She wore a beautiful red dress to the party.","zh":"她穿了一件漂亮的紅色洋裝去參加派對。"},{"en":"The children love to dress up as their favorite heroes.","zh":"孩子們喜歡打扮成他們最喜歡的英雄。"},{"en":"You should get dressed quickly, or we will miss the bus.","zh":"你該快點穿好衣服，否則我們會錯過公車。"}]},{"word":"dresser","pos":"n.","phonetic":"[ˈdrɛsɚ]","meaning":"梳妝台；服裝設計師","definition":"a chest of drawers for clothes","collocations":["bedroom dresser","wooden dresser"],"example":"She put her jewelry on the dresser.","exampleZh":"她把珠寶放在梳妝台上。","synonyms":[],"level":4,"theme":"居家與生活","examples":[{"en":"She put her jewelry on the dresser.","zh":"她把珠寶放在梳妝台上。"},{"en":"A beautiful wooden dresser stood against the bedroom wall.","zh":"一個漂亮的木製梳妝台靠著臥室的牆擺放著。"},{"en":"She keeps a small mirror on top of her dresser.","zh":"她在梳妝台上放了一面小鏡子。"}]},{"word":"dressing","pos":"n.","phonetic":"[ˈdrɛsɪŋ]","meaning":"醬料；敷料；穿衣","definition":"a sauce for food, or a covering for a wound","collocations":["salad dressing","wound dressing","dressing room"],"example":"She poured dressing over the salad.","exampleZh":"她把醬料淋在沙拉上。","synonyms":["sauce"],"level":4,"theme":"食物與烹飪","examples":[{"en":"She poured dressing over the salad.","zh":"她把醬料淋在沙拉上。"},{"en":"The nurse gently changed the dressing on his injured arm.","zh":"護士輕輕地更換了他受傷手臂上的敷料。"},{"en":"Actors waited in the dressing room before the show began.","zh":"演出開始前，演員們在化妝間裡等候。"}]},{"word":"drift","pos":"v. / n.","phonetic":"[drɪft]","meaning":"漂流；漂移","definition":"to be carried slowly by a current of air or water","collocations":["drift away","drift apart","snow drift"],"example":"The boat drifted slowly down the river.","exampleZh":"那艘船緩緩地順流而下。","synonyms":["float","wander"],"level":4,"theme":"自然與環境","examples":[{"en":"The boat drifted slowly down the river.","zh":"那艘船緩緩地順流而下。"},{"en":"Over the years, the two old friends slowly drifted apart.","zh":"多年來，這兩位老朋友漸漸疏遠了。"},{"en":"The empty raft drifted away from the shore in the wind.","zh":"那艘空木筏隨風漂離了岸邊。"}]},{"word":"drill","pos":"n. / v.","phonetic":"[drɪl]","meaning":"鑽孔機；訓練；演習","definition":"a tool for boring holes, or to practice repeatedly","collocations":["fire drill","drill a hole","practice drills"],"example":"The school held a fire drill this morning.","exampleZh":"學校今天早上舉行了消防演習。","synonyms":["exercise","practice"],"level":3,"theme":"教育與學習","examples":[{"en":"The school held a fire drill this morning.","zh":"學校今天早上舉行了消防演習。"},{"en":"He used an electric drill to make a hole in the wall.","zh":"他用電鑽在牆上鑽了一個洞。"},{"en":"The soccer team does the same passing drills every practice.","zh":"足球隊每次練習都做同樣的傳球訓練。"}]},{"word":"drink","pos":"v. / n.","phonetic":"[drɪŋk]","meaning":"喝；飲料","definition":"to take liquid into the mouth and swallow","collocations":["drink water","soft drink","drink alcohol"],"example":"You should drink more water every day.","exampleZh":"你每天應該多喝水。","synonyms":["beverage","sip"],"level":1,"theme":"食物與烹飪","examples":[{"en":"You should drink more water every day.","zh":"你每天應該多喝水。"},{"en":"Doctors advise people not to drink alcohol before driving.","zh":"醫生建議民眾開車前不要喝酒。"},{"en":"She ordered a cold soft drink to go with her burger.","zh":"她點了一杯冰涼的軟性飲料來搭配她的漢堡。"}]},{"word":"drip","pos":"v. / n.","phonetic":"[drɪp]","meaning":"滴；滴落","definition":"to fall in drops","collocations":["drip water","dripping wet","drip coffee"],"example":"Water dripped from the leaking faucet.","exampleZh":"水從漏水的水龍頭滴下。","synonyms":["dribble","leak"],"level":3,"theme":"自然與環境","examples":[{"en":"Water dripped from the leaking faucet.","zh":"水從漏水的水龍頭滴下。"},{"en":"He came in dripping wet after being caught in the rain.","zh":"他淋了雨，渾身濕透地走了進來。"},{"en":"Rain began to drip slowly through the hole in the roof.","zh":"雨水開始從屋頂的破洞緩緩滴落下來。"}]},{"word":"drive","pos":"v. / n.","phonetic":"[draɪv]","meaning":"駕駛；開車；驅動力","definition":"to operate and control a vehicle","collocations":["drive a car","driving license","drive someone crazy"],"example":"My father drives me to school every day.","exampleZh":"我爸爸每天開車送我上學。","synonyms":["operate","motivate"],"level":1,"theme":"交通與旅行","examples":[{"en":"My father drives me to school every day.","zh":"我爸爸每天開車送我上學。"},{"en":"The constant noise from the street is driving me crazy.","zh":"街上不停的噪音快把我逼瘋了。"},{"en":"You must pass a test to get a driving license.","zh":"你必須通過考試才能取得駕照。"}]},{"word":"driver","pos":"n.","phonetic":"[ˈdraɪvɚ]","meaning":"駕駛員；司機","definition":"a person who drives a vehicle","collocations":["bus driver","careful driver","taxi driver"],"example":"The bus driver stopped to let the passengers on.","exampleZh":"公車司機停下來讓乘客上車。","synonyms":[],"level":1,"theme":"交通與旅行","examples":[{"en":"The bus driver stopped to let the passengers on.","zh":"公車司機停下來讓乘客上車。"},{"en":"The taxi driver knew a shortcut to avoid the traffic jam.","zh":"計程車司機知道一條可以避開塞車的捷徑。"},{"en":"A careful driver always checks the mirrors before turning.","zh":"謹慎的駕駛在轉彎前總會先查看後照鏡。"}]},{"word":"driveway","pos":"n.","phonetic":"[ˈdraɪvˌwe]","meaning":"私人車道","definition":"a private road leading to a house","collocations":["long driveway","park in the driveway"],"example":"He parked his car in the driveway.","exampleZh":"他把車停在車道上。","synonyms":[],"level":3,"theme":"居家與生活","examples":[{"en":"He parked his car in the driveway.","zh":"他把車停在車道上。"},{"en":"Their house has a long driveway lined with tall trees.","zh":"他們家有一條兩旁種著高大樹木的長車道。"},{"en":"Please don't block the driveway with your bicycle.","zh":"請不要用你的腳踏車擋住車道。"}]},{"word":"drizzle","pos":"n. / v.","phonetic":"[ˈdrɪzl̩]","meaning":"毛毛雨","definition":"light rain falling in fine drops","collocations":["light drizzle","drizzle outside"],"example":"A light drizzle fell as we walked home.","exampleZh":"我們走路回家時下著毛毛雨。","synonyms":["sprinkle","mist"],"level":5,"theme":"天氣與季節","examples":[{"en":"A light drizzle fell as we walked home.","zh":"我們走路回家時下著毛毛雨。"},{"en":"There is a light drizzle outside, so take an umbrella.","zh":"外面下著毛毛雨，所以帶把傘吧。"},{"en":"The morning drizzle made the streets shiny and wet.","zh":"早晨的毛毛雨讓街道變得濕亮。"}]},{"word":"drone","pos":"n. / v.","phonetic":"[dron]","meaning":"無人機；嗡嗡聲","definition":"a remote-controlled aircraft, or a continuous low sound","collocations":["fly a drone","drone camera","drone on"],"example":"The company used a drone to film the event.","exampleZh":"這家公司用無人機拍攝這場活動。","synonyms":[],"level":5,"theme":"科技與媒體","examples":[{"en":"The company used a drone to film the event.","zh":"這家公司用無人機拍攝這場活動。"},{"en":"The photographer used a drone to capture the whole valley.","zh":"攝影師用無人機拍下了整個山谷。"},{"en":"The teacher droned on until half the class fell asleep.","zh":"老師單調地講個不停，直到半個班的人都睡著了。"}]},{"word":"droop","pos":"v.","phonetic":"[drup]","meaning":"下垂；低垂","definition":"to bend or hang downward","collocations":["droop with fatigue","drooping flowers","shoulders droop"],"example":"The flowers began to droop without water.","exampleZh":"這些花因為缺水開始垂下來。","synonyms":["sag","wilt"],"level":6,"theme":"自然與環境","examples":[{"en":"The flowers began to droop without water.","zh":"這些花因為缺水開始垂下來。"},{"en":"His shoulders drooped with fatigue after the long hike.","zh":"長途健行後，他的肩膀因疲憊而下垂。"},{"en":"The drooping flowers stood up again after we watered them.","zh":"低垂的花朵在我們澆水後又挺立起來了。"}]},{"word":"drop","pos":"v. / n.","phonetic":"[drɑp]","meaning":"掉落；滴；下降","definition":"to fall or let fall","collocations":["drop a hint","drop by","price drop"],"example":"Please don't drop the glass; it will break.","exampleZh":"請不要摔破玻璃杯，它會破掉。","synonyms":["fall","decline"],"level":2,"theme":"動作與行為","examples":[{"en":"Please don't drop the glass; it will break.","zh":"請不要摔破玻璃杯，它會破掉。"},{"en":"She dropped a hint that she would like a new bag.","zh":"她暗示說她想要一個新包包。"},{"en":"Feel free to drop by my house whenever you are nearby.","zh":"只要你在附近，隨時都可以順道來我家坐坐。"}]},{"word":"drought","pos":"n.","phonetic":"[draʊt]","meaning":"乾旱","definition":"a prolonged period of abnormally low rainfall","collocations":["severe drought","drought season","suffer from drought"],"example":"The region suffered a severe drought last summer.","exampleZh":"這個地區去年夏天遭受了嚴重的乾旱。","synonyms":["dry spell"],"level":5,"theme":"自然與環境","examples":[{"en":"The region suffered a severe drought last summer.","zh":"這個地區去年夏天遭受了嚴重的乾旱。"},{"en":"During the drought, farmers struggled to keep their crops alive.","zh":"在乾旱期間，農民們努力想讓農作物存活。"},{"en":"The long drought left the reservoir almost completely empty.","zh":"長期的乾旱使水庫幾乎完全乾涸。"}]},{"word":"drown","pos":"v.","phonetic":"[draʊn]","meaning":"淹死；溺水","definition":"to die or kill by being submerged in water and unable to breathe","collocations":["drown in water","nearly drown","drown out"],"example":"The lifeguard saved the boy from drowning.","exampleZh":"救生員救了那個差點溺水的男孩。","synonyms":["sink"],"level":4,"theme":"身體與健康","examples":[{"en":"The lifeguard saved the boy from drowning.","zh":"救生員救了那個差點溺水的男孩。"},{"en":"The loud music almost drowned out our conversation at dinner.","zh":"吵雜的音樂幾乎蓋過了我們晚餐時的談話。"},{"en":"He nearly drowned in the river before someone pulled him out.","zh":"在有人把他拉上來之前，他差點在河裡溺水。"}]},{"word":"drowsy","pos":"adj.","phonetic":"[ˈdraʊzi]","meaning":"昏昏欲睡的","definition":"feeling sleepy","collocations":["feel drowsy","drowsy driving","drowsy afternoon"],"example":"The medicine made her feel drowsy.","exampleZh":"那藥讓她感到昏昏欲睡。","synonyms":["sleepy","tired"],"level":5,"theme":"身體與健康","examples":[{"en":"The medicine made her feel drowsy.","zh":"那藥讓她感到昏昏欲睡。"},{"en":"Drowsy driving is very dangerous and can cause serious accidents.","zh":"疲勞駕駛非常危險，可能會造成嚴重的車禍。"},{"en":"The warm classroom made all the students feel drowsy.","zh":"溫暖的教室讓所有學生都覺得昏昏欲睡。"}]},{"word":"drug","pos":"n.","phonetic":"[drʌg]","meaning":"藥物；毒品","definition":"a medicine or an illegal substance","collocations":["take drugs","drug abuse","prescription drug"],"example":"The doctor prescribed a new drug for his illness.","exampleZh":"醫生為他的病開了一種新藥。","synonyms":["medicine","narcotic"],"level":3,"theme":"身體與健康","examples":[{"en":"The doctor prescribed a new drug for his illness.","zh":"醫生為他的病開了一種新藥。"},{"en":"Schools often teach students about the dangers of drug abuse.","zh":"學校經常教導學生濫用毒品的危險。"},{"en":"You should not take this prescription drug without a doctor's advice.","zh":"沒有醫生的建議，你不應該服用這種處方藥。"}]},{"word":"drugstore","pos":"n.","phonetic":"[ˈdrʌgˌstor]","meaning":"藥妝店","definition":"a store that sells medicine and other goods","collocations":["local drugstore","buy at the drugstore"],"example":"I bought some shampoo at the drugstore.","exampleZh":"我在藥妝店買了一些洗髮精。","synonyms":["pharmacy"],"level":3,"theme":"商業與金錢","examples":[{"en":"I bought some shampoo at the drugstore.","zh":"我在藥妝店買了一些洗髮精。"},{"en":"You can buy bandages and vitamins at the local drugstore.","zh":"你可以在當地的藥妝店買到繃帶和維他命。"},{"en":"The drugstore near the station stays open until midnight.","zh":"車站附近的藥妝店營業到午夜。"}]},{"word":"drum","pos":"n. / v.","phonetic":"[drʌm]","meaning":"鼓；打鼓","definition":"a percussion instrument","collocations":["play the drums","drum set","beat a drum"],"example":"He plays the drums in a rock band.","exampleZh":"他在搖滾樂團裡打鼓。","synonyms":[],"level":2,"theme":"藝術與音樂","examples":[{"en":"He plays the drums in a rock band.","zh":"他在搖滾樂團裡打鼓。"},{"en":"The soldiers marched forward as someone beat a large drum.","zh":"有人敲著一面大鼓，士兵們向前行進。"},{"en":"My brother saved money to buy a new drum set.","zh":"我哥哥存錢買了一套新的爵士鼓。"}]},{"word":"drumstick","pos":"n.","phonetic":"[ˈdrʌmˌstɪk]","meaning":"鼓棒；雞腿","definition":"a stick used for playing drums, or a chicken leg","collocations":["chicken drumstick","hold a drumstick"],"example":"She ordered a fried chicken drumstick for lunch.","exampleZh":"她午餐點了一份炸雞腿。","synonyms":[],"level":3,"theme":"食物與烹飪","examples":[{"en":"She ordered a fried chicken drumstick for lunch.","zh":"她午餐點了一份炸雞腿。"},{"en":"The little boy happily bit into a juicy chicken drumstick.","zh":"小男孩開心地咬了一口多汁的雞腿。"},{"en":"The drummer held a drumstick in each hand and began to play.","zh":"鼓手雙手各握著一根鼓棒，開始演奏。"}]},{"word":"drunk","pos":"adj. / n.","phonetic":"[drʌŋk]","meaning":"喝醉的；醉漢","definition":"affected by alcohol","collocations":["get drunk","drunk driving","drunk driver"],"example":"He was too drunk to drive home.","exampleZh":"他醉得無法開車回家。","synonyms":["intoxicated"],"level":4,"theme":"身體與健康","examples":[{"en":"He was too drunk to drive home.","zh":"他醉得無法開車回家。"},{"en":"Drunk driving is against the law and puts lives at risk.","zh":"酒後駕車是違法的，而且會危及性命。"},{"en":"He got so drunk at the party that he could barely stand.","zh":"他在派對上喝得酩酊大醉，幾乎站不穩。"}]},{"word":"dry","pos":"adj. / v.","phonetic":"[draɪ]","meaning":"乾燥的；使乾燥","definition":"free from moisture","collocations":["dry weather","dry clothes","dry season"],"example":"The towel felt completely dry.","exampleZh":"那條毛巾摸起來完全乾了。","synonyms":["arid","dehydrated"],"level":1,"theme":"天氣與季節","examples":[{"en":"The towel felt completely dry.","zh":"那條毛巾摸起來完全乾了。"},{"en":"During the dry season, the grass turns brown and brittle.","zh":"在乾季期間，草會變得枯黃又脆。"},{"en":"She hung the wet clothes outside to dry in the sun.","zh":"她把濕衣服掛在外面讓太陽曬乾。"}]},{"word":"dryer","pos":"n.","phonetic":"[ˈdraɪɚ]","meaning":"烘乾機","definition":"a machine for drying clothes or hair","collocations":["hair dryer","clothes dryer","use a dryer"],"example":"She put the wet clothes in the dryer.","exampleZh":"她把濕衣服放進烘乾機裡。","synonyms":[],"level":3,"theme":"居家與生活","examples":[{"en":"She put the wet clothes in the dryer.","zh":"她把濕衣服放進烘乾機裡。"},{"en":"She used a hair dryer to style her hair before school.","zh":"上學前她用吹風機整理頭髮。"},{"en":"Our clothes dryer broke, so we hung the laundry outside.","zh":"我們的烘衣機壞了，所以我們把洗好的衣服晾在外面。"}]},{"word":"dryness","pos":"n.","phonetic":"[ˈdraɪnɪs]","meaning":"乾燥","definition":"the quality of being dry","collocations":["skin dryness","dryness of the air"],"example":"The lotion helps reduce skin dryness.","exampleZh":"這款乳液有助於減少皮膚乾燥。","synonyms":["aridity"],"level":5,"theme":"身體與健康","examples":[{"en":"The lotion helps reduce skin dryness.","zh":"這款乳液有助於減少皮膚乾燥。"},{"en":"The dryness of the winter air often makes my lips crack.","zh":"冬天空氣的乾燥常常讓我的嘴唇龜裂。"},{"en":"Drinking enough water can help reduce skin dryness.","zh":"喝足夠的水有助於減少皮膚的乾燥。"}]},{"word":"dubious","pos":"adj.","phonetic":"[ˈdjubɪəs]","meaning":"可疑的；懷疑的","definition":"hesitating or doubting","collocations":["dubious claim","dubious about","dubious reputation"],"example":"I'm dubious about his explanation.","exampleZh":"我對他的解釋感到懷疑。","synonyms":["doubtful","suspicious"],"level":6,"theme":"情緒與感受","examples":[{"en":"I'm dubious about his explanation.","zh":"我對他的解釋感到懷疑。"},{"en":"The salesman made a dubious claim about the product's benefits.","zh":"那個推銷員對產品的功效做出了可疑的宣稱。"},{"en":"She felt dubious about lending money to a stranger.","zh":"她對借錢給陌生人這件事感到懷疑。"}]},{"word":"duck","pos":"n. / v.","phonetic":"[dʌk]","meaning":"鴨子；躲避","definition":"a water bird, or to lower the head quickly","collocations":["feed the ducks","duck down","roast duck"],"example":"The children fed bread to the ducks in the pond.","exampleZh":"孩子們在池塘裡餵鴨子吃麵包。","synonyms":[],"level":1,"theme":"動物與植物","examples":[{"en":"The children fed bread to the ducks in the pond.","zh":"孩子們在池塘裡餵鴨子吃麵包。"},{"en":"He quickly ducked down to avoid the low branch.","zh":"他迅速低下頭以避開低矮的樹枝。"},{"en":"We ordered roast duck at the famous restaurant downtown.","zh":"我們在市中心那家著名的餐廳點了烤鴨。"}]},{"word":"duckling","pos":"n.","phonetic":"[ˈdʌklɪŋ]","meaning":"小鴨","definition":"a young duck","collocations":["ugly duckling","baby duckling"],"example":"The mother duck was followed by five ducklings.","exampleZh":"母鴨後面跟著五隻小鴨。","synonyms":[],"level":2,"theme":"動物與植物","examples":[{"en":"The mother duck was followed by five ducklings.","zh":"母鴨後面跟著五隻小鴨。"},{"en":"A fluffy baby duckling swam close behind its mother.","zh":"一隻毛茸茸的小鴨緊跟在媽媽後面游著。"},{"en":"The story of the ugly duckling teaches us not to judge by looks.","zh":"醜小鴨的故事教導我們不要以貌取人。"}]},{"word":"due","pos":"adj.","phonetic":"[dju]","meaning":"到期的；應得的；由於","definition":"expected at a certain time; owed","collocations":["due date","due to","payment due"],"example":"The report is due next Monday.","exampleZh":"這份報告下週一到期。","synonyms":["owed","expected"],"level":3,"theme":"時間與空間","examples":[{"en":"The report is due next Monday.","zh":"這份報告下週一到期。"},{"en":"The flight was delayed due to the heavy snow.","zh":"由於大雪，班機延誤了。"},{"en":"Don't forget that your library books are due tomorrow.","zh":"別忘了你的圖書館書籍明天就到期了。"}]},{"word":"duel","pos":"n. / v.","phonetic":"[ˈdjuəl]","meaning":"決鬥","definition":"a formal fight between two people","collocations":["fight a duel","sword duel"],"example":"In the movie, the two knights fought a duel.","exampleZh":"在電影裡，兩位騎士進行了一場決鬥。","synonyms":["contest","fight"],"level":6,"theme":"社會與文化","examples":[{"en":"In the movie, the two knights fought a duel.","zh":"在電影裡，兩位騎士進行了一場決鬥。"},{"en":"Long ago, gentlemen would fight a duel to defend their honor.","zh":"很久以前，紳士們會以決鬥來捍衛自己的榮譽。"},{"en":"The exciting sword duel was the best scene in the play.","zh":"那場精彩的劍術決鬥是這齣戲最棒的場景。"}]},{"word":"duet","pos":"n.","phonetic":"[djuˈɛt]","meaning":"二重唱；二重奏","definition":"a musical composition for two performers","collocations":["sing a duet","piano duet","perform a duet"],"example":"The two singers performed a beautiful duet.","exampleZh":"這兩位歌手表演了一首美妙的二重唱。","synonyms":[],"level":4,"theme":"藝術與音樂","examples":[{"en":"The two singers performed a beautiful duet.","zh":"這兩位歌手表演了一首美妙的二重唱。"},{"en":"The sisters practiced a piano duet for the school concert.","zh":"姊妹倆為學校音樂會練習了一首鋼琴二重奏。"},{"en":"He invited me to sing a duet with him on stage.","zh":"他邀請我和他一起在台上合唱二重唱。"}]},{"word":"duke","pos":"n.","phonetic":"[djuk]","meaning":"公爵","definition":"a nobleman of high rank","collocations":["royal duke","duke and duchess"],"example":"The duke owned a large castle in the countryside.","exampleZh":"那位公爵在鄉間擁有一座大城堡。","synonyms":[],"level":5,"theme":"社會與文化","examples":[{"en":"The duke owned a large castle in the countryside.","zh":"那位公爵在鄉間擁有一座大城堡。"},{"en":"The duke and duchess welcomed hundreds of guests to the ball.","zh":"公爵和公爵夫人歡迎數百名賓客參加舞會。"},{"en":"According to the legend, the young duke ruled with great kindness.","zh":"根據傳說，這位年輕的公爵以極大的仁慈統治。"}]},{"word":"dull","pos":"adj.","phonetic":"[dʌl]","meaning":"無趣的；遲鈍的；不鋒利的","definition":"not interesting; not sharp","collocations":["dull knife","dull lecture","dull pain"],"example":"The movie was so dull that I fell asleep.","exampleZh":"這部電影太無聊了，我睡著了。","synonyms":["boring","blunt"],"level":3,"theme":"性質與描述","examples":[{"en":"The movie was so dull that I fell asleep.","zh":"這部電影太無聊了，我睡著了。"},{"en":"It is hard to cut vegetables with such a dull knife.","zh":"用這麼鈍的刀很難切菜。"},{"en":"She felt a dull pain in her back after sitting all day.","zh":"坐了一整天後，她的背部感到一陣隱隱的疼痛。"}]},{"word":"dumb","pos":"adj.","phonetic":"[dʌm]","meaning":"啞的；愚蠢的","definition":"unable to speak; stupid","collocations":["dumb question","deaf and dumb","feel dumb"],"example":"That was a really dumb mistake to make.","exampleZh":"那真的是一個很愚蠢的錯誤。","synonyms":["silent","stupid"],"level":3,"theme":"性質與描述","examples":[{"en":"That was a really dumb mistake to make.","zh":"那真的是一個很愚蠢的錯誤。"},{"en":"There is no such thing as a dumb question in this class.","zh":"在這堂課裡，沒有所謂的愚蠢問題。"},{"en":"I felt so dumb after forgetting my teacher's name.","zh":"忘了老師的名字後，我覺得自己好蠢。"}]},{"word":"dummy","pos":"n. / adj.","phonetic":"[ˈdʌmi]","meaning":"假人；仿製品","definition":"a model of a human body; not real","collocations":["crash test dummy","dummy text"],"example":"The store used a dummy to display clothes.","exampleZh":"這家店用假人模特兒展示衣服。","synonyms":["model","fake"],"level":4,"theme":"其他","examples":[{"en":"The store used a dummy to display clothes.","zh":"這家店用假人模特兒展示衣服。"},{"en":"Engineers use a crash test dummy to check car safety.","zh":"工程師用碰撞測試假人來檢查汽車的安全性。"},{"en":"The designer filled the page with dummy text for now.","zh":"設計師目前先在頁面上填入了假文字。"}]},{"word":"dump","pos":"v. / n.","phonetic":"[dʌmp]","meaning":"傾倒；丟棄；垃圾場","definition":"to put down or drop carelessly","collocations":["dump garbage","dump truck","dump site"],"example":"Please don't dump trash in the river.","exampleZh":"請不要把垃圾倒進河裡。","synonyms":["discard","unload"],"level":4,"theme":"自然與環境","examples":[{"en":"Please don't dump trash in the river.","zh":"請不要把垃圾倒進河裡。"},{"en":"A large dump truck carried the soil away from the site.","zh":"一輛大型傾卸卡車把泥土從工地運走。"},{"en":"It is illegal to dump garbage in this public park.","zh":"在這座公園裡傾倒垃圾是違法的。"}]},{"word":"dumpling","pos":"n.","phonetic":"[ˈdʌmplɪŋ]","meaning":"餃子；湯圓","definition":"a small piece of dough cooked in soup or steamed","collocations":["steamed dumpling","dumpling soup","make dumplings"],"example":"We made dumplings together for the festival.","exampleZh":"我們一起包餃子過節。","synonyms":[],"level":2,"theme":"食物與烹飪","examples":[{"en":"We made dumplings together for the festival.","zh":"我們一起包餃子過節。"},{"en":"The restaurant is famous for its juicy steamed dumplings.","zh":"這家餐廳以它多汁的蒸餃而聞名。"},{"en":"On cold days, a bowl of hot dumpling soup is comforting.","zh":"在寒冷的日子裡，一碗熱騰騰的餃子湯很暖心。"}]},{"word":"dune","pos":"n.","phonetic":"[djun]","meaning":"沙丘","definition":"a hill of sand formed by the wind","collocations":["sand dune","dune buggy"],"example":"We climbed a huge sand dune near the beach.","exampleZh":"我們爬上海邊一座巨大的沙丘。","synonyms":[],"level":5,"theme":"自然與環境","examples":[{"en":"We climbed a huge sand dune near the beach.","zh":"我們爬上海邊一座巨大的沙丘。"},{"en":"The wind slowly changed the shape of the sand dunes.","zh":"風慢慢地改變了沙丘的形狀。"},{"en":"Tourists rode a dune buggy across the wide desert.","zh":"遊客們駕著沙灘車越過廣闊的沙漠。"}]},{"word":"dungeon","pos":"n.","phonetic":"[ˈdʌndʒən]","meaning":"地牢","definition":"an underground prison, especially in a castle","collocations":["dark dungeon","locked in a dungeon"],"example":"The prisoner was kept in a cold, dark dungeon.","exampleZh":"那名囚犯被關在一個又冷又黑的地牢裡。","synonyms":["cell","prison"],"level":5,"theme":"社會與文化","examples":[{"en":"The prisoner was kept in a cold, dark dungeon.","zh":"那名囚犯被關在一個又冷又黑的地牢裡。"},{"en":"In the fairy tale, the princess was locked in a dungeon.","zh":"在這個童話故事裡，公主被關在地牢裡。"},{"en":"The castle's dark dungeon had not been opened for centuries.","zh":"城堡陰暗的地牢已經好幾個世紀沒有被打開過了。"}]},{"word":"duo","pos":"n.","phonetic":"[ˈdjuo]","meaning":"二人組；搭檔","definition":"two people who do something together","collocations":["comedy duo","musical duo"],"example":"The two singers formed a popular duo.","exampleZh":"這兩位歌手組成了一個受歡迎的二人組。","synonyms":["pair","couple"],"level":5,"theme":"藝術與音樂","examples":[{"en":"The two singers formed a popular duo.","zh":"這兩位歌手組成了一個受歡迎的二人組。"},{"en":"The comedy duo made the whole audience laugh out loud.","zh":"這對喜劇搭檔逗得全場觀眾哈哈大笑。"},{"en":"As a musical duo, they wrote and performed all their own songs.","zh":"身為一個音樂二人組，他們創作並演出了所有自己的歌曲。"}]},{"word":"duplicate","pos":"v. / n. / adj.","phonetic":"[ˈdjupləˌket]","meaning":"複製；副本","definition":"to make an exact copy of something","collocations":["duplicate a document","duplicate key","exact duplicate"],"example":"Please duplicate this file and send a copy to me.","exampleZh":"請複製這份文件並寄一份副本給我。","synonyms":["copy","replicate"],"level":5,"theme":"科技與媒體","examples":[{"en":"Please duplicate this file and send a copy to me.","zh":"請複製這份文件並寄一份副本給我。"},{"en":"I keep a duplicate key in case I lock myself out.","zh":"我留了一把備份鑰匙，以防被鎖在門外。"},{"en":"This painting is an exact duplicate of the famous original.","zh":"這幅畫是那幅著名原作的精確複製品。"}]},{"word":"durability","pos":"n.","phonetic":"[ˌdjʊrəˈbɪləti]","meaning":"耐久性","definition":"the ability to last a long time","collocations":["test durability","product durability"],"example":"The company tested the durability of the new phone.","exampleZh":"這家公司測試了新手機的耐久性。","synonyms":[],"level":6,"theme":"科技與媒體","examples":[{"en":"The company tested the durability of the new phone.","zh":"這家公司測試了新手機的耐久性。"},{"en":"Customers often ask about the durability of outdoor furniture.","zh":"顧客常常詢問戶外家具的耐久性。"},{"en":"The factory tests the durability of every pair of boots.","zh":"工廠會測試每一雙靴子的耐久性。"}]},{"word":"durable","pos":"adj.","phonetic":"[ˈdjʊrəbl̩]","meaning":"耐用的","definition":"able to withstand wear; long-lasting","collocations":["durable material","durable goods","durable friendship"],"example":"This backpack is made of durable material.","exampleZh":"這個背包是用耐用的材質製成的。","synonyms":["sturdy","long-lasting"],"level":5,"theme":"性質與描述","examples":[{"en":"This backpack is made of durable material.","zh":"這個背包是用耐用的材質製成的。"},{"en":"These hiking boots are made from strong, durable material.","zh":"這雙登山靴是用堅固耐用的材料製成的。"},{"en":"Their durable friendship has lasted since elementary school.","zh":"他們牢固的友誼從小學一直維持到現在。"}]},{"word":"duration","pos":"n.","phonetic":"[djʊˈreʃən]","meaning":"期間；持續時間","definition":"the time during which something continues","collocations":["duration of the flight","short duration","entire duration"],"example":"The duration of the flight is about three hours.","exampleZh":"這趟飛行的時間大約是三個小時。","synonyms":["length","period"],"level":5,"theme":"時間與空間","examples":[{"en":"The duration of the flight is about three hours.","zh":"這趟飛行的時間大約是三個小時。"},{"en":"Please stay seated for the entire duration of the performance.","zh":"在整場表演期間，請保持坐在座位上。"},{"en":"The medicine's effect lasts only for a short duration.","zh":"這種藥的效果只持續很短的時間。"}]},{"word":"during","pos":"prep.","phonetic":"[ˈdjʊrɪŋ]","meaning":"在……期間","definition":"throughout the course of","collocations":["during the day","during vacation","during class"],"example":"Please turn off your phone during class.","exampleZh":"上課期間請把手機關機。","synonyms":["throughout"],"level":1,"theme":"時間與空間","examples":[{"en":"Please turn off your phone during class.","zh":"上課期間請把手機關機。"},{"en":"During the summer vacation, we traveled to the countryside.","zh":"在暑假期間，我們去了鄉下旅行。"},{"en":"He usually feels sleepy during the day after staying up late.","zh":"熬夜之後，他白天通常會覺得想睡。"}]},{"word":"dusk","pos":"n.","phonetic":"[dʌsk]","meaning":"黃昏","definition":"the time of day just before darkness","collocations":["at dusk","dusk till dawn"],"example":"We watched the birds return home at dusk.","exampleZh":"我們在黃昏時看著鳥兒回巢。","synonyms":["twilight"],"level":4,"theme":"天氣與季節","examples":[{"en":"We watched the birds return home at dusk.","zh":"我們在黃昏時看著鳥兒回巢。"},{"en":"The streetlights turn on automatically at dusk.","zh":"路燈在黃昏時會自動亮起。"},{"en":"The fishermen worked from dawn till dusk to fill their nets.","zh":"漁夫們從黎明工作到黃昏，好裝滿他們的漁網。"}]},{"word":"dust","pos":"n. / v.","phonetic":"[dʌst]","meaning":"灰塵；撢灰塵","definition":"fine dry powder of dirt","collocations":["dust off","layer of dust","dust the shelves"],"example":"There was a thick layer of dust on the shelf.","exampleZh":"架子上有一層厚厚的灰塵。","synonyms":["dirt","grime"],"level":2,"theme":"居家與生活","examples":[{"en":"There was a thick layer of dust on the shelf.","zh":"架子上有一層厚厚的灰塵。"},{"en":"She dusted the shelves carefully before placing the new books.","zh":"在擺上新書之前，她仔細地撢去書架上的灰塵。"},{"en":"He dusted off the old photo album he found in the attic.","zh":"他撢去在閣樓找到的舊相簿上的灰塵。"}]},{"word":"dusty","pos":"adj.","phonetic":"[ˈdʌsti]","meaning":"滿是灰塵的","definition":"covered with dust","collocations":["dusty road","dusty shelf","dusty attic"],"example":"The old books were dusty and yellowed.","exampleZh":"那些舊書滿是灰塵而且泛黃。","synonyms":[],"level":3,"theme":"性質與描述","examples":[{"en":"The old books were dusty and yellowed.","zh":"那些舊書滿是灰塵而且泛黃。"},{"en":"They drove along a dusty road toward the small village.","zh":"他們沿著一條塵土飛揚的道路開往那個小村莊。"},{"en":"The dusty attic was full of forgotten furniture and boxes.","zh":"滿是灰塵的閣樓堆滿了被遺忘的家具和箱子。"}]},{"word":"dutiful","pos":"adj.","phonetic":"[ˈdjutɪfəl]","meaning":"盡責的；孝順的","definition":"conscientious in performing duties","collocations":["dutiful son","dutiful employee"],"example":"He is a dutiful son who always helps his parents.","exampleZh":"他是個孝順的兒子，總是幫助父母。","synonyms":["obedient","responsible"],"level":6,"theme":"人物與家庭","examples":[{"en":"He is a dutiful son who always helps his parents.","zh":"他是個孝順的兒子，總是幫助父母。"},{"en":"As a dutiful employee, she never missed an important deadline.","zh":"身為一名盡責的員工，她從未錯過任何重要的截止期限。"},{"en":"The dutiful daughter visited her elderly parents every weekend.","zh":"這位孝順的女兒每個週末都去探望年邁的父母。"}]},{"word":"duty","pos":"n.","phonetic":"[ˈdjuti]","meaning":"責任；職責；關稅","definition":"a moral or legal obligation","collocations":["sense of duty","on duty","duty-free"],"example":"It is our duty to protect the environment.","exampleZh":"保護環境是我們的責任。","synonyms":["obligation","responsibility"],"level":3,"theme":"抽象概念","examples":[{"en":"It is our duty to protect the environment.","zh":"保護環境是我們的責任。"},{"en":"The nurse who is on duty tonight will check on you soon.","zh":"今晚值班的護士很快就會來看你。"},{"en":"We bought some perfume at the duty-free shop in the airport.","zh":"我們在機場的免稅店買了一些香水。"}]},{"word":"dwarf","pos":"n. / v.","phonetic":"[dwɔrf]","meaning":"侏儒；使顯得矮小","definition":"a very small person, animal, or thing; to make something seem small by comparison","collocations":["dwarf star","seven dwarfs","dwarf a building"],"example":"The tall building dwarfs everything around it.","exampleZh":"這棟高樓讓周圍的一切都顯得矮小。","synonyms":[],"level":5,"theme":"性質與描述","examples":[{"en":"The tall building dwarfs everything around it.","zh":"這棟高樓讓周圍的一切都顯得矮小。"},{"en":"In the famous tale, Snow White lives with seven dwarfs.","zh":"在那個著名的故事裡，白雪公主和七個小矮人住在一起。"},{"en":"The giant ship dwarfed the small fishing boats in the harbor.","zh":"那艘巨大的船讓港口裡的小漁船顯得格外渺小。"}]},{"word":"dwell","pos":"v.","phonetic":"[dwɛl]","meaning":"居住；細想","definition":"to live in a place, or to think about for a long time","collocations":["dwell on","dwell in","don't dwell on it"],"example":"Don't dwell on your past mistakes.","exampleZh":"別老想著你過去的錯誤。","synonyms":["reside","live"],"level":6,"theme":"居家與生活","examples":[{"en":"Don't dwell on your past mistakes.","zh":"別老想著你過去的錯誤。"},{"en":"Try not to dwell on the loss and focus on the future.","zh":"試著不要老是想著這次的失敗，把焦點放在未來吧。"},{"en":"Long ago, many people dwelt in caves for shelter.","zh":"很久以前，許多人住在洞穴裡以求庇護。"}]},{"word":"dwelling","pos":"n.","phonetic":"[ˈdwɛlɪŋ]","meaning":"住所；住宅","definition":"a house or place to live in","collocations":["human dwelling","modest dwelling"],"example":"The old farmhouse was their family dwelling for generations.","exampleZh":"那間老農舍是他們家族世代居住的地方。","synonyms":["residence","house"],"level":6,"theme":"居家與生活","examples":[{"en":"The old farmhouse was their family dwelling for generations.","zh":"那間老農舍是他們家族世代居住的地方。"},{"en":"The explorers discovered an ancient human dwelling in the cliff.","zh":"探險家在懸崖裡發現了一個古老的人類住所。"},{"en":"They lived happily in a modest dwelling by the sea.","zh":"他們在海邊一間簡樸的住宅裡幸福地生活著。"}]},{"word":"dwindle","pos":"v.","phonetic":"[ˈdwɪndl̩]","meaning":"逐漸減少","definition":"to gradually decrease in size or amount","collocations":["dwindle away","dwindling resources","dwindling population"],"example":"Their savings began to dwindle after he lost his job.","exampleZh":"他失業後，他們的存款開始逐漸減少。","synonyms":["decrease","shrink"],"level":6,"theme":"商業與金錢","examples":[{"en":"Their savings began to dwindle after he lost his job.","zh":"他失業後，他們的存款開始逐漸減少。"},{"en":"The town's population has been dwindling for many years.","zh":"這個小鎮的人口多年來一直在逐漸減少。"},{"en":"Their food supplies dwindled away during the long winter.","zh":"在漫長的冬天裡，他們的糧食逐漸消耗殆盡。"}]},{"word":"dye","pos":"n. / v.","phonetic":"[daɪ]","meaning":"染料；染色","definition":"a substance used to change the color of something","collocations":["hair dye","dye fabric","food dye"],"example":"She used a natural dye to color the fabric blue.","exampleZh":"她用天然染料把布染成藍色。","synonyms":["color","tint"],"level":4,"theme":"藝術與音樂","examples":[{"en":"She used a natural dye to color the fabric blue.","zh":"她用天然染料把布染成藍色。"},{"en":"She decided to dye her hair a bright shade of red.","zh":"她決定把頭髮染成鮮豔的紅色。"},{"en":"The bakery uses natural food dye to color the cakes.","zh":"這家麵包店用天然食用色素為蛋糕上色。"}]},{"word":"dying","pos":"adj. / v.","phonetic":"[ˈdaɪɪŋ]","meaning":"垂死的；臨終的","definition":"close to death","collocations":["dying wish","dying breath","dying patient"],"example":"The dying man whispered his last words.","exampleZh":"那位垂死的男子輕聲說出最後的話。","synonyms":[],"level":4,"theme":"身體與健康","examples":[{"en":"The dying man whispered his last words.","zh":"那位垂死的男子輕聲說出最後的話。"},{"en":"The old king's dying wish was to see his son once more.","zh":"老國王臨終的願望是再見他兒子一面。"},{"en":"Nurses do their best to comfort every dying patient.","zh":"護士們盡全力安慰每一位垂死的病人。"}]},{"word":"dynamic","pos":"adj.","phonetic":"[daɪˈnæmɪk]","meaning":"充滿活力的；動態的","definition":"characterized by constant change or activity","collocations":["dynamic personality","dynamic economy","dynamic duo"],"example":"She has a dynamic personality that inspires her team.","exampleZh":"她充滿活力的個性激勵了她的團隊。","synonyms":["energetic","active"],"level":5,"theme":"性質與描述","examples":[{"en":"She has a dynamic personality that inspires her team.","zh":"她充滿活力的個性激勵了她的團隊。"},{"en":"The city has a dynamic economy full of new businesses.","zh":"這座城市擁有充滿活力、新企業林立的經濟。"},{"en":"Their dynamic teamwork helped the group win the championship.","zh":"他們充滿活力的團隊合作幫助這個隊伍贏得了冠軍。"}]},{"word":"dynamite","pos":"n.","phonetic":"[ˈdaɪnəˌmaɪt]","meaning":"炸藥","definition":"a powerful explosive","collocations":["stick of dynamite","blow up with dynamite"],"example":"Workers used dynamite to clear the rocks.","exampleZh":"工人用炸藥清除岩石。","synonyms":["explosive"],"level":5,"theme":"科學與數學","examples":[{"en":"Workers used dynamite to clear the rocks.","zh":"工人用炸藥清除岩石。"},{"en":"The miners used dynamite to break through the solid rock.","zh":"礦工們用炸藥炸穿了堅硬的岩石。"},{"en":"A single stick of dynamite can cause a huge explosion.","zh":"單單一根炸藥就能造成巨大的爆炸。"}]},{"word":"dynamo","pos":"n.","phonetic":"[ˈdaɪnəˌmo]","meaning":"發電機；精力充沛的人","definition":"a machine that generates electricity, or an energetic person","collocations":["human dynamo","small dynamo"],"example":"She is a real dynamo, always full of energy.","exampleZh":"她真是個精力充沛的人，總是活力滿滿。","synonyms":["generator"],"level":6,"theme":"科學與數學","examples":[{"en":"She is a real dynamo, always full of energy.","zh":"她真是個精力充沛的人，總是活力滿滿。"},{"en":"A small dynamo on the bike powers its front light.","zh":"腳踏車上的小發電機為它的前燈供電。"},{"en":"Our new coach is a human dynamo who never seems to tire.","zh":"我們的新教練是個精力充沛的人，似乎從不感到疲倦。"}]},{"word":"dynasty","pos":"n.","phonetic":"[ˈdaɪnəsti]","meaning":"王朝","definition":"a line of hereditary rulers","collocations":["Tang Dynasty","ruling dynasty","dynasty collapse"],"example":"The Tang Dynasty was a golden age in Chinese history.","exampleZh":"唐朝是中國歷史上的黃金時代。","synonyms":[],"level":5,"theme":"社會與文化","examples":[{"en":"The Tang Dynasty was a golden age in Chinese history.","zh":"唐朝是中國歷史上的黃金時代。"},{"en":"The ruling dynasty collapsed after years of war and famine.","zh":"在多年的戰爭與飢荒後，這個統治王朝崩潰了。"},{"en":"Historians study how each dynasty shaped the nation's culture.","zh":"歷史學家研究每個王朝如何塑造這個國家的文化。"}]},{"word":"e-mail","pos":"n. / v.","phonetic":"[ˈiˌmel]","meaning":"電子郵件；發電子郵件","definition":"a message sent electronically over the internet","collocations":["send an e-mail","check e-mail","e-mail address"],"example":"Please e-mail me the report tonight.","exampleZh":"請今晚把報告寄電子郵件給我。","synonyms":[],"level":2,"theme":"科技與媒體","examples":[{"en":"Please e-mail me the report tonight.","zh":"請今晚把報告寄電子郵件給我。"},{"en":"Could you write down your e-mail address for me?","zh":"你可以把你的電子郵件地址寫給我嗎？"},{"en":"I check my e-mail every morning before I start work.","zh":"我每天早上開始工作前都會查看電子郵件。"}]},{"word":"each","pos":"adj. / pron.","phonetic":"[itʃ]","meaning":"每一個","definition":"used to refer to every individual thing or person in a group separately","collocations":["each one","each other","each of us"],"example":"Each student must bring a pencil.","exampleZh":"每個學生都必須帶一支鉛筆。","synonyms":["every"],"level":1,"theme":"抽象概念","examples":[{"en":"Each student must bring a pencil.","zh":"每個學生都必須帶一支鉛筆。"},{"en":"The twins always help each other with their homework.","zh":"這對雙胞胎總是互相幫忙做功課。"},{"en":"Each of us has a special role to play on the team.","zh":"我們每個人在隊裡都有一個特別的角色要扮演。"}]},{"word":"eager","pos":"adj.","phonetic":"[ˈigɚ]","meaning":"渴望的；熱切的","definition":"strongly wanting to do or have something","collocations":["eager to learn","eager for success","an eager student"],"example":"She is eager to learn new languages.","exampleZh":"她渴望學習新的語言。","synonyms":["keen","enthusiastic"],"level":3,"theme":"情緒與感受","examples":[{"en":"She is eager to learn new languages.","zh":"她渴望學習新的語言。"},{"en":"The eager student raised her hand to answer every question.","zh":"那位熱切的學生舉手回答每一個問題。"},{"en":"He was eager for success and practiced every single day.","zh":"他渴望成功，每一天都在練習。"}]},{"word":"ear","pos":"n.","phonetic":"[ɪr]","meaning":"耳朵","definition":"the organ used for hearing","collocations":["ear infection","play it by ear","have an ear for music"],"example":"He whispered the answer into my ear.","exampleZh":"他把答案輕聲說進我耳裡。","synonyms":[],"level":1,"theme":"身體與健康","examples":[{"en":"He whispered the answer into my ear.","zh":"他把答案輕聲說進我耳裡。"},{"en":"She has a good ear for music and learns songs quickly.","zh":"她對音樂很有天賦，學歌學得很快。"},{"en":"The doctor said my ear infection would heal within a week.","zh":"醫生說我的耳朵感染一週內就會痊癒。"}]},{"word":"early","pos":"adj. / adv.","phonetic":"[ˈɝlɪ]","meaning":"早的；提早地","definition":"before the usual or expected time","collocations":["early morning","get up early","early stage"],"example":"We arrived early to get good seats.","exampleZh":"我們提早到場以佔到好位子。","synonyms":["ahead of time"],"level":1,"theme":"時間與空間","examples":[{"en":"We arrived early to get good seats.","zh":"我們提早到場以佔到好位子。"},{"en":"The disease is much easier to treat at an early stage.","zh":"這種疾病在早期階段比較容易治療。"},{"en":"I like to get up early and jog before breakfast.","zh":"我喜歡早起，在吃早餐前慢跑。"}]},{"word":"earn","pos":"v.","phonetic":"[ɝn]","meaning":"賺得；獲得","definition":"to receive money or a reward for work done","collocations":["earn money","earn a living","earn respect"],"example":"He earns a good salary as an engineer.","exampleZh":"他當工程師賺取不錯的薪水。","synonyms":["gain","obtain"],"level":2,"theme":"商業與金錢","examples":[{"en":"He earns a good salary as an engineer.","zh":"他當工程師賺取不錯的薪水。"},{"en":"She worked hard to earn the respect of her colleagues.","zh":"她努力工作以贏得同事們的尊重。"},{"en":"Many students take part-time jobs to earn extra money.","zh":"許多學生打工來賺取額外的錢。"}]},{"word":"earth","pos":"n.","phonetic":"[ɝθ]","meaning":"地球；泥土","definition":"the planet on which we live","collocations":["planet Earth","on earth","the surface of the earth"],"example":"The Earth revolves around the sun.","exampleZh":"地球繞著太陽公轉。","synonyms":["world","globe"],"level":1,"theme":"自然與環境","examples":[{"en":"The Earth revolves around the sun.","zh":"地球繞著太陽公轉。"},{"en":"We must work together to protect our planet Earth.","zh":"我們必須共同努力保護我們的地球。"},{"en":"The farmer dug into the soft, dark earth to plant seeds.","zh":"農夫在鬆軟的黑土裡挖洞來播種。"}]},{"word":"earthquake","pos":"n.","phonetic":"[ˈɝθˌkwek]","meaning":"地震","definition":"a sudden violent shaking of the ground","collocations":["a strong earthquake","earthquake damage","survive an earthquake"],"example":"The earthquake destroyed many buildings.","exampleZh":"這場地震摧毀了許多建築物。","synonyms":["tremor"],"level":2,"theme":"自然與環境","examples":[{"en":"The earthquake destroyed many buildings.","zh":"這場地震摧毀了許多建築物。"},{"en":"A strong earthquake shook the whole city early this morning.","zh":"今天一大早，一場強烈的地震撼動了整座城市。"},{"en":"Rescue teams searched for survivors after the earthquake damage.","zh":"在地震造成損害之後，救援隊搜尋著倖存者。"}]},{"word":"ease","pos":"n. / v.","phonetic":"[iz]","meaning":"輕鬆；容易；減輕","definition":"the state of being comfortable or without difficulty; to make less severe","collocations":["with ease","ease the pain","at ease"],"example":"She solved the puzzle with ease.","exampleZh":"她輕鬆地解開了這個謎題。","synonyms":["comfort","relieve"],"level":3,"theme":"性質與描述","examples":[{"en":"She solved the puzzle with ease.","zh":"她輕鬆地解開了這個謎題。"},{"en":"The medicine helped to ease the pain in his knee.","zh":"這種藥有助於減輕他膝蓋的疼痛。"},{"en":"Her kind words put the nervous new student at ease.","zh":"她親切的話語讓緊張的新同學放鬆了下來。"}]},{"word":"easily","pos":"adv.","phonetic":"[ˈizlɪ]","meaning":"容易地；輕易地","definition":"without difficulty","collocations":["win easily","easily accessible","easily forgotten"],"example":"He easily passed the exam.","exampleZh":"他輕鬆地通過了考試。","synonyms":["effortlessly"],"level":2,"theme":"性質與描述","examples":[{"en":"He easily passed the exam.","zh":"他輕鬆地通過了考試。"},{"en":"The library is easily accessible by bus or on foot.","zh":"這座圖書館搭公車或步行都很容易到達。"},{"en":"With practice, these words can be easily remembered.","zh":"透過練習，這些單字可以輕易地被記住。"}]},{"word":"east","pos":"n. / adj. / adv.","phonetic":"[ist]","meaning":"東方；東方的","definition":"the direction from which the sun rises","collocations":["the Far East","face east","east coast"],"example":"The sun rises in the east.","exampleZh":"太陽從東方升起。","synonyms":[],"level":1,"theme":"時間與空間","examples":[{"en":"The sun rises in the east.","zh":"太陽從東方升起。"},{"en":"Our new house faces east, so we enjoy the morning sun.","zh":"我們的新家朝東，所以我們能享受早晨的陽光。"},{"en":"They spent their holiday exploring the beautiful east coast.","zh":"他們在美麗的東海岸探索，度過假期。"}]},{"word":"eastern","pos":"adj.","phonetic":"[ˈistɚn]","meaning":"東方的；東部的","definition":"located in or belonging to the east","collocations":["eastern Asia","eastern culture","eastern side"],"example":"They visited several eastern countries.","exampleZh":"他們造訪了幾個東方國家。","synonyms":[],"level":2,"theme":"時間與空間","examples":[{"en":"They visited several eastern countries.","zh":"他們造訪了幾個東方國家。"},{"en":"The temple stands on the eastern side of the mountain.","zh":"這座寺廟坐落在山的東側。"},{"en":"Many eastern cultures value respect for one's elders.","zh":"許多東方文化重視對長輩的尊敬。"}]},{"word":"easy","pos":"adj.","phonetic":"[ˈizɪ]","meaning":"容易的；輕鬆的","definition":"not difficult; requiring little effort","collocations":["an easy task","take it easy","easy to understand"],"example":"This math problem is easy for me.","exampleZh":"這道數學題對我來說很簡單。","synonyms":["simple"],"level":1,"theme":"性質與描述","examples":[{"en":"This math problem is easy for me.","zh":"這道數學題對我來說很簡單。"},{"en":"The teacher explained the rules in a way that was easy to understand.","zh":"老師用一種容易理解的方式解釋了規則。"},{"en":"You have worked hard all week, so take it easy today.","zh":"你整週都很努力，所以今天就放輕鬆吧。"}]},{"word":"eat","pos":"v.","phonetic":"[it]","meaning":"吃","definition":"to put food into the mouth and swallow it","collocations":["eat breakfast","eat out","eat healthily"],"example":"We usually eat dinner at seven.","exampleZh":"我們通常七點吃晚餐。","synonyms":["consume"],"level":1,"theme":"食物與烹飪","examples":[{"en":"We usually eat dinner at seven.","zh":"我們通常七點吃晚餐。"},{"en":"My family decided to eat out to celebrate my birthday.","zh":"我家決定出去外面吃飯來慶祝我的生日。"},{"en":"If you eat healthily, you will have more energy each day.","zh":"如果你吃得健康，每天都會更有精神。"}]},{"word":"echo","pos":"n. / v.","phonetic":"[ˈɛko]","meaning":"回聲；回響","definition":"a sound that is reflected off a surface and heard again","collocations":["hear an echo","echo through the valley","voices echoed"],"example":"Her voice echoed in the empty hall.","exampleZh":"她的聲音在空蕩的大廳裡回響。","synonyms":["reverberate"],"level":3,"theme":"自然與環境","examples":[{"en":"Her voice echoed in the empty hall.","zh":"她的聲音在空蕩的大廳裡回響。"},{"en":"We shouted loudly and heard the echo bounce off the mountains.","zh":"我們大聲喊叫，聽見回聲從山間反彈回來。"},{"en":"The children's laughter echoed through the empty gym.","zh":"孩子們的笑聲在空蕩蕩的體育館裡回響。"}]},{"word":"economic","pos":"adj.","phonetic":"[ˌikəˈnɑmɪk]","meaning":"經濟的","definition":"relating to trade, industry, and money","collocations":["economic growth","economic crisis","economic policy"],"example":"The country is facing an economic crisis.","exampleZh":"這個國家正面臨經濟危機。","synonyms":["financial"],"level":4,"theme":"商業與金錢","examples":[{"en":"The country is facing an economic crisis.","zh":"這個國家正面臨經濟危機。"},{"en":"Steady economic growth helped many families escape poverty.","zh":"穩定的經濟成長幫助許多家庭脫離貧困。"},{"en":"The government announced a new economic policy this week.","zh":"政府在本週宣布了一項新的經濟政策。"}]},{"word":"economical","pos":"adj.","phonetic":"[ˌikəˈnɑmɪkl]","meaning":"節約的；經濟實惠的","definition":"giving good value for the amount of money spent","collocations":["an economical car","economical use of resources","economical way"],"example":"This car is very economical to run.","exampleZh":"這輛車開起來很省油。","synonyms":["thrifty","efficient"],"level":5,"theme":"商業與金錢","examples":[{"en":"This car is very economical to run.","zh":"這輛車開起來很省油。"},{"en":"Cooking at home is a more economical way to eat well.","zh":"在家煮飯是吃得好又更經濟實惠的方式。"},{"en":"The factory found an economical use of its leftover materials.","zh":"工廠找到了一種節約利用剩餘材料的方法。"}]},{"word":"economics","pos":"n.","phonetic":"[ˌikəˈnɑmɪks]","meaning":"經濟學","definition":"the study of how goods and services are produced and used","collocations":["study economics","economics major","basic economics"],"example":"She is studying economics at university.","exampleZh":"她在大學主修經濟學。","synonyms":[],"level":5,"theme":"教育與學習","examples":[{"en":"She is studying economics at university.","zh":"她在大學主修經濟學。"},{"en":"Basic economics helps us understand how prices are set.","zh":"基礎經濟學幫助我們了解價格是如何訂定的。"},{"en":"As an economics major, he reads the financial news daily.","zh":"身為經濟學主修的學生，他每天都閱讀財經新聞。"}]},{"word":"economy","pos":"n.","phonetic":"[ɪˈkɑnəmɪ]","meaning":"經濟；經濟體系","definition":"the wealth and resources of a country or region","collocations":["a strong economy","global economy","economy grows"],"example":"The nation's economy is growing rapidly.","exampleZh":"這個國家的經濟正快速成長。","synonyms":[],"level":4,"theme":"商業與金錢","examples":[{"en":"The nation's economy is growing rapidly.","zh":"這個國家的經濟正快速成長。"},{"en":"A strong economy usually creates more jobs for young people.","zh":"強健的經濟通常會為年輕人創造更多工作機會。"},{"en":"Events in one country can affect the whole global economy.","zh":"一個國家發生的事件可能影響整個全球經濟。"}]},{"word":"edge","pos":"n.","phonetic":"[ɛdʒ]","meaning":"邊緣；優勢","definition":"the outside limit of an object or area","collocations":["the edge of the table","on the edge","have an edge over"],"example":"He stood at the edge of the cliff.","exampleZh":"他站在懸崖邊緣。","synonyms":["border","rim"],"level":3,"theme":"時間與空間","examples":[{"en":"He stood at the edge of the cliff.","zh":"他站在懸崖邊緣。"},{"en":"Her fluent English gives her an edge over other job seekers.","zh":"她流利的英文讓她比其他求職者更有優勢。"},{"en":"Be careful not to leave the cup on the edge of the table.","zh":"小心別把杯子放在桌子邊緣。"}]},{"word":"edible","pos":"adj.","phonetic":"[ˈɛdəbḷ]","meaning":"可食用的","definition":"fit to be eaten","collocations":["edible plants","edible mushrooms","not edible"],"example":"Not all wild mushrooms are edible.","exampleZh":"並非所有野生蘑菇都可以食用。","synonyms":[],"level":5,"theme":"食物與烹飪","examples":[{"en":"Not all wild mushrooms are edible.","zh":"並非所有野生蘑菇都可以食用。"},{"en":"The guide showed us which wild plants are safely edible.","zh":"嚮導告訴我們哪些野生植物可以安全食用。"},{"en":"These bright red berries look pretty but are not edible.","zh":"這些鮮紅的漿果看起來很漂亮，但不能食用。"}]},{"word":"edit","pos":"v.","phonetic":"[ˈɛdɪt]","meaning":"編輯；校訂","definition":"to prepare written material for publication by correcting errors","collocations":["edit a document","edit a video","edit carefully"],"example":"She edited the article before it was published.","exampleZh":"她在文章發表前先進行了編輯。","synonyms":["revise"],"level":4,"theme":"科技與媒體","examples":[{"en":"She edited the article before it was published.","zh":"她在文章發表前先進行了編輯。"},{"en":"He spent the afternoon learning how to edit a video.","zh":"他花了一個下午學習如何剪輯影片。"},{"en":"Please edit the document carefully before printing it.","zh":"列印之前，請仔細校訂這份文件。"}]},{"word":"edition","pos":"n.","phonetic":"[ɪˈdɪʃən]","meaning":"版本；版次","definition":"a particular version of a printed text","collocations":["first edition","special edition","the latest edition"],"example":"This is the second edition of the textbook.","exampleZh":"這是這本教科書的第二版。","synonyms":["version"],"level":4,"theme":"科技與媒體","examples":[{"en":"This is the second edition of the textbook.","zh":"這是這本教科書的第二版。"},{"en":"Collectors pay a lot of money for a rare first edition.","zh":"收藏家願意花大錢購買稀有的初版書。"},{"en":"The latest edition of the dictionary includes many new words.","zh":"這本字典的最新版本收錄了許多新詞。"}]},{"word":"editor","pos":"n.","phonetic":"[ˈɛdɪtɚ]","meaning":"編輯；編輯者","definition":"a person who edits texts, films, or newspapers","collocations":["chief editor","newspaper editor","video editor"],"example":"She works as an editor for a magazine.","exampleZh":"她在一本雜誌擔任編輯。","synonyms":[],"level":4,"theme":"工作與職業","examples":[{"en":"She works as an editor for a magazine.","zh":"她在一本雜誌擔任編輯。"},{"en":"The chief editor decided which stories appeared on the front page.","zh":"總編輯決定哪些報導出現在頭版。"},{"en":"As a video editor, she cut the film down to two hours.","zh":"身為影片剪輯師，她把片子剪到只剩兩個小時。"}]},{"word":"educate","pos":"v.","phonetic":"[ˈɛdʒʊˌket]","meaning":"教育；培養","definition":"to give intellectual, moral, and social instruction to someone","collocations":["educate children","educate the public","well educated"],"example":"Schools aim to educate students for the future.","exampleZh":"學校旨在教育學生為未來做好準備。","synonyms":["teach","instruct"],"level":3,"theme":"教育與學習","examples":[{"en":"Schools aim to educate students for the future.","zh":"學校旨在教育學生為未來做好準備。"},{"en":"The campaign aims to educate the public about healthy eating.","zh":"這項活動旨在教育大眾有關健康飲食的知識。"},{"en":"Good parents try to educate their children with patience.","zh":"好的父母會試著以耐心來教育他們的孩子。"}]},{"word":"education","pos":"n.","phonetic":"[ˌɛdʒʊˈkeʃən]","meaning":"教育","definition":"the process of teaching or learning","collocations":["higher education","receive education","education system"],"example":"Education is important for everyone.","exampleZh":"教育對每個人都很重要。","synonyms":["schooling"],"level":2,"theme":"教育與學習","examples":[{"en":"Education is important for everyone.","zh":"教育對每個人都很重要。"},{"en":"Many parents save money so their children can receive higher education.","zh":"許多父母存錢，好讓孩子能接受高等教育。"},{"en":"A good education system benefits the whole country.","zh":"良好的教育體系對整個國家都有益。"}]},{"word":"educational","pos":"adj.","phonetic":"[ˌɛdʒʊˈkeʃənḷ]","meaning":"教育的；有教育意義的","definition":"relating to education, or providing knowledge","collocations":["educational program","educational toy","educational background"],"example":"The museum offers many educational activities.","exampleZh":"這間博物館提供許多具教育意義的活動。","synonyms":[],"level":3,"theme":"教育與學習","examples":[{"en":"The museum offers many educational activities.","zh":"這間博物館提供許多具教育意義的活動。"},{"en":"This television channel shows many educational programs for kids.","zh":"這個電視頻道播放許多給孩子看的教育性節目。"},{"en":"They bought an educational toy to help their son learn numbers.","zh":"他們買了一個益智玩具來幫助兒子學習數字。"}]},{"word":"effect","pos":"n.","phonetic":"[ɪˈfɛkt]","meaning":"效果；影響","definition":"a change that is a result of an action","collocations":["side effect","have an effect on","take effect"],"example":"The medicine had an immediate effect.","exampleZh":"這藥立刻產生了效果。","synonyms":["result","impact"],"level":3,"theme":"抽象概念","examples":[{"en":"The medicine had an immediate effect.","zh":"這藥立刻產生了效果。"},{"en":"The new rule will take effect at the start of next month.","zh":"這項新規定將在下個月初開始生效。"},{"en":"Too much screen time can have a bad effect on your eyes.","zh":"看螢幕的時間太長可能對你的眼睛有不良影響。"}]},{"word":"effective","pos":"adj.","phonetic":"[ɪˈfɛktɪv]","meaning":"有效的","definition":"successful in producing a desired result","collocations":["effective method","cost-effective","highly effective"],"example":"This is an effective way to learn vocabulary.","exampleZh":"這是一個學習單字的有效方法。","synonyms":["efficient"],"level":4,"theme":"性質與描述","examples":[{"en":"This is an effective way to learn vocabulary.","zh":"這是一個學習單字的有效方法。"},{"en":"Reading aloud is a highly effective way to improve pronunciation.","zh":"朗讀是改善發音非常有效的方法。"},{"en":"Riding a bike is a cost-effective way to get around town.","zh":"騎腳踏車是在城裡到處移動既省錢又有效的方式。"}]},{"word":"efficiency","pos":"n.","phonetic":"[ɪˈfɪʃənsɪ]","meaning":"效率","definition":"the ability to do something well without wasting time or energy","collocations":["increase efficiency","work efficiency","energy efficiency"],"example":"The new system improved office efficiency.","exampleZh":"新系統提升了辦公室的效率。","synonyms":[],"level":5,"theme":"工作與職業","examples":[{"en":"The new system improved office efficiency.","zh":"新系統提升了辦公室的效率。"},{"en":"Better tools greatly increased the workers' efficiency.","zh":"更好的工具大大提高了工人的效率。"},{"en":"The new refrigerator is praised for its high energy efficiency.","zh":"這台新冰箱因其高能源效率而受到好評。"}]},{"word":"efficient","pos":"adj.","phonetic":"[ɪˈfɪʃənt]","meaning":"有效率的","definition":"achieving maximum productivity with minimum wasted effort","collocations":["an efficient worker","efficient use of time","fuel efficient"],"example":"She is an efficient manager.","exampleZh":"她是一位有效率的經理。","synonyms":["productive"],"level":5,"theme":"性質與描述","examples":[{"en":"She is an efficient manager.","zh":"她是一位有效率的經理。"},{"en":"Making a to-do list is an efficient use of your time.","zh":"列一張待辦清單是有效率地運用時間的方法。"},{"en":"This small car is very fuel efficient on long trips.","zh":"這輛小車在長途旅行時非常省油。"}]},{"word":"effort","pos":"n.","phonetic":"[ˈɛfɚt]","meaning":"努力","definition":"a vigorous or determined attempt","collocations":["make an effort","great effort","effort to improve"],"example":"He made a great effort to finish the project.","exampleZh":"他非常努力完成了這個專案。","synonyms":["endeavor"],"level":2,"theme":"抽象概念","examples":[{"en":"He made a great effort to finish the project.","zh":"他非常努力完成了這個專案。"},{"en":"She made a real effort to improve her spoken English.","zh":"她真的很努力去改善她的英語口說。"},{"en":"With great effort, the team finally reached the mountain top.","zh":"經過極大的努力，這支隊伍終於登上了山頂。"}]},{"word":"egg","pos":"n.","phonetic":"[ɛg]","meaning":"蛋；卵","definition":"an oval object produced by a female bird, reptile, or fish","collocations":["fried egg","boiled egg","egg yolk"],"example":"She fried an egg for breakfast.","exampleZh":"她煎了一顆蛋當早餐。","synonyms":[],"level":1,"theme":"食物與烹飪","examples":[{"en":"She fried an egg for breakfast.","zh":"她煎了一顆蛋當早餐。"},{"en":"He likes a boiled egg and toast for breakfast.","zh":"他早餐喜歡吃一顆水煮蛋配吐司。"},{"en":"The recipe asks you to separate the egg yolk from the white.","zh":"這份食譜要你把蛋黃和蛋白分開。"}]},{"word":"eight","pos":"n. / adj.","phonetic":"[et]","meaning":"八","definition":"the number 8","collocations":["eight o'clock","eight years old","group of eight"],"example":"There are eight students in the club.","exampleZh":"社團裡有八個學生。","synonyms":[],"level":1,"theme":"科學與數學","examples":[{"en":"There are eight students in the club.","zh":"社團裡有八個學生。"},{"en":"The train leaves at eight o'clock every morning.","zh":"這班火車每天早上八點發車。"},{"en":"A group of eight friends went camping by the lake.","zh":"一群八個朋友去湖邊露營。"}]},{"word":"eighteen","pos":"n. / adj.","phonetic":"[ˌeˈtin]","meaning":"十八","definition":"the number 18","collocations":["eighteen years old","turn eighteen"],"example":"She turned eighteen last week.","exampleZh":"她上禮拜滿十八歲了。","synonyms":[],"level":1,"theme":"科學與數學","examples":[{"en":"She turned eighteen last week.","zh":"她上禮拜滿十八歲了。"},{"en":"In many countries, you can vote once you turn eighteen.","zh":"在許多國家，你一滿十八歲就可以投票。"},{"en":"There are eighteen players on the school's baseball team.","zh":"學校的棒球隊有十八名球員。"}]},{"word":"eighth","pos":"n. / adj.","phonetic":"[etθ]","meaning":"第八","definition":"coming after seventh in order","collocations":["eighth grade","the eighth floor"],"example":"He is in eighth grade this year.","exampleZh":"他今年讀國二。","synonyms":[],"level":1,"theme":"科學與數學","examples":[{"en":"He is in eighth grade this year.","zh":"他今年讀國二。"},{"en":"Her office is on the eighth floor of the tall building.","zh":"她的辦公室在那棟高樓的八樓。"},{"en":"August is the eighth month of the year.","zh":"八月是一年中的第八個月。"}]},{"word":"eighty","pos":"n. / adj.","phonetic":"[ˈetɪ]","meaning":"八十","definition":"the number 80","collocations":["eighty years old","eighty percent"],"example":"My grandfather is eighty years old.","exampleZh":"我祖父八十歲了。","synonyms":[],"level":1,"theme":"科學與數學","examples":[{"en":"My grandfather is eighty years old.","zh":"我祖父八十歲了。"},{"en":"About eighty percent of the students passed the difficult test.","zh":"大約有百分之八十的學生通過了那場困難的考試。"},{"en":"The old bridge is more than eighty years old.","zh":"這座舊橋已經有八十多年的歷史了。"}]},{"word":"either","pos":"pron. / adj. / conj. / adv.","phonetic":"[ˈiðɚ]","meaning":"（兩者中）任一；也（不）","definition":"used to refer to one of two possibilities","collocations":["either way","either...or","not either"],"example":"You can choose either color.","exampleZh":"你可以選擇任一顏色。","synonyms":[],"level":2,"theme":"抽象概念","examples":[{"en":"You can choose either color.","zh":"你可以選擇任一顏色。"},{"en":"You can take either the bus or the train to the museum.","zh":"你可以搭公車或火車去博物館，兩者皆可。"},{"en":"I don't like coffee, and my sister doesn't either.","zh":"我不喜歡咖啡，我妹妹也不喜歡。"}]},{"word":"elaborate","pos":"adj. / v.","phonetic":"[ɪˈlæbərɪt]","meaning":"精心製作的；詳盡闡述","definition":"involving many careful details; to explain in more detail","collocations":["elaborate plan","elaborate design","elaborate on"],"example":"Could you elaborate on your idea?","exampleZh":"你能詳細說明一下你的想法嗎？","synonyms":["detailed","expand"],"level":6,"theme":"抽象概念","examples":[{"en":"Could you elaborate on your idea?","zh":"你能詳細說明一下你的想法嗎？"},{"en":"The wedding cake had an elaborate design of sugar flowers.","zh":"那個結婚蛋糕有著精緻的糖花設計。"},{"en":"The teacher asked the student to elaborate on his answer.","zh":"老師要求那位學生對他的答案做更詳細的說明。"}]},{"word":"elastic","pos":"adj. / n.","phonetic":"[ɪˈlæstɪk]","meaning":"有彈性的；橡皮筋","definition":"able to stretch and return to its original shape","collocations":["elastic band","elastic material","elastic waistband"],"example":"The elastic band snapped when she stretched it.","exampleZh":"她拉伸時橡皮筋斷了。","synonyms":["flexible"],"level":5,"theme":"性質與描述","examples":[{"en":"The elastic band snapped when she stretched it.","zh":"她拉伸時橡皮筋斷了。"},{"en":"These sports pants have an elastic waistband for comfort.","zh":"這件運動褲有彈性腰帶，穿起來很舒適。"},{"en":"She tied her hair back with a small elastic band.","zh":"她用一條小橡皮筋把頭髮綁了起來。"}]},{"word":"elbow","pos":"n.","phonetic":"[ˈɛlbo]","meaning":"手肘","definition":"the joint between the upper and lower parts of the arm","collocations":["elbow pain","bend your elbow","elbow room"],"example":"He hurt his elbow while playing basketball.","exampleZh":"他打籃球時傷到了手肘。","synonyms":[],"level":2,"theme":"身體與健康","examples":[{"en":"He hurt his elbow while playing basketball.","zh":"他打籃球時傷到了手肘。"},{"en":"The bus was so crowded that there was no elbow room.","zh":"公車太擁擠了，連轉身活動的空間都沒有。"},{"en":"Slowly bend your elbow and lift the weight upward.","zh":"慢慢彎曲你的手肘，把重物往上舉。"}]},{"word":"elder","pos":"adj. / n.","phonetic":"[ˈɛldɚ]","meaning":"年長的；長輩","definition":"older than another person, especially in a family","collocations":["elder brother","respect your elders","village elder"],"example":"His elder sister works as a nurse.","exampleZh":"他的姊姊是護士。","synonyms":["older"],"level":3,"theme":"人物與家庭","examples":[{"en":"His elder sister works as a nurse.","zh":"他的姊姊是護士。"},{"en":"In our culture, children are taught to respect their elders.","zh":"在我們的文化中，孩子們被教導要尊敬長輩。"},{"en":"My elder brother always looks after me when our parents are out.","zh":"父母外出時，我哥哥總是照顧我。"}]},{"word":"elderly","pos":"adj.","phonetic":"[ˈɛldɚlɪ]","meaning":"年長的；老年的","definition":"used to describe people who are old, especially in a polite way","collocations":["elderly people","care for the elderly","an elderly couple"],"example":"We should take good care of elderly people.","exampleZh":"我們應該好好照顧年長者。","synonyms":["aged"],"level":3,"theme":"人物與家庭","examples":[{"en":"We should take good care of elderly people.","zh":"我們應該好好照顧年長者。"},{"en":"Volunteers visit the elderly couple next door every weekend.","zh":"志工每個週末都去探望隔壁的老夫婦。"},{"en":"The city built more benches so elderly people can rest.","zh":"城市增設了更多長椅，好讓年長者可以休息。"}]},{"word":"elect","pos":"v.","phonetic":"[ɪˈlɛkt]","meaning":"選舉；選出","definition":"to choose someone by voting","collocations":["elect a president","newly elected","elect officials"],"example":"The citizens elected a new mayor.","exampleZh":"市民們選出了新市長。","synonyms":["vote for"],"level":4,"theme":"政治與法律","examples":[{"en":"The citizens elected a new mayor.","zh":"市民們選出了新市長。"},{"en":"The club members will elect a new leader next week.","zh":"社團成員下週將選出一位新的領導人。"},{"en":"The newly elected mayor promised to build more parks.","zh":"新當選的市長承諾要興建更多公園。"}]},{"word":"election","pos":"n.","phonetic":"[ɪˈlɛkʃən]","meaning":"選舉","definition":"a formal process of choosing a person for a position by voting","collocations":["win an election","presidential election","hold an election"],"example":"The presidential election will be held next month.","exampleZh":"總統選舉將於下個月舉行。","synonyms":["vote"],"level":4,"theme":"政治與法律","examples":[{"en":"The presidential election will be held next month.","zh":"總統選舉將於下個月舉行。"},{"en":"Thousands of people voted in the local election yesterday.","zh":"昨天有數千人參與了地方選舉的投票。"},{"en":"To win the election, the candidate visited many small towns.","zh":"為了贏得選舉，這位候選人拜訪了許多小城鎮。"}]},{"word":"electric","pos":"adj.","phonetic":"[ɪˈlɛktrɪk]","meaning":"電動的；電的","definition":"powered by electricity","collocations":["electric car","electric guitar","electric shock"],"example":"They bought a new electric car.","exampleZh":"他們買了一輛新的電動車。","synonyms":[],"level":3,"theme":"科技與媒體","examples":[{"en":"They bought a new electric car.","zh":"他們買了一輛新的電動車。"},{"en":"He learned to play the electric guitar in a rock band.","zh":"他在一個搖滾樂團裡學會了彈電吉他。"},{"en":"Be careful with wet hands to avoid an electric shock.","zh":"手濕的時候要小心，以免觸電。"}]},{"word":"electrical","pos":"adj.","phonetic":"[ɪˈlɛktrɪkḷ]","meaning":"與電有關的；電力的","definition":"relating to or concerned with electricity","collocations":["electrical engineer","electrical appliance","electrical fault"],"example":"He studies electrical engineering.","exampleZh":"他主修電機工程。","synonyms":[],"level":4,"theme":"科技與媒體","examples":[{"en":"He studies electrical engineering.","zh":"他主修電機工程。"},{"en":"An electrical fault caused the lights to go out suddenly.","zh":"電路故障導致燈光突然熄滅。"},{"en":"Never use an electrical appliance near the bathtub.","zh":"絕對不要在浴缸附近使用電器用品。"}]},{"word":"electricity","pos":"n.","phonetic":"[ɪˌlɛkˈtrɪsətɪ]","meaning":"電力","definition":"a form of energy used for lighting and power","collocations":["generate electricity","electricity bill","supply electricity"],"example":"The storm cut off the electricity in the village.","exampleZh":"暴風雨切斷了村莊的電力。","synonyms":["power"],"level":3,"theme":"科技與媒體","examples":[{"en":"The storm cut off the electricity in the village.","zh":"暴風雨切斷了村莊的電力。"},{"en":"Solar panels on the roof help generate clean electricity.","zh":"屋頂上的太陽能板有助於產生乾淨的電力。"},{"en":"Turning off unused lights lowers our monthly electricity bill.","zh":"關掉不用的燈可以降低我們每月的電費。"}]},{"word":"electronic","pos":"adj.","phonetic":"[ɪˌlɛkˈtrɑnɪk]","meaning":"電子的","definition":"having many small parts that control an electrical current, such as a computer","collocations":["electronic device","electronic mail","electronic music"],"example":"She sells electronic devices online.","exampleZh":"她在網路上販售電子產品。","synonyms":[],"level":4,"theme":"科技與媒體","examples":[{"en":"She sells electronic devices online.","zh":"她在網路上販售電子產品。"},{"en":"Please switch off all electronic devices during the exam.","zh":"考試期間，請關閉所有電子設備。"},{"en":"The young DJ loves creating electronic music at home.","zh":"這位年輕的DJ喜歡在家創作電子音樂。"}]},{"word":"elegant","pos":"adj.","phonetic":"[ˈɛləgənt]","meaning":"優雅的","definition":"graceful and stylish in appearance or manner","collocations":["elegant dress","elegant style","elegant woman"],"example":"She wore an elegant dress to the party.","exampleZh":"她穿了一件優雅的禮服參加派對。","synonyms":["graceful"],"level":5,"theme":"服裝與外表","examples":[{"en":"She wore an elegant dress to the party.","zh":"她穿了一件優雅的禮服參加派對。"},{"en":"The furniture in the hotel lobby has a simple, elegant style.","zh":"飯店大廳的家具具有簡約而優雅的風格。"},{"en":"The elegant woman moved gracefully across the ballroom.","zh":"那位優雅的女士在舞廳中優美地移動著。"}]},{"word":"element","pos":"n.","phonetic":"[ˈɛləmənt]","meaning":"要素；元素","definition":"a basic part or feature of something","collocations":["key element","chemical element","essential element"],"example":"Trust is an important element of friendship.","exampleZh":"信任是友誼中重要的要素。","synonyms":["component"],"level":4,"theme":"科學與數學","examples":[{"en":"Trust is an important element of friendship.","zh":"信任是友誼中重要的要素。"},{"en":"Good communication is a key element of successful teamwork.","zh":"良好的溝通是成功團隊合作的關鍵要素。"},{"en":"Oxygen is a chemical element that all animals need to live.","zh":"氧是一種所有動物生存都需要的化學元素。"}]},{"word":"elementary","pos":"adj.","phonetic":"[ˌɛləˈmɛntərɪ]","meaning":"基本的；初級的","definition":"relating to the basic elements of a subject; introductory","collocations":["elementary school","elementary level","elementary knowledge"],"example":"My sister goes to elementary school.","exampleZh":"我妹妹讀小學。","synonyms":["basic"],"level":3,"theme":"教育與學習","examples":[{"en":"My sister goes to elementary school.","zh":"我妹妹讀小學。"},{"en":"Students at the elementary level first learn simple greetings.","zh":"初級程度的學生首先學習簡單的問候語。"},{"en":"A basic first-aid course teaches elementary knowledge of safety.","zh":"基礎急救課程教授關於安全的基本知識。"}]},{"word":"elephant","pos":"n.","phonetic":"[ˈɛləfənt]","meaning":"大象","definition":"a very large animal with a long trunk and big ears","collocations":["baby elephant","herd of elephants","elephant tusk"],"example":"The elephant used its trunk to grab food.","exampleZh":"大象用牠的鼻子抓取食物。","synonyms":[],"level":1,"theme":"動物與植物","examples":[{"en":"The elephant used its trunk to grab food.","zh":"大象用牠的鼻子抓取食物。"},{"en":"A whole herd of elephants crossed the river together.","zh":"一整群大象一起渡過了河。"},{"en":"The playful baby elephant sprayed water with its trunk.","zh":"頑皮的小象用鼻子噴水。"}]},{"word":"elevator","pos":"n.","phonetic":"[ˈɛləˌvetɚ]","meaning":"電梯","definition":"a machine that carries people or goods between floors of a building","collocations":["take the elevator","elevator door","elevator button"],"example":"We took the elevator to the tenth floor.","exampleZh":"我們搭電梯到十樓。","synonyms":["lift"],"level":2,"theme":"居家與生活","examples":[{"en":"We took the elevator to the tenth floor.","zh":"我們搭電梯到十樓。"},{"en":"The elevator button lit up as we waited on the ground floor.","zh":"當我們在一樓等待時，電梯按鈕亮了起來。"},{"en":"The elevator door opened slowly, and everyone stepped inside.","zh":"電梯門緩緩打開，大家都走了進去。"}]},{"word":"eleven","pos":"n. / adj.","phonetic":"[ɪˈlɛvən]","meaning":"十一","definition":"the number 11","collocations":["eleven o'clock","eleven years old"],"example":"There are eleven players on a soccer team.","exampleZh":"一支足球隊有十一位球員。","synonyms":[],"level":1,"theme":"科學與數學","examples":[{"en":"There are eleven players on a soccer team.","zh":"一支足球隊有十一位球員。"},{"en":"My little brother turned eleven years old last weekend.","zh":"我弟弟上週末滿十一歲了。"},{"en":"The library closes at eleven o'clock every night.","zh":"圖書館每天晚上十一點關門。"}]},{"word":"eliminate","pos":"v.","phonetic":"[ɪˈlɪməˌnet]","meaning":"消除；淘汰","definition":"to completely remove or get rid of something","collocations":["eliminate errors","eliminate poverty","be eliminated from"],"example":"The team was eliminated in the first round.","exampleZh":"這支隊伍在第一輪就被淘汰了。","synonyms":["remove","get rid of"],"level":5,"theme":"動作與行為","examples":[{"en":"The team was eliminated in the first round.","zh":"這支隊伍在第一輪就被淘汰了。"},{"en":"Careful proofreading can eliminate most errors in your essay.","zh":"仔細校對可以消除文章中大部分的錯誤。"},{"en":"The government hopes to eliminate poverty within the next decade.","zh":"政府希望在未來十年內消除貧窮。"}]},{"word":"elite","pos":"n. / adj.","phonetic":"[ɪˈlit]","meaning":"菁英；菁英的","definition":"a select group considered the best or most powerful","collocations":["elite athletes","social elite","elite university"],"example":"Only the elite athletes qualified for the finals.","exampleZh":"只有菁英運動員取得了決賽資格。","synonyms":["best","top"],"level":6,"theme":"社會與文化","examples":[{"en":"Only the elite athletes qualified for the finals.","zh":"只有菁英運動員取得了決賽資格。"},{"en":"She dreams of studying at an elite university abroad.","zh":"她夢想到國外的菁英大學就讀。"},{"en":"Only members of the social elite were invited to the ball.","zh":"只有社會菁英才被邀請參加那場舞會。"}]},{"word":"else","pos":"adv.","phonetic":"[ɛls]","meaning":"其他；別的","definition":"in addition; other than someone or something already mentioned","collocations":["something else","or else","anyone else"],"example":"Is there anything else you need?","exampleZh":"你還需要其他東西嗎？","synonyms":["other"],"level":2,"theme":"抽象概念","examples":[{"en":"Is there anything else you need?","zh":"你還需要其他東西嗎？"},{"en":"Would anyone else like to share their opinion with the class?","zh":"還有其他人想和全班分享意見嗎？"},{"en":"Hurry up, or else we will miss the bus.","zh":"快點，不然我們會錯過公車。"}]},{"word":"elsewhere","pos":"adv.","phonetic":"[ˈɛlsˌhwɛr]","meaning":"在別處；到別處","definition":"in, at, or to another place","collocations":["move elsewhere","look elsewhere","found elsewhere"],"example":"If this shop is closed, we can shop elsewhere.","exampleZh":"如果這家店關了，我們可以去別的地方購物。","synonyms":["somewhere else"],"level":4,"theme":"時間與空間","examples":[{"en":"If this shop is closed, we can shop elsewhere.","zh":"如果這家店關了，我們可以去別的地方購物。"},{"en":"The rent was too high, so the family decided to move elsewhere.","zh":"房租太高了，所以這家人決定搬到別處。"},{"en":"If you can't find the book here, try looking elsewhere.","zh":"如果你在這裡找不到那本書，試試到別處找找。"}]},{"word":"embarrass","pos":"v.","phonetic":"[ɪmˈbærəs]","meaning":"使尷尬；使難堪","definition":"to cause someone to feel awkward or ashamed","collocations":["embarrass someone","don't embarrass me","embarrass yourself"],"example":"His joke embarrassed her in front of everyone.","exampleZh":"他的玩笑讓她在大家面前很尷尬。","synonyms":["humiliate"],"level":4,"theme":"情緒與感受","examples":[{"en":"His joke embarrassed her in front of everyone.","zh":"他的玩笑讓她在大家面前很尷尬。"},{"en":"Please don't embarrass me in front of my friends.","zh":"拜託不要在我朋友面前讓我難堪。"},{"en":"He tried not to embarrass himself during the interview.","zh":"他努力在面試中不讓自己出糗。"}]},{"word":"embarrassed","pos":"adj.","phonetic":"[ɪmˈbærəst]","meaning":"感到尷尬的","definition":"feeling ashamed or awkward","collocations":["feel embarrassed","embarrassed about","embarrassed smile"],"example":"I felt embarrassed when I forgot her name.","exampleZh":"我忘記她的名字時感到很尷尬。","synonyms":["ashamed"],"level":3,"theme":"情緒與感受","examples":[{"en":"I felt embarrassed when I forgot her name.","zh":"我忘記她的名字時感到很尷尬。"},{"en":"She gave an embarrassed smile after tripping on the stage.","zh":"在舞台上絆倒後，她露出尷尬的微笑。"},{"en":"I felt embarrassed about the mistake I made in class.","zh":"我對自己在課堂上犯的錯誤感到尷尬。"}]},{"word":"embarrassing","pos":"adj.","phonetic":"[ɪmˈbærəsɪŋ]","meaning":"令人尷尬的","definition":"causing feelings of embarrassment","collocations":["embarrassing moment","embarrassing situation","how embarrassing"],"example":"It was an embarrassing moment for the whole team.","exampleZh":"那對整支隊伍來說是個尷尬的時刻。","synonyms":["awkward"],"level":3,"theme":"情緒與感受","examples":[{"en":"It was an embarrassing moment for the whole team.","zh":"那對整支隊伍來說是個尷尬的時刻。"},{"en":"Forgetting my lines on stage was a truly embarrassing moment.","zh":"在台上忘詞是一個真的很令人尷尬的時刻。"},{"en":"Calling the teacher by the wrong name put me in an embarrassing situation.","zh":"叫錯老師的名字讓我陷入令人尷尬的處境。"}]},{"word":"embrace","pos":"v. / n.","phonetic":"[ɪmˈbres]","meaning":"擁抱；欣然接受","definition":"to hold someone closely; to accept an idea or change willingly","collocations":["embrace change","warm embrace","embrace a new idea"],"example":"They embraced each other at the airport.","exampleZh":"他們在機場互相擁抱。","synonyms":["hug","accept"],"level":5,"theme":"情緒與感受","examples":[{"en":"They embraced each other at the airport.","zh":"他們在機場互相擁抱。"},{"en":"Successful companies are willing to embrace change quickly.","zh":"成功的公司願意迅速地欣然接受改變。"},{"en":"The mother welcomed her son home with a warm embrace.","zh":"母親用溫暖的擁抱迎接兒子回家。"}]},{"word":"emerge","pos":"v.","phonetic":"[ɪˈmɝdʒ]","meaning":"出現；浮現","definition":"to come out from somewhere or come into existence","collocations":["emerge from","new evidence emerges","emerge victorious"],"example":"The sun emerged from behind the clouds.","exampleZh":"太陽從雲後面出現了。","synonyms":["appear"],"level":5,"theme":"抽象概念","examples":[{"en":"The sun emerged from behind the clouds.","zh":"太陽從雲後面出現了。"},{"en":"A rabbit suddenly emerged from behind the bushes.","zh":"一隻兔子突然從灌木叢後面冒了出來。"},{"en":"The team emerged victorious after a long and difficult match.","zh":"經過漫長而艱難的比賽後，這支隊伍獲得了勝利。"}]},{"word":"emergency","pos":"n.","phonetic":"[ɪˈmɝdʒənsɪ]","meaning":"緊急情況","definition":"a serious, unexpected situation requiring immediate action","collocations":["emergency room","in case of emergency","emergency exit"],"example":"Call 911 in case of an emergency.","exampleZh":"遇到緊急情況時，請撥打911。","synonyms":["crisis"],"level":3,"theme":"身體與健康","examples":[{"en":"Call 911 in case of an emergency.","zh":"遇到緊急情況時，請撥打911。"},{"en":"Please remember where the emergency exit is located.","zh":"請記住緊急出口的位置。"},{"en":"The injured hiker was rushed to the emergency room.","zh":"受傷的登山者被緊急送往急診室。"}]},{"word":"eminent","pos":"adj.","phonetic":"[ˈɛmənənt]","meaning":"卓越的；著名的","definition":"famous and respected within a particular field","collocations":["eminent scientist","eminent scholar","an eminent figure"],"example":"He is an eminent scientist in his field.","exampleZh":"他是他這個領域中一位卓越的科學家。","synonyms":["distinguished","renowned"],"level":6,"theme":"社會與文化","examples":[{"en":"He is an eminent scientist in his field.","zh":"他是他這個領域中一位卓越的科學家。"},{"en":"The conference invited an eminent scholar to give the opening speech.","zh":"研討會邀請了一位卓越的學者發表開幕演說。"},{"en":"She is an eminent figure in the world of modern art.","zh":"她是現代藝術界一位著名的人物。"}]},{"word":"emotion","pos":"n.","phonetic":"[ɪˈmoʃən]","meaning":"情感；情緒","definition":"a strong feeling such as love, fear, or anger","collocations":["show emotion","strong emotion","control your emotions"],"example":"She couldn't hide her emotion during the speech.","exampleZh":"她在演講中無法掩藏自己的情緒。","synonyms":["feeling"],"level":3,"theme":"情緒與感受","examples":[{"en":"She couldn't hide her emotion during the speech.","zh":"她在演講中無法掩藏自己的情緒。"},{"en":"It is important to control your emotions when you are angry.","zh":"生氣時控制自己的情緒是很重要的。"},{"en":"The poem is full of strong emotion about lost love.","zh":"這首詩充滿了對逝去愛情的強烈情感。"}]},{"word":"emotional","pos":"adj.","phonetic":"[ɪˈmoʃənḷ]","meaning":"情緒的；情感的","definition":"relating to emotions; showing strong feelings","collocations":["emotional support","emotional moment","become emotional"],"example":"The reunion was an emotional moment for the family.","exampleZh":"這場重逢對這個家庭來說是感人的一刻。","synonyms":["sentimental"],"level":3,"theme":"情緒與感受","examples":[{"en":"The reunion was an emotional moment for the family.","zh":"這場重逢對這個家庭來說是感人的一刻。"},{"en":"My friends gave me emotional support during a difficult time.","zh":"在艱難的時期，我的朋友們給了我情感上的支持。"},{"en":"He became emotional when he talked about his late grandmother.","zh":"當他談到過世的祖母時，變得情緒激動。"}]},{"word":"emphasis","pos":"n.","phonetic":"[ˈɛmfəsɪs]","meaning":"強調；重點","definition":"special importance or attention given to something","collocations":["put emphasis on","place emphasis","emphasis on quality"],"example":"The school places great emphasis on creativity.","exampleZh":"這所學校非常強調創造力。","synonyms":["stress"],"level":5,"theme":"抽象概念","examples":[{"en":"The school places great emphasis on creativity.","zh":"這所學校非常強調創造力。"},{"en":"This restaurant puts great emphasis on fresh ingredients.","zh":"這家餐廳非常強調新鮮的食材。"},{"en":"Our coach places emphasis on teamwork rather than individual skill.","zh":"我們的教練重視團隊合作，而非個人技巧。"}]},{"word":"emphasize","pos":"v.","phonetic":"[ˈɛmfəˌsaɪz]","meaning":"強調","definition":"to give special importance to something","collocations":["emphasize the importance","strongly emphasize","emphasize a point"],"example":"The teacher emphasized the importance of practice.","exampleZh":"老師強調練習的重要性。","synonyms":["stress","highlight"],"level":5,"theme":"溝通與語言","examples":[{"en":"The teacher emphasized the importance of practice.","zh":"老師強調練習的重要性。"},{"en":"The doctor emphasized the importance of a balanced diet.","zh":"醫生強調均衡飲食的重要性。"},{"en":"She raised her voice to emphasize her main point.","zh":"她提高音量以強調她的重點。"}]},{"word":"empire","pos":"n.","phonetic":"[ˈɛmpaɪr]","meaning":"帝國","definition":"a group of countries ruled by a single supreme authority","collocations":["Roman Empire","build an empire","fall of the empire"],"example":"The Roman Empire once ruled much of Europe.","exampleZh":"羅馬帝國曾統治歐洲大部分地區。","synonyms":[],"level":5,"theme":"政治與法律","examples":[{"en":"The Roman Empire once ruled much of Europe.","zh":"羅馬帝國曾統治歐洲大部分地區。"},{"en":"Over many years, he built a business empire from nothing.","zh":"多年來，他白手起家建立了一個商業帝國。"},{"en":"Historians still study the fall of that ancient empire.","zh":"歷史學家仍在研究那個古代帝國的衰亡。"}]},{"word":"employ","pos":"v.","phonetic":"[ɪmˈplɔɪ]","meaning":"雇用；使用","definition":"to give work to someone in exchange for payment","collocations":["employ workers","employ a method","fully employed"],"example":"The factory employs over 500 workers.","exampleZh":"這間工廠雇用了超過五百名員工。","synonyms":["hire"],"level":4,"theme":"工作與職業","examples":[{"en":"The factory employs over 500 workers.","zh":"這間工廠雇用了超過五百名員工。"},{"en":"The restaurant plans to employ ten more workers this summer.","zh":"這家餐廳計劃在今年夏天多雇用十名員工。"},{"en":"Scientists employ various methods to test their theories.","zh":"科學家運用各種方法來檢驗他們的理論。"}]},{"word":"employee","pos":"n.","phonetic":"[ˌɛmplɔɪˈi]","meaning":"員工","definition":"a person who works for another person or company for pay","collocations":["hire an employee","loyal employee","employee benefits"],"example":"The company treats its employees well.","exampleZh":"這間公司善待員工。","synonyms":["worker","staff"],"level":3,"theme":"工作與職業","examples":[{"en":"The company treats its employees well.","zh":"這間公司善待員工。"},{"en":"The company offers good benefits to every employee.","zh":"這家公司為每位員工提供良好的福利。"},{"en":"She has been a loyal employee for over twenty years.","zh":"她已經是一位忠誠的員工超過二十年了。"}]},{"word":"employer","pos":"n.","phonetic":"[ɪmˈplɔɪɚ]","meaning":"雇主","definition":"a person or organization that employs people","collocations":["good employer","employer and employee","potential employer"],"example":"Her employer gave her a raise.","exampleZh":"她的雇主給她加薪了。","synonyms":["boss"],"level":3,"theme":"工作與職業","examples":[{"en":"Her employer gave her a raise.","zh":"她的雇主給她加薪了。"},{"en":"A good employer listens carefully to the workers' concerns.","zh":"一位好雇主會仔細聆聽員工的顧慮。"},{"en":"She impressed her potential employer during the interview.","zh":"她在面試中給未來的雇主留下了深刻的印象。"}]},{"word":"employment","pos":"n.","phonetic":"[ɪmˈplɔɪmənt]","meaning":"就業；雇用","definition":"the state of having paid work","collocations":["find employment","full employment","employment rate"],"example":"The new factory created many employment opportunities.","exampleZh":"這間新工廠創造了許多就業機會。","synonyms":["job","work"],"level":4,"theme":"工作與職業","examples":[{"en":"The new factory created many employment opportunities.","zh":"這間新工廠創造了許多就業機會。"},{"en":"Many young graduates struggle to find employment these days.","zh":"如今許多年輕的畢業生很難找到工作。"},{"en":"The employment rate has risen steadily over the past year.","zh":"就業率在過去一年穩定地上升。"}]},{"word":"enable","pos":"v.","phonetic":"[ɪnˈebl]","meaning":"使能夠；賦予權力","definition":"to make someone able to do something, or make something possible","collocations":["enable someone to do","enable access","technology that enables"],"example":"The new software enables users to edit videos easily.","exampleZh":"這套新軟體讓使用者能輕鬆剪輯影片。","synonyms":["allow","permit"],"level":3,"theme":"科技與媒體","examples":[{"en":"The new software enables users to edit videos easily.","zh":"這套新軟體讓使用者能輕鬆剪輯影片。"},{"en":"A scholarship enabled her to study at her dream school.","zh":"一筆獎學金使她能夠在夢想中的學校就讀。"},{"en":"This app enables users to translate signs instantly.","zh":"這個應用程式讓使用者能夠即時翻譯標誌。"}]},{"word":"enclose","pos":"v.","phonetic":"[ɪnˈkloz]","meaning":"圍住；附上（文件等）","definition":"to surround an area completely, or to put something inside an envelope with a letter","collocations":["enclose a garden","enclose a check","enclosed area"],"example":"Please find the documents enclosed with this letter.","exampleZh":"請查收隨信附上的文件。","synonyms":["surround","attach"],"level":4,"theme":"溝通與語言","examples":[{"en":"Please find the documents enclosed with this letter.","zh":"請查收隨信附上的文件。"},{"en":"A tall wall encloses the school playground on all sides.","zh":"一道高牆將學校的操場四面圍住。"},{"en":"Please enclose a copy of your certificate with the application.","zh":"請將證書的影本附在申請表中。"}]},{"word":"encounter","pos":"v. / n.","phonetic":"[ɪnˈkaʊntɚ]","meaning":"遭遇；邂逅；相遇","definition":"to meet or experience something, especially something unexpected","collocations":["encounter difficulty","a chance encounter","encounter a problem"],"example":"We encountered many difficulties during the trip.","exampleZh":"我們在旅途中遇到了許多困難。","synonyms":["meet","face"],"level":4,"theme":"動作與行為","examples":[{"en":"We encountered many difficulties during the trip.","zh":"我們在旅途中遇到了許多困難。"},{"en":"The hikers encountered a bear on the mountain trail.","zh":"登山者在山徑上遇到了一隻熊。"},{"en":"A chance encounter at the café led to a lifelong friendship.","zh":"咖啡館的一次偶然相遇，帶來了一段終生的友誼。"}]},{"word":"encourage","pos":"v.","phonetic":"[ɪnˈkɝɪdʒ]","meaning":"鼓勵；激勵","definition":"to give someone support, confidence, or hope","collocations":["encourage someone to","encourage growth","words of encouragement"],"example":"Her parents always encourage her to follow her dreams.","exampleZh":"她的父母總是鼓勵她追求夢想。","synonyms":["motivate","inspire"],"level":2,"theme":"情緒與感受","examples":[{"en":"Her parents always encourage her to follow her dreams.","zh":"她的父母總是鼓勵她追求夢想。"},{"en":"The coach encouraged the players to never give up.","zh":"教練鼓勵球員們永不放棄。"},{"en":"A few words of encouragement can brighten someone's whole day.","zh":"幾句鼓勵的話能照亮某人的一整天。"}]},{"word":"endanger","pos":"v.","phonetic":"[ɪnˈdendʒɚ]","meaning":"危害；使遭遇危險","definition":"to put someone or something at risk of harm or destruction","collocations":["endanger species","endanger lives","endangered animals"],"example":"Pollution endangers many species of wildlife.","exampleZh":"污染危害著許多野生動物物種。","synonyms":["threaten","jeopardize"],"level":4,"theme":"自然與環境","examples":[{"en":"Pollution endangers many species of wildlife.","zh":"污染危害著許多野生動物物種。"},{"en":"Driving too fast can endanger the lives of pedestrians.","zh":"開車太快可能危及行人的生命。"},{"en":"Cutting down forests endangers many rare animals.","zh":"砍伐森林危害了許多稀有動物。"}]},{"word":"endeavor","pos":"v. / n.","phonetic":"[ɪnˈdɛvɚ]","meaning":"努力；盡力；嘗試","definition":"to try hard to achieve something; a serious attempt","collocations":["endeavor to do","a joint endeavor","best endeavors"],"example":"The team will endeavor to finish the project on time.","exampleZh":"這個團隊將努力準時完成這項專案。","synonyms":["attempt","strive"],"level":5,"theme":"工作與職業","examples":[{"en":"The team will endeavor to finish the project on time.","zh":"這個團隊將努力準時完成這項專案。"},{"en":"Scientists endeavor to find a cure for the disease.","zh":"科學家努力尋找這種疾病的療法。"},{"en":"Building the bridge was a joint endeavor between two countries.","zh":"建造這座橋是兩國共同的努力。"}]},{"word":"ending","pos":"n.","phonetic":"[ˈɛndɪŋ]","meaning":"結局；結尾","definition":"the final part of a story, film, or event","collocations":["happy ending","surprise ending","the ending of a movie"],"example":"I love movies with a happy ending.","exampleZh":"我喜歡有快樂結局的電影。","synonyms":["conclusion","finale"],"level":1,"theme":"藝術與音樂","examples":[{"en":"I love movies with a happy ending.","zh":"我喜歡有快樂結局的電影。"},{"en":"The novel has a surprise ending that no one expected.","zh":"這本小說有一個出人意料的結局。"},{"en":"Many children's stories finish with a happy ending.","zh":"許多兒童故事以幸福的結局收尾。"}]},{"word":"endless","pos":"adj.","phonetic":"[ˈɛndlɪs]","meaning":"無盡的；沒完沒了的","definition":"having or seeming to have no end","collocations":["endless possibilities","endless discussion","seemingly endless"],"example":"The desert seemed endless under the burning sun.","exampleZh":"在烈日下，沙漠似乎沒有盡頭。","synonyms":["infinite","unending"],"level":3,"theme":"性質與描述","examples":[{"en":"The desert seemed endless under the burning sun.","zh":"在烈日下，沙漠似乎沒有盡頭。"},{"en":"With hard work, your future holds endless possibilities.","zh":"只要努力，你的未來有著無限的可能性。"},{"en":"The meeting turned into an endless discussion about small details.","zh":"會議變成了對細節沒完沒了的討論。"}]},{"word":"endure","pos":"v.","phonetic":"[ɪnˈdʊr]","meaning":"忍受；持續；耐久","definition":"to suffer something difficult, painful, or unpleasant patiently","collocations":["endure pain","endure hardship","hard to endure"],"example":"Soldiers had to endure freezing temperatures during the war.","exampleZh":"士兵們在戰爭期間得忍受酷寒的氣溫。","synonyms":["bear","withstand"],"level":5,"theme":"情緒與感受","examples":[{"en":"Soldiers had to endure freezing temperatures during the war.","zh":"士兵們在戰爭期間得忍受酷寒的氣溫。"},{"en":"The marathon runner had to endure great pain to finish.","zh":"馬拉松跑者必須忍受巨大的痛苦才能完賽。"},{"en":"Their friendship endured for over fifty years.","zh":"他們的友誼持續了超過五十年。"}]},{"word":"enemy","pos":"n.","phonetic":"[ˈɛnəmi]","meaning":"敵人；仇敵","definition":"a person who is hostile or opposed to someone or something","collocations":["a bitter enemy","enemy forces","make an enemy"],"example":"The two nations were once bitter enemies.","exampleZh":"這兩個國家曾經是死對頭。","synonyms":["foe","opponent"],"level":2,"theme":"社會與文化","examples":[{"en":"The two nations were once bitter enemies.","zh":"這兩個國家曾經是死對頭。"},{"en":"You should be careful not to make an enemy of your neighbor.","zh":"你應該小心，不要與鄰居結仇。"},{"en":"The soldiers bravely defended the town against the enemy forces.","zh":"士兵們勇敢地保衛小鎮，抵抗敵軍。"}]},{"word":"energetic","pos":"adj.","phonetic":"[ˌɛnɚˈdʒɛtɪk]","meaning":"精力充沛的；充滿活力的","definition":"having or showing a lot of energy and enthusiasm","collocations":["an energetic child","energetic performance","feel energetic"],"example":"The children were too energetic to sit still.","exampleZh":"孩子們精力太旺盛，坐不住。","synonyms":["lively","vigorous"],"level":3,"theme":"性質與描述","examples":[{"en":"The children were too energetic to sit still.","zh":"孩子們精力太旺盛，坐不住。"},{"en":"The dancers gave an energetic performance that thrilled the crowd.","zh":"舞者們活力四射的表演讓觀眾興奮不已。"},{"en":"After a good night's sleep, I feel energetic in the morning.","zh":"睡了一夜好覺後，我早上感到精力充沛。"}]},{"word":"energy","pos":"n.","phonetic":"[ˈɛnɚdʒi]","meaning":"能量；精力；能源","definition":"the strength and vitality needed for activity, or power from fuel sources","collocations":["solar energy","full of energy","save energy"],"example":"We should try to save energy at home.","exampleZh":"我們在家裡應該試著節省能源。","synonyms":["power","vigor"],"level":2,"theme":"科學與數學","examples":[{"en":"We should try to save energy at home.","zh":"我們在家裡應該試著節省能源。"},{"en":"Many homes now use solar energy to reduce electricity bills.","zh":"現在許多家庭使用太陽能來減少電費。"},{"en":"The puppy is full of energy and loves to run around.","zh":"這隻小狗精力充沛，喜歡到處跑。"}]},{"word":"enforce","pos":"v.","phonetic":"[ɪnˈfɔrs]","meaning":"執行；實施（法律等）","definition":"to make sure that a law, rule, or requirement is obeyed","collocations":["enforce a law","enforce rules","strictly enforced"],"example":"The government decided to enforce the new traffic law.","exampleZh":"政府決定要執行新的交通法規。","synonyms":["implement","impose"],"level":5,"theme":"政治與法律","examples":[{"en":"The government decided to enforce the new traffic law.","zh":"政府決定要執行新的交通法規。"},{"en":"The teachers strictly enforce the rules against cheating.","zh":"老師嚴格執行禁止作弊的規定。"},{"en":"Police officers are responsible for enforcing traffic laws.","zh":"警察負責執行交通法規。"}]},{"word":"engage","pos":"v.","phonetic":"[ɪnˈgedʒ]","meaning":"從事；使參與；訂婚","definition":"to participate or become involved in an activity, or to attract someone's interest","collocations":["engage in conversation","engage the audience","get engaged"],"example":"Students actively engaged in the class discussion.","exampleZh":"學生們積極參與了課堂討論。","synonyms":["participate","involve"],"level":4,"theme":"教育與學習","examples":[{"en":"Students actively engaged in the class discussion.","zh":"學生們積極參與了課堂討論。"},{"en":"The speaker used stories to engage the audience's attention.","zh":"講者用故事來吸引觀眾的注意力。"},{"en":"The couple got engaged after dating for three years.","zh":"這對情侶交往三年後訂婚了。"}]},{"word":"engine","pos":"n.","phonetic":"[ˈɛndʒən]","meaning":"引擎；發動機","definition":"a machine that converts energy into mechanical motion","collocations":["car engine","start the engine","engine trouble"],"example":"The mechanic checked the car's engine before the trip.","exampleZh":"技師在出發前檢查了汽車的引擎。","synonyms":["motor"],"level":2,"theme":"交通與旅行","examples":[{"en":"The mechanic checked the car's engine before the trip.","zh":"技師在出發前檢查了汽車的引擎。"},{"en":"He turned the key to start the engine of his old car.","zh":"他轉動鑰匙發動他那輛老車的引擎。"},{"en":"We had engine trouble halfway through the road trip.","zh":"公路旅行進行到一半時，我們的引擎出了問題。"}]},{"word":"engineer","pos":"n.","phonetic":"[ˌɛndʒəˈnɪr]","meaning":"工程師","definition":"a person who designs, builds, or maintains engines, machines, or structures","collocations":["civil engineer","software engineer","become an engineer"],"example":"She works as a software engineer at a tech company.","exampleZh":"她在一家科技公司擔任軟體工程師。","synonyms":[],"level":2,"theme":"工作與職業","examples":[{"en":"She works as a software engineer at a tech company.","zh":"她在一家科技公司擔任軟體工程師。"},{"en":"The civil engineer designed a safer road for the town.","zh":"這位土木工程師為小鎮設計了一條更安全的道路。"},{"en":"He studied hard because he wanted to become an engineer.","zh":"他努力讀書，因為他想成為一名工程師。"}]},{"word":"enhance","pos":"v.","phonetic":"[ɪnˈhæns]","meaning":"提升；增強；提高","definition":"to improve the quality, value, or extent of something","collocations":["enhance performance","enhance the flavor","enhance one's image"],"example":"Regular exercise can enhance your overall health.","exampleZh":"規律運動能提升你整體的健康。","synonyms":["improve","boost"],"level":5,"theme":"性質與描述","examples":[{"en":"Regular exercise can enhance your overall health.","zh":"規律運動能提升你整體的健康。"},{"en":"Adding a little salt can enhance the flavor of the soup.","zh":"加一點鹽可以提升湯的風味。"},{"en":"A good night's sleep can enhance your performance at school.","zh":"一夜好眠可以提升你在學校的表現。"}]},{"word":"enjoy","pos":"v.","phonetic":"[ɪnˈdʒɔɪ]","meaning":"享受；喜歡","definition":"to take pleasure in an activity or occasion","collocations":["enjoy oneself","enjoy the movie","enjoy life"],"example":"They enjoyed the concert last night.","exampleZh":"他們昨晚很享受那場演唱會。","synonyms":["like","appreciate"],"level":1,"theme":"情緒與感受","examples":[{"en":"They enjoyed the concert last night.","zh":"他們昨晚很享受那場演唱會。"},{"en":"The children really enjoyed themselves at the amusement park.","zh":"孩子們在遊樂園玩得非常開心。"},{"en":"My grandparents know how to enjoy life in the countryside.","zh":"我的祖父母懂得享受鄉間的生活。"}]},{"word":"enlarge","pos":"v.","phonetic":"[ɪnˈlɑrdʒ]","meaning":"擴大；放大","definition":"to make or become bigger","collocations":["enlarge a photo","enlarge the scope","enlarge upon"],"example":"Could you enlarge this photo for the frame?","exampleZh":"你可以把這張照片放大以便裝框嗎？","synonyms":["expand","magnify"],"level":4,"theme":"性質與描述","examples":[{"en":"Could you enlarge this photo for the frame?","zh":"你可以把這張照片放大以便裝框嗎？"},{"en":"The company plans to enlarge the scope of its research.","zh":"公司計劃擴大其研究的範圍。"},{"en":"She asked the shop to enlarge the photo for the wall.","zh":"她請店家把照片放大以掛在牆上。"}]},{"word":"enormous","pos":"adj.","phonetic":"[ɪˈnɔrməs]","meaning":"巨大的；龐大的","definition":"very large in size, quantity, or extent","collocations":["an enormous amount","enormous pressure","enormous success"],"example":"The company made an enormous profit this year.","exampleZh":"這間公司今年賺了巨額利潤。","synonyms":["huge","massive"],"level":3,"theme":"性質與描述","examples":[{"en":"The company made an enormous profit this year.","zh":"這間公司今年賺了巨額利潤。"},{"en":"The students felt enormous pressure before the final exams.","zh":"學生們在期末考前感到巨大的壓力。"},{"en":"The charity concert was an enormous success.","zh":"這場慈善音樂會取得了巨大的成功。"}]},{"word":"enough","pos":"adj. / adv. / pron.","phonetic":"[ɪˈnʌf]","meaning":"足夠的；充分地","definition":"as much or as many as required","collocations":["enough time","enough money","good enough"],"example":"We don't have enough time to finish this today.","exampleZh":"我們沒有足夠的時間今天完成這個。","synonyms":["sufficient","adequate"],"level":1,"theme":"抽象概念","examples":[{"en":"We don't have enough time to finish this today.","zh":"我們沒有足夠的時間今天完成這個。"},{"en":"Make sure you save enough money for the school trip.","zh":"確保你為校外旅行存夠了錢。"},{"en":"Her painting was good enough to win first prize.","zh":"她的畫作好到足以贏得首獎。"}]},{"word":"enrich","pos":"v.","phonetic":"[ɪnˈrɪtʃ]","meaning":"使豐富；使富裕","definition":"to improve the quality or value of something","collocations":["enrich the soil","enrich one's knowledge","culturally enriched"],"example":"Reading widely can enrich your vocabulary.","exampleZh":"廣泛閱讀能豐富你的字彙。","synonyms":["improve","enhance"],"level":5,"theme":"教育與學習","examples":[{"en":"Reading widely can enrich your vocabulary.","zh":"廣泛閱讀能豐富你的字彙。"},{"en":"Traveling abroad can enrich your knowledge of other cultures.","zh":"出國旅行可以豐富你對其他文化的認識。"},{"en":"Farmers add compost to enrich the soil before planting.","zh":"農夫在種植前加入堆肥來使土壤變得肥沃。"}]},{"word":"enroll","pos":"v.","phonetic":"[ɪnˈrol]","meaning":"註冊；入學；加入","definition":"to officially register as a member, student, or participant","collocations":["enroll in a course","enroll at school","enrollment fee"],"example":"She enrolled in a painting class last month.","exampleZh":"她上個月報名了一堂繪畫課。","synonyms":["register","sign up"],"level":4,"theme":"教育與學習","examples":[{"en":"She enrolled in a painting class last month.","zh":"她上個月報名了一堂繪畫課。"},{"en":"I decided to enroll in an online English course this year.","zh":"我決定今年報名一門線上英文課程。"},{"en":"Hundreds of students enroll at this university every autumn.","zh":"每年秋天有數百名學生進入這所大學就讀。"}]},{"word":"ensure","pos":"v.","phonetic":"[ɪnˈʃʊr]","meaning":"確保；保證","definition":"to make certain that something will happen or be the case","collocations":["ensure safety","ensure quality","ensure that"],"example":"The teacher checked twice to ensure everyone understood.","exampleZh":"老師檢查了兩次以確保每個人都理解了。","synonyms":["guarantee","assure"],"level":4,"theme":"抽象概念","examples":[{"en":"The teacher checked twice to ensure everyone understood.","zh":"老師檢查了兩次以確保每個人都理解了。"},{"en":"The lifeguards work hard to ensure the safety of swimmers.","zh":"救生員努力確保泳客的安全。"},{"en":"Please double-check your work to ensure that no mistakes remain.","zh":"請再次檢查你的作業，以確保沒有留下錯誤。"}]},{"word":"entail","pos":"v.","phonetic":"[ɪnˈtel]","meaning":"牽涉；使必須；伴隨","definition":"to involve something as a necessary or logical consequence","collocations":["entail risk","entail costs","the job entails"],"example":"Running a business entails a lot of responsibility.","exampleZh":"經營事業伴隨著許多責任。","synonyms":["involve","require"],"level":6,"theme":"抽象概念","examples":[{"en":"Running a business entails a lot of responsibility.","zh":"經營事業伴隨著許多責任。"},{"en":"Starting your own business often entails a lot of risk.","zh":"自己創業往往牽涉很大的風險。"},{"en":"The new position entails frequent travel to other cities.","zh":"這個新職位需要經常到其他城市出差。"}]},{"word":"enter","pos":"v.","phonetic":"[ˈɛntɚ]","meaning":"進入；參加","definition":"to come or go into a place, or to become involved in an activity","collocations":["enter a room","enter a contest","enter data"],"example":"He knocked before entering the office.","exampleZh":"他進辦公室前先敲了門。","synonyms":["go in","join"],"level":1,"theme":"動作與行為","examples":[{"en":"He knocked before entering the office.","zh":"他進辦公室前先敲了門。"},{"en":"She decided to enter the school's singing contest.","zh":"她決定參加學校的歌唱比賽。"},{"en":"Please knock before you enter the meeting room.","zh":"進入會議室前請先敲門。"}]},{"word":"entertain","pos":"v.","phonetic":"[ˌɛntɚˈten]","meaning":"娛樂；招待；款待","definition":"to provide amusement or enjoyment, or to receive guests","collocations":["entertain guests","entertain an idea","entertain the audience"],"example":"The clown entertained the children at the party.","exampleZh":"那位小丑在派對上逗樂了孩子們。","synonyms":["amuse","host"],"level":3,"theme":"藝術與音樂","examples":[{"en":"The clown entertained the children at the party.","zh":"那位小丑在派對上逗樂了孩子們。"},{"en":"The magician entertained the audience for a full hour.","zh":"魔術師娛樂觀眾整整一個小時。"},{"en":"They love to entertain guests at their home on weekends.","zh":"他們喜歡週末在家裡招待客人。"}]},{"word":"enthusiasm","pos":"n.","phonetic":"[ɪnˈθjuzɪˌæzəm]","meaning":"熱情；熱忱","definition":"intense and eager enjoyment or interest in something","collocations":["show enthusiasm","full of enthusiasm","lack enthusiasm"],"example":"She spoke about her project with great enthusiasm.","exampleZh":"她滿懷熱情地談論她的專案。","synonyms":["passion","excitement"],"level":4,"theme":"情緒與感受","examples":[{"en":"She spoke about her project with great enthusiasm.","zh":"她滿懷熱情地談論她的專案。"},{"en":"The new students showed great enthusiasm on their first day.","zh":"新生們在第一天展現了極大的熱情。"},{"en":"His voice was full of enthusiasm as he described his plan.","zh":"當他描述計劃時，聲音充滿了熱忱。"}]},{"word":"enthusiastic","pos":"adj.","phonetic":"[ɪnˌθjuziˈæstɪk]","meaning":"熱情的；熱心的","definition":"showing intense enjoyment, interest, or approval","collocations":["enthusiastic about","enthusiastic supporter","become enthusiastic"],"example":"He is very enthusiastic about learning new languages.","exampleZh":"他對學習新語言非常熱衷。","synonyms":["eager","passionate"],"level":4,"theme":"情緒與感受","examples":[{"en":"He is very enthusiastic about learning new languages.","zh":"他對學習新語言非常熱衷。"},{"en":"She is enthusiastic about protecting the ocean from plastic.","zh":"她熱衷於保護海洋免受塑膠汙染。"},{"en":"The fans were enthusiastic supporters of the local team.","zh":"球迷們是當地球隊熱情的支持者。"}]},{"word":"entire","pos":"adj.","phonetic":"[ɪnˈtaɪr]","meaning":"整個的；全部的","definition":"whole or complete, with no part left out","collocations":["the entire family","entire life","entire process"],"example":"The entire class passed the final exam.","exampleZh":"全班同學都通過了期末考試。","synonyms":["whole","complete"],"level":3,"theme":"抽象概念","examples":[{"en":"The entire class passed the final exam.","zh":"全班同學都通過了期末考試。"},{"en":"The entire village came out to watch the festival parade.","zh":"整個村莊的人都出來觀看節慶遊行。"},{"en":"He spent his entire life studying the stars.","zh":"他一生都在研究星星。"}]},{"word":"entitle","pos":"v.","phonetic":"[ɪnˈtaɪtl]","meaning":"給予權利；命名","definition":"to give someone a right to do or have something, or to give a title to a work","collocations":["be entitled to","entitle a book","entitled to vote"],"example":"Every citizen is entitled to a fair trial.","exampleZh":"每位公民都享有公平審判的權利。","synonyms":["qualify","authorize"],"level":5,"theme":"政治與法律","examples":[{"en":"Every citizen is entitled to a fair trial.","zh":"每位公民都享有公平審判的權利。"},{"en":"Every student is entitled to a free library card.","zh":"每位學生都有權獲得一張免費的圖書館借書證。"},{"en":"The author entitled her new book after her hometown.","zh":"作者以她的家鄉為她的新書命名。"}]},{"word":"entrance","pos":"n.","phonetic":"[ˈɛntrəns]","meaning":"入口；進入；入學","definition":"a way into a place, or the act of entering","collocations":["main entrance","entrance exam","entrance fee"],"example":"Meet me at the entrance of the museum.","exampleZh":"在博物館入口處等我。","synonyms":["entry","doorway"],"level":2,"theme":"教育與學習","examples":[{"en":"Meet me at the entrance of the museum.","zh":"在博物館入口處等我。"},{"en":"There is a long line at the main entrance of the stadium.","zh":"體育館的主要入口排著長長的隊伍。"},{"en":"She studied all summer to pass the university entrance exam.","zh":"她整個夏天都在讀書，為了通過大學入學考試。"}]},{"word":"entry","pos":"n.","phonetic":"[ˈɛntri]","meaning":"進入；入口；條目","definition":"the act of coming or going in, or an item recorded in a list","collocations":["entry fee","diary entry","gain entry"],"example":"She wrote a new entry in her diary every night.","exampleZh":"她每晚都在日記裡寫一篇新的紀錄。","synonyms":["entrance","admission"],"level":2,"theme":"教育與學習","examples":[{"en":"She wrote a new entry in her diary every night.","zh":"她每晚都在日記裡寫一篇新的紀錄。"},{"en":"The museum charges a small entry fee for adults.","zh":"博物館向成人收取少額的入場費。"},{"en":"He wrote a short entry in his journal before going to bed.","zh":"他睡前在日記裡寫了一則短短的記事。"}]},{"word":"envelope","pos":"n.","phonetic":"[ˈɛnvəˌlop]","meaning":"信封","definition":"a flat paper container used to enclose a letter or document","collocations":["seal an envelope","stamp an envelope","a padded envelope"],"example":"He put the letter in an envelope and mailed it.","exampleZh":"他把信放進信封裡然後寄出去。","synonyms":[],"level":2,"theme":"溝通與語言","examples":[{"en":"He put the letter in an envelope and mailed it.","zh":"他把信放進信封裡然後寄出去。"},{"en":"She sealed the envelope and dropped it in the mailbox.","zh":"她封好信封，把它投進郵筒。"},{"en":"The fragile gift arrived safely in a padded envelope.","zh":"這份易碎的禮物裝在有襯墊的信封裡安全送達。"}]},{"word":"environment","pos":"n.","phonetic":"[ɪnˈvaɪrənmənt]","meaning":"環境；周遭事物","definition":"the surroundings or conditions in which a person, animal, or plant lives","collocations":["protect the environment","working environment","natural environment"],"example":"We must protect the environment for future generations.","exampleZh":"我們必須為了後代子孫保護環境。","synonyms":["surroundings"],"level":2,"theme":"自然與環境","examples":[{"en":"We must protect the environment for future generations.","zh":"我們必須為了後代子孫保護環境。"},{"en":"Recycling is one simple way to protect the environment.","zh":"回收是保護環境的一個簡單方法。"},{"en":"A quiet working environment helps me concentrate better.","zh":"安靜的工作環境有助於我更專心。"}]},{"word":"envy","pos":"n. / v.","phonetic":"[ˈɛnvi]","meaning":"羨慕；嫉妒","definition":"a feeling of discontented longing for someone else's advantages","collocations":["green with envy","envy someone's success","feel envy"],"example":"I envy people who can speak many languages.","exampleZh":"我很羨慕那些會說多國語言的人。","synonyms":["jealousy","covet"],"level":4,"theme":"情緒與感受","examples":[{"en":"I envy people who can speak many languages.","zh":"我很羨慕那些會說多國語言的人。"},{"en":"Her classmates were green with envy over her new bicycle.","zh":"她的同學們對她的新腳踏車羨慕不已。"},{"en":"I don't envy people who have to work on holidays.","zh":"我不羨慕那些假日還得工作的人。"}]},{"word":"episode","pos":"n.","phonetic":"[ˈɛpəˌsod]","meaning":"（電視劇的）一集；插曲；事件","definition":"a single event or one part of a television series or story","collocations":["the latest episode","a funny episode","binge-watch episodes"],"example":"I watched the newest episode of my favorite drama.","exampleZh":"我看了我最喜歡的連續劇的最新一集。","synonyms":["installment"],"level":3,"theme":"科技與媒體","examples":[{"en":"I watched the newest episode of my favorite drama.","zh":"我看了我最喜歡的連續劇的最新一集。"},{"en":"We stayed up late to watch the latest episode of the show.","zh":"我們熬夜看這部影集的最新一集。"},{"en":"She told us about a funny episode from her childhood.","zh":"她告訴我們一段她童年時有趣的插曲。"}]},{"word":"equal","pos":"adj. / v.","phonetic":"[ˈikwəl]","meaning":"平等的；相等的；等於","definition":"being the same in status, rights, or amount","collocations":["equal rights","equal opportunity","equal to"],"example":"Everyone should have equal rights before the law.","exampleZh":"每個人在法律面前都應享有平等的權利。","synonyms":["identical","equivalent"],"level":2,"theme":"社會與文化","examples":[{"en":"Everyone should have equal rights before the law.","zh":"每個人在法律面前都應享有平等的權利。"},{"en":"Men and women should receive equal pay for equal work.","zh":"男女應該同工同酬。"},{"en":"Two plus three equals five.","zh":"二加三等於五。"}]},{"word":"equator","pos":"n.","phonetic":"[ɪˈkwetɚ]","meaning":"赤道","definition":"an imaginary line around the earth equally distant from both poles","collocations":["near the equator","cross the equator","equatorial region"],"example":"Countries near the equator have hot climates all year.","exampleZh":"靠近赤道的國家全年氣候炎熱。","synonyms":[],"level":3,"theme":"自然與環境","examples":[{"en":"Countries near the equator have hot climates all year.","zh":"靠近赤道的國家全年氣候炎熱。"},{"en":"The ship's passengers celebrated as they crossed the equator.","zh":"當船隻越過赤道時，乘客們慶祝了一番。"},{"en":"Places near the equator receive strong sunlight all year.","zh":"靠近赤道的地方全年都接收強烈的陽光。"}]},{"word":"equip","pos":"v.","phonetic":"[ɪˈkwɪp]","meaning":"裝備；配備","definition":"to supply someone or something with necessary items for a task","collocations":["equip a kitchen","fully equipped","equip students with"],"example":"The lab is equipped with the latest technology.","exampleZh":"這間實驗室配備了最新的科技設備。","synonyms":["furnish","supply"],"level":4,"theme":"科技與媒體","examples":[{"en":"The lab is equipped with the latest technology.","zh":"這間實驗室配備了最新的科技設備。"},{"en":"Good teachers equip students with the skills to solve problems.","zh":"好的老師使學生具備解決問題的能力。"},{"en":"The new ambulance is fully equipped with modern medical tools.","zh":"這輛新救護車配備了完善的現代醫療器材。"}]},{"word":"equipment","pos":"n.","phonetic":"[ɪˈkwɪpmənt]","meaning":"設備；裝備","definition":"the necessary items for a particular purpose","collocations":["sports equipment","camping equipment","piece of equipment"],"example":"They bought new equipment for the gym.","exampleZh":"他們為健身房買了新的設備。","synonyms":["gear","apparatus"],"level":2,"theme":"科技與媒體","examples":[{"en":"They bought new equipment for the gym.","zh":"他們為健身房買了新的設備。"},{"en":"We packed all our camping equipment into the car.","zh":"我們把所有露營裝備都裝進了車裡。"},{"en":"The gym recently bought a new piece of exercise equipment.","zh":"健身房最近買了一件新的運動器材。"}]},{"word":"era","pos":"n.","phonetic":"[ˈɪrə]","meaning":"時代；年代","definition":"a long and distinct period of history with a particular characteristic","collocations":["a new era","the digital era","end of an era"],"example":"The internet has ushered in a new era of communication.","exampleZh":"網際網路帶來了溝通的新時代。","synonyms":["age","period"],"level":4,"theme":"時間與空間","examples":[{"en":"The internet has ushered in a new era of communication.","zh":"網際網路帶來了溝通的新時代。"},{"en":"The smartphone marked the beginning of the digital era.","zh":"智慧型手機標誌著數位時代的開端。"},{"en":"When the old shop closed, it felt like the end of an era.","zh":"當那家老店關門時，感覺就像一個時代的結束。"}]},{"word":"erase","pos":"v.","phonetic":"[ɪˈres]","meaning":"擦掉；抹除","definition":"to remove all traces of something, especially writing or a memory","collocations":["erase a mistake","erase memory","erase the board"],"example":"She erased the wrong answer and wrote a new one.","exampleZh":"她擦掉了錯誤的答案並寫下新的。","synonyms":["delete","remove"],"level":3,"theme":"教育與學習","examples":[{"en":"She erased the wrong answer and wrote a new one.","zh":"她擦掉了錯誤的答案並寫下新的。"},{"en":"The teacher asked a student to erase the board after class.","zh":"老師請一位學生下課後把黑板擦乾淨。"},{"en":"Time cannot erase the happy memories of our childhood.","zh":"時間無法抹去我們童年的快樂回憶。"}]},{"word":"erect","pos":"v. / adj.","phonetic":"[ɪˈrɛkt]","meaning":"建造；豎立；直立的","definition":"to build or set up something, or standing straight up","collocations":["erect a statue","erect a building","stand erect"],"example":"Workers erected a new bridge across the river.","exampleZh":"工人們在河上建造了一座新橋。","synonyms":["build","construct"],"level":5,"theme":"居家與生活","examples":[{"en":"Workers erected a new bridge across the river.","zh":"工人們在河上建造了一座新橋。"},{"en":"The city plans to erect a statue in honor of the poet.","zh":"市府計劃豎立一座雕像來紀念這位詩人。"},{"en":"The soldiers stood erect during the flag ceremony.","zh":"士兵們在升旗典禮中筆直地站立。"}]},{"word":"error","pos":"n.","phonetic":"[ˈɛrɚ]","meaning":"錯誤；過失","definition":"a mistake, especially one that causes problems","collocations":["make an error","human error","error message"],"example":"The report contained several spelling errors.","exampleZh":"這份報告有好幾個拼字錯誤。","synonyms":["mistake","fault"],"level":2,"theme":"教育與學習","examples":[{"en":"The report contained several spelling errors.","zh":"這份報告有好幾個拼字錯誤。"},{"en":"A small human error caused the whole machine to stop.","zh":"一個小小的人為疏失導致整台機器停止運轉。"},{"en":"An error message appeared on the screen when I saved the file.","zh":"當我儲存檔案時，螢幕上出現了錯誤訊息。"}]},{"word":"escalator","pos":"n.","phonetic":"[ˈɛskəˌletɚ]","meaning":"電扶梯","definition":"a moving staircase that carries people between floors","collocations":["take the escalator","ride an escalator","broken escalator"],"example":"We took the escalator up to the second floor.","exampleZh":"我們搭電扶梯上到二樓。","synonyms":[],"level":2,"theme":"居家與生活","examples":[{"en":"We took the escalator up to the second floor.","zh":"我們搭電扶梯上到二樓。"},{"en":"The escalator was broken, so we had to use the stairs.","zh":"電扶梯壞了，所以我們只好走樓梯。"},{"en":"Hold the handrail carefully when you ride an escalator.","zh":"搭乘電扶梯時請小心握住扶手。"}]},{"word":"escape","pos":"v. / n.","phonetic":"[ɪˈskep]","meaning":"逃跑；逃脫；逃避","definition":"to break free from confinement or danger","collocations":["escape from prison","narrow escape","escape danger"],"example":"The prisoner tried to escape from jail last night.","exampleZh":"那名囚犯昨晚試圖越獄。","synonyms":["flee","break free"],"level":3,"theme":"動作與行為","examples":[{"en":"The prisoner tried to escape from jail last night.","zh":"那名囚犯昨晚試圖越獄。"},{"en":"The family had a narrow escape when their house caught fire.","zh":"當房子起火時，這家人死裡逃生。"},{"en":"Reading novels is her favorite way to escape from daily stress.","zh":"讀小說是她逃離日常壓力最喜歡的方式。"}]},{"word":"especially","pos":"adv.","phonetic":"[ɪˈspɛʃəli]","meaning":"尤其；特別是","definition":"used to single out one person, thing, or situation over others","collocations":["especially important","especially when","especially for"],"example":"I love all seasons, especially autumn.","exampleZh":"我喜歡所有季節，尤其是秋天。","synonyms":["particularly","specifically"],"level":2,"theme":"抽象概念","examples":[{"en":"I love all seasons, especially autumn.","zh":"我喜歡所有季節，尤其是秋天。"},{"en":"Drinking water is especially important during hot weather.","zh":"在炎熱的天氣裡，喝水尤其重要。"},{"en":"He baked this cake especially for his mother's birthday.","zh":"他特別為母親的生日烤了這個蛋糕。"}]},{"word":"essay","pos":"n.","phonetic":"[ˈɛse]","meaning":"文章；論說文","definition":"a short piece of writing on a particular subject","collocations":["write an essay","essay contest","persuasive essay"],"example":"She wrote an essay about environmental protection.","exampleZh":"她寫了一篇關於環境保護的文章。","synonyms":["composition","article"],"level":3,"theme":"教育與學習","examples":[{"en":"She wrote an essay about environmental protection.","zh":"她寫了一篇關於環境保護的文章。"},{"en":"Our teacher asked us to write a persuasive essay this week.","zh":"老師要我們這週寫一篇論說文。"},{"en":"She won first prize in the national essay contest.","zh":"她在全國作文比賽中贏得首獎。"}]},{"word":"essential","pos":"adj.","phonetic":"[ɪˈsɛnʃəl]","meaning":"必要的；基本的","definition":"absolutely necessary or extremely important","collocations":["essential skills","essential for","play an essential role"],"example":"Water is essential to all forms of life.","exampleZh":"水對所有生命形式來說都是不可或缺的。","synonyms":["necessary","vital"],"level":4,"theme":"抽象概念","examples":[{"en":"Water is essential to all forms of life.","zh":"水對所有生命形式來說都是不可或缺的。"},{"en":"Communication is an essential skill in almost every job.","zh":"溝通在幾乎每一份工作中都是必備的技能。"},{"en":"Sleep plays an essential role in keeping us healthy.","zh":"睡眠在維持我們健康方面扮演著重要的角色。"}]},{"word":"establish","pos":"v.","phonetic":"[ɪˈstæblɪʃ]","meaning":"建立；設立；確立","definition":"to set up an organization or system, or to show something is true","collocations":["establish a company","establish a relationship","establish facts"],"example":"The company was established in 1990.","exampleZh":"這間公司成立於1990年。","synonyms":["found","set up"],"level":4,"theme":"商業與金錢","examples":[{"en":"The company was established in 1990.","zh":"這間公司成立於1990年。"},{"en":"They worked together to establish a new charity for children.","zh":"他們合作為孩童設立了一個新的慈善機構。"},{"en":"The detective tried to establish the facts of the case.","zh":"偵探試圖確立這起案件的事實。"}]},{"word":"estate","pos":"n.","phonetic":"[ɪˈstet]","meaning":"地產；財產；莊園","definition":"a large area of land with a house, or all a person's property","collocations":["real estate","country estate","family estate"],"example":"He inherited a large estate from his grandfather.","exampleZh":"他從祖父那裡繼承了一大片地產。","synonyms":["property","land"],"level":5,"theme":"商業與金錢","examples":[{"en":"He inherited a large estate from his grandfather.","zh":"他從祖父那裡繼承了一大片地產。"},{"en":"Prices in the real estate market have risen sharply.","zh":"房地產市場的價格大幅上漲。"},{"en":"The old family estate has been passed down for generations.","zh":"這座古老的家族莊園已經傳承了好幾代。"}]},{"word":"estimate","pos":"v. / n.","phonetic":"[ˈɛstəˌmet]","meaning":"估計；估算","definition":"to roughly calculate the value, number, or extent of something","collocations":["rough estimate","estimate the cost","give an estimate"],"example":"The builder gave us an estimate for the repairs.","exampleZh":"工人給了我們一份維修費用的估價。","synonyms":["calculate","guess"],"level":4,"theme":"商業與金錢","examples":[{"en":"The builder gave us an estimate for the repairs.","zh":"工人給了我們一份維修費用的估價。"},{"en":"Experts estimate that millions of people visit the park yearly.","zh":"專家估計每年有數百萬人參觀這座公園。"},{"en":"Can you give me a rough estimate of the repair cost?","zh":"你能給我一個修理費用的大概估算嗎？"}]},{"word":"ethnic","pos":"adj.","phonetic":"[ˈɛθnɪk]","meaning":"種族的；民族的","definition":"relating to a group of people who share a national, racial, or cultural identity","collocations":["ethnic group","ethnic minority","ethnic diversity"],"example":"The city is known for its ethnic diversity.","exampleZh":"這座城市以其種族多樣性聞名。","synonyms":["racial","cultural"],"level":5,"theme":"社會與文化","examples":[{"en":"The city is known for its ethnic diversity.","zh":"這座城市以其種族多樣性聞名。"},{"en":"The festival celebrates the traditions of many ethnic groups.","zh":"這個節慶頌揚許多民族的傳統。"},{"en":"The country is proud of its rich ethnic diversity.","zh":"這個國家為其豐富的種族多樣性感到自豪。"}]},{"word":"euro","pos":"n.","phonetic":"[ˈjʊro]","meaning":"歐元","definition":"the official currency of most countries in the European Union","collocations":["pay in euros","the euro exchange rate","a hundred euros"],"example":"He exchanged his dollars for euros before the trip.","exampleZh":"他在旅行前把美元換成了歐元。","synonyms":[],"level":3,"theme":"商業與金錢","examples":[{"en":"He exchanged his dollars for euros before the trip.","zh":"他在旅行前把美元換成了歐元。"},{"en":"The souvenir shop only accepts payment in euros.","zh":"這家紀念品店只接受歐元付款。"},{"en":"She checked the euro exchange rate before her trip to Europe.","zh":"她在歐洲旅行前查看了歐元的匯率。"}]},{"word":"evaluate","pos":"v.","phonetic":"[ɪˈvæljuˌet]","meaning":"評估；評鑑","definition":"to judge or determine the significance, worth, or quality of something","collocations":["evaluate performance","evaluate the results","carefully evaluated"],"example":"Teachers evaluate students' progress every semester.","exampleZh":"老師每學期都會評估學生的學習進度。","synonyms":["assess","judge"],"level":5,"theme":"教育與學習","examples":[{"en":"Teachers evaluate students' progress every semester.","zh":"老師每學期都會評估學生的學習進度。"},{"en":"The judges will evaluate each performance based on creativity.","zh":"評審會根據創意來評估每一場表演。"},{"en":"Scientists carefully evaluated the results of the experiment.","zh":"科學家仔細評估了實驗的結果。"}]},{"word":"eve","pos":"n.","phonetic":"[iv]","meaning":"前夕；前一天","definition":"the day or evening before an event or occasion","collocations":["Christmas Eve","on the eve of","New Year's Eve"],"example":"We always have a big dinner on Christmas Eve.","exampleZh":"我們每年聖誕夜都會吃一頓豐盛的晚餐。","synonyms":[],"level":3,"theme":"時間與空間","examples":[{"en":"We always have a big dinner on Christmas Eve.","zh":"我們每年聖誕夜都會吃一頓豐盛的晚餐。"},{"en":"On New Year's Eve, we watched fireworks light up the sky.","zh":"在除夕夜，我們看著煙火照亮天空。"},{"en":"The players felt nervous on the eve of the big match.","zh":"在大賽的前夕，球員們感到緊張。"}]},{"word":"even","pos":"adj. / adv.","phonetic":"[ˈivən]","meaning":"甚至；平坦的；偶數的","definition":"used to emphasize something surprising, or level and smooth","collocations":["even so","even number","even surface"],"example":"Even the teacher was surprised by his answer.","exampleZh":"甚至連老師都對他的答案感到驚訝。","synonyms":["level","flat"],"level":1,"theme":"抽象概念","examples":[{"en":"Even the teacher was surprised by his answer.","zh":"甚至連老師都對他的答案感到驚訝。"},{"en":"The road was smooth and even all the way to the village.","zh":"這條路一路平坦順暢直到村莊。"},{"en":"Two, four, and six are all even numbers.","zh":"二、四和六都是偶數。"}]},{"word":"evening","pos":"n.","phonetic":"[ˈivnɪŋ]","meaning":"傍晚；晚上","definition":"the period of time at the end of the day before night","collocations":["this evening","evening gown","every evening"],"example":"We usually watch TV together in the evening.","exampleZh":"我們通常在晚上一起看電視。","synonyms":[],"level":1,"theme":"時間與空間","examples":[{"en":"We usually watch TV together in the evening.","zh":"我們通常在晚上一起看電視。"},{"en":"The whole family takes a walk together every evening.","zh":"全家人每天傍晚一起散步。"},{"en":"She wore a beautiful evening gown to the party.","zh":"她穿著一件美麗的晚禮服去參加派對。"}]},{"word":"event","pos":"n.","phonetic":"[ɪˈvɛnt]","meaning":"事件；活動；賽事","definition":"a thing that happens, especially one of importance","collocations":["a special event","sporting event","in any event"],"example":"The school held a special event to celebrate the anniversary.","exampleZh":"學校舉辦了一場特別活動來慶祝周年紀念。","synonyms":["occasion","happening"],"level":2,"theme":"社會與文化","examples":[{"en":"The school held a special event to celebrate the anniversary.","zh":"學校舉辦了一場特別活動來慶祝周年紀念。"},{"en":"The whole town gathered for the annual sporting event.","zh":"全鎮的人聚集參加一年一度的體育賽事。"},{"en":"The wedding was the most special event of the year for them.","zh":"這場婚禮是他們那年最特別的活動。"}]},{"word":"eventually","pos":"adv.","phonetic":"[ɪˈvɛntʃuəli]","meaning":"最終；終於","definition":"in the end, especially after a long delay or series of events","collocations":["eventually succeed","eventually decided","will eventually"],"example":"After years of hard work, she eventually became a doctor.","exampleZh":"經過多年努力，她最終成為了一名醫生。","synonyms":["finally","ultimately"],"level":3,"theme":"時間與空間","examples":[{"en":"After years of hard work, she eventually became a doctor.","zh":"經過多年努力，她最終成為了一名醫生。"},{"en":"After many failures, the inventor eventually succeeded.","zh":"在多次失敗後，這位發明家最終成功了。"},{"en":"They argued for hours but eventually decided to compromise.","zh":"他們爭論了好幾個小時，但最終決定妥協。"}]},{"word":"ever","pos":"adv.","phonetic":"[ˈɛvɚ]","meaning":"曾經；究竟；永遠","definition":"at any time, used especially in questions and negatives","collocations":["ever since","hardly ever","best ever"],"example":"Have you ever been to Japan?","exampleZh":"你曾經去過日本嗎？","synonyms":[],"level":1,"theme":"時間與空間","examples":[{"en":"Have you ever been to Japan?","zh":"你曾經去過日本嗎？"},{"en":"This is the best meal I have ever tasted.","zh":"這是我嚐過最好吃的一餐。"},{"en":"He has loved music ever since he was a child.","zh":"他從小就一直熱愛音樂。"}]},{"word":"every","pos":"adj.","phonetic":"[ˈɛvri]","meaning":"每一個的","definition":"used to refer to all the individual members of a set without exception","collocations":["every day","every time","every single one"],"example":"She practices piano every day after school.","exampleZh":"她每天放學後都練習彈鋼琴。","synonyms":["each"],"level":1,"theme":"抽象概念","examples":[{"en":"She practices piano every day after school.","zh":"她每天放學後都練習彈鋼琴。"},{"en":"The bakery sells fresh bread every single day.","zh":"這家麵包店每一天都賣新鮮的麵包。"},{"en":"Every time it rains, the streets flood quickly.","zh":"每次下雨，街道很快就淹水。"}]},{"word":"evidence","pos":"n.","phonetic":"[ˈɛvədəns]","meaning":"證據；跡象","definition":"facts or information that show whether something is true","collocations":["strong evidence","lack of evidence","provide evidence"],"example":"The police found no evidence of a crime.","exampleZh":"警方沒有找到犯罪的證據。","synonyms":["proof"],"level":3,"theme":"政治與法律","examples":[{"en":"The police found no evidence of a crime.","zh":"警方沒有找到犯罪的證據。"},{"en":"There is strong evidence that exercise improves memory.","zh":"有強力的證據顯示運動能增進記憶力。"},{"en":"The suspect was released due to a lack of evidence.","zh":"由於缺乏證據，嫌疑人被釋放了。"}]},{"word":"evident","pos":"adj.","phonetic":"[ˈɛvədənt]","meaning":"明顯的；顯而易見的","definition":"clear and obvious to see or understand","collocations":["evident that","become evident","clearly evident"],"example":"It was evident that she had been crying.","exampleZh":"很明顯她剛剛哭過。","synonyms":["obvious","apparent"],"level":4,"theme":"抽象概念","examples":[{"en":"It was evident that she had been crying.","zh":"很明顯她剛剛哭過。"},{"en":"It soon became evident that the plan would not work.","zh":"很快就顯而易見，這個計劃行不通。"},{"en":"Her talent for painting was clearly evident from a young age.","zh":"她的繪畫天賦從小就顯而易見。"}]},{"word":"evil","pos":"adj. / n.","phonetic":"[ˈivl]","meaning":"邪惡的；罪惡","definition":"profoundly immoral and morally wrong, or wickedness itself","collocations":["evil spirit","the lesser of two evils","evil intentions"],"example":"In the story, the hero defeats the evil king.","exampleZh":"在故事中，英雄打敗了邪惡的國王。","synonyms":["wicked","sinister"],"level":3,"theme":"抽象概念","examples":[{"en":"In the story, the hero defeats the evil king.","zh":"在故事中，英雄打敗了邪惡的國王。"},{"en":"In the fairy tale, an evil witch cursed the princess.","zh":"在童話故事中，一個邪惡的女巫詛咒了公主。"},{"en":"He hid his evil intentions behind a friendly smile.","zh":"他把邪惡的意圖藏在友善的微笑背後。"}]},{"word":"evolution","pos":"n.","phonetic":"[ˌɛvəˈluʃən]","meaning":"演化；進化；發展","definition":"the gradual development of something, or the biological process of species change","collocations":["theory of evolution","human evolution","technological evolution"],"example":"Darwin's theory of evolution changed the way we see biology.","exampleZh":"達爾文的演化論改變了我們看待生物學的方式。","synonyms":["development"],"level":5,"theme":"科學與數學","examples":[{"en":"Darwin's theory of evolution changed the way we see biology.","zh":"達爾文的演化論改變了我們看待生物學的方式。"},{"en":"The museum has an exhibit about human evolution.","zh":"博物館有一個關於人類演化的展覽。"},{"en":"The rapid technological evolution has changed how we work.","zh":"快速的科技發展已經改變了我們工作的方式。"}]},{"word":"evolve","pos":"v.","phonetic":"[ɪˈvɑlv]","meaning":"演化；逐漸發展","definition":"to develop gradually, especially from a simple to a complex form","collocations":["evolve over time","evolve into","continue to evolve"],"example":"Language evolves as new words are created every year.","exampleZh":"語言隨著每年新詞的產生而不斷演化。","synonyms":["develop","progress"],"level":5,"theme":"科學與數學","examples":[{"en":"Language evolves as new words are created every year.","zh":"語言隨著每年新詞的產生而不斷演化。"},{"en":"The small shop gradually evolved into a large chain store.","zh":"這家小店逐漸發展成一家大型連鎖店。"},{"en":"Fashion styles continue to evolve with each generation.","zh":"時尚風格隨著每一代人不斷演變。"}]},{"word":"exact","pos":"adj.","phonetic":"[ɪgˈzækt]","meaning":"確切的；精確的","definition":"not approximated in any way; precise","collocations":["exact time","exact same","the exact opposite"],"example":"I don't know the exact time the train leaves.","exampleZh":"我不知道火車出發的確切時間。","synonyms":["precise","accurate"],"level":3,"theme":"性質與描述","examples":[{"en":"I don't know the exact time the train leaves.","zh":"我不知道火車出發的確切時間。"},{"en":"Can you tell me the exact time the movie starts?","zh":"你能告訴我電影確切的開演時間嗎？"},{"en":"The twins wore the exact same shirt to school today.","zh":"這對雙胞胎今天穿了一模一樣的襯衫上學。"}]},{"word":"exaggerate","pos":"v.","phonetic":"[ɪgˈzædʒəˌret]","meaning":"誇大；誇張","definition":"to represent something as being larger or more extreme than it really is","collocations":["exaggerate the truth","tend to exaggerate","don't exaggerate"],"example":"He always exaggerates when he tells stories.","exampleZh":"他講故事時總是誇大其詞。","synonyms":["overstate"],"level":4,"theme":"溝通與語言","examples":[{"en":"He always exaggerates when he tells stories.","zh":"他講故事時總是誇大其詞。"},{"en":"Don't exaggerate; the test wasn't nearly that difficult.","zh":"別誇張，那場考試根本沒那麼難。"},{"en":"Advertisements often exaggerate the benefits of a product.","zh":"廣告常常誇大產品的好處。"}]},{"word":"exam","pos":"n.","phonetic":"[ɪgˈzæm]","meaning":"考試","definition":"a formal test of knowledge or skill in a subject","collocations":["take an exam","pass an exam","final exam"],"example":"She studied hard for her math exam.","exampleZh":"她為數學考試認真讀書。","synonyms":["test","examination"],"level":1,"theme":"教育與學習","examples":[{"en":"She studied hard for her math exam.","zh":"她為數學考試認真讀書。"},{"en":"I need to review my notes before the final exam.","zh":"在期末考前我需要複習我的筆記。"},{"en":"She was thrilled to pass the difficult chemistry exam.","zh":"她很興奮通過了那場困難的化學考試。"}]},{"word":"examine","pos":"v.","phonetic":"[ɪgˈzæmɪn]","meaning":"檢查；審視；測驗","definition":"to inspect something carefully, or to test someone's knowledge","collocations":["examine closely","examine a patient","be examined on"],"example":"The doctor examined the patient's injured leg.","exampleZh":"醫生檢查了病人受傷的腿。","synonyms":["inspect","check"],"level":2,"theme":"身體與健康","examples":[{"en":"The doctor examined the patient's injured leg.","zh":"醫生檢查了病人受傷的腿。"},{"en":"The scientist examined the tiny insect under a microscope.","zh":"科學家在顯微鏡下仔細檢視這隻小昆蟲。"},{"en":"The nurse examined the child's throat carefully.","zh":"護士仔細檢查了孩子的喉嚨。"}]},{"word":"example","pos":"n.","phonetic":"[ɪgˈzæmpl]","meaning":"例子；榜樣","definition":"a thing that illustrates a general rule, or a model to be followed","collocations":["for example","set an example","a good example"],"example":"She always sets a good example for her younger siblings.","exampleZh":"她總是為弟妹樹立好榜樣。","synonyms":["instance","model"],"level":1,"theme":"抽象概念","examples":[{"en":"She always sets a good example for her younger siblings.","zh":"她總是為弟妹樹立好榜樣。"},{"en":"Parents should set a good example for their children.","zh":"父母應該為孩子樹立好榜樣。"},{"en":"Could you give me an example of how to use this word?","zh":"你能給我一個如何使用這個字的例子嗎？"}]},{"word":"exceed","pos":"v.","phonetic":"[ɪkˈsid]","meaning":"超過；超出","definition":"to go beyond what is allowed, expected, or possible","collocations":["exceed expectations","exceed the limit","exceed the budget"],"example":"Sales this quarter exceeded our expectations.","exampleZh":"這一季的銷售超出了我們的預期。","synonyms":["surpass","go beyond"],"level":4,"theme":"商業與金錢","examples":[{"en":"Sales this quarter exceeded our expectations.","zh":"這一季的銷售超出了我們的預期。"},{"en":"Drivers who exceed the speed limit will be fined.","zh":"超速的駕駛人將會被罰款。"},{"en":"The final results exceeded everyone's expectations.","zh":"最終的結果超出了所有人的預期。"}]},{"word":"excellent","pos":"adj.","phonetic":"[ˈɛksələnt]","meaning":"優秀的；傑出的","definition":"extremely good; outstanding","collocations":["excellent performance","excellent grades","an excellent idea"],"example":"She got excellent grades in every subject.","exampleZh":"她每一科都拿到了優異的成績。","synonyms":["outstanding","superb"],"level":1,"theme":"性質與描述","examples":[{"en":"She got excellent grades in every subject.","zh":"她每一科都拿到了優異的成績。"},{"en":"Going for a walk together is an excellent idea.","zh":"一起去散步是個很棒的主意。"},{"en":"The young pianist gave an excellent performance last night.","zh":"這位年輕的鋼琴家昨晚有精彩的演出。"}]},{"word":"fabric","pos":"n.","phonetic":"[ˈfæbrɪk]","meaning":"布料；織物；結構","definition":"cloth material made by weaving or knitting fibers","collocations":["cotton fabric","fabric softener","the fabric of society"],"example":"This dress is made of soft cotton fabric.","exampleZh":"這件洋裝是用柔軟的棉布做的。","synonyms":["cloth","textile"],"level":3,"theme":"服裝與外表","examples":[{"en":"This dress is made of soft cotton fabric.","zh":"這件洋裝是用柔軟的棉布做的。"},{"en":"She chose a soft cotton fabric to make the summer dress.","zh":"她挑選了柔軟的棉布來製作這件夏季洋裝。"},{"en":"Trust is an important part of the fabric of society.","zh":"信任是社會結構中重要的一部分。"}]},{"word":"fabricate","pos":"v.","phonetic":"[ˈfæbrɪˌket]","meaning":"捏造；虛構；製造","definition":"to invent false information in order to deceive someone, or to construct something","collocations":["fabricate a story","fabricate evidence","fabricate a device"],"example":"The reporter was fired for fabricating quotes in his article.","exampleZh":"那名記者因為在報導中捏造引言而被解雇。","synonyms":["invent","concoct"],"level":6,"theme":"溝通與語言","examples":[{"en":"The reporter was fired for fabricating quotes in his article.","zh":"那名記者因為在報導中捏造引言而被解雇。"},{"en":"The student fabricated an excuse for missing the class.","zh":"這名學生捏造了一個蹺課的藉口。"},{"en":"It is a serious crime to fabricate evidence in court.","zh":"在法庭上偽造證據是嚴重的罪行。"}]},{"word":"face","pos":"n. / v.","phonetic":"[fes]","meaning":"臉；面對；正視","definition":"the front part of the head; to confront a situation","collocations":["face to face","face the truth","face a challenge"],"example":"You have to face your problems, not avoid them.","exampleZh":"你必須面對你的問題，而不是逃避。","synonyms":["confront","countenance"],"level":1,"theme":"身體與健康","examples":[{"en":"You have to face your problems, not avoid them.","zh":"你必須面對你的問題，而不是逃避。"},{"en":"Sooner or later, you must face the truth about the situation.","zh":"你遲早得正視這個情況的真相。"},{"en":"The two old friends finally met face to face after years.","zh":"這兩位老友在多年後終於面對面相見。"}]},{"word":"facilitate","pos":"v.","phonetic":"[fəˈsɪləˌtet]","meaning":"促進；使便利","definition":"to make an action or process easier","collocations":["facilitate communication","facilitate learning","facilitate trade"],"example":"The new software facilitates cooperation among team members.","exampleZh":"這套新軟體促進了團隊成員之間的合作。","synonyms":["ease","enable"],"level":6,"theme":"抽象概念","examples":[{"en":"The new software facilitates cooperation among team members.","zh":"這套新軟體促進了團隊成員之間的合作。"},{"en":"Group activities can facilitate learning in the classroom.","zh":"小組活動可以促進課堂上的學習。"},{"en":"The new bridge will facilitate trade between the two towns.","zh":"這座新橋將促進兩鎮之間的貿易。"}]},{"word":"facility","pos":"n.","phonetic":"[fəˈsɪlətɪ]","meaning":"設施；才能","definition":"a building or equipment provided for a purpose","collocations":["sports facility","medical facility","storage facility"],"example":"The school built a new sports facility for students.","exampleZh":"學校為學生蓋了一座新的運動設施。","synonyms":["amenity","installation"],"level":4,"theme":"居家與生活","examples":[{"en":"The school built a new sports facility for students.","zh":"學校為學生蓋了一座新的運動設施。"},{"en":"The town built a modern medical facility for its residents.","zh":"鎮上為居民建造了一座現代化的醫療設施。"},{"en":"The new library is a bright and comfortable facility.","zh":"這座新圖書館是個明亮又舒適的設施。"}]},{"word":"fact","pos":"n.","phonetic":"[fækt]","meaning":"事實；實情","definition":"a thing that is known or proved to be true","collocations":["in fact","a known fact","fact and fiction"],"example":"It is a fact that the earth revolves around the sun.","exampleZh":"地球繞著太陽運轉是個事實。","synonyms":["truth","reality"],"level":1,"theme":"抽象概念","examples":[{"en":"It is a fact that the earth revolves around the sun.","zh":"地球繞著太陽運轉是個事實。"},{"en":"It is a known fact that plants need sunlight to grow.","zh":"植物需要陽光才能生長是眾所周知的事實。"},{"en":"The movie mixes historical fact and fiction cleverly.","zh":"這部電影巧妙地融合了歷史事實與虛構。"}]},{"word":"factor","pos":"n.","phonetic":"[ˈfæktɚ]","meaning":"因素；要素","definition":"a circumstance that contributes to a result","collocations":["key factor","risk factor","contributing factor"],"example":"Price is an important factor when buying a car.","exampleZh":"價格是買車時的重要因素。","synonyms":["element","component"],"level":3,"theme":"抽象概念","examples":[{"en":"Price is an important factor when buying a car.","zh":"價格是買車時的重要因素。"},{"en":"Hard work is a key factor in her success.","zh":"努力是她成功的關鍵因素。"},{"en":"Smoking is a major risk factor for many diseases.","zh":"吸菸是許多疾病的主要風險因素。"}]},{"word":"factory","pos":"n.","phonetic":"[ˈfæktərɪ]","meaning":"工廠","definition":"a building where goods are manufactured","collocations":["car factory","factory worker","run a factory"],"example":"My father works in a shoe factory.","exampleZh":"我爸爸在一家製鞋工廠工作。","synonyms":["plant","mill"],"level":2,"theme":"工作與職業","examples":[{"en":"My father works in a shoe factory.","zh":"我爸爸在一家製鞋工廠工作。"},{"en":"The new car factory will create hundreds of jobs.","zh":"這座新的汽車工廠將創造數百個工作機會。"},{"en":"The factory workers take a break at noon every day.","zh":"工廠工人每天中午休息。"}]},{"word":"faculty","pos":"n.","phonetic":"[ˈfækəltɪ]","meaning":"能力；才能；（大學的）院系、全體教師","definition":"a natural ability, or the teaching staff of a school or department","collocations":["mental faculty","faculty member","the faculty of arts"],"example":"He lost the faculty of speech after the accident.","exampleZh":"意外發生後，他喪失了說話的能力。","synonyms":["ability","staff"],"level":5,"theme":"教育與學習","examples":[{"en":"He lost the faculty of speech after the accident.","zh":"意外發生後，他喪失了說話的能力。"},{"en":"Every faculty member attended the important staff meeting.","zh":"每位教職員都出席了這場重要的教職員會議。"},{"en":"Reading regularly keeps your mental faculties sharp.","zh":"規律地閱讀能讓你的心智能力保持敏銳。"}]},{"word":"fad","pos":"n.","phonetic":"[fæd]","meaning":"一時的流行；風潮","definition":"an intense but short-lived fashion or interest","collocations":["a passing fad","a diet fad","follow a fad"],"example":"Bubble tea was once dismissed as just a fad, but it's still popular today.","exampleZh":"珍珠奶茶曾被視為一時流行，但至今仍很受歡迎。","synonyms":["craze","trend"],"level":4,"theme":"社會與文化","examples":[{"en":"Bubble tea was once dismissed as just a fad, but it's still popular today.","zh":"珍珠奶茶曾被視為一時流行，但至今仍很受歡迎。"},{"en":"Many people worried the electric scooter was just a passing fad.","zh":"許多人擔心電動滑板車只是一時的流行。"},{"en":"She never follows a diet fad without asking her doctor first.","zh":"她從不在沒先問醫生的情況下追隨減肥風潮。"}]},{"word":"fade","pos":"v.","phonetic":"[fed]","meaning":"褪色；逐漸消失","definition":"to gradually lose color, strength, or clarity","collocations":["fade away","colors fade","fade into the background"],"example":"The bright red curtains had faded in the sun.","exampleZh":"鮮紅色的窗簾在陽光下已經褪色了。","synonyms":["dim","vanish"],"level":3,"theme":"性質與描述","examples":[{"en":"The bright red curtains had faded in the sun.","zh":"鮮紅色的窗簾在陽光下已經褪色了。"},{"en":"The old poster's colors had faded after years in the sun.","zh":"這張舊海報的顏色在陽光下曬了多年後已經褪色。"},{"en":"The sound of the music slowly faded away.","zh":"音樂的聲音慢慢地消失了。"}]},{"word":"fail","pos":"v.","phonetic":"[fel]","meaning":"失敗；不及格","definition":"to be unsuccessful in achieving a goal","collocations":["fail an exam","fail to do something","fail miserably"],"example":"He failed the math test and had to retake it.","exampleZh":"他數學考試不及格，必須重考。","synonyms":["flunk","lose"],"level":2,"theme":"教育與學習","examples":[{"en":"He failed the math test and had to retake it.","zh":"他數學考試不及格，必須重考。"},{"en":"If you don't study, you might fail the history exam.","zh":"如果你不讀書，可能會歷史考試不及格。"},{"en":"He failed to arrive on time because of the heavy traffic.","zh":"由於嚴重的交通堵塞，他未能準時抵達。"}]},{"word":"failure","pos":"n.","phonetic":"[ˈfeljɚ]","meaning":"失敗；故障","definition":"lack of success; the state of not functioning","collocations":["heart failure","failure to comply","end in failure"],"example":"Fear of failure stopped her from trying new things.","exampleZh":"害怕失敗使她不敢嘗試新事物。","synonyms":["defeat","breakdown"],"level":3,"theme":"抽象概念","examples":[{"en":"Fear of failure stopped her from trying new things.","zh":"害怕失敗使她不敢嘗試新事物。"},{"en":"Every failure taught her a valuable lesson about life.","zh":"每一次失敗都教會她關於人生寶貴的一課。"},{"en":"The experiment ended in failure, but the team didn't give up.","zh":"實驗以失敗告終，但團隊並未放棄。"}]},{"word":"faint","pos":"adj. / v.","phonetic":"[fent]","meaning":"微弱的；暈倒","definition":"barely perceptible; to lose consciousness briefly","collocations":["faint smell","faint hope","faint from heat"],"example":"She felt faint from the heat and had to sit down.","exampleZh":"她因為太熱而感到頭暈，只好坐下來。","synonyms":["dim","pass out"],"level":4,"theme":"身體與健康","examples":[{"en":"She felt faint from the heat and had to sit down.","zh":"她因為太熱而感到頭暈，只好坐下來。"},{"en":"There was a faint smell of coffee coming from the kitchen.","zh":"廚房傳來一股淡淡的咖啡香。"},{"en":"The runner nearly fainted from the extreme heat.","zh":"這名跑者因為酷熱幾乎昏了過去。"}]},{"word":"fair","pos":"adj. / n.","phonetic":"[fɛr]","meaning":"公平的；園遊會","definition":"treating people equally; a public event with entertainment","collocations":["fair play","science fair","fair chance"],"example":"The teacher tried to be fair to all the students.","exampleZh":"老師努力對所有學生都公平。","synonyms":["just","impartial"],"level":2,"theme":"性質與描述","examples":[{"en":"The teacher tried to be fair to all the students.","zh":"老師努力對所有學生都公平。"},{"en":"Everyone deserves a fair chance to prove their ability.","zh":"每個人都應該有公平的機會來證明自己的能力。"},{"en":"Her science fair project won an award for its creativity.","zh":"她的科展作品因其創意而獲獎。"}]},{"word":"fairy","pos":"n.","phonetic":"[ˈfɛrɪ]","meaning":"仙女；小精靈","definition":"a small imaginary magical being in stories","collocations":["fairy tale","tooth fairy","fairy godmother"],"example":"Children love reading fairy tales before bed.","exampleZh":"孩子們喜歡在睡前讀童話故事。","synonyms":["sprite","pixie"],"level":2,"theme":"藝術與音樂","examples":[{"en":"Children love reading fairy tales before bed.","zh":"孩子們喜歡在睡前讀童話故事。"},{"en":"The little girl believes the tooth fairy leaves coins at night.","zh":"小女孩相信牙仙會在夜裡留下硬幣。"},{"en":"In the fairy tale, a kind fairy grants the girl three wishes.","zh":"在這則童話中，一位善良的仙女實現了女孩的三個願望。"}]},{"word":"faith","pos":"n.","phonetic":"[feθ]","meaning":"信念；信任；信仰","definition":"complete trust or confidence in someone or something","collocations":["have faith in","lose faith","religious faith"],"example":"I have faith in your ability to solve this problem.","exampleZh":"我對你解決這個問題的能力有信心。","synonyms":["trust","belief"],"level":3,"theme":"抽象概念","examples":[{"en":"I have faith in your ability to solve this problem.","zh":"我對你解決這個問題的能力有信心。"},{"en":"Even after the loss, the coach never lost faith in his team.","zh":"即使在落敗之後，教練也從未對他的球隊失去信心。"},{"en":"Her religious faith gives her strength during hard times.","zh":"她的宗教信仰在艱難時給予她力量。"}]},{"word":"fake","pos":"adj. / v. / n.","phonetic":"[fek]","meaning":"假的；偽造","definition":"not genuine; imitation of something real","collocations":["fake news","fake smile","fake a signature"],"example":"She bought a fake designer bag at the market.","exampleZh":"她在市場買了一個假的名牌包。","synonyms":["false","counterfeit"],"level":3,"theme":"性質與描述","examples":[{"en":"She bought a fake designer bag at the market.","zh":"她在市場買了一個假的名牌包。"},{"en":"Be careful not to share fake news on social media.","zh":"小心不要在社群媒體上分享假新聞。"},{"en":"He gave a fake smile to hide his disappointment.","zh":"他擠出假笑來掩飾失望。"}]},{"word":"fall","pos":"v. / n.","phonetic":"[fɔl]","meaning":"落下；跌倒；秋天","definition":"to drop down; the season of autumn","collocations":["fall down","fall in love","fall asleep"],"example":"The leaves fall from the trees in autumn.","exampleZh":"秋天樹葉會從樹上掉落。","synonyms":["drop","tumble"],"level":1,"theme":"天氣與季節","examples":[{"en":"The leaves fall from the trees in autumn.","zh":"秋天樹葉會從樹上掉落。"},{"en":"Be careful not to fall down on the slippery floor.","zh":"小心別在滑溜的地板上跌倒。"},{"en":"The tired child fell asleep during the car ride home.","zh":"疲倦的孩子在回家的車上睡著了。"}]},{"word":"false","pos":"adj.","phonetic":"[fɔls]","meaning":"錯誤的；虛假的","definition":"not true or correct; deliberately deceptive","collocations":["true or false","false alarm","false teeth"],"example":"The statement turned out to be completely false.","exampleZh":"這個說法結果完全是錯誤的。","synonyms":["untrue","wrong"],"level":2,"theme":"性質與描述","examples":[{"en":"The statement turned out to be completely false.","zh":"這個說法結果完全是錯誤的。"},{"en":"The fire turned out to be a false alarm, luckily.","zh":"幸運的是，那場火警結果只是虛驚一場。"},{"en":"Decide whether each of the following statements is true or false.","zh":"判斷以下每個句子是對還是錯。"}]},{"word":"falter","pos":"v.","phonetic":"[ˈfɔltɚ]","meaning":"猶豫；動搖；顫抖","definition":"to lose strength or momentum, or to speak hesitantly","collocations":["falter in one's voice","the economy falters","falter under pressure"],"example":"Her voice faltered as she read the sad news aloud.","exampleZh":"她唸出這則悲傷的消息時聲音顫抖了。","synonyms":["hesitate","waver"],"level":5,"theme":"情緒與感受","examples":[{"en":"Her voice faltered as she read the sad news aloud.","zh":"她唸出這則悲傷的消息時聲音顫抖了。"},{"en":"The young speaker began to falter under the audience's gaze.","zh":"這位年輕的演講者在觀眾的注視下開始語塞。"},{"en":"Her confidence never faltered, even during the toughest games.","zh":"即使在最艱難的比賽中，她的信心也從未動搖。"}]},{"word":"fame","pos":"n.","phonetic":"[fem]","meaning":"名聲；名望","definition":"the state of being known by many people","collocations":["rise to fame","gain fame","fame and fortune"],"example":"The singer achieved worldwide fame overnight.","exampleZh":"這位歌手一夕之間獲得全球知名度。","synonyms":["renown","celebrity"],"level":4,"theme":"社會與文化","examples":[{"en":"The singer achieved worldwide fame overnight.","zh":"這位歌手一夕之間獲得全球知名度。"},{"en":"The young actor rose to fame after his first movie.","zh":"這位年輕演員在他的第一部電影後聲名大噪。"},{"en":"She cared more about her art than about fame and fortune.","zh":"比起名利，她更在乎她的藝術。"}]},{"word":"familiar","pos":"adj.","phonetic":"[fəˈmɪljɚ]","meaning":"熟悉的","definition":"well known from frequent exposure","collocations":["familiar face","familiar with","sound familiar"],"example":"This song sounds familiar to me.","exampleZh":"這首歌聽起來很耳熟。","synonyms":["known","acquainted"],"level":3,"theme":"性質與描述","examples":[{"en":"This song sounds familiar to me.","zh":"這首歌聽起來很耳熟。"},{"en":"It was nice to see a familiar face in the crowd.","zh":"在人群中看到一張熟悉的臉真好。"},{"en":"Are you familiar with the rules of this board game?","zh":"你熟悉這個桌遊的規則嗎？"}]},{"word":"family","pos":"n.","phonetic":"[ˈfæməlɪ]","meaning":"家庭；家人","definition":"a group of parents and children living together","collocations":["family member","family gathering","immediate family"],"example":"We have a big family reunion every Chinese New Year.","exampleZh":"我們每年農曆新年都有一場盛大的家庭聚會。","synonyms":["household","kin"],"level":1,"theme":"人物與家庭","examples":[{"en":"We have a big family reunion every Chinese New Year.","zh":"我們每年農曆新年都有一場盛大的家庭聚會。"},{"en":"Every family member helped to prepare the holiday dinner.","zh":"每位家庭成員都幫忙準備節日的晚餐。"},{"en":"We hold a big family gathering every summer.","zh":"我們每年夏天都會舉辦一場盛大的家庭聚會。"}]},{"word":"famine","pos":"n.","phonetic":"[ˈfæmɪn]","meaning":"飢荒","definition":"extreme scarcity of food in a region","collocations":["severe famine","famine relief","cause a famine"],"example":"The drought led to a terrible famine in the region.","exampleZh":"乾旱導致該地區發生嚴重的飢荒。","synonyms":["hunger","starvation"],"level":5,"theme":"社會與文化","examples":[{"en":"The drought led to a terrible famine in the region.","zh":"乾旱導致該地區發生嚴重的飢荒。"},{"en":"The long drought caused a severe famine across the land.","zh":"長期的乾旱在這片土地上引發了嚴重的飢荒。"},{"en":"Volunteers collected food and money for famine relief.","zh":"志工們為飢荒救濟募集了食物和金錢。"}]},{"word":"famous","pos":"adj.","phonetic":"[ˈfeməs]","meaning":"有名的；著名的","definition":"known about by many people","collocations":["famous for","world-famous","become famous"],"example":"Taiwan is famous for its night markets.","exampleZh":"台灣以夜市聞名。","synonyms":["renowned","celebrated"],"level":1,"theme":"社會與文化","examples":[{"en":"Taiwan is famous for its night markets.","zh":"台灣以夜市聞名。"},{"en":"This small town is famous for its delicious dumplings.","zh":"這座小鎮以美味的水餃聞名。"},{"en":"He became famous after winning the international piano competition.","zh":"他在贏得國際鋼琴比賽後成名了。"}]},{"word":"fan","pos":"n.","phonetic":"[fæn]","meaning":"風扇；迷；粉絲","definition":"a device for creating air movement; an enthusiastic admirer","collocations":["electric fan","sports fan","fan club"],"example":"She is a huge fan of that pop singer.","exampleZh":"她是那位流行歌手的超級粉絲。","synonyms":["admirer","supporter"],"level":1,"theme":"運動與休閒","examples":[{"en":"She is a huge fan of that pop singer.","zh":"她是那位流行歌手的超級粉絲。"},{"en":"On hot days, we turn on the electric fan to stay cool.","zh":"炎熱的日子裡，我們開電風扇來保持涼爽。"},{"en":"As a loyal sports fan, he never misses a home game.","zh":"身為忠實的運動迷，他從不錯過任何一場主場比賽。"}]},{"word":"fancy","pos":"adj. / v.","phonetic":"[ˈfænsɪ]","meaning":"花俏的；喜歡；想要","definition":"elaborate or expensive in style; to feel a liking for","collocations":["fancy restaurant","fancy dress","fancy that"],"example":"We went to a fancy restaurant for our anniversary.","exampleZh":"我們去一家高級餐廳慶祝結婚紀念日。","synonyms":["elaborate","stylish"],"level":3,"theme":"性質與描述","examples":[{"en":"We went to a fancy restaurant for our anniversary.","zh":"我們去一家高級餐廳慶祝結婚紀念日。"},{"en":"They celebrated their anniversary at a fancy restaurant downtown.","zh":"他們在市中心一家高級餐廳慶祝結婚週年。"},{"en":"Do you fancy a cup of tea after the long walk?","zh":"走了這麼久，你想來杯茶嗎？"}]},{"word":"fantastic","pos":"adj.","phonetic":"[fænˈtæstɪk]","meaning":"極好的；奇異的","definition":"extremely good or attractive; imaginative and strange","collocations":["fantastic idea","look fantastic","fantastic news"],"example":"We had a fantastic time at the beach.","exampleZh":"我們在海灘玩得非常愉快。","synonyms":["wonderful","amazing"],"level":2,"theme":"情緒與感受","examples":[{"en":"We had a fantastic time at the beach.","zh":"我們在海灘玩得非常愉快。"},{"en":"Starting a book club sounds like a fantastic idea.","zh":"成立讀書會聽起來是個很棒的主意。"},{"en":"You look fantastic in that new blue jacket.","zh":"你穿那件新的藍色外套看起來棒極了。"}]},{"word":"fantasy","pos":"n.","phonetic":"[ˈfæntəsɪ]","meaning":"幻想；奇幻小說","definition":"imaginative fiction involving magical elements","collocations":["fantasy novel","live in fantasy","fantasy world"],"example":"He loves reading fantasy novels about dragons and magic.","exampleZh":"他喜歡讀關於龍與魔法的奇幻小說。","synonyms":["imagination","daydream"],"level":4,"theme":"藝術與音樂","examples":[{"en":"He loves reading fantasy novels about dragons and magic.","zh":"他喜歡讀關於龍與魔法的奇幻小說。"},{"en":"He escapes into a fantasy world whenever he reads a novel.","zh":"每當他讀小說時，就逃進一個奇幻的世界裡。"},{"en":"The author is famous for her exciting fantasy novels.","zh":"這位作者以她精彩的奇幻小說聞名。"}]},{"word":"far","pos":"adv. / adj.","phonetic":"[fɑr]","meaning":"遙遠地；遠的","definition":"at, to, or by a great distance","collocations":["far away","so far","as far as"],"example":"The train station is not far from here.","exampleZh":"火車站離這裡不遠。","synonyms":["distant","remote"],"level":1,"theme":"時間與空間","examples":[{"en":"The train station is not far from here.","zh":"火車站離這裡不遠。"},{"en":"The mountains looked beautiful, though they were far away.","zh":"那些山看起來很美，雖然它們離得很遠。"},{"en":"So far, everything about the trip has gone smoothly.","zh":"到目前為止，這趟旅行的一切都很順利。"}]},{"word":"farm","pos":"n. / v.","phonetic":"[fɑrm]","meaning":"農場；耕種","definition":"land used for growing crops or raising animals","collocations":["farm animal","farm crops","organic farm"],"example":"My grandparents own a small farm in the countryside.","exampleZh":"我祖父母在鄉下擁有一座小農場。","synonyms":["ranch","cultivate"],"level":1,"theme":"自然與環境","examples":[{"en":"My grandparents own a small farm in the countryside.","zh":"我祖父母在鄉下擁有一座小農場。"},{"en":"The children learned to feed the farm animals during the visit.","zh":"孩子們在參觀期間學會了餵農場的動物。"},{"en":"This organic farm grows vegetables without any chemicals.","zh":"這座有機農場種植不含任何化學物質的蔬菜。"}]},{"word":"farmer","pos":"n.","phonetic":"[ˈfɑrmɚ]","meaning":"農夫","definition":"a person who owns or manages a farm","collocations":["local farmer","farmer's market","hardworking farmer"],"example":"The farmer harvested the rice in early autumn.","exampleZh":"農夫在初秋時收割稻米。","synonyms":["grower","cultivator"],"level":1,"theme":"工作與職業","examples":[{"en":"The farmer harvested the rice in early autumn.","zh":"農夫在初秋時收割稻米。"},{"en":"Every Saturday, we buy fresh fruit at the farmer's market.","zh":"每個星期六，我們在農夫市集買新鮮的水果。"},{"en":"The hardworking farmer wakes up before sunrise every day.","zh":"這位勤勞的農夫每天在日出前起床。"}]},{"word":"fascinate","pos":"v.","phonetic":"[ˈfæsəˌnet]","meaning":"使著迷；使入迷","definition":"to attract and hold the attention of someone strongly","collocations":["fascinate the audience","fascinated by","fascinating story"],"example":"The magic show fascinated all the children.","exampleZh":"那場魔術表演讓所有孩子都著迷了。","synonyms":["captivate","enchant"],"level":4,"theme":"情緒與感受","examples":[{"en":"The magic show fascinated all the children.","zh":"那場魔術表演讓所有孩子都著迷了。"},{"en":"The story of ancient Egypt has always fascinated me.","zh":"古埃及的故事一直讓我著迷。"},{"en":"The dolphins' clever tricks fascinated everyone at the show.","zh":"海豚聰明的把戲讓表演現場的每個人都著迷。"}]},{"word":"fashion","pos":"n.","phonetic":"[ˈfæʃən]","meaning":"流行；時尚","definition":"a popular trend in clothing or style","collocations":["fashion show","in fashion","fashion designer"],"example":"She works as a fashion designer in Paris.","exampleZh":"她在巴黎擔任時裝設計師。","synonyms":["trend","style"],"level":3,"theme":"服裝與外表","examples":[{"en":"She works as a fashion designer in Paris.","zh":"她在巴黎擔任時裝設計師。"},{"en":"Bright colors are in fashion this spring.","zh":"鮮豔的顏色是今年春天的流行。"},{"en":"She attended a fashion show to see the newest designs.","zh":"她參加了一場時裝秀，觀賞最新的設計。"}]},{"word":"fast","pos":"adj. / adv. / v.","phonetic":"[fæst]","meaning":"快的；快速地；禁食","definition":"moving or capable of moving quickly; to abstain from food","collocations":["fast food","fast asleep","run fast"],"example":"He can run very fast for his age.","exampleZh":"以他的年紀來說，他跑得非常快。","synonyms":["quick","rapid"],"level":1,"theme":"性質與描述","examples":[{"en":"He can run very fast for his age.","zh":"以他的年紀來說，他跑得非常快。"},{"en":"Eating too much fast food is not good for your health.","zh":"吃太多速食對你的健康不好。"},{"en":"By nine o'clock, the baby was already fast asleep.","zh":"到了九點，寶寶已經熟睡了。"}]},{"word":"fasten","pos":"v.","phonetic":"[ˈfæsn̩]","meaning":"繫緊；固定","definition":"to close or attach something firmly","collocations":["fasten a seatbelt","fasten a button","fasten together"],"example":"Please fasten your seatbelt before takeoff.","exampleZh":"起飛前請繫好安全帶。","synonyms":["secure","attach"],"level":3,"theme":"動作與行為","examples":[{"en":"Please fasten your seatbelt before takeoff.","zh":"起飛前請繫好安全帶。"},{"en":"Remember to fasten your seatbelt before the car moves.","zh":"在車子開動前記得繫好安全帶。"},{"en":"She fastened the top button of her coat against the cold wind.","zh":"她扣上外套最上面的鈕扣以抵擋冷風。"}]},{"word":"fat","pos":"adj. / n.","phonetic":"[fæt]","meaning":"肥胖的；脂肪","definition":"having too much body weight; the greasy substance in food","collocations":["low fat","fat content","get fat"],"example":"Too much fried food can make you fat.","exampleZh":"吃太多油炸食物會讓你變胖。","synonyms":["overweight","plump"],"level":1,"theme":"身體與健康","examples":[{"en":"Too much fried food can make you fat.","zh":"吃太多油炸食物會讓你變胖。"},{"en":"This milk is a healthy low fat choice for breakfast.","zh":"這種牛奶是早餐健康的低脂選擇。"},{"en":"Eating too many sweets can make you gain fat.","zh":"吃太多甜食會讓你增加脂肪。"}]},{"word":"fatal","pos":"adj.","phonetic":"[ˈfetl̩]","meaning":"致命的","definition":"causing or capable of causing death","collocations":["fatal accident","fatal mistake","fatal disease"],"example":"The car crash resulted in a fatal injury.","exampleZh":"那場車禍造成了致命的傷害。","synonyms":["deadly","lethal"],"level":5,"theme":"身體與健康","examples":[{"en":"The car crash resulted in a fatal injury.","zh":"那場車禍造成了致命的傷害。"},{"en":"Ignoring the warning signs could be a fatal mistake.","zh":"忽視這些警告標誌可能是個致命的錯誤。"},{"en":"Doctors worked hard to cure the once fatal disease.","zh":"醫生們努力治療這種曾經致命的疾病。"}]},{"word":"fate","pos":"n.","phonetic":"[fet]","meaning":"命運","definition":"the development of events beyond a person's control","collocations":["decide one's fate","cruel fate","fate and destiny"],"example":"He believes fate brought them together.","exampleZh":"他相信是命運讓他們相遇。","synonyms":["destiny","fortune"],"level":4,"theme":"抽象概念","examples":[{"en":"He believes fate brought them together.","zh":"他相信是命運讓他們相遇。"},{"en":"The judge's decision would decide the prisoner's fate.","zh":"法官的判決將決定這名囚犯的命運。"},{"en":"By a cruel fate, the letter arrived one day too late.","zh":"由於殘酷的命運，那封信晚了一天才到。"}]},{"word":"father","pos":"n.","phonetic":"[ˈfɑðɚ]","meaning":"父親","definition":"a male parent","collocations":["father figure","single father","father-in-law"],"example":"My father taught me how to ride a bike.","exampleZh":"我爸爸教我怎麼騎腳踏車。","synonyms":["dad","papa"],"level":1,"theme":"人物與家庭","examples":[{"en":"My father taught me how to ride a bike.","zh":"我爸爸教我怎麼騎腳踏車。"},{"en":"His uncle became a father figure to him after the loss.","zh":"在失去親人後，他的叔叔成了他父親般的角色。"},{"en":"As a single father, he raised three children on his own.","zh":"身為單親父親，他獨自扶養三個孩子。"}]},{"word":"fatigue","pos":"n.","phonetic":"[fəˈtiɡ]","meaning":"疲勞；疲乏","definition":"extreme tiredness resulting from physical or mental effort","collocations":["suffer from fatigue","mental fatigue","fatigue sets in"],"example":"Long hours at the computer left him with severe eye fatigue.","exampleZh":"長時間使用電腦讓他的眼睛非常疲勞。","synonyms":["exhaustion","tiredness"],"level":5,"theme":"身體與健康","examples":[{"en":"Long hours at the computer left him with severe eye fatigue.","zh":"長時間使用電腦讓他的眼睛非常疲勞。"},{"en":"After the long hike, fatigue set in and everyone rested.","zh":"長途健行後，疲勞來襲，大家都休息了。"},{"en":"Studying all night led to serious mental fatigue.","zh":"整夜讀書導致了嚴重的精神疲勞。"}]},{"word":"faucet","pos":"n.","phonetic":"[ˈfɔsɪt]","meaning":"水龍頭","definition":"a device that controls the flow of water from a pipe","collocations":["turn on the faucet","a leaky faucet","fix the faucet"],"example":"Please remember to turn off the faucet after washing dishes.","exampleZh":"洗完碗後請記得把水龍頭關上。","synonyms":["tap"],"level":3,"theme":"居家與生活","examples":[{"en":"Please remember to turn off the faucet after washing dishes.","zh":"洗完碗後請記得把水龍頭關上。"},{"en":"A leaky faucet can waste a lot of water over time.","zh":"漏水的水龍頭久而久之會浪費很多水。"},{"en":"He turned on the faucet to fill the glass with water.","zh":"他打開水龍頭，把杯子裝滿水。"}]},{"word":"fault","pos":"n.","phonetic":"[fɔlt]","meaning":"過錯；缺點","definition":"responsibility for a mistake; a flaw or defect","collocations":["my fault","find fault","fault line"],"example":"It's not your fault that the plan failed.","exampleZh":"計畫失敗不是你的錯。","synonyms":["blame","flaw"],"level":3,"theme":"抽象概念","examples":[{"en":"It's not your fault that the plan failed.","zh":"計畫失敗不是你的錯。"},{"en":"The accident was nobody's fault; it was just bad luck.","zh":"這場意外不是任何人的錯，只是運氣不好。"},{"en":"She always finds fault with other people's work.","zh":"她總是挑剔別人的工作。"}]},{"word":"favor","pos":"n. / v.","phonetic":"[ˈfevɚ]","meaning":"恩惠；偏愛","definition":"an act of kindness; to prefer one thing over another","collocations":["do a favor","in favor of","favor one option"],"example":"Could you do me a favor and open the door?","exampleZh":"你可以幫我一個忙，把門打開嗎？","synonyms":["kindness","preference"],"level":3,"theme":"溝通與語言","examples":[{"en":"Could you do me a favor and open the door?","zh":"你可以幫我一個忙，把門打開嗎？"},{"en":"Could you do me a favor and water my plants this weekend?","zh":"你能幫我個忙，這週末幫我澆花嗎？"},{"en":"Most students were in favor of the new class schedule.","zh":"大多數學生都贊成新的課程表。"}]},{"word":"favorable","pos":"adj.","phonetic":"[ˈfevərəbḷ]","meaning":"有利的；贊同的","definition":"advantageous or showing approval","collocations":["favorable conditions","a favorable impression","favorable terms"],"example":"The weather forecast is favorable for our weekend trip.","exampleZh":"天氣預報顯示這個週末很適合出遊。","synonyms":["positive","advantageous"],"level":4,"theme":"性質與描述","examples":[{"en":"The weather forecast is favorable for our weekend trip.","zh":"天氣預報顯示這個週末很適合出遊。"},{"en":"The warm weather created favorable conditions for the picnic.","zh":"溫暖的天氣為野餐創造了有利的條件。"},{"en":"Her polite manners made a favorable impression on the guests.","zh":"她有禮的舉止給客人留下了良好的印象。"}]},{"word":"favorite","pos":"adj. / n.","phonetic":"[ˈfevərɪt]","meaning":"最喜愛的","definition":"preferred above all others","collocations":["favorite color","favorite food","personal favorite"],"example":"Pizza is my favorite food.","exampleZh":"披薩是我最喜歡的食物。","synonyms":["preferred","beloved"],"level":1,"theme":"食物與烹飪","examples":[{"en":"Pizza is my favorite food.","zh":"披薩是我最喜歡的食物。"},{"en":"Blue has always been my favorite color since childhood.","zh":"藍色從小就一直是我最喜歡的顏色。"},{"en":"Of all the songs, this one is my personal favorite.","zh":"在所有的歌曲中，這首是我個人的最愛。"}]},{"word":"fear","pos":"n. / v.","phonetic":"[fɪr]","meaning":"恐懼；害怕","definition":"an unpleasant emotion caused by a threat","collocations":["fear of heights","live in fear","fear the worst"],"example":"She has a fear of spiders.","exampleZh":"她害怕蜘蛛。","synonyms":["fright","dread"],"level":2,"theme":"情緒與感受","examples":[{"en":"She has a fear of spiders.","zh":"她害怕蜘蛛。"},{"en":"His fear of heights kept him from climbing the tower.","zh":"他懼高，因此不敢爬上那座塔。"},{"en":"When the phone rang late at night, she feared the worst.","zh":"當電話在深夜響起時，她擔心會有最壞的消息。"}]},{"word":"feasible","pos":"adj.","phonetic":"[ˈfizəbḷ]","meaning":"可行的；行得通的","definition":"capable of being done or carried out","collocations":["a feasible plan","economically feasible","feasible solution"],"example":"Is it feasible to finish the project by Friday?","exampleZh":"這個計畫有可能在星期五前完成嗎？","synonyms":["practical","viable"],"level":5,"theme":"抽象概念","examples":[{"en":"Is it feasible to finish the project by Friday?","zh":"這個計畫有可能在星期五前完成嗎？"},{"en":"The engineers presented a feasible plan to build the tunnel.","zh":"工程師們提出了一個可行的隧道建造計劃。"},{"en":"We need to find a feasible solution to reduce food waste.","zh":"我們需要找到一個可行的方法來減少食物浪費。"}]},{"word":"feast","pos":"n. / v.","phonetic":"[fist]","meaning":"盛宴；饗宴","definition":"a large elaborate meal, often celebratory","collocations":["hold a feast","feast on","wedding feast"],"example":"The family prepared a huge feast for the New Year.","exampleZh":"這家人為新年準備了一頓豐盛的盛宴。","synonyms":["banquet","spread"],"level":4,"theme":"食物與烹飪","examples":[{"en":"The family prepared a huge feast for the New Year.","zh":"這家人為新年準備了一頓豐盛的盛宴。"},{"en":"The villagers held a great feast to celebrate the harvest.","zh":"村民們舉辦了一場盛宴來慶祝豐收。"},{"en":"At the wedding feast, guests enjoyed a dozen delicious dishes.","zh":"在婚宴上，賓客們享用了十幾道美味佳餚。"}]},{"word":"feat","pos":"n.","phonetic":"[fit]","meaning":"功績；壯舉","definition":"an achievement that requires great courage, skill, or strength","collocations":["a remarkable feat","perform a feat","feat of engineering"],"example":"Climbing the mountain alone was quite a feat.","exampleZh":"獨自攀登那座山是相當了不起的壯舉。","synonyms":["achievement","accomplishment"],"level":5,"theme":"抽象概念","examples":[{"en":"Climbing the mountain alone was quite a feat.","zh":"獨自攀登那座山是相當了不起的壯舉。"},{"en":"Swimming across the wide river was a remarkable feat.","zh":"游泳橫渡這條寬闊的河流是一項了不起的壯舉。"},{"en":"The ancient bridge is an amazing feat of engineering.","zh":"這座古橋是一項令人驚嘆的工程壯舉。"}]},{"word":"feather","pos":"n.","phonetic":"[ˈfɛðɚ]","meaning":"羽毛","definition":"one of the light growths forming a bird's plumage","collocations":["bird feather","light as a feather","feather pillow"],"example":"A peacock's feathers are strikingly beautiful.","exampleZh":"孔雀的羽毛美得驚人。","synonyms":["plume"],"level":3,"theme":"動物與植物","examples":[{"en":"A peacock's feathers are strikingly beautiful.","zh":"孔雀的羽毛美得驚人。"},{"en":"The tiny box was light as a feather in my hand.","zh":"這個小盒子在我手中輕如羽毛。"},{"en":"She rested her head on a soft feather pillow.","zh":"她把頭靠在柔軟的羽毛枕頭上。"}]},{"word":"feature","pos":"n. / v.","phonetic":"[ˈfitʃɚ]","meaning":"特徵；特色；以...為特色","definition":"a distinctive attribute or aspect of something","collocations":["key feature","facial feature","feature a guest"],"example":"The phone's best feature is its camera.","exampleZh":"這支手機最棒的特色是它的相機。","synonyms":["characteristic","trait"],"level":3,"theme":"性質與描述","examples":[{"en":"The phone's best feature is its camera.","zh":"這支手機最棒的特色是它的相機。"},{"en":"The waterproof design is a key feature of this watch.","zh":"防水設計是這支手錶的主要特色。"},{"en":"This week's program will feature a famous local chef.","zh":"本週的節目將邀請一位知名的當地廚師。"}]},{"word":"federal","pos":"adj.","phonetic":"[ˈfɛdərəl]","meaning":"聯邦的","definition":"relating to a system of national government","collocations":["federal government","federal law","federal agency"],"example":"The federal government passed a new law on education.","exampleZh":"聯邦政府通過了一項有關教育的新法律。","synonyms":["national"],"level":5,"theme":"政治與法律","examples":[{"en":"The federal government passed a new law on education.","zh":"聯邦政府通過了一項有關教育的新法律。"},{"en":"A new federal law now requires all cars to pass strict safety tests.","zh":"一項新的聯邦法律現在要求所有汽車必須通過嚴格的安全測試。"},{"en":"The federal agency is investigating the cause of the sudden power failure.","zh":"聯邦機構正在調查這次突然停電的原因。"}]},{"word":"fee","pos":"n.","phonetic":"[fi]","meaning":"費用","definition":"a payment made for professional services or entry","collocations":["entrance fee","tuition fee","pay a fee"],"example":"There is an entrance fee for the museum.","exampleZh":"參觀這座博物館需要付入場費。","synonyms":["charge","payment"],"level":3,"theme":"商業與金錢","examples":[{"en":"There is an entrance fee for the museum.","zh":"參觀這座博物館需要付入場費。"},{"en":"My parents worked hard to pay my tuition fee every semester.","zh":"我的父母努力工作，每學期支付我的學費。"},{"en":"You must pay a small fee before joining the swimming club.","zh":"加入游泳社之前，你必須支付一小筆費用。"}]},{"word":"feeble","pos":"adj.","phonetic":"[ˈfibḷ]","meaning":"虛弱的；微弱的","definition":"lacking physical or mental strength","collocations":["a feeble old man","a feeble excuse","feeble light"],"example":"The patient gave a feeble smile before falling asleep.","exampleZh":"病人露出虛弱的微笑後便睡著了。","synonyms":["weak","frail"],"level":5,"theme":"身體與健康","examples":[{"en":"The patient gave a feeble smile before falling asleep.","zh":"病人露出虛弱的微笑後便睡著了。"},{"en":"The feeble old man could barely walk to the front door.","zh":"那位虛弱的老人幾乎無法走到前門。"},{"en":"He gave a feeble excuse for being late to class again.","zh":"他為再次上課遲到找了一個牽強的藉口。"}]},{"word":"feed","pos":"v.","phonetic":"[fid]","meaning":"餵養；提供食物","definition":"to give food to a person or animal","collocations":["feed a baby","feed the dog","feed on"],"example":"She feeds her cat twice a day.","exampleZh":"她每天餵貓兩次。","synonyms":["nourish","nurture"],"level":1,"theme":"食物與烹飪","examples":[{"en":"She feeds her cat twice a day.","zh":"她每天餵貓兩次。"},{"en":"Every morning she feeds the chickens before going to school.","zh":"每天早上她上學前都會餵雞。"},{"en":"Owls usually feed on small animals such as mice at night.","zh":"貓頭鷹通常在夜間以老鼠等小動物為食。"}]},{"word":"feedback","pos":"n.","phonetic":"[ˈfidˌbæk]","meaning":"回饋；意見","definition":"information given about performance for improvement","collocations":["give feedback","positive feedback","feedback form"],"example":"The teacher gave useful feedback on my essay.","exampleZh":"老師對我的作文給了有用的回饋。","synonyms":["response","comment"],"level":4,"theme":"教育與學習","examples":[{"en":"The teacher gave useful feedback on my essay.","zh":"老師對我的作文給了有用的回饋。"},{"en":"Please fill out the feedback form after you finish the course.","zh":"課程結束後，請填寫意見回饋表。"},{"en":"The students gave positive feedback about the new science teacher.","zh":"學生們對新的自然科老師給予了正面的回饋。"}]},{"word":"feel","pos":"v.","phonetic":"[fil]","meaning":"感覺；觸摸","definition":"to experience an emotion or physical sensation","collocations":["feel sad","feel free","feel like"],"example":"I feel happy when I listen to music.","exampleZh":"我聽音樂的時候會感到快樂。","synonyms":["sense","perceive"],"level":1,"theme":"情緒與感受","examples":[{"en":"I feel happy when I listen to music.","zh":"我聽音樂的時候會感到快樂。"},{"en":"Feel free to ask me any questions after the lecture ends.","zh":"講座結束後，歡迎隨時問我任何問題。"},{"en":"After the long hike, I felt like drinking a cold glass of water.","zh":"長途健行之後，我很想喝一杯冰水。"}]},{"word":"female","pos":"adj. / n.","phonetic":"[ˈfimel]","meaning":"女性的；雌性的","definition":"belonging to the sex that can bear offspring","collocations":["female student","female athlete","male and female"],"example":"Female students make up half of the class.","exampleZh":"女學生佔了班上一半的人數。","synonyms":["woman","girl"],"level":2,"theme":"人物與家庭","examples":[{"en":"Female students make up half of the class.","zh":"女學生佔了班上一半的人數。"},{"en":"The female athlete broke the national record in the long jump.","zh":"這位女性運動員打破了跳遠的全國紀錄。"},{"en":"Both male and female students may join the school choir.","zh":"男女學生都可以加入學校合唱團。"}]},{"word":"feminine","pos":"adj.","phonetic":"[ˈfɛmənɪn]","meaning":"女性的；女性化的","definition":"having qualities traditionally associated with women","collocations":["feminine charm","feminine clothes","feminine voice"],"example":"She has a soft, feminine style of dressing.","exampleZh":"她的穿衣風格柔和又女性化。","synonyms":["womanly"],"level":4,"theme":"服裝與外表","examples":[{"en":"She has a soft, feminine style of dressing.","zh":"她的穿衣風格柔和又女性化。"},{"en":"She spoke in a soft, feminine voice that calmed everyone down.","zh":"她以柔和、女性化的聲音說話，讓大家都平靜下來。"},{"en":"The dress was designed to show off her feminine charm.","zh":"這件洋裝的設計是為了展現她的女性魅力。"}]},{"word":"fence","pos":"n.","phonetic":"[fɛns]","meaning":"籬笆；圍欄","definition":"a barrier enclosing an area, made of posts and wire","collocations":["wooden fence","climb a fence","build a fence"],"example":"The dog jumped over the fence.","exampleZh":"那隻狗跳過了圍欄。","synonyms":["barrier","railing"],"level":2,"theme":"居家與生活","examples":[{"en":"The dog jumped over the fence.","zh":"那隻狗跳過了圍欄。"},{"en":"My grandfather built a wooden fence around his vegetable garden.","zh":"我的祖父在他的菜園四周築了一道木籬笆。"},{"en":"The children were warned not to climb the fence near the pond.","zh":"孩子們被警告不要爬過池塘旁的圍欄。"}]},{"word":"fertile","pos":"adj.","phonetic":"[ˈfɝtl̩]","meaning":"肥沃的；多產的","definition":"producing abundant vegetation or crops","collocations":["fertile soil","fertile land","fertile ground"],"example":"The valley has fertile soil perfect for farming.","exampleZh":"這座山谷有肥沃的土壤，非常適合耕種。","synonyms":["productive","rich"],"level":5,"theme":"自然與環境","examples":[{"en":"The valley has fertile soil perfect for farming.","zh":"這座山谷有肥沃的土壤，非常適合耕種。"},{"en":"The farmers grow rice on the fertile land beside the river.","zh":"農夫在河邊肥沃的土地上種植稻米。"},{"en":"This region's fertile soil makes it ideal for growing fruit.","zh":"這個地區肥沃的土壤使它非常適合種植水果。"}]},{"word":"fertilizer","pos":"n.","phonetic":"[ˈfɝtḷˌaɪzɚ]","meaning":"肥料","definition":"a substance added to soil to make plants grow better","collocations":["chemical fertilizer","apply fertilizer","organic fertilizer"],"example":"Farmers spread fertilizer over the fields before planting.","exampleZh":"農夫在播種前先在田裡施肥。","synonyms":[],"level":4,"theme":"自然與環境","examples":[{"en":"Farmers spread fertilizer over the fields before planting.","zh":"農夫在播種前先在田裡施肥。"},{"en":"Many farmers now prefer organic fertilizer to protect the soil.","zh":"許多農夫現在偏好使用有機肥料以保護土壤。"},{"en":"You should apply fertilizer to the plants once a month.","zh":"你應該每個月為植物施肥一次。"}]},{"word":"festival","pos":"n.","phonetic":"[ˈfɛstəvl̩]","meaning":"節慶；慶典","definition":"a day or period of celebration","collocations":["film festival","music festival","traditional festival"],"example":"The Dragon Boat Festival is celebrated in early summer.","exampleZh":"端午節在初夏時節慶祝。","synonyms":["celebration","carnival"],"level":2,"theme":"社會與文化","examples":[{"en":"The Dragon Boat Festival is celebrated in early summer.","zh":"端午節在初夏時節慶祝。"},{"en":"Thousands of fans attended the outdoor music festival last summer.","zh":"去年夏天，數千名歌迷參加了戶外音樂節。"},{"en":"The Lantern Festival is one of Taiwan's most beloved traditional festivals.","zh":"元宵節是台灣最受喜愛的傳統節慶之一。"}]},{"word":"festive","pos":"adj.","phonetic":"[ˈfɛstɪv]","meaning":"節慶的；喜氣洋洋的","definition":"relating to or suitable for a celebration","collocations":["a festive mood","festive decorations","festive season"],"example":"The whole street was decorated in a festive mood for Christmas.","exampleZh":"整條街都裝飾得充滿聖誕節的喜慶氣氛。","synonyms":["celebratory","joyful"],"level":4,"theme":"社會與文化","examples":[{"en":"The whole street was decorated in a festive mood for Christmas.","zh":"整條街都裝飾得充滿聖誕節的喜慶氣氛。"},{"en":"The classroom was full of festive decorations before the New Year.","zh":"新年前，教室裡佈滿了節慶裝飾。"},{"en":"During the festive season, the shops stay open much later.","zh":"在節慶期間，商店營業到很晚。"}]},{"word":"fetch","pos":"v.","phonetic":"[fɛtʃ]","meaning":"去拿來；取來","definition":"to go for and bring back something","collocations":["fetch water","fetch a doctor","fetch a ball"],"example":"The dog ran to fetch the ball.","exampleZh":"那隻狗跑去撿球。","synonyms":["retrieve","bring"],"level":4,"theme":"動作與行為","examples":[{"en":"The dog ran to fetch the ball.","zh":"那隻狗跑去撿球。"},{"en":"Could you please fetch me a glass of water from the kitchen?","zh":"你可以幫我從廚房拿一杯水來嗎？"},{"en":"The villagers had to fetch water from a well every day.","zh":"村民們每天都必須從井裡取水。"}]},{"word":"fever","pos":"n.","phonetic":"[ˈfivɚ]","meaning":"發燒","definition":"an abnormally high body temperature","collocations":["high fever","run a fever","fever reducer"],"example":"The child had a high fever and stayed home from school.","exampleZh":"這個孩子發高燒，因此沒去上學。","synonyms":["temperature"],"level":2,"theme":"身體與健康","examples":[{"en":"The child had a high fever and stayed home from school.","zh":"這個孩子發高燒，因此沒去上學。"},{"en":"The nurse gave him medicine to bring down his high fever.","zh":"護士給他吃藥以退燒。"},{"en":"If you run a fever, you should rest and drink plenty of water.","zh":"如果你發燒，就應該休息並多喝水。"}]},{"word":"fiber","pos":"n.","phonetic":"[ˈfaɪbɚ]","meaning":"纖維","definition":"a thread-like structure or dietary substance","collocations":["dietary fiber","fiber optic","muscle fiber"],"example":"Vegetables are a good source of fiber.","exampleZh":"蔬菜是纖維的良好來源。","synonyms":["strand","filament"],"level":4,"theme":"科學與數學","examples":[{"en":"Vegetables are a good source of fiber.","zh":"蔬菜是纖維的良好來源。"},{"en":"Whole grains contain a lot of dietary fiber that aids digestion.","zh":"全穀類含有大量有助消化的膳食纖維。"},{"en":"Fiber optic cables allow data to travel at incredible speeds.","zh":"光纖電纜使資料能以驚人的速度傳輸。"}]},{"word":"fiction","pos":"n.","phonetic":"[ˈfɪkʃən]","meaning":"小說；虛構","definition":"literature describing imaginary events and people","collocations":["science fiction","fiction book","fact and fiction"],"example":"She prefers reading fiction to nonfiction.","exampleZh":"比起非虛構作品，她更喜歡讀小說。","synonyms":["novel","story"],"level":3,"theme":"藝術與音樂","examples":[{"en":"She prefers reading fiction to nonfiction.","zh":"比起非虛構作品，她更喜歡讀小說。"},{"en":"He enjoys reading science fiction about life on distant planets.","zh":"他喜歡閱讀關於遙遠星球生命的科幻小說。"},{"en":"Sometimes it is hard to tell fact from fiction online.","zh":"有時很難分辨網路上的事實與虛構。"}]},{"word":"field","pos":"n.","phonetic":"[fild]","meaning":"田野；領域；球場","definition":"an open area of land; an area of study or activity","collocations":["rice field","field trip","field of study"],"example":"We went on a field trip to the science museum.","exampleZh":"我們去科學博物館校外教學。","synonyms":["meadow","domain"],"level":2,"theme":"自然與環境","examples":[{"en":"We went on a field trip to the science museum.","zh":"我們去科學博物館校外教學。"},{"en":"Farmers were busy working in the rice fields at sunrise.","zh":"日出時分，農夫們正忙著在稻田裡工作。"},{"en":"She hopes to become an expert in the field of medicine.","zh":"她希望成為醫學領域的專家。"}]},{"word":"fierce","pos":"adj.","phonetic":"[fɪrs]","meaning":"兇猛的；激烈的","definition":"showing intense and often violent behavior","collocations":["fierce competition","fierce animal","fierce battle"],"example":"The two teams were in fierce competition for the title.","exampleZh":"這兩隊為了冠軍展開激烈的競爭。","synonyms":["ferocious","intense"],"level":4,"theme":"性質與描述","examples":[{"en":"The two teams were in fierce competition for the title.","zh":"這兩隊為了冠軍展開激烈的競爭。"},{"en":"There is fierce competition among students to enter top universities.","zh":"學生之間為了進入頂尖大學而競爭激烈。"},{"en":"The lion is a fierce animal that hunts in groups.","zh":"獅子是成群獵食的兇猛動物。"}]},{"word":"fight","pos":"v. / n.","phonetic":"[faɪt]","meaning":"打架；奮鬥；戰鬥","definition":"to engage in physical combat or struggle","collocations":["fight for","get into a fight","fight against"],"example":"They fought for their country's independence.","exampleZh":"他們為國家的獨立而奮戰。","synonyms":["battle","struggle"],"level":1,"theme":"動作與行為","examples":[{"en":"They fought for their country's independence.","zh":"他們為國家的獨立而奮戰。"},{"en":"Doctors are working hard to fight against the spread of disease.","zh":"醫生們正努力對抗疾病的蔓延。"},{"en":"The two boys got into a fight over a small misunderstanding.","zh":"這兩個男孩因為一個小小的誤會而打了起來。"}]},{"word":"figure","pos":"n. / v.","phonetic":"[ˈfɪɡjɚ]","meaning":"數字；身材；理解","definition":"a number; a shape or form; to work out an answer","collocations":["figure out","public figure","keep one's figure"],"example":"I couldn't figure out how to solve the puzzle.","exampleZh":"我想不出該怎麼解開這個謎題。","synonyms":["number","shape"],"level":2,"theme":"科學與數學","examples":[{"en":"I couldn't figure out how to solve the puzzle.","zh":"我想不出該怎麼解開這個謎題。"},{"en":"The sales figures this month were much higher than expected.","zh":"這個月的銷售數字比預期高出許多。"},{"en":"It took me a while to figure out the math problem.","zh":"我花了一些時間才弄懂這道數學題。"}]},{"word":"file","pos":"n. / v.","phonetic":"[faɪl]","meaning":"檔案；歸檔","definition":"a collection of data stored under one name","collocations":["computer file","file a complaint","delete a file"],"example":"Please save the document as a PDF file.","exampleZh":"請把這份文件存成PDF檔案。","synonyms":["document","record"],"level":2,"theme":"科技與媒體","examples":[{"en":"Please save the document as a PDF file.","zh":"請把這份文件存成PDF檔案。"},{"en":"She decided to file a complaint about the noisy neighbors.","zh":"她決定針對吵鬧的鄰居提出申訴。"},{"en":"Remember to back up your computer files before the update.","zh":"更新之前記得備份你的電腦檔案。"}]},{"word":"fill","pos":"v.","phonetic":"[fɪl]","meaning":"填滿；裝滿","definition":"to make something full by putting things in it","collocations":["fill up","fill in the blank","fill a form"],"example":"She filled the glass with water.","exampleZh":"她把杯子裝滿了水。","synonyms":["stuff","load"],"level":1,"theme":"動作與行為","examples":[{"en":"She filled the glass with water.","zh":"她把杯子裝滿了水。"},{"en":"Please fill in the blanks with the correct answers.","zh":"請在空格中填入正確的答案。"},{"en":"The workers filled up the truck with boxes of fruit.","zh":"工人們把卡車裝滿了一箱箱的水果。"}]},{"word":"film","pos":"n. / v.","phonetic":"[fɪlm]","meaning":"電影；影片；拍攝","definition":"a motion picture; to record moving images","collocations":["watch a film","film director","film a scene"],"example":"We watched a great film about space travel last night.","exampleZh":"我們昨晚看了一部關於太空旅行的精彩電影。","synonyms":["movie","motion picture"],"level":2,"theme":"藝術與音樂","examples":[{"en":"We watched a great film about space travel last night.","zh":"我們昨晚看了一部關於太空旅行的精彩電影。"},{"en":"The film director spent months planning every important scene.","zh":"這位電影導演花了好幾個月規劃每個重要的場景。"},{"en":"They filmed the final scene on a quiet beach at dawn.","zh":"他們在黎明時分於一處寧靜的海灘拍攝了最後一幕。"}]},{"word":"filter","pos":"n. / v.","phonetic":"[ˈfɪltɚ]","meaning":"濾器；過濾","definition":"a device that removes unwanted substances, or to pass through such a device","collocations":["water filter","filter out impurities","air filter"],"example":"This machine filters the coffee to remove the grounds.","exampleZh":"這台機器會過濾咖啡以去除咖啡渣。","synonyms":["strain","sieve"],"level":3,"theme":"科技與媒體","examples":[{"en":"This machine filters the coffee to remove the grounds.","zh":"這台機器會過濾咖啡以去除咖啡渣。"},{"en":"We installed a water filter to remove impurities from the tap.","zh":"我們安裝了濾水器以去除自來水中的雜質。"},{"en":"The air filter should be cleaned regularly to keep the room fresh.","zh":"空氣濾網應該定期清潔，以保持室內清新。"}]},{"word":"final","pos":"adj. / n.","phonetic":"[ˈfaɪnl̩]","meaning":"最後的；決賽","definition":"coming last in a series; the last game of a competition","collocations":["final exam","final decision","reach the final"],"example":"Our team made it to the final of the tournament.","exampleZh":"我們隊伍打進了這場錦標賽的決賽。","synonyms":["last","concluding"],"level":2,"theme":"教育與學習","examples":[{"en":"Our team made it to the final of the tournament.","zh":"我們隊伍打進了這場錦標賽的決賽。"},{"en":"Students are studying hard for their final exams next week.","zh":"學生們正為下週的期末考努力讀書。"},{"en":"The manager made the final decision after a long discussion.","zh":"經理在長時間討論後做出了最終決定。"}]},{"word":"finale","pos":"n.","phonetic":"[fɪˈnɑlɪ]","meaning":"（表演、樂曲等的）終曲；壓軸","definition":"the last part of a performance, event, or piece of music","collocations":["grand finale","season finale","the finale of a concert"],"example":"Fireworks lit up the sky for the grand finale of the show.","exampleZh":"煙火在表演的壓軸時分照亮了天空。","synonyms":["climax","conclusion"],"level":5,"theme":"藝術與音樂","examples":[{"en":"Fireworks lit up the sky for the grand finale of the show.","zh":"煙火在表演的壓軸時分照亮了天空。"},{"en":"The orchestra played a powerful finale that thrilled the audience.","zh":"管弦樂團演奏了震撼人心的終曲，讓觀眾激動不已。"},{"en":"Fans could not wait to watch the season finale of the show.","zh":"粉絲們迫不及待想看這部影集的季終集。"}]},{"word":"finance","pos":"n. / v.","phonetic":"[ˈfaɪnæns]","meaning":"財務；金融；資助","definition":"the management of money; to provide funds for something","collocations":["personal finance","finance a project","finance minister"],"example":"The bank agreed to finance the new building project.","exampleZh":"銀行同意資助這個新建案。","synonyms":["funding","budget"],"level":5,"theme":"商業與金錢","examples":[{"en":"The bank agreed to finance the new building project.","zh":"銀行同意資助這個新建案。"},{"en":"Learning about personal finance helps students manage money wisely.","zh":"學習個人理財有助於學生明智地管理金錢。"},{"en":"The government agreed to finance the construction of a new bridge.","zh":"政府同意資助一座新橋的建造。"}]},{"word":"find","pos":"v.","phonetic":"[faɪnd]","meaning":"找到；發現","definition":"to discover or locate something","collocations":["find out","find a solution","find fault"],"example":"I finally found my lost keys under the sofa.","exampleZh":"我終於在沙發下找到了我遺失的鑰匙。","synonyms":["discover","locate"],"level":1,"theme":"動作與行為","examples":[{"en":"I finally found my lost keys under the sofa.","zh":"我終於在沙發下找到了我遺失的鑰匙。"},{"en":"The team worked together to find a solution to the problem.","zh":"團隊齊心協力尋找解決問題的辦法。"},{"en":"We were surprised to find out that the store had closed.","zh":"得知那家店已經關門，我們很驚訝。"}]},{"word":"fine","pos":"adj. / n.","phonetic":"[faɪn]","meaning":"好的；晴朗的；罰款","definition":"of good quality; a sum of money paid as punishment","collocations":["fine weather","traffic fine","feel fine"],"example":"He had to pay a fine for parking illegally.","exampleZh":"他因為違規停車而必須繳罰款。","synonyms":["good","penalty"],"level":1,"theme":"性質與描述","examples":[{"en":"He had to pay a fine for parking illegally.","zh":"他因為違規停車而必須繳罰款。"},{"en":"We enjoyed the fine weather during our picnic in the park.","zh":"在公園野餐時，我們享受著晴朗的好天氣。"},{"en":"He received a traffic fine for driving over the speed limit.","zh":"他因超速駕駛而收到一張交通罰單。"}]},{"word":"finger","pos":"n.","phonetic":"[ˈfɪŋɡɚ]","meaning":"手指","definition":"one of the digits of the hand","collocations":["index finger","cross fingers","point a finger"],"example":"She cut her finger while chopping vegetables.","exampleZh":"她切菜的時候切到手指了。","synonyms":["digit"],"level":1,"theme":"身體與健康","examples":[{"en":"She cut her finger while chopping vegetables.","zh":"她切菜的時候切到手指了。"},{"en":"She pointed her index finger at the map to show the way.","zh":"她用食指指著地圖指出方向。"},{"en":"I'll cross my fingers and hope you pass the exam.","zh":"我會祈求好運，希望你能通過考試。"}]},{"word":"finish","pos":"v. / n.","phonetic":"[ˈfɪnɪʃ]","meaning":"完成；結束","definition":"to bring a task or activity to an end","collocations":["finish homework","finish line","finish up"],"example":"She finished her homework before dinner.","exampleZh":"她在晚餐前完成了作業。","synonyms":["complete","end"],"level":1,"theme":"動作與行為","examples":[{"en":"She finished her homework before dinner.","zh":"她在晚餐前完成了作業。"},{"en":"The runner raised his arms as he crossed the finish line.","zh":"跑者衝過終點線時舉起了雙臂。"},{"en":"Let's finish up the project before the weekend arrives.","zh":"我們在週末到來之前把這個專案完成吧。"}]},{"word":"fire","pos":"n. / v.","phonetic":"[faɪr]","meaning":"火；解雇","definition":"combustion producing light and heat; to dismiss an employee","collocations":["fire alarm","catch fire","fire an employee"],"example":"The firefighters quickly put out the fire.","exampleZh":"消防員很快就把火撲滅了。","synonyms":["flame","dismiss"],"level":1,"theme":"自然與環境","examples":[{"en":"The firefighters quickly put out the fire.","zh":"消防員很快就把火撲滅了。"},{"en":"The fire alarm rang loudly, and everyone rushed outside quickly.","zh":"火災警報大聲響起，每個人都迅速衝到外面。"},{"en":"The dry grass caught fire because of the intense heat.","zh":"乾草因為酷熱而著火了。"}]},{"word":"firm","pos":"adj. / n.","phonetic":"[fɝm]","meaning":"堅定的；公司","definition":"solid and steady; a business organization","collocations":["law firm","firm grip","stand firm"],"example":"He gave a firm handshake to the manager.","exampleZh":"他和經理堅定地握了手。","synonyms":["solid","company"],"level":3,"theme":"商業與金錢","examples":[{"en":"He gave a firm handshake to the manager.","zh":"他和經理堅定地握了手。"},{"en":"She works as a lawyer at a well-known law firm downtown.","zh":"她在市中心一家知名的律師事務所擔任律師。"},{"en":"Despite the pressure, he stood firm in his decision.","zh":"儘管有壓力，他仍堅持自己的決定。"}]},{"word":"fit","pos":"adj. / v.","phonetic":"[fɪt]","meaning":"健康的；合適；適合","definition":"in good physical condition; to be the right size or shape","collocations":["fit in","keep fit","fit for purpose"],"example":"You need to exercise regularly to stay fit.","exampleZh":"你需要規律運動才能保持健康。","synonyms":["healthy","suitable"],"level":2,"theme":"身體與健康","examples":[{"en":"You need to exercise regularly to stay fit.","zh":"你需要規律運動才能保持健康。"},{"en":"She goes jogging every morning to keep fit and healthy.","zh":"她每天早上都去慢跑以保持健康。"},{"en":"The new student soon began to fit in with his classmates.","zh":"這位新學生很快就融入了同學之中。"}]},{"word":"fix","pos":"v.","phonetic":"[fɪks]","meaning":"修理；固定；解決","definition":"to repair or mend something","collocations":["fix a problem","fix up","fix a date"],"example":"The mechanic fixed my car in an hour.","exampleZh":"技師在一小時內修好了我的車。","synonyms":["repair","mend"],"level":2,"theme":"動作與行為","examples":[{"en":"The mechanic fixed my car in an hour.","zh":"技師在一小時內修好了我的車。"},{"en":"The engineer quickly fixed the problem with the broken machine.","zh":"工程師迅速解決了故障機器的問題。"},{"en":"Let's fix a date for our next class reunion soon.","zh":"我們趕快敲定下次同學會的日期吧。"}]},{"word":"flag","pos":"n.","phonetic":"[flæg]","meaning":"旗幟","definition":"a piece of cloth used as a symbol or signal","collocations":["national flag","raise a flag","wave a flag"],"example":"Students raised the national flag every morning.","exampleZh":"學生們每天早上都會升國旗。","synonyms":["banner","emblem"],"level":2,"theme":"政治與法律","examples":[{"en":"Students raised the national flag every morning.","zh":"學生們每天早上都會升國旗。"},{"en":"The crowd waved small flags as the athletes marched past.","zh":"當運動員行進經過時，群眾揮舞著小旗子。"},{"en":"Soldiers raised the national flag slowly at the ceremony.","zh":"士兵們在典禮上緩緩升起國旗。"}]},{"word":"flame","pos":"n.","phonetic":"[flem]","meaning":"火焰","definition":"the visible part of a fire","collocations":["in flames","candle flame","burst into flame"],"example":"The candle flame flickered in the wind.","exampleZh":"蠟燭的火焰在風中搖曳。","synonyms":["fire","blaze"],"level":3,"theme":"自然與環境","examples":[{"en":"The candle flame flickered in the wind.","zh":"蠟燭的火焰在風中搖曳。"},{"en":"Within minutes, the whole barn was in flames.","zh":"幾分鐘之內，整座穀倉陷入火海。"},{"en":"She leaned close to blow out the candle flame.","zh":"她靠近吹熄了蠟燭的火焰。"}]},{"word":"flare","pos":"n. / v.","phonetic":"[flɛr]","meaning":"閃耀；（怒氣等）突然爆發；信號彈","definition":"a sudden burst of bright light, or to burst out suddenly","collocations":["flare up","a signal flare","tempers flare"],"example":"His anger flared up when he saw the broken window.","exampleZh":"他看到破掉的窗戶時怒氣頓時爆發。","synonyms":["blaze","flash"],"level":5,"theme":"情緒與感受","examples":[{"en":"His anger flared up when he saw the broken window.","zh":"他看到破掉的窗戶時怒氣頓時爆發。"},{"en":"The sailors fired a signal flare to call for help.","zh":"水手們發射信號彈求救。"},{"en":"Tempers flared during the heated argument about the rules.","zh":"在關於規則的激烈爭論中，眾人情緒爆發。"}]},{"word":"flash","pos":"n. / v.","phonetic":"[flæʃ]","meaning":"閃光；閃現","definition":"a sudden brief burst of light","collocations":["camera flash","flash of lightning","in a flash"],"example":"A flash of lightning lit up the sky.","exampleZh":"一道閃電照亮了天空。","synonyms":["flare","gleam"],"level":3,"theme":"自然與環境","examples":[{"en":"A flash of lightning lit up the sky.","zh":"一道閃電照亮了天空。"},{"en":"The camera flash startled the sleeping baby for a moment.","zh":"相機的閃光燈讓熟睡的嬰兒受到了片刻的驚嚇。"},{"en":"The idea came to her in a flash during the meeting.","zh":"在會議中，這個點子瞬間閃過她的腦海。"}]},{"word":"flask","pos":"n.","phonetic":"[flæsk]","meaning":"燒瓶；水壺；小酒瓶","definition":"a container used for carrying liquids or for laboratory experiments","collocations":["a vacuum flask","a hip flask","fill a flask"],"example":"He carried a flask of hot tea on the cold mountain hike.","exampleZh":"他在寒冷的登山途中帶了一壺熱茶。","synonyms":["bottle","flagon"],"level":4,"theme":"科學與數學","examples":[{"en":"He carried a flask of hot tea on the cold mountain hike.","zh":"他在寒冷的登山途中帶了一壺熱茶。"},{"en":"The scientist heated the liquid in a glass flask carefully.","zh":"科學家小心地在玻璃燒瓶中加熱液體。"},{"en":"She filled her vacuum flask with hot soup for lunch.","zh":"她在保溫瓶裡裝滿了熱湯當午餐。"}]},{"word":"flat","pos":"adj. / n.","phonetic":"[flæt]","meaning":"平坦的；公寓","definition":"having a level surface; a set of rooms for living","collocations":["flat surface","flat tire","rent a flat"],"example":"They live in a small flat in the city center.","exampleZh":"他們住在市中心的一間小公寓。","synonyms":["level","apartment"],"level":2,"theme":"居家與生活","examples":[{"en":"They live in a small flat in the city center.","zh":"他們住在市中心的一間小公寓。"},{"en":"We had to stop because the car had a flat tire.","zh":"我們不得不停下，因為車子爆胎了。"},{"en":"The young couple decided to rent a small flat near the office.","zh":"這對年輕夫妻決定在辦公室附近租一間小公寓。"}]},{"word":"flavor","pos":"n. / v.","phonetic":"[ˈflevɚ]","meaning":"味道；風味","definition":"the distinctive taste of a food or drink","collocations":["flavor of the month","add flavor","chocolate flavor"],"example":"This ice cream comes in many different flavors.","exampleZh":"這款冰淇淋有許多不同的口味。","synonyms":["taste","seasoning"],"level":3,"theme":"食物與烹飪","examples":[{"en":"This ice cream comes in many different flavors.","zh":"這款冰淇淋有許多不同的口味。"},{"en":"A pinch of salt can add flavor to almost any dish.","zh":"一小撮鹽幾乎能為任何菜餚增添風味。"},{"en":"The children argued over who would get the chocolate flavor.","zh":"孩子們為了誰能拿到巧克力口味而爭論。"}]},{"word":"flee","pos":"v.","phonetic":"[fli]","meaning":"逃離；逃避","definition":"to run away from danger or trouble","collocations":["flee the country","flee from danger","flee in terror"],"example":"Thousands of residents fled the city before the storm hit.","exampleZh":"暴風雨來襲前，數千名居民逃離了這座城市。","synonyms":["escape","run away"],"level":5,"theme":"動作與行為","examples":[{"en":"Thousands of residents fled the city before the storm hit.","zh":"暴風雨來襲前，數千名居民逃離了這座城市。"},{"en":"The family had to flee the country during the war.","zh":"戰爭期間，這家人不得不逃離該國。"},{"en":"The frightened deer fled from the sound of hunters.","zh":"受驚的鹿逃離了獵人的聲音。"}]},{"word":"fleet","pos":"n.","phonetic":"[flit]","meaning":"艦隊；（同一機構的）車隊","definition":"a group of ships, vehicles, or aircraft operated together","collocations":["a fishing fleet","a fleet of taxis","naval fleet"],"example":"The company owns a large fleet of delivery trucks.","exampleZh":"這家公司擁有一大批送貨卡車。","synonyms":["armada","convoy"],"level":5,"theme":"交通與旅行","examples":[{"en":"The company owns a large fleet of delivery trucks.","zh":"這家公司擁有一大批送貨卡車。"},{"en":"A large fishing fleet set out to sea before dawn.","zh":"一支龐大的漁船隊在黎明前出海。"},{"en":"The airport operates a fleet of buses to carry passengers.","zh":"機場營運著一支巴士車隊來載送乘客。"}]},{"word":"flexible","pos":"adj.","phonetic":"[ˈflɛksəbl̩]","meaning":"有彈性的；靈活的","definition":"capable of bending easily or adapting to change","collocations":["flexible schedule","flexible material","stay flexible"],"example":"My job offers flexible working hours.","exampleZh":"我的工作提供彈性的工作時間。","synonyms":["adaptable","elastic"],"level":4,"theme":"性質與描述","examples":[{"en":"My job offers flexible working hours.","zh":"我的工作提供彈性的工作時間。"},{"en":"Working from home gives me a more flexible schedule.","zh":"在家工作讓我有更彈性的時間安排。"},{"en":"This new material is strong yet remarkably flexible.","zh":"這種新材料既堅固又非常有彈性。"}]},{"word":"flight","pos":"n.","phonetic":"[flaɪt]","meaning":"飛行；班機","definition":"an act of traveling through the air","collocations":["book a flight","flight attendant","domestic flight"],"example":"Our flight to Tokyo was delayed by two hours.","exampleZh":"我們飛往東京的班機延誤了兩個小時。","synonyms":["journey","trip"],"level":2,"theme":"交通與旅行","examples":[{"en":"Our flight to Tokyo was delayed by two hours.","zh":"我們飛往東京的班機延誤了兩個小時。"},{"en":"She booked a flight to Kaohsiung for the holiday weekend.","zh":"她訂了一張連假飛往高雄的班機。"},{"en":"The flight attendant kindly helped the elderly passenger find her seat.","zh":"空服員親切地幫助年長的乘客找到座位。"}]},{"word":"float","pos":"v.","phonetic":"[flot]","meaning":"漂浮","definition":"to rest on the surface of a liquid without sinking","collocations":["float on water","float in the air","float around"],"example":"The leaves floated gently on the pond.","exampleZh":"樹葉輕輕地漂浮在池塘上。","synonyms":["drift","hover"],"level":3,"theme":"自然與環境","examples":[{"en":"The leaves floated gently on the pond.","zh":"樹葉輕輕地漂浮在池塘上。"},{"en":"Colorful balloons floated in the air above the birthday party.","zh":"五顏六色的氣球在生日派對上方飄浮著。"},{"en":"A small wooden boat floated slowly down the calm river.","zh":"一艘小木船緩緩地順著平靜的河流漂流。"}]},{"word":"flood","pos":"n. / v.","phonetic":"[flʌd]","meaning":"洪水；淹沒","definition":"an overflow of water onto normally dry land","collocations":["flash flood","flood control","flood the streets"],"example":"Heavy rain caused a flood in the low-lying areas.","exampleZh":"豪雨造成低窪地區淹水。","synonyms":["deluge","overflow"],"level":3,"theme":"自然與環境","examples":[{"en":"Heavy rain caused a flood in the low-lying areas.","zh":"豪雨造成低窪地區淹水。"},{"en":"A sudden flash flood swept away several cars in the town.","zh":"一場突如其來的暴洪沖走了鎮上好幾輛車。"},{"en":"Heavy rain flooded the streets and stopped all the traffic.","zh":"大雨淹沒了街道，使所有交通停擺。"}]},{"word":"floor","pos":"n.","phonetic":"[flor]","meaning":"地板；樓層","definition":"the lower surface of a room; a level of a building","collocations":["ground floor","sweep the floor","second floor"],"example":"The office is on the third floor.","exampleZh":"辦公室在三樓。","synonyms":["ground","level"],"level":1,"theme":"居家與生活","examples":[{"en":"The office is on the third floor.","zh":"辦公室在三樓。"},{"en":"The library's reading room is on the second floor.","zh":"圖書館的閱覽室在二樓。"},{"en":"He swept the floor carefully after the busy party ended.","zh":"熱鬧的派對結束後，他仔細地掃了地板。"}]},{"word":"flour","pos":"n.","phonetic":"[flaʊr]","meaning":"麵粉","definition":"a powder made by grinding grain, used in cooking","collocations":["wheat flour","flour and sugar","sift flour"],"example":"She mixed flour, sugar, and eggs to make a cake.","exampleZh":"她把麵粉、糖和雞蛋混合在一起做蛋糕。","synonyms":[],"level":2,"theme":"食物與烹飪","examples":[{"en":"She mixed flour, sugar, and eggs to make a cake.","zh":"她把麵粉、糖和雞蛋混合在一起做蛋糕。"},{"en":"You need to sift the flour before adding it to the bowl.","zh":"在把麵粉加入碗裡之前，你需要先過篩。"},{"en":"The baker uses only high-quality wheat flour for his bread.","zh":"這位烘焙師只用高品質的小麥麵粉來做麵包。"}]},{"word":"flow","pos":"v. / n.","phonetic":"[flo]","meaning":"流動；流暢","definition":"to move steadily and continuously in a current","collocations":["flow smoothly","cash flow","flow into"],"example":"The river flows through several small towns.","exampleZh":"這條河流經好幾個小鎮。","synonyms":["stream","run"],"level":3,"theme":"自然與環境","examples":[{"en":"The river flows through several small towns.","zh":"這條河流經好幾個小鎮。"},{"en":"Several small streams flow into the wide, gentle river.","zh":"幾條小溪流入這條寬闊而平緩的河流。"},{"en":"Good planning helps the whole project flow smoothly.","zh":"良好的規劃有助於整個專案順利進行。"}]},{"word":"flower","pos":"n.","phonetic":"[ˈflaʊɚ]","meaning":"花","definition":"the colorful reproductive part of a plant","collocations":["flower bed","wild flower","flower shop"],"example":"She planted flowers in the garden.","exampleZh":"她在花園裡種了花。","synonyms":["blossom","bloom"],"level":1,"theme":"動物與植物","examples":[{"en":"She planted flowers in the garden.","zh":"她在花園裡種了花。"},{"en":"She stopped at the flower shop to buy a bunch of roses.","zh":"她在花店停下來買了一束玫瑰。"},{"en":"Colorful wild flowers covered the hillside in spring.","zh":"春天時，五彩繽紛的野花覆蓋了山坡。"}]},{"word":"flu","pos":"n.","phonetic":"[flu]","meaning":"流行性感冒","definition":"an infectious viral illness causing fever and aches","collocations":["catch the flu","flu shot","flu season"],"example":"He stayed home because he had the flu.","exampleZh":"他因為得了流感而待在家裡。","synonyms":["influenza"],"level":2,"theme":"身體與健康","examples":[{"en":"He stayed home because he had the flu.","zh":"他因為得了流感而待在家裡。"},{"en":"Many people get a flu shot before the cold season begins.","zh":"許多人在寒冷季節開始前會去打流感疫苗。"},{"en":"She caught the flu and had to miss three days of school.","zh":"她得了流感，不得不請假三天沒去學校。"}]},{"word":"fluent","pos":"adj.","phonetic":"[ˈfluənt]","meaning":"流利的","definition":"able to speak or write a language easily and accurately","collocations":["fluent in English","speak fluently","fluent speaker"],"example":"She is fluent in three languages.","exampleZh":"她精通三種語言。","synonyms":["proficient","articulate"],"level":4,"theme":"溝通與語言","examples":[{"en":"She is fluent in three languages.","zh":"她精通三種語言。"},{"en":"After living abroad, he became fluent in English and French.","zh":"在國外生活後，他的英語和法語都變得流利。"},{"en":"Being a fluent speaker of Japanese helped her get the job.","zh":"日語流利幫助她得到了這份工作。"}]},{"word":"fly","pos":"v. / n.","phonetic":"[flaɪ]","meaning":"飛；蒼蠅","definition":"to move through the air using wings; a small flying insect","collocations":["fly a kite","catch a fly","fly abroad"],"example":"Birds fly south for the winter.","exampleZh":"鳥類冬天會飛往南方。","synonyms":["soar"],"level":1,"theme":"動物與植物","examples":[{"en":"Birds fly south for the winter.","zh":"鳥類冬天會飛往南方。"},{"en":"The children love to fly kites on the windy beach.","zh":"孩子們喜歡在多風的海灘上放風箏。"},{"en":"A fly kept buzzing around the fruit on the table.","zh":"一隻蒼蠅一直在桌上的水果周圍嗡嗡飛。"}]},{"word":"focus","pos":"v. / n.","phonetic":"[ˈfokəs]","meaning":"專注；焦點","definition":"to concentrate attention or effort on something","collocations":["focus on","in focus","lose focus"],"example":"You need to focus on your studies this semester.","exampleZh":"這學期你需要專注在學業上。","synonyms":["concentrate","center"],"level":3,"theme":"教育與學習","examples":[{"en":"You need to focus on your studies this semester.","zh":"這學期你需要專注在學業上。"},{"en":"It is hard to focus on homework when the room is noisy.","zh":"房間吵鬧時很難專心寫作業。"},{"en":"The photo was blurry because the camera was not in focus.","zh":"由於相機沒對準焦，這張照片很模糊。"}]},{"word":"fold","pos":"v.","phonetic":"[fold]","meaning":"摺疊","definition":"to bend something over on itself","collocations":["fold clothes","fold paper","fold up"],"example":"She folded the laundry neatly.","exampleZh":"她把洗好的衣服摺得整整齊齊。","synonyms":["crease","bend"],"level":3,"theme":"動作與行為","examples":[{"en":"She folded the laundry neatly.","zh":"她把洗好的衣服摺得整整齊齊。"},{"en":"He carefully folded the paper into the shape of a crane.","zh":"他小心地把紙摺成一隻紙鶴的形狀。"},{"en":"Please fold up the chairs and put them against the wall.","zh":"請把椅子摺起來，靠牆放好。"}]},{"word":"folk","pos":"n. / adj.","phonetic":"[fok]","meaning":"民間的；人們","definition":"people in general; traditional and of the common people","collocations":["folk music","folk tale","folks back home"],"example":"He enjoys listening to traditional folk music.","exampleZh":"他喜歡聽傳統民謠音樂。","synonyms":["people","traditional"],"level":4,"theme":"藝術與音樂","examples":[{"en":"He enjoys listening to traditional folk music.","zh":"他喜歡聽傳統民謠音樂。"},{"en":"My grandmother often told us old folk tales at bedtime.","zh":"我的祖母常在睡前對我們講古老的民間故事。"},{"en":"The village holds a folk music concert every autumn.","zh":"這個村莊每年秋天都會舉辦一場民俗音樂會。"}]},{"word":"follow","pos":"v.","phonetic":"[ˈfɑlo]","meaning":"跟隨；遵循","definition":"to go or come after a person or thing","collocations":["follow instructions","follow up","follow someone"],"example":"Please follow the instructions carefully.","exampleZh":"請仔細遵循指示。","synonyms":["pursue","obey"],"level":1,"theme":"動作與行為","examples":[{"en":"Please follow the instructions carefully.","zh":"請仔細遵循指示。"},{"en":"If you follow these instructions, the recipe is quite easy.","zh":"只要遵循這些說明，這道食譜其實相當簡單。"},{"en":"The little duck followed its mother across the busy road.","zh":"小鴨子跟著媽媽穿過繁忙的馬路。"}]},{"word":"fond","pos":"adj.","phonetic":"[fɑnd]","meaning":"喜愛的","definition":"having an affection or liking for something","collocations":["fond of","fond memory","grow fond of"],"example":"I am very fond of chocolate cake.","exampleZh":"我非常喜歡巧克力蛋糕。","synonyms":["affectionate","attached"],"level":4,"theme":"情緒與感受","examples":[{"en":"I am very fond of chocolate cake.","zh":"我非常喜歡巧克力蛋糕。"},{"en":"She has many fond memories of her childhood summers.","zh":"她對童年的夏日有許多美好的回憶。"},{"en":"Over the years, he grew fond of gardening on weekends.","zh":"多年來，他漸漸愛上了週末園藝。"}]},{"word":"food","pos":"n.","phonetic":"[fud]","meaning":"食物","definition":"any nutritious substance eaten to maintain life","collocations":["fast food","healthy food","food chain"],"example":"Vietnamese food is popular in Taiwan.","exampleZh":"越南料理在台灣很受歡迎。","synonyms":["nourishment","meal"],"level":1,"theme":"食物與烹飪","examples":[{"en":"Vietnamese food is popular in Taiwan.","zh":"越南料理在台灣很受歡迎。"},{"en":"Eating too much fast food can be harmful to your health.","zh":"吃太多速食可能會危害你的健康。"},{"en":"The teacher explained how energy moves along the food chain.","zh":"老師解釋了能量如何沿著食物鏈傳遞。"}]},{"word":"fool","pos":"n. / v.","phonetic":"[ful]","meaning":"傻瓜；愚弄","definition":"a person who acts unwisely; to trick someone","collocations":["make a fool of","fool around","act like a fool"],"example":"Don't make a fool of yourself at the party.","exampleZh":"在派對上別讓自己出糗。","synonyms":["idiot","trick"],"level":3,"theme":"情緒與感受","examples":[{"en":"Don't make a fool of yourself at the party.","zh":"在派對上別讓自己出糗。"},{"en":"Stop fooling around and start doing your homework now.","zh":"別再鬼混了，現在就開始做你的作業。"},{"en":"He tried to fool his friends with a silly magic trick.","zh":"他試圖用一個蠢蠢的魔術戲法愚弄他的朋友。"}]},{"word":"foolish","pos":"adj.","phonetic":"[ˈfulɪʃ]","meaning":"愚蠢的","definition":"lacking good sense or judgment","collocations":["foolish mistake","foolish idea","feel foolish"],"example":"It was foolish of him to quit his job without a plan.","exampleZh":"他沒有計畫就辭職，實在很愚蠢。","synonyms":["silly","unwise"],"level":3,"theme":"性質與描述","examples":[{"en":"It was foolish of him to quit his job without a plan.","zh":"他沒有計畫就辭職，實在很愚蠢。"},{"en":"It was a foolish mistake to leave the door unlocked.","zh":"沒鎖門是個愚蠢的錯誤。"},{"en":"She felt foolish after giving the wrong answer in class.","zh":"在課堂上答錯後，她覺得很愚蠢。"}]},{"word":"foot","pos":"n.","phonetic":"[fʊt]","meaning":"腳；英呎","definition":"the lower extremity of the leg; a unit of length","collocations":["on foot","foot of the mountain","foot the bill"],"example":"We walked to the store on foot.","exampleZh":"我們走路去商店。","synonyms":[],"level":1,"theme":"身體與健康","examples":[{"en":"We walked to the store on foot.","zh":"我們走路去商店。"},{"en":"We rested at the foot of the mountain before climbing up.","zh":"在往上爬之前，我們在山腳下休息。"},{"en":"My new shoes hurt my right foot after the long walk.","zh":"走了很久之後，我的新鞋子弄痛了我的右腳。"}]},{"word":"football","pos":"n.","phonetic":"[ˈfʊt͵bɔl]","meaning":"足球；美式足球","definition":"a game played by two teams kicking a ball, or the ball used","collocations":["play football","football match","football team"],"example":"The boys played football in the park after school.","exampleZh":"男孩們放學後在公園踢足球。","synonyms":["soccer"],"level":1,"theme":"運動與休閒","examples":[{"en":"The boys played football in the park after school.","zh":"男孩們放學後在公園踢足球。"},{"en":"Our school football team won the championship this year.","zh":"我們學校的足球隊今年贏得了冠軍。"},{"en":"Thousands of fans watched the exciting football match.","zh":"數千名球迷觀看了這場精彩的足球賽。"}]},{"word":"forbid","pos":"v.","phonetic":"[fɚˈbɪd]","meaning":"禁止","definition":"to refuse to allow something","collocations":["forbid smoking","strictly forbidden","forbid someone to do"],"example":"Smoking is forbidden inside the building.","exampleZh":"建築物內禁止吸菸。","synonyms":["prohibit","ban"],"level":4,"theme":"政治與法律","examples":[{"en":"Smoking is forbidden inside the building.","zh":"建築物內禁止吸菸。"},{"en":"The school forbids students to use phones during exams.","zh":"學校禁止學生在考試期間使用手機。"},{"en":"Taking photos is strictly forbidden inside the museum.","zh":"博物館內嚴格禁止拍照。"}]},{"word":"force","pos":"n. / v.","phonetic":"[fors]","meaning":"力量；強迫","definition":"physical strength or power; to compel someone to act","collocations":["by force","force someone to","police force"],"example":"The wind's force knocked down several trees.","exampleZh":"強風的力量吹倒了好幾棵樹。","synonyms":["power","compel"],"level":2,"theme":"科學與數學","examples":[{"en":"The wind's force knocked down several trees.","zh":"強風的力量吹倒了好幾棵樹。"},{"en":"No one should force you to sign a contract you dislike.","zh":"沒有人應該強迫你簽署一份你不喜歡的合約。"},{"en":"The strong force of the waves pushed the boat toward the rocks.","zh":"海浪強大的力量把船推向岩石。"}]},{"word":"forecast","pos":"n. / v.","phonetic":"[ˈforˌkæst]","meaning":"預報；預測","definition":"a prediction of future events, especially weather","collocations":["weather forecast","forecast rain","economic forecast"],"example":"The weather forecast predicts rain tomorrow.","exampleZh":"天氣預報預測明天會下雨。","synonyms":["prediction","projection"],"level":4,"theme":"天氣與季節","examples":[{"en":"The weather forecast predicts rain tomorrow.","zh":"天氣預報預測明天會下雨。"},{"en":"According to the weather forecast, it will be sunny tomorrow.","zh":"根據氣象預報，明天將是晴天。"},{"en":"Experts forecast steady growth for the economy next year.","zh":"專家預測明年經濟將穩定成長。"}]},{"word":"forehead","pos":"n.","phonetic":"[ˈfɔrˌhɛd]","meaning":"額頭","definition":"the part of the face above the eyebrows","collocations":["wipe one's forehead","high forehead","kiss on the forehead"],"example":"Sweat dripped down his forehead in the summer heat.","exampleZh":"在夏天的酷熱中，汗水從他的額頭滴下。","synonyms":["brow"],"level":3,"theme":"身體與健康","examples":[{"en":"Sweat dripped down his forehead in the summer heat.","zh":"在夏天的酷熱中，汗水從他的額頭滴下。"},{"en":"The runner wiped the sweat from his forehead with a towel.","zh":"跑者用毛巾擦去額頭上的汗水。"},{"en":"The mother gently kissed her sleeping baby on the forehead.","zh":"母親輕輕地在熟睡嬰兒的額頭上親了一下。"}]},{"word":"foreign","pos":"adj.","phonetic":"[ˈfɔrɪn]","meaning":"外國的","definition":"belonging to a country other than one's own","collocations":["foreign language","foreign country","foreign policy"],"example":"Learning a foreign language opens new opportunities.","exampleZh":"學習外語能開啟新的機會。","synonyms":["overseas","international"],"level":2,"theme":"社會與文化","examples":[{"en":"Learning a foreign language opens new opportunities.","zh":"學習外語能開啟新的機會。"},{"en":"Traveling to a foreign country can broaden your horizons.","zh":"到外國旅行可以開闊你的視野。"},{"en":"She is studying a foreign language to prepare for her trip.","zh":"她正在學一門外語，為她的旅行做準備。"}]},{"word":"foresee","pos":"v.","phonetic":"[forˈsi]","meaning":"預見；預料","definition":"to know or realize something will happen before it happens","collocations":["foresee a problem","hard to foresee"],"example":"No one could foresee the sudden change in the market.","exampleZh":"沒有人能預見市場的突然變化。","synonyms":["predict","anticipate"],"level":5,"theme":"抽象概念","examples":[{"en":"No one could foresee the sudden change in the market.","zh":"沒有人能預見市場的突然變化。"},{"en":"The wise manager was able to foresee the coming problem.","zh":"這位睿智的經理能夠預見即將到來的問題。"},{"en":"It is hard to foresee how the weather will change tomorrow.","zh":"很難預料明天天氣會如何變化。"}]},{"word":"forest","pos":"n.","phonetic":"[ˈfɔrɪst]","meaning":"森林","definition":"a large area covered chiefly with trees","collocations":["rain forest","forest fire","walk in the forest"],"example":"We went hiking in the forest last weekend.","exampleZh":"我們上週末去森林裡健行。","synonyms":["woods","woodland"],"level":2,"theme":"自然與環境","examples":[{"en":"We went hiking in the forest last weekend.","zh":"我們上週末去森林裡健行。"},{"en":"A careless camper started a huge forest fire last summer.","zh":"去年夏天，一名粗心的露營者引發了一場大森林火災。"},{"en":"We enjoyed a quiet walk in the forest after breakfast.","zh":"早餐後，我們在森林裡享受了一段寧靜的散步。"}]},{"word":"forever","pos":"adv.","phonetic":"[fɚˈɛvɚ]","meaning":"永遠","definition":"for all future time","collocations":["last forever","forever young","friends forever"],"example":"Nothing lasts forever, so cherish the moment.","exampleZh":"沒有什麼是永恆的，所以要珍惜當下。","synonyms":["eternally","always"],"level":2,"theme":"時間與空間","examples":[{"en":"Nothing lasts forever, so cherish the moment.","zh":"沒有什麼是永恆的，所以要珍惜當下。"},{"en":"They promised to stay friends forever after graduation.","zh":"他們約定畢業後要永遠當朋友。"},{"en":"No difficult time lasts forever, so keep your hopes up.","zh":"沒有任何艱難的時刻會永遠持續，所以要保持希望。"}]},{"word":"forget","pos":"v.","phonetic":"[fɚˈgɛt]","meaning":"忘記","definition":"to fail to remember something","collocations":["forget about it","forget to do something","never forget"],"example":"Don't forget to bring your umbrella tomorrow.","exampleZh":"明天別忘了帶雨傘。","synonyms":["overlook"],"level":1,"theme":"教育與學習","examples":[{"en":"Don't forget to bring your umbrella tomorrow.","zh":"明天別忘了帶雨傘。"},{"en":"I will never forget the day I first rode a bicycle.","zh":"我永遠不會忘記我第一次騎腳踏車的那一天。"},{"en":"He forgot to turn off the lights before leaving home.","zh":"他離家前忘了關燈。"}]},{"word":"forgetful","pos":"adj.","phonetic":"[fɚˈgɛtfəl]","meaning":"健忘的","definition":"tending to forget things easily","collocations":["forgetful person","become forgetful"],"example":"My grandfather has become quite forgetful in his old age.","exampleZh":"我爺爺年紀大了變得相當健忘。","synonyms":["absent-minded"],"level":4,"theme":"性質與描述","examples":[{"en":"My grandfather has become quite forgetful in his old age.","zh":"我爺爺年紀大了變得相當健忘。"},{"en":"Being forgetful, she often leaves her umbrella on the bus.","zh":"由於健忘，她常常把雨傘忘在公車上。"},{"en":"As people grow older, they may become more forgetful.","zh":"人隨著年齡增長，可能會變得更健忘。"}]},{"word":"forgive","pos":"v.","phonetic":"[fɚˈgɪv]","meaning":"原諒","definition":"to stop feeling anger toward someone for an offense","collocations":["forgive and forget","forgive someone for","ask for forgiveness"],"example":"She finally forgave her brother for the mistake.","exampleZh":"她終於原諒了哥哥的過錯。","synonyms":["pardon","excuse"],"level":3,"theme":"情緒與感受","examples":[{"en":"She finally forgave her brother for the mistake.","zh":"她終於原諒了哥哥的過錯。"},{"en":"It takes a kind heart to forgive and forget so easily.","zh":"要能如此輕易地既往不咎，需要一顆善良的心。"},{"en":"He apologized and asked his sister to forgive him.","zh":"他道歉並請求姊姊原諒他。"}]},{"word":"fork","pos":"n.","phonetic":"[fork]","meaning":"叉子","definition":"a utensil with prongs used for eating","collocations":["knife and fork","use a fork","fork in the road"],"example":"He picked up his fork and started eating.","exampleZh":"他拿起叉子開始吃飯。","synonyms":[],"level":1,"theme":"食物與烹飪","examples":[{"en":"He picked up his fork and started eating.","zh":"他拿起叉子開始吃飯。"},{"en":"In Western dining, people usually eat with a knife and fork.","zh":"在西式用餐中，人們通常用刀叉進食。"},{"en":"We reached a fork in the road and turned left.","zh":"我們來到一個岔路口，然後左轉。"}]},{"word":"form","pos":"n. / v.","phonetic":"[form]","meaning":"形式；表格；形成","definition":"the shape of something; a document to fill in; to create","collocations":["fill out a form","in the form of","form a group"],"example":"Please fill out this application form.","exampleZh":"請填寫這張申請表。","synonyms":["shape","document"],"level":2,"theme":"抽象概念","examples":[{"en":"Please fill out this application form.","zh":"請填寫這張申請表。"},{"en":"The students formed a group to work on the science project.","zh":"學生們組成一個小組來做這個科學專案。"},{"en":"Please fill out this form before you see the doctor.","zh":"看醫生之前，請先填寫這張表格。"}]},{"word":"formal","pos":"adj.","phonetic":"[ˈfɔrml̩]","meaning":"正式的","definition":"following established rules or conventions","collocations":["formal dress","formal education","formal event"],"example":"You should wear formal clothes to the interview.","exampleZh":"你應該穿正式服裝去面試。","synonyms":["official","proper"],"level":3,"theme":"服裝與外表","examples":[{"en":"You should wear formal clothes to the interview.","zh":"你應該穿正式服裝去面試。"},{"en":"Everyone wore formal dress to the awards ceremony.","zh":"每個人都穿著正式服裝參加頒獎典禮。"},{"en":"A formal education gives students a solid foundation for life.","zh":"正規教育為學生的人生打下堅實的基礎。"}]},{"word":"format","pos":"n. / v.","phonetic":"[ˈfɔrmæt]","meaning":"格式；使成形式","definition":"the way something is arranged or presented","collocations":["file format","in this format","format a document"],"example":"Please save the file in PDF format.","exampleZh":"請將檔案存成PDF格式。","synonyms":["layout","structure"],"level":4,"theme":"科技與媒體","examples":[{"en":"Please save the file in PDF format.","zh":"請將檔案存成PDF格式。"},{"en":"The teacher asked us to format the report neatly.","zh":"老師要求我們把報告排版得整齊。"},{"en":"This video is saved in a format that most phones can play.","zh":"這段影片儲存成大多數手機都能播放的格式。"}]},{"word":"formation","pos":"n.","phonetic":"[fɔrˈmeʃən]","meaning":"形成；隊形","definition":"the process of forming something, or an arrangement of things","collocations":["rock formation","in formation","cloud formation"],"example":"The formation of the new team took several months.","exampleZh":"新團隊的組成花了好幾個月。","synonyms":["creation"],"level":5,"theme":"抽象概念","examples":[{"en":"The formation of the new team took several months.","zh":"新團隊的組成花了好幾個月。"},{"en":"Tourists admired the strange rock formation along the coast.","zh":"遊客們讚嘆著海岸邊奇特的岩石構造。"},{"en":"The birds flew across the sky in a perfect V formation.","zh":"鳥兒以完美的 V 字隊形飛過天空。"}]},{"word":"former","pos":"adj.","phonetic":"[ˈfɔrmɚ]","meaning":"以前的；前者的","definition":"having been previously; the first of two mentioned","collocations":["former president","former student","the former and the latter"],"example":"The former president gave a speech at the university.","exampleZh":"前任總統在這所大學發表演說。","synonyms":["previous","past"],"level":4,"theme":"時間與空間","examples":[{"en":"The former president gave a speech at the university.","zh":"前任總統在這所大學發表演說。"},{"en":"A former student returned to thank her favorite teacher.","zh":"一位以前的學生回來感謝她最喜愛的老師。"},{"en":"Between tea and coffee, I always prefer the former.","zh":"在茶和咖啡之間，我總是比較喜歡前者。"}]},{"word":"formula","pos":"n.","phonetic":"[ˈfɔrmjələ]","meaning":"公式；配方","definition":"a mathematical rule expressed in symbols, or a fixed method","collocations":["chemical formula","secret formula","math formula"],"example":"Students must memorize the formula for the exam.","exampleZh":"學生必須為考試背誦這個公式。","synonyms":["equation"],"level":4,"theme":"科學與數學","examples":[{"en":"Students must memorize the formula for the exam.","zh":"學生必須為考試背誦這個公式。"},{"en":"The teacher wrote the math formula clearly on the board.","zh":"老師把數學公式清楚地寫在黑板上。"},{"en":"The company keeps the formula for its drink a secret.","zh":"這家公司對其飲料的配方保密。"}]},{"word":"fortunate","pos":"adj.","phonetic":"[ˈfɔrtʃənɪt]","meaning":"幸運的","definition":"having good luck; lucky","collocations":["fortunate enough","a fortunate event"],"example":"We were fortunate enough to find a good seat.","exampleZh":"我們很幸運找到了好座位。","synonyms":["lucky"],"level":4,"theme":"情緒與感受","examples":[{"en":"We were fortunate enough to find a good seat.","zh":"我們很幸運找到了好座位。"},{"en":"We were fortunate enough to catch the last train home.","zh":"我們夠幸運，趕上了回家的最後一班火車。"},{"en":"She felt fortunate to have such supportive parents.","zh":"她覺得很幸運能有如此支持她的父母。"}]},{"word":"fortune","pos":"n.","phonetic":"[ˈfɔrtʃən]","meaning":"財富；運氣","definition":"a large amount of money; chance in life","collocations":["make a fortune","good fortune","fortune teller"],"example":"He made a fortune from his online business.","exampleZh":"他透過線上事業賺了一大筆財富。","synonyms":["wealth","luck"],"level":4,"theme":"商業與金錢","examples":[{"en":"He made a fortune from his online business.","zh":"他透過線上事業賺了一大筆財富。"},{"en":"The old sailor believed the ring brought him good fortune.","zh":"這位老水手相信這枚戒指為他帶來了好運。"},{"en":"She made a small fortune by selling handmade jewelry.","zh":"她靠賣手工首飾賺了一小筆財富。"}]},{"word":"forward","pos":"adv. / adj. / v.","phonetic":"[ˈfɔrwɚd]","meaning":"向前；期待；轉發","definition":"toward the front or ahead; to send onward","collocations":["look forward to","move forward","forward an email"],"example":"I look forward to seeing you this weekend.","exampleZh":"我很期待這週末見到你。","synonyms":["ahead","onward"],"level":2,"theme":"時間與空間","examples":[{"en":"I look forward to seeing you this weekend.","zh":"我很期待這週末見到你。"},{"en":"The whole team is ready to move forward with the new plan.","zh":"整個團隊都準備好推動這項新計畫了。"},{"en":"Could you forward that email to me when you get a chance?","zh":"你有空的時候可以把那封電子郵件轉寄給我嗎？"}]},{"word":"fossil","pos":"n.","phonetic":"[ˈfɑsl̩]","meaning":"化石","definition":"the remains of an ancient plant or animal preserved in rock","collocations":["fossil fuel","dig up a fossil","dinosaur fossil"],"example":"Scientists discovered a dinosaur fossil in the desert.","exampleZh":"科學家在沙漠中發現了一個恐龍化石。","synonyms":[],"level":4,"theme":"自然與環境","examples":[{"en":"Scientists discovered a dinosaur fossil in the desert.","zh":"科學家在沙漠中發現了一個恐龍化石。"},{"en":"Burning fossil fuel releases gases that harm the environment.","zh":"燃燒化石燃料會釋放危害環境的氣體。"},{"en":"The students were excited to dig up a small fossil.","zh":"學生們對挖出一塊小化石感到興奮。"}]},{"word":"foster","pos":"v. / adj.","phonetic":"[ˈfɔstɚ]","meaning":"養育；培養；寄養的","definition":"to encourage development, or to bring up a child not one's own","collocations":["foster family","foster a relationship","foster child"],"example":"The program aims to foster creativity in young children.","exampleZh":"這項計畫旨在培養幼兒的創造力。","synonyms":["nurture","promote"],"level":5,"theme":"人物與家庭","examples":[{"en":"The program aims to foster creativity in young children.","zh":"這項計畫旨在培養幼兒的創造力。"},{"en":"Reading to children helps foster a lifelong love of books.","zh":"唸書給孩子聽有助於培養他們一生對書本的熱愛。"},{"en":"The kind couple welcomed a foster child into their home.","zh":"這對善良的夫妻歡迎一名寄養孩童進入他們的家。"}]},{"word":"foul","pos":"n. / adj.","phonetic":"[faʊl]","meaning":"犯規；惡臭的；骯髒的","definition":"an act that breaks the rules of a game, or extremely unpleasant","collocations":["commit a foul","foul smell","foul play"],"example":"The referee called a foul against the defender.","exampleZh":"裁判判定後衛犯規。","synonyms":["dirty","offensive"],"level":5,"theme":"運動與休閒","examples":[{"en":"The referee called a foul against the defender.","zh":"裁判判定後衛犯規。"},{"en":"A foul smell came from the garbage left in the sun.","zh":"留在太陽下的垃圾散發出一股惡臭。"},{"en":"The player committed a foul and received a yellow card.","zh":"這名球員犯規並吃了一張黃牌。"}]},{"word":"found","pos":"v.","phonetic":"[faʊnd]","meaning":"建立；創立","definition":"to establish an organization or institution","collocations":["found a company","newly founded","found a school"],"example":"The company was founded in 1990.","exampleZh":"這家公司成立於1990年。","synonyms":["establish","create"],"level":3,"theme":"商業與金錢","examples":[{"en":"The company was founded in 1990.","zh":"這家公司成立於1990年。"},{"en":"Two brothers founded the small bakery over fifty years ago.","zh":"兩兄弟在五十多年前創立了這家小烘焙坊。"},{"en":"The newly founded club already has over a hundred members.","zh":"這個新成立的社團已經有超過一百名成員。"}]},{"word":"foundation","pos":"n.","phonetic":"[faʊnˈdeʃən]","meaning":"基礎；地基；基金會","definition":"the base of a building; an underlying basis; a charitable organization","collocations":["lay the foundation","charity foundation","foundation course"],"example":"A strong foundation is essential for a tall building.","exampleZh":"堅固的地基對高樓來說是必要的。","synonyms":["base","basis"],"level":5,"theme":"抽象概念","examples":[{"en":"A strong foundation is essential for a tall building.","zh":"堅固的地基對高樓來說是必要的。"},{"en":"The workers spent weeks laying the foundation of the house.","zh":"工人們花了好幾週打房子的地基。"},{"en":"The charity foundation helps poor children go to school.","zh":"這個慈善基金會幫助貧困的孩子上學。"}]},{"word":"founder","pos":"n.","phonetic":"[ˈfaʊndɚ]","meaning":"創辦人","definition":"a person who establishes an organization or institution","collocations":["company founder","co-founder"],"example":"The founder of the company started with almost no money.","exampleZh":"這家公司的創辦人幾乎是白手起家。","synonyms":["creator","originator"],"level":5,"theme":"工作與職業","examples":[{"en":"The founder of the company started with almost no money.","zh":"這家公司的創辦人幾乎是白手起家。"},{"en":"The founder of the school still visits the students every year.","zh":"這所學校的創辦人每年仍會來探望學生。"},{"en":"As a young co-founder, she worked day and night on the app.","zh":"身為年輕的共同創辦人，她日以繼夜地開發這個應用程式。"}]},{"word":"fountain","pos":"n.","phonetic":"[ˈfaʊntn̩]","meaning":"噴泉","definition":"a structure that shoots water into the air decoratively","collocations":["water fountain","fountain pen","public fountain"],"example":"Tourists gathered around the fountain to take photos.","exampleZh":"遊客們聚集在噴泉旁拍照。","synonyms":[],"level":3,"theme":"居家與生活","examples":[{"en":"Tourists gathered around the fountain to take photos.","zh":"遊客們聚集在噴泉旁拍照。"},{"en":"Children laughed as they played near the public fountain.","zh":"孩子們在公共噴泉旁玩耍時開心地笑著。"},{"en":"He signed the important letter with an old fountain pen.","zh":"他用一支老舊的鋼筆簽署了這封重要的信。"}]},{"word":"fox","pos":"n.","phonetic":"[fɑks]","meaning":"狐狸","definition":"a small wild animal known for its cunning","collocations":["a sly fox","fox hunting"],"example":"A fox was seen crossing the road at night.","exampleZh":"晚上有人看到一隻狐狸過馬路。","synonyms":[],"level":2,"theme":"動物與植物","examples":[{"en":"A fox was seen crossing the road at night.","zh":"晚上有人看到一隻狐狸過馬路。"},{"en":"The clever fox quietly slipped past the sleeping dogs.","zh":"這隻聰明的狐狸悄悄地溜過了熟睡的狗。"},{"en":"In many stories, the fox is shown as a sly animal.","zh":"在許多故事中，狐狸被描繪成狡猾的動物。"}]},{"word":"fragile","pos":"adj.","phonetic":"[ˈfrædʒəl]","meaning":"易碎的；脆弱的","definition":"easily broken or damaged","collocations":["fragile glass","fragile relationship","extremely fragile"],"example":"Please be careful, the vase is very fragile.","exampleZh":"請小心，這個花瓶很容易破。","synonyms":["delicate","weak"],"level":5,"theme":"性質與描述","examples":[{"en":"Please be careful, the vase is very fragile.","zh":"請小心，這個花瓶很容易破。"},{"en":"Please handle these fragile glasses gently while washing them.","zh":"清洗這些易碎的玻璃杯時請輕柔處理。"},{"en":"Their friendship became fragile after the big argument.","zh":"在那場大爭吵之後，他們的友誼變得脆弱。"}]},{"word":"fragment","pos":"n.","phonetic":"[ˈfrægmənt]","meaning":"碎片；片段","definition":"a small piece broken off from something larger","collocations":["a fragment of glass","broken into fragments"],"example":"She found a fragment of the ancient pottery.","exampleZh":"她找到一片古代陶器的碎片。","synonyms":["piece","fraction"],"level":5,"theme":"性質與描述","examples":[{"en":"She found a fragment of the ancient pottery.","zh":"她找到一片古代陶器的碎片。"},{"en":"A sharp fragment of glass lay on the kitchen floor.","zh":"廚房地板上躺著一片鋒利的玻璃碎片。"},{"en":"The old vase fell and broke into tiny fragments.","zh":"這個古老的花瓶掉落，碎成了細小的碎片。"}]},{"word":"fragrance","pos":"n.","phonetic":"[ˈfregrəns]","meaning":"香味；芳香","definition":"a pleasant, sweet smell","collocations":["sweet fragrance","the fragrance of flowers"],"example":"The fragrance of roses filled the garden.","exampleZh":"玫瑰的香味瀰漫了整個花園。","synonyms":["scent","aroma"],"level":4,"theme":"性質與描述","examples":[{"en":"The fragrance of roses filled the garden.","zh":"玫瑰的香味瀰漫了整個花園。"},{"en":"The sweet fragrance of fresh bread filled the small shop.","zh":"新鮮麵包的甜美香氣瀰漫了這家小店。"},{"en":"She loves the gentle fragrance of jasmine in the evening.","zh":"她喜歡傍晚時茉莉花淡淡的芳香。"}]},{"word":"fragrant","pos":"adj.","phonetic":"[ˈfregrənt]","meaning":"芳香的","definition":"having a pleasant, sweet smell","collocations":["fragrant flowers","fragrant tea"],"example":"She poured a cup of fragrant tea for her guests.","exampleZh":"她為客人倒了一杯芳香的茶。","synonyms":["scented","aromatic"],"level":4,"theme":"性質與描述","examples":[{"en":"She poured a cup of fragrant tea for her guests.","zh":"她為客人倒了一杯芳香的茶。"},{"en":"The garden was full of fragrant flowers in early summer.","zh":"初夏時，花園裡開滿了芬芳的花朵。"},{"en":"She served her guests a cup of fragrant jasmine tea.","zh":"她為客人端上一杯芳香的茉莉花茶。"}]},{"word":"frame","pos":"n. / v.","phonetic":"[frem]","meaning":"框架；相框","definition":"a rigid structure surrounding something; to enclose in a border","collocations":["picture frame","frame of mind","window frame"],"example":"She put the photo in a wooden frame.","exampleZh":"她把照片放進木製相框裡。","synonyms":["border","structure"],"level":3,"theme":"居家與生活","examples":[{"en":"She put the photo in a wooden frame.","zh":"她把照片放進木製相框裡。"},{"en":"She hung the family photo in a golden picture frame.","zh":"她把全家福掛在一個金色的相框裡。"},{"en":"The old window frame was painted a bright shade of blue.","zh":"舊的窗框被漆成明亮的藍色。"}]},{"word":"framework","pos":"n.","phonetic":"[ˈfrem͵wɝk]","meaning":"架構；框架","definition":"a basic structure supporting a system or concept","collocations":["legal framework","within a framework","conceptual framework"],"example":"The government set up a new legal framework for businesses.","exampleZh":"政府為企業設立了新的法律架構。","synonyms":["structure"],"level":6,"theme":"抽象概念","examples":[{"en":"The government set up a new legal framework for businesses.","zh":"政府為企業設立了新的法律架構。"},{"en":"The essay follows a clear framework with three main parts.","zh":"這篇文章遵循一個清楚的架構，分為三大部分。"},{"en":"A good legal framework protects the rights of workers.","zh":"良好的法律架構保障勞工的權益。"}]},{"word":"frank","pos":"adj.","phonetic":"[fræŋk]","meaning":"坦率的；直言的","definition":"open and honest in speech","collocations":["to be frank","frank discussion","frank opinion"],"example":"To be frank, I don't think this plan will work.","exampleZh":"坦白說，我不認為這個計畫行得通。","synonyms":["honest","candid"],"level":4,"theme":"溝通與語言","examples":[{"en":"To be frank, I don't think this plan will work.","zh":"坦白說，我不認為這個計畫行得通。"},{"en":"I appreciate your frank opinion about my first draft.","zh":"我很感激你對我初稿的坦率意見。"},{"en":"They had a frank discussion about the team's weaknesses.","zh":"他們就團隊的弱點進行了坦率的討論。"}]},{"word":"frantic","pos":"adj.","phonetic":"[ˈfræntɪk]","meaning":"驚慌失措的；瘋狂的","definition":"wild or distraught with fear, anxiety, or other emotion","collocations":["frantic search","frantic effort"],"example":"She made a frantic call for help.","exampleZh":"她驚慌地打電話求救。","synonyms":["panicked","desperate"],"level":6,"theme":"情緒與感受","examples":[{"en":"She made a frantic call for help.","zh":"她驚慌地打電話求救。"},{"en":"After a frantic search, she finally found her passport.","zh":"一陣驚慌失措的搜尋後，她終於找到了她的護照。"},{"en":"The parents made a frantic effort to reach the hospital in time.","zh":"父母瘋狂地努力想及時趕到醫院。"}]},{"word":"fraud","pos":"n.","phonetic":"[frɔd]","meaning":"詐欺；騙子","definition":"wrongful or criminal deception intended to result in gain","collocations":["commit fraud","credit card fraud"],"example":"He was arrested for committing bank fraud.","exampleZh":"他因銀行詐欺罪被逮捕。","synonyms":["deception","scam"],"level":6,"theme":"政治與法律","examples":[{"en":"He was arrested for committing bank fraud.","zh":"他因銀行詐欺罪被逮捕。"},{"en":"The police warned people about a new kind of credit card fraud.","zh":"警方提醒民眾注意一種新型的信用卡詐欺。"},{"en":"The man was sent to prison for committing fraud.","zh":"這名男子因犯下詐欺罪而入獄。"}]},{"word":"freak","pos":"n. / adj.","phonetic":"[frik]","meaning":"怪人；狂熱者；異常的","definition":"a person regarded as strange, or something highly unusual","collocations":["a freak accident","fitness freak","freak out"],"example":"It was a freak accident that no one expected.","exampleZh":"那是一場沒人預料到的意外事故。","synonyms":["oddity"],"level":5,"theme":"性質與描述","examples":[{"en":"It was a freak accident that no one expected.","zh":"那是一場沒人預料到的意外事故。"},{"en":"A freak storm suddenly hit the coast without any warning.","zh":"一場異常的暴風雨毫無預警地襲擊了海岸。"},{"en":"My brother is a fitness freak who exercises twice a day.","zh":"我哥哥是個健身狂，每天運動兩次。"}]},{"word":"freckle","pos":"n.","phonetic":"[ˈfrɛkl̩]","meaning":"雀斑","definition":"a small light brown spot on the skin","collocations":["freckles on the nose","covered in freckles"],"example":"She has cute freckles across her nose.","exampleZh":"她的鼻子上有可愛的雀斑。","synonyms":[],"level":4,"theme":"服裝與外表","examples":[{"en":"She has cute freckles across her nose.","zh":"她的鼻子上有可愛的雀斑。"},{"en":"After the summer, his cheeks were covered in freckles.","zh":"夏天過後，他的臉頰上佈滿了雀斑。"},{"en":"The little girl has tiny freckles across her nose.","zh":"這個小女孩的鼻子上有細小的雀斑。"}]},{"word":"free","pos":"adj. / v.","phonetic":"[fri]","meaning":"自由的；免費的；釋放","definition":"not under control; costing nothing; to release","collocations":["free time","for free","set free"],"example":"Admission to the museum is free on Sundays.","exampleZh":"星期天參觀博物館免費入場。","synonyms":["liberated","gratis"],"level":1,"theme":"抽象概念","examples":[{"en":"Admission to the museum is free on Sundays.","zh":"星期天參觀博物館免費入場。"},{"en":"In my free time, I enjoy painting and reading novels.","zh":"在空閒時間，我喜歡畫畫和讀小說。"},{"en":"The children set the injured bird free after it recovered.","zh":"小鳥康復後，孩子們把牠放生了。"}]},{"word":"freedom","pos":"n.","phonetic":"[ˈfridəm]","meaning":"自由","definition":"the power to act, speak, or think without restraint","collocations":["freedom of speech","gain freedom","personal freedom"],"example":"People fought hard for freedom of speech.","exampleZh":"人們為了言論自由奮力抗爭。","synonyms":["liberty","independence"],"level":3,"theme":"政治與法律","examples":[{"en":"People fought hard for freedom of speech.","zh":"人們為了言論自由奮力抗爭。"},{"en":"Freedom of speech allows people to express their opinions.","zh":"言論自由讓人們能夠表達自己的意見。"},{"en":"After years of struggle, the people finally gained their freedom.","zh":"經過多年的奮鬥，人民終於獲得了自由。"}]},{"word":"freeze","pos":"v.","phonetic":"[friz]","meaning":"結冰；冷凍","definition":"to become solid due to extreme cold","collocations":["freeze to death","freeze food","freezing cold"],"example":"The lake froze completely during the harsh winter.","exampleZh":"湖水在嚴冬中完全結冰了。","synonyms":["ice over"],"level":2,"theme":"天氣與季節","examples":[{"en":"The lake froze completely during the harsh winter.","zh":"湖水在嚴冬中完全結冰了。"},{"en":"You can freeze the extra soup and eat it next week.","zh":"你可以把多出來的湯冷凍起來，下週再吃。"},{"en":"The water in the pipes froze during the freezing cold night.","zh":"在酷寒的夜裡，水管裡的水結冰了。"}]},{"word":"freezer","pos":"n.","phonetic":"[ˈfrizɚ]","meaning":"冷凍庫","definition":"an appliance for freezing and storing food","collocations":["put in the freezer","freezer bag"],"example":"She put the ice cream in the freezer.","exampleZh":"她把冰淇淋放進冷凍庫。","synonyms":[],"level":2,"theme":"居家與生活","examples":[{"en":"She put the ice cream in the freezer.","zh":"她把冰淇淋放進冷凍庫。"},{"en":"Please put the leftover meat in the freezer tonight.","zh":"今晚請把剩下的肉放進冷凍庫。"},{"en":"She stored the dumplings in a freezer bag to keep them fresh.","zh":"她把水餃裝進冷凍袋以保持新鮮。"}]},{"word":"freight","pos":"n.","phonetic":"[fret]","meaning":"貨運；貨物","definition":"goods transported by truck, train, ship, or aircraft","collocations":["freight train","air freight","freight charges"],"example":"The goods were shipped by freight train.","exampleZh":"這些貨物是用貨運火車運送的。","synonyms":["cargo"],"level":6,"theme":"交通與旅行","examples":[{"en":"The goods were shipped by freight train.","zh":"這些貨物是用貨運火車運送的。"},{"en":"A long freight train slowly crossed the wide bridge.","zh":"一列長長的貨運列車緩緩駛過這座寬闊的橋。"},{"en":"Sending the package by air freight is faster but more expensive.","zh":"以空運寄送這個包裹較快，但也較貴。"}]},{"word":"frequency","pos":"n.","phonetic":"[ˈfrikwənsɪ]","meaning":"頻率","definition":"the rate at which something occurs over time","collocations":["radio frequency","high frequency","increase in frequency"],"example":"The frequency of earthquakes has increased this year.","exampleZh":"今年地震發生的頻率增加了。","synonyms":["rate"],"level":5,"theme":"科學與數學","examples":[{"en":"The frequency of earthquakes has increased this year.","zh":"今年地震發生的頻率增加了。"},{"en":"The doctor was worried about the increasing frequency of her headaches.","zh":"醫生擔心她頭痛的頻率越來越高。"},{"en":"Some animals can hear sounds at a very high frequency.","zh":"有些動物能聽見非常高頻的聲音。"}]},{"word":"frequent","pos":"adj.","phonetic":"[ˈfrikwənt]","meaning":"頻繁的","definition":"occurring often or at close intervals","collocations":["frequent visitor","frequent flyer","frequent trips"],"example":"He is a frequent traveler between Taipei and Tokyo.","exampleZh":"他經常往返台北和東京之間。","synonyms":["regular","common"],"level":4,"theme":"性質與描述","examples":[{"en":"He is a frequent traveler between Taipei and Tokyo.","zh":"他經常往返台北和東京之間。"},{"en":"She is a frequent visitor to the city library on weekends.","zh":"她週末經常到市立圖書館。"},{"en":"His job requires frequent trips between two different cities.","zh":"他的工作需要頻繁往返於兩座不同的城市。"}]},{"word":"fresh","pos":"adj.","phonetic":"[frɛʃ]","meaning":"新鮮的","definition":"recently made or obtained; not stale","collocations":["fresh air","fresh fruit","fresh start"],"example":"We bought fresh vegetables at the market this morning.","exampleZh":"我們今早在市場買了新鮮蔬菜。","synonyms":["new","crisp"],"level":2,"theme":"食物與烹飪","examples":[{"en":"We bought fresh vegetables at the market this morning.","zh":"我們今早在市場買了新鮮蔬菜。"},{"en":"We opened the windows to let in some fresh air.","zh":"我們打開窗戶，讓一些新鮮空氣進來。"},{"en":"Moving to a new town gave her a fresh start.","zh":"搬到一個新城鎮讓她有了一個全新的開始。"}]},{"word":"freshman","pos":"n.","phonetic":"[ˈfrɛʃmən]","meaning":"大一新生；高一新生","definition":"a first-year student at high school or college","collocations":["freshman year","college freshman"],"example":"As a freshman, she felt nervous on the first day.","exampleZh":"身為新生，她第一天感到很緊張。","synonyms":[],"level":3,"theme":"教育與學習","examples":[{"en":"As a freshman, she felt nervous on the first day.","zh":"身為新生，她第一天感到很緊張。"},{"en":"During his freshman year, he joined the school basketball team.","zh":"在高一那年，他加入了學校籃球隊。"},{"en":"As a college freshman, she was eager to make new friends.","zh":"身為大一新生，她渴望結交新朋友。"}]},{"word":"friction","pos":"n.","phonetic":"[ˈfrɪkʃən]","meaning":"摩擦；摩擦力；不和","definition":"the resistance one surface encounters when moving over another, or conflict","collocations":["friction between","reduce friction"],"example":"Friction between the two teams caused delays in the project.","exampleZh":"兩個團隊之間的摩擦導致專案延誤。","synonyms":["conflict","resistance"],"level":6,"theme":"科學與數學","examples":[{"en":"Friction between the two teams caused delays in the project.","zh":"兩個團隊之間的摩擦導致專案延誤。"},{"en":"Oil is used to reduce friction between the moving parts.","zh":"機油被用來減少活動零件之間的摩擦。"},{"en":"There was growing friction between the two departments.","zh":"兩個部門之間的摩擦日益加劇。"}]},{"word":"friend","pos":"n.","phonetic":"[frɛnd]","meaning":"朋友","definition":"a person one likes and trusts","collocations":["best friend","make friends","close friend"],"example":"She has been my best friend since childhood.","exampleZh":"她從小就是我最好的朋友。","synonyms":["companion","buddy"],"level":1,"theme":"人物與家庭","examples":[{"en":"She has been my best friend since childhood.","zh":"她從小就是我最好的朋友。"},{"en":"It is easy to make friends when you join a club.","zh":"當你加入社團時，很容易結交朋友。"},{"en":"A true friend will support you during difficult times.","zh":"真正的朋友會在困難時支持你。"}]},{"word":"friendly","pos":"adj.","phonetic":"[ˈfrɛndlɪ]","meaning":"友善的","definition":"kind and pleasant toward others","collocations":["friendly smile","user-friendly","friendly relationship"],"example":"Our new neighbors are very friendly.","exampleZh":"我們的新鄰居非常友善。","synonyms":["kind","amiable"],"level":1,"theme":"情緒與感受","examples":[{"en":"Our new neighbors are very friendly.","zh":"我們的新鄰居非常友善。"},{"en":"The new app is very user-friendly and easy to learn.","zh":"這款新的應用程式非常好用且容易上手。"},{"en":"The shopkeeper greeted every customer with a friendly smile.","zh":"店主以友善的微笑迎接每一位顧客。"}]},{"word":"friendship","pos":"n.","phonetic":"[ˈfrɛndʃɪp]","meaning":"友誼","definition":"a relationship of mutual affection between people","collocations":["lifelong friendship","build friendship"],"example":"Their friendship has lasted for over twenty years.","exampleZh":"他們的友誼已經持續了二十多年。","synonyms":["companionship"],"level":2,"theme":"人物與家庭","examples":[{"en":"Their friendship has lasted for over twenty years.","zh":"他們的友誼已經持續了二十多年。"},{"en":"Playing on the same team helped them build a strong friendship.","zh":"在同一隊打球幫助他們建立了深厚的友誼。"},{"en":"Their lifelong friendship began on the very first day of school.","zh":"他們一生的友誼始於上學的第一天。"}]},{"word":"fright","pos":"n.","phonetic":"[fraɪt]","meaning":"驚嚇；恐懼","definition":"a sudden feeling of intense fear","collocations":["get a fright","give someone a fright","jump with fright"],"example":"The loud noise gave her quite a fright.","exampleZh":"那個巨大的噪音把她嚇了一跳。","synonyms":["scare","terror"],"level":4,"theme":"情緒與感受","examples":[{"en":"The loud noise gave her quite a fright.","zh":"那個巨大的噪音把她嚇了一跳。"},{"en":"The sudden knock at the door gave me a terrible fright.","zh":"門上突然的敲擊聲把我嚇了一大跳。"},{"en":"She jumped with fright when the cat leaped onto the table.","zh":"當貓跳上桌子時，她嚇得跳了起來。"}]},{"word":"frighten","pos":"v.","phonetic":"[ˈfraɪtn̩]","meaning":"使驚嚇；使害怕","definition":"to make someone feel afraid","collocations":["frighten away","easily frightened"],"example":"The sudden thunder frightened the little child.","exampleZh":"突如其來的雷聲嚇到了那個小孩。","synonyms":["scare","alarm"],"level":3,"theme":"情緒與感受","examples":[{"en":"The sudden thunder frightened the little child.","zh":"突如其來的雷聲嚇到了那個小孩。"},{"en":"The loud fireworks frightened the dogs in the neighborhood.","zh":"響亮的煙火嚇壞了附近的狗。"},{"en":"The scarecrow is used to frighten away hungry birds.","zh":"稻草人被用來嚇走飢餓的鳥兒。"}]},{"word":"fringe","pos":"n.","phonetic":"[frɪndʒ]","meaning":"邊緣；瀏海","definition":"the outer edge of an area, or hair cut across the forehead","collocations":["fringe benefit","on the fringe of"],"example":"The village lies on the fringe of the forest.","exampleZh":"這個村莊位於森林的邊緣。","synonyms":["edge","border"],"level":6,"theme":"時間與空間","examples":[{"en":"The village lies on the fringe of the forest.","zh":"這個村莊位於森林的邊緣。"},{"en":"Their farm sits on the fringe of a quiet little town.","zh":"他們的農場座落在一個寧靜小鎮的邊緣。"},{"en":"She trimmed her fringe so it would not cover her eyes.","zh":"她修剪了瀏海，讓它不會遮住眼睛。"}]},{"word":"frog","pos":"n.","phonetic":"[frɔg]","meaning":"青蛙","definition":"a small tailless amphibian that jumps","collocations":["frog pond","jumping frog","green frog"],"example":"We heard frogs croaking near the pond at night.","exampleZh":"我們晚上聽到池塘附近青蛙的叫聲。","synonyms":[],"level":1,"theme":"動物與植物","examples":[{"en":"We heard frogs croaking near the pond at night.","zh":"我們晚上聽到池塘附近青蛙的叫聲。"},{"en":"A green frog jumped into the pond with a loud splash.","zh":"一隻綠色的青蛙撲通一聲跳進了池塘。"},{"en":"The children watched tiny frogs hopping among the leaves.","zh":"孩子們看著小青蛙在葉子間跳來跳去。"}]},{"word":"front","pos":"n. / adj.","phonetic":"[frʌnt]","meaning":"前面；前方的","definition":"the foremost part or side of something","collocations":["in front of","front door","front page"],"example":"There is a big garden in front of the house.","exampleZh":"房子前面有一個大花園。","synonyms":["forefront"],"level":1,"theme":"時間與空間","examples":[{"en":"There is a big garden in front of the house.","zh":"房子前面有一個大花園。"},{"en":"The news about the flood appeared on the front page.","zh":"關於洪水的新聞出現在頭版。"},{"en":"Someone left a package in front of our front door.","zh":"有人在我們的前門放了一個包裹。"}]},{"word":"frontier","pos":"n.","phonetic":"[frʌnˈtɪr]","meaning":"邊界；前沿；新領域","definition":"a border between two countries, or the edge of new knowledge","collocations":["new frontier","frontier town","the frontier of science"],"example":"Scientists are exploring the frontier of medical research.","exampleZh":"科學家正在探索醫學研究的新領域。","synonyms":["border","boundary"],"level":6,"theme":"科學與數學","examples":[{"en":"Scientists are exploring the frontier of medical research.","zh":"科學家正在探索醫學研究的新領域。"},{"en":"Space remains an exciting new frontier for young scientists.","zh":"太空對年輕科學家來說仍是令人興奮的新領域。"},{"en":"Long ago, the small frontier town grew quickly during the gold rush.","zh":"很久以前，這座小邊境城鎮在淘金熱期間迅速發展。"}]},{"word":"frost","pos":"n.","phonetic":"[frɔst]","meaning":"霜","definition":"a thin layer of ice that forms on cold surfaces","collocations":["frost on the grass","early frost"],"example":"There was frost on the car windows this morning.","exampleZh":"今天早上車窗上結了一層霜。","synonyms":["ice"],"level":3,"theme":"天氣與季節","examples":[{"en":"There was frost on the car windows this morning.","zh":"今天早上車窗上結了一層霜。"},{"en":"A thin layer of frost covered the grass this cold morning.","zh":"在這個寒冷的早晨，一層薄霜覆蓋了草地。"},{"en":"An early frost damaged many of the farmer's young plants.","zh":"一場早來的霜害了農夫許多幼小的植株。"}]},{"word":"frown","pos":"v. / n.","phonetic":"[fraʊn]","meaning":"皺眉","definition":"to bring the eyebrows together showing displeasure","collocations":["frown at","deep frown","frown upon"],"example":"She frowned when she read the bad news.","exampleZh":"她讀到壞消息時皺起了眉頭。","synonyms":["scowl","glower"],"level":4,"theme":"情緒與感受","examples":[{"en":"She frowned when she read the bad news.","zh":"她讀到壞消息時皺起了眉頭。"},{"en":"The teacher frowned at the students who were talking loudly.","zh":"老師對大聲說話的學生皺起了眉頭。"},{"en":"A deep frown appeared on his face as he read the letter.","zh":"當他讀信時，他臉上出現了深深的皺眉。"}]},{"word":"frozen","pos":"adj.","phonetic":"[ˈfrozn̩]","meaning":"冷凍的；結冰的","definition":"turned into ice; extremely cold","collocations":["frozen food","frozen lake","frozen solid"],"example":"We bought some frozen dumplings from the store.","exampleZh":"我們在店裡買了一些冷凍水餃。","synonyms":["iced"],"level":2,"theme":"食物與烹飪","examples":[{"en":"We bought some frozen dumplings from the store.","zh":"我們在店裡買了一些冷凍水餃。"},{"en":"During winter, children skated on the frozen lake.","zh":"冬天時，孩子們在結冰的湖面上溜冰。"},{"en":"The pipe was frozen solid after the extremely cold night.","zh":"在極冷的夜晚過後，水管完全凍住了。"}]},{"word":"fruit","pos":"n.","phonetic":"[frut]","meaning":"水果；成果","definition":"the sweet edible product of a plant; a result of effort","collocations":["fresh fruit","fruit juice","fruit of labor"],"example":"Eating fresh fruit every day is good for your health.","exampleZh":"每天吃新鮮水果對健康有益。","synonyms":[],"level":1,"theme":"食物與烹飪","examples":[{"en":"Eating fresh fruit every day is good for your health.","zh":"每天吃新鮮水果對健康有益。"},{"en":"A glass of fresh fruit juice is a refreshing morning drink.","zh":"一杯新鮮的果汁是提神的早晨飲品。"},{"en":"The successful harvest was the fruit of their hard labor.","zh":"豐收是他們辛勤勞動的成果。"}]},{"word":"fruitful","pos":"adj.","phonetic":"[ˈfrutfəl]","meaning":"富有成效的；豐碩的","definition":"producing good results","collocations":["fruitful discussion","fruitful cooperation"],"example":"The meeting turned out to be very fruitful.","exampleZh":"這場會議結果非常有成效。","synonyms":["productive"],"level":5,"theme":"性質與描述","examples":[{"en":"The meeting turned out to be very fruitful.","zh":"這場會議結果非常有成效。"},{"en":"The two schools enjoyed years of fruitful cooperation.","zh":"這兩所學校享有多年富有成效的合作。"},{"en":"We had a fruitful discussion and solved several problems.","zh":"我們進行了一場富有成效的討論，並解決了幾個問題。"}]},{"word":"frustrate","pos":"v.","phonetic":"[ˈfrʌsˌtret]","meaning":"使沮喪；使受挫","definition":"to prevent someone from achieving something, causing annoyance","collocations":["feel frustrated","frustrate a plan","frustrating experience"],"example":"The slow internet connection frustrated him.","exampleZh":"緩慢的網路連線讓他感到很挫折。","synonyms":["discourage","hinder"],"level":4,"theme":"情緒與感受","examples":[{"en":"The slow internet connection frustrated him.","zh":"緩慢的網路連線讓他感到很挫折。"},{"en":"The heavy traffic frustrated the drivers on their way home.","zh":"沉重的交通讓回家路上的駕駛人感到沮喪。"},{"en":"Losing the game by one point was a frustrating experience.","zh":"以一分之差輸掉比賽是個令人沮喪的經歷。"}]},{"word":"frustration","pos":"n.","phonetic":"[frʌsˈtreʃən]","meaning":"挫折；沮喪","definition":"the feeling of being upset from being unable to achieve something","collocations":["out of frustration","express frustration"],"example":"He sighed in frustration after failing again.","exampleZh":"他再次失敗後沮喪地嘆了口氣。","synonyms":["disappointment"],"level":5,"theme":"情緒與感受","examples":[{"en":"He sighed in frustration after failing again.","zh":"他再次失敗後沮喪地嘆了口氣。"},{"en":"Out of frustration, he threw his pen onto the desk.","zh":"出於沮喪，他把筆摔到桌上。"},{"en":"She expressed her frustration about the constant delays.","zh":"她表達了對不斷延誤的沮喪。"}]},{"word":"fry","pos":"v.","phonetic":"[fraɪ]","meaning":"油炸；煎","definition":"to cook food in hot oil or fat","collocations":["fry an egg","deep-fry","stir-fry"],"example":"She fried some eggs for breakfast.","exampleZh":"她煎了幾顆蛋當早餐。","synonyms":["sauté"],"level":2,"theme":"食物與烹飪","examples":[{"en":"She fried some eggs for breakfast.","zh":"她煎了幾顆蛋當早餐。"},{"en":"My father likes to stir-fry vegetables with a little garlic.","zh":"我父親喜歡用一點大蒜快炒蔬菜。"},{"en":"The cook deep-fried the chicken until it turned golden brown.","zh":"廚師把雞肉油炸至金黃色。"}]},{"word":"fuel","pos":"n. / v.","phonetic":"[ˈfjuəl]","meaning":"燃料；加油","definition":"material burned to produce heat or power","collocations":["fossil fuel","fuel efficiency","fuel tank"],"example":"The rising cost of fuel affects transportation prices.","exampleZh":"燃料成本上漲影響了運輸價格。","synonyms":["gasoline","energy"],"level":4,"theme":"自然與環境","examples":[{"en":"The rising cost of fuel affects transportation prices.","zh":"燃料成本上漲影響了運輸價格。"},{"en":"Modern cars are designed to have better fuel efficiency.","zh":"現代汽車設計成具有更好的燃油效率。"},{"en":"We stopped at a station to fill the fuel tank.","zh":"我們在一個加油站停下來加滿油箱。"}]},{"word":"fugitive","pos":"n.","phonetic":"[ˈfjudʒətɪv]","meaning":"逃犯；逃亡者","definition":"a person who has escaped from custody or is in hiding","collocations":["a wanted fugitive","fugitive from justice"],"example":"The fugitive was finally caught after ten years.","exampleZh":"這名逃犯在十年後終於被逮捕。","synonyms":["runaway"],"level":6,"theme":"政治與法律","examples":[{"en":"The fugitive was finally caught after ten years.","zh":"這名逃犯在十年後終於被逮捕。"},{"en":"The police searched everywhere for the dangerous fugitive.","zh":"警方四處搜尋這名危險的逃犯。"},{"en":"As a fugitive from justice, he lived in constant fear.","zh":"身為在逃的通緝犯，他生活在無盡的恐懼中。"}]},{"word":"fulfill","pos":"v.","phonetic":"[fʊlˈfɪl]","meaning":"實現；完成","definition":"to achieve or bring to completion a goal or duty","collocations":["fulfill a dream","fulfill a promise","fulfill a role"],"example":"She worked hard to fulfill her dream of becoming a doctor.","exampleZh":"她努力實現成為醫生的夢想。","synonyms":["achieve","accomplish"],"level":5,"theme":"抽象概念","examples":[{"en":"She worked hard to fulfill her dream of becoming a doctor.","zh":"她努力實現成為醫生的夢想。"},{"en":"He finally fulfilled his promise to visit his old teacher.","zh":"他終於實現了拜訪老師的承諾。"},{"en":"Every member must fulfill his role for the team to succeed.","zh":"每個成員都必須完成自己的職責，團隊才能成功。"}]},{"word":"full","pos":"adj.","phonetic":"[fʊl]","meaning":"滿的；飽的","definition":"containing as much as possible; not hungry","collocations":["full moon","full of","feel full"],"example":"I feel full after eating that huge meal.","exampleZh":"吃完那頓大餐後我覺得很飽。","synonyms":["complete","packed"],"level":1,"theme":"性質與描述","examples":[{"en":"I feel full after eating that huge meal.","zh":"吃完那頓大餐後我覺得很飽。"},{"en":"The bright full moon lit up the entire quiet village.","zh":"明亮的滿月照亮了整個寧靜的村莊。"},{"en":"The basket was full of ripe apples from the orchard.","zh":"籃子裡裝滿了果園裡成熟的蘋果。"}]},{"word":"fume","pos":"n. / v.","phonetic":"[fjum]","meaning":"煙霧；廢氣；發怒","definition":"strong-smelling smoke or gas, or to be very angry","collocations":["exhaust fumes","fume with anger"],"example":"The car's exhaust fumes polluted the air.","exampleZh":"汽車的廢氣汙染了空氣。","synonyms":["smoke"],"level":6,"theme":"自然與環境","examples":[{"en":"The car's exhaust fumes polluted the air.","zh":"汽車的廢氣汙染了空氣。"},{"en":"Thick exhaust fumes from the buses filled the busy street.","zh":"公車排放的濃濃廢氣瀰漫了繁忙的街道。"},{"en":"She was fuming with anger when her plan was ignored.","zh":"當她的計畫被忽視時，她氣得火冒三丈。"}]},{"word":"fun","pos":"n. / adj.","phonetic":"[fʌn]","meaning":"樂趣；有趣的","definition":"enjoyment or amusement","collocations":["have fun","fun activity","for fun"],"example":"We had a lot of fun at the amusement park.","exampleZh":"我們在遊樂園玩得很開心。","synonyms":["enjoyment","amusement"],"level":1,"theme":"運動與休閒","examples":[{"en":"We had a lot of fun at the amusement park.","zh":"我們在遊樂園玩得很開心。"},{"en":"Learning English can be a fun activity when you play games.","zh":"當你玩遊戲時，學英文可以是件有趣的活動。"},{"en":"The children had lots of fun building sandcastles at the beach.","zh":"孩子們在海灘上堆沙堡玩得很開心。"}]},{"word":"function","pos":"n. / v.","phonetic":"[ˈfʌŋkʃən]","meaning":"功能；作用","definition":"the purpose or role of something; to operate","collocations":["function properly","main function","body function"],"example":"This app has many useful functions.","exampleZh":"這個應用程式有許多實用的功能。","synonyms":["purpose","role"],"level":4,"theme":"科技與媒體","examples":[{"en":"This app has many useful functions.","zh":"這個應用程式有許多實用的功能。"},{"en":"The main function of the heart is to pump blood.","zh":"心臟的主要功能是輸送血液。"},{"en":"The old printer no longer functions properly.","zh":"這台舊印表機已無法正常運作。"}]},{"word":"fund","pos":"n. / v.","phonetic":"[fʌnd]","meaning":"資金；資助","definition":"a sum of money for a specific purpose","collocations":["raise funds","fund a project","emergency fund"],"example":"The school raised funds for the new library.","exampleZh":"學校為新圖書館募款。","synonyms":["finance","capital"],"level":4,"theme":"商業與金錢","examples":[{"en":"The school raised funds for the new library.","zh":"學校為新圖書館募款。"},{"en":"The students held a bake sale to raise funds for charity.","zh":"學生們舉辦烘焙義賣以為慈善募款。"},{"en":"A wealthy man agreed to fund the research project.","zh":"一位富人同意資助這項研究計畫。"}]},{"word":"fundamental","pos":"adj.","phonetic":"[ˌfʌndəˈmɛntl̩]","meaning":"基本的；根本的","definition":"forming a necessary base or core part","collocations":["fundamental right","fundamental principle","fundamental change"],"example":"Education is a fundamental right for every child.","exampleZh":"教育是每個孩子的基本權利。","synonyms":["basic","essential"],"level":5,"theme":"抽象概念","examples":[{"en":"Education is a fundamental right for every child.","zh":"教育是每個孩子的基本權利。"},{"en":"Honesty is a fundamental principle in any good relationship.","zh":"誠實是任何良好關係中的根本原則。"},{"en":"The new policy brought a fundamental change to the school.","zh":"這項新政策為學校帶來了根本性的改變。"}]},{"word":"funeral","pos":"n.","phonetic":"[ˈfjunərəl]","meaning":"葬禮","definition":"a ceremony held for a dead person before burial","collocations":["attend a funeral","funeral service","funeral home"],"example":"Many people attended the funeral to pay respects.","exampleZh":"許多人出席葬禮以表達敬意。","synonyms":["burial","memorial"],"level":4,"theme":"社會與文化","examples":[{"en":"Many people attended the funeral to pay respects.","zh":"許多人出席葬禮以表達敬意。"},{"en":"Family and friends gathered for the quiet funeral service.","zh":"親友們聚在一起參加這場安靜的葬禮。"},{"en":"She wore black to attend her grandfather's funeral.","zh":"她穿著黑衣參加祖父的葬禮。"}]},{"word":"fungus","pos":"n.","phonetic":"[ˈfʌŋgəs]","meaning":"真菌；黴菌","definition":"an organism such as a mushroom or mold that feeds on organic matter","collocations":["fungus grows","fungal infection"],"example":"Mushrooms are a type of fungus.","exampleZh":"蘑菇是一種真菌。","synonyms":["mold"],"level":6,"theme":"自然與環境","examples":[{"en":"Mushrooms are a type of fungus.","zh":"蘑菇是一種真菌。"},{"en":"A strange fungus grows on the damp wall of the basement.","zh":"一種奇怪的黴菌長在地下室潮濕的牆上。"},{"en":"Keeping your feet dry can help prevent a fungal infection.","zh":"保持腳部乾燥有助於預防黴菌感染。"}]},{"word":"funny","pos":"adj.","phonetic":"[ˈfʌnɪ]","meaning":"好笑的；滑稽的","definition":"causing laughter or amusement","collocations":["funny joke","funny story","act funny"],"example":"He told a funny joke that made everyone laugh.","exampleZh":"他講了一個好笑的笑話，逗得大家哈哈大笑。","synonyms":["amusing","hilarious"],"level":1,"theme":"情緒與感受","examples":[{"en":"He told a funny joke that made everyone laugh.","zh":"他講了一個好笑的笑話，逗得大家哈哈大笑。"},{"en":"She told such a funny story that we could not stop laughing.","zh":"她講了一個非常好笑的故事，讓我們笑個不停。"},{"en":"The clown made funny faces to entertain the little children.","zh":"小丑扮鬼臉逗小孩子開心。"}]},{"word":"fur","pos":"n.","phonetic":"[fɝ]","meaning":"毛皮；獸毛","definition":"the soft, thick hair covering the skin of many mammals","collocations":["fur coat","animal fur"],"example":"The cat has soft white fur.","exampleZh":"這隻貓有柔軟的白色毛皮。","synonyms":["hair"],"level":3,"theme":"動物與植物","examples":[{"en":"The cat has soft white fur.","zh":"這隻貓有柔軟的白色毛皮。"},{"en":"The rabbit's soft white fur kept it warm in the snow.","zh":"兔子柔軟的白色毛皮讓牠在雪中保持溫暖。"},{"en":"Many people no longer buy coats made from animal fur.","zh":"許多人不再購買用動物毛皮製成的外套。"}]},{"word":"furious","pos":"adj.","phonetic":"[ˈfjʊrɪəs]","meaning":"狂怒的；猛烈的","definition":"extremely angry, or very intense","collocations":["furious argument","become furious"],"example":"My mother was furious when she saw my messy room.","exampleZh":"我媽媽看到我凌亂的房間時非常憤怒。","synonyms":["enraged","fierce"],"level":5,"theme":"情緒與感受","examples":[{"en":"My mother was furious when she saw my messy room.","zh":"我媽媽看到我凌亂的房間時非常憤怒。"},{"en":"He became furious when he discovered the broken window.","zh":"當他發現破掉的窗戶時，他勃然大怒。"},{"en":"The two neighbors had a furious argument over the noise.","zh":"兩個鄰居因為噪音而激烈爭吵。"}]},{"word":"furnace","pos":"n.","phonetic":"[ˈfɝnɪs]","meaning":"火爐；熔爐","definition":"an enclosed structure for burning fuel to generate heat","collocations":["blast furnace","gas furnace"],"example":"The furnace keeps the whole house warm in winter.","exampleZh":"這個火爐讓整棟房子在冬天保持溫暖。","synonyms":["stove"],"level":6,"theme":"居家與生活","examples":[{"en":"The furnace keeps the whole house warm in winter.","zh":"這個火爐讓整棟房子在冬天保持溫暖。"},{"en":"The workers melted the iron in a huge blast furnace.","zh":"工人們在一座巨大的高爐中熔化鐵。"},{"en":"The old furnace in the basement heats the whole building.","zh":"地下室裡的舊火爐為整棟建築供暖。"}]},{"word":"furnish","pos":"v.","phonetic":"[ˈfɝnɪʃ]","meaning":"布置；供應家具","definition":"to equip a room or building with furniture","collocations":["fully furnished","furnish an apartment"],"example":"They furnished their new apartment with modern furniture.","exampleZh":"他們用現代家具布置了新公寓。","synonyms":["equip"],"level":5,"theme":"居家與生活","examples":[{"en":"They furnished their new apartment with modern furniture.","zh":"他們用現代家具布置了新公寓。"},{"en":"They spent a whole weekend furnishing their new apartment.","zh":"他們花了整個週末布置他們的新公寓。"},{"en":"The room comes fully furnished with a bed and a desk.","zh":"這個房間附有全套家具，包括一張床和一張書桌。"}]},{"word":"furniture","pos":"n.","phonetic":"[ˈfɝnɪtʃɚ]","meaning":"傢俱","definition":"movable objects such as tables and chairs used in a room","collocations":["office furniture","buy furniture","wooden furniture"],"example":"They bought new furniture for their living room.","exampleZh":"他們為客廳買了新的傢俱。","synonyms":[],"level":2,"theme":"居家與生活","examples":[{"en":"They bought new furniture for their living room.","zh":"他們為客廳買了新的傢俱。"},{"en":"They chose simple wooden furniture for the living room.","zh":"他們為客廳挑選了簡單的木製家具。"},{"en":"The company ordered new office furniture for its staff.","zh":"公司為員工訂購了新的辦公家具。"}]},{"word":"further","pos":"adv. / adj.","phonetic":"[ˈfɝðɚ]","meaning":"更遠地；進一步的","definition":"to a greater extent or degree; additional","collocations":["further information","further study","look further"],"example":"Please contact us for further information.","exampleZh":"如需進一步資訊請與我們聯絡。","synonyms":["additional","extra"],"level":3,"theme":"時間與空間","examples":[{"en":"Please contact us for further information.","zh":"如需進一步資訊請與我們聯絡。"},{"en":"If you need further information, please visit our school library website.","zh":"如果你需要進一步的資訊，請瀏覽我們學校圖書館的網站。"},{"en":"She decided to pursue further study in biology after graduation.","zh":"畢業後她決定攻讀生物學方面的進階研究。"}]},{"word":"fury","pos":"n.","phonetic":"[ˈfjʊrɪ]","meaning":"狂怒；暴怒","definition":"wild or violent anger","collocations":["in a fury","fly into a fury","sudden fury"],"example":"He shouted in fury when he saw the damage.","exampleZh":"他看到損害時憤怒地大叫。","synonyms":["rage","wrath"],"level":5,"theme":"情緒與感受","examples":[{"en":"He shouted in fury when he saw the damage.","zh":"他看到損害時憤怒地大叫。"},{"en":"In a sudden fury, he tore the letter into tiny pieces.","zh":"他一陣突如其來的狂怒，把信撕成了碎片。"},{"en":"She flew into a fury when she discovered the broken vase.","zh":"當她發現花瓶被打破時，她勃然大怒。"}]},{"word":"future","pos":"n. / adj.","phonetic":"[ˈfjutʃɚ]","meaning":"未來","definition":"the time that is to come","collocations":["in the future","future plans","near future"],"example":"She has big plans for her future career.","exampleZh":"她對未來的職涯有很大的計畫。","synonyms":["tomorrow","prospect"],"level":1,"theme":"時間與空間","examples":[{"en":"She has big plans for her future career.","zh":"她對未來的職涯有很大的計畫。"},{"en":"In the future, more people may travel to space for vacation.","zh":"未來，可能會有更多人到太空度假。"},{"en":"We discussed our future plans during the long train ride home.","zh":"在漫長的回家火車上，我們討論了未來的計畫。"}]},{"word":"gadget","pos":"n.","phonetic":"[ˈɡædʒɪt]","meaning":"小裝置；小工具","definition":"a small tool or device that does something useful","collocations":["a new gadget","electronic gadget","handy gadget"],"example":"He loves buying the latest kitchen gadgets.","exampleZh":"他喜歡購買最新的廚房小工具。","synonyms":["device","tool"],"level":3,"theme":"科技與媒體","examples":[{"en":"He loves buying the latest kitchen gadgets.","zh":"他喜歡購買最新的廚房小工具。"},{"en":"This handy gadget can peel an apple in just a few seconds.","zh":"這個方便的小工具只要幾秒就能削好一顆蘋果。"},{"en":"He spent all his savings on the latest electronic gadget.","zh":"他把所有積蓄都花在最新的電子小裝置上。"}]},{"word":"gain","pos":"v. / n.","phonetic":"[gen]","meaning":"獲得；增加","definition":"to obtain or increase something, especially something beneficial","collocations":["gain weight","gain experience","gain confidence"],"example":"She gained a lot of experience from the internship.","exampleZh":"她從實習中獲得了很多經驗。","synonyms":["obtain","acquire"],"level":2,"theme":"抽象概念","examples":[{"en":"She gained a lot of experience from the internship.","zh":"她從實習中獲得了很多經驗。"},{"en":"Volunteering at the hospital helped her gain valuable experience.","zh":"在醫院當志工幫助她獲得寶貴的經驗。"},{"en":"Many students gain confidence after giving a class presentation.","zh":"許多學生在課堂報告後變得更有自信。"}]},{"word":"gallery","pos":"n.","phonetic":"[ˈgælərɪ]","meaning":"美術館；畫廊","definition":"a room or building where works of art are shown to the public","collocations":["art gallery","visit a gallery","gallery owner"],"example":"We spent the afternoon at an art gallery downtown.","exampleZh":"我們下午在市區的一家美術館度過。","synonyms":["museum","exhibition hall"],"level":3,"theme":"藝術與音樂","examples":[{"en":"We spent the afternoon at an art gallery downtown.","zh":"我們下午在市區的一家美術館度過。"},{"en":"The art gallery is showing paintings by young local artists this month.","zh":"這間美術館本月正展出當地年輕藝術家的畫作。"},{"en":"We plan to visit a gallery near the museum this weekend.","zh":"我們打算這個週末去參觀博物館附近的一間畫廊。"}]},{"word":"gallon","pos":"n.","phonetic":"[ˈɡælən]","meaning":"加侖（容量單位）","definition":"a unit for measuring liquid","collocations":["a gallon of milk","miles per gallon","ten gallons of gas"],"example":"The car uses one gallon of gasoline every twenty miles.","exampleZh":"這輛車每二十英里耗用一加侖汽油。","synonyms":[],"level":3,"theme":"科學與數學","examples":[{"en":"The car uses one gallon of gasoline every twenty miles.","zh":"這輛車每二十英里耗用一加侖汽油。"},{"en":"Please buy a gallon of milk on your way home.","zh":"回家路上請買一加侖的牛奶。"},{"en":"This small car can travel forty miles per gallon of fuel.","zh":"這輛小車每加侖燃料可行駛四十英里。"}]},{"word":"gallop","pos":"v. / n.","phonetic":"[ˈɡæləp]","meaning":"（馬）疾馳；飛奔","definition":"to run very fast, especially of a horse","collocations":["gallop across the field","break into a gallop","full gallop"],"example":"The horse galloped across the open field.","exampleZh":"那匹馬在開闊的原野上疾馳。","synonyms":["race","dash"],"level":4,"theme":"動物與植物","examples":[{"en":"The horse galloped across the open field.","zh":"那匹馬在開闊的原野上疾馳。"},{"en":"The wild horses galloped across the field toward the river.","zh":"野馬疾馳過原野，朝河邊奔去。"},{"en":"As the gate opened, the pony broke into a gallop.","zh":"門一打開，小馬便開始飛奔起來。"}]},{"word":"gamble","pos":"v. / n.","phonetic":"[ˈɡæmbḷ]","meaning":"賭博；冒險","definition":"to risk money or something valuable on an uncertain outcome","collocations":["gamble on the stock market","take a gamble","gamble away money"],"example":"He gambled all his savings on a single bet.","exampleZh":"他把所有積蓄都賭在一場賭局上。","synonyms":["bet","risk"],"level":4,"theme":"商業與金錢","examples":[{"en":"He gambled all his savings on a single bet.","zh":"他把所有積蓄都賭在一場賭局上。"},{"en":"Starting a business is always a gamble, but he took the risk.","zh":"創業總是一場冒險，但他還是承擔了風險。"},{"en":"He lost his job after gambling away his entire monthly salary.","zh":"他把整個月的薪水都賭光後失去了工作。"}]},{"word":"game","pos":"n.","phonetic":"[gem]","meaning":"遊戲；比賽","definition":"an activity done for entertainment, often with rules and competition","collocations":["play a game","video game","win the game"],"example":"The children played a game of tag in the yard.","exampleZh":"孩子們在院子裡玩抓人遊戲。","synonyms":["match","contest"],"level":1,"theme":"運動與休閒","examples":[{"en":"The children played a game of tag in the yard.","zh":"孩子們在院子裡玩抓人遊戲。"},{"en":"Our team worked hard together to win the final game.","zh":"我們的隊伍齊心努力，贏得了最後一場比賽。"},{"en":"He spends too many hours playing video games after school.","zh":"他放學後花太多時間玩電玩遊戲。"}]},{"word":"gang","pos":"n. / v.","phonetic":"[ɡæŋ]","meaning":"幫派；一夥人","definition":"an organized group of people, often involved in crime","collocations":["a street gang","gang member","gang up on someone"],"example":"The police arrested members of a local gang.","exampleZh":"警方逮捕了當地一個幫派的成員。","synonyms":["group","band"],"level":3,"theme":"社會與文化","examples":[{"en":"The police arrested members of a local gang.","zh":"警方逮捕了當地一個幫派的成員。"},{"en":"A local street gang was blamed for the recent robberies.","zh":"當地一個街頭幫派被指控犯下最近的搶案。"},{"en":"The bullies ganged up on the new student during recess.","zh":"那些霸凌者在下課時間聯合起來欺負新來的學生。"}]},{"word":"gap","pos":"n.","phonetic":"[ɡæp]","meaning":"缺口；差距；空隙","definition":"a space between two things or a difference between two situations","collocations":["fill the gap","a wide gap","generation gap"],"example":"There is a big gap between the rich and the poor.","exampleZh":"貧富之間存在很大的差距。","synonyms":["gulf","space"],"level":2,"theme":"抽象概念","examples":[{"en":"There is a big gap between the rich and the poor.","zh":"貧富之間存在很大的差距。"},{"en":"The government hopes to close the gap between rich and poor.","zh":"政府希望縮小貧富之間的差距。"},{"en":"There is often a generation gap between teenagers and their parents.","zh":"青少年和父母之間常常有代溝。"}]},{"word":"garage","pos":"n.","phonetic":"[gəˈrɑʒ]","meaning":"車庫；修車廠","definition":"a building where a car is kept or repaired","collocations":["park in the garage","garage sale","car garage"],"example":"He parked his car in the garage overnight.","exampleZh":"他把車停在車庫過夜。","synonyms":[],"level":1,"theme":"居家與生活","examples":[{"en":"He parked his car in the garage overnight.","zh":"他把車停在車庫過夜。"},{"en":"They held a garage sale to get rid of their old furniture.","zh":"他們舉辦了車庫拍賣來處理掉舊家具。"},{"en":"The mechanic at the garage fixed my brakes yesterday.","zh":"修車廠的技師昨天修好了我的煞車。"}]},{"word":"garbage","pos":"n.","phonetic":"[ˈgɑrbɪdʒ]","meaning":"垃圾；廢物","definition":"waste material that is thrown away","collocations":["take out the garbage","garbage can","garbage truck"],"example":"Please take out the garbage before you leave.","exampleZh":"你離開前請把垃圾拿出去丟。","synonyms":["trash","rubbish"],"level":1,"theme":"居家與生活","examples":[{"en":"Please take out the garbage before you leave.","zh":"你離開前請把垃圾拿出去丟。"},{"en":"The garbage truck comes to our street every Tuesday morning.","zh":"垃圾車每週二早上會來我們這條街。"},{"en":"Remember to throw the empty bottles into the garbage can.","zh":"記得把空瓶子丟進垃圾桶。"}]},{"word":"garden","pos":"n. / v.","phonetic":"[ˈgɑrdn̩]","meaning":"花園;菜園;園藝","definition":"a piece of land used for growing flowers, vegetables, or fruit","collocations":["water the garden","vegetable garden","garden design"],"example":"My grandmother loves working in her garden every morning.","exampleZh":"我祖母每天早上都喜歡在她的花園裡忙碌。","synonyms":[],"level":1,"theme":"居家與生活","examples":[{"en":"My grandmother loves working in her garden every morning.","zh":"我祖母每天早上都喜歡在她的花園裡忙碌。"},{"en":"She waters the garden every evening before it gets dark.","zh":"她每天傍晚天黑前都會為花園澆水。"},{"en":"We grow tomatoes and peppers in our small vegetable garden.","zh":"我們在小菜園裡種番茄和辣椒。"}]},{"word":"garlic","pos":"n.","phonetic":"[ˈgɑrlɪk]","meaning":"大蒜","definition":"a plant of the onion family with a strong smell and taste, used in cooking","collocations":["a clove of garlic","garlic bread","chop garlic"],"example":"The recipe calls for three cloves of garlic.","exampleZh":"這道食譜需要三瓣大蒜。","synonyms":[],"level":2,"theme":"食物與烹飪","examples":[{"en":"The recipe calls for three cloves of garlic.","zh":"這道食譜需要三瓣大蒜。"},{"en":"Please chop three cloves of garlic for the noodle sauce.","zh":"請切三瓣大蒜來做麵的醬料。"},{"en":"Garlic bread is my favorite side dish at Italian restaurants.","zh":"大蒜麵包是我在義大利餐廳最愛的配菜。"}]},{"word":"garment","pos":"n.","phonetic":"[ˈɡɑrmənt]","meaning":"衣服；服裝","definition":"a piece of clothing","collocations":["a fine garment","garment industry","wool garments"],"example":"The garment was made of soft silk.","exampleZh":"這件衣服是用柔軟的絲綢做成的。","synonyms":["clothing","apparel"],"level":4,"theme":"服裝與外表","examples":[{"en":"The garment was made of soft silk.","zh":"這件衣服是用柔軟的絲綢做成的。"},{"en":"Each garment in the shop is made from pure cotton.","zh":"店裡每一件衣服都是用純棉製成的。"},{"en":"The garment industry provides jobs for thousands of local workers.","zh":"服裝業為數千名當地工人提供工作機會。"}]},{"word":"garnish","pos":"v. / n.","phonetic":"[ˈɡɑrnɪʃ]","meaning":"裝飾（食物）；配菜","definition":"to decorate food with a small extra item","collocations":["garnish with parsley","a simple garnish","garnish a dish"],"example":"The chef garnished the soup with fresh herbs.","exampleZh":"主廚用新鮮香草裝飾這道湯。","synonyms":["decorate","adorn"],"level":5,"theme":"食物與烹飪","examples":[{"en":"The chef garnished the soup with fresh herbs.","zh":"主廚用新鮮香草裝飾這道湯。"},{"en":"The cook garnished the salad with a few slices of lemon.","zh":"廚師用幾片檸檬裝飾了這道沙拉。"},{"en":"A simple garnish of parsley made the dish look elegant.","zh":"簡單的一點荷蘭芹配菜讓這道菜看起來很雅緻。"}]},{"word":"gas","pos":"n.","phonetic":"[gæs]","meaning":"氣體；瓦斯；汽油","definition":"a substance like air that has no fixed shape, or fuel used in vehicles","collocations":["natural gas","gas station","run out of gas"],"example":"We stopped at a gas station to fill up the tank.","exampleZh":"我們在加油站停下來加油。","synonyms":["fuel"],"level":2,"theme":"科學與數學","examples":[{"en":"We stopped at a gas station to fill up the tank.","zh":"我們在加油站停下來加油。"},{"en":"Our kitchen stove runs on natural gas instead of electricity.","zh":"我們廚房的爐子是用天然氣而不是電。"},{"en":"We almost ran out of gas on the winding mountain road.","zh":"我們在蜿蜒的山路上差點就沒油了。"}]},{"word":"gasoline","pos":"n.","phonetic":"[ˈgæsəˌlin]","meaning":"汽油","definition":"a liquid fuel made from petroleum, used mainly in car engines","collocations":["gasoline price","burn gasoline","gasoline engine"],"example":"Gasoline prices have risen sharply this year.","exampleZh":"今年汽油價格大幅上漲。","synonyms":["petrol"],"level":3,"theme":"交通與旅行","examples":[{"en":"Gasoline prices have risen sharply this year.","zh":"今年汽油價格大幅上漲。"},{"en":"The price of gasoline keeps rising, so he rides his bike.","zh":"汽油價格持續上漲，所以他改騎腳踏車。"},{"en":"A modern gasoline engine is far more efficient than older ones.","zh":"現代的汽油引擎比舊型的效率高出許多。"}]},{"word":"gasp","pos":"v. / n.","phonetic":"[ɡæsp]","meaning":"喘氣；倒抽一口氣","definition":"to take a sudden short breath, often from surprise or shock","collocations":["gasp for air","gasp in surprise","a gasp of horror"],"example":"The audience gasped when the magician disappeared.","exampleZh":"魔術師消失時,觀眾都倒抽了一口氣。","synonyms":["pant","choke"],"level":3,"theme":"動作與行為","examples":[{"en":"The audience gasped when the magician disappeared.","zh":"魔術師消失時,觀眾都倒抽了一口氣。"},{"en":"She gasped in surprise when she saw her exam results.","zh":"當她看到考試成績時，驚訝得倒抽了一口氣。"},{"en":"After the long swim, he came up gasping for air.","zh":"游了很久之後，他浮出水面大口喘氣。"}]},{"word":"gate","pos":"n.","phonetic":"[get]","meaning":"大門；閘門；登機門","definition":"a barrier used to close an opening in a fence or wall, or an airport boarding entrance","collocations":["open the gate","boarding gate","front gate"],"example":"Passengers should proceed to gate twelve for boarding.","exampleZh":"旅客請前往十二號登機門登機。","synonyms":["entrance"],"level":1,"theme":"交通與旅行","examples":[{"en":"Passengers should proceed to gate twelve for boarding.","zh":"旅客請前往十二號登機門登機。"},{"en":"Please remember to close the front gate when you leave.","zh":"離開時請記得關上前門。"},{"en":"Our flight leaves from boarding gate fifteen in ten minutes.","zh":"我們的班機十分鐘後從十五號登機門起飛。"}]},{"word":"gather","pos":"v.","phonetic":"[ˈgæðɚ]","meaning":"聚集；收集","definition":"to come together in a group, or to collect things","collocations":["gather information","gather around","gather data"],"example":"The students gathered around the teacher to hear the story.","exampleZh":"學生們聚集在老師身邊聽故事。","synonyms":["collect","assemble"],"level":2,"theme":"動作與行為","examples":[{"en":"The students gathered around the teacher to hear the story.","zh":"學生們聚集在老師身邊聽故事。"},{"en":"Reporters gathered outside the school to gather information about the event.","zh":"記者聚集在學校外面，收集有關這起事件的資訊。"},{"en":"The whole family gathers around the table for dinner every night.","zh":"全家人每晚都會圍在餐桌旁吃晚餐。"}]},{"word":"gauge","pos":"n. / v.","phonetic":"[gedʒ]","meaning":"測量儀器；判斷；估計","definition":"an instrument for measuring something, or to estimate or judge something","collocations":["fuel gauge","gauge the reaction","pressure gauge"],"example":"The driver checked the fuel gauge before the trip.","exampleZh":"司機在出發前檢查了油量表。","synonyms":["measure","estimate"],"level":5,"theme":"科學與數學","examples":[{"en":"The driver checked the fuel gauge before the trip.","zh":"司機在出發前檢查了油量表。"},{"en":"The fuel gauge showed that the tank was nearly empty.","zh":"油表顯示油箱幾乎空了。"},{"en":"It was hard to gauge the audience's reaction to the speech.","zh":"很難判斷觀眾對這場演講的反應。"}]},{"word":"gaze","pos":"v. / n.","phonetic":"[gez]","meaning":"凝視；注視","definition":"to look steadily at someone or something for a long time","collocations":["gaze at","fix one's gaze","gaze into the distance"],"example":"She gazed at the stars for hours.","exampleZh":"她凝視著星星好幾個小時。","synonyms":["stare","look"],"level":4,"theme":"動作與行為","examples":[{"en":"She gazed at the stars for hours.","zh":"她凝視著星星好幾個小時。"},{"en":"The little boy gazed at the toys in the shop window.","zh":"小男孩凝視著商店櫥窗裡的玩具。"},{"en":"She fixed her gaze on the distant mountains for a while.","zh":"她的目光凝視著遠方的群山好一會兒。"}]},{"word":"gear","pos":"n.","phonetic":"[gɪr]","meaning":"齒輪；排檔；裝備","definition":"a toothed wheel in a machine, or equipment needed for an activity","collocations":["change gear","camping gear","gear up"],"example":"He packed all his camping gear into the car.","exampleZh":"他把所有的露營裝備都裝進車裡。","synonyms":["equipment"],"level":3,"theme":"科技與媒體","examples":[{"en":"He packed all his camping gear into the car.","zh":"他把所有的露營裝備都裝進車裡。"},{"en":"Remember to change gear when you drive up the steep hill.","zh":"開車上陡坡時記得換檔。"},{"en":"They packed all their camping gear before the weekend trip.","zh":"他們在週末旅行前打包好所有的露營裝備。"}]},{"word":"gender","pos":"n.","phonetic":"[ˈdʒɛndɚ]","meaning":"性別","definition":"the state of being male or female, especially with regard to social and cultural roles","collocations":["gender equality","gender gap","gender roles"],"example":"The company promotes gender equality in the workplace.","exampleZh":"這家公司在職場上提倡性別平等。","synonyms":["sex"],"level":4,"theme":"社會與文化","examples":[{"en":"The company promotes gender equality in the workplace.","zh":"這家公司在職場上提倡性別平等。"},{"en":"The school treats every student equally, regardless of gender.","zh":"這所學校平等對待每位學生，不分性別。"},{"en":"Many countries are working to reduce the gender gap in pay.","zh":"許多國家正努力縮小薪資上的性別差距。"}]},{"word":"gene","pos":"n.","phonetic":"[dʒin]","meaning":"基因","definition":"a unit of heredity passed from parents to offspring","collocations":["gene mutation","carry a gene","gene therapy"],"example":"Scientists identified the gene responsible for the disease.","exampleZh":"科學家找出了導致這種疾病的基因。","synonyms":[],"level":4,"theme":"科學與數學","examples":[{"en":"Scientists identified the gene responsible for the disease.","zh":"科學家找出了導致這種疾病的基因。"},{"en":"Children may carry a gene for a certain eye color.","zh":"孩子可能帶有某種眼睛顏色的基因。"},{"en":"Doctors hope gene therapy can one day cure this rare disease.","zh":"醫生希望基因療法有一天能治癒這種罕見疾病。"}]},{"word":"general","pos":"adj. / n.","phonetic":"[ˈdʒɛnərəl]","meaning":"一般的；普遍的；將軍","definition":"affecting or including most people or things; a senior military officer","collocations":["in general","general public","general knowledge"],"example":"In general, the students did well on the test.","exampleZh":"整體來說，學生們這次考試考得不錯。","synonyms":["common","overall"],"level":2,"theme":"抽象概念","examples":[{"en":"In general, the students did well on the test.","zh":"整體來說，學生們這次考試考得不錯。"},{"en":"In general, students who read widely write better essays.","zh":"一般來說，廣泛閱讀的學生作文寫得比較好。"},{"en":"The lecture aimed to improve the general knowledge of the class.","zh":"這場講座旨在增進全班的一般常識。"}]},{"word":"generate","pos":"v.","phonetic":"[ˈdʒɛnəˌret]","meaning":"產生；引起","definition":"to produce or create something","collocations":["generate income","generate ideas","generate electricity"],"example":"Wind turbines generate electricity without pollution.","exampleZh":"風力渦輪機在不造成污染的情況下發電。","synonyms":["produce","create"],"level":4,"theme":"科學與數學","examples":[{"en":"Wind turbines generate electricity without pollution.","zh":"風力渦輪機在不造成污染的情況下發電。"},{"en":"Solar panels on the roof generate electricity for the whole house.","zh":"屋頂上的太陽能板為整棟房子產生電力。"},{"en":"The teacher asked us to generate ideas for the science project.","zh":"老師要我們為科學專題想出一些點子。"}]},{"word":"generation","pos":"n.","phonetic":"[ˌdʒɛnəˈreʃən]","meaning":"世代；一代人","definition":"all the people born and living at about the same time","collocations":["younger generation","generation gap","future generations"],"example":"There is often a generation gap between parents and children.","exampleZh":"父母和孩子之間常常存在代溝。","synonyms":[],"level":3,"theme":"人物與家庭","examples":[{"en":"There is often a generation gap between parents and children.","zh":"父母和孩子之間常常存在代溝。"},{"en":"We must protect the environment for future generations.","zh":"我們必須為後代子孫保護環境。"},{"en":"The younger generation prefers watching short videos on their phones.","zh":"年輕世代比較喜歡用手機看短影片。"}]},{"word":"generic","pos":"adj.","phonetic":"[dʒəˈnɛrɪk]","meaning":"一般的；通用的；非品牌的","definition":"relating to a whole group rather than one specific thing","collocations":["generic name","generic product","a generic term"],"example":"Aspirin is a generic name for a common painkiller.","exampleZh":"阿斯匹靈是一種常見止痛藥的通用名稱。","synonyms":["general","common"],"level":5,"theme":"性質與描述","examples":[{"en":"Aspirin is a generic name for a common painkiller.","zh":"阿斯匹靈是一種常見止痛藥的通用名稱。"},{"en":"The doctor prescribed a generic medicine that costs much less.","zh":"醫生開了一種便宜許多的非品牌藥物。"},{"en":"\"Tissue\" has become a generic term for many paper products.","zh":"「面紙」已成為許多紙製品的通用名稱。"}]},{"word":"generous","pos":"adj.","phonetic":"[ˈdʒɛnərəs]","meaning":"慷慨的；大方的","definition":"willing to give more of something, such as money or time, than is necessary","collocations":["generous donation","generous with","a generous offer"],"example":"He is generous with his time and always helps others.","exampleZh":"他很慷慨地付出時間，總是樂於幫助別人。","synonyms":["kind","giving"],"level":3,"theme":"情緒與感受","examples":[{"en":"He is generous with his time and always helps others.","zh":"他很慷慨地付出時間，總是樂於幫助別人。"},{"en":"Our neighbor was generous enough to lend us his ladder.","zh":"我們的鄰居很慷慨，把梯子借給了我們。"},{"en":"The company made a generous donation to the local school.","zh":"這家公司向當地學校做了慷慨的捐款。"}]},{"word":"genetic","pos":"adj.","phonetic":"[dʒəˈnɛtɪk]","meaning":"基因的；遺傳的","definition":"relating to genes or heredity","collocations":["genetic disease","genetic engineering","genetic makeup"],"example":"Some illnesses are caused by genetic factors.","exampleZh":"有些疾病是由遺傳因素引起的。","synonyms":["hereditary","inherited"],"level":5,"theme":"科學與數學","examples":[{"en":"Some illnesses are caused by genetic factors.","zh":"有些疾病是由遺傳因素引起的。"},{"en":"Height is partly determined by genetic factors from your parents.","zh":"身高部分是由來自父母的遺傳因素決定的。"},{"en":"Scientists warn that genetic engineering raises many ethical questions.","zh":"科學家警告基因工程會引發許多倫理問題。"}]},{"word":"genius","pos":"n.","phonetic":"[ˈdʒinjəs]","meaning":"天才；才華","definition":"exceptional intellectual or creative power, or a person who has this","collocations":["a genius idea","musical genius","pure genius"],"example":"Einstein is often considered a scientific genius.","exampleZh":"愛因斯坦常被認為是科學天才。","synonyms":["prodigy"],"level":4,"theme":"教育與學習","examples":[{"en":"Einstein is often considered a scientific genius.","zh":"愛因斯坦常被認為是科學天才。"},{"en":"Everyone agreed that her plan to save water was pure genius.","zh":"大家都同意她的節水計畫真是天才之作。"},{"en":"The young musical genius composed her first song at age six.","zh":"這位年輕的音樂天才六歲就創作了她的第一首歌。"}]},{"word":"gentle","pos":"adj.","phonetic":"[ˈdʒɛntl̩]","meaning":"溫和的；輕柔的","definition":"mild and kind in nature or manner","collocations":["a gentle breeze","gentle voice","gentle reminder"],"example":"A gentle breeze blew through the open window.","exampleZh":"一陣柔和的微風吹過敞開的窗戶。","synonyms":["mild","tender"],"level":2,"theme":"性質與描述","examples":[{"en":"A gentle breeze blew through the open window.","zh":"一陣柔和的微風吹過敞開的窗戶。"},{"en":"A gentle breeze cooled the students during the outdoor lesson.","zh":"一陣微風在戶外課時為學生們帶來涼意。"},{"en":"The nurse spoke in a gentle voice to calm the frightened child.","zh":"護士用溫柔的聲音安撫那個受驚的孩子。"}]},{"word":"gentleman","pos":"n.","phonetic":"[ˈdʒɛntlmən]","meaning":"紳士；先生","definition":"a polite, honorable man; a formal way to address a man","collocations":["ladies and gentlemen","a true gentleman","act like a gentleman"],"example":"Ladies and gentlemen, please take your seats.","exampleZh":"各位先生女士，請就座。","synonyms":[],"level":3,"theme":"人物與家庭","examples":[{"en":"Ladies and gentlemen, please take your seats.","zh":"各位先生女士，請就座。"},{"en":"He is a true gentleman who always holds the door open for others.","zh":"他是位真正的紳士，總是為別人開門。"},{"en":"Ladies and gentlemen, please welcome our special guest tonight.","zh":"各位女士先生，請歡迎今晚的特別來賓。"}]},{"word":"genuine","pos":"adj.","phonetic":"[ˈdʒɛnjuɪn]","meaning":"真正的；真誠的","definition":"truly what it is said to be; sincere and honest","collocations":["genuine leather","genuine concern","genuine interest"],"example":"She showed genuine concern for her friend's health.","exampleZh":"她對朋友的健康表現出真誠的關心。","synonyms":["authentic","sincere"],"level":4,"theme":"性質與描述","examples":[{"en":"She showed genuine concern for her friend's health.","zh":"她對朋友的健康表現出真誠的關心。"},{"en":"The bag is made of genuine leather, not a cheap imitation.","zh":"這個包是用真皮製成的，不是廉價的仿製品。"},{"en":"She showed genuine interest in learning about other cultures.","zh":"她對認識其他文化展現出真誠的興趣。"}]},{"word":"geography","pos":"n.","phonetic":"[dʒiˈɑgrəfɪ]","meaning":"地理；地理學","definition":"the study of the physical features of the earth and its people","collocations":["study geography","geography class","physical geography"],"example":"We learned about mountains and rivers in geography class.","exampleZh":"我們在地理課學到了關於山脈和河流的知識。","synonyms":[],"level":2,"theme":"教育與學習","examples":[{"en":"We learned about mountains and rivers in geography class.","zh":"我們在地理課學到了關於山脈和河流的知識。"},{"en":"In geography class we studied the world's largest deserts.","zh":"在地理課上我們研究了世界上最大的沙漠。"},{"en":"Learning geography helps us understand different countries and cultures.","zh":"學習地理幫助我們了解不同的國家和文化。"}]},{"word":"geometry","pos":"n.","phonetic":"[dʒiˈɑmətri]","meaning":"幾何學","definition":"the branch of mathematics that deals with shapes and space","collocations":["study geometry","geometry class","basic geometry"],"example":"We learned about triangles in geometry class.","exampleZh":"我們在幾何課上學到了三角形。","synonyms":[],"level":4,"theme":"科學與數學","examples":[{"en":"We learned about triangles in geometry class.","zh":"我們在幾何課上學到了三角形。"},{"en":"We used a compass to draw circles in geometry class.","zh":"我們在幾何課上用圓規畫圓。"},{"en":"Basic geometry teaches us how to measure angles and areas.","zh":"基礎幾何教我們如何測量角度和面積。"}]},{"word":"germ","pos":"n.","phonetic":"[dʒɝm]","meaning":"細菌；病菌","definition":"a very small living thing that causes disease","collocations":["kill germs","spread germs","germ-free"],"example":"Washing your hands helps get rid of germs.","exampleZh":"洗手有助於去除細菌。","synonyms":["bacteria","microbe"],"level":3,"theme":"身體與健康","examples":[{"en":"Washing your hands helps get rid of germs.","zh":"洗手有助於去除細菌。"},{"en":"Washing your hands well helps kill germs before eating.","zh":"吃東西前把手洗乾淨有助於殺死細菌。"},{"en":"Covering your mouth when you cough stops germs from spreading.","zh":"咳嗽時摀住嘴巴可以防止細菌傳播。"}]},{"word":"germinate","pos":"v.","phonetic":"[ˈdʒɜrməˌnet]","meaning":"發芽；萌芽","definition":"to begin to grow, as a seed does","collocations":["seeds germinate","germinate quickly","begin to germinate"],"example":"The seeds germinate quickly in warm soil.","exampleZh":"這些種子在溫暖的土壤中很快就發芽了。","synonyms":["sprout","develop"],"level":6,"theme":"自然與環境","examples":[{"en":"The seeds germinate quickly in warm soil.","zh":"這些種子在溫暖的土壤中很快就發芽了。"},{"en":"The bean seeds began to germinate after three warm days.","zh":"這些豆子的種子在溫暖三天後開始發芽。"},{"en":"Most seeds germinate quickly when the soil stays moist.","zh":"大多數種子在土壤保持濕潤時會很快發芽。"}]},{"word":"gesture","pos":"n. / v.","phonetic":"[ˈdʒɛstʃɚ]","meaning":"手勢；姿態；表示","definition":"a movement of the body, especially the hands, to express meaning or feeling","collocations":["make a gesture","a kind gesture","gesture toward"],"example":"He made a friendly gesture by waving hello.","exampleZh":"他友善地揮手打招呼。","synonyms":["motion","signal"],"level":4,"theme":"溝通與語言","examples":[{"en":"He made a friendly gesture by waving hello.","zh":"他友善地揮手打招呼。"},{"en":"He made a friendly gesture and invited us to sit down.","zh":"他做了一個友善的手勢，邀請我們坐下。"},{"en":"Sending flowers was a kind gesture to cheer her up.","zh":"送花是個貼心的舉動，讓她開心起來。"}]},{"word":"ghost","pos":"n.","phonetic":"[gost]","meaning":"鬼；幽靈","definition":"the spirit of a dead person that is believed to appear to living people","collocations":["ghost story","believe in ghosts","ghost town"],"example":"The children told scary ghost stories around the campfire.","exampleZh":"孩子們圍著營火講恐怖的鬼故事。","synonyms":["spirit","phantom"],"level":2,"theme":"社會與文化","examples":[{"en":"The children told scary ghost stories around the campfire.","zh":"孩子們圍著營火講恐怖的鬼故事。"},{"en":"They told scary ghost stories around the campfire at night.","zh":"他們晚上圍著營火講可怕的鬼故事。"},{"en":"After the factory closed, the area became a quiet ghost town.","zh":"工廠關閉後，那個地區變成了安靜的鬼城。"}]},{"word":"giant","pos":"adj. / n.","phonetic":"[ˈdʒaɪənt]","meaning":"巨大的；巨人","definition":"extremely large; a mythical creature of very great size","collocations":["giant panda","giant screen","a friendly giant"],"example":"The giant panda is native to China.","exampleZh":"大貓熊原產於中國。","synonyms":["huge","enormous"],"level":2,"theme":"性質與描述","examples":[{"en":"The giant panda is native to China.","zh":"大貓熊原產於中國。"},{"en":"The children watched the giant panda eat bamboo at the zoo.","zh":"孩子們在動物園看巨大的貓熊吃竹子。"},{"en":"The film was shown on a giant screen at the theater.","zh":"這部電影在戲院的巨大螢幕上播放。"}]},{"word":"gift","pos":"n.","phonetic":"[gɪft]","meaning":"禮物；天賦","definition":"something given to someone without payment; a natural talent","collocations":["birthday gift","gift for music","wrap a gift"],"example":"She gave her mother a beautiful gift on her birthday.","exampleZh":"她在媽媽生日時送了一份美麗的禮物。","synonyms":["present","talent"],"level":1,"theme":"人物與家庭","examples":[{"en":"She gave her mother a beautiful gift on her birthday.","zh":"她在媽媽生日時送了一份美麗的禮物。"},{"en":"She carefully wrapped the gift in bright red paper.","zh":"她小心地用鮮紅色的紙包裝禮物。"},{"en":"He has a natural gift for music and plays several instruments.","zh":"他天生有音樂天賦，會演奏好幾種樂器。"}]},{"word":"gigantic","pos":"adj.","phonetic":"[dʒaɪˈgæntɪk]","meaning":"巨大的；龐大的","definition":"extremely large in size, extent, or degree","collocations":["a gigantic wave","gigantic building","gigantic effort"],"example":"A gigantic wave crashed onto the shore.","exampleZh":"一陣巨浪撲向岸邊。","synonyms":["huge","enormous"],"level":5,"theme":"性質與描述","examples":[{"en":"A gigantic wave crashed onto the shore.","zh":"一陣巨浪撲向岸邊。"},{"en":"A gigantic wave suddenly rose and crashed onto the beach.","zh":"一道巨浪突然升起，猛烈拍打在海灘上。"},{"en":"Building the bridge required a gigantic effort from many workers.","zh":"建造這座橋需要許多工人付出巨大的努力。"}]},{"word":"giggle","pos":"v. / n.","phonetic":"[ˈgɪgl̩]","meaning":"咯咯地笑","definition":"to laugh in a silly or nervous way","collocations":["giggle nervously","burst into giggles","girls giggling"],"example":"The girls giggled at the funny joke.","exampleZh":"女孩們聽到那個笑話咯咯地笑了起來。","synonyms":["laugh","chuckle"],"level":3,"theme":"情緒與感受","examples":[{"en":"The girls giggled at the funny joke.","zh":"女孩們聽到那個笑話咯咯地笑了起來。"},{"en":"The children giggled nervously before the teacher entered the room.","zh":"老師進教室前，孩子們緊張地咯咯笑。"},{"en":"She burst into giggles at her friend's silly drawing.","zh":"她看到朋友愚蠢的塗鴉後咯咯笑了起來。"}]},{"word":"gill","pos":"n.","phonetic":"[ɡɪl]","meaning":"（魚的）鰓","definition":"the organ fish use to breathe underwater","collocations":["fish gills","breathe through gills","red gills"],"example":"Fish use their gills to breathe underwater.","exampleZh":"魚用鰓在水中呼吸。","synonyms":[],"level":4,"theme":"動物與植物","examples":[{"en":"Fish use their gills to breathe underwater.","zh":"魚用鰓在水中呼吸。"},{"en":"Fish take in oxygen from the water through their gills.","zh":"魚透過鰓從水中吸取氧氣。"},{"en":"The healthy fish had bright red gills under its head.","zh":"這條健康的魚頭部下方有鮮紅色的鰓。"}]},{"word":"ginger","pos":"n.","phonetic":"[ˈdʒɪndʒɚ]","meaning":"薑","definition":"a spicy root used in cooking and traditional medicine","collocations":["ginger tea","fresh ginger","ground ginger"],"example":"She added some fresh ginger to the soup.","exampleZh":"她在湯裡加了一些新鮮的薑。","synonyms":[],"level":3,"theme":"食物與烹飪","examples":[{"en":"She added some fresh ginger to the soup.","zh":"她在湯裡加了一些新鮮的薑。"},{"en":"My mother makes warm ginger tea whenever I catch a cold.","zh":"每當我感冒時，媽媽就會煮溫熱的薑茶。"},{"en":"Add a little fresh ginger to make the fish taste better.","zh":"加一點新鮮的薑會讓魚的味道更好。"}]},{"word":"giraffe","pos":"n.","phonetic":"[dʒəˈræf]","meaning":"長頸鹿","definition":"a large African animal with a very long neck and legs","collocations":["a tall giraffe","giraffe's neck","feed the giraffe"],"example":"The giraffe stretched its long neck to reach the leaves.","exampleZh":"長頸鹿伸長脖子去吃樹葉。","synonyms":[],"level":1,"theme":"動物與植物","examples":[{"en":"The giraffe stretched its long neck to reach the leaves.","zh":"長頸鹿伸長脖子去吃樹葉。"},{"en":"The tall giraffe reached the leaves at the top of the tree.","zh":"高大的長頸鹿吃到了樹頂的葉子。"},{"en":"Children love to feed the giraffe at the safari park.","zh":"孩子們喜歡在野生動物園餵長頸鹿。"}]},{"word":"girl","pos":"n.","phonetic":"[gɝl]","meaning":"女孩","definition":"a female child or young woman","collocations":["little girl","girl next door","girls' school"],"example":"The little girl was playing with her dolls.","exampleZh":"小女孩正在玩她的洋娃娃。","synonyms":[],"level":1,"theme":"人物與家庭","examples":[{"en":"The little girl was playing with her dolls.","zh":"小女孩正在玩她的洋娃娃。"},{"en":"The little girl waved happily at the passing train.","zh":"小女孩開心地向經過的火車揮手。"},{"en":"My sister studies at an all-girls school in the city.","zh":"我妹妹在城裡的一所女子學校讀書。"}]},{"word":"girlfriend","pos":"n.","phonetic":"[ˈɡɜrlˌfrɛnd]","meaning":"女朋友","definition":"a girl or woman in a romantic relationship with someone","collocations":["his girlfriend","meet a girlfriend","break up with a girlfriend"],"example":"He introduced his girlfriend to his parents.","exampleZh":"他向父母介紹了他的女朋友。","synonyms":[],"level":2,"theme":"人物與家庭","examples":[{"en":"He introduced his girlfriend to his parents.","zh":"他向父母介紹了他的女朋友。"},{"en":"He bought a small gift for his girlfriend's birthday.","zh":"他為女朋友的生日買了一份小禮物。"},{"en":"She introduced her new girlfriend to her closest friends.","zh":"她把新交的女朋友介紹給最要好的朋友們認識。"}]},{"word":"glacier","pos":"n.","phonetic":"[ˈɡleʃər]","meaning":"冰河；冰川","definition":"a huge mass of ice that moves slowly over land","collocations":["melting glacier","a glacier retreats","climb a glacier"],"example":"The glacier has been melting rapidly due to climate change.","exampleZh":"由於氣候變遷,這座冰河一直快速融化。","synonyms":["ice sheet"],"level":5,"theme":"自然與環境","examples":[{"en":"The glacier has been melting rapidly due to climate change.","zh":"由於氣候變遷,這座冰河一直快速融化。"},{"en":"The huge glacier moves slowly down the valley each year.","zh":"這條巨大的冰河每年緩慢地順著山谷向下移動。"},{"en":"Rising temperatures are causing the glacier to melt quickly.","zh":"氣溫上升導致這條冰河快速融化。"}]},{"word":"glad","pos":"adj.","phonetic":"[glæd]","meaning":"高興的；樂意的","definition":"feeling pleasure or happiness","collocations":["glad to hear","be glad of","glad tidings"],"example":"I'm glad you could come to the party.","exampleZh":"我很高興你能來參加派對。","synonyms":["happy","pleased"],"level":1,"theme":"情緒與感受","examples":[{"en":"I'm glad you could come to the party.","zh":"我很高興你能來參加派對。"},{"en":"I'm so glad to hear that you passed the entrance exam.","zh":"很高興聽到你通過了入學考試。"},{"en":"She was glad of the chance to rest after the long hike.","zh":"長途健行後，她很慶幸有機會休息。"}]},{"word":"glamorous","pos":"adj.","phonetic":"[ˈɡlæmərəs]","meaning":"迷人的；富有魅力的","definition":"attractive in an exciting and fashionable way","collocations":["a glamorous life","glamorous career","glamorous star"],"example":"Being a movie star seemed like a glamorous life.","exampleZh":"當電影明星似乎是個充滿魅力的生活。","synonyms":["attractive","stylish"],"level":5,"theme":"服裝與外表","examples":[{"en":"Being a movie star seemed like a glamorous life.","zh":"當電影明星似乎是個充滿魅力的生活。"},{"en":"Many teenagers think a singer's life is exciting and glamorous.","zh":"許多青少年認為歌手的生活既刺激又迷人。"},{"en":"She looked glamorous in a long silver dress at the party.","zh":"她在派對上穿著銀色長裙，看起來光彩迷人。"}]},{"word":"glamour","pos":"n.","phonetic":"[ˈɡlæmər]","meaning":"魅力；迷人的吸引力","definition":"an attractive and exciting quality that appeals to others","collocations":["the glamour of fame","add glamour","lose its glamour"],"example":"The glamour of Hollywood attracts many young actors.","exampleZh":"好萊塢的魅力吸引了許多年輕演員。","synonyms":["charm","appeal"],"level":5,"theme":"藝術與音樂","examples":[{"en":"The glamour of Hollywood attracts many young actors.","zh":"好萊塢的魅力吸引了許多年輕演員。"},{"en":"The glamour of city life attracted her away from the village.","zh":"都市生活的魅力把她從村莊吸引走了。"},{"en":"After many years, the job slowly lost its glamour for him.","zh":"多年之後，這份工作對他而言漸漸失去了魅力。"}]},{"word":"glance","pos":"v. / n.","phonetic":"[glæns]","meaning":"瞥一眼；匆匆一看","definition":"to look at something quickly and briefly","collocations":["glance at","at a glance","quick glance"],"example":"She glanced at her watch during the meeting.","exampleZh":"她在開會時瞥了一眼手錶。","synonyms":["look","peek"],"level":3,"theme":"動作與行為","examples":[{"en":"She glanced at her watch during the meeting.","zh":"她在開會時瞥了一眼手錶。"},{"en":"He glanced at the clock and realized he was already late.","zh":"他瞥了一眼時鐘，發現自己已經遲到了。"},{"en":"At a glance, I could tell she was feeling upset.","zh":"一眼就能看出她心情不好。"}]},{"word":"gland","pos":"n.","phonetic":"[ɡlænd]","meaning":"腺體","definition":"an organ in the body that produces substances such as hormones","collocations":["sweat gland","thyroid gland","swollen glands"],"example":"The thyroid gland controls how fast the body uses energy.","exampleZh":"甲狀腺控制身體消耗能量的速度。","synonyms":[],"level":6,"theme":"身體與健康","examples":[{"en":"The thyroid gland controls how fast the body uses energy.","zh":"甲狀腺控制身體消耗能量的速度。"},{"en":"Sweat glands help the body cool down on a hot day.","zh":"汗腺在炎熱的日子幫助身體降溫。"},{"en":"The doctor checked whether the boy's glands were swollen.","zh":"醫生檢查了男孩的腺體是否腫大。"}]},{"word":"glare","pos":"v. / n.","phonetic":"[glɛr]","meaning":"怒視；強光","definition":"to stare in an angry way, or an unpleasantly strong bright light","collocations":["glare at someone","sun's glare","angry glare"],"example":"He glared at the driver who cut him off.","exampleZh":"他怒視著那個超車擋道的司機。","synonyms":["stare","scowl"],"level":4,"theme":"情緒與感受","examples":[{"en":"He glared at the driver who cut him off.","zh":"他怒視著那個超車擋道的司機。"},{"en":"The angry teacher glared at the students who were talking.","zh":"生氣的老師怒視著那些在講話的學生。"},{"en":"The glare of the sun made it hard to see the road.","zh":"刺眼的陽光讓人很難看清楚道路。"}]},{"word":"glass","pos":"n.","phonetic":"[glæs]","meaning":"玻璃；玻璃杯","definition":"a hard, transparent material, or a container made of it used for drinking","collocations":["a glass of water","broken glass","glass window"],"example":"He poured a glass of milk for his little brother.","exampleZh":"他為弟弟倒了一杯牛奶。","synonyms":[],"level":1,"theme":"居家與生活","examples":[{"en":"He poured a glass of milk for his little brother.","zh":"他為弟弟倒了一杯牛奶。"},{"en":"She drank a tall glass of water after her morning run.","zh":"晨跑後她喝了一大杯水。"},{"en":"Be careful of the broken glass on the kitchen floor.","zh":"小心廚房地板上的碎玻璃。"}]},{"word":"gleam","pos":"v. / n.","phonetic":"[ɡlim]","meaning":"閃爍；發亮","definition":"to shine with a soft light","collocations":["gleam in the sunlight","eyes gleam","a gleam of hope"],"example":"The polished floor gleamed under the lights.","exampleZh":"擦亮的地板在燈光下閃閃發光。","synonyms":["shine","glow"],"level":5,"theme":"性質與描述","examples":[{"en":"The polished floor gleamed under the lights.","zh":"擦亮的地板在燈光下閃閃發光。"},{"en":"The freshly washed car gleamed in the morning sunlight.","zh":"剛洗好的車在晨光下閃閃發亮。"},{"en":"There was a gleam of hope in the students' eyes.","zh":"學生們的眼中閃現一絲希望的光芒。"}]},{"word":"glide","pos":"v.","phonetic":"[glaɪd]","meaning":"滑行；滑翔","definition":"to move smoothly and continuously without effort","collocations":["glide across","glide through the air","gracefully glide"],"example":"The skater glided smoothly across the ice.","exampleZh":"滑冰選手輕盈地滑過冰面。","synonyms":["slide","float"],"level":4,"theme":"動作與行為","examples":[{"en":"The skater glided smoothly across the ice.","zh":"滑冰選手輕盈地滑過冰面。"},{"en":"The swan glided gracefully across the calm lake.","zh":"天鵝優雅地滑過平靜的湖面。"},{"en":"The paper plane glided through the air and landed softly.","zh":"紙飛機在空中滑翔，然後輕輕落地。"}]},{"word":"glimmer","pos":"n. / v.","phonetic":"[ˈɡlɪmər]","meaning":"微光；閃爍；一絲（希望等）","definition":"a weak or unsteady light, or a small sign of something","collocations":["a glimmer of hope","glimmer in the dark","faint glimmer"],"example":"There was still a glimmer of hope for the missing hikers.","exampleZh":"失蹤的登山客仍有一絲希望。","synonyms":["flicker","glow"],"level":5,"theme":"抽象概念","examples":[{"en":"There was still a glimmer of hope for the missing hikers.","zh":"失蹤的登山客仍有一絲希望。"},{"en":"A faint glimmer of light appeared at the end of the tunnel.","zh":"隧道盡頭出現了一絲微弱的光。"},{"en":"Even in hard times, she kept a glimmer of hope.","zh":"即使在艱難時刻，她仍保有一絲希望。"}]},{"word":"glimpse","pos":"n. / v.","phonetic":"[glɪmps]","meaning":"一瞥；瞥見","definition":"a brief or partial view of something","collocations":["catch a glimpse","glimpse of hope","brief glimpse"],"example":"I caught a glimpse of the singer as she left the theater.","exampleZh":"我瞥見那位歌手離開劇院的身影。","synonyms":["glance","peek"],"level":5,"theme":"動作與行為","examples":[{"en":"I caught a glimpse of the singer as she left the theater.","zh":"我瞥見那位歌手離開劇院的身影。"},{"en":"I caught a glimpse of the deer before it ran away.","zh":"在那隻鹿跑走前，我瞥見了牠一眼。"},{"en":"The tour gave us a brief glimpse of factory life.","zh":"這趟參觀讓我們短暫一窺工廠的生活。"}]},{"word":"glisten","pos":"v.","phonetic":"[ˈɡlɪsn̩]","meaning":"閃耀；閃閃發光","definition":"to shine because of being wet or covered with light","collocations":["glisten with sweat","dew glistens","eyes glisten with tears"],"example":"Her eyes glistened with tears of joy.","exampleZh":"她的眼睛因喜悅而閃著淚光。","synonyms":["sparkle","shine"],"level":5,"theme":"性質與描述","examples":[{"en":"Her eyes glistened with tears of joy.","zh":"她的眼睛因喜悅而閃著淚光。"},{"en":"The morning dew glistened on the green leaves in the garden.","zh":"清晨的露珠在花園裡的綠葉上閃閃發光。"},{"en":"His forehead glistened with sweat after the long race.","zh":"長跑之後，他的額頭閃著汗水的光。"}]},{"word":"glitch","pos":"n.","phonetic":"[ɡlɪtʃ]","meaning":"（電腦或機器的）小故障","definition":"a small problem or fault, especially in a machine or plan","collocations":["a technical glitch","fix a glitch","software glitch"],"example":"A software glitch delayed the flight for two hours.","exampleZh":"一個軟體故障使班機延誤了兩小時。","synonyms":["fault","malfunction"],"level":5,"theme":"科技與媒體","examples":[{"en":"A software glitch delayed the flight for two hours.","zh":"一個軟體故障使班機延誤了兩小時。"},{"en":"A technical glitch caused the website to crash during the exam.","zh":"一個技術故障導致網站在考試期間當機。"},{"en":"The engineers worked all night to fix the software glitch.","zh":"工程師們熬夜修復這個軟體故障。"}]},{"word":"global","pos":"adj.","phonetic":"[ˈglobl̩]","meaning":"全球的；全世界的","definition":"relating to the whole world","collocations":["global warming","global economy","global market"],"example":"Global warming is affecting weather patterns worldwide.","exampleZh":"全球暖化正影響著世界各地的氣候型態。","synonyms":["worldwide","international"],"level":3,"theme":"自然與環境","examples":[{"en":"Global warming is affecting weather patterns worldwide.","zh":"全球暖化正影響著世界各地的氣候型態。"},{"en":"Global warming is one of the biggest challenges we face today.","zh":"全球暖化是我們今日面臨的最大挑戰之一。"},{"en":"Many products in the global market come from several countries.","zh":"全球市場上的許多產品來自好幾個國家。"}]},{"word":"globalization","pos":"n.","phonetic":"[ˌɡlobələˈzeʃən]","meaning":"全球化","definition":"the process by which businesses and cultures become connected worldwide","collocations":["economic globalization","the effects of globalization","globalization of trade"],"example":"Globalization has changed the way companies do business.","exampleZh":"全球化改變了企業經營的方式。","synonyms":[],"level":6,"theme":"商業與金錢","examples":[{"en":"Globalization has changed the way companies do business.","zh":"全球化改變了企業經營的方式。"},{"en":"Globalization has made it easier to buy goods from abroad.","zh":"全球化讓購買國外商品變得更容易了。"},{"en":"Students today should understand the effects of globalization on jobs.","zh":"現今的學生應該了解全球化對工作的影響。"}]},{"word":"globe","pos":"n.","phonetic":"[glob]","meaning":"地球儀；地球；全球","definition":"a model of the earth shaped like a ball, or the earth itself","collocations":["around the globe","spin the globe","the globe"],"example":"News of the discovery spread around the globe.","exampleZh":"這項發現的消息傳遍了全世界。","synonyms":["earth","world"],"level":3,"theme":"自然與環境","examples":[{"en":"News of the discovery spread around the globe.","zh":"這項發現的消息傳遍了全世界。"},{"en":"The teacher spun the globe to show us where Africa is.","zh":"老師轉動地球儀，讓我們看非洲在哪裡。"},{"en":"News of the invention quickly spread around the globe.","zh":"這項發明的消息很快就傳遍了全球。"}]},{"word":"gloomy","pos":"adj.","phonetic":"[ˈglumɪ]","meaning":"陰沉的；憂鬱的","definition":"dark or dull, especially in a way that makes one feel sad","collocations":["gloomy weather","gloomy mood","gloomy outlook"],"example":"The gloomy weather made everyone feel tired.","exampleZh":"陰沉的天氣讓大家都感到疲倦。","synonyms":["dark","depressing"],"level":5,"theme":"情緒與感受","examples":[{"en":"The gloomy weather made everyone feel tired.","zh":"陰沉的天氣讓大家都感到疲倦。"},{"en":"The gloomy weather kept everyone indoors all weekend.","zh":"陰沉的天氣讓大家整個週末都待在室內。"},{"en":"He was in a gloomy mood after failing the test.","zh":"考試不及格後，他心情很低落。"}]},{"word":"glorious","pos":"adj.","phonetic":"[ˈglorɪəs]","meaning":"光榮的；壯麗的","definition":"having, worthy of, or bringing fame or admiration; wonderfully impressive","collocations":["glorious victory","glorious sunset","glorious history"],"example":"The team celebrated a glorious victory in the final.","exampleZh":"球隊在決賽中慶祝了光榮的勝利。","synonyms":["magnificent","splendid"],"level":5,"theme":"性質與描述","examples":[{"en":"The team celebrated a glorious victory in the final.","zh":"球隊在決賽中慶祝了光榮的勝利。"},{"en":"We watched a glorious sunset from the top of the hill.","zh":"我們從山頂上欣賞了壯麗的日落。"},{"en":"The team enjoyed a glorious victory in the national final.","zh":"這支隊伍在全國決賽中贏得了光榮的勝利。"}]},{"word":"glory","pos":"n.","phonetic":"[ˈglorɪ]","meaning":"光榮；榮耀","definition":"high renown or honor, or great beauty","collocations":["moment of glory","in all its glory","seek glory"],"example":"He basked in the glory of his championship win.","exampleZh":"他沉浸在贏得冠軍的榮耀之中。","synonyms":["honor","fame"],"level":4,"theme":"抽象概念","examples":[{"en":"He basked in the glory of his championship win.","zh":"他沉浸在贏得冠軍的榮耀之中。"},{"en":"The runner enjoyed his moment of glory on the winners' stand.","zh":"這位跑者在頒獎台上享受他光榮的時刻。"},{"en":"In autumn, the maple trees stand in all their glory.","zh":"秋天時，楓樹展現出全部的美麗風采。"}]},{"word":"glossary","pos":"n.","phonetic":"[ˈɡlɑsəri]","meaning":"詞彙表；術語彙編","definition":"a list of difficult words and their meanings, usually at the end of a book","collocations":["check the glossary","a glossary of terms","include a glossary"],"example":"You can find the meaning of new words in the glossary.","exampleZh":"你可以在詞彙表裡找到生字的意思。","synonyms":["word list"],"level":4,"theme":"教育與學習","examples":[{"en":"You can find the meaning of new words in the glossary.","zh":"你可以在詞彙表裡找到生字的意思。"},{"en":"If you meet a hard word, check the glossary at the back.","zh":"如果你遇到難懂的字，請查閱書後的詞彙表。"},{"en":"The textbook includes a glossary of important scientific terms.","zh":"這本教科書收錄了一份重要科學術語的詞彙表。"}]},{"word":"glossy","pos":"adj.","phonetic":"[ˈɡlɑsi]","meaning":"光滑有光澤的；亮面的","definition":"smooth and shiny","collocations":["glossy paper","glossy hair","glossy magazine"],"example":"The magazine was printed on glossy paper.","exampleZh":"這本雜誌印在光面紙上。","synonyms":["shiny","polished"],"level":4,"theme":"性質與描述","examples":[{"en":"The magazine was printed on glossy paper.","zh":"這本雜誌印在光面紙上。"},{"en":"The magazine was printed on thick, glossy paper.","zh":"這本雜誌印在厚實光亮的紙上。"},{"en":"After using the new shampoo, her hair looked smooth and glossy.","zh":"用了新洗髮精後，她的頭髮看起來又滑又亮。"}]},{"word":"glove","pos":"n.","phonetic":"[glʌv]","meaning":"手套","definition":"a covering for the hand, with separate parts for each finger","collocations":["a pair of gloves","wear gloves","boxing gloves"],"example":"She put on her gloves before going out into the cold.","exampleZh":"她在出門到寒冷的戶外前戴上了手套。","synonyms":[],"level":1,"theme":"服裝與外表","examples":[{"en":"She put on her gloves before going out into the cold.","zh":"她在出門到寒冷的戶外前戴上了手套。"},{"en":"She wore a warm pair of gloves during the cold morning.","zh":"寒冷的早晨她戴了一副溫暖的手套。"},{"en":"The boxer tightened his gloves before the match began.","zh":"拳擊手在比賽開始前繫緊了他的拳擊手套。"}]},{"word":"glow","pos":"v. / n.","phonetic":"[glo]","meaning":"發光；容光煥發","definition":"to produce a steady, soft light, or such a light","collocations":["glow in the dark","healthy glow","the fire glowed"],"example":"The fireflies glowed in the dark garden.","exampleZh":"螢火蟲在黑暗的花園裡發著光。","synonyms":["shine","gleam"],"level":3,"theme":"性質與描述","examples":[{"en":"The fireflies glowed in the dark garden.","zh":"螢火蟲在黑暗的花園裡發著光。"},{"en":"The tiny lights glowed softly in the dark garden.","zh":"微小的燈光在黑暗的花園裡柔和地發亮。"},{"en":"Her face had a healthy glow after the morning jog.","zh":"晨跑後她的臉上散發著健康的光彩。"}]},{"word":"glue","pos":"n. / v.","phonetic":"[glu]","meaning":"膠水；黏著","definition":"a sticky substance used to join things together","collocations":["a tube of glue","glue together","glue stick"],"example":"He used glue to fix the broken toy.","exampleZh":"他用膠水修理了壞掉的玩具。","synonyms":["adhesive"],"level":1,"theme":"居家與生活","examples":[{"en":"He used glue to fix the broken toy.","zh":"他用膠水修理了壞掉的玩具。"},{"en":"He used a little glue to fix the pages back together.","zh":"他用一點膠水把書頁重新黏回去。"},{"en":"She glued the broken handle back onto the teacup.","zh":"她把斷掉的把手重新黏回茶杯上。"}]},{"word":"gnaw","pos":"v.","phonetic":"[nɔ]","meaning":"啃；咬","definition":"to keep biting something repeatedly","collocations":["gnaw on a bone","gnaw at something","gnaw away"],"example":"The dog was gnawing on a bone in the yard.","exampleZh":"那隻狗在院子裡啃骨頭。","synonyms":["chew","bite"],"level":5,"theme":"動作與行為","examples":[{"en":"The dog was gnawing on a bone in the yard.","zh":"那隻狗在院子裡啃骨頭。"},{"en":"The puppy loves to gnaw on an old rubber toy.","zh":"小狗喜歡啃一個舊的橡膠玩具。"},{"en":"Mice had gnawed a hole through the corner of the box.","zh":"老鼠在箱子的角落啃出了一個洞。"}]},{"word":"goal","pos":"n.","phonetic":"[gol]","meaning":"目標；(足球)進球","definition":"an aim or desired result; a point scored in soccer or hockey","collocations":["set a goal","score a goal","achieve a goal"],"example":"Her goal is to become a doctor someday.","exampleZh":"她的目標是有一天成為一名醫生。","synonyms":["aim","objective"],"level":2,"theme":"抽象概念","examples":[{"en":"Her goal is to become a doctor someday.","zh":"她的目標是有一天成為一名醫生。"},{"en":"Her main goal is to improve her English before college.","zh":"她主要的目標是在上大學前把英文學好。"},{"en":"He scored the winning goal in the last minute of the match.","zh":"他在比賽最後一分鐘踢進了致勝的一球。"}]},{"word":"goalkeeper","pos":"n.","phonetic":"[ˈɡolˌkipər]","meaning":"守門員","definition":"the player who stops the ball from entering the goal","collocations":["team goalkeeper","skilled goalkeeper","the goalkeeper saves the ball"],"example":"The goalkeeper made an amazing save in the final minute.","exampleZh":"守門員在最後一分鐘做出了精采的撲救。","synonyms":["keeper"],"level":3,"theme":"運動與休閒","examples":[{"en":"The goalkeeper made an amazing save in the final minute.","zh":"守門員在最後一分鐘做出了精采的撲救。"},{"en":"The goalkeeper jumped high and blocked the powerful shot.","zh":"守門員高高躍起，擋下了那記強勁的射門。"},{"en":"A good goalkeeper needs quick hands and steady nerves.","zh":"優秀的守門員需要敏捷的雙手和穩定的膽識。"}]},{"word":"goat","pos":"n.","phonetic":"[got]","meaning":"山羊","definition":"a horned farm animal related to sheep","collocations":["a herd of goats","goat milk","raise goats"],"example":"The farmer keeps several goats on his land.","exampleZh":"農夫在他的土地上養了幾隻山羊。","synonyms":[],"level":1,"theme":"動物與植物","examples":[{"en":"The farmer keeps several goats on his land.","zh":"農夫在他的土地上養了幾隻山羊。"},{"en":"The farmer milks his goats early every morning.","zh":"農夫每天一大早就為他的山羊擠奶。"},{"en":"A small herd of goats climbed the rocky hillside.","zh":"一小群山羊爬上了多岩石的山坡。"}]},{"word":"gobble","pos":"v.","phonetic":"[ˈɡɑbḷ]","meaning":"狼吞虎嚥地吃","definition":"to eat food very quickly and noisily","collocations":["gobble up food","gobble down a meal","gobble everything in sight"],"example":"The children gobbled up their lunch before playing outside.","exampleZh":"孩子們狼吞虎嚥地吃完午餐後就出去玩了。","synonyms":["devour","gulp"],"level":4,"theme":"食物與烹飪","examples":[{"en":"The children gobbled up their lunch before playing outside.","zh":"孩子們狼吞虎嚥地吃完午餐後就出去玩了。"},{"en":"The hungry boys gobbled up the pizza in just a few minutes.","zh":"飢餓的男孩們幾分鐘就把披薩狼吞虎嚥吃光了。"},{"en":"Don't gobble down your food; chew it slowly instead.","zh":"別狼吞虎嚥，要慢慢咀嚼食物。"}]},{"word":"goggles","pos":"n.","phonetic":"[ˈɡɑɡḷz]","meaning":"護目鏡；蛙鏡","definition":"special glasses worn to protect the eyes","collocations":["swimming goggles","safety goggles","wear goggles"],"example":"Wear safety goggles when using power tools.","exampleZh":"使用電動工具時要戴安全護目鏡。","synonyms":[],"level":3,"theme":"服裝與外表","examples":[{"en":"Wear safety goggles when using power tools.","zh":"使用電動工具時要戴安全護目鏡。"},{"en":"Always wear safety goggles when you do chemistry experiments.","zh":"做化學實驗時一定要戴上安全護目鏡。"},{"en":"She adjusted her swimming goggles before diving into the pool.","zh":"她跳進泳池前調整了她的蛙鏡。"}]},{"word":"gold","pos":"n. / adj.","phonetic":"[gold]","meaning":"黃金；金色的","definition":"a valuable yellow precious metal, or the color of it","collocations":["pure gold","gold medal","gold ring"],"example":"The athlete won a gold medal at the Olympics.","exampleZh":"這位運動員在奧運會上贏得了金牌。","synonyms":[],"level":1,"theme":"商業與金錢","examples":[{"en":"The athlete won a gold medal at the Olympics.","zh":"這位運動員在奧運會上贏得了金牌。"},{"en":"The champion proudly wore her shiny gold medal.","zh":"冠軍驕傲地戴著她閃亮的金牌。"},{"en":"He gave his wife a simple gold ring on their anniversary.","zh":"在結婚週年時，他送給妻子一枚簡單的金戒指。"}]},{"word":"golden","pos":"adj.","phonetic":"[ˈgoldn̩]","meaning":"金色的；黃金的；極好的","definition":"made of gold, or having a bright, attractive yellow color; excellent","collocations":["golden opportunity","golden hair","golden age"],"example":"This is a golden opportunity you shouldn't miss.","exampleZh":"這是一個你不該錯過的絕佳機會。","synonyms":[],"level":2,"theme":"性質與描述","examples":[{"en":"This is a golden opportunity you shouldn't miss.","zh":"這是一個你不該錯過的絕佳機會。"},{"en":"Don't miss this golden opportunity to study abroad for free.","zh":"別錯過這個免費出國留學的絕佳機會。"},{"en":"The fields turned a beautiful golden color in autumn.","zh":"秋天時田野變成美麗的金黃色。"}]},{"word":"golf","pos":"n.","phonetic":"[gɑlf]","meaning":"高爾夫球","definition":"a game played by hitting a small ball into a series of holes with clubs","collocations":["play golf","golf course","golf club"],"example":"My father plays golf every weekend.","exampleZh":"我爸爸每個週末都打高爾夫球。","synonyms":[],"level":2,"theme":"運動與休閒","examples":[{"en":"My father plays golf every weekend.","zh":"我爸爸每個週末都打高爾夫球。"},{"en":"My uncle plays golf on the course near his house.","zh":"我叔叔在他家附近的球場打高爾夫球。"},{"en":"He bought a new set of golf clubs for the tournament.","zh":"他為了這場比賽買了一組新的高爾夫球桿。"}]},{"word":"good","pos":"adj. / n.","phonetic":"[gʊd]","meaning":"好的；良好的；益處","definition":"of high quality or a positive standard; benefit","collocations":["good idea","good at","for the good of","do good"],"example":"She is very good at playing the piano.","exampleZh":"她很擅長彈鋼琴。","synonyms":["fine","nice"],"level":1,"theme":"性質與描述","examples":[{"en":"She is very good at playing the piano.","zh":"她很擅長彈鋼琴。"},{"en":"That's a good idea; let's try it during the group project.","zh":"這是個好主意，我們在小組專題中試試看吧。"},{"en":"The new rules were made for the good of all students.","zh":"這些新規定是為了全體學生的益處而制定的。"}]},{"word":"goodbye","pos":"int. / n.","phonetic":"[ˌgʊdˈbaɪ]","meaning":"再見","definition":"a word used when leaving or parting from someone","collocations":["say goodbye","wave goodbye","a sad goodbye"],"example":"They said goodbye at the airport.","exampleZh":"他們在機場道別。","synonyms":["farewell"],"level":1,"theme":"溝通與語言","examples":[{"en":"They said goodbye at the airport.","zh":"他們在機場道別。"},{"en":"They waved goodbye as the bus slowly left the station.","zh":"公車緩緩駛離車站時，他們揮手道別。"},{"en":"Saying goodbye to old classmates after graduation felt very sad.","zh":"畢業後和老同學道別讓人感到非常難過。"}]},{"word":"goods","pos":"n.","phonetic":"[gʊdz]","meaning":"商品；貨物","definition":"things that are made to be sold","collocations":["consumer goods","deliver goods","household goods"],"example":"The truck was loaded with goods for the market.","exampleZh":"卡車裝滿了要運到市場的貨物。","synonyms":["merchandise","products"],"level":3,"theme":"商業與金錢","examples":[{"en":"The truck was loaded with goods for the market.","zh":"卡車裝滿了要運到市場的貨物。"},{"en":"The store sells household goods at very reasonable prices.","zh":"這家商店以非常合理的價格販售家用商品。"},{"en":"Trucks deliver fresh goods to the market every morning.","zh":"卡車每天早上把新鮮貨物運送到市場。"}]},{"word":"goose","pos":"n.","phonetic":"[gus]","meaning":"鵝","definition":"a large water bird related to the duck, with a long neck","collocations":["a flock of geese","wild goose","roast goose"],"example":"A flock of geese flew south for the winter.","exampleZh":"一群鵝飛往南方過冬。","synonyms":[],"level":2,"theme":"動物與植物","examples":[{"en":"A flock of geese flew south for the winter.","zh":"一群鵝飛往南方過冬。"},{"en":"A flock of geese flew south as winter approached.","zh":"冬天將至，一群鵝往南飛去。"},{"en":"The family enjoyed roast goose during the holiday dinner.","zh":"這家人在節日晚餐時享用了烤鵝。"}]},{"word":"gorgeous","pos":"adj.","phonetic":"[ˈgɔrdʒəs]","meaning":"華麗的；極美的","definition":"beautiful, attractive, or wonderful in appearance","collocations":["gorgeous view","gorgeous dress","gorgeous weather"],"example":"The view from the mountain top was absolutely gorgeous.","exampleZh":"從山頂看到的景色美極了。","synonyms":["beautiful","stunning"],"level":4,"theme":"性質與描述","examples":[{"en":"The view from the mountain top was absolutely gorgeous.","zh":"從山頂看到的景色美極了。"},{"en":"From the hilltop we admired the gorgeous view of the bay.","zh":"從山頂上我們欣賞了海灣的絕美景色。"},{"en":"She wore a gorgeous dress to her sister's wedding.","zh":"她穿著一件華美的洋裝去參加姊姊的婚禮。"}]},{"word":"gorilla","pos":"n.","phonetic":"[ɡəˈrɪlə]","meaning":"大猩猩","definition":"a very large, strong ape found in Africa","collocations":["a mountain gorilla","gorilla habitat","a family of gorillas"],"example":"The zoo added a new baby gorilla to its family.","exampleZh":"動物園迎來了一隻新出生的小猩猩。","synonyms":["ape"],"level":2,"theme":"動物與植物","examples":[{"en":"The zoo added a new baby gorilla to its family.","zh":"動物園迎來了一隻新出生的小猩猩。"},{"en":"The zoo welcomed a new baby gorilla last week.","zh":"動物園上週迎接了一隻新生的大猩猩寶寶。"},{"en":"Cutting down forests destroys the natural habitat of gorillas.","zh":"砍伐森林破壞了大猩猩的自然棲息地。"}]},{"word":"gospel","pos":"n.","phonetic":"[ˈgɑspəl]","meaning":"福音；真理","definition":"the teaching or message of Jesus Christ; an undeniable truth","collocations":["gospel music","spread the gospel","take something as gospel"],"example":"He treats his coach's advice as gospel.","exampleZh":"他把教練的建議奉為真理。","synonyms":[],"level":5,"theme":"社會與文化","examples":[{"en":"He treats his coach's advice as gospel.","zh":"他把教練的建議奉為真理。"},{"en":"The choir sang beautiful gospel music at the church.","zh":"唱詩班在教堂裡唱著優美的福音音樂。"},{"en":"He takes every word of his coach as gospel.","zh":"他把教練說的每句話都當作真理。"}]},{"word":"gossip","pos":"n. / v.","phonetic":"[ˈgɑsəp]","meaning":"八卦；閒話","definition":"casual talk about other people's private lives, often not confirmed as true","collocations":["office gossip","spread gossip","gossip about"],"example":"She doesn't like to spread gossip about her coworkers.","exampleZh":"她不喜歡散播關於同事的八卦。","synonyms":["rumor","talk"],"level":4,"theme":"溝通與語言","examples":[{"en":"She doesn't like to spread gossip about her coworkers.","zh":"她不喜歡散播關於同事的八卦。"},{"en":"She refuses to spread gossip about her classmates.","zh":"她拒絕散播關於同學的八卦。"},{"en":"The two friends love to gossip about their favorite singers.","zh":"這兩個朋友喜歡八卦她們最愛的歌手。"}]},{"word":"gourmet","pos":"n. / adj.","phonetic":"[ɡʊrˈme]","meaning":"美食家；精緻美食的","definition":"a person who enjoys fine food, or relating to high-quality food","collocations":["gourmet food","gourmet restaurant","a true gourmet"],"example":"The hotel is famous for its gourmet restaurant.","exampleZh":"這家飯店以其精緻美食餐廳聞名。","synonyms":["connoisseur"],"level":5,"theme":"食物與烹飪","examples":[{"en":"The hotel is famous for its gourmet restaurant.","zh":"這家飯店以其精緻美食餐廳聞名。"},{"en":"The new restaurant serves gourmet food from around the world.","zh":"這家新餐廳供應來自世界各地的精緻美食。"},{"en":"As a true gourmet, he can name every spice in the dish.","zh":"身為真正的美食家，他能說出這道菜裡的每種香料。"}]},{"word":"govern","pos":"v.","phonetic":"[ˈgʌvɚn]","meaning":"統治；管理","definition":"to officially control and lead a country or organization","collocations":["govern a country","govern effectively","govern by law"],"example":"The president promised to govern fairly and honestly.","exampleZh":"總統承諾要公正誠實地治理國家。","synonyms":["rule","control"],"level":4,"theme":"政治與法律","examples":[{"en":"The president promised to govern fairly and honestly.","zh":"總統承諾要公正誠實地治理國家。"},{"en":"The mayor promised to govern the city honestly and fairly.","zh":"市長承諾會誠實公正地治理這座城市。"},{"en":"Clear rules help teachers govern a large classroom effectively.","zh":"明確的規則幫助老師有效地管理大班級。"}]},{"word":"government","pos":"n.","phonetic":"[ˈgʌvɚnmənt]","meaning":"政府","definition":"the group of people who officially govern a country or state","collocations":["local government","government policy","run for government"],"example":"The government announced a new education policy.","exampleZh":"政府宣布了一項新的教育政策。","synonyms":[],"level":2,"theme":"政治與法律","examples":[{"en":"The government announced a new education policy.","zh":"政府宣布了一項新的教育政策。"},{"en":"The government announced a new policy to support young farmers.","zh":"政府宣布了一項支持年輕農民的新政策。"},{"en":"Our local government is building more parks in the neighborhood.","zh":"我們的地方政府正在社區裡興建更多公園。"}]},{"word":"governor","pos":"n.","phonetic":"[ˈgʌvɚnɚ]","meaning":"州長；總督","definition":"a person who officially governs a state or region","collocations":["state governor","elect a governor","governor's office"],"example":"The governor signed the new law yesterday.","exampleZh":"州長昨天簽署了這項新法律。","synonyms":[],"level":4,"theme":"政治與法律","examples":[{"en":"The governor signed the new law yesterday.","zh":"州長昨天簽署了這項新法律。"},{"en":"The governor visited our school to give a short speech.","zh":"州長造訪我們學校發表了一場簡短的演說。"},{"en":"Citizens will elect a new governor this coming November.","zh":"公民將在今年十一月選出新任州長。"}]},{"word":"gown","pos":"n.","phonetic":"[gaʊn]","meaning":"長袍；禮服","definition":"a long formal dress or robe","collocations":["evening gown","wedding gown","graduation gown"],"example":"She wore a beautiful blue gown to the ball.","exampleZh":"她穿著一件漂亮的藍色禮服去參加舞會。","synonyms":["dress","robe"],"level":3,"theme":"服裝與外表","examples":[{"en":"She wore a beautiful blue gown to the ball.","zh":"她穿著一件漂亮的藍色禮服去參加舞會。"},{"en":"She wore an elegant evening gown to the school dance.","zh":"她穿著優雅的晚禮服參加學校的舞會。"},{"en":"Each student put on a black graduation gown for the ceremony.","zh":"每位學生都穿上黑色的畢業袍參加典禮。"}]},{"word":"grab","pos":"v.","phonetic":"[græb]","meaning":"抓住；奪取","definition":"to take hold of something suddenly and roughly","collocations":["grab a chance","grab hold of","grab lunch"],"example":"He grabbed his bag and ran out the door.","exampleZh":"他抓起書包就跑出門去。","synonyms":["seize","snatch"],"level":2,"theme":"動作與行為","examples":[{"en":"He grabbed his bag and ran out the door.","zh":"他抓起書包就跑出門去。"},{"en":"He grabbed his umbrella and rushed out into the rain.","zh":"他抓起雨傘，衝進了雨中。"},{"en":"Let's grab a quick lunch before the afternoon class starts.","zh":"我們在下午課開始前快點吃個午餐吧。"}]},{"word":"grace","pos":"n.","phonetic":"[gres]","meaning":"優雅；恩典","definition":"elegance and beauty of movement or form; kindness shown to someone","collocations":["with grace","grace period","fall from grace"],"example":"The dancer moved across the stage with great grace.","exampleZh":"這位舞者以優美的姿態橫越舞台。","synonyms":["elegance"],"level":4,"theme":"抽象概念","examples":[{"en":"The dancer moved across the stage with great grace.","zh":"這位舞者以優美的姿態橫越舞台。"},{"en":"The dancer crossed the stage with remarkable grace.","zh":"這位舞者以非凡的優雅姿態越過舞台。"},{"en":"The bank gave him a short grace period to repay the loan.","zh":"銀行給了他一小段寬限期來償還貸款。"}]},{"word":"graceful","pos":"adj.","phonetic":"[ˈgresfəl]","meaning":"優雅的；優美的","definition":"moving in a smooth and attractive way","collocations":["graceful movement","graceful swan","graceful exit"],"example":"The swan glided across the lake in a graceful manner.","exampleZh":"天鵝以優雅的姿態滑過湖面。","synonyms":["elegant"],"level":3,"theme":"性質與描述","examples":[{"en":"The swan glided across the lake in a graceful manner.","zh":"天鵝以優雅的姿態滑過湖面。"},{"en":"The gymnast made a graceful landing after her final jump.","zh":"體操選手在最後一跳後優雅地落地。"},{"en":"Even in defeat, she made a graceful exit from the court.","zh":"即使落敗，她也優雅地離開了球場。"}]},{"word":"gracious","pos":"adj.","phonetic":"[ˈgreʃəs]","meaning":"親切的；和藹的","definition":"kind, polite, and pleasant especially to someone of lower status","collocations":["a gracious host","gracious manner","gracious in defeat"],"example":"Our host was gracious enough to let us stay another night.","exampleZh":"我們的主人很親切地讓我們多住一晚。","synonyms":["polite","courteous"],"level":5,"theme":"性質與描述","examples":[{"en":"Our host was gracious enough to let us stay another night.","zh":"我們的主人很親切地讓我們多住一晚。"},{"en":"Our gracious host offered us tea and homemade cookies.","zh":"我們親切的主人請我們喝茶和吃自製餅乾。"},{"en":"He was gracious in defeat and warmly congratulated the winner.","zh":"他輸得有風度，並熱情地恭喜了勝利者。"}]},{"word":"grade","pos":"n. / v.","phonetic":"[gred]","meaning":"年級；成績；等級","definition":"a level of school, a mark given for work, or a level of quality","collocations":["get good grades","fifth grade","grade papers"],"example":"She got good grades on her final exams.","exampleZh":"她在期末考試中拿到了好成績。","synonyms":["score","rank"],"level":1,"theme":"教育與學習","examples":[{"en":"She got good grades on her final exams.","zh":"她在期末考試中拿到了好成績。"},{"en":"She worked hard and got good grades this semester.","zh":"她很努力，這學期拿到了好成績。"},{"en":"My little brother just started the fifth grade this year.","zh":"我弟弟今年剛升上五年級。"}]},{"word":"gradient","pos":"n.","phonetic":"[ˈɡrediənt]","meaning":"坡度；梯度","definition":"the degree of steepness of a slope, or a gradual change in value","collocations":["a steep gradient","temperature gradient","color gradient"],"example":"The road has a steep gradient near the mountain top.","exampleZh":"這條路靠近山頂處坡度很陡。","synonyms":["slope"],"level":6,"theme":"科學與數學","examples":[{"en":"The road has a steep gradient near the mountain top.","zh":"這條路靠近山頂處坡度很陡。"},{"en":"Cyclists struggled with the steep gradient of the mountain road.","zh":"自行車手在山路陡峭的坡度上騎得很吃力。"},{"en":"The poster uses a color gradient from blue to green.","zh":"這張海報使用了從藍到綠的漸層色。"}]},{"word":"gradual","pos":"adj.","phonetic":"[ˈgrædʒʊəl]","meaning":"逐漸的；漸進的","definition":"happening slowly over a long period of time","collocations":["gradual change","gradual increase","a gradual process"],"example":"There has been a gradual increase in average temperatures.","exampleZh":"平均氣溫一直在逐漸上升。","synonyms":["slow","steady"],"level":4,"theme":"抽象概念","examples":[{"en":"There has been a gradual increase in average temperatures.","zh":"平均氣溫一直在逐漸上升。"},{"en":"There has been a gradual increase in the number of readers.","zh":"讀者的數量出現了逐漸的增加。"},{"en":"Learning a language is a gradual process that takes patience.","zh":"學習語言是一個需要耐心的漸進過程。"}]},{"word":"gradually","pos":"adv.","phonetic":"[ˈgrædʒʊəli]","meaning":"逐漸地","definition":"slowly over a period of time","collocations":["gradually increase","gradually change","gradually improve"],"example":"The weather gradually became warmer as spring arrived.","exampleZh":"隨著春天到來，天氣逐漸變暖。","synonyms":["slowly","steadily"],"level":3,"theme":"時間與空間","examples":[{"en":"The weather gradually became warmer as spring arrived.","zh":"隨著春天到來，天氣逐漸變暖。"},{"en":"The sky gradually grew darker as evening approached.","zh":"隨著傍晚來臨，天空逐漸變暗。"},{"en":"With daily practice, her pronunciation gradually improved.","zh":"透過每天練習，她的發音逐漸進步了。"}]},{"word":"graduate","pos":"v. / n.","phonetic":"[ˈgrædʒʊˌet]","meaning":"畢業；畢業生","definition":"to complete a course of study successfully, or a person who has done so","collocations":["graduate from college","college graduate","graduate school"],"example":"She will graduate from high school next June.","exampleZh":"她將於明年六月從高中畢業。","synonyms":[],"level":3,"theme":"教育與學習","examples":[{"en":"She will graduate from high school next June.","zh":"她將於明年六月從高中畢業。"},{"en":"She hopes to graduate from college with top honors.","zh":"她希望以最優異的成績從大學畢業。"},{"en":"As a recent graduate, he is now looking for his first job.","zh":"身為剛畢業的社會新鮮人，他正在找第一份工作。"}]},{"word":"graduation","pos":"n.","phonetic":"[ˌgrædʒʊˈeʃən]","meaning":"畢業；畢業典禮","definition":"the act of graduating, or the ceremony for this","collocations":["graduation ceremony","graduation day","attend graduation"],"example":"Her parents were proud at her graduation ceremony.","exampleZh":"她的父母在畢業典禮上感到非常驕傲。","synonyms":[],"level":3,"theme":"教育與學習","examples":[{"en":"Her parents were proud at her graduation ceremony.","zh":"她的父母在畢業典禮上感到非常驕傲。"},{"en":"Her whole family attended her graduation ceremony last week.","zh":"上週她全家人都出席了她的畢業典禮。"},{"en":"On graduation day, the students threw their caps into the air.","zh":"畢業當天，學生們把帽子拋向空中。"}]},{"word":"graffiti","pos":"n.","phonetic":"[ɡrəˈfiti]","meaning":"塗鴉","definition":"words or drawings, often illegal, painted on public walls","collocations":["spray graffiti","remove graffiti","colorful graffiti"],"example":"The wall was covered in colorful graffiti.","exampleZh":"這面牆上滿是色彩繽紛的塗鴉。","synonyms":[],"level":5,"theme":"藝術與音樂","examples":[{"en":"The wall was covered in colorful graffiti.","zh":"這面牆上滿是色彩繽紛的塗鴉。"},{"en":"Colorful graffiti covered the walls under the old bridge.","zh":"五顏六色的塗鴉覆蓋了舊橋下的牆面。"},{"en":"The city hired workers to remove graffiti from public buildings.","zh":"市政府僱用工人清除公共建築上的塗鴉。"}]},{"word":"grain","pos":"n.","phonetic":"[gren]","meaning":"穀物；顆粒","definition":"the seeds of cereal plants, or a small hard particle","collocations":["whole grain","grain of sand","grain of rice"],"example":"Whole grain bread is healthier than white bread.","exampleZh":"全穀麵包比白麵包更健康。","synonyms":[],"level":3,"theme":"食物與烹飪","examples":[{"en":"Whole grain bread is healthier than white bread.","zh":"全穀麵包比白麵包更健康。"},{"en":"Doctors say whole grain foods are good for your health.","zh":"醫生說全穀類食物對你的健康有益。"},{"en":"A single grain of sand was stuck under her fingernail.","zh":"一粒沙子卡在她的指甲底下。"}]},{"word":"gram","pos":"n.","phonetic":"[græm]","meaning":"公克","definition":"a unit of weight in the metric system","collocations":["a hundred grams","gram of sugar","measure in grams"],"example":"Please add two hundred grams of flour.","exampleZh":"請加入兩百公克的麵粉。","synonyms":[],"level":2,"theme":"科學與數學","examples":[{"en":"Please add two hundred grams of flour.","zh":"請加入兩百公克的麵粉。"},{"en":"Please add two hundred grams of sugar to the batter.","zh":"請在麵糊裡加入兩百公克的糖。"},{"en":"The nurse weighed the medicine carefully in grams.","zh":"護士小心地以公克為單位秤量藥物。"}]},{"word":"grammar","pos":"n.","phonetic":"[ˈgræmɚ]","meaning":"文法；語法","definition":"the rules by which words change and combine to form sentences","collocations":["grammar rules","check grammar","English grammar"],"example":"The teacher explained the grammar rule about verb tenses.","exampleZh":"老師解釋了關於動詞時態的文法規則。","synonyms":[],"level":2,"theme":"教育與學習","examples":[{"en":"The teacher explained the grammar rule about verb tenses.","zh":"老師解釋了關於動詞時態的文法規則。"},{"en":"The teacher explained the grammar rules for the past tense.","zh":"老師講解了過去式的文法規則。"},{"en":"Good grammar makes your writing clearer and easier to read.","zh":"良好的文法讓你的寫作更清楚、更容易閱讀。"}]},{"word":"grammatical","pos":"adj.","phonetic":"[ɡrəˈmætɪkḷ]","meaning":"文法上的；符合文法的","definition":"relating to grammar or correct according to grammar rules","collocations":["a grammatical error","grammatical structure","grammatically correct"],"example":"The essay had several grammatical errors.","exampleZh":"這篇文章有幾處文法錯誤。","synonyms":[],"level":5,"theme":"教育與學習","examples":[{"en":"The essay had several grammatical errors.","zh":"這篇文章有幾處文法錯誤。"},{"en":"The editor found several grammatical errors in the report.","zh":"編輯在報告中發現了好幾個文法錯誤。"},{"en":"Make sure every sentence in your essay is grammatically correct.","zh":"確保你作文中的每個句子都符合文法。"}]},{"word":"grand","pos":"adj.","phonetic":"[grænd]","meaning":"宏偉的；盛大的","definition":"large, impressive, and splendid in appearance or style","collocations":["grand opening","grand piano","grand plan"],"example":"The hotel held a grand opening ceremony last night.","exampleZh":"這家飯店昨晚舉行了盛大的開幕儀式。","synonyms":["magnificent","impressive"],"level":3,"theme":"性質與描述","examples":[{"en":"The hotel held a grand opening ceremony last night.","zh":"這家飯店昨晚舉行了盛大的開幕儀式。"},{"en":"The new library held a grand opening on Saturday morning.","zh":"新圖書館在星期六早上舉行了盛大的開幕。"},{"en":"A grand piano stood in the center of the concert hall.","zh":"一架平台鋼琴立在音樂廳的正中央。"}]},{"word":"grandchild","pos":"n.","phonetic":"[ˈgrænˌtʃaɪld]","meaning":"孫子；孫女","definition":"a child of one's son or daughter","collocations":["visit grandchildren","spoil a grandchild","first grandchild"],"example":"Her grandchildren visit her every summer.","exampleZh":"她的孫子孫女每年夏天都會來看她。","synonyms":[],"level":2,"theme":"人物與家庭","examples":[{"en":"Her grandchildren visit her every summer.","zh":"她的孫子孫女每年夏天都會來看她。"},{"en":"The old man loves to spoil his youngest grandchild.","zh":"這位老人喜歡寵愛他最小的孫子。"},{"en":"Their grandchildren come to visit during the summer holidays.","zh":"他們的孫子孫女在暑假期間會來拜訪。"}]},{"word":"grandfather","pos":"n.","phonetic":"[ˈgrændˌfɑðɚ]","meaning":"祖父；外祖父","definition":"the father of one's father or mother","collocations":["grandfather clock","great-grandfather","live with grandfather"],"example":"My grandfather tells wonderful stories about his childhood.","exampleZh":"我爺爺會講他小時候的精彩故事。","synonyms":[],"level":1,"theme":"人物與家庭","examples":[{"en":"My grandfather tells wonderful stories about his childhood.","zh":"我爺爺會講他小時候的精彩故事。"},{"en":"An old grandfather clock ticks loudly in the hallway.","zh":"一座古老的立鐘在走廊裡響亮地滴答作響。"},{"en":"My grandfather taught me how to fish when I was young.","zh":"我小時候祖父教我怎麼釣魚。"}]},{"word":"grandmother","pos":"n.","phonetic":"[ˈgrændˌmʌðɚ]","meaning":"祖母；外祖母","definition":"the mother of one's father or mother","collocations":["visit grandmother","grandmother's cooking","great-grandmother"],"example":"My grandmother bakes cookies for us every weekend.","exampleZh":"我奶奶每個週末都會為我們烤餅乾。","synonyms":[],"level":1,"theme":"人物與家庭","examples":[{"en":"My grandmother bakes cookies for us every weekend.","zh":"我奶奶每個週末都會為我們烤餅乾。"},{"en":"My grandmother's cooking always reminds me of home.","zh":"祖母做的菜總是讓我想起家。"},{"en":"Every summer we visit our grandmother in the countryside.","zh":"每年夏天我們都會去鄉下探望祖母。"}]},{"word":"grandparent","pos":"n.","phonetic":"[ˈgrændˌpɛrənt]","meaning":"祖父母；外祖父母","definition":"the parent of one's father or mother","collocations":["live with grandparents","grandparents' house","visit grandparents"],"example":"I spend every Chinese New Year with my grandparents.","exampleZh":"我每年春節都會跟祖父母一起度過。","synonyms":[],"level":1,"theme":"人物與家庭","examples":[{"en":"I spend every Chinese New Year with my grandparents.","zh":"我每年春節都會跟祖父母一起度過。"},{"en":"We spend every Lunar New Year at our grandparents' house.","zh":"我們每年農曆新年都在祖父母家過。"},{"en":"Her grandparents often tell stories about the old days.","zh":"她的祖父母常常講述往日的故事。"}]},{"word":"grandson","pos":"n.","phonetic":"[ˈgrændˌsʌn]","meaning":"孫子","definition":"a son of one's son or daughter","collocations":["proud grandson","eldest grandson","raise a grandson"],"example":"He is very proud of his grandson's achievements.","exampleZh":"他對孫子的成就感到非常驕傲。","synonyms":[],"level":1,"theme":"人物與家庭","examples":[{"en":"He is very proud of his grandson's achievements.","zh":"他對孫子的成就感到非常驕傲。"},{"en":"He is very proud of his grandson's high test scores.","zh":"他為孫子優異的考試成績感到非常驕傲。"},{"en":"The eldest grandson helped his grandfather in the garden.","zh":"長孫在花園裡幫助他的祖父。"}]},{"word":"granite","pos":"n.","phonetic":"[ˈɡrænɪt]","meaning":"花崗岩","definition":"a hard gray or pink rock used in building","collocations":["granite countertop","polished granite","a granite statue"],"example":"The kitchen counter is made of granite.","exampleZh":"廚房的檯面是用花崗岩做的。","synonyms":[],"level":5,"theme":"自然與環境","examples":[{"en":"The kitchen counter is made of granite.","zh":"廚房的檯面是用花崗岩做的。"},{"en":"The kitchen has a smooth granite countertop that is easy to clean.","zh":"廚房有一個容易清潔的光滑花崗岩檯面。"},{"en":"A tall granite statue stood in the middle of the square.","zh":"一座高大的花崗岩雕像矗立在廣場中央。"}]},{"word":"grant","pos":"v. / n.","phonetic":"[grænt]","meaning":"同意給予；補助金","definition":"to agree to give or allow something requested; a sum of money given for a purpose","collocations":["grant permission","research grant","take for granted"],"example":"The university granted her a scholarship to study abroad.","exampleZh":"大學授予她一筆獎學金以出國留學。","synonyms":["allow","award"],"level":4,"theme":"商業與金錢","examples":[{"en":"The university granted her a scholarship to study abroad.","zh":"大學授予她一筆獎學金以出國留學。"},{"en":"The principal granted the students permission to leave early.","zh":"校長准許學生們提早離校。"},{"en":"She received a research grant to study rare mountain plants.","zh":"她獲得了一筆研究補助金來研究稀有的高山植物。"}]},{"word":"grape","pos":"n.","phonetic":"[grep]","meaning":"葡萄","definition":"a small round fruit, usually green or purple, that grows in bunches","collocations":["a bunch of grapes","grape juice","seedless grapes"],"example":"She bought a bunch of purple grapes at the market.","exampleZh":"她在市場買了一串紫葡萄。","synonyms":[],"level":1,"theme":"食物與烹飪","examples":[{"en":"She bought a bunch of purple grapes at the market.","zh":"她在市場買了一串紫葡萄。"},{"en":"She washed a bunch of green grapes for the picnic.","zh":"她為野餐洗了一串綠葡萄。"},{"en":"These sweet grapes are used to make delicious juice.","zh":"這些甜葡萄被用來製作美味的果汁。"}]},{"word":"grapefruit","pos":"n.","phonetic":"[ˈgrepˌfrut]","meaning":"葡萄柚","definition":"a large, round, bitter-sweet citrus fruit","collocations":["grapefruit juice","pink grapefruit","half a grapefruit"],"example":"He drinks grapefruit juice every morning.","exampleZh":"他每天早上都喝葡萄柚汁。","synonyms":[],"level":2,"theme":"食物與烹飪","examples":[{"en":"He drinks grapefruit juice every morning.","zh":"他每天早上都喝葡萄柚汁。"},{"en":"He eats half a grapefruit for breakfast every morning.","zh":"他每天早餐吃半顆葡萄柚。"},{"en":"A glass of fresh grapefruit juice tastes slightly bitter.","zh":"一杯新鮮的葡萄柚汁嚐起來有點苦。"}]},{"word":"graph","pos":"n.","phonetic":"[græf]","meaning":"圖表；曲線圖","definition":"a diagram showing the relationship between numbers or quantities","collocations":["bar graph","draw a graph","read a graph"],"example":"The report includes a graph showing sales over the past year.","exampleZh":"這份報告包含一張顯示去年銷售額的圖表。","synonyms":["chart"],"level":2,"theme":"科學與數學","examples":[{"en":"The report includes a graph showing sales over the past year.","zh":"這份報告包含一張顯示去年銷售額的圖表。"},{"en":"The bar graph clearly shows how sales rose each month.","zh":"這張長條圖清楚顯示每個月銷售額如何上升。"},{"en":"Students learned how to read a graph in math class.","zh":"學生在數學課上學會如何解讀圖表。"}]},{"word":"graphic","pos":"adj. / n.","phonetic":"[ˈɡræfɪk]","meaning":"圖表的；生動的；（複數）圖像","definition":"relating to visual images, or described in vivid detail","collocations":["graphic design","graphic novel","computer graphics"],"example":"The report included several graphic charts to explain the data.","exampleZh":"這份報告附有幾張圖表來說明數據。","synonyms":["visual","vivid"],"level":4,"theme":"科技與媒體","examples":[{"en":"The report included several graphic charts to explain the data.","zh":"這份報告附有幾張圖表來說明數據。"},{"en":"She studies graphic design at a well-known art school.","zh":"她在一所知名的藝術學校學習平面設計。"},{"en":"My brother enjoys reading graphic novels on rainy afternoons.","zh":"我哥哥喜歡在下雨的午後閱讀圖像小說。"}]},{"word":"grasp","pos":"v. / n.","phonetic":"[græsp]","meaning":"抓住；理解","definition":"to hold firmly, or to understand something completely","collocations":["grasp the concept","grasp an opportunity","firm grasp"],"example":"It took him a while to grasp the new concept.","exampleZh":"他花了一段時間才理解這個新概念。","synonyms":["understand","seize"],"level":4,"theme":"教育與學習","examples":[{"en":"It took him a while to grasp the new concept.","zh":"他花了一段時間才理解這個新概念。"},{"en":"It took her a while to grasp the difficult math concept.","zh":"她花了一段時間才理解那個困難的數學概念。"},{"en":"He quickly grasped the rope and pulled himself up.","zh":"他迅速抓住繩子，把自己拉了上來。"}]},{"word":"grass","pos":"n.","phonetic":"[græs]","meaning":"草；草地","definition":"a green plant with narrow leaves that covers fields and lawns","collocations":["cut the grass","green grass","walk on the grass"],"example":"The children played happily on the green grass.","exampleZh":"孩子們在綠色的草地上開心地玩耍。","synonyms":["lawn"],"level":1,"theme":"自然與環境","examples":[{"en":"The children played happily on the green grass.","zh":"孩子們在綠色的草地上開心地玩耍。"},{"en":"The children lay on the soft grass and watched the clouds.","zh":"孩子們躺在柔軟的草地上看雲。"},{"en":"My father cuts the grass in our yard every weekend.","zh":"我爸爸每個週末都會修剪我們院子裡的草。"}]},{"word":"grasshopper","pos":"n.","phonetic":"[ˈgræsˌhɑpɚ]","meaning":"蚱蜢；草蜢","definition":"a jumping insect with long back legs","collocations":["a green grasshopper","grasshopper jumps","catch a grasshopper"],"example":"A grasshopper jumped across the field.","exampleZh":"一隻蚱蜢跳過了那片田地。","synonyms":[],"level":2,"theme":"動物與植物","examples":[{"en":"A grasshopper jumped across the field.","zh":"一隻蚱蜢跳過了那片田地。"},{"en":"A green grasshopper jumped suddenly out of the tall grass.","zh":"一隻綠色的蚱蜢突然從高草叢裡跳了出來。"},{"en":"The curious boy tried to catch a grasshopper in the field.","zh":"好奇的男孩試著在田野裡抓一隻蚱蜢。"}]},{"word":"grassland","pos":"n.","phonetic":"[ˈɡræslænd]","meaning":"草原","definition":"a large area of open land covered with grass","collocations":["open grassland","African grassland","vast grasslands"],"example":"Herds of zebra roam across the African grassland.","exampleZh":"成群的斑馬在非洲草原上漫遊。","synonyms":["prairie","meadow"],"level":3,"theme":"自然與環境","examples":[{"en":"Herds of zebra roam across the African grassland.","zh":"成群的斑馬在非洲草原上漫遊。"},{"en":"Herds of zebra roam freely across the wide grassland.","zh":"成群的斑馬在遼闊的草原上自由漫遊。"},{"en":"The open grassland stretched as far as we could see.","zh":"開闊的草原一望無際地延伸到我們視線的盡頭。"}]},{"word":"grateful","pos":"adj.","phonetic":"[ˈgretfəl]","meaning":"感激的；感謝的","definition":"feeling or showing thanks","collocations":["grateful for","feel grateful","grateful heart"],"example":"I am truly grateful for your help and support.","exampleZh":"我真心感謝你的幫助與支持。","synonyms":["thankful","appreciative"],"level":3,"theme":"情緒與感受","examples":[{"en":"I am truly grateful for your help and support.","zh":"我真心感謝你的幫助與支持。"},{"en":"I am truly grateful for everything my teachers have done.","zh":"我對老師們所做的一切深深感激。"},{"en":"She felt grateful to the stranger who returned her wallet.","zh":"她很感激那位歸還她皮夾的陌生人。"}]},{"word":"gratitude","pos":"n.","phonetic":"[ˈɡrætəˌtud]","meaning":"感激；感謝","definition":"the feeling of being thankful","collocations":["show gratitude","express gratitude","a sense of gratitude"],"example":"She wrote a letter to express her gratitude to her teacher.","exampleZh":"她寫了一封信向老師表達她的感激之情。","synonyms":["thankfulness","appreciation"],"level":4,"theme":"情緒與感受","examples":[{"en":"She wrote a letter to express her gratitude to her teacher.","zh":"她寫了一封信向老師表達她的感激之情。"},{"en":"He wrote a card to express his gratitude for their help.","zh":"他寫了一張卡片來表達對他們幫助的感激。"},{"en":"She felt deep gratitude toward the doctors who saved her life.","zh":"她對救了她一命的醫生們懷有深深的感激。"}]},{"word":"grave","pos":"n. / adj.","phonetic":"[grev]","meaning":"墳墓；嚴重的","definition":"a place where a dead body is buried; very serious","collocations":["dig a grave","grave danger","grave mistake"],"example":"The situation is grave and requires immediate action.","exampleZh":"情況很嚴重，需要立即採取行動。","synonyms":["serious","tomb"],"level":4,"theme":"抽象概念","examples":[{"en":"The situation is grave and requires immediate action.","zh":"情況很嚴重，需要立即採取行動。"},{"en":"Cutting down the rainforest is a grave mistake for our planet.","zh":"砍伐雨林對我們的星球是個嚴重的錯誤。"},{"en":"They laid fresh flowers on their grandmother's grave.","zh":"他們在祖母的墳前放上新鮮的花。"}]},{"word":"gravel","pos":"n.","phonetic":"[ˈɡrævḷ]","meaning":"碎石；砂礫","definition":"small stones used to cover paths or roads","collocations":["a gravel road","gravel path","spread gravel"],"example":"The car bounced along the gravel road.","exampleZh":"這輛車在碎石路上顛簸前進。","synonyms":["pebbles"],"level":4,"theme":"自然與環境","examples":[{"en":"The car bounced along the gravel road.","zh":"這輛車在碎石路上顛簸前進。"},{"en":"The car bounced slowly along the narrow gravel road.","zh":"車子沿著狹窄的碎石路緩緩顛簸前進。"},{"en":"Workers spread gravel over the muddy garden path.","zh":"工人在泥濘的花園小徑上鋪滿碎石。"}]},{"word":"graveyard","pos":"n.","phonetic":"[ˈɡrevˌjɑrd]","meaning":"墓地；墳場","definition":"an area of land, often near a church, where dead people are buried","collocations":["an old graveyard","visit a graveyard","graveyard shift"],"example":"The old graveyard behind the church dates back two hundred years.","exampleZh":"教堂後面那座古老墓地已有兩百年歷史。","synonyms":["cemetery"],"level":4,"theme":"社會與文化","examples":[{"en":"The old graveyard behind the church dates back two hundred years.","zh":"教堂後面那座古老墓地已有兩百年歷史。"},{"en":"The old graveyard behind the church is very quiet at night.","zh":"教堂後面的舊墓地在夜裡非常安靜。"},{"en":"Some nurses have to work the graveyard shift at the hospital.","zh":"有些護士得在醫院上大夜班。"}]},{"word":"gravity","pos":"n.","phonetic":"[ˈgrævətɪ]","meaning":"重力；地心引力","definition":"the force that attracts objects toward the center of the earth","collocations":["force of gravity","zero gravity","law of gravity"],"example":"Gravity pulls objects toward the center of the Earth.","exampleZh":"重力將物體拉向地球中心。","synonyms":[],"level":4,"theme":"科學與數學","examples":[{"en":"Gravity pulls objects toward the center of the Earth.","zh":"重力將物體拉向地球中心。"},{"en":"Gravity is the force that keeps us on the ground.","zh":"重力是讓我們留在地面上的力量。"},{"en":"In space, astronauts float because there is almost zero gravity.","zh":"在太空中，太空人因為幾乎沒有重力而漂浮著。"}]},{"word":"gravy","pos":"n.","phonetic":"[ˈgrevi]","meaning":"肉汁","definition":"a sauce made from the juices of cooked meat","collocations":["turkey gravy","pour gravy","gravy boat"],"example":"She poured gravy over the mashed potatoes.","exampleZh":"她把肉汁淋在馬鈴薯泥上。","synonyms":["sauce"],"level":3,"theme":"食物與烹飪","examples":[{"en":"She poured gravy over the mashed potatoes.","zh":"她把肉汁淋在馬鈴薯泥上。"},{"en":"She poured warm gravy over the roast chicken and rice.","zh":"她把溫熱的肉汁淋在烤雞和米飯上。"},{"en":"The turkey tasted even better with homemade gravy.","zh":"火雞配上自製肉汁，味道更棒了。"}]},{"word":"gray","pos":"adj. / n.","phonetic":"[gre]","meaning":"灰色的；灰色","definition":"a color between black and white","collocations":["gray hair","gray sky","turn gray"],"example":"The sky turned gray before the storm.","exampleZh":"暴風雨來臨前天空變得灰暗。","synonyms":["grey"],"level":2,"theme":"性質與描述","examples":[{"en":"The sky turned gray before the storm.","zh":"暴風雨來臨前天空變得灰暗。"},{"en":"The sky turned gray just before the heavy rain began.","zh":"在大雨開始前，天空轉為灰色。"},{"en":"My grandfather's hair has slowly turned gray over the years.","zh":"這些年來我祖父的頭髮漸漸變灰白了。"}]},{"word":"graze","pos":"v.","phonetic":"[grez]","meaning":"吃草；擦傷","definition":"(of animals) to eat grass; to scrape the skin slightly","collocations":["cattle graze","graze on grass","graze a knee"],"example":"The cows were grazing peacefully in the field.","exampleZh":"牛群正在田野裡安靜地吃草。","synonyms":["scrape"],"level":5,"theme":"動物與植物","examples":[{"en":"The cows were grazing peacefully in the field.","zh":"牛群正在田野裡安靜地吃草。"},{"en":"The cows grazed quietly on the hillside all afternoon.","zh":"牛群整個下午靜靜地在山坡上吃草。"},{"en":"He fell off his bike and grazed his left knee.","zh":"他從腳踏車上摔下來，擦傷了左膝。"}]},{"word":"grease","pos":"n. / v.","phonetic":"[gris]","meaning":"油脂；潤滑油；上油","definition":"a thick oily substance, or to put such a substance on something","collocations":["cooking grease","grease the pan","engine grease"],"example":"Grease the pan before you pour in the batter.","exampleZh":"倒入麵糊前先在鍋子上抹油。","synonyms":["oil","fat"],"level":5,"theme":"食物與烹飪","examples":[{"en":"Grease the pan before you pour in the batter.","zh":"倒入麵糊前先在鍋子上抹油。"},{"en":"Please grease the pan well before you pour in the batter.","zh":"倒入麵糊前請先在鍋子上抹好油。"},{"en":"The mechanic's hands were covered with black engine grease.","zh":"技師的雙手沾滿了黑色的引擎油脂。"}]},{"word":"greasy","pos":"adj.","phonetic":"[ˈgrisi]","meaning":"油膩的","definition":"covered with or containing a lot of grease","collocations":["greasy food","greasy hair","greasy hands"],"example":"He wiped his greasy hands on a napkin.","exampleZh":"他用餐巾紙擦了擦油膩的雙手。","synonyms":["oily"],"level":4,"theme":"食物與烹飪","examples":[{"en":"He wiped his greasy hands on a napkin.","zh":"他用餐巾紙擦了擦油膩的雙手。"},{"en":"Eating too much greasy food is bad for your stomach.","zh":"吃太多油膩的食物對你的胃不好。"},{"en":"He wiped his greasy fingers on a paper napkin.","zh":"他把油膩的手指擦在紙巾上。"}]},{"word":"great","pos":"adj.","phonetic":"[gret]","meaning":"偉大的；很棒的；巨大的","definition":"very good, important, or large in amount","collocations":["a great idea","great deal","great success"],"example":"That was a great movie we watched last night.","exampleZh":"我們昨晚看的那部電影很棒。","synonyms":["excellent","huge"],"level":1,"theme":"性質與描述","examples":[{"en":"That was a great movie we watched last night.","zh":"我們昨晚看的那部電影很棒。"},{"en":"Watching that documentary was a great way to spend the evening.","zh":"看那部紀錄片是度過夜晚很棒的方式。"},{"en":"The scientist made a great contribution to modern medicine.","zh":"這位科學家對現代醫學做出了偉大的貢獻。"}]},{"word":"greed","pos":"n.","phonetic":"[grid]","meaning":"貪婪","definition":"an intense and selfish desire for wealth or power","collocations":["out of greed","human greed","greed for money"],"example":"His greed for money eventually ruined his career.","exampleZh":"他對金錢的貪婪最終毀了他的事業。","synonyms":["avarice"],"level":5,"theme":"抽象概念","examples":[{"en":"His greed for money eventually ruined his career.","zh":"他對金錢的貪婪最終毀了他的事業。"},{"en":"His greed for money led him to make dishonest choices.","zh":"他對金錢的貪婪使他做出不誠實的選擇。"},{"en":"Human greed is one major cause of environmental damage.","zh":"人類的貪婪是造成環境破壞的主要原因之一。"}]},{"word":"greedy","pos":"adj.","phonetic":"[ˈgridi]","meaning":"貪婪的；貪心的","definition":"having an intense desire for more than one needs","collocations":["greedy for power","don't be greedy","a greedy person"],"example":"Don't be so greedy; share the cookies with your sister.","exampleZh":"別那麼貪心，把餅乾分給你妹妹。","synonyms":["selfish"],"level":3,"theme":"情緒與感受","examples":[{"en":"Don't be so greedy; share the cookies with your sister.","zh":"別那麼貪心，把餅乾分給你妹妹。"},{"en":"Don't be greedy; leave some snacks for the others.","zh":"別貪心，留一些點心給其他人。"},{"en":"The greedy man wanted to keep all the profit for himself.","zh":"那個貪婪的人想把所有利潤都留給自己。"}]},{"word":"green","pos":"adj. / n.","phonetic":"[grin]","meaning":"綠色的；環保的","definition":"the color of grass and leaves; environmentally friendly","collocations":["green energy","dark green","go green"],"example":"The company is trying to go green by using less plastic.","exampleZh":"這家公司試圖透過減少塑膠使用來實現環保。","synonyms":[],"level":1,"theme":"性質與描述","examples":[{"en":"The company is trying to go green by using less plastic.","zh":"這家公司試圖透過減少塑膠使用來實現環保。"},{"en":"Our school encourages everyone to go green and save energy.","zh":"我們學校鼓勵大家響應環保、節約能源。"},{"en":"She painted her bedroom wall a soft shade of green.","zh":"她把臥室的牆漆成柔和的綠色。"}]},{"word":"greenhouse","pos":"n.","phonetic":"[ˈgrinˌhaʊs]","meaning":"溫室","definition":"a glass building for growing plants","collocations":["greenhouse effect","greenhouse gas","grow in a greenhouse"],"example":"The greenhouse effect is a major cause of global warming.","exampleZh":"溫室效應是全球暖化的主要原因之一。","synonyms":[],"level":3,"theme":"自然與環境","examples":[{"en":"The greenhouse effect is a major cause of global warming.","zh":"溫室效應是全球暖化的主要原因之一。"},{"en":"They grow fresh tomatoes in a greenhouse during the winter.","zh":"他們在冬天用溫室種植新鮮的番茄。"},{"en":"Cars produce greenhouse gases that slowly warm the planet.","zh":"汽車排放使地球逐漸暖化的溫室氣體。"}]},{"word":"greet","pos":"v.","phonetic":"[grit]","meaning":"問候；迎接","definition":"to say hello to someone or welcome them","collocations":["greet a guest","greet each other","greet warmly"],"example":"She greeted her guests with a warm smile.","exampleZh":"她用溫暖的笑容迎接客人。","synonyms":["welcome"],"level":2,"theme":"溝通與語言","examples":[{"en":"She greeted her guests with a warm smile.","zh":"她用溫暖的笑容迎接客人。"},{"en":"The teacher greeted each student warmly at the classroom door.","zh":"老師在教室門口熱情地問候每一位學生。"},{"en":"They greeted each other with a friendly handshake.","zh":"他們以友善的握手互相問候。"}]},{"word":"greeting","pos":"n.","phonetic":"[ˈgritɪŋ]","meaning":"問候；問候語","definition":"a word or gesture used to welcome someone","collocations":["greeting card","warm greeting","exchange greetings"],"example":"They exchanged friendly greetings at the door.","exampleZh":"他們在門口互相友善地問候。","synonyms":["welcome"],"level":2,"theme":"溝通與語言","examples":[{"en":"They exchanged friendly greetings at the door.","zh":"他們在門口互相友善地問候。"},{"en":"She sent a greeting card to her friend on his birthday.","zh":"她在朋友生日時寄了一張賀卡給他。"},{"en":"The host welcomed us with a warm greeting at the door.","zh":"主人在門口以溫暖的問候歡迎我們。"}]},{"word":"grief","pos":"n.","phonetic":"[grif]","meaning":"悲傷；悲痛","definition":"deep sorrow, especially caused by someone's death","collocations":["deep grief","grief over a loss","express grief"],"example":"She was overcome with grief after her grandmother's death.","exampleZh":"祖母過世後她悲痛不已。","synonyms":["sorrow","sadness"],"level":5,"theme":"情緒與感受","examples":[{"en":"She was overcome with grief after her grandmother's death.","zh":"祖母過世後她悲痛不已。"},{"en":"She was filled with deep grief after losing her old dog.","zh":"失去她的老狗後，她充滿了深深的悲傷。"},{"en":"Talking to close friends helped him deal with his grief.","zh":"和好友傾訴幫助他面對自己的悲傷。"}]},{"word":"grieve","pos":"v.","phonetic":"[griv]","meaning":"悲痛；哀悼","definition":"to feel or show deep sorrow, especially over a death","collocations":["grieve for someone","grieve over a loss","time to grieve"],"example":"The whole town grieved for the victims of the accident.","exampleZh":"整個小鎮都在為那場意外的受害者哀悼。","synonyms":["mourn"],"level":5,"theme":"情緒與感受","examples":[{"en":"The whole town grieved for the victims of the accident.","zh":"整個小鎮都在為那場意外的受害者哀悼。"},{"en":"She still grieves for her grandmother, who died last spring.","zh":"她仍在為去年春天過世的祖母哀悼。"},{"en":"The family needs time to grieve before returning to normal life.","zh":"這家人需要時間哀悼，才能回歸正常生活。"}]},{"word":"grill","pos":"n. / v.","phonetic":"[grɪl]","meaning":"烤架；烤肉；燒烤","definition":"a frame for cooking food over fire, or to cook food this way","collocations":["grill meat","charcoal grill","grill vegetables"],"example":"We grilled some chicken and vegetables for dinner.","exampleZh":"我們烤了一些雞肉和蔬菜當晚餐。","synonyms":["barbecue"],"level":3,"theme":"食物與烹飪","examples":[{"en":"We grilled some chicken and vegetables for dinner.","zh":"我們烤了一些雞肉和蔬菜當晚餐。"},{"en":"My father likes to grill fish over a charcoal fire on weekends.","zh":"我父親週末喜歡用炭火燒烤魚。"},{"en":"We bought a new grill to cook meat in the backyard.","zh":"我們買了一個新烤架，在後院烤肉。"}]},{"word":"grim","pos":"adj.","phonetic":"[grɪm]","meaning":"嚴峻的；陰沉的","definition":"very serious, worrying, or unpleasant","collocations":["grim news","grim expression","grim reality"],"example":"The doctor's grim expression worried the family.","exampleZh":"醫生嚴肅的表情讓這家人擔心。","synonyms":["serious","bleak"],"level":5,"theme":"情緒與感受","examples":[{"en":"The doctor's grim expression worried the family.","zh":"醫生嚴肅的表情讓這家人擔心。"},{"en":"The news about the flood damage was truly grim.","zh":"關於水災損失的消息確實令人沮喪。"},{"en":"Losing his job forced him to face the grim reality of debt.","zh":"失業迫使他面對負債的嚴峻現實。"}]},{"word":"grin","pos":"v. / n.","phonetic":"[grɪn]","meaning":"露齒而笑","definition":"to smile broadly showing the teeth","collocations":["grin widely","grin at someone","grin from ear to ear"],"example":"He grinned when he heard the good news.","exampleZh":"他聽到好消息時咧嘴一笑。","synonyms":["smile"],"level":4,"theme":"情緒與感受","examples":[{"en":"He grinned when he heard the good news.","zh":"他聽到好消息時咧嘴一笑。"},{"en":"The little boy grinned from ear to ear when he won the prize.","zh":"這個小男孩贏得獎品時笑得合不攏嘴。"},{"en":"She grinned at me proudly after passing the difficult exam.","zh":"她通過那場困難的考試後，得意地對我露齒而笑。"}]},{"word":"grind","pos":"v.","phonetic":"[graɪnd]","meaning":"磨碎；碾磨","definition":"to crush something into small pieces or powder","collocations":["grind coffee beans","grind to a halt","grind grain"],"example":"She ground the coffee beans before making coffee.","exampleZh":"她在煮咖啡之前先磨了咖啡豆。","synonyms":["crush"],"level":4,"theme":"食物與烹飪","examples":[{"en":"She ground the coffee beans before making coffee.","zh":"她在煮咖啡之前先磨了咖啡豆。"},{"en":"Traffic ground to a halt because of the accident on the bridge.","zh":"由於橋上發生車禍，交通完全停滯。"},{"en":"The old mill was used to grind grain into flour.","zh":"這座老磨坊過去用來把穀物磨成麵粉。"}]},{"word":"grip","pos":"n. / v.","phonetic":"[grɪp]","meaning":"緊握；掌控","definition":"a firm hold, or to hold something tightly","collocations":["grip the wheel","lose grip","tight grip"],"example":"He gripped the steering wheel tightly during the storm.","exampleZh":"暴風雨中他緊緊握住方向盤。","synonyms":["hold","clutch"],"level":4,"theme":"動作與行為","examples":[{"en":"He gripped the steering wheel tightly during the storm.","zh":"暴風雨中他緊緊握住方向盤。"},{"en":"The climber kept a tight grip on the rope as he descended.","zh":"攀岩者下降時緊緊抓住繩索。"},{"en":"She gripped my hand tightly when the plane took off.","zh":"飛機起飛時，她緊緊握住我的手。"}]},{"word":"grocery","pos":"n.","phonetic":"[ˈgrosəri]","meaning":"雜貨店；食品雜貨","definition":"a store that sells food and household items","collocations":["grocery store","grocery shopping","grocery bag"],"example":"I need to go to the grocery store to buy milk.","exampleZh":"我需要去雜貨店買牛奶。","synonyms":[],"level":2,"theme":"食物與烹飪","examples":[{"en":"I need to go to the grocery store to buy milk.","zh":"我需要去雜貨店買牛奶。"},{"en":"My mother does the grocery shopping every Saturday morning.","zh":"我母親每個星期六早上都去採買食品雜貨。"},{"en":"He carried the heavy grocery bags up three flights of stairs.","zh":"他把沉重的雜貨袋扛上三層樓。"}]},{"word":"groom","pos":"n. / v.","phonetic":"[grum]","meaning":"新郎；打理；照料","definition":"a man about to be married, or to clean and care for an animal","collocations":["bride and groom","groom a horse","well-groomed"],"example":"The groom looked nervous before the wedding ceremony.","exampleZh":"婚禮之前新郎看起來很緊張。","synonyms":[],"level":3,"theme":"人物與家庭","examples":[{"en":"The groom looked nervous before the wedding ceremony.","zh":"婚禮之前新郎看起來很緊張。"},{"en":"The bride and groom smiled happily during the wedding photos.","zh":"新娘和新郎在拍婚紗照時開心地微笑。"},{"en":"She spends an hour every day grooming her long-haired dog.","zh":"她每天花一個小時為她的長毛狗梳理毛髮。"}]},{"word":"gross","pos":"adj.","phonetic":"[gros]","meaning":"噁心的；總計的；粗俗的","definition":"very unpleasant; total before deductions","collocations":["gross income","gross domestic product","that's gross"],"example":"The gross income of the company increased this year.","exampleZh":"這家公司今年的總收入增加了。","synonyms":["total","disgusting"],"level":5,"theme":"商業與金錢","examples":[{"en":"The gross income of the company increased this year.","zh":"這家公司今年的總收入增加了。"},{"en":"The country's gross domestic product grew steadily last year.","zh":"該國的國內生產毛額去年穩定成長。"},{"en":"Eating with dirty hands is really gross.","zh":"用髒手吃東西真的很噁心。"}]},{"word":"ground","pos":"n. / v.","phonetic":"[graʊnd]","meaning":"地面；根據；使停飛","definition":"the surface of the earth; a reason; to prevent aircraft from flying","collocations":["on the ground","ground floor","stand your ground"],"example":"The leaves fell and covered the ground.","exampleZh":"樹葉掉落並覆蓋了地面。","synonyms":["earth","land"],"level":2,"theme":"自然與環境","examples":[{"en":"The leaves fell and covered the ground.","zh":"樹葉掉落並覆蓋了地面。"},{"en":"All flights were grounded because of the heavy snowstorm.","zh":"所有班機都因暴風雪而停飛。"},{"en":"The bookstore is on the ground floor of the shopping mall.","zh":"那家書店位於購物中心的一樓。"}]},{"word":"group","pos":"n. / v.","phonetic":"[grup]","meaning":"團體；小組；分組","definition":"a number of people or things gathered together","collocations":["work in groups","a group of friends","group project"],"example":"We were divided into small groups for the project.","exampleZh":"我們被分成小組進行這項專題。","synonyms":["team","set"],"level":1,"theme":"社會與文化","examples":[{"en":"We were divided into small groups for the project.","zh":"我們被分成小組進行這項專題。"},{"en":"Our teacher asked us to work in groups of four.","zh":"老師要我們四人一組進行分組。"},{"en":"A group of tourists gathered in front of the ancient temple.","zh":"一群觀光客聚集在古老的寺廟前。"}]},{"word":"grow","pos":"v.","phonetic":"[gro]","meaning":"成長；種植；增加","definition":"to increase in size or develop; to cultivate plants","collocations":["grow up","grow vegetables","grow rapidly"],"example":"Children grow so quickly in just a few years.","exampleZh":"孩子在短短幾年內就長得很快。","synonyms":["develop","increase"],"level":1,"theme":"動作與行為","examples":[{"en":"Children grow so quickly in just a few years.","zh":"孩子在短短幾年內就長得很快。"},{"en":"My grandparents grow fresh vegetables in their small garden.","zh":"我的祖父母在他們的小花園裡種植新鮮蔬菜。"},{"en":"The city's population has grown rapidly in the past decade.","zh":"這座城市的人口在過去十年迅速增加。"}]},{"word":"growl","pos":"v. / n.","phonetic":"[graʊl]","meaning":"低吼；咆哮","definition":"to make a low, rough, threatening sound, as a dog does","collocations":["dog growls","growl at someone","a low growl"],"example":"The dog growled at the stranger approaching the gate.","exampleZh":"那隻狗對著靠近大門的陌生人低吼。","synonyms":["snarl"],"level":5,"theme":"動物與植物","examples":[{"en":"The dog growled at the stranger approaching the gate.","zh":"那隻狗對著靠近大門的陌生人低吼。"},{"en":"We heard a low growl coming from the dark forest.","zh":"我們聽見從黑暗森林傳來一聲低吼。"},{"en":"The angry bear growled at the hikers who came too close.","zh":"那隻憤怒的熊對靠得太近的登山客咆哮。"}]},{"word":"grown-up","pos":"n. / adj.","phonetic":"[ˈgronˌʌp]","meaning":"成年人；成熟的","definition":"an adult, or having become an adult","collocations":["act like a grown-up","grown-up behavior","talk to a grown-up"],"example":"The kids wanted to be treated like grown-ups.","exampleZh":"孩子們希望被當作成年人對待。","synonyms":["adult"],"level":3,"theme":"人物與家庭","examples":[{"en":"The kids wanted to be treated like grown-ups.","zh":"孩子們希望被當作成年人對待。"},{"en":"If you get lost, find a grown-up and ask for help.","zh":"如果你迷路了，找個大人求助。"},{"en":"At seventeen, she already handles problems in a grown-up way.","zh":"十七歲的她已經以成熟的方式處理問題。"}]},{"word":"growth","pos":"n.","phonetic":"[groθ]","meaning":"成長；增長；發育","definition":"the process of increasing in size or amount","collocations":["economic growth","population growth","rapid growth"],"example":"The country has experienced rapid economic growth this decade.","exampleZh":"這個國家在這十年間經歷了快速的經濟成長。","synonyms":["development","increase"],"level":3,"theme":"商業與金錢","examples":[{"en":"The country has experienced rapid economic growth this decade.","zh":"這個國家在這十年間經歷了快速的經濟成長。"},{"en":"Regular exercise supports healthy growth in young children.","zh":"規律運動有助於幼童的健康發育。"},{"en":"Experts are worried about the slow economic growth this year.","zh":"專家們擔心今年緩慢的經濟成長。"}]},{"word":"grudge","pos":"n.","phonetic":"[grʌdʒ]","meaning":"怨恨；心結","definition":"a persistent feeling of resentment about something in the past","collocations":["hold a grudge","bear a grudge","let go of a grudge"],"example":"He still holds a grudge against his old business partner.","exampleZh":"他至今仍對他的舊生意夥伴心懷怨恨。","synonyms":["resentment"],"level":6,"theme":"情緒與感受","examples":[{"en":"He still holds a grudge against his old business partner.","zh":"他至今仍對他的舊生意夥伴心懷怨恨。"},{"en":"It is healthier to let go of a grudge than to stay angry.","zh":"放下怨恨比一直生氣更健康。"},{"en":"She bore a grudge against her classmate for years.","zh":"她對那位同學懷恨多年。"}]},{"word":"grumble","pos":"v.","phonetic":"[ˈgrʌmbəl]","meaning":"抱怨；發牢騷","definition":"to complain in a bad-tempered way","collocations":["grumble about something","grumble under one's breath","stop grumbling"],"example":"The students grumbled about the amount of homework.","exampleZh":"學生們抱怨作業量太多。","synonyms":["complain"],"level":5,"theme":"溝通與語言","examples":[{"en":"The students grumbled about the amount of homework.","zh":"學生們抱怨作業量太多。"},{"en":"The workers grumbled about having to stay late again.","zh":"工人們抱怨又得加班到很晚。"},{"en":"He grumbled under his breath while cleaning his room.","zh":"他一邊打掃房間，一邊低聲發牢騷。"}]},{"word":"guarantee","pos":"v. / n.","phonetic":"[ˌgærənˈti]","meaning":"保證；擔保","definition":"a promise that something will happen or be done","collocations":["guarantee success","money-back guarantee","under guarantee"],"example":"The company offers a one-year guarantee on all products.","exampleZh":"這家公司對所有產品提供一年保固。","synonyms":["promise","assurance"],"level":4,"theme":"商業與金錢","examples":[{"en":"The company offers a one-year guarantee on all products.","zh":"這家公司對所有產品提供一年保固。"},{"en":"Hard work does not always guarantee success, but it helps.","zh":"努力不一定保證成功，但確實有幫助。"},{"en":"The store offers a money-back guarantee if you are not satisfied.","zh":"如果你不滿意，這家店提供退款保證。"}]},{"word":"guard","pos":"n. / v.","phonetic":"[gɑrd]","meaning":"守衛；警衛；防衛","definition":"a person who protects a place or people; to protect","collocations":["security guard","guard against","stand guard"],"example":"A security guard stands at the entrance of the building.","exampleZh":"一名保全人員站在大樓入口處。","synonyms":["protect","watch"],"level":2,"theme":"工作與職業","examples":[{"en":"A security guard stands at the entrance of the building.","zh":"一名保全人員站在大樓入口處。"},{"en":"Wearing a mask can help guard against the spread of germs.","zh":"戴口罩有助於防範病菌的傳播。"},{"en":"Two soldiers stood guard outside the palace gate.","zh":"兩名士兵在宮殿大門外站崗守衛。"}]},{"word":"guardian","pos":"n.","phonetic":"[ˈgɑrdiən]","meaning":"監護人；守護者","definition":"a person who is legally responsible for someone unable to care for themselves","collocations":["legal guardian","act as guardian","parent or guardian"],"example":"Her uncle became her legal guardian after her parents passed away.","exampleZh":"她父母過世後，叔叔成了她的法定監護人。","synonyms":["protector"],"level":4,"theme":"社會與文化","examples":[{"en":"Her uncle became her legal guardian after her parents passed away.","zh":"她父母過世後，叔叔成了她的法定監護人。"},{"en":"Every student must have a parent or guardian sign this form.","zh":"每位學生都必須有父母或監護人簽署這份表格。"},{"en":"After the accident, her aunt acted as her guardian.","zh":"意外發生後，她的阿姨擔任她的監護人。"}]},{"word":"guess","pos":"v. / n.","phonetic":"[gɛs]","meaning":"猜測；猜想","definition":"to give an answer without being sure it is correct","collocations":["take a guess","guess the answer","best guess"],"example":"Can you guess how old I am?","exampleZh":"你能猜出我幾歲嗎？","synonyms":["estimate","suppose"],"level":1,"theme":"抽象概念","examples":[{"en":"Can you guess how old I am?","zh":"你能猜出我幾歲嗎？"},{"en":"Take a guess at how many candies are in the jar.","zh":"猜猜看罐子裡有多少顆糖果。"},{"en":"I couldn't remember the date, so I made my best guess.","zh":"我記不得日期，所以只能盡量猜測。"}]},{"word":"habit","pos":"n.","phonetic":"[ˈhæbɪt]","meaning":"習慣；癖好","definition":"a thing that you do often and regularly","collocations":["form a habit","bad habit","habit of doing something","break a habit"],"example":"Reading before bed is a good habit.","exampleZh":"睡前閱讀是個好習慣。","synonyms":["custom","routine"],"level":2,"theme":"動作與行為","examples":[{"en":"Reading before bed is a good habit.","zh":"睡前閱讀是個好習慣。"},{"en":"Biting your nails is a bad habit that is hard to break.","zh":"咬指甲是個很難改掉的壞習慣。"},{"en":"She has formed the habit of jogging every morning.","zh":"她已養成每天早上慢跑的習慣。"}]},{"word":"habitat","pos":"n.","phonetic":"[ˈhæbəˌtæt]","meaning":"棲息地；產地","definition":"the natural home of an animal or plant","collocations":["natural habitat","wildlife habitat","destroy a habitat"],"example":"The forest is the natural habitat of many rare species.","exampleZh":"這片森林是許多稀有物種的天然棲息地。","synonyms":["environment"],"level":4,"theme":"自然與環境","examples":[{"en":"The forest is the natural habitat of many rare species.","zh":"這片森林是許多稀有物種的天然棲息地。"},{"en":"Cutting down trees destroys the natural habitat of many birds.","zh":"砍伐樹木會破壞許多鳥類的自然棲息地。"},{"en":"The wetland is an important habitat for migrating birds.","zh":"這片濕地是候鳥重要的棲息地。"}]},{"word":"habitual","pos":"adj.","phonetic":"[hə'bɪtʃʊəl]","meaning":"習慣性的；慣常的","definition":"done regularly as a habit","collocations":["habitual liar","habitual behavior","habitual smoker"],"example":"He is a habitual latecomer to meetings.","exampleZh":"他習慣性地開會遲到。","synonyms":["usual","customary"],"level":4,"theme":"抽象概念","examples":[{"en":"He is a habitual latecomer to meetings.","zh":"他習慣性地開會遲到。"},{"en":"As a habitual smoker, he finds it hard to quit.","zh":"身為一個習慣性抽菸者，他發覺很難戒掉。"},{"en":"Her habitual kindness makes everyone feel welcome.","zh":"她慣常的善良讓每個人都感到受歡迎。"}]},{"word":"haggle","pos":"v.","phonetic":"['hæg!]","meaning":"討價還價","definition":"to argue about the price of something","collocations":["haggle over the price","haggle with a vendor"],"example":"Tourists often haggle over prices at the market.","exampleZh":"遊客常在市場上討價還價。","synonyms":["bargain"],"level":5,"theme":"商業與金錢","examples":[{"en":"Tourists often haggle over prices at the market.","zh":"遊客常在市場上討價還價。"},{"en":"My grandmother loves to haggle with vendors at the night market.","zh":"我奶奶喜歡在夜市和攤販討價還價。"},{"en":"They haggled over the price of the antique for an hour.","zh":"他們為那件古董的價格討價還價了一個小時。"}]},{"word":"hail","pos":"v. / n.","phonetic":"[hel]","meaning":"冰雹；招呼；歡呼","definition":"to greet or call out to someone; pellets of ice falling from the sky","collocations":["hail a taxi","hail from a city","heavy hail"],"example":"She stepped outside and hailed a passing cab.","exampleZh":"她走到外面招手叫了一輛計程車。","synonyms":["greet"],"level":3,"theme":"天氣與季節","examples":[{"en":"She stepped outside and hailed a passing cab.","zh":"她走到外面招手叫了一輛計程車。"},{"en":"Heavy hail damaged the crops in the fields overnight.","zh":"猛烈的冰雹一夜之間毀壞了田裡的作物。"},{"en":"He raised his hand to hail a taxi in the rain.","zh":"他在雨中舉起手招了一輛計程車。"}]},{"word":"hair","pos":"n.","phonetic":"[hɛr]","meaning":"頭髮；毛髮","definition":"the mass of thin strands that grows on the head or skin","collocations":["curly hair","cut one's hair","hair loss"],"example":"She has long, curly hair.","exampleZh":"她有一頭長而捲曲的頭髮。","synonyms":[],"level":1,"theme":"身體與健康","examples":[{"en":"She has long, curly hair.","zh":"她有一頭長而捲曲的頭髮。"},{"en":"She decided to cut her hair short before the summer.","zh":"她決定在夏天前把頭髮剪短。"},{"en":"Stress can sometimes cause serious hair loss.","zh":"壓力有時會造成嚴重的掉髮。"}]},{"word":"half","pos":"n. / adj.","phonetic":"[hæf]","meaning":"一半；半數的","definition":"one of two equal parts of something","collocations":["half an hour","cut in half","half price"],"example":"He ate half of the sandwich.","exampleZh":"他吃了三明治的一半。","synonyms":[],"level":1,"theme":"科學與數學","examples":[{"en":"He ate half of the sandwich.","zh":"他吃了三明治的一半。"},{"en":"The train will arrive in half an hour.","zh":"火車將在半小時後抵達。"},{"en":"All the winter coats were sold at half price.","zh":"所有的冬季外套都以半價出售。"}]},{"word":"hallway","pos":"n.","phonetic":"[ˈhɔlˌwe]","meaning":"走廊；門廳","definition":"a passage in a building that connects rooms","collocations":["walk down the hallway","narrow hallway","school hallway"],"example":"Students were talking loudly in the hallway.","exampleZh":"學生們在走廊上大聲談話。","synonyms":["corridor"],"level":2,"theme":"居家與生活","examples":[{"en":"Students were talking loudly in the hallway.","zh":"學生們在走廊上大聲談話。"},{"en":"Please do not run in the school hallway.","zh":"請不要在學校走廊上奔跑。"},{"en":"A row of lockers lined the narrow hallway.","zh":"一排置物櫃排列在狹窄的走廊上。"}]},{"word":"halt","pos":"v. / n.","phonetic":"[hɔlt]","meaning":"停止；中止","definition":"to stop moving or doing something","collocations":["come to a halt","halt production","grind to a halt"],"example":"The train came to a sudden halt.","exampleZh":"火車突然停了下來。","synonyms":["stop"],"level":3,"theme":"動作與行為","examples":[{"en":"The train came to a sudden halt.","zh":"火車突然停了下來。"},{"en":"The factory had to halt production because of a power failure.","zh":"工廠因停電而不得不停止生產。"},{"en":"The bus came to a sudden halt at the red light.","zh":"公車在紅燈前突然停了下來。"}]},{"word":"halve","pos":"v.","phonetic":"[hæv]","meaning":"把…分成兩半；使減半","definition":"to divide something into two equal parts or reduce by half","collocations":["halve the recipe","halve the cost","halve the time"],"example":"We need to halve the ingredients for a smaller cake.","exampleZh":"做小蛋糕我們需要把食材份量減半。","synonyms":["reduce"],"level":3,"theme":"動作與行為","examples":[{"en":"We need to halve the ingredients for a smaller cake.","zh":"做小蛋糕我們需要把食材份量減半。"},{"en":"Buying tickets online can halve the time you spend waiting.","zh":"線上購票可以使你排隊等待的時間減半。"},{"en":"Please halve the apple and share it with your sister.","zh":"請把蘋果切成兩半，和你妹妹分著吃。"}]},{"word":"hammer","pos":"n. / v.","phonetic":"[ˈhæmɚ]","meaning":"鐵鎚；錘打","definition":"a tool used for hitting nails, or to hit with such a tool","collocations":["hammer a nail","hit with a hammer","hammer away"],"example":"He used a hammer to fix the loose board.","exampleZh":"他用鐵鎚修好了鬆脫的木板。","synonyms":["mallet"],"level":3,"theme":"居家與生活","examples":[{"en":"He used a hammer to fix the loose board.","zh":"他用鐵鎚修好了鬆脫的木板。"},{"en":"He carefully hammered a nail into the wooden shelf.","zh":"他小心地把一根釘子錘進木架裡。"},{"en":"The carpenter kept hammering away until the frame was solid.","zh":"木匠不停地敲打，直到框架穩固為止。"}]},{"word":"hamper","pos":"v. / n.","phonetic":"['hæmpɚ]","meaning":"妨礙；食物籃","definition":"to prevent progress; a large basket with a lid","collocations":["hamper progress","hamper efforts","a picnic hamper"],"example":"Heavy rain hampered the rescue operation.","exampleZh":"豪雨阻礙了救援行動。","synonyms":["hinder","obstruct"],"level":5,"theme":"動作與行為","examples":[{"en":"Heavy rain hampered the rescue operation.","zh":"豪雨阻礙了救援行動。"},{"en":"Thick fog hampered the search for the missing climbers.","zh":"濃霧妨礙了對失蹤登山客的搜救。"},{"en":"We packed sandwiches and fruit into the picnic hamper.","zh":"我們把三明治和水果裝進野餐籃裡。"}]},{"word":"handful","pos":"n.","phonetic":"['hændfʊl]","meaning":"一把；少數","definition":"a small quantity or number of something","collocations":["a handful of people","a handful of sand","only a handful"],"example":"Only a handful of students showed up early.","exampleZh":"只有少數幾個學生提早到場。","synonyms":["few"],"level":3,"theme":"抽象概念","examples":[{"en":"Only a handful of students showed up early.","zh":"只有少數幾個學生提早到場。"},{"en":"Only a handful of guests remained after midnight.","zh":"午夜過後只剩下少數幾位客人。"},{"en":"The child grabbed a handful of sand at the beach.","zh":"那孩子在海灘上抓了一把沙。"}]},{"word":"handicap","pos":"n. / v.","phonetic":"['hændɪˌkæp]","meaning":"障礙；殘障；不利條件","definition":"a condition that limits ability or a disadvantage","collocations":["physical handicap","a handicap in life","handicap someone's chances"],"example":"A lack of education can be a serious handicap.","exampleZh":"缺乏教育可能是一項嚴重的不利條件。","synonyms":["disadvantage"],"level":4,"theme":"身體與健康","examples":[{"en":"A lack of education can be a serious handicap.","zh":"缺乏教育可能是一項嚴重的不利條件。"},{"en":"Poor communication skills can be a handicap in the workplace.","zh":"溝通能力不佳在職場上可能是一種不利條件。"},{"en":"He refused to let his physical handicap stop his dreams.","zh":"他拒絕讓身體上的殘障阻擋他的夢想。"}]},{"word":"handle","pos":"v. / n.","phonetic":"[ˈhændl]","meaning":"處理；把手","definition":"to deal with a problem or situation, or the part of an object held by hand","collocations":["handle a problem","door handle","handle with care"],"example":"She knows how to handle difficult customers.","exampleZh":"她知道如何應付難纏的顧客。","synonyms":["manage","deal with"],"level":3,"theme":"動作與行為","examples":[{"en":"She knows how to handle difficult customers.","zh":"她知道如何應付難纏的顧客。"},{"en":"The box is marked 'handle with care' because it holds glass.","zh":"這個箱子標示著「小心輕放」，因為裡面裝著玻璃。"},{"en":"The door handle was so cold that it hurt my hand.","zh":"那個門把冷到弄痛了我的手。"}]},{"word":"handout","pos":"n.","phonetic":"['hændˌaʊt]","meaning":"講義；施捨物","definition":"a printed sheet given out; something given free to those in need","collocations":["distribute handouts","a class handout","live on handouts"],"example":"The teacher gave each student a handout before class.","exampleZh":"老師上課前發給每位學生一份講義。","synonyms":["leaflet"],"level":4,"theme":"教育與學習","examples":[{"en":"The teacher gave each student a handout before class.","zh":"老師上課前發給每位學生一份講義。"},{"en":"Please read the handout before we discuss the topic.","zh":"在我們討論主題之前，請先閱讀這份講義。"},{"en":"The volunteers distributed handouts to the homeless people.","zh":"志工們把救濟物品發給無家可歸的人。"}]},{"word":"handsome","pos":"adj.","phonetic":"[ˈhænsəm]","meaning":"英俊的；可觀的","definition":"good-looking, especially of a man","collocations":["handsome man","handsome reward","tall and handsome"],"example":"The actor is famous for being tall and handsome.","exampleZh":"這位演員以高大英俊聞名。","synonyms":["good-looking"],"level":2,"theme":"服裝與外表","examples":[{"en":"The actor is famous for being tall and handsome.","zh":"這位演員以高大英俊聞名。"},{"en":"The company offered a handsome reward for returning the lost dog.","zh":"公司為歸還走失的狗提供了可觀的獎金。"},{"en":"Everyone agreed that the new teacher was quite handsome.","zh":"每個人都認為那位新老師相當英俊。"}]},{"word":"handy","pos":"adj.","phonetic":"[ˈhændi]","meaning":"方便的；手巧的","definition":"useful or convenient, or skillful with one's hands","collocations":["come in handy","handy tool","handy with tools"],"example":"A smartphone is handy for checking directions.","exampleZh":"智慧型手機在查路線時很方便。","synonyms":["convenient","useful"],"level":3,"theme":"性質與描述","examples":[{"en":"A smartphone is handy for checking directions.","zh":"智慧型手機在查路線時很方便。"},{"en":"Keep a flashlight nearby; it may come in handy during a blackout.","zh":"手邊放一支手電筒，停電時可能會派上用場。"},{"en":"My uncle is very handy with tools and fixed the leaky pipe.","zh":"我叔叔很會使用工具，修好了漏水的水管。"}]},{"word":"hang","pos":"v.","phonetic":"[hæŋ]","meaning":"懸掛；吊掛","definition":"to attach or suspend something so it does not touch the ground","collocations":["hang a picture","hang out","hang up the phone"],"example":"She hung the painting on the wall.","exampleZh":"她把那幅畫掛在牆上。","synonyms":["suspend"],"level":2,"theme":"動作與行為","examples":[{"en":"She hung the painting on the wall.","zh":"她把那幅畫掛在牆上。"},{"en":"Let's hang out at the park after school today.","zh":"今天放學後我們去公園逛逛吧。"},{"en":"She hung the wet towels on the line to dry.","zh":"她把濕毛巾掛在曬衣繩上晾乾。"}]},{"word":"hangover","pos":"n.","phonetic":"['hæŋˌovɚ]","meaning":"宿醉","definition":"the unpleasant effects felt after drinking too much alcohol","collocations":["have a hangover","cure a hangover","a bad hangover"],"example":"He had a terrible hangover after the party.","exampleZh":"派對後他宿醉得很嚴重。","synonyms":[],"level":4,"theme":"身體與健康","examples":[{"en":"He had a terrible hangover after the party.","zh":"派對後他宿醉得很嚴重。"},{"en":"He drank too much and woke up with a bad hangover.","zh":"他喝太多了，醒來時嚴重宿醉。"},{"en":"Some people believe that water can help cure a hangover.","zh":"有些人相信喝水有助於解宿醉。"}]},{"word":"haphazard","pos":"adj.","phonetic":"[hæp'hæzɚd]","meaning":"隨意的；雜亂無章的","definition":"lacking any order or organization","collocations":["haphazard planning","a haphazard arrangement","haphazard approach"],"example":"The files were stored in a haphazard manner.","exampleZh":"這些檔案被雜亂無章地存放著。","synonyms":["random","disorganized"],"level":5,"theme":"性質與描述","examples":[{"en":"The files were stored in a haphazard manner.","zh":"這些檔案被雜亂無章地存放著。"},{"en":"His haphazard approach to studying led to poor grades.","zh":"他雜亂無章的讀書方式導致成績不佳。"},{"en":"The books were piled in a haphazard way on the desk.","zh":"那些書雜亂無章地堆在書桌上。"}]},{"word":"happen","pos":"v.","phonetic":"[ˈhæpən]","meaning":"發生；碰巧","definition":"to take place, especially without being planned","collocations":["happen to someone","what happened","happen by chance"],"example":"Nobody knows what happened to the missing keys.","exampleZh":"沒有人知道那把不見的鑰匙發生了什麼事。","synonyms":["occur","take place"],"level":1,"theme":"動作與行為","examples":[{"en":"Nobody knows what happened to the missing keys.","zh":"沒有人知道那把不見的鑰匙發生了什麼事。"},{"en":"We happened to meet an old friend at the train station.","zh":"我們碰巧在火車站遇見一位老朋友。"},{"en":"Tell me exactly what happened during the meeting.","zh":"告訴我會議中究竟發生了什麼事。"}]},{"word":"harass","pos":"v.","phonetic":"[hə'ræs]","meaning":"騷擾；使煩惱","definition":"to trouble or annoy someone persistently","collocations":["harass employees","harass someone constantly","harass by phone"],"example":"The company was accused of harassing its workers.","exampleZh":"這家公司被指控騷擾員工。","synonyms":["bother","pester"],"level":5,"theme":"社會與文化","examples":[{"en":"The company was accused of harassing its workers.","zh":"這家公司被指控騷擾員工。"},{"en":"Strangers should never harass others by phone late at night.","zh":"陌生人絕不該在深夜以電話騷擾他人。"},{"en":"The manager was warned not to harass his employees.","zh":"那位經理被警告不得騷擾他的員工。"}]},{"word":"harbor","pos":"n. / v.","phonetic":"[ˈhɑrbɚ]","meaning":"港口；懷有（情感）","definition":"a place where ships can shelter, or to keep a feeling in mind","collocations":["fishing harbor","harbor a grudge","safe harbor"],"example":"The fishing boats returned to the harbor before the storm.","exampleZh":"漁船在暴風雨來臨前返回了港口。","synonyms":["port"],"level":4,"theme":"交通與旅行","examples":[{"en":"The fishing boats returned to the harbor before the storm.","zh":"漁船在暴風雨來臨前返回了港口。"},{"en":"Dozens of colorful boats were docked in the small harbor.","zh":"數十艘色彩鮮豔的船隻停靠在小港口裡。"},{"en":"She still harbors hopes of becoming a professional singer.","zh":"她仍懷抱著成為職業歌手的希望。"}]},{"word":"hardship","pos":"n.","phonetic":"[ˈhɑrdʃɪp]","meaning":"艱難；困苦","definition":"severe suffering or difficulty","collocations":["face hardship","economic hardship","endure hardship"],"example":"The family endured great hardship during the war.","exampleZh":"這家人在戰爭期間承受了極大的苦難。","synonyms":["difficulty","suffering"],"level":5,"theme":"抽象概念","examples":[{"en":"The family endured great hardship during the war.","zh":"這家人在戰爭期間承受了極大的苦難。"},{"en":"Many families faced great hardship after the earthquake.","zh":"地震過後，許多家庭面臨極大的困苦。"},{"en":"He endured years of hardship to finish his education.","zh":"他忍受多年的艱辛才完成學業。"}]},{"word":"hardware","pos":"n.","phonetic":"[ˈhɑrdˌwɛr]","meaning":"硬體；五金器具","definition":"the physical parts of a computer, or metal tools and equipment","collocations":["computer hardware","hardware store","hardware upgrade"],"example":"The new hardware made the computer run much faster.","exampleZh":"新硬體讓這台電腦運作得快多了。","synonyms":[],"level":3,"theme":"科技與媒體","examples":[{"en":"The new hardware made the computer run much faster.","zh":"新硬體讓這台電腦運作得快多了。"},{"en":"We went to the hardware store to buy nails and paint.","zh":"我們去五金行買釘子和油漆。"},{"en":"The game runs slowly because the computer hardware is outdated.","zh":"這款遊戲跑得很慢，因為電腦硬體過時了。"}]},{"word":"hardy","pos":"adj.","phonetic":"['hɑrdi]","meaning":"耐寒的；強健的","definition":"able to endure difficult conditions","collocations":["hardy plants","a hardy crew","hardy survivors"],"example":"These hardy plants can survive the harsh winter.","exampleZh":"這些耐寒的植物能撐過嚴冬。","synonyms":["tough","sturdy"],"level":4,"theme":"性質與描述","examples":[{"en":"These hardy plants can survive the harsh winter.","zh":"這些耐寒的植物能撐過嚴冬。"},{"en":"Cactuses are hardy plants that can survive with very little water.","zh":"仙人掌是能夠在極少水分下存活的強健植物。"},{"en":"The hardy climbers reached the summit despite the freezing wind.","zh":"那些強健的登山者不顧刺骨寒風，抵達了山頂。"}]},{"word":"harm","pos":"n. / v.","phonetic":"[hɑrm]","meaning":"傷害；損害","definition":"physical or other damage, or to cause such damage","collocations":["cause harm","do no harm","harm the environment"],"example":"Too much sun can harm your skin.","exampleZh":"過度曬太陽會傷害你的皮膚。","synonyms":["damage","hurt"],"level":3,"theme":"抽象概念","examples":[{"en":"Too much sun can harm your skin.","zh":"過度曬太陽會傷害你的皮膚。"},{"en":"Throwing trash into rivers can seriously harm the environment.","zh":"把垃圾丟進河裡會嚴重危害環境。"},{"en":"The medicine is safe and will do no harm to children.","zh":"這種藥很安全，不會對兒童造成傷害。"}]},{"word":"harmless","pos":"adj.","phonetic":"['hɑrmlɪs]","meaning":"無害的","definition":"not able or likely to cause damage or injury","collocations":["a harmless joke","a harmless insect","seemingly harmless"],"example":"The snake looks scary but is actually harmless.","exampleZh":"這條蛇看起來嚇人，其實是無害的。","synonyms":["safe"],"level":3,"theme":"性質與描述","examples":[{"en":"The snake looks scary but is actually harmless.","zh":"這條蛇看起來嚇人，其實是無害的。"},{"en":"It was just a harmless joke, so please don't be angry.","zh":"那只是個無傷大雅的玩笑，請別生氣。"},{"en":"Most spiders in the garden are completely harmless.","zh":"花園裡大多數的蜘蛛都是完全無害的。"}]},{"word":"harmony","pos":"n.","phonetic":"[ˈhɑrmənɪ]","meaning":"和諧；和睦","definition":"a state of peaceful agreement or pleasant combination","collocations":["live in harmony","in perfect harmony","musical harmony"],"example":"The two families have lived in harmony for years.","exampleZh":"這兩家人已經和睦相處多年。","synonyms":["peace","accord"],"level":4,"theme":"社會與文化","examples":[{"en":"The two families have lived in harmony for years.","zh":"這兩家人已經和睦相處多年。"},{"en":"The choir sang the final song in perfect harmony.","zh":"合唱團以完美的和聲唱完了最後一首歌。"},{"en":"People of many cultures live in harmony in this city.","zh":"許多不同文化的人在這座城市裡和睦共處。"}]},{"word":"harness","pos":"n. / v.","phonetic":"['hɑrnɪs]","meaning":"馬具；安全帶；利用","definition":"a set of straps for an animal or person; to control and use energy","collocations":["harness solar energy","wear a safety harness","harness the power of"],"example":"Engineers are trying to harness wind energy more efficiently.","exampleZh":"工程師正努力更有效地利用風能。","synonyms":["utilize"],"level":4,"theme":"科學與數學","examples":[{"en":"Engineers are trying to harness wind energy more efficiently.","zh":"工程師正努力更有效地利用風能。"},{"en":"Scientists are learning to harness solar energy more efficiently.","zh":"科學家正學習更有效地利用太陽能。"},{"en":"Every worker on the roof must wear a safety harness.","zh":"屋頂上的每位工人都必須繫上安全帶。"}]},{"word":"harsh","pos":"adj.","phonetic":"[hɑrʃ]","meaning":"嚴厲的；刺耳的；嚴酷的","definition":"unpleasantly rough, severe, or critical","collocations":["harsh criticism","harsh climate","harsh words"],"example":"The teacher's harsh criticism upset the student.","exampleZh":"老師嚴厲的批評讓學生很難過。","synonyms":["severe","stern"],"level":3,"theme":"性質與描述","examples":[{"en":"The teacher's harsh criticism upset the student.","zh":"老師嚴厲的批評讓學生很難過。"},{"en":"Few plants can survive the harsh climate of the desert.","zh":"很少有植物能在沙漠嚴酷的氣候中存活。"},{"en":"He regretted the harsh words he said to his brother.","zh":"他後悔對弟弟說了那些嚴厲的話。"}]},{"word":"harvest","pos":"n. / v.","phonetic":"[ˈhɑrvɪst]","meaning":"收穫；收割","definition":"the gathering of crops, or to gather crops","collocations":["harvest crops","rice harvest","autumn harvest"],"example":"Farmers harvest rice in the autumn.","exampleZh":"農夫在秋天收割稻米。","synonyms":["reap","gather"],"level":3,"theme":"自然與環境","examples":[{"en":"Farmers harvest rice in the autumn.","zh":"農夫在秋天收割稻米。"},{"en":"The whole village celebrates after the autumn harvest.","zh":"秋收之後，整個村莊都在慶祝。"},{"en":"Farmers work long hours to harvest the crops before winter.","zh":"農民長時間工作，趕在冬天前收割作物。"}]},{"word":"hasty","pos":"adj.","phonetic":"['hesti]","meaning":"匆忙的；草率的","definition":"done too quickly, without enough thought","collocations":["a hasty decision","a hasty retreat","hasty conclusion"],"example":"Don't make a hasty decision you might regret later.","exampleZh":"別做出可能日後會後悔的草率決定。","synonyms":["rushed","hurried"],"level":4,"theme":"性質與描述","examples":[{"en":"Don't make a hasty decision you might regret later.","zh":"別做出可能日後會後悔的草率決定。"},{"en":"Don't jump to a hasty conclusion before you hear both sides.","zh":"在聽完雙方說法前，別急著下草率的結論。"},{"en":"Their hasty retreat left many supplies behind.","zh":"他們匆忙的撤退遺留下許多物資。"}]},{"word":"hatch","pos":"v. / n.","phonetic":"[hætʃ]","meaning":"孵化；策劃；艙口","definition":"to break out of an egg; to plan something secretly; an opening in a floor or wall","collocations":["hatch eggs","hatch a plan","open the hatch"],"example":"The eggs will hatch in about three weeks.","exampleZh":"這些蛋大約三週後就會孵化。","synonyms":["devise"],"level":3,"theme":"動物與植物","examples":[{"en":"The eggs will hatch in about three weeks.","zh":"這些蛋大約三週後就會孵化。"},{"en":"The two friends hatched a plan to surprise their teacher.","zh":"這兩個朋友策劃了一個要給老師驚喜的計畫。"},{"en":"The baby chicks began to hatch early in the morning.","zh":"小雞在清晨開始孵化。"}]},{"word":"hatred","pos":"n.","phonetic":"[ˈhetrɪd]","meaning":"仇恨；憎恨","definition":"an intense feeling of dislike","collocations":["feel hatred","racial hatred","hatred toward someone"],"example":"The war left deep hatred between the two nations.","exampleZh":"那場戰爭在兩國之間留下了深深的仇恨。","synonyms":["hostility"],"level":5,"theme":"情緒與感受","examples":[{"en":"The war left deep hatred between the two nations.","zh":"那場戰爭在兩國之間留下了深深的仇恨。"},{"en":"The film teaches us that hatred only leads to more suffering.","zh":"這部電影告訴我們，仇恨只會帶來更多痛苦。"},{"en":"She felt no hatred toward the man who had wronged her.","zh":"她對那個曾傷害她的人並不憎恨。"}]},{"word":"haughty","pos":"adj.","phonetic":"['hɔti]","meaning":"傲慢的；高傲的","definition":"arrogantly superior and disdainful","collocations":["a haughty attitude","a haughty manner","haughty look"],"example":"Her haughty attitude made her unpopular at school.","exampleZh":"她高傲的態度讓她在學校不受歡迎。","synonyms":["arrogant","proud"],"level":6,"theme":"情緒與感受","examples":[{"en":"Her haughty attitude made her unpopular at school.","zh":"她高傲的態度讓她在學校不受歡迎。"},{"en":"The waiter's haughty manner annoyed all the customers.","zh":"那位服務生傲慢的態度惹惱了所有顧客。"},{"en":"She gave him a haughty look and walked away.","zh":"她高傲地瞥了他一眼便走開了。"}]},{"word":"haul","pos":"v. / n.","phonetic":"[hɔl]","meaning":"拖拉；搬運","definition":"to pull or carry something heavy with effort","collocations":["haul cargo","haul away","long haul"],"example":"The truck hauled the timber to the port.","exampleZh":"卡車把木材運到港口。","synonyms":["drag","pull"],"level":5,"theme":"動作與行為","examples":[{"en":"The truck hauled the timber to the port.","zh":"卡車把木材運到港口。"},{"en":"Workers hauled the heavy boxes onto the delivery truck.","zh":"工人們把沉重的箱子搬上送貨卡車。"},{"en":"It was a long haul, but we finally moved all the furniture.","zh":"這是一段辛苦的搬運，但我們終於把所有家具都搬完了。"}]},{"word":"haunt","pos":"v.","phonetic":"[hɔnt]","meaning":"（鬼魂）出沒；縈繞","definition":"to visit a place regularly as a ghost, or to trouble someone's mind constantly","collocations":["haunted house","memory haunts someone","haunt a place"],"example":"People say the old mansion is haunted.","exampleZh":"人們說那棟老宅鬧鬼。","synonyms":["torment"],"level":5,"theme":"抽象概念","examples":[{"en":"People say the old mansion is haunted.","zh":"人們說那棟老宅鬧鬼。"},{"en":"The memory of the accident haunted him for many years.","zh":"那場意外的記憶縈繞在他心頭多年。"},{"en":"Children love to visit the haunted house at the fair.","zh":"孩子們喜歡去園遊會的鬼屋。"}]},{"word":"haven","pos":"n.","phonetic":"['hevən]","meaning":"避風港；避難所","definition":"a place of safety or refuge","collocations":["a safe haven","a tax haven","find a haven"],"example":"The small island became a haven for wildlife.","exampleZh":"這座小島成了野生動物的庇護所。","synonyms":["refuge","shelter"],"level":4,"theme":"居家與生活","examples":[{"en":"The small island became a haven for wildlife.","zh":"這座小島成了野生動物的庇護所。"},{"en":"The library is a quiet haven for students during exams.","zh":"考試期間，圖書館是學生們安靜的避風港。"},{"en":"The national park is a safe haven for endangered animals.","zh":"這座國家公園是瀕危動物的安全避難所。"}]},{"word":"hawk","pos":"n.","phonetic":"[hɔk]","meaning":"鷹","definition":"a large bird of prey with sharp eyesight","collocations":["hawk circling","hawk's eye","hunting hawk"],"example":"A hawk circled high above the field.","exampleZh":"一隻老鷹在田野上空盤旋。","synonyms":[],"level":4,"theme":"動物與植物","examples":[{"en":"A hawk circled high above the field.","zh":"一隻老鷹在田野上空盤旋。"},{"en":"With its sharp eyes, the hawk spotted a mouse below.","zh":"老鷹以銳利的雙眼發現了下方的一隻老鼠。"},{"en":"A hawk swooped down suddenly to catch its prey.","zh":"一隻老鷹突然俯衝而下抓住獵物。"}]},{"word":"hazard","pos":"n.","phonetic":"[ˈhæzɚd]","meaning":"危險；危害","definition":"a danger or risk","collocations":["safety hazard","health hazard","fire hazard"],"example":"Wet floors are a safety hazard.","exampleZh":"濕滑的地板是一種安全危害。","synonyms":["danger","risk"],"level":5,"theme":"抽象概念","examples":[{"en":"Wet floors are a safety hazard.","zh":"濕滑的地板是一種安全危害。"},{"en":"Leaving toys on the stairs is a serious safety hazard.","zh":"把玩具留在樓梯上是嚴重的安全危害。"},{"en":"Smoking in a forest can be a dangerous fire hazard.","zh":"在森林裡抽菸可能造成危險的火災隱患。"}]},{"word":"hazardous","pos":"adj.","phonetic":"['hæzɚdəs]","meaning":"危險的；有害的","definition":"risky or dangerous, especially to health or safety","collocations":["hazardous waste","hazardous conditions","hazardous materials"],"example":"Workers must wear gloves when handling hazardous chemicals.","exampleZh":"工人在處理危險化學品時必須戴手套。","synonyms":["dangerous","risky"],"level":4,"theme":"自然與環境","examples":[{"en":"Workers must wear gloves when handling hazardous chemicals.","zh":"工人在處理危險化學品時必須戴手套。"},{"en":"The factory must dispose of its hazardous waste properly.","zh":"工廠必須妥善處理其有害廢棄物。"},{"en":"Driving in such hazardous conditions is not worth the risk.","zh":"在如此危險的路況下開車不值得冒這個險。"}]},{"word":"haze","pos":"n.","phonetic":"[hez]","meaning":"薄霧；霾","definition":"a slight obscuring of the air by dust, smoke, or moisture","collocations":["morning haze","haze over the city","thick haze"],"example":"A haze hung over the city all morning.","exampleZh":"整個早上城市上空都籠罩著薄霧。","synonyms":["fog","mist"],"level":5,"theme":"天氣與季節","examples":[{"en":"A haze hung over the city all morning.","zh":"整個早上城市上空都籠罩著薄霧。"},{"en":"A thin morning haze covered the rice fields at dawn.","zh":"黎明時分，一層薄薄的晨霧籠罩著稻田。"},{"en":"The thick haze made it hard to see the distant mountains.","zh":"濃厚的霾使人難以看清遠處的山巒。"}]},{"word":"headache","pos":"n.","phonetic":"[ˈhɛdˌek]","meaning":"頭痛；令人頭痛的事","definition":"a pain in the head, or a difficult problem","collocations":["get a headache","severe headache","cause a headache"],"example":"I have a terrible headache today.","exampleZh":"我今天頭痛得很厲害。","synonyms":[],"level":2,"theme":"身體與健康","examples":[{"en":"I have a terrible headache today.","zh":"我今天頭痛得很厲害。"},{"en":"Staring at the screen too long gave me a headache.","zh":"盯著螢幕太久讓我頭痛。"},{"en":"Finding parking downtown is always a huge headache.","zh":"在市中心找停車位總是件令人頭痛的事。"}]},{"word":"headline","pos":"n.","phonetic":"[ˈhɛdˌlaɪn]","meaning":"標題；頭條新聞","definition":"the title at the top of a newspaper article","collocations":["news headline","make headlines","front-page headline"],"example":"The scandal made headlines around the world.","exampleZh":"這起醜聞成為全球頭條新聞。","synonyms":[],"level":3,"theme":"科技與媒體","examples":[{"en":"The scandal made headlines around the world.","zh":"這起醜聞成為全球頭條新聞。"},{"en":"The athlete's record-breaking win made headlines everywhere.","zh":"這位運動員破紀錄的勝利成了各地的頭條新聞。"},{"en":"I usually read the headlines before the full articles.","zh":"我通常在讀完整文章前先看標題。"}]},{"word":"headphone","pos":"n.","phonetic":"[ˈhɛdˌfon]","meaning":"耳機","definition":"a device worn over the ears to listen to audio privately","collocations":["wear headphones","noise-canceling headphones","plug in headphones"],"example":"She listens to music with her headphones on the bus.","exampleZh":"她在公車上戴著耳機聽音樂。","synonyms":["earphones"],"level":2,"theme":"科技與媒體","examples":[{"en":"She listens to music with her headphones on the bus.","zh":"她在公車上戴著耳機聽音樂。"},{"en":"He put on his noise-canceling headphones to study in peace.","zh":"他戴上降噪耳機以便安靜地讀書。"},{"en":"Please plug in your headphones so you don't disturb others.","zh":"請插上你的耳機，以免打擾別人。"}]},{"word":"headquarters","pos":"n.","phonetic":"['hɛd'kwɔrtɚz]","meaning":"總部；總公司","definition":"the main office of an organization","collocations":["company headquarters","military headquarters","move headquarters"],"example":"The company's headquarters is located in Taipei.","exampleZh":"這家公司的總部位於台北。","synonyms":["main office"],"level":3,"theme":"工作與職業","examples":[{"en":"The company's headquarters is located in Taipei.","zh":"這家公司的總部位於台北。"},{"en":"The company plans to move its headquarters to a bigger city.","zh":"公司計畫將總部遷到一座更大的城市。"},{"en":"Reporters gathered outside the company's headquarters for news.","zh":"記者們聚集在公司總部外等候消息。"}]},{"word":"heal","pos":"v.","phonetic":"[hil]","meaning":"治癒；痊癒","definition":"to become or make healthy again","collocations":["heal a wound","heal quickly","heal over time"],"example":"The cut on his hand healed within a week.","exampleZh":"他手上的傷口一週內就痊癒了。","synonyms":["cure","recover"],"level":3,"theme":"身體與健康","examples":[{"en":"The cut on his hand healed within a week.","zh":"他手上的傷口一週內就痊癒了。"},{"en":"The doctor said the broken bone would heal in six weeks.","zh":"醫生說骨折會在六週內痊癒。"},{"en":"Time and rest helped her heal after the surgery.","zh":"時間和休息幫助她在手術後康復。"}]},{"word":"healthy","pos":"adj.","phonetic":"[ˈhɛlθɪ]","meaning":"健康的；有益健康的","definition":"in good physical or mental condition, or good for health","collocations":["healthy diet","stay healthy","healthy lifestyle"],"example":"Eating vegetables is part of a healthy diet.","exampleZh":"吃蔬菜是健康飲食的一部分。","synonyms":["fit","well"],"level":1,"theme":"身體與健康","examples":[{"en":"Eating vegetables is part of a healthy diet.","zh":"吃蔬菜是健康飲食的一部分。"},{"en":"Getting enough sleep is an important part of a healthy lifestyle.","zh":"充足的睡眠是健康生活方式的重要部分。"},{"en":"She keeps healthy by cycling to school every day.","zh":"她每天騎腳踏車上學來保持健康。"}]},{"word":"heap","pos":"n. / v.","phonetic":"[hip]","meaning":"堆；一堆","definition":"an untidy pile of things, or to pile things up","collocations":["a heap of clothes","heap up","in heaps"],"example":"He left his clothes in a heap on the floor.","exampleZh":"他把衣服堆在地板上。","synonyms":["pile","stack"],"level":4,"theme":"居家與生活","examples":[{"en":"He left his clothes in a heap on the floor.","zh":"他把衣服堆在地板上。"},{"en":"There was a heap of dry leaves in the corner of the yard.","zh":"院子的角落裡有一堆乾枯的葉子。"},{"en":"The workers heaped the sandbags along the riverbank.","zh":"工人們把沙包堆在河岸邊。"}]},{"word":"heartbeat","pos":"n.","phonetic":"[ˈhɑrtˌbit]","meaning":"心跳","definition":"a single movement of the heart as it pumps blood","collocations":["fast heartbeat","normal heartbeat","irregular heartbeat"],"example":"The doctor listened to the patient's heartbeat.","exampleZh":"醫生聆聽病人的心跳。","synonyms":["pulse"],"level":3,"theme":"身體與健康","examples":[{"en":"The doctor listened to the patient's heartbeat.","zh":"醫生聆聽病人的心跳。"},{"en":"After running upstairs, I could feel my fast heartbeat.","zh":"跑上樓後，我能感覺到自己快速的心跳。"},{"en":"The nurse checked whether the baby's heartbeat was normal.","zh":"護士檢查嬰兒的心跳是否正常。"}]},{"word":"heartfelt","pos":"adj.","phonetic":"['hɑrt'fɛlt]","meaning":"衷心的；發自內心的","definition":"sincere and deeply felt","collocations":["heartfelt thanks","a heartfelt apology","heartfelt gratitude"],"example":"She sent a heartfelt letter to thank her mentor.","exampleZh":"她寄了一封衷心感謝恩師的信。","synonyms":["sincere","genuine"],"level":4,"theme":"情緒與感受","examples":[{"en":"She sent a heartfelt letter to thank her mentor.","zh":"她寄了一封衷心感謝恩師的信。"},{"en":"She offered a heartfelt apology for arriving so late.","zh":"她為遲到這麼久致上發自內心的道歉。"},{"en":"The winner gave heartfelt thanks to her parents and coach.","zh":"得獎者衷心感謝她的父母和教練。"}]},{"word":"hearth","pos":"n.","phonetic":"[hɑrθ]","meaning":"爐床；壁爐邊；家","definition":"the floor of a fireplace, or the home in general","collocations":["sit by the hearth","hearth and home","a warm hearth"],"example":"The family gathered around the hearth on cold nights.","exampleZh":"寒冷的夜晚，一家人聚在爐邊。","synonyms":["fireside"],"level":5,"theme":"居家與生活","examples":[{"en":"The family gathered around the hearth on cold nights.","zh":"寒冷的夜晚，一家人聚在爐邊。"},{"en":"On winter evenings, we read stories by the warm hearth.","zh":"冬天的夜晚，我們在溫暖的壁爐邊讀故事。"},{"en":"The cat curled up peacefully in front of the hearth.","zh":"貓咪在壁爐前安詳地蜷縮成一團。"}]},{"word":"heave","pos":"v.","phonetic":"[hiv]","meaning":"用力舉起；用力拉；喘息","definition":"to lift or pull something heavy with great effort","collocations":["heave a sigh","heave the box","heave and pull"],"example":"He heaved the heavy suitcase onto the shelf.","exampleZh":"他用力把沉重的行李箱抬到架子上。","synonyms":["lift","haul"],"level":5,"theme":"動作與行為","examples":[{"en":"He heaved the heavy suitcase onto the shelf.","zh":"他用力把沉重的行李箱抬到架子上。"},{"en":"She heaved a sigh of relief when the exam was over.","zh":"考試結束時，她鬆了一口氣。"},{"en":"The movers heaved the sofa up the narrow staircase.","zh":"搬運工人費力地把沙發抬上狹窄的樓梯。"}]},{"word":"heaven","pos":"n.","phonetic":"[ˈhɛvən]","meaning":"天堂；天國","definition":"the place believed to be where God or gods live, and good people go after death","collocations":["go to heaven","heaven and earth","heaven on earth"],"example":"In many religions, people believe good souls go to heaven.","exampleZh":"在許多宗教中，人們相信善良的靈魂會上天堂。","synonyms":["paradise"],"level":3,"theme":"社會與文化","examples":[{"en":"In many religions, people believe good souls go to heaven.","zh":"在許多宗教中，人們相信善良的靈魂會上天堂。"},{"en":"The peaceful valley felt like heaven on earth to the tired hikers.","zh":"對疲憊的登山客來說，這寧靜的山谷宛如人間天堂。"},{"en":"Many people believe kind souls go to heaven after death.","zh":"許多人相信善良的靈魂死後會上天堂。"}]},{"word":"hectare","pos":"n.","phonetic":"['hɛktɛr]","meaning":"公頃","definition":"a unit of area equal to 10,000 square meters","collocations":["ten hectares of land","per hectare","a hectare of forest"],"example":"The farm covers about fifty hectares.","exampleZh":"這座農場占地約五十公頃。","synonyms":[],"level":4,"theme":"科學與數學","examples":[{"en":"The farm covers about fifty hectares.","zh":"這座農場占地約五十公頃。"},{"en":"The new nature reserve protects a hundred hectares of forest.","zh":"這座新的自然保護區保護了一百公頃的森林。"},{"en":"The farmer plants rice on five hectares of land.","zh":"這位農夫在五公頃的土地上種稻。"}]},{"word":"hectic","pos":"adj.","phonetic":"['hɛktɪk]","meaning":"忙碌的；繁忙的","definition":"full of activity and difficult to manage","collocations":["a hectic schedule","a hectic day","hectic pace"],"example":"She had a hectic week preparing for the exam.","exampleZh":"她為了準備考試度過忙碌的一週。","synonyms":["busy","frantic"],"level":4,"theme":"工作與職業","examples":[{"en":"She had a hectic week preparing for the exam.","zh":"她為了準備考試度過忙碌的一週。"},{"en":"After a hectic day at school, she just wanted to rest.","zh":"在學校忙碌的一天之後，她只想休息。"},{"en":"Life in the big city moves at a hectic pace.","zh":"大城市的生活步調非常忙碌緊湊。"}]},{"word":"hedge","pos":"n.","phonetic":"[hɛdʒ]","meaning":"樹籬；灌木籬","definition":"a row of bushes forming a boundary","collocations":["trim a hedge","garden hedge","hedge maze"],"example":"The gardener trimmed the hedge into a neat shape.","exampleZh":"園丁把樹籬修剪成整齊的形狀。","synonyms":[],"level":5,"theme":"自然與環境","examples":[{"en":"The gardener trimmed the hedge into a neat shape.","zh":"園丁把樹籬修剪成整齊的形狀。"},{"en":"A tall green hedge surrounds their quiet garden.","zh":"一道高高的綠色樹籬環繞著他們寧靜的花園。"},{"en":"The children got lost in the giant hedge maze at the park.","zh":"孩子們在公園巨大的樹籬迷宮裡迷了路。"}]},{"word":"hedgehog","pos":"n.","phonetic":"['hɛdʒˌhɔg]","meaning":"刺蝟","definition":"a small spiny mammal that curls into a ball when threatened","collocations":["a spiny hedgehog","curl up like a hedgehog"],"example":"A hedgehog curled into a ball when it sensed danger.","exampleZh":"刺蝟一感到危險就蜷縮成一團。","synonyms":[],"level":2,"theme":"動物與植物","examples":[{"en":"A hedgehog curled into a ball when it sensed danger.","zh":"刺蝟一感到危險就蜷縮成一團。"},{"en":"A tiny hedgehog wandered across the garden at night.","zh":"一隻小刺蝟在夜裡漫步穿過花園。"},{"en":"When frightened, the hedgehog curls up into a spiny ball.","zh":"受到驚嚇時，刺蝟會蜷縮成帶刺的一團。"}]},{"word":"heel","pos":"n.","phonetic":"[hil]","meaning":"腳跟；鞋跟","definition":"the back part of the foot, or the raised part of a shoe under it","collocations":["high heels","sore heel","heel of the shoe"],"example":"She wore high heels to the party.","exampleZh":"她穿著高跟鞋去參加派對。","synonyms":[],"level":3,"theme":"身體與健康","examples":[{"en":"She wore high heels to the party.","zh":"她穿著高跟鞋去參加派對。"},{"en":"After the long walk, she had a painful blister on her heel.","zh":"走了很長的路後，她的腳跟起了一個很痛的水泡。"},{"en":"The heel of my shoe broke while I was running for the bus.","zh":"我趕公車時，鞋跟斷了。"}]},{"word":"height","pos":"n.","phonetic":"[haɪt]","meaning":"高度；身高","definition":"the measurement of how tall someone or something is","collocations":["average height","height and weight","gain height"],"example":"He is about 180 centimeters in height.","exampleZh":"他的身高大約一百八十公分。","synonyms":["tallness"],"level":2,"theme":"科學與數學","examples":[{"en":"He is about 180 centimeters in height.","zh":"他的身高大約一百八十公分。"},{"en":"The nurse recorded each child's height and weight.","zh":"護士記錄了每個孩子的身高和體重。"},{"en":"The plane slowly gained height after leaving the runway.","zh":"飛機離開跑道後緩緩爬升。"}]},{"word":"heir","pos":"n.","phonetic":"[ɛr]","meaning":"繼承人","definition":"a person legally entitled to property or a title","collocations":["heir to the throne","sole heir","the rightful heir"],"example":"The prince is the heir to the throne.","exampleZh":"王子是王位的繼承人。","synonyms":["successor"],"level":4,"theme":"人物與家庭","examples":[{"en":"The prince is the heir to the throne.","zh":"王子是王位的繼承人。"},{"en":"As the only child, she became the sole heir to the farm.","zh":"身為獨生女，她成了這座農場的唯一繼承人。"},{"en":"The young prince is the rightful heir to the throne.","zh":"這位年輕的王子是王位的合法繼承人。"}]},{"word":"helicopter","pos":"n.","phonetic":"[ˈhɛlɪˌkɑptɚ]","meaning":"直升機","definition":"an aircraft with horizontal spinning blades that can take off vertically","collocations":["fly a helicopter","rescue helicopter","helicopter pilot"],"example":"A rescue helicopter arrived to help the injured hikers.","exampleZh":"一架救援直升機趕來幫助受傷的登山客。","synonyms":["chopper"],"level":3,"theme":"交通與旅行","examples":[{"en":"A rescue helicopter arrived to help the injured hikers.","zh":"一架救援直升機趕來幫助受傷的登山客。"},{"en":"A rescue helicopter lifted the stranded sailors to safety.","zh":"一架救援直升機把受困的水手救到安全的地方。"},{"en":"It takes years of training to become a helicopter pilot.","zh":"成為直升機駕駛員需要多年的訓練。"}]},{"word":"helm","pos":"n.","phonetic":"[hɛlm]","meaning":"舵；領導地位","definition":"the wheel or handle used to steer a ship; a position of leadership","collocations":["at the helm","take the helm","seize the helm"],"example":"She took the helm of the company last year.","exampleZh":"她去年接掌了這家公司的領導地位。","synonyms":["leadership"],"level":5,"theme":"交通與旅行","examples":[{"en":"She took the helm of the company last year.","zh":"她去年接掌了這家公司的領導地位。"},{"en":"With a new leader at the helm, the club became more active.","zh":"有了新領導人掌舵，這個社團變得更加活躍。"},{"en":"The captain stood at the helm and steered through the fog.","zh":"船長站在舵前，駕船穿過濃霧。"}]},{"word":"helmet","pos":"n.","phonetic":"[ˈhɛlmɪt]","meaning":"安全帽；頭盔","definition":"a hard hat worn to protect the head","collocations":["wear a helmet","bicycle helmet","safety helmet"],"example":"Always wear a helmet when riding a motorcycle.","exampleZh":"騎機車時一定要戴安全帽。","synonyms":[],"level":2,"theme":"運動與休閒","examples":[{"en":"Always wear a helmet when riding a motorcycle.","zh":"騎機車時一定要戴安全帽。"},{"en":"You must wear a bicycle helmet to protect your head.","zh":"你必須戴上自行車安全帽以保護頭部。"},{"en":"Construction workers put on safety helmets before entering the site.","zh":"建築工人進入工地前戴上安全帽。"}]},{"word":"hemisphere","pos":"n.","phonetic":"[ˈhɛməsˌfɪr]","meaning":"半球；大腦半球","definition":"half of the earth, or half of a sphere","collocations":["northern hemisphere","southern hemisphere","brain hemisphere"],"example":"Australia is located in the southern hemisphere.","exampleZh":"澳洲位於南半球。","synonyms":[],"level":6,"theme":"科學與數學","examples":[{"en":"Australia is located in the southern hemisphere.","zh":"澳洲位於南半球。"},{"en":"In the northern hemisphere, summer usually begins in June.","zh":"在北半球，夏天通常從六月開始。"},{"en":"The left hemisphere of the brain controls the right side of the body.","zh":"大腦的左半球控制身體的右側。"}]},{"word":"hemp","pos":"n.","phonetic":"[hɛmp]","meaning":"大麻；麻纖維","definition":"a plant grown for its tough fiber, used to make rope and fabric","collocations":["hemp rope","hemp fabric","grow hemp"],"example":"The rope was made of strong hemp fiber.","exampleZh":"這條繩子是用堅韌的麻纖維製成的。","synonyms":[],"level":4,"theme":"自然與環境","examples":[{"en":"The rope was made of strong hemp fiber.","zh":"這條繩子是用堅韌的麻纖維製成的。"},{"en":"The bag was woven from strong, natural hemp fibers.","zh":"這個袋子是用堅韌的天然麻纖維編織而成。"},{"en":"Farmers in this region have grown hemp for centuries.","zh":"這個地區的農民種植大麻已有數百年之久。"}]},{"word":"herb","pos":"n.","phonetic":"[ɝb]","meaning":"香草；藥草","definition":"a plant used for flavoring food or for medicine","collocations":["fresh herbs","a herb garden","dried herbs"],"example":"She grows fresh herbs in her kitchen garden.","exampleZh":"她在廚房花園裡種植新鮮香草。","synonyms":[],"level":3,"theme":"食物與烹飪","examples":[{"en":"She grows fresh herbs in her kitchen garden.","zh":"她在廚房花園裡種植新鮮香草。"},{"en":"She sprinkled fresh herbs over the soup before serving.","zh":"上菜前，她在湯上撒了一些新鮮香草。"},{"en":"My grandmother uses dried herbs to make healthy tea.","zh":"我奶奶用乾燥的藥草泡養生茶。"}]},{"word":"herd","pos":"n. / v.","phonetic":"[hɝd]","meaning":"獸群；放牧","definition":"a large group of animals living together, or to move them together","collocations":["herd of cattle","herd sheep","in a herd"],"example":"A herd of elephants crossed the river together.","exampleZh":"一群大象一起渡過了河流。","synonyms":["flock"],"level":4,"theme":"動物與植物","examples":[{"en":"A herd of elephants crossed the river together.","zh":"一群大象一起渡過了河流。"},{"en":"The farmer used a dog to herd the sheep into the pen.","zh":"農夫用一隻狗把羊群趕進圍欄裡。"},{"en":"A large herd of cattle grazed peacefully on the hillside.","zh":"一大群牛在山坡上安詳地吃草。"}]},{"word":"heritage","pos":"n.","phonetic":"[ˈhɛrətɪdʒ]","meaning":"遺產；傳統文化","definition":"features belonging to the culture of a particular society passed down over generations","collocations":["cultural heritage","world heritage site","family heritage"],"example":"The temple is part of the city's cultural heritage.","exampleZh":"這座寺廟是這座城市文化遺產的一部分。","synonyms":["legacy","tradition"],"level":5,"theme":"社會與文化","examples":[{"en":"The temple is part of the city's cultural heritage.","zh":"這座寺廟是這座城市文化遺產的一部分。"},{"en":"The old fortress was named a world heritage site last year.","zh":"這座古老的堡壘去年被列為世界遺產。"},{"en":"Traditional festivals are an important part of our cultural heritage.","zh":"傳統節慶是我們文化遺產的重要部分。"}]},{"word":"hermit","pos":"n.","phonetic":"['hɝmɪt]","meaning":"隱士；隱居者","definition":"a person who lives alone, away from society","collocations":["live like a hermit","a hermit crab","become a hermit"],"example":"He became a hermit and lived alone in the mountains.","exampleZh":"他成了隱士，獨自住在山中。","synonyms":["recluse"],"level":5,"theme":"社會與文化","examples":[{"en":"He became a hermit and lived alone in the mountains.","zh":"他成了隱士，獨自住在山中。"},{"en":"The old man lived like a hermit in a hut by the sea.","zh":"那位老人像隱士般住在海邊的小屋裡。"},{"en":"A small hermit crab crawled slowly along the wet sand.","zh":"一隻小寄居蟹在濕沙上緩緩爬行。"}]},{"word":"heroic","pos":"adj.","phonetic":"[hɪˈroɪk]","meaning":"英勇的；英雄般的","definition":"showing great courage","collocations":["heroic effort","heroic act","heroic rescue"],"example":"The firefighter made a heroic effort to save the child.","exampleZh":"消防員英勇地努力救出那名孩童。","synonyms":["brave","courageous"],"level":5,"theme":"性質與描述","examples":[{"en":"The firefighter made a heroic effort to save the child.","zh":"消防員英勇地努力救出那名孩童。"},{"en":"The lifeguard's heroic rescue saved two drowning swimmers.","zh":"救生員英勇的救援救了兩名溺水的泳客。"},{"en":"Their heroic effort to put out the fire was praised by all.","zh":"他們奮力滅火的英勇行為受到眾人稱讚。"}]},{"word":"heroin","pos":"n.","phonetic":"['hɛro.ɪn]","meaning":"海洛因","definition":"a highly addictive illegal drug","collocations":["heroin addiction","use heroin","heroin abuse"],"example":"Heroin addiction destroyed many young lives.","exampleZh":"海洛因成癮毀了許多年輕人的一生。","synonyms":[],"level":5,"theme":"社會與文化","examples":[{"en":"Heroin addiction destroyed many young lives.","zh":"海洛因成癮毀了許多年輕人的一生。"},{"en":"Doctors warned the students about the dangers of heroin abuse.","zh":"醫生向學生們警告濫用海洛因的危險。"},{"en":"The clinic helps patients recover from heroin addiction.","zh":"這家診所幫助病患從海洛因成癮中康復。"}]},{"word":"heroine","pos":"n.","phonetic":"['hɛro.ɪn]","meaning":"女英雄；女主角","definition":"a woman admired for her courage, or the main female character in a story","collocations":["the heroine of the story","a national heroine","a tragic heroine"],"example":"The heroine of the novel risks her life to save her village.","exampleZh":"這部小說的女主角冒著生命危險拯救她的村莊。","synonyms":[],"level":3,"theme":"藝術與音樂","examples":[{"en":"The heroine of the novel risks her life to save her village.","zh":"這部小說的女主角冒著生命危險拯救她的村莊。"},{"en":"The heroine of the film bravely rescues her younger brother.","zh":"這部電影的女主角勇敢地救出了她的弟弟。"},{"en":"She became a national heroine after her daring rescue.","zh":"在那次大膽的救援之後，她成了全國的女英雄。"}]},{"word":"hesitant","pos":"adj.","phonetic":"['hɛzətənt]","meaning":"猶豫的；躊躇的","definition":"slow to act or speak because of feeling unsure","collocations":["hesitant to speak","feel hesitant","a hesitant smile"],"example":"He was hesitant to share his opinion in front of everyone.","exampleZh":"他猶豫著不敢在大家面前發表意見。","synonyms":["reluctant","uncertain"],"level":4,"theme":"情緒與感受","examples":[{"en":"He was hesitant to share his opinion in front of everyone.","zh":"他猶豫著不敢在大家面前發表意見。"},{"en":"She was hesitant to try the strange food at first.","zh":"起初她對嘗試那道奇怪的食物感到猶豫。"},{"en":"He gave a hesitant smile before answering the question.","zh":"他在回答問題前露出猶豫的微笑。"}]},{"word":"hesitate","pos":"v.","phonetic":"[ˈhɛzəˌtet]","meaning":"猶豫；躊躇","definition":"to pause before doing or saying something because of uncertainty","collocations":["hesitate to ask","without hesitation","hesitate before answering"],"example":"Don't hesitate to ask if you have any questions.","exampleZh":"如果你有任何問題，不要猶豫儘管問。","synonyms":["waver","pause"],"level":4,"theme":"動作與行為","examples":[{"en":"Don't hesitate to ask if you have any questions.","zh":"如果你有任何問題，不要猶豫儘管問。"},{"en":"She did not hesitate to help the old woman cross the street.","zh":"她毫不猶豫地幫助那位老婦人過馬路。"},{"en":"He hesitated for a moment before opening the mysterious box.","zh":"打開那個神秘的盒子前，他猶豫了片刻。"}]},{"word":"hibernate","pos":"v.","phonetic":"['haɪbɚˌnet]","meaning":"冬眠","definition":"to spend the winter in a dormant state","collocations":["bears hibernate","hibernate in winter","begin to hibernate"],"example":"Bears hibernate in caves throughout the winter.","exampleZh":"熊在冬天整個季節都在洞穴裡冬眠。","synonyms":[],"level":3,"theme":"動物與植物","examples":[{"en":"Bears hibernate in caves throughout the winter.","zh":"熊在冬天整個季節都在洞穴裡冬眠。"},{"en":"Many animals hibernate in winter to save their energy.","zh":"許多動物在冬天冬眠以節省體力。"},{"en":"The frogs bury themselves in mud and hibernate until spring.","zh":"青蛙把自己埋進泥裡冬眠，直到春天。"}]},{"word":"hiccup","pos":"n. / v.","phonetic":"['hɪkʌp]","meaning":"打嗝；小問題","definition":"a sudden involuntary sound in the throat; a minor problem","collocations":["get the hiccups","a slight hiccup","cure hiccups"],"example":"She got the hiccups after drinking her soda too fast.","exampleZh":"她喝汽水太快而打起嗝來。","synonyms":[],"level":3,"theme":"身體與健康","examples":[{"en":"She got the hiccups after drinking her soda too fast.","zh":"她喝汽水太快而打起嗝來。"},{"en":"Drinking water slowly may help stop the hiccups.","zh":"慢慢喝水或許有助於止住打嗝。"},{"en":"Apart from a slight hiccup with the tickets, the trip went well.","zh":"除了車票上的小狀況，這趟旅行進行得很順利。"}]},{"word":"hide","pos":"v.","phonetic":"[haɪd]","meaning":"隱藏；躲藏","definition":"to put or keep something out of sight","collocations":["hide something","hide from someone","play hide and seek"],"example":"The children hid behind the curtains.","exampleZh":"孩子們躲在窗簾後面。","synonyms":["conceal"],"level":1,"theme":"動作與行為","examples":[{"en":"The children hid behind the curtains.","zh":"孩子們躲在窗簾後面。"},{"en":"The kids love to play hide and seek in the garden.","zh":"孩子們喜歡在花園裡玩捉迷藏。"},{"en":"He tried to hide his disappointment behind a smile.","zh":"他試著用微笑掩藏失望。"}]},{"word":"hideous","pos":"adj.","phonetic":"['hɪdiəs]","meaning":"醜陋的；可怕的","definition":"extremely ugly or unpleasant","collocations":["a hideous monster","a hideous crime","hideous scar"],"example":"The movie's hideous monster frightened the children.","exampleZh":"電影裡醜陋的怪物把孩子們嚇壞了。","synonyms":["ugly","horrible"],"level":4,"theme":"性質與描述","examples":[{"en":"The movie's hideous monster frightened the children.","zh":"電影裡醜陋的怪物把孩子們嚇壞了。"},{"en":"The mask was so hideous that it scared the little children.","zh":"那個面具醜陋得嚇壞了小孩子們。"},{"en":"The old wallpaper had a truly hideous pattern.","zh":"那舊壁紙的圖案真是醜得可怕。"}]},{"word":"hierarchy","pos":"n.","phonetic":"['haɪərˌɑrki]","meaning":"階層；等級制度","definition":"a system in which people are ranked according to status or authority","collocations":["social hierarchy","corporate hierarchy","climb the hierarchy"],"example":"He quickly rose through the corporate hierarchy.","exampleZh":"他在公司的階層制度中迅速晉升。","synonyms":["ranking"],"level":5,"theme":"社會與文化","examples":[{"en":"He quickly rose through the corporate hierarchy.","zh":"他在公司的階層制度中迅速晉升。"},{"en":"In many schools, there is a clear social hierarchy among students.","zh":"在許多學校裡，學生之間存在著明顯的社會階層。"},{"en":"She worked hard and slowly climbed the corporate hierarchy.","zh":"她努力工作，慢慢在公司的階層制度中往上爬。"}]},{"word":"highlight","pos":"v. / n.","phonetic":"[ˈhaɪˌlaɪt]","meaning":"強調；精彩部分","definition":"to draw special attention to something, or the most memorable part","collocations":["highlight a point","highlight of the trip","highlight reel"],"example":"The concert was the highlight of my summer.","exampleZh":"那場演唱會是我這個夏天最精彩的事。","synonyms":["emphasize"],"level":4,"theme":"抽象概念","examples":[{"en":"The concert was the highlight of my summer.","zh":"那場演唱會是我這個夏天最精彩的事。"},{"en":"The teacher used a marker to highlight the key points.","zh":"老師用螢光筆標出重點。"},{"en":"Visiting the ancient castle was the highlight of our trip.","zh":"參觀那座古堡是我們旅程中最精彩的部分。"}]},{"word":"highway","pos":"n.","phonetic":"[ˈhaɪˌwe]","meaning":"公路；大道","definition":"a main road, especially one connecting cities","collocations":["national highway","highway traffic","drive on the highway"],"example":"Traffic on the highway was heavy this morning.","exampleZh":"今天早上公路上的交通很擁擠。","synonyms":["freeway"],"level":2,"theme":"交通與旅行","examples":[{"en":"Traffic on the highway was heavy this morning.","zh":"今天早上公路上的交通很擁擠。"},{"en":"We drove along the coastal highway to enjoy the ocean view.","zh":"我們沿著濱海公路開車，欣賞海景。"},{"en":"Highway traffic was heavy during the holiday weekend.","zh":"假日週末的公路交通十分繁忙。"}]},{"word":"hijack","pos":"v.","phonetic":"[ˈhaɪˌdʒæk]","meaning":"劫持（飛機、車輛）","definition":"to illegally seize control of a vehicle, especially an aircraft","collocations":["hijack a plane","hijack a bus","attempt to hijack"],"example":"The armed men tried to hijack the airplane.","exampleZh":"那些武裝分子試圖劫持這架飛機。","synonyms":["seize"],"level":6,"theme":"政治與法律","examples":[{"en":"The armed men tried to hijack the airplane.","zh":"那些武裝分子試圖劫持這架飛機。"},{"en":"Security measures make it much harder to hijack a plane today.","zh":"如今的安全措施使得劫持飛機困難許多。"},{"en":"The criminals attempted to hijack the armored truck.","zh":"那些歹徒企圖劫持那輛裝甲車。"}]},{"word":"hike","pos":"v. / n.","phonetic":"[haɪk]","meaning":"健行；徒步旅行","definition":"to walk for a long distance, especially in the countryside","collocations":["go for a hike","hike a trail","mountain hike"],"example":"We went for a long hike in the mountains.","exampleZh":"我們去山上健行了很長一段路。","synonyms":["trek"],"level":3,"theme":"運動與休閒","examples":[{"en":"We went for a long hike in the mountains.","zh":"我們去山上健行了很長一段路。"},{"en":"We plan to hike a forest trail early on Sunday morning.","zh":"我們計畫在星期天一大早去健行一條森林步道。"},{"en":"The mountain hike was tiring but the view was worth it.","zh":"這趟登山健行很累，但風景值回票價。"}]},{"word":"hint","pos":"n. / v.","phonetic":"[hɪnt]","meaning":"暗示；提示","definition":"a slight indication of something, or to suggest indirectly","collocations":["give a hint","take a hint","hint at something"],"example":"She gave me a hint about the surprise party.","exampleZh":"她給了我一個關於驚喜派對的暗示。","synonyms":["clue","suggestion"],"level":3,"theme":"溝通與語言","examples":[{"en":"She gave me a hint about the surprise party.","zh":"她給了我一個關於驚喜派對的暗示。"},{"en":"The teacher gave us a hint about the final exam questions.","zh":"老師給了我們一些關於期末考題的提示。"},{"en":"Her smile hinted at some good news she was keeping secret.","zh":"她的微笑暗示著她藏著某個好消息。"}]},{"word":"hip","pos":"n.","phonetic":"[hɪp]","meaning":"臀部；髖部","definition":"the part of the body between the waist and the thigh","collocations":["hip joint","hip pain","hands on hips"],"example":"She put her hands on her hips and laughed.","exampleZh":"她雙手叉腰大笑。","synonyms":[],"level":3,"theme":"身體與健康","examples":[{"en":"She put her hands on her hips and laughed.","zh":"她雙手叉腰大笑。"},{"en":"The dancer moved her hips gracefully to the rhythm.","zh":"舞者隨著節奏優雅地擺動臀部。"},{"en":"After the fall, the old man complained of sharp hip pain.","zh":"跌倒後，那位老人抱怨髖部劇烈疼痛。"}]},{"word":"hire","pos":"v.","phonetic":"[haɪr]","meaning":"雇用；租用","definition":"to employ someone, or to pay to use something temporarily","collocations":["hire an employee","hire a car","newly hired"],"example":"The company decided to hire two new engineers.","exampleZh":"這家公司決定雇用兩名新工程師。","synonyms":["employ","rent"],"level":3,"theme":"工作與職業","examples":[{"en":"The company decided to hire two new engineers.","zh":"這家公司決定雇用兩名新工程師。"},{"en":"The restaurant plans to hire more waiters for the summer.","zh":"這家餐廳計畫在夏天雇用更多服務生。"},{"en":"We decided to hire a car for our trip around the island.","zh":"我們決定租一輛車環島旅行。"}]},{"word":"hive","pos":"n.","phonetic":"[haɪv]","meaning":"蜂巢；蜂窩","definition":"a structure in which bees live","collocations":["beehive","build a hive","hive of activity"],"example":"The farmer keeps several bee hives in his garden.","exampleZh":"這位農夫在花園裡養了好幾個蜂巢。","synonyms":[],"level":5,"theme":"動物與植物","examples":[{"en":"The farmer keeps several bee hives in his garden.","zh":"這位農夫在花園裡養了好幾個蜂巢。"},{"en":"Thousands of bees flew busily around the wooden hive.","zh":"數千隻蜜蜂在木製蜂巢周圍忙碌地飛舞。"},{"en":"The market was a hive of activity on Sunday morning.","zh":"星期天早上的市場是一片熱鬧繁忙的景象。"}]},{"word":"hoarse","pos":"adj.","phonetic":"[hors]","meaning":"沙啞的","definition":"having a rough, harsh voice, often from a sore throat","collocations":["hoarse voice","shout oneself hoarse","sound hoarse"],"example":"He was hoarse after cheering at the game all day.","exampleZh":"他整天在球賽上吶喊,聲音都沙啞了。","synonyms":["raspy"],"level":5,"theme":"身體與健康","examples":[{"en":"He was hoarse after cheering at the game all day.","zh":"他整天在球賽上吶喊,聲音都沙啞了。"},{"en":"After the concert, the singer's voice was completely hoarse.","zh":"演唱會後，歌手的聲音完全沙啞了。"},{"en":"The fans shouted themselves hoarse cheering for the team.","zh":"球迷們為球隊加油，喊到聲音都啞了。"}]},{"word":"hoax","pos":"n.","phonetic":"[hoks]","meaning":"惡作劇；騙局","definition":"a trick meant to deceive people into believing something false","collocations":["a hoax call","expose a hoax","internet hoax"],"example":"The bomb threat turned out to be a hoax.","exampleZh":"那起炸彈威脅結果是一場騙局。","synonyms":["trick","fraud"],"level":6,"theme":"抽象概念","examples":[{"en":"The bomb threat turned out to be a hoax.","zh":"那起炸彈威脅結果是一場騙局。"},{"en":"The story about the monster turned out to be a hoax.","zh":"那個關於怪物的故事原來是一場騙局。"},{"en":"Reporters worked hard to expose the internet hoax.","zh":"記者們努力揭穿那個網路騙局。"}]},{"word":"hobby","pos":"n.","phonetic":"[ˈhɑbɪ]","meaning":"嗜好；業餘愛好","definition":"an activity done regularly for enjoyment in one's free time","collocations":["favorite hobby","hobby of collecting","take up a hobby"],"example":"Photography is my favorite hobby.","exampleZh":"攝影是我最喜歡的嗜好。","synonyms":["pastime"],"level":2,"theme":"運動與休閒","examples":[{"en":"Photography is my favorite hobby.","zh":"攝影是我最喜歡的嗜好。"},{"en":"During the summer, he took up gardening as a new hobby.","zh":"暑假期間，他培養了園藝這項新嗜好。"},{"en":"Her hobby of collecting stamps started when she was ten.","zh":"她集郵的嗜好從十歲時就開始了。"}]},{"word":"hoist","pos":"v.","phonetic":"[hɔɪst]","meaning":"升起；吊起","definition":"to raise something heavy, often with ropes or a pulley","collocations":["hoist a flag","hoist the sail","hoist up"],"example":"The sailors hoisted the sail before setting off.","exampleZh":"水手們在出發前升起了船帆。","synonyms":["lift","raise"],"level":6,"theme":"動作與行為","examples":[{"en":"The sailors hoisted the sail before setting off.","zh":"水手們在出發前升起了船帆。"},{"en":"The students hoisted the school flag every Monday morning.","zh":"學生們每星期一早上升起校旗。"},{"en":"A crane hoisted the steel beams to the top of the building.","zh":"一台起重機把鋼樑吊到大樓頂端。"}]},{"word":"hold","pos":"v. / n.","phonetic":"[hold]","meaning":"拿著；握住；持有","definition":"to have or keep something in one's hand or arms","collocations":["hold hands","hold a meeting","get hold of"],"example":"She held the baby gently in her arms.","exampleZh":"她輕輕地抱著寶寶。","synonyms":["grasp","grip"],"level":1,"theme":"動作與行為","examples":[{"en":"She held the baby gently in her arms.","zh":"她輕輕地抱著寶寶。"},{"en":"The couple held hands as they walked along the beach.","zh":"這對情侶手牽手沿著海灘散步。"},{"en":"The club will hold a meeting to plan the school festival.","zh":"社團將舉行一場會議來籌劃校慶。"}]},{"word":"holder","pos":"n.","phonetic":"[ˈholdɚ]","meaning":"持有人；支架","definition":"a person who possesses something, or an object that holds something","collocations":["record holder","cup holder","ticket holder"],"example":"He is the current holder of the world record.","exampleZh":"他是目前的世界紀錄保持人。","synonyms":["owner"],"level":3,"theme":"其他","examples":[{"en":"He is the current holder of the world record.","zh":"他是目前的世界紀錄保持人。"},{"en":"She placed her drink in the cup holder next to her seat.","zh":"她把飲料放進座位旁的杯架裡。"},{"en":"Only ticket holders are allowed to enter the concert hall.","zh":"只有持票者才能進入音樂廳。"}]},{"word":"hole","pos":"n.","phonetic":"[hol]","meaning":"洞；孔","definition":"an opening or hollow space in something","collocations":["dig a hole","a hole in the wall","fill a hole"],"example":"The dog dug a hole in the garden.","exampleZh":"狗在花園裡挖了一個洞。","synonyms":["gap","opening"],"level":1,"theme":"性質與描述","examples":[{"en":"The dog dug a hole in the garden.","zh":"狗在花園裡挖了一個洞。"},{"en":"The workers dug a deep hole to plant the young tree.","zh":"工人們挖了一個深洞來種下這棵小樹。"},{"en":"There is a small hole in my sock that needs mending.","zh":"我的襪子上有個需要縫補的小洞。"}]},{"word":"holiday","pos":"n.","phonetic":"[ˈhɑləˌde]","meaning":"假日；假期","definition":"a day or period of rest from work or school","collocations":["national holiday","go on holiday","summer holiday"],"example":"We are planning a family holiday to the beach.","exampleZh":"我們正在計劃一次全家的海灘假期。","synonyms":["vacation","break"],"level":1,"theme":"交通與旅行","examples":[{"en":"We are planning a family holiday to the beach.","zh":"我們正在計劃一次全家的海灘假期。"},{"en":"During the summer holiday, we visited our cousins in the countryside.","zh":"暑假期間，我們去鄉下拜訪表親。"},{"en":"The shops are closed today because it is a national holiday.","zh":"因為今天是國定假日，商店都關門了。"}]},{"word":"hollow","pos":"adj.","phonetic":"[ˈhɑlo]","meaning":"中空的；空洞的","definition":"having a hole or empty space inside","collocations":["hollow tree","hollow sound","feel hollow"],"example":"The old tree trunk was completely hollow inside.","exampleZh":"那棵老樹的樹幹裡面完全是中空的。","synonyms":["empty"],"level":4,"theme":"性質與描述","examples":[{"en":"The old tree trunk was completely hollow inside.","zh":"那棵老樹的樹幹裡面完全是中空的。"},{"en":"An owl made its nest inside the hollow tree.","zh":"一隻貓頭鷹在那棵中空的樹裡築巢。"},{"en":"Knocking on the wall produced a strange hollow sound.","zh":"敲打牆壁發出奇怪的空洞聲響。"}]},{"word":"holy","pos":"adj.","phonetic":"[ˈholi]","meaning":"神聖的；聖潔的","definition":"connected with God or a particular religion, considered sacred","collocations":["holy place","holy book","holy water"],"example":"Pilgrims visit the holy city every year.","exampleZh":"朝聖者每年都會造訪這座聖城。","synonyms":["sacred"],"level":4,"theme":"社會與文化","examples":[{"en":"Pilgrims visit the holy city every year.","zh":"朝聖者每年都會造訪這座聖城。"},{"en":"Visitors must remove their shoes before entering the holy temple.","zh":"訪客進入神聖的寺廟前必須脫鞋。"},{"en":"The river is considered a holy place by local people.","zh":"當地人視這條河為神聖之地。"}]},{"word":"home","pos":"n. / adv.","phonetic":"[hom]","meaning":"家；家鄉","definition":"the place where one lives","collocations":["at home","go home","home cooking"],"example":"There is no place like home.","exampleZh":"沒有一個地方比得上家。","synonyms":["house","residence"],"level":1,"theme":"居家與生活","examples":[{"en":"There is no place like home.","zh":"沒有一個地方比得上家。"},{"en":"Nothing beats the taste of my mother's home cooking.","zh":"沒有什麼比得上我母親家常菜的味道。"},{"en":"After living abroad for years, he finally returned home.","zh":"在國外生活多年後，他終於回到家鄉。"}]},{"word":"homework","pos":"n.","phonetic":"[ˈhomˌwɝk]","meaning":"家庭作業","definition":"school work that students do at home","collocations":["do homework","homework assignment","finish homework"],"example":"She always finishes her homework before dinner.","exampleZh":"她總是在晚餐前完成家庭作業。","synonyms":[],"level":1,"theme":"教育與學習","examples":[{"en":"She always finishes her homework before dinner.","zh":"她總是在晚餐前完成家庭作業。"},{"en":"He finished his homework quickly so he could play outside.","zh":"他很快寫完作業，好到外面玩。"},{"en":"Our math homework assignment is due next Monday.","zh":"我們的數學作業下星期一要交。"}]},{"word":"honest","pos":"adj.","phonetic":"[ˈɑnɪst]","meaning":"誠實的；正直的","definition":"telling the truth and not cheating or stealing","collocations":["honest answer","be honest with someone","honest opinion"],"example":"To be honest, I don't like the plan.","exampleZh":"老實說，我不喜歡這個計畫。","synonyms":["truthful","sincere"],"level":2,"theme":"性質與描述","examples":[{"en":"To be honest, I don't like the plan.","zh":"老實說，我不喜歡這個計畫。"},{"en":"Please give me your honest opinion of my essay.","zh":"請給我你對我文章的誠實意見。"},{"en":"It is always best to be honest with your parents.","zh":"對父母誠實永遠是最好的。"}]},{"word":"honesty","pos":"n.","phonetic":"[ˈɑnɪstɪ]","meaning":"誠實；正直","definition":"the quality of being truthful and sincere","collocations":["value honesty","honesty policy","act with honesty"],"example":"Honesty is the most important quality in a friend.","exampleZh":"誠實是一個朋友最重要的特質。","synonyms":["integrity"],"level":3,"theme":"抽象概念","examples":[{"en":"Honesty is the most important quality in a friend.","zh":"誠實是一個朋友最重要的特質。"},{"en":"Her teachers admire her honesty and hard work.","zh":"老師們欣賞她的誠實與努力。"},{"en":"The company values honesty above everything else.","zh":"這家公司把誠實看得比一切都重要。"}]},{"word":"honey","pos":"n.","phonetic":"[ˈhʌnɪ]","meaning":"蜂蜜；親愛的","definition":"a sweet sticky substance made by bees","collocations":["a jar of honey","honey bee","honey and lemon"],"example":"She added a spoonful of honey to her tea.","exampleZh":"她在茶裡加了一匙蜂蜜。","synonyms":[],"level":1,"theme":"食物與烹飪","examples":[{"en":"She added a spoonful of honey to her tea.","zh":"她在茶裡加了一匙蜂蜜。"},{"en":"A cup of warm honey and lemon can soothe a sore throat.","zh":"一杯溫熱的蜂蜜檸檬能舒緩喉嚨痛。"},{"en":"The busy honey bees moved from flower to flower.","zh":"忙碌的蜜蜂在花叢間飛來飛去。"}]},{"word":"honor","pos":"n. / v.","phonetic":"[ˈɑnɚ]","meaning":"榮譽；尊敬","definition":"great respect, or to show respect for someone","collocations":["great honor","honor a promise","in honor of"],"example":"It was a great honor to receive the award.","exampleZh":"獲得這個獎項是莫大的榮譽。","synonyms":["respect","glory"],"level":4,"theme":"抽象概念","examples":[{"en":"It was a great honor to receive the award.","zh":"獲得這個獎項是莫大的榮譽。"},{"en":"A special dinner was held in honor of the retiring teacher.","zh":"為了向這位退休的老師致敬，特別舉辦了一場晚宴。"},{"en":"A true friend always honors his promises.","zh":"真正的朋友總是信守他的承諾。"}]},{"word":"honorable","pos":"adj.","phonetic":"[ˈɑnərəbḷ]","meaning":"值得尊敬的；光榮的","definition":"deserving honor and respect","collocations":["an honorable man","honorable mention","honorable behavior"],"example":"He made an honorable decision to admit his mistake.","exampleZh":"他做出了承認錯誤的光榮決定。","synonyms":["respectable","noble"],"level":5,"theme":"性質與描述","examples":[{"en":"He made an honorable decision to admit his mistake.","zh":"他做出了承認錯誤的光榮決定。"},{"en":"Returning the lost wallet was an honorable thing to do.","zh":"歸還撿到的錢包是件值得尊敬的事。"},{"en":"Her project received an honorable mention at the science fair.","zh":"她的作品在科展中獲得佳作。"}]},{"word":"hood","pos":"n.","phonetic":"[hʊd]","meaning":"兜帽；引擎蓋","definition":"a covering for the head and neck, often part of a coat","collocations":["a raincoat hood","pull up the hood","car hood"],"example":"She pulled her hood up to keep dry in the rain.","exampleZh":"她拉起兜帽以免淋濕。","synonyms":[],"level":3,"theme":"服裝與外表","examples":[{"en":"She pulled her hood up to keep dry in the rain.","zh":"她拉起兜帽以免淋濕。"},{"en":"The mechanic opened the car hood to check the engine.","zh":"技師打開引擎蓋檢查引擎。"},{"en":"She pulled up her hood as the rain grew heavier.","zh":"雨越下越大，她拉起了兜帽。"}]},{"word":"hook","pos":"n. / v.","phonetic":"[hʊk]","meaning":"鉤子；鉤住","definition":"a curved piece of metal or plastic used to catch or hang things","collocations":["fishing hook","hang on a hook","hook up"],"example":"He hung his coat on the hook by the door.","exampleZh":"他把外套掛在門邊的掛鉤上。","synonyms":[],"level":3,"theme":"居家與生活","examples":[{"en":"He hung his coat on the hook by the door.","zh":"他把外套掛在門邊的掛鉤上。"},{"en":"He carefully attached the bait to the fishing hook.","zh":"他小心地把魚餌掛在魚鉤上。"},{"en":"Please hang your umbrella on the hook by the door.","zh":"請把你的雨傘掛在門邊的鉤子上。"}]},{"word":"hop","pos":"v. / n.","phonetic":"[hɑp]","meaning":"單腳跳；跳躍","definition":"to jump on one foot or move by jumping","collocations":["hop on one foot","hop over","hop on a bus"],"example":"The rabbit hopped across the field.","exampleZh":"兔子跳過了那片田野。","synonyms":["jump","leap"],"level":2,"theme":"動作與行為","examples":[{"en":"The rabbit hopped across the field.","zh":"兔子跳過了那片田野。"},{"en":"The children laughed as they hopped over the puddles.","zh":"孩子們笑著跳過一個個水坑。"},{"en":"We hopped on a bus and headed straight to the museum.","zh":"我們跳上公車，直接前往博物館。"}]},{"word":"hope","pos":"v. / n.","phonetic":"[hop]","meaning":"希望；期望","definition":"to want something to happen or be true","collocations":["hope for the best","give up hope","hope so"],"example":"I hope you feel better soon.","exampleZh":"我希望你早點康復。","synonyms":["wish","expect"],"level":1,"theme":"情緒與感受","examples":[{"en":"I hope you feel better soon.","zh":"我希望你早點康復。"},{"en":"Even in hard times, we should never give up hope.","zh":"即使在艱難時刻，我們也絕不該放棄希望。"},{"en":"I hope for the best, but I am prepared for the worst.","zh":"我抱最好的期望，但也做了最壞的準備。"}]},{"word":"hopeful","pos":"adj.","phonetic":"[ˈhopfəl]","meaning":"有希望的；抱有希望的","definition":"feeling or expressing hope that something will happen","collocations":["remain hopeful","hopeful sign","hopeful about the future"],"example":"Doctors are hopeful that she will make a full recovery.","exampleZh":"醫生們對她能完全康復抱持希望。","synonyms":["optimistic"],"level":3,"theme":"情緒與感受","examples":[{"en":"Doctors are hopeful that she will make a full recovery.","zh":"醫生們對她能完全康復抱持希望。"},{"en":"Despite the setback, the team remained hopeful about winning.","zh":"儘管遭遇挫折，隊伍仍對獲勝抱持希望。"},{"en":"The green buds on the trees are a hopeful sign of spring.","zh":"樹上的嫩芽是春天到來的希望徵兆。"}]},{"word":"horizon","pos":"n.","phonetic":"[həˈraɪzən]","meaning":"地平線；視野","definition":"the line where the earth and sky appear to meet","collocations":["on the horizon","broaden one's horizon","above the horizon"],"example":"The sun slowly rose above the horizon.","exampleZh":"太陽緩緩升起在地平線上。","synonyms":[],"level":4,"theme":"自然與環境","examples":[{"en":"The sun slowly rose above the horizon.","zh":"太陽緩緩升起在地平線上。"},{"en":"Traveling abroad can really broaden your horizons.","zh":"出國旅行確實能開闊你的視野。"},{"en":"We watched the ship disappear slowly over the horizon.","zh":"我們看著那艘船慢慢消失在地平線盡頭。"}]},{"word":"horizontal","pos":"adj.","phonetic":"[ˌhɔrəˈzɑntl]","meaning":"水平的；橫的","definition":"parallel to the ground, flat and level","collocations":["horizontal line","horizontal position","horizontal axis"],"example":"Draw a horizontal line across the page.","exampleZh":"在頁面上畫一條水平線。","synonyms":[],"level":5,"theme":"科學與數學","examples":[{"en":"Draw a horizontal line across the page.","zh":"在頁面上畫一條水平線。"},{"en":"The x-axis of the graph is the horizontal axis.","zh":"圖表的 x 軸是水平軸。"},{"en":"Lay the ladder in a horizontal position on the ground.","zh":"把梯子水平地放在地上。"}]},{"word":"horn","pos":"n.","phonetic":"[hɔrn]","meaning":"角；喇叭；號角","definition":"a hard pointed growth on an animal's head, or a device that makes a loud sound","collocations":["car horn","honk the horn","bull's horn"],"example":"The driver honked his horn to warn the cyclist.","exampleZh":"駕駛按喇叭警告那位騎自行車的人。","synonyms":[],"level":3,"theme":"動物與植物","examples":[{"en":"The driver honked his horn to warn the cyclist.","zh":"駕駛按喇叭警告那位騎自行車的人。"},{"en":"The impatient driver honked his horn at the slow truck.","zh":"那位不耐煩的駕駛對著慢吞吞的卡車按喇叭。"},{"en":"The bull lowered its head and pointed its sharp horns forward.","zh":"那頭公牛低下頭，把尖角朝前指著。"}]},{"word":"horrible","pos":"adj.","phonetic":"[ˈhɔrəbl]","meaning":"可怕的；糟糕的","definition":"extremely unpleasant or frightening","collocations":["horrible accident","horrible weather","feel horrible"],"example":"We had a horrible experience during the storm.","exampleZh":"我們在暴風雨中經歷了可怕的事。","synonyms":["terrible","awful"],"level":2,"theme":"性質與描述","examples":[{"en":"We had a horrible experience during the storm.","zh":"我們在暴風雨中經歷了可怕的事。"},{"en":"We were stuck indoors all day because of the horrible weather.","zh":"因為天氣糟透了，我們整天都被困在室內。"},{"en":"She felt horrible after forgetting her friend's birthday.","zh":"忘了朋友的生日後，她覺得很糟糕。"}]},{"word":"horrify","pos":"v.","phonetic":"[ˈhɔrəˌfaɪ]","meaning":"使驚恐；使震驚","definition":"to make someone feel shocked and afraid","collocations":["horrify the public","be horrified by","horrifying news"],"example":"The report horrified the whole nation.","exampleZh":"這篇報導震驚了整個國家。","synonyms":["shock","terrify"],"level":5,"theme":"情緒與感受","examples":[{"en":"The report horrified the whole nation.","zh":"這篇報導震驚了整個國家。"},{"en":"The cruel treatment of the animals horrified everyone who saw it.","zh":"動物遭受的殘忍對待使每個目睹的人都感到震驚。"},{"en":"She was horrified by the mess left after the party.","zh":"派對後留下的髒亂讓她感到驚駭。"}]},{"word":"horror","pos":"n.","phonetic":"[ˈhɔrɚ]","meaning":"恐怖；驚駭","definition":"an intense feeling of fear, shock, or disgust","collocations":["horror movie","in horror","horror story"],"example":"She screamed in horror when she saw the spider.","exampleZh":"她看到蜘蛛時嚇得尖叫起來。","synonyms":["terror","dread"],"level":3,"theme":"情緒與感受","examples":[{"en":"She screamed in horror when she saw the spider.","zh":"她看到蜘蛛時嚇得尖叫起來。"},{"en":"My little brother is too scared to watch horror movies.","zh":"我弟弟太害怕了，不敢看恐怖片。"},{"en":"The crowd watched in horror as the building caught fire.","zh":"群眾驚恐地看著那棟建築起火。"}]},{"word":"horse","pos":"n.","phonetic":"[hɔrs]","meaning":"馬","definition":"a large animal used for riding and pulling loads","collocations":["ride a horse","horse race","wild horse"],"example":"The cowboy rode his horse across the plain.","exampleZh":"牛仔騎著他的馬穿越平原。","synonyms":[],"level":1,"theme":"動物與植物","examples":[{"en":"The cowboy rode his horse across the plain.","zh":"牛仔騎著他的馬穿越平原。"},{"en":"She learned to ride a horse during her summer vacation.","zh":"她在暑假期間學會了騎馬。"},{"en":"A group of wild horses ran freely across the open plain.","zh":"一群野馬在開闊的平原上自由奔馳。"}]},{"word":"hose","pos":"n.","phonetic":"[hoz]","meaning":"軟管；水管","definition":"a flexible tube used to carry water or other liquid","collocations":["garden hose","water hose","hose down"],"example":"He used a hose to wash his car.","exampleZh":"他用水管洗車。","synonyms":["tube","pipe"],"level":3,"theme":"居家與生活","examples":[{"en":"He used a hose to wash his car.","zh":"他用水管洗車。"},{"en":"He connected the garden hose to water the flowers.","zh":"他接上花園水管來澆花。"},{"en":"The firefighters used a powerful hose to put out the flames.","zh":"消防員用強力水管撲滅火焰。"}]},{"word":"hospital","pos":"n.","phonetic":"[ˈhɑspɪtl]","meaning":"醫院","definition":"a place where sick or injured people are treated","collocations":["go to the hospital","hospital bed","admit to hospital"],"example":"He was taken to the hospital after the accident.","exampleZh":"意外發生後他被送到醫院。","synonyms":[],"level":1,"theme":"身體與健康","examples":[{"en":"He was taken to the hospital after the accident.","zh":"意外發生後他被送到醫院。"},{"en":"She was admitted to the hospital for a minor operation.","zh":"她因為一個小手術住進了醫院。"},{"en":"The nurse gently helped him into the hospital bed.","zh":"護士輕輕地扶他躺上病床。"}]},{"word":"hospitality","pos":"n.","phonetic":"[ˌhɑspɪˈtælətɪ]","meaning":"好客；款待","definition":"friendly and generous treatment of guests","collocations":["show hospitality","thank for the hospitality","hospitality industry"],"example":"We were grateful for the warm hospitality of our hosts.","exampleZh":"我們很感激主人熱情的款待。","synonyms":["warmth"],"level":5,"theme":"社會與文化","examples":[{"en":"We were grateful for the warm hospitality of our hosts.","zh":"我們很感激主人熱情的款待。"},{"en":"The villagers showed us warm hospitality during our stay.","zh":"村民們在我們停留期間熱情款待我們。"},{"en":"Many young people find jobs in the hospitality industry.","zh":"許多年輕人在餐旅業找到工作。"}]},{"word":"host","pos":"n. / v.","phonetic":"[host]","meaning":"主人；主持人；主辦","definition":"a person who receives guests, or to organize an event","collocations":["host a party","talk show host","host country"],"example":"Taiwan hosted an international sports event last year.","exampleZh":"台灣去年主辦了一場國際運動賽事。","synonyms":["organizer"],"level":3,"theme":"社會與文化","examples":[{"en":"Taiwan hosted an international sports event last year.","zh":"台灣去年主辦了一場國際運動賽事。"},{"en":"Our school will host the regional science competition this year.","zh":"今年我們學校將主辦區域科學競賽。"},{"en":"She decided to host a small party for her close friends.","zh":"她決定為她的好友們舉辦一場小型派對。"}]},{"word":"hostage","pos":"n.","phonetic":"[ˈhɑstɪdʒ]","meaning":"人質","definition":"a person held captive as security for demands","collocations":["take hostage","release a hostage","hostage situation"],"example":"The police negotiated to free the hostages.","exampleZh":"警方協商以釋放人質。","synonyms":["captive"],"level":6,"theme":"政治與法律","examples":[{"en":"The police negotiated to free the hostages.","zh":"警方協商以釋放人質。"},{"en":"The robbers finally agreed to release the hostage unharmed.","zh":"搶匪最終同意毫髮無傷地釋放人質。"},{"en":"Police officers carefully handled the tense hostage situation.","zh":"警察小心地處理這緊張的人質事件。"}]},{"word":"hostile","pos":"adj.","phonetic":"[ˈhɑstl]","meaning":"敵對的；不友善的","definition":"unfriendly and aggressive","collocations":["hostile attitude","hostile country","hostile environment"],"example":"The two neighbors have a hostile relationship.","exampleZh":"這兩位鄰居的關係很敵對。","synonyms":["unfriendly","aggressive"],"level":5,"theme":"情緒與感受","examples":[{"en":"The two neighbors have a hostile relationship.","zh":"這兩位鄰居的關係很敵對。"},{"en":"The new student was surprised by such a hostile attitude.","zh":"這位新同學對如此不友善的態度感到驚訝。"},{"en":"Few animals can survive in the hostile environment of the desert.","zh":"很少有動物能在沙漠這種嚴酷的環境中存活。"}]},{"word":"hot","pos":"adj.","phonetic":"[hɑt]","meaning":"熱的；辣的","definition":"having a high temperature","collocations":["hot weather","hot soup","hot topic"],"example":"It was so hot that everyone stayed indoors.","exampleZh":"天氣太熱了,大家都待在室內。","synonyms":["warm"],"level":1,"theme":"天氣與季節","examples":[{"en":"It was so hot that everyone stayed indoors.","zh":"天氣太熱了,大家都待在室內。"},{"en":"Climate change has become a hot topic among students.","zh":"氣候變遷已成為學生之間熱門的話題。"},{"en":"A bowl of hot soup is perfect on a cold winter night.","zh":"在寒冷的冬夜，一碗熱湯再完美不過了。"}]},{"word":"hotel","pos":"n.","phonetic":"[hoˈtɛl]","meaning":"旅館；飯店","definition":"a building where travelers pay to stay overnight","collocations":["check into a hotel","five-star hotel","book a hotel"],"example":"We stayed at a small hotel near the beach.","exampleZh":"我們住在海邊附近的一家小旅館。","synonyms":["inn"],"level":1,"theme":"交通與旅行","examples":[{"en":"We stayed at a small hotel near the beach.","zh":"我們住在海邊附近的一家小旅館。"},{"en":"We booked a hotel near the station to save travel time.","zh":"我們訂了一家車站附近的旅館以節省交通時間。"},{"en":"They checked into the hotel and rested after the long flight.","zh":"經過長途飛行後，他們辦理入住並休息。"}]},{"word":"hour","pos":"n.","phonetic":"[aʊr]","meaning":"小時","definition":"a period of sixty minutes","collocations":["an hour later","rush hour","office hours"],"example":"The meeting lasted for almost two hours.","exampleZh":"這場會議持續了將近兩個小時。","synonyms":[],"level":1,"theme":"時間與空間","examples":[{"en":"The meeting lasted for almost two hours.","zh":"這場會議持續了將近兩個小時。"},{"en":"Try to avoid the roads during the morning rush hour.","zh":"盡量避開早上尖峰時段的道路。"},{"en":"The library extends its office hours during exam week.","zh":"圖書館在考試週延長開放時間。"}]},{"word":"hourly","pos":"adj. / adv.","phonetic":"[ˈaʊrlɪ]","meaning":"每小時的；按時計算的","definition":"happening or done every hour, or calculated by the hour","collocations":["hourly wage","hourly rate","update hourly"],"example":"The part-time job pays an hourly wage of 180 dollars.","exampleZh":"這份兼職工作的時薪是一百八十元。","synonyms":[],"level":4,"theme":"時間與空間","examples":[{"en":"The part-time job pays an hourly wage of 180 dollars.","zh":"這份兼職工作的時薪是一百八十元。"},{"en":"The weather station updates its forecast hourly.","zh":"氣象站每小時更新一次預報。"},{"en":"Her new part-time job offers a higher hourly rate.","zh":"她的新兼職工作提供較高的時薪。"}]},{"word":"house","pos":"n.","phonetic":"[haʊs]","meaning":"房子；住宅","definition":"a building where people live","collocations":["build a house","move house","house rent"],"example":"They bought a house near the park.","exampleZh":"他們在公園附近買了一棟房子。","synonyms":["home","residence"],"level":1,"theme":"居家與生活","examples":[{"en":"They bought a house near the park.","zh":"他們在公園附近買了一棟房子。"},{"en":"My uncle plans to build a house on the hill next year.","zh":"我叔叔打算明年在山丘上蓋一棟房子。"},{"en":"The family decided to move house because the rent was too high.","zh":"那家人因為房租太貴而決定搬家。"}]},{"word":"household","pos":"n. / adj.","phonetic":"[ˈhaʊsˌhold]","meaning":"家庭；家戶的","definition":"a house and its occupants regarded as a unit","collocations":["household chores","household income","average household"],"example":"Every household in the neighborhood received a notice.","exampleZh":"社區裡每一戶都收到了通知。","synonyms":["family"],"level":4,"theme":"人物與家庭","examples":[{"en":"Every household in the neighborhood received a notice.","zh":"社區裡每一戶都收到了通知。"},{"en":"Sharing the household chores makes life easier for everyone at home.","zh":"分擔家務讓家裡每個人的生活都更輕鬆。"},{"en":"The average household income in the town has risen this year.","zh":"這個鎮上的平均家庭收入今年上升了。"}]},{"word":"housewife","pos":"n.","phonetic":"[ˈhaʊsˌwaɪf]","meaning":"家庭主婦","definition":"a married woman who manages her household as her main occupation","collocations":["a busy housewife","full-time housewife"],"example":"As a housewife, she manages the family budget carefully.","exampleZh":"身為家庭主婦,她仔細管理家庭預算。","synonyms":[],"level":3,"theme":"人物與家庭","examples":[{"en":"As a housewife, she manages the family budget carefully.","zh":"身為家庭主婦,她仔細管理家庭預算。"},{"en":"My mother is a full-time housewife who takes care of us all.","zh":"我媽媽是位全職家庭主婦，照顧我們全家人。"},{"en":"As a busy housewife, she rarely has time to rest during the day.","zh":"身為忙碌的家庭主婦，她白天很少有時間休息。"}]},{"word":"housework","pos":"n.","phonetic":"[ˈhaʊsˌwɝk]","meaning":"家事；家務","definition":"work such as cleaning that is done in the home","collocations":["do housework","share housework","daily housework"],"example":"They share the housework equally.","exampleZh":"他們平均分擔家務。","synonyms":["chores"],"level":2,"theme":"居家與生活","examples":[{"en":"They share the housework equally.","zh":"他們平均分擔家務。"},{"en":"I help my parents do the housework every weekend.","zh":"我每個週末都幫父母做家事。"},{"en":"Doing daily housework can actually be a good form of exercise.","zh":"做日常家務其實可以是一種很好的運動。"}]},{"word":"hover","pos":"v.","phonetic":"[ˈhʌvɚ]","meaning":"盤旋；徘徊","definition":"to stay in one place in the air","collocations":["hover over","helicopter hovers","hover near"],"example":"The helicopter hovered above the rescue scene.","exampleZh":"直升機在救援現場上空盤旋。","synonyms":["float"],"level":5,"theme":"動作與行為","examples":[{"en":"The helicopter hovered above the rescue scene.","zh":"直升機在救援現場上空盤旋。"},{"en":"A colorful butterfly hovered over the flowers in the garden.","zh":"一隻色彩繽紛的蝴蝶在花園裡的花朵上方盤旋。"},{"en":"The shy student hovered near the door, afraid to come in.","zh":"那個害羞的學生在門邊徘徊，不敢進來。"}]},{"word":"however","pos":"adv. / conj.","phonetic":"[haʊˈɛvɚ]","meaning":"然而；不過","definition":"used to introduce a statement that contrasts with what came before","collocations":["however hard","however, it is","no matter how"],"example":"The weather was cold; however, we still went hiking.","exampleZh":"天氣很冷,然而我們還是去健行了。","synonyms":["nevertheless"],"level":2,"theme":"溝通與語言","examples":[{"en":"The weather was cold; however, we still went hiking.","zh":"天氣很冷,然而我們還是去健行了。"},{"en":"The test was difficult; however, most students passed it.","zh":"這場考試很難，然而大多數學生都及格了。"},{"en":"However hard he tried, he could not solve the puzzle.","zh":"無論他多麼努力，都無法解開這個謎題。"}]},{"word":"howl","pos":"v. / n.","phonetic":"[haʊl]","meaning":"嚎叫；怒吼","definition":"to make a long, loud crying sound, as a wolf or wind does","collocations":["wolf howls","howl in pain","howling wind"],"example":"The wolves howled loudly in the night.","exampleZh":"狼群在夜裡大聲嚎叫。","synonyms":["wail"],"level":5,"theme":"動物與植物","examples":[{"en":"The wolves howled loudly in the night.","zh":"狼群在夜裡大聲嚎叫。"},{"en":"The dog began to howl loudly when it heard the siren.","zh":"那隻狗聽到警笛聲便開始大聲嚎叫。"},{"en":"The howling wind kept us awake throughout the stormy night.","zh":"呼嘯的狂風讓我們在暴風雨的夜裡整夜無法入睡。"}]},{"word":"hug","pos":"v. / n.","phonetic":"[hʌg]","meaning":"擁抱","definition":"to put one's arms around someone as a sign of affection","collocations":["give a hug","hug tightly","warm hug"],"example":"She gave her mother a big hug at the airport.","exampleZh":"她在機場給了媽媽一個大大的擁抱。","synonyms":["embrace"],"level":2,"theme":"情緒與感受","examples":[{"en":"She gave her mother a big hug at the airport.","zh":"她在機場給了媽媽一個大大的擁抱。"},{"en":"The little boy hugged his teddy bear tightly before sleeping.","zh":"小男孩睡前緊緊抱著他的泰迪熊。"},{"en":"After winning the game, the players shared a warm hug.","zh":"贏得比賽後，球員們彼此給了一個溫暖的擁抱。"}]},{"word":"huge","pos":"adj.","phonetic":"[hjudʒ]","meaning":"巨大的；龐大的","definition":"extremely large in size or amount","collocations":["huge success","huge amount","huge crowd"],"example":"The concert attracted a huge crowd of fans.","exampleZh":"這場演唱會吸引了一大群粉絲。","synonyms":["enormous","massive"],"level":2,"theme":"性質與描述","examples":[{"en":"The concert attracted a huge crowd of fans.","zh":"這場演唱會吸引了一大群粉絲。"},{"en":"The new movie was a huge success at the box office.","zh":"這部新電影在票房上獲得巨大的成功。"},{"en":"Cleaning the beach took a huge amount of time and effort.","zh":"清理海灘花費了大量的時間和精力。"}]},{"word":"hull","pos":"n.","phonetic":"[hʌl]","meaning":"船身；殼","definition":"the main body of a ship or boat","collocations":["ship's hull","damage the hull","steel hull"],"example":"Water leaked in through a crack in the hull.","exampleZh":"水從船身的裂縫滲了進來。","synonyms":["frame"],"level":6,"theme":"交通與旅行","examples":[{"en":"Water leaked in through a crack in the hull.","zh":"水從船身的裂縫滲了進來。"},{"en":"The workers painted the steel hull of the huge cargo ship.","zh":"工人們為那艘巨大貨船的鋼製船身上漆。"},{"en":"The sharp rocks could easily damage the hull of a small boat.","zh":"尖銳的岩石很容易損壞小船的船身。"}]},{"word":"human","pos":"adj. / n.","phonetic":"[ˈhjumən]","meaning":"人類的；人類","definition":"relating to or being a person","collocations":["human being","human rights","human nature"],"example":"Human beings depend on nature for survival.","exampleZh":"人類依賴大自然才能生存。","synonyms":["person"],"level":2,"theme":"人物與家庭","examples":[{"en":"Human beings depend on nature for survival.","zh":"人類依賴大自然才能生存。"},{"en":"It is human nature to feel curious about the unknown.","zh":"對未知事物感到好奇是人類的天性。"},{"en":"The organization works hard to protect human rights around the world.","zh":"這個組織努力保護全世界的人權。"}]},{"word":"humane","pos":"adj.","phonetic":"[hjuˈmen]","meaning":"人道的；仁慈的","definition":"showing kindness and compassion toward others","collocations":["humane treatment","humane society","humane way"],"example":"The shelter provides humane care for stray animals.","exampleZh":"這間收容所為流浪動物提供人道的照顧。","synonyms":["kind","compassionate"],"level":5,"theme":"抽象概念","examples":[{"en":"The shelter provides humane care for stray animals.","zh":"這間收容所為流浪動物提供人道的照顧。"},{"en":"The zoo is praised for its humane treatment of the animals.","zh":"這座動物園因人道對待動物而受到讚揚。"},{"en":"We should find a humane way to deal with stray dogs.","zh":"我們應該找到一種人道的方式來處理流浪狗。"}]},{"word":"humanity","pos":"n.","phonetic":"[hjuˈmænətɪ]","meaning":"人類；人道；仁慈","definition":"the human race, or the quality of being humane","collocations":["treat with humanity","for the good of humanity","crimes against humanity"],"example":"The disaster reminded us of our shared humanity.","exampleZh":"這場災難提醒了我們共同的人性。","synonyms":["mankind"],"level":5,"theme":"抽象概念","examples":[{"en":"The disaster reminded us of our shared humanity.","zh":"這場災難提醒了我們共同的人性。"},{"en":"The doctor treated every patient with kindness and humanity.","zh":"這位醫生以仁慈和人道對待每一位病人。"},{"en":"New medicines are being developed for the good of all humanity.","zh":"人們正在研發新藥，造福全人類。"}]},{"word":"humble","pos":"adj.","phonetic":"[ˈhʌmbl]","meaning":"謙虛的；卑微的","definition":"having a modest opinion of one's importance","collocations":["humble opinion","humble background","stay humble"],"example":"Despite his success, he remains humble.","exampleZh":"儘管很成功，他仍然十分謙虛。","synonyms":["modest"],"level":4,"theme":"性質與描述","examples":[{"en":"Despite his success, he remains humble.","zh":"儘管很成功，他仍然十分謙虛。"},{"en":"Even after winning the prize, she stayed humble and thankful.","zh":"即使贏得獎項，她仍然保持謙虛和感恩。"},{"en":"The famous author came from a humble farming background.","zh":"這位著名作家出身於卑微的農家背景。"}]},{"word":"humid","pos":"adj.","phonetic":"[ˈhjumɪd]","meaning":"潮濕的；濕熱的","definition":"marked by a high level of water vapor in the air","collocations":["humid weather","hot and humid","humid climate"],"example":"Summers in Taiwan are hot and humid.","exampleZh":"台灣的夏天既悶熱又潮濕。","synonyms":["damp","moist"],"level":3,"theme":"天氣與季節","examples":[{"en":"Summers in Taiwan are hot and humid.","zh":"台灣的夏天既悶熱又潮濕。"},{"en":"The humid climate makes it hard for my clothes to dry.","zh":"潮濕的氣候讓我的衣服很難晾乾。"},{"en":"During the rainy season, the air becomes very hot and humid.","zh":"在雨季期間，空氣變得又熱又潮濕。"}]},{"word":"humidity","pos":"n.","phonetic":"[hjuˈmɪdətɪ]","meaning":"濕度","definition":"the amount of moisture in the air","collocations":["high humidity","humidity level","relative humidity"],"example":"The high humidity made the day feel even hotter.","exampleZh":"高濕度讓這一天感覺更加悶熱。","synonyms":["dampness"],"level":4,"theme":"天氣與季節","examples":[{"en":"The high humidity made the day feel even hotter.","zh":"高濕度讓這一天感覺更加悶熱。"},{"en":"The high humidity in summer often makes people feel tired.","zh":"夏天的高濕度常常使人感到疲倦。"},{"en":"Farmers check the humidity level before storing their grain.","zh":"農夫在儲存穀物前會檢查濕度。"}]},{"word":"humiliate","pos":"v.","phonetic":"[hjuˈmɪlɪˌet]","meaning":"使丟臉；羞辱","definition":"to make someone feel ashamed or foolish in front of others","collocations":["humiliate someone publicly","feel humiliated","humiliating defeat"],"example":"He felt humiliated after being criticized in front of the class.","exampleZh":"在全班面前被批評後,他覺得很丟臉。","synonyms":["embarrass","shame"],"level":6,"theme":"情緒與感受","examples":[{"en":"He felt humiliated after being criticized in front of the class.","zh":"在全班面前被批評後,他覺得很丟臉。"},{"en":"The coach never tries to humiliate players in front of others.","zh":"這位教練從不試圖在別人面前羞辱球員。"},{"en":"The team suffered a humiliating defeat in the final round.","zh":"這支隊伍在最後一輪遭遇了難堪的敗仗。"}]},{"word":"humor","pos":"n.","phonetic":"[ˈhjumɚ]","meaning":"幽默；幽默感","definition":"the quality of being funny or amusing","collocations":["sense of humor","dry humor","good humor"],"example":"He has a great sense of humor.","exampleZh":"他很有幽默感。","synonyms":["wit"],"level":3,"theme":"性質與描述","examples":[{"en":"He has a great sense of humor.","zh":"他很有幽默感。"},{"en":"Her sense of humor makes even boring lessons enjoyable.","zh":"她的幽默感讓連無聊的課程都變得有趣。"},{"en":"He stayed in good humor despite the long delay at the station.","zh":"儘管在車站久候，他仍保持愉快的心情。"}]},{"word":"humorous","pos":"adj.","phonetic":"[ˈhjumərəs]","meaning":"幽默的；詼諧的","definition":"funny and causing amusement","collocations":["a humorous story","humorous remark","humorous tone"],"example":"She told a humorous story about her trip abroad.","exampleZh":"她講了一個關於她出國旅行的有趣故事。","synonyms":["funny","amusing"],"level":4,"theme":"性質與描述","examples":[{"en":"She told a humorous story about her trip abroad.","zh":"她講了一個關於她出國旅行的有趣故事。"},{"en":"The teacher explained the lesson in a humorous tone.","zh":"老師用幽默的語氣講解這堂課。"},{"en":"His humorous remark made the whole class burst into laughter.","zh":"他幽默的評論讓全班哄堂大笑。"}]},{"word":"hunch","pos":"n.","phonetic":"[hʌntʃ]","meaning":"預感；直覺","definition":"a feeling that something is true without proof","collocations":["have a hunch","follow your hunch","just a hunch"],"example":"I had a hunch that she would win the contest.","exampleZh":"我有預感她會贏得比賽。","synonyms":["feeling","instinct"],"level":5,"theme":"抽象概念","examples":[{"en":"I had a hunch that she would win the contest.","zh":"我有預感她會贏得比賽。"},{"en":"I have a hunch that it will rain later this afternoon.","zh":"我有預感今天下午晚點會下雨。"},{"en":"Sometimes it is wise to follow your hunch when making decisions.","zh":"有時候做決定時，跟隨你的直覺是明智的。"}]},{"word":"hundred","pos":"n.","phonetic":"[ˈhʌndrəd]","meaning":"一百","definition":"the number 100","collocations":["a hundred times","hundreds of people","one hundred percent"],"example":"Hundreds of people gathered to watch the parade.","exampleZh":"數百人聚集觀看遊行。","synonyms":[],"level":1,"theme":"科學與數學","examples":[{"en":"Hundreds of people gathered to watch the parade.","zh":"數百人聚集觀看遊行。"},{"en":"I have told you a hundred times to close the door.","zh":"我已經跟你說過一百次要關門了。"},{"en":"Hundreds of students signed up for the summer camp this year.","zh":"今年有數百名學生報名參加夏令營。"}]},{"word":"hunger","pos":"n.","phonetic":"[ˈhʌŋgɚ]","meaning":"飢餓；渴望","definition":"a feeling caused by the need for food, or a strong desire","collocations":["die of hunger","hunger for knowledge","satisfy hunger"],"example":"The charity works to end world hunger.","exampleZh":"這個慈善機構致力於終結世界飢餓問題。","synonyms":["starvation"],"level":3,"theme":"食物與烹飪","examples":[{"en":"The charity works to end world hunger.","zh":"這個慈善機構致力於終結世界飢餓問題。"},{"en":"A bowl of hot soup helped satisfy his hunger.","zh":"一碗熱湯幫助他滿足了飢餓。"},{"en":"Her hunger for knowledge led her to read every night.","zh":"她對知識的渴望促使她每晚讀書。"}]},{"word":"hungry","pos":"adj.","phonetic":"[ˈhʌŋgrɪ]","meaning":"飢餓的","definition":"feeling a need or desire to eat food","collocations":["feel hungry","hungry for success","go hungry"],"example":"After the long hike, we were all very hungry.","exampleZh":"經過長途健行後,我們都非常餓。","synonyms":["starving"],"level":1,"theme":"身體與健康","examples":[{"en":"After the long hike, we were all very hungry.","zh":"經過長途健行後,我們都非常餓。"},{"en":"The children felt hungry after playing outside all afternoon.","zh":"孩子們在外面玩了一整個下午後感到飢餓。"},{"en":"The young athlete is hungry for success in the coming season.","zh":"這位年輕運動員渴望在即將到來的賽季中取得成功。"}]},{"word":"hunt","pos":"v. / n.","phonetic":"[hʌnt]","meaning":"打獵；搜尋","definition":"to chase and kill animals for food or sport, or to search for something","collocations":["hunt for food","job hunt","hunt down"],"example":"Lions hunt in groups to catch large prey.","exampleZh":"獅子成群結隊地捕獵大型獵物。","synonyms":["chase","pursue"],"level":2,"theme":"動作與行為","examples":[{"en":"Lions hunt in groups to catch large prey.","zh":"獅子成群結隊地捕獵大型獵物。"},{"en":"After graduation, she began a serious job hunt in the city.","zh":"畢業後，她開始在城市裡認真找工作。"},{"en":"In winter, some animals must hunt for food under the snow.","zh":"冬天時，有些動物必須在雪下尋找食物。"}]},{"word":"hunter","pos":"n.","phonetic":"[ˈhʌntɚ]","meaning":"獵人","definition":"a person who hunts wild animals","collocations":["a skilled hunter","hunter and gatherer","bounty hunter"],"example":"The hunter tracked the deer through the forest.","exampleZh":"獵人在森林中追蹤那隻鹿。","synonyms":[],"level":2,"theme":"工作與職業","examples":[{"en":"The hunter tracked the deer through the forest.","zh":"獵人在森林中追蹤那隻鹿。"},{"en":"The skilled hunter knew exactly where the rabbits would hide.","zh":"這位技術高超的獵人清楚知道兔子會躲在哪裡。"},{"en":"Long ago, humans lived as hunters and gatherers in the forest.","zh":"很久以前，人類以狩獵採集者的身分生活在森林裡。"}]},{"word":"hurdle","pos":"n.","phonetic":"[ˈhɝdl̩]","meaning":"障礙；跨欄","definition":"a problem or difficulty that must be overcome, or a barrier in a race","collocations":["overcome a hurdle","clear a hurdle","final hurdle"],"example":"Finding funding was the biggest hurdle for the new business.","exampleZh":"籌措資金是這家新公司最大的障礙。","synonyms":["obstacle","barrier"],"level":6,"theme":"抽象概念","examples":[{"en":"Finding funding was the biggest hurdle for the new business.","zh":"籌措資金是這家新公司最大的障礙。"},{"en":"Passing the interview was the final hurdle before getting the job.","zh":"通過面試是得到這份工作前的最後一道障礙。"},{"en":"The runner cleared every hurdle and won the race easily.","zh":"這名跑者跨過每一個欄架，輕鬆贏得比賽。"}]},{"word":"hurl","pos":"v.","phonetic":"[hɝl]","meaning":"猛力投擲","definition":"to throw something with great force","collocations":["hurl a rock","hurl insults","hurl oneself"],"example":"The protesters hurled bottles at the police.","exampleZh":"抗議者向警方投擲瓶子。","synonyms":["throw","toss"],"level":6,"theme":"動作與行為","examples":[{"en":"The protesters hurled bottles at the police.","zh":"抗議者向警方投擲瓶子。"},{"en":"The angry child hurled his toy across the room.","zh":"那個生氣的孩子把玩具猛力扔過房間。"},{"en":"Waves hurled the small boat against the rocky shore.","zh":"海浪把小船猛力拋向多岩石的岸邊。"}]},{"word":"hurricane","pos":"n.","phonetic":"[ˈhɝɪˌken]","meaning":"颶風","definition":"a violent storm with very strong winds, especially in the Atlantic","collocations":["hurricane warning","strong hurricane","hurricane season"],"example":"The hurricane caused severe flooding along the coast.","exampleZh":"這場颶風造成沿海地區嚴重淹水。","synonyms":["typhoon","storm"],"level":4,"theme":"天氣與季節","examples":[{"en":"The hurricane caused severe flooding along the coast.","zh":"這場颶風造成沿海地區嚴重淹水。"},{"en":"The weather bureau issued a hurricane warning for the whole coast.","zh":"氣象局對整個海岸發布了颶風警報。"},{"en":"Many families prepared food and water before the hurricane season.","zh":"許多家庭在颶風季來臨前準備了食物和水。"}]},{"word":"hurry","pos":"v. / n.","phonetic":"[ˈhɝɪ]","meaning":"匆忙；趕緊","definition":"to move or act quickly","collocations":["hurry up","in a hurry","hurry home"],"example":"We need to hurry, or we'll miss the train.","exampleZh":"我們得快點,不然會錯過火車。","synonyms":["rush"],"level":1,"theme":"動作與行為","examples":[{"en":"We need to hurry, or we'll miss the train.","zh":"我們得快點,不然會錯過火車。"},{"en":"Please hurry up, or we will be late for school.","zh":"請快一點，不然我們上學會遲到。"},{"en":"She was in such a hurry that she forgot her umbrella.","zh":"她匆忙到忘了帶雨傘。"}]},{"word":"hurt","pos":"v. / adj.","phonetic":"[hɝt]","meaning":"傷害；受傷的","definition":"to cause pain or injury, or feeling pain or emotional distress","collocations":["get hurt","hurt someone's feelings","hurt badly"],"example":"She hurt her ankle while playing basketball.","exampleZh":"她打籃球時傷到了腳踝。","synonyms":["injure","wound"],"level":1,"theme":"身體與健康","examples":[{"en":"She hurt her ankle while playing basketball.","zh":"她打籃球時傷到了腳踝。"},{"en":"Be careful with the knife so you don't get hurt.","zh":"小心用刀，這樣你才不會受傷。"},{"en":"His unkind words really hurt his best friend's feelings.","zh":"他不友善的話真的傷了他最好朋友的感情。"}]},{"word":"husband","pos":"n.","phonetic":"[ˈhʌzbənd]","meaning":"丈夫","definition":"a married man in relation to his spouse","collocations":["loving husband","husband and wife","future husband"],"example":"Her husband cooks dinner every night.","exampleZh":"她的丈夫每晚都煮晚餐。","synonyms":[],"level":1,"theme":"人物與家庭","examples":[{"en":"Her husband cooks dinner every night.","zh":"她的丈夫每晚都煮晚餐。"},{"en":"Her husband always helps her wash the dishes after dinner.","zh":"她的丈夫總是在晚餐後幫她洗碗。"},{"en":"As husband and wife, they support each other through hard times.","zh":"身為夫妻，他們在艱難時刻互相扶持。"}]},{"word":"hush","pos":"v. / int.","phonetic":"[hʌʃ]","meaning":"安靜；使安靜","definition":"to make or become silent","collocations":["hush up","hush now","a hush fell"],"example":"A hush fell over the room as the teacher entered.","exampleZh":"老師走進來時,教室裡頓時安靜了下來。","synonyms":["quiet","silence"],"level":5,"theme":"溝通與語言","examples":[{"en":"A hush fell over the room as the teacher entered.","zh":"老師走進來時,教室裡頓時安靜了下來。"},{"en":"The mother gently hushed her crying baby to sleep.","zh":"母親輕輕地哄哭泣的寶寶入睡。"},{"en":"A sudden hush fell over the audience as the lights dimmed.","zh":"燈光變暗時，觀眾突然安靜了下來。"}]},{"word":"husky","pos":"adj. / n.","phonetic":"[ˈhʌskɪ]","meaning":"沙啞的；魁梧的；哈士奇犬","definition":"having a low, rough voice, or big and strong in build","collocations":["husky voice","husky build","Siberian husky"],"example":"He spoke in a husky voice after the long lecture.","exampleZh":"長時間演講後,他的聲音變得沙啞。","synonyms":["hoarse"],"level":6,"theme":"性質與描述","examples":[{"en":"He spoke in a husky voice after the long lecture.","zh":"長時間演講後,他的聲音變得沙啞。"},{"en":"The singer's husky voice made the sad song even more moving.","zh":"這位歌手沙啞的嗓音讓這首悲傷的歌更加動人。"},{"en":"A friendly Siberian husky pulled the sled across the snow.","zh":"一隻友善的西伯利亞哈士奇拉著雪橇越過雪地。"}]},{"word":"hut","pos":"n.","phonetic":"[hʌt]","meaning":"小屋；棚屋","definition":"a small simple shelter or house","collocations":["a straw hut","mountain hut","build a hut"],"example":"The hikers spent the night in a small mountain hut.","exampleZh":"登山客在山上的小屋過了一夜。","synonyms":["cabin","shack"],"level":3,"theme":"居家與生活","examples":[{"en":"The hikers spent the night in a small mountain hut.","zh":"登山客在山上的小屋過了一夜。"},{"en":"The farmer kept his tools inside a small straw hut.","zh":"農夫把工具放在一間小小的稻草棚屋裡。"},{"en":"We built a simple hut on the beach out of driftwood.","zh":"我們用漂流木在海灘上搭了一間簡陋的小屋。"}]},{"word":"hybrid","pos":"n. / adj.","phonetic":"[ˈhaɪbrɪd]","meaning":"混合物；混種的","definition":"something made by combining two different things, such as plants, animals, or technologies","collocations":["hybrid car","hybrid species","hybrid model"],"example":"The company now produces a popular hybrid car.","exampleZh":"這家公司現在生產一款熱門的油電混合車。","synonyms":["mixture"],"level":6,"theme":"科學與數學","examples":[{"en":"The company now produces a popular hybrid car.","zh":"這家公司現在生產一款熱門的油電混合車。"},{"en":"Many drivers choose a hybrid car to save on fuel.","zh":"許多駕駛人選擇油電混合車以節省燃料。"},{"en":"Scientists created a new hybrid species of rose in the lab.","zh":"科學家在實驗室裡培育出一種新的玫瑰混種。"}]},{"word":"hydrogen","pos":"n.","phonetic":"[ˈhaɪdrədʒən]","meaning":"氫","definition":"a colorless gas that is the lightest chemical element","collocations":["hydrogen gas","hydrogen fuel","hydrogen atom"],"example":"Water is made up of hydrogen and oxygen atoms.","exampleZh":"水是由氫原子和氧原子組成的。","synonyms":[],"level":5,"theme":"科學與數學","examples":[{"en":"Water is made up of hydrogen and oxygen atoms.","zh":"水是由氫原子和氧原子組成的。"},{"en":"Some future cars may run on clean hydrogen fuel.","zh":"未來有些汽車可能會使用乾淨的氫燃料。"},{"en":"A water molecule contains two hydrogen atoms and one oxygen atom.","zh":"一個水分子含有兩個氫原子和一個氧原子。"}]},{"word":"hygiene","pos":"n.","phonetic":"[ˈhaɪdʒin]","meaning":"衛生；保健","definition":"practices that keep people and places clean and healthy","collocations":["personal hygiene","dental hygiene","hygiene standards"],"example":"Good personal hygiene helps prevent illness.","exampleZh":"良好的個人衛生有助於預防疾病。","synonyms":["cleanliness"],"level":5,"theme":"身體與健康","examples":[{"en":"Good personal hygiene helps prevent illness.","zh":"良好的個人衛生有助於預防疾病。"},{"en":"Washing your hands often is an important part of personal hygiene.","zh":"勤洗手是個人衛生的重要一環。"},{"en":"The restaurant follows strict hygiene standards in its kitchen.","zh":"這家餐廳的廚房遵守嚴格的衛生標準。"}]},{"word":"hymn","pos":"n.","phonetic":"[hɪm]","meaning":"讚美詩；聖歌","definition":"a religious song of praise, typically sung in church","collocations":["sing a hymn","church hymn","hymn book"],"example":"The congregation sang a hymn together during the service.","exampleZh":"會眾在禮拜中一起唱了一首聖歌。","synonyms":["anthem"],"level":5,"theme":"藝術與音樂","examples":[{"en":"The congregation sang a hymn together during the service.","zh":"會眾在禮拜中一起唱了一首聖歌。"},{"en":"The choir practiced a beautiful hymn for Sunday's service.","zh":"唱詩班為週日的禮拜練習了一首優美的聖歌。"},{"en":"She opened the hymn book and began to sing softly.","zh":"她翻開讚美詩集，開始輕聲歌唱。"}]},{"word":"hyphen","pos":"n.","phonetic":"[ˈhaɪfən]","meaning":"連字號","definition":"the punctuation mark (-) used to join words or parts of words","collocations":["insert a hyphen","hyphenated word","use a hyphen"],"example":"The word 'well-known' is written with a hyphen.","exampleZh":"「well-known」這個詞是用連字號寫的。","synonyms":[],"level":5,"theme":"溝通與語言","examples":[{"en":"The word 'well-known' is written with a hyphen.","zh":"「well-known」這個詞是用連字號寫的。"},{"en":"Remember to insert a hyphen between the two parts of the word.","zh":"記得在這個字的兩個部分之間加上連字號。"},{"en":"The teacher explained when to use a hyphen in English.","zh":"老師解釋了在英文中何時使用連字號。"}]},{"word":"hypothesis","pos":"n.","phonetic":"[haɪˈpɑθəsɪs]","meaning":"假設；假說","definition":"an idea or explanation that is tested through study and experimentation","collocations":["test a hypothesis","propose a hypothesis","working hypothesis"],"example":"The scientist designed an experiment to test her hypothesis.","exampleZh":"這位科學家設計了一個實驗來驗證她的假設。","synonyms":["theory","assumption"],"level":6,"theme":"科學與數學","examples":[{"en":"The scientist designed an experiment to test her hypothesis.","zh":"這位科學家設計了一個實驗來驗證她的假設。"},{"en":"The students designed an experiment to test their hypothesis.","zh":"學生們設計了一個實驗來檢驗他們的假設。"},{"en":"The professor proposed a new hypothesis about how bees communicate.","zh":"教授提出了一個關於蜜蜂如何溝通的新假說。"}]},{"word":"hysterical","pos":"adj.","phonetic":"[hɪsˈtɛrɪkl̩]","meaning":"歇斯底里的；情緒失控的","definition":"showing extreme, uncontrolled emotion","collocations":["hysterical laughter","become hysterical","hysterical crowd"],"example":"She became hysterical when she heard the shocking news.","exampleZh":"她聽到這個震驚的消息後變得歇斯底里。","synonyms":["frantic"],"level":6,"theme":"情緒與感受","examples":[{"en":"She became hysterical when she heard the shocking news.","zh":"她聽到這個震驚的消息後變得歇斯底里。"},{"en":"The comedy was so funny that the audience broke into hysterical laughter.","zh":"這齣喜劇太好笑了，觀眾爆出歇斯底里的大笑。"},{"en":"She became hysterical when she could not find her lost child.","zh":"當她找不到走失的孩子時，變得歇斯底里。"}]},{"word":"icicle","pos":"n.","phonetic":"[ˈaɪsɪkl̩]","meaning":"冰柱","definition":"a hanging spike of ice formed by dripping water that freezes","collocations":["icicles hang from the roof","form icicles"],"example":"Icicles hung from the roof in winter.","exampleZh":"冬天屋簷下掛著冰柱。","synonyms":[],"level":3,"theme":"天氣與季節","examples":[{"en":"Icicles hung from the roof in winter.","zh":"冬天屋簷下掛著冰柱。"},{"en":"Long icicles hung from the roof after the freezing night.","zh":"在寒冷的夜晚過後，長長的冰柱從屋頂垂下來。"},{"en":"Icicles began to form along the edge of the window.","zh":"冰柱開始在窗戶邊緣形成。"}]},{"word":"icon","pos":"n.","phonetic":"[ˈaɪkɑn]","meaning":"圖示；偶像；聖像","definition":"a symbol or image, especially one shown on a computer screen","collocations":["click an icon","a cultural icon","fashion icon"],"example":"Click the icon to open the app.","exampleZh":"點擊圖示以開啟應用程式。","synonyms":["symbol","idol"],"level":4,"theme":"科技與媒體","examples":[{"en":"Click the icon to open the app.","zh":"點擊圖示以開啟應用程式。"},{"en":"Double-click the icon on the screen to start the program.","zh":"在螢幕上雙擊這個圖示以啟動程式。"},{"en":"The singer became a cultural icon for her generation.","zh":"這位歌手成為她那個世代的文化偶像。"}]},{"word":"icy","pos":"adj.","phonetic":"[ˈaɪsi]","meaning":"冰冷的；結冰的","definition":"covered with or as cold as ice","collocations":["icy road","icy wind","icy stare"],"example":"The roads were icy after the snowstorm.","exampleZh":"暴風雪過後道路結冰了。","synonyms":["freezing","frosty"],"level":2,"theme":"天氣與季節","examples":[{"en":"The roads were icy after the snowstorm.","zh":"暴風雪過後道路結冰了。"},{"en":"Drivers must slow down on the icy road in winter.","zh":"冬天在結冰的路面上駕駛人必須放慢速度。"},{"en":"An icy wind blew across the empty playground.","zh":"一陣冰冷的風吹過空蕩蕩的操場。"}]},{"word":"idea","pos":"n.","phonetic":"[aɪˈdiə]","meaning":"想法；主意；概念","definition":"a thought, plan, or suggestion","collocations":["have an idea","a good idea","share ideas"],"example":"She had a great idea for the project.","exampleZh":"她對這個專案有個好主意。","synonyms":["thought","notion"],"level":1,"theme":"教育與學習","examples":[{"en":"She had a great idea for the project.","zh":"她對這個專案有個好主意。"},{"en":"We often share ideas during our weekly group meetings.","zh":"我們在每週的小組會議中經常分享想法。"},{"en":"Going to the beach on such a hot day is a good idea.","zh":"在這麼熱的日子去海邊是個好主意。"}]},{"word":"ideal","pos":"adj. / n.","phonetic":"[aɪˈdiəl]","meaning":"理想的；理想","definition":"most suitable; a perfect example of something","collocations":["ideal solution","ideal for","an ideal world"],"example":"This job is ideal for a recent graduate.","exampleZh":"這份工作非常適合應屆畢業生。","synonyms":["perfect","best"],"level":3,"theme":"抽象概念","examples":[{"en":"This job is ideal for a recent graduate.","zh":"這份工作非常適合應屆畢業生。"},{"en":"This quiet park is ideal for studying on weekends.","zh":"這座安靜的公園非常適合週末讀書。"},{"en":"In an ideal world, everyone would have enough food to eat.","zh":"在理想的世界裡，每個人都有足夠的食物可吃。"}]},{"word":"identical","pos":"adj.","phonetic":"[aɪˈdɛntɪkl̩]","meaning":"完全相同的","definition":"exactly alike; the same in every detail","collocations":["identical twins","identical copies"],"example":"The twins wore identical outfits.","exampleZh":"這對雙胞胎穿著一模一樣的衣服。","synonyms":["same","alike"],"level":4,"theme":"性質與描述","examples":[{"en":"The twins wore identical outfits.","zh":"這對雙胞胎穿著一模一樣的衣服。"},{"en":"The two sisters are identical twins and look exactly alike.","zh":"這對姊妹是同卵雙胞胎，長得一模一樣。"},{"en":"The printer made ten identical copies of the report.","zh":"印表機印出了十份完全相同的報告。"}]},{"word":"identify","pos":"v.","phonetic":"[aɪˈdɛntəˌfaɪ]","meaning":"識別；確認身份","definition":"to recognize or establish who or what someone or something is","collocations":["identify a problem","identify oneself","identify with"],"example":"Police asked him to identify the suspect.","exampleZh":"警方要求他指認嫌犯。","synonyms":["recognize","distinguish"],"level":4,"theme":"溝通與語言","examples":[{"en":"Police asked him to identify the suspect.","zh":"警方要求他指認嫌犯。"},{"en":"Scientists work hard to identify the cause of the disease.","zh":"科學家努力找出這種疾病的原因。"},{"en":"Visitors must identify themselves at the front gate.","zh":"訪客必須在大門口表明自己的身分。"}]},{"word":"identity","pos":"n.","phonetic":"[aɪˈdɛntəti]","meaning":"身份；特性","definition":"who a person is, or the characteristics that define someone","collocations":["national identity","prove one's identity","identity card"],"example":"He had to show ID to prove his identity.","exampleZh":"他必須出示證件證明身份。","synonyms":[],"level":4,"theme":"社會與文化","examples":[{"en":"He had to show ID to prove his identity.","zh":"他必須出示證件證明身份。"},{"en":"You need to show your identity card to enter the library.","zh":"你需要出示身分證才能進入圖書館。"},{"en":"Learning our history helps build a strong national identity.","zh":"學習我們的歷史有助於建立強烈的民族認同。"}]},{"word":"idiom","pos":"n.","phonetic":"[ˈɪdiəm]","meaning":"慣用語；成語","definition":"a phrase whose meaning cannot be understood from the individual words","collocations":["an English idiom","learn idioms","a common idiom"],"example":"\"Break the ice\" is a common idiom.","exampleZh":"「打破僵局」是常見的慣用語。","synonyms":["expression","phrase"],"level":5,"theme":"溝通與語言","examples":[{"en":"\"Break the ice\" is a common idiom.","zh":"「打破僵局」是常見的慣用語。"},{"en":"Learning idioms can make your English sound more natural.","zh":"學習慣用語能讓你的英文聽起來更自然。"},{"en":"The phrase \"a piece of cake\" is a common English idiom.","zh":"「a piece of cake」是一個常見的英文慣用語。"}]},{"word":"idle","pos":"adj. / v.","phonetic":"[ˈaɪdl̩]","meaning":"閒置的；懶惰的；空轉","definition":"not working or being used; lazy","collocations":["sit idle","an idle machine","idle talk"],"example":"The factory has been idle for months.","exampleZh":"這家工廠已經停工好幾個月了。","synonyms":["inactive","lazy"],"level":4,"theme":"性質與描述","examples":[{"en":"The factory has been idle for months.","zh":"這家工廠已經停工好幾個月了。"},{"en":"The old machines sat idle in the corner of the factory.","zh":"那些舊機器閒置在工廠的角落裡。"},{"en":"Don't waste the whole afternoon in idle talk.","zh":"別把整個下午浪費在閒聊上。"}]},{"word":"idol","pos":"n.","phonetic":"[ˈaɪdl̩]","meaning":"偶像","definition":"a person who is greatly admired","collocations":["pop idol","teen idol","worship an idol"],"example":"She is a pop idol among teenagers.","exampleZh":"她是青少年心中的流行偶像。","synonyms":["star","hero"],"level":3,"theme":"藝術與音樂","examples":[{"en":"She is a pop idol among teenagers.","zh":"她是青少年心中的流行偶像。"},{"en":"The young singer quickly became a teen idol across the country.","zh":"這位年輕歌手很快就成為全國的青少年偶像。"},{"en":"Many fans lined up for hours to meet their favorite idol.","zh":"許多粉絲排隊數小時只為見到他們最喜愛的偶像。"}]},{"word":"if","pos":"conj.","phonetic":"[ɪf]","meaning":"如果；假如","definition":"on the condition that; supposing that","collocations":["if possible","even if","as if"],"example":"If it rains, we will stay home.","exampleZh":"如果下雨，我們就待在家裡。","synonyms":[],"level":1,"theme":"抽象概念","examples":[{"en":"If it rains, we will stay home.","zh":"如果下雨，我們就待在家裡。"},{"en":"If possible, please finish your homework before dinner.","zh":"如果可以的話，請在晚餐前完成你的作業。"},{"en":"Even if it snows tomorrow, the game will still be played.","zh":"即使明天下雪，比賽仍會照常進行。"}]},{"word":"ignite","pos":"v.","phonetic":"[ɪɡˈnaɪt]","meaning":"點燃；引發","definition":"to set something on fire or start something intense","collocations":["ignite a fire","ignite a debate","ignite passion"],"example":"The spark ignited the dry grass instantly.","exampleZh":"火花瞬間點燃了乾草。","synonyms":["kindle","spark"],"level":4,"theme":"科學與數學","examples":[{"en":"The spark ignited the dry grass instantly.","zh":"火花瞬間點燃了乾草。"},{"en":"A single match can ignite a huge fire in a dry forest.","zh":"一根火柴就能在乾燥的森林裡引發熊熊大火。"},{"en":"The teacher's story ignited the students' passion for science.","zh":"老師的故事點燃了學生對科學的熱情。"}]},{"word":"ignorant","pos":"adj.","phonetic":"[ˈɪgnərənt]","meaning":"無知的","definition":"lacking knowledge or awareness of something","collocations":["ignorant of","remain ignorant","ignorant about"],"example":"He was ignorant of the local customs.","exampleZh":"他對當地習俗一無所知。","synonyms":["uninformed","unaware"],"level":5,"theme":"性質與描述","examples":[{"en":"He was ignorant of the local customs.","zh":"他對當地習俗一無所知。"},{"en":"Many tourists are ignorant of the local traffic rules.","zh":"許多遊客對當地的交通規則一無所知。"},{"en":"We should not remain ignorant about environmental problems.","zh":"我們不應該對環境問題一直保持無知。"}]},{"word":"ignore","pos":"v.","phonetic":"[ɪgˈnɔr]","meaning":"忽視；不理睬","definition":"to pay no attention to something or someone","collocations":["ignore advice","ignore a warning","ignore the rules"],"example":"He ignored the warning sign.","exampleZh":"他忽視了警告標誌。","synonyms":["overlook","disregard"],"level":2,"theme":"動作與行為","examples":[{"en":"He ignored the warning sign.","zh":"他忽視了警告標誌。"},{"en":"You should never ignore a warning about severe weather.","zh":"你絕不該忽視關於惡劣天氣的警告。"},{"en":"He ignored his doctor's advice and kept eating junk food.","zh":"他忽視醫生的建議，繼續吃垃圾食物。"}]},{"word":"ill","pos":"adj.","phonetic":"[ɪl]","meaning":"生病的","definition":"not in good health; sick","collocations":["fall ill","seriously ill","feel ill"],"example":"She felt ill after eating the fish.","exampleZh":"她吃了魚之後覺得不舒服。","synonyms":["sick","unwell"],"level":1,"theme":"身體與健康","examples":[{"en":"She felt ill after eating the fish.","zh":"她吃了魚之後覺得不舒服。"},{"en":"She suddenly fell ill during the long train journey.","zh":"她在漫長的火車旅程中突然生病了。"},{"en":"If you feel ill, you should stay home and rest.","zh":"如果你覺得不舒服，就應該待在家裡休息。"}]},{"word":"illegal","pos":"adj.","phonetic":"[ɪˈligl̩]","meaning":"非法的","definition":"not allowed by law","collocations":["illegal parking","illegal drugs","illegal immigrant"],"example":"It is illegal to drive without a license.","exampleZh":"無照駕駛是違法的。","synonyms":["unlawful"],"level":3,"theme":"政治與法律","examples":[{"en":"It is illegal to drive without a license.","zh":"無照駕駛是違法的。"},{"en":"The police gave him a ticket for illegal parking.","zh":"警察因他違規停車而開了罰單。"},{"en":"It is illegal to sell these products without a license.","zh":"沒有執照販售這些產品是違法的。"}]},{"word":"illness","pos":"n.","phonetic":"[ˈɪlnɪs]","meaning":"疾病","definition":"a disease or period of poor health","collocations":["serious illness","recover from illness","mental illness"],"example":"He missed school due to illness.","exampleZh":"他因生病而沒去上學。","synonyms":["sickness","disease"],"level":2,"theme":"身體與健康","examples":[{"en":"He missed school due to illness.","zh":"他因生病而沒去上學。"},{"en":"He is slowly recovering from a serious illness.","zh":"他正慢慢從一場重病中康復。"},{"en":"More people are learning about mental illness these days.","zh":"現在越來越多人開始了解精神疾病。"}]},{"word":"illuminate","pos":"v.","phonetic":"[ɪˈlumɪˌnet]","meaning":"照亮；闡明","definition":"to light something up or make something clear","collocations":["illuminate a room","illuminate the truth"],"example":"Lanterns illuminated the narrow street at night.","exampleZh":"燈籠在夜裡照亮了狹窄的街道。","synonyms":["brighten","clarify"],"level":5,"theme":"科學與數學","examples":[{"en":"Lanterns illuminated the narrow street at night.","zh":"燈籠在夜裡照亮了狹窄的街道。"},{"en":"Bright lanterns illuminated the temple during the festival.","zh":"明亮的燈籠在節慶期間照亮了寺廟。"},{"en":"The professor's example helped illuminate a difficult idea.","zh":"教授的例子有助於闡明一個艱深的概念。"}]},{"word":"illusion","pos":"n.","phonetic":"[ɪˈluʒən]","meaning":"幻覺；錯覺","definition":"a false idea or belief, or something that appears different from reality","collocations":["an optical illusion","under the illusion that"],"example":"The magician created the illusion of flying.","exampleZh":"魔術師製造出飛翔的幻覺。","synonyms":["fantasy","delusion"],"level":5,"theme":"抽象概念","examples":[{"en":"The magician created the illusion of flying.","zh":"魔術師製造出飛翔的幻覺。"},{"en":"The clever drawing creates an optical illusion of movement.","zh":"這幅巧妙的畫作製造出一種運動的錯覺。"},{"en":"He was under the illusion that he could pass without studying.","zh":"他抱著不用讀書就能及格的錯覺。"}]},{"word":"illustrate","pos":"v.","phonetic":"[ˈɪləˌstret]","meaning":"說明；圖解","definition":"to explain or make clear by using examples, pictures, or diagrams","collocations":["illustrate a point","illustrate a book","clearly illustrate"],"example":"The teacher used a diagram to illustrate the process.","exampleZh":"老師用圖表來說明這個過程。","synonyms":["demonstrate","depict"],"level":4,"theme":"教育與學習","examples":[{"en":"The teacher used a diagram to illustrate the process.","zh":"老師用圖表來說明這個過程。"},{"en":"The speaker used a simple story to illustrate her point.","zh":"講者用一個簡單的故事來說明她的論點。"},{"en":"A talented artist illustrated the children's storybook.","zh":"一位才華洋溢的藝術家為這本兒童故事書畫插圖。"}]},{"word":"illustration","pos":"n.","phonetic":"[ˌɪləˈstreʃən]","meaning":"插圖；例證","definition":"a picture in a book, or an example that makes something clear","collocations":["colorful illustrations","a clear illustration","book illustrations"],"example":"The book is full of beautiful illustrations.","exampleZh":"這本書裡滿是精美的插圖。","synonyms":["picture","example"],"level":4,"theme":"藝術與音樂","examples":[{"en":"The book is full of beautiful illustrations.","zh":"這本書裡滿是精美的插圖。"},{"en":"The science textbook has many colorful illustrations.","zh":"這本自然課本有許多色彩繽紛的插圖。"},{"en":"Her essay gave a clear illustration of how recycling works.","zh":"她的文章清楚地說明了回收是如何運作的。"}]},{"word":"image","pos":"n.","phonetic":"[ˈɪmɪdʒ]","meaning":"影像；形象","definition":"a picture or representation of something; the impression people have of someone","collocations":["public image","mirror image","a clear image"],"example":"The company wants to improve its public image.","exampleZh":"這家公司想改善其公眾形象。","synonyms":["picture","impression"],"level":3,"theme":"科技與媒體","examples":[{"en":"The company wants to improve its public image.","zh":"這家公司想改善其公眾形象。"},{"en":"The new telescope produced a clear image of the distant moon.","zh":"這台新望遠鏡拍出了遙遠月球的清晰影像。"},{"en":"The company hired a designer to improve its public image.","zh":"這家公司聘請設計師來提升公司的公眾形象。"}]},{"word":"imaginary","pos":"adj.","phonetic":"[ɪˈmædʒəˌnɛri]","meaning":"想像的；虛構的","definition":"existing only in the mind, not real","collocations":["an imaginary friend","imaginary line"],"example":"Many children have imaginary friends.","exampleZh":"許多孩子都有想像中的朋友。","synonyms":["fictional","unreal"],"level":3,"theme":"抽象概念","examples":[{"en":"Many children have imaginary friends.","zh":"許多孩子都有想像中的朋友。"},{"en":"The equator is an imaginary line around the middle of the Earth.","zh":"赤道是環繞地球中間的一條假想線。"},{"en":"As a child, he often played with an imaginary friend.","zh":"小時候，他常常和一個想像中的朋友玩耍。"}]},{"word":"imagination","pos":"n.","phonetic":"[ɪˌmædʒəˈneʃən]","meaning":"想像力","definition":"the ability to form new ideas or pictures in the mind","collocations":["use one's imagination","a vivid imagination","fire the imagination"],"example":"Children have a rich imagination.","exampleZh":"孩子們擁有豐富的想像力。","synonyms":["creativity"],"level":3,"theme":"教育與學習","examples":[{"en":"Children have a rich imagination.","zh":"孩子們擁有豐富的想像力。"},{"en":"Writing stories is a great way to use your imagination.","zh":"寫故事是運用想像力的好方法。"},{"en":"The young painter has a truly vivid imagination.","zh":"這位年輕畫家擁有非常豐富的想像力。"}]},{"word":"imagine","pos":"v.","phonetic":"[ɪˈmædʒɪn]","meaning":"想像","definition":"to form a picture or idea of something in the mind","collocations":["imagine a scene","can't imagine","just imagine"],"example":"Try to imagine life without electricity.","exampleZh":"試著想像沒有電的生活。","synonyms":["picture","envision"],"level":2,"theme":"教育與學習","examples":[{"en":"Try to imagine life without electricity.","zh":"試著想像沒有電的生活。"},{"en":"I can't imagine living in a city without any parks.","zh":"我無法想像住在一個沒有任何公園的城市裡。"},{"en":"Just imagine how peaceful life on that quiet island would be.","zh":"想像一下在那座寧靜島嶼上的生活會多麼平靜。"}]},{"word":"imitate","pos":"v.","phonetic":"[ˈɪməˌtet]","meaning":"模仿","definition":"to copy the behavior, appearance, or sound of someone or something","collocations":["imitate a voice","imitate an artist","imitate behavior"],"example":"Children often imitate their parents.","exampleZh":"孩子們常常模仿父母。","synonyms":["copy","mimic"],"level":4,"theme":"動作與行為","examples":[{"en":"Children often imitate their parents.","zh":"孩子們常常模仿父母。"},{"en":"The clever parrot can imitate the voice of its owner.","zh":"這隻聰明的鸚鵡能模仿主人的聲音。"},{"en":"Young players often imitate the moves of famous athletes.","zh":"年輕球員常常模仿知名運動員的動作。"}]},{"word":"imitation","pos":"n.","phonetic":"[ˌɪməˈteʃən]","meaning":"模仿；仿製品","definition":"the act of copying something, or a copy of the real thing","collocations":["a cheap imitation","in imitation of","imitation leather"],"example":"The bag is a cheap imitation of the real one.","exampleZh":"這個包包是仿冒品。","synonyms":["copy","replica"],"level":4,"theme":"抽象概念","examples":[{"en":"The bag is a cheap imitation of the real one.","zh":"這個包包是仿冒品。"},{"en":"The belt is made of imitation leather, not the real thing.","zh":"這條皮帶是仿皮製成的，不是真皮。"},{"en":"The painting is only a cheap imitation of a famous work.","zh":"這幅畫只是一幅名作的廉價仿製品。"}]},{"word":"immediate","pos":"adj.","phonetic":"[ɪˈmidiɪt]","meaning":"立即的","definition":"happening or done right away","collocations":["immediate action","immediate response","in the immediate future"],"example":"The situation requires immediate attention.","exampleZh":"這個情況需要立即處理。","synonyms":["instant","prompt"],"level":4,"theme":"時間與空間","examples":[{"en":"The situation requires immediate attention.","zh":"這個情況需要立即處理。"},{"en":"The fire alarm demands immediate action from everyone.","zh":"火災警報要求每個人立即採取行動。"},{"en":"We do not expect any big changes in the immediate future.","zh":"我們預期在近期內不會有任何重大改變。"}]},{"word":"immediately","pos":"adv.","phonetic":"[ɪˈmidiɪtli]","meaning":"立刻地","definition":"at once; without delay","collocations":["act immediately","leave immediately","respond immediately"],"example":"Please respond immediately.","exampleZh":"請立刻回覆。","synonyms":["instantly","at once"],"level":3,"theme":"時間與空間","examples":[{"en":"Please respond immediately.","zh":"請立刻回覆。"},{"en":"When the bell rang, the students left the classroom immediately.","zh":"鐘聲一響，學生們立刻離開了教室。"},{"en":"The nurse responded immediately to the patient's call.","zh":"護士立刻回應了病人的呼叫。"}]},{"word":"immense","pos":"adj.","phonetic":"[ɪˈmɛns]","meaning":"巨大的；廣大的","definition":"extremely large in size or degree","collocations":["immense pressure","an immense amount of"],"example":"The team faced immense pressure before the final match.","exampleZh":"球隊在決賽前面臨巨大的壓力。","synonyms":["huge","enormous"],"level":4,"theme":"性質與描述","examples":[{"en":"The team faced immense pressure before the final match.","zh":"球隊在決賽前面臨巨大的壓力。"},{"en":"The rescue workers put in an immense amount of effort.","zh":"救援人員付出了巨大的努力。"},{"en":"Students often feel immense pressure before important exams.","zh":"學生在重要考試前常感受到巨大的壓力。"}]},{"word":"immigrant","pos":"n.","phonetic":"[ˈɪməgrənt]","meaning":"移民","definition":"a person who comes to live permanently in a foreign country","collocations":["illegal immigrant","immigrant family","immigrant community"],"example":"Many immigrants come to the city for work.","exampleZh":"許多移民來到這座城市工作。","synonyms":["settler"],"level":5,"theme":"社會與文化","examples":[{"en":"Many immigrants come to the city for work.","zh":"許多移民來到這座城市工作。"},{"en":"The immigrant family opened a small restaurant in the town.","zh":"這個移民家庭在鎮上開了一家小餐館。"},{"en":"The city has a large immigrant community from many countries.","zh":"這座城市有一個來自許多國家的龐大移民社群。"}]},{"word":"immigrate","pos":"v.","phonetic":"[ˈɪməˌgret]","meaning":"移居；移民","definition":"to move to another country in order to live there permanently","collocations":["immigrate to a country","immigrate from"],"example":"They immigrated to Canada last year.","exampleZh":"他們去年移民到加拿大。","synonyms":["relocate"],"level":5,"theme":"社會與文化","examples":[{"en":"They immigrated to Canada last year.","zh":"他們去年移民到加拿大。"},{"en":"Her grandparents immigrated to this country fifty years ago.","zh":"她的祖父母五十年前移民到這個國家。"},{"en":"Many families immigrate from rural areas in search of jobs.","zh":"許多家庭從鄉村地區移居他處以尋找工作。"}]},{"word":"impact","pos":"n. / v.","phonetic":"[ˈɪmpækt]","meaning":"衝擊；影響","definition":"a strong effect or influence on something","collocations":["have an impact on","environmental impact","make an impact"],"example":"The new policy will have a big impact on farmers.","exampleZh":"這項新政策將對農民造成重大影響。","synonyms":["effect","influence"],"level":4,"theme":"抽象概念","examples":[{"en":"The new policy will have a big impact on farmers.","zh":"這項新政策將對農民造成重大影響。"},{"en":"Social media has a huge impact on how teenagers think.","zh":"社群媒體對青少年的思考方式有巨大的影響。"},{"en":"The factory tried to reduce its environmental impact.","zh":"這家工廠試圖減少對環境的衝擊。"}]},{"word":"impartial","pos":"adj.","phonetic":"[ɪmˈpɑrʃəl]","meaning":"公正的；不偏袒的","definition":"treating all sides fairly, not biased","collocations":["an impartial judge","remain impartial"],"example":"A good referee must remain impartial during the game.","exampleZh":"好的裁判在比賽中必須保持公正。","synonyms":["fair","neutral"],"level":5,"theme":"政治與法律","examples":[{"en":"A good referee must remain impartial during the game.","zh":"好的裁判在比賽中必須保持公正。"},{"en":"An impartial judge listens carefully to both sides of the story.","zh":"公正的法官會仔細聆聽故事的雙方說法。"},{"en":"A good reporter should remain impartial when covering the news.","zh":"好的記者在報導新聞時應該保持公正。"}]},{"word":"impatience","pos":"n.","phonetic":"[ɪmˈpeʃəns]","meaning":"不耐煩","definition":"the state or feeling of being impatient","collocations":["show impatience","out of impatience","sigh with impatience"],"example":"She sighed with impatience.","exampleZh":"她不耐煩地嘆了口氣。","synonyms":["restlessness"],"level":4,"theme":"情緒與感受","examples":[{"en":"She sighed with impatience.","zh":"她不耐煩地嘆了口氣。"},{"en":"He tapped his foot, showing his impatience at the long wait.","zh":"他不停地跺腳，顯露出對久候的不耐煩。"},{"en":"Out of impatience, she opened the gift before her birthday.","zh":"出於不耐煩，她在生日前就拆開了禮物。"}]},{"word":"impatient","pos":"adj.","phonetic":"[ɪmˈpeʃənt]","meaning":"不耐煩的","definition":"not willing to wait calmly or tolerate delay","collocations":["get impatient","impatient with","grow impatient"],"example":"He became impatient waiting in line.","exampleZh":"他排隊等候時變得不耐煩。","synonyms":["restless"],"level":3,"theme":"情緒與感受","examples":[{"en":"He became impatient waiting in line.","zh":"他排隊等候時變得不耐煩。"},{"en":"The passengers grew impatient as the bus was badly delayed.","zh":"公車嚴重誤點，乘客們變得不耐煩。"},{"en":"Try not to be impatient with your younger brother.","zh":"盡量不要對你的弟弟不耐煩。"}]},{"word":"imperial","pos":"adj.","phonetic":"[ɪmˈpɪriəl]","meaning":"帝國的；皇家的","definition":"relating to an empire or its ruler","collocations":["imperial palace","imperial rule"],"example":"Tourists visited the old imperial palace in the city.","exampleZh":"遊客們參觀了城裡古老的皇宮。","synonyms":["royal","regal"],"level":5,"theme":"社會與文化","examples":[{"en":"Tourists visited the old imperial palace in the city.","zh":"遊客們參觀了城裡古老的皇宮。"},{"en":"The old imperial palace is now a popular museum.","zh":"那座古老的皇宮如今是一座熱門的博物館。"},{"en":"Under imperial rule, ordinary people had very little power.","zh":"在帝國統治下，一般百姓幾乎沒有權力。"}]},{"word":"implement","pos":"v. / n.","phonetic":"[ˈɪmpləˌmɛnt]","meaning":"實施；工具","definition":"to put a plan into action, or a tool used for a task","collocations":["implement a policy","farm implements"],"example":"The school will implement the new rules next semester.","exampleZh":"學校下學期將實施新規定。","synonyms":["execute","carry out"],"level":5,"theme":"工作與職業","examples":[{"en":"The school will implement the new rules next semester.","zh":"學校下學期將實施新規定。"},{"en":"The city will implement a new recycling policy next month.","zh":"這座城市下個月將實施新的回收政策。"},{"en":"The old farmer kept his simple implements in the shed.","zh":"這位老農夫把他簡單的農具放在棚子裡。"}]},{"word":"implication","pos":"n.","phonetic":"[ˌɪmplɪˈkeʃən]","meaning":"含意；影響","definition":"a possible effect or meaning that is not directly stated","collocations":["serious implications","the implications of a decision"],"example":"The report examined the implications of climate change.","exampleZh":"這份報告探討了氣候變遷的影響。","synonyms":["consequence","effect"],"level":6,"theme":"抽象概念","examples":[{"en":"The report examined the implications of climate change.","zh":"這份報告探討了氣候變遷的影響。"},{"en":"The teacher explained the serious implications of cheating.","zh":"老師解釋了作弊的嚴重後果。"},{"en":"We must carefully consider the implications of this decision.","zh":"我們必須仔細考慮這個決定的影響。"}]},{"word":"imply","pos":"v.","phonetic":"[ɪmˈplaɪ]","meaning":"暗示","definition":"to suggest something without saying it directly","collocations":["imply that","strongly imply","seem to imply"],"example":"Her silence implied disagreement.","exampleZh":"她的沉默暗示了不同意。","synonyms":["suggest","hint"],"level":5,"theme":"溝通與語言","examples":[{"en":"Her silence implied disagreement.","zh":"她的沉默暗示了不同意。"},{"en":"Her smile seemed to imply that she already knew the answer.","zh":"她的微笑似乎暗示她已經知道答案了。"},{"en":"The report strongly implies that more research is needed.","zh":"這份報告強烈暗示需要更多的研究。"}]},{"word":"impolite","pos":"adj.","phonetic":"[ˌɪmpəˈlaɪt]","meaning":"不禮貌的","definition":"not having good manners; rude","collocations":["impolite behavior","impolite to interrupt","rather impolite"],"example":"It's impolite to interrupt others.","exampleZh":"打斷別人說話是不禮貌的。","synonyms":["rude"],"level":3,"theme":"性質與描述","examples":[{"en":"It's impolite to interrupt others.","zh":"打斷別人說話是不禮貌的。"},{"en":"It is impolite to talk loudly on the phone in the library.","zh":"在圖書館大聲講電話是不禮貌的。"},{"en":"His impolite behavior at dinner upset the whole family.","zh":"他在晚餐時不禮貌的舉止讓全家人都不高興。"}]},{"word":"importance","pos":"n.","phonetic":"[ɪmˈpɔrtns̩]","meaning":"重要性","definition":"the state or quality of being important","collocations":["of great importance","stress the importance","realize the importance"],"example":"Teachers stress the importance of reading.","exampleZh":"老師們強調閱讀的重要性。","synonyms":["significance"],"level":3,"theme":"抽象概念","examples":[{"en":"Teachers stress the importance of reading.","zh":"老師們強調閱讀的重要性。"},{"en":"The coach always stresses the importance of teamwork.","zh":"教練總是強調團隊合作的重要性。"},{"en":"Only later did she realize the importance of saving money.","zh":"直到後來她才意識到儲蓄的重要性。"}]},{"word":"important","pos":"adj.","phonetic":"[ɪmˈpɔrtnt]","meaning":"重要的","definition":"of great value, significance, or effect","collocations":["important decision","important role","important information"],"example":"Education is important for the future.","exampleZh":"教育對未來很重要。","synonyms":["significant","essential"],"level":1,"theme":"性質與描述","examples":[{"en":"Education is important for the future.","zh":"教育對未來很重要。"},{"en":"Choosing a college is an important decision for many students.","zh":"選擇大學對許多學生來說是一個重要的決定。"},{"en":"Sleep plays an important role in keeping us healthy.","zh":"睡眠在維持我們的健康方面扮演重要的角色。"}]},{"word":"impose","pos":"v.","phonetic":"[ɪmˈpoz]","meaning":"強加；施加","definition":"to force a rule, tax, or punishment to be accepted","collocations":["impose a fine","impose rules","impose a tax"],"example":"The government imposed a new tax.","exampleZh":"政府課徵了一項新稅。","synonyms":["enforce"],"level":5,"theme":"政治與法律","examples":[{"en":"The government imposed a new tax.","zh":"政府課徵了一項新稅。"},{"en":"The city may impose a fine on people who litter.","zh":"這座城市可能會對亂丟垃圾的人處以罰款。"},{"en":"Parents should not impose their own dreams on their children.","zh":"父母不該把自己的夢想強加在孩子身上。"}]},{"word":"impossible","pos":"adj.","phonetic":"[ɪmˈpɑsəbl̩]","meaning":"不可能的","definition":"not able to happen, exist, or be done","collocations":["impossible to believe","almost impossible","find it impossible"],"example":"It's impossible to finish the work in one day.","exampleZh":"一天之內完成這項工作是不可能的。","synonyms":["unachievable"],"level":2,"theme":"性質與描述","examples":[{"en":"It's impossible to finish the work in one day.","zh":"一天之內完成這項工作是不可能的。"},{"en":"It is almost impossible to finish this book in one night.","zh":"要在一個晚上讀完這本書幾乎是不可能的。"},{"en":"She found it impossible to sleep because of the loud music.","zh":"因為吵鬧的音樂，她發現自己根本無法入睡。"}]},{"word":"impress","pos":"v.","phonetic":"[ɪmˈprɛs]","meaning":"使印象深刻","definition":"to make someone feel admiration or respect","collocations":["impress the judges","try to impress","easily impressed"],"example":"She impressed everyone with her speech.","exampleZh":"她的演講讓每個人都印象深刻。","synonyms":["amaze"],"level":3,"theme":"情緒與感受","examples":[{"en":"She impressed everyone with her speech.","zh":"她的演講讓每個人都印象深刻。"},{"en":"The young pianist hoped to impress the judges with her skill.","zh":"這位年輕鋼琴家希望以她的技巧讓評審印象深刻。"},{"en":"His polite manners impressed everyone at the interview.","zh":"他有禮的舉止讓面試中的每個人都印象深刻。"}]},{"word":"impression","pos":"n.","phonetic":"[ɪmˈprɛʃən]","meaning":"印象","definition":"an idea, feeling, or opinion about something formed without careful thought","collocations":["first impression","make an impression","under the impression"],"example":"He made a good first impression at the interview.","exampleZh":"他在面試時給人留下良好的第一印象。","synonyms":["feeling"],"level":3,"theme":"情緒與感受","examples":[{"en":"He made a good first impression at the interview.","zh":"他在面試時給人留下良好的第一印象。"},{"en":"A neat appearance helps you make a good first impression.","zh":"整潔的外表有助於你留下良好的第一印象。"},{"en":"I was under the impression that the shop opened at nine.","zh":"我原以為這家店九點開門。"}]},{"word":"impressive","pos":"adj.","phonetic":"[ɪmˈprɛsɪv]","meaning":"令人印象深刻的","definition":"deserving admiration because of size, quality, or skill","collocations":["impressive performance","impressive results","truly impressive"],"example":"The building has an impressive design.","exampleZh":"這棟建築有著令人印象深刻的設計。","synonyms":["remarkable"],"level":3,"theme":"性質與描述","examples":[{"en":"The building has an impressive design.","zh":"這棟建築有著令人印象深刻的設計。"},{"en":"The gymnast gave a truly impressive performance last night.","zh":"這位體操選手昨晚的表現真的令人印象深刻。"},{"en":"The students achieved impressive results in the science fair.","zh":"學生們在科展中取得了令人印象深刻的成果。"}]},{"word":"imprison","pos":"v.","phonetic":"[ɪmˈprɪzn̩]","meaning":"監禁","definition":"to put someone in prison or confine them","collocations":["imprison a criminal","be imprisoned for","wrongly imprisoned"],"example":"He was imprisoned for theft.","exampleZh":"他因偷竊而被監禁。","synonyms":["jail","confine"],"level":5,"theme":"政治與法律","examples":[{"en":"He was imprisoned for theft.","zh":"他因偷竊而被監禁。"},{"en":"The court decided to imprison the thief for two years.","zh":"法院決定將這名小偷監禁兩年。"},{"en":"The man was wrongly imprisoned for a crime he did not commit.","zh":"這名男子因一樁他沒有犯下的罪而被冤枉監禁。"}]},{"word":"improve","pos":"v.","phonetic":"[ɪmˈpruv]","meaning":"改善；進步","definition":"to make or become better","collocations":["improve skills","improve health","improve gradually"],"example":"Her English has improved a lot.","exampleZh":"她的英文進步很多。","synonyms":["enhance","better"],"level":2,"theme":"動作與行為","examples":[{"en":"Her English has improved a lot.","zh":"她的英文進步很多。"},{"en":"Reading every day can help you improve your writing skills.","zh":"每天閱讀能幫助你提升寫作技巧。"},{"en":"His health improved gradually after he started exercising.","zh":"開始運動後，他的健康狀況逐漸改善。"}]},{"word":"improvement","pos":"n.","phonetic":"[ɪmˈpruvmənt]","meaning":"改善；進步","definition":"the process of improving something, or the result of it","collocations":["room for improvement","make improvements","show improvement"],"example":"There has been a great improvement in his grades.","exampleZh":"他的成績有很大的進步。","synonyms":["progress"],"level":3,"theme":"教育與學習","examples":[{"en":"There has been a great improvement in his grades.","zh":"他的成績有很大的進步。"},{"en":"Your essay is good, but there is still room for improvement.","zh":"你的文章不錯，但仍有進步的空間。"},{"en":"The team made great improvements after weeks of practice.","zh":"經過數週的練習後，這支隊伍有了很大的進步。"}]},{"word":"impulse","pos":"n.","phonetic":"[ˈɪmpʌls]","meaning":"衝動","definition":"a sudden strong desire to do something","collocations":["on impulse","buy on impulse","control an impulse"],"example":"She bought the dress on impulse.","exampleZh":"她一時衝動買下了那件洋裝。","synonyms":["urge"],"level":5,"theme":"情緒與感受","examples":[{"en":"She bought the dress on impulse.","zh":"她一時衝動買下了那件洋裝。"},{"en":"He bought the expensive guitar on impulse and later regretted it.","zh":"他一時衝動買了那把昂貴的吉他，後來很後悔。"},{"en":"Learning to control your impulses is part of growing up.","zh":"學會控制自己的衝動是成長的一部分。"}]},{"word":"incentive","pos":"n.","phonetic":"[ɪnˈsɛntɪv]","meaning":"誘因；獎勵","definition":"something that encourages a person to do something","collocations":["a strong incentive","financial incentive"],"example":"The company offers incentives to boost sales performance.","exampleZh":"公司提供獎勵以提升銷售業績。","synonyms":["motivation","reward"],"level":5,"theme":"商業與金錢","examples":[{"en":"The company offers incentives to boost sales performance.","zh":"公司提供獎勵以提升銷售業績。"},{"en":"Good grades can be a strong incentive to study harder.","zh":"好成績可以是更努力讀書的強烈誘因。"},{"en":"The store offers a financial incentive to loyal customers.","zh":"這家商店為忠實顧客提供金錢上的獎勵。"}]},{"word":"inch","pos":"n.","phonetic":"[ɪntʃ]","meaning":"英吋","definition":"a unit of length equal to 2.54 centimeters","collocations":["inch by inch","every inch","a few inches"],"example":"The board is two inches thick.","exampleZh":"這塊板子有兩英吋厚。","synonyms":[],"level":2,"theme":"科學與數學","examples":[{"en":"The board is two inches thick.","zh":"這塊板子有兩英吋厚。"},{"en":"The snail moved forward inch by inch across the leaf.","zh":"蝸牛一吋一吋地在葉子上向前爬。"},{"en":"Please cut a few inches off the bottom of the curtain.","zh":"請把窗簾底部剪掉幾吋。"}]},{"word":"incident","pos":"n.","phonetic":"[ˈɪnsədənt]","meaning":"事件；事故","definition":"an event or occurrence, especially one that is unpleasant or unusual","collocations":["a strange incident","report an incident","an isolated incident"],"example":"The police were called to investigate the incident.","exampleZh":"警方被叫去調查這起事件。","synonyms":["event","occurrence"],"level":4,"theme":"社會與文化","examples":[{"en":"The police were called to investigate the incident.","zh":"警方被叫去調查這起事件。"},{"en":"The teacher asked the students to report any strange incident.","zh":"老師要求學生回報任何奇怪的事件。"},{"en":"Luckily, the accident was an isolated incident on that road.","zh":"幸運的是，那起事故在那條路上是個別事件。"}]},{"word":"incline","pos":"v. / n.","phonetic":"[ɪnˈklaɪn]","meaning":"傾向；斜坡","definition":"to lean or tend toward something, or a slope","collocations":["incline toward","a steep incline"],"example":"I'm inclined to agree with your opinion.","exampleZh":"我傾向於同意你的看法。","synonyms":["tend","lean"],"level":5,"theme":"抽象概念","examples":[{"en":"I'm inclined to agree with your opinion.","zh":"我傾向於同意你的看法。"},{"en":"The cyclists struggled to ride up the steep incline.","zh":"騎士們吃力地騎上那道陡峭的斜坡。"},{"en":"I incline toward staying home rather than going out tonight.","zh":"今晚我比較傾向待在家裡而不是外出。"}]},{"word":"include","pos":"v.","phonetic":"[ɪnˈklud]","meaning":"包括","definition":"to contain something as part of a whole","collocations":["include tax","price includes","include everyone"],"example":"The price includes breakfast.","exampleZh":"這個價格包含早餐。","synonyms":["contain"],"level":2,"theme":"抽象概念","examples":[{"en":"The price includes breakfast.","zh":"這個價格包含早餐。"},{"en":"The tour price includes meals and hotel accommodation.","zh":"這趟旅遊的費用包含餐點和飯店住宿。"},{"en":"Please make sure to include everyone in the group photo.","zh":"請務必讓每個人都出現在團體照裡。"}]},{"word":"inclusive","pos":"adj.","phonetic":"[ɪnˈklusɪv]","meaning":"包容的；包含在內的","definition":"including everyone or everything, not leaving anyone out","collocations":["an inclusive society","all-inclusive package"],"example":"The school promotes an inclusive environment for all students.","exampleZh":"這所學校推廣讓所有學生都能融入的環境。","synonyms":["comprehensive","all-embracing"],"level":5,"theme":"社會與文化","examples":[{"en":"The school promotes an inclusive environment for all students.","zh":"這所學校推廣讓所有學生都能融入的環境。"},{"en":"Our school works hard to build an inclusive society for all.","zh":"我們學校努力為所有人建立一個包容的社會。"},{"en":"The travel agency offers an all-inclusive package to the island.","zh":"這家旅行社提供前往那座島嶼的全包式套裝行程。"}]},{"word":"income","pos":"n.","phonetic":"[ˈɪnˌkʌm]","meaning":"收入","definition":"money that a person or organization receives regularly","collocations":["monthly income","low income","annual income"],"example":"His income has increased this year.","exampleZh":"他今年的收入增加了。","synonyms":["earnings"],"level":3,"theme":"商業與金錢","examples":[{"en":"His income has increased this year.","zh":"他今年的收入增加了。"},{"en":"Families with a low income can apply for extra support.","zh":"低收入的家庭可以申請額外的補助。"},{"en":"Part of his monthly income goes into a savings account.","zh":"他每月收入的一部分會存入儲蓄帳戶。"}]},{"word":"incorporate","pos":"v.","phonetic":"[ɪnˈkɔrpəˌret]","meaning":"納入；合併","definition":"to include something as part of a whole","collocations":["incorporate ideas","incorporate feedback"],"example":"The designer incorporated traditional patterns into the new dress.","exampleZh":"設計師把傳統圖案融入了這件新洋裝。","synonyms":["integrate","include"],"level":6,"theme":"抽象概念","examples":[{"en":"The designer incorporated traditional patterns into the new dress.","zh":"設計師把傳統圖案融入了這件新洋裝。"},{"en":"The teacher decided to incorporate students' ideas into the lesson.","zh":"老師決定把學生的想法納入課程中。"},{"en":"The writer incorporated the readers' feedback into the new edition.","zh":"作者把讀者的意見納入了新版本中。"}]},{"word":"increase","pos":"v. / n.","phonetic":"[ɪnˈkris]","meaning":"增加","definition":"to become or make greater in size, amount, or degree","collocations":["increase in price","sharp increase","increase steadily"],"example":"Prices increased sharply last month.","exampleZh":"上個月物價大幅上漲。","synonyms":["rise","grow"],"level":2,"theme":"商業與金錢","examples":[{"en":"Prices increased sharply last month.","zh":"上個月物價大幅上漲。"},{"en":"The number of visitors to the museum increased steadily this year.","zh":"今年參觀博物館的人數穩定增加。"},{"en":"There was a sharp increase in fruit prices after the typhoon.","zh":"颱風過後，水果價格急遽上漲。"}]},{"word":"incredible","pos":"adj.","phonetic":"[ɪnˈkrɛdəbḷ]","meaning":"難以置信的；驚人的","definition":"impossible or very difficult to believe; extraordinary","collocations":["an incredible story","incredible amount","seem incredible"],"example":"It's incredible how fast she learned the language.","exampleZh":"她學語言的速度快得令人難以置信。","synonyms":["unbelievable","amazing"],"level":3,"theme":"性質與描述","examples":[{"en":"It's incredible how fast she learned the language.","zh":"她學語言的速度快得令人難以置信。"},{"en":"The old sailor told us an incredible story about a giant wave.","zh":"這位老水手告訴我們一個關於巨浪的驚人故事。"},{"en":"It seems incredible that she wrote the whole novel in a month.","zh":"她在一個月內寫完整本小說，實在令人難以置信。"}]},{"word":"incur","pos":"v.","phonetic":"[ɪnˈkɜr]","meaning":"招致；蒙受","definition":"to experience something unpleasant, such as a cost or loss, as a result of one's actions","collocations":["incur a loss","incur debt","incur costs"],"example":"Late payments will incur an extra fee.","exampleZh":"逾期付款將產生額外費用。","synonyms":["suffer","sustain"],"level":6,"theme":"商業與金錢","examples":[{"en":"Late payments will incur an extra fee.","zh":"逾期付款將產生額外費用。"},{"en":"Returning the book late will incur a small fine.","zh":"逾期歸還書籍會招致一筆小額罰款。"},{"en":"The company incurred heavy losses during the economic crisis.","zh":"這家公司在經濟危機期間蒙受了巨大的損失。"}]},{"word":"indeed","pos":"adv.","phonetic":"[ɪnˈdid]","meaning":"的確；確實","definition":"used to emphasize a statement or answer","collocations":["yes, indeed","indeed true","very good indeed"],"example":"It was indeed a difficult decision.","exampleZh":"這的確是個困難的決定。","synonyms":["truly","really"],"level":3,"theme":"抽象概念","examples":[{"en":"It was indeed a difficult decision.","zh":"這的確是個困難的決定。"},{"en":"The mountain view from the top was beautiful indeed.","zh":"從山頂看到的景色的確非常美麗。"},{"en":"It is indeed true that hard work leads to success.","zh":"努力會帶來成功，這的確是真的。"}]},{"word":"independence","pos":"n.","phonetic":"[ˌɪndɪˈpɛndəns]","meaning":"獨立","definition":"freedom from control or support by others","collocations":["gain independence","declare independence","financial independence"],"example":"The country gained independence in 1945.","exampleZh":"這個國家於1945年獲得獨立。","synonyms":["freedom"],"level":4,"theme":"政治與法律","examples":[{"en":"The country gained independence in 1945.","zh":"這個國家於1945年獲得獨立。"},{"en":"Moving out of her parents' home gave her a sense of independence.","zh":"搬離父母家給了她一種獨立的感覺。"},{"en":"A part-time job helped him gain some financial independence.","zh":"一份兼職工作幫助他獲得了一些經濟上的獨立。"}]},{"word":"independent","pos":"adj.","phonetic":"[ˌɪndɪˈpɛndənt]","meaning":"獨立的","definition":"not controlled or influenced by others","collocations":["independent country","become independent","independent thinking"],"example":"She is financially independent.","exampleZh":"她在經濟上是獨立的。","synonyms":["self-reliant"],"level":3,"theme":"性質與描述","examples":[{"en":"She is financially independent.","zh":"她在經濟上是獨立的。"},{"en":"The school encourages independent thinking among its students.","zh":"這所學校鼓勵學生獨立思考。"},{"en":"After college, she became completely independent from her family.","zh":"大學畢業後，她完全獨立，不再依賴家人。"}]},{"word":"index","pos":"n.","phonetic":"[ˈɪndɛks]","meaning":"索引；指數","definition":"an alphabetical list of names or topics; a measure of change in something","collocations":["stock index","index finger","an index of prices"],"example":"You can find the topic quickly by checking the index.","exampleZh":"你可以查看索引來快速找到這個主題。","synonyms":[],"level":4,"theme":"科學與數學","examples":[{"en":"You can find the topic quickly by checking the index.","zh":"你可以查看索引來快速找到這個主題。"},{"en":"You can find the chapter you need by checking the index.","zh":"你可以透過查閱索引找到你需要的章節。"},{"en":"The teacher pointed at the map with her index finger.","zh":"老師用食指指著地圖。"}]},{"word":"indicate","pos":"v.","phonetic":"[ˈɪndəˌket]","meaning":"指出；顯示","definition":"to point out or show something clearly","collocations":["indicate a direction","research indicates","clearly indicate"],"example":"Studies indicate that exercise improves health.","exampleZh":"研究顯示運動能改善健康。","synonyms":["show","suggest"],"level":4,"theme":"溝通與語言","examples":[{"en":"Studies indicate that exercise improves health.","zh":"研究顯示運動能改善健康。"},{"en":"The arrow on the sign indicates the way to the exit.","zh":"標誌上的箭頭指出通往出口的方向。"},{"en":"Recent research indicates that reading improves memory.","zh":"最近的研究顯示閱讀能增進記憶力。"}]},{"word":"indifferent","pos":"adj.","phonetic":"[ɪnˈdɪfərənt]","meaning":"漠不關心的；平庸的","definition":"having no particular interest or concern","collocations":["indifferent to","remain indifferent"],"example":"He seemed indifferent to the outcome of the game.","exampleZh":"他似乎對比賽結果漠不關心。","synonyms":["apathetic","unconcerned"],"level":5,"theme":"情緒與感受","examples":[{"en":"He seemed indifferent to the outcome of the game.","zh":"他似乎對比賽結果漠不關心。"},{"en":"He seemed completely indifferent to what others thought of him.","zh":"他似乎對別人怎麼看他完全漠不關心。"},{"en":"We cannot remain indifferent to the suffering of others.","zh":"我們不能對他人的苦難漠不關心。"}]},{"word":"indignant","pos":"adj.","phonetic":"[ɪnˈdɪɡnənt]","meaning":"憤慨的；憤怒的","definition":"feeling anger because of something unfair or unjust","collocations":["indignant at","an indignant reply"],"example":"She was indignant at being blamed for the mistake.","exampleZh":"她對被指責犯錯感到憤慨。","synonyms":["angry","outraged"],"level":6,"theme":"情緒與感受","examples":[{"en":"She was indignant at being blamed for the mistake.","zh":"她對被指責犯錯感到憤慨。"},{"en":"The workers were indignant at the unfair pay cuts.","zh":"工人們對不公平的減薪感到憤慨。"},{"en":"She gave an indignant reply when accused of lying.","zh":"當被指控說謊時，她憤慨地回應。"}]},{"word":"indispensable","pos":"adj.","phonetic":"[ˌɪndɪˈspɛnsəbəl]","meaning":"不可或缺的","definition":"absolutely necessary; too important to be without","collocations":["an indispensable tool","become indispensable"],"example":"Clean water is indispensable for human survival.","exampleZh":"乾淨的水對人類生存不可或缺。","synonyms":["essential","vital"],"level":6,"theme":"抽象概念","examples":[{"en":"Clean water is indispensable for human survival.","zh":"乾淨的水對人類生存不可或缺。"},{"en":"A smartphone has become an indispensable tool in daily life.","zh":"智慧型手機已成為日常生活中不可或缺的工具。"},{"en":"Fresh water is indispensable to every living thing.","zh":"淡水對每一種生物都是不可或缺的。"}]},{"word":"individual","pos":"n. / adj.","phonetic":"[ˌɪndəˈvɪdʒuəl]","meaning":"個人；個別的","definition":"a single person; considered separately rather than as part of a group","collocations":["an individual right","individual needs","each individual"],"example":"Each individual has unique talents.","exampleZh":"每個人都有獨特的才能。","synonyms":["person"],"level":3,"theme":"人物與家庭","examples":[{"en":"Each individual has unique talents.","zh":"每個人都有獨特的才能。"},{"en":"The teacher pays attention to the individual needs of each child.","zh":"老師關注每個孩子的個別需求。"},{"en":"Every individual has the right to express his or her opinion.","zh":"每個人都有表達自己意見的權利。"}]},{"word":"indoor","pos":"adj.","phonetic":"[ˈɪnˌdɔr]","meaning":"室內的","definition":"located, used, or done inside a building","collocations":["indoor swimming pool","indoor activities","indoor stadium"],"example":"We played basketball at the indoor stadium.","exampleZh":"我們在室內體育館打籃球。","synonyms":[],"level":2,"theme":"居家與生活","examples":[{"en":"We played basketball at the indoor stadium.","zh":"我們在室內體育館打籃球。"},{"en":"On rainy days we enjoy indoor activities like board games.","zh":"下雨天我們喜歡玩桌遊之類的室內活動。"},{"en":"The hotel has a heated indoor swimming pool for guests.","zh":"這家飯店有一座供房客使用的溫水室內游泳池。"}]},{"word":"indulge","pos":"v.","phonetic":"[ɪnˈdʌldʒ]","meaning":"放縱；沉溺","definition":"to allow oneself to enjoy something, often to excess","collocations":["indulge in","indulge a child"],"example":"On weekends she likes to indulge in chocolate cake.","exampleZh":"週末她喜歡放縱自己吃巧克力蛋糕。","synonyms":["pamper","satisfy"],"level":5,"theme":"食物與烹飪","examples":[{"en":"On weekends she likes to indulge in chocolate cake.","zh":"週末她喜歡放縱自己吃巧克力蛋糕。"},{"en":"After the exams, they indulged in a big ice-cream treat.","zh":"考完試後，他們盡情享用了一大份冰淇淋。"},{"en":"Grandparents often indulge their grandchildren with sweets.","zh":"祖父母常常用糖果來寵愛他們的孫子。"}]},{"word":"industrial","pos":"adj.","phonetic":"[ɪnˈdʌstrɪəl]","meaning":"工業的","definition":"relating to industry or manufacturing","collocations":["industrial area","industrial waste","industrial revolution"],"example":"The city has many industrial zones.","exampleZh":"這座城市有許多工業區。","synonyms":["manufacturing"],"level":3,"theme":"工作與職業","examples":[{"en":"The city has many industrial zones.","zh":"這座城市有許多工業區。"},{"en":"The factory must treat its industrial waste before releasing it.","zh":"這家工廠在排放前必須處理其工業廢棄物。"},{"en":"The Industrial Revolution changed how goods were produced.","zh":"工業革命改變了商品的生產方式。"}]},{"word":"industrious","pos":"adj.","phonetic":"[ɪnˈdʌstriəs]","meaning":"勤勉的；勤奮的","definition":"working hard and steadily","collocations":["an industrious worker","industrious student"],"example":"The industrious farmer worked in the field from dawn.","exampleZh":"這位勤奮的農夫從清晨就在田裡工作。","synonyms":["diligent","hardworking"],"level":5,"theme":"工作與職業","examples":[{"en":"The industrious farmer worked in the field from dawn.","zh":"這位勤奮的農夫從清晨就在田裡工作。"},{"en":"The industrious student reviewed her notes every single evening.","zh":"這位勤奮的學生每天晚上都複習她的筆記。"},{"en":"Bees are known for being industrious little creatures.","zh":"蜜蜂以勤勞的小生物而聞名。"}]},{"word":"industry","pos":"n.","phonetic":"[ˈɪndəstri]","meaning":"產業；工業","definition":"economic activity concerned with producing goods or services","collocations":["heavy industry","the tourism industry","a growing industry"],"example":"Taiwan's tech industry is booming.","exampleZh":"台灣的科技產業正蓬勃發展。","synonyms":["manufacturing"],"level":3,"theme":"工作與職業","examples":[{"en":"Taiwan's tech industry is booming.","zh":"台灣的科技產業正蓬勃發展。"},{"en":"The tourism industry brings many jobs to the coastal town.","zh":"觀光產業為這座海濱小鎮帶來許多工作機會。"},{"en":"Green energy is a fast-growing industry around the world.","zh":"綠能是全球快速成長的產業。"}]},{"word":"inevitable","pos":"adj.","phonetic":"[ɪnˈɛvɪtəbəl]","meaning":"不可避免的","definition":"certain to happen; unavoidable","collocations":["an inevitable outcome","seem inevitable"],"example":"Change is inevitable as technology keeps advancing.","exampleZh":"隨著科技不斷進步，改變是不可避免的。","synonyms":["unavoidable","certain"],"level":5,"theme":"抽象概念","examples":[{"en":"Change is inevitable as technology keeps advancing.","zh":"隨著科技不斷進步，改變是不可避免的。"},{"en":"Getting older is an inevitable part of life.","zh":"變老是人生中不可避免的一部分。"},{"en":"With so little practice, defeat seemed inevitable.","zh":"練習這麼少，失敗似乎是不可避免的。"}]},{"word":"infamous","pos":"adj.","phonetic":"[ˈɪnfəməs]","meaning":"惡名昭彰的","definition":"well known for a bad quality or deed","collocations":["an infamous criminal","infamous for"],"example":"The pirate became infamous for his cruelty.","exampleZh":"這名海盜因殘暴而惡名昭彰。","synonyms":["notorious","disreputable"],"level":6,"theme":"社會與文化","examples":[{"en":"The pirate became infamous for his cruelty.","zh":"這名海盜因殘暴而惡名昭彰。"},{"en":"The area was once infamous for its high crime rate.","zh":"這個地區曾經因高犯罪率而惡名昭彰。"},{"en":"The infamous storm destroyed hundreds of homes years ago.","zh":"那場惡名昭彰的風暴多年前摧毀了數百戶人家。"}]},{"word":"infant","pos":"n.","phonetic":"[ˈɪnfənt]","meaning":"嬰兒","definition":"a very young child, especially one not yet able to walk","collocations":["infant care","newborn infant","infant formula"],"example":"The infant slept peacefully in the crib.","exampleZh":"嬰兒在嬰兒床裡安詳地睡著。","synonyms":["baby"],"level":4,"theme":"人物與家庭","examples":[{"en":"The infant slept peacefully in the crib.","zh":"嬰兒在嬰兒床裡安詳地睡著。"},{"en":"The nurse gently held the newborn infant in her arms.","zh":"護士溫柔地把新生嬰兒抱在懷裡。"},{"en":"Parents of a young infant often lose a lot of sleep.","zh":"有幼小嬰兒的父母常常睡眠不足。"}]},{"word":"infect","pos":"v.","phonetic":"[ɪnˈfɛkt]","meaning":"感染","definition":"to cause disease in a person, animal, or plant","collocations":["infect a wound","become infected","infect cells"],"example":"The virus can infect many cells quickly.","exampleZh":"這種病毒能迅速感染許多細胞。","synonyms":["contaminate"],"level":4,"theme":"身體與健康","examples":[{"en":"The virus can infect many cells quickly.","zh":"這種病毒能迅速感染許多細胞。"},{"en":"Dirty water can easily infect an open wound.","zh":"髒水很容易使傷口感染。"},{"en":"The virus can infect healthy cells within hours.","zh":"這種病毒能在數小時內感染健康的細胞。"}]},{"word":"infection","pos":"n.","phonetic":"[ɪnˈfɛkʃən]","meaning":"感染；傳染病","definition":"a disease caused by bacteria, viruses, or other germs","collocations":["bacterial infection","spread infection","ear infection"],"example":"He got an ear infection.","exampleZh":"他耳朵受到感染。","synonyms":["disease"],"level":4,"theme":"身體與健康","examples":[{"en":"He got an ear infection.","zh":"他耳朵受到感染。"},{"en":"Washing your hands often helps stop the spread of infection.","zh":"勤洗手有助於阻止感染的傳播。"},{"en":"The doctor gave him medicine to treat the bacterial infection.","zh":"醫生給他藥物來治療細菌感染。"}]},{"word":"infectious","pos":"adj.","phonetic":"[ɪnˈfɛkʃəs]","meaning":"傳染性的；有感染力的","definition":"capable of spreading disease, or quickly affecting others' emotions","collocations":["an infectious disease","infectious laughter"],"example":"Her infectious enthusiasm cheered up the whole team.","exampleZh":"她富有感染力的熱情鼓舞了整個團隊。","synonyms":["contagious","catching"],"level":5,"theme":"身體與健康","examples":[{"en":"Her infectious enthusiasm cheered up the whole team.","zh":"她富有感染力的熱情鼓舞了整個團隊。"},{"en":"The nurse wore a mask to avoid catching the infectious disease.","zh":"護士戴上口罩以避免感染這種傳染病。"},{"en":"The child's infectious laughter made everyone around him smile.","zh":"這孩子富有感染力的笑聲讓身邊每個人都露出微笑。"}]},{"word":"inferior","pos":"adj.","phonetic":"[ɪnˈfɪriər]","meaning":"較差的；次等的","definition":"lower in quality, status, or rank","collocations":["feel inferior","inferior quality"],"example":"The cheap toy broke because of its inferior materials.","exampleZh":"這個便宜的玩具因材質較差而壞掉了。","synonyms":["lower","substandard"],"level":5,"theme":"性質與描述","examples":[{"en":"The cheap toy broke because of its inferior materials.","zh":"這個便宜的玩具因材質較差而壞掉了。"},{"en":"The cheap umbrella broke quickly because of its inferior quality.","zh":"這把便宜的雨傘因品質低劣而很快就壞了。"},{"en":"You should never feel inferior just because you made a mistake.","zh":"你絕不該只因為犯了一個錯就覺得自己低人一等。"}]},{"word":"infinite","pos":"adj.","phonetic":"[ˈɪnfənɪt]","meaning":"無限的；無窮的","definition":"having no limit or end","collocations":["infinite space","infinite patience"],"example":"The universe seems to stretch out into infinite space.","exampleZh":"宇宙似乎向無限的空間延伸。","synonyms":["endless","limitless"],"level":4,"theme":"科學與數學","examples":[{"en":"The universe seems to stretch out into infinite space.","zh":"宇宙似乎向無限的空間延伸。"},{"en":"A good teacher needs almost infinite patience with students.","zh":"好老師對學生需要幾乎無窮的耐心。"},{"en":"Standing under the night sky, I felt how infinite space is.","zh":"站在夜空下，我感受到宇宙是多麼無邊無際。"}]},{"word":"inflate","pos":"v.","phonetic":"[ɪnˈflet]","meaning":"使膨脹；使充氣","definition":"to fill something with air or gas, or to increase in size or amount","collocations":["inflate a balloon","inflate prices"],"example":"He inflated the tires before the long trip.","exampleZh":"他在長途旅行前把輪胎打氣。","synonyms":["expand","pump up"],"level":5,"theme":"科學與數學","examples":[{"en":"He inflated the tires before the long trip.","zh":"他在長途旅行前把輪胎打氣。"},{"en":"The children helped inflate the balloons for the party.","zh":"孩子們幫忙為派對吹氣球。"},{"en":"Some sellers inflate prices right before a big holiday.","zh":"有些賣家會在大節日前抬高價格。"}]},{"word":"inflation","pos":"n.","phonetic":"[ɪnˈfleʃən]","meaning":"通貨膨脹","definition":"a general rise in prices and fall in the value of money","collocations":["rising inflation","control inflation"],"example":"High inflation has made daily goods more expensive.","exampleZh":"高通貨膨脹使日常用品變得更貴。","synonyms":["price rise"],"level":4,"theme":"商業與金錢","examples":[{"en":"High inflation has made daily goods more expensive.","zh":"高通貨膨脹使日常用品變得更貴。"},{"en":"Rising inflation has made everyday shopping more expensive.","zh":"上升的通貨膨脹使日常購物變得更加昂貴。"},{"en":"The government is trying hard to control inflation.","zh":"政府正努力控制通貨膨脹。"}]},{"word":"influence","pos":"n. / v.","phonetic":"[ˈɪnfluəns]","meaning":"影響","definition":"the power to affect someone's or something's behavior or development","collocations":["have influence on","under the influence","a bad influence"],"example":"Parents have a strong influence on children.","exampleZh":"父母對孩子有很大的影響。","synonyms":["effect","impact"],"level":3,"theme":"抽象概念","examples":[{"en":"Parents have a strong influence on children.","zh":"父母對孩子有很大的影響。"},{"en":"Good friends can have a positive influence on your habits.","zh":"好朋友能對你的習慣產生正面的影響。"},{"en":"The weather greatly influences what crops farmers can grow.","zh":"天氣大大影響著農夫能種植什麼作物。"}]},{"word":"influential","pos":"adj.","phonetic":"[ˌɪnfluˈɛnʃəl]","meaning":"有影響力的","definition":"having great influence on someone or something","collocations":["an influential leader","highly influential"],"example":"She is one of the most influential scientists of her time.","exampleZh":"她是當代最具影響力的科學家之一。","synonyms":["powerful","significant"],"level":5,"theme":"社會與文化","examples":[{"en":"She is one of the most influential scientists of her time.","zh":"她是當代最具影響力的科學家之一。"},{"en":"The professor is a highly influential figure in her field.","zh":"這位教授在她的領域裡是極具影響力的人物。"},{"en":"An influential coach can shape a young player's entire career.","zh":"一位有影響力的教練能形塑年輕球員的整個生涯。"}]},{"word":"inform","pos":"v.","phonetic":"[ɪnˈfɔrm]","meaning":"通知","definition":"to give information to someone","collocations":["inform someone of","keep informed","inform the police"],"example":"Please inform us of any changes.","exampleZh":"有任何變動請通知我們。","synonyms":["notify"],"level":4,"theme":"溝通與語言","examples":[{"en":"Please inform us of any changes.","zh":"有任何變動請通知我們。"},{"en":"Please inform your teacher if you cannot attend the trip.","zh":"如果你無法參加這次旅行，請通知你的老師。"},{"en":"The neighbors decided to inform the police about the noise.","zh":"鄰居們決定把噪音的事通報警方。"}]},{"word":"information","pos":"n.","phonetic":"[ˌɪnfɚˈmeʃən]","meaning":"資訊；消息","definition":"facts or details about something","collocations":["gather information","useful information","personal information"],"example":"The website provides useful information.","exampleZh":"這個網站提供了有用的資訊。","synonyms":["data"],"level":1,"theme":"科技與媒體","examples":[{"en":"The website provides useful information.","zh":"這個網站提供了有用的資訊。"},{"en":"Never share your personal information with strangers online.","zh":"絕不要在網路上與陌生人分享你的個人資訊。"},{"en":"We gathered information about the museum before our visit.","zh":"我們在參觀前蒐集了關於這座博物館的資訊。"}]},{"word":"ingenious","pos":"adj.","phonetic":"[ɪnˈdʒinjəs]","meaning":"巧妙的；有創意的","definition":"clever, original, and inventive","collocations":["an ingenious idea","ingenious solution"],"example":"The engineer came up with an ingenious solution to the problem.","exampleZh":"工程師想出了一個巧妙的解決方案。","synonyms":["inventive","clever"],"level":6,"theme":"科技與媒體","examples":[{"en":"The engineer came up with an ingenious solution to the problem.","zh":"工程師想出了一個巧妙的解決方案。"},{"en":"She found an ingenious way to store books in her tiny room.","zh":"她想出一個巧妙的方法在她的小房間裡收納書籍。"},{"en":"The young inventor built an ingenious machine from spare parts.","zh":"這位年輕發明家用零件組裝出一台精巧的機器。"}]},{"word":"ingredient","pos":"n.","phonetic":"[ɪnˈgridiənt]","meaning":"原料；成分","definition":"a food item that is combined with others to make a dish","collocations":["main ingredient","mix ingredients","fresh ingredients"],"example":"Flour is the main ingredient of bread.","exampleZh":"麵粉是麵包的主要原料。","synonyms":["component"],"level":4,"theme":"食物與烹飪","examples":[{"en":"Flour is the main ingredient of bread.","zh":"麵粉是麵包的主要原料。"},{"en":"The chef always uses fresh ingredients in his soups.","zh":"這位廚師總是在他的湯裡使用新鮮的食材。"},{"en":"Mix all the ingredients together before baking the cake.","zh":"在烤蛋糕之前把所有材料混合在一起。"}]},{"word":"inhabit","pos":"v.","phonetic":"[ɪnˈhæbɪt]","meaning":"居住於；棲息於","definition":"to live in a particular place","collocations":["inhabit a region","species that inhabit"],"example":"Many rare species inhabit this tropical rainforest.","exampleZh":"許多稀有物種棲息在這片熱帶雨林中。","synonyms":["dwell","reside"],"level":5,"theme":"自然與環境","examples":[{"en":"Many rare species inhabit this tropical rainforest.","zh":"許多稀有物種棲息在這片熱帶雨林中。"},{"en":"Penguins inhabit some of the coldest regions on Earth.","zh":"企鵝棲息在地球上一些最寒冷的地區。"},{"en":"Few people inhabit the remote mountains in the north.","zh":"很少有人居住在北部偏遠的山區。"}]},{"word":"inhabitant","pos":"n.","phonetic":"[ɪnˈhæbɪtənt]","meaning":"居民；棲息生物","definition":"a person or animal that lives in a particular place","collocations":["local inhabitants","original inhabitants"],"example":"The island's inhabitants rely mainly on fishing.","exampleZh":"這座島的居民主要以捕魚維生。","synonyms":["resident","native"],"level":4,"theme":"人物與家庭","examples":[{"en":"The island's inhabitants rely mainly on fishing.","zh":"這座島的居民主要以捕魚維生。"},{"en":"The local inhabitants welcomed the tired travelers warmly.","zh":"當地居民熱情地歡迎疲憊的旅人。"},{"en":"The original inhabitants of the island lived by fishing.","zh":"這座島嶼最早的居民靠捕魚為生。"}]},{"word":"inherent","pos":"adj.","phonetic":"[ɪnˈhɪrənt]","meaning":"固有的；與生俱來的","definition":"existing as a natural or basic part of something","collocations":["an inherent risk","inherent quality"],"example":"There is an inherent risk in every investment.","exampleZh":"每一項投資都存在固有的風險。","synonyms":["innate","intrinsic"],"level":6,"theme":"抽象概念","examples":[{"en":"There is an inherent risk in every investment.","zh":"每一項投資都存在固有的風險。"},{"en":"There is an inherent danger in climbing such steep cliffs.","zh":"攀爬如此陡峭的懸崖有其固有的危險。"},{"en":"Kindness seems to be an inherent quality in her character.","zh":"善良似乎是她性格中與生俱來的特質。"}]},{"word":"inherit","pos":"v.","phonetic":"[ɪnˈhɛrɪt]","meaning":"繼承","definition":"to receive money, property, or a title from someone after their death","collocations":["inherit a fortune","inherit traits","inherit the throne"],"example":"She inherited a large house from her grandmother.","exampleZh":"她從祖母那裡繼承了一棟大房子。","synonyms":["receive"],"level":4,"theme":"人物與家庭","examples":[{"en":"She inherited a large house from her grandmother.","zh":"她從祖母那裡繼承了一棟大房子。"},{"en":"She inherited her mother's love of music and painting.","zh":"她繼承了母親對音樂和繪畫的熱愛。"},{"en":"The young prince will one day inherit the throne.","zh":"這位年輕的王子有一天將繼承王位。"}]},{"word":"initial","pos":"adj. / n.","phonetic":"[ɪˈnɪʃəl]","meaning":"最初的；首字母","definition":"happening at the beginning; the first letter of a name","collocations":["initial stage","initial reaction","initial cost"],"example":"His initial reaction was surprise.","exampleZh":"他最初的反應是驚訝。","synonyms":["first","original"],"level":4,"theme":"時間與空間","examples":[{"en":"His initial reaction was surprise.","zh":"他最初的反應是驚訝。"},{"en":"In the initial stage of the plan, we mainly gathered data.","zh":"在計畫的最初階段，我們主要是蒐集資料。"},{"en":"Please write your initials at the bottom of the form.","zh":"請在表格底部寫上你姓名的首字母。"}]},{"word":"initiate","pos":"v.","phonetic":"[ɪˈnɪʃiˌet]","meaning":"發起；創始","definition":"to cause a process or action to begin","collocations":["initiate a project","initiate talks"],"example":"The government initiated a new recycling program.","exampleZh":"政府發起了一項新的回收計畫。","synonyms":["begin","launch"],"level":6,"theme":"抽象概念","examples":[{"en":"The government initiated a new recycling program.","zh":"政府發起了一項新的回收計畫。"},{"en":"The two schools decided to initiate a book-sharing project.","zh":"這兩所學校決定發起一項圖書共享計畫。"},{"en":"The mayor initiated talks between the workers and the company.","zh":"市長發起了工人與公司之間的談判。"}]},{"word":"initiative","pos":"n.","phonetic":"[ɪˈnɪʃətɪv]","meaning":"主動性；倡議","definition":"the ability to act independently, or a new plan to solve a problem","collocations":["take the initiative","a new initiative"],"example":"She showed great initiative by starting the recycling club.","exampleZh":"她發起回收社團，展現了極大的主動精神。","synonyms":["enterprise","proactivity"],"level":5,"theme":"工作與職業","examples":[{"en":"She showed great initiative by starting the recycling club.","zh":"她發起回收社團，展現了極大的主動精神。"},{"en":"She took the initiative to organize a cleanup of the river.","zh":"她主動發起了一次清理河川的活動。"},{"en":"The city launched a new initiative to plant more trees.","zh":"這座城市推出了一項種植更多樹木的新倡議。"}]},{"word":"injure","pos":"v.","phonetic":"[ˈɪndʒɚ]","meaning":"傷害","definition":"to cause physical harm to a person or animal","collocations":["injure a leg","seriously injured","injure oneself"],"example":"He injured his knee during the game.","exampleZh":"他在比賽中傷了膝蓋。","synonyms":["hurt","wound"],"level":3,"theme":"身體與健康","examples":[{"en":"He injured his knee during the game.","zh":"他在比賽中傷了膝蓋。"},{"en":"He was seriously injured when he fell off his bicycle.","zh":"他從腳踏車上摔下來時受了重傷。"},{"en":"Always warm up first so you don't injure your muscles.","zh":"一定要先熱身，這樣才不會傷到肌肉。"}]},{"word":"injury","pos":"n.","phonetic":"[ˈɪndʒəri]","meaning":"受傷；傷害","definition":"physical harm or damage done to the body","collocations":["suffer an injury","sports injury","minor injury"],"example":"She recovered quickly from her injury.","exampleZh":"她的傷勢很快就痊癒了。","synonyms":["wound","harm"],"level":3,"theme":"身體與健康","examples":[{"en":"She recovered quickly from her injury.","zh":"她的傷勢很快就痊癒了。"},{"en":"The player had to leave the field because of a knee injury.","zh":"這名球員因膝蓋受傷不得不離場。"},{"en":"Luckily, it was only a minor injury and healed quickly.","zh":"幸好只是輕傷，很快就痊癒了。"}]},{"word":"ink","pos":"n.","phonetic":"[ɪŋk]","meaning":"墨水","definition":"a colored liquid used for writing or printing","collocations":["pen and ink","run out of ink","black ink"],"example":"The printer is out of ink.","exampleZh":"印表機的墨水用完了。","synonyms":[],"level":2,"theme":"教育與學習","examples":[{"en":"The printer is out of ink.","zh":"印表機的墨水用完了。"},{"en":"My pen ran out of ink in the middle of the exam.","zh":"我的筆在考試中途沒墨水了。"},{"en":"The artist drew the entire picture in black ink.","zh":"這位藝術家用黑色墨水畫了整幅畫。"}]},{"word":"inn","pos":"n.","phonetic":"[ɪn]","meaning":"小旅館；客棧","definition":"a small hotel or pub, typically in the countryside","collocations":["stay at an inn","a country inn","run an inn"],"example":"We stayed at a cozy inn near the lake.","exampleZh":"我們住在湖邊一間舒適的小旅館。","synonyms":["lodge"],"level":2,"theme":"交通與旅行","examples":[{"en":"We stayed at a cozy inn near the lake.","zh":"我們住在湖邊一間舒適的小旅館。"},{"en":"The tired hikers stayed at a small country inn overnight.","zh":"疲憊的健行者在一間鄉間小旅館過夜。"},{"en":"An old couple has run this cozy inn for thirty years.","zh":"一對老夫婦經營這間溫馨的小客棧已有三十年。"}]},{"word":"inner","pos":"adj.","phonetic":"[ˈɪnɚ]","meaning":"內部的；內心的","definition":"located inside; relating to private thoughts and feelings","collocations":["inner peace","inner city","inner feelings"],"example":"She found inner peace through meditation.","exampleZh":"她透過冥想找到了內心的平靜。","synonyms":["internal"],"level":3,"theme":"情緒與感受","examples":[{"en":"She found inner peace through meditation.","zh":"她透過冥想找到了內心的平靜。"},{"en":"Deep breathing can help you find a sense of inner peace.","zh":"深呼吸能幫助你找到內心的平靜。"},{"en":"She rarely shares her inner feelings with anyone.","zh":"她很少與任何人分享自己內心的感受。"}]},{"word":"innocent","pos":"adj.","phonetic":"[ˈɪnəsn̩t]","meaning":"無辜的；純真的","definition":"not guilty of a crime; free from sin or moral wrong","collocations":["innocent victim","prove innocent","innocent child"],"example":"The jury found him innocent.","exampleZh":"陪審團判他無罪。","synonyms":["guiltless"],"level":4,"theme":"政治與法律","examples":[{"en":"The jury found him innocent.","zh":"陪審團判他無罪。"},{"en":"Many innocent people were affected by the sudden flood.","zh":"許多無辜的人受到這場突如其來的洪水影響。"},{"en":"The lawyer worked hard to prove that his client was innocent.","zh":"律師努力證明他的當事人是無辜的。"}]},{"word":"innovate","pos":"v.","phonetic":"[ˈɪnəˌvet]","meaning":"創新","definition":"to introduce new ideas, methods, or products","collocations":["innovate constantly","innovate in technology"],"example":"Companies must innovate to stay competitive.","exampleZh":"企業必須不斷創新才能保持競爭力。","synonyms":["invent","modernize"],"level":5,"theme":"科技與媒體","examples":[{"en":"Companies must innovate to stay competitive.","zh":"企業必須不斷創新才能保持競爭力。"},{"en":"Successful companies must innovate constantly to stay ahead.","zh":"成功的公司必須不斷創新才能保持領先。"},{"en":"Engineers continue to innovate in the field of clean energy.","zh":"工程師持續在潔淨能源領域推陳出新。"}]},{"word":"innovation","pos":"n.","phonetic":"[ˌɪnəˈveʃən]","meaning":"創新；新方法","definition":"a new idea, method, or product","collocations":["technological innovation","drive innovation"],"example":"The smartphone was a major innovation in communication.","exampleZh":"智慧型手機是通訊上的一大創新。","synonyms":["invention","breakthrough"],"level":4,"theme":"科技與媒體","examples":[{"en":"The smartphone was a major innovation in communication.","zh":"智慧型手機是通訊上的一大創新。"},{"en":"The electric car is an exciting example of technological innovation.","zh":"電動車是技術創新一個令人振奮的例子。"},{"en":"Curiosity and hard work often drive innovation.","zh":"好奇心和努力往往推動創新。"}]},{"word":"input","pos":"n. / v.","phonetic":"[ˈɪnˌpʊt]","meaning":"輸入；投入","definition":"information or data put into a computer or system","collocations":["input data","provide input","input device"],"example":"Please input your password to continue.","exampleZh":"請輸入你的密碼以繼續。","synonyms":[],"level":4,"theme":"科技與媒體","examples":[{"en":"Please input your password to continue.","zh":"請輸入你的密碼以繼續。"},{"en":"The students provided helpful input during the group discussion about the project.","zh":"學生們在關於這個專案的小組討論中提供了有用的意見。"},{"en":"You must input the correct data before the computer can process it.","zh":"你必須先輸入正確的資料，電腦才能處理它。"}]},{"word":"inquire","pos":"v.","phonetic":"[ɪnˈkwaɪr]","meaning":"詢問；查詢","definition":"to ask for information from someone","collocations":["inquire about","inquire into","inquire politely"],"example":"She called the office to inquire about the job opening.","exampleZh":"她打電話到辦公室詢問職缺的事。","synonyms":["ask","question"],"level":4,"theme":"溝通與語言","examples":[{"en":"She called the office to inquire about the job opening.","zh":"她打電話到辦公室詢問職缺的事。"},{"en":"Many customers inquire about the store's opening hours during the holidays.","zh":"許多顧客詢問這家商店在假期期間的營業時間。"},{"en":"The reporter inquired politely into the details of the accident.","zh":"記者禮貌地查詢了這起意外的細節。"}]},{"word":"insect","pos":"n.","phonetic":"[ˈɪnsɛkt]","meaning":"昆蟲","definition":"a small animal with six legs, often with wings","collocations":["insect bite","insect repellent","harmful insects"],"example":"Bees and ants are common insects.","exampleZh":"蜜蜂和螞蟻是常見的昆蟲。","synonyms":["bug"],"level":2,"theme":"動物與植物","examples":[{"en":"Bees and ants are common insects.","zh":"蜜蜂和螞蟻是常見的昆蟲。"},{"en":"Remember to bring insect repellent when we go camping in the forest.","zh":"我們去森林露營時記得帶防蟲液。"},{"en":"Farmers use nets to protect their crops from harmful insects.","zh":"農夫用網子保護他們的作物免受有害昆蟲的侵害。"}]},{"word":"insert","pos":"v.","phonetic":"[ɪnˈsɝt]","meaning":"插入；嵌入","definition":"to place or fit something into something else","collocations":["insert a coin","insert a card","insert a comment"],"example":"Insert the key into the lock and turn it.","exampleZh":"把鑰匙插入鎖裡然後轉動。","synonyms":["put in"],"level":4,"theme":"動作與行為","examples":[{"en":"Insert the key into the lock and turn it.","zh":"把鑰匙插入鎖裡然後轉動。"},{"en":"Please insert a coin into the machine to buy a cold drink.","zh":"請投入一枚硬幣到機器裡購買一瓶冷飲。"},{"en":"The teacher asked me to insert a comment in the margin of my essay.","zh":"老師要我在作文的頁邊空白處插入一段評語。"}]},{"word":"inside","pos":"prep. / adv. / n.","phonetic":"[ɪnˈsaɪd]","meaning":"在...裡面；內部","definition":"within a place, container, or space","collocations":["inside out","go inside","inside the box"],"example":"Let's go inside; it's cold outside.","exampleZh":"我們進去吧，外面很冷。","synonyms":["within"],"level":1,"theme":"時間與空間","examples":[{"en":"Let's go inside; it's cold outside.","zh":"我們進去吧，外面很冷。"},{"en":"He was so careless that he wore his shirt inside out.","zh":"他太粗心了，把襯衫穿反了。"},{"en":"The children found a surprise gift hidden inside the box.","zh":"孩子們發現一份驚喜禮物藏在盒子裡面。"}]},{"word":"insist","pos":"v.","phonetic":"[ɪnˈsɪst]","meaning":"堅持","definition":"to demand something firmly, refusing to accept a refusal","collocations":["insist on","insist that","insist firmly"],"example":"She insisted on paying the bill.","exampleZh":"她堅持要付帳。","synonyms":["demand"],"level":4,"theme":"溝通與語言","examples":[{"en":"She insisted on paying the bill.","zh":"她堅持要付帳。"},{"en":"My parents insist that I finish my homework before watching television.","zh":"我的父母堅持要我在看電視前先完成功課。"},{"en":"She firmly insisted on walking home alone despite the heavy rain.","zh":"儘管下著大雨，她仍堅持要獨自走路回家。"}]},{"word":"inspect","pos":"v.","phonetic":"[ɪnˈspɛkt]","meaning":"檢查；視察","definition":"to look at someone or something closely to assess condition or quality","collocations":["inspect the building","carefully inspect","inspect goods"],"example":"The officer inspected the car before approving it.","exampleZh":"官員在核准前仔細檢查了那輛車。","synonyms":["examine","check"],"level":4,"theme":"工作與職業","examples":[{"en":"The officer inspected the car before approving it.","zh":"官員在核准前仔細檢查了那輛車。"},{"en":"The engineers came to inspect the building for any safety problems.","zh":"工程師來檢查這棟建築物是否有任何安全問題。"},{"en":"Workers carefully inspect each product before it leaves the factory.","zh":"工人在每件產品出廠前都仔細檢查。"}]},{"word":"inspire","pos":"v.","phonetic":"[ɪnˈspaɪr]","meaning":"激勵；啟發","definition":"to fill someone with the desire or ability to do something","collocations":["inspire confidence","inspire others","feel inspired"],"example":"The teacher inspired her students to dream big.","exampleZh":"這位老師激勵學生們懷抱遠大的夢想。","synonyms":["motivate","encourage"],"level":4,"theme":"情緒與感受","examples":[{"en":"The teacher inspired her students to dream big.","zh":"這位老師激勵學生們懷抱遠大的夢想。"},{"en":"Her brave story inspired others to never give up on their dreams.","zh":"她勇敢的故事激勵了其他人永不放棄他們的夢想。"},{"en":"After the speech, many young people felt inspired to help their community.","zh":"演講結束後，許多年輕人受到啟發，想要幫助他們的社區。"}]},{"word":"instance","pos":"n.","phonetic":"[ˈɪnstəns]","meaning":"例子；實例","definition":"an example or single occurrence of something","collocations":["for instance","in this instance","a rare instance"],"example":"For instance, many students struggle with time management.","exampleZh":"舉例來說，許多學生都在時間管理上遇到困難。","synonyms":["example","case"],"level":4,"theme":"抽象概念","examples":[{"en":"For instance, many students struggle with time management.","zh":"舉例來說，許多學生都在時間管理上遇到困難。"},{"en":"There are many healthy snacks; for instance, fruits and nuts are great choices.","zh":"有許多健康的零食；例如，水果和堅果都是很好的選擇。"},{"en":"In this instance, the teacher decided to make an exception for the sick student.","zh":"在這個例子中，老師決定為這位生病的學生破例。"}]},{"word":"instant","pos":"adj. / n.","phonetic":"[ˈɪnstənt]","meaning":"立即的；瞬間","definition":"happening or done immediately; a very short moment","collocations":["instant noodles","instant coffee","an instant later"],"example":"He felt an instant connection with her.","exampleZh":"他對她感到一見如故。","synonyms":["immediate"],"level":3,"theme":"時間與空間","examples":[{"en":"He felt an instant connection with her.","zh":"他對她感到一見如故。"},{"en":"College students often eat instant noodles when they are busy studying.","zh":"大學生忙於讀書時經常吃泡麵。"},{"en":"The lightning flashed, and an instant later we heard the thunder.","zh":"閃電閃過，一瞬間後我們就聽到了雷聲。"}]},{"word":"instead","pos":"adv.","phonetic":"[ɪnˈstɛd]","meaning":"取而代之；反而","definition":"as an alternative or substitute","collocations":["instead of","go instead","choose this instead"],"example":"Let's take the bus instead of driving.","exampleZh":"我們搭公車吧，不要開車了。","synonyms":["rather"],"level":2,"theme":"抽象概念","examples":[{"en":"Let's take the bus instead of driving.","zh":"我們搭公車吧，不要開車了。"},{"en":"She chose to drink water instead of soda to stay healthy.","zh":"為了保持健康，她選擇喝水而不是汽水。"},{"en":"I was too tired to cook, so we ordered pizza instead.","zh":"我太累了不想煮飯，所以我們改點了披薩。"}]},{"word":"instinct","pos":"n.","phonetic":"[ˈɪnstɪŋkt]","meaning":"本能；直覺","definition":"an innate, natural tendency to behave in a certain way","collocations":["survival instinct","trust your instinct","maternal instinct"],"example":"Animals rely on instinct to survive in the wild.","exampleZh":"動物靠本能在野外求生。","synonyms":["intuition"],"level":5,"theme":"抽象概念","examples":[{"en":"Animals rely on instinct to survive in the wild.","zh":"動物靠本能在野外求生。"},{"en":"You should trust your instinct when something feels dangerous.","zh":"當某件事感覺危險時，你應該相信自己的直覺。"},{"en":"A mother bird's maternal instinct drives her to protect her young.","zh":"母鳥的母性本能驅使她保護自己的幼鳥。"}]},{"word":"institute","pos":"n.","phonetic":"[ˈɪnstəˌtjut]","meaning":"機構；學院；研究所","definition":"an organization founded for a particular purpose, especially research or education","collocations":["research institute","technology institute","institute of art"],"example":"He works at a scientific research institute.","exampleZh":"他在一間科學研究機構工作。","synonyms":["organization","institution"],"level":5,"theme":"教育與學習","examples":[{"en":"He works at a scientific research institute.","zh":"他在一間科學研究機構工作。"},{"en":"She hopes to study at a famous technology institute after graduation.","zh":"她希望畢業後能到一所著名的科技學院就讀。"},{"en":"The research institute is looking for new ways to clean the ocean.","zh":"這家研究機構正在尋找清潔海洋的新方法。"}]},{"word":"instruct","pos":"v.","phonetic":"[ɪnˈstrʌkt]","meaning":"指示；教導","definition":"to teach someone a skill or give them an order","collocations":["instruct students","instruct someone to do","clearly instruct"],"example":"The coach instructed the players to warm up first.","exampleZh":"教練指示球員先熱身。","synonyms":["teach","direct"],"level":4,"theme":"教育與學習","examples":[{"en":"The coach instructed the players to warm up first.","zh":"教練指示球員先熱身。"},{"en":"The manager instructed the new staff to arrive early for training.","zh":"經理指示新進員工要提早到達參加訓練。"},{"en":"Our teacher instructs students patiently until they understand the lesson.","zh":"我們的老師耐心地教導學生，直到他們理解課程為止。"}]},{"word":"instrument","pos":"n.","phonetic":"[ˈɪnstrəmənt]","meaning":"工具；樂器","definition":"a tool used for delicate or scientific work, or a device for making music","collocations":["play an instrument","musical instrument","precision instrument"],"example":"The violin is a beautiful instrument.","exampleZh":"小提琴是一種美妙的樂器。","synonyms":["tool","device"],"level":3,"theme":"藝術與音樂","examples":[{"en":"The violin is a beautiful instrument.","zh":"小提琴是一種美妙的樂器。"},{"en":"Learning to play a musical instrument can improve your memory.","zh":"學習演奏樂器可以增進你的記憶力。"},{"en":"Scientists use precision instruments to measure very small distances.","zh":"科學家使用精密儀器來測量非常微小的距離。"}]},{"word":"insult","pos":"v. / n.","phonetic":"[ɪnˈsʌlt]","meaning":"侮辱；辱罵","definition":"to speak to or treat someone with disrespect","collocations":["insult someone","take it as an insult","hurl insults"],"example":"He felt insulted by her rude remark.","exampleZh":"他被她粗魯的話侮辱了。","synonyms":["offend","abuse"],"level":4,"theme":"溝通與語言","examples":[{"en":"He felt insulted by her rude remark.","zh":"他被她粗魯的話侮辱了。"},{"en":"It is rude to insult someone because of their appearance.","zh":"因為外表而侮辱別人是很無禮的。"},{"en":"She took his careless words as a personal insult.","zh":"她把他不經意的話當成對她個人的侮辱。"}]},{"word":"insurance","pos":"n.","phonetic":"[ɪnˈʃʊrəns]","meaning":"保險","definition":"a system of protection against financial loss","collocations":["health insurance","buy insurance","insurance company"],"example":"Every driver in the country must have car insurance.","exampleZh":"這個國家的每位駕駛都必須有汽車保險。","synonyms":[],"level":4,"theme":"商業與金錢","examples":[{"en":"Every driver in the country must have car insurance.","zh":"這個國家的每位駕駛都必須有汽車保險。"},{"en":"My father bought health insurance to protect our whole family.","zh":"我的父親買了健康保險來保障我們全家人。"},{"en":"The insurance company paid for the damage after the storm.","zh":"保險公司在暴風雨後支付了損失的賠償。"}]},{"word":"intelligent","pos":"adj.","phonetic":"[ɪnˈtɛlədʒənt]","meaning":"聰明的；有智慧的","definition":"having or showing a high level of mental capability","collocations":["highly intelligent","intelligent design","intelligent student"],"example":"Dolphins are known to be highly intelligent animals.","exampleZh":"海豚以高智商聞名。","synonyms":["smart","clever"],"level":3,"theme":"性質與描述","examples":[{"en":"Dolphins are known to be highly intelligent animals.","zh":"海豚以高智商聞名。"},{"en":"The intelligent student solved the difficult math problem in minutes.","zh":"這位聰明的學生在幾分鐘內就解出了那道困難的數學題。"},{"en":"Crows are surprisingly intelligent and can even use simple tools.","zh":"烏鴉出乎意料地聰明，甚至會使用簡單的工具。"}]},{"word":"intend","pos":"v.","phonetic":"[ɪnˈtɛnd]","meaning":"打算；意圖","definition":"to have a plan or purpose in mind; to want to do something","collocations":["intend to do","what is intended","fully intend"],"example":"I intend to finish the project by Friday.","exampleZh":"我打算在星期五前完成這個專案。","synonyms":["plan","mean"],"level":4,"theme":"抽象概念","examples":[{"en":"I intend to finish the project by Friday.","zh":"我打算在星期五前完成這個專案。"},{"en":"We intend to visit our grandparents during the summer vacation.","zh":"我們打算在暑假期間去探望祖父母。"},{"en":"She fully intended to apologize, but she never got the chance.","zh":"她本來完全打算道歉，但她始終沒有機會。"}]},{"word":"intense","pos":"adj.","phonetic":"[ɪnˈtɛns]","meaning":"強烈的；緊張的","definition":"of extreme force, degree, or strength","collocations":["intense heat","intense competition","intense emotion"],"example":"The competition between the two teams was intense.","exampleZh":"這兩隊之間的競爭非常激烈。","synonyms":["extreme","fierce"],"level":4,"theme":"情緒與感受","examples":[{"en":"The competition between the two teams was intense.","zh":"這兩隊之間的競爭非常激烈。"},{"en":"The intense heat of summer made everyone want to stay indoors.","zh":"夏天強烈的高溫讓每個人都想待在室內。"},{"en":"There was intense competition among the students for the scholarship.","zh":"學生之間為了獎學金展開了激烈的競爭。"}]},{"word":"interest","pos":"n. / v.","phonetic":"[ˈɪntərɪst]","meaning":"興趣；利息；利益","definition":"a feeling of wanting to know or be involved in something; money paid for the use of money","collocations":["take interest in","interest rate","lose interest"],"example":"She has always shown a great interest in astronomy.","exampleZh":"她一直對天文學展現濃厚的興趣。","synonyms":["curiosity"],"level":2,"theme":"教育與學習","examples":[{"en":"She has always shown a great interest in astronomy.","zh":"她一直對天文學展現濃厚的興趣。"},{"en":"The bank offers a higher interest rate on long-term savings.","zh":"這家銀行對長期存款提供較高的利率。"},{"en":"He soon lost interest in the game and went home early.","zh":"他很快就對這個遊戲失去了興趣，然後提早回家了。"}]},{"word":"interfere","pos":"v.","phonetic":"[ˌɪntɚˈfɪr]","meaning":"干涉；干擾","definition":"to intervene in a situation without invitation or excuse","collocations":["interfere with","interfere in","don't interfere"],"example":"Please don't interfere in our private matters.","exampleZh":"請不要干涉我們的私人事務。","synonyms":["meddle","intervene"],"level":5,"theme":"抽象概念","examples":[{"en":"Please don't interfere in our private matters.","zh":"請不要干涉我們的私人事務。"},{"en":"Too much noise can interfere with your ability to concentrate.","zh":"太多的噪音會干擾你集中注意力的能力。"},{"en":"Good parents know when not to interfere in their children's choices.","zh":"好的父母知道何時不該干涉孩子的選擇。"}]},{"word":"interior","pos":"n. / adj.","phonetic":"[ɪnˈtɪriɚ]","meaning":"內部；室內的","definition":"the inner part of something, especially a building","collocations":["interior design","car interior","interior wall"],"example":"The interior of the house was recently renovated.","exampleZh":"這棟房子的內部最近重新裝修過。","synonyms":["inside"],"level":4,"theme":"居家與生活","examples":[{"en":"The interior of the house was recently renovated.","zh":"這棟房子的內部最近重新裝修過。"},{"en":"She studies interior design and dreams of decorating hotels.","zh":"她主修室內設計，夢想著能裝潢飯店。"},{"en":"The interior walls were painted a soft shade of blue.","zh":"室內的牆壁被漆成柔和的藍色。"}]},{"word":"internal","pos":"adj.","phonetic":"[ɪnˈtɝnl̩]","meaning":"內部的；體內的","definition":"existing or occurring inside a body, organization, or country","collocations":["internal organs","internal affairs","internal conflict"],"example":"The doctor checked for any internal injuries.","exampleZh":"醫生檢查了是否有任何內傷。","synonyms":["inner","interior"],"level":4,"theme":"身體與健康","examples":[{"en":"The doctor checked for any internal injuries.","zh":"醫生檢查了是否有任何內傷。"},{"en":"The heart and lungs are important internal organs.","zh":"心臟和肺是重要的體內器官。"},{"en":"The company solved its internal conflict through honest discussion.","zh":"這家公司透過誠實的討論解決了它的內部衝突。"}]},{"word":"international","pos":"adj.","phonetic":"[ˌɪntɚˈnæʃənl̩]","meaning":"國際的","definition":"involving more than one country","collocations":["international trade","international flight","international students"],"example":"The company does international business.","exampleZh":"這家公司從事國際貿易。","synonyms":["global"],"level":3,"theme":"政治與法律","examples":[{"en":"The company does international business.","zh":"這家公司從事國際貿易。"},{"en":"Many international students come to Taiwan to learn Chinese.","zh":"許多國際學生來到台灣學習中文。"},{"en":"The airport handles hundreds of international flights every day.","zh":"這座機場每天處理數百架國際航班。"}]},{"word":"internet","pos":"n.","phonetic":"[ˈɪntɚˌnɛt]","meaning":"網際網路","definition":"a global computer network providing information and communication facilities","collocations":["surf the internet","internet connection","access the internet"],"example":"Most students today do research on the internet.","exampleZh":"現今大多數學生都在網路上做研究。","synonyms":["web"],"level":2,"theme":"科技與媒體","examples":[{"en":"Most students today do research on the internet.","zh":"現今大多數學生都在網路上做研究。"},{"en":"A stable internet connection is necessary for online classes.","zh":"穩定的網路連線對於線上課程是必要的。"},{"en":"He spends hours surfing the internet for interesting videos.","zh":"他花好幾個小時上網瀏覽有趣的影片。"}]},{"word":"interpret","pos":"v.","phonetic":"[ɪnˈtɝprɪt]","meaning":"詮釋；口譯","definition":"to explain the meaning of something or translate speech orally","collocations":["interpret a poem","interpret data","interpret for someone"],"example":"It's not easy to interpret his strange behavior.","exampleZh":"要解讀他奇怪的行為並不容易。","synonyms":["explain","translate"],"level":5,"theme":"溝通與語言","examples":[{"en":"It's not easy to interpret his strange behavior.","zh":"要解讀他奇怪的行為並不容易。"},{"en":"Scientists carefully interpret the data before making any conclusions.","zh":"科學家在下任何結論之前仔細地解讀資料。"},{"en":"She helped interpret for the foreign visitors during the meeting.","zh":"她在會議期間幫忙為外國訪客口譯。"}]},{"word":"interrupt","pos":"v.","phonetic":"[ˌɪntəˈrʌpt]","meaning":"打斷；打擾","definition":"to stop the continuous progress of an activity or a person speaking","collocations":["interrupt a conversation","sorry to interrupt","interrupt class"],"example":"Sorry to interrupt, but there's an urgent phone call for you.","exampleZh":"抱歉打擾了，有一通緊急電話找你。","synonyms":["disturb","cut in"],"level":4,"theme":"溝通與語言","examples":[{"en":"Sorry to interrupt, but there's an urgent phone call for you.","zh":"抱歉打擾了，有一通緊急電話找你。"},{"en":"It is impolite to interrupt a conversation between two adults.","zh":"打斷兩位大人之間的談話是不禮貌的。"},{"en":"The sudden alarm interrupted our class this morning.","zh":"突然的警報聲打斷了我們今天早上的課。"}]},{"word":"interval","pos":"n.","phonetic":"[ˈɪntɚvl̩]","meaning":"間隔；(節目)中場休息","definition":"an intervening period of time between two events","collocations":["at regular intervals","short interval","interval between shows"],"example":"The buses arrive at ten-minute intervals.","exampleZh":"公車每隔十分鐘來一班。","synonyms":["gap","break"],"level":5,"theme":"時間與空間","examples":[{"en":"The buses arrive at ten-minute intervals.","zh":"公車每隔十分鐘來一班。"},{"en":"The nurse checked the patient's temperature at regular intervals.","zh":"護士每隔固定的時間就為病人量一次體溫。"},{"en":"We bought some snacks during the interval between the two shows.","zh":"我們在兩場表演之間的中場休息時買了一些點心。"}]},{"word":"interview","pos":"n. / v.","phonetic":"[ˈɪntɚˌvju]","meaning":"面試；訪談","definition":"a meeting at which someone is asked questions, for a job or by the media","collocations":["job interview","conduct an interview","interview candidates"],"example":"She was very nervous before her job interview.","exampleZh":"她在面試前非常緊張。","synonyms":[],"level":3,"theme":"工作與職業","examples":[{"en":"She was very nervous before her job interview.","zh":"她在面試前非常緊張。"},{"en":"The manager will interview five candidates for the new position.","zh":"經理將面試五位應徵這個新職位的人選。"},{"en":"The radio host conducted an interview with a famous author.","zh":"電台主持人對一位著名作家進行了訪談。"}]},{"word":"intimate","pos":"adj.","phonetic":"[ˈɪntəmɪt]","meaning":"親密的；私人的","definition":"closely acquainted; having a close personal relationship","collocations":["intimate friend","intimate relationship","intimate details"],"example":"They have shared an intimate friendship since childhood.","exampleZh":"他們從小就有著親密的友誼。","synonyms":["close","personal"],"level":5,"theme":"情緒與感受","examples":[{"en":"They have shared an intimate friendship since childhood.","zh":"他們從小就有著親密的友誼。"},{"en":"She only shares her intimate secrets with her closest friend.","zh":"她只跟她最要好的朋友分享私密的秘密。"},{"en":"The two sisters have always had an intimate relationship.","zh":"這兩姊妹一直有著親密的關係。"}]},{"word":"into","pos":"prep.","phonetic":"[ˈɪntu]","meaning":"進入；到...裡面","definition":"expressing movement toward the inside of a place or thing","collocations":["walk into","turn into","look into"],"example":"The cat jumped into the box.","exampleZh":"那隻貓跳進了箱子裡。","synonyms":[],"level":1,"theme":"時間與空間","examples":[{"en":"The cat jumped into the box.","zh":"那隻貓跳進了箱子裡。"},{"en":"The caterpillar slowly turned into a beautiful butterfly.","zh":"毛毛蟲慢慢地變成了一隻美麗的蝴蝶。"},{"en":"The police promised to look into the mysterious case.","zh":"警方承諾會調查這起神秘的案件。"}]},{"word":"introduce","pos":"v.","phonetic":"[ˌɪntrəˈdjus]","meaning":"介紹；引進","definition":"to present someone by name to another; to bring something into use for the first time","collocations":["introduce oneself","introduce a new policy","introduce a friend"],"example":"Let me introduce you to my colleague, Sarah.","exampleZh":"讓我把你介紹給我的同事莎拉。","synonyms":["present"],"level":2,"theme":"溝通與語言","examples":[{"en":"Let me introduce you to my colleague, Sarah.","zh":"讓我把你介紹給我的同事莎拉。"},{"en":"On the first day of school, each student introduced themselves to the class.","zh":"開學第一天，每位學生都向全班自我介紹。"},{"en":"The government introduced a new policy to reduce plastic waste.","zh":"政府推行了一項減少塑膠垃圾的新政策。"}]},{"word":"invade","pos":"v.","phonetic":"[ɪnˈved]","meaning":"入侵；侵略","definition":"to enter a country or region with military force to conquer it","collocations":["invade a country","invade privacy","foreign invaders"],"example":"Enemy troops invaded the small village at dawn.","exampleZh":"敵軍在黎明時分入侵了這個小村莊。","synonyms":["attack","occupy"],"level":5,"theme":"政治與法律","examples":[{"en":"Enemy troops invaded the small village at dawn.","zh":"敵軍在黎明時分入侵了這個小村莊。"},{"en":"Reading someone's diary is a way to invade their privacy.","zh":"偷看別人的日記是一種侵犯隱私的行為。"},{"en":"Weeds quickly invaded the garden after weeks of heavy rain.","zh":"下了好幾週的大雨後，雜草很快就入侵了花園。"}]},{"word":"invent","pos":"v.","phonetic":"[ɪnˈvɛnt]","meaning":"發明；捏造","definition":"to create or design something that has not existed before","collocations":["invent a machine","invent an excuse","who invented"],"example":"Thomas Edison invented the light bulb.","exampleZh":"湯瑪斯·愛迪生發明了電燈泡。","synonyms":["create","devise"],"level":3,"theme":"科技與媒體","examples":[{"en":"Thomas Edison invented the light bulb.","zh":"湯瑪斯·愛迪生發明了電燈泡。"},{"en":"The boy tried to invent an excuse for being late to class.","zh":"這個男孩試圖捏造一個上課遲到的藉口。"},{"en":"Engineers hope to invent a machine that cleans the air.","zh":"工程師希望發明一台能淨化空氣的機器。"}]},{"word":"invention","pos":"n.","phonetic":"[ɪnˈvɛnʃən]","meaning":"發明；發明物","definition":"the action of inventing something, or a device created for the first time","collocations":["a useful invention","modern invention","the invention of"],"example":"The smartphone is one of the greatest inventions of our time.","exampleZh":"智慧型手機是我們這個時代最偉大的發明之一。","synonyms":["creation","innovation"],"level":3,"theme":"科技與媒體","examples":[{"en":"The smartphone is one of the greatest inventions of our time.","zh":"智慧型手機是我們這個時代最偉大的發明之一。"},{"en":"The invention of the wheel changed human history forever.","zh":"輪子的發明永遠地改變了人類的歷史。"},{"en":"The umbrella is a simple but very useful invention.","zh":"雨傘是一項簡單但非常實用的發明。"}]},{"word":"invest","pos":"v.","phonetic":"[ɪnˈvɛst]","meaning":"投資","definition":"to put money into something in order to gain a profit","collocations":["invest in stocks","invest money","invest time"],"example":"He decided to invest in the stock market.","exampleZh":"他決定投資股票市場。","synonyms":[],"level":4,"theme":"商業與金錢","examples":[{"en":"He decided to invest in the stock market.","zh":"他決定投資股票市場。"},{"en":"It is wise to invest time in learning new skills.","zh":"花時間學習新技能是明智的做法。"},{"en":"My uncle invested his savings in a small coffee shop.","zh":"我的叔叔把積蓄投資在一家小咖啡店。"}]},{"word":"investigate","pos":"v.","phonetic":"[ɪnˈvɛstəˌget]","meaning":"調查；研究","definition":"to carry out research or an official inquiry into something","collocations":["investigate a crime","investigate the cause","thoroughly investigate"],"example":"The police are investigating the cause of the fire.","exampleZh":"警方正在調查這場火災的起因。","synonyms":["examine","explore"],"level":4,"theme":"政治與法律","examples":[{"en":"The police are investigating the cause of the fire.","zh":"警方正在調查這場火災的起因。"},{"en":"Scientists are investigating the cause of the strange disease.","zh":"科學家正在調查這種奇怪疾病的起因。"},{"en":"The detective thoroughly investigated every clue at the scene.","zh":"偵探徹底調查了現場的每一條線索。"}]},{"word":"invisible","pos":"adj.","phonetic":"[ɪnˈvɪzəbḷ]","meaning":"隱形的；看不見的","definition":"unable to be seen","collocations":["invisible ink","become invisible","an invisible force"],"example":"The scientist created a suit that made him nearly invisible.","exampleZh":"這位科學家做出一套幾乎讓他隱形的衣服。","synonyms":["unseen"],"level":3,"theme":"性質與描述","examples":[{"en":"The scientist created a suit that made him nearly invisible.","zh":"這位科學家做出一套幾乎讓他隱形的衣服。"},{"en":"The children wrote secret messages using invisible ink.","zh":"孩子們用隱形墨水寫下秘密訊息。"},{"en":"Gravity is an invisible force that pulls objects toward the ground.","zh":"重力是一種將物體拉向地面的看不見的力量。"}]},{"word":"invite","pos":"v.","phonetic":"[ɪnˈvaɪt]","meaning":"邀請","definition":"to ask someone to attend an event or come somewhere","collocations":["invite friends","invite someone over","kindly invite"],"example":"We invited all our relatives to the wedding.","exampleZh":"我們邀請了所有的親戚來參加婚禮。","synonyms":["ask","request"],"level":2,"theme":"社會與文化","examples":[{"en":"We invited all our relatives to the wedding.","zh":"我們邀請了所有的親戚來參加婚禮。"},{"en":"She decided to invite a few friends over for dinner.","zh":"她決定邀請幾個朋友過來吃晚餐。"},{"en":"They kindly invited us to join their New Year celebration.","zh":"他們親切地邀請我們參加他們的新年慶祝活動。"}]},{"word":"involve","pos":"v.","phonetic":"[ɪnˈvɑlv]","meaning":"涉及；使參與","definition":"to include or affect something or someone as a necessary part","collocations":["involve risk","get involved in","involve many people"],"example":"The project will involve a lot of teamwork.","exampleZh":"這個專案將需要大量的團隊合作。","synonyms":["include","entail"],"level":3,"theme":"抽象概念","examples":[{"en":"The project will involve a lot of teamwork.","zh":"這個專案將需要大量的團隊合作。"},{"en":"Climbing that steep mountain may involve serious risk.","zh":"攀登那座陡峭的山可能涉及嚴重的風險。"},{"en":"Many volunteers got involved in cleaning up the dirty beach.","zh":"許多志工參與了清理骯髒海灘的活動。"}]},{"word":"iron","pos":"n. / v.","phonetic":"[ˈaɪɚn]","meaning":"鐵；熨斗；熨燙","definition":"a strong, hard metal; a device used to smooth clothes","collocations":["iron a shirt","made of iron","iron will"],"example":"She ironed her shirt before the interview.","exampleZh":"她在面試前熨了她的襯衫。","synonyms":[],"level":2,"theme":"居家與生活","examples":[{"en":"She ironed her shirt before the interview.","zh":"她在面試前熨了她的襯衫。"},{"en":"The old gate was made of iron and had rusted over time.","zh":"那扇舊大門是鐵製的，隨著時間已經生鏽了。"},{"en":"With an iron will, she trained every day to win the race.","zh":"憑著鋼鐵般的意志，她每天訓練以贏得比賽。"}]},{"word":"irony","pos":"n.","phonetic":"[ˈaɪrəni]","meaning":"諷刺；反語","definition":"a situation or use of language marked by incongruity between expectation and reality","collocations":["the irony of the situation","dramatic irony","full of irony"],"example":"The irony is that he lost the race he trained so hard for.","exampleZh":"諷刺的是，他為之苦練的那場比賽卻輸了。","synonyms":["sarcasm"],"level":5,"theme":"抽象概念","examples":[{"en":"The irony is that he lost the race he trained so hard for.","zh":"諷刺的是，他為之苦練的那場比賽卻輸了。"},{"en":"The irony is that the fire station itself caught fire.","zh":"諷刺的是，消防局本身竟然著火了。"},{"en":"There was a touch of irony in her cheerful reply.","zh":"她愉快的回答中帶著一絲諷刺。"}]},{"word":"irritate","pos":"v.","phonetic":"[ˈɪrəˌtet]","meaning":"使惱怒；刺激","definition":"to make someone annoyed or impatient; to cause inflammation to a body part","collocations":["irritate the skin","easily irritated","irritate someone"],"example":"The loud noise from next door really irritates me.","exampleZh":"隔壁傳來的噪音真的讓我很惱火。","synonyms":["annoy","bother"],"level":5,"theme":"情緒與感受","examples":[{"en":"The loud noise from next door really irritates me.","zh":"隔壁傳來的噪音真的讓我很惱火。"},{"en":"The rough wool sweater irritated her sensitive skin.","zh":"那件粗糙的羊毛毛衣刺激了她敏感的皮膚。"},{"en":"He is easily irritated when people are late for appointments.","zh":"當人們約會遲到時，他很容易被惹惱。"}]},{"word":"island","pos":"n.","phonetic":"[ˈaɪlənd]","meaning":"島嶼","definition":"a piece of land surrounded by water","collocations":["a tropical island","live on an island","island nation"],"example":"Taiwan is an island located in East Asia.","exampleZh":"台灣是位於東亞的一座島嶼。","synonyms":[],"level":1,"theme":"自然與環境","examples":[{"en":"Taiwan is an island located in East Asia.","zh":"台灣是位於東亞的一座島嶼。"},{"en":"They spent their honeymoon on a beautiful tropical island.","zh":"他們在一座美麗的熱帶島嶼上度過蜜月。"},{"en":"People who live on a small island often depend on fishing.","zh":"住在小島上的人們經常仰賴捕魚維生。"}]},{"word":"isolate","pos":"v.","phonetic":"[ˈaɪsəˌlet]","meaning":"使隔離；使孤立","definition":"to set apart from others; to place alone","collocations":["isolate a patient","feel isolated","isolate oneself"],"example":"The sick patients were isolated to prevent the disease from spreading.","exampleZh":"病患被隔離以防止疾病傳播。","synonyms":["separate","seclude"],"level":5,"theme":"身體與健康","examples":[{"en":"The sick patients were isolated to prevent the disease from spreading.","zh":"病患被隔離以防止疾病傳播。"},{"en":"Moving to a new city made him feel isolated at first.","zh":"搬到一個新城市起初讓他感到孤立。"},{"en":"The scientist isolated the sample to study it more carefully.","zh":"科學家將樣本隔離出來以便更仔細地研究。"}]},{"word":"issue","pos":"n. / v.","phonetic":"[ˈɪʃu]","meaning":"議題；問題；發行","definition":"an important topic for debate; to formally supply or distribute something","collocations":["a major issue","issue a statement","environmental issues"],"example":"Climate change is a major issue facing the world today.","exampleZh":"氣候變遷是當今世界面臨的重大議題。","synonyms":["topic","matter"],"level":3,"theme":"社會與文化","examples":[{"en":"Climate change is a major issue facing the world today.","zh":"氣候變遷是當今世界面臨的重大議題。"},{"en":"The government issued a statement about the new traffic rules.","zh":"政府發布了一份關於新交通規則的聲明。"},{"en":"Students discussed important environmental issues during the class debate.","zh":"學生在課堂辯論中討論了重要的環境議題。"}]},{"word":"itch","pos":"v. / n.","phonetic":"[ɪtʃ]","meaning":"發癢；癢","definition":"an uncomfortable sensation on the skin that causes a desire to scratch","collocations":["itch all over","an itch on the arm","make someone itch"],"example":"The mosquito bite on my leg started to itch.","exampleZh":"我腿上被蚊子咬的地方開始發癢。","synonyms":["scratch"],"level":3,"theme":"身體與健康","examples":[{"en":"The mosquito bite on my leg started to itch.","zh":"我腿上被蚊子咬的地方開始發癢。"},{"en":"After walking through the tall grass, my legs began to itch all over.","zh":"走過高高的草叢後，我的雙腿開始全都發癢。"},{"en":"The wool blanket made her skin itch during the night.","zh":"那條羊毛毯讓她的皮膚在夜裡發癢。"}]},{"word":"item","pos":"n.","phonetic":"[ˈaɪtəm]","meaning":"項目；物品","definition":"an individual article or object, especially one included in a list","collocations":["an item on the list","expensive item","a news item"],"example":"Please check each item on the shopping list.","exampleZh":"請檢查購物清單上的每一項物品。","synonyms":["article","object"],"level":2,"theme":"商業與金錢","examples":[{"en":"Please check each item on the shopping list.","zh":"請檢查購物清單上的每一項物品。"},{"en":"She crossed off each item on her shopping list one by one.","zh":"她把購物清單上的每一個項目逐一劃掉。"},{"en":"An interesting news item caught my attention this morning.","zh":"今天早上一則有趣的新聞吸引了我的注意。"}]},{"word":"ivory","pos":"n.","phonetic":"[ˈaɪvəri]","meaning":"象牙","definition":"a hard creamy-white substance forming the tusks of elephants","collocations":["ivory tusk","ivory carving","illegal ivory trade"],"example":"The illegal trade of ivory has endangered many elephants.","exampleZh":"非法象牙貿易已使許多大象瀕臨滅絕。","synonyms":[],"level":5,"theme":"動物與植物","examples":[{"en":"The illegal trade of ivory has endangered many elephants.","zh":"非法象牙貿易已使許多大象瀕臨滅絕。"},{"en":"The museum displayed a delicate ivory carving from ancient times.","zh":"博物館展示了一件來自古代的精緻象牙雕刻。"},{"en":"Many countries have banned the illegal ivory trade to protect elephants.","zh":"許多國家已禁止非法象牙交易以保護大象。"}]},{"word":"ivy","pos":"n.","phonetic":"[ˈaɪvi]","meaning":"常春藤","definition":"a climbing evergreen plant with dark green leaves","collocations":["ivy-covered wall","climbing ivy","a bed of ivy"],"example":"The old castle walls were covered with ivy.","exampleZh":"這座古老城堡的牆壁爬滿了常春藤。","synonyms":[],"level":5,"theme":"動物與植物","examples":[{"en":"The old castle walls were covered with ivy.","zh":"這座古老城堡的牆壁爬滿了常春藤。"},{"en":"Green ivy climbed slowly up the side of the old library.","zh":"綠色的常春藤緩緩地爬上老圖書館的側面。"},{"en":"The ivy-covered wall gave the house a charming, old-fashioned look.","zh":"爬滿常春藤的牆使這棟房子有一種迷人的復古外觀。"}]},{"word":"jacket","pos":"n.","phonetic":"[ˈdʒækɪt]","meaning":"夾克；外套","definition":"a short coat, usually with sleeves","collocations":["put on a jacket","leather jacket","life jacket"],"example":"She wore a warm jacket to school this morning.","exampleZh":"她今天早上穿著一件保暖的夾克去上學。","synonyms":["coat"],"level":1,"theme":"服裝與外表","examples":[{"en":"She wore a warm jacket to school this morning.","zh":"她今天早上穿著一件保暖的夾克去上學。"},{"en":"Everyone on the boat must wear a life jacket for safety.","zh":"船上的每個人都必須穿救生衣以策安全。"},{"en":"He put on a thick jacket before going out into the snow.","zh":"他在走進雪中之前穿上了一件厚外套。"}]},{"word":"jail","pos":"n. / v.","phonetic":"[dʒel]","meaning":"監獄；監禁","definition":"a place where criminals are kept as punishment","collocations":["go to jail","put someone in jail","escape from jail"],"example":"The thief was sent to jail for two years.","exampleZh":"那個小偷被關進監獄兩年。","synonyms":["prison"],"level":3,"theme":"政治與法律","examples":[{"en":"The thief was sent to jail for two years.","zh":"那個小偷被關進監獄兩年。"},{"en":"The judge decided to put the dangerous criminal in jail.","zh":"法官決定將這名危險的罪犯關進監獄。"},{"en":"Two prisoners tried to escape from jail last night.","zh":"兩名囚犯昨晚試圖從監獄逃跑。"}]},{"word":"jam","pos":"n. / v.","phonetic":"[dʒæm]","meaning":"果醬；擁擠；卡住","definition":"a sweet food made from fruit, or to become stuck","collocations":["strawberry jam","traffic jam","jam the door"],"example":"We were stuck in a traffic jam for an hour.","exampleZh":"我們被困在車陣中長達一個小時。","synonyms":["block"],"level":2,"theme":"食物與烹飪","examples":[{"en":"We were stuck in a traffic jam for an hour.","zh":"我們被困在車陣中長達一個小時。"},{"en":"She spread strawberry jam on her warm toast for breakfast.","zh":"她早餐時在溫熱的吐司上塗草莓果醬。"},{"en":"The heavy box jammed the door so we couldn't open it.","zh":"那個沉重的箱子卡住了門，所以我們打不開它。"}]},{"word":"January","pos":"n.","phonetic":"[ˈdʒænjuˌɛrɪ]","meaning":"一月","definition":"the first month of the year","collocations":["in January","early January","last January"],"example":"My birthday is in January.","exampleZh":"我的生日在一月。","synonyms":[],"level":1,"theme":"天氣與季節","examples":[{"en":"My birthday is in January.","zh":"我的生日在一月。"},{"en":"The weather in January is usually cold and rainy here.","zh":"這裡一月的天氣通常又冷又多雨。"},{"en":"We started our new project in early January this year.","zh":"我們今年在一月初開始了新的專案。"}]},{"word":"jar","pos":"n.","phonetic":"[dʒɑr]","meaning":"罐子；廣口瓶","definition":"a glass container with a wide opening, used for storing food","collocations":["a jar of honey","glass jar","open a jar"],"example":"She kept the cookies in a large glass jar.","exampleZh":"她把餅乾放在一個大玻璃罐裡。","synonyms":["container"],"level":2,"theme":"居家與生活","examples":[{"en":"She kept the cookies in a large glass jar.","zh":"她把餅乾放在一個大玻璃罐裡。"},{"en":"She bought a jar of honey at the local farmers' market.","zh":"她在當地的農夫市集買了一罐蜂蜜。"},{"en":"He struggled to open the jar because the lid was too tight.","zh":"他很難打開這個罐子，因為蓋子太緊了。"}]},{"word":"jaw","pos":"n.","phonetic":"[dʒɔ]","meaning":"顎；下巴","definition":"either of the two bones that form the framework of the mouth","collocations":["lower jaw","clench one's jaw","broken jaw"],"example":"He broke his jaw in the accident.","exampleZh":"他在那場意外中弄斷了下巴。","synonyms":[],"level":3,"theme":"身體與健康","examples":[{"en":"He broke his jaw in the accident.","zh":"他在那場意外中弄斷了下巴。"},{"en":"He clenched his jaw tightly to hold back his anger.","zh":"他緊咬著下巴，忍住怒氣。"},{"en":"The dentist examined her lower jaw for any problems.","zh":"牙醫檢查她的下顎是否有任何問題。"}]},{"word":"jazz","pos":"n.","phonetic":"[dʒæz]","meaning":"爵士樂","definition":"a type of music with strong rhythms, originating from African American culture","collocations":["jazz music","jazz band","play jazz"],"example":"He plays the saxophone in a jazz band.","exampleZh":"他在一個爵士樂團裡吹薩克斯風。","synonyms":[],"level":3,"theme":"藝術與音樂","examples":[{"en":"He plays the saxophone in a jazz band.","zh":"他在一個爵士樂團裡吹薩克斯風。"},{"en":"We listened to relaxing jazz music at the small cafe.","zh":"我們在那家小咖啡館裡聽著放鬆的爵士樂。"},{"en":"The jazz band performed on the street corner every weekend.","zh":"那支爵士樂團每個週末都在街角表演。"}]},{"word":"jealous","pos":"adj.","phonetic":"[ˈdʒɛləs]","meaning":"嫉妒的；吃醋的","definition":"feeling envious of someone's advantages or success","collocations":["feel jealous","jealous of someone","get jealous"],"example":"She felt jealous when her friend won the prize.","exampleZh":"當她的朋友贏得獎項時，她感到嫉妒。","synonyms":["envious"],"level":3,"theme":"情緒與感受","examples":[{"en":"She felt jealous when her friend won the prize.","zh":"當她的朋友贏得獎項時，她感到嫉妒。"},{"en":"He felt jealous of his older brother's shiny new bicycle.","zh":"他嫉妒他哥哥閃亮的新腳踏車。"},{"en":"Try not to get jealous when your classmates succeed.","zh":"當你的同學成功時，盡量不要嫉妒。"}]},{"word":"jeans","pos":"n.","phonetic":"[dʒinz]","meaning":"牛仔褲","definition":"trousers made of strong cotton cloth, usually blue","collocations":["a pair of jeans","blue jeans","wear jeans"],"example":"He always wears jeans and a T-shirt.","exampleZh":"他總是穿牛仔褲和T恤。","synonyms":[],"level":1,"theme":"服裝與外表","examples":[{"en":"He always wears jeans and a T-shirt.","zh":"他總是穿牛仔褲和T恤。"},{"en":"She bought a new pair of jeans for the school trip.","zh":"她為了校外教學買了一條新牛仔褲。"},{"en":"These blue jeans are comfortable enough to wear all day.","zh":"這條藍色牛仔褲舒適到可以穿一整天。"}]},{"word":"jelly","pos":"n.","phonetic":"[ˈdʒɛlɪ]","meaning":"果凍；果醬","definition":"a soft, sweet food that shakes when moved","collocations":["jelly beans","grape jelly","make jelly"],"example":"The children love eating jelly for dessert.","exampleZh":"孩子們喜歡吃果凍當甜點。","synonyms":[],"level":1,"theme":"食物與烹飪","examples":[{"en":"The children love eating jelly for dessert.","zh":"孩子們喜歡吃果凍當甜點。"},{"en":"The colorful jelly beans were the children's favorite treat.","zh":"五顏六色的雷根糖是孩子們最愛的零食。"},{"en":"My grandmother taught me how to make grape jelly at home.","zh":"我的祖母教我如何在家自製葡萄果醬。"}]},{"word":"jet","pos":"n.","phonetic":"[dʒɛt]","meaning":"噴射機；噴射流","definition":"an aircraft powered by jet engines","collocations":["jet plane","jet engine","jet lag"],"example":"The jet took off smoothly from the runway.","exampleZh":"噴射機平穩地從跑道起飛。","synonyms":["airplane"],"level":3,"theme":"交通與旅行","examples":[{"en":"The jet took off smoothly from the runway.","zh":"噴射機平穩地從跑道起飛。"},{"en":"After the long flight, she suffered from serious jet lag.","zh":"經過漫長的飛行後，她受到嚴重時差之苦。"},{"en":"The powerful jet engine roared as the plane sped up.","zh":"飛機加速時，強大的噴射引擎發出轟鳴聲。"}]},{"word":"jewel","pos":"n.","phonetic":"[ˈdʒuəl]","meaning":"珠寶；寶石","definition":"a precious stone used in jewelry","collocations":["precious jewel","jewel box","shining jewel"],"example":"The crown was decorated with rare jewels.","exampleZh":"這頂皇冠裝飾著稀有的寶石。","synonyms":["gem"],"level":3,"theme":"服裝與外表","examples":[{"en":"The crown was decorated with rare jewels.","zh":"這頂皇冠裝飾著稀有的寶石。"},{"en":"The queen kept her precious jewels in a locked box.","zh":"王后把她珍貴的寶石鎖在一個盒子裡。"},{"en":"A shining jewel sparkled on top of the golden ring.","zh":"一顆閃亮的寶石在金戒指上閃閃發光。"}]},{"word":"jewelry","pos":"n.","phonetic":"[ˈdʒuəlrɪ]","meaning":"珠寶；首飾","definition":"decorative items such as rings and necklaces worn on the body","collocations":["jewelry store","wear jewelry","gold jewelry"],"example":"She bought some jewelry for her mother's birthday.","exampleZh":"她買了一些珠寶送給媽媽當生日禮物。","synonyms":["accessories"],"level":3,"theme":"服裝與外表","examples":[{"en":"She bought some jewelry for her mother's birthday.","zh":"她買了一些珠寶送給媽媽當生日禮物。"},{"en":"She rarely wears jewelry except on very special occasions.","zh":"除了非常特別的場合，她很少配戴首飾。"},{"en":"The thief broke into the jewelry store late at night.","zh":"小偷在深夜闖入了那家珠寶店。"}]},{"word":"job","pos":"n.","phonetic":"[dʒɑb]","meaning":"工作；職業","definition":"the regular work a person does to earn money","collocations":["find a job","part-time job","do a good job"],"example":"He got a job at a local bakery.","exampleZh":"他在當地一家麵包店找到了工作。","synonyms":["occupation","work"],"level":1,"theme":"工作與職業","examples":[{"en":"He got a job at a local bakery.","zh":"他在當地一家麵包店找到了工作。"},{"en":"She works a part-time job at the library after school.","zh":"她放學後在圖書館做兼職工作。"},{"en":"The teacher praised him for doing a good job on his report.","zh":"老師稱讚他的報告做得很好。"}]},{"word":"jog","pos":"v. / n.","phonetic":"[dʒɑg]","meaning":"慢跑","definition":"to run at a slow, steady pace, especially for exercise","collocations":["go jogging","jog in the park","morning jog"],"example":"I jog in the park every morning.","exampleZh":"我每天早上都在公園裡慢跑。","synonyms":["run"],"level":2,"theme":"運動與休閒","examples":[{"en":"I jog in the park every morning.","zh":"我每天早上都在公園裡慢跑。"},{"en":"We often go jogging together before breakfast on weekends.","zh":"週末我們常常在早餐前一起去慢跑。"},{"en":"A short morning jog helps him feel awake and energetic.","zh":"早晨短暫的慢跑幫助他感到清醒且有活力。"}]},{"word":"join","pos":"v.","phonetic":"[dʒɔɪn]","meaning":"加入；參加；連接","definition":"to become a member of a group, or to connect things together","collocations":["join a club","join hands","join forces"],"example":"Would you like to join our basketball team?","exampleZh":"你想加入我們的籃球隊嗎？","synonyms":["participate","connect"],"level":1,"theme":"動作與行為","examples":[{"en":"Would you like to join our basketball team?","zh":"你想加入我們的籃球隊嗎？"},{"en":"The two schools joined forces to organize a charity event.","zh":"這兩所學校聯手舉辦了一場慈善活動。"},{"en":"She decided to join the school's photography club this semester.","zh":"她決定這學期加入學校的攝影社。"}]},{"word":"joint","pos":"n. / adj.","phonetic":"[dʒɔɪnt]","meaning":"關節；接合處；聯合的","definition":"a point where two bones meet, or shared by two or more people","collocations":["knee joint","joint effort","joint account"],"example":"The two companies made a joint decision to merge.","exampleZh":"這兩家公司做出了合併的共同決定。","synonyms":["shared","combined"],"level":4,"theme":"身體與健康","examples":[{"en":"The two companies made a joint decision to merge.","zh":"這兩家公司做出了合併的共同決定。"},{"en":"After the marathon, the runner's knee joint felt very sore.","zh":"馬拉松結束後，這名跑者的膝關節感到非常痠痛。"},{"en":"The clean park was the result of a joint effort by the neighbors.","zh":"這座乾淨的公園是鄰居們共同努力的成果。"}]},{"word":"joke","pos":"n. / v.","phonetic":"[dʒok]","meaning":"笑話；玩笑","definition":"something said or done to cause laughter","collocations":["tell a joke","play a joke on","just joking"],"example":"He told a funny joke at the party.","exampleZh":"他在派對上講了一個好笑的笑話。","synonyms":["gag"],"level":2,"theme":"溝通與語言","examples":[{"en":"He told a funny joke at the party.","zh":"他在派對上講了一個好笑的笑話。"},{"en":"My uncle loves to tell a funny joke at every family dinner.","zh":"我的叔叔喜歡在每次家庭晚餐時講一個好笑的笑話。"},{"en":"Don't be angry; I was just joking with you.","zh":"別生氣，我只是在跟你開玩笑。"}]},{"word":"jolly","pos":"adj.","phonetic":"[ˈdʒɑlɪ]","meaning":"快活的；愉快的","definition":"happy and cheerful","collocations":["jolly mood","jolly old man","a jolly time"],"example":"The jolly old man greeted everyone with a smile.","exampleZh":"那位快活的老人微笑著和每個人打招呼。","synonyms":["cheerful","merry"],"level":5,"theme":"情緒與感受","examples":[{"en":"The jolly old man greeted everyone with a smile.","zh":"那位快活的老人微笑著和每個人打招呼。"},{"en":"Everyone was in a jolly mood during the holiday party.","zh":"假日派對上大家都心情愉快。"},{"en":"We had a jolly time singing songs around the campfire.","zh":"我們圍著營火唱歌，度過了一段快活的時光。"}]},{"word":"journal","pos":"n.","phonetic":"[ˈdʒɝnl]","meaning":"日誌；期刊","definition":"a regular written record of events, or a magazine on a special subject","collocations":["keep a journal","scientific journal","write in a journal"],"example":"She writes in her journal every night before bed.","exampleZh":"她每晚睡前都會在日誌上寫東西。","synonyms":["diary","magazine"],"level":4,"theme":"教育與學習","examples":[{"en":"She writes in her journal every night before bed.","zh":"她每晚睡前都會在日誌上寫東西。"},{"en":"Keeping a journal helps her remember her happiest moments.","zh":"寫日誌幫助她記住最快樂的時刻。"},{"en":"The professor published her research in a scientific journal.","zh":"這位教授將她的研究發表在一份科學期刊上。"}]},{"word":"journalist","pos":"n.","phonetic":"[ˈdʒɝnəlɪst]","meaning":"新聞記者","definition":"a person who writes news for newspapers, magazines, or broadcasts","collocations":["a young journalist","work as a journalist","investigative journalist"],"example":"The journalist interviewed the mayor about the new policy.","exampleZh":"那位記者就新政策採訪了市長。","synonyms":["reporter"],"level":4,"theme":"工作與職業","examples":[{"en":"The journalist interviewed the mayor about the new policy.","zh":"那位記者就新政策採訪了市長。"},{"en":"She dreams of working as a journalist for a major newspaper.","zh":"她夢想能在一家大報社擔任記者。"},{"en":"The investigative journalist spent months uncovering the truth.","zh":"這名調查記者花了好幾個月揭露真相。"}]},{"word":"journey","pos":"n. / v.","phonetic":"[ˈdʒɝnɪ]","meaning":"旅程；旅行","definition":"an act of traveling from one place to another, often a long one","collocations":["a long journey","go on a journey","journey home"],"example":"They went on a long journey across Europe.","exampleZh":"他們展開了一趟橫越歐洲的長途旅程。","synonyms":["trip","voyage"],"level":3,"theme":"交通與旅行","examples":[{"en":"They went on a long journey across Europe.","zh":"他們展開了一趟橫越歐洲的長途旅程。"},{"en":"The journey home took longer than usual because of the snow.","zh":"因為下雪，回家的旅程比平常花了更久的時間。"},{"en":"Learning a language is a long journey that requires patience.","zh":"學習一門語言是一段需要耐心的漫長旅程。"}]},{"word":"joy","pos":"n.","phonetic":"[dʒɔɪ]","meaning":"喜悅；快樂","definition":"a feeling of great happiness","collocations":["with joy","bring joy","jump for joy"],"example":"Her face lit up with joy when she saw the puppy.","exampleZh":"當她看到小狗時，臉上洋溢著喜悅。","synonyms":["happiness","delight"],"level":2,"theme":"情緒與感受","examples":[{"en":"Her face lit up with joy when she saw the puppy.","zh":"當她看到小狗時，臉上洋溢著喜悅。"},{"en":"The children jumped for joy when they saw the falling snow.","zh":"孩子們看到飄落的雪時高興得跳了起來。"},{"en":"Volunteering at the animal shelter brings her great joy.","zh":"在動物收容所當志工為她帶來極大的喜悅。"}]},{"word":"joyful","pos":"adj.","phonetic":"[ˈdʒɔɪfəl]","meaning":"喜悅的；歡欣的","definition":"feeling, expressing, or causing great happiness","collocations":["joyful occasion","joyful news","a joyful celebration"],"example":"It was a joyful celebration for the whole family.","exampleZh":"這對全家人來說是一場歡樂的慶祝活動。","synonyms":["happy","cheerful"],"level":4,"theme":"情緒與感受","examples":[{"en":"It was a joyful celebration for the whole family.","zh":"這對全家人來說是一場歡樂的慶祝活動。"},{"en":"The birth of the baby was joyful news for the whole family.","zh":"寶寶的誕生對全家人來說是喜悅的消息。"},{"en":"Their wedding was a truly joyful occasion for everyone.","zh":"他們的婚禮對每個人來說都是一個真正歡欣的場合。"}]},{"word":"judge","pos":"n. / v.","phonetic":"[dʒʌdʒ]","meaning":"法官；裁判；判斷","definition":"a public official who decides cases in a court of law, or to form an opinion","collocations":["a fair judge","judge a competition","judge by appearance"],"example":"The judge listened carefully before making a decision.","exampleZh":"法官在做出判決前仔細地聆聽。","synonyms":["evaluate"],"level":3,"theme":"政治與法律","examples":[{"en":"The judge listened carefully before making a decision.","zh":"法官在做出判決前仔細地聆聽。"},{"en":"You should never judge a person by their appearance.","zh":"你絕不應該以外表來評斷一個人。"},{"en":"Three teachers were invited to judge the singing competition.","zh":"三位老師受邀擔任歌唱比賽的評審。"}]},{"word":"judgment","pos":"n.","phonetic":"[ˈdʒʌdʒmənt]","meaning":"判斷；判決；評價","definition":"the ability to make sensible decisions, or an official decision of a court","collocations":["good judgment","make a judgment","court judgment"],"example":"You should trust your own judgment.","exampleZh":"你應該相信自己的判斷。","synonyms":["verdict","opinion"],"level":5,"theme":"抽象概念","examples":[{"en":"You should trust your own judgment.","zh":"你應該相信自己的判斷。"},{"en":"A good leader must show fair judgment in difficult situations.","zh":"一位好的領導者必須在困難的情況下展現公正的判斷。"},{"en":"Don't make a quick judgment before you know all the facts.","zh":"在你了解所有事實之前，不要太快下判斷。"}]},{"word":"judo","pos":"n.","phonetic":"[ˈdʒudo]","meaning":"柔道","definition":"a Japanese sport in which two people fight using specific holds and throws","collocations":["practice judo","judo lesson","judo champion"],"example":"He has practiced judo since he was ten years old.","exampleZh":"他從十歲起就開始練習柔道。","synonyms":[],"level":3,"theme":"運動與休閒","examples":[{"en":"He has practiced judo since he was ten years old.","zh":"他從十歲起就開始練習柔道。"},{"en":"She takes a judo lesson at the gym every Tuesday evening.","zh":"她每週二晚上在健身房上柔道課。"},{"en":"The judo champion bowed politely to her opponent before the match.","zh":"這位柔道冠軍在比賽前禮貌地向對手鞠躬。"}]},{"word":"juice","pos":"n.","phonetic":"[dʒus]","meaning":"果汁","definition":"the liquid contained in fruit or vegetables","collocations":["orange juice","fresh juice","a glass of juice"],"example":"She drank a glass of orange juice for breakfast.","exampleZh":"她早餐喝了一杯柳橙汁。","synonyms":[],"level":1,"theme":"食物與烹飪","examples":[{"en":"She drank a glass of orange juice for breakfast.","zh":"她早餐喝了一杯柳橙汁。"},{"en":"Nothing tastes better than a glass of fresh juice on a hot day.","zh":"在炎熱的日子裡，沒有什麼比一杯新鮮果汁更美味了。"},{"en":"The cafe serves apple juice made from local fruit.","zh":"這家咖啡館供應用當地水果製成的蘋果汁。"}]},{"word":"juicy","pos":"adj.","phonetic":"[ˈdʒusɪ]","meaning":"多汁的","definition":"containing a lot of juice","collocations":["juicy fruit","juicy steak","sweet and juicy"],"example":"The watermelon was sweet and juicy.","exampleZh":"這顆西瓜又甜又多汁。","synonyms":[],"level":2,"theme":"食物與烹飪","examples":[{"en":"The watermelon was sweet and juicy.","zh":"這顆西瓜又甜又多汁。"},{"en":"These oranges are so juicy that the juice ran down my hand.","zh":"這些柳橙多汁到果汁順著我的手流下來。"},{"en":"The chef served a thick, juicy steak with fresh vegetables.","zh":"主廚端出一塊厚實多汁的牛排，搭配新鮮蔬菜。"}]},{"word":"July","pos":"n.","phonetic":"[dʒʊˈlaɪ]","meaning":"七月","definition":"the seventh month of the year","collocations":["in July","hot July","early July"],"example":"We usually go to the beach in July.","exampleZh":"我們通常在七月去海邊。","synonyms":[],"level":1,"theme":"天氣與季節","examples":[{"en":"We usually go to the beach in July.","zh":"我們通常在七月去海邊。"},{"en":"The summer camp begins in early July every single year.","zh":"夏令營每年都在七月初開始。"},{"en":"July is often the hottest month of the year in Taiwan.","zh":"七月常常是台灣一年中最熱的月份。"}]},{"word":"jump","pos":"v. / n.","phonetic":"[dʒʌmp]","meaning":"跳；跳躍","definition":"to push oneself off the ground using the legs","collocations":["jump up","jump rope","jump for joy"],"example":"The dog jumped over the fence.","exampleZh":"那隻狗跳過了圍籬。","synonyms":["leap","hop"],"level":1,"theme":"動作與行為","examples":[{"en":"The dog jumped over the fence.","zh":"那隻狗跳過了圍籬。"},{"en":"The students like to jump rope during their lunch break.","zh":"學生們喜歡在午休時間跳繩。"},{"en":"He jumped up quickly when he heard the doorbell ring.","zh":"他一聽到門鈴響就迅速跳了起來。"}]},{"word":"junction","pos":"n.","phonetic":"[ˈdʒʌŋkʃən]","meaning":"交叉路口；接合點","definition":"a place where roads, railway lines, or rivers meet","collocations":["road junction","railway junction","at the junction"],"example":"Turn left at the next junction.","exampleZh":"在下一個路口左轉。","synonyms":["intersection"],"level":5,"theme":"交通與旅行","examples":[{"en":"Turn left at the next junction.","zh":"在下一個路口左轉。"},{"en":"Please slow down as you approach the busy road junction.","zh":"當你接近繁忙的交叉路口時請減速。"},{"en":"The old town grew up around an important railway junction.","zh":"這座老城鎮圍繞著一個重要的鐵路交會點發展起來。"}]},{"word":"June","pos":"n.","phonetic":"[dʒun]","meaning":"六月","definition":"the sixth month of the year","collocations":["in June","graduate in June","early June"],"example":"Graduation ceremonies are usually held in June.","exampleZh":"畢業典禮通常在六月舉行。","synonyms":[],"level":1,"theme":"天氣與季節","examples":[{"en":"Graduation ceremonies are usually held in June.","zh":"畢業典禮通常在六月舉行。"},{"en":"The rainy season usually begins in June in this region.","zh":"這個地區的雨季通常在六月開始。"},{"en":"My cousin will graduate from high school this June.","zh":"我的表哥將在今年六月從高中畢業。"}]},{"word":"jungle","pos":"n.","phonetic":"[ˈdʒʌŋgl]","meaning":"叢林；密林","definition":"a dense forest found in tropical areas","collocations":["tropical jungle","explore the jungle","jungle animals"],"example":"Many wild animals live deep in the jungle.","exampleZh":"許多野生動物棲息在叢林深處。","synonyms":["rainforest"],"level":3,"theme":"自然與環境","examples":[{"en":"Many wild animals live deep in the jungle.","zh":"許多野生動物棲息在叢林深處。"},{"en":"The explorers spent two weeks crossing the thick tropical jungle.","zh":"探險家花了兩週橫越茂密的熱帶叢林。"},{"en":"Many colorful birds and jungle animals live in the rainforest.","zh":"許多色彩繽紛的鳥類和叢林動物住在雨林裡。"}]},{"word":"junior","pos":"adj. / n.","phonetic":"[ˈdʒunjɚ]","meaning":"資淺的；年少的；晚輩","definition":"younger in age or lower in rank","collocations":["junior high school","junior staff","junior partner"],"example":"My sister is a junior high school student.","exampleZh":"我妹妹是國中生。","synonyms":[],"level":3,"theme":"教育與學習","examples":[{"en":"My sister is a junior high school student.","zh":"我妹妹是國中生。"},{"en":"The junior staff received training from their experienced colleagues.","zh":"資淺的員工接受了經驗豐富的同事的訓練。"},{"en":"My brother just started his first year of junior high school.","zh":"我的弟弟剛開始他國中的第一年。"}]},{"word":"junk","pos":"n.","phonetic":"[dʒʌŋk]","meaning":"垃圾；廢棄物","definition":"unwanted or useless items","collocations":["junk food","junk mail","a pile of junk"],"example":"He sold his old junk at the flea market.","exampleZh":"他把舊雜物拿到跳蚤市場賣掉。","synonyms":["trash","garbage"],"level":3,"theme":"居家與生活","examples":[{"en":"He sold his old junk at the flea market.","zh":"他把舊雜物拿到跳蚤市場賣掉。"},{"en":"Eating too much junk food is bad for your health.","zh":"吃太多垃圾食物對你的健康有害。"},{"en":"My email inbox was full of junk mail this morning.","zh":"今天早上我的電子郵件信箱裡塞滿了垃圾郵件。"}]},{"word":"just","pos":"adv. / adj.","phonetic":"[dʒʌst]","meaning":"剛剛；只是；公正的","definition":"exactly, or fair and reasonable","collocations":["just now","just in time","a just decision"],"example":"The judge made a just decision for both sides.","exampleZh":"法官為雙方做出了公正的裁決。","synonyms":["fair"],"level":1,"theme":"性質與描述","examples":[{"en":"The judge made a just decision for both sides.","zh":"法官為雙方做出了公正的裁決。"},{"en":"We arrived at the station just in time to catch the train.","zh":"我們剛好及時抵達車站趕上火車。"},{"en":"I just finished my homework, so now I can relax.","zh":"我剛剛做完功課，所以現在可以放鬆了。"}]},{"word":"justice","pos":"n.","phonetic":"[ˈdʒʌstɪs]","meaning":"正義；司法；公正","definition":"fair treatment or behavior according to the law","collocations":["social justice","bring to justice","fight for justice"],"example":"The victims finally received justice after years of waiting.","exampleZh":"經過多年等待，受害者終於得到了正義。","synonyms":["fairness"],"level":4,"theme":"政治與法律","examples":[{"en":"The victims finally received justice after years of waiting.","zh":"經過多年等待，受害者終於得到了正義。"},{"en":"Many young people marched to fight for social justice.","zh":"許多年輕人遊行為社會正義而奮鬥。"},{"en":"The police worked hard to bring the criminal to justice.","zh":"警方努力將罪犯繩之以法。"}]},{"word":"justify","pos":"v.","phonetic":"[ˈdʒʌstəˌfaɪ]","meaning":"證明…是正當的；為…辯護","definition":"to show or prove that something is right or reasonable","collocations":["justify a decision","justify one's actions","hard to justify"],"example":"He couldn't justify spending so much money on a watch.","exampleZh":"他無法證明花這麼多錢買手錶是合理的。","synonyms":["defend","explain"],"level":5,"theme":"抽象概念","examples":[{"en":"He couldn't justify spending so much money on a watch.","zh":"他無法證明花這麼多錢買手錶是合理的。"},{"en":"Nothing can justify treating other people so unfairly.","zh":"沒有什麼能為如此不公平地對待他人的行為辯護。"},{"en":"The manager had to justify her decision to the whole team.","zh":"經理必須向整個團隊證明她的決定是正當的。"}]},{"word":"juvenile","pos":"adj. / n.","phonetic":"[ˈdʒuvənl]","meaning":"青少年的；未成年人","definition":"relating to young people, or a young person","collocations":["juvenile crime","juvenile delinquent","juvenile court"],"example":"The city built a new center for juvenile offenders.","exampleZh":"這座城市為青少年犯建立了一個新的中心。","synonyms":["youthful"],"level":6,"theme":"社會與文化","examples":[{"en":"The city built a new center for juvenile offenders.","zh":"這座城市為青少年犯建立了一個新的中心。"},{"en":"The city started a new program to reduce juvenile crime.","zh":"這座城市啟動了一項減少青少年犯罪的新計畫。"},{"en":"Sports and clubs can keep juveniles away from trouble.","zh":"運動和社團可以讓青少年遠離麻煩。"}]},{"word":"keen","pos":"adj.","phonetic":"[kin]","meaning":"熱衷的；敏銳的；渴望的","definition":"having a strong interest or enthusiasm for something","collocations":["keen interest","keen sense of smell","be keen on something"],"example":"She is keen on learning new languages.","exampleZh":"她熱衷於學習新語言。","synonyms":["eager","sharp"],"level":4,"theme":"情緒與感受","examples":[{"en":"She is keen on learning new languages.","zh":"她熱衷於學習新語言。"},{"en":"The boy has a keen interest in astronomy and space travel.","zh":"這個男孩對天文學和太空旅行有濃厚的興趣。"},{"en":"Dogs have a keen sense of smell that helps them find things.","zh":"狗有敏銳的嗅覺，幫助牠們找到東西。"}]},{"word":"keep","pos":"v.","phonetic":"[kip]","meaning":"保持；保留；飼養","definition":"to have or retain possession of something, or to continue in a specified condition","collocations":["keep a promise","keep in touch","keep a diary"],"example":"Please keep in touch after you move abroad.","exampleZh":"你搬到國外後請保持聯絡。","synonyms":["retain","maintain"],"level":1,"theme":"動作與行為","examples":[{"en":"Please keep in touch after you move abroad.","zh":"你搬到國外後請保持聯絡。"},{"en":"A trustworthy person always keeps his promise to others.","zh":"一個值得信賴的人總是對別人信守承諾。"},{"en":"She keeps a diary to record her thoughts and feelings.","zh":"她寫日記來記錄她的想法和感受。"}]},{"word":"keeper","pos":"n.","phonetic":"[ˈkipɚ]","meaning":"看守人；管理員","definition":"a person who guards, looks after, or is in charge of something","collocations":["zoo keeper","goalkeeper","keeper of records"],"example":"The zoo keeper feeds the animals every morning.","exampleZh":"動物園管理員每天早上餵動物。","synonyms":["guardian","custodian"],"level":3,"theme":"工作與職業","examples":[{"en":"The zoo keeper feeds the animals every morning.","zh":"動物園管理員每天早上餵動物。"},{"en":"The goalkeeper made an amazing save in the final minute.","zh":"守門員在最後一分鐘做出了精彩的撲救。"},{"en":"The lighthouse keeper lived alone on the rocky island.","zh":"燈塔看守人獨自住在那座多岩石的島嶼上。"}]},{"word":"kettle","pos":"n.","phonetic":"[ˈkɛtl̩]","meaning":"水壺；茶壺","definition":"a container used for boiling water","collocations":["boil a kettle","electric kettle","put the kettle on"],"example":"He put the kettle on to make some tea.","exampleZh":"他把水壺放上爐子燒水泡茶。","synonyms":[],"level":2,"theme":"居家與生活","examples":[{"en":"He put the kettle on to make some tea.","zh":"他把水壺放上爐子燒水泡茶。"},{"en":"She filled the electric kettle and switched it on for tea.","zh":"她把電熱水壺裝滿水，然後開機準備泡茶。"},{"en":"The kettle whistled loudly once the water started to boil.","zh":"水一開始沸騰，水壺就大聲地鳴叫起來。"}]},{"word":"key","pos":"n. / adj.","phonetic":"[ki]","meaning":"鑰匙；關鍵的","definition":"a small metal device for locking, or something essential and crucial","collocations":["a key issue","the key to success","spare key"],"example":"Hard work is the key to success.","exampleZh":"努力是成功的關鍵。","synonyms":["crucial","essential"],"level":1,"theme":"抽象概念","examples":[{"en":"Hard work is the key to success.","zh":"努力是成功的關鍵。"},{"en":"We keep a spare key hidden under the flowerpot.","zh":"我們把一把備用鑰匙藏在花盆下面。"},{"en":"Communication is a key issue in any successful relationship.","zh":"溝通是任何成功關係中的關鍵問題。"}]},{"word":"keyboard","pos":"n.","phonetic":"[ˈkiˌbord]","meaning":"鍵盤","definition":"a set of keys on a computer or musical instrument","collocations":["computer keyboard","type on a keyboard","piano keyboard"],"example":"She types very fast on the keyboard.","exampleZh":"她在鍵盤上打字打得很快。","synonyms":[],"level":2,"theme":"科技與媒體","examples":[{"en":"She types very fast on the keyboard.","zh":"她在鍵盤上打字打得很快。"},{"en":"He spilled coffee on his computer keyboard by accident.","zh":"他不小心把咖啡灑在電腦鍵盤上。"},{"en":"She practices scales on the piano keyboard every afternoon.","zh":"她每天下午在鋼琴鍵盤上練習音階。"}]},{"word":"kick","pos":"v. / n.","phonetic":"[kɪk]","meaning":"踢；踢腿","definition":"to hit something with the foot","collocations":["kick a ball","kick off","give someone a kick"],"example":"The player kicked the ball into the goal.","exampleZh":"那名球員把球踢進了球門。","synonyms":["boot","strike"],"level":1,"theme":"運動與休閒","examples":[{"en":"The player kicked the ball into the goal.","zh":"那名球員把球踢進了球門。"},{"en":"The soccer match will kick off at three o'clock this afternoon.","zh":"這場足球賽將在今天下午三點開始。"},{"en":"The little boy learned to kick a ball at the park.","zh":"這個小男孩在公園裡學會了踢球。"}]},{"word":"kid","pos":"n. / v.","phonetic":"[kɪd]","meaning":"小孩；開玩笑","definition":"a young child, or to joke with someone","collocations":["little kid","kid around","just kidding"],"example":"The kids played happily in the park.","exampleZh":"孩子們在公園裡玩得很開心。","synonyms":["child","joke"],"level":1,"theme":"人物與家庭","examples":[{"en":"The kids played happily in the park.","zh":"孩子們在公園裡玩得很開心。"},{"en":"The little kid held tightly onto his mother's hand.","zh":"這個小孩緊緊抓著他媽媽的手。"},{"en":"Stop kidding around and finish your homework right now.","zh":"別再鬧了，現在就把功課做完。"}]},{"word":"kidnap","pos":"v.","phonetic":"[ˈkɪdˌnæp]","meaning":"綁架","definition":"to take someone away illegally by force, usually to demand money","collocations":["kidnap a child","kidnap for ransom","kidnap victim"],"example":"The criminals were arrested for trying to kidnap the businessman.","exampleZh":"那些罪犯因企圖綁架那位商人而被逮捕。","synonyms":["abduct"],"level":5,"theme":"政治與法律","examples":[{"en":"The criminals were arrested for trying to kidnap the businessman.","zh":"那些罪犯因企圖綁架那位商人而被逮捕。"},{"en":"The police rescued the kidnap victim before any harm was done.","zh":"警方在任何傷害發生前就救出了綁架案的受害者。"},{"en":"In the movie, robbers tried to kidnap a rich man's son for ransom.","zh":"在電影中，強盜試圖綁架一個有錢人的兒子來勒索贖金。"}]},{"word":"kidney","pos":"n.","phonetic":"[ˈkɪdnɪ]","meaning":"腎臟","definition":"one of the two organs that remove waste from the blood","collocations":["kidney failure","kidney stone","kidney transplant"],"example":"He needed a kidney transplant after his illness.","exampleZh":"他生病後需要進行腎臟移植。","synonyms":[],"level":4,"theme":"身體與健康","examples":[{"en":"He needed a kidney transplant after his illness.","zh":"他生病後需要進行腎臟移植。"},{"en":"Drinking enough water helps prevent painful kidney stones.","zh":"喝足夠的水有助於預防疼痛的腎結石。"},{"en":"The kidneys clean waste from the blood inside our bodies.","zh":"腎臟清除我們體內血液中的廢物。"}]},{"word":"kill","pos":"v.","phonetic":"[kɪl]","meaning":"殺死；扼殺","definition":"to cause the death of a person, animal, or plant","collocations":["kill time","kill two birds with one stone","kill a plant"],"example":"Reading books is a great way to kill time on a long flight.","exampleZh":"看書是在長途飛行中打發時間的好方法。","synonyms":["slay","destroy"],"level":2,"theme":"動作與行為","examples":[{"en":"Reading books is a great way to kill time on a long flight.","zh":"看書是在長途飛行中打發時間的好方法。"},{"en":"Too much water can actually kill a small houseplant.","zh":"過多的水實際上會害死一棵小的室內植物。"},{"en":"By walking to work, she kills two birds with one stone.","zh":"藉由走路上班，她一舉兩得。"}]},{"word":"kilogram","pos":"n.","phonetic":"[ˈkɪləˌgræm]","meaning":"公斤","definition":"a unit of mass equal to 1,000 grams","collocations":["one kilogram","kilogram of rice","weigh in kilograms"],"example":"The bag of rice weighs five kilograms.","exampleZh":"這袋米重五公斤。","synonyms":["kilo"],"level":2,"theme":"科學與數學","examples":[{"en":"The bag of rice weighs five kilograms.","zh":"這袋米重五公斤。"},{"en":"The newborn baby weighed just over three kilograms.","zh":"這個新生兒的體重剛好超過三公斤。"},{"en":"Please buy two kilograms of apples from the market.","zh":"請從市場買兩公斤蘋果。"}]},{"word":"kilometer","pos":"n.","phonetic":"[ˈkɪləˌmitɚ]","meaning":"公里","definition":"a unit of length equal to 1,000 meters","collocations":["ten kilometers away","kilometers per hour","run a kilometer"],"example":"The school is two kilometers from my house.","exampleZh":"學校離我家兩公里遠。","synonyms":[],"level":2,"theme":"科學與數學","examples":[{"en":"The school is two kilometers from my house.","zh":"學校離我家兩公里遠。"},{"en":"The nearest hospital is about five kilometers away from here.","zh":"最近的醫院離這裡大約五公里遠。"},{"en":"He can run a kilometer in under four minutes.","zh":"他能在四分鐘內跑完一公里。"}]},{"word":"kind","pos":"adj. / n.","phonetic":"[kaɪnd]","meaning":"親切的；種類","definition":"friendly and considerate, or a category of things","collocations":["be kind to someone","kind of person","different kinds"],"example":"It was very kind of you to help me.","exampleZh":"你能幫我真是太好心了。","synonyms":["gentle","type"],"level":1,"theme":"性質與描述","examples":[{"en":"It was very kind of you to help me.","zh":"你能幫我真是太好心了。"},{"en":"The store sells many different kinds of fresh bread.","zh":"這家商店販售許多不同種類的新鮮麵包。"},{"en":"She is the kind of person who always helps strangers.","zh":"她是那種總是幫助陌生人的人。"}]},{"word":"kindergarten","pos":"n.","phonetic":"[ˈkɪndɚˌgɑrtn̩]","meaning":"幼稚園","definition":"a school or class for young children before elementary school","collocations":["attend kindergarten","kindergarten teacher","start kindergarten"],"example":"My little sister just started kindergarten this year.","exampleZh":"我妹妹今年剛開始上幼稚園。","synonyms":[],"level":2,"theme":"教育與學習","examples":[{"en":"My little sister just started kindergarten this year.","zh":"我妹妹今年剛開始上幼稚園。"},{"en":"The kindergarten teacher sang songs to calm the crying children.","zh":"幼稚園老師唱歌來安撫哭泣的孩子們。"},{"en":"Children usually attend kindergarten before entering elementary school.","zh":"孩子們通常在進入小學之前上幼稚園。"}]},{"word":"kindness","pos":"n.","phonetic":"[ˈkaɪndnɪs]","meaning":"仁慈；善意","definition":"the quality of being friendly, generous, and considerate","collocations":["show kindness","act of kindness","out of kindness"],"example":"She thanked him for his kindness and generosity.","exampleZh":"她感謝他的仁慈與慷慨。","synonyms":["compassion","generosity"],"level":3,"theme":"抽象概念","examples":[{"en":"She thanked him for his kindness and generosity.","zh":"她感謝他的仁慈與慷慨。"},{"en":"A small act of kindness can brighten someone's whole day.","zh":"一個小小的善舉可以照亮某人的一整天。"},{"en":"She showed great kindness by helping the lost tourist.","zh":"她幫助迷路的觀光客，展現了極大的善意。"}]},{"word":"king","pos":"n.","phonetic":"[kɪŋ]","meaning":"國王","definition":"a male ruler of a country, usually by inheritance","collocations":["king and queen","crown a king","royal king"],"example":"The king ruled the country for forty years.","exampleZh":"這位國王統治這個國家四十年。","synonyms":["monarch","ruler"],"level":1,"theme":"政治與法律","examples":[{"en":"The king ruled the country for forty years.","zh":"這位國王統治這個國家四十年。"},{"en":"The young prince will one day be crowned king.","zh":"這位年輕的王子有一天將被加冕為國王。"},{"en":"The king and queen greeted the crowd from the balcony.","zh":"國王和王后從陽台上向群眾致意。"}]},{"word":"kingdom","pos":"n.","phonetic":"[ˈkɪŋdəm]","meaning":"王國","definition":"a country ruled by a king or queen","collocations":["united kingdom","animal kingdom","ancient kingdom"],"example":"The animal kingdom is full of amazing creatures.","exampleZh":"動物王國充滿了令人驚奇的生物。","synonyms":["realm"],"level":3,"theme":"政治與法律","examples":[{"en":"The animal kingdom is full of amazing creatures.","zh":"動物王國充滿了令人驚奇的生物。"},{"en":"The lion is often called the king of the animal kingdom.","zh":"獅子常被稱為動物王國之王。"},{"en":"Archaeologists discovered the ruins of an ancient kingdom.","zh":"考古學家發現了一個古代王國的遺跡。"}]},{"word":"kiss","pos":"v. / n.","phonetic":"[kɪs]","meaning":"親吻","definition":"to touch someone with the lips as a sign of affection","collocations":["kiss goodbye","blow a kiss","give a kiss"],"example":"She gave her mother a kiss before leaving for school.","exampleZh":"她出門上學前親了媽媽一下。","synonyms":["peck"],"level":2,"theme":"情緒與感受","examples":[{"en":"She gave her mother a kiss before leaving for school.","zh":"她出門上學前親了媽媽一下。"},{"en":"She blew a kiss to her family as the train left the station.","zh":"火車離開車站時，她向她的家人飛吻。"},{"en":"He kissed his daughter goodbye before heading to work.","zh":"他在去上班前親吻女兒道別。"}]},{"word":"kit","pos":"n.","phonetic":"[kɪt]","meaning":"工具組；用具箱","definition":"a set of tools or equipment for a particular purpose","collocations":["first-aid kit","tool kit","repair kit"],"example":"Every car should carry a first-aid kit.","exampleZh":"每輛車都應該備有急救箱。","synonyms":["set","equipment"],"level":3,"theme":"居家與生活","examples":[{"en":"Every car should carry a first-aid kit.","zh":"每輛車都應該備有急救箱。"},{"en":"Keep a first-aid kit in your car for emergencies.","zh":"在你的車裡放一個急救箱以備緊急之需。"},{"en":"He opened his tool kit to fix the broken wooden chair.","zh":"他打開工具箱來修理那把壞掉的木椅。"}]},{"word":"kitchen","pos":"n.","phonetic":"[ˈkɪtʃɪn]","meaning":"廚房","definition":"a room where food is prepared and cooked","collocations":["kitchen table","clean the kitchen","kitchen sink"],"example":"My mom is cooking dinner in the kitchen.","exampleZh":"我媽媽正在廚房裡煮晚餐。","synonyms":[],"level":1,"theme":"居家與生活","examples":[{"en":"My mom is cooking dinner in the kitchen.","zh":"我媽媽正在廚房裡煮晚餐。"},{"en":"The whole family gathered around the kitchen table for breakfast.","zh":"全家人圍著廚房的餐桌吃早餐。"},{"en":"After cooking, they spent an hour cleaning the kitchen.","zh":"煮完飯後，他們花了一個小時清理廚房。"}]},{"word":"kite","pos":"n.","phonetic":"[kaɪt]","meaning":"風箏","definition":"a light frame covered with paper or cloth flown in the wind on a string","collocations":["fly a kite","kite flying","colorful kite"],"example":"The children flew a kite on the windy beach.","exampleZh":"孩子們在多風的海灘上放風箏。","synonyms":[],"level":1,"theme":"運動與休閒","examples":[{"en":"The children flew a kite on the windy beach.","zh":"孩子們在多風的海灘上放風箏。"},{"en":"On a windy day, the park is full of colorful kites.","zh":"在有風的日子，公園裡滿是五顏六色的風箏。"},{"en":"The boy ran across the field to get his kite flying.","zh":"那個男孩跑過田野讓他的風箏飛起來。"}]},{"word":"kitten","pos":"n.","phonetic":"[ˈkɪtn̩]","meaning":"小貓","definition":"a young cat","collocations":["cute kitten","adopt a kitten","playful kitten"],"example":"We adopted a kitten from the animal shelter.","exampleZh":"我們從動物收容所領養了一隻小貓。","synonyms":[],"level":1,"theme":"動物與植物","examples":[{"en":"We adopted a kitten from the animal shelter.","zh":"我們從動物收容所領養了一隻小貓。"},{"en":"The playful kitten chased the ball of yarn across the floor.","zh":"這隻頑皮的小貓追著毛線球在地板上跑。"},{"en":"They decided to adopt a cute kitten from a neighbor.","zh":"他們決定從鄰居那裡領養一隻可愛的小貓。"}]},{"word":"knee","pos":"n.","phonetic":"[ni]","meaning":"膝蓋","definition":"the joint between the thigh and the lower leg","collocations":["hurt your knee","on bended knee","knee injury"],"example":"He injured his knee while playing basketball.","exampleZh":"他打籃球時傷了膝蓋。","synonyms":[],"level":2,"theme":"身體與健康","examples":[{"en":"He injured his knee while playing basketball.","zh":"他打籃球時傷了膝蓋。"},{"en":"A serious knee injury kept the athlete out of the game.","zh":"嚴重的膝蓋傷勢使這名運動員無法上場比賽。"},{"en":"She fell off her bike and hurt her knee badly.","zh":"她從腳踏車上摔下來，膝蓋受了重傷。"}]},{"word":"kneel","pos":"v.","phonetic":"[nil]","meaning":"跪下","definition":"to go down on one or both knees","collocations":["kneel down","kneel before someone","kneel in prayer"],"example":"She knelt down to pray at the temple.","exampleZh":"她在寺廟裡跪下祈禱。","synonyms":[],"level":4,"theme":"動作與行為","examples":[{"en":"She knelt down to pray at the temple.","zh":"她在寺廟裡跪下祈禱。"},{"en":"He knelt down to tie his little sister's shoelaces.","zh":"他跪下來幫他的小妹妹綁鞋帶。"},{"en":"The gardener knelt in the soil to plant the flowers.","zh":"園丁跪在泥土中種植花朵。"}]},{"word":"knife","pos":"n.","phonetic":"[naɪf]","meaning":"刀子","definition":"a tool with a sharp blade used for cutting","collocations":["sharp knife","kitchen knife","knife and fork"],"example":"Be careful with that sharp knife.","exampleZh":"小心那把鋒利的刀子。","synonyms":["blade"],"level":1,"theme":"居家與生活","examples":[{"en":"Be careful with that sharp knife.","zh":"小心那把鋒利的刀子。"},{"en":"He used a sharp kitchen knife to slice the vegetables.","zh":"他用一把鋒利的廚房刀切蔬菜。"},{"en":"In many countries, people eat steak with a knife and fork.","zh":"在許多國家，人們用刀叉吃牛排。"}]},{"word":"knight","pos":"n.","phonetic":"[naɪt]","meaning":"騎士；爵士","definition":"a man honored for military bravery, or given the title Sir","collocations":["brave knight","knight in shining armor","medieval knight"],"example":"The brave knight rescued the princess from the tower.","exampleZh":"那位勇敢的騎士把公主從塔裡救了出來。","synonyms":[],"level":4,"theme":"社會與文化","examples":[{"en":"The brave knight rescued the princess from the tower.","zh":"那位勇敢的騎士把公主從塔裡救了出來。"},{"en":"The story tells of a medieval knight who fought a dragon.","zh":"這個故事講述一位與龍搏鬥的中世紀騎士。"},{"en":"Every knight promised to protect the kingdom and its people.","zh":"每位騎士都承諾保護這個王國及其人民。"}]},{"word":"knit","pos":"v.","phonetic":"[nɪt]","meaning":"編織","definition":"to make clothing by looping wool or thread together with needles","collocations":["knit a sweater","knit together","learn to knit"],"example":"My grandmother taught me how to knit a scarf.","exampleZh":"我奶奶教我如何織圍巾。","synonyms":["weave"],"level":4,"theme":"服裝與外表","examples":[{"en":"My grandmother taught me how to knit a scarf.","zh":"我奶奶教我如何織圍巾。"},{"en":"My mother knit a warm sweater for me last winter.","zh":"我媽媽去年冬天為我織了一件溫暖的毛衣。"},{"en":"She is learning to knit a pair of gloves for her friend.","zh":"她正在學習為她的朋友織一雙手套。"}]},{"word":"knob","pos":"n.","phonetic":"[nɑb]","meaning":"把手；旋鈕","definition":"a round handle or control switch on a door or device","collocations":["door knob","turn the knob","volume knob"],"example":"Turn the knob to open the door.","exampleZh":"轉動門把來開門。","synonyms":["handle"],"level":4,"theme":"居家與生活","examples":[{"en":"Turn the knob to open the door.","zh":"轉動門把來開門。"},{"en":"He turned the volume knob down so the baby could sleep.","zh":"他把音量旋鈕轉小，好讓寶寶能夠睡覺。"},{"en":"The door knob was so old that it finally fell off.","zh":"這個門把太舊了，最後掉了下來。"}]},{"word":"knock","pos":"v. / n.","phonetic":"[nɑk]","meaning":"敲；敲擊","definition":"to hit a surface, especially a door, to attract attention","collocations":["knock on the door","knock over","knock someone out"],"example":"Someone knocked on the door late at night.","exampleZh":"深夜有人敲門。","synonyms":["rap","tap"],"level":2,"theme":"動作與行為","examples":[{"en":"Someone knocked on the door late at night.","zh":"深夜有人敲門。"},{"en":"Please knock on the door before you enter the room.","zh":"進房間前請先敲門。"},{"en":"The naughty cat accidentally knocked over the glass of water.","zh":"那隻頑皮的貓不小心打翻了那杯水。"}]},{"word":"knot","pos":"n. / v.","phonetic":"[nɑt]","meaning":"結；打結","definition":"a fastening made by tying rope or string, or to tie such a fastening","collocations":["tie a knot","untie a knot","knot in a rope"],"example":"He tied a knot to secure the boat to the dock.","exampleZh":"他打了個結把船繫在碼頭上。","synonyms":[],"level":4,"theme":"居家與生活","examples":[{"en":"He tied a knot to secure the boat to the dock.","zh":"他打了個結把船繫在碼頭上。"},{"en":"The sailor quickly tied a knot to secure the sail.","zh":"水手迅速打了一個結來固定船帆。"},{"en":"It took me several minutes to untie the tight knot.","zh":"我花了好幾分鐘才解開那個緊緊的結。"}]},{"word":"know","pos":"v.","phonetic":"[no]","meaning":"知道；認識","definition":"to be aware of or familiar with information or a person","collocations":["know for sure","get to know","know how to"],"example":"I don't know the answer to this question.","exampleZh":"我不知道這個問題的答案。","synonyms":["understand","recognize"],"level":1,"theme":"教育與學習","examples":[{"en":"I don't know the answer to this question.","zh":"我不知道這個問題的答案。"},{"en":"I would like to get to know my new classmates better.","zh":"我想更了解我的新同學。"},{"en":"She knows how to solve the problem quickly and correctly.","zh":"她知道如何快速且正確地解決這個問題。"}]},{"word":"knowledge","pos":"n.","phonetic":"[ˈnɑlɪdʒ]","meaning":"知識","definition":"facts, information, and skills acquired through experience or education","collocations":["general knowledge","gain knowledge","knowledge of"],"example":"Reading widely can broaden your knowledge of the world.","exampleZh":"廣泛閱讀能增廣你對世界的知識。","synonyms":["understanding","learning"],"level":2,"theme":"教育與學習","examples":[{"en":"Reading widely can broaden your knowledge of the world.","zh":"廣泛閱讀能增廣你對世界的知識。"},{"en":"Travelling abroad gave her a deeper knowledge of other cultures.","zh":"出國旅行讓她對其他文化有了更深的認識。"},{"en":"Students gain knowledge not only from books but also from experience.","zh":"學生不僅從書本中獲得知識，也從經驗中學習。"}]},{"word":"knowledgeable","pos":"adj.","phonetic":"[ˈnɑlɪdʒəbl̩]","meaning":"博學的；有見識的","definition":"having or showing knowledge or intelligence about a subject","collocations":["knowledgeable about","highly knowledgeable","knowledgeable staff"],"example":"The tour guide was very knowledgeable about local history.","exampleZh":"這位導遊對當地歷史非常了解。","synonyms":["informed","learned"],"level":5,"theme":"教育與學習","examples":[{"en":"The tour guide was very knowledgeable about local history.","zh":"這位導遊對當地歷史非常了解。"},{"en":"The staff at the bookstore are very knowledgeable about history.","zh":"這家書店的員工對歷史非常博學。"},{"en":"She is knowledgeable about plants and grows many at home.","zh":"她對植物很有見識，在家裡種了很多。"}]},{"word":"known","pos":"adj.","phonetic":"[non]","meaning":"已知的；著名的","definition":"recognized, familiar, or identified","collocations":["well-known","known for","known fact"],"example":"The city is well-known for its delicious street food.","exampleZh":"這座城市以美味的街頭小吃聞名。","synonyms":["recognized","famous"],"level":3,"theme":"性質與描述","examples":[{"en":"The city is well-known for its delicious street food.","zh":"這座城市以美味的街頭小吃聞名。"},{"en":"The small town is known for its beautiful cherry blossoms.","zh":"這個小鎮以美麗的櫻花而聞名。"},{"en":"It is a known fact that regular exercise improves your mood.","zh":"規律運動能改善心情是一個眾所周知的事實。"}]},{"word":"knuckle","pos":"n.","phonetic":"[ˈnʌkl̩]","meaning":"指關節","definition":"a joint of the finger","collocations":["crack your knuckles","rap on the knuckles","bruised knuckle"],"example":"He cracked his knuckles before starting to type.","exampleZh":"他開始打字前先扳了扳手指關節。","synonyms":[],"level":5,"theme":"身體與健康","examples":[{"en":"He cracked his knuckles before starting to type.","zh":"他開始打字前先扳了扳手指關節。"},{"en":"Please stop cracking your knuckles; the sound really bothers me.","zh":"請別再折你的指關節了，那聲音真的讓我很困擾。"},{"en":"He gently rapped his knuckles on the wooden table.","zh":"他用指關節輕輕地敲了敲木桌。"}]},{"word":"koala","pos":"n.","phonetic":"[koˈɑlə]","meaning":"無尾熊","definition":"a small tree-dwelling Australian marsupial","collocations":["koala bear","cuddly koala","koala habitat"],"example":"Koalas spend most of their day sleeping in trees.","exampleZh":"無尾熊大部分時間都在樹上睡覺。","synonyms":[],"level":2,"theme":"動物與植物","examples":[{"en":"Koalas spend most of their day sleeping in trees.","zh":"無尾熊大部分時間都在樹上睡覺。"},{"en":"The cuddly koala clung tightly to the tall eucalyptus tree.","zh":"那隻可愛的無尾熊緊緊地抱著高大的尤加利樹。"},{"en":"Forest fires have destroyed much of the koala's natural habitat.","zh":"森林大火摧毀了無尾熊大部分的自然棲息地。"}]},{"word":"kung fu","pos":"n.","phonetic":"[ˈkʌŋ ˈfu]","meaning":"功夫；中國武術","definition":"a Chinese martial art","collocations":["practice kung fu","kung fu master","learn kung fu"],"example":"He has practiced kung fu since he was five years old.","exampleZh":"他從五歲起就開始練習功夫。","synonyms":["martial arts"],"level":3,"theme":"運動與休閒","examples":[{"en":"He has practiced kung fu since he was five years old.","zh":"他從五歲起就開始練習功夫。"},{"en":"The kung fu master taught his students to stay calm and focused.","zh":"這位功夫大師教導學生保持冷靜和專注。"},{"en":"Many tourists come to the old temple to learn kung fu.","zh":"許多觀光客來到這座古老的寺廟學習功夫。"}]},{"word":"label","pos":"n. / v.","phonetic":"[ˈlebl̩]","meaning":"標籤；標示","definition":"a piece of paper or material attached to something giving information about it, or to attach such information","collocations":["label a product","warning label","price label"],"example":"The label shows all the ingredients used in the food.","exampleZh":"標籤上列出了這食品所使用的所有成分。","synonyms":["tag","mark"],"level":3,"theme":"商業與金錢","examples":[{"en":"The label shows all the ingredients used in the food.","zh":"標籤上列出了這食品所使用的所有成分。"},{"en":"Always read the warning label before taking any medicine.","zh":"服用任何藥物前一定要閱讀警告標籤。"},{"en":"The staff carefully labeled each box before shipping it out.","zh":"員工在寄出前仔細地為每個箱子貼上標籤。"}]},{"word":"labor","pos":"n. / v.","phonetic":"[ˈlebɚ]","meaning":"勞動；勞工；努力工作","definition":"hard physical or mental work, or the workers who provide it","collocations":["manual labor","labor force","labor market"],"example":"Farming requires a lot of manual labor.","exampleZh":"務農需要大量的體力勞動。","synonyms":["work","toil"],"level":4,"theme":"工作與職業","examples":[{"en":"Farming requires a lot of manual labor.","zh":"務農需要大量的體力勞動。"},{"en":"Building the stone wall required hours of hard manual labor.","zh":"建造這道石牆需要好幾個小時的辛苦體力勞動。"},{"en":"The country's labor force is growing steadily every year.","zh":"這個國家的勞動力每年都在穩定地成長。"}]},{"word":"laboratory","pos":"n.","phonetic":"[ˈlæbrəˌtɔri]","meaning":"實驗室","definition":"a room or building equipped for scientific experiments","collocations":["chemistry laboratory","laboratory test","laboratory equipment"],"example":"The scientists conducted the experiment in the laboratory.","exampleZh":"科學家們在實驗室裡進行了這項實驗。","synonyms":["lab"],"level":5,"theme":"科學與數學","examples":[{"en":"The scientists conducted the experiment in the laboratory.","zh":"科學家們在實驗室裡進行了這項實驗。"},{"en":"Students must wear safety goggles in the chemistry laboratory.","zh":"學生在化學實驗室裡必須配戴護目鏡。"},{"en":"The laboratory test confirmed that the water was safe to drink.","zh":"實驗室檢驗證實這水可以安全飲用。"}]},{"word":"lack","pos":"n. / v.","phonetic":"[læk]","meaning":"缺乏；不足","definition":"the state of not having enough of something","collocations":["lack of confidence","lack of sleep","lack money"],"example":"He failed the exam due to a lack of preparation.","exampleZh":"他因為準備不足而考試不及格。","synonyms":["shortage","absence"],"level":3,"theme":"抽象概念","examples":[{"en":"He failed the exam due to a lack of preparation.","zh":"他因為準備不足而考試不及格。"},{"en":"A lack of sleep can make it hard to concentrate in class.","zh":"睡眠不足會讓人難以在課堂上集中注意力。"},{"en":"The plan failed because the team lacked enough money.","zh":"這個計畫失敗了，因為團隊缺乏足夠的資金。"}]},{"word":"ladder","pos":"n.","phonetic":"[ˈlædɚ]","meaning":"梯子；階梯","definition":"a structure with steps used for climbing up or down","collocations":["climb a ladder","career ladder","wooden ladder"],"example":"He climbed the ladder to fix the roof.","exampleZh":"他爬上梯子去修理屋頂。","synonyms":[],"level":2,"theme":"居家與生活","examples":[{"en":"He climbed the ladder to fix the roof.","zh":"他爬上梯子去修理屋頂。"},{"en":"He carefully climbed the wooden ladder to pick the apples.","zh":"他小心地爬上木梯去摘蘋果。"},{"en":"Hard work helped her move up the career ladder quickly.","zh":"努力工作幫助她快速地在職涯階梯上晉升。"}]},{"word":"lady","pos":"n.","phonetic":"[ˈledi]","meaning":"女士；淑女","definition":"a woman, especially one who is polite and well-mannered","collocations":["young lady","first lady","ladies and gentlemen"],"example":"The old lady smiled kindly at the children.","exampleZh":"那位老太太親切地對孩子們微笑。","synonyms":["woman"],"level":1,"theme":"人物與家庭","examples":[{"en":"The old lady smiled kindly at the children.","zh":"那位老太太親切地對孩子們微笑。"},{"en":"The kind old lady offered her seat to the pregnant woman.","zh":"那位親切的老太太把座位讓給了孕婦。"},{"en":"Ladies and gentlemen, please welcome our special guest tonight.","zh":"各位女士先生，請歡迎我們今晚的特別來賓。"}]},{"word":"lake","pos":"n.","phonetic":"[lek]","meaning":"湖；湖泊","definition":"a large body of water surrounded by land","collocations":["swim in a lake","lake view","frozen lake"],"example":"We went boating on the lake last summer.","exampleZh":"去年夏天我們在湖上划船。","synonyms":[],"level":1,"theme":"自然與環境","examples":[{"en":"We went boating on the lake last summer.","zh":"去年夏天我們在湖上划船。"},{"en":"In winter, the frozen lake becomes a popular place for skating.","zh":"冬天時，結冰的湖泊成為受歡迎的溜冰場所。"},{"en":"Our hotel room had a wonderful view of the calm lake.","zh":"我們的飯店房間可以看到平靜湖泊的美麗景色。"}]},{"word":"lamb","pos":"n.","phonetic":"[læm]","meaning":"小羊；羔羊肉","definition":"a young sheep, or its meat","collocations":["roast lamb","lamb chop","baby lamb"],"example":"The farmer keeps several lambs in the field.","exampleZh":"這位農夫在田裡養了幾隻小羊。","synonyms":[],"level":2,"theme":"動物與植物","examples":[{"en":"The farmer keeps several lambs in the field.","zh":"這位農夫在田裡養了幾隻小羊。"},{"en":"A newborn lamb stayed close to its mother in the field.","zh":"一隻剛出生的小羊在田野裡緊挨著牠的母親。"},{"en":"The restaurant is famous for its tender roast lamb.","zh":"這家餐廳以其鮮嫩的烤羔羊肉聞名。"}]},{"word":"lamp","pos":"n.","phonetic":"[læmp]","meaning":"燈；檯燈","definition":"a device that produces light","collocations":["table lamp","turn on a lamp","street lamp"],"example":"She turned off the lamp before going to sleep.","exampleZh":"她睡前把檯燈關掉了。","synonyms":["light"],"level":1,"theme":"居家與生活","examples":[{"en":"She turned off the lamp before going to sleep.","zh":"她睡前把檯燈關掉了。"},{"en":"She turned on the table lamp to read her book at night.","zh":"她打開檯燈以便在晚上閱讀她的書。"},{"en":"The street lamps light up the whole road every evening.","zh":"街燈每天晚上照亮整條道路。"}]},{"word":"land","pos":"n. / v.","phonetic":"[lænd]","meaning":"陸地；土地；降落","definition":"the solid surface of the earth, or to come down onto ground after flight","collocations":["land a plane","piece of land","farm land"],"example":"The plane landed safely at the airport.","exampleZh":"飛機安全地降落在機場。","synonyms":["ground","soil"],"level":1,"theme":"交通與旅行","examples":[{"en":"The plane landed safely at the airport.","zh":"飛機安全地降落在機場。"},{"en":"The farmer bought a large piece of land near the river.","zh":"這位農夫在河邊買了一大片土地。"},{"en":"The pilot managed to land the plane safely during the storm.","zh":"飛行員在暴風雨中設法讓飛機安全降落。"}]},{"word":"landscape","pos":"n.","phonetic":"[ˈlændˌskep]","meaning":"風景；景觀","definition":"all the visible features of an area of land","collocations":["rural landscape","landscape painting","urban landscape"],"example":"The artist painted a beautiful mountain landscape.","exampleZh":"這位畫家畫了一幅美麗的山景畫。","synonyms":["scenery"],"level":4,"theme":"自然與環境","examples":[{"en":"The artist painted a beautiful mountain landscape.","zh":"這位畫家畫了一幅美麗的山景畫。"},{"en":"From the hilltop, we admired the peaceful rural landscape.","zh":"從山頂上，我們欣賞著寧靜的鄉村景色。"},{"en":"The museum displayed several beautiful landscape paintings.","zh":"博物館展出了幾幅美麗的風景畫。"}]},{"word":"lane","pos":"n.","phonetic":"[len]","meaning":"小巷；車道","definition":"a narrow road, or a strip of a wider road","collocations":["bike lane","country lane","fast lane"],"example":"Cyclists should stay in the bike lane.","exampleZh":"騎自行車的人應該待在自行車道上。","synonyms":[],"level":2,"theme":"交通與旅行","examples":[{"en":"Cyclists should stay in the bike lane.","zh":"騎自行車的人應該待在自行車道上。"},{"en":"We walked along a quiet country lane lined with tall trees.","zh":"我們沿著一條兩旁種滿高大樹木的寧靜鄉間小路散步。"},{"en":"Drivers should not change lanes without signaling first.","zh":"駕駛人不應在未先打方向燈的情況下變換車道。"}]},{"word":"language","pos":"n.","phonetic":"[ˈlæŋgwɪdʒ]","meaning":"語言","definition":"a system of communication used by people of a particular country or area","collocations":["foreign language","body language","native language"],"example":"Learning a new language takes time and practice.","exampleZh":"學習一種新語言需要時間和練習。","synonyms":["speech","tongue"],"level":2,"theme":"溝通與語言","examples":[{"en":"Learning a new language takes time and practice.","zh":"學習一種新語言需要時間和練習。"},{"en":"Her body language showed that she was feeling very nervous.","zh":"她的肢體語言顯示出她感到非常緊張。"},{"en":"Learning a foreign language opens the door to new cultures.","zh":"學習一門外語為認識新文化打開了大門。"}]},{"word":"lantern","pos":"n.","phonetic":"[ˈlæntɚn]","meaning":"燈籠；提燈","definition":"a light source enclosed in a transparent case","collocations":["paper lantern","light a lantern","lantern festival"],"example":"Children carried paper lanterns during the festival.","exampleZh":"孩子們在節慶時提著紙燈籠。","synonyms":[],"level":3,"theme":"社會與文化","examples":[{"en":"Children carried paper lanterns during the festival.","zh":"孩子們在節慶時提著紙燈籠。"},{"en":"During the Lantern Festival, the streets glow with bright lights.","zh":"在元宵節期間，街道被明亮的燈火照得閃閃發光。"},{"en":"They hung several red paper lanterns outside the front door.","zh":"他們在前門外掛上幾個紅色的紙燈籠。"}]},{"word":"laptop","pos":"n.","phonetic":"[ˈlæpˌtɑp]","meaning":"筆記型電腦","definition":"a small portable computer","collocations":["laptop computer","open a laptop","laptop screen"],"example":"She works on her laptop at the coffee shop.","exampleZh":"她在咖啡店用筆電工作。","synonyms":[],"level":2,"theme":"科技與媒體","examples":[{"en":"She works on her laptop at the coffee shop.","zh":"她在咖啡店用筆電工作。"},{"en":"He closed his laptop and packed it into his bag.","zh":"他闔上筆記型電腦，把它裝進背包裡。"},{"en":"Staring at a laptop screen for too long hurts my eyes.","zh":"盯著筆電螢幕太久會傷害我的眼睛。"}]},{"word":"large","pos":"adj.","phonetic":"[lɑrdʒ]","meaning":"大的；巨大的","definition":"big in size, amount, or extent","collocations":["large amount","large scale","extra large"],"example":"They bought a large house near the sea.","exampleZh":"他們在海邊買了一棟大房子。","synonyms":["big","huge"],"level":1,"theme":"性質與描述","examples":[{"en":"They bought a large house near the sea.","zh":"他們在海邊買了一棟大房子。"},{"en":"A large amount of rain fell during the typhoon last night.","zh":"昨晚颱風期間下了大量的雨。"},{"en":"The factory produces goods on a very large scale.","zh":"這家工廠大規模地生產商品。"}]},{"word":"last","pos":"adj. / v.","phonetic":"[læst]","meaning":"最後的；持續","definition":"coming after all others in time or order; to continue for a period","collocations":["last chance","last long","at last"],"example":"The concert lasted for three hours.","exampleZh":"這場演唱會持續了三個小時。","synonyms":["final","continue"],"level":1,"theme":"時間與空間","examples":[{"en":"The concert lasted for three hours.","zh":"這場演唱會持續了三個小時。"},{"en":"This is your very last chance to hand in the homework.","zh":"這是你交作業的最後機會了。"},{"en":"These sturdy leather boots should last for many years.","zh":"這雙堅固的皮靴應該能穿很多年。"}]},{"word":"late","pos":"adj. / adv.","phonetic":"[let]","meaning":"遲的；晚的","definition":"after the expected or usual time","collocations":["be late for","late night","arrive late"],"example":"He was late for school again this morning.","exampleZh":"他今天早上上學又遲到了。","synonyms":["overdue"],"level":1,"theme":"時間與空間","examples":[{"en":"He was late for school again this morning.","zh":"他今天早上上學又遲到了。"},{"en":"If you don't hurry, you will be late for the movie.","zh":"如果你不快點，你看電影就會遲到。"},{"en":"After a late night of studying, she woke up feeling tired.","zh":"熬夜念書之後，她起床時感到疲倦。"}]},{"word":"latter","pos":"adj. / n.","phonetic":"[ˈlætɚ]","meaning":"後者的；後面的","definition":"the second of two things or people mentioned","collocations":["the latter half","former and latter","in the latter case"],"example":"Of the two options, I prefer the latter.","exampleZh":"在這兩個選項中，我比較喜歡後者。","synonyms":[],"level":5,"theme":"抽象概念","examples":[{"en":"Of the two options, I prefer the latter.","zh":"在這兩個選項中，我比較喜歡後者。"},{"en":"The team improved greatly during the latter half of the season.","zh":"這支球隊在球季的後半段進步很多。"},{"en":"You can have tea or coffee; I will choose the latter.","zh":"你可以喝茶或咖啡；我會選擇後者。"}]},{"word":"laugh","pos":"v. / n.","phonetic":"[læf]","meaning":"笑；大笑","definition":"to make sounds showing happiness or amusement","collocations":["laugh out loud","laugh at","burst into laughter"],"example":"The joke made everyone laugh loudly.","exampleZh":"那個笑話讓大家都笑出聲來。","synonyms":["chuckle","giggle"],"level":1,"theme":"情緒與感受","examples":[{"en":"The joke made everyone laugh loudly.","zh":"那個笑話讓大家都笑出聲來。"},{"en":"The funny movie made the whole audience laugh out loud.","zh":"這部好笑的電影讓全場觀眾放聲大笑。"},{"en":"It is unkind to laugh at someone who has made a mistake.","zh":"嘲笑一個犯錯的人是很不厚道的。"}]},{"word":"launch","pos":"v. / n.","phonetic":"[lɔntʃ]","meaning":"發射；發起；推出","definition":"to send something into space, or to start something new such as a product","collocations":["launch a rocket","launch a product","product launch"],"example":"The company will launch a new smartphone next month.","exampleZh":"這家公司下個月將推出一款新手機。","synonyms":["start","introduce"],"level":4,"theme":"科技與媒體","examples":[{"en":"The company will launch a new smartphone next month.","zh":"這家公司下個月將推出一款新手機。"},{"en":"Scientists will launch a rocket into space next week.","zh":"科學家下週將發射一枚火箭進入太空。"},{"en":"The company held a big event for its new product launch.","zh":"這家公司為它的新產品發表會舉辦了一場盛大的活動。"}]},{"word":"laundry","pos":"n.","phonetic":"[ˈlɔndri]","meaning":"待洗衣物；洗衣店","definition":"clothes and other items that need to be washed, or the place where washing is done","collocations":["do the laundry","laundry basket","laundry service"],"example":"She does the laundry every Sunday morning.","exampleZh":"她每個星期天早上洗衣服。","synonyms":[],"level":2,"theme":"居家與生活","examples":[{"en":"She does the laundry every Sunday morning.","zh":"她每個星期天早上洗衣服。"},{"en":"I have to do the laundry before my friends come over tonight.","zh":"今晚朋友來之前，我必須先把待洗衣物洗好。"},{"en":"Please put your dirty socks into the laundry basket.","zh":"請把你的髒襪子放進洗衣籃裡。"}]},{"word":"law","pos":"n.","phonetic":"[lɔ]","meaning":"法律；法規","definition":"a rule established by a government that must be obeyed","collocations":["break the law","obey the law","law school"],"example":"It is against the law to drive without a license.","exampleZh":"無照駕駛是違法的。","synonyms":["rule","regulation"],"level":2,"theme":"政治與法律","examples":[{"en":"It is against the law to drive without a license.","zh":"無照駕駛是違法的。"},{"en":"My cousin studies hard because she wants to enter law school.","zh":"我表姊很用功，因為她想進法學院。"},{"en":"Good citizens obey the law and respect one another.","zh":"好公民遵守法律並且互相尊重。"}]},{"word":"lawn","pos":"n.","phonetic":"[lɔn]","meaning":"草坪","definition":"an area of short, regularly cut grass","collocations":["mow the lawn","front lawn","lawn mower"],"example":"My father mows the lawn every weekend.","exampleZh":"我爸爸每個週末都會修剪草坪。","synonyms":[],"level":2,"theme":"居家與生活","examples":[{"en":"My father mows the lawn every weekend.","zh":"我爸爸每個週末都會修剪草坪。"},{"en":"The children were playing happily on the green front lawn.","zh":"孩子們在綠色的前院草坪上開心地玩耍。"},{"en":"We need to buy a new lawn mower for the garden.","zh":"我們得為花園買一台新的割草機。"}]},{"word":"lawyer","pos":"n.","phonetic":"[ˈlɔjɚ]","meaning":"律師","definition":"a person who is qualified to practice law","collocations":["hire a lawyer","become a lawyer","defense lawyer"],"example":"She hired a lawyer to handle the case.","exampleZh":"她請了一位律師來處理這個案子。","synonyms":["attorney"],"level":3,"theme":"工作與職業","examples":[{"en":"She hired a lawyer to handle the case.","zh":"她請了一位律師來處理這個案子。"},{"en":"After years of study, she finally became a lawyer.","zh":"經過多年的學習，她終於成為一名律師。"},{"en":"The defense lawyer argued that his client was innocent.","zh":"辯護律師主張他的委託人是無辜的。"}]},{"word":"lay","pos":"v.","phonetic":"[le]","meaning":"放置；產卵","definition":"to put something down carefully, or to produce eggs","collocations":["lay eggs","lay the table","lay down"],"example":"Hens lay eggs almost every day.","exampleZh":"母雞幾乎每天都會下蛋。","synonyms":["place","put"],"level":2,"theme":"動作與行為","examples":[{"en":"Hens lay eggs almost every day.","zh":"母雞幾乎每天都會下蛋。"},{"en":"Please help me lay the table before the guests arrive.","zh":"客人到達之前，請幫我擺好餐桌。"},{"en":"He carefully laid the sleeping baby down in the crib.","zh":"他小心地把熟睡的嬰兒放進嬰兒床裡。"}]},{"word":"layer","pos":"n.","phonetic":"[ˈleɚ]","meaning":"層；層次","definition":"a level, sheet, or thickness of material covering a surface","collocations":["a layer of","ozone layer","layer cake"],"example":"There is a thick layer of snow on the ground.","exampleZh":"地上有一層厚厚的雪。","synonyms":["level","coat"],"level":3,"theme":"自然與環境","examples":[{"en":"There is a thick layer of snow on the ground.","zh":"地上有一層厚厚的雪。"},{"en":"The ozone layer protects us from harmful sunlight.","zh":"臭氧層保護我們免受有害陽光的傷害。"},{"en":"She spread a thin layer of butter on the toast.","zh":"她在吐司上塗了一層薄薄的奶油。"}]},{"word":"lazy","pos":"adj.","phonetic":"[ˈlezi]","meaning":"懶惰的","definition":"unwilling to work or use energy","collocations":["lazy student","feel lazy","lazy afternoon"],"example":"The lazy cat slept all day long.","exampleZh":"這隻懶惰的貓睡了一整天。","synonyms":["idle"],"level":1,"theme":"性質與描述","examples":[{"en":"The lazy cat slept all day long.","zh":"這隻懶惰的貓睡了一整天。"},{"en":"On a lazy afternoon, I like to read comics in bed.","zh":"在慵懶的午後，我喜歡躺在床上看漫畫。"},{"en":"The lazy student never finishes his homework on time.","zh":"那個懶惰的學生從不準時完成作業。"}]},{"word":"lead","pos":"v. / n.","phonetic":"[lid]","meaning":"帶領；領先","definition":"to guide a group of people, or to be in first place","collocations":["lead the way","take the lead","lead a team"],"example":"She will lead the team in the competition.","exampleZh":"她將在比賽中帶領這個團隊。","synonyms":["guide","direct"],"level":3,"theme":"工作與職業","examples":[{"en":"She will lead the team in the competition.","zh":"她將在比賽中帶領這個團隊。"},{"en":"The tour guide will lead the way through the old temple.","zh":"導遊會帶領大家穿過那座古老的寺廟。"},{"en":"Our team took the lead in the second half of the game.","zh":"我們的隊伍在下半場取得領先。"}]},{"word":"leader","pos":"n.","phonetic":"[ˈlidɚ]","meaning":"領導者","definition":"a person who leads or commands a group","collocations":["team leader","become a leader","world leader"],"example":"A good leader listens to others' opinions.","exampleZh":"一位好的領導者會傾聽他人的意見。","synonyms":["head","chief"],"level":2,"theme":"工作與職業","examples":[{"en":"A good leader listens to others' opinions.","zh":"一位好的領導者會傾聽他人的意見。"},{"en":"As team leader, she encourages everyone to share ideas.","zh":"身為隊長，她鼓勵每個人分享想法。"},{"en":"World leaders gathered to discuss climate change.","zh":"各國領袖齊聚一堂討論氣候變遷。"}]},{"word":"leaf","pos":"n.","phonetic":"[lif]","meaning":"葉子","definition":"a flat, usually green part of a plant that grows from a stem","collocations":["fallen leaves","green leaf","leaf through"],"example":"The leaves turn red and yellow in autumn.","exampleZh":"樹葉在秋天會轉紅變黃。","synonyms":[],"level":1,"theme":"動物與植物","examples":[{"en":"The leaves turn red and yellow in autumn.","zh":"樹葉在秋天會轉紅變黃。"},{"en":"I like to leaf through magazines while waiting for the bus.","zh":"我喜歡在等公車時隨手翻閱雜誌。"},{"en":"The ground was covered with colorful fallen leaves.","zh":"地上鋪滿了色彩繽紛的落葉。"}]},{"word":"leak","pos":"v. / n.","phonetic":"[lik]","meaning":"漏；洩漏","definition":"to let liquid or gas escape through a hole or crack","collocations":["leak information","water leak","gas leak"],"example":"The roof leaks whenever it rains heavily.","exampleZh":"每次下大雨屋頂就會漏水。","synonyms":["drip","seep"],"level":4,"theme":"居家與生活","examples":[{"en":"The roof leaks whenever it rains heavily.","zh":"每次下大雨屋頂就會漏水。"},{"en":"Someone leaked the exam questions before the test.","zh":"有人在考試前洩漏了試題。"},{"en":"We smelled gas and quickly reported the leak.","zh":"我們聞到瓦斯味，立刻通報了洩漏。"}]},{"word":"lean","pos":"v. / adj.","phonetic":"[lin]","meaning":"傾斜；倚靠；瘦的","definition":"to bend or rest against something; thin and fit, with little fat","collocations":["lean against","lean forward","lean meat"],"example":"He leaned against the wall while waiting.","exampleZh":"他等待時倚靠在牆上。","synonyms":["tilt","slim"],"level":3,"theme":"動作與行為","examples":[{"en":"He leaned against the wall while waiting.","zh":"他等待時倚靠在牆上。"},{"en":"She leaned forward to hear the teacher more clearly.","zh":"她身體向前傾，好把老師的話聽得更清楚。"},{"en":"The doctor suggested eating more lean meat and vegetables.","zh":"醫生建議多吃瘦肉和蔬菜。"}]},{"word":"leap","pos":"v. / n.","phonetic":"[lip]","meaning":"跳躍","definition":"to jump a long distance or with great effort","collocations":["leap year","leap forward","quantum leap"],"example":"The frog leaped into the pond.","exampleZh":"這隻青蛙跳進了池塘裡。","synonyms":["jump","spring"],"level":3,"theme":"動作與行為","examples":[{"en":"The frog leaped into the pond.","zh":"這隻青蛙跳進了池塘裡。"},{"en":"Technology has taken a huge leap forward in recent years.","zh":"近年來科技有了巨大的躍進。"},{"en":"February has an extra day during a leap year.","zh":"閏年時二月會多出一天。"}]},{"word":"learn","pos":"v.","phonetic":"[lɝn]","meaning":"學習","definition":"to gain knowledge or skill through study or experience","collocations":["learn from mistakes","learn a lesson","learn to swim"],"example":"Children learn languages quickly.","exampleZh":"孩子們學習語言的速度很快。","synonyms":["study","acquire"],"level":1,"theme":"教育與學習","examples":[{"en":"Children learn languages quickly.","zh":"孩子們學習語言的速度很快。"},{"en":"It is important to learn from your mistakes and keep trying.","zh":"從錯誤中學習並持續嘗試是很重要的。"},{"en":"My little brother is learning to swim this summer.","zh":"我弟弟這個夏天正在學游泳。"}]},{"word":"least","pos":"adj. / adv. / pron.","phonetic":"[list]","meaning":"最少的；最小的","definition":"smallest in amount, extent, or degree","collocations":["at least","the least","least expensive"],"example":"This is the least expensive option available.","exampleZh":"這是目前最便宜的選擇。","synonyms":[],"level":2,"theme":"抽象概念","examples":[{"en":"This is the least expensive option available.","zh":"這是目前最便宜的選擇。"},{"en":"You should at least apologize for being so late.","zh":"你至少該為遲到這麼久道歉。"},{"en":"Among all the phones, this one is the least expensive.","zh":"在所有手機當中，這一支是最便宜的。"}]},{"word":"leather","pos":"n.","phonetic":"[ˈlɛðɚ]","meaning":"皮革","definition":"material made from the skin of an animal, used for clothing and other goods","collocations":["leather jacket","leather shoes","genuine leather"],"example":"He bought a stylish leather jacket.","exampleZh":"他買了一件時尚的皮夾克。","synonyms":[],"level":3,"theme":"服裝與外表","examples":[{"en":"He bought a stylish leather jacket.","zh":"他買了一件時尚的皮夾克。"},{"en":"These shoes are made of genuine leather and will last long.","zh":"這雙鞋是真皮製成的，會很耐穿。"},{"en":"He polished his leather shoes before the interview.","zh":"面試前他把皮鞋擦亮了。"}]},{"word":"leave","pos":"v. / n.","phonetic":"[liv]","meaning":"離開；留下；假期","definition":"to go away from a place, or a period of permitted absence from work","collocations":["leave home","leave a message","sick leave"],"example":"She will leave for Taipei tomorrow morning.","exampleZh":"她明天早上將前往台北。","synonyms":["depart","go"],"level":1,"theme":"動作與行為","examples":[{"en":"She will leave for Taipei tomorrow morning.","zh":"她明天早上將前往台北。"},{"en":"Please leave a message after the beep and I will call back.","zh":"請在嗶聲後留言，我會回電給你。"},{"en":"She took three days of sick leave to recover from the flu.","zh":"她請了三天病假來讓感冒康復。"}]},{"word":"lecture","pos":"n. / v.","phonetic":"[ˈlɛktʃɚ]","meaning":"講課；演講","definition":"a talk given to a group of people to teach them about a subject","collocations":["attend a lecture","give a lecture","lecture hall"],"example":"The professor gave an interesting lecture on history.","exampleZh":"這位教授做了一場有趣的歷史演講。","synonyms":["speech","talk"],"level":3,"theme":"教育與學習","examples":[{"en":"The professor gave an interesting lecture on history.","zh":"這位教授做了一場有趣的歷史演講。"},{"en":"Hundreds of students filled the lecture hall this morning.","zh":"今天早上有數百名學生擠滿了演講廳。"},{"en":"We attended a fascinating lecture on ancient Egypt.","zh":"我們聽了一場關於古埃及的精彩演講。"}]},{"word":"left","pos":"adj. / n.","phonetic":"[lɛft]","meaning":"左邊的；左邊","definition":"the side that is opposite to the right","collocations":["turn left","left hand","on the left"],"example":"Turn left at the next corner.","exampleZh":"在下一個轉角向左轉。","synonyms":[],"level":1,"theme":"時間與空間","examples":[{"en":"Turn left at the next corner.","zh":"在下一個轉角向左轉。"},{"en":"The library is on the left, just past the coffee shop.","zh":"圖書館在左邊，就在咖啡店過去一點。"},{"en":"She writes with her left hand instead of her right.","zh":"她用左手而不是右手寫字。"}]},{"word":"leg","pos":"n.","phonetic":"[lɛg]","meaning":"腿","definition":"one of the limbs on which a person or animal walks and stands","collocations":["break a leg","cross one's legs","leg muscle"],"example":"He hurt his leg while playing basketball.","exampleZh":"他打籃球時傷到了腿。","synonyms":[],"level":1,"theme":"身體與健康","examples":[{"en":"He hurt his leg while playing basketball.","zh":"他打籃球時傷到了腿。"},{"en":"Runners need strong leg muscles to finish a race.","zh":"跑者需要強壯的腿部肌肉才能完成比賽。"},{"en":"Before the show, her friends told her to break a leg.","zh":"演出前，她的朋友們祝她好運。"}]},{"word":"legal","pos":"adj.","phonetic":"[ˈligl̩]","meaning":"合法的；法律的","definition":"relating to the law, or allowed by law","collocations":["legal action","legal advice","legal system"],"example":"Smoking is legal but restricted in public places.","exampleZh":"吸菸是合法的，但在公共場所受到限制。","synonyms":["lawful"],"level":4,"theme":"政治與法律","examples":[{"en":"Smoking is legal but restricted in public places.","zh":"吸菸是合法的，但在公共場所受到限制。"},{"en":"You should get legal advice before signing the contract.","zh":"簽約前你應該尋求法律諮詢。"},{"en":"It is not legal to park your car on this street.","zh":"在這條街上停車是不合法的。"}]},{"word":"legend","pos":"n.","phonetic":"[ˈlɛdʒənd]","meaning":"傳說；傳奇人物","definition":"a traditional story from the past, or a very famous person","collocations":["local legend","become a legend","legend has it"],"example":"According to legend, a dragon once lived in the lake.","exampleZh":"傳說中，曾有一條龍住在這座湖裡。","synonyms":["myth"],"level":4,"theme":"社會與文化","examples":[{"en":"According to legend, a dragon once lived in the lake.","zh":"傳說中，曾有一條龍住在這座湖裡。"},{"en":"Legend has it that a fairy once lived on this mountain.","zh":"傳說曾有一位仙女住在這座山上。"},{"en":"The old singer became a legend in the music world.","zh":"那位老歌手成為音樂界的傳奇人物。"}]},{"word":"leisure","pos":"n.","phonetic":"[ˈliʒɚ]","meaning":"休閒；閒暇","definition":"free time available for relaxation or enjoyment","collocations":["leisure time","leisure activities","at leisure"],"example":"He spends his leisure time playing golf.","exampleZh":"他利用休閒時間打高爾夫球。","synonyms":["free time"],"level":4,"theme":"運動與休閒","examples":[{"en":"He spends his leisure time playing golf.","zh":"他利用休閒時間打高爾夫球。"},{"en":"Reading and hiking are her favorite leisure activities.","zh":"閱讀和健行是她最喜歡的休閒活動。"},{"en":"During leisure time, our family often plays board games.","zh":"閒暇時，我們全家常一起玩桌遊。"}]},{"word":"lemon","pos":"n.","phonetic":"[ˈlɛmən]","meaning":"檸檬","definition":"a sour yellow citrus fruit","collocations":["lemon juice","squeeze a lemon","lemon tea"],"example":"She added lemon juice to the fish dish.","exampleZh":"她在魚料理中加了檸檬汁。","synonyms":[],"level":2,"theme":"食物與烹飪","examples":[{"en":"She added lemon juice to the fish dish.","zh":"她在魚料理中加了檸檬汁。"},{"en":"She squeezed a lemon to make a glass of fresh juice.","zh":"她擠了一顆檸檬，做成一杯新鮮果汁。"},{"en":"A cup of warm lemon tea helps me relax at night.","zh":"一杯溫熱的檸檬茶能幫助我在夜裡放鬆。"}]},{"word":"lend","pos":"v.","phonetic":"[lɛnd]","meaning":"借出","definition":"to give something to someone for a period of time, expecting it back","collocations":["lend money","lend a hand","lend a book"],"example":"Could you lend me your pen for a minute?","exampleZh":"你可以借我你的筆一下嗎？","synonyms":["loan"],"level":2,"theme":"商業與金錢","examples":[{"en":"Could you lend me your pen for a minute?","zh":"你可以借我你的筆一下嗎？"},{"en":"Could you lend a hand with these heavy boxes?","zh":"你能幫忙搬這些重箱子嗎？"},{"en":"I lent my favorite book to a classmate last week.","zh":"上週我把我最愛的書借給了一位同學。"}]},{"word":"length","pos":"n.","phonetic":"[lɛŋθ]","meaning":"長度","definition":"the measurement of how long something is from end to end","collocations":["full length","at length","length of time"],"example":"The length of the river is over 500 kilometers.","exampleZh":"這條河的長度超過五百公里。","synonyms":[],"level":3,"theme":"科學與數學","examples":[{"en":"The length of the river is over 500 kilometers.","zh":"這條河的長度超過五百公里。"},{"en":"The teacher explained the topic at length during class.","zh":"老師在課堂上詳細地解釋了這個主題。"},{"en":"We measured the length of the table with a ruler.","zh":"我們用尺量了桌子的長度。"}]},{"word":"lens","pos":"n.","phonetic":"[lɛnz]","meaning":"鏡片；透鏡","definition":"a curved piece of glass or plastic used to focus light in cameras or glasses","collocations":["camera lens","contact lens","zoom lens"],"example":"He cleaned the lens before taking the photo.","exampleZh":"他在拍照前先清潔了鏡頭。","synonyms":[],"level":4,"theme":"科技與媒體","examples":[{"en":"He cleaned the lens before taking the photo.","zh":"他在拍照前先清潔了鏡頭。"},{"en":"He wears contact lenses instead of glasses at school.","zh":"在學校他戴隱形眼鏡而不戴一般眼鏡。"},{"en":"A zoom lens lets you photograph faraway birds clearly.","zh":"變焦鏡頭讓你能清楚拍到遠處的鳥。"}]},{"word":"less","pos":"adj. / adv. / pron.","phonetic":"[lɛs]","meaning":"較少的","definition":"a smaller amount of something","collocations":["less than","more or less","less likely"],"example":"You should eat less sugar for better health.","exampleZh":"為了健康，你應該少吃點糖。","synonyms":[],"level":1,"theme":"抽象概念","examples":[{"en":"You should eat less sugar for better health.","zh":"為了健康，你應該少吃點糖。"},{"en":"The trip took less than two hours by high-speed rail.","zh":"搭高鐵這趟旅程花了不到兩個小時。"},{"en":"People who exercise are less likely to get sick.","zh":"常運動的人比較不容易生病。"}]},{"word":"lesson","pos":"n.","phonetic":"[ˈlɛsn̩]","meaning":"課程；教訓","definition":"a period of learning, or something learned from experience","collocations":["take lessons","learn a lesson","piano lesson"],"example":"We had an English lesson this morning.","exampleZh":"我們今天早上上了一堂英文課。","synonyms":["class"],"level":1,"theme":"教育與學習","examples":[{"en":"We had an English lesson this morning.","zh":"我們今天早上上了一堂英文課。"},{"en":"She takes piano lessons twice a week after school.","zh":"她放學後每週上兩次鋼琴課。"},{"en":"Failing the test taught him an important lesson.","zh":"考試不及格給了他一個重要的教訓。"}]},{"word":"let","pos":"v.","phonetic":"[lɛt]","meaning":"讓；允許","definition":"to allow something to happen or someone to do something","collocations":["let go","let someone know","let alone"],"example":"Please let me know if you need help.","exampleZh":"如果你需要幫忙，請讓我知道。","synonyms":["allow","permit"],"level":1,"theme":"動作與行為","examples":[{"en":"Please let me know if you need help.","zh":"如果你需要幫忙，請讓我知道。"},{"en":"Let me know as soon as you arrive at the station.","zh":"你一到車站就讓我知道。"},{"en":"He cannot even ride a bike, let alone drive a car.","zh":"他連腳踏車都不會騎，更別說開車了。"}]},{"word":"letter","pos":"n.","phonetic":"[ˈlɛtɚ]","meaning":"信；字母","definition":"a written message sent to someone, or a symbol of the alphabet","collocations":["write a letter","capital letter","love letter"],"example":"She wrote a letter to her grandmother.","exampleZh":"她寫了一封信給她的祖母。","synonyms":[],"level":1,"theme":"溝通與語言","examples":[{"en":"She wrote a letter to her grandmother.","zh":"她寫了一封信給她的祖母。"},{"en":"Please begin each sentence with a capital letter.","zh":"每個句子請以大寫字母開頭。"},{"en":"He wrote a heartfelt letter to thank his teacher.","zh":"他寫了一封真摯的信來感謝他的老師。"}]},{"word":"level","pos":"n. / adj.","phonetic":"[ˈlɛvl̩]","meaning":"水平；程度；等級的","definition":"a standard, amount, or position on a scale; flat and even","collocations":["high level","sea level","level ground"],"example":"The water level rose after the heavy rain.","exampleZh":"大雨過後水位上升了。","synonyms":["standard","degree"],"level":2,"theme":"抽象概念","examples":[{"en":"The water level rose after the heavy rain.","zh":"大雨過後水位上升了。"},{"en":"The village lies just a few meters above sea level.","zh":"這個村莊僅位於海平面上方幾公尺。"},{"en":"We set up the tent on level ground near the river.","zh":"我們在河邊的平地上搭起帳篷。"}]},{"word":"liberty","pos":"n.","phonetic":"[ˈlɪbɚti]","meaning":"自由","definition":"the freedom to live, think, and act as one chooses","collocations":["personal liberty","take the liberty","civil liberty"],"example":"People fought for liberty and equality.","exampleZh":"人們為自由與平等而奮鬥。","synonyms":["freedom"],"level":6,"theme":"政治與法律","examples":[{"en":"People fought for liberty and equality.","zh":"人們為自由與平等而奮鬥。"},{"en":"Everyone should enjoy the liberty to express their opinions.","zh":"每個人都應享有表達意見的自由。"},{"en":"I took the liberty of ordering coffee for both of us.","zh":"我擅自作主為我們兩人點了咖啡。"}]},{"word":"library","pos":"n.","phonetic":"[ˈlaɪˌbrɛri]","meaning":"圖書館","definition":"a place containing books for reading or borrowing","collocations":["school library","public library","library card"],"example":"I borrowed three books from the library.","exampleZh":"我從圖書館借了三本書。","synonyms":[],"level":1,"theme":"教育與學習","examples":[{"en":"I borrowed three books from the library.","zh":"我從圖書館借了三本書。"},{"en":"You need a library card to borrow these reference books.","zh":"你需要借書證才能借閱這些參考書。"},{"en":"The public library stays open until nine every evening.","zh":"這間公立圖書館每晚開放到九點。"}]},{"word":"license","pos":"n. / v.","phonetic":"[ˈlaɪsn̩s]","meaning":"執照；許可證","definition":"an official document giving permission to do or own something","collocations":["driver's license","business license","license plate"],"example":"You need a license to drive a car legally.","exampleZh":"你需要有駕照才能合法開車。","synonyms":["permit"],"level":4,"theme":"政治與法律","examples":[{"en":"You need a license to drive a car legally.","zh":"你需要有駕照才能合法開車。"},{"en":"He finally passed the test and got his driver's license.","zh":"他終於通過考試，拿到了駕照。"},{"en":"The police wrote down the car's license plate number.","zh":"警察記下了那輛車的車牌號碼。"}]},{"word":"lid","pos":"n.","phonetic":"[lɪd]","meaning":"蓋子","definition":"a removable cover for the top of a container","collocations":["put the lid on","jar lid","lift the lid"],"example":"Please put the lid back on the pot.","exampleZh":"請把蓋子放回鍋子上。","synonyms":["cover"],"level":2,"theme":"居家與生活","examples":[{"en":"Please put the lid back on the pot.","zh":"請把蓋子放回鍋子上。"},{"en":"She lifted the lid and smelled the delicious soup.","zh":"她掀開蓋子，聞到了美味的湯。"},{"en":"The jar lid was too tight for me to open.","zh":"那個罐子的蓋子太緊，我打不開。"}]},{"word":"lie","pos":"v. / n.","phonetic":"[laɪ]","meaning":"說謊；躺；謊言","definition":"to say something that is not true, or to rest in a flat position","collocations":["tell a lie","lie down","white lie"],"example":"He lay down on the sofa to rest.","exampleZh":"他躺在沙發上休息。","synonyms":["fib","recline"],"level":2,"theme":"動作與行為","examples":[{"en":"He lay down on the sofa to rest.","zh":"他躺在沙發上休息。"},{"en":"You should never tell a lie to your parents.","zh":"你絕對不該對父母說謊。"},{"en":"Feeling tired, she decided to lie down for a while.","zh":"覺得累了，她決定躺下來休息一會兒。"}]},{"word":"life","pos":"n.","phonetic":"[laɪf]","meaning":"生活；生命","definition":"the state of being alive, or a person's existence","collocations":["daily life","wildlife","way of life"],"example":"City life can be both exciting and stressful.","exampleZh":"城市生活既刺激又充滿壓力。","synonyms":["existence"],"level":1,"theme":"抽象概念","examples":[{"en":"City life can be both exciting and stressful.","zh":"城市生活既刺激又充滿壓力。"},{"en":"Smartphones have become part of our daily life.","zh":"智慧型手機已成為我們日常生活的一部分。"},{"en":"The documentary explores wildlife in the deep ocean.","zh":"這部紀錄片探索深海中的野生生物。"}]},{"word":"lift","pos":"v. / n.","phonetic":"[lɪft]","meaning":"舉起；電梯","definition":"to raise something to a higher position","collocations":["lift weights","give a lift","lift up"],"example":"He lifted the heavy box onto the truck.","exampleZh":"他把沉重的箱子抬上卡車。","synonyms":["raise"],"level":2,"theme":"動作與行為","examples":[{"en":"He lifted the heavy box onto the truck.","zh":"他把沉重的箱子抬上卡車。"},{"en":"He lifts weights at the gym three times a week.","zh":"他每週去健身房舉重三次。"},{"en":"My neighbor kindly gave me a lift to school.","zh":"我的鄰居好心載我一程到學校。"}]},{"word":"light","pos":"n. / adj. / v.","phonetic":"[laɪt]","meaning":"光；輕的；點燃","definition":"brightness that comes from the sun or a lamp; not heavy; to set something on fire","collocations":["turn on the light","light rain","light a candle"],"example":"She turned on the light in the dark room.","exampleZh":"她打開了昏暗房間裡的燈。","synonyms":["bright"],"level":1,"theme":"自然與環境","examples":[{"en":"She turned on the light in the dark room.","zh":"她打開了昏暗房間裡的燈。"},{"en":"They lit a candle when the power suddenly went out.","zh":"停電時他們點燃了一根蠟燭。"},{"en":"We went for a walk despite the light rain.","zh":"儘管下著小雨，我們還是去散步了。"}]},{"word":"lightning","pos":"n.","phonetic":"[ˈlaɪtnɪŋ]","meaning":"閃電","definition":"a bright flash of light in the sky produced by a storm","collocations":["lightning strikes","thunder and lightning","lightning speed"],"example":"The lightning lit up the entire sky.","exampleZh":"閃電照亮了整個天空。","synonyms":[],"level":3,"theme":"天氣與季節","examples":[{"en":"The lightning lit up the entire sky.","zh":"閃電照亮了整個天空。"},{"en":"The runner crossed the finish line at lightning speed.","zh":"那名跑者以閃電般的速度衝過終點線。"},{"en":"During the storm, thunder and lightning frightened the dog.","zh":"暴風雨中，雷聲和閃電嚇壞了那隻狗。"}]},{"word":"like","pos":"v. / prep.","phonetic":"[laɪk]","meaning":"喜歡；像","definition":"to find something pleasant or enjoyable; similar to","collocations":["like music","look like","feel like"],"example":"I like listening to music before bed.","exampleZh":"我喜歡在睡前聽音樂。","synonyms":["enjoy"],"level":1,"theme":"情緒與感受","examples":[{"en":"I like listening to music before bed.","zh":"我喜歡在睡前聽音樂。"},{"en":"My sister looks like our mother when she smiles.","zh":"我妹妹微笑時看起來很像我們的媽媽。"},{"en":"I feel like eating something sweet after dinner.","zh":"晚餐後我想吃點甜的東西。"}]},{"word":"likely","pos":"adj. / adv.","phonetic":"[ˈlaɪkli]","meaning":"可能的","definition":"probable or expected to happen","collocations":["likely to happen","more likely","most likely"],"example":"It is likely to rain this afternoon.","exampleZh":"今天下午很可能會下雨。","synonyms":["probable"],"level":3,"theme":"抽象概念","examples":[{"en":"It is likely to rain this afternoon.","zh":"今天下午很可能會下雨。"},{"en":"The team is most likely to win the championship.","zh":"這支隊伍最有可能贏得冠軍。"},{"en":"Without an umbrella, you are likely to get wet.","zh":"沒帶傘的話，你很可能會淋濕。"}]},{"word":"limit","pos":"n. / v.","phonetic":"[ˈlɪmɪt]","meaning":"限制；界限","definition":"the greatest or smallest amount allowed, or to restrict something","collocations":["speed limit","set a limit","age limit"],"example":"Please obey the speed limit while driving.","exampleZh":"開車時請遵守速限。","synonyms":["restrict","boundary"],"level":3,"theme":"抽象概念","examples":[{"en":"Please obey the speed limit while driving.","zh":"開車時請遵守速限。"},{"en":"There is an age limit for watching this scary movie.","zh":"觀看這部恐怖片有年齡限制。"},{"en":"My parents set a limit on my screen time each day.","zh":"我父母限制我每天使用螢幕的時間。"}]},{"word":"line","pos":"n. / v.","phonetic":"[laɪn]","meaning":"線；排隊","definition":"a long thin mark, or a row of people or things","collocations":["wait in line","draw a line","phone line"],"example":"Please stand in line and wait for your turn.","exampleZh":"請排隊並等待輪到你。","synonyms":["row","queue"],"level":1,"theme":"性質與描述","examples":[{"en":"Please stand in line and wait for your turn.","zh":"請排隊並等待輪到你。"},{"en":"Draw a straight line between these two points.","zh":"在這兩點之間畫一條直線。"},{"en":"Customers waited in line for the new phone.","zh":"顧客們排隊等候新手機。"}]},{"word":"link","pos":"n. / v.","phonetic":"[lɪŋk]","meaning":"連結；關聯","definition":"a connection between two things, or to connect them","collocations":["click a link","link together","weak link"],"example":"Click the link to visit our website.","exampleZh":"點擊這個連結來造訪我們的網站。","synonyms":["connection","join"],"level":3,"theme":"科技與媒體","examples":[{"en":"Click the link to visit our website.","zh":"點擊這個連結來造訪我們的網站。"},{"en":"These two events are closely linked together.","zh":"這兩起事件緊密相關。"},{"en":"A poorly trained player can be the team's weak link.","zh":"訓練不足的球員可能是球隊的弱點。"}]},{"word":"lion","pos":"n.","phonetic":"[ˈlaɪən]","meaning":"獅子","definition":"a large wild cat found mainly in Africa","collocations":["male lion","roar like a lion","lion cub"],"example":"The lion is known as the king of the jungle.","exampleZh":"獅子被稱為叢林之王。","synonyms":[],"level":1,"theme":"動物與植物","examples":[{"en":"The lion is known as the king of the jungle.","zh":"獅子被稱為叢林之王。"},{"en":"The lion cub stayed close to its mother.","zh":"幼獅緊緊跟在母親身邊。"},{"en":"The angry coach roared like a lion at the players.","zh":"憤怒的教練對球員們像獅子般大吼。"}]},{"word":"lip","pos":"n.","phonetic":"[lɪp]","meaning":"嘴唇","definition":"either of the two fleshy parts around the opening of the mouth","collocations":["upper lip","lip balm","bite one's lip"],"example":"She applied some lip balm before going out.","exampleZh":"她出門前擦了一些護唇膏。","synonyms":[],"level":1,"theme":"身體與健康","examples":[{"en":"She applied some lip balm before going out.","zh":"她出門前擦了一些護唇膏。"},{"en":"She bit her lip nervously before the interview.","zh":"面試前她緊張地咬著嘴唇。"},{"en":"Apply lip balm to protect your lips in winter.","zh":"冬天擦護唇膏來保護你的嘴唇。"}]},{"word":"liquid","pos":"n. / adj.","phonetic":"[ˈlɪkwɪd]","meaning":"液體；液態的","definition":"a substance, such as water, that flows freely and is neither solid nor gas","collocations":["liquid form","clear liquid","liquid diet"],"example":"Water is a liquid at room temperature.","exampleZh":"水在室溫下是液體。","synonyms":["fluid"],"level":3,"theme":"科學與數學","examples":[{"en":"Water is a liquid at room temperature.","zh":"水在室溫下是液體。"},{"en":"The medicine comes in liquid form for young children.","zh":"這種藥有適合幼童的液體形式。"},{"en":"After surgery, the patient was put on a liquid diet.","zh":"手術後，病人採用流質飲食。"}]},{"word":"loaf","pos":"n.","phonetic":"[lof]","meaning":"一條(麵包)","definition":"a shaped mass of bread baked in one piece","collocations":["a loaf of bread","sliced loaf"],"example":"She bought a loaf of fresh bread from the bakery.","exampleZh":"她從麵包店買了一條新鮮的麵包。","synonyms":[],"level":2,"theme":"食物與烹飪","examples":[{"en":"She bought a loaf of fresh bread from the bakery.","zh":"她從麵包店買了一條新鮮的麵包。"},{"en":"He sliced the loaf and made sandwiches for lunch.","zh":"他把那條麵包切片，做成午餐的三明治。"},{"en":"We buy a fresh loaf of bread every morning.","zh":"我們每天早上買一條新鮮麵包。"}]},{"word":"loan","pos":"n. / v.","phonetic":"[lon]","meaning":"貸款；借出","definition":"money that is borrowed and repaid with interest; to lend something","collocations":["bank loan","take out a loan","loan money"],"example":"They took out a loan to buy their first house.","exampleZh":"他們貸款買了第一間房子。","synonyms":["credit","lend"],"level":3,"theme":"商業與金錢","examples":[{"en":"They took out a loan to buy their first house.","zh":"他們貸款買了第一間房子。"},{"en":"The bank approved their loan for a new car.","zh":"銀行核准了他們買新車的貸款。"},{"en":"He offered to loan money to his struggling friend.","zh":"他主動借錢給經濟困難的朋友。"}]},{"word":"loath","pos":"adj.","phonetic":"[loθ]","meaning":"不情願的","definition":"reluctant or unwilling to do something","collocations":["loath to admit","loath to leave"],"example":"He was loath to admit his mistake.","exampleZh":"他不情願承認自己的錯誤。","synonyms":["reluctant","unwilling"],"level":6,"theme":"情緒與感受","examples":[{"en":"He was loath to admit his mistake.","zh":"他不情願承認自己的錯誤。"},{"en":"The children were loath to leave the amusement park.","zh":"孩子們很不情願離開遊樂園。"},{"en":"She was loath to lend her new bike to anyone.","zh":"她很不願意把新腳踏車借給任何人。"}]},{"word":"loathe","pos":"v.","phonetic":"[loð]","meaning":"憎恨；厭惡","definition":"to feel strong hatred or disgust for something","collocations":["loathe someone","loathe the idea"],"example":"She loathes waking up early in winter.","exampleZh":"她很討厭冬天早起。","synonyms":["hate","detest"],"level":6,"theme":"情緒與感受","examples":[{"en":"She loathes waking up early in winter.","zh":"她很討厭冬天早起。"},{"en":"I absolutely loathe cleaning my room on weekends.","zh":"我極度厭惡在週末打掃我的房間。"},{"en":"He loathes the idea of moving to another city.","zh":"他很厭惡搬到另一個城市的想法。"}]},{"word":"loathsome","pos":"adj.","phonetic":"[ˈloðsəm]","meaning":"令人厭惡的","definition":"causing hatred or disgust","collocations":["loathsome creature","loathsome smell"],"example":"The loathsome smell filled the entire room.","exampleZh":"那令人作嘔的氣味瀰漫整個房間。","synonyms":["disgusting","repulsive"],"level":6,"theme":"性質與描述","examples":[{"en":"The loathsome smell filled the entire room.","zh":"那令人作嘔的氣味瀰漫整個房間。"},{"en":"A loathsome insect crawled across the kitchen floor.","zh":"一隻令人厭惡的昆蟲爬過廚房地板。"},{"en":"Everyone avoided the loathsome habit of littering.","zh":"大家都避免亂丟垃圾這種令人厭惡的習慣。"}]},{"word":"lob","pos":"v. / n.","phonetic":"[lɑb]","meaning":"高吊球；擲","definition":"to throw or hit something in a high arc","collocations":["lob the ball","hit a lob"],"example":"She lobbed the tennis ball over her opponent.","exampleZh":"她把網球高高吊過對手頭頂。","synonyms":["toss","throw"],"level":5,"theme":"運動與休閒","examples":[{"en":"She lobbed the tennis ball over her opponent.","zh":"她把網球高高吊過對手頭頂。"},{"en":"She lobbed the ball high over the net.","zh":"她把球高高地吊過網子。"},{"en":"The player hit a perfect lob to win the point.","zh":"那名選手打出一記完美的高吊球贏得該分。"}]},{"word":"lobby","pos":"n. / v.","phonetic":"[ˈlɑbi]","meaning":"大廳；遊說","definition":"an entrance hall; to try to influence officials on an issue","collocations":["hotel lobby","lobby for change","lobby group"],"example":"We met in the hotel lobby before dinner.","exampleZh":"我們晚餐前在飯店大廳碰面。","synonyms":["hall","foyer"],"level":4,"theme":"政治與法律","examples":[{"en":"We met in the hotel lobby before dinner.","zh":"我們晚餐前在飯店大廳碰面。"},{"en":"The guests gathered in the bright hotel lobby.","zh":"客人們聚集在明亮的飯店大廳裡。"},{"en":"Many parents lobbied for safer roads near the school.","zh":"許多家長遊說爭取學校附近更安全的道路。"}]},{"word":"lobe","pos":"n.","phonetic":"[lob]","meaning":"耳垂；(器官)葉","definition":"a rounded projecting part, especially of the ear or an organ","collocations":["ear lobe","brain lobe"],"example":"She wears small earrings on her ear lobes.","exampleZh":"她耳垂上戴著小耳環。","synonyms":[],"level":5,"theme":"身體與健康","examples":[{"en":"She wears small earrings on her ear lobes.","zh":"她耳垂上戴著小耳環。"},{"en":"The doctor gently examined the child's ear lobe.","zh":"醫生輕輕檢查了孩子的耳垂。"},{"en":"Different lobes of the brain control different functions.","zh":"大腦的不同腦葉控制著不同的功能。"}]},{"word":"lobster","pos":"n.","phonetic":"[ˈlɑbstɚ]","meaning":"龍蝦","definition":"a large sea creature with a hard shell and large claws","collocations":["fresh lobster","lobster tail","boiled lobster"],"example":"Lobster is a popular dish at seafood restaurants.","exampleZh":"龍蝦是海鮮餐廳很受歡迎的一道菜。","synonyms":[],"level":3,"theme":"食物與烹飪","examples":[{"en":"Lobster is a popular dish at seafood restaurants.","zh":"龍蝦是海鮮餐廳很受歡迎的一道菜。"},{"en":"We enjoyed fresh lobster at the harbor restaurant.","zh":"我們在港邊餐廳享用了新鮮的龍蝦。"},{"en":"The chef served boiled lobster with melted butter.","zh":"主廚端上了配融化奶油的水煮龍蝦。"}]},{"word":"local","pos":"adj.","phonetic":"[ˈlokl̩]","meaning":"當地的；地方性的","definition":"relating to a particular area or neighborhood","collocations":["local news","local government","local resident","local market"],"example":"She shops at the local market every weekend.","exampleZh":"她每個週末都在當地市場購物。","synonyms":["regional","nearby"],"level":2,"theme":"居家與生活","examples":[{"en":"She shops at the local market every weekend.","zh":"她每個週末都在當地市場購物。"},{"en":"The local news reported heavy traffic downtown.","zh":"地方新聞報導市中心交通嚴重壅塞。"},{"en":"Local residents warmly welcomed the new library.","zh":"當地居民熱情地歡迎這座新圖書館。"}]},{"word":"locale","pos":"n.","phonetic":"[loˈkæl]","meaning":"地點；現場","definition":"a place where something happens, especially in a story or film","collocations":["film locale","exotic locale"],"example":"The tropical island was a perfect locale for the movie.","exampleZh":"這座熱帶島嶼是這部電影絕佳的拍攝地點。","synonyms":["location","setting"],"level":6,"theme":"時間與空間","examples":[{"en":"The tropical island was a perfect locale for the movie.","zh":"這座熱帶島嶼是這部電影絕佳的拍攝地點。"},{"en":"The director chose a quiet village as the film locale.","zh":"導演選了一個寧靜的村莊作為電影的拍攝地點。"},{"en":"The novel is set in an exotic tropical locale.","zh":"這部小說的場景設在一個充滿異國風情的熱帶地點。"}]},{"word":"locality","pos":"n.","phonetic":"[loˈkæləti]","meaning":"地區；當地","definition":"an area or neighborhood","collocations":["in this locality","a rural locality"],"example":"Several schools are located in this locality.","exampleZh":"這個地區有好幾所學校。","synonyms":["area","district"],"level":6,"theme":"時間與空間","examples":[{"en":"Several schools are located in this locality.","zh":"這個地區有好幾所學校。"},{"en":"Fresh vegetables are grown in this rural locality.","zh":"這個鄉村地區種植著新鮮的蔬菜。"},{"en":"Few doctors work in such a remote locality.","zh":"很少有醫生在如此偏遠的地區工作。"}]},{"word":"localize","pos":"v.","phonetic":"[ˈlokəˌlaɪz]","meaning":"使地方化；使在地化","definition":"to restrict something to a particular area; to adapt for a local market","collocations":["localize an infection","localize production"],"example":"The company localized its products for the Asian market.","exampleZh":"這家公司將產品在地化以進入亞洲市場。","synonyms":["confine","restrict"],"level":6,"theme":"商業與金錢","examples":[{"en":"The company localized its products for the Asian market.","zh":"這家公司將產品在地化以進入亞洲市場。"},{"en":"The company decided to localize production in Asia.","zh":"這家公司決定將生產在地化於亞洲。"},{"en":"Doctors worked quickly to localize the infection.","zh":"醫生們迅速設法把感染局限在局部範圍。"}]},{"word":"locate","pos":"v.","phonetic":"[ˈloket]","meaning":"找出...的位置；設置在","definition":"to find the exact position of something","collocations":["locate a store","locate the source","easily located"],"example":"We used GPS to locate the nearest hospital.","exampleZh":"我們用GPS定位最近的醫院。","synonyms":["find","pinpoint"],"level":3,"theme":"時間與空間","examples":[{"en":"We used GPS to locate the nearest hospital.","zh":"我們用GPS定位最近的醫院。"},{"en":"The app helps you locate the nearest bus stop.","zh":"這個應用程式幫你找到最近的公車站。"},{"en":"Engineers tried to locate the source of the noise.","zh":"工程師們試圖找出噪音的來源。"}]},{"word":"location","pos":"n.","phonetic":"[loˈkeʃən]","meaning":"位置；地點","definition":"a particular place or position","collocations":["perfect location","filming location","current location"],"example":"The hotel's location is very convenient for tourists.","exampleZh":"這間飯店的位置對遊客來說非常方便。","synonyms":["place","site"],"level":3,"theme":"時間與空間","examples":[{"en":"The hotel's location is very convenient for tourists.","zh":"這間飯店的位置對遊客來說非常方便。"},{"en":"Please share your current location so I can find you.","zh":"請分享你目前的位置，好讓我找到你。"},{"en":"The cafe's quiet location makes it perfect for studying.","zh":"這家咖啡館安靜的地點使它非常適合讀書。"}]},{"word":"lock","pos":"n. / v.","phonetic":"[lɑk]","meaning":"鎖；鎖上","definition":"a device for fastening a door or container; to fasten with a lock","collocations":["lock the door","under lock and key","lock in place"],"example":"Please remember to lock the door before you leave.","exampleZh":"離開前請記得鎖門。","synonyms":["fasten","secure"],"level":1,"theme":"居家與生活","examples":[{"en":"Please remember to lock the door before you leave.","zh":"離開前請記得鎖門。"},{"en":"Remember to lock the windows before the typhoon.","zh":"颱風來之前記得鎖好窗戶。"},{"en":"The valuable documents are kept under lock and key.","zh":"那些貴重文件被妥善地鎖了起來。"}]},{"word":"locker","pos":"n.","phonetic":"[ˈlɑkɚ]","meaning":"置物櫃；儲物櫃","definition":"a small lockable cupboard for personal belongings","collocations":["gym locker","locker room","rent a locker"],"example":"He keeps his gym clothes in a locker.","exampleZh":"他把運動服放在置物櫃裡。","synonyms":["cabinet","cupboard"],"level":2,"theme":"居家與生活","examples":[{"en":"He keeps his gym clothes in a locker.","zh":"他把運動服放在置物櫃裡。"},{"en":"Students store their books in a locker at school.","zh":"學生把書本放在學校的置物櫃裡。"},{"en":"You can rent a locker at the train station.","zh":"你可以在火車站租用一個置物櫃。"}]},{"word":"locomotive","pos":"n.","phonetic":"[ˌlokəˈmotɪv]","meaning":"火車頭；機車","definition":"a powered railway vehicle used for pulling trains","collocations":["steam locomotive","diesel locomotive"],"example":"The old locomotive is now displayed in the museum.","exampleZh":"這台老舊的火車頭現在展示在博物館裡。","synonyms":["engine"],"level":5,"theme":"交通與旅行","examples":[{"en":"The old locomotive is now displayed in the museum.","zh":"這台老舊的火車頭現在展示在博物館裡。"},{"en":"A powerful steam locomotive pulled the long train.","zh":"一輛強而有力的蒸汽火車頭拉著長長的列車。"},{"en":"Children love watching the diesel locomotive pass by.","zh":"孩子們喜歡看柴油火車頭經過。"}]},{"word":"lodge","pos":"n. / v.","phonetic":"[lɑdʒ]","meaning":"小屋；投宿；提出(申訴)","definition":"a small house, especially in the country; to stay somewhere temporarily; to file a complaint","collocations":["ski lodge","lodge a complaint","hunting lodge"],"example":"They stayed at a mountain lodge during their trip.","exampleZh":"他們旅行期間住在山中小屋。","synonyms":["cabin","cottage"],"level":5,"theme":"居家與生活","examples":[{"en":"They stayed at a mountain lodge during their trip.","zh":"他們旅行期間住在山中小屋。"},{"en":"The customer lodged a complaint about the cold food.","zh":"那位顧客針對冷掉的食物提出了投訴。"},{"en":"We spent the night in a cozy ski lodge.","zh":"我們在一間舒適的滑雪小屋過了一夜。"}]},{"word":"lodging","pos":"n.","phonetic":"[ˈlɑdʒɪŋ]","meaning":"住宿；租屋處","definition":"a place to stay temporarily","collocations":["find lodging","lodging expenses"],"example":"The company provides lodging for new employees.","exampleZh":"這家公司為新員工提供住宿。","synonyms":["accommodation"],"level":5,"theme":"居家與生活","examples":[{"en":"The company provides lodging for new employees.","zh":"這家公司為新員工提供住宿。"},{"en":"The travelers found cheap lodging near the station.","zh":"旅客們在車站附近找到了便宜的住宿。"},{"en":"The scholarship covers both tuition and lodging expenses.","zh":"這份獎學金涵蓋了學費和住宿費用。"}]},{"word":"lofty","pos":"adj.","phonetic":"[ˈlɔfti]","meaning":"崇高的；高聳的","definition":"noble and admirable in nature; very high","collocations":["lofty goal","lofty ideal","lofty ceiling"],"example":"The team had lofty goals for the new season.","exampleZh":"這支隊伍對新賽季懷有崇高的目標。","synonyms":["noble","towering"],"level":6,"theme":"抽象概念","examples":[{"en":"The team had lofty goals for the new season.","zh":"這支隊伍對新賽季懷有崇高的目標。"},{"en":"She set herself the lofty goal of learning five languages.","zh":"她為自己設下學會五種語言的崇高目標。"},{"en":"The old church has a lofty ceiling covered with paintings.","zh":"這座古老教堂有著高聳且畫滿壁畫的天花板。"}]},{"word":"log","pos":"n. / v.","phonetic":"[lɔg]","meaning":"木材；日誌；記錄","definition":"a section of a felled tree; to record information systematically","collocations":["log cabin","log in","keep a log"],"example":"The captain wrote everything in the ship's log.","exampleZh":"船長把所有事情都記在航海日誌裡。","synonyms":["record","journal"],"level":2,"theme":"科技與媒體","examples":[{"en":"The captain wrote everything in the ship's log.","zh":"船長把所有事情都記在航海日誌裡。"},{"en":"You must log in with your password to see the grades.","zh":"你必須用密碼登入才能查看成績。"},{"en":"The scientists keep a log of the daily temperature.","zh":"科學家們記錄每天的氣溫。"}]},{"word":"logic","pos":"n.","phonetic":"[ˈlɑdʒɪk]","meaning":"邏輯；邏輯學","definition":"a sensible or valid way of reasoning","collocations":["sound logic","logic puzzle","follow the logic"],"example":"There is no logic behind his sudden decision.","exampleZh":"他突然的決定毫無邏輯可言。","synonyms":["reasoning"],"level":4,"theme":"科學與數學","examples":[{"en":"There is no logic behind his sudden decision.","zh":"他突然的決定毫無邏輯可言。"},{"en":"I could not follow the logic of his confusing argument.","zh":"我無法理解他那令人困惑的論點邏輯。"},{"en":"Solving logic puzzles trains your brain to think clearly.","zh":"解邏輯謎題能訓練你的大腦清晰思考。"}]},{"word":"logical","pos":"adj.","phonetic":"[ˈlɑdʒɪkl̩]","meaning":"合乎邏輯的；合理的","definition":"based on sensible reasoning","collocations":["logical explanation","logical conclusion","logical thinking"],"example":"Her argument was clear and logical.","exampleZh":"她的論點清楚又合乎邏輯。","synonyms":["reasonable","rational"],"level":4,"theme":"科學與數學","examples":[{"en":"Her argument was clear and logical.","zh":"她的論點清楚又合乎邏輯。"},{"en":"There must be a logical explanation for the missing keys.","zh":"鑰匙不見一定有個合理的解釋。"},{"en":"Good scientists rely on careful, logical thinking.","zh":"優秀的科學家依靠謹慎且合乎邏輯的思考。"}]},{"word":"logo","pos":"n.","phonetic":"[ˈlogo]","meaning":"標誌；商標","definition":"a symbol used to identify a company or product","collocations":["company logo","brand logo","design a logo"],"example":"The company changed its logo last year.","exampleZh":"這家公司去年更換了商標。","synonyms":["emblem","symbol"],"level":3,"theme":"商業與金錢","examples":[{"en":"The company changed its logo last year.","zh":"這家公司去年更換了商標。"},{"en":"A student designed a new logo for the school club.","zh":"一名學生為學校社團設計了新的標誌。"},{"en":"You can recognize the brand by its simple logo.","zh":"你可以透過它簡單的商標認出這個品牌。"}]},{"word":"lollipop","pos":"n.","phonetic":"[ˈlɑliˌpɑp]","meaning":"棒棒糖","definition":"a hard candy on a small stick","collocations":["lick a lollipop","lollipop stick"],"example":"The child was happily licking a lollipop.","exampleZh":"那個孩子開心地舔著棒棒糖。","synonyms":[],"level":1,"theme":"食物與烹飪","examples":[{"en":"The child was happily licking a lollipop.","zh":"那個孩子開心地舔著棒棒糖。"},{"en":"The dentist gave each child a sugar-free lollipop.","zh":"牙醫給每個孩子一根無糖的棒棒糖。"},{"en":"She slowly licked the strawberry lollipop after lunch.","zh":"午餐後她慢慢地舔著草莓棒棒糖。"}]},{"word":"loneliness","pos":"n.","phonetic":"[ˈlonlɪnəs]","meaning":"孤獨；寂寞","definition":"the state of being lonely","collocations":["feelings of loneliness","deal with loneliness"],"example":"Loneliness can affect both physical and mental health.","exampleZh":"孤獨感會影響身心健康。","synonyms":["solitude","isolation"],"level":4,"theme":"情緒與感受","examples":[{"en":"Loneliness can affect both physical and mental health.","zh":"孤獨感會影響身心健康。"},{"en":"Moving abroad, he had to deal with deep loneliness.","zh":"搬到國外後，他必須面對深深的孤獨。"},{"en":"Talking to friends can ease feelings of loneliness.","zh":"和朋友聊天能減輕孤獨的感覺。"}]},{"word":"lonely","pos":"adj.","phonetic":"[ˈlonli]","meaning":"孤獨的；寂寞的","definition":"sad because one has no friends or company","collocations":["feel lonely","lonely life","lonely night"],"example":"She felt lonely after moving to a new city.","exampleZh":"搬到新城市後她感到很孤單。","synonyms":["solitary","isolated"],"level":2,"theme":"情緒與感受","examples":[{"en":"She felt lonely after moving to a new city.","zh":"搬到新城市後她感到很孤單。"},{"en":"The old man felt lonely after his children moved away.","zh":"孩子們搬走後，那位老人感到很孤單。"},{"en":"On a lonely night, she called her best friend.","zh":"在一個寂寞的夜晚，她打電話給她最好的朋友。"}]},{"word":"lonesome","pos":"adj.","phonetic":"[ˈlonsəm]","meaning":"寂寞的；孤獨的","definition":"feeling alone and sad","collocations":["lonesome journey","feel lonesome"],"example":"He led a lonesome life after retiring.","exampleZh":"他退休後過著孤獨的生活。","synonyms":["lonely","solitary"],"level":5,"theme":"情緒與感受","examples":[{"en":"He led a lonesome life after retiring.","zh":"他退休後過著孤獨的生活。"},{"en":"The traveler began a long, lonesome journey across the desert.","zh":"那名旅人展開了一趟橫越沙漠、漫長又孤獨的旅程。"},{"en":"Without his dog, the farmer felt truly lonesome.","zh":"沒有了他的狗，那名農夫感到真正的寂寞。"}]},{"word":"long","pos":"adj. / adv. / v.","phonetic":"[lɔŋ]","meaning":"長的；長久地；渴望","definition":"measuring a great distance or duration; to strongly wish for something","collocations":["long time","long for","before long"],"example":"She has been longing to see her family again.","exampleZh":"她一直渴望能再見到家人。","synonyms":["extended","yearn"],"level":1,"theme":"性質與描述","examples":[{"en":"She has been longing to see her family again.","zh":"她一直渴望能再見到家人。"},{"en":"After months abroad, she longed for her mother's cooking.","zh":"在國外待了幾個月後，她渴望吃到媽媽做的菜。"},{"en":"Be patient; the train will arrive before long.","zh":"耐心一點，火車不久就會到了。"}]},{"word":"longevity","pos":"n.","phonetic":"[lɑnˈdʒɛvəti]","meaning":"長壽；持久","definition":"long life or long duration","collocations":["increase longevity","longevity of a product"],"example":"A healthy diet contributes to longevity.","exampleZh":"健康飲食有助於長壽。","synonyms":["durability"],"level":6,"theme":"身體與健康","examples":[{"en":"A healthy diet contributes to longevity.","zh":"健康飲食有助於長壽。"},{"en":"Regular exercise may increase a person's longevity.","zh":"規律運動可能增加一個人的壽命。"},{"en":"Good care improves the longevity of your smartphone.","zh":"妥善保養能延長你智慧型手機的使用壽命。"}]},{"word":"longing","pos":"n. / adj.","phonetic":"[ˈlɔŋɪŋ]","meaning":"渴望；渴望的","definition":"a strong feeling of wanting something","collocations":["a longing for","longing look"],"example":"She had a deep longing to travel abroad.","exampleZh":"她一直深深渴望能出國旅行。","synonyms":["yearning","desire"],"level":5,"theme":"情緒與感受","examples":[{"en":"She had a deep longing to travel abroad.","zh":"她一直深深渴望能出國旅行。"},{"en":"She gazed at the cake with a longing look.","zh":"她用渴望的眼神凝視著那塊蛋糕。"},{"en":"He felt a strong longing for his childhood home.","zh":"他對童年的家有著強烈的思念。"}]},{"word":"longitude","pos":"n.","phonetic":"[ˈlɑndʒəˌtud]","meaning":"經度","definition":"the distance east or west of a point on the earth measured in degrees","collocations":["lines of longitude","longitude and latitude"],"example":"Every place on Earth has its own longitude and latitude.","exampleZh":"地球上每個地方都有自己的經度和緯度。","synonyms":[],"level":5,"theme":"科學與數學","examples":[{"en":"Every place on Earth has its own longitude and latitude.","zh":"地球上每個地方都有自己的經度和緯度。"},{"en":"Sailors once used the stars to work out their longitude.","zh":"水手們過去曾利用星星來計算他們的經度。"},{"en":"Lines of longitude run from the North to the South Pole.","zh":"經線從北極延伸到南極。"}]},{"word":"look","pos":"v. / n.","phonetic":"[lʊk]","meaning":"看；看起來；外表","definition":"to direct one's eyes toward something; appearance","collocations":["look at","look like","take a look"],"example":"Take a look at this photo I found.","exampleZh":"看看我找到的這張照片。","synonyms":["glance","appearance"],"level":1,"theme":"動作與行為","examples":[{"en":"Take a look at this photo I found.","zh":"看看我找到的這張照片。"},{"en":"Take a look at the beautiful sunset over the sea.","zh":"看看海面上美麗的日落。"},{"en":"Please look both ways before crossing the street.","zh":"過馬路前請左右兩邊都看看。"}]},{"word":"loop","pos":"n. / v.","phonetic":"[lup]","meaning":"環；迴圈；使成環狀","definition":"a shape produced by a curve that bends round and crosses itself","collocations":["in a loop","loop the video","feedback loop"],"example":"The road forms a loop around the lake.","exampleZh":"這條路繞湖形成一個環形。","synonyms":["circle","ring"],"level":4,"theme":"科學與數學","examples":[{"en":"The road forms a loop around the lake.","zh":"這條路繞湖形成一個環形。"},{"en":"The roller coaster turns upside down in a giant loop.","zh":"雲霄飛車在一個巨大的環圈中翻轉。"},{"en":"The song kept playing in a loop all afternoon.","zh":"那首歌整個下午不斷地循環播放。"}]},{"word":"loophole","pos":"n.","phonetic":"[ˈlupˌhol]","meaning":"漏洞(法律或規則上的)","definition":"a way of avoiding a rule without actually breaking the law","collocations":["legal loophole","tax loophole","close a loophole"],"example":"The lawyer found a loophole in the contract.","exampleZh":"律師在合約中發現了一個漏洞。","synonyms":["gap"],"level":6,"theme":"政治與法律","examples":[{"en":"The lawyer found a loophole in the contract.","zh":"律師在合約中發現了一個漏洞。"},{"en":"The government closed the tax loophole last year.","zh":"政府去年堵住了那個稅務漏洞。"},{"en":"Clever companies sometimes exploit legal loopholes.","zh":"精明的公司有時會鑽法律漏洞。"}]},{"word":"loose","pos":"adj. / v.","phonetic":"[lus]","meaning":"鬆的；寬鬆的；鬆開","definition":"not firmly fixed in place; to set free","collocations":["loose clothes","come loose","set loose"],"example":"This shirt is too loose for me.","exampleZh":"這件襯衫對我來說太寬鬆了。","synonyms":["slack","baggy"],"level":3,"theme":"服裝與外表","examples":[{"en":"This shirt is too loose for me.","zh":"這件襯衫對我來說太寬鬆了。"},{"en":"In summer, I prefer wearing loose, cotton clothes.","zh":"夏天我比較喜歡穿寬鬆的棉質衣服。"},{"en":"One of the screws on the chair has come loose.","zh":"椅子上有一顆螺絲鬆掉了。"}]},{"word":"loosen","pos":"v.","phonetic":"[ˈlusn̩]","meaning":"鬆開；放鬆","definition":"to make or become less tight","collocations":["loosen a knot","loosen up","loosen your grip"],"example":"He loosened his tie after the meeting.","exampleZh":"開會後他鬆開了領帶。","synonyms":["relax","untie"],"level":4,"theme":"動作與行為","examples":[{"en":"He loosened his tie after the meeting.","zh":"開會後他鬆開了領帶。"},{"en":"He loosened his grip so the puppy could run free.","zh":"他鬆開了手，好讓小狗能自由奔跑。"},{"en":"Try to loosen up before your big performance.","zh":"在你的重要演出前試著放鬆一下。"}]},{"word":"loot","pos":"n. / v.","phonetic":"[lut]","meaning":"戰利品；掠奪物；掠奪","definition":"goods stolen or taken by force; to steal goods, typically during a war or riot","collocations":["loot a shop","stolen loot"],"example":"The soldiers carried away loot from the town.","exampleZh":"士兵們從城裡帶走了掠奪物。","synonyms":["plunder","steal"],"level":6,"theme":"政治與法律","examples":[{"en":"The soldiers carried away loot from the town.","zh":"士兵們從城裡帶走了掠奪物。"},{"en":"The thieves hid the stolen loot in an old barn.","zh":"竊賊把偷來的贓物藏在一座舊穀倉裡。"},{"en":"During the riot, some people tried to loot the shops.","zh":"暴動期間，有些人試圖搶劫商店。"}]},{"word":"lopsided","pos":"adj.","phonetic":"[ˈlɑpˌsaɪdɪd]","meaning":"不平衡的；歪斜的","definition":"with one side lower, larger, or heavier than the other","collocations":["lopsided smile","lopsided victory"],"example":"The old table had a lopsided leg.","exampleZh":"那張舊桌子有一隻腳是歪的。","synonyms":["uneven","unbalanced"],"level":6,"theme":"性質與描述","examples":[{"en":"The old table had a lopsided leg.","zh":"那張舊桌子有一隻腳是歪的。"},{"en":"He gave a lopsided smile when he heard the joke.","zh":"聽到那個笑話時，他露出歪斜的笑容。"},{"en":"Our team won a lopsided victory by twenty points.","zh":"我們隊以二十分的懸殊差距大勝。"}]},{"word":"lord","pos":"n.","phonetic":"[lɔrd]","meaning":"貴族；領主；上帝","definition":"a man of noble rank or high office","collocations":["lord and lady","feudal lord","my lord"],"example":"In the past, the lord owned all the land in the village.","exampleZh":"過去，這位領主擁有村裡所有的土地。","synonyms":["nobleman","master"],"level":5,"theme":"社會與文化","examples":[{"en":"In the past, the lord owned all the land in the village.","zh":"過去，這位領主擁有村裡所有的土地。"},{"en":"The feudal lord ruled over the entire valley.","zh":"那位封建領主統治著整個山谷。"},{"en":"Long ago, a lord and lady lived in this castle.","zh":"很久以前，一位領主和夫人住在這座城堡裡。"}]},{"word":"lose","pos":"v.","phonetic":"[luz]","meaning":"失去；輸掉；迷失","definition":"to fail to keep, win, or find something","collocations":["lose weight","lose a game","lose one's way"],"example":"Try not to lose your temper during the discussion.","exampleZh":"討論時盡量別發脾氣。","synonyms":["misplace","forfeit"],"level":1,"theme":"動作與行為","examples":[{"en":"Try not to lose your temper during the discussion.","zh":"討論時盡量別發脾氣。"},{"en":"He hopes to lose weight before the summer holiday.","zh":"他希望在暑假前減重。"},{"en":"We lost our way in the forest after sunset.","zh":"日落後我們在森林裡迷了路。"}]},{"word":"loss","pos":"n.","phonetic":"[lɔs]","meaning":"損失；喪失","definition":"the fact or process of losing something","collocations":["weight loss","suffer a loss","sense of loss"],"example":"The company reported a huge financial loss last year.","exampleZh":"這家公司去年通報了巨大的財務損失。","synonyms":["deficit"],"level":3,"theme":"商業與金錢","examples":[{"en":"The company reported a huge financial loss last year.","zh":"這家公司去年通報了巨大的財務損失。"},{"en":"After his dog died, he felt a deep sense of loss.","zh":"他的狗死後，他感到深深的失落。"},{"en":"Healthy eating led to a steady weight loss.","zh":"健康飲食帶來了穩定的體重減輕。"}]},{"word":"lost","pos":"adj.","phonetic":"[lɔst]","meaning":"迷路的；失去的","definition":"unable to find one's way; no longer possessed","collocations":["get lost","lost property","feel lost"],"example":"We got lost in the old town without a map.","exampleZh":"我們在舊城區沒有地圖，結果迷路了。","synonyms":["missing","confused"],"level":1,"theme":"交通與旅行","examples":[{"en":"We got lost in the old town without a map.","zh":"我們在舊城區沒有地圖，結果迷路了。"},{"en":"Please take your lost property to the front desk.","zh":"請把你的失物拿到服務台。"},{"en":"On the first day of school, I felt completely lost.","zh":"開學第一天，我感到完全不知所措。"}]},{"word":"lot","pos":"n.","phonetic":"[lɑt]","meaning":"大量；一群；地段","definition":"a large number or amount; a piece of land","collocations":["a lot of","parking lot","vacant lot"],"example":"There is a parking lot behind the mall.","exampleZh":"購物中心後面有一個停車場。","synonyms":["plenty","quantity"],"level":1,"theme":"居家與生活","examples":[{"en":"There is a parking lot behind the mall.","zh":"購物中心後面有一個停車場。"},{"en":"The children turned the vacant lot into a playground.","zh":"孩子們把那塊空地變成了遊樂場。"},{"en":"There are a lot of good reasons to study English.","zh":"學習英文有很多充分的理由。"}]},{"word":"loud","pos":"adj.","phonetic":"[laʊd]","meaning":"大聲的；吵鬧的","definition":"producing a lot of noise","collocations":["loud noise","loud music","out loud"],"example":"The music was too loud for the small room.","exampleZh":"這音樂對這個小房間來說太大聲了。","synonyms":["noisy"],"level":1,"theme":"性質與描述","examples":[{"en":"The music was too loud for the small room.","zh":"這音樂對這個小房間來說太大聲了。"},{"en":"The teacher asked her to read the poem out loud.","zh":"老師請她把那首詩大聲朗讀出來。"},{"en":"A loud noise from the street woke me up early.","zh":"街上一聲巨響把我一早吵醒。"}]},{"word":"lounge","pos":"n. / v.","phonetic":"[laʊndʒ]","meaning":"休息室；躺臥","definition":"a room for relaxing or waiting; to sit or lie comfortably","collocations":["airport lounge","lounge chair","lounge around"],"example":"Passengers were waiting in the departure lounge.","exampleZh":"乘客們在候機室等待。","synonyms":["relax","sitting room"],"level":4,"theme":"交通與旅行","examples":[{"en":"Passengers were waiting in the departure lounge.","zh":"乘客們在候機室等待。"},{"en":"We relaxed in comfortable lounge chairs by the pool.","zh":"我們在泳池邊舒適的躺椅上放鬆。"},{"en":"On rainy days, my brother just lounges around at home.","zh":"下雨天時，我弟弟就只是在家裡懶洋洋地閒晃。"}]},{"word":"lousy","pos":"adj.","phonetic":"[ˈlaʊzi]","meaning":"差勁的；糟糕的","definition":"very bad or unpleasant","collocations":["lousy weather","lousy job","feel lousy"],"example":"I had a lousy day at work.","exampleZh":"我今天工作很不順。","synonyms":["terrible","awful"],"level":5,"theme":"情緒與感受","examples":[{"en":"I had a lousy day at work.","zh":"我今天工作很不順。"},{"en":"The lousy weather ruined our weekend picnic plans.","zh":"糟糕的天氣毀了我們週末的野餐計畫。"},{"en":"I feel lousy today because I caught a cold.","zh":"我今天很不舒服，因為感冒了。"}]},{"word":"lovable","pos":"adj.","phonetic":"[ˈlʌvəbl̩]","meaning":"可愛的；討人喜歡的","definition":"easy to love","collocations":["lovable character","lovable puppy"],"example":"The movie's main character is very lovable.","exampleZh":"這部電影的主角非常討人喜歡。","synonyms":["adorable","charming"],"level":4,"theme":"性質與描述","examples":[{"en":"The movie's main character is very lovable.","zh":"這部電影的主角非常討人喜歡。"},{"en":"Their lovable puppy greets everyone at the door.","zh":"他們那隻討人喜歡的小狗會在門口迎接每個人。"},{"en":"The cartoon's lovable hero made all the children laugh.","zh":"那部卡通裡討喜的主角逗得所有孩子哈哈大笑。"}]},{"word":"love","pos":"n. / v.","phonetic":"[lʌv]","meaning":"愛；喜愛","definition":"a deep feeling of affection","collocations":["fall in love","love at first sight","love story"],"example":"They fell in love during their trip to Paris.","exampleZh":"他們在巴黎旅行時墜入愛河。","synonyms":["adore","affection"],"level":1,"theme":"情緒與感受","examples":[{"en":"They fell in love during their trip to Paris.","zh":"他們在巴黎旅行時墜入愛河。"},{"en":"The movie tells a touching love story between two students.","zh":"這部電影述說兩名學生之間動人的愛情故事。"},{"en":"Many people believe in love at first sight.","zh":"許多人相信一見鍾情。"}]},{"word":"lovely","pos":"adj.","phonetic":"[ˈlʌvli]","meaning":"可愛的；令人愉快的","definition":"beautiful or delightful","collocations":["lovely weather","lovely view","lovely person"],"example":"We had a lovely time at the beach.","exampleZh":"我們在海灘上度過了一段美好的時光。","synonyms":["charming","delightful"],"level":1,"theme":"性質與描述","examples":[{"en":"We had a lovely time at the beach.","zh":"我們在海灘上度過了一段美好的時光。"},{"en":"What lovely weather we are having this spring!","zh":"今年春天的天氣真是宜人！"},{"en":"From the hilltop, we enjoyed a lovely view of the city.","zh":"從山頂上，我們欣賞了城市的美麗景色。"}]},{"word":"low","pos":"adj. / adv.","phonetic":"[lo]","meaning":"低的；矮的","definition":"not high or tall; below the usual level","collocations":["low price","low voice","low temperature"],"example":"Prices are lower during the off-season.","exampleZh":"淡季時價格較低。","synonyms":["reduced"],"level":1,"theme":"性質與描述","examples":[{"en":"Prices are lower during the off-season.","zh":"淡季時價格較低。"},{"en":"She spoke in a low voice so no one could hear.","zh":"她用低沉的聲音說話，以免有人聽見。"},{"en":"The store sells fresh fruit at surprisingly low prices.","zh":"這家店以出奇低廉的價格販售新鮮水果。"}]},{"word":"lower","pos":"v. / adj.","phonetic":"[ˈloɚ]","meaning":"降低；放低","definition":"to move something down; less high","collocations":["lower prices","lower your voice","lower the flag"],"example":"The government decided to lower the tax rate.","exampleZh":"政府決定調降稅率。","synonyms":["reduce","decrease"],"level":2,"theme":"商業與金錢","examples":[{"en":"The government decided to lower the tax rate.","zh":"政府決定調降稅率。"},{"en":"Please lower your voice; the baby is sleeping.","zh":"請小聲一點，寶寶正在睡覺。"},{"en":"The shop lowered its prices during the summer sale.","zh":"這家店在夏季特賣期間降低了價格。"}]},{"word":"lowland","pos":"n.","phonetic":"[ˈloˌlænd]","meaning":"低地；平原","definition":"an area of low-lying land","collocations":["lowland area","lowland farming"],"example":"Rice grows well in the lowland regions.","exampleZh":"稻米在低地地區生長良好。","synonyms":["plain"],"level":5,"theme":"自然與環境","examples":[{"en":"Rice grows well in the lowland regions.","zh":"稻米在低地地區生長良好。"},{"en":"Heavy rain often floods the lowland areas near the river.","zh":"大雨常淹沒河邊的低窪地區。"},{"en":"Lowland farming provides much of the country's rice.","zh":"低地農耕供應了這個國家大部分的稻米。"}]},{"word":"lowly","pos":"adj.","phonetic":"[ˈloli]","meaning":"卑微的；低下的","definition":"low in status or importance","collocations":["lowly position","lowly beginnings"],"example":"He rose from a lowly clerk to company president.","exampleZh":"他從一名卑微的職員晉升為公司總裁。","synonyms":["humble","modest"],"level":6,"theme":"工作與職業","examples":[{"en":"He rose from a lowly clerk to company president.","zh":"他從一名卑微的職員晉升為公司總裁。"},{"en":"Despite his lowly beginnings, he became a famous doctor.","zh":"儘管出身卑微，他仍成為了一位著名的醫生。"},{"en":"She started in a lowly position but worked her way up.","zh":"她從卑微的職位起步，卻一步步往上爬。"}]},{"word":"loyal","pos":"adj.","phonetic":"[ˈlɔɪəl]","meaning":"忠誠的；忠實的","definition":"giving firm and constant support to someone or something","collocations":["loyal customer","loyal friend","stay loyal"],"example":"He has always been loyal to his friends.","exampleZh":"他一直對朋友非常忠誠。","synonyms":["faithful","devoted"],"level":3,"theme":"人物與家庭","examples":[{"en":"He has always been loyal to his friends.","zh":"他一直對朋友非常忠誠。"},{"en":"A loyal friend will support you in hard times.","zh":"忠實的朋友會在困難時支持你。"},{"en":"The shop offers discounts to its most loyal customers.","zh":"這家店為最忠實的顧客提供折扣。"}]},{"word":"loyalty","pos":"n.","phonetic":"[ˈlɔɪəlti]","meaning":"忠誠；忠心","definition":"the quality of being loyal","collocations":["brand loyalty","show loyalty","loyalty program"],"example":"The company rewards customer loyalty with discounts.","exampleZh":"這家公司以折扣回饋顧客的忠誠度。","synonyms":["faithfulness","devotion"],"level":4,"theme":"商業與金錢","examples":[{"en":"The company rewards customer loyalty with discounts.","zh":"這家公司以折扣回饋顧客的忠誠度。"},{"en":"The airline's loyalty program gives members free flights.","zh":"這家航空公司的忠誠計畫提供會員免費航班。"},{"en":"The dog showed great loyalty by waiting at the door.","zh":"那隻狗在門口守候，展現了極大的忠誠。"}]},{"word":"luck","pos":"n.","phonetic":"[lʌk]","meaning":"運氣；幸運","definition":"success or failure caused by chance","collocations":["good luck","bad luck","by luck"],"example":"Good luck on your final exam tomorrow!","exampleZh":"祝你明天期末考好運！","synonyms":["fortune","chance"],"level":1,"theme":"抽象概念","examples":[{"en":"Good luck on your final exam tomorrow!","zh":"祝你明天期末考好運！"},{"en":"By sheer luck, I found my lost wallet on the bus.","zh":"純粹靠運氣，我在公車上找到了遺失的錢包。"},{"en":"We wished the athletes good luck before the race.","zh":"比賽前我們祝運動員們好運。"}]},{"word":"lucky","pos":"adj.","phonetic":"[ˈlʌki]","meaning":"幸運的","definition":"having good luck","collocations":["lucky number","feel lucky","lucky day"],"example":"I felt lucky to find a parking spot so quickly.","exampleZh":"我很幸運能這麼快找到停車位。","synonyms":["fortunate"],"level":1,"theme":"抽象概念","examples":[{"en":"I felt lucky to find a parking spot so quickly.","zh":"我很幸運能這麼快找到停車位。"},{"en":"Seven is considered a lucky number in many countries.","zh":"在許多國家，七被視為幸運數字。"},{"en":"I feel lucky to have such supportive parents.","zh":"能有這麼支持我的父母，我覺得很幸運。"}]},{"word":"luggage","pos":"n.","phonetic":"[ˈlʌgɪdʒ]","meaning":"行李","definition":"bags and suitcases used for traveling","collocations":["carry luggage","luggage claim","pack luggage"],"example":"Please make sure your luggage is properly labeled.","exampleZh":"請確認你的行李有貼好標籤。","synonyms":["baggage"],"level":2,"theme":"交通與旅行","examples":[{"en":"Please make sure your luggage is properly labeled.","zh":"請確認你的行李有貼好標籤。"},{"en":"We waited at the luggage claim for our suitcases.","zh":"我們在行李提領處等候我們的行李箱。"},{"en":"She packed her luggage the night before the flight.","zh":"她在航班前一晚打包好了行李。"}]},{"word":"lullaby","pos":"n.","phonetic":"[ˈlʌləˌbaɪ]","meaning":"搖籃曲","definition":"a quiet, gentle song sung to send a child to sleep","collocations":["sing a lullaby","gentle lullaby"],"example":"The mother sang a lullaby to her sleepy baby.","exampleZh":"媽媽對著想睡的寶寶唱搖籃曲。","synonyms":[],"level":4,"theme":"藝術與音樂","examples":[{"en":"The mother sang a lullaby to her sleepy baby.","zh":"媽媽對著想睡的寶寶唱搖籃曲。"},{"en":"A gentle lullaby slowly put the baby to sleep.","zh":"一首輕柔的搖籃曲慢慢哄睡了寶寶。"},{"en":"Grandmother sang an old lullaby by the crib.","zh":"奶奶在嬰兒床邊唱著一首古老的搖籃曲。"}]},{"word":"lumber","pos":"n. / v.","phonetic":"[ˈlʌmbɚ]","meaning":"木材；笨重地移動","definition":"wood prepared for building; to move in a slow, heavy way","collocations":["lumber industry","lumber mill","lumber along"],"example":"The truck was loaded with lumber for the new house.","exampleZh":"卡車載滿了要蓋新房子的木材。","synonyms":["timber"],"level":5,"theme":"自然與環境","examples":[{"en":"The truck was loaded with lumber for the new house.","zh":"卡車載滿了要蓋新房子的木材。"},{"en":"The heavy bear lumbered slowly across the road.","zh":"那頭笨重的熊緩慢地橫越馬路。"},{"en":"Workers cut trees into lumber at the busy mill.","zh":"工人們在繁忙的鋸木廠把樹木切成木材。"}]},{"word":"luminous","pos":"adj.","phonetic":"[ˈlumənəs]","meaning":"發光的；明亮的","definition":"giving off light, especially in the dark; bright","collocations":["luminous stars","luminous paint"],"example":"The clock has luminous hands that glow in the dark.","exampleZh":"這個時鐘有在黑暗中發光的指針。","synonyms":["bright","glowing"],"level":6,"theme":"自然與環境","examples":[{"en":"The clock has luminous hands that glow in the dark.","zh":"這個時鐘有在黑暗中發光的指針。"},{"en":"The luminous stars on the ceiling glow after dark.","zh":"天花板上的發光星星在天黑後會發亮。"},{"en":"They painted the sign with luminous paint for safety.","zh":"為了安全，他們用發光塗料漆了那個標誌。"}]},{"word":"lump","pos":"n.","phonetic":"[lʌmp]","meaning":"塊；腫塊","definition":"a compact, solid mass of a substance","collocations":["a lump of sugar","feel a lump","lump sum"],"example":"She found a small lump under her skin.","exampleZh":"她在皮膚下發現了一個小腫塊。","synonyms":["mass","chunk"],"level":4,"theme":"身體與健康","examples":[{"en":"She found a small lump under her skin.","zh":"她在皮膚下發現了一個小腫塊。"},{"en":"He dropped a lump of sugar into his hot tea.","zh":"他把一塊方糖放進熱茶裡。"},{"en":"The winner received the prize money as a lump sum.","zh":"得獎者以一次付清的方式領取了獎金。"}]},{"word":"lunar","pos":"adj.","phonetic":"[ˈlunɚ]","meaning":"月亮的；陰曆的","definition":"relating to the moon","collocations":["lunar calendar","lunar eclipse","lunar new year"],"example":"Many Asian countries celebrate the Lunar New Year.","exampleZh":"許多亞洲國家慶祝農曆新年。","synonyms":[],"level":4,"theme":"天氣與季節","examples":[{"en":"Many Asian countries celebrate the Lunar New Year.","zh":"許多亞洲國家慶祝農曆新年。"},{"en":"Families gather for a big meal during Lunar New Year.","zh":"農曆新年期間，家人們團聚享用豐盛的一餐。"},{"en":"We watched a beautiful lunar eclipse last night.","zh":"昨晚我們觀看了一場美麗的月食。"}]},{"word":"lunch","pos":"n.","phonetic":"[lʌntʃ]","meaning":"午餐","definition":"a meal eaten in the middle of the day","collocations":["have lunch","pack a lunch","lunch break"],"example":"We usually have lunch together at noon.","exampleZh":"我們通常中午一起吃午餐。","synonyms":[],"level":1,"theme":"食物與烹飪","examples":[{"en":"We usually have lunch together at noon.","zh":"我們通常中午一起吃午餐。"},{"en":"My mother packs a healthy lunch for me every day.","zh":"我媽媽每天為我準備健康的午餐便當。"},{"en":"During the lunch break, we played basketball outside.","zh":"午休時間，我們在外面打籃球。"}]},{"word":"lung","pos":"n.","phonetic":"[lʌŋ]","meaning":"肺","definition":"either of the two organs in the chest used for breathing","collocations":["lung cancer","lung capacity","healthy lungs"],"example":"Smoking can seriously damage your lungs.","exampleZh":"抽菸會嚴重傷害你的肺。","synonyms":[],"level":3,"theme":"身體與健康","examples":[{"en":"Smoking can seriously damage your lungs.","zh":"抽菸會嚴重傷害你的肺。"},{"en":"Swimming can greatly improve your lung capacity.","zh":"游泳能大幅增進你的肺活量。"},{"en":"Fresh mountain air is good for your lungs.","zh":"清新的山間空氣對你的肺很好。"}]},{"word":"lunge","pos":"v. / n.","phonetic":"[lʌndʒ]","meaning":"猛衝；刺","definition":"to move forward suddenly and forcefully","collocations":["lunge forward","lunge at someone"],"example":"The dog lunged at the mail carrier.","exampleZh":"那隻狗突然朝郵差撲過去。","synonyms":["dash","plunge"],"level":5,"theme":"動作與行為","examples":[{"en":"The dog lunged at the mail carrier.","zh":"那隻狗突然朝郵差撲過去。"},{"en":"The goalkeeper lunged forward to catch the ball.","zh":"守門員向前猛撲去接球。"},{"en":"The cat suddenly lunged at the tiny mouse.","zh":"那隻貓突然向那隻小老鼠猛撲過去。"}]},{"word":"lurch","pos":"v. / n.","phonetic":"[lɝtʃ]","meaning":"蹣跚而行；突然傾斜","definition":"to move suddenly in an unsteady or uncontrolled way","collocations":["lurch forward","drunken lurch"],"example":"The bus lurched forward as it started moving.","exampleZh":"巴士開動時猛然一晃。","synonyms":["stagger","stumble"],"level":6,"theme":"動作與行為","examples":[{"en":"The bus lurched forward as it started moving.","zh":"巴士開動時猛然一晃。"},{"en":"The old boat lurched violently in the rough waves.","zh":"那艘舊船在洶湧的波浪中劇烈地搖晃。"},{"en":"He lurched forward when the train stopped suddenly.","zh":"火車突然停下時，他身體猛地向前一晃。"}]},{"word":"luscious","pos":"adj.","phonetic":"[ˈlʌʃəs]","meaning":"甜美多汁的；誘人的","definition":"having a rich, sweet, and delicious taste","collocations":["luscious fruit","luscious dessert"],"example":"She served a bowl of luscious strawberries for dessert.","exampleZh":"她端上一碗甜美多汁的草莓當甜點。","synonyms":["delicious","juicy"],"level":5,"theme":"食物與烹飪","examples":[{"en":"She served a bowl of luscious strawberries for dessert.","zh":"她端上一碗甜美多汁的草莓當甜點。"},{"en":"The market sells luscious peaches in the summer.","zh":"這個市場在夏天販售甜美多汁的桃子。"},{"en":"For dessert, she prepared a luscious chocolate cake.","zh":"她為甜點準備了一個誘人的巧克力蛋糕。"}]},{"word":"machine","pos":"n.","phonetic":"[məˈʃin]","meaning":"機器；機械","definition":"a piece of equipment with moving parts used to do a particular kind of work","collocations":["washing machine","machine gun","operate a machine"],"example":"The factory bought a new machine to speed up production.","exampleZh":"工廠購買了一台新機器以加快生產速度。","synonyms":["device","apparatus"],"level":2,"theme":"科技與媒體","examples":[{"en":"The factory bought a new machine to speed up production.","zh":"工廠購買了一台新機器以加快生產速度。"},{"en":"Our washing machine broke down again this morning.","zh":"今天早上我們的洗衣機又故障了。"},{"en":"Workers must be trained before they operate the machine.","zh":"工人在操作機器前必須接受訓練。"}]},{"word":"magazine","pos":"n.","phonetic":"[ˌmægəˈzin]","meaning":"雜誌","definition":"a thin publication with articles and photographs published regularly","collocations":["fashion magazine","read a magazine","subscribe to a magazine"],"example":"She reads a fashion magazine every month.","exampleZh":"她每個月都會看一本時尚雜誌。","synonyms":["journal","periodical"],"level":2,"theme":"科技與媒體","examples":[{"en":"She reads a fashion magazine every month.","zh":"她每個月都會看一本時尚雜誌。"},{"en":"My father subscribes to a monthly science magazine.","zh":"我爸爸訂閱了一本月刊科學雜誌。"},{"en":"I flipped through a travel magazine while waiting.","zh":"等候時我隨手翻閱了一本旅遊雜誌。"}]},{"word":"magic","pos":"n. / adj.","phonetic":"[ˈmædʒɪk]","meaning":"魔法；魔術的","definition":"the power of appearing to make impossible things happen","collocations":["magic trick","like magic","magic word"],"example":"The magician performed an amazing magic trick.","exampleZh":"魔術師表演了一個驚人的魔術。","synonyms":["sorcery"],"level":2,"theme":"藝術與音樂","examples":[{"en":"The magician performed an amazing magic trick.","zh":"魔術師表演了一個驚人的魔術。"},{"en":"The stain disappeared as if by magic.","zh":"那個污漬彷彿變魔術般消失了。"},{"en":"For children, please is often called the magic word.","zh":"對孩子來說，「請」常被稱為神奇的字眼。"}]},{"word":"magician","pos":"n.","phonetic":"[məˈdʒɪʃən]","meaning":"魔術師；魔法師","definition":"a person who performs magic tricks to entertain people","collocations":["skilled magician","hire a magician","famous magician"],"example":"The magician pulled a rabbit out of his hat.","exampleZh":"魔術師從帽子裡變出一隻兔子。","synonyms":["illusionist"],"level":3,"theme":"藝術與音樂","examples":[{"en":"The magician pulled a rabbit out of his hat.","zh":"魔術師從帽子裡變出一隻兔子。"},{"en":"They hired a magician to entertain the birthday guests.","zh":"他們請了一位魔術師來娛樂生日派對的賓客。"},{"en":"The skilled magician made a coin vanish instantly.","zh":"那位技藝高超的魔術師讓一枚硬幣瞬間消失。"}]},{"word":"magnet","pos":"n.","phonetic":"[ˈmægnɪt]","meaning":"磁鐵","definition":"a piece of metal that can attract iron and steel toward it","collocations":["refrigerator magnet","powerful magnet","act like a magnet"],"example":"The magnet on the fridge held up the note.","exampleZh":"冰箱上的磁鐵夾住了那張紙條。","synonyms":[],"level":3,"theme":"科學與數學","examples":[{"en":"The magnet on the fridge held up the note.","zh":"冰箱上的磁鐵夾住了那張紙條。"},{"en":"She brought home a colorful magnet from her trip.","zh":"她從旅行中帶回一個色彩繽紛的磁鐵。"},{"en":"A powerful magnet can lift small metal objects.","zh":"強力磁鐵能吸起小型金屬物品。"}]},{"word":"magnificent","pos":"adj.","phonetic":"[mægˈnɪfəsənt]","meaning":"壯麗的；宏偉的","definition":"extremely good, beautiful, or impressive","collocations":["magnificent view","magnificent building","magnificent performance"],"example":"The magnificent view from the mountain took our breath away.","exampleZh":"從山上望去的壯麗景色令我們屏息。","synonyms":["splendid","grand"],"level":5,"theme":"性質與描述","examples":[{"en":"The magnificent view from the mountain took our breath away.","zh":"從山上望去的壯麗景色令我們屏息。"},{"en":"The palace is a truly magnificent building.","zh":"這座宮殿是一棟真正宏偉的建築。"},{"en":"The orchestra gave a magnificent performance last night.","zh":"昨晚管弦樂團帶來了一場壯麗的演出。"}]},{"word":"mail","pos":"n. / v.","phonetic":"[mel]","meaning":"郵件；郵寄","definition":"letters and packages sent by post, or to send them","collocations":["send mail","mail a letter","junk mail"],"example":"Please mail this package to my sister.","exampleZh":"請把這個包裹寄給我姊姊。","synonyms":["post"],"level":1,"theme":"溝通與語言","examples":[{"en":"Please mail this package to my sister.","zh":"請把這個包裹寄給我姊姊。"},{"en":"I threw away all the junk mail without reading it.","zh":"我沒看就把所有的垃圾郵件都丟了。"},{"en":"She went to the post office to mail a letter.","zh":"她去郵局寄一封信。"}]},{"word":"main","pos":"adj.","phonetic":"[men]","meaning":"主要的","definition":"most important; principal","collocations":["main reason","main course","main road"],"example":"The main reason for his success is hard work.","exampleZh":"他成功的主要原因是努力工作。","synonyms":["primary","principal"],"level":2,"theme":"性質與描述","examples":[{"en":"The main reason for his success is hard work.","zh":"他成功的主要原因是努力工作。"},{"en":"The main road into town was closed for repairs.","zh":"通往鎮上的主要道路因維修而封閉。"},{"en":"For the main course, we ordered grilled fish.","zh":"主菜我們點了烤魚。"}]},{"word":"mainland","pos":"n.","phonetic":"[ˈmenˌlænd]","meaning":"大陸；本土","definition":"a large area of land that forms the main part of a country","collocations":["mainland China","return to the mainland","mainland Europe"],"example":"Many people flew from the island to the mainland.","exampleZh":"許多人從島上搭飛機到大陸。","synonyms":[],"level":4,"theme":"自然與環境","examples":[{"en":"Many people flew from the island to the mainland.","zh":"許多人從島上搭飛機到大陸。"},{"en":"A ferry carries passengers from the island to the mainland.","zh":"一艘渡輪載運乘客從島上前往本島。"},{"en":"The bridge finally connected the island to the mainland.","zh":"這座橋終於把島嶼和本土連接了起來。"}]},{"word":"maintain","pos":"v.","phonetic":"[menˈten]","meaning":"維持；維修","definition":"to make something continue at the same level, or to keep something in good condition","collocations":["maintain a relationship","maintain order","maintain equipment"],"example":"It is important to maintain a healthy diet.","exampleZh":"維持健康的飲食很重要。","synonyms":["sustain","preserve"],"level":4,"theme":"動作與行為","examples":[{"en":"It is important to maintain a healthy diet.","zh":"維持健康的飲食很重要。"},{"en":"Teachers work hard to maintain order in the classroom.","zh":"老師努力維持教室裡的秩序。"},{"en":"It takes effort to maintain a long friendship.","zh":"維持一段長久的友誼是需要用心的。"}]},{"word":"maintenance","pos":"n.","phonetic":"[ˈmentənəns]","meaning":"維護；保養","definition":"the process of keeping something in good condition","collocations":["regular maintenance","car maintenance","maintenance cost"],"example":"The car needs regular maintenance to run smoothly.","exampleZh":"這輛車需要定期保養才能順暢運作。","synonyms":["upkeep"],"level":5,"theme":"工作與職業","examples":[{"en":"The car needs regular maintenance to run smoothly.","zh":"這輛車需要定期保養才能順暢運作。"},{"en":"Regular maintenance keeps the elevator running safely.","zh":"定期保養能讓電梯安全運轉。"},{"en":"The maintenance cost of an old house can be high.","zh":"老房子的維護費用可能很高。"}]},{"word":"major","pos":"adj. / v. / n.","phonetic":"[ˈmedʒɚ]","meaning":"主要的；主修","definition":"greater in importance, size, or amount; to study as a main subject","collocations":["major problem","major in","major role"],"example":"She decided to major in economics.","exampleZh":"她決定主修經濟學。","synonyms":["primary","main"],"level":3,"theme":"教育與學習","examples":[{"en":"She decided to major in economics.","zh":"她決定主修經濟學。"},{"en":"Traffic is a major problem in most big cities.","zh":"交通是大多數大城市的主要問題。"},{"en":"She plans to major in biology at university.","zh":"她計畫在大學主修生物學。"}]},{"word":"majority","pos":"n.","phonetic":"[məˈdʒɔrətɪ]","meaning":"大多數","definition":"the larger part of a group of people or things","collocations":["vast majority","majority vote","majority of people"],"example":"The majority of students passed the exam.","exampleZh":"大多數學生都通過了考試。","synonyms":["most"],"level":4,"theme":"抽象概念","examples":[{"en":"The majority of students passed the exam.","zh":"大多數學生都通過了考試。"},{"en":"The vast majority of students enjoy the new lunch menu.","zh":"絕大多數的學生喜歡新的午餐菜單。"},{"en":"The plan was approved by a majority vote.","zh":"這項計畫以多數表決通過。"}]},{"word":"make","pos":"v.","phonetic":"[mek]","meaning":"製造；使得","definition":"to produce or create something","collocations":["make a decision","make a mistake","make money"],"example":"She made a delicious cake for the party.","exampleZh":"她為派對做了一個美味的蛋糕。","synonyms":["create","produce"],"level":1,"theme":"動作與行為","examples":[{"en":"She made a delicious cake for the party.","zh":"她為派對做了一個美味的蛋糕。"},{"en":"Everyone makes a mistake from time to time.","zh":"每個人都難免會犯錯。"},{"en":"It is not easy to make a difficult decision quickly.","zh":"要迅速做出艱難的決定並不容易。"}]},{"word":"makeup","pos":"n.","phonetic":"[ˈmekˌʌp]","meaning":"化妝品","definition":"substances used to color and beautify the face","collocations":["wear makeup","put on makeup","makeup artist"],"example":"She never leaves the house without makeup.","exampleZh":"她出門前一定會化妝。","synonyms":["cosmetics"],"level":3,"theme":"服裝與外表","examples":[{"en":"She never leaves the house without makeup.","zh":"她出門前一定會化妝。"},{"en":"The makeup artist prepared the actors before the show.","zh":"化妝師在演出前為演員們化妝打扮。"},{"en":"She put on light makeup for the school photo.","zh":"她為了拍學校照片化了淡妝。"}]},{"word":"male","pos":"adj. / n.","phonetic":"[mel]","meaning":"男性的；雄性的","definition":"of the sex that cannot give birth to young","collocations":["male student","male nurse","male animal"],"example":"The male lion has a large mane.","exampleZh":"雄獅有一頭濃密的鬃毛。","synonyms":[],"level":2,"theme":"人物與家庭","examples":[{"en":"The male lion has a large mane.","zh":"雄獅有一頭濃密的鬃毛。"},{"en":"The hospital hired several kind and patient male nurses.","zh":"這家醫院聘用了幾位親切又有耐心的男護理師。"},{"en":"In many species, the male animal is more colorful.","zh":"在許多物種中，雄性動物的顏色較鮮豔。"}]},{"word":"mall","pos":"n.","phonetic":"[mɔl]","meaning":"購物中心","definition":"a large building or group of buildings containing many stores","collocations":["shopping mall","go to the mall","mall parking lot"],"example":"We spent the afternoon shopping at the mall.","exampleZh":"我們整個下午都在購物中心逛街。","synonyms":[],"level":2,"theme":"居家與生活","examples":[{"en":"We spent the afternoon shopping at the mall.","zh":"我們整個下午都在購物中心逛街。"},{"en":"The new shopping mall has a huge food court.","zh":"這間新的購物中心有一個超大的美食廣場。"},{"en":"We could not find a spot in the mall parking lot.","zh":"我們在購物中心的停車場找不到車位。"}]},{"word":"mammal","pos":"n.","phonetic":"[ˈmæməl]","meaning":"哺乳動物","definition":"a warm-blooded animal that feeds milk to its young","collocations":["marine mammal","mammal species","study mammals"],"example":"Whales are the largest mammals on Earth.","exampleZh":"鯨魚是地球上最大的哺乳動物。","synonyms":[],"level":3,"theme":"動物與植物","examples":[{"en":"Whales are the largest mammals on Earth.","zh":"鯨魚是地球上最大的哺乳動物。"},{"en":"Dolphins are intelligent marine mammals.","zh":"海豚是聰明的海洋哺乳動物。"},{"en":"Scientists study mammals to understand how they survive.","zh":"科學家研究哺乳動物以了解牠們如何生存。"}]},{"word":"man","pos":"n.","phonetic":"[mæn]","meaning":"男人；人類","definition":"an adult male human being","collocations":["young man","old man","man and woman"],"example":"The old man walked slowly down the street.","exampleZh":"那位老人沿著街道緩緩走著。","synonyms":[],"level":1,"theme":"人物與家庭","examples":[{"en":"The old man walked slowly down the street.","zh":"那位老人沿著街道緩緩走著。"},{"en":"A young man kindly helped the old lady cross the road.","zh":"一位年輕男子好心地扶老太太過馬路。"},{"en":"Both men and women can succeed in any career.","zh":"男人和女人在任何職業上都能成功。"}]},{"word":"manage","pos":"v.","phonetic":"[ˈmænɪdʒ]","meaning":"管理；設法做到","definition":"to be in charge of something, or to succeed in doing something difficult","collocations":["manage a company","manage time","manage to survive"],"example":"She manages a small restaurant downtown.","exampleZh":"她在市中心經營一家小餐廳。","synonyms":["handle","run"],"level":3,"theme":"工作與職業","examples":[{"en":"She manages a small restaurant downtown.","zh":"她在市中心經營一家小餐廳。"},{"en":"Somehow he managed to finish the project on time.","zh":"他總算設法準時完成了這項專案。"},{"en":"Learning to manage your time well is a useful skill.","zh":"學會妥善管理時間是一項實用的技能。"}]},{"word":"management","pos":"n.","phonetic":"[ˈmænɪdʒmənt]","meaning":"管理","definition":"the control and organization of something","collocations":["time management","management team","business management"],"example":"Good time management can reduce stress.","exampleZh":"良好的時間管理可以減輕壓力。","synonyms":["administration"],"level":4,"theme":"商業與金錢","examples":[{"en":"Good time management can reduce stress.","zh":"良好的時間管理可以減輕壓力。"},{"en":"Good time management helps students avoid stress.","zh":"良好的時間管理能幫助學生避免壓力。"},{"en":"The management team announced a new company plan.","zh":"管理團隊宣布了一項新的公司計畫。"}]},{"word":"manager","pos":"n.","phonetic":"[ˈmænɪdʒɚ]","meaning":"經理","definition":"a person responsible for controlling a business or department","collocations":["sales manager","hire a manager","manager's office"],"example":"The manager approved my vacation request.","exampleZh":"經理批准了我的休假申請。","synonyms":["supervisor"],"level":2,"theme":"工作與職業","examples":[{"en":"The manager approved my vacation request.","zh":"經理批准了我的休假申請。"},{"en":"The sales manager praised her team's hard work.","zh":"業務經理稱讚了她團隊的努力。"},{"en":"Please report the problem to the manager's office.","zh":"請把這個問題向經理辦公室反映。"}]},{"word":"mankind","pos":"n.","phonetic":"[mænˈkaɪnd]","meaning":"人類","definition":"human beings considered collectively","collocations":["benefit mankind","history of mankind","for the good of mankind"],"example":"Scientists hope this discovery will benefit mankind.","exampleZh":"科學家希望這項發現能造福人類。","synonyms":["humanity"],"level":4,"theme":"抽象概念","examples":[{"en":"Scientists hope this discovery will benefit mankind.","zh":"科學家希望這項發現能造福人類。"},{"en":"Clean energy could greatly benefit all of mankind.","zh":"乾淨能源可能對全人類大有益處。"},{"en":"The invention of writing changed the history of mankind.","zh":"文字的發明改變了人類的歷史。"}]},{"word":"manner","pos":"n.","phonetic":"[ˈmænɚ]","meaning":"方式；態度","definition":"the way in which something is done or happens","collocations":["in a gentle manner","good manners","table manners"],"example":"He spoke to the children in a gentle manner.","exampleZh":"他用溫和的方式對孩子們說話。","synonyms":["way","style"],"level":3,"theme":"溝通與語言","examples":[{"en":"He spoke to the children in a gentle manner.","zh":"他用溫和的方式對孩子們說話。"},{"en":"Children should learn good table manners at home.","zh":"孩子們應該在家學習良好的餐桌禮儀。"},{"en":"The nurse spoke to the patient in a kind manner.","zh":"護理師以親切的態度對病人說話。"}]},{"word":"mansion","pos":"n.","phonetic":"[ˈmænʃən]","meaning":"宅邸；豪宅","definition":"a large, impressive house","collocations":["luxury mansion","live in a mansion","old mansion"],"example":"The rock star bought a huge mansion by the sea.","exampleZh":"那位搖滾明星在海邊買了一座豪宅。","synonyms":["manor"],"level":4,"theme":"居家與生活","examples":[{"en":"The rock star bought a huge mansion by the sea.","zh":"那位搖滾明星在海邊買了一座豪宅。"},{"en":"A mysterious family lived in the old mansion on the hill.","zh":"一個神祕的家族住在山丘上那棟古老的宅邸裡。"},{"en":"The actor bought a luxury mansion with a swimming pool.","zh":"那位演員買下了一棟附游泳池的豪華宅邸。"}]},{"word":"manual","pos":"adj. / n.","phonetic":"[ˈmænjuəl]","meaning":"手動的；手冊","definition":"done with the hands; a book of instructions","collocations":["manual labor","instruction manual","manual transmission"],"example":"Please read the manual before using the machine.","exampleZh":"使用機器前請先閱讀說明書。","synonyms":["handbook"],"level":4,"theme":"科技與媒體","examples":[{"en":"Please read the manual before using the machine.","zh":"使用機器前請先閱讀說明書。"},{"en":"Read the instruction manual carefully before assembling the desk.","zh":"組裝書桌前請仔細閱讀說明書。"},{"en":"Building the stone wall required a lot of manual labor.","zh":"砌這道石牆需要大量的體力勞動。"}]},{"word":"manufacture","pos":"v. / n.","phonetic":"[ˌmænjəˈfæktʃɚ]","meaning":"製造","definition":"to make goods in large quantities using machinery","collocations":["manufacture cars","manufacturing process","locally manufactured"],"example":"The company manufactures electronic devices.","exampleZh":"這家公司製造電子產品。","synonyms":["produce"],"level":5,"theme":"工作與職業","examples":[{"en":"The company manufactures electronic devices.","zh":"這家公司製造電子產品。"},{"en":"This factory manufactures thousands of bicycles each month.","zh":"這家工廠每個月製造數千輛腳踏車。"},{"en":"Many shoppers prefer locally manufactured products.","zh":"許多消費者偏好本地製造的產品。"}]},{"word":"many","pos":"adj. / pron.","phonetic":"[ˈmɛnɪ]","meaning":"許多的","definition":"a large number of people or things","collocations":["many people","how many","so many"],"example":"Many students joined the club this year.","exampleZh":"今年有許多學生加入了這個社團。","synonyms":["numerous"],"level":1,"theme":"抽象概念","examples":[{"en":"Many students joined the club this year.","zh":"今年有許多學生加入了這個社團。"},{"en":"How many students signed up for the science fair?","zh":"有多少學生報名了科學展覽？"},{"en":"So many people came that the hall was completely full.","zh":"來了這麼多人，把大廳擠得滿滿的。"}]},{"word":"map","pos":"n.","phonetic":"[mæp]","meaning":"地圖","definition":"a drawing that shows the features of an area of land","collocations":["read a map","road map","map out a plan"],"example":"Use the map to find the fastest route.","exampleZh":"使用地圖找出最快的路線。","synonyms":["chart"],"level":1,"theme":"交通與旅行","examples":[{"en":"Use the map to find the fastest route.","zh":"使用地圖找出最快的路線。"},{"en":"Before the trip, we mapped out a detailed plan.","zh":"旅行前，我們仔細規劃了一份詳盡的計畫。"},{"en":"Learning to read a map is a useful skill for hikers.","zh":"學會看地圖對登山者來說是項實用的技能。"}]},{"word":"maple","pos":"n.","phonetic":"[ˈmepəl]","meaning":"楓樹","definition":"a tree with broad leaves that turn red or orange in autumn","collocations":["maple leaf","maple syrup","maple tree"],"example":"Maple syrup comes from the sap of maple trees.","exampleZh":"楓糖漿是從楓樹的樹汁中提煉出來的。","synonyms":[],"level":3,"theme":"動物與植物","examples":[{"en":"Maple syrup comes from the sap of maple trees.","zh":"楓糖漿是從楓樹的樹汁中提煉出來的。"},{"en":"The red maple leaf is a symbol of Canada.","zh":"紅色的楓葉是加拿大的象徵。"},{"en":"We poured warm maple syrup over the pancakes.","zh":"我們把溫熱的楓糖漿淋在鬆餅上。"}]},{"word":"marathon","pos":"n.","phonetic":"[ˈmærəˌθɑn]","meaning":"馬拉松","definition":"a long-distance running race of about 42 kilometers","collocations":["run a marathon","marathon runner","train for a marathon"],"example":"He trained for six months to run the marathon.","exampleZh":"他訓練了六個月才跑這場馬拉松。","synonyms":[],"level":4,"theme":"運動與休閒","examples":[{"en":"He trained for six months to run the marathon.","zh":"他訓練了六個月才跑這場馬拉松。"},{"en":"Thousands of runners took part in the city marathon.","zh":"數千名跑者參加了這場城市馬拉松。"},{"en":"A marathon runner must train patiently for many months.","zh":"馬拉松跑者必須耐心地訓練好幾個月。"}]},{"word":"march","pos":"v. / n.","phonetic":"[mɑrtʃ]","meaning":"行進；遊行","definition":"to walk with regular steps, often in a group","collocations":["march forward","protest march","march in step"],"example":"The soldiers marched down the street.","exampleZh":"士兵們沿著街道行進。","synonyms":["parade"],"level":3,"theme":"動作與行為","examples":[{"en":"The soldiers marched down the street.","zh":"士兵們沿著街道行進。"},{"en":"The band marched forward proudly during the school parade.","zh":"樂隊在學校遊行時驕傲地向前行進。"},{"en":"Thousands of students joined the protest march for cleaner rivers.","zh":"數千名學生加入了要求河川更乾淨的抗議遊行。"}]},{"word":"margin","pos":"n.","phonetic":"[ˈmɑrdʒɪn]","meaning":"頁邊空白；差額","definition":"the empty space at the edge of a page, or a difference in amount","collocations":["profit margin","in the margin","narrow margin"],"example":"He won the election by a narrow margin.","exampleZh":"他以些微差距贏得選舉。","synonyms":["edge","border"],"level":5,"theme":"商業與金錢","examples":[{"en":"He won the election by a narrow margin.","zh":"他以些微差距贏得選舉。"},{"en":"The teacher wrote helpful comments in the margin of my essay.","zh":"老師在我作文的頁邊空白處寫了有用的評語。"},{"en":"The store's profit margin grew after it cut delivery costs.","zh":"這家店在削減運送成本後，利潤差額增加了。"}]},{"word":"marine","pos":"adj.","phonetic":"[məˈrin]","meaning":"海洋的","definition":"relating to the sea","collocations":["marine life","marine biology","marine animal"],"example":"Marine biologists study life in the ocean.","exampleZh":"海洋生物學家研究海洋中的生物。","synonyms":[],"level":4,"theme":"自然與環境","examples":[{"en":"Marine biologists study life in the ocean.","zh":"海洋生物學家研究海洋中的生物。"},{"en":"Plastic waste seriously threatens marine life along the coast.","zh":"塑膠垃圾嚴重威脅沿岸的海洋生物。"},{"en":"She hopes to study marine biology at university next year.","zh":"她希望明年在大學研讀海洋生物學。"}]},{"word":"mark","pos":"n. / v.","phonetic":"[mɑrk]","meaning":"記號；分數；標記","definition":"a symbol or sign; to give a grade to schoolwork","collocations":["mark an exam","get high marks","leave a mark"],"example":"She got full marks on the math test.","exampleZh":"她數學考試得了滿分。","synonyms":["grade","score"],"level":2,"theme":"教育與學習","examples":[{"en":"She got full marks on the math test.","zh":"她數學考試得了滿分。"},{"en":"The teacher spent all weekend marking the final exams.","zh":"老師整個週末都在批改期末考試卷。"},{"en":"He always gets high marks in history and geography.","zh":"他歷史和地理總是拿到高分。"}]},{"word":"market","pos":"n.","phonetic":"[ˈmɑrkɪt]","meaning":"市場","definition":"a place where goods are bought and sold","collocations":["farmers' market","stock market","market price"],"example":"We buy fresh vegetables at the market every Saturday.","exampleZh":"我們每週六都在市場買新鮮蔬菜。","synonyms":[],"level":2,"theme":"商業與金錢","examples":[{"en":"We buy fresh vegetables at the market every Saturday.","zh":"我們每週六都在市場買新鮮蔬菜。"},{"en":"My grandmother buys fresh fish at the traditional market daily.","zh":"我奶奶每天在傳統市場買新鮮的魚。"},{"en":"Many investors lost money when the stock market fell sharply.","zh":"當股市大幅下跌時，許多投資人賠了錢。"}]},{"word":"marriage","pos":"n.","phonetic":"[ˈmærɪdʒ]","meaning":"婚姻","definition":"the state of being legally married","collocations":["happy marriage","marriage ceremony","arranged marriage"],"example":"They celebrated ten years of marriage.","exampleZh":"他們慶祝結婚十週年。","synonyms":["wedlock"],"level":3,"theme":"人物與家庭","examples":[{"en":"They celebrated ten years of marriage.","zh":"他們慶祝結婚十週年。"},{"en":"A happy marriage requires patience, trust, and honest communication.","zh":"幸福的婚姻需要耐心、信任與誠實的溝通。"},{"en":"The wedding guests wished the couple a long and joyful marriage.","zh":"婚禮賓客祝這對新人擁有長久又快樂的婚姻。"}]},{"word":"marry","pos":"v.","phonetic":"[ˈmærɪ]","meaning":"結婚","definition":"to become someone's husband or wife","collocations":["marry someone","get married","marry young"],"example":"They plan to marry next spring.","exampleZh":"他們計畫明年春天結婚。","synonyms":["wed"],"level":2,"theme":"人物與家庭","examples":[{"en":"They plan to marry next spring.","zh":"他們計畫明年春天結婚。"},{"en":"She decided to marry her college sweetheart after graduation.","zh":"她決定畢業後與大學時代的戀人結婚。"},{"en":"In the past, some people chose to marry young.","zh":"過去有些人選擇很年輕就結婚。"}]},{"word":"marvelous","pos":"adj.","phonetic":"[ˈmɑrvələs]","meaning":"令人驚奇的；極好的","definition":"causing great wonder; extremely good","collocations":["marvelous idea","marvelous performance","simply marvelous"],"example":"The chef prepared a marvelous meal for us.","exampleZh":"主廚為我們準備了一頓極好的餐點。","synonyms":["wonderful","splendid"],"level":5,"theme":"性質與描述","examples":[{"en":"The chef prepared a marvelous meal for us.","zh":"主廚為我們準備了一頓極好的餐點。"},{"en":"What a marvelous idea to plant trees around the school!","zh":"在學校周圍種樹真是個極好的主意！"},{"en":"The pianist gave a simply marvelous performance last night.","zh":"那位鋼琴家昨晚的演出簡直令人驚嘆。"}]},{"word":"mask","pos":"n. / v.","phonetic":"[mæsk]","meaning":"面具；口罩","definition":"a covering for the face worn for protection or disguise","collocations":["wear a mask","face mask","mask one's feelings"],"example":"Everyone wore a mask during the flu outbreak.","exampleZh":"流感爆發期間大家都戴著口罩。","synonyms":["disguise"],"level":2,"theme":"服裝與外表","examples":[{"en":"Everyone wore a mask during the flu outbreak.","zh":"流感爆發期間大家都戴著口罩。"},{"en":"You must wear a face mask when you feel sick.","zh":"當你覺得不舒服時，必須戴上口罩。"},{"en":"He tried to mask his disappointment with a forced smile.","zh":"他試圖用勉強的微笑掩飾失望。"}]},{"word":"mass","pos":"n. / adj.","phonetic":"[mæs]","meaning":"大量；質量","definition":"a large amount or number of something; the quantity of matter in an object","collocations":["mass production","mass media","a mass of people"],"example":"The mass media influences public opinion.","exampleZh":"大眾媒體影響著公眾輿論。","synonyms":["bulk"],"level":4,"theme":"科學與數學","examples":[{"en":"The mass media influences public opinion.","zh":"大眾媒體影響著公眾輿論。"},{"en":"Mass production allows factories to make goods more cheaply.","zh":"大量生產讓工廠能更便宜地製造商品。"},{"en":"A mass of people gathered in the square to celebrate.","zh":"一大群人聚集在廣場上慶祝。"}]},{"word":"massage","pos":"n. / v.","phonetic":"[məˈsɑʒ]","meaning":"按摩","definition":"the rubbing and pressing of muscles to relax them","collocations":["give a massage","back massage","massage therapy"],"example":"A good massage can relieve stress.","exampleZh":"一場好的按摩可以舒緩壓力。","synonyms":["rub"],"level":4,"theme":"身體與健康","examples":[{"en":"A good massage can relieve stress.","zh":"一場好的按摩可以舒緩壓力。"},{"en":"After the long hike, a back massage felt wonderful.","zh":"長途健行後，背部按摩感覺很舒服。"},{"en":"The therapist gently massaged the tension out of his shoulders.","zh":"治療師輕柔地按摩，緩解他肩膀的緊繃。"}]},{"word":"massive","pos":"adj.","phonetic":"[ˈmæsɪv]","meaning":"巨大的","definition":"large and heavy or solid","collocations":["massive amount","massive building","massive success"],"example":"The company suffered massive losses last year.","exampleZh":"這家公司去年遭受巨大的損失。","synonyms":["huge","enormous"],"level":5,"theme":"性質與描述","examples":[{"en":"The company suffered massive losses last year.","zh":"這家公司去年遭受巨大的損失。"},{"en":"A massive crowd waited outside the stadium for the concert.","zh":"一大群人在體育場外等待演唱會。"},{"en":"The new library is a massive building near the park.","zh":"新圖書館是公園附近一棟巨大的建築。"}]},{"word":"master","pos":"n. / v.","phonetic":"[ˈmæstɚ]","meaning":"主人；精通","definition":"a person with control over something; to become skilled at something","collocations":["master a skill","master's degree","master the art"],"example":"It takes years to master a foreign language.","exampleZh":"要精通一門外語需要多年時間。","synonyms":["expert"],"level":3,"theme":"教育與學習","examples":[{"en":"It takes years to master a foreign language.","zh":"要精通一門外語需要多年時間。"},{"en":"It took her years to master the violin.","zh":"她花了好幾年才精通小提琴。"},{"en":"He hopes to earn a master's degree in engineering.","zh":"他希望取得工程學的碩士學位。"}]},{"word":"match","pos":"n. / v.","phonetic":"[mætʃ]","meaning":"比賽；配對","definition":"a game between two teams or players; to be similar or suitable","collocations":["tennis match","match colors","perfect match"],"example":"The two teams will play a match tomorrow.","exampleZh":"這兩隊明天將進行一場比賽。","synonyms":["game","contest"],"level":2,"theme":"運動與休閒","examples":[{"en":"The two teams will play a match tomorrow.","zh":"這兩隊明天將進行一場比賽。"},{"en":"Our school won the basketball match by two points.","zh":"我們學校以兩分之差贏得籃球比賽。"},{"en":"This scarf matches your coat perfectly.","zh":"這條圍巾和你的外套非常相配。"}]},{"word":"material","pos":"n. / adj.","phonetic":"[məˈtɪrɪəl]","meaning":"材料；物質的","definition":"the substance from which something is made","collocations":["raw material","building material","material world"],"example":"Cotton is a common material for clothing.","exampleZh":"棉花是製作衣服的常見材料。","synonyms":["substance","fabric"],"level":3,"theme":"科學與數學","examples":[{"en":"Cotton is a common material for clothing.","zh":"棉花是製作衣服的常見材料。"},{"en":"Wood is a natural building material used around the world.","zh":"木材是世界各地都使用的天然建築材料。"},{"en":"The factory buys raw material from local farmers.","zh":"這家工廠向當地農民購買原料。"}]},{"word":"math","pos":"n.","phonetic":"[mæθ]","meaning":"數學","definition":"the study of numbers, shapes, and quantities","collocations":["math class","math homework","good at math"],"example":"He is very good at math.","exampleZh":"他數學很好。","synonyms":["mathematics"],"level":1,"theme":"科學與數學","examples":[{"en":"He is very good at math.","zh":"他數學很好。"},{"en":"I have to finish my math homework before dinner.","zh":"我必須在晚餐前完成數學作業。"},{"en":"She is really good at math and enjoys solving puzzles.","zh":"她數學很好，也喜歡解謎題。"}]},{"word":"mathematics","pos":"n.","phonetic":"[ˌmæθəˈmætɪks]","meaning":"數學","definition":"the science of numbers, quantities, and shapes","collocations":["study mathematics","applied mathematics","mathematics teacher"],"example":"Mathematics is required for engineering students.","exampleZh":"數學是工程系學生的必修課程。","synonyms":["math"],"level":3,"theme":"科學與數學","examples":[{"en":"Mathematics is required for engineering students.","zh":"數學是工程系學生的必修課程。"},{"en":"Applied mathematics helps engineers design safer bridges.","zh":"應用數學幫助工程師設計更安全的橋樑。"},{"en":"Our new mathematics teacher explains difficult ideas clearly.","zh":"我們新的數學老師把困難的概念解釋得很清楚。"}]},{"word":"matter","pos":"n. / v.","phonetic":"[ˈmætɚ]","meaning":"事情；重要","definition":"a subject or situation being discussed; to be important","collocations":["as a matter of fact","no matter what","matter of time"],"example":"It doesn't matter what others think of you.","exampleZh":"別人怎麼看你並不重要。","synonyms":["issue","affair"],"level":2,"theme":"抽象概念","examples":[{"en":"It doesn't matter what others think of you.","zh":"別人怎麼看你並不重要。"},{"en":"As a matter of fact, I already finished the report.","zh":"事實上，我已經完成那份報告了。"},{"en":"No matter what happens, your family will support you.","zh":"無論發生什麼事，你的家人都會支持你。"}]},{"word":"mattress","pos":"n.","phonetic":"[ˈmætrɪs]","meaning":"床墊","definition":"a large flat pad used as, or on, a bed","collocations":["soft mattress","memory foam mattress","change the mattress"],"example":"We bought a new mattress for a better night's sleep.","exampleZh":"我們買了一張新床墊以獲得更好的睡眠。","synonyms":[],"level":3,"theme":"居家與生活","examples":[{"en":"We bought a new mattress for a better night's sleep.","zh":"我們買了一張新床墊以獲得更好的睡眠。"},{"en":"A soft mattress helps me fall asleep more easily.","zh":"柔軟的床墊讓我更容易入睡。"},{"en":"They decided to change the mattress after ten years.","zh":"用了十年後，他們決定換掉床墊。"}]},{"word":"mature","pos":"adj. / v.","phonetic":"[məˈtjʊr]","meaning":"成熟的","definition":"fully grown or developed, physically or mentally","collocations":["mature attitude","mature tree","grow mature"],"example":"She behaves in a mature way for her age.","exampleZh":"以她的年紀來說，她的行為相當成熟。","synonyms":["grown-up"],"level":4,"theme":"性質與描述","examples":[{"en":"She behaves in a mature way for her age.","zh":"以她的年紀來說，她的行為相當成熟。"},{"en":"She handled the difficult situation with a mature attitude.","zh":"她以成熟的態度處理那個困難的情況。"},{"en":"The apples on that mature tree taste especially sweet.","zh":"那棵成熟樹上的蘋果嚐起來特別甜。"}]},{"word":"maximum","pos":"adj. / n.","phonetic":"[ˈmæksəməm]","meaning":"最大的；最大量","definition":"the greatest amount or number possible","collocations":["maximum speed","maximum capacity","reach a maximum"],"example":"The elevator has a maximum capacity of ten people.","exampleZh":"這台電梯的最大載重量為十人。","synonyms":["peak"],"level":4,"theme":"科學與數學","examples":[{"en":"The elevator has a maximum capacity of ten people.","zh":"這台電梯的最大載重量為十人。"},{"en":"The bus can carry a maximum of forty passengers.","zh":"這輛公車最多可載四十名乘客。"},{"en":"Drivers must not exceed the maximum speed on this road.","zh":"駕駛人不得超過這條路的最高速限。"}]},{"word":"may","pos":"v.","phonetic":"[me]","meaning":"可能；可以","definition":"used to express possibility or to ask for permission","collocations":["may I","it may rain","may as well"],"example":"It may rain later this afternoon.","exampleZh":"今天下午稍晚可能會下雨。","synonyms":["might"],"level":1,"theme":"抽象概念","examples":[{"en":"It may rain later this afternoon.","zh":"今天下午稍晚可能會下雨。"},{"en":"May I borrow your pen for a moment?","zh":"我可以借用你的筆一下嗎？"},{"en":"We may as well start the meeting without him.","zh":"我們不妨在沒有他的情況下開始會議。"}]},{"word":"maybe","pos":"adv.","phonetic":"[ˈmebɪ]","meaning":"也許","definition":"perhaps; possibly","collocations":["maybe later","maybe not","maybe so"],"example":"Maybe we should leave earlier tomorrow.","exampleZh":"也許我們明天應該早點出發。","synonyms":["perhaps"],"level":1,"theme":"抽象概念","examples":[{"en":"Maybe we should leave earlier tomorrow.","zh":"也許我們明天應該早點出發。"},{"en":"Maybe we can visit the museum later this afternoon.","zh":"也許我們今天下午稍晚可以去參觀博物館。"},{"en":"You look tired; maybe you should rest a while.","zh":"你看起來很累，也許你該休息一會兒。"}]},{"word":"mayor","pos":"n.","phonetic":"[ˈmeɚ]","meaning":"市長","definition":"the head of a city or town government","collocations":["elect a mayor","city mayor","mayor's office"],"example":"The mayor gave a speech at the ceremony.","exampleZh":"市長在典禮上發表了演說。","synonyms":[],"level":3,"theme":"政治與法律","examples":[{"en":"The mayor gave a speech at the ceremony.","zh":"市長在典禮上發表了演說。"},{"en":"The citizens will elect a new mayor next month.","zh":"市民下個月將選出一位新市長。"},{"en":"The mayor's office announced plans to build more parks.","zh":"市長辦公室宣布了興建更多公園的計畫。"}]},{"word":"maze","pos":"n.","phonetic":"[mez]","meaning":"迷宮","definition":"a network of paths designed as a puzzle","collocations":["corn maze","get lost in a maze","solve a maze"],"example":"The children got lost in the corn maze.","exampleZh":"孩子們在玉米迷宮裡迷路了。","synonyms":["labyrinth"],"level":4,"theme":"運動與休閒","examples":[{"en":"The children got lost in the corn maze.","zh":"孩子們在玉米迷宮裡迷路了。"},{"en":"The children laughed as they tried to solve the maze.","zh":"孩子們一邊努力破解迷宮，一邊開心地笑著。"},{"en":"It's easy to get lost in a maze of narrow streets.","zh":"在狹窄街道的迷宮中很容易迷路。"}]},{"word":"meal","pos":"n.","phonetic":"[mil]","meaning":"一餐","definition":"the food eaten at one particular time","collocations":["have a meal","skip a meal","home-cooked meal"],"example":"We had a big meal to celebrate the holiday.","exampleZh":"我們吃了一頓豐盛的大餐來慶祝節日。","synonyms":[],"level":1,"theme":"食物與烹飪","examples":[{"en":"We had a big meal to celebrate the holiday.","zh":"我們吃了一頓豐盛的大餐來慶祝節日。"},{"en":"We always enjoy a home-cooked meal on Sundays.","zh":"我們總是在星期天享用一頓家常飯菜。"},{"en":"You shouldn't skip a meal before a long exam.","zh":"長時間考試前你不該不吃飯。"}]},{"word":"mean","pos":"v. / adj.","phonetic":"[min]","meaning":"意指；小氣的","definition":"to intend to express or convey something; unkind or unwilling to spend","collocations":["mean well","what do you mean","mean to someone"],"example":"What do you mean by that comment?","exampleZh":"你那句話是什麼意思？","synonyms":["signify","unkind"],"level":2,"theme":"溝通與語言","examples":[{"en":"What do you mean by that comment?","zh":"你那句話是什麼意思？"},{"en":"What exactly do you mean by that strange remark?","zh":"你那句奇怪的話到底是什麼意思？"},{"en":"It was mean of him to laugh at her mistake.","zh":"他嘲笑她的錯誤，真是刻薄。"}]},{"word":"meaning","pos":"n.","phonetic":"[ˈminɪŋ]","meaning":"意義","definition":"what is meant by a word, action, or concept","collocations":["true meaning","hidden meaning","meaning of life"],"example":"The teacher explained the meaning of the poem.","exampleZh":"老師解釋了這首詩的意義。","synonyms":["sense"],"level":2,"theme":"溝通與語言","examples":[{"en":"The teacher explained the meaning of the poem.","zh":"老師解釋了這首詩的意義。"},{"en":"Many people search for the true meaning of happiness.","zh":"許多人尋找幸福的真正意義。"},{"en":"The poem has a hidden meaning about growing up.","zh":"這首詩有一個關於成長的隱含意義。"}]},{"word":"meanwhile","pos":"adv.","phonetic":"[ˈminˌhwaɪl]","meaning":"同時；與此同時","definition":"at the same time, or during the intervening period","collocations":["in the meanwhile","meanwhile, elsewhere","meanwhile, at home"],"example":"Meanwhile, the rest of us waited outside.","exampleZh":"與此同時，我們其他人在外面等待。","synonyms":["simultaneously"],"level":4,"theme":"時間與空間","examples":[{"en":"Meanwhile, the rest of us waited outside.","zh":"與此同時，我們其他人在外面等待。"},{"en":"I cooked dinner; meanwhile, my brother set the table.","zh":"我煮晚餐，與此同時，我弟弟擺好餐桌。"},{"en":"The guests chatted happily; meanwhile, the rain kept falling.","zh":"客人們開心地聊天，與此同時，雨還一直下著。"}]},{"word":"measure","pos":"v. / n.","phonetic":"[ˈmɛʒɚ]","meaning":"測量；措施","definition":"to find the size or amount of something; a plan of action","collocations":["measure length","take measures","safety measure"],"example":"The tailor measured my waist carefully.","exampleZh":"裁縫師仔細地量了我的腰圍。","synonyms":["gauge"],"level":3,"theme":"科學與數學","examples":[{"en":"The tailor measured my waist carefully.","zh":"裁縫師仔細地量了我的腰圍。"},{"en":"Please measure the length of the table before buying cloth.","zh":"買布之前請先測量桌子的長度。"},{"en":"The school took new measures to keep students safe.","zh":"學校採取了新措施來保護學生安全。"}]},{"word":"measurement","pos":"n.","phonetic":"[ˈmɛʒɚmənt]","meaning":"測量；尺寸","definition":"the size, length, or amount of something found by measuring","collocations":["take measurements","accurate measurement","body measurements"],"example":"The tailor took his measurements for the suit.","exampleZh":"裁縫師量了他的尺寸來做西裝。","synonyms":["dimension"],"level":4,"theme":"科學與數學","examples":[{"en":"The tailor took his measurements for the suit.","zh":"裁縫師量了他的尺寸來做西裝。"},{"en":"An accurate measurement is essential in every science experiment.","zh":"精確的測量在每個科學實驗中都很重要。"},{"en":"The carpenter took careful measurements before cutting the wood.","zh":"木匠在鋸木頭前仔細地量了尺寸。"}]},{"word":"meat","pos":"n.","phonetic":"[mit]","meaning":"肉","definition":"the flesh of an animal used as food","collocations":["red meat","meat and vegetables","raw meat"],"example":"She doesn't eat meat because she's vegetarian.","exampleZh":"她因為吃素而不吃肉。","synonyms":[],"level":1,"theme":"食物與烹飪","examples":[{"en":"She doesn't eat meat because she's vegetarian.","zh":"她因為吃素而不吃肉。"},{"en":"Doctors advise eating less red meat for better health.","zh":"醫生建議少吃紅肉以維持較好的健康。"},{"en":"She served meat and vegetables at the family dinner.","zh":"她在家庭晚餐上端出了肉和蔬菜。"}]},{"word":"mechanic","pos":"n.","phonetic":"[məˈkænɪk]","meaning":"技工；機械工","definition":"a person who repairs and maintains machines, especially vehicles","collocations":["car mechanic","skilled mechanic","auto mechanic"],"example":"The mechanic fixed the car's engine in an hour.","exampleZh":"技工在一小時內修好了汽車引擎。","synonyms":[],"level":3,"theme":"工作與職業","examples":[{"en":"The mechanic fixed the car's engine in an hour.","zh":"技工在一小時內修好了汽車引擎。"},{"en":"A skilled mechanic can find the problem within minutes.","zh":"技術熟練的技工能在幾分鐘內找出問題。"},{"en":"We took the old truck to an honest auto mechanic.","zh":"我們把那輛舊卡車送去給一位誠實的汽車技工。"}]},{"word":"medal","pos":"n.","phonetic":"[ˈmɛdəl]","meaning":"獎牌","definition":"a metal disc given as an award for an achievement","collocations":["gold medal","win a medal","medal ceremony"],"example":"She won a gold medal in swimming.","exampleZh":"她在游泳項目中贏得金牌。","synonyms":[],"level":2,"theme":"運動與休閒","examples":[{"en":"She won a gold medal in swimming.","zh":"她在游泳項目中贏得金牌。"},{"en":"The young runner dreamed of winning an Olympic medal.","zh":"那位年輕的跑者夢想贏得一面奧運獎牌。"},{"en":"Proud parents watched their son receive a gold medal.","zh":"驕傲的父母看著兒子領取金牌。"}]},{"word":"media","pos":"n.","phonetic":"[ˈmidɪə]","meaning":"媒體","definition":"the main means of mass communication, such as TV and the internet","collocations":["social media","news media","media coverage"],"example":"Social media has changed how we communicate.","exampleZh":"社群媒體改變了我們的溝通方式。","synonyms":[],"level":3,"theme":"科技與媒體","examples":[{"en":"Social media has changed how we communicate.","zh":"社群媒體改變了我們的溝通方式。"},{"en":"The news media reported the storm damage across the country.","zh":"新聞媒體報導了全國各地的風暴災情。"},{"en":"Teenagers spend many hours on social media every day.","zh":"青少年每天花很多時間在社群媒體上。"}]},{"word":"medical","pos":"adj.","phonetic":"[ˈmɛdɪkəl]","meaning":"醫學的；醫療的","definition":"relating to the treatment of illness and injuries","collocations":["medical care","medical treatment","medical school"],"example":"He needs immediate medical attention.","exampleZh":"他需要立即的醫療照護。","synonyms":[],"level":3,"theme":"身體與健康","examples":[{"en":"He needs immediate medical attention.","zh":"他需要立即的醫療照護。"},{"en":"The injured hiker received medical care at the hospital.","zh":"受傷的登山者在醫院接受了醫療照護。"},{"en":"She studied hard to enter medical school.","zh":"她努力讀書以進入醫學院。"}]},{"word":"medicine","pos":"n.","phonetic":"[ˈmɛdəsən]","meaning":"藥；醫學","definition":"a substance used to treat illness; the science of treating disease","collocations":["take medicine","cold medicine","study medicine"],"example":"Take this medicine twice a day after meals.","exampleZh":"請在飯後每天服用兩次這種藥。","synonyms":["drug"],"level":2,"theme":"身體與健康","examples":[{"en":"Take this medicine twice a day after meals.","zh":"請在飯後每天服用兩次這種藥。"},{"en":"Remember to take your cold medicine after breakfast.","zh":"記得早餐後服用你的感冒藥。"},{"en":"He went abroad to study medicine and become a doctor.","zh":"他出國研讀醫學，想成為一名醫生。"}]},{"word":"medium","pos":"adj. / n.","phonetic":"[ˈmidɪəm]","meaning":"中等的；媒介","definition":"middle in size or amount; a means by which something is communicated","collocations":["medium size","medium heat","communication medium"],"example":"I'd like a medium coffee, please.","exampleZh":"我要一杯中杯咖啡，謝謝。","synonyms":["average"],"level":3,"theme":"性質與描述","examples":[{"en":"I'd like a medium coffee, please.","zh":"我要一杯中杯咖啡，謝謝。"},{"en":"I usually order a medium bowl of noodles for lunch.","zh":"我午餐通常點一碗中份的麵。"},{"en":"Painting became her favorite medium for expressing emotions.","zh":"繪畫成了她表達情感最喜愛的媒介。"}]},{"word":"meet","pos":"v.","phonetic":"[mit]","meaning":"遇見；會面","definition":"to come together with someone by chance or arrangement","collocations":["meet a deadline","meet friends","nice to meet you"],"example":"Nice to meet you! I've heard so much about you.","exampleZh":"很高興認識你！久仰大名。","synonyms":["encounter"],"level":1,"theme":"人物與家庭","examples":[{"en":"Nice to meet you! I've heard so much about you.","zh":"很高興認識你！久仰大名。"},{"en":"Let's meet at the library entrance after class.","zh":"我們下課後在圖書館入口碰面吧。"},{"en":"The team worked overtime to meet the deadline.","zh":"團隊加班以趕上截止期限。"}]},{"word":"meeting","pos":"n.","phonetic":"[ˈmitɪŋ]","meaning":"會議","definition":"a gathering of people for discussion","collocations":["attend a meeting","hold a meeting","business meeting"],"example":"The manager scheduled a meeting for Monday morning.","exampleZh":"經理安排了週一早上的會議。","synonyms":["conference"],"level":2,"theme":"工作與職業","examples":[{"en":"The manager scheduled a meeting for Monday morning.","zh":"經理安排了週一早上的會議。"},{"en":"All department members must attend the meeting on Friday.","zh":"所有部門成員都必須參加星期五的會議。"},{"en":"They will hold a meeting to discuss the school festival.","zh":"他們將舉行會議討論校慶活動。"}]},{"word":"melody","pos":"n.","phonetic":"[ˈmɛlədɪ]","meaning":"旋律","definition":"a sequence of musical notes that forms a tune","collocations":["sweet melody","catchy melody","sing a melody"],"example":"The song has a beautiful melody.","exampleZh":"這首歌有優美的旋律。","synonyms":["tune"],"level":4,"theme":"藝術與音樂","examples":[{"en":"The song has a beautiful melody.","zh":"這首歌有優美的旋律。"},{"en":"The gentle melody of the lullaby helped the baby sleep.","zh":"搖籃曲輕柔的旋律幫助寶寶入睡。"},{"en":"I couldn't stop humming that catchy melody all day.","zh":"我一整天都忍不住哼著那段朗朗上口的旋律。"}]},{"word":"melt","pos":"v.","phonetic":"[mɛlt]","meaning":"融化","definition":"to change from a solid to a liquid because of heat","collocations":["melt ice","melt in your mouth","ice melts"],"example":"The ice cream melted quickly in the sun.","exampleZh":"冰淇淋在陽光下很快就融化了。","synonyms":["dissolve","thaw"],"level":2,"theme":"科學與數學","examples":[{"en":"The ice cream melted quickly in the sun.","zh":"冰淇淋在陽光下很快就融化了。"},{"en":"The spring sun made the snow on the roof melt.","zh":"春天的陽光使屋頂上的雪融化了。"},{"en":"This chocolate is so smooth it melts in your mouth.","zh":"這巧克力如此滑順，入口即化。"}]},{"word":"member","pos":"n.","phonetic":"[ˈmɛmbɚ]","meaning":"成員","definition":"a person who belongs to a group or organization","collocations":["family member","club member","become a member"],"example":"Every family member helped clean the house.","exampleZh":"每位家庭成員都幫忙打掃房子。","synonyms":[],"level":2,"theme":"人物與家庭","examples":[{"en":"Every family member helped clean the house.","zh":"每位家庭成員都幫忙打掃房子。"},{"en":"Every club member paid a small fee to join.","zh":"每位社團成員都繳了一小筆費用才加入。"},{"en":"Each family member has a different chore at home.","zh":"家裡每個成員都有不同的家務。"}]},{"word":"membership","pos":"n.","phonetic":"[ˈmɛmbɚˌʃɪp]","meaning":"會員資格","definition":"the state of being a member of a group or club","collocations":["gym membership","apply for membership","annual membership"],"example":"She bought a gym membership for the new year.","exampleZh":"她為新的一年買了健身房會員資格。","synonyms":[],"level":4,"theme":"商業與金錢","examples":[{"en":"She bought a gym membership for the new year.","zh":"她為新的一年買了健身房會員資格。"},{"en":"Her gym membership includes free swimming lessons.","zh":"她的健身房會員資格包含免費游泳課。"},{"en":"You must apply for membership before using the library.","zh":"使用圖書館前你必須先申請會員資格。"}]},{"word":"memorial","pos":"n. / adj.","phonetic":"[məˈmorɪəl]","meaning":"紀念碑；紀念的","definition":"something built to remember a person or event","collocations":["war memorial","memorial service","memorial day"],"example":"The city built a memorial to honor the soldiers.","exampleZh":"這座城市建了一座紀念碑來紀念士兵。","synonyms":["monument"],"level":5,"theme":"社會與文化","examples":[{"en":"The city built a memorial to honor the soldiers.","zh":"這座城市建了一座紀念碑來紀念士兵。"},{"en":"A memorial service was held for the beloved teacher.","zh":"為那位深受愛戴的老師舉行了追思會。"},{"en":"The park has a war memorial honoring fallen soldiers.","zh":"公園裡有一座紀念陣亡士兵的戰爭紀念碑。"}]},{"word":"memorize","pos":"v.","phonetic":"[ˈmɛməˌraɪz]","meaning":"記憶；背誦","definition":"to learn something so as to remember it exactly","collocations":["memorize vocabulary","memorize a speech","memorize lines"],"example":"Students had to memorize the poem for class.","exampleZh":"學生必須為了課堂背誦這首詩。","synonyms":["learn by heart"],"level":3,"theme":"教育與學習","examples":[{"en":"Students had to memorize the poem for class.","zh":"學生必須為了課堂背誦這首詩。"},{"en":"She stayed up late to memorize her English vocabulary.","zh":"她熬夜背誦她的英文單字。"},{"en":"The actor had to memorize a long speech for the play.","zh":"那位演員必須為這齣戲背誦一長段台詞。"}]},{"word":"memory","pos":"n.","phonetic":"[ˈmɛmərɪ]","meaning":"記憶；回憶","definition":"the ability to remember things, or something remembered","collocations":["good memory","childhood memory","memory loss"],"example":"She has fond memories of her childhood.","exampleZh":"她對童年有美好的回憶。","synonyms":["recollection"],"level":2,"theme":"抽象概念","examples":[{"en":"She has fond memories of her childhood.","zh":"她對童年有美好的回憶。"},{"en":"My grandfather has an amazing memory for old songs.","zh":"我爺爺對老歌有驚人的記憶力。"},{"en":"That summer trip remains one of my happiest memories.","zh":"那次夏日旅行仍是我最快樂的回憶之一。"}]},{"word":"mental","pos":"adj.","phonetic":"[ˈmɛntəl]","meaning":"心理的；精神的","definition":"relating to the mind","collocations":["mental health","mental illness","mental strength"],"example":"Mental health is just as important as physical health.","exampleZh":"心理健康與生理健康同樣重要。","synonyms":["psychological"],"level":3,"theme":"身體與健康","examples":[{"en":"Mental health is just as important as physical health.","zh":"心理健康與生理健康同樣重要。"},{"en":"Regular exercise can improve both mental and physical health.","zh":"規律運動能改善心理與身體的健康。"},{"en":"Solving puzzles is good mental exercise for the brain.","zh":"解謎題是對大腦很好的心智鍛鍊。"}]},{"word":"mention","pos":"v. / n.","phonetic":"[ˈmɛnʃən]","meaning":"提及","definition":"to speak or write about something briefly","collocations":["mention a name","not to mention","mention in passing"],"example":"She didn't mention the accident to anyone.","exampleZh":"她沒有向任何人提及這場意外。","synonyms":["refer to"],"level":2,"theme":"溝通與語言","examples":[{"en":"She didn't mention the accident to anyone.","zh":"她沒有向任何人提及這場意外。"},{"en":"He forgot to mention that the meeting was cancelled.","zh":"他忘了提到會議已經取消了。"},{"en":"She is talented, not to mention very hardworking.","zh":"她很有才華，更別提她非常勤奮。"}]},{"word":"menu","pos":"n.","phonetic":"[ˈmɛnju]","meaning":"菜單","definition":"a list of dishes available in a restaurant","collocations":["order from the menu","dinner menu","menu item"],"example":"Could I see the menu, please?","exampleZh":"請問我可以看一下菜單嗎？","synonyms":[],"level":1,"theme":"食物與烹飪","examples":[{"en":"Could I see the menu, please?","zh":"請問我可以看一下菜單嗎？"},{"en":"The waiter handed us the dinner menu with a smile.","zh":"服務生微笑著把晚餐菜單遞給我們。"},{"en":"Every item on the menu looked absolutely delicious.","zh":"菜單上的每道菜看起來都非常美味。"}]},{"word":"merchant","pos":"n.","phonetic":"[ˈmɝtʃənt]","meaning":"商人","definition":"a person involved in buying and selling goods, especially on a large scale","collocations":["wealthy merchant","merchant ship","local merchant"],"example":"The merchant sold silk and spices from the East.","exampleZh":"這位商人販賣來自東方的絲綢和香料。","synonyms":["trader"],"level":4,"theme":"商業與金錢","examples":[{"en":"The merchant sold silk and spices from the East.","zh":"這位商人販賣來自東方的絲綢和香料。"},{"en":"The wealthy merchant traveled far to sell his goods.","zh":"那位富有的商人遠行去販售他的貨物。"},{"en":"A local merchant donated food to the shelter.","zh":"一位當地商人捐贈食物給收容所。"}]},{"word":"mercy","pos":"n.","phonetic":"[ˈmɝsɪ]","meaning":"慈悲；憐憫","definition":"compassion or forgiveness shown toward someone one has power over","collocations":["show mercy","beg for mercy","have mercy"],"example":"The judge showed mercy and reduced the sentence.","exampleZh":"法官展現慈悲，減輕了刑期。","synonyms":["compassion"],"level":5,"theme":"抽象概念","examples":[{"en":"The judge showed mercy and reduced the sentence.","zh":"法官展現慈悲，減輕了刑期。"},{"en":"The king decided to show mercy to the young prisoner.","zh":"國王決定對那名年輕囚犯展現慈悲。"},{"en":"The defeated soldiers begged their enemy for mercy.","zh":"戰敗的士兵向敵人乞求憐憫。"}]},{"word":"mere","pos":"adj.","phonetic":"[mɪr]","meaning":"僅僅的","definition":"used to emphasize how small, unimportant, or simple something is","collocations":["mere coincidence","a mere child","mere seconds"],"example":"It took her a mere five minutes to finish.","exampleZh":"她只花了短短五分鐘就完成了。","synonyms":["simple"],"level":5,"theme":"性質與描述","examples":[{"en":"It took her a mere five minutes to finish.","zh":"她只花了短短五分鐘就完成了。"},{"en":"The whole trip cost a mere two hundred dollars.","zh":"整趟旅行僅僅花了兩百元。"},{"en":"He solved the puzzle in mere seconds.","zh":"他僅僅在幾秒內就解開了謎題。"}]},{"word":"merely","pos":"adv.","phonetic":"[ˈmɪrlɪ]","meaning":"僅僅","definition":"just; only","collocations":["merely a suggestion","not merely","merely by chance"],"example":"I merely wanted to help, not to criticize.","exampleZh":"我只是想幫忙，並不是想批評。","synonyms":["simply","only"],"level":5,"theme":"抽象概念","examples":[{"en":"I merely wanted to help, not to criticize.","zh":"我只是想幫忙，並不是想批評。"},{"en":"I was merely trying to explain my point clearly.","zh":"我僅僅是想把我的觀點解釋清楚。"},{"en":"This is merely a suggestion, not a strict rule.","zh":"這僅僅是個建議，不是嚴格的規定。"}]},{"word":"merge","pos":"v.","phonetic":"[mɝdʒ]","meaning":"合併","definition":"to combine or join together to form one thing","collocations":["merge companies","merge lanes","merge into one"],"example":"The two companies decided to merge.","exampleZh":"這兩家公司決定合併。","synonyms":["combine","unite"],"level":5,"theme":"商業與金錢","examples":[{"en":"The two companies decided to merge.","zh":"這兩家公司決定合併。"},{"en":"The two small schools will merge into one next year.","zh":"這兩所小學校明年將合併成一所。"},{"en":"Cars must merge carefully where the two lanes meet.","zh":"在兩條車道匯合處，車輛必須小心地併線。"}]},{"word":"merit","pos":"n.","phonetic":"[ˈmɛrɪt]","meaning":"優點；價值","definition":"the quality of being good or deserving praise","collocations":["merit system","on its own merits","artistic merit"],"example":"The proposal has some merit but needs revision.","exampleZh":"這項提案有一些優點，但需要修改。","synonyms":["worth","value"],"level":5,"theme":"抽象概念","examples":[{"en":"The proposal has some merit but needs revision.","zh":"這項提案有一些優點，但需要修改。"},{"en":"The judges evaluated each painting on its own merits.","zh":"評審依據每幅畫本身的優點來評分。"},{"en":"Your plan has real merit, but it needs more detail.","zh":"你的計畫確實有其價值，但需要更多細節。"}]},{"word":"merry","pos":"adj.","phonetic":"[ˈmɛrɪ]","meaning":"歡樂的","definition":"cheerful and lively","collocations":["merry Christmas","merry mood","make merry"],"example":"Merry Christmas and a happy new year!","exampleZh":"聖誕快樂，新年快樂！","synonyms":["cheerful","jolly"],"level":3,"theme":"情緒與感受","examples":[{"en":"Merry Christmas and a happy new year!","zh":"聖誕快樂，新年快樂！"},{"en":"The whole village was in a merry mood during the festival.","zh":"整個村莊在節慶期間都洋溢著歡樂的氣氛。"},{"en":"Children sang merry songs around the warm fire.","zh":"孩子們圍著溫暖的火堆唱著歡樂的歌。"}]},{"word":"mess","pos":"n. / v.","phonetic":"[mɛs]","meaning":"混亂；弄亂","definition":"a state of disorder or untidiness","collocations":["make a mess","clean up the mess","in a mess"],"example":"The kids made a mess in the kitchen.","exampleZh":"孩子們把廚房弄得一團亂。","synonyms":["disorder","clutter"],"level":2,"theme":"居家與生活","examples":[{"en":"The kids made a mess in the kitchen.","zh":"孩子們把廚房弄得一團亂。"},{"en":"Please clean up the mess before your parents come home.","zh":"請在你父母回家前收拾好這片混亂。"},{"en":"The puppy made a mess all over the living room.","zh":"小狗把客廳弄得一團亂。"}]},{"word":"message","pos":"n.","phonetic":"[ˈmɛsɪdʒ]","meaning":"訊息","definition":"a piece of information sent to or given to someone","collocations":["leave a message","text message","send a message"],"example":"I sent him a message about the meeting time.","exampleZh":"我傳了一則訊息告訴他會議時間。","synonyms":["note"],"level":2,"theme":"溝通與語言","examples":[{"en":"I sent him a message about the meeting time.","zh":"我傳了一則訊息告訴他會議時間。"},{"en":"She left a message asking me to call her back.","zh":"她留了一則訊息要我回電給她。"},{"en":"I'll send you a message once I arrive safely.","zh":"我平安抵達後會傳訊息給你。"}]},{"word":"messy","pos":"adj.","phonetic":"[ˈmɛsɪ]","meaning":"凌亂的","definition":"untidy or disordered","collocations":["messy room","messy hair","messy situation"],"example":"His room is always messy after school.","exampleZh":"他放學後房間總是很凌亂。","synonyms":["untidy"],"level":2,"theme":"居家與生活","examples":[{"en":"His room is always messy after school.","zh":"他放學後房間總是很凌亂。"},{"en":"His desk is so messy that he can't find anything.","zh":"他的書桌太凌亂了，什麼都找不到。"},{"en":"The strong wind left her hair messy and tangled.","zh":"強風把她的頭髮吹得凌亂又打結。"}]},{"word":"metal","pos":"n.","phonetic":"[ˈmɛtəl]","meaning":"金屬","definition":"a solid material that is typically hard, shiny, and conducts electricity","collocations":["heavy metal","metal detector","made of metal"],"example":"The bridge is made of strong metal.","exampleZh":"這座橋是用堅固的金屬建造的。","synonyms":[],"level":2,"theme":"科學與數學","examples":[{"en":"The bridge is made of strong metal.","zh":"這座橋是用堅固的金屬建造的。"},{"en":"The old gate is made of heavy rusted metal.","zh":"那扇舊大門是用沉重生鏽的金屬做的。"},{"en":"Airport staff use a metal detector to check bags.","zh":"機場人員用金屬探測器檢查行李。"}]},{"word":"method","pos":"n.","phonetic":"[ˈmɛθəd]","meaning":"方法","definition":"a particular procedure for accomplishing something","collocations":["teaching method","scientific method","effective method"],"example":"This new method makes learning easier.","exampleZh":"這種新方法讓學習變得更容易。","synonyms":["approach","technique"],"level":3,"theme":"教育與學習","examples":[{"en":"This new method makes learning easier.","zh":"這種新方法讓學習變得更容易。"},{"en":"Scientists follow the scientific method to test their ideas.","zh":"科學家遵循科學方法來檢驗他們的想法。"},{"en":"This teaching method makes grammar much easier to learn.","zh":"這種教學方法讓文法更容易學習。"}]},{"word":"metropolitan","pos":"adj.","phonetic":"[ˌmɛtrəˈpɑlətən]","meaning":"大都市的","definition":"relating to a large city or urban area","collocations":["metropolitan area","metropolitan life","metropolitan population"],"example":"The metropolitan area has a population of five million.","exampleZh":"這個大都會區的人口有五百萬。","synonyms":["urban"],"level":6,"theme":"社會與文化","examples":[{"en":"The metropolitan area has a population of five million.","zh":"這個大都會區的人口有五百萬。"},{"en":"Life in a metropolitan area can be fast and stressful.","zh":"大都市地區的生活可能既快速又充滿壓力。"},{"en":"The metropolitan railway connects dozens of busy stations.","zh":"大都會鐵路連接了數十個繁忙的車站。"}]},{"word":"microphone","pos":"n.","phonetic":"[ˈmaɪkrəˌfon]","meaning":"麥克風","definition":"a device used to make sound louder or record it","collocations":["speak into a microphone","wireless microphone","test the microphone"],"example":"The singer held the microphone close to her mouth.","exampleZh":"歌手把麥克風靠近嘴邊。","synonyms":["mic"],"level":3,"theme":"科技與媒體","examples":[{"en":"The singer held the microphone close to her mouth.","zh":"歌手把麥克風靠近嘴邊。"},{"en":"Please speak clearly into the microphone so everyone hears you.","zh":"請對著麥克風清楚地說話，好讓大家都聽得到。"},{"en":"The technician tested the microphone before the speech began.","zh":"技術人員在演講開始前測試了麥克風。"}]},{"word":"microscope","pos":"n.","phonetic":"[ˈmaɪkrəˌskop]","meaning":"顯微鏡","definition":"an instrument used to view objects too small to see with the naked eye","collocations":["look through a microscope","electron microscope","under the microscope"],"example":"We examined the cells under a microscope.","exampleZh":"我們用顯微鏡觀察細胞。","synonyms":[],"level":3,"theme":"科學與數學","examples":[{"en":"We examined the cells under a microscope.","zh":"我們用顯微鏡觀察細胞。"},{"en":"Students looked through the microscope to observe tiny cells.","zh":"學生們透過顯微鏡觀察微小的細胞。"},{"en":"Under the microscope, the leaf revealed a complex pattern.","zh":"在顯微鏡下，那片葉子顯露出複雜的紋路。"}]},{"word":"microwave","pos":"n. / v.","phonetic":"[ˈmaɪkrəˌwev]","meaning":"微波爐；微波加熱","definition":"an oven that cooks or heats food using electromagnetic waves","collocations":["microwave oven","microwave dinner","heat in the microwave"],"example":"He heated the leftovers in the microwave.","exampleZh":"他用微波爐加熱剩菜。","synonyms":[],"level":2,"theme":"居家與生活","examples":[{"en":"He heated the leftovers in the microwave.","zh":"他用微波爐加熱剩菜。"},{"en":"Please microwave the soup for two minutes before serving.","zh":"上菜前請把湯用微波爐加熱兩分鐘。"},{"en":"A microwave oven can heat leftovers very quickly.","zh":"微波爐可以很快地加熱剩菜。"}]},{"word":"middle","pos":"n. / adj.","phonetic":"[ˈmɪdəl]","meaning":"中間的","definition":"the point or part equally distant from the edges or ends","collocations":["middle school","in the middle of","middle age"],"example":"She sat in the middle of the room.","exampleZh":"她坐在房間的中間。","synonyms":["center"],"level":1,"theme":"時間與空間","examples":[{"en":"She sat in the middle of the room.","zh":"她坐在房間的中間。"},{"en":"My younger sister just started middle school this year.","zh":"我妹妹今年剛開始上國中。"},{"en":"The phone rang in the middle of the night.","zh":"電話在半夜響了起來。"}]},{"word":"midnight","pos":"n.","phonetic":"[ˈmɪdˌnaɪt]","meaning":"午夜","definition":"twelve o'clock at night","collocations":["at midnight","midnight snack","past midnight"],"example":"We watched the fireworks at midnight.","exampleZh":"我們在午夜觀賞了煙火。","synonyms":[],"level":2,"theme":"時間與空間","examples":[{"en":"We watched the fireworks at midnight.","zh":"我們在午夜觀賞了煙火。"},{"en":"We stayed up until midnight to welcome the new year.","zh":"我們熬夜到午夜迎接新年。"},{"en":"He often enjoys a small midnight snack while studying.","zh":"他讀書時常常享用一點午夜點心。"}]},{"word":"might","pos":"v. / n.","phonetic":"[maɪt]","meaning":"可能；力量","definition":"used to express possibility; great strength or power","collocations":["might as well","with all one's might","might rain"],"example":"It might rain tomorrow, so bring an umbrella.","exampleZh":"明天可能會下雨，所以帶把傘吧。","synonyms":["power","force"],"level":2,"theme":"抽象概念","examples":[{"en":"It might rain tomorrow, so bring an umbrella.","zh":"明天可能會下雨，所以帶把傘吧。"},{"en":"You might catch a cold if you don't wear a jacket.","zh":"如果你不穿外套，可能會感冒。"},{"en":"The rescuers pulled the rope with all their might.","zh":"救援人員用盡全力拉著繩索。"}]},{"word":"mighty","pos":"adj.","phonetic":"[ˈmaɪtɪ]","meaning":"強大的","definition":"very strong or powerful","collocations":["mighty river","mighty nation","mighty warrior"],"example":"The mighty river flows through five countries.","exampleZh":"這條大河流經五個國家。","synonyms":["powerful"],"level":4,"theme":"性質與描述","examples":[{"en":"The mighty river flows through five countries.","zh":"這條大河流經五個國家。"},{"en":"The mighty river carved a deep valley over centuries.","zh":"這條強大的河流歷經數世紀刻鑿出一道深谷。"},{"en":"The mighty warrior protected the village from danger.","zh":"那位強大的戰士保護村莊免於危險。"}]},{"word":"migrate","pos":"v.","phonetic":"[ˈmaɪgret]","meaning":"遷徙；移居","definition":"to move from one place to another, especially seasonally","collocations":["migrate south","birds migrate","migrate to a new country"],"example":"Many birds migrate south for the winter.","exampleZh":"許多鳥類會在冬天遷徙到南方。","synonyms":["relocate"],"level":5,"theme":"動物與植物","examples":[{"en":"Many birds migrate south for the winter.","zh":"許多鳥類會在冬天遷徙到南方。"},{"en":"Some whales migrate thousands of kilometers each year.","zh":"有些鯨魚每年遷徙數千公里。"},{"en":"Her family decided to migrate to a new country.","zh":"她的家人決定移居到一個新的國家。"}]},{"word":"mild","pos":"adj.","phonetic":"[maɪld]","meaning":"溫和的","definition":"not severe, harsh, or extreme","collocations":["mild weather","mild flavor","mild reaction"],"example":"The weather has been mild this winter.","exampleZh":"今年冬天天氣一直很溫和。","synonyms":["gentle"],"level":4,"theme":"天氣與季節","examples":[{"en":"The weather has been mild this winter.","zh":"今年冬天天氣一直很溫和。"},{"en":"The soup has a mild flavor that children enjoy.","zh":"這道湯味道溫和，孩子們很喜歡。"},{"en":"We enjoyed the mild weather during our spring picnic.","zh":"我們在春季野餐時享受著溫和的天氣。"}]},{"word":"mile","pos":"n.","phonetic":"[maɪl]","meaning":"英里","definition":"a unit of distance equal to about 1.6 kilometers","collocations":["run a mile","miles away","mile marker"],"example":"The store is about two miles from here.","exampleZh":"那家店距離這裡大約兩英里。","synonyms":[],"level":2,"theme":"交通與旅行","examples":[{"en":"The store is about two miles from here.","zh":"那家店距離這裡大約兩英里。"},{"en":"The nearest train station is only a mile away.","zh":"最近的火車站只有一英里遠。"},{"en":"She trains hard to run a mile in six minutes.","zh":"她努力訓練，要在六分鐘內跑完一英里。"}]},{"word":"military","pos":"adj. / n.","phonetic":"[ˈmɪləˌtɛrɪ]","meaning":"軍事的；軍隊","definition":"relating to soldiers or the armed forces","collocations":["military base","military service","join the military"],"example":"He served in the military for ten years.","exampleZh":"他在軍隊服役了十年。","synonyms":["armed forces"],"level":4,"theme":"政治與法律","examples":[{"en":"He served in the military for ten years.","zh":"他在軍隊服役了十年。"},{"en":"His older brother decided to join the military after college.","zh":"他哥哥決定大學畢業後從軍。"},{"en":"The soldiers returned to the military base before sunset.","zh":"士兵們在日落前回到軍事基地。"}]},{"word":"mimic","pos":"v. / n.","phonetic":"[ˈmɪmɪk]","meaning":"模仿；模仿者","definition":"to imitate the way someone speaks or behaves","collocations":["mimic someone's accent","mimic a sound"],"example":"The parrot can mimic human speech perfectly.","exampleZh":"這隻鸚鵡能完美模仿人類的說話聲。","synonyms":["imitate","copy"],"level":4,"theme":"動作與行為","examples":[{"en":"The parrot can mimic human speech perfectly.","zh":"這隻鸚鵡能完美模仿人類的說話聲。"},{"en":"The comedian can mimic the accent of every region.","zh":"那位喜劇演員能模仿每個地區的口音。"},{"en":"Young children often mimic the behavior of their parents.","zh":"幼童常常模仿父母的行為。"}]},{"word":"mingle","pos":"v.","phonetic":"[ˈmɪŋɡḷ]","meaning":"混合；交際","definition":"to mix or move around socially with others","collocations":["mingle with guests","mingle at a party"],"example":"He mingled with the other guests at the reception.","exampleZh":"他在招待會上和其他賓客交際應酬。","synonyms":["mix","socialize"],"level":5,"theme":"溝通與語言","examples":[{"en":"He mingled with the other guests at the reception.","zh":"他在招待會上和其他賓客交際應酬。"},{"en":"She loves to mingle with new people at parties.","zh":"她喜歡在派對上和新朋友交際。"},{"en":"Guests mingled freely while soft music played.","zh":"在輕柔的音樂聲中，賓客們自在地交際往來。"}]},{"word":"minimal","pos":"adj.","phonetic":"[ˈmɪnɪmḷ]","meaning":"最小的；極少的","definition":"of a very small amount or degree","collocations":["minimal effort","minimal risk","minimal impact"],"example":"The new design requires minimal maintenance.","exampleZh":"這個新設計只需要極少的維護。","synonyms":["slight","negligible"],"level":4,"theme":"性質與描述","examples":[{"en":"The new design requires minimal maintenance.","zh":"這個新設計只需要極少的維護。"},{"en":"The project succeeded with minimal effort from the team.","zh":"這個專案在團隊極少的努力下就成功了。"},{"en":"Choose a plant that needs minimal water and sunlight.","zh":"選一種只需極少水分和陽光的植物。"}]},{"word":"minimize","pos":"v.","phonetic":"[ˈmɪnəˌmaɪz]","meaning":"使減到最少；最小化","definition":"to reduce something to the smallest possible amount","collocations":["minimize risk","minimize damage","minimize costs"],"example":"We should minimize waste whenever possible.","exampleZh":"我們應該盡可能減少浪費。","synonyms":["reduce","lessen"],"level":4,"theme":"抽象概念","examples":[{"en":"We should minimize waste whenever possible.","zh":"我們應該盡可能減少浪費。"},{"en":"Wearing a helmet helps minimize the risk of head injury.","zh":"戴安全帽有助於將頭部受傷的風險降到最低。"},{"en":"The company tried to minimize costs during the crisis.","zh":"公司在危機期間設法將成本降到最低。"}]},{"word":"minister","pos":"n.","phonetic":"[ˈmɪnɪstɚ]","meaning":"部長；牧師","definition":"a senior government official or head of a religious congregation","collocations":["prime minister","foreign minister"],"example":"The minister announced a new education policy.","exampleZh":"部長宣布了一項新的教育政策。","synonyms":["official","secretary"],"level":4,"theme":"政治與法律","examples":[{"en":"The minister announced a new education policy.","zh":"部長宣布了一項新的教育政策。"},{"en":"The prime minister answered questions from reporters calmly.","zh":"首相冷靜地回答記者的問題。"},{"en":"The minister prayed with the family at the funeral.","zh":"牧師在葬禮上與那家人一起禱告。"}]},{"word":"ministry","pos":"n.","phonetic":"[ˈmɪnɪstri]","meaning":"部；部門","definition":"a government department headed by a minister","collocations":["ministry of education","ministry of health"],"example":"The ministry is responsible for public transportation.","exampleZh":"該部門負責公共運輸事務。","synonyms":["department","bureau"],"level":4,"theme":"政治與法律","examples":[{"en":"The ministry is responsible for public transportation.","zh":"該部門負責公共運輸事務。"},{"en":"The Ministry of Education announced a new school schedule.","zh":"教育部宣布了新的上學時間表。"},{"en":"The Ministry of Health promotes healthy eating habits.","zh":"衛生部推廣健康的飲食習慣。"}]},{"word":"minor","pos":"adj. / n.","phonetic":"[ˈmaɪnɚ]","meaning":"較小的；未成年人","definition":"not very important, serious, or dangerous; a person under legal age","collocations":["minor injury","minor issue","protect minors"],"example":"She suffered only minor injuries in the accident.","exampleZh":"她在意外中只受了輕傷。","synonyms":["slight","insignificant"],"level":3,"theme":"性質與描述","examples":[{"en":"She suffered only minor injuries in the accident.","zh":"她在意外中只受了輕傷。"},{"en":"Luckily, the car accident caused only minor damage.","zh":"幸運的是，這場車禍只造成輕微的損壞。"},{"en":"The law protects minors from dangerous working conditions.","zh":"法律保護未成年人免於危險的工作環境。"}]},{"word":"minority","pos":"n.","phonetic":"[maɪˈnɔrəti]","meaning":"少數；少數族群","definition":"the smaller part of a group, or a small group different from the rest","collocations":["ethnic minority","in the minority"],"example":"Only a minority of students disagreed with the plan.","exampleZh":"只有少數學生反對這項計畫。","synonyms":["few"],"level":4,"theme":"社會與文化","examples":[{"en":"Only a minority of students disagreed with the plan.","zh":"只有少數學生反對這項計畫。"},{"en":"Only a small minority of voters opposed the new park.","zh":"只有少數選民反對這座新公園。"},{"en":"The school celebrates the culture of every ethnic minority.","zh":"學校讚揚每個少數族群的文化。"}]},{"word":"minus","pos":"prep. / adj. / n.","phonetic":"[ˈmaɪnəs]","meaning":"減；負的；減號","definition":"reduced by the subtraction of; below zero","collocations":["minus sign","ten minus three","minus degrees"],"example":"Ten minus four equals six.","exampleZh":"十減四等於六。","synonyms":["less"],"level":2,"theme":"科學與數學","examples":[{"en":"Ten minus four equals six.","zh":"十減四等於六。"},{"en":"Twenty minus eight leaves twelve.","zh":"二十減八剩下十二。"},{"en":"The temperature dropped to minus five degrees last night.","zh":"昨晚氣溫降到零下五度。"}]},{"word":"minute","pos":"adj.","phonetic":"[maɪˈnjut]","meaning":"極小的；微小的","definition":"extremely small in size or amount","collocations":["minute detail","a minute amount"],"example":"She noticed the minute differences between the two paintings.","exampleZh":"她注意到這兩幅畫之間的細微差異。","synonyms":["tiny","microscopic"],"level":5,"theme":"性質與描述","examples":[{"en":"She noticed the minute differences between the two paintings.","zh":"她注意到這兩幅畫之間的細微差異。"},{"en":"The scientist examined the minute cracks in the glass.","zh":"科學家檢查玻璃上細微的裂縫。"},{"en":"Even a minute amount of salt can change the taste.","zh":"即使是極少量的鹽也能改變味道。"}]},{"word":"miracle","pos":"n.","phonetic":"[ˈmɪrəkḷ]","meaning":"奇蹟","definition":"an extraordinary and welcome event that seems impossible","collocations":["a miracle cure","by a miracle","work a miracle"],"example":"It was a miracle that no one was hurt in the crash.","exampleZh":"沒有人在這場車禍中受傷真是奇蹟。","synonyms":["wonder","marvel"],"level":3,"theme":"抽象概念","examples":[{"en":"It was a miracle that no one was hurt in the crash.","zh":"沒有人在這場車禍中受傷真是奇蹟。"},{"en":"It was a miracle that everyone survived the earthquake.","zh":"每個人都在地震中生還，真是個奇蹟。"},{"en":"The doctors hoped for a miracle to save the patient.","zh":"醫生們盼望有個奇蹟能救活這名病患。"}]},{"word":"miraculous","pos":"adj.","phonetic":"[məˈrækjələs]","meaning":"奇蹟般的","definition":"remarkable and surprising, like a miracle","collocations":["miraculous recovery","miraculous escape"],"example":"Doctors called her recovery miraculous.","exampleZh":"醫生們稱她的康復是奇蹟。","synonyms":["astonishing","incredible"],"level":5,"theme":"性質與描述","examples":[{"en":"Doctors called her recovery miraculous.","zh":"醫生們稱她的康復是奇蹟。"},{"en":"The patient made a miraculous recovery after the surgery.","zh":"這名病患在手術後奇蹟般地康復了。"},{"en":"Their miraculous escape from the fire amazed everyone.","zh":"他們奇蹟般地逃離火場，令所有人驚訝。"}]},{"word":"mirror","pos":"n. / v.","phonetic":"[ˈmɪrɚ]","meaning":"鏡子；反映","definition":"a reflective surface; to reflect or resemble closely","collocations":["look in the mirror","rearview mirror","mirror reality"],"example":"The lake surface mirrored the mountains perfectly.","exampleZh":"湖面完美地映照出群山的倒影。","synonyms":["reflect"],"level":2,"theme":"居家與生活","examples":[{"en":"The lake surface mirrored the mountains perfectly.","zh":"湖面完美地映照出群山的倒影。"},{"en":"She checked her hair in the mirror before leaving.","zh":"她出門前在鏡子裡檢查了頭髮。"},{"en":"His kind actions mirror the values his parents taught him.","zh":"他善良的行為反映了父母教給他的價值觀。"}]},{"word":"miscellaneous","pos":"adj.","phonetic":"[ˌmɪsəˈleniəs]","meaning":"各式各樣的；雜項的","definition":"consisting of various types not easily classified together","collocations":["miscellaneous items","miscellaneous expenses"],"example":"The drawer was full of miscellaneous tools and parts.","exampleZh":"抽屜裡裝滿了各式各樣的工具和零件。","synonyms":["various","assorted"],"level":6,"theme":"性質與描述","examples":[{"en":"The drawer was full of miscellaneous tools and parts.","zh":"抽屜裡裝滿了各式各樣的工具和零件。"},{"en":"The box was filled with miscellaneous items from the attic.","zh":"那個箱子裝滿了閣樓裡各式各樣的雜物。"},{"en":"She keeps a small budget for miscellaneous expenses each month.","zh":"她每月保留一小筆預算用於雜項支出。"}]},{"word":"mischief","pos":"n.","phonetic":"[ˈmɪstʃɪf]","meaning":"惡作劇；淘氣","definition":"playful misbehavior, especially by children","collocations":["get into mischief","full of mischief"],"example":"The twins were always getting into mischief.","exampleZh":"這對雙胞胎總是在惡作劇。","synonyms":["prank","naughtiness"],"level":5,"theme":"情緒與感受","examples":[{"en":"The twins were always getting into mischief.","zh":"這對雙胞胎總是在惡作劇。"},{"en":"The kitten was full of mischief and knocked over the vase.","zh":"那隻小貓十分淘氣，把花瓶打翻了。"},{"en":"The boys got into mischief while their teacher was away.","zh":"老師不在時，男孩們搞起了惡作劇。"}]},{"word":"mischievous","pos":"adj.","phonetic":"[ˈmɪstʃɪvəs]","meaning":"淘氣的；惡作劇的","definition":"playfully causing trouble or annoyance","collocations":["mischievous grin","mischievous child"],"example":"He gave a mischievous smile before hiding her keys.","exampleZh":"他露出淘氣的笑容,然後把她的鑰匙藏了起來。","synonyms":["naughty","impish"],"level":5,"theme":"情緒與感受","examples":[{"en":"He gave a mischievous smile before hiding her keys.","zh":"他露出淘氣的笑容,然後把她的鑰匙藏了起來。"},{"en":"The mischievous child hid his sister's shoes for fun.","zh":"那個淘氣的孩子為了好玩把姊姊的鞋子藏起來。"},{"en":"She gave a mischievous grin before telling the joke.","zh":"她在說笑話前露出淘氣的笑容。"}]},{"word":"miser","pos":"n.","phonetic":"[ˈmaɪzɚ]","meaning":"守財奴；吝嗇鬼","definition":"a person who hoards money and spends as little as possible","collocations":["a stingy miser","act like a miser"],"example":"The old miser never bought new clothes.","exampleZh":"那個老守財奴從不買新衣服。","synonyms":["scrooge"],"level":6,"theme":"人物與家庭","examples":[{"en":"The old miser never bought new clothes.","zh":"那個老守財奴從不買新衣服。"},{"en":"The lonely miser refused to share even a single coin.","zh":"那個孤獨的守財奴連一枚硬幣都不肯分享。"},{"en":"Don't act like a miser; treat your friends sometimes.","zh":"別像個吝嗇鬼，偶爾請請你的朋友。"}]},{"word":"miserable","pos":"adj.","phonetic":"[ˈmɪzərəbḷ]","meaning":"悲慘的；痛苦的","definition":"very unhappy or uncomfortable","collocations":["feel miserable","miserable weather","miserable life"],"example":"He felt miserable after losing his job.","exampleZh":"失業後他覺得很痛苦。","synonyms":["wretched","unhappy"],"level":4,"theme":"情緒與感受","examples":[{"en":"He felt miserable after losing his job.","zh":"失業後他覺得很痛苦。"},{"en":"She felt miserable after catching a cold on her birthday.","zh":"生日當天感冒讓她覺得很難受。"},{"en":"The cold, rainy weather made everyone feel miserable.","zh":"又冷又下雨的天氣讓每個人都覺得難受。"}]},{"word":"misery","pos":"n.","phonetic":"[ˈmɪzəri]","meaning":"痛苦；悲慘","definition":"a state of great suffering or unhappiness","collocations":["live in misery","end someone's misery"],"example":"The war brought misery to millions of people.","exampleZh":"這場戰爭為數百萬人帶來了痛苦。","synonyms":["suffering","distress"],"level":4,"theme":"情緒與感受","examples":[{"en":"The war brought misery to millions of people.","zh":"這場戰爭為數百萬人帶來了痛苦。"},{"en":"The long drought brought misery to the poor farmers.","zh":"長期乾旱為貧窮的農民帶來了苦難。"},{"en":"A cup of hot tea eased her misery on that cold night.","zh":"一杯熱茶在那個寒冷的夜裡減輕了她的痛苦。"}]},{"word":"misfortune","pos":"n.","phonetic":"[ˌmɪsˈfɔrtʃən]","meaning":"不幸；厄運","definition":"bad luck or an unlucky event","collocations":["have the misfortune to","a series of misfortunes"],"example":"She had the misfortune to lose her passport abroad.","exampleZh":"她不幸在國外弄丟了護照。","synonyms":["bad luck","hardship"],"level":5,"theme":"抽象概念","examples":[{"en":"She had the misfortune to lose her passport abroad.","zh":"她不幸在國外弄丟了護照。"},{"en":"He had the misfortune to break his leg before the game.","zh":"他很不幸在比賽前摔斷了腿。"},{"en":"A series of misfortunes nearly ruined the family business.","zh":"一連串的不幸幾乎毀了這個家族企業。"}]},{"word":"mislead","pos":"v.","phonetic":"[mɪsˈlid]","meaning":"誤導；欺騙","definition":"to give someone a false impression or wrong idea","collocations":["mislead the public","misleading information"],"example":"The advertisement misled customers about the product's price.","exampleZh":"這則廣告在價格上誤導了顧客。","synonyms":["deceive","fool"],"level":5,"theme":"溝通與語言","examples":[{"en":"The advertisement misled customers about the product's price.","zh":"這則廣告在價格上誤導了顧客。"},{"en":"The confusing sign misled tourists onto the wrong path.","zh":"那個令人困惑的標誌把遊客誤導到錯誤的路上。"},{"en":"Companies must not mislead the public with false claims.","zh":"公司不得以不實的說法誤導大眾。"}]},{"word":"misplace","pos":"v.","phonetic":"[mɪsˈples]","meaning":"放錯地方；遺失","definition":"to put something in the wrong place and be unable to find it","collocations":["misplace your keys","misplace trust"],"example":"I misplaced my glasses again this morning.","exampleZh":"我今天早上又把眼鏡放錯地方找不到了。","synonyms":["lose","mislay"],"level":4,"theme":"動作與行為","examples":[{"en":"I misplaced my glasses again this morning.","zh":"我今天早上又把眼鏡放錯地方找不到了。"},{"en":"I always misplace my keys when I'm in a hurry.","zh":"我趕時間時總是把鑰匙放錯地方。"},{"en":"He misplaced his ticket and missed the early train.","zh":"他弄丟了車票，錯過了早班火車。"}]},{"word":"missile","pos":"n.","phonetic":"[ˈmɪsḷ]","meaning":"飛彈；導彈","definition":"a weapon that is self-propelled and guided to its target","collocations":["launch a missile","guided missile"],"example":"The country tested a new long-range missile.","exampleZh":"該國測試了一枚新型長程飛彈。","synonyms":["rocket"],"level":5,"theme":"政治與法律","examples":[{"en":"The country tested a new long-range missile.","zh":"該國測試了一枚新型長程飛彈。"},{"en":"The army successfully launched a missile during the test.","zh":"軍隊在測試中成功發射了一枚飛彈。"},{"en":"A guided missile can strike targets far away.","zh":"導引飛彈能擊中遠處的目標。"}]},{"word":"mist","pos":"n.","phonetic":"[mɪst]","meaning":"薄霧；水氣","definition":"a thin cloud of tiny water droplets near the ground","collocations":["morning mist","mist rolls in"],"example":"A light mist covered the valley at dawn.","exampleZh":"清晨時薄霧籠罩著山谷。","synonyms":["fog","haze"],"level":3,"theme":"天氣與季節","examples":[{"en":"A light mist covered the valley at dawn.","zh":"清晨時薄霧籠罩著山谷。"},{"en":"A thin mist covered the mountains early in the morning.","zh":"清晨時分，一層薄霧籠罩著群山。"},{"en":"As the mist rolled in, the harbor slowly disappeared.","zh":"隨著薄霧湧入，港口慢慢消失了。"}]},{"word":"mistake","pos":"n. / v.","phonetic":"[məˈstek]","meaning":"錯誤；弄錯","definition":"an action or judgment that is incorrect","collocations":["make a mistake","by mistake","mistake one for another"],"example":"It was a mistake to sign the contract without reading it.","exampleZh":"沒讀就簽約是個錯誤。","synonyms":["error","blunder"],"level":2,"theme":"抽象概念","examples":[{"en":"It was a mistake to sign the contract without reading it.","zh":"沒讀就簽約是個錯誤。"},{"en":"Everyone makes a mistake now and then, so don't worry.","zh":"每個人偶爾都會犯錯，所以別擔心。"},{"en":"She took my umbrella by mistake this morning.","zh":"她今天早上錯拿了我的雨傘。"}]},{"word":"mistress","pos":"n.","phonetic":"[ˈmɪstrɪs]","meaning":"女主人；情婦","definition":"a woman in a position of authority or control; a woman having an affair with a married man","collocations":["mistress of the house"],"example":"The mistress of the house welcomed the guests warmly.","exampleZh":"女主人熱情地歡迎賓客。","synonyms":["lady"],"level":6,"theme":"人物與家庭","examples":[{"en":"The mistress of the house welcomed the guests warmly.","zh":"女主人熱情地歡迎賓客。"},{"en":"The mistress of the house prepared tea for her guests.","zh":"這家的女主人為客人準備了茶。"},{"en":"The loyal dog followed its mistress everywhere she went.","zh":"那隻忠心的狗跟著女主人到處走。"}]},{"word":"misunderstand","pos":"v.","phonetic":"[ˌmɪsʌndɚˈstænd]","meaning":"誤解；誤會","definition":"to fail to understand something correctly","collocations":["misunderstand a question","easily misunderstood"],"example":"Please don't misunderstand my intentions.","exampleZh":"請不要誤會我的意圖。","synonyms":["misinterpret"],"level":3,"theme":"溝通與語言","examples":[{"en":"Please don't misunderstand my intentions.","zh":"請不要誤會我的意圖。"},{"en":"Please don't misunderstand me; I only wanted to help.","zh":"請別誤會我，我只是想幫忙。"},{"en":"His silence was easily misunderstood as anger.","zh":"他的沉默很容易被誤解為生氣。"}]},{"word":"mitigate","pos":"v.","phonetic":"[ˈmɪtəˌɡet]","meaning":"減輕；緩和","definition":"to make something less severe or harmful","collocations":["mitigate risk","mitigate the effects of"],"example":"The government introduced measures to mitigate air pollution.","exampleZh":"政府採取措施以減輕空氣污染。","synonyms":["alleviate","ease"],"level":6,"theme":"抽象概念","examples":[{"en":"The government introduced measures to mitigate air pollution.","zh":"政府採取措施以減輕空氣污染。"},{"en":"Planting more trees can help mitigate the effects of pollution.","zh":"種植更多樹木有助於減輕污染的影響。"},{"en":"The city built walls to mitigate the risk of flooding.","zh":"這座城市築起牆來減輕淹水的風險。"}]},{"word":"mixture","pos":"n.","phonetic":"[ˈmɪkstʃɚ]","meaning":"混合物；混合","definition":"a combination of different things or substances","collocations":["a mixture of","cake mixture"],"example":"The soup is a mixture of vegetables and spices.","exampleZh":"這道湯是蔬菜和香料的混合物。","synonyms":["blend","combination"],"level":3,"theme":"食物與烹飪","examples":[{"en":"The soup is a mixture of vegetables and spices.","zh":"這道湯是蔬菜和香料的混合物。"},{"en":"The cake mixture should be smooth before you bake it.","zh":"蛋糕麵糊在烘烤前應該要滑順。"},{"en":"Her face showed a mixture of joy and surprise.","zh":"她的臉上流露出喜悅與驚訝交織的神情。"}]},{"word":"mnemonic","pos":"n. / adj.","phonetic":"[nɪˈmɑnɪk]","meaning":"記憶術；助記的","definition":"a technique that helps you remember something","collocations":["mnemonic device","use a mnemonic","memory mnemonic"],"example":"Students often use a mnemonic to remember the order of colors.","exampleZh":"學生常用記憶術來記住顏色的順序。","synonyms":[],"level":6,"theme":"教育與學習","examples":[{"en":"Students often use a mnemonic to remember the order of colors.","zh":"學生常用記憶術來記住顏色的順序。"},{"en":"Our teacher taught us a mnemonic to remember the planets.","zh":"老師教我們一個記住行星順序的記憶口訣。"},{"en":"A good mnemonic device makes long lists easier to recall.","zh":"好的助記法讓長長的清單更容易記住。"}]},{"word":"moan","pos":"v. / n.","phonetic":"[mon]","meaning":"呻吟；抱怨","definition":"to make a long, low sound expressing pain or complaint","collocations":["moan in pain","moan about something"],"example":"He moaned softly as the nurse cleaned his wound.","exampleZh":"護士清理他的傷口時,他輕輕呻吟著。","synonyms":["groan","complain"],"level":4,"theme":"身體與健康","examples":[{"en":"He moaned softly as the nurse cleaned his wound.","zh":"護士清理他的傷口時,他輕輕呻吟著。"},{"en":"The sick child began to moan softly in his sleep.","zh":"生病的孩子在睡夢中開始輕輕呻吟。"},{"en":"He always moans about the homework instead of doing it.","zh":"他總是抱怨作業，而不去做。"}]},{"word":"mobile","pos":"adj.","phonetic":"[ˈmobl̩]","meaning":"可移動的；行動的","definition":"able to move or be moved easily","collocations":["mobile phone","mobile home","highly mobile"],"example":"She uses her mobile phone to check messages all day.","exampleZh":"她整天都用手機查看訊息。","synonyms":["movable","portable"],"level":2,"theme":"科技與媒體","examples":[{"en":"She uses her mobile phone to check messages all day.","zh":"她整天都用手機查看訊息。"},{"en":"Please turn off your mobile phone during the exam.","zh":"考試期間請關掉你的手機。"},{"en":"The clinic uses a mobile unit to reach rural villages.","zh":"這家診所用行動醫療車前往偏遠村莊。"}]},{"word":"mobilize","pos":"v.","phonetic":"[ˈmobəˌlaɪz]","meaning":"動員；調動","definition":"to organize people or resources for action","collocations":["mobilize troops","mobilize support","mobilize resources"],"example":"The government mobilized volunteers to help after the flood.","exampleZh":"政府動員志工在水災後提供協助。","synonyms":["organize","rally"],"level":5,"theme":"社會與文化","examples":[{"en":"The government mobilized volunteers to help after the flood.","zh":"政府動員志工在水災後提供協助。"},{"en":"Volunteers were mobilized to clean up the polluted beach.","zh":"志工被動員起來清理受污染的海灘。"},{"en":"The coach mobilized the whole team for extra practice.","zh":"教練調動全隊進行額外練習。"}]},{"word":"mock","pos":"v. / adj.","phonetic":"[mɑk]","meaning":"嘲笑；模擬的","definition":"to make fun of someone; not real, imitation","collocations":["mock exam","mock someone","mock trial"],"example":"The students took a mock exam before the real test.","exampleZh":"學生們在正式考試前先做了一次模擬考。","synonyms":["ridicule","imitation"],"level":4,"theme":"教育與學習","examples":[{"en":"The students took a mock exam before the real test.","zh":"學生們在正式考試前先做了一次模擬考。"},{"en":"We took a mock exam to prepare for the real one.","zh":"我們做了一次模擬考來準備正式考試。"},{"en":"It's cruel to mock someone for their accent.","zh":"因為口音而嘲笑別人是很殘忍的。"}]},{"word":"mode","pos":"n.","phonetic":"[mod]","meaning":"方式；模式","definition":"a particular way or style of doing something","collocations":["mode of transport","silent mode","in a mode"],"example":"Please switch your phone to silent mode during the meeting.","exampleZh":"開會期間請把手機切換成靜音模式。","synonyms":["manner","method"],"level":4,"theme":"科技與媒體","examples":[{"en":"Please switch your phone to silent mode during the meeting.","zh":"開會期間請把手機切換成靜音模式。"},{"en":"The train is my favorite mode of transport.","zh":"火車是我最喜愛的交通方式。"},{"en":"Remember to set your phone to silent mode in class.","zh":"上課時記得把手機設為靜音模式。"}]},{"word":"model","pos":"n. / v.","phonetic":"[ˈmɑdl̩]","meaning":"模型；模特兒；作為榜樣","definition":"a representation of something, or a person who displays clothes","collocations":["role model","fashion model","build a model"],"example":"She is a good role model for young students.","exampleZh":"她是年輕學生的好榜樣。","synonyms":["example","prototype"],"level":2,"theme":"人物與家庭","examples":[{"en":"She is a good role model for young students.","zh":"她是年輕學生的好榜樣。"},{"en":"The students built a model of the solar system.","zh":"學生們製作了一個太陽系的模型。"},{"en":"A famous fashion model wore the designer's newest dress.","zh":"一位知名的時裝模特兒穿上了設計師的最新洋裝。"}]},{"word":"moderate","pos":"adj. / v.","phonetic":"[ˈmɑdərɪt]","meaning":"適度的；溫和的；緩和","definition":"average in amount or degree; not extreme","collocations":["moderate exercise","moderate temperature","moderate a discussion"],"example":"Doctors recommend moderate exercise every day.","exampleZh":"醫生建議每天做適度的運動。","synonyms":["reasonable","average"],"level":5,"theme":"性質與描述","examples":[{"en":"Doctors recommend moderate exercise every day.","zh":"醫生建議每天做適度的運動。"},{"en":"The teacher agreed to moderate the class debate fairly.","zh":"老師同意公平地主持班上的辯論。"},{"en":"A moderate amount of sunshine is good for your health.","zh":"適度的陽光對你的健康有益。"}]},{"word":"modern","pos":"adj.","phonetic":"[ˈmɑdɚn]","meaning":"現代的；新式的","definition":"relating to the present time, not the past","collocations":["modern technology","modern society","modern art"],"example":"Modern technology has changed the way we communicate.","exampleZh":"現代科技已經改變了我們溝通的方式。","synonyms":["contemporary","current"],"level":2,"theme":"科技與媒體","examples":[{"en":"Modern technology has changed the way we communicate.","zh":"現代科技已經改變了我們溝通的方式。"},{"en":"The museum displays both ancient pottery and modern art.","zh":"這座博物館同時展出古代陶器與現代藝術。"},{"en":"Modern society depends heavily on the internet.","zh":"現代社會高度依賴網際網路。"}]},{"word":"modernize","pos":"v.","phonetic":"[ˈmɑdɚˌnaɪz]","meaning":"使現代化","definition":"to make something more modern","collocations":["modernize a factory","modernize equipment","modernize the system"],"example":"The company plans to modernize its factories next year.","exampleZh":"這家公司計畫明年將工廠現代化。","synonyms":["update","upgrade"],"level":5,"theme":"科技與媒體","examples":[{"en":"The company plans to modernize its factories next year.","zh":"這家公司計畫明年將工廠現代化。"},{"en":"The city plans to modernize its old public library.","zh":"這座城市計畫將老舊的公共圖書館現代化。"},{"en":"Farmers modernized their tools to grow more crops.","zh":"農民更新工具，以種植更多作物。"}]},{"word":"modest","pos":"adj.","phonetic":"[ˈmɑdɪst]","meaning":"謙虛的；適度的","definition":"not talking much about one's own abilities; not large","collocations":["stay modest","modest income","modest success"],"example":"Despite his success, he remains modest and kind.","exampleZh":"儘管他成功了，他仍然謙虛又善良。","synonyms":["humble","moderate"],"level":4,"theme":"性質與描述","examples":[{"en":"Despite his success, he remains modest and kind.","zh":"儘管他成功了，他仍然謙虛又善良。"},{"en":"Although she won the prize, she stayed modest about it.","zh":"雖然她得了獎，卻對此保持謙虛。"},{"en":"They live comfortably on a modest income.","zh":"他們靠著適度的收入過著舒適的生活。"}]},{"word":"modify","pos":"v.","phonetic":"[ˈmɑdəˌfaɪ]","meaning":"修改；調整","definition":"to change something slightly","collocations":["modify a plan","modify behavior","modify a design"],"example":"We need to modify our plan due to the weather.","exampleZh":"由於天氣因素，我們需要修改計畫。","synonyms":["adjust","alter"],"level":4,"theme":"動作與行為","examples":[{"en":"We need to modify our plan due to the weather.","zh":"由於天氣因素，我們需要修改計畫。"},{"en":"We had to modify our travel plan because of the storm.","zh":"由於暴風雨，我們必須修改旅行計畫。"},{"en":"The engineer modified the design to make it safer.","zh":"工程師修改了設計，使它更安全。"}]},{"word":"moist","pos":"adj.","phonetic":"[mɔɪst]","meaning":"潮濕的","definition":"slightly wet","collocations":["moist soil","moist air","moist skin"],"example":"The soil felt moist after the rain.","exampleZh":"下雨過後，土壤摸起來濕濕的。","synonyms":["damp","humid"],"level":2,"theme":"自然與環境","examples":[{"en":"The soil felt moist after the rain.","zh":"下雨過後，土壤摸起來濕濕的。"},{"en":"Keep the towel moist so the plant stays cool.","zh":"讓毛巾保持潮濕，好讓植物保持涼爽。"},{"en":"The cake was soft and moist, just the way I like it.","zh":"這蛋糕柔軟又濕潤，正是我喜歡的樣子。"}]},{"word":"moisture","pos":"n.","phonetic":"[ˈmɔɪstʃɚ]","meaning":"濕氣；水分","definition":"small amounts of water in the air or in a substance","collocations":["retain moisture","moisture in the air","lack of moisture"],"example":"The greenhouse keeps moisture in the air for the plants.","exampleZh":"溫室能為植物保持空氣中的濕氣。","synonyms":["dampness","humidity"],"level":3,"theme":"自然與環境","examples":[{"en":"The greenhouse keeps moisture in the air for the plants.","zh":"溫室能為植物保持空氣中的濕氣。"},{"en":"The dry air removed all the moisture from her skin.","zh":"乾燥的空氣帶走了她皮膚所有的水分。"},{"en":"These plants need soil that retains moisture well.","zh":"這些植物需要能好好保持水分的土壤。"}]},{"word":"moisturize","pos":"v.","phonetic":"[ˈmɔɪstʃəˌraɪz]","meaning":"滋潤；保濕","definition":"to add moisture to the skin","collocations":["moisturize your skin","moisturize daily","moisturizing cream"],"example":"You should moisturize your skin every night before bed.","exampleZh":"你應該每晚睡前為皮膚保濕。","synonyms":["hydrate"],"level":5,"theme":"身體與健康","examples":[{"en":"You should moisturize your skin every night before bed.","zh":"你應該每晚睡前為皮膚保濕。"},{"en":"You should moisturize your hands after washing them.","zh":"洗手後你應該為雙手保濕。"},{"en":"This cream helps moisturize dry, cracked skin.","zh":"這款乳霜有助於滋潤乾燥龜裂的皮膚。"}]},{"word":"molecular","pos":"adj.","phonetic":"[məˈlɛkjəlɚ]","meaning":"分子的","definition":"relating to molecules","collocations":["molecular structure","molecular biology","molecular level"],"example":"Scientists study diseases at the molecular level.","exampleZh":"科學家在分子層級研究疾病。","synonyms":[],"level":6,"theme":"科學與數學","examples":[{"en":"Scientists study diseases at the molecular level.","zh":"科學家在分子層級研究疾病。"},{"en":"The class learned about the molecular structure of water.","zh":"這堂課學到了水的分子結構。"},{"en":"Researchers study genes at the molecular level.","zh":"研究人員在分子層次上研究基因。"}]},{"word":"molecule","pos":"n.","phonetic":"[ˈmɑləˌkjul]","meaning":"分子","definition":"the smallest unit of a substance that has its chemical properties","collocations":["water molecule","molecule structure","tiny molecule"],"example":"A water molecule contains two hydrogen atoms and one oxygen atom.","exampleZh":"一個水分子含有兩個氫原子和一個氧原子。","synonyms":[],"level":5,"theme":"科學與數學","examples":[{"en":"A water molecule contains two hydrogen atoms and one oxygen atom.","zh":"一個水分子含有兩個氫原子和一個氧原子。"},{"en":"Every water molecule is far too small to see.","zh":"每個水分子都小到肉眼無法看見。"},{"en":"Scientists broke the molecule into smaller parts.","zh":"科學家把這個分子分解成更小的部分。"}]},{"word":"moment","pos":"n.","phonetic":"[ˈmomənt]","meaning":"片刻；瞬間","definition":"a very short period of time","collocations":["at the moment","for a moment","a special moment"],"example":"Please wait a moment while I check the schedule.","exampleZh":"請稍等片刻，我確認一下行程。","synonyms":["instant","second"],"level":1,"theme":"時間與空間","examples":[{"en":"Please wait a moment while I check the schedule.","zh":"請稍等片刻，我確認一下行程。"},{"en":"Please wait a moment while I find your file.","zh":"請稍等片刻，我找一下你的檔案。"},{"en":"For a moment, everyone in the room fell silent.","zh":"有那麼一瞬間，房裡的每個人都安靜下來。"}]},{"word":"momentary","pos":"adj.","phonetic":"[ˈmomənˌtɛri]","meaning":"短暫的；瞬間的","definition":"lasting for a very short time","collocations":["momentary silence","momentary pause","momentary lapse"],"example":"There was a momentary silence before the applause began.","exampleZh":"在掌聲響起前有短暫的寂靜。","synonyms":["brief","fleeting"],"level":5,"theme":"時間與空間","examples":[{"en":"There was a momentary silence before the applause began.","zh":"在掌聲響起前有短暫的寂靜。"},{"en":"A momentary pause let the speaker catch her breath.","zh":"短暫的停頓讓講者得以喘口氣。"},{"en":"His momentary confusion quickly turned into understanding.","zh":"他瞬間的困惑很快變成了理解。"}]},{"word":"momentum","pos":"n.","phonetic":"[moˈmɛntəm]","meaning":"動力；氣勢","definition":"the force that keeps an object moving or a process developing","collocations":["gain momentum","lose momentum","build momentum"],"example":"The campaign gained momentum after the news coverage.","exampleZh":"這場活動在新聞報導後聲勢大增。","synonyms":["impetus","drive"],"level":6,"theme":"抽象概念","examples":[{"en":"The campaign gained momentum after the news coverage.","zh":"這場活動在新聞報導後聲勢大增。"},{"en":"The fundraising campaign slowly began to gain momentum.","zh":"這場募款活動慢慢開始蓄積氣勢。"},{"en":"The team lost momentum after the injury of their captain.","zh":"隊長受傷後，球隊失去了氣勢。"}]},{"word":"monarch","pos":"n.","phonetic":"[ˈmɑnɚk]","meaning":"君主；國王／女王","definition":"a king or queen who rules a country","collocations":["reigning monarch","the monarch's palace","become a monarch"],"example":"The monarch has ruled the country for over thirty years.","exampleZh":"這位君主已經統治這個國家超過三十年。","synonyms":["ruler","sovereign"],"level":6,"theme":"政治與法律","examples":[{"en":"The monarch has ruled the country for over thirty years.","zh":"這位君主已經統治這個國家超過三十年。"},{"en":"The young monarch promised to serve his people faithfully.","zh":"這位年輕的君主承諾要忠誠地為人民服務。"},{"en":"Crowds gathered outside the reigning monarch's palace.","zh":"群眾聚集在在位君主的宮殿外。"}]},{"word":"monastery","pos":"n.","phonetic":"[ˈmɑnəˌstɛri]","meaning":"修道院","definition":"a building where monks live together","collocations":["visit a monastery","live in a monastery","ancient monastery"],"example":"The monks have lived in this monastery for centuries.","exampleZh":"這些僧侶已在這座修道院居住了好幾個世紀。","synonyms":[],"level":6,"theme":"社會與文化","examples":[{"en":"The monks have lived in this monastery for centuries.","zh":"這些僧侶已在這座修道院居住了好幾個世紀。"},{"en":"The travelers stayed one night in a quiet mountain monastery.","zh":"旅人們在一座寧靜的山中修道院過了一夜。"},{"en":"Monks have prayed in this ancient monastery for centuries.","zh":"僧侶們在這座古老的修道院裡祈禱了數個世紀。"}]},{"word":"monetary","pos":"adj.","phonetic":"[ˈmɑnəˌtɛri]","meaning":"貨幣的；金錢的","definition":"relating to money","collocations":["monetary policy","monetary value","monetary system"],"example":"The bank changed its monetary policy last month.","exampleZh":"銀行上個月改變了貨幣政策。","synonyms":["financial"],"level":6,"theme":"商業與金錢","examples":[{"en":"The bank changed its monetary policy last month.","zh":"銀行上個月改變了貨幣政策。"},{"en":"The award has more symbolic than monetary value.","zh":"這個獎項的象徵意義大於金錢價值。"},{"en":"The central bank adjusted its monetary policy to control inflation.","zh":"中央銀行調整貨幣政策以控制通貨膨脹。"}]},{"word":"money","pos":"n.","phonetic":"[ˈmʌni]","meaning":"金錢；錢","definition":"what is used to buy and sell things","collocations":["make money","save money","spend money"],"example":"He works hard to earn money for his family.","exampleZh":"他努力工作為家人賺錢。","synonyms":["cash","currency"],"level":1,"theme":"商業與金錢","examples":[{"en":"He works hard to earn money for his family.","zh":"他努力工作為家人賺錢。"},{"en":"She saves money every week to buy a new bicycle.","zh":"她每週存錢，想買一輛新腳踏車。"},{"en":"Learning to manage money wisely is an important skill.","zh":"學會明智地管理金錢是一項重要的技能。"}]},{"word":"monitor","pos":"n. / v.","phonetic":"[ˈmɑnətɚ]","meaning":"螢幕；監視器；監控","definition":"a screen for displaying information; to watch and check something","collocations":["computer monitor","monitor progress","monitor closely"],"example":"The teacher will monitor the students' progress every week.","exampleZh":"老師每週都會監控學生的學習進度。","synonyms":["screen","observe"],"level":3,"theme":"科技與媒體","examples":[{"en":"The teacher will monitor the students' progress every week.","zh":"老師每週都會監控學生的學習進度。"},{"en":"Nurses carefully monitor the patient's heartbeat all night.","zh":"護士整夜仔細監控病患的心跳。"},{"en":"He bought a larger monitor to make reading easier.","zh":"他買了一台更大的螢幕，讓閱讀更輕鬆。"}]},{"word":"monkey","pos":"n.","phonetic":"[ˈmʌŋki]","meaning":"猴子","definition":"a small furry animal that climbs trees","collocations":["a playful monkey","monkey bars","monkey around"],"example":"The monkey climbed to the top of the tree.","exampleZh":"猴子爬到樹的頂端。","synonyms":[],"level":1,"theme":"動物與植物","examples":[{"en":"The monkey climbed to the top of the tree.","zh":"猴子爬到樹的頂端。"},{"en":"A playful monkey stole a banana from the visitor's bag.","zh":"一隻頑皮的猴子從遊客的包包裡偷走了一根香蕉。"},{"en":"The children love climbing the monkey bars at recess.","zh":"孩子們喜歡在下課時攀爬單槓。"}]},{"word":"monologue","pos":"n.","phonetic":"[ˈmɑnəˌlɔg]","meaning":"獨白","definition":"a long speech by one person, especially in a play","collocations":["deliver a monologue","opening monologue","dramatic monologue"],"example":"The actor delivered a powerful monologue in the second act.","exampleZh":"演員在第二幕發表了一段扣人心弦的獨白。","synonyms":["soliloquy"],"level":6,"theme":"藝術與音樂","examples":[{"en":"The actor delivered a powerful monologue in the second act.","zh":"演員在第二幕發表了一段扣人心弦的獨白。"},{"en":"The actress delivered a moving monologue about lost love.","zh":"女演員演出了一段關於失去愛情的動人獨白。"},{"en":"His opening monologue made the whole audience laugh.","zh":"他開場的獨白讓全場觀眾大笑。"}]},{"word":"monopoly","pos":"n.","phonetic":"[məˈnɑpəli]","meaning":"壟斷；獨佔","definition":"complete control of a market by one company","collocations":["hold a monopoly","state monopoly","break a monopoly"],"example":"The company has a monopoly on the local telephone market.","exampleZh":"這家公司壟斷了當地的電話市場。","synonyms":["exclusive control"],"level":6,"theme":"商業與金錢","examples":[{"en":"The company has a monopoly on the local telephone market.","zh":"這家公司壟斷了當地的電話市場。"},{"en":"The new law was designed to break the company's monopoly.","zh":"這項新法律旨在打破該公司的壟斷。"},{"en":"No single business should hold a monopoly on clean water.","zh":"沒有任何一家企業應該壟斷乾淨的水源。"}]},{"word":"monotonous","pos":"adj.","phonetic":"[məˈnɑtənəs]","meaning":"單調的；乏味的","definition":"boring because it never changes","collocations":["monotonous voice","monotonous job","monotonous routine"],"example":"He found the factory job monotonous and tiring.","exampleZh":"他覺得工廠的工作單調又累人。","synonyms":["boring","tedious"],"level":6,"theme":"情緒與感受","examples":[{"en":"He found the factory job monotonous and tiring.","zh":"他覺得工廠的工作單調又累人。"},{"en":"The speaker's monotonous voice put half the class to sleep.","zh":"講者單調的聲音讓半數同學睡著了。"},{"en":"She quit the monotonous job to look for something creative.","zh":"她辭去了單調的工作，去尋找有創意的事。"}]},{"word":"monsoon","pos":"n.","phonetic":"[mɑnˈsun]","meaning":"季風；雨季","definition":"a seasonal wind bringing heavy rain in South Asia","collocations":["monsoon season","heavy monsoon rain","monsoon winds"],"example":"The monsoon season brings heavy rain to the region every year.","exampleZh":"季風季節每年都為這個地區帶來大量降雨。","synonyms":[],"level":6,"theme":"天氣與季節","examples":[{"en":"The monsoon season brings heavy rain to the region every year.","zh":"季風季節每年都為這個地區帶來大量降雨。"},{"en":"The monsoon season floods many streets in the city.","zh":"雨季使城市裡許多街道淹水。"},{"en":"Farmers depend on the monsoon rains to water their crops.","zh":"農民仰賴季風帶來的雨水灌溉作物。"}]},{"word":"monster","pos":"n.","phonetic":"[ˈmɑnstɚ]","meaning":"怪物","definition":"a large, ugly, and frightening imaginary creature","collocations":["scary monster","sea monster","monster movie"],"example":"The children were scared of the monster in the movie.","exampleZh":"孩子們被電影裡的怪物嚇到了。","synonyms":["beast"],"level":2,"theme":"其他","examples":[{"en":"The children were scared of the monster in the movie.","zh":"孩子們被電影裡的怪物嚇到了。"},{"en":"In the story, a friendly monster protects the village.","zh":"在這個故事裡，一隻友善的怪物守護著村莊。"},{"en":"My little brother is afraid of the sea monster in the film.","zh":"我弟弟害怕電影裡的海怪。"}]},{"word":"month","pos":"n.","phonetic":"[mʌnθ]","meaning":"月份","definition":"one of the twelve periods that a year is divided into","collocations":["last month","next month","a month ago"],"example":"We are going on vacation next month.","exampleZh":"我們下個月要去度假。","synonyms":[],"level":1,"theme":"時間與空間","examples":[{"en":"We are going on vacation next month.","zh":"我們下個月要去度假。"},{"en":"We are planning a family trip for next month.","zh":"我們正在計畫下個月的家庭旅行。"},{"en":"It has been almost a month since I saw her.","zh":"我上次見到她已經快一個月了。"}]},{"word":"monthly","pos":"adj. / adv.","phonetic":"[ˈmʌnθli]","meaning":"每月的；每月一次","definition":"happening or done once a month","collocations":["monthly fee","monthly report","paid monthly"],"example":"The gym charges a monthly fee for membership.","exampleZh":"健身房收取每月的會員費。","synonyms":[],"level":3,"theme":"時間與空間","examples":[{"en":"The gym charges a monthly fee for membership.","zh":"健身房收取每月的會員費。"},{"en":"The magazine publishes a special monthly issue for students.","zh":"這本雜誌為學生出版特別的月刊。"},{"en":"Our family pays the electricity bill monthly.","zh":"我們家每月繳一次電費。"}]},{"word":"monument","pos":"n.","phonetic":"[ˈmɑnjəmənt]","meaning":"紀念碑；紀念館","definition":"a structure built to remember a person or event","collocations":["historical monument","national monument","build a monument"],"example":"Tourists visit the monument to learn about the war heroes.","exampleZh":"遊客參觀紀念碑以認識戰爭英雄。","synonyms":["memorial"],"level":4,"theme":"社會與文化","examples":[{"en":"Tourists visit the monument to learn about the war heroes.","zh":"遊客參觀紀念碑以認識戰爭英雄。"},{"en":"Tourists took photos in front of the famous stone monument.","zh":"遊客在著名的石造紀念碑前拍照。"},{"en":"The government built a monument to honor the peace treaty.","zh":"政府建了一座紀念碑以紀念這項和平條約。"}]},{"word":"monumental","pos":"adj.","phonetic":"[ˌmɑnjəˈmɛntl]","meaning":"重大的；紀念性的","definition":"great in importance, size, or extent","collocations":["monumental task","monumental achievement","monumental change"],"example":"Winning the championship was a monumental achievement for the team.","exampleZh":"贏得冠軍對這支隊伍來說是重大的成就。","synonyms":["huge","significant"],"level":6,"theme":"抽象概念","examples":[{"en":"Winning the championship was a monumental achievement for the team.","zh":"贏得冠軍對這支隊伍來說是重大的成就。"},{"en":"Building the bridge was a monumental task for the engineers.","zh":"建造這座橋對工程師來說是項艱鉅的任務。"},{"en":"Landing on the moon was a monumental achievement for humanity.","zh":"登陸月球是人類的一項重大成就。"}]},{"word":"mood","pos":"n.","phonetic":"[mud]","meaning":"心情；情緒","definition":"the way someone feels at a particular time","collocations":["good mood","bad mood","in the mood"],"example":"She is in a good mood because she passed the test.","exampleZh":"她因為通過考試而心情很好。","synonyms":["feeling","temper"],"level":3,"theme":"情緒與感受","examples":[{"en":"She is in a good mood because she passed the test.","zh":"她因為通過考試而心情很好。"},{"en":"A good night's sleep can improve your mood the next day.","zh":"一夜好眠能讓你隔天的心情變好。"},{"en":"He was in a bad mood after losing the chess game.","zh":"輸了西洋棋後，他心情很糟。"}]},{"word":"moody","pos":"adj.","phonetic":"[ˈmudi]","meaning":"情緒化的；喜怒無常的","definition":"often changing mood unpredictably","collocations":["moody teenager","moody weather","get moody"],"example":"Teenagers can sometimes be moody and hard to understand.","exampleZh":"青少年有時情緒化，難以理解。","synonyms":["temperamental"],"level":5,"theme":"情緒與感受","examples":[{"en":"Teenagers can sometimes be moody and hard to understand.","zh":"青少年有時情緒化，難以理解。"},{"en":"She becomes moody whenever she skips breakfast.","zh":"她只要沒吃早餐就變得情緒化。"},{"en":"The moody sky changed from bright blue to dark grey.","zh":"陰晴不定的天空從亮藍變成了暗灰。"}]},{"word":"moon","pos":"n.","phonetic":"[mun]","meaning":"月亮；衛星","definition":"the natural satellite that orbits the Earth","collocations":["full moon","moon landing","under the moon"],"example":"The full moon lit up the night sky.","exampleZh":"滿月照亮了夜空。","synonyms":[],"level":1,"theme":"自然與環境","examples":[{"en":"The full moon lit up the night sky.","zh":"滿月照亮了夜空。"},{"en":"A bright full moon shone over the quiet lake.","zh":"一輪明亮的滿月照耀著寧靜的湖面。"},{"en":"Astronomers study the many moons of the giant planets.","zh":"天文學家研究巨大行星的眾多衛星。"}]},{"word":"moonlight","pos":"n.","phonetic":"[ˈmunˌlaɪt]","meaning":"月光","definition":"light that comes from the moon","collocations":["by moonlight","moonlight walk","soft moonlight"],"example":"They took a romantic walk by moonlight along the beach.","exampleZh":"他們在月光下沿著海灘浪漫地散步。","synonyms":[],"level":4,"theme":"自然與環境","examples":[{"en":"They took a romantic walk by moonlight along the beach.","zh":"他們在月光下沿著海灘浪漫地散步。"},{"en":"The garden looked magical under the soft moonlight.","zh":"花園在柔和的月光下顯得如夢似幻。"},{"en":"They danced by moonlight on the quiet rooftop.","zh":"他們在寧靜的屋頂上藉著月光起舞。"}]},{"word":"moral","pos":"adj. / n.","phonetic":"[ˈmɔrəl]","meaning":"道德的；寓意","definition":"concerning principles of right and wrong; a lesson from a story","collocations":["moral values","moral support","the moral of the story"],"example":"The moral of the story is to always be honest.","exampleZh":"這個故事的寓意是要永遠誠實。","synonyms":["ethical"],"level":4,"theme":"抽象概念","examples":[{"en":"The moral of the story is to always be honest.","zh":"這個故事的寓意是要永遠誠實。"},{"en":"Parents try to teach their children strong moral values.","zh":"父母努力教導孩子堅定的道德價值觀。"},{"en":"The moral of the story is that kindness is always rewarded.","zh":"這個故事的寓意是善良總會有回報。"}]},{"word":"more","pos":"adj. / adv. / pron.","phonetic":"[mɔr]","meaning":"更多的；更","definition":"a greater or additional amount or degree","collocations":["more than","much more","one more"],"example":"I need more time to finish this project.","exampleZh":"我需要更多時間完成這個專案。","synonyms":["additional"],"level":1,"theme":"抽象概念","examples":[{"en":"I need more time to finish this project.","zh":"我需要更多時間完成這個專案。"},{"en":"Could you give me a little more time to decide?","zh":"你能再多給我一點時間做決定嗎？"},{"en":"The more you practice, the better you will become.","zh":"你練習得越多，就會變得越好。"}]},{"word":"moreover","pos":"adv.","phonetic":"[mɔrˈovɚ]","meaning":"此外；而且","definition":"in addition to what has just been said","collocations":["moreover, ...","moreover it is clear"],"example":"The plan is expensive; moreover, it may not even work.","exampleZh":"這個計畫很昂貴，此外還可能行不通。","synonyms":["furthermore","besides"],"level":5,"theme":"溝通與語言","examples":[{"en":"The plan is expensive; moreover, it may not even work.","zh":"這個計畫很昂貴，此外還可能行不通。"},{"en":"The hotel was expensive; moreover, the rooms were quite small.","zh":"那家飯店很貴，而且房間相當小。"},{"en":"He speaks three languages; moreover, he learns quickly.","zh":"他會說三種語言，而且學得很快。"}]},{"word":"morning","pos":"n.","phonetic":"[ˈmɔrnɪŋ]","meaning":"早晨；上午","definition":"the early part of the day","collocations":["good morning","this morning","every morning"],"example":"She goes jogging every morning before school.","exampleZh":"她每天早上上學前都去慢跑。","synonyms":[],"level":1,"theme":"時間與空間","examples":[{"en":"She goes jogging every morning before school.","zh":"她每天早上上學前都去慢跑。"},{"en":"The birds start singing early every summer morning.","zh":"每個夏天的早晨，鳥兒都很早開始歌唱。"},{"en":"I usually drink a cup of tea in the morning.","zh":"我早上通常會喝一杯茶。"}]},{"word":"mortal","pos":"adj. / n.","phonetic":"[ˈmɔrtl]","meaning":"必死的；凡人","definition":"subject to death; a human being","collocations":["mortal danger","mortal enemy","ordinary mortal"],"example":"All living creatures are mortal and will eventually die.","exampleZh":"所有生物都難逃一死。","synonyms":["human"],"level":6,"theme":"抽象概念","examples":[{"en":"All living creatures are mortal and will eventually die.","zh":"所有生物都難逃一死。"},{"en":"Ancient stories often describe heroes who are only mortal.","zh":"古代故事常描述那些終究只是凡人的英雄。"},{"en":"The knight faced mortal danger to save the village.","zh":"這名騎士冒著生命危險去拯救村莊。"}]},{"word":"mortality","pos":"n.","phonetic":"[mɔrˈtæləti]","meaning":"死亡率；必死性","definition":"the state of being subject to death; death rate","collocations":["mortality rate","infant mortality","reduce mortality"],"example":"Improved healthcare has lowered infant mortality rates.","exampleZh":"醫療進步降低了嬰兒死亡率。","synonyms":[],"level":6,"theme":"身體與健康","examples":[{"en":"Improved healthcare has lowered infant mortality rates.","zh":"醫療進步降低了嬰兒死亡率。"},{"en":"Better nutrition has greatly reduced infant mortality worldwide.","zh":"更好的營養大幅降低了全球的嬰兒死亡率。"},{"en":"The disease has a high mortality rate without treatment.","zh":"這種疾病若不治療，死亡率很高。"}]},{"word":"mortgage","pos":"n.","phonetic":"[ˈmɔrgɪdʒ]","meaning":"房屋貸款；抵押貸款","definition":"a loan used to buy a house or land","collocations":["pay off a mortgage","mortgage payment","take out a mortgage"],"example":"They took out a mortgage to buy their first house.","exampleZh":"他們貸款買了第一間房子。","synonyms":["loan"],"level":6,"theme":"商業與金錢","examples":[{"en":"They took out a mortgage to buy their first house.","zh":"他們貸款買了第一間房子。"},{"en":"They work hard to pay off their mortgage each month.","zh":"他們努力工作，每個月償還房屋貸款。"},{"en":"The couple took out a mortgage to buy a small apartment.","zh":"這對夫妻辦了房貸購買一間小公寓。"}]},{"word":"mosaic","pos":"n.","phonetic":"[moˈzeɪɪk]","meaning":"馬賽克；鑲嵌畫","definition":"a picture made from small pieces of colored stone or glass","collocations":["mosaic tile","ancient mosaic","colorful mosaic"],"example":"The floor was decorated with an ancient Roman mosaic.","exampleZh":"地板上裝飾著一幅古羅馬馬賽克畫。","synonyms":[],"level":6,"theme":"藝術與音樂","examples":[{"en":"The floor was decorated with an ancient Roman mosaic.","zh":"地板上裝飾著一幅古羅馬馬賽克畫。"},{"en":"The museum displays a colorful mosaic made of glass pieces.","zh":"博物館展出一幅由玻璃碎片拼成的彩色鑲嵌畫。"},{"en":"Workers carefully restored the ancient mosaic on the wall.","zh":"工人們仔細修復牆上的古老鑲嵌畫。"}]},{"word":"mosquito","pos":"n.","phonetic":"[məˈskito]","meaning":"蚊子","definition":"a small flying insect that bites and sucks blood","collocations":["mosquito bite","mosquito net","kill a mosquito"],"example":"A mosquito bit me while I was sleeping.","exampleZh":"我睡覺時被一隻蚊子咬了。","synonyms":[],"level":2,"theme":"動物與植物","examples":[{"en":"A mosquito bit me while I was sleeping.","zh":"我睡覺時被一隻蚊子咬了。"},{"en":"A mosquito net over the bed kept the insects away all night.","zh":"床上的蚊帳整夜把蟲子擋在外面。"},{"en":"She quickly killed the mosquito buzzing near her ear.","zh":"她迅速打死了在耳邊嗡嗡叫的蚊子。"}]},{"word":"moss","pos":"n.","phonetic":"[mɔs]","meaning":"苔蘚","definition":"a small green plant that grows on damp surfaces","collocations":["covered in moss","green moss","moss grows"],"example":"Green moss covered the old stone wall.","exampleZh":"綠色的苔蘚覆蓋著這座老石牆。","synonyms":[],"level":4,"theme":"動物與植物","examples":[{"en":"Green moss covered the old stone wall.","zh":"綠色的苔蘚覆蓋著這座老石牆。"},{"en":"Thick green moss grew on the shady side of the tree.","zh":"厚厚的綠色苔蘚長在樹木陰暗的一側。"},{"en":"The ancient statue was completely covered in soft moss.","zh":"那座古老的雕像上覆滿了柔軟的苔蘚。"}]},{"word":"most","pos":"adj. / adv. / pron.","phonetic":"[most]","meaning":"最多的；大部分","definition":"the greatest amount or number","collocations":["most people","at most","most of all"],"example":"Most students finished the exam on time.","exampleZh":"大部分學生都準時完成了考試。","synonyms":["majority"],"level":1,"theme":"抽象概念","examples":[{"en":"Most students finished the exam on time.","zh":"大部分學生都準時完成了考試。"},{"en":"Most people in the class enjoy playing basketball after school.","zh":"班上大部分的人都喜歡放學後打籃球。"},{"en":"The trip will take three hours at most, so relax.","zh":"這趟旅程最多三個小時，所以放輕鬆吧。"}]},{"word":"mostly","pos":"adv.","phonetic":"[ˈmostli]","meaning":"大多；主要地","definition":"mainly or generally","collocations":["mostly true","mostly sunny","mostly used"],"example":"The weather this week was mostly sunny.","exampleZh":"這週的天氣大多是晴朗的。","synonyms":["mainly","largely"],"level":3,"theme":"抽象概念","examples":[{"en":"The weather this week was mostly sunny.","zh":"這週的天氣大多是晴朗的。"},{"en":"His new novel is mostly based on his own childhood.","zh":"他的新小說大多以他自己的童年為基礎。"},{"en":"The audience was mostly made up of young students.","zh":"觀眾主要由年輕學生組成。"}]},{"word":"motel","pos":"n.","phonetic":"[moˈtɛl]","meaning":"汽車旅館","definition":"a hotel for travelers by car, usually near a road","collocations":["cheap motel","stay at a motel","roadside motel"],"example":"We stayed at a motel by the highway during our road trip.","exampleZh":"我們公路旅行時住在高速公路旁的一間汽車旅館。","synonyms":[],"level":2,"theme":"交通與旅行","examples":[{"en":"We stayed at a motel by the highway during our road trip.","zh":"我們公路旅行時住在高速公路旁的一間汽車旅館。"},{"en":"They found a cheap motel to rest for the night.","zh":"他們找到一間便宜的汽車旅館過夜休息。"},{"en":"The roadside motel offered free parking for every guest.","zh":"這間路邊的汽車旅館為每位客人提供免費停車。"}]},{"word":"mother","pos":"n.","phonetic":"[ˈmʌðɚ]","meaning":"母親","definition":"a female parent","collocations":["single mother","mother tongue","loving mother"],"example":"My mother always encourages me to try my best.","exampleZh":"我媽媽總是鼓勵我盡力而為。","synonyms":["mom"],"level":1,"theme":"人物與家庭","examples":[{"en":"My mother always encourages me to try my best.","zh":"我媽媽總是鼓勵我盡力而為。"},{"en":"As a single mother, she works hard to support two children.","zh":"身為單親媽媽，她努力工作養育兩個孩子。"},{"en":"Chinese is the mother tongue of many students here.","zh":"中文是這裡許多學生的母語。"}]},{"word":"motion","pos":"n.","phonetic":"[ˈmoʃən]","meaning":"動作；運動；提議","definition":"the action or process of moving","collocations":["in motion","slow motion","set in motion"],"example":"The camera captured the ball's motion in slow motion.","exampleZh":"攝影機以慢動作捕捉了球的移動軌跡。","synonyms":["movement"],"level":4,"theme":"運動與休閒","examples":[{"en":"The camera captured the ball's motion in slow motion.","zh":"攝影機以慢動作捕捉了球的移動軌跡。"},{"en":"The gentle motion of the boat slowly rocked us to sleep.","zh":"小船輕柔的擺動慢慢地把我們搖入夢鄉。"},{"en":"Her careless words set a series of problems in motion.","zh":"她不經意的話引發了一連串的問題。"}]},{"word":"motivate","pos":"v.","phonetic":"[ˈmotəˌvet]","meaning":"激勵；激發動機","definition":"to give someone a reason to do something","collocations":["motivate students","motivate employees","highly motivated"],"example":"Good teachers know how to motivate their students.","exampleZh":"好老師懂得如何激勵學生。","synonyms":["inspire","encourage"],"level":4,"theme":"教育與學習","examples":[{"en":"Good teachers know how to motivate their students.","zh":"好老師懂得如何激勵學生。"},{"en":"A good coach can motivate players to train even harder.","zh":"好的教練能激勵球員更加努力訓練。"},{"en":"Rewards often motivate employees to reach their monthly goals.","zh":"獎勵常能激勵員工達成每月目標。"}]},{"word":"motivation","pos":"n.","phonetic":"[ˌmotəˈveʃən]","meaning":"動機；動力","definition":"a reason or enthusiasm for doing something","collocations":["lack of motivation","source of motivation","find motivation"],"example":"Her motivation to succeed comes from her family.","exampleZh":"她成功的動力來自她的家人。","synonyms":["drive","incentive"],"level":4,"theme":"抽象概念","examples":[{"en":"Her motivation to succeed comes from her family.","zh":"她成功的動力來自她的家人。"},{"en":"After failing twice, he completely lost his motivation to study.","zh":"失敗兩次後，他完全失去了讀書的動力。"},{"en":"Her love of animals is the main source of her motivation.","zh":"她對動物的熱愛是她動力的主要來源。"}]},{"word":"motive","pos":"n.","phonetic":"[ˈmotɪv]","meaning":"動機","definition":"a reason for doing something, often hidden","collocations":["hidden motive","true motive","question someone's motive"],"example":"The police tried to find the suspect's motive for the crime.","exampleZh":"警方試圖找出嫌犯犯罪的動機。","synonyms":["reason","purpose"],"level":5,"theme":"抽象概念","examples":[{"en":"The police tried to find the suspect's motive for the crime.","zh":"警方試圖找出嫌犯犯罪的動機。"},{"en":"Detectives searched for a hidden motive behind the strange gift.","zh":"偵探們尋找那份奇怪禮物背後隱藏的動機。"},{"en":"Many people questioned the politician's true motive for the promise.","zh":"許多人質疑那位政治人物承諾背後真正的動機。"}]},{"word":"motor","pos":"n.","phonetic":"[ˈmotɚ]","meaning":"馬達；引擎","definition":"a machine that produces motion or power","collocations":["electric motor","motor vehicle","start the motor"],"example":"The electric motor powers the small fan.","exampleZh":"這台電動馬達為小型風扇提供動力。","synonyms":["engine"],"level":3,"theme":"科技與媒體","examples":[{"en":"The electric motor powers the small fan.","zh":"這台電動馬達為小型風扇提供動力。"},{"en":"The old boat's motor suddenly stopped in the middle of the lake.","zh":"那艘舊船的馬達在湖中央突然停了下來。"},{"en":"A modern electric motor makes the vehicle very quiet.","zh":"現代的電動馬達讓這輛車非常安靜。"}]},{"word":"motorcycle","pos":"n.","phonetic":"[ˈmotɚˌsaɪkl̩]","meaning":"摩托車","definition":"a two-wheeled vehicle powered by an engine","collocations":["ride a motorcycle","motorcycle helmet","fast motorcycle"],"example":"He rides his motorcycle to work every day.","exampleZh":"他每天騎摩托車上班。","synonyms":[],"level":2,"theme":"交通與旅行","examples":[{"en":"He rides his motorcycle to work every day.","zh":"他每天騎摩托車上班。"},{"en":"Always wear a motorcycle helmet to protect your head.","zh":"騎摩托車一定要戴安全帽保護頭部。"},{"en":"They rode a fast motorcycle along the coastal road.","zh":"他們騎著一輛快速的摩托車沿著海岸公路奔馳。"}]},{"word":"mount","pos":"v. / n.","phonetic":"[maʊnt]","meaning":"登上；安裝；增加","definition":"to climb up onto something; to increase gradually","collocations":["mount a horse","mount a campaign","pressure mounts"],"example":"Pressure has been mounting on the government to act.","exampleZh":"政府正面臨越來越大的壓力採取行動。","synonyms":["climb","increase"],"level":5,"theme":"動作與行為","examples":[{"en":"Pressure has been mounting on the government to act.","zh":"政府正面臨越來越大的壓力採取行動。"},{"en":"The young rider carefully mounted the horse for the first time.","zh":"這位年輕騎士小心翼翼地第一次騎上馬。"},{"en":"Workers mounted a large screen on the classroom wall.","zh":"工人們在教室牆上裝了一個大螢幕。"}]},{"word":"mountain","pos":"n.","phonetic":"[ˈmaʊntn̩]","meaning":"山；山脈","definition":"a very high hill","collocations":["climb a mountain","mountain range","mountain view"],"example":"They climbed the mountain to watch the sunrise.","exampleZh":"他們爬上山去看日出。","synonyms":[],"level":1,"theme":"自然與環境","examples":[{"en":"They climbed the mountain to watch the sunrise.","zh":"他們爬上山去看日出。"},{"en":"We hiked up the mountain to enjoy the beautiful mountain view.","zh":"我們爬上山，欣賞美麗的山景。"},{"en":"A long mountain range stretched across the entire horizon.","zh":"一道綿長的山脈橫貫整個地平線。"}]},{"word":"mountainous","pos":"adj.","phonetic":"[ˈmaʊntənəs]","meaning":"多山的","definition":"having many mountains","collocations":["mountainous region","mountainous terrain","mountainous country"],"example":"The village is located in a mountainous region.","exampleZh":"這個村莊位於多山的地區。","synonyms":[],"level":5,"theme":"自然與環境","examples":[{"en":"The village is located in a mountainous region.","zh":"這個村莊位於多山的地區。"},{"en":"Driving through the mountainous region took much longer than expected.","zh":"開車穿越多山的地區花的時間比預期還久。"},{"en":"The mountainous terrain made farming very difficult for villagers.","zh":"多山的地形讓村民耕作變得非常困難。"}]},{"word":"mourn","pos":"v.","phonetic":"[mɔrn]","meaning":"哀悼；悲痛","definition":"to feel sad because someone has died","collocations":["mourn a loss","mourn for someone","mourn the death"],"example":"The whole town mourned the death of the beloved teacher.","exampleZh":"全鎮的人都為這位深受愛戴的老師的過世感到悲痛。","synonyms":["grieve"],"level":6,"theme":"情緒與感受","examples":[{"en":"The whole town mourned the death of the beloved teacher.","zh":"全鎮的人都為這位深受愛戴的老師的過世感到悲痛。"},{"en":"The family gathered to mourn the loss of their grandfather.","zh":"全家人聚在一起哀悼祖父的離世。"},{"en":"People across the country mourned for the victims of the flood.","zh":"全國各地的人們為洪水的罹難者哀悼。"}]},{"word":"mouse","pos":"n.","phonetic":"[maʊs]","meaning":"老鼠；滑鼠","definition":"a small rodent; a device used to control a computer cursor","collocations":["computer mouse","catch a mouse","click the mouse"],"example":"Click the mouse twice to open the file.","exampleZh":"點兩下滑鼠來開啟這個檔案。","synonyms":[],"level":1,"theme":"科技與媒體","examples":[{"en":"Click the mouse twice to open the file.","zh":"點兩下滑鼠來開啟這個檔案。"},{"en":"The cat waited quietly to catch the little grey mouse.","zh":"貓咪靜靜地等著抓那隻灰色的小老鼠。"},{"en":"Move the computer mouse gently to select the correct icon.","zh":"輕輕移動滑鼠來選取正確的圖示。"}]},{"word":"mouth","pos":"n.","phonetic":"[maʊθ]","meaning":"嘴巴；口","definition":"the opening in the face used for eating and speaking","collocations":["open your mouth","mouth of a river","shut your mouth"],"example":"The river's mouth opens into the sea.","exampleZh":"這條河的出海口通往大海。","synonyms":[],"level":1,"theme":"身體與健康","examples":[{"en":"The river's mouth opens into the sea.","zh":"這條河的出海口通往大海。"},{"en":"Please cover your mouth when you cough or sneeze.","zh":"咳嗽或打噴嚏時請摀住嘴巴。"},{"en":"A small boat sailed slowly toward the mouth of the river.","zh":"一艘小船緩緩駛向河口。"}]},{"word":"move","pos":"v. / n.","phonetic":"[muv]","meaning":"移動；搬家","definition":"to change position or location","collocations":["move house","move forward","a smart move"],"example":"We plan to move to a bigger apartment next year.","exampleZh":"我們計畫明年搬到更大的公寓。","synonyms":["shift","relocate"],"level":1,"theme":"動作與行為","examples":[{"en":"We plan to move to a bigger apartment next year.","zh":"我們計畫明年搬到更大的公寓。"},{"en":"Our family will move house to the countryside next spring.","zh":"我們全家明年春天要搬到鄉下。"},{"en":"Accepting that job abroad turned out to be a smart move.","zh":"接受那份國外的工作結果證明是明智之舉。"}]},{"word":"movement","pos":"n.","phonetic":"[ˈmuvmənt]","meaning":"移動；運動；動作","definition":"an act of moving; an organized group working for a cause","collocations":["social movement","free movement","sudden movement"],"example":"The civil rights movement changed history forever.","exampleZh":"民權運動永遠改變了歷史。","synonyms":["motion"],"level":3,"theme":"社會與文化","examples":[{"en":"The civil rights movement changed history forever.","zh":"民權運動永遠改變了歷史。"},{"en":"A sudden movement in the bushes startled the sleeping deer.","zh":"灌木叢中突然的動靜驚動了熟睡的鹿。"},{"en":"The environmental movement encouraged people to reduce plastic waste.","zh":"這場環保運動鼓勵人們減少塑膠垃圾。"}]},{"word":"movie","pos":"n.","phonetic":"[ˈmuvi]","meaning":"電影","definition":"a film shown at a cinema or on television","collocations":["watch a movie","movie theater","favorite movie"],"example":"We watched a great movie together last weekend.","exampleZh":"我們上週末一起看了一部很棒的電影。","synonyms":["film"],"level":1,"theme":"藝術與音樂","examples":[{"en":"We watched a great movie together last weekend.","zh":"我們上週末一起看了一部很棒的電影。"},{"en":"Let's go to the movie theater to see the new comedy.","zh":"我們去電影院看那部新的喜劇吧。"},{"en":"Her favorite movie always makes her laugh and cry.","zh":"她最喜歡的電影總是讓她又哭又笑。"}]},{"word":"mow","pos":"v.","phonetic":"[mo]","meaning":"割（草）","definition":"to cut grass with a machine","collocations":["mow the lawn","mow the grass","mow weekly"],"example":"My father mows the lawn every Saturday morning.","exampleZh":"我爸爸每週六早上都會割草。","synonyms":["cut"],"level":2,"theme":"居家與生活","examples":[{"en":"My father mows the lawn every Saturday morning.","zh":"我爸爸每週六早上都會割草。"},{"en":"He promised to mow the lawn before the guests arrived.","zh":"他答應在客人到來之前把草坪割好。"},{"en":"We usually mow the grass in the backyard every weekend.","zh":"我們通常每個週末都會割後院的草。"}]},{"word":"much","pos":"adj. / adv. / pron.","phonetic":"[mʌtʃ]","meaning":"許多；很","definition":"a large amount of something","collocations":["so much","too much","much better"],"example":"Thank you so much for your help.","exampleZh":"非常感謝你的幫忙。","synonyms":["a lot"],"level":1,"theme":"抽象概念","examples":[{"en":"Thank you so much for your help.","zh":"非常感謝你的幫忙。"},{"en":"You have eaten too much candy, so stop for now.","zh":"你吃了太多糖果，現在先停下來吧。"},{"en":"This year's exam was much easier than last year's.","zh":"今年的考試比去年容易多了。"}]},{"word":"mud","pos":"n.","phonetic":"[mʌd]","meaning":"泥巴","definition":"soft wet earth","collocations":["covered in mud","stuck in mud","mud puddle"],"example":"The children played happily in the mud after the rain.","exampleZh":"下雨過後，孩子們在泥巴裡開心地玩耍。","synonyms":[],"level":2,"theme":"自然與環境","examples":[{"en":"The children played happily in the mud after the rain.","zh":"下雨過後，孩子們在泥巴裡開心地玩耍。"},{"en":"Our car got badly stuck in the thick mud after the storm.","zh":"暴風雨過後，我們的車深陷在濃稠的泥巴裡。"},{"en":"The dog came home covered in mud from head to tail.","zh":"那隻狗回家時從頭到尾都沾滿了泥巴。"}]},{"word":"muddy","pos":"adj.","phonetic":"[ˈmʌdi]","meaning":"泥濘的","definition":"covered with or full of mud","collocations":["muddy road","muddy shoes","muddy water"],"example":"His shoes were muddy after the hike.","exampleZh":"健行之後他的鞋子沾滿了泥巴。","synonyms":["dirty"],"level":3,"theme":"自然與環境","examples":[{"en":"His shoes were muddy after the hike.","zh":"健行之後他的鞋子沾滿了泥巴。"},{"en":"The heavy rain turned the mountain path into a muddy road.","zh":"大雨把山路變成了一條泥濘的道路。"},{"en":"She washed her muddy shoes before entering the house.","zh":"她進屋前先洗掉了鞋上的泥巴。"}]},{"word":"muffin","pos":"n.","phonetic":"[ˈmʌfɪn]","meaning":"鬆餅；瑪芬","definition":"a small round sweet bread often eaten for breakfast","collocations":["blueberry muffin","bake a muffin","warm muffin"],"example":"She baked blueberry muffins for breakfast.","exampleZh":"她烤了藍莓瑪芬當早餐。","synonyms":[],"level":2,"theme":"食物與烹飪","examples":[{"en":"She baked blueberry muffins for breakfast.","zh":"她烤了藍莓瑪芬當早餐。"},{"en":"He enjoyed a warm muffin and hot milk for breakfast.","zh":"他早餐享用了一個溫熱的瑪芬和熱牛奶。"},{"en":"My aunt taught me how to bake a blueberry muffin.","zh":"我阿姨教我如何烤藍莓瑪芬。"}]},{"word":"muffle","pos":"v.","phonetic":"[ˈmʌfl̩]","meaning":"使（聲音）減弱；蒙住","definition":"to make a sound quieter or less clear","collocations":["muffle a sound","muffled voice","muffle a cry"],"example":"She tried to muffle her laughter during the quiet meeting.","exampleZh":"她試著在安靜的會議中壓低笑聲。","synonyms":["deaden","dampen"],"level":6,"theme":"溝通與語言","examples":[{"en":"She tried to muffle her laughter during the quiet meeting.","zh":"她試著在安靜的會議中壓低笑聲。"},{"en":"Thick curtains helped muffle the noise from the busy street.","zh":"厚重的窗簾有助於減弱繁忙街道的噪音。"},{"en":"He pressed a pillow to his face to muffle a cry.","zh":"他把枕頭壓在臉上以壓住哭聲。"}]},{"word":"mug","pos":"n. / v.","phonetic":"[mʌg]","meaning":"馬克杯；搶劫","definition":"a large cup with a handle; to rob someone violently","collocations":["coffee mug","mug of tea","mugged in the street"],"example":"He drank a mug of hot coffee before work.","exampleZh":"他上班前喝了一杯熱咖啡。","synonyms":["cup"],"level":2,"theme":"居家與生活","examples":[{"en":"He drank a mug of hot coffee before work.","zh":"他上班前喝了一杯熱咖啡。"},{"en":"She warmed her cold hands around a mug of tea.","zh":"她用一杯茶暖著冰冷的雙手。"},{"en":"A tourist was mugged in the street late at night.","zh":"一名遊客深夜在街上被搶劫了。"}]},{"word":"multicultural","pos":"adj.","phonetic":"[ˌmʌltiˈkʌltʃərəl]","meaning":"多元文化的","definition":"including people of several different cultures","collocations":["multicultural society","multicultural education","multicultural city"],"example":"Taiwan has become a more multicultural society over the years.","exampleZh":"這些年來，台灣已成為一個更多元文化的社會。","synonyms":["diverse"],"level":6,"theme":"社會與文化","examples":[{"en":"Taiwan has become a more multicultural society over the years.","zh":"這些年來，台灣已成為一個更多元文化的社會。"},{"en":"Our school celebrates its multicultural community with a food festival.","zh":"我們學校以美食節慶祝校園的多元文化。"},{"en":"Living in a multicultural city taught her to respect differences.","zh":"住在一個多元文化的城市教會她尊重差異。"}]},{"word":"multimedia","pos":"n. / adj.","phonetic":"[ˌmʌltiˈmidiə]","meaning":"多媒體","definition":"using more than one form of communication, such as text, sound, and images","collocations":["multimedia presentation","multimedia device","multimedia lesson"],"example":"The teacher used multimedia tools to make the lesson interesting.","exampleZh":"老師使用多媒體工具讓課程變得有趣。","synonyms":[],"level":5,"theme":"科技與媒體","examples":[{"en":"The teacher used multimedia tools to make the lesson interesting.","zh":"老師使用多媒體工具讓課程變得有趣。"},{"en":"The students prepared a lively multimedia presentation about recycling.","zh":"學生們準備了一場關於回收的生動多媒體簡報。"},{"en":"The museum uses multimedia devices to explain ancient history.","zh":"博物館運用多媒體設備來解說古代歷史。"}]},{"word":"multinational","pos":"adj. / n.","phonetic":"[ˌmʌltiˈnæʃənl̩]","meaning":"跨國的；跨國公司","definition":"involving several countries or a large international company","collocations":["multinational company","multinational corporation","multinational team"],"example":"She works for a multinational company with offices worldwide.","exampleZh":"她在一家在全球都有分公司的跨國企業工作。","synonyms":[],"level":6,"theme":"商業與金錢","examples":[{"en":"She works for a multinational company with offices worldwide.","zh":"她在一家在全球都有分公司的跨國企業工作。"},{"en":"A large multinational company opened a new office in our city.","zh":"一家大型跨國公司在我們的城市開設了新辦公室。"},{"en":"The project brought together a multinational team of scientists.","zh":"這個計畫集結了一支跨國的科學家團隊。"}]},{"word":"multiple","pos":"adj.","phonetic":"[ˈmʌltəpl̩]","meaning":"多個的；多樣的","definition":"more than one; many","collocations":["multiple choices","multiple times","multiple reasons"],"example":"There are multiple reasons why the project failed.","exampleZh":"這個專案失敗有很多原因。","synonyms":["numerous"],"level":4,"theme":"抽象概念","examples":[{"en":"There are multiple reasons why the project failed.","zh":"這個專案失敗有很多原因。"},{"en":"The test contains multiple choices for every single question.","zh":"這份測驗每一題都有多個選項。"},{"en":"I called her multiple times, but she never answered.","zh":"我打了好幾次電話給她，但她都沒接。"}]},{"word":"multiply","pos":"v.","phonetic":"[ˈmʌltəˌplaɪ]","meaning":"乘；使增加","definition":"to add a number to itself a certain number of times; to increase greatly","collocations":["multiply numbers","multiply rapidly","multiply by two"],"example":"Students learn to multiply and divide numbers in third grade.","exampleZh":"學生在三年級學習數字的乘法和除法。","synonyms":["increase"],"level":2,"theme":"科學與數學","examples":[{"en":"Students learn to multiply and divide numbers in third grade.","zh":"學生在三年級學習數字的乘法和除法。"},{"en":"To find the area, multiply the length by the width.","zh":"要算出面積，就把長乘以寬。"},{"en":"Without predators, the rabbit population can multiply rapidly.","zh":"沒有天敵，兔子的數量會迅速增加。"}]},{"word":"multitude","pos":"n.","phonetic":"[ˈmʌltəˌtud]","meaning":"眾多；大量","definition":"a large number of people or things","collocations":["a multitude of reasons","a multitude of people","face a multitude"],"example":"A multitude of fans gathered outside the stadium.","exampleZh":"一大群粉絲聚集在體育場外。","synonyms":["crowd","mass"],"level":6,"theme":"抽象概念","examples":[{"en":"A multitude of fans gathered outside the stadium.","zh":"一大群粉絲聚集在體育場外。"},{"en":"A multitude of tourists filled the narrow streets of the old town.","zh":"大批遊客擠滿了老城區狹窄的街道。"},{"en":"She refused the offer for a multitude of personal reasons.","zh":"她因為許多個人因素而拒絕了這個提議。"}]},{"word":"municipal","pos":"adj.","phonetic":"[mjuˈnɪsəpl̩]","meaning":"市政的；地方自治的","definition":"relating to a city or town's local government","collocations":["municipal government","municipal building","municipal services"],"example":"The municipal government announced new recycling rules.","exampleZh":"市政府宣布了新的資源回收規定。","synonyms":[],"level":6,"theme":"政治與法律","examples":[{"en":"The municipal government announced new recycling rules.","zh":"市政府宣布了新的資源回收規定。"},{"en":"The municipal government promised to repair the old public library.","zh":"市政府承諾修繕那座老舊的公共圖書館。"},{"en":"Free municipal services include garbage collection and street cleaning.","zh":"免費的市政服務包括垃圾收集和街道清潔。"}]},{"word":"municipality","pos":"n.","phonetic":"[mjuˌnɪsəˈpæləti]","meaning":"自治市；市政當局","definition":"a town or district with its own local government","collocations":["local municipality","the municipality decided","neighboring municipality"],"example":"The municipality built a new park for local residents.","exampleZh":"這個自治市為當地居民興建了一座新公園。","synonyms":[],"level":6,"theme":"政治與法律","examples":[{"en":"The municipality built a new park for local residents.","zh":"這個自治市為當地居民興建了一座新公園。"},{"en":"The local municipality decided to plant more trees downtown.","zh":"當地的自治市決定在市中心種植更多樹木。"},{"en":"Each neighboring municipality shares the cost of the new bridge.","zh":"每個相鄰的自治市共同分擔新橋的費用。"}]},{"word":"murder","pos":"n. / v.","phonetic":"[ˈmɝdɚ]","meaning":"謀殺","definition":"the crime of intentionally killing someone","collocations":["commit murder","murder case","solve a murder"],"example":"The detective spent months solving the murder case.","exampleZh":"這名偵探花了好幾個月才偵破這件謀殺案。","synonyms":["homicide"],"level":4,"theme":"政治與法律","examples":[{"en":"The detective spent months solving the murder case.","zh":"這名偵探花了好幾個月才偵破這件謀殺案。"},{"en":"The clever detective finally solved the difficult murder case.","zh":"這位聰明的偵探終於破了這樁棘手的謀殺案。"},{"en":"No one could believe such a gentle man would commit murder.","zh":"沒有人相信如此溫和的人會犯下謀殺罪。"}]},{"word":"murky","pos":"adj.","phonetic":"[ˈmɝki]","meaning":"陰暗的；渾濁的","definition":"dark and unclear, especially because of dirt","collocations":["murky water","murky past","murky sky"],"example":"The lake's murky water made it hard to see the fish.","exampleZh":"湖水渾濁，很難看到裡面的魚。","synonyms":["dark","cloudy"],"level":6,"theme":"性質與描述","examples":[{"en":"The lake's murky water made it hard to see the fish.","zh":"湖水渾濁，很難看到裡面的魚。"},{"en":"We could not see the bottom through the murky water.","zh":"渾濁的水讓我們看不到底部。"},{"en":"Reporters tried to uncover the company's murky past.","zh":"記者們試圖揭開這家公司不光彩的過去。"}]},{"word":"murmur","pos":"n. / v.","phonetic":"[ˈmɝmɚ]","meaning":"低語；喃喃低聲","definition":"to say something in a soft, low voice","collocations":["murmur softly","a murmur of voices","murmur an apology"],"example":"She murmured a quiet apology and left the room.","exampleZh":"她低聲道歉後便離開了房間。","synonyms":["whisper","mutter"],"level":5,"theme":"溝通與語言","examples":[{"en":"She murmured a quiet apology and left the room.","zh":"她低聲道歉後便離開了房間。"},{"en":"A soft murmur of voices spread through the quiet library.","zh":"低柔的說話聲在安靜的圖書館裡蔓延開來。"},{"en":"The tired child murmured something and fell fast asleep.","zh":"疲倦的孩子喃喃地說了些什麼便沉沉睡去。"}]},{"word":"muscle","pos":"n.","phonetic":"[ˈmʌsl̩]","meaning":"肌肉","definition":"a body tissue that produces movement","collocations":["build muscle","muscle pain","strong muscles"],"example":"Regular exercise helps you build muscle and stay healthy.","exampleZh":"規律運動有助於鍛鍊肌肉並保持健康。","synonyms":[],"level":3,"theme":"身體與健康","examples":[{"en":"Regular exercise helps you build muscle and stay healthy.","zh":"規律運動有助於鍛鍊肌肉並保持健康。"},{"en":"Lifting weights every day helps you build muscle steadily.","zh":"每天舉重能幫助你穩定地增長肌肉。"},{"en":"After the long run, she felt muscle pain in her legs.","zh":"長跑之後，她的腿感到肌肉痠痛。"}]},{"word":"muscular","pos":"adj.","phonetic":"[ˈmʌskjəlɚ]","meaning":"肌肉發達的","definition":"having strong, well-developed muscles","collocations":["muscular arms","muscular body","muscular strength"],"example":"The athlete has a muscular body from years of training.","exampleZh":"這位運動員經過多年訓練練就一身肌肉。","synonyms":["strong","athletic"],"level":5,"theme":"身體與健康","examples":[{"en":"The athlete has a muscular body from years of training.","zh":"這位運動員經過多年訓練練就一身肌肉。"},{"en":"Years of swimming gave him strong, muscular arms.","zh":"多年的游泳讓他有著強壯結實的手臂。"},{"en":"The dancer's muscular body allowed graceful, powerful movements.","zh":"這位舞者肌肉發達的身體使動作既優雅又有力。"}]},{"word":"museum","pos":"n.","phonetic":"[mjuˈziəm]","meaning":"博物館","definition":"a building where art or historical objects are shown","collocations":["visit a museum","art museum","museum exhibit"],"example":"We visited the art museum during our trip to the city.","exampleZh":"我們在城市之旅中參觀了美術館。","synonyms":[],"level":2,"theme":"藝術與音樂","examples":[{"en":"We visited the art museum during our trip to the city.","zh":"我們在城市之旅中參觀了美術館。"},{"en":"We spent the whole afternoon exploring the science museum.","zh":"我們花了整個下午探索這座科學博物館。"},{"en":"The new museum exhibit displays paintings from the last century.","zh":"這個新的博物館展覽展出了上個世紀的畫作。"}]},{"word":"mushroom","pos":"n. / v.","phonetic":"[ˈmʌʃrʊm]","meaning":"蘑菇；迅速增長","definition":"a fungus with a stem and cap, often edible; to grow rapidly","collocations":["fried mushroom","mushroom soup","mushroom in size"],"example":"She added fresh mushrooms to the soup.","exampleZh":"她在湯裡加了新鮮的蘑菇。","synonyms":[],"level":2,"theme":"食物與烹飪","examples":[{"en":"She added fresh mushrooms to the soup.","zh":"她在湯裡加了新鮮的蘑菇。"},{"en":"A warm bowl of mushroom soup is perfect on a cold day.","zh":"寒冷的日子裡，一碗溫熱的蘑菇湯再完美不過了。"},{"en":"New coffee shops mushroomed all over the busy neighborhood.","zh":"新的咖啡店在這個熱鬧的社區裡如雨後春筍般冒出。"}]},{"word":"music","pos":"n.","phonetic":"[ˈmjuzɪk]","meaning":"音樂","definition":"sounds arranged in a pleasing pattern","collocations":["listen to music","classical music","music class"],"example":"She listens to music while doing her homework.","exampleZh":"她一邊做作業一邊聽音樂。","synonyms":[],"level":1,"theme":"藝術與音樂","examples":[{"en":"She listens to music while doing her homework.","zh":"她一邊做作業一邊聽音樂。"},{"en":"He plays classical music softly while reading a book.","zh":"他一邊看書一邊輕輕地播放古典音樂。"},{"en":"Our music class starts right after the lunch break.","zh":"我們的音樂課在午休後緊接著開始。"}]},{"word":"musical","pos":"adj. / n.","phonetic":"[ˈmjuzɪkl̩]","meaning":"音樂的；音樂劇","definition":"relating to music; a play or film with singing and dancing","collocations":["musical instrument","musical talent","Broadway musical"],"example":"He has great musical talent and plays three instruments.","exampleZh":"他很有音樂天賦，會演奏三種樂器。","synonyms":[],"level":2,"theme":"藝術與音樂","examples":[{"en":"He has great musical talent and plays three instruments.","zh":"他很有音樂天賦，會演奏三種樂器。"},{"en":"She has real musical talent and sings in the school choir.","zh":"她有真正的音樂天賦，並在學校合唱團裡唱歌。"},{"en":"We watched an exciting musical full of singing and dancing.","zh":"我們看了一齣充滿歌唱與舞蹈的精彩音樂劇。"}]},{"word":"musician","pos":"n.","phonetic":"[mjuˈzɪʃən]","meaning":"音樂家","definition":"a person who plays or writes music","collocations":["talented musician","professional musician","street musician"],"example":"The street musician played beautiful violin music.","exampleZh":"這位街頭音樂家演奏了美妙的小提琴音樂。","synonyms":[],"level":2,"theme":"工作與職業","examples":[{"en":"The street musician played beautiful violin music.","zh":"這位街頭音樂家演奏了美妙的小提琴音樂。"},{"en":"A talented musician performed live during the school festival.","zh":"一位才華洋溢的音樂家在校慶時現場演出。"},{"en":"The street musician earned coins by playing lovely tunes.","zh":"這位街頭音樂家靠演奏動聽的曲子賺取零錢。"}]},{"word":"must","pos":"v. / n.","phonetic":"[mʌst]","meaning":"必須；必要的事物","definition":"used to show that something is necessary","collocations":["must-have","must do","you must"],"example":"You must wear a helmet when riding a motorcycle.","exampleZh":"你騎摩托車時必須戴安全帽。","synonyms":["have to"],"level":1,"theme":"抽象概念","examples":[{"en":"You must wear a helmet when riding a motorcycle.","zh":"你騎摩托車時必須戴安全帽。"},{"en":"Students must finish their homework before watching television.","zh":"學生必須在看電視前完成作業。"},{"en":"A warm coat is a real must during the cold winter.","zh":"在寒冷的冬天，一件保暖外套是必備之物。"}]},{"word":"mustache","pos":"n.","phonetic":"[ˈmʌstæʃ]","meaning":"八字鬍","definition":"hair that grows above a man's upper lip","collocations":["grow a mustache","thick mustache","shave a mustache"],"example":"He grew a mustache over the summer.","exampleZh":"他在夏天蓄了鬍子。","synonyms":[],"level":3,"theme":"服裝與外表","examples":[{"en":"He grew a mustache over the summer.","zh":"他在夏天蓄了鬍子。"},{"en":"The old sailor had a thick grey mustache and kind eyes.","zh":"那位年長的水手留著濃密的灰色八字鬍，眼神慈祥。"},{"en":"He decided to shave his mustache before the interview.","zh":"他決定在面試前刮掉八字鬍。"}]},{"word":"mustard","pos":"n.","phonetic":"[ˈmʌstɚd]","meaning":"芥末醬","definition":"a yellow paste made from mustard seeds, used as a condiment","collocations":["mustard sauce","hot dog with mustard","yellow mustard"],"example":"He put mustard on his hot dog.","exampleZh":"他在熱狗上加了芥末醬。","synonyms":[],"level":3,"theme":"食物與烹飪","examples":[{"en":"He put mustard on his hot dog.","zh":"他在熱狗上加了芥末醬。"},{"en":"She spread a little yellow mustard on her sandwich.","zh":"她在三明治上抹了一點黃芥末醬。"},{"en":"I always order my hot dog with mustard and onions.","zh":"我點熱狗時總是加芥末醬和洋蔥。"}]},{"word":"mutation","pos":"n.","phonetic":"[mjuˈteʃən]","meaning":"突變","definition":"a change in the genetic structure of an organism","collocations":["genetic mutation","gene mutation","cause a mutation"],"example":"The scientist studied a rare genetic mutation.","exampleZh":"這位科學家研究一種罕見的基因突變。","synonyms":[],"level":6,"theme":"科學與數學","examples":[{"en":"The scientist studied a rare genetic mutation.","zh":"這位科學家研究一種罕見的基因突變。"},{"en":"A tiny genetic mutation can change the color of a flower.","zh":"微小的基因突變可以改變花朵的顏色。"},{"en":"Scientists study how a gene mutation causes certain diseases.","zh":"科學家研究基因突變如何導致某些疾病。"}]},{"word":"mute","pos":"adj. / v.","phonetic":"[mjut]","meaning":"沉默的；靜音","definition":"unable or unwilling to speak; to turn off sound","collocations":["mute button","remain mute","mute the TV"],"example":"She pressed the mute button during the commercial.","exampleZh":"廣告時她按下了靜音按鈕。","synonyms":["silent"],"level":5,"theme":"科技與媒體","examples":[{"en":"She pressed the mute button during the commercial.","zh":"廣告時她按下了靜音按鈕。"},{"en":"He hit the mute button so the loud advertisement went silent.","zh":"他按下靜音鍵，吵鬧的廣告就安靜了下來。"},{"en":"The shocking news left the whole audience completely mute.","zh":"這則震驚的消息讓全場觀眾都啞口無言。"}]},{"word":"mutter","pos":"v.","phonetic":"[ˈmʌtɚ]","meaning":"喃喃自語；小聲抱怨","definition":"to speak quietly in a low voice, often complaining","collocations":["mutter under one's breath","mutter angrily","mutter something"],"example":"He muttered angrily under his breath after losing the game.","exampleZh":"輸掉比賽後，他氣呼呼地小聲嘀咕。","synonyms":["murmur","grumble"],"level":5,"theme":"溝通與語言","examples":[{"en":"He muttered angrily under his breath after losing the game.","zh":"輸掉比賽後，他氣呼呼地小聲嘀咕。"},{"en":"She began to mutter under her breath about the long wait.","zh":"她開始低聲抱怨等了這麼久。"},{"en":"The old man muttered something and shuffled slowly away.","zh":"那位老人喃喃地說了些話，緩緩地拖著腳步離開。"}]},{"word":"mutton","pos":"n.","phonetic":"[ˈmʌtn̩]","meaning":"羊肉","definition":"the meat of an adult sheep","collocations":["roast mutton","mutton curry","mutton stew"],"example":"They served mutton curry at the restaurant.","exampleZh":"這間餐廳供應羊肉咖哩。","synonyms":[],"level":4,"theme":"食物與烹飪","examples":[{"en":"They served mutton curry at the restaurant.","zh":"這間餐廳供應羊肉咖哩。"},{"en":"Grandmother slowly cooked a delicious mutton stew all afternoon.","zh":"奶奶花了整個下午慢燉一鍋美味的羊肉燉菜。"},{"en":"The restaurant is famous for its spicy mutton curry.","zh":"這家餐廳以辣味的羊肉咖哩聞名。"}]},{"word":"mutual","pos":"adj.","phonetic":"[ˈmjutʃuəl]","meaning":"互相的；共同的","definition":"felt or done equally by two or more people","collocations":["mutual respect","mutual friend","mutual agreement"],"example":"Their friendship is built on mutual respect and trust.","exampleZh":"他們的友誼建立在互相尊重與信任之上。","synonyms":["reciprocal","common"],"level":5,"theme":"抽象概念","examples":[{"en":"Their friendship is built on mutual respect and trust.","zh":"他們的友誼建立在互相尊重與信任之上。"},{"en":"A good team depends on mutual respect among its members.","zh":"好的團隊仰賴成員之間的互相尊重。"},{"en":"We were introduced by a mutual friend at the party.","zh":"我們是在派對上經由共同的朋友介紹認識的。"}]},{"word":"myself","pos":"pron.","phonetic":"[maɪˈsɛlf]","meaning":"我自己","definition":"used to refer back to the speaker","collocations":["by myself","enjoy myself","myself included"],"example":"I made this cake myself for the party.","exampleZh":"這個蛋糕是我自己為派對做的。","synonyms":[],"level":1,"theme":"抽象概念","examples":[{"en":"I made this cake myself for the party.","zh":"這個蛋糕是我自己為派對做的。"},{"en":"I fixed the broken bicycle all by myself yesterday.","zh":"我昨天自己一個人把壞掉的腳踏車修好了。"},{"en":"I really enjoyed myself at the beach with my friends.","zh":"我和朋友在海邊玩得非常盡興。"}]},{"word":"mysterious","pos":"adj.","phonetic":"[mɪˈstɪriəs]","meaning":"神秘的","definition":"difficult to understand or explain","collocations":["mysterious stranger","mysterious disappearance","mysterious sound"],"example":"A mysterious stranger appeared at the door last night.","exampleZh":"昨晚有個神秘的陌生人出現在門口。","synonyms":["puzzling","strange"],"level":3,"theme":"性質與描述","examples":[{"en":"A mysterious stranger appeared at the door last night.","zh":"昨晚有個神秘的陌生人出現在門口。"},{"en":"A mysterious sound came from the empty room upstairs.","zh":"樓上空房間傳來一陣神秘的聲音。"},{"en":"The mysterious disappearance of the ship puzzled everyone.","zh":"那艘船神秘的失蹤讓所有人都困惑不已。"}]},{"word":"mystery","pos":"n.","phonetic":"[ˈmɪstəri]","meaning":"謎；神秘","definition":"something that is difficult to explain or understand","collocations":["solve a mystery","mystery novel","remain a mystery"],"example":"The detective finally solved the mystery of the missing jewels.","exampleZh":"這位偵探終於解開了失竊珠寶的謎團。","synonyms":["puzzle","enigma"],"level":3,"theme":"抽象概念","examples":[{"en":"The detective finally solved the mystery of the missing jewels.","zh":"這位偵探終於解開了失竊珠寶的謎團。"},{"en":"She stayed up late reading an exciting mystery novel.","zh":"她熬夜讀一本刺激的推理小說。"},{"en":"How the ancient pyramids were built remains a mystery.","zh":"古代金字塔是如何建成的仍是一個謎。"}]},{"word":"myth","pos":"n.","phonetic":"[mɪθ]","meaning":"神話；迷思","definition":"a traditional story or a widely believed but false idea","collocations":["ancient myth","popular myth","just a myth"],"example":"The ancient Greeks had many myths about their gods.","exampleZh":"古希臘人有許多關於他們神祇的神話。","synonyms":["legend"],"level":4,"theme":"社會與文化","examples":[{"en":"The ancient Greeks had many myths about their gods.","zh":"古希臘人有許多關於他們神祇的神話。"},{"en":"Every ancient culture created its own myths about the stars.","zh":"每個古老的文化都創造了自己關於星星的神話。"},{"en":"It is just a popular myth that goldfish have no memory.","zh":"金魚沒有記憶只是一個廣為流傳的迷思。"}]},{"word":"mythology","pos":"n.","phonetic":"[mɪˈθɑlədʒi]","meaning":"神話學；神話體系","definition":"a collection of myths, especially of a particular culture","collocations":["Greek mythology","study mythology","ancient mythology"],"example":"She wrote her thesis on Greek mythology.","exampleZh":"她的論文寫的是希臘神話。","synonyms":[],"level":5,"theme":"社會與文化","examples":[{"en":"She wrote her thesis on Greek mythology.","zh":"她的論文寫的是希臘神話。"},{"en":"In Greek mythology, many gods lived on a high mountain.","zh":"在希臘神話中，許多神祇住在一座高山上。"},{"en":"He loves to study the ancient mythology of northern Europe.","zh":"他熱愛研究北歐的古老神話。"}]},{"word":"naive","pos":"adj.","phonetic":"[naˈiv]","meaning":"天真的；幼稚的","definition":"showing a lack of experience or judgment","collocations":["naive question","politically naive","naive belief"],"example":"It was naive of him to trust a stranger so easily.","exampleZh":"他這麼輕易相信陌生人真是天真。","synonyms":["innocent","gullible"],"level":5,"theme":"情緒與感受","examples":[{"en":"It was naive of him to trust a stranger so easily.","zh":"他這麼輕易相信陌生人真是天真。"},{"en":"It was naive of her to believe the stranger's promise.","zh":"她相信陌生人的承諾實在太天真了。"},{"en":"He asked a rather naive question about how money works.","zh":"他問了一個關於金錢運作相當天真的問題。"}]},{"word":"name","pos":"n. / v.","phonetic":"[nem]","meaning":"名字；名稱；為…命名","definition":"a word or set of words by which a person, animal, place, or thing is known","collocations":["first name","call someone names","name after"],"example":"My name is written on the first page of the book.","exampleZh":"我的名字寫在這本書的第一頁上。","synonyms":["title","label"],"level":1,"theme":"人物與家庭","examples":[{"en":"My name is written on the first page of the book.","zh":"我的名字寫在這本書的第一頁上。"},{"en":"Please write your first name clearly at the top.","zh":"請在最上方清楚地寫下你的名字。"},{"en":"They decided to name their daughter after her grandmother.","zh":"他們決定以祖母的名字為女兒命名。"}]},{"word":"namely","pos":"adv.","phonetic":"[ˈnemlɪ]","meaning":"即；也就是","definition":"that is to say; used to introduce something specific","collocations":["namely that","two options, namely"],"example":"There is one main reason, namely, the high cost.","exampleZh":"有一個主要原因，那就是高昂的成本。","synonyms":["that is"],"level":5,"theme":"溝通與語言","examples":[{"en":"There is one main reason, namely, the high cost.","zh":"有一個主要原因，那就是高昂的成本。"},{"en":"Only one student passed, namely the girl in the front row.","zh":"只有一位學生及格，也就是前排的那個女孩。"},{"en":"We have two choices, namely staying home or going out.","zh":"我們有兩個選擇，即待在家裡或出門。"}]},{"word":"narrate","pos":"v.","phonetic":"[næˈret]","meaning":"敘述；講述","definition":"to give a spoken account of something","collocations":["narrate a story","narrate a film"],"example":"The documentary was narrated by a famous actor.","exampleZh":"這部紀錄片由一位知名演員旁白敘述。","synonyms":["tell","recount"],"level":5,"theme":"藝術與音樂","examples":[{"en":"The documentary was narrated by a famous actor.","zh":"這部紀錄片由一位知名演員旁白敘述。"},{"en":"A famous actor was invited to narrate the nature film.","zh":"一位知名演員受邀為這部自然影片旁白。"},{"en":"Grandfather loves to narrate stories from his youth.","zh":"祖父喜歡講述他年輕時的故事。"}]},{"word":"narration","pos":"n.","phonetic":"[næˈreʃən]","meaning":"敘述；旁白","definition":"the act of telling a story or giving an account","collocations":["voice narration","the narration of events"],"example":"The narration explained the history of the ancient castle.","exampleZh":"旁白解說了這座古堡的歷史。","synonyms":[],"level":5,"theme":"藝術與音樂","examples":[{"en":"The narration explained the history of the ancient castle.","zh":"旁白解說了這座古堡的歷史。"},{"en":"The calm narration made the documentary easy to follow.","zh":"沉穩的旁白讓這部紀錄片容易理解。"},{"en":"Her clear narration of events helped the police a lot.","zh":"她對事件清楚的敘述對警方幫助很大。"}]},{"word":"narrative","pos":"n. / adj.","phonetic":"[ˈnærətɪv]","meaning":"敘事；故事的","definition":"a spoken or written account of connected events; a story","collocations":["narrative style","personal narrative","narrative poem"],"example":"The novel has a complex narrative structure.","exampleZh":"這部小說有著複雜的敘事結構。","synonyms":["story","account"],"level":5,"theme":"藝術與音樂","examples":[{"en":"The novel has a complex narrative structure.","zh":"這部小說有著複雜的敘事結構。"},{"en":"The teacher praised the boy's imaginative personal narrative.","zh":"老師稱讚這個男孩富有想像力的個人敘事。"},{"en":"This film tells its story in a simple narrative style.","zh":"這部電影以簡單的敘事風格講述故事。"}]},{"word":"narrow","pos":"adj. / v.","phonetic":"[ˈnæro]","meaning":"狹窄的；勉強的；使變窄","definition":"having a small distance from one side to the other","collocations":["narrow street","narrow escape","narrow down"],"example":"The car could barely fit through the narrow street.","exampleZh":"這輛車幾乎無法通過這條狹窄的街道。","synonyms":["thin","tight"],"level":2,"theme":"性質與描述","examples":[{"en":"The car could barely fit through the narrow street.","zh":"這輛車幾乎無法通過這條狹窄的街道。"},{"en":"They walked carefully along the narrow mountain path.","zh":"他們小心翼翼地沿著狹窄的山路行走。"},{"en":"Let's narrow down the list to just three good options.","zh":"我們把清單縮減到只剩三個好選項吧。"}]},{"word":"nasty","pos":"adj.","phonetic":"[ˈnæstɪ]","meaning":"令人不快的；惡劣的","definition":"very unpleasant or unkind","collocations":["nasty smell","nasty habit","nasty surprise"],"example":"The medicine has a nasty taste.","exampleZh":"這藥的味道很難聞。","synonyms":["unpleasant","mean"],"level":4,"theme":"性質與描述","examples":[{"en":"The medicine has a nasty taste.","zh":"這藥的味道很難聞。"},{"en":"A nasty smell came from the garbage left in the sun.","zh":"曬在太陽下的垃圾散發出難聞的氣味。"},{"en":"Biting your nails is a really nasty habit to break.","zh":"咬指甲是個很難戒掉的壞習慣。"}]},{"word":"nation","pos":"n.","phonetic":"[ˈneʃən]","meaning":"國家；民族","definition":"a country considered as a group of people with its own territory and government","collocations":["a developed nation","the nation's economy","united nations"],"example":"Every nation has its own culture and traditions.","exampleZh":"每個國家都有自己的文化和傳統。","synonyms":["country","state"],"level":2,"theme":"社會與文化","examples":[{"en":"Every nation has its own culture and traditions.","zh":"每個國家都有自己的文化和傳統。"},{"en":"The whole nation celebrated the team's surprising victory.","zh":"全國都在慶祝這支隊伍出乎意料的勝利。"},{"en":"A developed nation usually offers good education for all.","zh":"已開發國家通常為所有人提供良好的教育。"}]},{"word":"national","pos":"adj.","phonetic":"[ˈnæʃənl]","meaning":"國家的；全國性的","definition":"relating to or belonging to a particular nation","collocations":["national holiday","national park","national anthem"],"example":"Independence Day is a national holiday.","exampleZh":"獨立紀念日是一個全國性的假日。","synonyms":["nationwide"],"level":2,"theme":"社會與文化","examples":[{"en":"Independence Day is a national holiday.","zh":"獨立紀念日是一個全國性的假日。"},{"en":"Our family visited a beautiful national park last summer.","zh":"去年夏天我們全家造訪了一座美麗的國家公園。"},{"en":"Everyone stood up when the national anthem began to play.","zh":"當國歌開始演奏時，每個人都站了起來。"}]},{"word":"nationality","pos":"n.","phonetic":"[ˌnæʃəˈnælətɪ]","meaning":"國籍","definition":"the legal status of belonging to a particular nation","collocations":["dual nationality","of British nationality","apply for nationality"],"example":"What is your nationality?","exampleZh":"你的國籍是什麼？","synonyms":["citizenship"],"level":3,"theme":"社會與文化","examples":[{"en":"What is your nationality?","zh":"你的國籍是什麼？"},{"en":"The officer asked me to state my name and nationality.","zh":"那位官員要我說出我的姓名和國籍。"},{"en":"Because of his parents, he holds dual nationality.","zh":"由於父母的關係，他擁有雙重國籍。"}]},{"word":"nationwide","pos":"adj. / adv.","phonetic":"[ˈneʃənˌwaɪd]","meaning":"全國性的；全國範圍地","definition":"extending over or including a whole nation","collocations":["nationwide survey","nationwide campaign","broadcast nationwide"],"example":"The company launched a nationwide advertising campaign.","exampleZh":"這家公司發起了一場全國性的廣告活動。","synonyms":["national"],"level":4,"theme":"社會與文化","examples":[{"en":"The company launched a nationwide advertising campaign.","zh":"這家公司發起了一場全國性的廣告活動。"},{"en":"The store held a nationwide survey about shopping habits.","zh":"這家商店進行了一項關於購物習慣的全國性調查。"},{"en":"The important speech was broadcast nationwide last night.","zh":"這場重要的演說昨晚在全國播出。"}]},{"word":"native","pos":"adj. / n.","phonetic":"[ˈnetɪv]","meaning":"本地的；本土的；當地人","definition":"belonging to a particular place by birth","collocations":["native speaker","native language","native to"],"example":"She is a native speaker of French.","exampleZh":"她是法語的母語人士。","synonyms":["local","indigenous"],"level":3,"theme":"人物與家庭","examples":[{"en":"She is a native speaker of French.","zh":"她是法語的母語人士。"},{"en":"As a native speaker, she pronounces every word perfectly.","zh":"身為母語人士，她把每個字都發音得很完美。"},{"en":"This colorful bird is native to the tropical rainforest.","zh":"這種色彩鮮豔的鳥類原產於熱帶雨林。"}]},{"word":"natural","pos":"adj.","phonetic":"[ˈnætʃərəl]","meaning":"自然的；天生的；正常的","definition":"existing in nature and not made or caused by people","collocations":["natural resources","natural disaster","natural talent"],"example":"Earthquakes are natural disasters that can cause great damage.","exampleZh":"地震是一種能造成巨大破壞的自然災害。","synonyms":["genuine","innate"],"level":2,"theme":"自然與環境","examples":[{"en":"Earthquakes are natural disasters that can cause great damage.","zh":"地震是一種能造成巨大破壞的自然災害。"},{"en":"Our country is rich in natural resources like coal and gas.","zh":"我們國家擁有豐富的天然資源，如煤和天然氣。"},{"en":"She has a natural talent for painting and drawing.","zh":"她在繪畫方面有著天生的才能。"}]},{"word":"naturally","pos":"adv.","phonetic":"[ˈnætʃərəlɪ]","meaning":"自然地；天生地；當然","definition":"in a natural way; of course","collocations":["naturally curly","behave naturally","naturally gifted"],"example":"Naturally, she was upset when she heard the news.","exampleZh":"她聽到這消息時當然很沮喪。","synonyms":["of course"],"level":2,"theme":"性質與描述","examples":[{"en":"Naturally, she was upset when she heard the news.","zh":"她聽到這消息時當然很沮喪。"},{"en":"Her hair is naturally curly and shines in the sun.","zh":"她的頭髮天生捲曲，在陽光下閃閃發亮。"},{"en":"Naturally, everyone wanted to help after hearing her story.","zh":"聽了她的故事後，大家自然都想幫忙。"}]},{"word":"nature","pos":"n.","phonetic":"[ˈnetʃɚ]","meaning":"大自然；本性；本質","definition":"the physical world and everything in it that is not made by humans","collocations":["the nature of","human nature","love nature"],"example":"He loves spending time in nature.","exampleZh":"他喜歡花時間親近大自然。","synonyms":["environment","character"],"level":2,"theme":"自然與環境","examples":[{"en":"He loves spending time in nature.","zh":"他喜歡花時間親近大自然。"},{"en":"On weekends we like hiking and enjoying nature together.","zh":"週末我們喜歡一起健行，享受大自然。"},{"en":"It is human nature to feel curious about the unknown.","zh":"對未知感到好奇是人的本性。"}]},{"word":"naughty","pos":"adj.","phonetic":"[ˈnɔtɪ]","meaning":"頑皮的；淘氣的","definition":"behaving badly, especially of a child","collocations":["naughty boy","naughty behavior","act naughty"],"example":"The naughty boy hid his sister's toys.","exampleZh":"那個頑皮的男孩把他妹妹的玩具藏起來。","synonyms":["mischievous","disobedient"],"level":2,"theme":"人物與家庭","examples":[{"en":"The naughty boy hid his sister's toys.","zh":"那個頑皮的男孩把他妹妹的玩具藏起來。"},{"en":"The naughty boy drew funny faces all over his desk.","zh":"這個頑皮的男孩在桌子上到處畫鬼臉。"},{"en":"Her naughty behavior made the whole classroom laugh.","zh":"她淘氣的舉動逗得全班哄堂大笑。"}]},{"word":"naval","pos":"adj.","phonetic":"[ˈnevl]","meaning":"海軍的","definition":"relating to a navy or navies","collocations":["naval base","naval officer","naval power"],"example":"The country built a large naval base on the coast.","exampleZh":"這個國家在海岸建了一個大型海軍基地。","synonyms":[],"level":5,"theme":"政治與法律","examples":[{"en":"The country built a large naval base on the coast.","zh":"這個國家在海岸建了一個大型海軍基地。"},{"en":"His grandfather trained young sailors at a large naval base.","zh":"他的祖父在一座大型海軍基地訓練年輕水手。"},{"en":"The proud naval officer wore a spotless white uniform.","zh":"那位驕傲的海軍軍官身穿一塵不染的白色制服。"}]},{"word":"navigate","pos":"v.","phonetic":"[ˈnævəˌget]","meaning":"導航；航行；探索","definition":"to plan and direct the route of a ship, aircraft, or vehicle","collocations":["navigate a ship","navigate the internet","navigate through"],"example":"The captain used a map to navigate the ship safely.","exampleZh":"船長使用地圖安全地為船隻導航。","synonyms":["steer","guide"],"level":5,"theme":"交通與旅行","examples":[{"en":"The captain used a map to navigate the ship safely.","zh":"船長使用地圖安全地為船隻導航。"},{"en":"The captain skillfully navigated the ship through the narrow channel.","zh":"船長熟練地駕駛船隻通過狹窄的水道。"},{"en":"My grandmother finds it hard to navigate the internet alone.","zh":"我奶奶覺得自己上網瀏覽很困難。"}]},{"word":"navigation","pos":"n.","phonetic":"[ˌnævəˈgeʃən]","meaning":"導航；航行術","definition":"the process or activity of planning a route and guiding movement","collocations":["GPS navigation","navigation system","satellite navigation"],"example":"The ship's navigation system guided it through the storm.","exampleZh":"這艘船的導航系統引導它穿過暴風雨。","synonyms":[],"level":5,"theme":"交通與旅行","examples":[{"en":"The ship's navigation system guided it through the storm.","zh":"這艘船的導航系統引導它穿過暴風雨。"},{"en":"The plane's navigation system kept it on the right course.","zh":"飛機的導航系統讓它保持在正確的航線上。"},{"en":"Modern drivers rely on GPS navigation to find new places.","zh":"現代駕駛人仰賴 GPS 導航來尋找陌生的地方。"}]},{"word":"navy","pos":"n.","phonetic":"[ˈnevɪ]","meaning":"海軍；深藍色","definition":"the part of a country's armed forces that fights at sea","collocations":["join the navy","navy blue","serve in the navy"],"example":"His father served in the navy for twenty years.","exampleZh":"他父親在海軍服役了二十年。","synonyms":["fleet"],"level":3,"theme":"政治與法律","examples":[{"en":"His father served in the navy for twenty years.","zh":"他父親在海軍服役了二十年。"},{"en":"He decided to join the navy right after finishing school.","zh":"他決定畢業後立刻加入海軍。"},{"en":"She wore a smart navy blue jacket to the interview.","zh":"她穿了一件俐落的深藍色外套去面試。"}]},{"word":"near","pos":"adv. / prep. / adj.","phonetic":"[nɪr]","meaning":"接近；靠近的","definition":"a short distance away in space or time","collocations":["near future","live near","draw near"],"example":"The school is near my house.","exampleZh":"學校離我家很近。","synonyms":["close","nearby"],"level":1,"theme":"時間與空間","examples":[{"en":"The school is near my house.","zh":"學校離我家很近。"},{"en":"In the near future, most cars may run on electricity.","zh":"在不久的將來，大多數的車可能都用電力驅動。"},{"en":"They chose to live near the school for their children.","zh":"他們為了孩子選擇住在學校附近。"}]},{"word":"nearby","pos":"adj. / adv.","phonetic":"[ˈnɪrˌbaɪ]","meaning":"附近的；在附近","definition":"not far away in distance","collocations":["nearby town","live nearby","a nearby restaurant"],"example":"We had dinner at a nearby restaurant.","exampleZh":"我們在附近的一家餐廳吃了晚餐。","synonyms":["close","near"],"level":2,"theme":"時間與空間","examples":[{"en":"We had dinner at a nearby restaurant.","zh":"我們在附近的一家餐廳吃了晚餐。"},{"en":"We bought fresh fruit from a small nearby market.","zh":"我們在附近的一個小市場買了新鮮的水果。"},{"en":"If you feel sick, there is a clinic nearby.","zh":"如果你覺得不舒服，附近有一家診所。"}]},{"word":"nearly","pos":"adv.","phonetic":"[ˈnɪrlɪ]","meaning":"幾乎；差不多","definition":"almost but not quite","collocations":["nearly finished","nearly every day","nearly impossible"],"example":"It's nearly midnight, so we should go to bed.","exampleZh":"現在快午夜了，我們應該去睡覺了。","synonyms":["almost"],"level":2,"theme":"時間與空間","examples":[{"en":"It's nearly midnight, so we should go to bed.","zh":"現在快午夜了，我們應該去睡覺了。"},{"en":"I have nearly finished reading this long history book.","zh":"我快要讀完這本厚厚的歷史書了。"},{"en":"Climbing that steep cliff is nearly impossible without training.","zh":"沒有受過訓練，攀爬那座陡峭的懸崖幾乎是不可能的。"}]},{"word":"nearsighted","pos":"adj.","phonetic":"[ˈnɪrˈsaɪtɪd]","meaning":"近視的","definition":"unable to see distant objects clearly","collocations":["nearsighted person","become nearsighted"],"example":"He has been nearsighted since childhood and wears glasses.","exampleZh":"他從小就近視，戴著眼鏡。","synonyms":["myopic"],"level":4,"theme":"身體與健康","examples":[{"en":"He has been nearsighted since childhood and wears glasses.","zh":"他從小就近視，戴著眼鏡。"},{"en":"Because he is nearsighted, he cannot read the distant sign.","zh":"因為他近視，所以看不清遠處的標誌。"},{"en":"Many students become nearsighted from staring at screens too long.","zh":"許多學生因為長時間盯著螢幕而變得近視。"}]},{"word":"neat","pos":"adj.","phonetic":"[nit]","meaning":"整潔的；乾淨俐落的","definition":"tidy and in good order","collocations":["neat and tidy","neat handwriting","keep neat"],"example":"She keeps her room neat and clean.","exampleZh":"她把房間保持得整潔乾淨。","synonyms":["tidy","orderly"],"level":2,"theme":"性質與描述","examples":[{"en":"She keeps her room neat and clean.","zh":"她把房間保持得整潔乾淨。"},{"en":"Her desk is always neat and tidy before class begins.","zh":"上課前她的桌子總是整潔有序。"},{"en":"The teacher praised his neat handwriting on the report.","zh":"老師稱讚他報告上工整的字跡。"}]},{"word":"necessarily","pos":"adv.","phonetic":"[ˌnɛsəˈsɛrəlɪ]","meaning":"必然地；一定","definition":"as a necessary result; inevitably","collocations":["not necessarily true","necessarily mean"],"example":"Being rich doesn't necessarily mean being happy.","exampleZh":"富有並不一定代表快樂。","synonyms":["inevitably"],"level":4,"theme":"抽象概念","examples":[{"en":"Being rich doesn't necessarily mean being happy.","zh":"富有並不一定代表快樂。"},{"en":"A high price does not necessarily mean better quality.","zh":"高價格不一定代表品質更好。"},{"en":"Being famous does not necessarily make a person happy.","zh":"出名不一定會讓一個人快樂。"}]},{"word":"necessary","pos":"adj.","phonetic":"[ˈnɛsəˌsɛrɪ]","meaning":"必要的；必需的","definition":"needed in order to achieve a certain result","collocations":["necessary condition","if necessary","absolutely necessary"],"example":"Water is necessary for all forms of life.","exampleZh":"水對所有生命形式都是必需的。","synonyms":["essential","required"],"level":2,"theme":"抽象概念","examples":[{"en":"Water is necessary for all forms of life.","zh":"水對所有生命形式都是必需的。"},{"en":"It is necessary to save money for unexpected emergencies.","zh":"為意外的緊急狀況存錢是必要的。"},{"en":"Please call me back only if it is absolutely necessary.","zh":"只有在絕對必要時才回我電話。"}]},{"word":"necessity","pos":"n.","phonetic":"[nəˈsɛsətɪ]","meaning":"必要性；必需品","definition":"the fact of being required or indispensable","collocations":["out of necessity","basic necessity","a necessity of life"],"example":"Clean water is a basic necessity for survival.","exampleZh":"乾淨的水是生存的基本必需品。","synonyms":["requirement"],"level":4,"theme":"抽象概念","examples":[{"en":"Clean water is a basic necessity for survival.","zh":"乾淨的水是生存的基本必需品。"},{"en":"For hikers, clean drinking water is a basic necessity.","zh":"對登山者來說，乾淨的飲用水是基本必需品。"},{"en":"Out of necessity, she learned to cook for the whole family.","zh":"出於需要，她學會了為全家人做飯。"}]},{"word":"neck","pos":"n.","phonetic":"[nɛk]","meaning":"脖子；頸部","definition":"the part of the body connecting the head to the shoulders","collocations":["a stiff neck","neck and neck","wrap around the neck"],"example":"The giraffe has a very long neck.","exampleZh":"長頸鹿有非常長的脖子。","synonyms":[],"level":1,"theme":"身體與健康","examples":[{"en":"The giraffe has a very long neck.","zh":"長頸鹿有非常長的脖子。"},{"en":"After sleeping badly, he woke up with a stiff neck.","zh":"睡得不好之後，他醒來時脖子僵硬。"},{"en":"The two runners were neck and neck until the very end.","zh":"這兩名跑者直到最後都不分軒輊。"}]},{"word":"necklace","pos":"n.","phonetic":"[ˈnɛklɪs]","meaning":"項鍊","definition":"a piece of jewelry worn around the neck","collocations":["wear a necklace","gold necklace","pearl necklace"],"example":"She wore a beautiful pearl necklace to the party.","exampleZh":"她戴著一條漂亮的珍珠項鍊去參加派對。","synonyms":[],"level":1,"theme":"服裝與外表","examples":[{"en":"She wore a beautiful pearl necklace to the party.","zh":"她戴著一條漂亮的珍珠項鍊去參加派對。"},{"en":"Her mother gave her a delicate gold necklace for her birthday.","zh":"她媽媽送她一條精緻的金項鍊當生日禮物。"},{"en":"She carefully placed the pearl necklace back in its box.","zh":"她小心地把珍珠項鍊放回盒子裡。"}]},{"word":"need","pos":"v. / n.","phonetic":"[nid]","meaning":"需要；需求","definition":"to require something because it is essential","collocations":["in need of","need help","basic needs"],"example":"Plants need sunlight and water to grow.","exampleZh":"植物需要陽光和水才能生長。","synonyms":["require","want"],"level":1,"theme":"抽象概念","examples":[{"en":"Plants need sunlight and water to grow.","zh":"植物需要陽光和水才能生長。"},{"en":"Newborn babies need plenty of sleep and gentle care.","zh":"新生兒需要充足的睡眠和溫柔的照顧。"},{"en":"The shelter is in urgent need of warm blankets this winter.","zh":"這間收容所今年冬天急需保暖的毛毯。"}]},{"word":"needle","pos":"n.","phonetic":"[ˈnidl]","meaning":"針；縫衣針","definition":"a thin, sharp piece of metal used for sewing or injections","collocations":["needle and thread","sewing needle","a needle in a haystack"],"example":"She threaded the needle carefully.","exampleZh":"她小心地穿針引線。","synonyms":[],"level":2,"theme":"居家與生活","examples":[{"en":"She threaded the needle carefully.","zh":"她小心地穿針引線。"},{"en":"She carefully threaded the needle to mend her torn shirt.","zh":"她小心地穿針，好縫補破掉的襯衫。"},{"en":"Finding my lost ring here is like finding a needle in a haystack.","zh":"在這裡找我遺失的戒指就像大海撈針一樣。"}]},{"word":"negative","pos":"adj. / n.","phonetic":"[ˈnɛgətɪv]","meaning":"負面的；消極的；否定的","definition":"expressing denial, refusal, or the presence of something bad","collocations":["negative effect","negative attitude","test negative"],"example":"Try not to think in such a negative way.","exampleZh":"試著不要那樣負面地思考。","synonyms":["pessimistic","unfavorable"],"level":3,"theme":"情緒與感受","examples":[{"en":"Try not to think in such a negative way.","zh":"試著不要那樣負面地思考。"},{"en":"Too much sugar can have a negative effect on your health.","zh":"過多的糖分可能對你的健康產生負面影響。"},{"en":"He tried to change his negative attitude toward failure.","zh":"他試著改變自己對失敗的消極態度。"}]},{"word":"neglect","pos":"v. / n.","phonetic":"[nɪˈglɛkt]","meaning":"忽視；疏忽","definition":"to fail to take care of someone or something","collocations":["neglect one's duty","child neglect","neglect one's health"],"example":"He neglected his health because of his busy work.","exampleZh":"他因工作繁忙而忽視了自己的健康。","synonyms":["ignore","overlook"],"level":4,"theme":"動作與行為","examples":[{"en":"He neglected his health because of his busy work.","zh":"他因工作繁忙而忽視了自己的健康。"},{"en":"Do not neglect your health just to earn more money.","zh":"不要為了多賺錢而忽視自己的健康。"},{"en":"The empty house fell apart after years of neglect.","zh":"這棟空屋在多年疏於照料後逐漸崩壞。"}]},{"word":"negotiate","pos":"v.","phonetic":"[nɪˈgoʃɪˌet]","meaning":"談判；協商","definition":"to have formal discussions to reach an agreement","collocations":["negotiate a deal","negotiate with","negotiate a price"],"example":"The two companies negotiated a new contract.","exampleZh":"兩家公司協商了一份新合約。","synonyms":["bargain","discuss"],"level":4,"theme":"商業與金錢","examples":[{"en":"The two companies negotiated a new contract.","zh":"兩家公司協商了一份新合約。"},{"en":"The two companies met to negotiate a fair business deal.","zh":"兩家公司會面協商一筆公平的生意。"},{"en":"She managed to negotiate a lower price for the old car.","zh":"她成功地談到了那輛舊車較低的價格。"}]},{"word":"negotiation","pos":"n.","phonetic":"[nɪˌgoʃɪˈeʃən]","meaning":"談判；協商","definition":"discussion aimed at reaching an agreement","collocations":["peace negotiation","under negotiation","negotiation skills"],"example":"The negotiation between the two countries lasted for months.","exampleZh":"兩國之間的談判持續了好幾個月。","synonyms":["bargaining"],"level":5,"theme":"商業與金錢","examples":[{"en":"The negotiation between the two countries lasted for months.","zh":"兩國之間的談判持續了好幾個月。"},{"en":"The peace negotiation between the two sides lasted many days.","zh":"雙方的和平談判持續了許多天。"},{"en":"Good negotiation skills helped her close the difficult deal.","zh":"良好的談判技巧幫助她完成了這筆棘手的交易。"}]},{"word":"neighbor","pos":"n.","phonetic":"[ˈnebɚ]","meaning":"鄰居","definition":"a person who lives near another person","collocations":["next-door neighbor","good neighbor","noisy neighbor"],"example":"Our neighbor helped us carry the boxes.","exampleZh":"我們的鄰居幫我們搬箱子。","synonyms":[],"level":2,"theme":"人物與家庭","examples":[{"en":"Our neighbor helped us carry the boxes.","zh":"我們的鄰居幫我們搬箱子。"},{"en":"Our next-door neighbor kindly watered our plants during the trip.","zh":"我們的隔壁鄰居在旅行期間好心地幫我們澆花。"},{"en":"A noisy neighbor kept playing loud music until midnight.","zh":"一個吵鬧的鄰居一直把音樂開得很大聲直到半夜。"}]},{"word":"neighborhood","pos":"n.","phonetic":"[ˈnebɚˌhʊd]","meaning":"鄰近地區；社區","definition":"a district or area, especially one forming a community","collocations":["quiet neighborhood","in the neighborhood","neighborhood watch"],"example":"They live in a quiet neighborhood near the park.","exampleZh":"他們住在公園附近的一個安靜社區。","synonyms":["community","area"],"level":3,"theme":"居家與生活","examples":[{"en":"They live in a quiet neighborhood near the park.","zh":"他們住在公園附近的一個安靜社區。"},{"en":"They moved to a quiet neighborhood with friendly people.","zh":"他們搬到了一個居民友善的安靜社區。"},{"en":"Our neighborhood watch keeps the streets safe at night.","zh":"我們的社區守望相助隊讓夜間的街道保持安全。"}]},{"word":"neither","pos":"pron. / conj. / adj.","phonetic":"[ˈniðɚ]","meaning":"兩者都不","definition":"not either of two people or things","collocations":["neither...nor","neither of us","neither option"],"example":"Neither of the two answers is correct.","exampleZh":"這兩個答案都不正確。","synonyms":[],"level":2,"theme":"抽象概念","examples":[{"en":"Neither of the two answers is correct.","zh":"這兩個答案都不正確。"},{"en":"Neither of us had ever tried surfing before that day.","zh":"在那天之前我們兩個都沒嘗試過衝浪。"},{"en":"She likes neither the color nor the style of the dress.","zh":"這件洋裝的顏色和款式她都不喜歡。"}]},{"word":"nephew","pos":"n.","phonetic":"[ˈnɛfju]","meaning":"姪子；外甥","definition":"the son of one's brother or sister, or of one's brother-in-law or sister-in-law","collocations":["favorite nephew","nephew and niece"],"example":"My nephew just started elementary school.","exampleZh":"我的姪子剛開始上小學。","synonyms":[],"level":2,"theme":"人物與家庭","examples":[{"en":"My nephew just started elementary school.","zh":"我的姪子剛開始上小學。"},{"en":"My little nephew loves building tall towers with blocks.","zh":"我的小姪子喜歡用積木堆高塔。"},{"en":"She bought a toy dinosaur for her favorite nephew.","zh":"她為她最疼愛的姪子買了一隻玩具恐龍。"}]},{"word":"nerve","pos":"n.","phonetic":"[nɝv]","meaning":"神經；勇氣；膽量","definition":"a thread-like structure carrying signals in the body; courage","collocations":["get on someone's nerves","lose one's nerve","nervous system"],"example":"Public speaking still gets on my nerves.","exampleZh":"公開演講仍然讓我很緊張。","synonyms":["courage"],"level":3,"theme":"身體與健康","examples":[{"en":"Public speaking still gets on my nerves.","zh":"公開演講仍然讓我很緊張。"},{"en":"His constant tapping really gets on my nerves.","zh":"他不停地敲桌子真的讓我很煩躁。"},{"en":"At the last moment, the diver lost his nerve.","zh":"在最後一刻，那名跳水者失去了勇氣。"}]},{"word":"nervous","pos":"adj.","phonetic":"[ˈnɝvəs]","meaning":"緊張的；不安的","definition":"anxious or worried about something","collocations":["nervous about","nervous breakdown","feel nervous"],"example":"She felt nervous before the exam.","exampleZh":"她考試前感到很緊張。","synonyms":["anxious","uneasy"],"level":2,"theme":"情緒與感受","examples":[{"en":"She felt nervous before the exam.","zh":"她考試前感到很緊張。"},{"en":"She felt very nervous about giving her first speech.","zh":"她對於發表第一次演說感到非常緊張。"},{"en":"He was nervous before opening the important exam results.","zh":"打開重要的考試成績前他很緊張。"}]},{"word":"nest","pos":"n. / v.","phonetic":"[nɛst]","meaning":"巢；窩；築巢","definition":"a structure built by a bird to lay eggs in","collocations":["bird's nest","build a nest","empty nest"],"example":"The bird built a nest in the tree.","exampleZh":"這隻鳥在樹上築了一個巢。","synonyms":[],"level":2,"theme":"動物與植物","examples":[{"en":"The bird built a nest in the tree.","zh":"這隻鳥在樹上築了一個巢。"},{"en":"Two small birds built a cozy nest under our roof.","zh":"兩隻小鳥在我們的屋簷下築了一個溫暖的巢。"},{"en":"When their children left home, the couple faced an empty nest.","zh":"孩子們離家後，這對夫妻面對著空巢期。"}]},{"word":"net","pos":"n. / adj.","phonetic":"[nɛt]","meaning":"網子；淨的","definition":"a material made of threads woven together with small holes","collocations":["fishing net","net income","surf the net"],"example":"The fisherman cast his net into the sea.","exampleZh":"漁夫把網子撒進海裡。","synonyms":[],"level":2,"theme":"科技與媒體","examples":[{"en":"The fisherman cast his net into the sea.","zh":"漁夫把網子撒進海裡。"},{"en":"The players jumped high to hit the ball over the net.","zh":"球員們高高跳起把球擊過球網。"},{"en":"After all costs, the shop's net income was quite small.","zh":"扣除所有成本後，這家店的淨收入相當微薄。"}]},{"word":"network","pos":"n.","phonetic":"[ˈnɛtˌwɝk]","meaning":"網路；人脈；網狀系統","definition":"a group of interconnected people, computers, or things","collocations":["social network","computer network","build a network"],"example":"She has a large network of friends and colleagues.","exampleZh":"她有一個龐大的朋友和同事人際網絡。","synonyms":["system"],"level":3,"theme":"科技與媒體","examples":[{"en":"She has a large network of friends and colleagues.","zh":"她有一個龐大的朋友和同事人際網絡。"},{"en":"A slow computer network delayed the whole team's work.","zh":"緩慢的電腦網路拖延了整個團隊的工作。"},{"en":"Over the years, she built a wide network of contacts.","zh":"多年來，她建立了廣泛的人脈網絡。"}]},{"word":"neutral","pos":"adj.","phonetic":"[ˈnjutrəl]","meaning":"中立的；中性的","definition":"not supporting either side in a conflict or dispute","collocations":["remain neutral","neutral country","neutral tone"],"example":"Switzerland remained neutral during the war.","exampleZh":"瑞士在戰爭期間保持中立。","synonyms":["impartial"],"level":4,"theme":"政治與法律","examples":[{"en":"Switzerland remained neutral during the war.","zh":"瑞士在戰爭期間保持中立。"},{"en":"A good judge must remain neutral and listen to both sides.","zh":"好的法官必須保持中立並聆聽雙方的意見。"},{"en":"She answered the difficult question in a calm, neutral tone.","zh":"她以冷靜中性的語氣回答了那個難題。"}]},{"word":"never","pos":"adv.","phonetic":"[ˈnɛvɚ]","meaning":"從不；絕不","definition":"at no time in the past or future","collocations":["never again","never mind","better late than never"],"example":"I have never been to Japan before.","exampleZh":"我以前從未去過日本。","synonyms":[],"level":1,"theme":"時間與空間","examples":[{"en":"I have never been to Japan before.","zh":"我以前從未去過日本。"},{"en":"I have never tasted such delicious homemade noodles before.","zh":"我以前從未嚐過這麼美味的手工麵條。"},{"en":"Never give up on your dreams, even when things get hard.","zh":"即使事情變得艱難，也絕不要放棄你的夢想。"}]},{"word":"nevertheless","pos":"adv.","phonetic":"[ˌnɛvɚðəˈlɛs]","meaning":"儘管如此；然而","definition":"in spite of that; nonetheless","collocations":["nevertheless, he tried","difficult nevertheless"],"example":"The task was difficult; nevertheless, she finished it.","exampleZh":"這項任務很困難，儘管如此她還是完成了。","synonyms":["however","nonetheless"],"level":5,"theme":"溝通與語言","examples":[{"en":"The task was difficult; nevertheless, she finished it.","zh":"這項任務很困難，儘管如此她還是完成了。"},{"en":"The path was steep; nevertheless, they reached the top.","zh":"這條路很陡；儘管如此，他們還是登上了山頂。"},{"en":"He was tired; nevertheless, he kept helping his classmates.","zh":"他很累；然而，他仍持續幫助同學。"}]},{"word":"new","pos":"adj.","phonetic":"[nju]","meaning":"新的；新鮮的","definition":"not existing before; recently made or discovered","collocations":["brand new","new year","new idea"],"example":"He bought a new car last week.","exampleZh":"他上週買了一輛新車。","synonyms":["fresh","recent"],"level":1,"theme":"性質與描述","examples":[{"en":"He bought a new car last week.","zh":"他上週買了一輛新車。"},{"en":"She had a brand new idea for the science project.","zh":"她對這個科學專題有了一個全新的點子。"},{"en":"We wished each other happiness for the new year.","zh":"我們互相祝福新的一年幸福快樂。"}]},{"word":"news","pos":"n.","phonetic":"[njuz]","meaning":"新聞；消息","definition":"information about recent events","collocations":["breaking news","good news","watch the news"],"example":"Did you watch the news last night?","exampleZh":"你昨晚看新聞了嗎？","synonyms":["information"],"level":1,"theme":"科技與媒體","examples":[{"en":"Did you watch the news last night?","zh":"你昨晚看新聞了嗎？"},{"en":"We were thrilled to hear the good news about her recovery.","zh":"聽到她康復的好消息，我們興奮不已。"},{"en":"Breaking news about the storm interrupted the television show.","zh":"關於這場風暴的即時新聞打斷了電視節目。"}]},{"word":"newspaper","pos":"n.","phonetic":"[ˈnjuzˌpepɚ]","meaning":"報紙","definition":"a printed publication containing news and articles","collocations":["read the newspaper","daily newspaper","local newspaper"],"example":"My grandfather reads the newspaper every morning.","exampleZh":"我祖父每天早上都看報紙。","synonyms":["paper"],"level":1,"theme":"科技與媒體","examples":[{"en":"My grandfather reads the newspaper every morning.","zh":"我祖父每天早上都看報紙。"},{"en":"He reads the daily newspaper while drinking his morning coffee.","zh":"他一邊喝早晨的咖啡一邊讀每日的報紙。"},{"en":"Her poem was published in the local newspaper last week.","zh":"她的詩上週刊登在當地的報紙上。"}]},{"word":"next","pos":"adj. / adv.","phonetic":"[nɛkst]","meaning":"下一個的；接下來","definition":"coming immediately after the present one","collocations":["next week","next to","next door"],"example":"We will meet again next Friday.","exampleZh":"我們下週五會再見面。","synonyms":["following"],"level":1,"theme":"時間與空間","examples":[{"en":"We will meet again next Friday.","zh":"我們下週五會再見面。"},{"en":"We are planning a family trip for next week.","zh":"我們正在規劃下週的家庭旅行。"},{"en":"The library is right next to the train station.","zh":"圖書館就在火車站的隔壁。"}]},{"word":"nice","pos":"adj.","phonetic":"[naɪs]","meaning":"好的；友善的；令人愉快的","definition":"pleasant, enjoyable, or satisfactory","collocations":["nice to meet you","nice weather","be nice to"],"example":"It was nice to meet you.","exampleZh":"很高興認識你。","synonyms":["pleasant","kind"],"level":1,"theme":"性質與描述","examples":[{"en":"It was nice to meet you.","zh":"很高興認識你。"},{"en":"The weather was so nice that we had a picnic.","zh":"天氣很好，所以我們去野餐了。"},{"en":"Please be nice to the new student on his first day.","zh":"請在新同學報到的第一天善待他。"}]},{"word":"nickname","pos":"n. / v.","phonetic":"[ˈnɪkˌnem]","meaning":"綽號；暱稱","definition":"an informal name given to a person instead of their real name","collocations":["give someone a nickname","known by the nickname"],"example":"His friends gave him the nickname \"Tiger\" for his speed.","exampleZh":"朋友們因為他的速度給他取了「老虎」這個綽號。","synonyms":["alias"],"level":3,"theme":"人物與家庭","examples":[{"en":"His friends gave him the nickname \"Tiger\" for his speed.","zh":"朋友們因為他的速度給他取了「老虎」這個綽號。"},{"en":"Because he runs so fast, his teammates gave him a nickname.","zh":"因為他跑得很快，隊友們給了他一個綽號。"},{"en":"She is known by the nickname \"Sunny\" for her bright smile.","zh":"因為燦爛的笑容，她有個「陽光」的暱稱。"}]},{"word":"niece","pos":"n.","phonetic":"[nis]","meaning":"姪女；外甥女","definition":"the daughter of one's brother or sister","collocations":["favorite niece","niece and nephew"],"example":"I bought a birthday gift for my niece.","exampleZh":"我買了一份生日禮物給我的姪女。","synonyms":[],"level":2,"theme":"人物與家庭","examples":[{"en":"I bought a birthday gift for my niece.","zh":"我買了一份生日禮物給我的姪女。"},{"en":"My little niece just learned how to ride a bicycle.","zh":"我的小姪女剛學會怎麼騎腳踏車。"},{"en":"I read a bedtime story to my niece every night.","zh":"我每晚都為姪女讀睡前故事。"}]},{"word":"night","pos":"n.","phonetic":"[naɪt]","meaning":"夜晚","definition":"the time from sunset to sunrise","collocations":["last night","good night","night shift"],"example":"The stars are bright tonight.","exampleZh":"今晚星星很明亮。","synonyms":["evening"],"level":1,"theme":"時間與空間","examples":[{"en":"The stars are bright tonight.","zh":"今晚星星很明亮。"},{"en":"We stayed up late last night watching the bright stars.","zh":"昨晚我們熬夜看著明亮的星星。"},{"en":"My father often works the night shift at the hospital.","zh":"我爸爸經常在醫院上夜班。"}]},{"word":"nightclub","pos":"n.","phonetic":"[ˈnaɪtˌklʌb]","meaning":"夜店；夜總會","definition":"a place open at night for dancing, music, and drinking","collocations":["go to a nightclub","popular nightclub"],"example":"They danced all night at the nightclub.","exampleZh":"他們在夜店跳舞跳了一整晚。","synonyms":[],"level":3,"theme":"運動與休閒","examples":[{"en":"They danced all night at the nightclub.","zh":"他們在夜店跳舞跳了一整晚。"},{"en":"They spent the evening dancing at a popular nightclub downtown.","zh":"他們整晚都在市中心一家熱門的夜店跳舞。"},{"en":"The famous band will perform at the nightclub this Friday.","zh":"這支知名樂團本週五將在夜店演出。"}]},{"word":"nightmare","pos":"n.","phonetic":"[ˈnaɪtˌmɛr]","meaning":"惡夢；夢魘","definition":"a frightening or unpleasant dream","collocations":["have a nightmare","living nightmare","nightmare scenario"],"example":"She woke up screaming from a terrible nightmare.","exampleZh":"她從一個可怕的惡夢中尖叫著醒來。","synonyms":[],"level":3,"theme":"情緒與感受","examples":[{"en":"She woke up screaming from a terrible nightmare.","zh":"她從一個可怕的惡夢中尖叫著醒來。"},{"en":"The scary movie gave the little girl a terrible nightmare.","zh":"這部恐怖電影害小女孩做了一個可怕的惡夢。"},{"en":"Losing his passport abroad turned into a real nightmare.","zh":"在國外弄丟護照變成了一場真正的噩夢。"}]},{"word":"nine","pos":"n.","phonetic":"[naɪn]","meaning":"九","definition":"the number 9","collocations":["nine o'clock","nine years old"],"example":"The store opens at nine o'clock.","exampleZh":"這家店九點開門。","synonyms":[],"level":1,"theme":"科學與數學","examples":[{"en":"The store opens at nine o'clock.","zh":"這家店九點開門。"},{"en":"The morning train always leaves at nine o'clock sharp.","zh":"早晨的火車總是準時九點開車。"},{"en":"Her little brother just turned nine years old today.","zh":"她的弟弟今天剛滿九歲。"}]},{"word":"nineteen","pos":"n.","phonetic":"[ˌnaɪnˈtin]","meaning":"十九","definition":"the number 19","collocations":["nineteen years old","page nineteen"],"example":"She turned nineteen last month.","exampleZh":"她上個月滿十九歲。","synonyms":[],"level":1,"theme":"科學與數學","examples":[{"en":"She turned nineteen last month.","zh":"她上個月滿十九歲。"},{"en":"She will start college when she turns nineteen next year.","zh":"她明年滿十九歲時將要上大學。"},{"en":"The answer to the puzzle is written on page nineteen.","zh":"謎題的答案寫在第十九頁。"}]},{"word":"ninety","pos":"n.","phonetic":"[ˈnaɪntɪ]","meaning":"九十","definition":"the number 90","collocations":["ninety percent","ninety years old"],"example":"Ninety percent of the students passed the test.","exampleZh":"百分之九十的學生通過了測驗。","synonyms":[],"level":1,"theme":"科學與數學","examples":[{"en":"Ninety percent of the students passed the test.","zh":"百分之九十的學生通過了測驗。"},{"en":"Almost ninety percent of the class attended the field trip.","zh":"班上將近百分之九十的人參加了校外教學。"},{"en":"Her grandfather stayed active even at ninety years old.","zh":"她的祖父即使九十歲了仍然精神矍鑠。"}]},{"word":"ninth","pos":"adj.","phonetic":"[naɪnθ]","meaning":"第九的","definition":"coming after eighth in a sequence","collocations":["ninth grade","ninth place"],"example":"This is the ninth chapter of the book.","exampleZh":"這是這本書的第九章。","synonyms":[],"level":1,"theme":"科學與數學","examples":[{"en":"This is the ninth chapter of the book.","zh":"這是這本書的第九章。"},{"en":"My cousin just started the ninth grade this September.","zh":"我表弟今年九月剛升上九年級。"},{"en":"After a tough race, he proudly finished in ninth place.","zh":"經過激烈的比賽，他自豪地拿下第九名。"}]},{"word":"no","pos":"adv. / adj. / int.","phonetic":"[no]","meaning":"不；沒有","definition":"used to give a negative answer or statement","collocations":["no problem","no way","no doubt"],"example":"No, I don't want any coffee, thank you.","exampleZh":"不，謝謝，我不要咖啡。","synonyms":[],"level":1,"theme":"溝通與語言","examples":[{"en":"No, I don't want any coffee, thank you.","zh":"不，謝謝，我不要咖啡。"},{"en":"There is no doubt that hard work leads to success.","zh":"毫無疑問，努力會帶來成功。"},{"en":"\"No problem,\" she said, and helped him fix the bike.","zh":"「沒問題，」她說著便幫他修理腳踏車。"}]},{"word":"noble","pos":"adj. / n.","phonetic":"[ˈnobl]","meaning":"高貴的；貴族的","definition":"having fine personal qualities or high moral principles","collocations":["noble cause","noble family","noble spirit"],"example":"He devoted his life to a noble cause.","exampleZh":"他將一生奉獻給一個崇高的事業。","synonyms":["honorable","dignified"],"level":4,"theme":"性質與描述","examples":[{"en":"He devoted his life to a noble cause.","zh":"他將一生奉獻給一個崇高的事業。"},{"en":"Helping the poor was his lifelong and noble cause.","zh":"幫助窮人是他畢生高尚的志業。"},{"en":"She showed a noble spirit by forgiving her old rival.","zh":"她原諒了昔日的對手，展現出高貴的情操。"}]},{"word":"nobody","pos":"pron.","phonetic":"[ˈnobʌdɪ]","meaning":"沒有人","definition":"no person; not anybody","collocations":["nobody knows","nobody else"],"example":"Nobody was home when I called.","exampleZh":"我打電話時沒有人在家。","synonyms":["no one"],"level":1,"theme":"抽象概念","examples":[{"en":"Nobody was home when I called.","zh":"我打電話時沒有人在家。"},{"en":"Nobody knows exactly how the old legend began.","zh":"沒有人確切知道這個古老傳說是如何開始的。"},{"en":"When the phone rang, nobody was there to answer it.","zh":"電話響起時，沒有人在那裡接聽。"}]},{"word":"nod","pos":"v. / n.","phonetic":"[nɑd]","meaning":"點頭","definition":"to move one's head down and up to show agreement","collocations":["nod one's head","nod in agreement","give a nod"],"example":"She nodded her head to show she agreed.","exampleZh":"她點頭表示同意。","synonyms":[],"level":2,"theme":"動作與行為","examples":[{"en":"She nodded her head to show she agreed.","zh":"她點頭表示同意。"},{"en":"She nodded her head slowly to show she understood.","zh":"她緩緩地點頭表示她明白了。"},{"en":"The teacher gave a friendly nod as the students entered.","zh":"學生們進來時，老師友善地點了點頭。"}]},{"word":"noise","pos":"n.","phonetic":"[nɔɪz]","meaning":"噪音；聲響","definition":"a sound, especially a loud or unpleasant one","collocations":["loud noise","make noise","background noise"],"example":"The construction noise woke me up early.","exampleZh":"施工的噪音把我很早就吵醒了。","synonyms":["sound","racket"],"level":1,"theme":"居家與生活","examples":[{"en":"The construction noise woke me up early.","zh":"施工的噪音把我很早就吵醒了。"},{"en":"The loud noise from the party kept the baby awake.","zh":"派對傳來的吵雜聲讓寶寶睡不著。"},{"en":"Please do not make noise while others are studying.","zh":"別人在讀書時請不要製造噪音。"}]},{"word":"noisy","pos":"adj.","phonetic":"[ˈnɔɪzɪ]","meaning":"吵鬧的","definition":"making a lot of noise","collocations":["noisy classroom","noisy neighbors","noisy street"],"example":"The classroom was too noisy to study in.","exampleZh":"教室太吵，無法讀書。","synonyms":["loud"],"level":1,"theme":"性質與描述","examples":[{"en":"The classroom was too noisy to study in.","zh":"教室太吵，無法讀書。"},{"en":"The noisy street outside made it hard to concentrate.","zh":"外面吵鬧的街道讓人難以專心。"},{"en":"The classroom became noisy the moment the teacher left.","zh":"老師一離開，教室就變得吵鬧起來。"}]},{"word":"nomination","pos":"n.","phonetic":"[ˌnɑməˈneʃən]","meaning":"提名","definition":"the act of proposing someone for a position or award","collocations":["receive a nomination","Oscar nomination","nomination for president"],"example":"The actress received a nomination for best actress.","exampleZh":"這位女演員獲得最佳女主角提名。","synonyms":[],"level":5,"theme":"政治與法律","examples":[{"en":"The actress received a nomination for best actress.","zh":"這位女演員獲得最佳女主角提名。"},{"en":"The young director received a nomination for best film.","zh":"這位年輕導演獲得了最佳影片的提名。"},{"en":"Her surprising nomination made the whole team very proud.","zh":"她意外的提名讓整個團隊都感到非常驕傲。"}]},{"word":"none","pos":"pron.","phonetic":"[nʌn]","meaning":"沒有一個；一點也不","definition":"not any; no person or amount","collocations":["none of them","none at all","none of the above"],"example":"None of the students answered the question correctly.","exampleZh":"沒有一個學生正確回答了這個問題。","synonyms":["nobody"],"level":2,"theme":"抽象概念","examples":[{"en":"None of the students answered the question correctly.","zh":"沒有一個學生正確回答了這個問題。"},{"en":"I looked everywhere, but none of my keys were there.","zh":"我到處找，但我的鑰匙一把也不在那裡。"},{"en":"She tasted all the soups, but liked none of them.","zh":"她嚐了所有的湯，但一種也不喜歡。"}]},{"word":"nonprofit","pos":"adj.","phonetic":"[ˌnɑnˈprɑfɪt]","meaning":"非營利的","definition":"not conducted or maintained for the purpose of making a profit","collocations":["nonprofit organization","nonprofit sector"],"example":"She works for a nonprofit organization that helps the homeless.","exampleZh":"她在一個幫助無家可歸者的非營利組織工作。","synonyms":[],"level":5,"theme":"商業與金錢","examples":[{"en":"She works for a nonprofit organization that helps the homeless.","zh":"她在一個幫助無家可歸者的非營利組織工作。"},{"en":"He volunteers at a nonprofit organization that plants trees.","zh":"他在一個種樹的非營利組織當志工。"},{"en":"Many jobs in the nonprofit sector focus on helping others.","zh":"非營利部門的許多工作都著重於幫助他人。"}]},{"word":"nonsense","pos":"n.","phonetic":"[ˈnɑnsɛns]","meaning":"胡說；無意義的話","definition":"words or ideas that are foolish or meaningless","collocations":["talk nonsense","pure nonsense","stop the nonsense"],"example":"Stop talking nonsense and get to work.","exampleZh":"別再胡說了，去工作吧。","synonyms":["rubbish"],"level":3,"theme":"溝通與語言","examples":[{"en":"Stop talking nonsense and get to work.","zh":"別再胡說了，去工作吧。"},{"en":"Stop talking nonsense and give me a serious answer.","zh":"別再胡說八道了，給我一個認真的答案。"},{"en":"The excited child made up pure nonsense about flying cats.","zh":"興奮的孩子編出了關於飛天貓的一派胡言。"}]},{"word":"nonstop","pos":"adj. / adv.","phonetic":"[ˈnɑnˈstɑp]","meaning":"不停的；直達的","definition":"without any stops or breaks","collocations":["nonstop flight","talk nonstop","work nonstop"],"example":"We took a nonstop flight from Taipei to New York.","exampleZh":"我們搭了從台北直飛紐約的班機。","synonyms":["continuous"],"level":4,"theme":"交通與旅行","examples":[{"en":"We took a nonstop flight from Taipei to New York.","zh":"我們搭了從台北直飛紐約的班機。"},{"en":"We booked a nonstop flight to save a lot of time.","zh":"我們訂了一班直達班機以節省許多時間。"},{"en":"The busy waiter worked nonstop through the whole evening.","zh":"忙碌的服務生整個晚上不停地工作。"}]},{"word":"noodle","pos":"n.","phonetic":"[ˈnudl]","meaning":"麵條","definition":"a long, thin strip of pasta or dough","collocations":["instant noodles","noodle soup","fried noodles"],"example":"We ordered a bowl of beef noodles for lunch.","exampleZh":"我們午餐點了一碗牛肉麵。","synonyms":[],"level":1,"theme":"食物與烹飪","examples":[{"en":"We ordered a bowl of beef noodles for lunch.","zh":"我們午餐點了一碗牛肉麵。"},{"en":"On cold nights, a bowl of hot noodle soup is comforting.","zh":"寒冷的夜晚，一碗熱麵湯令人暖心。"},{"en":"He quickly cooked some instant noodles after coming home.","zh":"回家後他很快地煮了一些泡麵。"}]},{"word":"noon","pos":"n.","phonetic":"[nun]","meaning":"正午；中午","definition":"twelve o'clock in the middle of the day","collocations":["at noon","before noon","noon break"],"example":"We will meet at noon for lunch.","exampleZh":"我們中午見面吃午餐。","synonyms":["midday"],"level":1,"theme":"時間與空間","examples":[{"en":"We will meet at noon for lunch.","zh":"我們中午見面吃午餐。"},{"en":"The sun is strongest at noon, so wear a hat outside.","zh":"正午時陽光最強，所以在戶外要戴帽子。"},{"en":"Workers gather in the park during their noon break.","zh":"工人們在午休時間聚集在公園裡。"}]},{"word":"nor","pos":"conj.","phonetic":"[nɔr]","meaning":"也不；亦不","definition":"used before the second part of a negative statement","collocations":["neither...nor","nor do I"],"example":"She doesn't like coffee, nor does she like tea.","exampleZh":"她不喜歡咖啡，也不喜歡茶。","synonyms":[],"level":2,"theme":"溝通與語言","examples":[{"en":"She doesn't like coffee, nor does she like tea.","zh":"她不喜歡咖啡，也不喜歡茶。"},{"en":"He does not eat meat, nor does he drink milk.","zh":"他不吃肉，也不喝牛奶。"},{"en":"The shy student neither smiled nor said a single word.","zh":"這位害羞的學生既沒有微笑也沒說一句話。"}]},{"word":"normal","pos":"adj.","phonetic":"[ˈnɔrml]","meaning":"正常的；普通的","definition":"usual, typical, or expected","collocations":["normal life","above normal","return to normal"],"example":"It's normal to feel nervous before a speech.","exampleZh":"在演講前感到緊張是正常的。","synonyms":["usual","typical"],"level":2,"theme":"性質與描述","examples":[{"en":"It's normal to feel nervous before a speech.","zh":"在演講前感到緊張是正常的。"},{"en":"After the exam, life slowly returned to normal.","zh":"考試過後，生活慢慢恢復了正常。"},{"en":"It is completely normal to make mistakes while learning.","zh":"學習時犯錯是完全正常的。"}]},{"word":"normally","pos":"adv.","phonetic":"[ˈnɔrmlɪ]","meaning":"通常；正常地","definition":"in usual or expected circumstances","collocations":["normally wake up early","function normally","behave normally"],"example":"Normally, I wake up at seven o'clock.","exampleZh":"我通常七點起床。","synonyms":["usually"],"level":2,"theme":"時間與空間","examples":[{"en":"Normally, I wake up at seven o'clock.","zh":"我通常七點起床。"},{"en":"Normally, I wake up early to jog around the park.","zh":"通常我會早起在公園附近慢跑。"},{"en":"After the repair, the machine started to function normally.","zh":"修理之後，機器開始正常運作。"}]},{"word":"north","pos":"n. / adj. / adv.","phonetic":"[nɔrθ]","meaning":"北方；北方的","definition":"the direction to the left of a person facing east","collocations":["north pole","north of","face north"],"example":"The wind is blowing from the north today.","exampleZh":"今天風從北方吹來。","synonyms":[],"level":1,"theme":"時間與空間","examples":[{"en":"The wind is blowing from the north today.","zh":"今天風從北方吹來。"},{"en":"A cold wind blew from the north all through the morning.","zh":"整個早上都有寒冷的風從北方吹來。"},{"en":"Their village lies just a few miles north of the city.","zh":"他們的村莊位於城市以北僅幾英里處。"}]},{"word":"northern","pos":"adj.","phonetic":"[ˈnɔrðɚn]","meaning":"北方的；北部的","definition":"located in or coming from the north","collocations":["northern hemisphere","northern part","northern lights"],"example":"They live in the northern part of the country.","exampleZh":"他們住在這個國家的北部。","synonyms":[],"level":2,"theme":"時間與空間","examples":[{"en":"They live in the northern part of the country.","zh":"他們住在這個國家的北部。"},{"en":"Winters are long and snowy in the northern part of the country.","zh":"這個國家的北部地區冬季漫長且多雪。"},{"en":"Tourists travel far to see the beautiful northern lights.","zh":"遊客們遠道而來只為觀賞美麗的北極光。"}]},{"word":"nose","pos":"n.","phonetic":"[noz]","meaning":"鼻子","definition":"the part of the face used for breathing and smelling","collocations":["blow one's nose","runny nose","nose bleed"],"example":"He has a cold and his nose is running.","exampleZh":"他感冒了，鼻水一直流。","synonyms":[],"level":1,"theme":"身體與健康","examples":[{"en":"He has a cold and his nose is running.","zh":"他感冒了，鼻水一直流。"},{"en":"The strong smell of flowers filled his nose in the garden.","zh":"花園裡濃烈的花香充滿了他的鼻腔。"},{"en":"She caught a cold and had a runny nose all day.","zh":"她感冒了，整天流鼻水。"}]},{"word":"nostalgia","pos":"n.","phonetic":"[nɑˈstældʒɪə]","meaning":"懷舊；鄉愁","definition":"a sentimental longing for the past","collocations":["feel nostalgia","a wave of nostalgia","nostalgia for the past"],"example":"The old song filled her with nostalgia for her childhood.","exampleZh":"這首老歌讓她充滿對童年的懷舊之情。","synonyms":["longing"],"level":6,"theme":"情緒與感受","examples":[{"en":"The old song filled her with nostalgia for her childhood.","zh":"這首老歌讓她充滿對童年的懷舊之情。"},{"en":"Looking at old photos filled her with sudden nostalgia.","zh":"看著舊照片，一股懷舊之情突然湧上她心頭。"},{"en":"The smell of fresh bread brings back nostalgia for home.","zh":"新鮮麵包的香味勾起了對家的思念。"}]},{"word":"not","pos":"adv.","phonetic":"[nɑt]","meaning":"不；沒有","definition":"used to form the negative of a verb","collocations":["not at all","not yet","not only...but also"],"example":"I am not going to the party tonight.","exampleZh":"我今晚不會去派對。","synonyms":[],"level":1,"theme":"溝通與語言","examples":[{"en":"I am not going to the party tonight.","zh":"我今晚不會去派對。"},{"en":"I am not sure whether it will rain this afternoon.","zh":"我不確定今天下午會不會下雨。"},{"en":"She is not only smart but also very hardworking.","zh":"她不僅聰明，而且非常勤奮。"}]},{"word":"notable","pos":"adj.","phonetic":"[ˈnotəbl]","meaning":"值得注意的；顯著的","definition":"worthy of attention or notice; remarkable","collocations":["notable exception","notable achievement","notable for"],"example":"He made a notable contribution to the field of science.","exampleZh":"他對科學領域做出了顯著的貢獻。","synonyms":["remarkable","significant"],"level":5,"theme":"性質與描述","examples":[{"en":"He made a notable contribution to the field of science.","zh":"他對科學領域做出了顯著的貢獻。"},{"en":"The scientist made a notable achievement in cancer research.","zh":"這位科學家在癌症研究上取得了顯著的成就。"},{"en":"With one notable exception, all the students passed the test.","zh":"除了一個明顯的例外，所有學生都通過了測驗。"}]},{"word":"note","pos":"n. / v.","phonetic":"[not]","meaning":"筆記；紙條；注意","definition":"a short piece of writing to help someone remember something","collocations":["take notes","leave a note","note down"],"example":"Please take notes during the lecture.","exampleZh":"請在講課時做筆記。","synonyms":["memo"],"level":2,"theme":"教育與學習","examples":[{"en":"Please take notes during the lecture.","zh":"請在講課時做筆記。"},{"en":"Remember to take notes carefully during the science lecture.","zh":"記得在科學講座中仔細做筆記。"},{"en":"She left a short note on the kitchen table for her mom.","zh":"她在廚房桌上為媽媽留了一張短箋。"}]},{"word":"notebook","pos":"n.","phonetic":"[ˈnotˌbʊk]","meaning":"筆記本","definition":"a small book with blank pages for writing notes","collocations":["a new notebook","notebook computer","write in a notebook"],"example":"She wrote the vocabulary words in her notebook.","exampleZh":"她把單字寫在她的筆記本裡。","synonyms":[],"level":1,"theme":"教育與學習","examples":[{"en":"She wrote the vocabulary words in her notebook.","zh":"她把單字寫在她的筆記本裡。"},{"en":"He bought a new notebook for his English vocabulary words.","zh":"他買了一本新的筆記本來記英文單字。"},{"en":"She carefully wrote every important date in her notebook.","zh":"她把每個重要的日期都仔細地寫在筆記本裡。"}]},{"word":"noteworthy","pos":"adj.","phonetic":"[ˈnotˌwɝðɪ]","meaning":"值得注意的；顯著的","definition":"deserving attention; significant","collocations":["noteworthy achievement","noteworthy event","particularly noteworthy"],"example":"The team's progress this year has been particularly noteworthy.","exampleZh":"這個團隊今年的進展特別值得注意。","synonyms":["remarkable","notable"],"level":6,"theme":"性質與描述","examples":[{"en":"The team's progress this year has been particularly noteworthy.","zh":"這個團隊今年的進展特別值得注意。"},{"en":"The young writer's first book was a noteworthy success.","zh":"這位年輕作家的第一本書是一項顯著的成功。"},{"en":"It is particularly noteworthy that she taught herself coding.","zh":"特別值得注意的是，她是自學程式設計的。"}]},{"word":"nothing","pos":"pron.","phonetic":"[ˈnʌθɪŋ]","meaning":"沒有東西；沒有事情","definition":"not anything; no single thing","collocations":["nothing special","for nothing","nothing to do"],"example":"There is nothing in the fridge to eat.","exampleZh":"冰箱裡沒有東西可以吃。","synonyms":[],"level":1,"theme":"抽象概念","examples":[{"en":"There is nothing in the fridge to eat.","zh":"冰箱裡沒有東西可以吃。"},{"en":"There was nothing special about the rainy Monday morning.","zh":"那個下雨的週一早晨並沒有什麼特別的。"},{"en":"After finishing his homework, he had nothing left to do.","zh":"寫完作業後，他就沒事可做了。"}]},{"word":"notice","pos":"v. / n.","phonetic":"[ˈnotɪs]","meaning":"注意到；通知","definition":"to become aware of something; a written announcement","collocations":["put up a notice","take notice of","without notice"],"example":"Did you notice the new sign on the door?","exampleZh":"你注意到門上的新標示了嗎？","synonyms":["observe"],"level":2,"theme":"溝通與語言","examples":[{"en":"Did you notice the new sign on the door?","zh":"你注意到門上的新標示了嗎？"},{"en":"Did you notice the small mistake on the second page?","zh":"你有注意到第二頁上的小錯誤嗎？"},{"en":"The school put up a notice about the coming sports day.","zh":"學校張貼了一則關於即將到來的運動會的公告。"}]},{"word":"notify","pos":"v.","phonetic":"[ˈnotəˌfaɪ]","meaning":"通知；告知","definition":"to formally inform someone of something","collocations":["notify the police","notify someone of","be notified"],"example":"Please notify us of any changes to your address.","exampleZh":"如果地址有任何變更，請通知我們。","synonyms":["inform","tell"],"level":4,"theme":"溝通與語言","examples":[{"en":"Please notify us of any changes to your address.","zh":"如果地址有任何變更，請通知我們。"},{"en":"Please notify the office if you plan to be absent.","zh":"如果你打算請假，請通知辦公室。"},{"en":"They promised to notify us of any change in the schedule.","zh":"他們答應會通知我們任何行程上的變動。"}]},{"word":"notion","pos":"n.","phonetic":"[ˈnoʃən]","meaning":"觀念；想法","definition":"a belief or idea about something","collocations":["have a notion","reject the notion","notion of freedom"],"example":"She has a strange notion about how to raise children.","exampleZh":"她對於如何教養孩子有一個奇怪的想法。","synonyms":["idea","concept"],"level":5,"theme":"抽象概念","examples":[{"en":"She has a strange notion about how to raise children.","zh":"她對於如何教養孩子有一個奇怪的想法。"},{"en":"Many people reject the notion that money can buy true happiness.","zh":"許多人不認同金錢能買到真正快樂的這種想法。"},{"en":"As a child, I had no notion of how hard farming was.","zh":"小時候，我對務農有多辛苦毫無概念。"}]},{"word":"notorious","pos":"adj.","phonetic":"[noˈtorɪəs]","meaning":"惡名昭彰的","definition":"famous for something bad","collocations":["notorious criminal","notorious for","notoriously difficult"],"example":"The city is notorious for its heavy traffic.","exampleZh":"這座城市以嚴重的交通問題而惡名昭彰。","synonyms":["infamous"],"level":6,"theme":"社會與文化","examples":[{"en":"The city is notorious for its heavy traffic.","zh":"這座城市以嚴重的交通問題而惡名昭彰。"},{"en":"The math teacher is notorious for giving surprise quizzes every week.","zh":"那位數學老師因每週突擊小考而惡名昭彰。"},{"en":"This mountain trail is notoriously difficult, even for experienced hikers.","zh":"這條山徑出了名的難走，連經驗豐富的登山者也不例外。"}]},{"word":"nourish","pos":"v.","phonetic":"[ˈnɝɪʃ]","meaning":"滋養；養育","definition":"to provide with the food or substances necessary for growth","collocations":["nourish the body","nourish a relationship","well-nourished"],"example":"A balanced diet nourishes both body and mind.","exampleZh":"均衡的飲食能滋養身體與心靈。","synonyms":["nurture","feed"],"level":5,"theme":"身體與健康","examples":[{"en":"A balanced diet nourishes both body and mind.","zh":"均衡的飲食能滋養身體與心靈。"},{"en":"Fresh vegetables and fruit nourish the body and boost your energy.","zh":"新鮮蔬果能滋養身體並提升你的精力。"},{"en":"Kind words from teachers can nourish a child's confidence over time.","zh":"老師親切的話語能逐漸滋養孩子的自信。"}]},{"word":"novel","pos":"n. / adj.","phonetic":"[ˈnɑvl]","meaning":"小說；新穎的","definition":"a long fictional story in book form; new and original","collocations":["write a novel","read a novel","novel idea"],"example":"She spent the whole summer writing her first novel.","exampleZh":"她花了整個夏天寫她的第一本小說。","synonyms":["fiction"],"level":3,"theme":"藝術與音樂","examples":[{"en":"She spent the whole summer writing her first novel.","zh":"她花了整個夏天寫她的第一本小說。"},{"en":"The scientist proposed a novel method to reduce plastic waste.","zh":"那位科學家提出了一種減少塑膠垃圾的新穎方法。"},{"en":"I stayed up late last night to finish reading this mystery novel.","zh":"昨晚我熬夜把這本推理小說讀完了。"}]},{"word":"novelist","pos":"n.","phonetic":"[ˈnɑvəlɪst]","meaning":"小說家","definition":"a person who writes novels","collocations":["famous novelist","best-selling novelist"],"example":"She dreams of becoming a famous novelist.","exampleZh":"她夢想成為一位知名小說家。","synonyms":["writer","author"],"level":4,"theme":"藝術與音樂","examples":[{"en":"She dreams of becoming a famous novelist.","zh":"她夢想成為一位知名小說家。"},{"en":"The young novelist won a national award for her debut book.","zh":"這位年輕小說家憑藉她的處女作贏得了全國大獎。"},{"en":"Many best-selling novelists spend years researching before they start writing.","zh":"許多暢銷小說家在動筆前會花上好幾年做研究。"}]},{"word":"November","pos":"n.","phonetic":"[noˈvɛmbɚ]","meaning":"十一月","definition":"the eleventh month of the year","collocations":["in November","early November"],"example":"Thanksgiving is celebrated in November in the United States.","exampleZh":"感恩節在美國於十一月慶祝。","synonyms":[],"level":1,"theme":"時間與空間","examples":[{"en":"Thanksgiving is celebrated in November in the United States.","zh":"感恩節在美國於十一月慶祝。"},{"en":"The maple leaves turn bright red in early November.","zh":"楓葉在十一月初轉為鮮紅色。"},{"en":"Our final exams will take place in the middle of November.","zh":"我們的期末考將在十一月中旬舉行。"}]},{"word":"now","pos":"adv.","phonetic":"[naʊ]","meaning":"現在","definition":"at the present time or moment","collocations":["right now","from now on","by now"],"example":"I have to leave right now.","exampleZh":"我現在必須馬上離開。","synonyms":["currently"],"level":1,"theme":"時間與空間","examples":[{"en":"I have to leave right now.","zh":"我現在必須馬上離開。"},{"en":"From now on, I will review my notes every single evening.","zh":"從現在起，我每天晚上都會複習筆記。"},{"en":"You should start packing right now, or we'll miss the train.","zh":"你現在就該開始打包，否則我們會錯過火車。"}]},{"word":"nowadays","pos":"adv.","phonetic":"[ˈnaʊəˌdez]","meaning":"如今；現今","definition":"at the present time, in contrast to the past","collocations":["nowadays people","common nowadays"],"example":"Nowadays, most people use smartphones to check the news.","exampleZh":"如今，大多數人用智慧型手機看新聞。","synonyms":["today","currently"],"level":3,"theme":"時間與空間","examples":[{"en":"Nowadays, most people use smartphones to check the news.","zh":"如今，大多數人用智慧型手機看新聞。"},{"en":"Nowadays, many students prefer to borrow e-books from the library.","zh":"如今，許多學生偏好從圖書館借閱電子書。"},{"en":"Paying with a mobile phone is very common nowadays.","zh":"用手機付款在現今非常普遍。"}]},{"word":"nowhere","pos":"adv.","phonetic":"[ˈnoˌhwɛr]","meaning":"任何地方都不；無處","definition":"not in, at, or to any place; not anywhere","collocations":["nowhere to be found","out of nowhere","get nowhere"],"example":"My keys are nowhere to be found.","exampleZh":"我的鑰匙到處都找不到。","synonyms":[],"level":2,"theme":"時間與空間","examples":[{"en":"My keys are nowhere to be found.","zh":"我的鑰匙到處都找不到。"},{"en":"I searched everywhere, but my glasses were nowhere to be found.","zh":"我到處找，但我的眼鏡怎麼都找不到。"},{"en":"Arguing about the past will get us nowhere, so let's move on.","zh":"爭論過去對我們毫無幫助，所以我們往前看吧。"}]},{"word":"nuclear","pos":"adj.","phonetic":"[ˈnjuklɪɚ]","meaning":"核子的；核能的","definition":"relating to the nucleus of an atom or to nuclear energy","collocations":["nuclear power","nuclear weapon","nuclear energy"],"example":"The country decided to build a new nuclear power plant.","exampleZh":"這個國家決定興建一座新的核能電廠。","synonyms":[],"level":4,"theme":"科學與數學","examples":[{"en":"The country decided to build a new nuclear power plant.","zh":"這個國家決定興建一座新的核能電廠。"},{"en":"The country relies heavily on nuclear power for its electricity.","zh":"那個國家的電力高度仰賴核能。"},{"en":"Scientists warn about the terrible dangers of nuclear weapons.","zh":"科學家警告核子武器的可怕危險。"}]},{"word":"nuisance","pos":"n.","phonetic":"[ˈnjusns]","meaning":"討厭的人或事；麻煩","definition":"a person, thing, or situation that is annoying or causes trouble","collocations":["a real nuisance","make a nuisance of oneself","public nuisance"],"example":"The constant noise from the road is a nuisance.","exampleZh":"馬路上不斷的噪音真是令人討厭。","synonyms":["annoyance","bother"],"level":6,"theme":"抽象概念","examples":[{"en":"The constant noise from the road is a nuisance.","zh":"馬路上不斷的噪音真是令人討厭。"},{"en":"The mosquitoes at the campsite were a real nuisance all night.","zh":"營地的蚊子整晚都真的很惱人。"},{"en":"Please don't make a nuisance of yourself in the library.","zh":"請不要在圖書館裡惹人厭。"}]},{"word":"number","pos":"n. / v.","phonetic":"[ˈnʌmbɚ]","meaning":"數字；號碼","definition":"a mathematical value used for counting or calculating","collocations":["phone number","a large number of","number one"],"example":"Please write down your phone number.","exampleZh":"請寫下你的電話號碼。","synonyms":["figure"],"level":1,"theme":"科學與數學","examples":[{"en":"Please write down your phone number.","zh":"請寫下你的電話號碼。"},{"en":"A large number of tourists visit this old temple every year.","zh":"每年都有大量遊客造訪這座古老的寺廟。"},{"en":"Could you please tell me the room number of the meeting?","zh":"你能告訴我會議的房間號碼嗎？"}]},{"word":"numerous","pos":"adj.","phonetic":"[ˈnjumərəs]","meaning":"許多的；為數眾多的","definition":"existing in large quantities; many","collocations":["numerous times","numerous occasions","numerous studies"],"example":"He has made numerous mistakes on this project.","exampleZh":"他在這個專案上犯了許多錯誤。","synonyms":["many","countless"],"level":4,"theme":"性質與描述","examples":[{"en":"He has made numerous mistakes on this project.","zh":"他在這個專案上犯了許多錯誤。"},{"en":"Numerous studies show that regular exercise improves memory.","zh":"為數眾多的研究顯示，規律運動能改善記憶力。"},{"en":"She has visited that museum on numerous occasions.","zh":"她已經在許多場合造訪過那座博物館。"}]},{"word":"nurse","pos":"n. / v.","phonetic":"[nɝs]","meaning":"護士；照顧","definition":"a person trained to care for sick or injured people","collocations":["registered nurse","nurse a patient","school nurse"],"example":"The nurse took care of the patient all night.","exampleZh":"這位護士整晚都在照顧病人。","synonyms":["caregiver"],"level":2,"theme":"工作與職業","examples":[{"en":"The nurse took care of the patient all night.","zh":"這位護士整晚都在照顧病人。"},{"en":"The registered nurse gently changed the bandage on his arm.","zh":"那位註冊護士輕柔地更換了他手臂上的繃帶。"},{"en":"She stayed home to nurse her sick brother back to health.","zh":"她待在家裡照顧生病的弟弟直到康復。"}]},{"word":"nursery","pos":"n.","phonetic":"[ˈnɝsərɪ]","meaning":"托兒所；苗圃","definition":"a room or place for young children, or for growing plants","collocations":["nursery school","nursery rhyme","plant nursery"],"example":"The baby's room was decorated as a cheerful nursery.","exampleZh":"嬰兒房被佈置成一間歡樂的育嬰室。","synonyms":[],"level":3,"theme":"教育與學習","examples":[{"en":"The baby's room was decorated as a cheerful nursery.","zh":"嬰兒房被佈置成一間歡樂的育嬰室。"},{"en":"The children sang a cheerful nursery rhyme before their afternoon nap.","zh":"孩子們在午睡前唱了一首歡樂的童謠。"},{"en":"We bought several young apple trees from a local plant nursery.","zh":"我們從當地的苗圃買了幾棵蘋果幼樹。"}]},{"word":"nut","pos":"n.","phonetic":"[nʌt]","meaning":"堅果；螺帽","definition":"a hard-shelled fruit or seed with an edible kernel","collocations":["a bowl of nuts","nuts and bolts","crack a nut"],"example":"She added some nuts to the salad.","exampleZh":"她在沙拉裡加了一些堅果。","synonyms":[],"level":2,"theme":"食物與烹飪","examples":[{"en":"She added some nuts to the salad.","zh":"她在沙拉裡加了一些堅果。"},{"en":"She put a bowl of nuts on the table for the guests.","zh":"她在桌上放了一碗堅果招待客人。"},{"en":"He tightened every nut and bolt before riding the bicycle.","zh":"他在騎腳踏車前把每個螺帽和螺栓都鎖緊。"}]},{"word":"nutrition","pos":"n.","phonetic":"[njuˈtrɪʃən]","meaning":"營養；營養學","definition":"the process of providing or obtaining food for health and growth","collocations":["good nutrition","nutrition label","lack of nutrition"],"example":"Good nutrition is essential for children's growth.","exampleZh":"良好的營養對兒童的成長至關重要。","synonyms":[],"level":4,"theme":"身體與健康","examples":[{"en":"Good nutrition is essential for children's growth.","zh":"良好的營養對兒童的成長至關重要。"},{"en":"Good nutrition during childhood helps build strong bones and teeth.","zh":"童年時期的良好營養有助於建立強健的骨骼和牙齒。"},{"en":"Always check the nutrition label before buying packaged snacks.","zh":"買包裝零食前記得先看營養標示。"}]},{"word":"nutritious","pos":"adj.","phonetic":"[njuˈtrɪʃəs]","meaning":"營養的；有營養的","definition":"containing substances that help the body grow and stay healthy","collocations":["nutritious food","nutritious meal","nutritious diet"],"example":"Eating nutritious food helps you stay healthy.","exampleZh":"吃有營養的食物有助於保持健康。","synonyms":["healthy","wholesome"],"level":3,"theme":"食物與烹飪","examples":[{"en":"Eating nutritious food helps you stay healthy.","zh":"吃有營養的食物有助於保持健康。"},{"en":"A bowl of oatmeal with fruit makes a nutritious breakfast.","zh":"一碗加水果的燕麥粥是營養的早餐。"},{"en":"The school cafeteria offers nutritious meals at a low price.","zh":"學校餐廳以低廉的價格提供營養的餐點。"}]},{"word":"nylon","pos":"n.","phonetic":"[ˈnaɪlɑn]","meaning":"尼龍","definition":"a strong synthetic fiber used to make clothes and other products","collocations":["nylon rope","nylon fabric","nylon stockings"],"example":"Her jacket is made of nylon and dries quickly.","exampleZh":"她的外套是尼龍材質，乾得很快。","synonyms":[],"level":3,"theme":"服裝與外表","examples":[{"en":"Her jacket is made of nylon and dries quickly.","zh":"她的外套是尼龍材質，乾得很快。"},{"en":"We climbed the cliff using a strong nylon rope.","zh":"我們用一條堅固的尼龍繩攀爬懸崖。"},{"en":"This backpack is made of nylon fabric, so it resists water.","zh":"這個背包是用尼龍布料製成的，所以防水。"}]},{"word":"oak","pos":"n.","phonetic":"[ok]","meaning":"橡樹；橡木","definition":"a large tree that produces acorns and hard wood","collocations":["an oak tree","solid oak furniture","oak leaves"],"example":"The old oak tree in the yard is over a hundred years old.","exampleZh":"院子裡那棵老橡樹已經超過一百年了。","synonyms":[],"level":3,"theme":"動物與植物","examples":[{"en":"The old oak tree in the yard is over a hundred years old.","zh":"院子裡那棵老橡樹已經超過一百年了。"},{"en":"A huge oak tree provides cool shade in the schoolyard.","zh":"一棵巨大的橡樹為校園提供了涼爽的樹蔭。"},{"en":"My grandfather made this sturdy desk from solid oak.","zh":"我祖父用實心橡木做了這張堅固的書桌。"}]},{"word":"oar","pos":"n.","phonetic":"[or]","meaning":"槳","definition":"a long pole with a flat blade used to row a boat","collocations":["row with oars","pull the oars","an oar blade"],"example":"He used the oar to push the boat away from the dock.","exampleZh":"他用槳把船推離碼頭。","synonyms":["paddle"],"level":3,"theme":"交通與旅行","examples":[{"en":"He used the oar to push the boat away from the dock.","zh":"他用槳把船推離碼頭。"},{"en":"She pulled the oars steadily to move the boat forward.","zh":"她穩定地划槳，讓船向前行進。"},{"en":"One oar slipped from his hand and floated away on the water.","zh":"一支槳從他手中滑落，漂在水面上飄走了。"}]},{"word":"oath","pos":"n.","phonetic":"[oθ]","meaning":"誓言；宣誓","definition":"a formal promise, often made in a legal or official setting","collocations":["take an oath","swear an oath","break an oath"],"example":"The witness took an oath to tell the truth.","exampleZh":"證人宣誓要說實話。","synonyms":["vow","pledge"],"level":5,"theme":"政治與法律","examples":[{"en":"The witness took an oath to tell the truth.","zh":"證人宣誓要說實話。"},{"en":"The new president took an oath to serve the people honestly.","zh":"新任總統宣誓要誠實地為人民服務。"},{"en":"He swore an oath never to reveal his friend's secret.","zh":"他發誓絕不洩漏朋友的秘密。"}]},{"word":"oatmeal","pos":"n.","phonetic":"[ˈotˌmil]","meaning":"燕麥片；燕麥粥","definition":"a food made from crushed oats, often cooked as a breakfast dish","collocations":["a bowl of oatmeal","oatmeal cookies","hot oatmeal"],"example":"She has a bowl of oatmeal with fruit every morning.","exampleZh":"她每天早上都吃一碗加水果的燕麥粥。","synonyms":[],"level":2,"theme":"食物與烹飪","examples":[{"en":"She has a bowl of oatmeal with fruit every morning.","zh":"她每天早上都吃一碗加水果的燕麥粥。"},{"en":"On cold mornings, a bowl of hot oatmeal keeps me warm.","zh":"在寒冷的早晨，一碗熱燕麥粥能讓我保持溫暖。"},{"en":"My mother baked a batch of oatmeal cookies for the picnic.","zh":"我媽媽為野餐烤了一批燕麥餅乾。"}]},{"word":"obedient","pos":"adj.","phonetic":"[əˈbidɪənt]","meaning":"服從的；順從的","definition":"willing to do what one is told to do","collocations":["an obedient dog","obedient to rules","stay obedient"],"example":"The obedient dog followed every command its owner gave.","exampleZh":"那隻聽話的狗會遵從主人的每個指令。","synonyms":["compliant","dutiful"],"level":4,"theme":"性質與描述","examples":[{"en":"The obedient dog followed every command its owner gave.","zh":"那隻聽話的狗會遵從主人的每個指令。"},{"en":"The obedient students lined up quietly before entering the hall.","zh":"順從的學生們安靜地排好隊才進入禮堂。"},{"en":"A well-trained dog stays obedient even in a noisy park.","zh":"訓練有素的狗即使在吵雜的公園裡也很聽話。"}]},{"word":"obese","pos":"adj.","phonetic":"[oˈbis]","meaning":"肥胖的","definition":"extremely overweight in a way that is unhealthy","collocations":["become obese","obese patients","clinically obese"],"example":"Eating too much fast food can make people obese.","exampleZh":"吃太多速食可能使人肥胖。","synonyms":["overweight","fat"],"level":5,"theme":"身體與健康","examples":[{"en":"Eating too much fast food can make people obese.","zh":"吃太多速食可能使人肥胖。"},{"en":"Doctors warned that he might become obese without regular exercise.","zh":"醫生警告他，若不規律運動可能會變得肥胖。"},{"en":"The clinic offers special programs for clinically obese patients.","zh":"這家診所為臨床上肥胖的病患提供特別方案。"}]},{"word":"obey","pos":"v.","phonetic":"[əˈbe]","meaning":"服從；遵守","definition":"to do what one is told or ordered to do","collocations":["obey the law","obey orders","obey your parents"],"example":"All drivers must obey the traffic rules.","exampleZh":"所有駕駛人都必須遵守交通規則。","synonyms":["comply","follow"],"level":2,"theme":"動作與行為","examples":[{"en":"All drivers must obey the traffic rules.","zh":"所有駕駛人都必須遵守交通規則。"},{"en":"Every citizen is expected to obey the law of the country.","zh":"每位公民都應當遵守國家的法律。"},{"en":"The soldiers were trained to obey orders without hesitation.","zh":"士兵受訓要毫不猶豫地服從命令。"}]},{"word":"object","pos":"n. / v.","phonetic":"[ˈɑbdʒɪkt]","meaning":"物體；目標；反對","definition":"a thing that can be seen or touched; or to express disagreement","collocations":["a strange object","object to a plan","the object of study"],"example":"She found a small metal object buried in the garden.","exampleZh":"她在花園裡發現了一個埋著的小金屬物體。","synonyms":["item","thing"],"level":2,"theme":"抽象概念","examples":[{"en":"She found a small metal object buried in the garden.","zh":"她在花園裡發現了一個埋著的小金屬物體。"},{"en":"Several parents strongly object to the new school uniform policy.","zh":"有幾位家長強烈反對新的校服規定。"},{"en":"The telescope revealed a bright object moving across the night sky.","zh":"望遠鏡顯示出一個明亮的物體劃過夜空。"}]},{"word":"objection","pos":"n.","phonetic":"[əbˈdʒɛkʃən]","meaning":"反對；異議","definition":"a statement expressing disagreement with something","collocations":["raise an objection","have no objection","an objection to a rule"],"example":"The lawyer raised an objection during the trial.","exampleZh":"律師在審判中提出了異議。","synonyms":["protest","opposition"],"level":5,"theme":"政治與法律","examples":[{"en":"The lawyer raised an objection during the trial.","zh":"律師在審判中提出了異議。"},{"en":"The committee members raised no objection to the final proposal.","zh":"委員會成員對最終提案沒有異議。"},{"en":"She had a strong objection to changing the meeting time.","zh":"她強烈反對更改開會時間。"}]},{"word":"objective","pos":"n. / adj.","phonetic":"[əbˈdʒɛktɪv]","meaning":"目標；客觀的","definition":"a goal one aims to achieve; or based on facts rather than feelings","collocations":["achieve an objective","an objective view","the main objective"],"example":"Our main objective is to increase customer satisfaction.","exampleZh":"我們的主要目標是提升顧客滿意度。","synonyms":["goal","aim"],"level":5,"theme":"抽象概念","examples":[{"en":"Our main objective is to increase customer satisfaction.","zh":"我們的主要目標是提升顧客滿意度。"},{"en":"Our main objective this semester is to improve our English writing.","zh":"我們這學期的主要目標是提升英文寫作能力。"},{"en":"A good judge must keep an objective view of both sides.","zh":"一位好的裁判必須對雙方保持客觀的看法。"}]},{"word":"oblige","pos":"v.","phonetic":"[əˈblaɪdʒ]","meaning":"使負有義務；迫使","definition":"to make someone legally or morally bound to do something","collocations":["obliged to pay","feel obliged","oblige someone to act"],"example":"The contract obliges both parties to complete the work on time.","exampleZh":"這份合約要求雙方都要準時完成工作。","synonyms":["compel","require"],"level":6,"theme":"抽象概念","examples":[{"en":"The contract obliges both parties to complete the work on time.","zh":"這份合約要求雙方都要準時完成工作。"},{"en":"The new rule obliges every rider to wear a helmet.","zh":"新規定要求每位騎士都必須戴安全帽。"},{"en":"I felt obliged to thank her for such a generous gift.","zh":"我覺得有義務感謝她如此慷慨的禮物。"}]},{"word":"obscure","pos":"adj. / v.","phonetic":"[əbˈskjʊr]","meaning":"模糊的；晦澀難懂的；遮蔽","definition":"not clearly expressed or understood; or to hide from view","collocations":["an obscure meaning","obscure the view","obscure reference"],"example":"The instructions were so obscure that no one understood them.","exampleZh":"那份說明太過晦澀，沒有人看得懂。","synonyms":["unclear","vague"],"level":6,"theme":"性質與描述","examples":[{"en":"The instructions were so obscure that no one understood them.","zh":"那份說明太過晦澀，沒有人看得懂。"},{"en":"Thick fog obscured the mountain peak from our view.","zh":"濃霧遮蔽了我們視野中的山峰。"},{"en":"The poem contains an obscure reference that few readers understand.","zh":"這首詩含有一個少有讀者能理解的晦澀典故。"}]},{"word":"observant","pos":"adj.","phonetic":"[əbˈzɝvənt]","meaning":"觀察力敏銳的","definition":"quick to notice things","collocations":["an observant student","observant of details"],"example":"An observant detective noticed the tiny footprint by the door.","exampleZh":"一位觀察力敏銳的偵探注意到門邊的小腳印。","synonyms":["attentive","perceptive"],"level":5,"theme":"性質與描述","examples":[{"en":"An observant detective noticed the tiny footprint by the door.","zh":"一位觀察力敏銳的偵探注意到門邊的小腳印。"},{"en":"An observant reader will notice the small clues hidden in the story.","zh":"觀察力敏銳的讀者會注意到故事中隱藏的小線索。"},{"en":"Being observant of details helped her solve the puzzle quickly.","zh":"對細節觀察敏銳幫助她迅速解開了謎題。"}]},{"word":"observation","pos":"n.","phonetic":"[ˌɑbzɚˈveʃən]","meaning":"觀察；觀測","definition":"the act of watching something carefully","collocations":["scientific observation","keep under observation","make an observation"],"example":"The scientist recorded her observations in a notebook.","exampleZh":"科學家把她的觀察結果記錄在筆記本上。","synonyms":["watching","monitoring"],"level":4,"theme":"科學與數學","examples":[{"en":"The scientist recorded her observations in a notebook.","zh":"科學家把她的觀察結果記錄在筆記本上。"},{"en":"Careful observation of the weather helped the farmers plan their harvest.","zh":"對天氣的仔細觀察幫助農民安排收成。"},{"en":"The patient was kept under observation in the hospital overnight.","zh":"那位病患在醫院被留院觀察了一夜。"}]},{"word":"observatory","pos":"n.","phonetic":"[əbˈzɝvəˌtori]","meaning":"天文台","definition":"a building equipped for observing astronomical events","collocations":["visit an observatory","a mountain observatory"],"example":"We visited the observatory to look at the stars through a telescope.","exampleZh":"我們參觀天文台,透過望遠鏡觀看星星。","synonyms":[],"level":5,"theme":"科學與數學","examples":[{"en":"We visited the observatory to look at the stars through a telescope.","zh":"我們參觀天文台,透過望遠鏡觀看星星。"},{"en":"From the mountain observatory, we watched a meteor shower at midnight.","zh":"我們在山上的天文台於午夜觀賞了一場流星雨。"},{"en":"The observatory opens to visitors on clear weekend nights.","zh":"這座天文台在晴朗的週末夜晚對訪客開放。"}]},{"word":"observe","pos":"v.","phonetic":"[əbˈzɝv]","meaning":"觀察；注意到；遵守","definition":"to watch carefully or notice something","collocations":["observe closely","observe a custom","observe behavior"],"example":"Researchers observed the animals in their natural habitat.","exampleZh":"研究人員在自然棲息地觀察這些動物。","synonyms":["watch","notice"],"level":3,"theme":"科學與數學","examples":[{"en":"Researchers observed the animals in their natural habitat.","zh":"研究人員在自然棲息地觀察這些動物。"},{"en":"Students observed the tiny cells closely through a microscope.","zh":"學生們透過顯微鏡仔細觀察那些微小的細胞。"},{"en":"In this village, people still observe many old traditions.","zh":"在這個村莊，人們仍然遵守許多古老的傳統。"}]},{"word":"observer","pos":"n.","phonetic":"[əbˈzɝvɚ]","meaning":"觀察者；旁觀者","definition":"a person who watches something happen but does not take part","collocations":["a neutral observer","an election observer","act as an observer"],"example":"An international observer monitored the election process.","exampleZh":"一位國際觀察員監督了整個選舉過程。","synonyms":["watcher","onlooker"],"level":4,"theme":"社會與文化","examples":[{"en":"An international observer monitored the election process.","zh":"一位國際觀察員監督了整個選舉過程。"},{"en":"As a neutral observer, she refused to take either side.","zh":"身為中立的觀察者，她拒絕偏袒任何一方。"},{"en":"A careful observer can tell when someone is hiding the truth.","zh":"細心的觀察者能看出某人何時在隱瞞真相。"}]},{"word":"obsess","pos":"v.","phonetic":"[əbˈsɛs]","meaning":"使著迷；使困擾","definition":"to think about someone or something all the time","collocations":["obsess over details","obsess about weight","be obsessed with"],"example":"He tends to obsess over small mistakes.","exampleZh":"他總是對小錯誤耿耿於懷。","synonyms":["fixate"],"level":5,"theme":"情緒與感受","examples":[{"en":"He tends to obsess over small mistakes.","zh":"他總是對小錯誤耿耿於懷。"},{"en":"He tends to obsess over every detail of his art project.","zh":"他往往會對美術作品的每個細節過度執著。"},{"en":"Don't obsess about one low grade; focus on the whole semester.","zh":"別為一次低分耿耿於懷，把焦點放在整個學期上。"}]},{"word":"obsession","pos":"n.","phonetic":"[əbˈsɛʃən]","meaning":"著迷；癡迷","definition":"an idea or thought that continually occupies a person's mind","collocations":["a growing obsession","an obsession with fame","become an obsession"],"example":"His obsession with video games affected his grades.","exampleZh":"他對電玩的癡迷影響了他的成績。","synonyms":["fixation","mania"],"level":5,"theme":"情緒與感受","examples":[{"en":"His obsession with video games affected his grades.","zh":"他對電玩的癡迷影響了他的成績。"},{"en":"Her obsession with fashion led her to study clothing design.","zh":"她對時尚的癡迷促使她去學習服裝設計。"},{"en":"Collecting stamps started as a hobby but became an obsession.","zh":"集郵一開始是興趣，後來卻變成一種癡迷。"}]},{"word":"obsolete","pos":"adj.","phonetic":"[ˌɑbsəˈlit]","meaning":"過時的；淘汰的","definition":"no longer in use or no longer useful because something newer exists","collocations":["become obsolete","obsolete equipment"],"example":"Many old machines have become obsolete due to new technology.","exampleZh":"許多舊機器因新科技而遭到淘汰。","synonyms":["outdated","old-fashioned"],"level":5,"theme":"科技與媒體","examples":[{"en":"Many old machines have become obsolete due to new technology.","zh":"許多舊機器因新科技而遭到淘汰。"},{"en":"Cassette tapes became obsolete after digital music appeared.","zh":"卡帶在數位音樂出現後就被淘汰了。"},{"en":"The factory replaced its obsolete equipment with modern machines.","zh":"工廠用現代機器取代了過時的設備。"}]},{"word":"obstacle","pos":"n.","phonetic":"[ˈɑbstəkl]","meaning":"障礙；阻礙","definition":"something that blocks progress or makes it difficult","collocations":["overcome an obstacle","face obstacles","a major obstacle"],"example":"Lack of money was the main obstacle to starting the business.","exampleZh":"資金不足是創業最大的障礙。","synonyms":["barrier","hurdle"],"level":4,"theme":"抽象概念","examples":[{"en":"Lack of money was the main obstacle to starting the business.","zh":"資金不足是創業最大的障礙。"},{"en":"With hard work, she overcame every obstacle on her path to college.","zh":"憑藉努力，她克服了通往大學路上的每個障礙。"},{"en":"Shyness can be a major obstacle when learning a new language.","zh":"害羞在學習新語言時可能是一大障礙。"}]},{"word":"obstruct","pos":"v.","phonetic":"[əbˈstrʌkt]","meaning":"阻礙；阻擋","definition":"to block or hinder movement or progress","collocations":["obstruct the view","obstruct justice","obstruct traffic"],"example":"The fallen tree obstructed the road for hours.","exampleZh":"倒下的樹擋住道路長達數小時。","synonyms":["block","hinder"],"level":5,"theme":"動作與行為","examples":[{"en":"The fallen tree obstructed the road for hours.","zh":"倒下的樹擋住道路長達數小時。"},{"en":"A large truck obstructed traffic on the narrow street for an hour.","zh":"一輛大卡車在狹窄的街道上阻擋交通長達一小時。"},{"en":"Please don't stand there and obstruct the view of others.","zh":"請不要站在那裡擋住別人的視線。"}]},{"word":"obtain","pos":"v.","phonetic":"[əbˈten]","meaning":"獲得；取得","definition":"to get something, especially through effort","collocations":["obtain permission","obtain information","obtain a degree"],"example":"She worked hard to obtain a scholarship for college.","exampleZh":"她努力爭取到一份大學獎學金。","synonyms":["acquire","gain"],"level":4,"theme":"動作與行為","examples":[{"en":"She worked hard to obtain a scholarship for college.","zh":"她努力爭取到一份大學獎學金。"},{"en":"You must obtain permission from your parents before the field trip.","zh":"你必須在校外教學前取得父母的同意。"},{"en":"After years of study, he finally obtained his medical degree.","zh":"經過多年苦讀，他終於取得了醫學學位。"}]},{"word":"obvious","pos":"adj.","phonetic":"[ˈɑbviəs]","meaning":"明顯的；顯而易見的","definition":"easy to see or understand","collocations":["an obvious mistake","for obvious reasons","make it obvious"],"example":"It was obvious that she was upset about the news.","exampleZh":"很明顯她對這個消息感到不安。","synonyms":["clear","evident"],"level":3,"theme":"性質與描述","examples":[{"en":"It was obvious that she was upset about the news.","zh":"很明顯她對這個消息感到不安。"},{"en":"It was obvious from her smile that she had passed the exam.","zh":"從她的笑容顯而易見，她通過了考試。"},{"en":"The teacher circled the obvious mistake in red ink.","zh":"老師用紅筆圈出了那個明顯的錯誤。"}]},{"word":"obviously","pos":"adv.","phonetic":"[ˈɑbviəsli]","meaning":"顯然地；明顯地","definition":"in a way that is clear and easy to notice","collocations":["obviously wrong","obviously upset","obviously true"],"example":"Obviously, the team needs more practice before the game.","exampleZh":"顯然，這支隊伍在比賽前需要更多練習。","synonyms":["clearly","evidently"],"level":3,"theme":"溝通與語言","examples":[{"en":"Obviously, the team needs more practice before the game.","zh":"顯然，這支隊伍在比賽前需要更多練習。"},{"en":"He was obviously tired after running the entire marathon.","zh":"跑完整場馬拉松後，他顯然累壞了。"},{"en":"The answer is obviously wrong, so please check your calculation.","zh":"這個答案顯然是錯的，所以請檢查你的計算。"}]},{"word":"occasion","pos":"n.","phonetic":"[əˈkeʒən]","meaning":"場合；時機","definition":"a particular time or event","collocations":["a special occasion","on this occasion","rise to the occasion"],"example":"We only use the good china on special occasions.","exampleZh":"我們只有在特別的場合才會用那套好瓷器。","synonyms":["event","occurrence"],"level":3,"theme":"時間與空間","examples":[{"en":"We only use the good china on special occasions.","zh":"我們只有在特別的場合才會用那套好瓷器。"},{"en":"A wedding is a special occasion that calls for formal clothes.","zh":"婚禮是需要穿正式服裝的特殊場合。"},{"en":"On this occasion, the whole family gathered to celebrate together.","zh":"在這個場合，全家人聚在一起共同慶祝。"}]},{"word":"occasional","pos":"adj.","phonetic":"[əˈkeʒənl]","meaning":"偶爾的；偶發的","definition":"happening sometimes but not often or regularly","collocations":["occasional visits","occasional rain","an occasional treat"],"example":"He enjoys an occasional cup of coffee in the afternoon.","exampleZh":"他偶爾喜歡在下午喝杯咖啡。","synonyms":["infrequent","rare"],"level":4,"theme":"時間與空間","examples":[{"en":"He enjoys an occasional cup of coffee in the afternoon.","zh":"他偶爾喜歡在下午喝杯咖啡。"},{"en":"We enjoyed the sunshine despite the occasional rain during our trip.","zh":"儘管旅途中偶爾下雨，我們仍享受了陽光。"},{"en":"An occasional treat won't ruin your healthy diet.","zh":"偶爾吃點零食不會破壞你健康的飲食。"}]},{"word":"occasionally","pos":"adv.","phonetic":"[əˈkeʒənli]","meaning":"偶爾地","definition":"sometimes but not often","collocations":["occasionally visit","eat out occasionally","occasionally happens"],"example":"She occasionally travels abroad for work.","exampleZh":"她偶爾會因工作出國。","synonyms":["sometimes","now and then"],"level":4,"theme":"時間與空間","examples":[{"en":"She occasionally travels abroad for work.","zh":"她偶爾會因工作出國。"},{"en":"My grandparents occasionally visit us during the summer holidays.","zh":"我的祖父母偶爾會在暑假期間來探望我們。"},{"en":"The old machine occasionally breaks down without any warning.","zh":"那台老機器偶爾會毫無預警地故障。"}]},{"word":"occupant","pos":"n.","phonetic":"[ˈɑkjəpənt]","meaning":"居住者；使用者","definition":"a person who occupies or lives in a particular place","collocations":["the occupant of a house","the vehicle's occupants"],"example":"The occupant of the apartment complained about the noise.","exampleZh":"那間公寓的住戶抱怨噪音問題。","synonyms":[],"level":4,"theme":"居家與生活","examples":[{"en":"The occupant of the apartment complained about the noise.","zh":"那間公寓的住戶抱怨噪音問題。"},{"en":"The new occupant of the house planted flowers in the front yard.","zh":"這棟房子的新住戶在前院種了花。"},{"en":"All the occupants of the car wore their seat belts.","zh":"車上所有的乘坐者都繫好了安全帶。"}]},{"word":"occupation","pos":"n.","phonetic":"[ˌɑkjəˈpeʃən]","meaning":"職業；佔領","definition":"a person's job or profession; the act of occupying a place","collocations":["state your occupation","a skilled occupation","military occupation"],"example":"Please state your name, age, and occupation on the form.","exampleZh":"請在表格上填寫你的姓名、年齡和職業。","synonyms":["job","profession"],"level":4,"theme":"工作與職業","examples":[{"en":"Please state your name, age, and occupation on the form.","zh":"請在表格上填寫你的姓名、年齡和職業。"},{"en":"Please write your name and occupation clearly on this form.","zh":"請在這張表格上清楚寫下你的姓名和職業。"},{"en":"Teaching is a rewarding but demanding occupation.","zh":"教書是一份有成就感但要求很高的職業。"}]},{"word":"occupy","pos":"v.","phonetic":"[ˈɑkjəˌpaɪ]","meaning":"佔據；佔領；使忙碌","definition":"to take up space, time, or attention, or to live in a place","collocations":["occupy a seat","occupy your time","occupy a building"],"example":"The children occupied themselves with puzzles during the trip.","exampleZh":"孩子們在旅途中用拼圖打發時間。","synonyms":["inhabit","fill"],"level":4,"theme":"動作與行為","examples":[{"en":"The children occupied themselves with puzzles during the trip.","zh":"孩子們在旅途中用拼圖打發時間。"},{"en":"Please don't occupy the seat that is reserved for the elderly.","zh":"請不要佔用保留給年長者的座位。"},{"en":"Reading comic books occupied most of his free time.","zh":"看漫畫佔據了他大部分的空閒時間。"}]},{"word":"occur","pos":"v.","phonetic":"[əˈkɝ]","meaning":"發生；出現","definition":"to happen or take place","collocations":["occur naturally","an accident occurs","occur to someone"],"example":"The earthquake occurred late at night when most people were asleep.","exampleZh":"地震發生在深夜，大多數人都已入睡。","synonyms":["happen","take place"],"level":3,"theme":"抽象概念","examples":[{"en":"The earthquake occurred late at night when most people were asleep.","zh":"地震發生在深夜，大多數人都已入睡。"},{"en":"Most traffic accidents occur when drivers are tired or distracted.","zh":"大多數交通事故發生在駕駛疲勞或分心時。"},{"en":"A brilliant idea suddenly occurred to me during the shower.","zh":"洗澡時我突然想到一個絕妙的點子。"}]},{"word":"occurrence","pos":"n.","phonetic":"[əˈkɝəns]","meaning":"發生的事；事件","definition":"something that happens; an event","collocations":["a common occurrence","a rare occurrence","daily occurrence"],"example":"Traffic jams are a common occurrence in this city.","exampleZh":"塞車在這座城市是很常見的事。","synonyms":["event","incident"],"level":5,"theme":"抽象概念","examples":[{"en":"Traffic jams are a common occurrence in this city.","zh":"塞車在這座城市是很常見的事。"},{"en":"Power failures are a rare occurrence in this modern city.","zh":"停電在這座現代城市裡是罕見的事。"},{"en":"Seeing wild monkeys here is a daily occurrence for the villagers.","zh":"對村民而言，在這裡看到野生猴子是每天都有的事。"}]},{"word":"ocean","pos":"n.","phonetic":"[ˈoʃən]","meaning":"海洋；大海","definition":"a very large body of salt water","collocations":["the deep ocean","ocean waves","across the ocean"],"example":"The ship sailed across the vast ocean for weeks.","exampleZh":"這艘船在浩瀚的海洋上航行了好幾個星期。","synonyms":["sea"],"level":1,"theme":"自然與環境","examples":[{"en":"The ship sailed across the vast ocean for weeks.","zh":"這艘船在浩瀚的海洋上航行了好幾個星期。"},{"en":"Huge ocean waves crashed against the rocks below the lighthouse.","zh":"巨大的海浪拍打著燈塔下方的岩石。"},{"en":"Scientists are still exploring the mysteries of the deep ocean.","zh":"科學家仍在探索深海的奧秘。"}]},{"word":"octopus","pos":"n.","phonetic":"[ˈɑktəpəs]","meaning":"章魚","definition":"a sea animal with a soft body and eight arms","collocations":["a giant octopus","an octopus tank","octopus tentacles"],"example":"The octopus quickly changed color to hide from danger.","exampleZh":"章魚迅速改變顏色以躲避危險。","synonyms":[],"level":2,"theme":"動物與植物","examples":[{"en":"The octopus quickly changed color to hide from danger.","zh":"章魚迅速改變顏色以躲避危險。"},{"en":"A giant octopus stretched its eight arms across the coral reef.","zh":"一隻巨大的章魚將牠的八隻腕伸過珊瑚礁。"},{"en":"We watched the octopus squeeze through a surprisingly narrow gap.","zh":"我們看著章魚擠過一個出乎意料狹窄的縫隙。"}]},{"word":"odd","pos":"adj.","phonetic":"[ɑd]","meaning":"奇怪的；奇數的","definition":"strange or unusual; not divisible by two evenly","collocations":["an odd number","an odd habit","act odd"],"example":"It seemed odd that no one answered the door.","exampleZh":"沒有人來應門，這感覺很奇怪。","synonyms":["strange","peculiar"],"level":3,"theme":"性質與描述","examples":[{"en":"It seemed odd that no one answered the door.","zh":"沒有人來應門，這感覺很奇怪。"},{"en":"One, three, and five are all odd numbers.","zh":"一、三和五都是奇數。"},{"en":"It felt odd to see the busy market completely empty.","zh":"看到熱鬧的市場空無一人，感覺很奇怪。"}]},{"word":"odor","pos":"n.","phonetic":"[ˈodɚ]","meaning":"氣味；臭味","definition":"a smell, especially an unpleasant one","collocations":["a strong odor","a bad odor","body odor"],"example":"A strange odor came from the kitchen.","exampleZh":"廚房傳來一股奇怪的氣味。","synonyms":["smell","scent"],"level":4,"theme":"性質與描述","examples":[{"en":"A strange odor came from the kitchen.","zh":"廚房傳來一股奇怪的氣味。"},{"en":"A strong odor of garlic filled the whole kitchen.","zh":"濃烈的大蒜氣味瀰漫了整個廚房。"},{"en":"The spoiled milk gave off a terrible odor.","zh":"那壞掉的牛奶散發出可怕的臭味。"}]},{"word":"off","pos":"adv. / prep. / adj.","phonetic":"[ɔf]","meaning":"離開；關掉的；不新鮮的","definition":"away from a place or position; not turned on","collocations":["turn off","get off","off duty"],"example":"Please turn off the lights before you leave.","exampleZh":"離開前請把燈關掉。","synonyms":[],"level":1,"theme":"動作與行為","examples":[{"en":"Please turn off the lights before you leave.","zh":"離開前請把燈關掉。"},{"en":"Remember to turn off the fan before you leave the classroom.","zh":"離開教室前記得把電風扇關掉。"},{"en":"The nurse is off duty after nine o'clock tonight.","zh":"那位護士今晚九點以後就下班了。"}]},{"word":"offend","pos":"v.","phonetic":"[əˈfɛnd]","meaning":"冒犯；使不悅","definition":"to make someone feel upset or angry","collocations":["offend someone","easily offended","offend religious beliefs"],"example":"His rude comment offended everyone at the table.","exampleZh":"他粗魯的評論冒犯了桌上的每個人。","synonyms":["insult","upset"],"level":5,"theme":"情緒與感受","examples":[{"en":"His rude comment offended everyone at the table.","zh":"他粗魯的評論冒犯了桌上的每個人。"},{"en":"I didn't mean to offend you with my careless joke.","zh":"我不是故意用我那不經意的玩笑冒犯你的。"},{"en":"Some viewers were offended by the show's rude language.","zh":"有些觀眾被節目中粗魯的言語冒犯了。"}]},{"word":"offense","pos":"n.","phonetic":"[əˈfɛns]","meaning":"冒犯；犯罪；進攻","definition":"an act that breaks a rule or law, or causes anger","collocations":["take offense","a criminal offense","mean no offense"],"example":"No offense, but I think your plan has a flaw.","exampleZh":"無意冒犯，但我覺得你的計畫有個缺陷。","synonyms":["violation","insult"],"level":5,"theme":"政治與法律","examples":[{"en":"No offense, but I think your plan has a flaw.","zh":"無意冒犯，但我覺得你的計畫有個缺陷。"},{"en":"Driving without a license is a serious offense.","zh":"無照駕駛是嚴重的犯罪行為。"},{"en":"She took offense at his comment about her cooking.","zh":"她因為他對她廚藝的評論而感到被冒犯。"}]},{"word":"offer","pos":"v. / n.","phonetic":"[ˈɔfɚ]","meaning":"提供；提議；出價","definition":"to present something for someone to accept or refuse","collocations":["offer help","a job offer","offer advice"],"example":"She offered to help me carry the boxes upstairs.","exampleZh":"她主動幫我把箱子搬到樓上。","synonyms":["propose","provide"],"level":2,"theme":"溝通與語言","examples":[{"en":"She offered to help me carry the boxes upstairs.","zh":"她主動幫我把箱子搬到樓上。"},{"en":"A kind stranger offered to help us find the train station.","zh":"一位好心的陌生人主動幫我們找火車站。"},{"en":"She accepted the job offer from the local newspaper.","zh":"她接受了當地報社的工作邀約。"}]},{"word":"office","pos":"n.","phonetic":"[ˈɔfɪs]","meaning":"辦公室；職位","definition":"a room or building where people work at desks","collocations":["work in an office","office hours","run for office"],"example":"My father works in an office downtown.","exampleZh":"我父親在市中心的一間辦公室工作。","synonyms":["workplace"],"level":1,"theme":"工作與職業","examples":[{"en":"My father works in an office downtown.","zh":"我父親在市中心的一間辦公室工作。"},{"en":"The library staff work in a small office behind the front desk.","zh":"圖書館的工作人員在櫃台後方的小辦公室裡工作。"},{"en":"Our teacher keeps regular office hours to answer our questions.","zh":"我們老師有固定的辦公時間來回答我們的問題。"}]},{"word":"officer","pos":"n.","phonetic":"[ˈɔfəsɚ]","meaning":"官員；警官；軍官","definition":"a person who holds a position of authority, especially in the police or military","collocations":["a police officer","a military officer","customs officer"],"example":"The police officer asked to see his driver's license.","exampleZh":"警官要求查看他的駕照。","synonyms":["official"],"level":2,"theme":"工作與職業","examples":[{"en":"The police officer asked to see his driver's license.","zh":"警官要求查看他的駕照。"},{"en":"A friendly police officer helped the lost child find her mother.","zh":"一位親切的警官幫助迷路的小孩找到了她的母親。"},{"en":"The customs officer carefully checked every passenger's luggage.","zh":"海關人員仔細檢查了每位旅客的行李。"}]},{"word":"official","pos":"adj. / n.","phonetic":"[əˈfɪʃəl]","meaning":"官方的；正式的；官員","definition":"relating to authority or government; a person holding a public position","collocations":["an official statement","government officials","make it official"],"example":"The government made an official announcement about the new policy.","exampleZh":"政府針對這項新政策發表了官方聲明。","synonyms":["formal","authorized"],"level":3,"theme":"政治與法律","examples":[{"en":"The government made an official announcement about the new policy.","zh":"政府針對這項新政策發表了官方聲明。"},{"en":"The school posted an official notice about the new dress code.","zh":"學校張貼了一則關於新服裝規定的官方公告。"},{"en":"Several government officials attended the opening of the bridge.","zh":"幾位政府官員出席了大橋的啟用典禮。"}]},{"word":"offspring","pos":"n.","phonetic":"[ˈɔfˌsprɪŋ]","meaning":"子女；後代","definition":"a person's child or children; an animal's young","collocations":["produce offspring","raise offspring"],"example":"Elephants care for their offspring for many years.","exampleZh":"大象會照顧牠們的後代長達許多年。","synonyms":["children","young"],"level":4,"theme":"人物與家庭","examples":[{"en":"Elephants care for their offspring for many years.","zh":"大象會照顧牠們的後代長達許多年。"},{"en":"Penguins work hard to protect their offspring from the cold.","zh":"企鵝努力保護牠們的後代免受寒冷侵襲。"},{"en":"Parents naturally want the best for their offspring.","zh":"父母自然都想給子女最好的一切。"}]},{"word":"often","pos":"adv.","phonetic":"[ˈɔfən]","meaning":"常常；經常","definition":"frequently; many times","collocations":["how often","quite often","not often"],"example":"We often go hiking on the weekends.","exampleZh":"我們週末常常去健行。","synonyms":["frequently"],"level":1,"theme":"時間與空間","examples":[{"en":"We often go hiking on the weekends.","zh":"我們週末常常去健行。"},{"en":"How often do you practice the piano after school?","zh":"你放學後多常練鋼琴？"},{"en":"We don't often see such a beautiful sunset in the city.","zh":"我們在城市裡不常看到如此美麗的日落。"}]},{"word":"oil","pos":"n. / v.","phonetic":"[ɔɪl]","meaning":"油；石油；上油","definition":"a thick liquid substance used for cooking, fuel, or lubrication","collocations":["cooking oil","crude oil","oil a machine"],"example":"She added a spoonful of olive oil to the salad.","exampleZh":"她在沙拉裡加了一匙橄欖油。","synonyms":[],"level":2,"theme":"食物與烹飪","examples":[{"en":"She added a spoonful of olive oil to the salad.","zh":"她在沙拉裡加了一匙橄欖油。"},{"en":"He heated some cooking oil in the pan before frying the eggs.","zh":"他在鍋裡加熱一些食用油才開始煎蛋。"},{"en":"You should oil the squeaky door hinge to stop the noise.","zh":"你應該在吱嘎作響的門鉸鏈上上油以停止噪音。"}]},{"word":"ointment","pos":"n.","phonetic":"[ˈɔɪntmənt]","meaning":"藥膏；油膏","definition":"a smooth substance rubbed on the skin to heal or soothe it","collocations":["apply ointment","a soothing ointment","antibiotic ointment"],"example":"The nurse applied ointment to the burn on his hand.","exampleZh":"護士在他手上的燙傷處塗了藥膏。","synonyms":["cream","salve"],"level":5,"theme":"身體與健康","examples":[{"en":"The nurse applied ointment to the burn on his hand.","zh":"護士在他手上的燙傷處塗了藥膏。"},{"en":"Apply this ointment twice a day to help the cut heal.","zh":"每天塗抹這種藥膏兩次，以幫助傷口癒合。"},{"en":"The doctor gave me a soothing ointment for the insect bites.","zh":"醫生給了我一種舒緩的藥膏來處理蟲咬。"}]},{"word":"okay","pos":"adj. / adv. / int.","phonetic":"[ˌoˈke]","meaning":"好的；可以的；沒問題","definition":"acceptable, satisfactory, or all right","collocations":["feel okay","it's okay","say okay"],"example":"Is it okay if I borrow your pen for a minute?","exampleZh":"我可以借用你的筆一下嗎？","synonyms":["fine","all right"],"level":1,"theme":"溝通與語言","examples":[{"en":"Is it okay if I borrow your pen for a minute?","zh":"我可以借用你的筆一下嗎？"},{"en":"Is it okay if we start the meeting ten minutes early?","zh":"我們提早十分鐘開始開會可以嗎？"},{"en":"After a good rest, she felt okay enough to go to school.","zh":"好好休息後，她覺得身體還好，可以去上學。"}]},{"word":"old","pos":"adj.","phonetic":"[old]","meaning":"老的；舊的","definition":"having lived or existed for a long time","collocations":["an old friend","grow old","an old house"],"example":"My grandmother is quite old but still very active.","exampleZh":"我奶奶年紀很大了，但依然很有活力。","synonyms":["aged","elderly"],"level":1,"theme":"性質與描述","examples":[{"en":"My grandmother is quite old but still very active.","zh":"我奶奶年紀很大了，但依然很有活力。"},{"en":"We visited an old friend whom we hadn't seen for years.","zh":"我們拜訪了一位多年不見的老朋友。"},{"en":"They decided to repair the old house instead of selling it.","zh":"他們決定修繕這棟舊房子而不是賣掉它。"}]},{"word":"olive","pos":"n.","phonetic":"[ˈɑlɪv]","meaning":"橄欖","definition":"a small fruit used to make oil or eaten as food","collocations":["olive oil","black olives","an olive tree"],"example":"The salad was topped with green olives and feta cheese.","exampleZh":"沙拉上放了綠橄欖和菲達乳酪。","synonyms":[],"level":3,"theme":"食物與烹飪","examples":[{"en":"The salad was topped with green olives and feta cheese.","zh":"沙拉上放了綠橄欖和菲達乳酪。"},{"en":"She drizzled some olive oil over the fresh green salad.","zh":"她在新鮮的綠色沙拉上淋了一些橄欖油。"},{"en":"A small olive tree grows in a pot on their balcony.","zh":"一棵小橄欖樹種在他們陽台的盆栽裡。"}]},{"word":"omen","pos":"n.","phonetic":"[ˈomən]","meaning":"預兆；徵兆","definition":"a sign believed to indicate a future event","collocations":["a good omen","a bad omen","an omen of disaster"],"example":"Some people believe a black cat crossing your path is a bad omen.","exampleZh":"有些人相信黑貓穿過你的路是不祥之兆。","synonyms":["sign","portent"],"level":6,"theme":"社會與文化","examples":[{"en":"Some people believe a black cat crossing your path is a bad omen.","zh":"有些人相信黑貓穿過你的路是不祥之兆。"},{"en":"The farmers saw the early rain as a good omen for the crops.","zh":"農民把提早到來的雨視為作物豐收的好預兆。"},{"en":"In many cultures, a shooting star is considered a lucky omen.","zh":"在許多文化中，流星被視為幸運的徵兆。"}]},{"word":"omit","pos":"v.","phonetic":"[oˈmɪt]","meaning":"省略；遺漏","definition":"to leave out or fail to include something","collocations":["omit a detail","omit a name","omit from the list"],"example":"She omitted her middle name from the application form.","exampleZh":"她在申請表上省略了她的中間名。","synonyms":["leave out","exclude"],"level":5,"theme":"溝通與語言","examples":[{"en":"She omitted her middle name from the application form.","zh":"她在申請表上省略了她的中間名。"},{"en":"Be careful not to omit any important detail in your report.","zh":"小心不要在你的報告中遺漏任何重要細節。"},{"en":"He accidentally omitted his phone number from the form.","zh":"他不小心在表格上漏填了電話號碼。"}]},{"word":"once","pos":"adv. / conj.","phonetic":"[wʌns]","meaning":"一次；曾經；一旦","definition":"one time; at some time in the past; as soon as","collocations":["once a week","once upon a time","once you finish"],"example":"Once you finish your homework, you can watch TV.","exampleZh":"一旦你做完功課，就可以看電視。","synonyms":[],"level":1,"theme":"時間與空間","examples":[{"en":"Once you finish your homework, you can watch TV.","zh":"一旦你做完功課，就可以看電視。"},{"en":"We visit our grandparents in the countryside once a month.","zh":"我們每個月去鄉下探望祖父母一次。"},{"en":"This quiet town was once a busy fishing port.","zh":"這座寧靜的小鎮曾經是繁忙的漁港。"}]},{"word":"one","pos":"n. / adj. / pron.","phonetic":"[wʌn]","meaning":"一；一個","definition":"the number 1; a single person or thing","collocations":["one day","one of the best","one by one"],"example":"One of my friends is moving to Taipei next month.","exampleZh":"我的一個朋友下個月要搬到台北。","synonyms":[],"level":1,"theme":"科學與數學","examples":[{"en":"One of my friends is moving to Taipei next month.","zh":"我的一個朋友下個月要搬到台北。"},{"en":"The students entered the exam hall one by one.","zh":"學生們一個接一個地進入考場。"},{"en":"This is one of the best novels I have ever read.","zh":"這是我讀過最好的小說之一。"}]},{"word":"ongoing","pos":"adj.","phonetic":"[ˈɑnˌgoɪŋ]","meaning":"持續進行的","definition":"continuing to happen or develop","collocations":["an ongoing investigation","ongoing support"],"example":"The company provides ongoing training for all new employees.","exampleZh":"這家公司為所有新員工提供持續性的培訓。","synonyms":["continuing","current"],"level":4,"theme":"性質與描述","examples":[{"en":"The company provides ongoing training for all new employees.","zh":"這家公司為所有新員工提供持續性的培訓。"},{"en":"The police are still conducting an ongoing investigation into the theft.","zh":"警方仍在對這起竊案進行持續的調查。"},{"en":"Learning a language is an ongoing process that never really ends.","zh":"學習語言是一個永無止境的持續過程。"}]},{"word":"onion","pos":"n.","phonetic":"[ˈʌnjən]","meaning":"洋蔥","definition":"a round vegetable with a strong smell and taste","collocations":["chop an onion","onion rings","fried onions"],"example":"Chopping onions often makes people's eyes water.","exampleZh":"切洋蔥常常讓人流眼淚。","synonyms":[],"level":1,"theme":"食物與烹飪","examples":[{"en":"Chopping onions often makes people's eyes water.","zh":"切洋蔥常常讓人流眼淚。"},{"en":"She fried some sliced onions until they turned golden brown.","zh":"她把切片的洋蔥炒到金黃色。"},{"en":"We ordered a plate of crispy onion rings to share.","zh":"我們點了一盤酥脆的洋蔥圈一起分享。"}]},{"word":"online","pos":"adj. / adv.","phonetic":"[ˈɑnˌlaɪn]","meaning":"線上的；上網","definition":"connected to or available through the internet","collocations":["shop online","an online course","online shopping"],"example":"More students are taking online courses these days.","exampleZh":"現在越來越多學生選修線上課程。","synonyms":[],"level":3,"theme":"科技與媒體","examples":[{"en":"More students are taking online courses these days.","zh":"現在越來越多學生選修線上課程。"},{"en":"I signed up for an online course to improve my writing.","zh":"我報名了一門線上課程來提升寫作能力。"},{"en":"Many people prefer online shopping because it saves time.","zh":"許多人偏好網購，因為它省時。"}]},{"word":"onlooker","pos":"n.","phonetic":"[ˈɑnˌlʊkɚ]","meaning":"旁觀者","definition":"a person who watches an event without taking part in it","collocations":["curious onlookers","a crowd of onlookers"],"example":"A group of onlookers gathered to watch the street performance.","exampleZh":"一群旁觀者聚集起來觀看街頭表演。","synonyms":["spectator","bystander"],"level":4,"theme":"社會與文化","examples":[{"en":"A group of onlookers gathered to watch the street performance.","zh":"一群旁觀者聚集起來觀看街頭表演。"},{"en":"A crowd of curious onlookers gathered around the street magician.","zh":"一群好奇的旁觀者聚集在街頭魔術師周圍。"},{"en":"Several onlookers helped the driver after the minor accident.","zh":"幾位旁觀者在那起小事故後幫助了駕駛。"}]},{"word":"only","pos":"adj. / adv.","phonetic":"[ˈonli]","meaning":"唯一的；只；僅僅","definition":"being the single one of its kind; no more than","collocations":["the only one","only if","if only"],"example":"She is the only student who finished the test early.","exampleZh":"她是唯一一位提早完成測驗的學生。","synonyms":["merely","just"],"level":1,"theme":"溝通與語言","examples":[{"en":"She is the only student who finished the test early.","zh":"她是唯一一位提早完成測驗的學生。"},{"en":"She was the only one who remembered to bring an umbrella.","zh":"她是唯一記得帶傘的人。"},{"en":"You may borrow the book only if you return it next week.","zh":"只有在你下週歸還的前提下，你才可以借這本書。"}]},{"word":"onto","pos":"prep.","phonetic":"[ˈɑntu]","meaning":"到⋯⋯之上","definition":"moving to a position on top of something","collocations":["climb onto","jump onto","hold onto"],"example":"The cat jumped onto the windowsill to watch the birds.","exampleZh":"貓跳到窗台上看鳥。","synonyms":[],"level":2,"theme":"時間與空間","examples":[{"en":"The cat jumped onto the windowsill to watch the birds.","zh":"貓跳到窗台上看鳥。"},{"en":"The children climbed onto the stage to receive their prizes.","zh":"孩子們爬上舞台領取他們的獎品。"},{"en":"Hold onto the railing tightly while walking down the stairs.","zh":"下樓梯時要緊緊抓住扶手。"}]},{"word":"onward","pos":"adv. / adj.","phonetic":"[ˈɑnwɚd]","meaning":"向前地；向前的","definition":"moving forward in space or time","collocations":["move onward","from now onward","onward journey"],"example":"We must keep moving onward despite the difficulties.","exampleZh":"儘管有困難，我們必須繼續向前邁進。","synonyms":["forward"],"level":4,"theme":"時間與空間","examples":[{"en":"We must keep moving onward despite the difficulties.","zh":"儘管有困難，我們必須繼續向前邁進。"},{"en":"Despite the storm, the ship sailed onward toward the harbor.","zh":"儘管有暴風雨，船仍向前航向港口。"},{"en":"From that day onward, he practiced English every morning.","zh":"從那天起，他每天早上都練習英文。"}]},{"word":"open","pos":"adj. / v.","phonetic":"[ˈopən]","meaning":"開的；打開；開放的","definition":"not closed; to make something no longer shut","collocations":["open a door","open hours","keep an open mind"],"example":"Please open the window; it's stuffy in here.","exampleZh":"請把窗戶打開，這裡很悶。","synonyms":["unlock"],"level":1,"theme":"動作與行為","examples":[{"en":"Please open the window; it's stuffy in here.","zh":"請把窗戶打開，這裡很悶。"},{"en":"A good scientist should keep an open mind about new ideas.","zh":"一位好的科學家對新想法應保持開放的心態。"},{"en":"She opened the old box and found her grandmother's letters.","zh":"她打開那個舊箱子，發現了她祖母的信件。"}]},{"word":"opening","pos":"n.","phonetic":"[ˈopənɪŋ]","meaning":"開幕；開口；空缺","definition":"a hole or space; the beginning of an event; a job vacancy","collocations":["a job opening","grand opening","an opening ceremony"],"example":"The company announced a new job opening in the marketing department.","exampleZh":"這間公司宣布行銷部門有一個新的職缺。","synonyms":["gap","vacancy"],"level":3,"theme":"工作與職業","examples":[{"en":"The company announced a new job opening in the marketing department.","zh":"這間公司宣布行銷部門有一個新的職缺。"},{"en":"There is a job opening for a librarian at our school.","zh":"我們學校有一個圖書館員的職缺。"},{"en":"Cold air rushed in through a small opening in the wall.","zh":"冷空氣從牆上一個小開口灌了進來。"}]},{"word":"opera","pos":"n.","phonetic":"[ˈɑpərə]","meaning":"歌劇","definition":"a play in which the words are sung to music","collocations":["watch an opera","opera house","opera singer"],"example":"They went to the opera house last night.","exampleZh":"他們昨晚去了歌劇院。","synonyms":[],"level":3,"theme":"藝術與音樂","examples":[{"en":"They went to the opera house last night.","zh":"他們昨晚去了歌劇院。"},{"en":"The famous opera singer amazed the audience with her powerful voice.","zh":"那位著名的歌劇演唱家以她渾厚的嗓音驚豔了觀眾。"},{"en":"We bought tickets to watch an Italian opera this weekend.","zh":"我們買了票要在這週末觀賞一齣義大利歌劇。"}]},{"word":"operate","pos":"v.","phonetic":"[ˈɑpəˌret]","meaning":"操作；運轉；動手術","definition":"to control or run a machine or system; to perform surgery","collocations":["operate a machine","operate on a patient","operate smoothly"],"example":"The surgeon operated on the patient for six hours.","exampleZh":"外科醫生為病人動了六個小時的手術。","synonyms":["run","function"],"level":4,"theme":"科技與媒體","examples":[{"en":"The surgeon operated on the patient for six hours.","zh":"外科醫生為病人動了六個小時的手術。"},{"en":"The workers learned how to operate the new printing machine.","zh":"工人們學會了如何操作那台新的印刷機。"},{"en":"The doctors will operate on her broken leg tomorrow morning.","zh":"醫生明天早上會為她骨折的腿動手術。"}]},{"word":"operation","pos":"n.","phonetic":"[ˌɑpəˈreʃən]","meaning":"手術；操作；運作","definition":"a surgical procedure; the process of working or functioning","collocations":["a rescue operation","a heart operation","in operation"],"example":"He is recovering well after his knee operation.","exampleZh":"他膝蓋手術後恢復得很好。","synonyms":["surgery","procedure"],"level":4,"theme":"身體與健康","examples":[{"en":"He is recovering well after his knee operation.","zh":"他膝蓋手術後恢復得很好。"},{"en":"The heart operation lasted several hours but was successful.","zh":"這場心臟手術持續了好幾個小時，但很成功。"},{"en":"The new subway line is finally in operation this year.","zh":"新的地鐵路線今年終於開始運作。"}]},{"word":"opinion","pos":"n.","phonetic":"[əˈpɪnjən]","meaning":"意見；看法","definition":"a personal view or judgment about something","collocations":["share an opinion","in my opinion","public opinion"],"example":"In my opinion, the new policy is a step in the right direction.","exampleZh":"依我看，這項新政策是朝正確方向邁進的一步。","synonyms":["view","belief"],"level":3,"theme":"溝通與語言","examples":[{"en":"In my opinion, the new policy is a step in the right direction.","zh":"依我看，這項新政策是朝正確方向邁進的一步。"},{"en":"Everyone is welcome to share an opinion during the class discussion.","zh":"在課堂討論中，歡迎每個人分享意見。"},{"en":"Public opinion about the new park has been very positive.","zh":"大眾對這座新公園的看法一直非常正面。"}]},{"word":"opponent","pos":"n.","phonetic":"[əˈponənt]","meaning":"對手；反對者","definition":"a person who competes against or disagrees with another","collocations":["defeat an opponent","a tough opponent","political opponent"],"example":"She easily defeated her opponent in the final match.","exampleZh":"她在決賽中輕鬆擊敗了對手。","synonyms":["rival","adversary"],"level":4,"theme":"運動與休閒","examples":[{"en":"She easily defeated her opponent in the final match.","zh":"她在決賽中輕鬆擊敗了對手。"},{"en":"The chess player studied his opponent's moves very carefully.","zh":"那位西洋棋手非常仔細地研究對手的棋步。"},{"en":"She shook hands with her opponent after the tennis match.","zh":"網球賽後，她和對手握了手。"}]},{"word":"opportunity","pos":"n.","phonetic":"[ˌɑpɚˈtunətɪ]","meaning":"機會","definition":"a chance to do something or achieve something","collocations":["a great opportunity","miss an opportunity","job opportunities"],"example":"Studying abroad gave her a great opportunity to learn a new language.","exampleZh":"出國留學讓她有很好的機會學習新語言。","synonyms":["chance"],"level":3,"theme":"抽象概念","examples":[{"en":"Studying abroad gave her a great opportunity to learn a new language.","zh":"出國留學讓她有很好的機會學習新語言。"},{"en":"Winning the contest gave him a great opportunity to travel abroad.","zh":"贏得比賽給了他一個出國旅行的大好機會。"},{"en":"Don't miss this rare opportunity to learn from a real expert.","zh":"別錯過這個向真正專家學習的難得機會。"}]},{"word":"oppose","pos":"v.","phonetic":"[əˈpoz]","meaning":"反對","definition":"to disagree with or resist a plan or idea","collocations":["oppose a plan","strongly oppose","oppose the government"],"example":"Many citizens oppose the new tax law.","exampleZh":"許多市民反對這項新稅法。","synonyms":["object to","resist"],"level":4,"theme":"政治與法律","examples":[{"en":"Many citizens oppose the new tax law.","zh":"許多市民反對這項新稅法。"},{"en":"Many residents strongly oppose the plan to cut down the old trees.","zh":"許多居民強烈反對砍掉那些老樹的計畫。"},{"en":"The workers opposed the decision to reduce their lunch break.","zh":"工人們反對縮短午休時間的決定。"}]},{"word":"opposite","pos":"adj. / n. / prep.","phonetic":"[ˈɑpəzɪt]","meaning":"相反的；對面的","definition":"completely different from something, or facing it","collocations":["opposite direction","the opposite sex","sit opposite"],"example":"He walked in the opposite direction.","exampleZh":"他朝相反的方向走去。","synonyms":["contrary","reverse"],"level":3,"theme":"性質與描述","examples":[{"en":"He walked in the opposite direction.","zh":"他朝相反的方向走去。"},{"en":"The library is on the opposite side of the street from the bank.","zh":"圖書館在銀行對面的街道那一側。"},{"en":"After the argument, the twins walked off in opposite directions.","zh":"吵完架後，這對雙胞胎往相反的方向走開了。"}]},{"word":"oppressive","pos":"adj.","phonetic":"[əˈprɛsɪv]","meaning":"壓迫的；沉悶難耐的","definition":"unjustly harsh or difficult to bear","collocations":["an oppressive regime","oppressive heat"],"example":"The people finally rebelled against the oppressive government.","exampleZh":"人民終於起義反抗那個壓迫人民的政府。","synonyms":["harsh","tyrannical"],"level":6,"theme":"政治與法律","examples":[{"en":"The people finally rebelled against the oppressive government.","zh":"人民終於起義反抗那個壓迫人民的政府。"},{"en":"The oppressive summer heat made it hard to concentrate in class.","zh":"沉悶難耐的夏日高溫讓人很難在課堂上專心。"},{"en":"People suffered greatly under the oppressive rule of the dictator.","zh":"人民在獨裁者的壓迫統治下受盡了苦難。"}]},{"word":"optical","pos":"adj.","phonetic":"[ˈɑptɪkl̩]","meaning":"光學的；視覺的","definition":"relating to vision or the sense of sight","collocations":["optical illusion","optical fiber"],"example":"The magic trick was simply an optical illusion.","exampleZh":"那個魔術其實只是個視覺錯覺。","synonyms":[],"level":4,"theme":"科學與數學","examples":[{"en":"The magic trick was simply an optical illusion.","zh":"那個魔術其實只是個視覺錯覺。"},{"en":"The two lines look different lengths, but it's just an optical illusion.","zh":"這兩條線看起來長度不同，但那只是視錯覺。"},{"en":"Optical fibers can carry huge amounts of data at high speed.","zh":"光纖能以高速傳輸大量資料。"}]},{"word":"optimism","pos":"n.","phonetic":"[ˈɑptəˌmɪzəm]","meaning":"樂觀","definition":"a feeling of hopefulness about the future","collocations":["a sense of optimism","cautious optimism","express optimism"],"example":"There is growing optimism about the economy.","exampleZh":"人們對經濟前景日益樂觀。","synonyms":["hopefulness"],"level":5,"theme":"情緒與感受","examples":[{"en":"There is growing optimism about the economy.","zh":"人們對經濟前景日益樂觀。"},{"en":"Her natural optimism helped the whole team stay motivated.","zh":"她天生的樂觀幫助整個團隊保持動力。"},{"en":"There is cautious optimism that the sick puppy will recover.","zh":"大家謹慎樂觀地認為那隻生病的小狗會康復。"}]},{"word":"optimistic","pos":"adj.","phonetic":"[ˌɑptəˈmɪstɪk]","meaning":"樂觀的","definition":"hopeful and confident about the future","collocations":["stay optimistic","optimistic about the future","remain optimistic"],"example":"She remains optimistic about her recovery.","exampleZh":"她對自己的康復保持樂觀。","synonyms":["positive","hopeful"],"level":4,"theme":"情緒與感受","examples":[{"en":"She remains optimistic about her recovery.","zh":"她對自己的康復保持樂觀。"},{"en":"She stayed optimistic even when the project ran into problems.","zh":"即使專案遇到問題，她仍保持樂觀。"},{"en":"Our coach is optimistic about our chances in the final game.","zh":"我們的教練對我們在決賽中的勝算感到樂觀。"}]},{"word":"option","pos":"n.","phonetic":"[ˈɑpʃən]","meaning":"選擇","definition":"a thing that may be chosen among alternatives","collocations":["have no option","the best option","consider an option"],"example":"Buying a used car is a cheaper option.","exampleZh":"買二手車是比較便宜的選擇。","synonyms":["choice","alternative"],"level":3,"theme":"抽象概念","examples":[{"en":"Buying a used car is a cheaper option.","zh":"買二手車是比較便宜的選擇。"},{"en":"Taking the train is the cheapest option for our school trip.","zh":"搭火車是我們校外旅行最便宜的選擇。"},{"en":"When the elevator broke, we had no option but to use the stairs.","zh":"電梯壞掉時，我們別無選擇只能走樓梯。"}]},{"word":"optional","pos":"adj.","phonetic":"[ˈɑpʃənḷ]","meaning":"可選擇的；非強制的","definition":"available to be chosen but not compulsory","collocations":["optional course","optional equipment","entirely optional"],"example":"Attending the workshop is optional, not required.","exampleZh":"參加這場工作坊是自由選擇的，非強制性。","synonyms":["voluntary"],"level":4,"theme":"教育與學習","examples":[{"en":"Attending the workshop is optional, not required.","zh":"參加這場工作坊是自由選擇的，非強制性。"},{"en":"The after-school music class is optional for all students.","zh":"課後的音樂課對所有學生來說都是非強制的。"},{"en":"Dessert is optional, but the main course is included in the price.","zh":"甜點可自由選擇，但主餐已包含在價格內。"}]},{"word":"oral","pos":"adj.","phonetic":"[ˈorəl]","meaning":"口頭的；口腔的","definition":"spoken rather than written, or relating to the mouth","collocations":["oral exam","oral hygiene","oral communication"],"example":"Students must pass an oral exam before graduation.","exampleZh":"學生畢業前必須通過口試。","synonyms":["spoken","verbal"],"level":4,"theme":"教育與學習","examples":[{"en":"Students must pass an oral exam before graduation.","zh":"學生畢業前必須通過口試。"},{"en":"Each student must give a short oral report in front of the class.","zh":"每位學生都必須在全班面前做一段簡短的口頭報告。"},{"en":"Brushing twice a day is important for good oral hygiene.","zh":"一天刷牙兩次對良好的口腔衛生很重要。"}]},{"word":"orange","pos":"n. / adj.","phonetic":"[ˈɔrɪndʒ]","meaning":"柳橙；橘色的","definition":"a round citrus fruit, or its color","collocations":["orange juice","peel an orange","orange peel"],"example":"I drink a glass of orange juice every morning.","exampleZh":"我每天早上都喝一杯柳橙汁。","synonyms":[],"level":1,"theme":"食物與烹飪","examples":[{"en":"I drink a glass of orange juice every morning.","zh":"我每天早上都喝一杯柳橙汁。"},{"en":"She peeled an orange and shared it with her little brother.","zh":"她剝了一顆柳橙，和她的小弟弟一起分享。"},{"en":"The evening sky slowly turned a beautiful shade of orange.","zh":"傍晚的天空慢慢轉為美麗的橘色。"}]},{"word":"orbit","pos":"n. / v.","phonetic":"[ˈɔrbɪt]","meaning":"軌道；繞行","definition":"the curved path of an object around a star or planet","collocations":["earth's orbit","orbit the sun","put into orbit"],"example":"The satellite orbits the Earth once every 90 minutes.","exampleZh":"這顆衛星每90分鐘繞地球一圈。","synonyms":[],"level":5,"theme":"科學與數學","examples":[{"en":"The satellite orbits the Earth once every 90 minutes.","zh":"這顆衛星每90分鐘繞地球一圈。"},{"en":"It takes about 365 days for the Earth to orbit the sun.","zh":"地球繞行太陽一圈大約需要三百六十五天。"},{"en":"Engineers successfully put the new satellite into orbit.","zh":"工程師成功地將新衛星送入軌道。"}]},{"word":"orchard","pos":"n.","phonetic":"[ˈɔrtʃɚd]","meaning":"果園","definition":"a piece of land where fruit trees are grown","collocations":["apple orchard","work in an orchard","visit an orchard"],"example":"We picked apples in the orchard last weekend.","exampleZh":"我們上週末在果園裡摘蘋果。","synonyms":[],"level":3,"theme":"自然與環境","examples":[{"en":"We picked apples in the orchard last weekend.","zh":"我們上週末在果園裡摘蘋果。"},{"en":"Every autumn we visit an apple orchard to pick fresh fruit.","zh":"每年秋天我們都會去蘋果園採摘新鮮水果。"},{"en":"The workers spent all morning picking peaches in the orchard.","zh":"工人們整個上午都在果園裡採桃子。"}]},{"word":"orchestra","pos":"n.","phonetic":"[ˈɔrkɪstrə]","meaning":"管弦樂團","definition":"a large group of musicians who play various instruments together","collocations":["join an orchestra","symphony orchestra","conduct an orchestra"],"example":"She plays the violin in the school orchestra.","exampleZh":"她在學校管弦樂團裡拉小提琴。","synonyms":[],"level":3,"theme":"藝術與音樂","examples":[{"en":"She plays the violin in the school orchestra.","zh":"她在學校管弦樂團裡拉小提琴。"},{"en":"She was thrilled to join the city's youth orchestra as a cellist.","zh":"她很興奮能以大提琴手的身分加入這座城市的青年管弦樂團。"},{"en":"The conductor raised his baton, and the orchestra began to play.","zh":"指揮舉起指揮棒，管弦樂團便開始演奏。"}]},{"word":"order","pos":"n. / v.","phonetic":"[ˈɔrdɚ]","meaning":"順序；命令；訂購","definition":"a request for goods, or an instruction to do something","collocations":["place an order","in order","give an order"],"example":"I ordered a pizza for dinner.","exampleZh":"我點了一份披薩當晚餐。","synonyms":["command","sequence"],"level":1,"theme":"商業與金錢","examples":[{"en":"I ordered a pizza for dinner.","zh":"我點了一份披薩當晚餐。"},{"en":"Please arrange these history events in the correct order.","zh":"請把這些歷史事件按正確的順序排列。"},{"en":"We placed an order for two large pizzas and a salad.","zh":"我們點了兩個大披薩和一份沙拉。"}]},{"word":"ordinary","pos":"adj.","phonetic":"[ˈɔrdəˌnɛrɪ]","meaning":"普通的；平凡的","definition":"with no special or distinctive features; normal","collocations":["an ordinary day","ordinary people","out of the ordinary"],"example":"It was just an ordinary day at school.","exampleZh":"那只是學校裡平凡的一天。","synonyms":["common","normal"],"level":3,"theme":"性質與描述","examples":[{"en":"It was just an ordinary day at school.","zh":"那只是學校裡平凡的一天。"},{"en":"She turned an ordinary cardboard box into a lovely toy house.","zh":"她把一個普通的紙箱變成了可愛的玩具屋。"},{"en":"Nothing out of the ordinary happened during the quiet afternoon.","zh":"那個寧靜的下午沒發生什麼不尋常的事。"}]},{"word":"ore","pos":"n.","phonetic":"[or]","meaning":"礦石","definition":"rock or mineral from which metal can be extracted","collocations":["iron ore","mine ore","an ore deposit"],"example":"The mountains are rich in iron ore.","exampleZh":"這些山脈蘊藏豐富的鐵礦石。","synonyms":[],"level":3,"theme":"自然與環境","examples":[{"en":"The mountains are rich in iron ore.","zh":"這些山脈蘊藏豐富的鐵礦石。"},{"en":"Workers dug deep into the mountain to mine iron ore.","zh":"工人深入山中開採鐵礦石。"},{"en":"This region is famous for its rich deposits of copper ore.","zh":"這個地區以豐富的銅礦石礦藏而聞名。"}]},{"word":"organ","pos":"n.","phonetic":"[ˈɔrgən]","meaning":"器官；風琴","definition":"a part of the body that has a particular function, or a musical instrument","collocations":["vital organ","organ donation","play the organ"],"example":"The heart is one of the most vital organs.","exampleZh":"心臟是最重要的器官之一。","synonyms":[],"level":4,"theme":"身體與健康","examples":[{"en":"The heart is one of the most vital organs.","zh":"心臟是最重要的器官之一。"},{"en":"The liver is an important organ that cleans the blood.","zh":"肝臟是清潔血液的重要器官。"},{"en":"She learned to play the organ at the local church.","zh":"她在當地的教堂學會了彈風琴。"}]},{"word":"organic","pos":"adj.","phonetic":"[ɔrˈgænɪk]","meaning":"有機的","definition":"produced without artificial chemicals or fertilizers","collocations":["organic food","organic farming","organic vegetables"],"example":"They only buy organic vegetables at the market.","exampleZh":"他們在市場只買有機蔬菜。","synonyms":[],"level":4,"theme":"食物與烹飪","examples":[{"en":"They only buy organic vegetables at the market.","zh":"他們在市場只買有機蔬菜。"},{"en":"This farm grows organic vegetables without any chemical pesticides.","zh":"這座農場種植不使用任何化學農藥的有機蔬菜。"},{"en":"Organic farming is better for the soil and the environment.","zh":"有機農法對土壤和環境比較好。"}]},{"word":"organism","pos":"n.","phonetic":"[ˈɔrgəˌnɪzəm]","meaning":"生物；有機體","definition":"an individual living thing","collocations":["a living organism","a marine organism"],"example":"Scientists discovered a new organism living deep in the ocean.","exampleZh":"科學家在深海發現了一種新的生物。","synonyms":[],"level":4,"theme":"科學與數學","examples":[{"en":"Scientists discovered a new organism living deep in the ocean.","zh":"科學家在深海發現了一種新的生物。"},{"en":"Even the tiniest organism plays a role in the ecosystem.","zh":"即使是最微小的生物在生態系中也扮演著角色。"},{"en":"Scientists study how living organisms adapt to their surroundings.","zh":"科學家研究生物如何適應牠們的環境。"}]},{"word":"organization","pos":"n.","phonetic":"[ˌɔrgənəˈzeʃən]","meaning":"組織；機構","definition":"a group of people who work together for a purpose","collocations":["charitable organization","join an organization","non-profit organization"],"example":"She works for a non-profit organization.","exampleZh":"她在一個非營利組織工作。","synonyms":["institution"],"level":3,"theme":"社會與文化","examples":[{"en":"She works for a non-profit organization.","zh":"她在一個非營利組織工作。"},{"en":"She volunteers for a charitable organization that helps homeless people.","zh":"她在一個幫助無家可歸者的慈善機構當志工。"},{"en":"The student decided to join an environmental organization at school.","zh":"那名學生決定加入學校裡的一個環保組織。"}]},{"word":"organize","pos":"v.","phonetic":"[ˈɔrgəˌnaɪz]","meaning":"組織；籌辦","definition":"to plan and arrange an event or activity","collocations":["organize an event","organize a meeting","well organized"],"example":"The teacher organized a field trip for the class.","exampleZh":"老師為班上籌辦了一次校外教學。","synonyms":["arrange","plan"],"level":3,"theme":"工作與職業","examples":[{"en":"The teacher organized a field trip for the class.","zh":"老師為班上籌辦了一次校外教學。"},{"en":"The class president organized a charity sale to raise money.","zh":"班長籌辦了一場慈善義賣來募款。"},{"en":"She keeps her desk well organized so she can find things easily.","zh":"她把書桌整理得井井有條，這樣就能輕鬆找到東西。"}]},{"word":"orientation","pos":"n.","phonetic":"[ˌorienˈteʃən]","meaning":"新生訓練；方向","definition":"introductory training; the direction something faces","collocations":["attend orientation","career orientation"],"example":"All new students must attend an orientation session before classes begin.","exampleZh":"所有新生在開課前都必須參加迎新說明會。","synonyms":[],"level":4,"theme":"教育與學習","examples":[{"en":"All new students must attend an orientation session before classes begin.","zh":"所有新生在開課前都必須參加迎新說明會。"},{"en":"New employees must attend a two-day orientation before starting work.","zh":"新進員工在開始工作前必須參加為期兩天的新人訓練。"},{"en":"The building's orientation allows sunlight to enter every morning.","zh":"這棟建築的座向讓陽光每天早上都能照進來。"}]},{"word":"origin","pos":"n.","phonetic":"[ˈɔrədʒɪn]","meaning":"起源；由來","definition":"the point or place where something begins","collocations":["origin of a word","country of origin","trace the origin"],"example":"The origin of this custom is unclear.","exampleZh":"這項習俗的起源並不清楚。","synonyms":["source","root"],"level":4,"theme":"抽象概念","examples":[{"en":"The origin of this custom is unclear.","zh":"這項習俗的起源並不清楚。"},{"en":"Historians are still debating the true origin of this festival.","zh":"歷史學家仍在爭論這個節日的真正起源。"},{"en":"The label shows the country of origin of the coffee beans.","zh":"標籤上顯示了咖啡豆的原產地。"}]},{"word":"original","pos":"adj. / n.","phonetic":"[əˈrɪdʒənḷ]","meaning":"最初的；原創的","definition":"existing from the beginning, or new and creative","collocations":["original idea","original copy","the original plan"],"example":"He came up with a very original idea.","exampleZh":"他想出了一個非常有創意的點子。","synonyms":["initial","creative"],"level":3,"theme":"抽象概念","examples":[{"en":"He came up with a very original idea.","zh":"他想出了一個非常有創意的點子。"},{"en":"The museum displays the original painting, not a copy.","zh":"博物館展出的是原作，而非複製品。"},{"en":"Her original idea impressed all the judges at the science fair.","zh":"她原創的點子讓科展的所有評審都印象深刻。"}]},{"word":"originate","pos":"v.","phonetic":"[əˈrɪdʒəˌnet]","meaning":"起源於","definition":"to begin or come from a particular place or time","collocations":["originate from","originate in","where it originated"],"example":"This tradition originated in ancient China.","exampleZh":"這項傳統起源於古代中國。","synonyms":["derive","stem"],"level":5,"theme":"抽象概念","examples":[{"en":"This tradition originated in ancient China.","zh":"這項傳統起源於古代中國。"},{"en":"Many English words originate from Latin and Greek.","zh":"許多英文單字源自拉丁文和希臘文。"},{"en":"This popular dessert originated in a small French village.","zh":"這道受歡迎的甜點起源於一個法國小村莊。"}]},{"word":"ornament","pos":"n.","phonetic":"[ˈɔrnəmənt]","meaning":"裝飾品","definition":"an object used to make something look more attractive","collocations":["a Christmas ornament","hang ornaments"],"example":"We hung colorful ornaments on the Christmas tree.","exampleZh":"我們在聖誕樹上掛滿了色彩繽紛的裝飾品。","synonyms":[],"level":3,"theme":"居家與生活","examples":[{"en":"We hung colorful ornaments on the Christmas tree.","zh":"我們在聖誕樹上掛滿了色彩繽紛的裝飾品。"},{"en":"She placed a tiny glass ornament on the shelf by the window.","zh":"她把一個小玻璃裝飾品放在窗邊的架子上。"},{"en":"The children made paper ornaments to decorate the classroom.","zh":"孩子們做了紙裝飾品來布置教室。"}]},{"word":"orphan","pos":"n. / v.","phonetic":"[ˈɔrfən]","meaning":"孤兒","definition":"a child whose parents are dead","collocations":["an orphan child","become an orphan","orphan shelter"],"example":"The war left many children orphans.","exampleZh":"戰爭使許多孩子成了孤兒。","synonyms":[],"level":4,"theme":"人物與家庭","examples":[{"en":"The war left many children orphans.","zh":"戰爭使許多孩子成了孤兒。"},{"en":"The kind couple decided to adopt an orphan from the shelter.","zh":"這對善良的夫妻決定從收容所領養一名孤兒。"},{"en":"The flood orphaned dozens of children in the small village.","zh":"這場洪水使小村莊裡數十名孩童成了孤兒。"}]},{"word":"orphanage","pos":"n.","phonetic":"[ˈɔrfənɪdʒ]","meaning":"孤兒院","definition":"an institution for the care of children without parents","collocations":["grow up in an orphanage","run an orphanage"],"example":"He spent his childhood in an orphanage before being adopted.","exampleZh":"他被領養前的童年是在孤兒院度過的。","synonyms":[],"level":4,"theme":"社會與文化","examples":[{"en":"He spent his childhood in an orphanage before being adopted.","zh":"他被領養前的童年是在孤兒院度過的。"},{"en":"Volunteers visit the orphanage every weekend to teach the children.","zh":"志工每個週末都會去孤兒院教孩子們。"},{"en":"The couple donated books and toys to the local orphanage.","zh":"這對夫妻捐了書籍和玩具給當地的孤兒院。"}]},{"word":"other","pos":"adj. / pron.","phonetic":"[ˈʌðɚ]","meaning":"其他的","definition":"used to refer to a person or thing different from one already mentioned","collocations":["each other","the other day","on the other hand"],"example":"I met an old friend the other day.","exampleZh":"前幾天我遇到一位老朋友。","synonyms":[],"level":1,"theme":"抽象概念","examples":[{"en":"I met an old friend the other day.","zh":"前幾天我遇到一位老朋友。"},{"en":"On the other hand, staying home can also be relaxing and fun.","zh":"另一方面，待在家也可以既放鬆又有趣。"},{"en":"Some students like math, while others prefer history.","zh":"有些學生喜歡數學，其他人則偏好歷史。"}]},{"word":"otherwise","pos":"adv. / conj.","phonetic":"[ˈʌðɚˌwaɪz]","meaning":"否則；另外","definition":"under other circumstances; or else","collocations":["or otherwise","otherwise known as","unless otherwise stated"],"example":"Hurry up, otherwise we'll miss the bus.","exampleZh":"快點，否則我們會錯過公車。","synonyms":["or else"],"level":3,"theme":"抽象概念","examples":[{"en":"Hurry up, otherwise we'll miss the bus.","zh":"快點，否則我們會錯過公車。"},{"en":"Write down the address, otherwise you might forget it later.","zh":"把地址寫下來，否則你之後可能會忘記。"},{"en":"The soup was a little salty, but otherwise the meal was perfect.","zh":"湯有點鹹，但除此之外這頓飯很完美。"}]},{"word":"ounce","pos":"n.","phonetic":"[aʊns]","meaning":"盎司","definition":"a unit of weight equal to about 28 grams","collocations":["an ounce of","a few ounces","weigh in ounces"],"example":"The recipe calls for eight ounces of flour.","exampleZh":"這份食譜需要八盎司的麵粉。","synonyms":[],"level":4,"theme":"科學與數學","examples":[{"en":"The recipe calls for eight ounces of flour.","zh":"這份食譜需要八盎司的麵粉。"},{"en":"Add two ounces of butter to make the sauce richer.","zh":"加入兩盎司的奶油讓醬汁更濃郁。"},{"en":"The tiny bird weighs only a few ounces.","zh":"這隻小鳥只有幾盎司重。"}]},{"word":"out","pos":"adv. / prep.","phonetic":"[aʊt]","meaning":"在外；出局","definition":"away from the inside of a place; not at home","collocations":["go out","out of order","run out"],"example":"We went out for dinner last night.","exampleZh":"我們昨晚出去吃晚餐。","synonyms":[],"level":1,"theme":"時間與空間","examples":[{"en":"We went out for dinner last night.","zh":"我們昨晚出去吃晚餐。"},{"en":"We ran out of milk, so I went to buy some more.","zh":"我們的牛奶用完了，所以我去多買了一些。"},{"en":"The batter was out after his third strike in the game.","zh":"那位打者在比賽中第三次揮棒落空後就出局了。"}]},{"word":"outbreak","pos":"n.","phonetic":"[ˈaʊtˌbrek]","meaning":"（疾病、戰爭等）爆發","definition":"a sudden occurrence of something unwelcome, such as disease","collocations":["a disease outbreak","an outbreak of violence"],"example":"The hospital reported a sudden outbreak of the flu.","exampleZh":"醫院通報流感突然爆發。","synonyms":[],"level":4,"theme":"身體與健康","examples":[{"en":"The hospital reported a sudden outbreak of the flu.","zh":"醫院通報流感突然爆發。"},{"en":"The sudden outbreak of flu forced the school to close for a week.","zh":"流感的突然爆發迫使學校停課一週。"},{"en":"Health workers rushed to control the outbreak of the disease.","zh":"衛生人員趕忙去控制這場疾病的爆發。"}]},{"word":"outburst","pos":"n.","phonetic":"[ˈaʊtˌbɝst]","meaning":"（情緒）爆發","definition":"a sudden release of strong emotion","collocations":["an angry outburst","an emotional outburst"],"example":"He apologized for his outburst during the meeting.","exampleZh":"他為自己在會議中的情緒失控道歉。","synonyms":[],"level":4,"theme":"情緒與感受","examples":[{"en":"He apologized for his outburst during the meeting.","zh":"他為自己在會議中的情緒失控道歉。"},{"en":"His angry outburst surprised everyone in the quiet classroom.","zh":"他的憤怒爆發讓安靜教室裡的每個人都嚇了一跳。"},{"en":"She regretted her emotional outburst and later apologized to her friend.","zh":"她後悔自己情緒失控，之後向朋友道了歉。"}]},{"word":"outcome","pos":"n.","phonetic":"[ˈaʊtˌkʌm]","meaning":"結果","definition":"the way a thing turns out; a result","collocations":["the final outcome","positive outcome","depend on the outcome"],"example":"We are waiting to hear the outcome of the election.","exampleZh":"我們正在等待選舉結果。","synonyms":["result","consequence"],"level":4,"theme":"抽象概念","examples":[{"en":"We are waiting to hear the outcome of the election.","zh":"我們正在等待選舉結果。"},{"en":"Everyone waited nervously to hear the outcome of the final match.","zh":"大家都緊張地等著聽決賽的結果。"},{"en":"The outcome of the experiment surprised even the researchers.","zh":"這項實驗的結果連研究人員都感到意外。"}]},{"word":"outdated","pos":"adj.","phonetic":"[ˌaʊtˈdetɪd]","meaning":"過時的","definition":"no longer useful, fashionable, or up-to-date","collocations":["outdated technology","outdated information"],"example":"The company replaced its outdated computer systems.","exampleZh":"公司汰換了過時的電腦系統。","synonyms":["obsolete","old-fashioned"],"level":4,"theme":"科技與媒體","examples":[{"en":"The company replaced its outdated computer systems.","zh":"公司汰換了過時的電腦系統。"},{"en":"The textbook contains outdated information about modern technology.","zh":"這本教科書含有關於現代科技的過時資訊。"},{"en":"He finally replaced his outdated phone with a newer model.","zh":"他終於用較新的機型換掉了他過時的手機。"}]},{"word":"outdoor","pos":"adj.","phonetic":"[ˈaʊtˌdɔr]","meaning":"戶外的","definition":"done or used outside rather than in a building","collocations":["outdoor activities","outdoor sports","outdoor pool"],"example":"Hiking is a popular outdoor activity in Taiwan.","exampleZh":"健行是台灣熱門的戶外活動。","synonyms":[],"level":2,"theme":"運動與休閒","examples":[{"en":"Hiking is a popular outdoor activity in Taiwan.","zh":"健行是台灣熱門的戶外活動。"},{"en":"Camping is a fun outdoor activity that the whole family enjoys.","zh":"露營是全家人都喜愛的有趣戶外活動。"},{"en":"The school built a new outdoor pool for summer swimming lessons.","zh":"學校蓋了一座新的戶外泳池供夏季游泳課使用。"}]},{"word":"outdoors","pos":"adv.","phonetic":"[ˌaʊtˈdɔrz]","meaning":"在戶外","definition":"in or into the open air, not inside a building","collocations":["play outdoors","spend time outdoors","eat outdoors"],"example":"Children should spend more time outdoors.","exampleZh":"孩子們應該多花時間在戶外活動。","synonyms":[],"level":2,"theme":"運動與休閒","examples":[{"en":"Children should spend more time outdoors.","zh":"孩子們應該多花時間在戶外活動。"},{"en":"The doctor said children should play outdoors more often.","zh":"醫生說孩子們應該更常在戶外玩耍。"},{"en":"On sunny days, we enjoy eating our lunch outdoors.","zh":"在晴朗的日子，我們喜歡在戶外吃午餐。"}]},{"word":"outer","pos":"adj.","phonetic":"[ˈaʊtɚ]","meaning":"外部的","definition":"on or near the outside; farther from the center","collocations":["outer space","outer layer","outer edge"],"example":"Astronauts explore outer space.","exampleZh":"太空人探索外太空。","synonyms":["exterior"],"level":3,"theme":"時間與空間","examples":[{"en":"Astronauts explore outer space.","zh":"太空人探索外太空。"},{"en":"Astronauts have long dreamed of exploring outer space.","zh":"太空人長久以來都夢想著探索外太空。"},{"en":"Peel off the outer layer of the onion before cooking it.","zh":"烹煮前先剝掉洋蔥的外層。"}]},{"word":"outfit","pos":"n.","phonetic":"[ˈaʊtˌfɪt]","meaning":"一套服裝","definition":"a set of clothes worn together","collocations":["a matching outfit","wear a new outfit"],"example":"She bought a new outfit for the job interview.","exampleZh":"她為了面試買了一套新服裝。","synonyms":["attire"],"level":3,"theme":"服裝與外表","examples":[{"en":"She bought a new outfit for the job interview.","zh":"她為了面試買了一套新服裝。"},{"en":"She chose a smart outfit for her first day at school.","zh":"她為開學第一天挑選了一套俐落的服裝。"},{"en":"He wore a matching outfit to the costume party.","zh":"他穿了一套搭配好的服裝去參加變裝派對。"}]},{"word":"outgoing","pos":"adj.","phonetic":"[ˈaʊtˌgoɪŋ]","meaning":"外向的；即將離任的","definition":"friendly and sociable; leaving a position soon","collocations":["an outgoing personality","the outgoing president"],"example":"My sister has an outgoing personality and makes friends easily.","exampleZh":"我妹妹個性外向,很容易交到朋友。","synonyms":["sociable","friendly"],"level":3,"theme":"性質與描述","examples":[{"en":"My sister has an outgoing personality and makes friends easily.","zh":"我妹妹個性外向,很容易交到朋友。"},{"en":"Her outgoing personality helps her make friends wherever she goes.","zh":"她外向的個性讓她無論走到哪都能交到朋友。"},{"en":"The outgoing class president gave a warm farewell speech.","zh":"即將卸任的班長發表了一段溫馨的告別演說。"}]},{"word":"outlet","pos":"n.","phonetic":"[ˈaʊtˌlɛt]","meaning":"插座；暢貨中心；宣洩管道","definition":"an electrical socket; a store; a way to express emotion","collocations":["an electrical outlet","a retail outlet","an outlet for stress"],"example":"Running is a great outlet for stress.","exampleZh":"跑步是紓解壓力的絕佳管道。","synonyms":[],"level":4,"theme":"商業與金錢","examples":[{"en":"Running is a great outlet for stress.","zh":"跑步是紓解壓力的絕佳管道。"},{"en":"Please plug the charger into the electrical outlet by the desk.","zh":"請把充電器插到書桌旁的插座上。"},{"en":"Painting became a healthy outlet for her stress after exams.","zh":"繪畫成了她考試後宣洩壓力的健康管道。"}]},{"word":"outline","pos":"n. / v.","phonetic":"[ˈaʊtˌlaɪn]","meaning":"大綱；輪廓","definition":"a general description or summary; a rough plan","collocations":["write an outline","outline a plan","rough outline"],"example":"Please write an outline before you start the essay.","exampleZh":"開始寫作文前請先寫大綱。","synonyms":["summary","sketch"],"level":4,"theme":"教育與學習","examples":[{"en":"Please write an outline before you start the essay.","zh":"開始寫作文前請先寫大綱。"},{"en":"Writing a clear outline first makes the essay much easier.","zh":"先寫好清楚的大綱會讓寫作文容易許多。"},{"en":"We could see the dark outline of the mountains at dusk.","zh":"黃昏時我們能看見群山黑色的輪廓。"}]},{"word":"outlook","pos":"n.","phonetic":"[ˈaʊtˌlʊk]","meaning":"展望；觀點","definition":"a general view of a situation, especially the future","collocations":["economic outlook","positive outlook","future outlook"],"example":"The economic outlook for next year looks promising.","exampleZh":"明年的經濟展望看起來很樂觀。","synonyms":["perspective","prospect"],"level":5,"theme":"抽象概念","examples":[{"en":"The economic outlook for next year looks promising.","zh":"明年的經濟展望看起來很樂觀。"},{"en":"The weather outlook for the weekend is bright and sunny.","zh":"週末的天氣展望是晴朗有陽光的。"},{"en":"A positive outlook can help you deal with difficult times.","zh":"正面的觀點能幫助你面對艱難的時刻。"}]},{"word":"output","pos":"n.","phonetic":"[ˈaʊtˌpʊt]","meaning":"產量；輸出","definition":"the amount of something produced by a person, machine, or system","collocations":["increase output","factory output","energy output"],"example":"The factory increased its output by 20 percent.","exampleZh":"這家工廠將產量提高了百分之二十。","synonyms":["production"],"level":4,"theme":"商業與金錢","examples":[{"en":"The factory increased its output by 20 percent.","zh":"這家工廠將產量提高了百分之二十。"},{"en":"The factory doubled its output after installing new machines.","zh":"工廠在安裝新機器後產量增加了一倍。"},{"en":"Solar panels increase their energy output on sunny days.","zh":"太陽能板在晴天時能提高其能量輸出。"}]},{"word":"outside","pos":"n. / adj. / prep.","phonetic":"[ˌaʊtˈsaɪd]","meaning":"外面","definition":"the external side or surface of something; not inside","collocations":["go outside","outside the box","the outside world"],"example":"It's raining outside.","exampleZh":"外面正在下雨。","synonyms":["exterior"],"level":1,"theme":"時間與空間","examples":[{"en":"It's raining outside.","zh":"外面正在下雨。"},{"en":"The children played happily outside until it got dark.","zh":"孩子們在外面開心地玩到天黑。"},{"en":"We should try to think outside the box to solve this problem.","zh":"我們應該試著跳脫框架思考來解決這個問題。"}]},{"word":"outstanding","pos":"adj.","phonetic":"[ˌaʊtˈstændɪŋ]","meaning":"傑出的；顯著的","definition":"exceptionally good or distinguished","collocations":["outstanding performance","outstanding student","outstanding achievement"],"example":"She received an award for her outstanding performance.","exampleZh":"她因傑出的表現獲得獎項。","synonyms":["excellent","remarkable"],"level":4,"theme":"性質與描述","examples":[{"en":"She received an award for her outstanding performance.","zh":"她因傑出的表現獲得獎項。"},{"en":"The young pianist gave an outstanding performance at the concert.","zh":"那位年輕的鋼琴家在音樂會上有傑出的表現。"},{"en":"He received a scholarship for his outstanding academic achievement.","zh":"他因傑出的學業成就而獲得獎學金。"}]},{"word":"oval","pos":"adj. / n.","phonetic":"[ˈovḷ]","meaning":"橢圓形的","definition":"having a rounded shape like an egg","collocations":["oval shape","oval table","oval face"],"example":"The table in the meeting room is oval.","exampleZh":"會議室裡的桌子是橢圓形的。","synonyms":[],"level":3,"theme":"性質與描述","examples":[{"en":"The table in the meeting room is oval.","zh":"會議室裡的桌子是橢圓形的。"},{"en":"The running track has an oval shape around the field.","zh":"那條跑道呈橢圓形環繞著操場。"},{"en":"She drew an oval face and added two big eyes.","zh":"她畫了一張橢圓形的臉，並加上兩隻大眼睛。"}]},{"word":"oven","pos":"n.","phonetic":"[ˈʌvən]","meaning":"烤箱","definition":"an enclosed compartment used for baking or roasting food","collocations":["preheat the oven","put in the oven","microwave oven"],"example":"Preheat the oven to 200 degrees before baking.","exampleZh":"烘烤前請先將烤箱預熱到200度。","synonyms":[],"level":1,"theme":"食物與烹飪","examples":[{"en":"Preheat the oven to 200 degrees before baking.","zh":"烘烤前請先將烤箱預熱到200度。"},{"en":"Preheat the oven before you put the cake batter inside.","zh":"在把蛋糕麵糊放進去之前先預熱烤箱。"},{"en":"She pulled a tray of fresh bread out of the oven.","zh":"她從烤箱裡拿出一盤新鮮的麵包。"}]},{"word":"over","pos":"prep. / adv.","phonetic":"[ˈovɚ]","meaning":"在...之上；結束","definition":"above or across; finished","collocations":["get over","all over","over there"],"example":"The movie is over now.","exampleZh":"電影現在結束了。","synonyms":[],"level":1,"theme":"時間與空間","examples":[{"en":"The movie is over now.","zh":"電影現在結束了。"},{"en":"It took her a long time to get over her cold.","zh":"她花了很長時間才從感冒中康復。"},{"en":"A colorful rainbow appeared over the mountains after the rain.","zh":"雨後，一道彩色的彩虹出現在群山之上。"}]},{"word":"overall","pos":"adj. / adv.","phonetic":"[ˌovɚˈɔl]","meaning":"整體的","definition":"taking everything into account; in general","collocations":["overall performance","overall quality","overall winner"],"example":"The team's overall performance improved this season.","exampleZh":"這支隊伍本季的整體表現進步了。","synonyms":["general","total"],"level":4,"theme":"抽象概念","examples":[{"en":"The team's overall performance improved this season.","zh":"這支隊伍本季的整體表現進步了。"},{"en":"The team's overall performance improved greatly this season.","zh":"這支隊伍本季的整體表現大幅進步。"},{"en":"Overall, the school trip was a wonderful experience for everyone.","zh":"整體而言，這次校外旅行對每個人都是美好的體驗。"}]},{"word":"overcast","pos":"adj.","phonetic":"[ˌovɚˈkæst]","meaning":"陰天的","definition":"covered with clouds","collocations":["an overcast sky","overcast weather"],"example":"The sky was overcast all day, so we canceled the picnic.","exampleZh":"天空整天都是陰天,所以我們取消了野餐。","synonyms":[],"level":4,"theme":"天氣與季節","examples":[{"en":"The sky was overcast all day, so we canceled the picnic.","zh":"天空整天都是陰天,所以我們取消了野餐。"},{"en":"The sky was overcast, so we decided to stay indoors.","zh":"天空陰陰的，所以我們決定待在室內。"},{"en":"Overcast weather can make some people feel a little sleepy.","zh":"陰天的天氣會讓有些人覺得有點想睡。"}]},{"word":"overcome","pos":"v.","phonetic":"[ˌovɚˈkʌm]","meaning":"克服","definition":"to succeed in dealing with a problem or difficulty","collocations":["overcome difficulties","overcome fear","overcome an obstacle"],"example":"She managed to overcome her fear of heights.","exampleZh":"她成功克服了懼高症。","synonyms":["conquer","defeat"],"level":4,"theme":"動作與行為","examples":[{"en":"She managed to overcome her fear of heights.","zh":"她成功克服了懼高症。"},{"en":"With practice, he overcame his fear of speaking in public.","zh":"透過練習，他克服了在公眾面前說話的恐懼。"},{"en":"The team worked together to overcome many difficulties.","zh":"這個團隊齊心協力克服了許多困難。"}]},{"word":"overflow","pos":"v. / n.","phonetic":"[ˌovɚˈflo]","meaning":"溢出；氾濫","definition":"to flow over the edges of something because it is too full","collocations":["overflow with","the river overflows","overflow the banks"],"example":"The river overflowed its banks after the heavy rain.","exampleZh":"大雨過後河水溢出了堤岸。","synonyms":["flood","spill"],"level":5,"theme":"自然與環境","examples":[{"en":"The river overflowed its banks after the heavy rain.","zh":"大雨過後河水溢出了堤岸。"},{"en":"She forgot the tap, and the bathtub began to overflow.","zh":"她忘了水龍頭，浴缸開始滿溢出來。"},{"en":"The stadium was overflowing with excited football fans.","zh":"體育場擠滿了興奮的足球迷。"}]},{"word":"overhead","pos":"adj. / adv.","phonetic":"[ˈovɚˌhɛd]","meaning":"頭頂上方的","definition":"above the level of the head; in the sky","collocations":["overhead light","overhead compartment","fly overhead"],"example":"Please put your bag in the overhead compartment.","exampleZh":"請把您的包包放進頭頂上方的置物櫃。","synonyms":[],"level":5,"theme":"時間與空間","examples":[{"en":"Please put your bag in the overhead compartment.","zh":"請把您的包包放進頭頂上方的置物櫃。"},{"en":"Please place your suitcase in the overhead compartment.","zh":"請將您的行李箱放進頭頂上方的置物櫃。"},{"en":"A flock of geese flew overhead as we crossed the field.","zh":"我們穿過田野時，一群大雁從頭頂上方飛過。"}]},{"word":"overjoyed","pos":"adj.","phonetic":"[ˌovɚˈdʒɔɪd]","meaning":"欣喜若狂的","definition":"extremely happy","collocations":["overjoyed at the news","feel overjoyed"],"example":"She was overjoyed to see her family again after so long.","exampleZh":"她因為終於再見到家人而欣喜若狂。","synonyms":["delighted","thrilled"],"level":3,"theme":"情緒與感受","examples":[{"en":"She was overjoyed to see her family again after so long.","zh":"她因為終於再見到家人而欣喜若狂。"},{"en":"She was overjoyed at the news that she had won the contest.","zh":"得知自己贏得比賽的消息，她欣喜若狂。"},{"en":"The children were overjoyed when it started to snow outside.","zh":"外面開始下雪時，孩子們欣喜若狂。"}]},{"word":"overlook","pos":"v.","phonetic":"[ˌovɚˈlʊk]","meaning":"忽視；俯瞰","definition":"to fail to notice something, or to have a view over a place from above","collocations":["overlook a mistake","overlook the sea","easily overlooked"],"example":"The hotel room overlooks the ocean.","exampleZh":"這間飯店房間俯瞰著海洋。","synonyms":["ignore","neglect"],"level":4,"theme":"動作與行為","examples":[{"en":"The hotel room overlooks the ocean.","zh":"這間飯店房間俯瞰著海洋。"},{"en":"Don't overlook small errors when you check your homework.","zh":"檢查作業時別忽略小錯誤。"},{"en":"Their new apartment overlooks a beautiful green park.","zh":"他們的新公寓俯瞰一座美麗的綠色公園。"}]},{"word":"overnight","pos":"adj. / adv.","phonetic":"[ˌovɚˈnaɪt]","meaning":"一夜之間；過夜的","definition":"happening during the night, or very suddenly","collocations":["overnight stay","become famous overnight","overnight trip"],"example":"The singer became famous overnight.","exampleZh":"這位歌手一夜之間成名了。","synonyms":[],"level":4,"theme":"時間與空間","examples":[{"en":"The singer became famous overnight.","zh":"這位歌手一夜之間成名了。"},{"en":"We booked an overnight stay at a small mountain hotel.","zh":"我們預訂在一間小型山間旅館過夜。"},{"en":"You can't master a language overnight; it takes patience.","zh":"你無法一夜之間精通一門語言，這需要耐心。"}]},{"word":"overpass","pos":"n.","phonetic":"[ˈovɚˌpæs]","meaning":"天橋；高架道路","definition":"a bridge that carries one road or path over another","collocations":["cross the overpass","build an overpass"],"example":"We drove under the overpass to avoid the traffic jam.","exampleZh":"我們開車經過天橋下方以避開塞車。","synonyms":[],"level":3,"theme":"交通與旅行","examples":[{"en":"We drove under the overpass to avoid the traffic jam.","zh":"我們開車經過天橋下方以避開塞車。"},{"en":"We crossed the overpass to reach the other side of the highway.","zh":"我們走過天橋到達高速公路的另一側。"},{"en":"The city plans to build a new overpass to ease the traffic.","zh":"市府計畫興建一座新的高架橋以紓解交通。"}]},{"word":"overseas","pos":"adj. / adv.","phonetic":"[ˌovɚˈsiz]","meaning":"海外的；到國外","definition":"in, to, or from a foreign country across the sea","collocations":["study overseas","overseas market","travel overseas"],"example":"Many students dream of studying overseas.","exampleZh":"許多學生夢想著到海外留學。","synonyms":["abroad"],"level":3,"theme":"交通與旅行","examples":[{"en":"Many students dream of studying overseas.","zh":"許多學生夢想著到海外留學。"},{"en":"After graduation, she hopes to study overseas for a year.","zh":"畢業後，她希望能到國外留學一年。"},{"en":"The company is trying to expand into the overseas market.","zh":"這家公司正試圖拓展海外市場。"}]},{"word":"oversee","pos":"v.","phonetic":"[ˌovɚˈsi]","meaning":"監督","definition":"to supervise a task, project, or person","collocations":["oversee a project","oversee construction","oversee staff"],"example":"He was hired to oversee the construction project.","exampleZh":"他被聘來監督這項建築工程。","synonyms":["supervise","monitor"],"level":5,"theme":"工作與職業","examples":[{"en":"He was hired to oversee the construction project.","zh":"他被聘來監督這項建築工程。"},{"en":"A senior teacher was asked to oversee the entire exam.","zh":"一位資深老師受託監督整場考試。"},{"en":"She will oversee the whole project until it is completed.","zh":"她將監督整個專案直到完成。"}]},{"word":"overtake","pos":"v.","phonetic":"[ˌovɚˈtek]","meaning":"超越；追過","definition":"to catch up with and pass someone or something moving in the same direction","collocations":["overtake a car","overtake a rival","overtake in sales"],"example":"The car overtook the truck on the highway.","exampleZh":"那輛汽車在高速公路上超越了卡車。","synonyms":["pass","surpass"],"level":5,"theme":"交通與旅行","examples":[{"en":"The car overtook the truck on the highway.","zh":"那輛汽車在高速公路上超越了卡車。"},{"en":"The young runner managed to overtake two rivals in the final lap.","zh":"那名年輕跑者在最後一圈成功超越了兩名對手。"},{"en":"Online stores are starting to overtake malls in total sales.","zh":"網路商店的總銷售額開始超越購物中心。"}]},{"word":"overthrow","pos":"v. / n.","phonetic":"[ˌovɚˈθro]","meaning":"推翻","definition":"to remove a government or leader from power by force","collocations":["overthrow the government","overthrow a regime","attempt to overthrow"],"example":"The rebels tried to overthrow the government.","exampleZh":"叛軍試圖推翻政府。","synonyms":["topple","overturn"],"level":6,"theme":"政治與法律","examples":[{"en":"The rebels tried to overthrow the government.","zh":"叛軍試圖推翻政府。"},{"en":"The angry citizens hoped to overthrow the cruel king peacefully.","zh":"憤怒的人民希望能和平地推翻那位殘暴的國王。"},{"en":"History books describe how the old regime was finally overthrown.","zh":"歷史書描述了舊政權最終是如何被推翻的。"}]},{"word":"overtime","pos":"n.","phonetic":"[ˈovɚˌtaɪm]","meaning":"加班；加班費","definition":"time worked in addition to regular hours","collocations":["work overtime","paid overtime"],"example":"He often works overtime to finish the project on schedule.","exampleZh":"他經常加班以便按時完成專案。","synonyms":[],"level":3,"theme":"工作與職業","examples":[{"en":"He often works overtime to finish the project on schedule.","zh":"他經常加班以便按時完成專案。"},{"en":"Many workers earn extra pay when they agree to work overtime.","zh":"許多員工同意加班時能賺取額外的加班費。"},{"en":"She was too tired to study after so much overtime this week.","zh":"這週加了這麼多班後，她累得無法讀書。"}]},{"word":"overwhelm","pos":"v.","phonetic":"[ˌovɚˈhwɛlm]","meaning":"使不知所措；壓倒","definition":"to have such a strong emotional effect on someone that they cannot cope","collocations":["feel overwhelmed","overwhelm with joy","overwhelmed by work"],"example":"She felt overwhelmed by all the homework.","exampleZh":"她被大量的作業壓得喘不過氣。","synonyms":["overpower","swamp"],"level":5,"theme":"情緒與感受","examples":[{"en":"She felt overwhelmed by all the homework.","zh":"她被大量的作業壓得喘不過氣。"},{"en":"The huge amount of new information began to overwhelm the students.","zh":"大量的新資訊開始讓學生們不知所措。"},{"en":"He was overwhelmed with joy when he won the scholarship.","zh":"當他贏得獎學金時，他欣喜若狂。"}]},{"word":"owe","pos":"v.","phonetic":"[o]","meaning":"欠（錢或情）；應給予","definition":"to be under an obligation to pay or repay something","collocations":["owe money","owe an apology","owe a debt"],"example":"I owe him fifty dollars for the concert tickets.","exampleZh":"我欠他五十美元的演唱會門票錢。","synonyms":[],"level":2,"theme":"商業與金錢","examples":[{"en":"I owe him fifty dollars for the concert tickets.","zh":"我欠他五十美元的演唱會門票錢。"},{"en":"I still owe my sister twenty dollars for the movie ticket.","zh":"我還欠我姐姐二十美元的電影票錢。"},{"en":"You owe your teacher an apology for being so rude.","zh":"你這麼無禮，應該向老師道歉。"}]},{"word":"owl","pos":"n.","phonetic":"[aʊl]","meaning":"貓頭鷹","definition":"a nocturnal bird of prey with large eyes","collocations":["a wise old owl","hoot like an owl"],"example":"The owl hooted softly in the dark forest.","exampleZh":"貓頭鷹在黑暗的森林裡輕輕地叫著。","synonyms":[],"level":2,"theme":"動物與植物","examples":[{"en":"The owl hooted softly in the dark forest.","zh":"貓頭鷹在黑暗的森林裡輕輕地叫著。"},{"en":"A wise old owl watched us silently from the tall tree.","zh":"一隻聰明的老貓頭鷹從高樹上靜靜地注視著我們。"},{"en":"At night we could hear an owl hooting near the cabin.","zh":"夜裡我們能聽見一隻貓頭鷹在小屋附近鳴叫。"}]},{"word":"ownership","pos":"n.","phonetic":"[ˈonɚˌʃɪp]","meaning":"所有權","definition":"the state or fact of owning something","collocations":["take ownership","joint ownership"],"example":"The company transferred ownership of the building to a new investor.","exampleZh":"公司把這棟大樓的所有權轉讓給一位新投資者。","synonyms":[],"level":4,"theme":"商業與金錢","examples":[{"en":"The company transferred ownership of the building to a new investor.","zh":"公司把這棟大樓的所有權轉讓給一位新投資者。"},{"en":"The two brothers share joint ownership of the small farm.","zh":"這兩兄弟共同擁有這座小農場的所有權。"},{"en":"Good leaders take ownership of their mistakes instead of blaming others.","zh":"好的領導者會為自己的錯誤負責，而不是責怪他人。"}]},{"word":"oyster","pos":"n.","phonetic":"[ˈɔɪstɚ]","meaning":"牡蠣；蚵仔","definition":"a shellfish with a hard shell, some of which produce pearls","collocations":["fresh oysters","oyster shell","raw oysters"],"example":"We ordered a dozen fresh oysters at the seafood restaurant.","exampleZh":"我們在海鮮餐廳點了一打新鮮牡蠣。","synonyms":[],"level":3,"theme":"食物與烹飪","examples":[{"en":"We ordered a dozen fresh oysters at the seafood restaurant.","zh":"我們在海鮮餐廳點了一打新鮮牡蠣。"},{"en":"The chef served us fresh oysters on a bed of ice.","zh":"廚師把新鮮的牡蠣放在冰塊上端給我們。"},{"en":"Some oysters can produce a precious pearl inside their shell.","zh":"有些牡蠣能在殼內產出珍貴的珍珠。"}]},{"word":"ozone","pos":"n.","phonetic":"[ˈozon]","meaning":"臭氧","definition":"a form of oxygen that forms a protective layer in the atmosphere","collocations":["the ozone layer","ozone depletion"],"example":"Scientists are studying how pollution damages the ozone layer.","exampleZh":"科學家正在研究污染如何破壞臭氧層。","synonyms":[],"level":4,"theme":"自然與環境","examples":[{"en":"Scientists are studying how pollution damages the ozone layer.","zh":"科學家正在研究污染如何破壞臭氧層。"},{"en":"The ozone layer protects living things from harmful sunlight.","zh":"臭氧層保護生物免受有害陽光的傷害。"},{"en":"Scientists warn that certain gases cause serious ozone depletion.","zh":"科學家警告某些氣體會造成嚴重的臭氧層破壞。"}]},{"word":"pace","pos":"n. / v.","phonetic":"[pes]","meaning":"步調；速度；踱步","definition":"the speed at which someone or something moves or does something","collocations":["at a slow pace","keep pace with","pace up and down"],"example":"The teacher set a fast pace for the lesson.","exampleZh":"老師把這堂課的步調設得很快。","synonyms":["speed","tempo"],"level":3,"theme":"動作與行為","examples":[{"en":"The teacher set a fast pace for the lesson.","zh":"老師把這堂課的步調設得很快。"},{"en":"We walked at a slow pace to enjoy the mountain scenery.","zh":"我們以緩慢的步調行走，好好欣賞山間景色。"},{"en":"The nervous father paced up and down outside the classroom.","zh":"緊張的父親在教室外來回踱步。"}]},{"word":"pack","pos":"v. / n.","phonetic":"[pæk]","meaning":"打包；裝箱；一群","definition":"to put things into a bag, box, or container","collocations":["pack a suitcase","pack up","a pack of wolves"],"example":"She packed her suitcase the night before the trip.","exampleZh":"她在出發前一晚打包好行李。","synonyms":["load","bundle"],"level":1,"theme":"居家與生活","examples":[{"en":"She packed her suitcase the night before the trip.","zh":"她在出發前一晚打包好行李。"},{"en":"Remember to pack a raincoat before the weekend hiking trip.","zh":"別忘了在週末健行前打包一件雨衣。"},{"en":"A pack of wolves howled somewhere deep in the forest.","zh":"一群狼在森林深處某處嚎叫著。"}]},{"word":"package","pos":"n. / v.","phonetic":"[ˈpækɪdʒ]","meaning":"包裹；套裝；包裝","definition":"a thing or things wrapped up or packed in a box","collocations":["deliver a package","package deal","package tour"],"example":"The mailman delivered a package to my house.","exampleZh":"郵差把包裹送到我家。","synonyms":["parcel","bundle"],"level":2,"theme":"居家與生活","examples":[{"en":"The mailman delivered a package to my house.","zh":"郵差把包裹送到我家。"},{"en":"The delivery worker left a heavy package outside our front door.","zh":"送貨員把一個沉重的包裹放在我們的前門外。"},{"en":"They booked a package tour that included hotels and meals.","zh":"他們預訂了一個包含飯店和餐點的套裝行程。"}]},{"word":"paddle","pos":"n. / v.","phonetic":"[ˈpædl]","meaning":"槳；用槳划","definition":"a short pole with a wide blade used to move a small boat through water","collocations":["paddle a canoe","a paddle boat","paddle across the lake"],"example":"They paddled the canoe across the quiet lake.","exampleZh":"他們划著獨木舟穿越安靜的湖面。","synonyms":["row"],"level":3,"theme":"運動與休閒","examples":[{"en":"They paddled the canoe across the quiet lake.","zh":"他們划著獨木舟穿越安靜的湖面。"},{"en":"The children learned to paddle a canoe across the calm lake.","zh":"孩子們學會用槳划獨木舟橫渡平靜的湖面。"},{"en":"He gripped the wooden paddle tightly and pushed against the current.","zh":"他緊握著木槳，用力抵抗水流。"}]},{"word":"page","pos":"n.","phonetic":"[pedʒ]","meaning":"頁；頁面","definition":"one side of a sheet of paper in a book","collocations":["turn the page","front page","web page"],"example":"Please turn to page ten of the textbook.","exampleZh":"請翻到課本第十頁。","synonyms":["sheet"],"level":1,"theme":"教育與學習","examples":[{"en":"Please turn to page ten of the textbook.","zh":"請翻到課本第十頁。"},{"en":"Please turn the page and read the next chapter aloud.","zh":"請翻頁並大聲朗讀下一章。"},{"en":"The exciting news appeared on the front page of the newspaper.","zh":"這則令人興奮的消息登上了報紙的頭版。"}]},{"word":"pain","pos":"n.","phonetic":"[pen]","meaning":"疼痛；痛苦","definition":"the physical suffering caused by illness or injury","collocations":["feel pain","chest pain","ease the pain"],"example":"He felt a sharp pain in his back.","exampleZh":"他感到背部一陣劇痛。","synonyms":["ache","suffering"],"level":2,"theme":"身體與健康","examples":[{"en":"He felt a sharp pain in his back.","zh":"他感到背部一陣劇痛。"},{"en":"She took some medicine to ease the pain in her knee.","zh":"她吃了一些藥來緩解膝蓋的疼痛。"},{"en":"He felt a sharp chest pain and called for help immediately.","zh":"他感到胸口一陣劇痛，立刻求救。"}]},{"word":"painful","pos":"adj.","phonetic":"[ˈpenfəl]","meaning":"疼痛的；痛苦的","definition":"causing pain or distress","collocations":["a painful injury","painful memory","painful experience"],"example":"Breaking a bone can be very painful.","exampleZh":"骨折可能非常疼痛。","synonyms":["sore","distressing"],"level":2,"theme":"身體與健康","examples":[{"en":"Breaking a bone can be very painful.","zh":"骨折可能非常疼痛。"},{"en":"Losing the championship was a painful experience for the whole team.","zh":"輸掉冠軍賽對整支隊伍來說是痛苦的經歷。"},{"en":"The doctor warned that the injury might be very painful.","zh":"醫生警告說這個傷勢可能會非常疼痛。"}]},{"word":"paint","pos":"v. / n.","phonetic":"[pent]","meaning":"油漆；繪畫；顏料","definition":"to cover a surface with paint or to create a picture","collocations":["paint a wall","paint a picture","wet paint"],"example":"They painted the fence white last weekend.","exampleZh":"他們上週末把籬笆漆成白色。","synonyms":["coat","depict"],"level":1,"theme":"藝術與音樂","examples":[{"en":"They painted the fence white last weekend.","zh":"他們上週末把籬笆漆成白色。"},{"en":"The volunteers offered to paint the old classroom walls bright blue.","zh":"志工們主動要把老舊的教室牆壁漆成亮藍色。"},{"en":"My grandmother loves to paint pictures of flowers in her garden.","zh":"我奶奶喜歡畫她花園裡的花朵。"}]},{"word":"painter","pos":"n.","phonetic":"[ˈpentɚ]","meaning":"畫家；油漆工","definition":"a person who paints pictures or buildings","collocations":["a famous painter","house painter","landscape painter"],"example":"The painter displayed his work in a small gallery.","exampleZh":"這位畫家在一間小畫廊展示他的作品。","synonyms":["artist"],"level":2,"theme":"藝術與音樂","examples":[{"en":"The painter displayed his work in a small gallery.","zh":"這位畫家在一間小畫廊展示他的作品。"},{"en":"The famous painter spent years working on a single canvas.","zh":"那位著名的畫家花了好幾年在同一幅畫布上作畫。"},{"en":"We hired a house painter to refresh the living room.","zh":"我們請了一位油漆工來重新粉刷客廳。"}]},{"word":"painting","pos":"n.","phonetic":"[ˈpentɪŋ]","meaning":"畫作；繪畫","definition":"a picture made with paint","collocations":["an oil painting","hang a painting","painting exhibition"],"example":"The painting hung above the fireplace.","exampleZh":"那幅畫掛在壁爐上方。","synonyms":["artwork","picture"],"level":2,"theme":"藝術與音樂","examples":[{"en":"The painting hung above the fireplace.","zh":"那幅畫掛在壁爐上方。"},{"en":"An old oil painting of the sea hung above the sofa.","zh":"一幅古老的海洋油畫掛在沙發上方。"},{"en":"The school held a painting exhibition to show the students' work.","zh":"學校舉辦了一場畫展來展示學生的作品。"}]},{"word":"pair","pos":"n. / v.","phonetic":"[pɛr]","meaning":"一雙；一對；配對","definition":"two things of the same kind used together","collocations":["a pair of shoes","pair up","pair off"],"example":"I bought a new pair of shoes yesterday.","exampleZh":"我昨天買了一雙新鞋。","synonyms":["couple","duo"],"level":1,"theme":"服裝與外表","examples":[{"en":"I bought a new pair of shoes yesterday.","zh":"我昨天買了一雙新鞋。"},{"en":"He needs a new pair of shoes for the sports competition.","zh":"他需要一雙新鞋參加運動比賽。"},{"en":"The teacher asked us to pair up and practice the dialogue.","zh":"老師要我們兩人一組練習對話。"}]},{"word":"pajamas","pos":"n.","phonetic":"[pəˈdʒæməz]","meaning":"睡衣","definition":"loose clothes worn in bed","collocations":["put on pajamas","a pair of pajamas","pajama party"],"example":"He changed into his pajamas before bed.","exampleZh":"他睡前換上睡衣。","synonyms":["nightwear"],"level":2,"theme":"服裝與外表","examples":[{"en":"He changed into his pajamas before bed.","zh":"他睡前換上睡衣。"},{"en":"The little boy put on his warm pajamas before going to sleep.","zh":"小男孩在睡覺前穿上他溫暖的睡衣。"},{"en":"She wore a pair of striped pajamas to the sleepover party.","zh":"她穿了一件條紋睡衣去參加睡衣派對。"}]},{"word":"pal","pos":"n.","phonetic":"[pæl]","meaning":"夥伴；朋友","definition":"a close friend","collocations":["best pal","old pal","pen pal"],"example":"He has been my pal since elementary school.","exampleZh":"他從小學就是我的好夥伴。","synonyms":["friend","buddy"],"level":3,"theme":"人物與家庭","examples":[{"en":"He has been my pal since elementary school.","zh":"他從小學就是我的好夥伴。"},{"en":"My old pal and I still meet for coffee every month.","zh":"我和我的老夥伴每個月仍會一起喝咖啡。"},{"en":"She writes letters to a pen pal living in another country.","zh":"她會寫信給住在另一個國家的筆友。"}]},{"word":"palace","pos":"n.","phonetic":"[ˈpælɪs]","meaning":"皇宮；宮殿","definition":"the official home of a king, queen, or president","collocations":["royal palace","palace guard","live in a palace"],"example":"Tourists lined up to visit the royal palace.","exampleZh":"遊客們排隊參觀皇宮。","synonyms":["mansion"],"level":3,"theme":"社會與文化","examples":[{"en":"Tourists lined up to visit the royal palace.","zh":"遊客們排隊參觀皇宮。"},{"en":"The ancient palace was decorated with gold and shining jewels.","zh":"這座古老的宮殿以黃金和閃亮的珠寶裝飾。"},{"en":"A guard stood silently at the tall gate of the palace.","zh":"一名衛兵靜靜地站在宮殿高大的門前。"}]},{"word":"pale","pos":"adj.","phonetic":"[pel]","meaning":"蒼白的；淺色的","definition":"having little color in the face; light in color","collocations":["turn pale","pale skin","pale blue"],"example":"She turned pale when she heard the bad news.","exampleZh":"她聽到壞消息時臉色變得蒼白。","synonyms":["pallid","light"],"level":3,"theme":"身體與健康","examples":[{"en":"She turned pale when she heard the bad news.","zh":"她聽到壞消息時臉色變得蒼白。"},{"en":"His face turned pale when he saw the frightening movie.","zh":"當他看到那部恐怖電影時，臉色變得蒼白。"},{"en":"She painted her bedroom a soft, pale blue color.","zh":"她把臥室漆成柔和的淺藍色。"}]},{"word":"palm","pos":"n.","phonetic":"[pɑm]","meaning":"手掌；棕櫚樹","definition":"the inner surface of the hand; a tropical tree","collocations":["read a palm","palm tree","sweaty palms"],"example":"He held the coin tightly in his palm.","exampleZh":"他把硬幣緊緊握在手掌裡。","synonyms":[],"level":3,"theme":"身體與健康","examples":[{"en":"He held the coin tightly in his palm.","zh":"他把硬幣緊緊握在手掌裡。"},{"en":"He wrote the phone number on the palm of his hand.","zh":"他把電話號碼寫在手掌上。"},{"en":"Tall palm trees lined the sandy beach near our hotel.","zh":"高大的棕櫚樹排列在我們飯店附近的沙灘旁。"}]},{"word":"pan","pos":"n.","phonetic":"[pæn]","meaning":"平底鍋","definition":"a metal container used for cooking food","collocations":["frying pan","a pan of water","non-stick pan"],"example":"She heated some oil in the pan.","exampleZh":"她在鍋裡加熱一些油。","synonyms":["skillet"],"level":2,"theme":"食物與烹飪","examples":[{"en":"She heated some oil in the pan.","zh":"她在鍋裡加熱一些油。"},{"en":"She cracked two eggs into the hot frying pan.","zh":"她把兩顆蛋打進熱鍋裡。"},{"en":"Pour a pan of water over the vegetables to clean them.","zh":"倒一鍋水在蔬菜上把它們洗乾淨。"}]},{"word":"pancake","pos":"n.","phonetic":"[ˈpænˌkek]","meaning":"薄煎餅","definition":"a thin, flat cake made of batter and fried on both sides","collocations":["make pancakes","a stack of pancakes","pancake batter"],"example":"We had pancakes with syrup for breakfast.","exampleZh":"我們早餐吃了淋糖漿的薄煎餅。","synonyms":[],"level":2,"theme":"食物與烹飪","examples":[{"en":"We had pancakes with syrup for breakfast.","zh":"我們早餐吃了淋糖漿的薄煎餅。"},{"en":"We made a tall stack of pancakes for the family breakfast.","zh":"我們為全家的早餐做了一疊高高的煎餅。"},{"en":"She poured the pancake batter carefully into the round pan.","zh":"她小心地把煎餅麵糊倒進圓鍋裡。"}]},{"word":"panda","pos":"n.","phonetic":"[ˈpændə]","meaning":"貓熊","definition":"a large black-and-white bear from China","collocations":["giant panda","panda cub","panda bear"],"example":"The giant panda is eating bamboo at the zoo.","exampleZh":"這隻大貓熊正在動物園吃竹子。","synonyms":[],"level":1,"theme":"動物與植物","examples":[{"en":"The giant panda is eating bamboo at the zoo.","zh":"這隻大貓熊正在動物園吃竹子。"},{"en":"The giant panda slowly chewed on a stick of bamboo.","zh":"大貓熊慢慢地嚼著一根竹子。"},{"en":"Visitors crowded around to watch the sleepy panda cub.","zh":"遊客們擠在一起觀看那隻愛睏的貓熊寶寶。"}]},{"word":"panel","pos":"n.","phonetic":"[ˈpænl̩]","meaning":"面板；小組；委員會","definition":"a flat piece of material, or a group of people who discuss or judge something","collocations":["control panel","panel discussion","solar panel"],"example":"A panel of experts discussed the new policy.","exampleZh":"一組專家討論了這項新政策。","synonyms":["board"],"level":4,"theme":"工作與職業","examples":[{"en":"A panel of experts discussed the new policy.","zh":"一組專家討論了這項新政策。"},{"en":"A panel of judges will decide the winner of the contest.","zh":"一組評審將決定這場比賽的優勝者。"},{"en":"He pressed a button on the control panel to start the machine.","zh":"他按下控制面板上的按鈕來啟動機器。"}]},{"word":"panic","pos":"n. / v.","phonetic":"[ˈpænɪk]","meaning":"恐慌；驚慌","definition":"a sudden feeling of great fear","collocations":["panic attack","don't panic","spread panic"],"example":"Don't panic; everything will be fine.","exampleZh":"別驚慌，一切都會沒事的。","synonyms":["alarm","fear"],"level":3,"theme":"情緒與感受","examples":[{"en":"Don't panic; everything will be fine.","zh":"別驚慌，一切都會沒事的。"},{"en":"Don't panic if the lights suddenly go out during the storm.","zh":"如果暴風雨中燈突然熄滅，不要驚慌。"},{"en":"A false alarm spread panic among the shoppers in the mall.","zh":"一次假警報在商場的購物者中引起恐慌。"}]},{"word":"panorama","pos":"n.","phonetic":"[ˌpænəˈræmə]","meaning":"全景；概觀","definition":"a wide view of an area or a complete survey of a subject","collocations":["a panorama of the city","a stunning panorama","view the panorama"],"example":"From the tower, we enjoyed a panorama of the whole valley.","exampleZh":"從塔上我們欣賞到整個山谷的全景。","synonyms":["view","vista"],"level":5,"theme":"自然與環境","examples":[{"en":"From the tower, we enjoyed a panorama of the whole valley.","zh":"從塔上我們欣賞到整個山谷的全景。"},{"en":"From the hilltop we admired a stunning panorama of the coast.","zh":"從山頂上我們欣賞到令人驚豔的海岸全景。"},{"en":"The museum offers a broad panorama of the country's history.","zh":"這座博物館提供了該國歷史的宏觀概覽。"}]},{"word":"pants","pos":"n.","phonetic":"[pænts]","meaning":"長褲","definition":"a piece of clothing covering the legs","collocations":["a pair of pants","tight pants","roll up pants"],"example":"He wore black pants to the interview.","exampleZh":"他穿著黑色長褲去面試。","synonyms":["trousers"],"level":1,"theme":"服裝與外表","examples":[{"en":"He wore black pants to the interview.","zh":"他穿著黑色長褲去面試。"},{"en":"He rolled up his pants before walking into the shallow stream.","zh":"他捲起褲管才走進淺淺的溪水裡。"},{"en":"These tight pants are uncomfortable for a long train ride.","zh":"這條緊身褲不適合長途火車旅程。"}]},{"word":"papaya","pos":"n.","phonetic":"[pəˈpaɪə]","meaning":"木瓜","definition":"a tropical fruit with orange flesh","collocations":["ripe papaya","papaya salad","papaya milk"],"example":"Papaya milk is a popular drink in Taiwan.","exampleZh":"木瓜牛奶是台灣一種很受歡迎的飲料。","synonyms":[],"level":2,"theme":"食物與烹飪","examples":[{"en":"Papaya milk is a popular drink in Taiwan.","zh":"木瓜牛奶是台灣一種很受歡迎的飲料。"},{"en":"A ripe papaya has sweet orange flesh and black seeds.","zh":"成熟的木瓜有著甜美的橘色果肉和黑色種子。"},{"en":"They ordered fresh papaya milk at the night market stall.","zh":"他們在夜市攤位點了新鮮的木瓜牛奶。"}]},{"word":"paper","pos":"n.","phonetic":"[ˈpepɚ]","meaning":"紙；報紙；報告","definition":"material used for writing or printing on","collocations":["a piece of paper","term paper","newspaper"],"example":"He wrote his notes on a piece of paper.","exampleZh":"他把筆記寫在一張紙上。","synonyms":["document"],"level":1,"theme":"教育與學習","examples":[{"en":"He wrote his notes on a piece of paper.","zh":"他把筆記寫在一張紙上。"},{"en":"She folded the piece of paper and slipped it into an envelope.","zh":"她把那張紙摺起來塞進信封裡。"},{"en":"He stayed up late finishing his history term paper.","zh":"他熬夜完成他的歷史學期報告。"}]},{"word":"parachute","pos":"n.","phonetic":"[ˈpærəˌʃut]","meaning":"降落傘","definition":"a device used to slow a fall from an aircraft","collocations":["open a parachute","parachute jump","skydiving parachute"],"example":"The pilot escaped by using a parachute.","exampleZh":"飛行員靠降落傘逃生。","synonyms":[],"level":4,"theme":"交通與旅行","examples":[{"en":"The pilot escaped by using a parachute.","zh":"飛行員靠降落傘逃生。"},{"en":"The skydiver pulled the cord to open her parachute in time.","zh":"跳傘者及時拉繩打開了她的降落傘。"},{"en":"A colorful parachute floated gently down toward the field.","zh":"一頂色彩繽紛的降落傘輕柔地飄落向田野。"}]},{"word":"parade","pos":"n. / v.","phonetic":"[pəˈred]","meaning":"遊行","definition":"a public procession celebrating a special event","collocations":["a military parade","victory parade","parade route"],"example":"Thousands watched the Christmas parade downtown.","exampleZh":"數千人在市中心觀看聖誕遊行。","synonyms":["procession"],"level":3,"theme":"社會與文化","examples":[{"en":"Thousands watched the Christmas parade downtown.","zh":"數千人在市中心觀看聖誕遊行。"},{"en":"Crowds lined the street to watch the lively New Year parade.","zh":"人群排列在街道兩旁觀看熱鬧的新年遊行。"},{"en":"The marching band led the parade down the main avenue.","zh":"軍樂隊帶領遊行隊伍走過大道。"}]},{"word":"paradox","pos":"n.","phonetic":"[ˈpærəˌdɑks]","meaning":"矛盾；似非而是的說法","definition":"a statement or situation that seems contradictory but may be true","collocations":["a strange paradox","the paradox of choice","solve a paradox"],"example":"It's a paradox that the busiest people often have the most free time.","exampleZh":"最忙碌的人往往擁有最多空閒時間，這是個矛盾現象。","synonyms":["contradiction"],"level":6,"theme":"抽象概念","examples":[{"en":"It's a paradox that the busiest people often have the most free time.","zh":"最忙碌的人往往擁有最多空閒時間，這是個矛盾現象。"},{"en":"It is a paradox that spending time resting can improve your work.","zh":"花時間休息反而能提升工作表現，這真是個矛盾。"},{"en":"The clever riddle contained a paradox the students could not solve.","zh":"這道巧妙的謎題含有一個學生無法解開的矛盾。"}]},{"word":"paragraph","pos":"n.","phonetic":"[ˈpærəˌgræf]","meaning":"段落","definition":"a section of a piece of writing","collocations":["first paragraph","write a paragraph","paragraph break"],"example":"The teacher asked us to write a short paragraph.","exampleZh":"老師要求我們寫一段短文。","synonyms":[],"level":3,"theme":"教育與學習","examples":[{"en":"The teacher asked us to write a short paragraph.","zh":"老師要求我們寫一段短文。"},{"en":"The first paragraph of the essay should state your main idea.","zh":"文章的第一段應該點出你的主要論點。"},{"en":"Start a new paragraph whenever you introduce a different topic.","zh":"每當你要介紹不同的主題時，就另起一段。"}]},{"word":"parallel","pos":"adj. / n.","phonetic":"[ˈpærəˌlɛl]","meaning":"平行的；相似之處","definition":"lines that are the same distance apart at every point","collocations":["parallel lines","run parallel to","draw a parallel"],"example":"The two roads run parallel to each other.","exampleZh":"這兩條路彼此平行。","synonyms":["equivalent"],"level":4,"theme":"科學與數學","examples":[{"en":"The two roads run parallel to each other.","zh":"這兩條路彼此平行。"},{"en":"The two straight lines are parallel and will never meet.","zh":"這兩條直線互相平行，永遠不會相交。"},{"en":"The writer drew a parallel between school life and a garden.","zh":"作者將校園生活與花園相比擬。"}]},{"word":"paralyze","pos":"v.","phonetic":"[ˈpærəˌlaɪz]","meaning":"使癱瘓；使麻痺","definition":"to make a person or thing unable to move or function","collocations":["paralyzed by fear","paralyze traffic","totally paralyzed"],"example":"The heavy snow paralyzed the entire city.","exampleZh":"這場大雪讓整座城市陷入癱瘓。","synonyms":["cripple","immobilize"],"level":5,"theme":"身體與健康","examples":[{"en":"The heavy snow paralyzed the entire city.","zh":"這場大雪讓整座城市陷入癱瘓。"},{"en":"The sudden accident could paralyze him from the waist down.","zh":"這場突如其來的意外可能使他腰部以下癱瘓。"},{"en":"Fear seemed to paralyze her, and she could not move.","zh":"恐懼似乎使她麻痺，她動彈不得。"}]},{"word":"parasite","pos":"n.","phonetic":"[ˈpærəˌsaɪt]","meaning":"寄生蟲；寄生生物","definition":"an organism that lives in or on another organism and feeds off it","collocations":["a blood-sucking parasite","host a parasite","parasite infection"],"example":"The parasite lives inside the host's intestines.","exampleZh":"這種寄生蟲住在宿主的腸道裡。","synonyms":[],"level":5,"theme":"動物與植物","examples":[{"en":"The parasite lives inside the host's intestines.","zh":"這種寄生蟲住在宿主的腸道裡。"},{"en":"A tiny parasite can live inside a fish and cause disease.","zh":"一種微小的寄生蟲能寄生在魚體內並引發疾病。"},{"en":"Doctors gave the dog medicine to remove the harmful parasite.","zh":"醫生給狗吃藥以清除有害的寄生蟲。"}]},{"word":"parcel","pos":"n.","phonetic":"[ˈpɑrsl̩]","meaning":"包裹","definition":"an object or objects wrapped in paper to be sent by mail","collocations":["send a parcel","wrap a parcel","parcel post"],"example":"She wrapped the gift into a neat parcel.","exampleZh":"她把禮物包成一個整齊的包裹。","synonyms":["package"],"level":4,"theme":"居家與生活","examples":[{"en":"She wrapped the gift into a neat parcel.","zh":"她把禮物包成一個整齊的包裹。"},{"en":"She carefully wrapped the books into a neat brown parcel.","zh":"她小心地把書包成一個整齊的棕色包裹。"},{"en":"The postman asked me to sign for the heavy parcel.","zh":"郵差要我簽收那個沉重的包裹。"}]},{"word":"pardon","pos":"v. / n.","phonetic":"[ˈpɑrdn̩]","meaning":"原諒；赦免","definition":"to forgive someone for a fault or mistake","collocations":["pardon me","beg your pardon","grant a pardon"],"example":"Pardon me, could you repeat that?","exampleZh":"不好意思，可以再說一次嗎？","synonyms":["forgive","excuse"],"level":3,"theme":"溝通與語言","examples":[{"en":"Pardon me, could you repeat that?","zh":"不好意思，可以再說一次嗎？"},{"en":"Pardon me, but could you tell me the way to the station?","zh":"不好意思，你能告訴我去車站的路嗎？"},{"en":"She asked him to pardon her for forgetting his birthday.","zh":"她請他原諒她忘了他的生日。"}]},{"word":"parent","pos":"n.","phonetic":"[ˈpɛrənt]","meaning":"父母；雙親","definition":"a father or mother","collocations":["single parent","parent meeting","become a parent"],"example":"Both of my parents work in the city.","exampleZh":"我父母都在市區工作。","synonyms":["guardian"],"level":1,"theme":"人物與家庭","examples":[{"en":"Both of my parents work in the city.","zh":"我父母都在市區工作。"},{"en":"Every parent wants their child to grow up healthy and happy.","zh":"每位父母都希望自己的孩子健康快樂地長大。"},{"en":"The school invited every parent to attend the meeting on Friday.","zh":"學校邀請每位家長參加週五的會議。"}]},{"word":"park","pos":"n. / v.","phonetic":"[pɑrk]","meaning":"公園；停車","definition":"a public area with grass and trees for recreation; to stop a vehicle","collocations":["national park","park a car","play in the park"],"example":"We had a picnic in the park on Sunday.","exampleZh":"我們星期天在公園野餐。","synonyms":[],"level":1,"theme":"居家與生活","examples":[{"en":"We had a picnic in the park on Sunday.","zh":"我們星期天在公園野餐。"},{"en":"They spread a blanket and relaxed in the shady park.","zh":"他們鋪開毯子，在樹蔭下的公園裡放鬆。"},{"en":"You cannot park your car in front of the hospital gate.","zh":"你不能把車停在醫院大門前。"}]},{"word":"parking","pos":"n.","phonetic":"[ˈpɑrkɪŋ]","meaning":"停車","definition":"the act of stopping a vehicle in a place for a period of time","collocations":["parking lot","free parking","no parking"],"example":"There is no parking available near the theater.","exampleZh":"戲院附近沒有停車位。","synonyms":[],"level":2,"theme":"交通與旅行","examples":[{"en":"There is no parking available near the theater.","zh":"戲院附近沒有停車位。"},{"en":"The driver searched for a parking space near the busy market.","zh":"駕駛在繁忙的市場附近尋找停車位。"},{"en":"A large sign said there was no parking on this street.","zh":"一個大牌子寫著這條街禁止停車。"}]},{"word":"parliament","pos":"n.","phonetic":"[ˈpɑrləmənt]","meaning":"國會；議會","definition":"a group of people who make laws for a country","collocations":["member of parliament","pass through parliament","dissolve parliament"],"example":"The new law was approved by parliament.","exampleZh":"這項新法律已獲國會通過。","synonyms":["congress"],"level":5,"theme":"政治與法律","examples":[{"en":"The new law was approved by parliament.","zh":"這項新法律已獲國會通過。"},{"en":"Members of parliament debated the new education law for hours.","zh":"國會議員針對新的教育法案辯論了好幾個小時。"},{"en":"The bill must pass through parliament before it becomes law.","zh":"這項法案必須通過國會才能成為法律。"}]},{"word":"parole","pos":"n. / v.","phonetic":"[pəˈrol]","meaning":"假釋","definition":"the release of a prisoner before their full sentence is completed, on condition of good behavior","collocations":["release on parole","grant parole","break parole"],"example":"He was released on parole after serving ten years.","exampleZh":"他服刑十年後獲得假釋。","synonyms":[],"level":6,"theme":"政治與法律","examples":[{"en":"He was released on parole after serving ten years.","zh":"他服刑十年後獲得假釋。"},{"en":"The prisoner behaved well and was granted parole early.","zh":"這名囚犯表現良好，提早獲得假釋。"},{"en":"Breaking the rules of parole could send him back to prison.","zh":"違反假釋規定可能會讓他被送回監獄。"}]},{"word":"parrot","pos":"n.","phonetic":"[ˈpærət]","meaning":"鸚鵡","definition":"a colorful tropical bird that can imitate speech","collocations":["talking parrot","pet parrot","parrot's cage"],"example":"The parrot repeated everything I said.","exampleZh":"那隻鸚鵡重複了我說的每一句話。","synonyms":[],"level":2,"theme":"動物與植物","examples":[{"en":"The parrot repeated everything I said.","zh":"那隻鸚鵡重複了我說的每一句話。"},{"en":"Our pet parrot can whistle a simple tune and say hello.","zh":"我們的寵物鸚鵡會吹一段簡單的曲子並說哈囉。"},{"en":"The colorful parrot cleverly imitated the sound of a doorbell.","zh":"那隻色彩鮮豔的鸚鵡巧妙地模仿門鈴聲。"}]},{"word":"part","pos":"n. / v.","phonetic":"[pɑrt]","meaning":"部分；角色","definition":"a piece or section of something larger","collocations":["take part in","spare part","play a part"],"example":"He played an important part in the project.","exampleZh":"他在這個計畫中扮演重要角色。","synonyms":["portion","section"],"level":1,"theme":"抽象概念","examples":[{"en":"He played an important part in the project.","zh":"他在這個計畫中扮演重要角色。"},{"en":"Everyone was invited to take part in the school cleanup day.","zh":"每個人都受邀參加學校的打掃日。"},{"en":"This small screw is a spare part for the broken clock.","zh":"這顆小螺絲是壞掉時鐘的備用零件。"}]},{"word":"partial","pos":"adj.","phonetic":"[ˈpɑrʃəl]","meaning":"部分的；偏袒的","definition":"not complete or total","collocations":["partial success","partial view","be partial to"],"example":"The rescue was only a partial success.","exampleZh":"這次救援只獲得部分成功。","synonyms":["incomplete"],"level":5,"theme":"性質與描述","examples":[{"en":"The rescue was only a partial success.","zh":"這次救援只獲得部分成功。"},{"en":"The plan was only a partial success, so we tried again.","zh":"這個計畫只獲得部分成功，所以我們再試了一次。"},{"en":"My grandfather is rather partial to sweet desserts after dinner.","zh":"我爺爺相當偏愛晚餐後的甜點。"}]},{"word":"participant","pos":"n.","phonetic":"[pɑrˈtɪsəpənt]","meaning":"參與者","definition":"a person who takes part in something","collocations":["active participant","each participant","participant list"],"example":"Every participant received a certificate.","exampleZh":"每位參與者都獲得一張證書。","synonyms":["member"],"level":5,"theme":"工作與職業","examples":[{"en":"Every participant received a certificate.","zh":"每位參與者都獲得一張證書。"},{"en":"Each participant in the workshop received a name tag and folder.","zh":"每位工作坊的參與者都拿到一個名牌和資料夾。"},{"en":"She was the youngest participant in the national speech contest.","zh":"她是全國演講比賽中最年輕的參賽者。"}]},{"word":"participate","pos":"v.","phonetic":"[pɑrˈtɪsəˌpet]","meaning":"參加；參與","definition":"to take part in an activity or event","collocations":["participate in a contest","actively participate","encourage to participate"],"example":"All students are encouraged to participate in the event.","exampleZh":"鼓勵所有學生參加這項活動。","synonyms":["join","take part"],"level":4,"theme":"動作與行為","examples":[{"en":"All students are encouraged to participate in the event.","zh":"鼓勵所有學生參加這項活動。"},{"en":"Students are encouraged to participate in the annual science fair.","zh":"學校鼓勵學生參加一年一度的科學展。"},{"en":"He was too shy to participate in the class discussion.","zh":"他太害羞了，不敢參與課堂討論。"}]},{"word":"particle","pos":"n.","phonetic":"[ˈpɑrtɪkl]","meaning":"微粒；粒子","definition":"a very small piece of matter","collocations":["dust particle","a particle of sand","subatomic particle"],"example":"Scientists study particles too small to see with the naked eye.","exampleZh":"科學家研究肉眼無法看見的微小粒子。","synonyms":["fragment"],"level":4,"theme":"科學與數學","examples":[{"en":"Scientists study particles too small to see with the naked eye.","zh":"科學家研究肉眼無法看見的微小粒子。"},{"en":"A single particle of dust floated in the beam of light.","zh":"一粒灰塵漂浮在那道光束中。"},{"en":"Scientists use powerful machines to study tiny subatomic particles.","zh":"科學家用強大的機器研究微小的次原子粒子。"}]},{"word":"particular","pos":"adj.","phonetic":"[pɚˈtɪkjəlɚ]","meaning":"特定的；挑剔的","definition":"specific or special; being fussy about something","collocations":["in particular","this particular case","particular about food"],"example":"He is very particular about what he eats.","exampleZh":"他對吃的東西非常挑剔。","synonyms":["specific","fussy"],"level":3,"theme":"性質與描述","examples":[{"en":"He is very particular about what he eats.","zh":"他對吃的東西非常挑剔。"},{"en":"She is very particular about keeping her desk neat and clean.","zh":"她對保持書桌整潔非常講究。"},{"en":"In this particular case, the rule does not really apply.","zh":"在這個特定的情況下，這條規則並不真正適用。"}]},{"word":"particularly","pos":"adv.","phonetic":"[pɚˈtɪkjəlɚli]","meaning":"特別地；尤其","definition":"especially; more than usual","collocations":["particularly interested","particularly difficult","particularly true"],"example":"The exam was particularly difficult this year.","exampleZh":"今年的考試特別難。","synonyms":["especially"],"level":3,"theme":"抽象概念","examples":[{"en":"The exam was particularly difficult this year.","zh":"今年的考試特別難。"},{"en":"The museum is particularly crowded on rainy weekend afternoons.","zh":"這座博物館在下雨的週末午後特別擁擠。"},{"en":"He is particularly interested in the history of ancient China.","zh":"他對古代中國的歷史特別感興趣。"}]},{"word":"partition","pos":"n. / v.","phonetic":"[pɑrˈtɪʃən]","meaning":"隔間；分割","definition":"a structure that divides a room, or the act of dividing something into parts","collocations":["a glass partition","partition a room","partition the land"],"example":"A thin partition separates the two offices.","exampleZh":"一道薄薄的隔間牆把兩間辦公室隔開。","synonyms":["divider"],"level":5,"theme":"居家與生活","examples":[{"en":"A thin partition separates the two offices.","zh":"一道薄薄的隔間牆把兩間辦公室隔開。"},{"en":"A glass partition divides the office into two quiet halves.","zh":"一道玻璃隔間把辦公室分成兩個安靜的區域。"},{"en":"They decided to partition the large room into smaller study areas.","zh":"他們決定把大房間隔成較小的讀書區。"}]},{"word":"partly","pos":"adv.","phonetic":"[ˈpɑrtli]","meaning":"部分地","definition":"to some extent, but not completely","collocations":["partly true","partly cloudy","partly due to"],"example":"The delay was partly due to bad weather.","exampleZh":"延誤部分是因為天氣不佳。","synonyms":["partially"],"level":3,"theme":"抽象概念","examples":[{"en":"The delay was partly due to bad weather.","zh":"延誤部分是因為天氣不佳。"},{"en":"The sky was partly cloudy, but the picnic still went well.","zh":"天空部分多雲，但野餐仍然進行得很順利。"},{"en":"His success was partly due to luck and partly to hard work.","zh":"他的成功一部分靠運氣，一部分靠努力。"}]},{"word":"partner","pos":"n.","phonetic":"[ˈpɑrtnɚ]","meaning":"夥伴；合夥人；配偶","definition":"a person who takes part in an activity with another","collocations":["business partner","dance partner","life partner"],"example":"She started the company with her business partner.","exampleZh":"她和她的事業夥伴一起創立了這家公司。","synonyms":["colleague","associate"],"level":3,"theme":"工作與職業","examples":[{"en":"She started the company with her business partner.","zh":"她和她的事業夥伴一起創立了這家公司。"},{"en":"She chose a reliable classmate as her partner for the project.","zh":"她選了一位可靠的同學作為這個專題的夥伴。"},{"en":"He trusts his business partner to handle the company's accounts.","zh":"他信任他的事業夥伴來處理公司的帳目。"}]},{"word":"party","pos":"n.","phonetic":"[ˈpɑrti]","meaning":"派對；政黨","definition":"a social gathering, or an organized political group","collocations":["birthday party","political party","throw a party"],"example":"We are throwing a surprise party for her birthday.","exampleZh":"我們正在為她的生日籌辦一場驚喜派對。","synonyms":["gathering"],"level":1,"theme":"社會與文化","examples":[{"en":"We are throwing a surprise party for her birthday.","zh":"我們正在為她的生日籌辦一場驚喜派對。"},{"en":"We decorated the room with balloons for the birthday party.","zh":"我們用氣球布置房間來慶祝生日派對。"},{"en":"The two political parties disagreed strongly on the new plan.","zh":"這兩個政黨對新計畫的意見大相逕庭。"}]},{"word":"pass","pos":"v. / n.","phonetic":"[pæs]","meaning":"通過；經過；通行證","definition":"to move past or through something; to succeed in a test","collocations":["pass an exam","pass by","boarding pass"],"example":"She worked hard to pass the final exam.","exampleZh":"她努力用功以通過期末考。","synonyms":["succeed","cross"],"level":1,"theme":"教育與學習","examples":[{"en":"She worked hard to pass the final exam.","zh":"她努力用功以通過期末考。"},{"en":"She studied every night in order to pass the difficult exam.","zh":"她每晚讀書，就是為了通過這場困難的考試。"},{"en":"Please show your boarding pass before entering the plane.","zh":"登機前請出示你的登機證。"}]},{"word":"passage","pos":"n.","phonetic":"[ˈpæsɪdʒ]","meaning":"通道；一段文章","definition":"a way through, or a short section of a text","collocations":["read a passage","narrow passage","passage of time"],"example":"Please read the passage and answer the questions.","exampleZh":"請閱讀這篇文章並回答問題。","synonyms":["corridor","extract"],"level":4,"theme":"教育與學習","examples":[{"en":"Please read the passage and answer the questions.","zh":"請閱讀這篇文章並回答問題。"},{"en":"Read the short passage carefully and underline the key words.","zh":"仔細閱讀這段短文，並在關鍵字下畫線。"},{"en":"A narrow passage led from the kitchen to the back garden.","zh":"一條狹窄的通道從廚房通往後花園。"}]},{"word":"passenger","pos":"n.","phonetic":"[ˈpæsn̩dʒɚ]","meaning":"乘客","definition":"a person traveling in a vehicle other than the driver","collocations":["airline passenger","passenger seat","carry passengers"],"example":"The bus can carry up to forty passengers.","exampleZh":"這輛公車最多可載四十名乘客。","synonyms":["traveler"],"level":2,"theme":"交通與旅行","examples":[{"en":"The bus can carry up to forty passengers.","zh":"這輛公車最多可載四十名乘客。"},{"en":"Every passenger must fasten the seat belt before takeoff.","zh":"每位乘客在起飛前都必須繫好安全帶。"},{"en":"The taxi driver helped the elderly passenger with her bags.","zh":"計程車司機幫年長的乘客提行李。"}]},{"word":"passerby","pos":"n.","phonetic":"[ˈpæsɚˌbaɪ]","meaning":"路人；過路人","definition":"a person who is walking past someone or something","collocations":["a curious passerby","stop a passerby","ask a passerby"],"example":"A passerby helped the old man cross the street.","exampleZh":"一位路人幫助那位老先生過馬路。","synonyms":["pedestrian"],"level":4,"theme":"人物與家庭","examples":[{"en":"A passerby helped the old man cross the street.","zh":"一位路人幫助那位老先生過馬路。"},{"en":"A kind passerby stopped to help us fix the flat tire.","zh":"一位好心的路人停下來幫我們修理爆胎。"},{"en":"The street performer drew a curious passerby to watch him.","zh":"街頭表演者吸引了一位好奇的路人駐足觀看。"}]},{"word":"passion","pos":"n.","phonetic":"[ˈpæʃən]","meaning":"熱情；激情","definition":"a very strong feeling of enthusiasm or love","collocations":["passion for music","with passion","follow your passion"],"example":"She has a real passion for painting.","exampleZh":"她對繪畫懷有真正的熱情。","synonyms":["enthusiasm","zeal"],"level":4,"theme":"情緒與感受","examples":[{"en":"She has a real passion for painting.","zh":"她對繪畫懷有真正的熱情。"},{"en":"His passion for music began when he was just five years old.","zh":"他對音樂的熱情始於他才五歲的時候。"},{"en":"She spoke about protecting animals with great passion.","zh":"她滿懷熱情地談論保護動物。"}]},{"word":"passionate","pos":"adj.","phonetic":"[ˈpæʃənɪt]","meaning":"熱情的；充滿激情的","definition":"showing strong feelings or enthusiasm","collocations":["passionate about","passionate speech","passionate love"],"example":"He is passionate about protecting the environment.","exampleZh":"他對保護環境充滿熱情。","synonyms":["enthusiastic"],"level":5,"theme":"情緒與感受","examples":[{"en":"He is passionate about protecting the environment.","zh":"他對保護環境充滿熱情。"},{"en":"The coach gave a passionate speech before the final game.","zh":"教練在決賽前發表了一場充滿熱情的演說。"},{"en":"She is passionate about helping children learn to read.","zh":"她對幫助孩子學習閱讀充滿熱情。"}]},{"word":"passive","pos":"adj.","phonetic":"[ˈpæsɪv]","meaning":"被動的；消極的","definition":"accepting what happens without acting to change it","collocations":["passive voice","passive smoking","stay passive"],"example":"He remained passive during the whole discussion.","exampleZh":"他在整場討論中都保持被動。","synonyms":["inactive"],"level":5,"theme":"性質與描述","examples":[{"en":"He remained passive during the whole discussion.","zh":"他在整場討論中都保持被動。"},{"en":"He stayed passive and let others make all the decisions.","zh":"他保持被動，讓別人做所有的決定。"},{"en":"The teacher explained how to change a sentence into passive voice.","zh":"老師解釋如何把句子改成被動語態。"}]},{"word":"passport","pos":"n.","phonetic":"[ˈpæsˌpɔrt]","meaning":"護照","definition":"an official document used for international travel","collocations":["renew a passport","valid passport","passport control"],"example":"Don't forget to bring your passport to the airport.","exampleZh":"別忘了帶護照去機場。","synonyms":[],"level":3,"theme":"交通與旅行","examples":[{"en":"Don't forget to bring your passport to the airport.","zh":"別忘了帶護照去機場。"},{"en":"You must renew your passport before it expires next month.","zh":"你必須在護照下個月到期前更新它。"},{"en":"The officer at passport control checked her photo carefully.","zh":"護照查驗處的官員仔細核對了她的照片。"}]},{"word":"password","pos":"n.","phonetic":"[ˈpæsˌwɝd]","meaning":"密碼","definition":"a secret word or phrase used to gain access","collocations":["forget a password","strong password","change your password"],"example":"Please enter your password to log in.","exampleZh":"請輸入你的密碼登入。","synonyms":["code"],"level":3,"theme":"科技與媒體","examples":[{"en":"Please enter your password to log in.","zh":"請輸入你的密碼登入。"},{"en":"Choose a strong password that mixes letters and numbers.","zh":"選一組混合字母和數字的強密碼。"},{"en":"He forgot his password and could not open the email account.","zh":"他忘了密碼，無法打開電子郵件帳號。"}]},{"word":"past","pos":"n. / adj. / prep.","phonetic":"[pæst]","meaning":"過去；以前的","definition":"the time before the present","collocations":["in the past","past experience","walk past"],"example":"He never talks about his past.","exampleZh":"他從不談論他的過去。","synonyms":["history"],"level":1,"theme":"時間與空間","examples":[{"en":"He never talks about his past.","zh":"他從不談論他的過去。"},{"en":"In the past, people wrote letters instead of sending messages.","zh":"過去，人們寫信而不是傳訊息。"},{"en":"We walked past the old library on our way to school.","zh":"我們上學途中經過了那座老舊的圖書館。"}]},{"word":"pasta","pos":"n.","phonetic":"[ˈpɑstə]","meaning":"義大利麵","definition":"an Italian food made from flour, water, and eggs","collocations":["cook pasta","pasta sauce","a bowl of pasta"],"example":"We had pasta with tomato sauce for dinner.","exampleZh":"我們晚餐吃了配番茄醬的義大利麵。","synonyms":[],"level":2,"theme":"食物與烹飪","examples":[{"en":"We had pasta with tomato sauce for dinner.","zh":"我們晚餐吃了配番茄醬的義大利麵。"},{"en":"He cooked a big bowl of pasta with fresh tomato sauce.","zh":"他煮了一大碗配上新鮮番茄醬的義大利麵。"},{"en":"Boil the pasta for about ten minutes until it is soft.","zh":"把義大利麵煮約十分鐘直到變軟。"}]},{"word":"paste","pos":"n. / v.","phonetic":"[pest]","meaning":"漿糊；糊狀物；黏貼","definition":"a soft, sticky mixture; to stick something with glue","collocations":["toothpaste","cut and paste","flour paste"],"example":"He used paste to stick the poster on the wall.","exampleZh":"他用漿糊把海報貼在牆上。","synonyms":["glue"],"level":3,"theme":"居家與生活","examples":[{"en":"He used paste to stick the poster on the wall.","zh":"他用漿糊把海報貼在牆上。"},{"en":"The children mixed flour and water to make a simple paste.","zh":"孩子們把麵粉和水混合做成簡單的漿糊。"},{"en":"He squeezed some toothpaste onto his brush before bed.","zh":"睡前他擠了一些牙膏在牙刷上。"}]},{"word":"pastime","pos":"n.","phonetic":"[ˈpæsˌtaɪm]","meaning":"消遣；娛樂","definition":"an activity done for enjoyment in spare time","collocations":["favorite pastime","popular pastime","harmless pastime"],"example":"Reading is her favorite pastime.","exampleZh":"閱讀是她最喜歡的消遣。","synonyms":["hobby"],"level":5,"theme":"運動與休閒","examples":[{"en":"Reading is her favorite pastime.","zh":"閱讀是她最喜歡的消遣。"},{"en":"Fishing by the river is his favorite weekend pastime.","zh":"在河邊釣魚是他最喜歡的週末消遣。"},{"en":"Collecting stamps was a popular pastime many years ago.","zh":"集郵在多年前是一種很受歡迎的消遣。"}]},{"word":"pasture","pos":"n.","phonetic":"[ˈpæstʃɚ]","meaning":"牧場；草地","definition":"land covered with grass, used for animals to graze on","collocations":["graze in the pasture","open pasture","green pasture"],"example":"The cows grazed peacefully in the pasture.","exampleZh":"牛群在牧場上安靜地吃草。","synonyms":["meadow"],"level":4,"theme":"自然與環境","examples":[{"en":"The cows grazed peacefully in the pasture.","zh":"牛群在牧場上安靜地吃草。"},{"en":"The sheep grazed quietly in the green mountain pasture.","zh":"羊群在青翠的山間牧場上安靜地吃草。"},{"en":"Farmers led their cattle to the open pasture at dawn.","zh":"農夫們在黎明時把牛群趕到開闊的牧場。"}]},{"word":"pat","pos":"v. / n.","phonetic":"[pæt]","meaning":"輕拍","definition":"to gently touch someone or something with the hand","collocations":["pat on the back","pat a dog","give a pat"],"example":"He gave the dog a gentle pat on the head.","exampleZh":"他輕輕拍了拍狗的頭。","synonyms":["tap"],"level":3,"theme":"動作與行為","examples":[{"en":"He gave the dog a gentle pat on the head.","zh":"他輕輕拍了拍狗的頭。"},{"en":"The coach gave each player a pat on the back after the game.","zh":"比賽後教練拍拍每位球員的背表示鼓勵。"},{"en":"She gently patted the crying baby until he fell asleep.","zh":"她輕拍哭泣的寶寶，直到他睡著。"}]},{"word":"patch","pos":"n. / v.","phonetic":"[pætʃ]","meaning":"補丁；小塊；修補","definition":"a small piece of material used to cover a hole","collocations":["patch of grass","patch up","apply a patch"],"example":"She sewed a patch onto his torn jeans.","exampleZh":"她在他破損的牛仔褲上縫了一塊補丁。","synonyms":["mend"],"level":4,"theme":"服裝與外表","examples":[{"en":"She sewed a patch onto his torn jeans.","zh":"她在他破損的牛仔褲上縫了一塊補丁。"},{"en":"They planted vegetables in a small patch of ground behind the house.","zh":"他們在屋後一小塊地上種了蔬菜。"},{"en":"He sewed a colorful patch over the hole in his backpack.","zh":"他在背包的破洞上縫了一塊彩色補丁。"}]},{"word":"patent","pos":"n. / v.","phonetic":"[ˈpætnt]","meaning":"專利；取得專利","definition":"an official right to be the only maker or seller of a new invention","collocations":["apply for a patent","hold a patent","patent an invention"],"example":"The company filed a patent for its new device.","exampleZh":"這家公司為其新裝置申請了專利。","synonyms":[],"level":5,"theme":"商業與金錢","examples":[{"en":"The company filed a patent for its new device.","zh":"這家公司為其新裝置申請了專利。"},{"en":"The young inventor applied for a patent on her clever design.","zh":"這位年輕的發明家為她巧妙的設計申請專利。"},{"en":"The company holds a patent for a new kind of battery.","zh":"這家公司擁有一種新型電池的專利。"}]},{"word":"path","pos":"n.","phonetic":"[pæθ]","meaning":"小徑；路徑","definition":"a way or track for walking","collocations":["walking path","career path","follow a path"],"example":"They followed a narrow path through the forest.","exampleZh":"他們沿著一條狹窄的小徑穿過森林。","synonyms":["trail","route"],"level":2,"theme":"交通與旅行","examples":[{"en":"They followed a narrow path through the forest.","zh":"他們沿著一條狹窄的小徑穿過森林。"},{"en":"A winding path led up the hill to the old temple.","zh":"一條蜿蜒的小徑通往山上的古老寺廟。"},{"en":"Choosing to study medicine set her on a new career path.","zh":"選擇讀醫學讓她走上了新的職涯道路。"}]},{"word":"pathetic","pos":"adj.","phonetic":"[pəˈθɛtɪk]","meaning":"可憐的；悲慘的；差勁的","definition":"arousing pity, or so poor in quality as to be contemptible","collocations":["a pathetic excuse","look pathetic","a pathetic attempt"],"example":"His excuse for being late sounded pathetic.","exampleZh":"他遲到的藉口聽起來很可憐、很爛。","synonyms":["pitiful"],"level":5,"theme":"情緒與感受","examples":[{"en":"His excuse for being late sounded pathetic.","zh":"他遲到的藉口聽起來很可憐、很爛。"},{"en":"The lost puppy gave a pathetic little cry in the rain.","zh":"迷路的小狗在雨中發出可憐的細小哀鳴。"},{"en":"His attempt to fix the bike was a rather pathetic effort.","zh":"他修腳踏車的嘗試是個相當差勁的努力。"}]},{"word":"pathway","pos":"n.","phonetic":"[ˈpæθˌwe]","meaning":"小徑；途徑","definition":"a path or route, often figurative for a way of achieving something","collocations":["a garden pathway","a pathway to success","follow a pathway"],"example":"A narrow pathway led through the forest.","exampleZh":"一條狹窄的小徑穿越森林。","synonyms":["path","route"],"level":3,"theme":"交通與旅行","examples":[{"en":"A narrow pathway led through the forest.","zh":"一條狹窄的小徑穿越森林。"},{"en":"A stone pathway wound gently through the peaceful garden.","zh":"一條石子小徑輕柔地蜿蜒穿過寧靜的花園。"},{"en":"Hard work and study can be a pathway to success.","zh":"努力與學習可以是通往成功的途徑。"}]},{"word":"patience","pos":"n.","phonetic":"[ˈpeʃəns]","meaning":"耐心","definition":"the ability to wait calmly without getting upset","collocations":["have patience","lose patience","test one's patience"],"example":"Teaching young children requires great patience.","exampleZh":"教導年幼的孩子需要極大的耐心。","synonyms":[],"level":3,"theme":"情緒與感受","examples":[{"en":"Teaching young children requires great patience.","zh":"教導年幼的孩子需要極大的耐心。"},{"en":"Learning a new language takes a lot of patience and practice.","zh":"學習一種新語言需要很多耐心和練習。"},{"en":"The long wait in line finally tested my patience.","zh":"漫長的排隊等待終於考驗了我的耐心。"}]},{"word":"patient","pos":"adj. / n.","phonetic":"[ˈpeʃənt]","meaning":"有耐心的；病人","definition":"able to wait calmly; a person receiving medical treatment","collocations":["be patient with","patient care","hospital patient"],"example":"The nurse took good care of every patient.","exampleZh":"護理師悉心照顧每一位病人。","synonyms":["tolerant"],"level":2,"theme":"身體與健康","examples":[{"en":"The nurse took good care of every patient.","zh":"護理師悉心照顧每一位病人。"},{"en":"Please be patient with children who are still learning to read.","zh":"對還在學習閱讀的孩子請有耐心。"},{"en":"The doctor spoke gently with each patient in the waiting room.","zh":"醫生溫和地與候診室裡的每位病人交談。"}]},{"word":"patio","pos":"n.","phonetic":"[ˈpætiˌo]","meaning":"露台；庭院","definition":"a paved outdoor area next to a house, used for sitting or eating","collocations":["a backyard patio","sit on the patio","patio furniture"],"example":"We had dinner on the patio under the stars.","exampleZh":"我們在星空下的露台上吃晚餐。","synonyms":["terrace"],"level":3,"theme":"居家與生活","examples":[{"en":"We had dinner on the patio under the stars.","zh":"我們在星空下的露台上吃晚餐。"},{"en":"We enjoyed our morning coffee on the sunny back patio.","zh":"我們在陽光普照的後院露台上享用早晨的咖啡。"},{"en":"They arranged new patio furniture for the summer barbecue.","zh":"他們為夏日烤肉擺放了新的露台家具。"}]},{"word":"patriot","pos":"n.","phonetic":"[ˈpetriət]","meaning":"愛國者","definition":"a person who loves and strongly supports their country","collocations":["a true patriot","patriot spirit","proud patriot"],"example":"The soldier was hailed as a true patriot.","exampleZh":"這名士兵被譽為真正的愛國者。","synonyms":[],"level":5,"theme":"政治與法律","examples":[{"en":"The soldier was hailed as a true patriot.","zh":"這名士兵被譽為真正的愛國者。"},{"en":"A true patriot works hard to make his country better.","zh":"一位真正的愛國者努力讓自己的國家變得更好。"},{"en":"The old soldier was remembered as a brave patriot.","zh":"那位老兵被銘記為一位勇敢的愛國者。"}]},{"word":"patriotic","pos":"adj.","phonetic":"[ˌpetriˈɑtɪk]","meaning":"愛國的","definition":"having or showing great love for one's country","collocations":["patriotic song","patriotic feelings","patriotic duty"],"example":"They sang a patriotic song during the ceremony.","exampleZh":"他們在典禮上唱了一首愛國歌曲。","synonyms":[],"level":5,"theme":"政治與法律","examples":[{"en":"They sang a patriotic song during the ceremony.","zh":"他們在典禮上唱了一首愛國歌曲。"},{"en":"The students sang a patriotic song during the flag ceremony.","zh":"學生們在升旗典禮上唱了一首愛國歌曲。"},{"en":"Many people felt patriotic pride during the national holiday.","zh":"許多人在國定假日感受到愛國的自豪。"}]},{"word":"patrol","pos":"n. / v.","phonetic":"[pəˈtrol]","meaning":"巡邏","definition":"to walk or travel around an area to check for trouble","collocations":["police patrol","patrol the streets","on patrol"],"example":"Police officers patrol the neighborhood every night.","exampleZh":"警察每晚在社區巡邏。","synonyms":["guard"],"level":4,"theme":"政治與法律","examples":[{"en":"Police officers patrol the neighborhood every night.","zh":"警察每晚在社區巡邏。"},{"en":"Two guards patrol the park entrance throughout the night.","zh":"兩名警衛整夜巡邏公園入口。"},{"en":"A police patrol keeps the quiet neighborhood safe and calm.","zh":"一支警察巡邏隊守護著寧靜安全的社區。"}]},{"word":"pattern","pos":"n.","phonetic":"[ˈpætɚn]","meaning":"圖案；模式","definition":"a repeated design or a regular way something happens","collocations":["weather pattern","floral pattern","behavior pattern"],"example":"The dress has a beautiful floral pattern.","exampleZh":"這件洋裝有漂亮的花卉圖案。","synonyms":["design","model"],"level":3,"theme":"性質與描述","examples":[{"en":"The dress has a beautiful floral pattern.","zh":"這件洋裝有漂亮的花卉圖案。"},{"en":"The scarf had a bright floral pattern of red and yellow.","zh":"這條圍巾有著紅黃相間的鮮豔花朵圖案。"},{"en":"Scientists studied the changing weather pattern over the ocean.","zh":"科學家研究了海洋上空變化的天氣模式。"}]},{"word":"pause","pos":"v. / n.","phonetic":"[pɔz]","meaning":"暫停","definition":"to stop for a short time before continuing","collocations":["pause a video","brief pause","pause for a moment"],"example":"She paused for a moment before answering.","exampleZh":"她停頓了一下才回答。","synonyms":["stop","halt"],"level":3,"theme":"動作與行為","examples":[{"en":"She paused for a moment before answering.","zh":"她停頓了一下才回答。"},{"en":"She paused for a moment to catch her breath before speaking.","zh":"她停頓片刻喘口氣，然後才開口說話。"},{"en":"He pressed a button to pause the video and take notes.","zh":"他按下按鈕暫停影片並做筆記。"}]},{"word":"pave","pos":"v.","phonetic":"[pev]","meaning":"鋪設；為...鋪路","definition":"to cover a surface with a hard material such as stone","collocations":["pave the way","pave a road","paved street"],"example":"This achievement paved the way for future success.","exampleZh":"這項成就為未來的成功鋪路。","synonyms":["surface"],"level":5,"theme":"交通與旅行","examples":[{"en":"This achievement paved the way for future success.","zh":"這項成就為未來的成功鋪路。"},{"en":"Workers came to pave the muddy road with smooth stones.","zh":"工人們來用平滑的石頭鋪設泥濘的道路。"},{"en":"Her early research helped pave the way for later discoveries.","zh":"她早期的研究為後來的發現鋪了路。"}]},{"word":"pavement","pos":"n.","phonetic":"[ˈpevmənt]","meaning":"人行道；路面","definition":"a hard-surfaced area for walking beside a road","collocations":["walk on the pavement","wet pavement","cracked pavement"],"example":"Children were playing hopscotch on the pavement.","exampleZh":"孩子們在人行道上玩跳房子。","synonyms":["sidewalk"],"level":5,"theme":"交通與旅行","examples":[{"en":"Children were playing hopscotch on the pavement.","zh":"孩子們在人行道上玩跳房子。"},{"en":"After the rain, the pavement was slippery and wet.","zh":"雨後的人行道又濕又滑。"},{"en":"The children drew colorful pictures on the pavement with chalk.","zh":"孩子們用粉筆在人行道上畫了色彩繽紛的圖畫。"}]},{"word":"paw","pos":"n.","phonetic":"[pɔ]","meaning":"爪子","definition":"the foot of an animal that has claws","collocations":["dog's paw","paw print","shake a paw"],"example":"The dog offered its paw for a shake.","exampleZh":"這隻狗伸出爪子要握手。","synonyms":[],"level":3,"theme":"動物與植物","examples":[{"en":"The dog offered its paw for a shake.","zh":"這隻狗伸出爪子要握手。"},{"en":"The cat lifted one soft paw and touched the window.","zh":"貓抬起一隻柔軟的爪子碰了碰窗戶。"},{"en":"We followed the muddy paw prints across the kitchen floor.","zh":"我們順著廚房地板上泥濘的爪印一路走。"}]},{"word":"pay","pos":"v. / n.","phonetic":"[pe]","meaning":"支付；薪水","definition":"to give money for something; wages","collocations":["pay a bill","pay attention","monthly pay"],"example":"He always pays his bills on time.","exampleZh":"他總是準時繳付帳單。","synonyms":["compensate","wage"],"level":1,"theme":"商業與金錢","examples":[{"en":"He always pays his bills on time.","zh":"他總是準時繳付帳單。"},{"en":"You should pay close attention to the teacher's instructions.","zh":"你應該密切注意老師的指示。"},{"en":"His monthly pay is enough to cover rent and food.","zh":"他每月的薪水足以支付房租和伙食。"}]},{"word":"payment","pos":"n.","phonetic":"[ˈpemənt]","meaning":"付款；支付","definition":"an amount of money paid for something","collocations":["monthly payment","make a payment","payment method"],"example":"The store accepts payment by credit card.","exampleZh":"這家店接受信用卡付款。","synonyms":["fee"],"level":2,"theme":"商業與金錢","examples":[{"en":"The store accepts payment by credit card.","zh":"這家店接受信用卡付款。"},{"en":"The shop accepts payment by cash, card, or mobile phone.","zh":"這家店接受現金、卡片或手機付款。"},{"en":"She makes a small monthly payment to buy the new laptop.","zh":"她每月付一小筆款項來購買新筆電。"}]},{"word":"peace","pos":"n.","phonetic":"[pis]","meaning":"和平；平靜","definition":"freedom from war or disturbance","collocations":["world peace","peace of mind","live in peace"],"example":"The two countries finally signed a peace agreement.","exampleZh":"這兩個國家終於簽署了和平協議。","synonyms":["harmony"],"level":2,"theme":"政治與法律","examples":[{"en":"The two countries finally signed a peace agreement.","zh":"這兩個國家終於簽署了和平協議。"},{"en":"After the long war, both nations longed for lasting peace.","zh":"經過漫長的戰爭後，兩國都渴望持久的和平。"},{"en":"Reading quietly in the garden gives her real peace of mind.","zh":"在花園裡安靜地閱讀讓她真正感到內心平靜。"}]},{"word":"peaceful","pos":"adj.","phonetic":"[ˈpisfəl]","meaning":"和平的；平靜的","definition":"calm and quiet, without violence","collocations":["peaceful village","peaceful protest","peaceful sleep"],"example":"They live in a peaceful little village.","exampleZh":"他們住在一個寧靜的小村莊。","synonyms":["calm","tranquil"],"level":2,"theme":"性質與描述","examples":[{"en":"They live in a peaceful little village.","zh":"他們住在一個寧靜的小村莊。"},{"en":"The lake looked calm and peaceful in the early morning light.","zh":"清晨的光線下，湖面顯得平靜安詳。"},{"en":"Thousands joined the peaceful protest to ask for cleaner air.","zh":"成千上萬的人加入和平抗議，要求更乾淨的空氣。"}]},{"word":"peach","pos":"n.","phonetic":"[pitʃ]","meaning":"桃子","definition":"a soft, round fruit with fuzzy pink-yellow skin","collocations":["ripe peach","peach tree","peach juice"],"example":"She bought a basket of fresh peaches at the market.","exampleZh":"她在市場買了一籃新鮮的桃子。","synonyms":[],"level":2,"theme":"食物與烹飪","examples":[{"en":"She bought a basket of fresh peaches at the market.","zh":"她在市場買了一籃新鮮的桃子。"},{"en":"She bit into a ripe peach and juice ran down her hand.","zh":"她咬了一口成熟的桃子，汁液順著手流下來。"},{"en":"A tall peach tree stood in the corner of the orchard.","zh":"一棵高大的桃樹立在果園的角落。"}]},{"word":"peacock","pos":"n.","phonetic":"[ˈpiˌkɑk]","meaning":"孔雀","definition":"a large bird with brightly colored tail feathers","collocations":["peacock feather","male peacock","peacock display"],"example":"The peacock spread its beautiful tail feathers.","exampleZh":"孔雀展開牠美麗的尾羽。","synonyms":[],"level":3,"theme":"動物與植物","examples":[{"en":"The peacock spread its beautiful tail feathers.","zh":"孔雀展開牠美麗的尾羽。"},{"en":"The male peacock spread its bright tail to attract attention.","zh":"雄孔雀展開牠亮麗的尾羽以吸引注意。"},{"en":"A single peacock feather lay on the garden path.","zh":"一根孔雀羽毛落在花園的小徑上。"}]},{"word":"peak","pos":"n. / v.","phonetic":"[pik]","meaning":"山頂；頂峰；達到高峰","definition":"the pointed top of a mountain; the highest point","collocations":["mountain peak","reach a peak","peak season"],"example":"They finally reached the peak of the mountain.","exampleZh":"他們終於登上山頂。","synonyms":["summit"],"level":4,"theme":"自然與環境","examples":[{"en":"They finally reached the peak of the mountain.","zh":"他們終於登上山頂。"},{"en":"After hours of climbing, they finally reached the snowy peak.","zh":"經過數小時的攀爬，他們終於抵達白雪覆蓋的山頂。"},{"en":"Hotel prices always rise during the busy peak season.","zh":"飯店價格在繁忙的旺季總是上漲。"}]},{"word":"peanut","pos":"n.","phonetic":"[ˈpiˌnʌt]","meaning":"花生","definition":"a small nut-like seed that grows underground","collocations":["peanut butter","roasted peanuts","peanut allergy"],"example":"He spread peanut butter on his toast.","exampleZh":"他在吐司上塗了花生醬。","synonyms":[],"level":2,"theme":"食物與烹飪","examples":[{"en":"He spread peanut butter on his toast.","zh":"他在吐司上塗了花生醬。"},{"en":"He spread peanut butter thickly on his warm toast.","zh":"他在溫熱的吐司上厚厚地塗了花生醬。"},{"en":"Some children have a serious peanut allergy, so be careful.","zh":"有些孩子對花生嚴重過敏，所以要小心。"}]},{"word":"pear","pos":"n.","phonetic":"[pɛr]","meaning":"梨子","definition":"a sweet fruit that is round at the bottom and narrow at the top","collocations":["juicy pear","pear tree","pear juice"],"example":"She sliced a pear for the fruit salad.","exampleZh":"她切了一顆梨子做水果沙拉。","synonyms":[],"level":1,"theme":"食物與烹飪","examples":[{"en":"She sliced a pear for the fruit salad.","zh":"她切了一顆梨子做水果沙拉。"},{"en":"She peeled a juicy pear and shared it with her friend.","zh":"她削了一顆多汁的梨子，和朋友分著吃。"},{"en":"The pear tree in our yard produces sweet fruit each autumn.","zh":"我們院子裡的梨樹每年秋天都結出甜美的果實。"}]},{"word":"pearl","pos":"n.","phonetic":"[pɝl]","meaning":"珍珠","definition":"a small, hard, shiny white ball formed inside an oyster","collocations":["pearl necklace","string of pearls","precious pearl"],"example":"She wore a beautiful pearl necklace to the wedding.","exampleZh":"她在婚禮上戴了一條漂亮的珍珠項鍊。","synonyms":[],"level":3,"theme":"服裝與外表","examples":[{"en":"She wore a beautiful pearl necklace to the wedding.","zh":"她在婚禮上戴了一條漂亮的珍珠項鍊。"},{"en":"The diver found a shining pearl hidden inside the oyster.","zh":"潛水員在牡蠣裡發現一顆閃亮的珍珠。"},{"en":"She fastened a string of white pearls around her neck.","zh":"她在脖子上繫上一串白色珍珠。"}]},{"word":"peasant","pos":"n.","phonetic":"[ˈpɛzənt]","meaning":"農民；佃農","definition":"a poor farmer of low social class, especially in the past","collocations":["peasant farmer","peasant life","poor peasant"],"example":"In the past, many peasants worked on the landlord's fields.","exampleZh":"過去許多農民在地主的田裡耕作。","synonyms":["farmer"],"level":5,"theme":"社會與文化","examples":[{"en":"In the past, many peasants worked on the landlord's fields.","zh":"過去許多農民在地主的田裡耕作。"},{"en":"Long ago, a poor peasant worked from sunrise to sunset.","zh":"很久以前，一位貧窮的農民從日出工作到日落。"},{"en":"The story described the hard life of peasant farmers.","zh":"這個故事描述了佃農艱苦的生活。"}]},{"word":"pebble","pos":"n.","phonetic":"[ˈpɛbl̩]","meaning":"小圓石；卵石","definition":"a small smooth stone found on a beach or riverbed","collocations":["skip a pebble","pebble beach","smooth pebble"],"example":"He threw a pebble into the pond and watched the ripples.","exampleZh":"他把一顆小石子丟進池塘，看著水波蕩漾。","synonyms":["stone"],"level":4,"theme":"自然與環境","examples":[{"en":"He threw a pebble into the pond and watched the ripples.","zh":"他把一顆小石子丟進池塘，看著水波蕩漾。"},{"en":"He picked up a smooth pebble and skipped it across the water.","zh":"他撿起一顆光滑的小圓石，讓它在水面上打水漂。"},{"en":"The children collected shiny pebbles along the quiet beach.","zh":"孩子們沿著寧靜的海灘撿拾閃亮的卵石。"}]},{"word":"peck","pos":"v. / n.","phonetic":"[pɛk]","meaning":"啄食；輕啄","definition":"to strike or bite at something with a beak","collocations":["peck at food","a peck on the cheek","hens pecking"],"example":"The hen pecked at the grain on the ground.","exampleZh":"母雞啄食著地上的穀粒。","synonyms":[],"level":3,"theme":"動物與植物","examples":[{"en":"The hen pecked at the grain on the ground.","zh":"母雞啄食著地上的穀粒。"},{"en":"The little birds began to peck at the seeds on the ground.","zh":"小鳥們開始啄食地上的種子。"},{"en":"She gave her grandmother a quick peck on the cheek.","zh":"她在奶奶臉頰上輕輕一吻。"}]},{"word":"peculiar","pos":"adj.","phonetic":"[pɪˈkjuljɚ]","meaning":"奇怪的；獨特的","definition":"strange or unusual","collocations":["peculiar smell","rather peculiar","peculiar to"],"example":"There was a peculiar smell coming from the kitchen.","exampleZh":"廚房傳來一股奇怪的味道。","synonyms":["strange","odd"],"level":5,"theme":"性質與描述","examples":[{"en":"There was a peculiar smell coming from the kitchen.","zh":"廚房傳來一股奇怪的味道。"},{"en":"A peculiar smell drifted out of the science laboratory.","zh":"一股奇怪的味道從科學實驗室飄了出來。"},{"en":"He has a peculiar habit of humming while he studies.","zh":"他有個奇特的習慣，讀書時會哼歌。"}]},{"word":"pedal","pos":"n. / v.","phonetic":"[ˈpɛdl̩]","meaning":"踏板；踩踏板","definition":"a lever operated by the foot on a bicycle or vehicle","collocations":["bicycle pedal","brake pedal","pedal fast"],"example":"He pedaled hard to reach the top of the hill.","exampleZh":"他用力踩踏板騎上山頂。","synonyms":[],"level":4,"theme":"交通與旅行","examples":[{"en":"He pedaled hard to reach the top of the hill.","zh":"他用力踩踏板騎上山頂。"},{"en":"She pushed hard on the pedal to climb the steep hill.","zh":"她用力踩踏板才爬上那陡峭的山坡。"},{"en":"The driver quickly pressed the brake pedal to stop the car.","zh":"駕駛迅速踩下煞車踏板讓車停下。"}]},{"word":"pedestrian","pos":"n. / adj.","phonetic":"[pəˈdɛstriən]","meaning":"行人；徒步的","definition":"a person walking rather than traveling in a vehicle","collocations":["pedestrian crossing","yield to pedestrians","a pedestrian zone"],"example":"Drivers must stop for pedestrians at the crossing.","exampleZh":"駕駛人在行人穿越道必須讓行人先行。","synonyms":["walker"],"level":4,"theme":"交通與旅行","examples":[{"en":"Drivers must stop for pedestrians at the crossing.","zh":"駕駛人在行人穿越道必須讓行人先行。"},{"en":"Cars must slow down and let the pedestrian cross safely.","zh":"車輛必須減速，讓行人安全通過。"},{"en":"This busy street has a wide pedestrian zone with no traffic.","zh":"這條繁忙的街道有一個沒有車輛的寬闊行人徒步區。"}]},{"word":"peel","pos":"v. / n.","phonetic":"[pil]","meaning":"剝皮；果皮","definition":"to remove the outer skin of a fruit or vegetable","collocations":["peel an apple","banana peel","orange peel"],"example":"She peeled the apple before slicing it.","exampleZh":"她先削蘋果皮再切片。","synonyms":["skin"],"level":3,"theme":"食物與烹飪","examples":[{"en":"She peeled the apple before slicing it.","zh":"她先削蘋果皮再切片。"},{"en":"Please peel the oranges before you put them in the bowl.","zh":"請把柳橙剝皮後再放進碗裡。"},{"en":"Someone slipped on a banana peel left on the floor.","zh":"有人踩到地上留著的香蕉皮而滑倒。"}]},{"word":"peep","pos":"v. / n.","phonetic":"[pip]","meaning":"偷看；窺視","definition":"to look quickly and secretly at something","collocations":["peep through","take a peep","peep hole"],"example":"He peeped through the curtains to see who was outside.","exampleZh":"他從窗簾縫隙偷看外面是誰。","synonyms":["peek","glance"],"level":4,"theme":"動作與行為","examples":[{"en":"He peeped through the curtains to see who was outside.","zh":"他從窗簾縫隙偷看外面是誰。"},{"en":"The curious child peeped through the fence to see the horses.","zh":"好奇的孩子從籬笆縫偷看那些馬。"},{"en":"She took a quick peep at the gift before hiding it again.","zh":"她偷瞄了一眼禮物，然後又把它藏起來。"}]},{"word":"peer","pos":"n. / v.","phonetic":"[pɪr]","meaning":"同輩；仔細看","definition":"a person of the same age or status; to look closely","collocations":["peer pressure","peer group","peer at"],"example":"Teenagers often feel peer pressure to fit in.","exampleZh":"青少年常常感受到同儕壓力而想融入群體。","synonyms":["equal"],"level":4,"theme":"人物與家庭","examples":[{"en":"Teenagers often feel peer pressure to fit in.","zh":"青少年常常感受到同儕壓力而想融入群體。"},{"en":"Many teenagers feel peer pressure to wear the latest fashion.","zh":"許多青少年感受到穿最新流行服飾的同儕壓力。"},{"en":"She peered closely at the map to find the small village.","zh":"她仔細端詳地圖，尋找那個小村莊。"}]},{"word":"peg","pos":"n. / v.","phonetic":"[pɛɡ]","meaning":"掛鉤；木釘；釘住","definition":"a short pin or hook used for hanging things or fastening something","collocations":["hang on a peg","a clothes peg","peg down a tent"],"example":"She hung her coat on the peg by the door.","exampleZh":"她把外套掛在門邊的掛鉤上。","synonyms":["hook"],"level":3,"theme":"居家與生活","examples":[{"en":"She hung her coat on the peg by the door.","zh":"她把外套掛在門邊的掛鉤上。"},{"en":"He hung his wet coat on a wooden peg by the door.","zh":"他把濕外套掛在門邊的木掛鉤上。"},{"en":"We used a peg to fasten the tent firmly to the ground.","zh":"我們用木釘把帳篷牢牢固定在地上。"}]},{"word":"pen","pos":"n.","phonetic":"[pɛn]","meaning":"筆；鋼筆","definition":"a tool used for writing with ink","collocations":["pen and paper","ballpoint pen","pen pal"],"example":"She signed the letter with a blue pen.","exampleZh":"她用藍色的筆簽了那封信。","synonyms":[],"level":1,"theme":"教育與學習","examples":[{"en":"She signed the letter with a blue pen.","zh":"她用藍色的筆簽了那封信。"},{"en":"He borrowed a blue pen to fill out the application form.","zh":"他借了一支藍筆來填寫申請表。"},{"en":"A good pen and clean paper make writing more enjoyable.","zh":"一支好筆和乾淨的紙讓書寫更愉快。"}]},{"word":"penalty","pos":"n.","phonetic":"[ˈpɛnl̩ti]","meaning":"處罰；罰款；罰球","definition":"a punishment for breaking a rule or law","collocations":["death penalty","pay a penalty","penalty kick"],"example":"The player was given a penalty for the foul.","exampleZh":"這名球員因犯規被判罰。","synonyms":["punishment","fine"],"level":5,"theme":"政治與法律","examples":[{"en":"The player was given a penalty for the foul.","zh":"這名球員因犯規被判罰。"},{"en":"The referee gave the team a penalty for the rough tackle.","zh":"裁判因為那次粗暴的鏟球判給該隊一次罰球。"},{"en":"Drivers who ignore the red light must pay a heavy penalty.","zh":"闖紅燈的駕駛必須繳交高額罰款。"}]},{"word":"pencil","pos":"n.","phonetic":"[ˈpɛnsl̩]","meaning":"鉛筆","definition":"a thin instrument used for writing or drawing","collocations":["sharpen a pencil","pencil case","pencil drawing"],"example":"He drew the picture with a pencil.","exampleZh":"他用鉛筆畫了這幅畫。","synonyms":[],"level":1,"theme":"教育與學習","examples":[{"en":"He drew the picture with a pencil.","zh":"他用鉛筆畫了這幅畫。"},{"en":"Please sharpen your pencil before you start the drawing test.","zh":"開始畫圖測驗前，請把你的鉛筆削尖。"},{"en":"She kept her erasers and pencils neatly in a small case.","zh":"她把橡皮擦和鉛筆整齊地放在小盒子裡。"}]},{"word":"penetrate","pos":"v.","phonetic":"[ˈpɛnəˌtret]","meaning":"穿透；滲透","definition":"to make a way through or into something","collocations":["penetrate the skin","penetrate a market","light penetrates"],"example":"The bullet penetrated the wooden door.","exampleZh":"子彈穿透了木門。","synonyms":["pierce"],"level":6,"theme":"動作與行為","examples":[{"en":"The bullet penetrated the wooden door.","zh":"子彈穿透了木門。"},{"en":"Sunlight could barely penetrate the thick forest leaves.","zh":"陽光幾乎無法穿透茂密的森林樹葉。"},{"en":"The sharp thorn penetrated the skin on her finger.","zh":"尖銳的刺刺穿了她手指的皮膚。"}]},{"word":"peninsula","pos":"n.","phonetic":"[pəˈnɪnsələ]","meaning":"半島","definition":"a piece of land almost surrounded by water","collocations":["Korean peninsula","narrow peninsula","peninsula coastline"],"example":"The Korean Peninsula is surrounded by three seas.","exampleZh":"朝鮮半島被三個海域環繞。","synonyms":[],"level":5,"theme":"自然與環境","examples":[{"en":"The Korean Peninsula is surrounded by three seas.","zh":"朝鮮半島被三個海域環繞。"},{"en":"A narrow peninsula stretched far out into the blue sea.","zh":"一個狹長的半島遠遠伸入蔚藍的大海。"},{"en":"The small fishing town sits at the tip of the peninsula.","zh":"這個小漁村坐落在半島的尖端。"}]},{"word":"penny","pos":"n.","phonetic":"[ˈpɛni]","meaning":"便士；一分錢","definition":"a coin of low value","collocations":["every penny","penny for your thoughts","not a penny"],"example":"He saved every penny he earned.","exampleZh":"他把賺來的每一分錢都存起來。","synonyms":["cent"],"level":2,"theme":"商業與金錢","examples":[{"en":"He saved every penny he earned.","zh":"他把賺來的每一分錢都存起來。"},{"en":"He saved every penny to buy his mother a birthday gift.","zh":"他省下每一分錢為母親買生日禮物。"},{"en":"The old jar was full of shiny copper pennies.","zh":"那個舊罐子裝滿了閃亮的銅便士。"}]},{"word":"pension","pos":"n.","phonetic":"[ˈpɛnʃən]","meaning":"退休金；養老金","definition":"a regular payment made to someone after retirement","collocations":["retirement pension","pension plan","monthly pension"],"example":"He receives a pension after thirty years of work.","exampleZh":"他工作三十年後領取退休金。","synonyms":[],"level":5,"theme":"商業與金錢","examples":[{"en":"He receives a pension after thirty years of work.","zh":"他工作三十年後領取退休金。"},{"en":"After retiring, my grandfather lives comfortably on his pension.","zh":"退休後，我爺爺靠退休金過著舒適的生活。"},{"en":"The company offers a good pension plan to loyal workers.","zh":"這家公司為忠實的員工提供良好的退休金計畫。"}]},{"word":"people","pos":"n.","phonetic":"[ˈpipl̩]","meaning":"人們；人民","definition":"human beings in general or a specific group","collocations":["young people","people say","local people"],"example":"Many people gathered to watch the fireworks.","exampleZh":"許多人聚集觀看煙火。","synonyms":["persons"],"level":1,"theme":"人物與家庭","examples":[{"en":"Many people gathered to watch the fireworks.","zh":"許多人聚集觀看煙火。"},{"en":"Young people today spend many hours on their smartphones.","zh":"現在的年輕人花很多時間在智慧型手機上。"},{"en":"Local people welcomed the visitors with warm smiles.","zh":"當地人以溫暖的笑容歡迎訪客。"}]},{"word":"pepper","pos":"n.","phonetic":"[ˈpɛpɚ]","meaning":"胡椒；辣椒","definition":"a spice used to flavor food, or a type of vegetable","collocations":["black pepper","salt and pepper","bell pepper"],"example":"Add a little salt and pepper to the soup.","exampleZh":"在湯裡加一點鹽和胡椒。","synonyms":[],"level":2,"theme":"食物與烹飪","examples":[{"en":"Add a little salt and pepper to the soup.","zh":"在湯裡加一點鹽和胡椒。"},{"en":"Sprinkle a little black pepper over the fried eggs.","zh":"在煎蛋上撒一點黑胡椒。"},{"en":"She chopped a red bell pepper for the fresh salad.","zh":"她切了一顆紅甜椒放進新鮮沙拉裡。"}]},{"word":"perceive","pos":"v.","phonetic":"[pɚˈsiv]","meaning":"察覺；認為","definition":"to become aware of something through the senses; to interpret","collocations":["perceive as","perceive a threat","widely perceived"],"example":"She was perceived as a confident leader.","exampleZh":"她被視為一位有自信的領導者。","synonyms":["notice","sense"],"level":5,"theme":"抽象概念","examples":[{"en":"She was perceived as a confident leader.","zh":"她被視為一位有自信的領導者。"},{"en":"Children often perceive the world differently from adults.","zh":"孩子對世界的感知往往與成人不同。"},{"en":"The dog quickly perceived a stranger near the front gate.","zh":"那隻狗很快察覺到前門附近有陌生人。"}]},{"word":"percent","pos":"n.","phonetic":"[pɚˈsɛnt]","meaning":"百分之...","definition":"one part in every hundred","collocations":["fifty percent","percent off","percent increase"],"example":"Fifty percent of the students passed the test.","exampleZh":"百分之五十的學生通過了測驗。","synonyms":[],"level":3,"theme":"科學與數學","examples":[{"en":"Fifty percent of the students passed the test.","zh":"百分之五十的學生通過了測驗。"},{"en":"Almost ninety percent of the class enjoyed the field trip.","zh":"幾乎百分之九十的同學都喜歡這次校外教學。"},{"en":"The store offered every item at twenty percent off today.","zh":"這家店今天所有商品都打八折。"}]},{"word":"percentage","pos":"n.","phonetic":"[pɚˈsɛntɪdʒ]","meaning":"百分比","definition":"a rate or proportion per hundred","collocations":["small percentage","percentage increase","calculate a percentage"],"example":"A large percentage of the budget goes to education.","exampleZh":"預算中很大一部分用於教育。","synonyms":["proportion"],"level":4,"theme":"科學與數學","examples":[{"en":"A large percentage of the budget goes to education.","zh":"預算中很大一部分用於教育。"},{"en":"A high percentage of students walk to school every day.","zh":"很高比例的學生每天步行上學。"},{"en":"The teacher showed us how to calculate a percentage.","zh":"老師教我們如何計算百分比。"}]},{"word":"perception","pos":"n.","phonetic":"[pɚˈsɛpʃən]","meaning":"知覺；看法；感知","definition":"the way something is understood or interpreted, or the ability to notice something","collocations":["public perception","change perception","perception of reality"],"example":"Public perception of the issue has changed over time.","exampleZh":"大眾對這個議題的看法已隨時間改變。","synonyms":["insight"],"level":5,"theme":"抽象概念","examples":[{"en":"Public perception of the issue has changed over time.","zh":"大眾對這個議題的看法已隨時間改變。"},{"en":"Travel can change your perception of other cultures.","zh":"旅行能改變你對其他文化的看法。"},{"en":"Good lighting affects our perception of colors in a room.","zh":"良好的照明會影響我們對房間裡顏色的感知。"}]},{"word":"perfect","pos":"adj. / v.","phonetic":"[ˈpɝfɪkt]","meaning":"完美的；使完美","definition":"having no flaws or mistakes; complete","collocations":["perfect score","perfect day","perfect one's skills"],"example":"She got a perfect score on the math test.","exampleZh":"她在數學考試中得到滿分。","synonyms":["flawless"],"level":2,"theme":"性質與描述","examples":[{"en":"She got a perfect score on the math test.","zh":"她在數學考試中得到滿分。"},{"en":"Sunny skies made it a perfect day for the beach.","zh":"晴朗的天空讓這一天成為去海邊的完美日子。"},{"en":"She practiced daily to perfect her skills on the piano.","zh":"她每天練習以精進她的鋼琴技巧。"}]},{"word":"perform","pos":"v.","phonetic":"[pɚˈfɔrm]","meaning":"表演；執行","definition":"to do an action, task, or piece of work; to entertain an audience","collocations":["perform a song","perform surgery","perform well"],"example":"The band will perform live at the concert tonight.","exampleZh":"這個樂團今晚將在演唱會上現場表演。","synonyms":["carry out","act"],"level":3,"theme":"藝術與音樂","examples":[{"en":"The band will perform live at the concert tonight.","zh":"這個樂團今晚將在演唱會上現場表演。"},{"en":"The choir will perform several songs at the winter concert.","zh":"合唱團將在冬季音樂會上演唱幾首歌。"},{"en":"He worked hard so that he could perform well on the exam.","zh":"他努力用功，好在考試中表現優異。"}]},{"word":"performance","pos":"n.","phonetic":"[pɚˈfɔrməns]","meaning":"表演；表現；績效","definition":"an act of performing, or how well someone does something","collocations":["live performance","job performance","give a performance"],"example":"The audience gave the actors a standing ovation after the performance.","exampleZh":"觀眾在表演結束後起立為演員鼓掌。","synonyms":["show"],"level":3,"theme":"藝術與音樂","examples":[{"en":"The audience gave the actors a standing ovation after the performance.","zh":"觀眾在表演結束後起立為演員鼓掌。"},{"en":"The dancers' graceful performance amazed the entire audience.","zh":"舞者優雅的表演讓全場觀眾驚豔。"},{"en":"Her strong performance at work earned her a promotion.","zh":"她在工作上的優異表現讓她獲得升遷。"}]},{"word":"perfume","pos":"n.","phonetic":"[ˈpɝfjum]","meaning":"香水","definition":"a liquid with a pleasant smell worn on the skin","collocations":["wear perfume","spray perfume","bottle of perfume"],"example":"She wore a light floral perfume to the party.","exampleZh":"她去派對時擦了淡淡的花香香水。","synonyms":["fragrance"],"level":3,"theme":"服裝與外表","examples":[{"en":"She wore a light floral perfume to the party.","zh":"她去派對時擦了淡淡的花香香水。"},{"en":"She sprayed a little perfume on her wrists before leaving.","zh":"出門前她在手腕上噴了一點香水。"},{"en":"The whole room smelled of sweet flower perfume.","zh":"整個房間都瀰漫著甜美的花香水味。"}]},{"word":"perhaps","pos":"adv.","phonetic":"[pɚˈhæps]","meaning":"也許；或許","definition":"used to express possibility; maybe","collocations":["perhaps not","perhaps because","perhaps later"],"example":"Perhaps we should wait until tomorrow to decide.","exampleZh":"或許我們應該等到明天再做決定。","synonyms":["maybe","possibly"],"level":2,"theme":"抽象概念","examples":[{"en":"Perhaps we should wait until tomorrow to decide.","zh":"或許我們應該等到明天再做決定。"},{"en":"Perhaps we should leave early to avoid the heavy traffic.","zh":"也許我們該早點出發以避開繁忙的車流。"},{"en":"She is not answering, so perhaps she is already asleep.","zh":"她沒有回應，或許她已經睡著了。"}]},{"word":"peril","pos":"n.","phonetic":"[ˈpɛrəl]","meaning":"危險；風險","definition":"a serious and immediate danger","collocations":["in peril","face peril","the perils of"],"example":"Sailors faced great peril during the storm.","exampleZh":"水手們在暴風雨中面臨極大的危險。","synonyms":["danger"],"level":5,"theme":"抽象概念","examples":[{"en":"Sailors faced great peril during the storm.","zh":"水手們在暴風雨中面臨極大的危險。"},{"en":"The climbers faced great peril as the storm grew stronger.","zh":"隨著暴風雨增強，登山者面臨極大的危險。"},{"en":"The teacher warned us about the perils of careless driving.","zh":"老師警告我們粗心開車的種種危險。"}]},{"word":"perimeter","pos":"n.","phonetic":"[pəˈrɪmətɚ]","meaning":"周長；周界","definition":"the outer boundary of an area or the total length of that boundary","collocations":["the perimeter of a field","patrol the perimeter","secure the perimeter"],"example":"Guards patrolled the perimeter of the base all night.","exampleZh":"警衛整夜巡邏基地的周界。","synonyms":["boundary"],"level":5,"theme":"科學與數學","examples":[{"en":"Guards patrolled the perimeter of the base all night.","zh":"警衛整夜巡邏基地的周界。"},{"en":"We measured the perimeter of the rectangular basketball court.","zh":"我們測量了長方形籃球場的周長。"},{"en":"A tall fence runs along the perimeter of the school.","zh":"一道高牆沿著學校的周界圍繞。"}]},{"word":"perish","pos":"v.","phonetic":"[ˈpɛrɪʃ]","meaning":"死亡；消逝","definition":"to die, especially in a sudden or violent way, or to disappear","collocations":["perish in a fire","perish from hunger","perish without trace"],"example":"Many soldiers perished in the harsh winter.","exampleZh":"許多士兵在嚴酷的冬天喪生。","synonyms":["die"],"level":5,"theme":"抽象概念","examples":[{"en":"Many soldiers perished in the harsh winter.","zh":"許多士兵在嚴酷的冬天喪生。"},{"en":"Without water, the young plants will quickly perish.","zh":"沒有水，這些幼苗很快就會枯死。"},{"en":"Many rare animals could perish if their forests disappear.","zh":"如果森林消失，許多稀有動物可能會滅亡。"}]},{"word":"permanent","pos":"adj.","phonetic":"[ˈpɚmənənt]","meaning":"永久的；固定的","definition":"lasting or intended to last forever or for a long time","collocations":["a permanent job","permanent damage","permanent resident"],"example":"The accident left a permanent scar on his arm.","exampleZh":"這場意外在他手臂上留下了永久的疤痕。","synonyms":["lasting"],"level":4,"theme":"性質與描述","examples":[{"en":"The accident left a permanent scar on his arm.","zh":"這場意外在他手臂上留下了永久的疤痕。"},{"en":"After months of temporary work, she finally found a permanent job.","zh":"做了幾個月的臨時工後，她終於找到一份長期的工作。"},{"en":"The strong sun can cause permanent damage to your eyes.","zh":"強烈的陽光可能對你的眼睛造成永久性傷害。"}]},{"word":"permission","pos":"n.","phonetic":"[pɚˈmɪʃən]","meaning":"許可；允許","definition":"the act of allowing someone to do something","collocations":["ask for permission","grant permission","without permission"],"example":"You need permission to enter this area.","exampleZh":"進入這個區域需要許可。","synonyms":["consent"],"level":3,"theme":"社會與文化","examples":[{"en":"You need permission to enter this area.","zh":"進入這個區域需要許可。"},{"en":"Students must ask for permission before leaving the classroom.","zh":"學生離開教室前必須先請求許可。"},{"en":"He borrowed the bike without permission and got in trouble.","zh":"他未經允許就借用腳踏車，結果惹上麻煩。"}]},{"word":"perpetual","pos":"adj.","phonetic":"[pɚˈpɛtʃuəl]","meaning":"永恆的；不斷的","definition":"never ending or changing","collocations":["perpetual motion","a perpetual smile","perpetual noise"],"example":"The city seems to be in a state of perpetual traffic.","exampleZh":"這座城市似乎總是處於不斷的塞車狀態。","synonyms":["eternal","constant"],"level":6,"theme":"性質與描述","examples":[{"en":"The city seems to be in a state of perpetual traffic.","zh":"這座城市似乎總是處於不斷的塞車狀態。"},{"en":"The busy market seemed to be in perpetual noise and motion.","zh":"繁忙的市場似乎永遠處於喧鬧與忙碌之中。"},{"en":"A perpetual smile brightened the kind old man's face.","zh":"一抹永恆的微笑照亮了那位和善老人的臉。"}]},{"word":"persist","pos":"v.","phonetic":"[pɚˈsɪst]","meaning":"堅持；持續","definition":"to continue firmly in a course of action despite difficulty or opposition","collocations":["persist in doing something","if symptoms persist","persist with a plan"],"example":"If the pain persists, see a doctor immediately.","exampleZh":"如果疼痛持續，請立刻就醫。","synonyms":["persevere"],"level":5,"theme":"動作與行為","examples":[{"en":"If the pain persists, see a doctor immediately.","zh":"如果疼痛持續，請立刻就醫。"},{"en":"If the cough persists for a week, please see a doctor.","zh":"如果咳嗽持續一週，請去看醫生。"},{"en":"She chose to persist with her plan despite the difficulties.","zh":"儘管困難重重，她仍選擇堅持她的計畫。"}]},{"word":"persistence","pos":"n.","phonetic":"[pɚˈsɪstəns]","meaning":"堅持；毅力","definition":"the quality of continuing firmly despite difficulty","collocations":["show persistence","reward persistence","sheer persistence"],"example":"Her persistence finally paid off when she won the scholarship.","exampleZh":"她的堅持終於得到回報，贏得了獎學金。","synonyms":["perseverance"],"level":5,"theme":"抽象概念","examples":[{"en":"Her persistence finally paid off when she won the scholarship.","zh":"她的堅持終於得到回報，贏得了獎學金。"},{"en":"Her persistence in practicing daily finally improved her grades.","zh":"她每天練習的毅力終於讓她的成績進步。"},{"en":"Solving hard puzzles takes patience and steady persistence.","zh":"解開難題需要耐心與穩定的堅持。"}]},{"word":"personnel","pos":"n.","phonetic":"[ˌpɚsnˈɛl]","meaning":"人員；職員","definition":"the people employed in an organization or the department that deals with them","collocations":["military personnel","personnel department","hire personnel"],"example":"All personnel must wear identification badges.","exampleZh":"所有人員都必須佩戴識別證。","synonyms":["staff"],"level":5,"theme":"工作與職業","examples":[{"en":"All personnel must wear identification badges.","zh":"所有人員都必須佩戴識別證。"},{"en":"All personnel must attend the safety training on Monday.","zh":"所有人員都必須參加週一的安全訓練。"},{"en":"The personnel department handles hiring and staff records.","zh":"人事部門負責招募與員工紀錄。"}]},{"word":"perspective","pos":"n.","phonetic":"[pɚˈspɛktɪv]","meaning":"觀點；透視","definition":"a particular way of looking at or thinking about something","collocations":["from my perspective","gain perspective","a different perspective"],"example":"Traveling abroad gave her a new perspective on life.","exampleZh":"出國旅行讓她對人生有了新的看法。","synonyms":["viewpoint"],"level":5,"theme":"抽象概念","examples":[{"en":"Traveling abroad gave her a new perspective on life.","zh":"出國旅行讓她對人生有了新的看法。"},{"en":"Listening to others can give you a fresh perspective on problems.","zh":"傾聽他人能讓你對問題有全新的觀點。"},{"en":"From my perspective, honesty matters more than winning.","zh":"從我的觀點來看，誠實比獲勝更重要。"}]},{"word":"perspiration","pos":"n.","phonetic":"[ˌpɚspəˈreʃən]","meaning":"汗；出汗","definition":"sweat, especially as produced through physical exertion","collocations":["beads of perspiration","break out in perspiration","wipe perspiration"],"example":"Perspiration ran down his face during the race.","exampleZh":"賽跑時汗水順著他的臉流下。","synonyms":["sweat"],"level":5,"theme":"身體與健康","examples":[{"en":"Perspiration ran down his face during the race.","zh":"賽跑時汗水順著他的臉流下。"},{"en":"Beads of perspiration formed on his forehead during the run.","zh":"跑步時他的額頭上冒出一顆顆汗珠。"},{"en":"She wiped the perspiration from her face with a towel.","zh":"她用毛巾擦去臉上的汗水。"}]},{"word":"persuasion","pos":"n.","phonetic":"[pɚˈsweʒən]","meaning":"說服；說服力","definition":"the act of persuading someone or the ability to persuade","collocations":["the power of persuasion","gentle persuasion","use persuasion"],"example":"It took a lot of persuasion to change his mind.","exampleZh":"花了很多說服的功夫才改變他的想法。","synonyms":[],"level":5,"theme":"溝通與語言","examples":[{"en":"It took a lot of persuasion to change his mind.","zh":"花了很多說服的功夫才改變他的想法。"},{"en":"After much gentle persuasion, he agreed to join the club.","zh":"經過許多溫和的勸說後，他同意加入社團。"},{"en":"A good teacher uses the power of persuasion, not force.","zh":"好老師運用說服力，而非強迫。"}]},{"word":"pessimistic","pos":"adj.","phonetic":"[ˌpɛsəˈmɪstɪk]","meaning":"悲觀的","definition":"tending to expect the worst outcome in any situation","collocations":["a pessimistic outlook","feel pessimistic","pessimistic about the future"],"example":"He's always pessimistic about his exam results.","exampleZh":"他對自己的考試成績總是很悲觀。","synonyms":["negative"],"level":5,"theme":"情緒與感受","examples":[{"en":"He's always pessimistic about his exam results.","zh":"他對自己的考試成績總是很悲觀。"},{"en":"Try not to feel pessimistic about the results before they come.","zh":"在結果出來前，盡量別對它感到悲觀。"},{"en":"He has a pessimistic outlook and expects things to go wrong.","zh":"他的看法悲觀，總預期事情會出錯。"}]},{"word":"pesticide","pos":"n.","phonetic":"[ˈpɛstɪˌsaɪd]","meaning":"殺蟲劑；農藥","definition":"a chemical substance used to kill insects and other pests","collocations":["spray pesticide","organic pesticide","pesticide residue"],"example":"Farmers use pesticide to protect their crops from insects.","exampleZh":"農夫使用殺蟲劑來保護作物免受昆蟲侵害。","synonyms":[],"level":5,"theme":"自然與環境","examples":[{"en":"Farmers use pesticide to protect their crops from insects.","zh":"農夫使用殺蟲劑來保護作物免受昆蟲侵害。"},{"en":"Some farmers choose organic pesticide to protect their crops.","zh":"有些農夫選擇有機農藥來保護他們的作物。"},{"en":"Wash the vegetables well to remove any pesticide residue.","zh":"把蔬菜洗乾淨以去除任何農藥殘留。"}]},{"word":"petal","pos":"n.","phonetic":"[ˈpɛtl]","meaning":"花瓣","definition":"one of the colored outer parts of a flower","collocations":["rose petals","fallen petals","a flower's petal"],"example":"The wind scattered rose petals across the garden.","exampleZh":"風把玫瑰花瓣吹散在花園各處。","synonyms":[],"level":3,"theme":"動物與植物","examples":[{"en":"The wind scattered rose petals across the garden.","zh":"風把玫瑰花瓣吹散在花園各處。"},{"en":"A single pink petal floated gently onto the still pond.","zh":"一片粉紅色的花瓣輕輕飄落在平靜的池塘上。"},{"en":"The rose lost its petals one by one in the wind.","zh":"玫瑰的花瓣在風中一片片地凋落。"}]},{"word":"pick","pos":"v. / n.","phonetic":"[pɪk]","meaning":"挑選；摘；採","definition":"to choose someone or something from a group of people or things","collocations":["pick a winner","pick flowers","pick a fight"],"example":"She picked the reddest apple from the tree.","exampleZh":"她從樹上摘了那顆最紅的蘋果。","synonyms":["choose","select"],"level":1,"theme":"動作與行為","examples":[{"en":"She picked the reddest apple from the tree.","zh":"她從樹上摘了那顆最紅的蘋果。"},{"en":"You may pick any book you like from the library shelf.","zh":"你可以從圖書館的書架上挑選任何你喜歡的書。"},{"en":"We went to the farm to pick strawberries in the morning.","zh":"我們早上去農場採草莓。"}]},{"word":"pickle","pos":"n. / v.","phonetic":"[ˈpɪkl]","meaning":"醃菜；泡菜；使醃漬","definition":"a vegetable, especially a cucumber, preserved in vinegar or salt water","collocations":["dill pickle","pickle vegetables","in a pickle"],"example":"He added a pickle to his sandwich.","exampleZh":"他在三明治裡加了一片醃黃瓜。","synonyms":[],"level":2,"theme":"食物與烹飪","examples":[{"en":"He added a pickle to his sandwich.","zh":"他在三明治裡加了一片醃黃瓜。"},{"en":"He likes to add a crunchy pickle to his hamburger.","zh":"他喜歡在漢堡裡加一片脆脆的酸黃瓜。"},{"en":"Grandma taught us how to pickle cucumbers in salty water.","zh":"奶奶教我們如何用鹽水醃漬小黃瓜。"}]},{"word":"picnic","pos":"n. / v.","phonetic":"[ˈpɪknɪk]","meaning":"野餐","definition":"an occasion when a meal is eaten outdoors, often in a park or forest","collocations":["go on a picnic","pack a picnic","picnic basket"],"example":"We had a picnic by the lake last Sunday.","exampleZh":"我們上星期天在湖邊野餐。","synonyms":["outing"],"level":1,"theme":"運動與休閒","examples":[{"en":"We had a picnic by the lake last Sunday.","zh":"我們上星期天在湖邊野餐。"},{"en":"They packed sandwiches and fruit for a picnic in the park.","zh":"他們準備了三明治和水果去公園野餐。"},{"en":"We spread a checkered cloth and enjoyed a lakeside picnic.","zh":"我們鋪開格子布，享受了一場湖邊野餐。"}]},{"word":"picture","pos":"n. / v.","phonetic":"[ˈpɪktʃɚ]","meaning":"圖畫；照片；想像","definition":"a painting, drawing, or photograph","collocations":["take a picture","draw a picture","picture frame"],"example":"He hung a picture of his family on the wall.","exampleZh":"他把一張家人的照片掛在牆上。","synonyms":["photo","image"],"level":1,"theme":"藝術與音樂","examples":[{"en":"He hung a picture of his family on the wall.","zh":"他把一張家人的照片掛在牆上。"},{"en":"Let's take a picture together in front of the waterfall.","zh":"我們一起在瀑布前拍張照吧。"},{"en":"The child drew a colorful picture of her happy family.","zh":"這孩子畫了一幅色彩繽紛、描繪她幸福家庭的圖畫。"}]},{"word":"piece","pos":"n.","phonetic":"[pis]","meaning":"片；塊；件","definition":"a portion of an object or of material, produced by cutting, tearing, or breaking the whole","collocations":["a piece of cake","piece by piece","break into pieces"],"example":"Could I have a piece of that chocolate cake?","exampleZh":"我可以吃一塊那個巧克力蛋糕嗎？","synonyms":["portion","part"],"level":1,"theme":"性質與描述","examples":[{"en":"Could I have a piece of that chocolate cake?","zh":"我可以吃一塊那個巧克力蛋糕嗎？"},{"en":"Would you like another piece of the homemade apple pie?","zh":"你想再來一塊自製的蘋果派嗎？"},{"en":"The old vase fell and broke into many small pieces.","zh":"那個舊花瓶掉下來，碎成許多小塊。"}]},{"word":"pierce","pos":"v.","phonetic":"[pɪrs]","meaning":"刺穿；穿孔","definition":"to make a hole in something with a sharp pointed object","collocations":["pierce the skin","pierce ears","pierce through"],"example":"The needle pierced the fabric easily.","exampleZh":"那根針輕易地刺穿了布料。","synonyms":["puncture","penetrate"],"level":4,"theme":"動作與行為","examples":[{"en":"The needle pierced the fabric easily.","zh":"那根針輕易地刺穿了布料。"},{"en":"A sharp nail pierced the bottom of his rubber boot.","zh":"一根尖銳的釘子刺穿了他橡膠靴的底部。"},{"en":"The bright headlights pierced through the thick evening fog.","zh":"明亮的車頭燈穿透了濃厚的夜霧。"}]},{"word":"pig","pos":"n.","phonetic":"[pɪg]","meaning":"豬","definition":"a farm animal with a fat body, short legs, and a curly tail, raised for meat","collocations":["raise pigs","pig farm","feed the pigs"],"example":"The farmer keeps several pigs in the barn.","exampleZh":"農夫在穀倉裡養了幾隻豬。","synonyms":["hog","swine"],"level":1,"theme":"動物與植物","examples":[{"en":"The farmer keeps several pigs in the barn.","zh":"農夫在穀倉裡養了幾隻豬。"},{"en":"My uncle raises pigs on a small farm near the river.","zh":"我叔叔在河邊的一座小農場養豬。"},{"en":"Every morning the children help feed the pigs before school.","zh":"每天早上孩子們上學前都會幫忙餵豬。"}]},{"word":"pigeon","pos":"n.","phonetic":"[ˈpɪdʒɪn]","meaning":"鴿子","definition":"a grey bird often seen in cities, that makes a soft cooing sound","collocations":["feed pigeons","carrier pigeon","a flock of pigeons"],"example":"Pigeons gathered around the old man feeding them bread.","exampleZh":"鴿子聚集在餵麵包的老人周圍。","synonyms":["dove"],"level":2,"theme":"動物與植物","examples":[{"en":"Pigeons gathered around the old man feeding them bread.","zh":"鴿子聚集在餵麵包的老人周圍。"},{"en":"A flock of pigeons flew up when the bell rang loudly.","zh":"鐘聲響亮地響起時，一群鴿子飛了起來。"},{"en":"In the past, people used a carrier pigeon to send messages.","zh":"過去，人們用信鴿來傳遞訊息。"}]},{"word":"pile","pos":"n. / v.","phonetic":"[paɪl]","meaning":"一堆；堆積","definition":"a number of things laid or lying one upon another","collocations":["a pile of clothes","pile up","pile on top"],"example":"He left a pile of books on the desk.","exampleZh":"他在桌上留了一堆書。","synonyms":["heap","stack"],"level":2,"theme":"居家與生活","examples":[{"en":"He left a pile of books on the desk.","zh":"他在桌上留了一堆書。"},{"en":"There is a huge pile of clothes waiting to be washed.","zh":"有一大堆衣服等著要洗。"},{"en":"Snow began to pile up on the roof during the storm.","zh":"暴風雪期間，雪開始堆積在屋頂上。"}]},{"word":"pilgrim","pos":"n.","phonetic":"[ˈpɪlgrɪm]","meaning":"朝聖者；香客","definition":"a person who travels to a sacred place for religious reasons","collocations":["religious pilgrim","pilgrims travel","a group of pilgrims"],"example":"Thousands of pilgrims visit the shrine every year.","exampleZh":"每年都有成千上萬的朝聖者造訪這座聖殿。","synonyms":["traveler"],"level":5,"theme":"社會與文化","examples":[{"en":"Thousands of pilgrims visit the shrine every year.","zh":"每年都有成千上萬的朝聖者造訪這座聖殿。"},{"en":"A group of pilgrims walked for days to reach the holy mountain.","zh":"一群朝聖者走了好幾天才抵達那座聖山。"},{"en":"The pilgrims prayed quietly as they entered the ancient temple.","zh":"朝聖者們進入古老的寺廟時安靜地祈禱。"}]},{"word":"pill","pos":"n.","phonetic":"[pɪl]","meaning":"藥丸；藥片","definition":"a small round piece of medicine that you swallow","collocations":["take a pill","sleeping pill","swallow a pill"],"example":"The doctor told her to take one pill after meals.","exampleZh":"醫生要她飯後服用一顆藥丸。","synonyms":["tablet","capsule"],"level":2,"theme":"身體與健康","examples":[{"en":"The doctor told her to take one pill after meals.","zh":"醫生要她飯後服用一顆藥丸。"},{"en":"She took a sleeping pill because she could not fall asleep.","zh":"她因為睡不著而吃了一顆安眠藥。"},{"en":"Remember to swallow the pill with a full glass of water.","zh":"記得配一整杯水把藥丸吞下去。"}]},{"word":"pillar","pos":"n.","phonetic":"[ˈpɪlɚ]","meaning":"柱子；支柱","definition":"a tall vertical structure of stone, wood, or metal, used as a support","collocations":["stone pillar","pillar of society","support pillars"],"example":"The roof was supported by four marble pillars.","exampleZh":"屋頂由四根大理石柱支撐著。","synonyms":["column","post"],"level":4,"theme":"居家與生活","examples":[{"en":"The roof was supported by four marble pillars.","zh":"屋頂由四根大理石柱支撐著。"},{"en":"Huge stone pillars held up the roof of the ancient temple.","zh":"巨大的石柱支撐著這座古老寺廟的屋頂。"},{"en":"My grandfather was regarded as a pillar of the community.","zh":"我的祖父被視為社區的支柱。"}]},{"word":"pillow","pos":"n.","phonetic":"[ˈpɪlo]","meaning":"枕頭","definition":"a cloth bag filled with soft material, used to support the head while sleeping","collocations":["fluffy pillow","pillow case","hug a pillow"],"example":"She fell asleep with her head on the soft pillow.","exampleZh":"她把頭靠在柔軟的枕頭上睡著了。","synonyms":["cushion"],"level":1,"theme":"居家與生活","examples":[{"en":"She fell asleep with her head on the soft pillow.","zh":"她把頭靠在柔軟的枕頭上睡著了。"},{"en":"She hugged a soft pillow while watching the scary movie.","zh":"她看恐怖片時抱著一個柔軟的枕頭。"},{"en":"My mother washed every pillow case before the guests arrived.","zh":"客人來之前，我媽媽把每個枕頭套都洗了。"}]},{"word":"pilot","pos":"n. / v.","phonetic":"[ˈpaɪlət]","meaning":"飛行員；駕駛員；試驗性的","definition":"a person who flies an aircraft","collocations":["airline pilot","pilot a plane","pilot program"],"example":"The pilot landed the plane safely despite the storm.","exampleZh":"儘管有暴風雨，飛行員仍安全地降落了飛機。","synonyms":["aviator"],"level":3,"theme":"工作與職業","examples":[{"en":"The pilot landed the plane safely despite the storm.","zh":"儘管有暴風雨，飛行員仍安全地降落了飛機。"},{"en":"He has dreamed of becoming an airline pilot since childhood.","zh":"他從小就夢想成為一名航空公司的飛行員。"},{"en":"The school started a pilot program to teach coding to beginners.","zh":"學校開始了一個試驗性計畫，教初學者寫程式。"}]},{"word":"pin","pos":"n. / v.","phonetic":"[pɪn]","meaning":"別針；大頭針；釘住","definition":"a small thin piece of metal with a sharp point, used for fastening things","collocations":["safety pin","pin up","pin down"],"example":"She used a pin to fasten the fabric together.","exampleZh":"她用一根大頭針把布料固定在一起。","synonyms":["fasten"],"level":2,"theme":"居家與生活","examples":[{"en":"She used a pin to fasten the fabric together.","zh":"她用一根大頭針把布料固定在一起。"},{"en":"She used a safety pin to hold the torn hem together.","zh":"她用一個安全別針把撕破的褲腳固定在一起。"},{"en":"He pinned the map up on the wall above his desk.","zh":"他把地圖釘在書桌上方的牆上。"}]},{"word":"pinch","pos":"v. / n.","phonetic":"[pɪntʃ]","meaning":"捏；夾；一撮","definition":"to squeeze a small amount of someone's skin between the thumb and finger","collocations":["pinch someone's cheek","a pinch of salt","feel the pinch"],"example":"She pinched the baby's cheek playfully.","exampleZh":"她開玩笑地捏了捏嬰兒的臉頰。","synonyms":["squeeze","nip"],"level":3,"theme":"動作與行為","examples":[{"en":"She pinched the baby's cheek playfully.","zh":"她開玩笑地捏了捏嬰兒的臉頰。"},{"en":"Add a pinch of salt to make the soup taste better.","zh":"加一撮鹽讓湯的味道更好。"},{"en":"Many families feel the pinch when prices keep rising.","zh":"物價不斷上漲時，許多家庭都感到經濟拮据。"}]},{"word":"pine","pos":"n. / v.","phonetic":"[paɪn]","meaning":"松樹；渴望","definition":"an evergreen tree with needle-shaped leaves","collocations":["pine tree","pine forest","pine for something"],"example":"The mountain was covered with tall pine trees.","exampleZh":"這座山覆蓋著高大的松樹。","synonyms":["longing"],"level":3,"theme":"動物與植物","examples":[{"en":"The mountain was covered with tall pine trees.","zh":"這座山覆蓋著高大的松樹。"},{"en":"We walked through a quiet pine forest on the mountain.","zh":"我們走過山上一片寧靜的松樹林。"},{"en":"After moving abroad, she pined for her hometown food.","zh":"搬到國外後，她渴望吃到家鄉的食物。"}]},{"word":"pineapple","pos":"n.","phonetic":"[ˈpaɪnˌæpl]","meaning":"鳳梨","definition":"a large tropical fruit with sweet yellow flesh and a thick, spiky skin","collocations":["pineapple juice","fresh pineapple","pineapple cake"],"example":"She sliced a ripe pineapple for dessert.","exampleZh":"她切了一顆熟鳳梨當甜點。","synonyms":[],"level":1,"theme":"食物與烹飪","examples":[{"en":"She sliced a ripe pineapple for dessert.","zh":"她切了一顆熟鳳梨當甜點。"},{"en":"We bought some pineapple cake as a gift for our teacher.","zh":"我們買了一些鳳梨酥當作送給老師的禮物。"},{"en":"A cold glass of pineapple juice is perfect on a hot day.","zh":"炎熱的日子來一杯冰涼的鳳梨汁最棒了。"}]},{"word":"pink","pos":"adj. / n.","phonetic":"[pɪŋk]","meaning":"粉紅色的","definition":"of a pale red color","collocations":["pink dress","turn pink","bright pink"],"example":"She wore a pretty pink dress to the party.","exampleZh":"她穿了一件漂亮的粉紅色洋裝去參加派對。","synonyms":[],"level":1,"theme":"服裝與外表","examples":[{"en":"She wore a pretty pink dress to the party.","zh":"她穿了一件漂亮的粉紅色洋裝去參加派對。"},{"en":"Her cheeks turned pink when the teacher praised her essay.","zh":"老師稱讚她的作文時，她的臉頰泛紅。"},{"en":"He painted his little sister's room a bright pink color.","zh":"他把妹妹的房間漆成鮮豔的粉紅色。"}]},{"word":"pint","pos":"n.","phonetic":"[paɪnt]","meaning":"品脫（容量單位）","definition":"a unit of liquid measure equal to about half a liter","collocations":["a pint of milk","a pint of beer","order a pint"],"example":"He bought a pint of milk from the store.","exampleZh":"他從店裡買了一品脫牛奶。","synonyms":[],"level":4,"theme":"科學與數學","examples":[{"en":"He bought a pint of milk from the store.","zh":"他從店裡買了一品脫牛奶。"},{"en":"Please buy a pint of milk on your way home tonight.","zh":"今晚回家路上請買一品脫的牛奶。"},{"en":"The recipe calls for about a pint of fresh cream.","zh":"這道食譜需要大約一品脫的新鮮奶油。"}]},{"word":"pioneer","pos":"n. / v.","phonetic":"[ˌpaɪəˈnɪr]","meaning":"先驅；開拓者；開創","definition":"a person who is among the first to explore a new area or develop a new idea","collocations":["pioneer of technology","early pioneers","pioneer a new method"],"example":"She was a pioneer in the field of computer science.","exampleZh":"她是電腦科學領域的先驅。","synonyms":["innovator","forerunner"],"level":5,"theme":"社會與文化","examples":[{"en":"She was a pioneer in the field of computer science.","zh":"她是電腦科學領域的先驅。"},{"en":"She helped pioneer a new method for teaching deaf students.","zh":"她協助開創了一種教導聽障學生的新方法。"},{"en":"The early pioneers faced many dangers as they crossed the plains.","zh":"早期的開拓者穿越平原時面臨許多危險。"}]},{"word":"pious","pos":"adj.","phonetic":"[ˈpaɪəs]","meaning":"虔誠的","definition":"having or showing a deep respect for religion and religious practices","collocations":["pious believer","pious hope","devoutly pious"],"example":"The old man was known as a pious and gentle believer.","exampleZh":"這位老人以虔誠又溫和的信徒聞名。","synonyms":["devout","religious"],"level":6,"theme":"社會與文化","examples":[{"en":"The old man was known as a pious and gentle believer.","zh":"這位老人以虔誠又溫和的信徒聞名。"},{"en":"The pious woman visited the temple to pray every morning.","zh":"那位虔誠的婦人每天早上都到寺廟祈禱。"},{"en":"He led a simple and pious life devoted to helping others.","zh":"他過著簡樸而虔誠的生活，致力於幫助他人。"}]},{"word":"pipe","pos":"n.","phonetic":"[paɪp]","meaning":"管子；煙斗","definition":"a tube through which a liquid or gas flows","collocations":["water pipe","smoke a pipe","pipe burst"],"example":"A burst pipe flooded the basement.","exampleZh":"一根破裂的水管使地下室淹水。","synonyms":["tube","duct"],"level":2,"theme":"居家與生活","examples":[{"en":"A burst pipe flooded the basement.","zh":"一根破裂的水管使地下室淹水。"},{"en":"A water pipe burst and flooded the kitchen last night.","zh":"昨晚一根水管爆裂，淹了廚房。"},{"en":"The old man sat by the fire and smoked his pipe.","zh":"老人坐在火爐旁抽著他的煙斗。"}]},{"word":"pirate","pos":"n. / v.","phonetic":"[ˈpaɪrət]","meaning":"海盜；盜版","definition":"someone who attacks and robs ships at sea","collocations":["pirate ship","pirate flag","pirate movies"],"example":"The pirates attacked the merchant ship at night.","exampleZh":"海盜在夜裡襲擊了那艘商船。","synonyms":["buccaneer"],"level":3,"theme":"社會與文化","examples":[{"en":"The pirates attacked the merchant ship at night.","zh":"海盜在夜裡襲擊了那艘商船。"},{"en":"The children built a pirate ship out of cardboard boxes.","zh":"孩子們用紙箱做了一艘海盜船。"},{"en":"Buying pirate copies of software is against the law.","zh":"購買盜版軟體是違法的。"}]},{"word":"pistol","pos":"n.","phonetic":"[ˈpɪstl]","meaning":"手槍","definition":"a small gun designed to be held and fired with one hand","collocations":["fire a pistol","pistol shot","carry a pistol"],"example":"The officer kept his pistol in a holster.","exampleZh":"警官把手槍放在槍套裡。","synonyms":["handgun"],"level":5,"theme":"政治與法律","examples":[{"en":"The officer kept his pistol in a holster.","zh":"警官把手槍放在槍套裡。"},{"en":"The referee fired a pistol to start the running race.","zh":"裁判鳴槍示意賽跑開始。"},{"en":"In the old film, the sheriff carried a pistol at his side.","zh":"在那部老電影裡，警長身邊佩帶著一把手槍。"}]},{"word":"pit","pos":"n.","phonetic":"[pɪt]","meaning":"坑洞；果核","definition":"a large hole in the ground, or the hard seed inside a fruit","collocations":["dig a pit","cherry pit","fall into a pit"],"example":"Workers dug a deep pit for the foundation.","exampleZh":"工人們挖了一個深坑作為地基。","synonyms":["hole","hollow"],"level":3,"theme":"自然與環境","examples":[{"en":"Workers dug a deep pit for the foundation.","zh":"工人們挖了一個深坑作為地基。"},{"en":"Be careful not to swallow the cherry pit while eating.","zh":"吃的時候小心別把櫻桃核吞下去。"},{"en":"The workers dug a large pit to plant the young tree.","zh":"工人們挖了一個大坑來種那棵小樹。"}]},{"word":"pitch","pos":"n. / v.","phonetic":"[pɪtʃ]","meaning":"投擲；音調；推銷；球場","definition":"to throw something, or the highness or lowness of a sound","collocations":["pitch a ball","sales pitch","perfect pitch"],"example":"The pitcher threw a fast pitch across home plate.","exampleZh":"投手投出了一顆越過本壘板的快速球。","synonyms":["throw","toss"],"level":4,"theme":"運動與休閒","examples":[{"en":"The pitcher threw a fast pitch across home plate.","zh":"投手投出了一顆越過本壘板的快速球。"},{"en":"The salesman gave a convincing pitch about the new phone.","zh":"業務員針對這款新手機做了一場有說服力的推銷。"},{"en":"She has perfect pitch and can name any note she hears.","zh":"她有絕對音感，能說出聽到的任何音符。"}]},{"word":"pitcher","pos":"n.","phonetic":"[ˈpɪtʃɚ]","meaning":"投手；水壺","definition":"a player who throws the ball in baseball, or a large container for liquid","collocations":["starting pitcher","a pitcher of water","relief pitcher"],"example":"The pitcher struck out three batters in a row.","exampleZh":"這位投手連續讓三名打者三振出局。","synonyms":[],"level":3,"theme":"運動與休閒","examples":[{"en":"The pitcher struck out three batters in a row.","zh":"這位投手連續讓三名打者三振出局。"},{"en":"The waiter brought a pitcher of water to our table.","zh":"服務生端了一壺水到我們桌上。"},{"en":"The starting pitcher looked calm before the big game.","zh":"先發投手在這場大賽前顯得很鎮定。"}]},{"word":"pity","pos":"n. / v.","phonetic":"[ˈpɪti]","meaning":"同情；憐憫；可惜","definition":"a feeling of sadness or sympathy for someone else's suffering","collocations":["feel pity for","what a pity","take pity on"],"example":"She felt pity for the stray dog in the rain.","exampleZh":"她對雨中的流浪狗感到憐憫。","synonyms":["sympathy","compassion"],"level":3,"theme":"情緒與感受","examples":[{"en":"She felt pity for the stray dog in the rain.","zh":"她對雨中的流浪狗感到憐憫。"},{"en":"What a pity that the concert was canceled at the last minute.","zh":"真可惜，音樂會在最後一刻被取消了。"},{"en":"A kind woman took pity on the lost kitten and adopted it.","zh":"一位好心的女士可憐那隻迷路的小貓，便收養了牠。"}]},{"word":"pizza","pos":"n.","phonetic":"[ˈpitsə]","meaning":"披薩","definition":"a dish of Italian origin made with a flat base of dough topped with cheese and other ingredients","collocations":["order pizza","slice of pizza","pizza delivery"],"example":"We ordered a large pizza for the party.","exampleZh":"我們為派對訂了一個大披薩。","synonyms":[],"level":1,"theme":"食物與烹飪","examples":[{"en":"We ordered a large pizza for the party.","zh":"我們為派對訂了一個大披薩。"},{"en":"Let's order a pizza and watch a movie together tonight.","zh":"我們今晚點個披薩一起看電影吧。"},{"en":"He grabbed a slice of pizza before running to class.","zh":"他抓了一片披薩就趕去上課。"}]},{"word":"place","pos":"n. / v.","phonetic":"[ples]","meaning":"地方；場所；放置","definition":"a particular position, point, or area in space; to put something somewhere","collocations":["take place","place an order","in the first place"],"example":"This is a great place to watch the sunset.","exampleZh":"這是個欣賞日落的絕佳地點。","synonyms":["location","spot"],"level":1,"theme":"時間與空間","examples":[{"en":"This is a great place to watch the sunset.","zh":"這是個欣賞日落的絕佳地點。"},{"en":"The graduation ceremony will take place in the main hall.","zh":"畢業典禮將在大禮堂舉行。"},{"en":"You should not have left your bike there in the first place.","zh":"你一開始就不該把腳踏車停在那裡。"}]},{"word":"plain","pos":"adj. / n.","phonetic":"[plen]","meaning":"平坦的；樸素的；平原","definition":"simple or ordinary in character, or a large flat area of land","collocations":["plain food","plain language","vast plain"],"example":"She prefers plain clothes without any decoration.","exampleZh":"她偏好沒有裝飾的樸素衣服。","synonyms":["simple","clear"],"level":3,"theme":"性質與描述","examples":[{"en":"She prefers plain clothes without any decoration.","zh":"她偏好沒有裝飾的樸素衣服。"},{"en":"Please explain the rules in plain language everyone understands.","zh":"請用大家都懂的簡單語言解釋這些規則。"},{"en":"Herds of wild horses ran across the vast plain.","zh":"成群的野馬奔馳過廣闊的平原。"}]},{"word":"plan","pos":"n. / v.","phonetic":"[plæn]","meaning":"計畫；打算","definition":"a detailed proposal for doing or achieving something","collocations":["make a plan","plan ahead","business plan"],"example":"They made a plan to travel around Europe next summer.","exampleZh":"他們計畫明年夏天環遊歐洲。","synonyms":["scheme","proposal"],"level":1,"theme":"抽象概念","examples":[{"en":"They made a plan to travel around Europe next summer.","zh":"他們計畫明年夏天環遊歐洲。"},{"en":"We need to plan ahead if we want to finish on time.","zh":"如果我們想準時完成，就必須提前規劃。"},{"en":"She wrote a detailed business plan before opening her café.","zh":"她在開咖啡館之前寫了一份詳細的商業計畫。"}]},{"word":"plane","pos":"n.","phonetic":"[plen]","meaning":"飛機；平面","definition":"an aircraft with wings and one or more engines","collocations":["catch a plane","plane ticket","board the plane"],"example":"Our plane departs at seven in the morning.","exampleZh":"我們的飛機早上七點起飛。","synonyms":["airplane","aircraft"],"level":1,"theme":"交通與旅行","examples":[{"en":"Our plane departs at seven in the morning.","zh":"我們的飛機早上七點起飛。"},{"en":"We arrived early to catch our plane to the island.","zh":"我們提早到，好趕上飛往那座島的飛機。"},{"en":"Passengers began to board the plane after the announcement.","zh":"廣播之後，乘客開始登機。"}]},{"word":"planet","pos":"n.","phonetic":"[ˈplænɪt]","meaning":"行星；地球","definition":"a large round object in space that moves around a star","collocations":["distant planet","protect the planet","planet Earth"],"example":"Mars is known as the red planet.","exampleZh":"火星被稱為紅色行星。","synonyms":[],"level":2,"theme":"自然與環境","examples":[{"en":"Mars is known as the red planet.","zh":"火星被稱為紅色行星。"},{"en":"Everyone should do their part to protect the planet.","zh":"每個人都應該盡一份力保護地球。"},{"en":"Scientists discovered a distant planet outside our solar system.","zh":"科學家發現了一顆太陽系外的遙遠行星。"}]},{"word":"plant","pos":"n. / v.","phonetic":"[plænt]","meaning":"植物；工廠；種植","definition":"a living thing that grows in the ground, or to put seeds in soil","collocations":["plant a tree","power plant","water the plants"],"example":"She waters the plants on her balcony every morning.","exampleZh":"她每天早上都會澆陽台上的植物。","synonyms":["vegetation"],"level":1,"theme":"動物與植物","examples":[{"en":"She waters the plants on her balcony every morning.","zh":"她每天早上都會澆陽台上的植物。"},{"en":"Our class decided to plant a tree on Earth Day.","zh":"我們班決定在地球日種一棵樹。"},{"en":"The new power plant will supply electricity to the whole town.","zh":"這座新發電廠將供應整個城鎮的電力。"}]},{"word":"plastic","pos":"n. / adj.","phonetic":"[ˈplæstɪk]","meaning":"塑膠；塑膠的","definition":"a light, strong material that can be molded into different shapes","collocations":["plastic bag","plastic bottle","reduce plastic waste"],"example":"Many countries are trying to reduce plastic waste.","exampleZh":"許多國家正努力減少塑膠垃圾。","synonyms":[],"level":2,"theme":"自然與環境","examples":[{"en":"Many countries are trying to reduce plastic waste.","zh":"許多國家正努力減少塑膠垃圾。"},{"en":"Bring your own bag to avoid using plastic bags at the store.","zh":"自備購物袋，以免在商店使用塑膠袋。"},{"en":"We collected empty plastic bottles for the recycling project.","zh":"我們為回收計畫收集空的塑膠瓶。"}]},{"word":"plate","pos":"n.","phonetic":"[plet]","meaning":"盤子；牌照","definition":"a flat dish used for eating or serving food","collocations":["dinner plate","license plate","clear the plates"],"example":"He set a plate of food in front of the guest.","exampleZh":"他在客人面前擺了一盤食物。","synonyms":["dish"],"level":1,"theme":"食物與烹飪","examples":[{"en":"He set a plate of food in front of the guest.","zh":"他在客人面前擺了一盤食物。"},{"en":"After dinner, the children helped clear the plates from the table.","zh":"晚餐後，孩子們幫忙把餐桌上的盤子收走。"},{"en":"The police wrote down the license plate of the speeding car.","zh":"警察記下了那輛超速汽車的車牌號碼。"}]},{"word":"platform","pos":"n.","phonetic":"[ˈplætˌfɔrm]","meaning":"月台；平台；講台","definition":"a raised, level surface where people stand, such as at a train station","collocations":["train platform","online platform","political platform"],"example":"The train arrived at platform three.","exampleZh":"火車抵達了第三月台。","synonyms":[],"level":3,"theme":"交通與旅行","examples":[{"en":"The train arrived at platform three.","zh":"火車抵達了第三月台。"},{"en":"Passengers waited on the platform for the delayed train.","zh":"乘客們在月台上等待誤點的火車。"},{"en":"She sells her handmade jewelry on a popular online platform.","zh":"她在一個熱門的網路平台上販售她的手工首飾。"}]},{"word":"play","pos":"v. / n.","phonetic":"[ple]","meaning":"玩；扮演；戲劇","definition":"to engage in games or other activities for enjoyment","collocations":["play a game","play the piano","watch a play"],"example":"The children love to play in the park after school.","exampleZh":"孩子們喜歡放學後在公園玩耍。","synonyms":["perform","act"],"level":1,"theme":"運動與休閒","examples":[{"en":"The children love to play in the park after school.","zh":"孩子們喜歡放學後在公園玩耍。"},{"en":"My little brother is learning to play the piano this year.","zh":"我弟弟今年正在學彈鋼琴。"},{"en":"We went to the theater to watch a play about friendship.","zh":"我們去劇院看了一齣關於友誼的戲劇。"}]},{"word":"player","pos":"n.","phonetic":"[ˈpleɚ]","meaning":"選手；玩家；播放器","definition":"a person who takes part in a sport or game","collocations":["team player","key player","music player"],"example":"He is the best player on the basketball team.","exampleZh":"他是籃球隊裡最厲害的球員。","synonyms":[],"level":1,"theme":"運動與休閒","examples":[{"en":"He is the best player on the basketball team.","zh":"他是籃球隊裡最厲害的球員。"},{"en":"She is a true team player who always supports her classmates.","zh":"她是個真正有團隊精神的人，總是支持她的同學。"},{"en":"He was the key player in our victory last weekend.","zh":"他是我們上週末獲勝的關鍵人物。"}]},{"word":"playground","pos":"n.","phonetic":"[ˈpleˌgraʊnd]","meaning":"遊樂場；操場","definition":"an outdoor area where children can play, often with swings and slides","collocations":["school playground","playground equipment","play in the playground"],"example":"The children ran happily around the playground.","exampleZh":"孩子們在遊樂場裡開心地跑來跑去。","synonyms":[],"level":1,"theme":"教育與學習","examples":[{"en":"The children ran happily around the playground.","zh":"孩子們在遊樂場裡開心地跑來跑去。"},{"en":"The new playground equipment is safe and fun for young children.","zh":"新的遊樂設施對幼童來說既安全又有趣。"},{"en":"During recess, the students rushed to play in the playground.","zh":"下課時間，學生們衝去遊樂場玩。"}]},{"word":"plea","pos":"n.","phonetic":"[pli]","meaning":"懇求；請求；答辯","definition":"an emotional request for something","collocations":["make a plea","plea for help","desperate plea"],"example":"She made a plea for help to the crowd.","exampleZh":"她向群眾發出求助的懇求。","synonyms":["appeal","request"],"level":5,"theme":"溝通與語言","examples":[{"en":"She made a plea for help to the crowd.","zh":"她向群眾發出求助的懇求。"},{"en":"The charity made a plea for donations to help flood victims.","zh":"那個慈善機構懇求大家捐款幫助水災災民。"},{"en":"Her desperate plea for help finally reached the rescue team.","zh":"她絕望的求救終於傳到了救援隊那裡。"}]},{"word":"plead","pos":"v.","phonetic":"[plid]","meaning":"懇求；辯護；答辯","definition":"to ask for something in a very serious and emotional way","collocations":["plead for mercy","plead guilty","plead with someone"],"example":"He pleaded with the judge for another chance.","exampleZh":"他懇求法官再給他一次機會。","synonyms":["beg","implore"],"level":5,"theme":"溝通與語言","examples":[{"en":"He pleaded with the judge for another chance.","zh":"他懇求法官再給他一次機會。"},{"en":"The boy pleaded with his mother to let him stay up late.","zh":"男孩懇求媽媽讓他熬夜。"},{"en":"The man decided to plead guilty and accept his punishment.","zh":"那名男子決定認罪並接受懲罰。"}]},{"word":"pleasant","pos":"adj.","phonetic":"[ˈplɛzənt]","meaning":"令人愉快的；宜人的","definition":"giving a feeling of happy satisfaction or enjoyment","collocations":["pleasant weather","pleasant surprise","a pleasant person"],"example":"We had a pleasant afternoon walking along the beach.","exampleZh":"我們在海邊漫步度過了一個愉快的下午。","synonyms":["enjoyable","agreeable"],"level":3,"theme":"情緒與感受","examples":[{"en":"We had a pleasant afternoon walking along the beach.","zh":"我們在海邊漫步度過了一個愉快的下午。"},{"en":"We enjoyed pleasant weather during our whole trip to the coast.","zh":"我們到海邊的整趟旅程都遇上宜人的天氣。"},{"en":"Meeting my old friend at the station was a pleasant surprise.","zh":"在車站遇見老朋友是個令人愉快的驚喜。"}]},{"word":"please","pos":"v. / adv.","phonetic":"[pliz]","meaning":"取悅；請","definition":"to make someone feel happy or satisfied","collocations":["please someone","hard to please","yes, please"],"example":"He always tries to please his parents.","exampleZh":"他總是努力討父母歡心。","synonyms":["satisfy","delight"],"level":1,"theme":"情緒與感受","examples":[{"en":"He always tries to please his parents.","zh":"他總是努力討父母歡心。"},{"en":"It is hard to please everyone when planning a group trip.","zh":"規劃團體旅行時很難讓每個人都滿意。"},{"en":"He worked extra hours, hoping to please his new manager.","zh":"他加班工作，希望能取悅他的新主管。"}]},{"word":"pleasure","pos":"n.","phonetic":"[ˈplɛʒɚ]","meaning":"愉快；樂趣","definition":"a feeling of happiness or satisfaction","collocations":["with pleasure","take pleasure in","guilty pleasure"],"example":"Reading brings her great pleasure every evening.","exampleZh":"閱讀每晚都為她帶來很大的樂趣。","synonyms":["enjoyment","delight"],"level":2,"theme":"情緒與感受","examples":[{"en":"Reading brings her great pleasure every evening.","zh":"閱讀每晚都為她帶來很大的樂趣。"},{"en":"She takes great pleasure in gardening every weekend.","zh":"她非常享受每個週末的園藝活動。"},{"en":"It was a real pleasure to meet your family this evening.","zh":"今晚能見到你的家人真是我的榮幸。"}]},{"word":"pledge","pos":"n. / v.","phonetic":"[plɛdʒ]","meaning":"誓言；保證；發誓","definition":"a serious promise to do something","collocations":["make a pledge","pledge allegiance","pledge support"],"example":"The company pledged to reduce its carbon emissions.","exampleZh":"這家公司承諾要減少碳排放。","synonyms":["promise","vow"],"level":5,"theme":"抽象概念","examples":[{"en":"The company pledged to reduce its carbon emissions.","zh":"這家公司承諾要減少碳排放。"},{"en":"The students made a pledge to keep their school clean.","zh":"學生們發誓要保持校園整潔。"},{"en":"Several companies pledged support for the disaster relief effort.","zh":"好幾家公司承諾支持這次的救災工作。"}]},{"word":"plentiful","pos":"adj.","phonetic":"[ˈplɛntɪfəl]","meaning":"豐富的；充足的","definition":"existing in large amounts or numbers","collocations":["plentiful resources","plentiful supply","plentiful harvest"],"example":"Fish were plentiful in the river back then.","exampleZh":"當年河裡的魚非常豐富。","synonyms":["abundant","ample"],"level":5,"theme":"性質與描述","examples":[{"en":"Fish were plentiful in the river back then.","zh":"當年河裡的魚非常豐富。"},{"en":"Thanks to the rain, this year's harvest was plentiful.","zh":"多虧了雨水，今年的收成很豐富。"},{"en":"The region has a plentiful supply of clean water.","zh":"這個地區有充足的乾淨水源供應。"}]},{"word":"plenty","pos":"n. / pron. / adv.","phonetic":"[ˈplɛnti]","meaning":"許多；充足","definition":"a large amount that is more than enough","collocations":["plenty of time","plenty of money","in plenty"],"example":"There is plenty of food for everyone at the party.","exampleZh":"派對上有足夠所有人吃的食物。","synonyms":["abundance"],"level":2,"theme":"性質與描述","examples":[{"en":"There is plenty of food for everyone at the party.","zh":"派對上有足夠所有人吃的食物。"},{"en":"Don't rush; we still have plenty of time before the show.","zh":"別急，離表演開始我們還有很多時間。"},{"en":"There are plenty of reasons to learn a second language.","zh":"學習第二語言有很多理由。"}]},{"word":"plot","pos":"n. / v.","phonetic":"[plɑt]","meaning":"情節；陰謀；策劃","definition":"the main events of a play, novel, or movie, or a secret plan","collocations":["movie plot","plot a scheme","plot against"],"example":"The plot of the novel was full of unexpected twists.","exampleZh":"這本小說的情節充滿了意想不到的轉折。","synonyms":["scheme","storyline"],"level":4,"theme":"藝術與音樂","examples":[{"en":"The plot of the novel was full of unexpected twists.","zh":"這本小說的情節充滿了意想不到的轉折。"},{"en":"The movie's plot kept the whole audience guessing until the end.","zh":"這部電影的情節讓全場觀眾一直猜到最後。"},{"en":"In the story, two brothers plot to take over the kingdom.","zh":"在故事中，兩兄弟密謀奪取王國。"}]},{"word":"plow","pos":"n. / v.","phonetic":"[plaʊ]","meaning":"犁；犁田","definition":"a farming tool used to turn over soil before planting seeds","collocations":["plow a field","snow plow","horse-drawn plow"],"example":"The farmer used a plow to prepare the field for planting.","exampleZh":"農夫用犁準備田地以便種植。","synonyms":[],"level":4,"theme":"自然與環境","examples":[{"en":"The farmer used a plow to prepare the field for planting.","zh":"農夫用犁準備田地以便種植。"},{"en":"Every spring the farmer begins to plow the field for corn.","zh":"每年春天，農夫開始犁田準備種玉米。"},{"en":"A snow plow cleared the road after the heavy storm.","zh":"一輛鏟雪車在暴風雪後清理了道路。"}]},{"word":"pluck","pos":"v.","phonetic":"[plʌk]","meaning":"摘；拔；彈奏","definition":"to pull something quickly to remove it from where it is attached","collocations":["pluck feathers","pluck up courage","pluck strings"],"example":"She plucked a flower from the garden.","exampleZh":"她從花園裡摘了一朵花。","synonyms":["pull","pick"],"level":5,"theme":"動作與行為","examples":[{"en":"She plucked a flower from the garden.","zh":"她從花園裡摘了一朵花。"},{"en":"She finally plucked up the courage to speak in front of the class.","zh":"她終於鼓起勇氣在全班面前發言。"},{"en":"The musician gently plucked the strings of his guitar.","zh":"那位音樂家輕輕地撥動他吉他的弦。"}]},{"word":"plug","pos":"n. / v.","phonetic":"[plʌg]","meaning":"插頭；塞子；插上","definition":"a device with metal pins that connects an appliance to an electrical supply","collocations":["plug in","electric plug","pull the plug"],"example":"Please plug in the charger before you leave.","exampleZh":"離開前請把充電器插上。","synonyms":["connector"],"level":3,"theme":"科技與媒體","examples":[{"en":"Please plug in the charger before you leave.","zh":"離開前請把充電器插上。"},{"en":"Please plug in the laptop before the battery runs out.","zh":"請在筆電沒電之前把它插上電源。"},{"en":"He pulled the plug on the game and told the kids to sleep.","zh":"他關掉了遊戲，叫孩子們去睡覺。"}]},{"word":"plum","pos":"n.","phonetic":"[plʌm]","meaning":"李子","definition":"a small, round, juicy fruit with smooth purple or red skin","collocations":["ripe plum","plum tree","plum jam"],"example":"She picked a ripe plum from the tree.","exampleZh":"她從樹上摘了一顆熟的李子。","synonyms":[],"level":3,"theme":"食物與烹飪","examples":[{"en":"She picked a ripe plum from the tree.","zh":"她從樹上摘了一顆熟的李子。"},{"en":"My grandmother makes delicious plum jam every autumn.","zh":"我奶奶每年秋天都會做美味的李子果醬。"},{"en":"The plum tree in our yard is full of purple fruit.","zh":"我們院子裡的李子樹結滿了紫色的果實。"}]},{"word":"plumber","pos":"n.","phonetic":"[ˈplʌmɚ]","meaning":"水管工人","definition":"a person whose job is to fit and repair water pipes and other plumbing equipment","collocations":["call a plumber","local plumber","plumber fixes pipes"],"example":"We called a plumber to fix the leaking pipe.","exampleZh":"我們找了水管工人來修漏水的管子。","synonyms":[],"level":3,"theme":"工作與職業","examples":[{"en":"We called a plumber to fix the leaking pipe.","zh":"我們找了水管工人來修漏水的管子。"},{"en":"We had to call a plumber when the sink stopped draining.","zh":"水槽排不了水時，我們只好叫水管工人來。"},{"en":"The plumber quickly found the leak under the bathroom floor.","zh":"水管工人很快就找到浴室地板下的漏水處。"}]},{"word":"plunge","pos":"v. / n.","phonetic":"[plʌndʒ]","meaning":"跳入；驟降；投入","definition":"to jump or dive suddenly into water or another substance","collocations":["plunge into water","prices plunge","take the plunge"],"example":"He plunged into the cold lake without hesitation.","exampleZh":"他毫不猶豫地跳進冰冷的湖裡。","synonyms":["dive","dip"],"level":5,"theme":"動作與行為","examples":[{"en":"He plunged into the cold lake without hesitation.","zh":"他毫不猶豫地跳進冰冷的湖裡。"},{"en":"After months of doubt, she took the plunge and started her own shop.","zh":"猶豫了好幾個月後，她下定決心開了自己的店。"},{"en":"Stock prices plunged sharply after the surprising news.","zh":"在那則令人意外的消息之後，股價急劇下跌。"}]},{"word":"plural","pos":"adj. / n.","phonetic":"[ˈplʊrəl]","meaning":"複數的；複數","definition":"a form of a word used to refer to more than one person or thing","collocations":["plural form","plural noun","singular and plural"],"example":"Add an 's' to make most nouns plural.","exampleZh":"大多數名詞加上 s 就變成複數形式。","synonyms":[],"level":3,"theme":"溝通與語言","examples":[{"en":"Add an 's' to make most nouns plural.","zh":"大多數名詞加上 s 就變成複數形式。"},{"en":"The plural form of 'child' is 'children,' not 'childs.'","zh":"「child」的複數形式是「children」，而不是「childs」。"},{"en":"Our teacher explained the difference between singular and plural nouns.","zh":"我們老師解釋了單數名詞和複數名詞的差別。"}]},{"word":"plus","pos":"prep. / conj. / adj.","phonetic":"[plʌs]","meaning":"加上；另外","definition":"with the addition of; used to show that one number or amount is added to another","collocations":["two plus two","plus tax","plus points"],"example":"Two plus three equals five.","exampleZh":"二加三等於五。","synonyms":["and","added to"],"level":2,"theme":"科學與數學","examples":[{"en":"Two plus three equals five.","zh":"二加三等於五。"},{"en":"The meal costs ten dollars plus tax at this restaurant.","zh":"在這家餐廳，這份餐點要十美元外加稅金。"},{"en":"Being able to speak two languages is a big plus for this job.","zh":"會說兩種語言對這份工作是一大加分。"}]},{"word":"pneumonia","pos":"n.","phonetic":"[nuˈmonjə]","meaning":"肺炎","definition":"a serious illness that affects the lungs and makes breathing difficult","collocations":["catch pneumonia","suffer from pneumonia","treat pneumonia"],"example":"The old man was hospitalized with pneumonia last winter.","exampleZh":"這位老人去年冬天因肺炎住院。","synonyms":[],"level":6,"theme":"身體與健康","examples":[{"en":"The old man was hospitalized with pneumonia last winter.","zh":"這位老人去年冬天因肺炎住院。"},{"en":"The doctor warned that a bad cold could turn into pneumonia.","zh":"醫生警告說，嚴重的感冒可能會變成肺炎。"},{"en":"She stayed in the hospital for a week to treat her pneumonia.","zh":"她住院一週來治療肺炎。"}]},{"word":"pocket","pos":"n. / v.","phonetic":"[ˈpɑkɪt]","meaning":"口袋；袋狀物","definition":"a small bag sewn into or on clothing for carrying small items","collocations":["pocket money","put in your pocket","empty pockets"],"example":"He kept his keys in his coat pocket.","exampleZh":"他把鑰匙放在外套口袋裡。","synonyms":[],"level":1,"theme":"服裝與外表","examples":[{"en":"He kept his keys in his coat pocket.","zh":"他把鑰匙放在外套口袋裡。"},{"en":"He saves part of his pocket money to buy a new book.","zh":"他存下一部分零用錢來買一本新書。"},{"en":"She put the folded note in her jacket pocket.","zh":"她把摺好的紙條放進外套口袋裡。"}]},{"word":"poem","pos":"n.","phonetic":"[ˈpoəm]","meaning":"詩","definition":"a piece of writing that expresses feelings or ideas using rhythm and often rhyme","collocations":["write a poem","recite a poem","love poem"],"example":"She wrote a poem about the changing seasons.","exampleZh":"她寫了一首關於季節變化的詩。","synonyms":["verse"],"level":2,"theme":"藝術與音樂","examples":[{"en":"She wrote a poem about the changing seasons.","zh":"她寫了一首關於季節變化的詩。"},{"en":"Each student had to recite a short poem in class today.","zh":"今天每個學生都要在課堂上背誦一首短詩。"},{"en":"He wrote a poem to thank his teacher on graduation day.","zh":"他在畢業當天寫了一首詩感謝他的老師。"}]},{"word":"poet","pos":"n.","phonetic":"[ˈpoɪt]","meaning":"詩人","definition":"a person who writes poems","collocations":["famous poet","modern poet","poet laureate"],"example":"He is regarded as one of the greatest poets of his time.","exampleZh":"他被視為當代最偉大的詩人之一。","synonyms":[],"level":2,"theme":"藝術與音樂","examples":[{"en":"He is regarded as one of the greatest poets of his time.","zh":"他被視為當代最偉大的詩人之一。"},{"en":"The famous poet visited our school to share her work.","zh":"那位著名的詩人來我們學校分享她的作品。"},{"en":"As a young poet, he filled notebooks with ideas and verses.","zh":"身為一位年輕詩人，他把筆記本寫滿了靈感和詩句。"}]},{"word":"poetry","pos":"n.","phonetic":"[ˈpoɪtri]","meaning":"詩；詩作","definition":"poems in general, considered as a form of literature","collocations":["read poetry","write poetry","poetry collection"],"example":"She has loved poetry since she was a child.","exampleZh":"她從小就熱愛詩歌。","synonyms":["verse"],"level":3,"theme":"藝術與音樂","examples":[{"en":"She has loved poetry since she was a child.","zh":"她從小就熱愛詩歌。"},{"en":"Reading poetry helps me relax after a long school day.","zh":"讀詩幫助我在漫長的上學日後放鬆。"},{"en":"She published her first poetry collection at the age of twenty.","zh":"她在二十歲時出版了她的第一本詩集。"}]},{"word":"point","pos":"n. / v.","phonetic":"[pɔɪnt]","meaning":"點；重點；指向","definition":"an idea or opinion expressed, or a particular position or place","collocations":["point out","make a point","point at"],"example":"She made a good point during the meeting.","exampleZh":"她在會議中提出了一個好觀點。","synonyms":["indicate","aim"],"level":1,"theme":"抽象概念","examples":[{"en":"She made a good point during the meeting.","zh":"她在會議中提出了一個好觀點。"},{"en":"The teacher pointed out a small mistake in my calculation.","zh":"老師指出了我計算中的一個小錯誤。"},{"en":"It is rude to point at strangers on the street.","zh":"在街上用手指著陌生人是很沒禮貌的。"}]},{"word":"poison","pos":"n. / v.","phonetic":"[ˈpɔɪzn̩]","meaning":"毒藥；毒害","definition":"a substance that can cause illness or death if swallowed or absorbed","collocations":["rat poison","poison someone","deadly poison"],"example":"The snake's bite injected poison into his leg.","exampleZh":"蛇咬傷把毒液注入了他的腿。","synonyms":["toxin"],"level":3,"theme":"科學與數學","examples":[{"en":"The snake's bite injected poison into his leg.","zh":"蛇咬傷把毒液注入了他的腿。"},{"en":"Keep the rat poison away from young children and pets.","zh":"把老鼠藥放在幼童和寵物拿不到的地方。"},{"en":"Some plants contain a deadly poison in their leaves.","zh":"有些植物的葉子含有致命的毒素。"}]},{"word":"poisonous","pos":"adj.","phonetic":"[ˈpɔɪzənəs]","meaning":"有毒的","definition":"containing poison or capable of causing serious harm or death","collocations":["poisonous snake","poisonous gas","poisonous mushroom"],"example":"Be careful, that mushroom is poisonous.","exampleZh":"小心，那個蘑菇有毒。","synonyms":["toxic","venomous"],"level":3,"theme":"自然與環境","examples":[{"en":"Be careful, that mushroom is poisonous.","zh":"小心，那個蘑菇有毒。"},{"en":"Hikers should learn to recognize poisonous snakes in the mountains.","zh":"登山者應該學會辨認山中的毒蛇。"},{"en":"Never eat a wild mushroom unless you are sure it is not poisonous.","zh":"除非你確定野菇無毒，否則絕不要食用。"}]},{"word":"poke","pos":"v. / n.","phonetic":"[pok]","meaning":"戳；刺；捅","definition":"to push a finger or pointed object quickly into someone or something","collocations":["poke fun at","poke someone in the ribs","poke a hole"],"example":"He poked her arm to get her attention.","exampleZh":"他戳了戳她的手臂以引起她的注意。","synonyms":["jab","prod"],"level":3,"theme":"動作與行為","examples":[{"en":"He poked her arm to get her attention.","zh":"他戳了戳她的手臂以引起她的注意。"},{"en":"He poked a small hole in the paper to make an eye.","zh":"他在紙上戳了一個小洞當作眼睛。"},{"en":"It is unkind to poke fun at someone's accent.","zh":"拿別人的口音開玩笑是不厚道的。"}]},{"word":"pole","pos":"n.","phonetic":"[pol]","meaning":"竿；柱；極地","definition":"a long, thin rounded piece of wood or metal, or one of the ends of the Earth's axis","collocations":["flag pole","fishing pole","North Pole"],"example":"They raised the flag on a tall pole.","exampleZh":"他們把旗子升到一根高高的旗竿上。","synonyms":["rod","post"],"level":2,"theme":"自然與環境","examples":[{"en":"They raised the flag on a tall pole.","zh":"他們把旗子升到一根高高的旗竿上。"},{"en":"He held his fishing pole steady and waited for a bite.","zh":"他穩穩地握著釣竿，等著魚上鉤。"},{"en":"Explorers face extreme cold when traveling to the North Pole.","zh":"探險家前往北極時會面臨極度的寒冷。"}]},{"word":"police","pos":"n.","phonetic":"[pəˈlis]","meaning":"警察","definition":"the official organization responsible for enforcing the law and catching criminals","collocations":["call the police","police officer","police station"],"example":"The police arrived quickly after the accident.","exampleZh":"事故發生後警察很快就趕到了。","synonyms":["law enforcement"],"level":1,"theme":"政治與法律","examples":[{"en":"The police arrived quickly after the accident.","zh":"事故發生後警察很快就趕到了。"},{"en":"A friendly police officer helped the child find her parents.","zh":"一位親切的警察幫那個孩子找到了她的父母。"},{"en":"They went to the police station to report the missing wallet.","zh":"他們去警察局報案，說皮夾不見了。"}]},{"word":"policy","pos":"n.","phonetic":"[ˈpɑləsi]","meaning":"政策；方針","definition":"a plan of action agreed on by a government, business, or organization","collocations":["government policy","company policy","foreign policy"],"example":"The new policy aims to reduce air pollution.","exampleZh":"這項新政策旨在減少空氣污染。","synonyms":["strategy","plan"],"level":4,"theme":"政治與法律","examples":[{"en":"The new policy aims to reduce air pollution.","zh":"這項新政策旨在減少空氣污染。"},{"en":"The company policy allows employees to work from home twice a week.","zh":"公司政策允許員工每週在家工作兩天。"},{"en":"The government announced a new policy to support small farmers.","zh":"政府宣布了一項支持小農的新政策。"}]},{"word":"polish","pos":"v. / n.","phonetic":"[ˈpɑlɪʃ]","meaning":"擦亮；磨光；亮光劑","definition":"to make something smooth and shiny by rubbing it","collocations":["polish shoes","nail polish","polish the floor"],"example":"He polished his shoes before the interview.","exampleZh":"他在面試前把鞋子擦亮了。","synonyms":["shine","buff"],"level":3,"theme":"居家與生活","examples":[{"en":"He polished his shoes before the interview.","zh":"他在面試前把鞋子擦亮了。"},{"en":"She spent the morning polishing the wooden floor until it shone.","zh":"她花了整個早上把木地板擦得發亮。"},{"en":"He carefully polished his old bicycle before selling it.","zh":"他在賣掉舊腳踏車之前仔細地把它擦亮。"}]},{"word":"polite","pos":"adj.","phonetic":"[pəˈlaɪt]","meaning":"有禮貌的；客氣的","definition":"having or showing good manners and respect for other people","collocations":["polite manner","politely ask","stay polite"],"example":"The waiter was very polite to all the customers.","exampleZh":"這位服務生對所有顧客都非常有禮貌。","synonyms":["courteous","respectful"],"level":2,"theme":"性質與描述","examples":[{"en":"The waiter was very polite to all the customers.","zh":"這位服務生對所有顧客都非常有禮貌。"},{"en":"He politely asked the elderly woman if she needed a seat.","zh":"他有禮貌地問那位老太太是否需要座位。"},{"en":"Even when he was angry, he tried to stay polite.","zh":"即使生氣時，他也努力保持有禮貌。"}]},{"word":"political","pos":"adj.","phonetic":"[pəˈlɪtɪkl̩]","meaning":"政治的","definition":"relating to the government or public affairs of a country","collocations":["political party","political issue","political leader"],"example":"The country is facing a serious political crisis.","exampleZh":"這個國家正面臨嚴重的政治危機。","synonyms":[],"level":3,"theme":"政治與法律","examples":[{"en":"The country is facing a serious political crisis.","zh":"這個國家正面臨嚴重的政治危機。"},{"en":"Students discussed an important political issue in their debate class.","zh":"學生們在辯論課上討論了一個重要的政治議題。"},{"en":"The two political parties disagreed about the new tax plan.","zh":"兩個政黨對於新的稅收計畫意見不合。"}]},{"word":"politician","pos":"n.","phonetic":"[ˌpɑləˈtɪʃən]","meaning":"政治人物；政客","definition":"a person who works in politics, especially as an elected member of government","collocations":["local politician","corrupt politician","famous politician"],"example":"The politician promised to improve public education.","exampleZh":"這位政治人物承諾要改善公共教育。","synonyms":[],"level":3,"theme":"政治與法律","examples":[{"en":"The politician promised to improve public education.","zh":"這位政治人物承諾要改善公共教育。"},{"en":"The local politician visited our neighborhood to hear our concerns.","zh":"那位地方政治人物來我們社區聽取我們的意見。"},{"en":"A good politician should always keep the promises made to voters.","zh":"好的政治人物應該永遠遵守對選民許下的承諾。"}]},{"word":"politics","pos":"n.","phonetic":"[ˈpɑləˌtɪks]","meaning":"政治；政治學","definition":"the activities associated with the governance of a country or area","collocations":["study politics","talk politics","enter politics"],"example":"She has been interested in politics since college.","exampleZh":"她從大學時期就對政治感興趣。","synonyms":[],"level":3,"theme":"政治與法律","examples":[{"en":"She has been interested in politics since college.","zh":"她從大學時期就對政治感興趣。"},{"en":"She decided to study politics because she wants to help society.","zh":"她決定研讀政治學，因為她想幫助社會。"},{"en":"My grandfather loves to talk politics at the dinner table.","zh":"我爺爺喜歡在飯桌上談論政治。"}]},{"word":"poll","pos":"n. / v.","phonetic":"[pol]","meaning":"民意調查；投票","definition":"a survey of people's opinions on a particular subject","collocations":["opinion poll","conduct a poll","poll results"],"example":"A recent poll shows most people support the new law.","exampleZh":"最近的一項民調顯示大多數人支持這項新法。","synonyms":["survey"],"level":4,"theme":"政治與法律","examples":[{"en":"A recent poll shows most people support the new law.","zh":"最近的一項民調顯示大多數人支持這項新法。"},{"en":"The newspaper conducted a poll about people's reading habits.","zh":"那家報社針對民眾的閱讀習慣進行了一項民意調查。"},{"en":"The latest poll results surprised many of the reporters.","zh":"最新的民調結果讓許多記者感到意外。"}]},{"word":"pollute","pos":"v.","phonetic":"[pəˈlut]","meaning":"污染","definition":"to make air, water, or soil dirty or harmful, often with harmful substances","collocations":["pollute the air","pollute rivers","factories pollute"],"example":"Factories along the river have polluted the water for years.","exampleZh":"多年來，河邊的工廠一直在污染水質。","synonyms":["contaminate"],"level":3,"theme":"自然與環境","examples":[{"en":"Factories along the river have polluted the water for years.","zh":"多年來，河邊的工廠一直在污染水質。"},{"en":"Burning trash in the open can seriously pollute the air.","zh":"露天焚燒垃圾會嚴重污染空氣。"},{"en":"The factory was fined for polluting the nearby river.","zh":"那家工廠因污染附近的河川而被罰款。"}]},{"word":"pollution","pos":"n.","phonetic":"[pəˈluʃən]","meaning":"污染","definition":"the presence of harmful substances in the environment","collocations":["air pollution","reduce pollution","noise pollution"],"example":"Air pollution has become a serious problem in big cities.","exampleZh":"空氣污染已成為大城市的嚴重問題。","synonyms":["contamination"],"level":3,"theme":"自然與環境","examples":[{"en":"Air pollution has become a serious problem in big cities.","zh":"空氣污染已成為大城市的嚴重問題。"},{"en":"Riding bikes instead of driving can help reduce pollution.","zh":"騎腳踏車代替開車有助於減少污染。"},{"en":"Noise pollution from the highway kept the residents awake.","zh":"來自高速公路的噪音污染讓居民無法入睡。"}]},{"word":"pond","pos":"n.","phonetic":"[pɑnd]","meaning":"池塘","definition":"a small area of still water, often man-made","collocations":["fish pond","pond in the garden","frogs in the pond"],"example":"There is a small pond behind the temple.","exampleZh":"寺廟後面有一個小池塘。","synonyms":["pool"],"level":2,"theme":"自然與環境","examples":[{"en":"There is a small pond behind the temple.","zh":"寺廟後面有一個小池塘。"},{"en":"Colorful fish swam slowly around the pond in the garden.","zh":"色彩繽紛的魚在花園的池塘裡慢慢地游來游去。"},{"en":"On summer nights, we hear frogs singing in the pond.","zh":"夏夜裡，我們聽見青蛙在池塘裡歌唱。"}]},{"word":"pony","pos":"n.","phonetic":"[ˈponi]","meaning":"小馬","definition":"a type of small horse","collocations":["ride a pony","pony tail","pony ride"],"example":"The children took turns riding the pony at the fair.","exampleZh":"孩子們在市集裡輪流騎小馬。","synonyms":[],"level":2,"theme":"動物與植物","examples":[{"en":"The children took turns riding the pony at the fair.","zh":"孩子們在市集裡輪流騎小馬。"},{"en":"The little girl was thrilled to ride a pony for the first time.","zh":"小女孩第一次騎小馬，興奮極了。"},{"en":"A gentle pony carried the children around the farm.","zh":"一匹溫馴的小馬載著孩子們繞農場一圈。"}]},{"word":"pool","pos":"n. / v.","phonetic":"[pul]","meaning":"游泳池；水池；集中","definition":"a small area of still water, or a structure filled with water for swimming","collocations":["swimming pool","pool resources","car pool"],"example":"The kids spent the whole afternoon in the swimming pool.","exampleZh":"孩子們整個下午都待在游泳池裡。","synonyms":[],"level":1,"theme":"運動與休閒","examples":[{"en":"The kids spent the whole afternoon in the swimming pool.","zh":"孩子們整個下午都待在游泳池裡。"},{"en":"The neighbors decided to pool their resources to build a park.","zh":"鄰居們決定集合大家的資源來建一座公園。"},{"en":"We swam in the hotel pool until the sun went down.","zh":"我們在飯店的游泳池裡游泳，直到太陽下山。"}]},{"word":"poor","pos":"adj.","phonetic":"[pʊr]","meaning":"貧窮的；差的；可憐的","definition":"having very little money or resources","collocations":["poor family","poor quality","poor thing"],"example":"They grew up in a poor neighborhood.","exampleZh":"他們在一個貧窮的社區長大。","synonyms":["needy","impoverished"],"level":1,"theme":"商業與金錢","examples":[{"en":"They grew up in a poor neighborhood.","zh":"他們在一個貧窮的社區長大。"},{"en":"The gloves fell apart quickly because of their poor quality.","zh":"那副手套因為品質差而很快就壞了。"},{"en":"The charity provides free meals for poor families in the city.","zh":"那個慈善機構為城裡的貧困家庭提供免費餐點。"}]},{"word":"popcorn","pos":"n.","phonetic":"[ˈpɑpˌkɔrn]","meaning":"爆米花","definition":"a snack food made from corn kernels that are heated until they burst open","collocations":["a bag of popcorn","buttered popcorn","popcorn machine"],"example":"They shared a big bucket of popcorn at the movies.","exampleZh":"他們在電影院分享了一大桶爆米花。","synonyms":[],"level":1,"theme":"食物與烹飪","examples":[{"en":"They shared a big bucket of popcorn at the movies.","zh":"他們在電影院分享了一大桶爆米花。"},{"en":"The smell of buttered popcorn filled the whole movie theater.","zh":"奶油爆米花的香味瀰漫了整間電影院。"},{"en":"We bought a big bag of popcorn to share during the film.","zh":"我們買了一大袋爆米花，好在看電影時分著吃。"}]},{"word":"popular","pos":"adj.","phonetic":"[ˈpɑpjəlɚ]","meaning":"受歡迎的；流行的","definition":"liked, admired, or supported by many people","collocations":["popular song","popular among students","become popular"],"example":"This restaurant is very popular with tourists.","exampleZh":"這家餐廳深受觀光客歡迎。","synonyms":["well-liked","favored"],"level":2,"theme":"社會與文化","examples":[{"en":"This restaurant is very popular with tourists.","zh":"這家餐廳深受觀光客歡迎。"},{"en":"This song quickly became popular among teenagers this summer.","zh":"這首歌今年夏天很快就在青少年間流行起來。"},{"en":"The new sandwich shop is very popular with local students.","zh":"那家新開的三明治店很受當地學生歡迎。"}]},{"word":"popularity","pos":"n.","phonetic":"[ˌpɑpjəˈlærəti]","meaning":"受歡迎；名氣","definition":"the state of being liked or admired by many people","collocations":["gain popularity","lose popularity","rise in popularity"],"example":"The singer's popularity grew rapidly after the concert.","exampleZh":"這位歌手在演唱會後人氣迅速上升。","synonyms":["fame"],"level":4,"theme":"社會與文化","examples":[{"en":"The singer's popularity grew rapidly after the concert.","zh":"這位歌手在演唱會後人氣迅速上升。"},{"en":"The young writer gained popularity after her novel won a prize.","zh":"那位年輕作家在小說得獎後聲名大噪。"},{"en":"Online learning has risen in popularity in recent years.","zh":"近年來線上學習越來越受歡迎。"}]},{"word":"population","pos":"n.","phonetic":"[ˌpɑpjəˈleʃən]","meaning":"人口","definition":"all the people who live in a particular area or country","collocations":["population growth","total population","aging population"],"example":"The population of the city has doubled in ten years.","exampleZh":"這座城市的人口在十年間增加了一倍。","synonyms":[],"level":3,"theme":"社會與文化","examples":[{"en":"The population of the city has doubled in ten years.","zh":"這座城市的人口在十年間增加了一倍。"},{"en":"The country is worried about its rapidly aging population.","zh":"這個國家為其快速老化的人口感到憂心。"},{"en":"The total population of the village is only a few hundred.","zh":"這個村莊的總人口只有幾百人。"}]},{"word":"porch","pos":"n.","phonetic":"[pɔrtʃ]","meaning":"門廊；走廊","definition":"a covered structure at the entrance to a house","collocations":["front porch","sit on the porch","screened porch"],"example":"They sat on the porch and watched the sunset.","exampleZh":"他們坐在門廊上欣賞日落。","synonyms":[],"level":3,"theme":"居家與生活","examples":[{"en":"They sat on the porch and watched the sunset.","zh":"他們坐在門廊上欣賞日落。"},{"en":"On warm evenings, my grandparents sit on the front porch.","zh":"溫暖的夜晚，我的祖父母會坐在前門廊上。"},{"en":"She left the package on the porch by the front door.","zh":"她把包裹留在前門旁的門廊上。"}]},{"word":"pork","pos":"n.","phonetic":"[pɔrk]","meaning":"豬肉","definition":"meat from a pig","collocations":["pork chop","roast pork","pork dumpling"],"example":"She cooked pork with garlic and soy sauce.","exampleZh":"她用大蒜和醬油煮了豬肉。","synonyms":[],"level":2,"theme":"食物與烹飪","examples":[{"en":"She cooked pork with garlic and soy sauce.","zh":"她用大蒜和醬油煮了豬肉。"},{"en":"My mother fried a juicy pork chop for dinner tonight.","zh":"我媽媽今晚煎了一塊多汁的豬排當晚餐。"},{"en":"We ordered a plate of steaming pork dumplings at the shop.","zh":"我們在店裡點了一盤熱騰騰的豬肉水餃。"}]},{"word":"port","pos":"n.","phonetic":"[pɔrt]","meaning":"港口","definition":"a town or area with a harbor where ships load and unload goods","collocations":["sea port","port city","arrive at port"],"example":"The ship docked at the port early in the morning.","exampleZh":"這艘船一大早就在港口靠岸了。","synonyms":["harbor"],"level":3,"theme":"交通與旅行","examples":[{"en":"The ship docked at the port early in the morning.","zh":"這艘船一大早就在港口靠岸了。"},{"en":"The fishing boats returned to the port before the storm arrived.","zh":"漁船在暴風雨來臨前返回港口。"},{"en":"This busy port city trades goods with countries around the world.","zh":"這座繁忙的港口城市與世界各國進行貨物貿易。"}]},{"word":"portable","pos":"adj.","phonetic":"[ˈpɔrtəbl̩]","meaning":"可攜帶的；輕便的","definition":"able to be easily carried or moved","collocations":["portable device","portable speaker","portable computer"],"example":"He bought a portable speaker for his trip.","exampleZh":"他買了一個輕便喇叭準備旅行用。","synonyms":["movable"],"level":4,"theme":"科技與媒體","examples":[{"en":"He bought a portable speaker for his trip.","zh":"他買了一個輕便喇叭準備旅行用。"},{"en":"A portable charger is very useful during a long train trip.","zh":"行動充電器在漫長的火車旅程中非常有用。"},{"en":"She carried a small portable fan on the hot summer day.","zh":"炎熱的夏日裡，她隨身帶著一台小型手提電風扇。"}]},{"word":"portion","pos":"n.","phonetic":"[ˈpɔrʃən]","meaning":"部分；一份","definition":"a part or share of a whole","collocations":["a portion of","food portion","large portion"],"example":"He ate only a small portion of the meal.","exampleZh":"他只吃了這頓飯的一小部分。","synonyms":["part","share"],"level":4,"theme":"食物與烹飪","examples":[{"en":"He ate only a small portion of the meal.","zh":"他只吃了這頓飯的一小部分。"},{"en":"This restaurant serves a large portion of noodles at a low price.","zh":"這家餐廳以低廉的價格供應一大份麵。"},{"en":"A portion of the ticket money will go to a children's charity.","zh":"一部分的票款將捐給兒童慈善機構。"}]},{"word":"portrait","pos":"n.","phonetic":"[ˈpɔrtrɪt]","meaning":"肖像；畫像","definition":"a painting, drawing, or photograph of a person","collocations":["family portrait","paint a portrait","self-portrait"],"example":"The artist painted a beautiful portrait of the queen.","exampleZh":"這位藝術家畫了一幅美麗的女王肖像。","synonyms":[],"level":4,"theme":"藝術與音樂","examples":[{"en":"The artist painted a beautiful portrait of the queen.","zh":"這位藝術家畫了一幅美麗的女王肖像。"},{"en":"A large family portrait hangs above the fireplace at home.","zh":"家裡的壁爐上方掛著一幅大型的全家福畫像。"},{"en":"The art student practiced by painting a self-portrait.","zh":"那位美術系學生透過畫自畫像來練習。"}]},{"word":"portray","pos":"v.","phonetic":"[pɔrˈtre]","meaning":"描繪；描寫；飾演","definition":"to describe or show someone or something in a particular way","collocations":["portray a character","portray as","accurately portray"],"example":"The actor portrayed the king with great emotion.","exampleZh":"這位演員以豐富的情感飾演這位國王。","synonyms":["depict","represent"],"level":5,"theme":"藝術與音樂","examples":[{"en":"The actor portrayed the king with great emotion.","zh":"這位演員以豐富的情感飾演這位國王。"},{"en":"The novel portrays village life in a warm and honest way.","zh":"這本小說以溫暖而真實的方式描繪了鄉村生活。"},{"en":"The young actress portrayed the lonely queen very convincingly.","zh":"那位年輕女演員把孤獨的皇后詮釋得非常有說服力。"}]},{"word":"pose","pos":"v. / n.","phonetic":"[poz]","meaning":"擺姿勢；造成；姿勢","definition":"to present or cause something, such as a problem or threat","collocations":["pose a threat","pose for a photo","strike a pose"],"example":"The rising sea level poses a serious threat to coastal cities.","exampleZh":"海平面上升對沿海城市構成嚴重威脅。","synonyms":["present","cause"],"level":4,"theme":"抽象概念","examples":[{"en":"The rising sea level poses a serious threat to coastal cities.","zh":"海平面上升對沿海城市構成嚴重威脅。"},{"en":"The whole team posed for a photo after winning the match.","zh":"全隊在贏得比賽後合影留念。"},{"en":"Heavy rain can pose a serious threat to mountain hikers.","zh":"大雨可能對登山客構成嚴重的威脅。"}]},{"word":"position","pos":"n. / v.","phonetic":"[pəˈzɪʃən]","meaning":"位置；職位；立場","definition":"the place where someone or something is located, or a job or rank","collocations":["job position","current position","position oneself"],"example":"She applied for a position in the marketing department.","exampleZh":"她應徵了行銷部門的一個職位。","synonyms":["location","post"],"level":2,"theme":"工作與職業","examples":[{"en":"She applied for a position in the marketing department.","zh":"她應徵了行銷部門的一個職位。"},{"en":"He applied for a teaching position at the local high school.","zh":"他應徵了當地高中的一個教職。"},{"en":"The runner positioned herself carefully at the starting line.","zh":"那名跑者在起跑線上仔細地就定位。"}]},{"word":"positive","pos":"adj.","phonetic":"[ˈpɑzətɪv]","meaning":"正面的；積極的；肯定的","definition":"good, favorable, or full of hope","collocations":["positive attitude","positive result","stay positive"],"example":"She always tries to stay positive even during hard times.","exampleZh":"即使在艱難的時刻，她也總是努力保持積極。","synonyms":["optimistic","favorable"],"level":2,"theme":"情緒與感受","examples":[{"en":"She always tries to stay positive even during hard times.","zh":"即使在艱難的時刻，她也總是努力保持積極。"},{"en":"A positive attitude can help you get through difficult times.","zh":"積極的態度能幫助你度過困難時期。"},{"en":"The test showed a positive result, so the plan worked well.","zh":"測試顯示出正面的結果，所以這個計畫進行得很順利。"}]},{"word":"possess","pos":"v.","phonetic":"[pəˈzɛs]","meaning":"擁有；具有","definition":"to have or own something","collocations":["possess a skill","possess qualities","legally possess"],"example":"He possesses a remarkable talent for painting.","exampleZh":"他擁有非凡的繪畫天賦。","synonyms":["own","have"],"level":4,"theme":"抽象概念","examples":[{"en":"He possesses a remarkable talent for painting.","zh":"他擁有非凡的繪畫天賦。"},{"en":"She possesses the patience needed to teach young children.","zh":"她具備教導幼童所需的耐心。"},{"en":"A good leader should possess both honesty and courage.","zh":"一個好的領導者應該同時具備誠實與勇氣。"}]},{"word":"possession","pos":"n.","phonetic":"[pəˈzɛʃən]","meaning":"擁有；財產；所有物","definition":"the state of owning or having something, or something that is owned","collocations":["personal possessions","take possession of","in possession"],"example":"She lost all her possessions in the fire.","exampleZh":"她在那場火災中失去了所有財產。","synonyms":["property","belongings"],"level":4,"theme":"商業與金錢","examples":[{"en":"She lost all her possessions in the fire.","zh":"她在那場火災中失去了所有財產。"},{"en":"He packed all his personal possessions into two large boxes.","zh":"他把所有的個人物品裝進兩個大箱子裡。"},{"en":"The family finally took possession of their new house last week.","zh":"那家人上週終於取得了他們新房子的所有權。"}]},{"word":"possibility","pos":"n.","phonetic":"[ˌpɑsəˈbɪləti]","meaning":"可能性","definition":"a chance that something may happen or be true","collocations":["a real possibility","explore possibilities","rule out the possibility"],"example":"There is a possibility that the meeting will be postponed.","exampleZh":"這場會議有可能會延期。","synonyms":["chance","likelihood"],"level":3,"theme":"抽象概念","examples":[{"en":"There is a possibility that the meeting will be postponed.","zh":"這場會議有可能會延期。"},{"en":"We should explore every possibility before making a final choice.","zh":"在做出最後決定之前，我們應該探索每一種可能性。"},{"en":"There is a real possibility that the team will win the title.","zh":"這支隊伍確實有可能贏得冠軍。"}]},{"word":"practical","pos":"adj.","phonetic":"[ˈpræktɪkl]","meaning":"實際的；實用的","definition":"concerned with actual use rather than theory","collocations":["practical solution","practical experience","practical joke"],"example":"He gave us some practical advice on saving money.","exampleZh":"他給了我們一些實用的省錢建議。","synonyms":["realistic","useful"],"level":2,"theme":"性質與描述","examples":[{"en":"He gave us some practical advice on saving money.","zh":"他給了我們一些實用的省錢建議。"},{"en":"The workshop gave us plenty of practical experience in cooking.","zh":"這場工作坊給了我們許多實用的烹飪經驗。"},{"en":"We need a practical solution that the whole class can follow.","zh":"我們需要一個全班都能執行的實際解決方案。"}]},{"word":"practice","pos":"n. / v.","phonetic":"[ˈpræktɪs]","meaning":"練習；實踐；慣例","definition":"repeated exercise to gain skill, or the actual application of an idea","collocations":["practice makes perfect","medical practice","practice a sport"],"example":"She practices the piano every evening.","exampleZh":"她每天晚上都會練習彈鋼琴。","synonyms":["exercise","rehearsal"],"level":1,"theme":"教育與學習","examples":[{"en":"She practices the piano every evening.","zh":"她每天晚上都會練習彈鋼琴。"},{"en":"Practice makes perfect, so she reviews her lines every day.","zh":"熟能生巧，所以她每天都複習她的台詞。"},{"en":"Swimming is a great sport to practice during the summer holidays.","zh":"游泳是暑假期間很棒的一項運動。"}]},{"word":"praise","pos":"v. / n.","phonetic":"[prez]","meaning":"稱讚；讚美","definition":"to express approval or admiration for someone or something","collocations":["praise highly","win praise","praise someone for"],"example":"The teacher praised the students for their hard work.","exampleZh":"老師稱讚學生們的努力。","synonyms":["compliment","admire"],"level":2,"theme":"溝通與語言","examples":[{"en":"The teacher praised the students for their hard work.","zh":"老師稱讚學生們的努力。"},{"en":"The coach praised the young player for her hard work.","zh":"教練稱讚那位年輕球員的努力。"},{"en":"Her science project won praise from all the judges.","zh":"她的科學專題獲得了所有評審的讚賞。"}]},{"word":"pray","pos":"v.","phonetic":"[pre]","meaning":"祈禱；祈求","definition":"to speak to God or a god, especially to ask for help","collocations":["pray for","pray to God","pray silently"],"example":"They prayed for peace in the world.","exampleZh":"他們祈求世界和平。","synonyms":["beseech"],"level":2,"theme":"社會與文化","examples":[{"en":"They prayed for peace in the world.","zh":"他們祈求世界和平。"},{"en":"The family prayed for good health at the start of the year.","zh":"一家人在年初為身體健康祈禱。"},{"en":"She closed her eyes and prayed silently before the meal.","zh":"她閉上眼睛，在用餐前默默祈禱。"}]},{"word":"prayer","pos":"n.","phonetic":"[prɛr]","meaning":"祈禱；禱告","definition":"a solemn request or thanksgiving to God","collocations":["say a prayer","morning prayer","prayer for peace"],"example":"She said a quiet prayer before the exam.","exampleZh":"她在考試前默默地禱告。","synonyms":[],"level":2,"theme":"社會與文化","examples":[{"en":"She said a quiet prayer before the exam.","zh":"她在考試前默默地禱告。"},{"en":"The whole village gathered to say a prayer for peace.","zh":"全村的人聚在一起為和平祈禱。"},{"en":"He begins each day with a short morning prayer.","zh":"他每天都以一段簡短的晨禱開始。"}]},{"word":"precious","pos":"adj.","phonetic":"[ˈprɛʃəs]","meaning":"珍貴的；寶貴的","definition":"of great value; treasured","collocations":["precious time","precious metal","precious memories"],"example":"Time is precious, so don't waste it.","exampleZh":"時間很珍貴，所以不要浪費。","synonyms":["valuable","priceless"],"level":3,"theme":"性質與描述","examples":[{"en":"Time is precious, so don't waste it.","zh":"時間很珍貴，所以不要浪費。"},{"en":"Our trip to the mountains left us with precious memories.","zh":"我們的山中之旅為我們留下了珍貴的回憶。"},{"en":"Don't waste your precious time worrying about small things.","zh":"別把你寶貴的時間浪費在擔心小事上。"}]},{"word":"precise","pos":"adj.","phonetic":"[prɪˈsaɪs]","meaning":"精確的；確切的","definition":"exact and accurate","collocations":["precise measurement","precise instructions","to be precise"],"example":"We need precise data before making a decision.","exampleZh":"我們需要精確的數據才能做決定。","synonyms":["exact","accurate"],"level":4,"theme":"性質與描述","examples":[{"en":"We need precise data before making a decision.","zh":"我們需要精確的數據才能做決定。"},{"en":"The scientist recorded precise measurements during the experiment.","zh":"那位科學家在實驗過程中記錄了精確的測量數據。"},{"en":"Follow the precise instructions to build the model correctly.","zh":"按照精確的說明才能正確地組裝這個模型。"}]},{"word":"predict","pos":"v.","phonetic":"[prɪˈdɪkt]","meaning":"預測；預言","definition":"to say that something will happen in the future","collocations":["predict the outcome","predict the weather","hard to predict"],"example":"Scientists predict that sea levels will rise.","exampleZh":"科學家預測海平面將會上升。","synonyms":["forecast","foresee"],"level":3,"theme":"科學與數學","examples":[{"en":"Scientists predict that sea levels will rise.","zh":"科學家預測海平面將會上升。"},{"en":"It is hard to predict how the match will end.","zh":"很難預測這場比賽會如何結束。"},{"en":"Modern technology helps us predict the weather more accurately.","zh":"現代科技幫助我們更準確地預測天氣。"}]},{"word":"prefer","pos":"v.","phonetic":"[prɪˈfɝ]","meaning":"比較喜歡；偏好","definition":"to like one thing better than another","collocations":["prefer A to B","prefer doing something","would prefer"],"example":"I prefer tea to coffee.","exampleZh":"比起咖啡，我比較喜歡茶。","synonyms":["favor"],"level":2,"theme":"情緒與感受","examples":[{"en":"I prefer tea to coffee.","zh":"比起咖啡，我比較喜歡茶。"},{"en":"I would prefer to walk rather than take the crowded bus.","zh":"我寧願走路，也不要搭擁擠的公車。"},{"en":"She prefers reading quietly at home to going to noisy parties.","zh":"比起去吵鬧的派對，她更喜歡在家安靜地看書。"}]},{"word":"preference","pos":"n.","phonetic":"[ˈprɛfərəns]","meaning":"偏好；喜好","definition":"a greater liking for one alternative over another","collocations":["personal preference","show a preference","food preference"],"example":"Do you have any preference for the color of the walls?","exampleZh":"你對牆壁的顏色有什麼偏好嗎？","synonyms":["liking"],"level":4,"theme":"情緒與感受","examples":[{"en":"Do you have any preference for the color of the walls?","zh":"你對牆壁的顏色有什麼偏好嗎？"},{"en":"Please tell me your food preference before I order lunch.","zh":"在我點午餐之前，請告訴我你的飲食偏好。"},{"en":"Choosing a hobby is really a matter of personal preference.","zh":"選擇嗜好其實是個人偏好的問題。"}]},{"word":"pregnant","pos":"adj.","phonetic":"[ˈprɛgnənt]","meaning":"懷孕的","definition":"having a baby developing in the womb","collocations":["get pregnant","pregnant woman","pregnant with twins"],"example":"My sister is six months pregnant.","exampleZh":"我姊姊懷孕六個月了。","synonyms":[],"level":3,"theme":"身體與健康","examples":[{"en":"My sister is six months pregnant.","zh":"我姊姊懷孕六個月了。"},{"en":"The pregnant woman was offered a seat on the crowded train.","zh":"有人在擁擠的火車上讓座給那位孕婦。"},{"en":"My aunt is pregnant with twins and feels very excited.","zh":"我阿姨懷了雙胞胎，感到非常興奮。"}]},{"word":"preparation","pos":"n.","phonetic":"[ˌprɛpəˈreʃən]","meaning":"準備；預備工作","definition":"the action of making something ready for use","collocations":["make preparations","in preparation for","careful preparation"],"example":"The preparation for the wedding took months.","exampleZh":"這場婚禮的準備工作花了好幾個月。","synonyms":["arrangement"],"level":4,"theme":"抽象概念","examples":[{"en":"The preparation for the wedding took months.","zh":"這場婚禮的準備工作花了好幾個月。"},{"en":"The team made careful preparations before the big competition.","zh":"這支隊伍在大賽前做了充分的準備。"},{"en":"Weeks of preparation went into the school's music festival.","zh":"學校的音樂節投入了好幾週的準備工作。"}]},{"word":"prepare","pos":"v.","phonetic":"[prɪˈpɛr]","meaning":"準備；預備","definition":"to make ready for something","collocations":["prepare for an exam","prepare a meal","prepare in advance"],"example":"She is preparing for her final exams.","exampleZh":"她正在準備期末考試。","synonyms":["arrange","get ready"],"level":2,"theme":"教育與學習","examples":[{"en":"She is preparing for her final exams.","zh":"她正在準備期末考試。"},{"en":"He stayed up late to prepare for tomorrow's history exam.","zh":"他熬夜準備明天的歷史考試。"},{"en":"My father likes to prepare a big meal on Sunday evenings.","zh":"我爸爸喜歡在星期天晚上準備一頓豐盛的晚餐。"}]},{"word":"presence","pos":"n.","phonetic":"[ˈprɛzns]","meaning":"出席；存在","definition":"the state of being present in a place","collocations":["presence of mind","in the presence of","police presence"],"example":"Her presence at the meeting made a difference.","exampleZh":"她出席會議帶來了改變。","synonyms":["attendance"],"level":4,"theme":"抽象概念","examples":[{"en":"Her presence at the meeting made a difference.","zh":"她出席會議帶來了改變。"},{"en":"The teacher's calm presence helped the nervous students relax.","zh":"老師沉穩的存在讓緊張的學生放鬆下來。"},{"en":"There was a strong police presence during the crowded festival.","zh":"在擁擠的慶典期間，警力部署得很密集。"}]},{"word":"present","pos":"adj. / n. / v.","phonetic":"[ˈprɛznt]","meaning":"出席的；禮物；呈現","definition":"being in a certain place; a gift; to show or give something formally","collocations":["present a gift","at present","present the results"],"example":"He gave his sister a birthday present.","exampleZh":"他送給妹妹一份生日禮物。","synonyms":["gift","introduce"],"level":1,"theme":"居家與生活","examples":[{"en":"He gave his sister a birthday present.","zh":"他送給妹妹一份生日禮物。"},{"en":"The students presented the results of their study to the class.","zh":"學生們向全班報告了他們研究的結果。"},{"en":"At present, we do not have enough money to buy a new computer.","zh":"目前我們沒有足夠的錢買一台新電腦。"}]},{"word":"preserve","pos":"v.","phonetic":"[prɪˈzɝv]","meaning":"保存；保護","definition":"to keep something in its original state or protect it from harm","collocations":["preserve food","preserve traditions","preserve the environment"],"example":"We must preserve the rainforest for future generations.","exampleZh":"我們必須為後代保護雨林。","synonyms":["protect","conserve"],"level":4,"theme":"自然與環境","examples":[{"en":"We must preserve the rainforest for future generations.","zh":"我們必須為後代保護雨林。"},{"en":"Salt has long been used to preserve food for the winter.","zh":"鹽長久以來都被用來保存過冬的食物。"},{"en":"The village works hard to preserve its old traditions.","zh":"這個村莊努力保存它古老的傳統。"}]},{"word":"president","pos":"n.","phonetic":"[ˈprɛzədənt]","meaning":"總統；總裁；董事長","definition":"the leader of a country or organization","collocations":["elect a president","president of the company","vice president"],"example":"The president gave a speech about the economy.","exampleZh":"總統發表了一場關於經濟的演說。","synonyms":[],"level":2,"theme":"政治與法律","examples":[{"en":"The president gave a speech about the economy.","zh":"總統發表了一場關於經濟的演說。"},{"en":"The members will elect a new president at next month's meeting.","zh":"成員們將在下個月的會議上選出一位新的會長。"},{"en":"As president of the club, she leads every weekly meeting.","zh":"身為社團的社長，她主持每一次的週會。"}]},{"word":"press","pos":"v. / n.","phonetic":"[prɛs]","meaning":"按；壓；新聞界","definition":"to push firmly against something, or the news media","collocations":["press a button","freedom of the press","press charges"],"example":"Press the button to start the machine.","exampleZh":"按下按鈕啟動機器。","synonyms":["push"],"level":2,"theme":"科技與媒體","examples":[{"en":"Press the button to start the machine.","zh":"按下按鈕啟動機器。"},{"en":"Simply press this green button to turn the machine on.","zh":"只要按下這個綠色按鈕就能開啟機器。"},{"en":"A free press plays an important role in a healthy society.","zh":"自由的新聞媒體在健全的社會中扮演重要的角色。"}]},{"word":"pressure","pos":"n.","phonetic":"[ˈprɛʃɚ]","meaning":"壓力；壓迫","definition":"the force applied to a surface, or mental or emotional strain","collocations":["blood pressure","under pressure","peer pressure"],"example":"Students often feel a lot of pressure before exams.","exampleZh":"學生在考試前常感到很大的壓力。","synonyms":["stress","strain"],"level":3,"theme":"情緒與感受","examples":[{"en":"Students often feel a lot of pressure before exams.","zh":"學生在考試前常感到很大的壓力。"},{"en":"Many teenagers give in to peer pressure to fit in.","zh":"許多青少年為了融入群體而屈服於同儕壓力。"},{"en":"She stayed calm under pressure during the final round.","zh":"在最後一輪比賽中，她在壓力下仍保持冷靜。"}]},{"word":"pretend","pos":"v.","phonetic":"[prɪˈtɛnd]","meaning":"假裝","definition":"to act as if something is true when it is not","collocations":["pretend to be","pretend not to notice","just pretending"],"example":"The kids pretended to be pirates.","exampleZh":"孩子們假裝自己是海盜。","synonyms":["fake","act"],"level":2,"theme":"動作與行為","examples":[{"en":"The kids pretended to be pirates.","zh":"孩子們假裝自己是海盜。"},{"en":"The children pretended to be astronauts exploring a new planet.","zh":"孩子們假裝是探索新行星的太空人。"},{"en":"He pretended not to notice the mess in his brother's room.","zh":"他假裝沒注意到他弟弟房間裡的一團亂。"}]},{"word":"pretty","pos":"adj. / adv.","phonetic":"[ˈprɪti]","meaning":"漂亮的；相當地","definition":"attractive, or fairly/quite","collocations":["pretty flower","pretty good","pretty much"],"example":"She wore a pretty dress to the party.","exampleZh":"她穿了一件漂亮的洋裝去參加派對。","synonyms":["attractive","fairly"],"level":1,"theme":"服裝與外表","examples":[{"en":"She wore a pretty dress to the party.","zh":"她穿了一件漂亮的洋裝去參加派對。"},{"en":"Her drawing of the garden turned out pretty good.","zh":"她畫的花園成果相當不錯。"},{"en":"We have pretty much finished cleaning the classroom.","zh":"我們差不多已經打掃完教室了。"}]},{"word":"prevent","pos":"v.","phonetic":"[prɪˈvɛnt]","meaning":"預防；阻止","definition":"to stop something from happening","collocations":["prevent disease","prevent an accident","prevent someone from doing"],"example":"Wearing a helmet can prevent serious injury.","exampleZh":"戴安全帽可以預防嚴重的傷害。","synonyms":["stop","avoid"],"level":3,"theme":"身體與健康","examples":[{"en":"Wearing a helmet can prevent serious injury.","zh":"戴安全帽可以預防嚴重的傷害。"},{"en":"Washing your hands often can help prevent disease.","zh":"經常洗手有助於預防疾病。"},{"en":"The fence prevents small children from running onto the road.","zh":"這道圍籬防止小孩子跑到馬路上。"}]},{"word":"previous","pos":"adj.","phonetic":"[ˈprivɪəs]","meaning":"先前的；以前的","definition":"existing or occurring before something else","collocations":["previous experience","the previous day","previous owner"],"example":"He learned a lot from his previous job.","exampleZh":"他從上一份工作中學到了很多。","synonyms":["prior","earlier"],"level":3,"theme":"時間與空間","examples":[{"en":"He learned a lot from his previous job.","zh":"他從上一份工作中學到了很多。"},{"en":"Her previous experience as a volunteer helped her get the job.","zh":"她先前擔任志工的經驗幫助她得到了這份工作。"},{"en":"The previous owner of the house planted these apple trees.","zh":"這棟房子的前任屋主種了這些蘋果樹。"}]},{"word":"price","pos":"n.","phonetic":"[praɪs]","meaning":"價格；價錢","definition":"the amount of money needed to buy something","collocations":["high price","price tag","at any price"],"example":"The price of gas has gone up again.","exampleZh":"汽油的價格又漲了。","synonyms":["cost"],"level":1,"theme":"商業與金錢","examples":[{"en":"The price of gas has gone up again.","zh":"汽油的價格又漲了。"},{"en":"She checked the price tag before deciding to buy the jacket.","zh":"她在決定買那件外套之前先看了價格標籤。"},{"en":"The high price of the tickets kept many fans away.","zh":"昂貴的票價讓許多粉絲卻步。"}]},{"word":"pride","pos":"n.","phonetic":"[praɪd]","meaning":"驕傲；自豪","definition":"a feeling of satisfaction from one's achievements","collocations":["take pride in","swallow one's pride","local pride"],"example":"She takes great pride in her work.","exampleZh":"她對自己的工作感到十分自豪。","synonyms":["dignity"],"level":3,"theme":"情緒與感受","examples":[{"en":"She takes great pride in her work.","zh":"她對自己的工作感到十分自豪。"},{"en":"The workers take great pride in the bridge they built.","zh":"工人們對他們建造的橋樑深感自豪。"},{"en":"He had to swallow his pride and ask his friend for help.","zh":"他不得不放下自尊，向朋友求助。"}]},{"word":"priest","pos":"n.","phonetic":"[prist]","meaning":"神父；牧師；祭司","definition":"a person, especially a man, who performs religious duties in Christianity","collocations":["become a priest","local priest","priest of the church"],"example":"The priest blessed the newly married couple.","exampleZh":"神父為這對新婚夫婦祝福。","synonyms":["clergyman"],"level":4,"theme":"社會與文化","examples":[{"en":"The priest blessed the newly married couple.","zh":"神父為這對新婚夫婦祝福。"},{"en":"The local priest visits sick people in the hospital every week.","zh":"當地的神父每週都會去醫院探望病人。"},{"en":"After years of study, he decided to become a priest.","zh":"經過多年的學習，他決定成為一名神父。"}]},{"word":"primary","pos":"adj.","phonetic":"[ˈpraɪˌmɛri]","meaning":"主要的；最初的","definition":"of chief importance; first in order","collocations":["primary school","primary reason","primary source"],"example":"Her primary goal is to finish the project on time.","exampleZh":"她的主要目標是準時完成這個計畫。","synonyms":["main","principal"],"level":3,"theme":"教育與學習","examples":[{"en":"Her primary goal is to finish the project on time.","zh":"她的主要目標是準時完成這個計畫。"},{"en":"The primary reason for the delay was the heavy snow.","zh":"延誤的主要原因是大雪。"},{"en":"Historians study primary sources to understand the past.","zh":"歷史學家研究第一手資料來了解過去。"}]},{"word":"prime","pos":"adj.","phonetic":"[praɪm]","meaning":"主要的；最好的；黃金的","definition":"of the best quality; most important","collocations":["prime minister","prime example","prime time"],"example":"This restaurant serves prime cuts of beef.","exampleZh":"這家餐廳供應上等的牛肉。","synonyms":["main","top"],"level":4,"theme":"性質與描述","examples":[{"en":"This restaurant serves prime cuts of beef.","zh":"這家餐廳供應上等的牛肉。"},{"en":"This essay is a prime example of clear and simple writing.","zh":"這篇文章是清晰簡潔寫作的絕佳範例。"},{"en":"The store is busiest during the prime time after work.","zh":"這家店在下班後的黃金時段最為忙碌。"}]},{"word":"prince","pos":"n.","phonetic":"[prɪns]","meaning":"王子","definition":"the son of a king or queen","collocations":["crown prince","fairy tale prince","prince charming"],"example":"The prince will inherit the throne one day.","exampleZh":"這位王子將來會繼承王位。","synonyms":[],"level":2,"theme":"人物與家庭","examples":[{"en":"The prince will inherit the throne one day.","zh":"這位王子將來會繼承王位。"},{"en":"In the fairy tale, the prince rescued the trapped villagers.","zh":"在童話故事裡，王子拯救了被困的村民。"},{"en":"The young prince learned how to rule from his wise father.","zh":"年輕的王子從他睿智的父親那裡學習如何治理國家。"}]},{"word":"princess","pos":"n.","phonetic":"[ˈprɪnsɪs]","meaning":"公主","definition":"the daughter of a king or queen","collocations":["fairy tale princess","little princess","princess dress"],"example":"The little girl dreamed of becoming a princess.","exampleZh":"小女孩夢想著成為一位公主。","synonyms":[],"level":2,"theme":"人物與家庭","examples":[{"en":"The little girl dreamed of becoming a princess.","zh":"小女孩夢想著成為一位公主。"},{"en":"The little girl wore a sparkling princess dress to the party.","zh":"小女孩穿著一件閃亮的公主裙去參加派對。"},{"en":"In the story, the princess was brave and kind to everyone.","zh":"在故事中，公主既勇敢又對每個人都很善良。"}]},{"word":"principal","pos":"n. / adj.","phonetic":"[ˈprɪnsəpl]","meaning":"校長；主要的","definition":"the head of a school; most important","collocations":["school principal","principal reason","principal role"],"example":"The principal welcomed the new students on the first day.","exampleZh":"校長在開學第一天歡迎新生。","synonyms":["headmaster","main"],"level":3,"theme":"教育與學習","examples":[{"en":"The principal welcomed the new students on the first day.","zh":"校長在開學第一天歡迎新生。"},{"en":"The school principal gave a speech at the opening ceremony.","zh":"校長在開學典禮上發表了演說。"},{"en":"Water plays a principal role in keeping our bodies healthy.","zh":"水在維持我們身體健康方面扮演著主要的角色。"}]},{"word":"principle","pos":"n.","phonetic":"[ˈprɪnsəpl]","meaning":"原則；原理","definition":"a fundamental rule or belief that guides behavior","collocations":["basic principle","in principle","stand by one's principles"],"example":"He refused to lie, as a matter of principle.","exampleZh":"出於原則，他拒絕說謊。","synonyms":["rule","doctrine"],"level":4,"theme":"抽象概念","examples":[{"en":"He refused to lie, as a matter of principle.","zh":"出於原則，他拒絕說謊。"},{"en":"Honesty is a basic principle that guides all her decisions.","zh":"誠實是引導她所有決定的一項基本原則。"},{"en":"He always stands by his principles, even when it is difficult.","zh":"即使在困難的時候，他也總是堅守自己的原則。"}]},{"word":"print","pos":"v. / n.","phonetic":"[prɪnt]","meaning":"印刷；列印；印刷品","definition":"to produce text or images on paper using a machine","collocations":["print out","print a document","fine print"],"example":"Please print the report before the meeting.","exampleZh":"請在會議前把報告印出來。","synonyms":[],"level":2,"theme":"科技與媒體","examples":[{"en":"Please print the report before the meeting.","zh":"請在會議前把報告印出來。"},{"en":"Please read the fine print before you sign the form.","zh":"在簽署表格之前，請詳讀那些小字條款。"},{"en":"Could you print out three copies of this report for me?","zh":"你可以幫我把這份報告印出三份嗎？"}]},{"word":"printer","pos":"n.","phonetic":"[ˈprɪntɚ]","meaning":"印表機；印刷工","definition":"a machine that prints text or images onto paper","collocations":["laser printer","printer paper","printer ink"],"example":"The printer is out of paper again.","exampleZh":"印表機的紙又用完了。","synonyms":[],"level":2,"theme":"科技與媒體","examples":[{"en":"The printer is out of paper again.","zh":"印表機的紙又用完了。"},{"en":"The office bought a new laser printer for the busy season.","zh":"辦公室為了旺季買了一台新的雷射印表機。"},{"en":"We need to buy more printer ink before the exam week.","zh":"我們得在考試週之前多買一些印表機墨水。"}]},{"word":"prison","pos":"n.","phonetic":"[ˈprɪzn]","meaning":"監獄","definition":"a place where criminals are kept as punishment","collocations":["go to prison","prison sentence","escape from prison"],"example":"He was sent to prison for stealing a car.","exampleZh":"他因偷車而被關進監獄。","synonyms":["jail"],"level":2,"theme":"政治與法律","examples":[{"en":"He was sent to prison for stealing a car.","zh":"他因偷車而被關進監獄。"},{"en":"The thief received a five-year prison sentence for his crimes.","zh":"那名小偷因為他的罪行被判五年徒刑。"},{"en":"In the novel, two men plan to escape from prison.","zh":"在小說中，兩名男子計畫越獄。"}]},{"word":"prisoner","pos":"n.","phonetic":"[ˈprɪznɚ]","meaning":"囚犯；犯人","definition":"a person who is kept in prison as punishment","collocations":["take someone prisoner","prisoner of war","release a prisoner"],"example":"The prisoner was released after ten years.","exampleZh":"這名囚犯在十年後被釋放。","synonyms":["convict"],"level":3,"theme":"政治與法律","examples":[{"en":"The prisoner was released after ten years.","zh":"這名囚犯在十年後被釋放。"},{"en":"The guards released the prisoner after his sentence ended.","zh":"刑期結束後，警衛釋放了那名囚犯。"},{"en":"In the story, the enemy took several soldiers prisoner.","zh":"在故事中，敵人俘虜了好幾名士兵。"}]},{"word":"private","pos":"adj.","phonetic":"[ˈpraɪvɪt]","meaning":"私人的；私密的","definition":"belonging to a particular person; not public","collocations":["private property","private life","in private"],"example":"This is a private matter between us.","exampleZh":"這是我們之間的私事。","synonyms":["personal"],"level":2,"theme":"性質與描述","examples":[{"en":"This is a private matter between us.","zh":"這是我們之間的私事。"},{"en":"This garden is private property, so visitors must ask first.","zh":"這座花園是私人財產，所以訪客必須先詢問。"},{"en":"She asked to speak with the teacher in private after class.","zh":"她要求下課後私下與老師談話。"}]},{"word":"prize","pos":"n.","phonetic":"[praɪz]","meaning":"獎品；獎金","definition":"something given as a reward for winning a competition","collocations":["win a prize","first prize","prize money"],"example":"She won first prize in the science fair.","exampleZh":"她在科展中贏得了第一名的獎項。","synonyms":["award","reward"],"level":2,"theme":"教育與學習","examples":[{"en":"She won first prize in the science fair.","zh":"她在科展中贏得了第一名的獎項。"},{"en":"He used his prize money to buy books for the library.","zh":"他用他的獎金為圖書館買書。"},{"en":"Her painting won first prize at the city art contest.","zh":"她的畫作在市立美術比賽中贏得了第一名。"}]},{"word":"probable","pos":"adj.","phonetic":"[ˈprɑbəbl]","meaning":"很可能的","definition":"likely to happen or be true","collocations":["probable cause","probable outcome","highly probable"],"example":"It is probable that prices will rise next year.","exampleZh":"明年物價很可能會上漲。","synonyms":["likely"],"level":4,"theme":"抽象概念","examples":[{"en":"It is probable that prices will rise next year.","zh":"明年物價很可能會上漲。"},{"en":"The most probable cause of the fire was a faulty wire.","zh":"這場火災最可能的原因是一條故障的電線。"},{"en":"It seems highly probable that the concert will sell out soon.","zh":"這場音樂會似乎極有可能很快就會售罄。"}]},{"word":"probably","pos":"adv.","phonetic":"[ˈprɑbəbli]","meaning":"大概；可能地","definition":"almost certainly; very likely","collocations":["probably not","will probably","probably the best"],"example":"It will probably rain tomorrow.","exampleZh":"明天大概會下雨。","synonyms":["likely"],"level":1,"theme":"抽象概念","examples":[{"en":"It will probably rain tomorrow.","zh":"明天大概會下雨。"},{"en":"This is probably the best noodle shop in our whole town.","zh":"這大概是我們鎮上最棒的麵店了。"},{"en":"We will probably visit our grandparents during the winter break.","zh":"我們寒假期間大概會去探望我們的祖父母。"}]},{"word":"problem","pos":"n.","phonetic":"[ˈprɑbləm]","meaning":"問題；難題","definition":"a matter or situation regarded as unwelcome or harmful","collocations":["solve a problem","math problem","no problem"],"example":"We need to find a solution to this problem.","exampleZh":"我們必須找出解決這個問題的方法。","synonyms":["issue"],"level":1,"theme":"抽象概念","examples":[{"en":"We need to find a solution to this problem.","zh":"我們必須找出解決這個問題的方法。"},{"en":"The students worked together to solve a difficult math problem.","zh":"學生們同心協力解決了一道困難的數學題。"},{"en":"He said \"No problem\" and happily helped me carry the boxes.","zh":"他說「沒問題」，並開心地幫我搬箱子。"}]},{"word":"procedure","pos":"n.","phonetic":"[prəˈsidʒɚ]","meaning":"程序；手續","definition":"an established way of doing something","collocations":["standard procedure","safety procedure","follow the procedure"],"example":"Please follow the correct procedure to apply for a visa.","exampleZh":"請依照正確的程序申請簽證。","synonyms":["process"],"level":5,"theme":"抽象概念","examples":[{"en":"Please follow the correct procedure to apply for a visa.","zh":"請依照正確的程序申請簽證。"},{"en":"Everyone must follow the safety procedure during the fire drill.","zh":"消防演習期間，每個人都必須遵守安全程序。"},{"en":"Checking the equipment first is standard procedure in the lab.","zh":"先檢查設備是實驗室的標準程序。"}]},{"word":"proceed","pos":"v.","phonetic":"[prəˈsid]","meaning":"繼續進行；前進","definition":"to continue or move forward with an action","collocations":["proceed with caution","proceed to the next step","proceed as planned"],"example":"Please proceed to the gate for boarding.","exampleZh":"請前往登機門準備登機。","synonyms":["continue","advance"],"level":5,"theme":"動作與行為","examples":[{"en":"Please proceed to the gate for boarding.","zh":"請前往登機門準備登機。"},{"en":"Once the light turns green, drivers may proceed with caution.","zh":"燈號一轉綠，駕駛人便可小心地前進。"},{"en":"After the introduction, we will proceed to the next step.","zh":"介紹結束後，我們將進行下一個步驟。"}]},{"word":"process","pos":"n. / v.","phonetic":"[ˈprɑsɛs]","meaning":"過程；程序；處理","definition":"a series of actions taken to achieve a result","collocations":["learning process","process information","in the process of"],"example":"Learning a language is a slow process.","exampleZh":"學習一種語言是一個緩慢的過程。","synonyms":["procedure"],"level":3,"theme":"抽象概念","examples":[{"en":"Learning a language is a slow process.","zh":"學習一種語言是一個緩慢的過程。"},{"en":"The brain needs time to process new information properly.","zh":"大腦需要時間才能好好處理新的資訊。"},{"en":"They are in the process of building a new library downtown.","zh":"他們正在市中心興建一座新的圖書館。"}]},{"word":"produce","pos":"v.","phonetic":"[prəˈdjus]","meaning":"生產；製造；產生","definition":"to make or create something","collocations":["produce goods","produce evidence","mass produce"],"example":"This factory produces thousands of cars every year.","exampleZh":"這家工廠每年生產數千輛汽車。","synonyms":["make","manufacture"],"level":2,"theme":"工作與職業","examples":[{"en":"This factory produces thousands of cars every year.","zh":"這家工廠每年生產數千輛汽車。"},{"en":"The lawyer produced clear evidence to support the case.","zh":"律師提出了明確的證據來支持這個案子。"},{"en":"Modern factories can mass produce clothing very quickly.","zh":"現代工廠能非常快速地大量生產服裝。"}]},{"word":"product","pos":"n.","phonetic":"[ˈprɑdʌkt]","meaning":"產品；成果","definition":"an item that is made or grown to be sold","collocations":["new product","product design","final product"],"example":"The company launched a new product last month.","exampleZh":"這家公司上個月推出了一項新產品。","synonyms":["goods"],"level":2,"theme":"商業與金錢","examples":[{"en":"The company launched a new product last month.","zh":"這家公司上個月推出了一項新產品。"},{"en":"The team worked hard to improve the product design.","zh":"團隊努力改良產品的設計。"},{"en":"Customers lined up to try the store's newest product.","zh":"顧客們排隊試用這家店最新的產品。"}]},{"word":"production","pos":"n.","phonetic":"[prəˈdʌkʃən]","meaning":"生產；製作","definition":"the process of making or growing goods for sale","collocations":["mass production","production line","film production"],"example":"The factory increased production to meet demand.","exampleZh":"這家工廠提高產量以滿足需求。","synonyms":["manufacturing"],"level":4,"theme":"商業與金錢","examples":[{"en":"The factory increased production to meet demand.","zh":"這家工廠提高產量以滿足需求。"},{"en":"Workers on the production line assemble hundreds of toys daily.","zh":"生產線上的工人每天組裝數百個玩具。"},{"en":"The film production took nearly two years to complete.","zh":"這部電影的製作花了將近兩年才完成。"}]},{"word":"profession","pos":"n.","phonetic":"[prəˈfɛʃən]","meaning":"職業；專業","definition":"a paid occupation that requires special training","collocations":["by profession","legal profession","choose a profession"],"example":"Teaching is a respected profession.","exampleZh":"教學是一項受人尊敬的職業。","synonyms":["occupation"],"level":4,"theme":"工作與職業","examples":[{"en":"Teaching is a respected profession.","zh":"教學是一項受人尊敬的職業。"},{"en":"She is a nurse by profession and loves helping patients.","zh":"她的職業是護理師，喜歡幫助病人。"},{"en":"Choosing a profession is an important decision for young people.","zh":"選擇職業對年輕人來說是個重要的決定。"}]},{"word":"professional","pos":"adj. / n.","phonetic":"[prəˈfɛʃənl]","meaning":"專業的；職業的；專業人士","definition":"relating to a profession, or a person engaged in a skilled occupation","collocations":["professional advice","professional athlete","act professionally"],"example":"She gave us some professional advice about investing.","exampleZh":"她給了我們一些關於投資的專業建議。","synonyms":["expert"],"level":3,"theme":"工作與職業","examples":[{"en":"She gave us some professional advice about investing.","zh":"她給了我們一些關於投資的專業建議。"},{"en":"You should get professional advice before starting your own business.","zh":"在自行創業之前，你應該尋求專業的建議。"},{"en":"The young swimmer dreams of becoming a professional athlete.","zh":"那位年輕的游泳選手夢想成為職業運動員。"}]},{"word":"professor","pos":"n.","phonetic":"[prəˈfɛsɚ]","meaning":"教授","definition":"a university teacher of the highest rank","collocations":["college professor","professor of history","associate professor"],"example":"The professor gave an interesting lecture on history.","exampleZh":"這位教授就歷史發表了一場有趣的演講。","synonyms":[],"level":2,"theme":"教育與學習","examples":[{"en":"The professor gave an interesting lecture on history.","zh":"這位教授就歷史發表了一場有趣的演講。"},{"en":"The professor of history explained how the ancient city was built.","zh":"那位歷史教授解釋了這座古城是如何建造的。"},{"en":"Our college professor encourages students to ask many questions.","zh":"我們的大學教授鼓勵學生多提問。"}]},{"word":"profit","pos":"n. / v.","phonetic":"[ˈprɑfɪt]","meaning":"利潤；獲利","definition":"a financial gain from business activity","collocations":["make a profit","profit margin","profit from"],"example":"The company made a huge profit this year.","exampleZh":"這家公司今年獲利豐厚。","synonyms":["gain"],"level":3,"theme":"商業與金錢","examples":[{"en":"The company made a huge profit this year.","zh":"這家公司今年獲利豐厚。"},{"en":"The small bakery finally began to make a profit this year.","zh":"那家小烘焙坊今年終於開始獲利了。"},{"en":"Both sides can profit from working closely together.","zh":"雙方都能從密切合作中獲益。"}]},{"word":"program","pos":"n. / v.","phonetic":"[ˈprogræm]","meaning":"節目；計畫；程式；編寫程式","definition":"a planned series of activities or a set of coded instructions for a computer","collocations":["TV program","computer program","program a robot"],"example":"He learned how to program a computer in college.","exampleZh":"他在大學時學會了如何寫電腦程式。","synonyms":["schedule"],"level":2,"theme":"科技與媒體","examples":[{"en":"He learned how to program a computer in college.","zh":"他在大學時學會了如何寫電腦程式。"},{"en":"My favorite TV program is a documentary about wild animals.","zh":"我最喜歡的電視節目是一部關於野生動物的紀錄片。"},{"en":"In class, we learned how to program a small robot.","zh":"在課堂上，我們學會了如何為一個小機器人編寫程式。"}]},{"word":"progress","pos":"n. / v.","phonetic":"[ˈprɑgrɛs]","meaning":"進步；進展","definition":"forward movement toward a goal or improvement over time","collocations":["make progress","in progress","progress report"],"example":"She has made great progress in her studies.","exampleZh":"她在課業上有很大的進步。","synonyms":["advancement"],"level":3,"theme":"教育與學習","examples":[{"en":"She has made great progress in her studies.","zh":"她在課業上有很大的進步。"},{"en":"The teacher sent a progress report to every student's parents.","zh":"老師寄了一份進度報告給每位學生的家長。"},{"en":"The repair work is still in progress, so please be patient.","zh":"修繕工程仍在進行中，所以請耐心等候。"}]},{"word":"prohibit","pos":"v.","phonetic":"[proˈhɪbɪt]","meaning":"禁止","definition":"to formally forbid something by law or rule","collocations":["prohibit smoking","strictly prohibited","prohibit the sale of"],"example":"Smoking is prohibited in this building.","exampleZh":"這棟大樓內禁止吸菸。","synonyms":["forbid","ban"],"level":5,"theme":"政治與法律","examples":[{"en":"Smoking is prohibited in this building.","zh":"這棟大樓內禁止吸菸。"},{"en":"The new rule strictly prohibits running beside the swimming pool.","zh":"新規定嚴格禁止在游泳池邊奔跑。"},{"en":"Many countries prohibit the sale of fireworks to children.","zh":"許多國家禁止將煙火販售給孩童。"}]},{"word":"project","pos":"n. / v.","phonetic":"[ˈprɑdʒɛkt]","meaning":"計畫；專案；投射","definition":"a planned piece of work, or to estimate/forecast something","collocations":["science project","project a growth rate","group project"],"example":"Our class is working on a science project.","exampleZh":"我們班正在進行一項科學專題。","synonyms":["plan"],"level":2,"theme":"教育與學習","examples":[{"en":"Our class is working on a science project.","zh":"我們班正在進行一項科學專題。"},{"en":"Our group project is about saving energy at home.","zh":"我們的分組專題是關於在家節約能源。"},{"en":"Experts project a steady growth rate for the coming year.","zh":"專家預估來年會有穩定的成長率。"}]},{"word":"promise","pos":"n. / v.","phonetic":"[ˈprɑmɪs]","meaning":"承諾；答應","definition":"a declaration that one will do something","collocations":["keep a promise","break a promise","promise to do"],"example":"He promised to call me every day.","exampleZh":"他答應每天都會打電話給我。","synonyms":["vow","pledge"],"level":1,"theme":"溝通與語言","examples":[{"en":"He promised to call me every day.","zh":"他答應每天都會打電話給我。"},{"en":"A good friend always tries to keep a promise.","zh":"一個好朋友總是努力信守承諾。"},{"en":"She promised to help me review before the final test.","zh":"她答應在期末考前幫我複習。"}]},{"word":"promote","pos":"v.","phonetic":"[prəˈmot]","meaning":"晉升；促進；宣傳","definition":"to raise someone to a higher position, or to encourage the development of something","collocations":["promote health","get promoted","promote a product"],"example":"She was promoted to manager last year.","exampleZh":"她去年被升職為經理。","synonyms":["advance","boost"],"level":4,"theme":"工作與職業","examples":[{"en":"She was promoted to manager last year.","zh":"她去年被升職為經理。"},{"en":"The company will promote several workers to team leader positions next month.","zh":"這家公司下個月將把幾名員工晉升為團隊領導。"},{"en":"Regular exercise and a balanced diet promote good health.","zh":"規律運動和均衡飲食能促進健康。"}]},{"word":"prompt","pos":"adj. / v.","phonetic":"[prɑmpt]","meaning":"迅速的；促使","definition":"done quickly and without delay; to cause someone to do something","collocations":["prompt response","prompt someone to act","prompt reply"],"example":"Thank you for your prompt reply to my email.","exampleZh":"謝謝你迅速回覆我的電子郵件。","synonyms":["quick","immediate"],"level":5,"theme":"性質與描述","examples":[{"en":"Thank you for your prompt reply to my email.","zh":"謝謝你迅速回覆我的電子郵件。"},{"en":"The teacher's question prompted the students to think more deeply.","zh":"老師的問題促使學生思考得更深入。"},{"en":"We received a prompt response from the customer service team.","zh":"我們收到了客服團隊迅速的回覆。"}]},{"word":"pronounce","pos":"v.","phonetic":"[prəˈnaʊns]","meaning":"發音；宣告","definition":"to make the sound of a word correctly","collocations":["pronounce a word","hard to pronounce","pronounce clearly"],"example":"It's difficult to pronounce this word correctly.","exampleZh":"這個字很難正確發音。","synonyms":["articulate"],"level":3,"theme":"溝通與語言","examples":[{"en":"It's difficult to pronounce this word correctly.","zh":"這個字很難正確發音。"},{"en":"Many learners find it hard to pronounce this long English word.","zh":"許多學習者覺得這個很長的英文單字很難發音。"},{"en":"Please pronounce your name clearly so everyone can hear it.","zh":"請清楚地念出你的名字，好讓大家都能聽到。"}]},{"word":"proof","pos":"n.","phonetic":"[pruf]","meaning":"證據；證明","definition":"evidence that establishes a fact or the truth of something","collocations":["proof of identity","provide proof","without proof"],"example":"Do you have any proof that he was there?","exampleZh":"你有任何證據證明他當時在場嗎？","synonyms":["evidence"],"level":4,"theme":"抽象概念","examples":[{"en":"Do you have any proof that he was there?","zh":"你有任何證據證明他當時在場嗎？"},{"en":"You must show proof of identity before entering the exam room.","zh":"進入考場前你必須出示身分證明。"},{"en":"The police found no proof that he had taken the money.","zh":"警方沒有找到他拿走錢的證據。"}]},{"word":"proper","pos":"adj.","phonetic":"[ˈprɑpɚ]","meaning":"適當的；正確的","definition":"correct, appropriate, or suitable","collocations":["proper way","proper training","proper behavior"],"example":"You should use the proper tools for this job.","exampleZh":"你應該使用適當的工具來做這件事。","synonyms":["appropriate","correct"],"level":3,"theme":"性質與描述","examples":[{"en":"You should use the proper tools for this job.","zh":"你應該使用適當的工具來做這件事。"},{"en":"Wearing the proper shoes is important when you go hiking.","zh":"去健行時穿適當的鞋子很重要。"},{"en":"The new employees received proper training before starting work.","zh":"新員工在開始工作前接受了適當的訓練。"}]},{"word":"properly","pos":"adv.","phonetic":"[ˈprɑpɚli]","meaning":"適當地；正確地","definition":"in a correct or suitable manner","collocations":["work properly","behave properly","dress properly"],"example":"Make sure the machine is working properly.","exampleZh":"確認機器運作正常。","synonyms":["correctly"],"level":3,"theme":"性質與描述","examples":[{"en":"Make sure the machine is working properly.","zh":"確認機器運作正常。"},{"en":"If you don't charge the phone properly, the battery drains fast.","zh":"如果你沒有正確地充電，手機電池會很快耗盡。"},{"en":"Please close the window properly so the rain can't get in.","zh":"請把窗戶關好，這樣雨水才進不來。"}]},{"word":"property","pos":"n.","phonetic":"[ˈprɑpɚti]","meaning":"財產；房產；特性","definition":"a thing or things owned; a quality belonging to something","collocations":["private property","real property","chemical property"],"example":"The house and land are her private property.","exampleZh":"這間房子和土地是她的私人財產。","synonyms":["possession"],"level":4,"theme":"商業與金錢","examples":[{"en":"The house and land are her private property.","zh":"這間房子和土地是她的私人財產。"},{"en":"This land is private property, so visitors are not allowed.","zh":"這塊土地是私人財產，所以不准訪客進入。"},{"en":"Scientists study the chemical properties of different metals.","zh":"科學家研究不同金屬的化學特性。"}]},{"word":"proportion","pos":"n.","phonetic":"[prəˈporʃən]","meaning":"比例；部分","definition":"a part or share of a whole in relation to it","collocations":["in proportion to","a large proportion of","out of proportion"],"example":"A large proportion of students passed the exam.","exampleZh":"很大一部分的學生通過了考試。","synonyms":["ratio"],"level":5,"theme":"科學與數學","examples":[{"en":"A large proportion of students passed the exam.","zh":"很大一部分的學生通過了考試。"},{"en":"A large proportion of the class enjoys playing team sports.","zh":"班上很大一部分的學生喜歡玩團隊運動。"},{"en":"The amount of salt should be in proportion to the water.","zh":"鹽的量應該和水成適當的比例。"}]},{"word":"propose","pos":"v.","phonetic":"[prəˈpoz]","meaning":"提議；求婚","definition":"to suggest a plan or idea, or to ask someone to marry you","collocations":["propose a solution","propose marriage","propose a toast"],"example":"He proposed to his girlfriend on the beach.","exampleZh":"他在海灘上向女友求婚。","synonyms":["suggest"],"level":4,"theme":"溝通與語言","examples":[{"en":"He proposed to his girlfriend on the beach.","zh":"他在海灘上向女友求婚。"},{"en":"The committee will propose a new solution to the traffic problem.","zh":"委員會將提議一個解決交通問題的新方案。"},{"en":"He plans to propose to his girlfriend during their trip.","zh":"他打算在旅行途中向女友求婚。"}]},{"word":"prospect","pos":"n.","phonetic":"[ˈprɑspɛkt]","meaning":"前景；可能性","definition":"the possibility of something happening in the future","collocations":["job prospect","future prospects","in prospect"],"example":"The company has good prospects for growth.","exampleZh":"這家公司的成長前景良好。","synonyms":["possibility","outlook"],"level":5,"theme":"抽象概念","examples":[{"en":"The company has good prospects for growth.","zh":"這家公司的成長前景良好。"},{"en":"The job offers good prospects for young graduates.","zh":"這份工作為年輕畢業生提供了良好的前景。"},{"en":"The prospect of studying abroad excites many high-school students.","zh":"出國留學的可能性令許多高中生興奮。"}]},{"word":"protect","pos":"v.","phonetic":"[prəˈtɛkt]","meaning":"保護","definition":"to keep someone or something safe from harm","collocations":["protect the environment","protect against","protect one's rights"],"example":"Wear sunscreen to protect your skin from the sun.","exampleZh":"擦防曬乳來保護皮膚免受陽光傷害。","synonyms":["defend","guard"],"level":2,"theme":"自然與環境","examples":[{"en":"Wear sunscreen to protect your skin from the sun.","zh":"擦防曬乳來保護皮膚免受陽光傷害。"},{"en":"We should all work together to protect the environment.","zh":"我們都應該齊心協力保護環境。"},{"en":"A thick coat protects hikers against the cold mountain wind.","zh":"厚外套能保護健行者抵禦寒冷的山風。"}]},{"word":"protection","pos":"n.","phonetic":"[prəˈtɛkʃən]","meaning":"保護；防護","definition":"the action of keeping someone or something safe","collocations":["skin protection","under protection","legal protection"],"example":"The helmet provides protection for cyclists.","exampleZh":"安全帽能為騎士提供保護。","synonyms":["defense"],"level":3,"theme":"身體與健康","examples":[{"en":"The helmet provides protection for cyclists.","zh":"安全帽能為騎士提供保護。"},{"en":"Cyclists wear helmets for protection against head injuries.","zh":"自行車騎士戴安全帽以防護頭部受傷。"},{"en":"The new law offers legal protection to injured workers.","zh":"新法律為受傷的勞工提供法律保護。"}]},{"word":"protein","pos":"n.","phonetic":"[ˈprotin]","meaning":"蛋白質","definition":"a nutrient essential for building and repairing the body","collocations":["protein source","high-protein diet","animal protein"],"example":"Eggs are a great source of protein.","exampleZh":"雞蛋是很好的蛋白質來源。","synonyms":[],"level":4,"theme":"食物與烹飪","examples":[{"en":"Eggs are a great source of protein.","zh":"雞蛋是很好的蛋白質來源。"},{"en":"Beans and eggs are an excellent source of protein.","zh":"豆類和雞蛋是極佳的蛋白質來源。"},{"en":"Athletes often follow a high-protein diet to build muscle.","zh":"運動員常採取高蛋白飲食來增長肌肉。"}]},{"word":"protest","pos":"n. / v.","phonetic":"[ˈprotɛst]","meaning":"抗議；反對","definition":"a strong expression of disagreement or objection","collocations":["stage a protest","protest against","in protest"],"example":"Hundreds of people joined the protest against the new law.","exampleZh":"數百人參加了反對這項新法律的抗議活動。","synonyms":["objection","demonstrate"],"level":4,"theme":"政治與法律","examples":[{"en":"Hundreds of people joined the protest against the new law.","zh":"數百人參加了反對這項新法律的抗議活動。"},{"en":"Many citizens joined the protest against rising food prices.","zh":"許多市民加入抗議食物價格上漲的行動。"},{"en":"The workers protested against the unfair new rules.","zh":"工人們抗議不公平的新規定。"}]},{"word":"proud","pos":"adj.","phonetic":"[praʊd]","meaning":"驕傲的；自豪的","definition":"feeling deep pleasure or satisfaction from achievements","collocations":["proud of","proud moment","stand proud"],"example":"Her parents are very proud of her achievements.","exampleZh":"她的父母對她的成就感到十分自豪。","synonyms":["satisfied"],"level":1,"theme":"情緒與感受","examples":[{"en":"Her parents are very proud of her achievements.","zh":"她的父母對她的成就感到十分自豪。"},{"en":"She felt proud of finishing the marathon for the first time.","zh":"她為第一次跑完馬拉松感到自豪。"},{"en":"The whole town is proud of the young science champion.","zh":"全鎮都以這位年輕的科學冠軍為榮。"}]},{"word":"prove","pos":"v.","phonetic":"[pruv]","meaning":"證明","definition":"to demonstrate the truth of something with evidence","collocations":["prove a theory","prove wrong","prove one's innocence"],"example":"The new evidence proved his innocence.","exampleZh":"新證據證明了他的清白。","synonyms":["demonstrate","confirm"],"level":2,"theme":"抽象概念","examples":[{"en":"The new evidence proved his innocence.","zh":"新證據證明了他的清白。"},{"en":"The scientist ran many tests to prove her theory.","zh":"這位科學家做了許多實驗來證明她的理論。"},{"en":"He worked hard to prove that his critics were wrong.","zh":"他努力工作以證明批評他的人錯了。"}]},{"word":"provide","pos":"v.","phonetic":"[prəˈvaɪd]","meaning":"提供；供給","definition":"to give someone something they need","collocations":["provide information","provide for a family","provide support"],"example":"The school provides free lunch for students in need.","exampleZh":"學校為有需要的學生提供免費午餐。","synonyms":["supply","give"],"level":3,"theme":"抽象概念","examples":[{"en":"The school provides free lunch for students in need.","zh":"學校為有需要的學生提供免費午餐。"},{"en":"The library provides free internet access to all students.","zh":"圖書館為所有學生提供免費的網路連線。"},{"en":"He works two jobs to provide for his young family.","zh":"他做兩份工作來供養他年輕的家庭。"}]},{"word":"province","pos":"n.","phonetic":"[ˈprɑvɪns]","meaning":"省；省份","definition":"a large administrative division of a country","collocations":["northern province","provincial capital","coastal province"],"example":"His hometown is in a small province in the south.","exampleZh":"他的家鄉在南部的一個小省份。","synonyms":["region"],"level":4,"theme":"時間與空間","examples":[{"en":"His hometown is in a small province in the south.","zh":"他的家鄉在南部的一個小省份。"},{"en":"Her grandparents live in a quiet province by the coast.","zh":"她的祖父母住在海岸邊一個寧靜的省份。"},{"en":"The northern province is famous for its beautiful mountains.","zh":"這個北方的省份以美麗的山脈聞名。"}]},{"word":"provoke","pos":"v.","phonetic":"[prəˈvok]","meaning":"激怒；引起","definition":"to cause a reaction or feeling, often anger","collocations":["provoke anger","provoke a reaction","provoke laughter"],"example":"His rude comment provoked an angry response.","exampleZh":"他無禮的評論引起了憤怒的回應。","synonyms":["trigger","incite"],"level":5,"theme":"情緒與感受","examples":[{"en":"His rude comment provoked an angry response.","zh":"他無禮的評論引起了憤怒的回應。"},{"en":"His unfair comment provoked anger among the audience.","zh":"他不公平的評論激怒了觀眾。"},{"en":"The funny cartoon provoked laughter from the whole class.","zh":"這部好笑的卡通引起全班哄堂大笑。"}]},{"word":"psychological","pos":"adj.","phonetic":"[ˌsaɪkəˈlɑdʒɪkl]","meaning":"心理的；心理學的","definition":"relating to the mind or mental processes","collocations":["psychological effect","psychological support","psychological test"],"example":"The accident left him with deep psychological scars.","exampleZh":"這場意外在他心裡留下了深深的創傷。","synonyms":["mental"],"level":5,"theme":"科學與數學","examples":[{"en":"The accident left him with deep psychological scars.","zh":"這場意外在他心裡留下了深深的創傷。"},{"en":"Losing the match had a strong psychological effect on the team.","zh":"輸掉比賽對這支隊伍造成強烈的心理影響。"},{"en":"Many patients need psychological support after a serious illness.","zh":"許多病人在重病後需要心理支持。"}]},{"word":"psychologist","pos":"n.","phonetic":"[saɪˈkɑlədʒɪst]","meaning":"心理學家","definition":"a person who studies or treats the human mind and behavior","collocations":["see a psychologist","clinical psychologist","child psychologist"],"example":"He decided to see a psychologist about his anxiety.","exampleZh":"他決定去找心理學家談談他的焦慮問題。","synonyms":[],"level":5,"theme":"工作與職業","examples":[{"en":"He decided to see a psychologist about his anxiety.","zh":"他決定去找心理學家談談他的焦慮問題。"},{"en":"The child psychologist helped the boy overcome his fear.","zh":"這位兒童心理學家幫助男孩克服恐懼。"},{"en":"She decided to see a psychologist to deal with her stress.","zh":"她決定去看心理學家來處理她的壓力。"}]},{"word":"psychology","pos":"n.","phonetic":"[saɪˈkɑlədʒi]","meaning":"心理學","definition":"the scientific study of the human mind and behavior","collocations":["study psychology","child psychology","psychology major"],"example":"She is majoring in psychology at university.","exampleZh":"她在大學主修心理學。","synonyms":[],"level":4,"theme":"科學與數學","examples":[{"en":"She is majoring in psychology at university.","zh":"她在大學主修心理學。"},{"en":"He plans to study psychology at university next year.","zh":"他打算明年在大學攻讀心理學。"},{"en":"Understanding child psychology helps teachers guide young learners.","zh":"了解兒童心理學有助於老師引導幼小的學習者。"}]},{"word":"puberty","pos":"n.","phonetic":"[ˈpjubɚti]","meaning":"青春期","definition":"the period during which adolescents reach sexual maturity","collocations":["reach puberty","during puberty","puberty changes"],"example":"Many physical changes happen during puberty.","exampleZh":"青春期會出現許多身體上的變化。","synonyms":["adolescence"],"level":5,"theme":"身體與健康","examples":[{"en":"Many physical changes happen during puberty.","zh":"青春期會出現許多身體上的變化。"},{"en":"Teenagers often experience many physical changes during puberty.","zh":"青少年在青春期常經歷許多身體上的變化。"},{"en":"Boys' voices usually deepen when they reach puberty.","zh":"男孩到了青春期時聲音通常會變低沉。"}]},{"word":"public","pos":"adj. / n.","phonetic":"[ˈpʌblɪk]","meaning":"公共的；公眾","definition":"open to or shared by all people; the general population","collocations":["public transportation","in public","general public"],"example":"The park is open to the public every day.","exampleZh":"這座公園每天都開放給大眾。","synonyms":["communal"],"level":2,"theme":"社會與文化","examples":[{"en":"The park is open to the public every day.","zh":"這座公園每天都開放給大眾。"},{"en":"The city encourages people to use public transportation.","zh":"這座城市鼓勵人們使用大眾運輸工具。"},{"en":"She felt nervous about speaking in public for the first time.","zh":"她對第一次公開演講感到緊張。"}]},{"word":"publish","pos":"v.","phonetic":"[ˈpʌblɪʃ]","meaning":"出版；發表","definition":"to prepare and issue a book, journal, or article for public sale or view","collocations":["publish a book","publish research","newly published"],"example":"The author published her first novel last year.","exampleZh":"這位作者去年出版了她的第一本小說。","synonyms":["release"],"level":4,"theme":"科技與媒體","examples":[{"en":"The author published her first novel last year.","zh":"這位作者去年出版了她的第一本小說。"},{"en":"The young writer hopes to publish her first book soon.","zh":"這位年輕作家希望很快出版她的第一本書。"},{"en":"The team will publish their research in a science journal.","zh":"這個團隊將在科學期刊上發表他們的研究。"}]},{"word":"pull","pos":"v. / n.","phonetic":"[pʊl]","meaning":"拉；拖","definition":"to apply force to move something toward oneself","collocations":["pull the rope","pull over","pull a muscle"],"example":"Please pull the door instead of pushing it.","exampleZh":"請把門拉開，不要用推的。","synonyms":["drag","tug"],"level":1,"theme":"動作與行為","examples":[{"en":"Please pull the door instead of pushing it.","zh":"請把門拉開，不要用推的。"},{"en":"The children tried to pull the heavy rope across the field.","zh":"孩子們試著把沉重的繩子拉過操場。"},{"en":"The driver pulled over to check the map.","zh":"駕駛把車停到路邊查看地圖。"}]},{"word":"pulse","pos":"n.","phonetic":"[pʌls]","meaning":"脈搏；脈動","definition":"the regular beating of blood through the arteries","collocations":["check one's pulse","weak pulse","pulse rate"],"example":"The nurse checked the patient's pulse.","exampleZh":"護理師檢查了病人的脈搏。","synonyms":["heartbeat"],"level":4,"theme":"身體與健康","examples":[{"en":"The nurse checked the patient's pulse.","zh":"護理師檢查了病人的脈搏。"},{"en":"The nurse gently checked the patient's pulse before the surgery.","zh":"護士在手術前輕輕地檢查了病人的脈搏。"},{"en":"After running fast, he could feel his pulse racing.","zh":"快跑之後，他能感覺到自己的脈搏加速跳動。"}]},{"word":"pump","pos":"n. / v.","phonetic":"[pʌmp]","meaning":"幫浦；抽水機；打氣","definition":"a device that moves liquid or gas, or to move it using such a device","collocations":["gas pump","pump water","pump up a tire"],"example":"He used a pump to inflate the bicycle tires.","exampleZh":"他用打氣筒給腳踏車輪胎打氣。","synonyms":[],"level":3,"theme":"科技與媒體","examples":[{"en":"He used a pump to inflate the bicycle tires.","zh":"他用打氣筒給腳踏車輪胎打氣。"},{"en":"Farmers use a pump to move water into the fields.","zh":"農夫用抽水機把水引入田裡。"},{"en":"He stopped at the gas station to pump up his tires.","zh":"他在加油站停下來為輪胎打氣。"}]},{"word":"punctual","pos":"adj.","phonetic":"[ˈpʌŋktʃuəl]","meaning":"準時的","definition":"arriving or doing something at the expected time; not late","collocations":["punctual arrival","always punctual","be punctual for"],"example":"He is always punctual for meetings.","exampleZh":"他開會總是很準時。","synonyms":["on time","prompt"],"level":5,"theme":"性質與描述","examples":[{"en":"He is always punctual for meetings.","zh":"他開會總是很準時。"},{"en":"A punctual student never keeps the teacher waiting.","zh":"準時的學生從不讓老師等候。"},{"en":"Please be punctual for the school trip tomorrow morning.","zh":"明天早上校外教學請務必準時。"}]},{"word":"punish","pos":"v.","phonetic":"[ˈpʌnɪʃ]","meaning":"處罰；懲罰","definition":"to make someone suffer for an offense or wrongdoing","collocations":["punish a crime","punish severely","get punished"],"example":"The teacher punished the students for cheating.","exampleZh":"老師處罰了作弊的學生。","synonyms":["penalize"],"level":3,"theme":"教育與學習","examples":[{"en":"The teacher punished the students for cheating.","zh":"老師處罰了作弊的學生。"},{"en":"The coach may punish players who arrive late for practice.","zh":"教練可能會處罰練習遲到的球員。"},{"en":"It is unfair to punish the whole class for one mistake.","zh":"因為一個錯誤就處罰全班是不公平的。"}]},{"word":"punishment","pos":"n.","phonetic":"[ˈpʌnɪʃmənt]","meaning":"懲罰；處罰","definition":"the act of punishing or the penalty imposed","collocations":["capital punishment","as punishment","harsh punishment"],"example":"His punishment for the crime was three years in prison.","exampleZh":"他因這項罪行被判處三年徒刑作為懲罰。","synonyms":["penalty"],"level":4,"theme":"政治與法律","examples":[{"en":"His punishment for the crime was three years in prison.","zh":"他因這項罪行被判處三年徒刑作為懲罰。"},{"en":"Losing his phone was a harsh punishment for the boy.","zh":"沒收手機對這男孩來說是嚴厲的懲罰。"},{"en":"As punishment, they had to clean the classroom after school.","zh":"作為懲罰，他們放學後必須打掃教室。"}]},{"word":"pupil","pos":"n.","phonetic":"[ˈpjupl]","meaning":"學生；瞳孔","definition":"a school student, or the black circular opening in the eye","collocations":["primary school pupil","dilated pupil","bright pupil"],"example":"The teacher praised her brightest pupil.","exampleZh":"老師稱讚她最聰明的學生。","synonyms":["student"],"level":3,"theme":"教育與學習","examples":[{"en":"The teacher praised her brightest pupil.","zh":"老師稱讚她最聰明的學生。"},{"en":"Every pupil in the class handed in the homework on time.","zh":"班上每位學生都準時交了作業。"},{"en":"In bright light, the pupil of the eye becomes smaller.","zh":"在強光下，眼睛的瞳孔會變小。"}]},{"word":"puppet","pos":"n.","phonetic":"[ˈpʌpɪt]","meaning":"木偶；傀儡","definition":"a small figure moved by strings or by hand","collocations":["puppet show","hand puppet","puppet government"],"example":"The children enjoyed the puppet show at the fair.","exampleZh":"孩子們很喜歡園遊會上的木偶戲。","synonyms":[],"level":2,"theme":"藝術與音樂","examples":[{"en":"The children enjoyed the puppet show at the fair.","zh":"孩子們很喜歡園遊會上的木偶戲。"},{"en":"The little girl made her hand puppet dance and sing.","zh":"小女孩讓她的手偶又跳又唱。"},{"en":"We watched a wonderful puppet show at the school fair.","zh":"我們在學校園遊會上看了一場精彩的木偶戲。"}]},{"word":"puppy","pos":"n.","phonetic":"[ˈpʌpi]","meaning":"小狗；幼犬","definition":"a young dog","collocations":["puppy love","cute puppy","raise a puppy"],"example":"We adopted a puppy from the shelter last week.","exampleZh":"我們上星期從收容所領養了一隻小狗。","synonyms":[],"level":1,"theme":"動物與植物","examples":[{"en":"We adopted a puppy from the shelter last week.","zh":"我們上星期從收容所領養了一隻小狗。"},{"en":"The children laughed as the puppy chased its own tail.","zh":"小狗追著自己的尾巴，孩子們笑了起來。"},{"en":"Raising a puppy takes patience and a lot of care.","zh":"養一隻幼犬需要耐心和許多照顧。"}]},{"word":"purchase","pos":"v. / n.","phonetic":"[ˈpɝtʃəs]","meaning":"購買；購買物","definition":"to buy something","collocations":["purchase a ticket","make a purchase","online purchase"],"example":"She purchased a new laptop for school.","exampleZh":"她為了上學買了一台新筆電。","synonyms":["buy"],"level":4,"theme":"商業與金錢","examples":[{"en":"She purchased a new laptop for school.","zh":"她為了上學買了一台新筆電。"},{"en":"She saved money for months to purchase a new bicycle.","zh":"她存了好幾個月的錢才購買一輛新腳踏車。"},{"en":"You can make a purchase online and pick it up later.","zh":"你可以線上購買，之後再取貨。"}]},{"word":"pure","pos":"adj.","phonetic":"[pjʊr]","meaning":"純的；純粹的","definition":"not mixed with any other substance or material; complete","collocations":["pure gold","pure water","pure luck"],"example":"This bottle contains pure orange juice with no sugar added.","exampleZh":"這瓶裝的是純柳橙汁，沒有加糖。","synonyms":["unmixed"],"level":3,"theme":"性質與描述","examples":[{"en":"This bottle contains pure orange juice with no sugar added.","zh":"這瓶裝的是純柳橙汁，沒有加糖。"},{"en":"This beautiful ring is made of pure gold.","zh":"這只美麗的戒指是用純金製成的。"},{"en":"Winning the prize was pure luck, she admitted.","zh":"她承認贏得獎品純粹是運氣。"}]},{"word":"purple","pos":"adj. / n.","phonetic":"[ˈpɝpl]","meaning":"紫色的；紫色","definition":"a color between red and blue","collocations":["purple flower","dark purple","turn purple"],"example":"She painted her bedroom walls purple.","exampleZh":"她把臥室的牆漆成紫色。","synonyms":[],"level":1,"theme":"服裝與外表","examples":[{"en":"She painted her bedroom walls purple.","zh":"她把臥室的牆漆成紫色。"},{"en":"A field of purple flowers stretched across the hillside.","zh":"一片紫色的花朵綿延在山坡上。"},{"en":"She chose a dark purple dress for the school concert.","zh":"她為學校音樂會選了一件深紫色的洋裝。"}]},{"word":"purpose","pos":"n.","phonetic":"[ˈpɝpəs]","meaning":"目的；意圖","definition":"the reason for which something is done or exists","collocations":["on purpose","serve a purpose","sense of purpose"],"example":"What is the purpose of this meeting?","exampleZh":"這次會議的目的是什麼？","synonyms":["aim","goal"],"level":2,"theme":"抽象概念","examples":[{"en":"What is the purpose of this meeting?","zh":"這次會議的目的是什麼？"},{"en":"The purpose of this experiment is to test the water quality.","zh":"這個實驗的目的是測試水質。"},{"en":"He didn't break the vase on purpose; it was an accident.","zh":"他不是故意打破花瓶的，那是意外。"}]},{"word":"pursue","pos":"v.","phonetic":"[pɚˈsu]","meaning":"追求；從事","definition":"to follow or work toward achieving a goal","collocations":["pursue a career","pursue happiness","pursue a dream"],"example":"She decided to pursue a career in medicine.","exampleZh":"她決定從事醫學方面的職業。","synonyms":["chase","seek"],"level":4,"theme":"工作與職業","examples":[{"en":"She decided to pursue a career in medicine.","zh":"她決定從事醫學方面的職業。"},{"en":"She hopes to pursue a career in engineering after college.","zh":"她希望大學畢業後從事工程方面的職業。"},{"en":"Never give up if you truly want to pursue your dream.","zh":"如果你真心想追求夢想，就永遠別放棄。"}]},{"word":"push","pos":"v. / n.","phonetic":"[pʊʃ]","meaning":"推；推動","definition":"to apply force to move something away from oneself","collocations":["push the door","push forward","push someone to do"],"example":"He pushed the cart down the aisle.","exampleZh":"他推著推車走過走道。","synonyms":["shove"],"level":1,"theme":"動作與行為","examples":[{"en":"He pushed the cart down the aisle.","zh":"他推著推車走過走道。"},{"en":"He had to push the door hard because it was stuck.","zh":"因為門卡住了，他必須用力推。"},{"en":"Her parents gently pushed her to try new things.","zh":"她的父母溫和地推動她去嘗試新事物。"}]},{"word":"put","pos":"v.","phonetic":"[pʊt]","meaning":"放；擺放","definition":"to move something into a particular place or position","collocations":["put away","put on","put off"],"example":"Please put the books back on the shelf.","exampleZh":"請把書放回書架上。","synonyms":["place"],"level":1,"theme":"動作與行為","examples":[{"en":"Please put the books back on the shelf.","zh":"請把書放回書架上。"},{"en":"Please put on your jacket before going out in the cold.","zh":"出門到寒冷的地方前請穿上外套。"},{"en":"Don't put off your homework until the last minute.","zh":"別把作業拖到最後一刻才做。"}]},{"word":"puzzle","pos":"n. / v.","phonetic":"[ˈpʌzl]","meaning":"謎題；拼圖；使困惑","definition":"a game or problem that tests ingenuity, or to confuse someone","collocations":["jigsaw puzzle","solve a puzzle","be puzzled by"],"example":"The children spent hours doing a jigsaw puzzle.","exampleZh":"孩子們花了好幾個小時玩拼圖。","synonyms":["riddle","confuse"],"level":2,"theme":"運動與休閒","examples":[{"en":"The children spent hours doing a jigsaw puzzle.","zh":"孩子們花了好幾個小時玩拼圖。"},{"en":"The strange noise at night puzzled the whole family.","zh":"夜裡奇怪的聲音使全家人困惑。"},{"en":"They worked together to solve the difficult puzzle.","zh":"他們一起合作解開這道困難的謎題。"}]},{"word":"pyramid","pos":"n.","phonetic":"[ˈpɪrəmɪd]","meaning":"金字塔；角錐體","definition":"a structure with a square base and four triangular sides meeting at a point","collocations":["ancient pyramid","food pyramid","build a pyramid"],"example":"Tourists from around the world visit the pyramids of Egypt.","exampleZh":"來自世界各地的遊客都會參觀埃及的金字塔。","synonyms":[],"level":3,"theme":"社會與文化","examples":[{"en":"Tourists from around the world visit the pyramids of Egypt.","zh":"來自世界各地的遊客都會參觀埃及的金字塔。"},{"en":"The food pyramid shows which foods we should eat most.","zh":"食物金字塔顯示我們應該多吃哪些食物。"},{"en":"Workers spent many years building the ancient pyramid.","zh":"工人們花了許多年建造這座古老的金字塔。"}]},{"word":"python","pos":"n.","phonetic":"[ˈpaɪθɑn]","meaning":"蟒蛇","definition":"a large nonvenomous snake that squeezes its prey","collocations":["pet python","giant python","a python's grip"],"example":"The zoo has a huge python in its reptile house.","exampleZh":"動物園的爬蟲館裡有一條巨大的蟒蛇。","synonyms":[],"level":4,"theme":"動物與植物","examples":[{"en":"The zoo has a huge python in its reptile house.","zh":"動物園的爬蟲館裡有一條巨大的蟒蛇。"},{"en":"A giant python slowly wrapped itself around the tree branch.","zh":"一條巨大的蟒蛇緩緩地纏繞在樹枝上。"},{"en":"The keeper carefully fed the pet python at the zoo.","zh":"飼育員在動物園裡小心地餵食寵物蟒蛇。"}]},{"word":"quack","pos":"n. / v.","phonetic":"[kwæk]","meaning":"呱呱聲；江湖郎中","definition":"the sound a duck makes, or a person who falsely claims to have medical skill","collocations":["duck quacks","quack doctor","quack remedy"],"example":"The duck let out a loud quack when we approached.","exampleZh":"我們靠近時，那隻鴨子發出響亮的呱呱聲。","synonyms":["charlatan"],"level":1,"theme":"動物與植物","examples":[{"en":"The duck let out a loud quack when we approached.","zh":"我們靠近時，那隻鴨子發出響亮的呱呱聲。"},{"en":"The ducks swam in the pond with a cheerful quack.","zh":"鴨子們在池塘裡游著，發出愉快的呱呱聲。"},{"en":"Don't trust that quack doctor's strange and useless cures.","zh":"別相信那個江湖郎中奇怪又沒用的療法。"}]},{"word":"quaint","pos":"adj.","phonetic":"[kwent]","meaning":"古雅的；古色古香的","definition":"attractively unusual or old-fashioned","collocations":["quaint village","quaint little shop","quaint custom"],"example":"We stayed in a quaint little cottage near the sea.","exampleZh":"我們住在海邊一間古色古香的小屋。","synonyms":["charming","old-fashioned"],"level":5,"theme":"性質與描述","examples":[{"en":"We stayed in a quaint little cottage near the sea.","zh":"我們住在海邊一間古色古香的小屋。"},{"en":"We visited a quaint village full of old stone houses.","zh":"我們造訪了一個滿是古老石屋的古色古香村莊。"},{"en":"The quaint little shop sold handmade toys and candles.","zh":"這家古雅的小店賣手工玩具和蠟燭。"}]},{"word":"quake","pos":"v. / n.","phonetic":"[kwek]","meaning":"顫抖；震動；地震","definition":"to shake violently, often from fear or an earthquake","collocations":["quake with fear","the ground quaked","an earthquake"],"example":"She began to quake with fear when the lights went out.","exampleZh":"燈光熄滅時，她害怕得開始顫抖。","synonyms":["tremble","shake"],"level":4,"theme":"情緒與感受","examples":[{"en":"She began to quake with fear when the lights went out.","zh":"燈光熄滅時，她害怕得開始顫抖。"},{"en":"The ground began to quake during the powerful earthquake.","zh":"在強烈的地震中，地面開始震動。"},{"en":"She started to quake with fear as the storm grew louder.","zh":"隨著暴風雨聲越來越大，她開始因恐懼而顫抖。"}]},{"word":"qualification","pos":"n.","phonetic":"[͵kwɑləfəˈkeʃən]","meaning":"資格；證書；條件","definition":"a skill or achievement that makes someone suitable for a job or task","collocations":["professional qualification","meet the qualifications","academic qualification"],"example":"You need a teaching qualification to work at this school.","exampleZh":"你需要教師資格才能在這所學校任教。","synonyms":["credential","certification"],"level":4,"theme":"教育與學習","examples":[{"en":"You need a teaching qualification to work at this school.","zh":"你需要教師資格才能在這所學校任教。"},{"en":"You need the right qualifications to become a nurse.","zh":"你需要適當的資格才能成為護士。"},{"en":"He listed all his academic qualifications on the form.","zh":"他在表格上列出了所有的學歷。"}]},{"word":"qualify","pos":"v.","phonetic":"[ˈkwɑlə͵faɪ]","meaning":"取得資格；使合格；限定","definition":"to have or gain the necessary skill or knowledge to do something","collocations":["qualify for a job","qualify as a doctor","qualify for the finals"],"example":"She studied hard to qualify as a lawyer.","exampleZh":"她努力讀書以取得律師資格。","synonyms":["become eligible"],"level":3,"theme":"教育與學習","examples":[{"en":"She studied hard to qualify as a lawyer.","zh":"她努力讀書以取得律師資格。"},{"en":"She studied for years to qualify as a doctor.","zh":"她苦讀多年才取得醫生的資格。"},{"en":"The team won the match and qualified for the finals.","zh":"這支隊伍贏得比賽，取得了決賽資格。"}]},{"word":"quality","pos":"n. / adj.","phonetic":"[ˈkwɑlətɪ]","meaning":"品質；特質；優質的","definition":"the standard of something as measured against other things of a similar kind","collocations":["high quality","quality of life","quality control"],"example":"The company is known for the high quality of its products.","exampleZh":"這家公司以產品的高品質聞名。","synonyms":["standard","grade"],"level":2,"theme":"性質與描述","examples":[{"en":"The company is known for the high quality of its products.","zh":"這家公司以產品的高品質聞名。"},{"en":"Customers trust this brand for its high quality.","zh":"顧客信賴這個品牌，因為它品質優良。"},{"en":"Kindness is a valuable quality that everyone deeply admires.","zh":"善良是一種人人都深深欽佩的珍貴特質。"}]},{"word":"quantity","pos":"n.","phonetic":"[ˈkwɑntətɪ]","meaning":"數量；分量","definition":"an amount or number of something","collocations":["a large quantity","in quantity","quantity over quality"],"example":"The factory produces a huge quantity of goods every day.","exampleZh":"這家工廠每天生產大量的貨物。","synonyms":["amount","volume"],"level":2,"theme":"科學與數學","examples":[{"en":"The factory produces a huge quantity of goods every day.","zh":"這家工廠每天生產大量的貨物。"},{"en":"The bakery sells bread in large quantities every morning.","zh":"這家麵包店每天早上大量販售麵包。"},{"en":"When cooking a meal, quality matters more than quantity.","zh":"烹煮一餐時，品質比數量更重要。"}]},{"word":"quarrel","pos":"n. / v.","phonetic":"[ˈkwɔrəl]","meaning":"爭吵；口角","definition":"an angry argument or disagreement","collocations":["have a quarrel","quarrel with someone","a family quarrel"],"example":"The two brothers had a quarrel over money.","exampleZh":"這對兄弟為了錢發生爭吵。","synonyms":["argument","dispute"],"level":3,"theme":"溝通與語言","examples":[{"en":"The two brothers had a quarrel over money.","zh":"這對兄弟為了錢發生爭吵。"},{"en":"The two friends had a quarrel but soon made up.","zh":"這兩個朋友吵了架，但很快就和好了。"},{"en":"It is silly to quarrel with your sister over a toy.","zh":"為了一個玩具和妹妹爭吵是很傻的。"}]},{"word":"quarter","pos":"n.","phonetic":"[ˈkwɔrtɚ]","meaning":"四分之一；一刻鐘；季度","definition":"one of four equal parts of something","collocations":["a quarter of an hour","the first quarter","quarter final"],"example":"The meeting will start in a quarter of an hour.","exampleZh":"會議將在十五分鐘後開始。","synonyms":[],"level":2,"theme":"時間與空間","examples":[{"en":"The meeting will start in a quarter of an hour.","zh":"會議將在十五分鐘後開始。"},{"en":"The bus will arrive in a quarter of an hour.","zh":"公車將在一刻鐘後抵達。"},{"en":"She ate a quarter of the pizza and saved the rest.","zh":"她吃了四分之一的披薩，剩下的留著。"}]},{"word":"quarterly","pos":"adj. / adv.","phonetic":"[ˈkwɔrtɚlɪ]","meaning":"每季的；按季度的","definition":"happening or produced four times a year","collocations":["quarterly report","quarterly meeting","paid quarterly"],"example":"The company publishes a quarterly report on its earnings.","exampleZh":"這家公司每季發布一份盈餘報告。","synonyms":[],"level":5,"theme":"商業與金錢","examples":[{"en":"The company publishes a quarterly report on its earnings.","zh":"這家公司每季發布一份盈餘報告。"},{"en":"The company holds a quarterly meeting to review its progress.","zh":"公司每季開一次會議來檢討進度。"},{"en":"Students receive a quarterly report on their grades.","zh":"學生每季會收到一份成績報告。"}]},{"word":"queen","pos":"n.","phonetic":"[kwin]","meaning":"女王；王后","definition":"a female ruler of a country, or the wife of a king","collocations":["the queen bee","queen of England","beauty queen"],"example":"The queen waved to the crowd from the palace balcony.","exampleZh":"女王從皇宮陽台向群眾揮手。","synonyms":[],"level":1,"theme":"政治與法律","examples":[{"en":"The queen waved to the crowd from the palace balcony.","zh":"女王從皇宮陽台向群眾揮手。"},{"en":"The queen greeted the visitors with a warm smile.","zh":"女王以溫暖的微笑迎接訪客。"},{"en":"In the hive, the queen bee lays all the eggs.","zh":"在蜂巢裡，蜂后負責產下所有的卵。"}]},{"word":"queer","pos":"adj.","phonetic":"[kwɪr]","meaning":"奇怪的；古怪的","definition":"strange or odd","collocations":["a queer feeling","something queer","look queer"],"example":"There was something queer about the old house.","exampleZh":"那棟老房子有些奇怪。","synonyms":["odd","strange"],"level":5,"theme":"性質與描述","examples":[{"en":"There was something queer about the old house.","zh":"那棟老房子有些奇怪。"},{"en":"A queer smell came from the old, empty kitchen.","zh":"一股奇怪的味道從那空蕩老舊的廚房飄出。"},{"en":"She had a queer feeling that someone was watching her.","zh":"她有種古怪的感覺，覺得有人在看著她。"}]},{"word":"quench","pos":"v.","phonetic":"[kwɛntʃ]","meaning":"解渴；撲滅","definition":"to satisfy thirst by drinking, or to put out a fire","collocations":["quench your thirst","quench a fire","quench the flames"],"example":"A cold glass of water quenched his thirst.","exampleZh":"一杯冰水解了他的渴。","synonyms":["satisfy","extinguish"],"level":5,"theme":"食物與烹飪","examples":[{"en":"A cold glass of water quenched his thirst.","zh":"一杯冰水解了他的渴。"},{"en":"A cool glass of lemonade quenched their thirst after the game.","zh":"一杯冰涼的檸檬水在比賽後解了他們的渴。"},{"en":"Firefighters worked hard to quench the flames in the forest.","zh":"消防員努力撲滅森林裡的火焰。"}]},{"word":"query","pos":"n. / v.","phonetic":"[ˈkwɪrɪ]","meaning":"疑問；詢問；質疑","definition":"a question, especially one asking for information or expressing doubt","collocations":["raise a query","query about","database query"],"example":"Please email us if you have any queries about the product.","exampleZh":"如果對產品有任何疑問，請寄電子郵件給我們。","synonyms":["question","inquiry"],"level":5,"theme":"溝通與語言","examples":[{"en":"Please email us if you have any queries about the product.","zh":"如果對產品有任何疑問，請寄電子郵件給我們。"},{"en":"Please raise a query if any part of the lesson is unclear.","zh":"若課程有任何不清楚的地方，請提出疑問。"},{"en":"The librarian answered every query about the new books patiently.","zh":"圖書館員耐心地回答關於新書的每個詢問。"}]},{"word":"quest","pos":"n.","phonetic":"[kwɛst]","meaning":"追求；探索；探尋","definition":"a long search for something that is difficult to find","collocations":["quest for knowledge","quest for truth","on a quest"],"example":"The knight set out on a quest to find the lost treasure.","exampleZh":"騎士出發去探尋那失落的寶藏。","synonyms":["search","pursuit"],"level":5,"theme":"抽象概念","examples":[{"en":"The knight set out on a quest to find the lost treasure.","zh":"騎士出發去探尋那失落的寶藏。"},{"en":"Her quest for knowledge led her to read hundreds of books.","zh":"她對知識的追求使她讀了數百本書。"},{"en":"The explorers set out on a quest to find clean water.","zh":"探險家們踏上尋找乾淨水源的探索之旅。"}]},{"word":"question","pos":"n. / v.","phonetic":"[ˈkwɛstʃən]","meaning":"問題；疑問；質疑","definition":"a sentence used to ask for information, or to express doubt about something","collocations":["ask a question","question a decision","good question"],"example":"The teacher asked a difficult question about history.","exampleZh":"老師問了一個關於歷史的難題。","synonyms":["ask","doubt"],"level":1,"theme":"溝通與語言","examples":[{"en":"The teacher asked a difficult question about history.","zh":"老師問了一個關於歷史的難題。"},{"en":"The student raised her hand to ask a question.","zh":"這位學生舉手問了一個問題。"},{"en":"Some people began to question the fairness of the new rule.","zh":"有些人開始質疑這項新規定的公平性。"}]},{"word":"questionnaire","pos":"n.","phonetic":"[͵kwɛstʃənˈɛr]","meaning":"問卷","definition":"a written set of questions given to people to gather information","collocations":["fill in a questionnaire","survey questionnaire","online questionnaire"],"example":"Please fill in this questionnaire about your shopping habits.","exampleZh":"請填寫這份關於購物習慣的問卷。","synonyms":["survey"],"level":4,"theme":"溝通與語言","examples":[{"en":"Please fill in this questionnaire about your shopping habits.","zh":"請填寫這份關於購物習慣的問卷。"},{"en":"Please fill in the questionnaire about your reading habits.","zh":"請填寫這份關於你閱讀習慣的問卷。"},{"en":"The class used an online questionnaire to collect opinions.","zh":"全班用線上問卷來收集意見。"}]},{"word":"queue","pos":"n. / v.","phonetic":"[kju]","meaning":"隊伍；排隊","definition":"a line of people or vehicles waiting for something","collocations":["queue up","wait in a queue","jump the queue"],"example":"We had to queue up for over an hour to buy tickets.","exampleZh":"我們得排隊超過一小時才能買到票。","synonyms":["line"],"level":4,"theme":"居家與生活","examples":[{"en":"We had to queue up for over an hour to buy tickets.","zh":"我們得排隊超過一小時才能買到票。"},{"en":"A long queue formed outside the popular ice-cream shop.","zh":"熱門冰淇淋店外排起了長長的隊伍。"},{"en":"We had to queue for an hour to enter the museum.","zh":"我們得排隊一小時才能進入博物館。"}]},{"word":"quick","pos":"adj. / adv.","phonetic":"[kwɪk]","meaning":"快的；迅速的","definition":"moving or happening fast","collocations":["a quick answer","quick meal","quick to react"],"example":"She gave a quick reply to the email.","exampleZh":"她迅速回覆了那封電子郵件。","synonyms":["fast","swift"],"level":1,"theme":"性質與描述","examples":[{"en":"She gave a quick reply to the email.","zh":"她迅速回覆了那封電子郵件。"},{"en":"She gave a quick answer before the bell rang.","zh":"在鐘響前她迅速地回答了。"},{"en":"Let's grab a quick meal before the movie starts.","zh":"我們在電影開始前快速吃頓飯吧。"}]},{"word":"quiet","pos":"adj. / n.","phonetic":"[ˈkwaɪət]","meaning":"安靜的；寧靜","definition":"making little or no noise","collocations":["a quiet place","keep quiet","quiet down"],"example":"Please be quiet in the library.","exampleZh":"在圖書館裡請保持安靜。","synonyms":["silent","calm"],"level":1,"theme":"性質與描述","examples":[{"en":"Please be quiet in the library.","zh":"在圖書館裡請保持安靜。"},{"en":"The library is a quiet place perfect for studying.","zh":"圖書館是個安靜的地方，非常適合讀書。"},{"en":"Please keep quiet while the baby is sleeping.","zh":"寶寶睡覺時請保持安靜。"}]},{"word":"quilt","pos":"n.","phonetic":"[kwɪlt]","meaning":"被子；棉被","definition":"a bed cover made of two layers of cloth with a soft material in between","collocations":["patchwork quilt","make a quilt","under the quilt"],"example":"Grandma sewed a beautiful patchwork quilt for the new baby.","exampleZh":"奶奶為新生兒縫製了一條美麗的拼布被子。","synonyms":["blanket","comforter"],"level":3,"theme":"居家與生活","examples":[{"en":"Grandma sewed a beautiful patchwork quilt for the new baby.","zh":"奶奶為新生兒縫製了一條美麗的拼布被子。"},{"en":"Grandmother sewed a warm quilt for the cold winter.","zh":"祖母縫了一床溫暖的棉被過寒冬。"},{"en":"The children snuggled under the soft patchwork quilt.","zh":"孩子們依偎在柔軟的拼布被子下。"}]},{"word":"quit","pos":"v.","phonetic":"[kwɪt]","meaning":"放棄；辭職；停止","definition":"to stop doing something, or to leave a job","collocations":["quit smoking","quit a job","quit trying"],"example":"He decided to quit his job and travel around the world.","exampleZh":"他決定辭職並環遊世界。","synonyms":["stop","resign"],"level":2,"theme":"工作與職業","examples":[{"en":"He decided to quit his job and travel around the world.","zh":"他決定辭職並環遊世界。"},{"en":"The doctor advised him to quit smoking for his health.","zh":"醫生建議他為了健康戒菸。"},{"en":"She refused to quit even when the task became difficult.","zh":"即使任務變得困難，她也拒絕放棄。"}]},{"word":"quite","pos":"adv.","phonetic":"[kwaɪt]","meaning":"相當；完全","definition":"to a fairly high degree; completely","collocations":["quite good","quite a lot","not quite"],"example":"The movie was quite interesting, actually.","exampleZh":"老實說，這部電影相當有趣。","synonyms":["fairly","rather"],"level":1,"theme":"性質與描述","examples":[{"en":"The movie was quite interesting, actually.","zh":"老實說，這部電影相當有趣。"},{"en":"The science lecture was quite interesting and easy to follow.","zh":"這場科學講座相當有趣且容易理解。"},{"en":"I'm not quite finished with my homework yet.","zh":"我的作業還沒完全做完。"}]},{"word":"quiver","pos":"v. / n.","phonetic":"[ˈkwɪvɚ]","meaning":"顫抖；發抖","definition":"to shake with a slight rapid motion, often from emotion","collocations":["quiver with excitement","voice quivered","quiver in fear"],"example":"Her voice quivered as she spoke about her loss.","exampleZh":"她談到自己的失去時，聲音顫抖著。","synonyms":["tremble","shiver"],"level":5,"theme":"情緒與感受","examples":[{"en":"Her voice quivered as she spoke about her loss.","zh":"她談到自己的失去時，聲音顫抖著。"},{"en":"His hands began to quiver with excitement before the results.","zh":"在結果公布前，他的手因興奮而開始顫抖。"},{"en":"Her lips quivered as she tried not to cry.","zh":"她努力不哭，嘴唇卻在發抖。"}]},{"word":"quiz","pos":"n. / v.","phonetic":"[kwɪz]","meaning":"小考；測驗；問答","definition":"a short test of knowledge, or to ask someone questions","collocations":["pop quiz","quiz show","take a quiz"],"example":"We had a surprise quiz in math class today.","exampleZh":"我們今天在數學課上有一個突擊小考。","synonyms":["test"],"level":2,"theme":"教育與學習","examples":[{"en":"We had a surprise quiz in math class today.","zh":"我們今天在數學課上有一個突擊小考。"},{"en":"The teacher gave a pop quiz at the start of class.","zh":"老師在上課一開始就來個突擊小考。"},{"en":"We enjoyed answering questions on the fun quiz show.","zh":"我們很享受在有趣的問答節目上回答問題。"}]},{"word":"quota","pos":"n.","phonetic":"[ˈkwotə]","meaning":"配額；限額","definition":"a fixed limited amount or number that is officially allowed","collocations":["meet a quota","sales quota","import quota"],"example":"Each salesperson must meet a monthly sales quota.","exampleZh":"每位業務員每月必須達成銷售配額。","synonyms":["allotment","share"],"level":6,"theme":"商業與金錢","examples":[{"en":"Each salesperson must meet a monthly sales quota.","zh":"每位業務員每月必須達成銷售配額。"},{"en":"Each salesperson must meet a strict monthly sales quota.","zh":"每位業務員都必須達到嚴格的每月銷售配額。"},{"en":"The country set an import quota on foreign cars.","zh":"這個國家對外國汽車設定了進口限額。"}]},{"word":"quotation","pos":"n.","phonetic":"[kwoˈteʃən]","meaning":"引用；引語；報價","definition":"a phrase taken from a text, or a stated price for a job or service","collocations":["famous quotation","get a quotation","quotation mark"],"example":"The teacher wrote a famous quotation on the board.","exampleZh":"老師在黑板上寫了一句名言。","synonyms":["quote","citation"],"level":5,"theme":"溝通與語言","examples":[{"en":"The teacher wrote a famous quotation on the board.","zh":"老師在黑板上寫了一句名言。"},{"en":"She began her speech with a famous quotation about hope.","zh":"她以一句關於希望的名言引語開始演講。"},{"en":"The builder gave us a quotation for repairing the roof.","zh":"建築工人給了我們修理屋頂的報價。"}]},{"word":"quote","pos":"v. / n.","phonetic":"[kwot]","meaning":"引用；引述；報價","definition":"to repeat the exact words of someone else, or a price offered for goods or services","collocations":["quote a price","quote from a book","direct quote"],"example":"He often quotes lines from his favorite novel.","exampleZh":"他常常引用他最喜歡的小說中的句子。","synonyms":["cite"],"level":4,"theme":"溝通與語言","examples":[{"en":"He often quotes lines from his favorite novel.","zh":"他常常引用他最喜歡的小說中的句子。"},{"en":"He likes to quote lines from his favorite poems.","zh":"他喜歡引用他最愛的詩句。"},{"en":"The shop will quote a price for fixing your phone.","zh":"這家店會為修理你的手機報個價格。"}]},{"word":"quotient","pos":"n.","phonetic":"[ˈkwoʃənt]","meaning":"商（數）","definition":"the result obtained by dividing one number by another","collocations":["intelligence quotient","the quotient of division"],"example":"Divide the two numbers to find the quotient.","exampleZh":"將這兩個數相除以求出商數。","synonyms":[],"level":6,"theme":"科學與數學","examples":[{"en":"Divide the two numbers to find the quotient.","zh":"將這兩個數相除以求出商數。"},{"en":"When you divide twenty by four, the quotient is five.","zh":"二十除以四，商是五。"},{"en":"The teacher explained how to find the quotient of two numbers.","zh":"老師解釋如何求出兩數相除的商。"}]},{"word":"rabbit","pos":"n.","phonetic":"[ˈræbɪt]","meaning":"兔子","definition":"a small mammal with long ears that lives in a burrow","collocations":["a wild rabbit","keep a rabbit as a pet","rabbit hole"],"example":"My little sister has a white rabbit as a pet.","exampleZh":"我妹妹養了一隻白兔當寵物。","synonyms":["bunny"],"level":1,"theme":"動物與植物","examples":[{"en":"My little sister has a white rabbit as a pet.","zh":"我妹妹養了一隻白兔當寵物。"},{"en":"A wild rabbit hopped quickly across the green field.","zh":"一隻野兔迅速地跳過綠色的田野。"},{"en":"My little sister keeps a fluffy rabbit as a pet.","zh":"我妹妹養了一隻毛茸茸的兔子當寵物。"}]},{"word":"race","pos":"n. / v.","phonetic":"[res]","meaning":"賽跑；比賽；種族","definition":"a competition to see who is fastest, or a group of people classified by shared physical traits","collocations":["win a race","a horse race","race against time"],"example":"He trained hard to win the race.","exampleZh":"他努力訓練以贏得這場比賽。","synonyms":["contest","competition"],"level":1,"theme":"運動與休閒","examples":[{"en":"He trained hard to win the race.","zh":"他努力訓練以贏得這場比賽。"},{"en":"He trained every day to win the school running race.","zh":"他每天訓練，只為贏得學校的賽跑比賽。"},{"en":"The two cars raced against time to reach the finish line.","zh":"這兩輛車與時間賽跑，衝向終點線。"}]},{"word":"rack","pos":"n. / v.","phonetic":"[ræk]","meaning":"架子；使痛苦","definition":"a frame or structure for holding or storing things","collocations":["a towel rack","a spice rack","rack one's brain"],"example":"He hung his coat on the rack by the door.","exampleZh":"他把外套掛在門邊的架子上。","synonyms":["shelf","stand"],"level":2,"theme":"居家與生活","examples":[{"en":"He hung his coat on the rack by the door.","zh":"他把外套掛在門邊的架子上。"},{"en":"She hung her wet towel on the rack to dry.","zh":"她把濕毛巾掛在架子上晾乾。"},{"en":"He racked his brain trying to remember the answer.","zh":"他絞盡腦汁試著想起答案。"}]},{"word":"radiant","pos":"adj.","phonetic":"[ˈredɪənt]","meaning":"容光煥發的；發光的","definition":"shining brightly or showing great happiness","collocations":["a radiant smile","radiant sunshine","look radiant"],"example":"The bride looked radiant on her wedding day.","exampleZh":"新娘在婚禮當天看起來容光煥發。","synonyms":["glowing","bright"],"level":4,"theme":"情緒與感受","examples":[{"en":"The bride looked radiant on her wedding day.","zh":"新娘在婚禮當天看起來容光煥發。"},{"en":"The bride looked radiant as she walked down the aisle.","zh":"新娘走過紅毯時看起來容光煥發。"},{"en":"Her radiant smile instantly brightened the mood of everyone present.","zh":"她燦爛的笑容立刻照亮了在場每個人的心情。"}]},{"word":"radiate","pos":"v.","phonetic":"[ˈredɪˌet]","meaning":"發射；散發","definition":"to send out light, heat, or energy in all directions","collocations":["radiate heat","radiate confidence","radiate from a center"],"example":"The stove radiated warmth throughout the small room.","exampleZh":"暖爐把熱氣散發到整個小房間。","synonyms":["emit","give off"],"level":4,"theme":"科學與數學","examples":[{"en":"The stove radiated warmth throughout the small room.","zh":"暖爐把熱氣散發到整個小房間。"},{"en":"The old stove radiated heat throughout the small cabin.","zh":"老舊的火爐向整間小木屋散發熱氣。"},{"en":"The confident speaker radiated calm and warmth to the audience.","zh":"這位自信的講者向觀眾散發著沉著與溫暖。"}]},{"word":"radiation","pos":"n.","phonetic":"[ˌredɪˈeʃən]","meaning":"輻射；放射線","definition":"energy that comes from a source in the form of rays or particles","collocations":["radiation exposure","solar radiation","radiation treatment"],"example":"Scientists measured the radiation levels near the plant.","exampleZh":"科學家測量了工廠附近的輻射量。","synonyms":[],"level":5,"theme":"科學與數學","examples":[{"en":"Scientists measured the radiation levels near the plant.","zh":"科學家測量了工廠附近的輻射量。"},{"en":"Scientists measured the radiation levels around the power plant.","zh":"科學家測量了電廠周圍的輻射量。"},{"en":"Too much solar radiation can damage your skin.","zh":"過多的太陽輻射會傷害你的皮膚。"}]},{"word":"radical","pos":"adj. / n.","phonetic":"[ˈrædɪkḷ]","meaning":"根本的；激進的；激進分子","definition":"relating to the most basic and important parts of something; extreme","collocations":["a radical change","radical ideas","a political radical"],"example":"The company made radical changes to its business model.","exampleZh":"這家公司對經營模式做了根本性的改變。","synonyms":["extreme","fundamental"],"level":5,"theme":"抽象概念","examples":[{"en":"The company made radical changes to its business model.","zh":"這家公司對經營模式做了根本性的改變。"},{"en":"The school made a radical change to its timetable.","zh":"學校對課表做了根本性的改變。"},{"en":"His radical ideas surprised nearly the whole school committee.","zh":"他激進的想法讓幾乎整個學校委員會都感到驚訝。"}]},{"word":"radio","pos":"n.","phonetic":"[ˈredɪˌo]","meaning":"收音機；無線電","definition":"a device that receives broadcast sound signals","collocations":["listen to the radio","turn on the radio","radio station"],"example":"She listens to the radio every morning.","exampleZh":"她每天早上都聽收音機。","synonyms":[],"level":1,"theme":"科技與媒體","examples":[{"en":"She listens to the radio every morning.","zh":"她每天早上都聽收音機。"},{"en":"My grandfather listens to the radio every morning.","zh":"我爺爺每天早上都聽收音機。"},{"en":"The sailors used a radio to call for help.","zh":"水手們用無線電呼救。"}]},{"word":"radius","pos":"n.","phonetic":"[ˈredɪəs]","meaning":"半徑；範圍","definition":"the distance from the center of a circle to its edge","collocations":["within a radius of","the radius of a circle"],"example":"The school is within a five-kilometer radius of our house.","exampleZh":"那所學校在我們家方圓五公里以內。","synonyms":[],"level":4,"theme":"科學與數學","examples":[{"en":"The school is within a five-kilometer radius of our house.","zh":"那所學校在我們家方圓五公里以內。"},{"en":"To find the area, first measure the radius of the circle.","zh":"要求面積，先量出圓的半徑。"},{"en":"There are three parks within a one-kilometer radius of my home.","zh":"在我家一公里的範圍內有三座公園。"}]},{"word":"raft","pos":"n.","phonetic":"[ræft]","meaning":"木筏；橡皮筏","definition":"a flat structure used for floating or traveling on water","collocations":["a rubber raft","paddle a raft","build a raft"],"example":"They floated down the river on a wooden raft.","exampleZh":"他們乘著木筏順流而下。","synonyms":["float"],"level":3,"theme":"交通與旅行","examples":[{"en":"They floated down the river on a wooden raft.","zh":"他們乘著木筏順流而下。"},{"en":"The friends built a wooden raft to cross the calm river.","zh":"朋友們造了一艘木筏來渡過平靜的河。"},{"en":"They paddled the rubber raft down the gentle stream.","zh":"他們划著橡皮筏順流而下。"}]},{"word":"rage","pos":"n. / v.","phonetic":"[redʒ]","meaning":"暴怒；肆虐","definition":"violent, uncontrollable anger","collocations":["fly into a rage","road rage","a fire raging"],"example":"He was shaking with rage after hearing the news.","exampleZh":"聽到這個消息後他氣得發抖。","synonyms":["fury","anger"],"level":3,"theme":"情緒與感受","examples":[{"en":"He was shaking with rage after hearing the news.","zh":"聽到這個消息後他氣得發抖。"},{"en":"He flew into a rage when he saw the broken window.","zh":"他看到破掉的窗戶時勃然大怒。"},{"en":"The forest fire raged for three days before rain came.","zh":"森林大火肆虐了三天，雨才降下。"}]},{"word":"raid","pos":"n. / v.","phonetic":"[red]","meaning":"突襲；搜查","definition":"a sudden attack or surprise visit by police to catch someone","collocations":["a police raid","raid a fridge","carry out a raid"],"example":"Police carried out a raid on the warehouse at dawn.","exampleZh":"警方在黎明時對倉庫展開突襲搜查。","synonyms":["attack","invasion"],"level":4,"theme":"政治與法律","examples":[{"en":"Police carried out a raid on the warehouse at dawn.","zh":"警方在黎明時對倉庫展開突襲搜查。"},{"en":"The police carried out a raid on the illegal factory.","zh":"警方對這間非法工廠進行了搜查。"},{"en":"The hungry boys raided the fridge after the game.","zh":"比賽結束後，飢餓的男孩們掃光了冰箱。"}]},{"word":"rail","pos":"n.","phonetic":"[rel]","meaning":"欄杆；鐵軌","definition":"a fixed bar used as a support or as part of a track","collocations":["hold the rail","travel by rail","a handrail"],"example":"She gripped the rail tightly as she climbed the stairs.","exampleZh":"她爬樓梯時緊緊抓住欄杆。","synonyms":["bar","track"],"level":3,"theme":"交通與旅行","examples":[{"en":"She gripped the rail tightly as she climbed the stairs.","zh":"她爬樓梯時緊緊抓住欄杆。"},{"en":"She held the rail tightly while climbing the steep stairs.","zh":"她爬陡峭的樓梯時緊緊抓著欄杆。"},{"en":"Many people prefer to travel by rail on long trips.","zh":"許多人長途旅行時偏好搭乘火車。"}]},{"word":"railway","pos":"n.","phonetic":"[ˈrelˌwe]","meaning":"鐵路","definition":"a track along which trains travel","collocations":["railway station","railway line","cross the railway"],"example":"The railway station was crowded during the holiday.","exampleZh":"假期期間火車站擠滿了人。","synonyms":["railroad"],"level":2,"theme":"交通與旅行","examples":[{"en":"The railway station was crowded during the holiday.","zh":"假期期間火車站擠滿了人。"},{"en":"The railway station was crowded during the holiday season.","zh":"假期期間火車站擠滿了人。"},{"en":"A new railway line will connect the two small towns.","zh":"一條新的鐵路線將連接這兩座小鎮。"}]},{"word":"rain","pos":"n. / v.","phonetic":"[ren]","meaning":"雨；下雨","definition":"water falling from clouds in drops","collocations":["heavy rain","rain cats and dogs","it starts to rain"],"example":"It started to rain right after we left home.","exampleZh":"我們一離開家就開始下雨了。","synonyms":["shower"],"level":1,"theme":"天氣與季節","examples":[{"en":"It started to rain right after we left home.","zh":"我們一離開家就開始下雨了。"},{"en":"Heavy rain forced the school to cancel the sports day.","zh":"大雨迫使學校取消了運動會。"},{"en":"It started to rain just as we reached the bus stop.","zh":"我們一到公車站就開始下雨了。"}]},{"word":"rainbow","pos":"n.","phonetic":"[ˈrenˌbo]","meaning":"彩虹","definition":"an arc of colors in the sky caused by sunlight and rain","collocations":["a rainbow appears","chase a rainbow","double rainbow"],"example":"A beautiful rainbow appeared after the storm.","exampleZh":"暴風雨過後出現了一道美麗的彩虹。","synonyms":[],"level":1,"theme":"天氣與季節","examples":[{"en":"A beautiful rainbow appeared after the storm.","zh":"暴風雨過後出現了一道美麗的彩虹。"},{"en":"A bright rainbow appeared in the sky after the storm.","zh":"暴風雨過後，一道明亮的彩虹出現在天空中。"},{"en":"The children pointed happily at the double rainbow.","zh":"孩子們開心地指著那道雙彩虹。"}]},{"word":"raincoat","pos":"n.","phonetic":"[ˈrenˌkot]","meaning":"雨衣","definition":"a coat made of waterproof material","collocations":["wear a raincoat","yellow raincoat","put on a raincoat"],"example":"Don't forget to wear your raincoat; it's raining outside.","exampleZh":"外面在下雨，別忘了穿雨衣。","synonyms":[],"level":1,"theme":"服裝與外表","examples":[{"en":"Don't forget to wear your raincoat; it's raining outside.","zh":"外面在下雨，別忘了穿雨衣。"},{"en":"Remember to wear your raincoat because it looks cloudy.","zh":"記得穿雨衣，因為天看起來陰陰的。"},{"en":"She put on a bright yellow raincoat before going outside.","zh":"她出門前穿上一件鮮黃色的雨衣。"}]},{"word":"raise","pos":"v. / n.","phonetic":"[rez]","meaning":"舉起；提高；養育；加薪","definition":"to lift something up or to increase an amount","collocations":["raise a hand","raise children","raise money","get a raise"],"example":"She raised her hand to ask a question.","exampleZh":"她舉手發問。","synonyms":["lift","increase"],"level":1,"theme":"動作與行為","examples":[{"en":"She raised her hand to ask a question.","zh":"她舉手發問。"},{"en":"She raised her hand to volunteer for the task.","zh":"她舉手自願接下這項任務。"},{"en":"The students raised money to help the local animal shelter.","zh":"學生們募款幫助當地的動物收容所。"}]},{"word":"rally","pos":"n. / v.","phonetic":"[ˈrælɪ]","meaning":"集會；振作","definition":"a large public meeting to support a cause, or to recover strength","collocations":["a political rally","rally support","rally together"],"example":"Thousands attended the rally to demand climate action.","exampleZh":"數千人參加了要求氣候行動的集會。","synonyms":["gathering","protest"],"level":5,"theme":"社會與文化","examples":[{"en":"Thousands attended the rally to demand climate action.","zh":"數千人參加了要求氣候行動的集會。"},{"en":"Thousands of people attended the rally for clean energy.","zh":"數千人參加了支持乾淨能源的集會。"},{"en":"The team rallied together to win the final game.","zh":"這支隊伍團結振作，贏得了決賽。"}]},{"word":"ramp","pos":"n.","phonetic":"[ræmp]","meaning":"斜坡；坡道","definition":"a sloping surface connecting two different levels","collocations":["a wheelchair ramp","an exit ramp","up the ramp"],"example":"The building has a ramp for wheelchair access.","exampleZh":"這棟建築設有輪椅使用的斜坡道。","synonyms":["slope"],"level":3,"theme":"居家與生活","examples":[{"en":"The building has a ramp for wheelchair access.","zh":"這棟建築設有輪椅使用的斜坡道。"},{"en":"The building has a ramp for wheelchair users.","zh":"這棟建築有供輪椅使用者用的坡道。"},{"en":"He pushed the heavy cart up the steep ramp.","zh":"他把沉重的推車推上陡峭的斜坡。"}]},{"word":"ranch","pos":"n.","phonetic":"[ræntʃ]","meaning":"大牧場","definition":"a large farm for raising cattle, horses, or sheep","collocations":["a cattle ranch","work on a ranch","a ranch owner"],"example":"His uncle owns a large cattle ranch in Texas.","exampleZh":"他叔叔在德州擁有一座大型牧場。","synonyms":["farm"],"level":3,"theme":"工作與職業","examples":[{"en":"His uncle owns a large cattle ranch in Texas.","zh":"他叔叔在德州擁有一座大型牧場。"},{"en":"His uncle raises horses on a large ranch.","zh":"他叔叔在一座大牧場上養馬。"},{"en":"The workers on the ranch start their day before sunrise.","zh":"牧場上的工人在日出前就開始一天的工作。"}]},{"word":"random","pos":"adj.","phonetic":"[ˈrændəm]","meaning":"隨機的；任意的","definition":"made or done without a particular plan or pattern","collocations":["a random sample","random order","at random"],"example":"The winners were chosen at random.","exampleZh":"得獎者是隨機抽選出來的。","synonyms":["arbitrary"],"level":3,"theme":"性質與描述","examples":[{"en":"The winners were chosen at random.","zh":"得獎者是隨機抽選出來的。"},{"en":"The teacher chose students in random order to answer.","zh":"老師以隨機順序點學生回答。"},{"en":"The prizes were given out to visitors at random.","zh":"獎品隨機發給訪客。"}]},{"word":"range","pos":"n. / v.","phonetic":"[rendʒ]","meaning":"範圍；山脈；種類","definition":"the area of variation between limits, or a series of mountains","collocations":["price range","a range of products","mountain range"],"example":"The store offers a wide range of products.","exampleZh":"這家店提供多樣的產品。","synonyms":["scope","variety"],"level":3,"theme":"性質與描述","examples":[{"en":"The store offers a wide range of products.","zh":"這家店提供多樣的產品。"},{"en":"The store offers a wide range of school supplies.","zh":"這家店提供各式各樣的學校用品。"},{"en":"A tall mountain range stretched along the horizon.","zh":"一座高聳的山脈沿著地平線綿延。"}]},{"word":"rank","pos":"n. / v.","phonetic":"[ræŋk]","meaning":"等級；排名","definition":"a position in a hierarchy or scale of achievement","collocations":["a high rank","rank first","rise through the ranks"],"example":"She rose through the ranks to become manager.","exampleZh":"她一路晉升,最後成為經理。","synonyms":["grade","position"],"level":4,"theme":"工作與職業","examples":[{"en":"She rose through the ranks to become manager.","zh":"她一路晉升,最後成為經理。"},{"en":"Her hard work helped her rank first in the class.","zh":"她的努力使她在班上排名第一。"},{"en":"He slowly rose through the ranks to become captain.","zh":"他慢慢地晉升，最後當上了隊長。"}]},{"word":"ransom","pos":"n.","phonetic":"[ˈrænsəm]","meaning":"贖金","definition":"money demanded for the release of a captured person","collocations":["pay a ransom","hold for ransom","demand a ransom"],"example":"The kidnappers demanded a huge ransom for his release.","exampleZh":"綁匪要求鉅額贖金才肯釋放他。","synonyms":[],"level":5,"theme":"政治與法律","examples":[{"en":"The kidnappers demanded a huge ransom for his release.","zh":"綁匪要求鉅額贖金才肯釋放他。"},{"en":"The kidnappers demanded a large ransom for the businessman.","zh":"綁匪要求為這名商人支付一大筆贖金。"},{"en":"The family could not afford to pay the ransom.","zh":"這家人付不起贖金。"}]},{"word":"rapid","pos":"adj.","phonetic":"[ˈræpɪd]","meaning":"快速的；迅速的","definition":"happening in a short time or at great speed","collocations":["rapid growth","rapid change","rapid progress"],"example":"The city has seen rapid economic growth.","exampleZh":"這座城市經歷了快速的經濟成長。","synonyms":["quick","swift"],"level":3,"theme":"性質與描述","examples":[{"en":"The city has seen rapid economic growth.","zh":"這座城市經歷了快速的經濟成長。"},{"en":"The town has seen rapid growth over the past decade.","zh":"這座城鎮在過去十年間快速成長。"},{"en":"Technology is changing at a rapid pace these days.","zh":"如今科技正以飛快的速度變化。"}]},{"word":"rare","pos":"adj.","phonetic":"[rɛr]","meaning":"稀有的；罕見的；(牛排)三分熟的","definition":"not occurring very often or found in small numbers","collocations":["a rare disease","rare species","rare occasion"],"example":"Giant pandas are a rare species.","exampleZh":"大貓熊是一種稀有物種。","synonyms":["uncommon","scarce"],"level":2,"theme":"性質與描述","examples":[{"en":"Giant pandas are a rare species.","zh":"大貓熊是一種稀有物種。"},{"en":"Giant pandas are a rare species found only in a few places.","zh":"大貓熊是只在少數地方發現的稀有物種。"},{"en":"It is rare to see snow in this warm region.","zh":"在這個溫暖的地區看到雪是很罕見的。"}]},{"word":"rascal","pos":"n.","phonetic":"[ˈræskḷ]","meaning":"頑童；無賴","definition":"a mischievous or dishonest person, often used playfully","collocations":["a little rascal","a sly rascal"],"example":"That little rascal hid my keys again.","exampleZh":"那個小頑童又把我的鑰匙藏起來了。","synonyms":["rogue"],"level":3,"theme":"人物與家庭","examples":[{"en":"That little rascal hid my keys again.","zh":"那個小頑童又把我的鑰匙藏起來了。"},{"en":"That little rascal hid his sister's shoes again.","zh":"那個小頑童又把他妹妹的鞋子藏起來了。"},{"en":"The sly rascal tricked everyone with his clever story.","zh":"這個狡猾的無賴用他聰明的故事騙了大家。"}]},{"word":"rash","pos":"n. / adj.","phonetic":"[ræʃ]","meaning":"疹子；輕率的","definition":"a red spot on skin from illness or irritation; acting without careful thought","collocations":["a skin rash","a rash decision","break out in a rash"],"example":"He broke out in a rash after eating shrimp.","exampleZh":"他吃了蝦子之後起了疹子。","synonyms":["hasty","reckless"],"level":4,"theme":"身體與健康","examples":[{"en":"He broke out in a rash after eating shrimp.","zh":"他吃了蝦子之後起了疹子。"},{"en":"He broke out in a red rash after touching the plant.","zh":"碰到那植物後，他起了紅色的疹子。"},{"en":"Making a rash decision now could cause big problems later.","zh":"現在做輕率的決定可能會在日後造成大麻煩。"}]},{"word":"rat","pos":"n.","phonetic":"[ræt]","meaning":"老鼠","definition":"a small rodent with a long tail","collocations":["lab rat","rat trap"],"example":"A rat scurried across the kitchen floor.","exampleZh":"一隻老鼠飛快地跑過廚房地板。","synonyms":["rodent"],"level":1,"theme":"動物與植物","examples":[{"en":"A rat scurried across the kitchen floor.","zh":"一隻老鼠飛快地跑過廚房地板。"},{"en":"A small rat ran quickly across the dark alley.","zh":"一隻小老鼠迅速地跑過黑暗的巷子。"},{"en":"Scientists sometimes use a lab rat to test new medicine.","zh":"科學家有時用實驗室的老鼠來測試新藥。"}]},{"word":"rate","pos":"n. / v.","phonetic":"[ret]","meaning":"比率；速度；評價","definition":"a measure of frequency or speed","collocations":["exchange rate","heart rate"],"example":"The exchange rate changes every day.","exampleZh":"匯率每天都在變動。","synonyms":["ratio","speed"],"level":2,"theme":"商業與金錢","examples":[{"en":"The exchange rate changes every day.","zh":"匯率每天都在變動。"},{"en":"The exchange rate between the two currencies changes daily.","zh":"這兩種貨幣之間的匯率每天變動。"},{"en":"The doctor checked the patient's heart rate carefully.","zh":"醫生仔細檢查了病人的心跳速率。"}]},{"word":"rather","pos":"adv.","phonetic":"[ˈræðɚ]","meaning":"寧可；相當地","definition":"to a certain extent; more accurately; preferably","collocations":["would rather","rather than","rather difficult"],"example":"I would rather stay home tonight.","exampleZh":"我今晚寧願待在家裡。","synonyms":["fairly","preferably"],"level":2,"theme":"抽象概念","examples":[{"en":"I would rather stay home tonight.","zh":"我今晚寧願待在家裡。"},{"en":"I would rather walk than take the crowded bus.","zh":"我寧可走路也不搭擁擠的公車。"},{"en":"The math test today was rather difficult for everyone.","zh":"今天的數學考試對每個人來說都相當困難。"}]},{"word":"ratio","pos":"n.","phonetic":"[ˈreʃo]","meaning":"比例；比率","definition":"the relationship between two amounts showing how many times one contains another","collocations":["a ratio of","the student-teacher ratio","a high ratio"],"example":"The ratio of boys to girls in the class is two to one.","exampleZh":"班上男女生比例是二比一。","synonyms":["proportion"],"level":4,"theme":"科學與數學","examples":[{"en":"The ratio of boys to girls in the class is two to one.","zh":"班上男女生比例是二比一。"},{"en":"The ratio of teachers to students is one to twenty.","zh":"師生比例是一比二十。"},{"en":"Mix the flour and sugar in a two-to-one ratio.","zh":"把麵粉和糖以二比一的比例混合。"}]},{"word":"ration","pos":"n. / v.","phonetic":"[ˈræʃən]","meaning":"配給；定量分配","definition":"a fixed amount of something allowed per person, especially in short supply","collocations":["food rations","ration supplies","a daily ration"],"example":"During the war, families received a weekly ration of sugar.","exampleZh":"戰爭期間,各家庭每週會獲得配給的糖。","synonyms":["allowance","portion"],"level":5,"theme":"商業與金錢","examples":[{"en":"During the war, families received a weekly ration of sugar.","zh":"戰爭期間,各家庭每週會獲得配給的糖。"},{"en":"During the war, each family received a small ration of rice.","zh":"戰爭期間，每個家庭只分到少量的米配給。"},{"en":"They had to ration their water carefully on the long hike.","zh":"在漫長的健行途中，他們必須小心地定量分配用水。"}]},{"word":"rational","pos":"adj.","phonetic":"[ˈræʃənḷ]","meaning":"理性的；合理的","definition":"based on clear thought and reason rather than emotion","collocations":["a rational decision","rational thinking","a rational explanation"],"example":"We need to make a rational decision, not an emotional one.","exampleZh":"我們需要做出理性而非情緒化的決定。","synonyms":["logical","sensible"],"level":5,"theme":"抽象概念","examples":[{"en":"We need to make a rational decision, not an emotional one.","zh":"我們需要做出理性而非情緒化的決定。"},{"en":"We should make a rational decision based on the facts.","zh":"我們應該根據事實做出理性的決定。"},{"en":"She gave a calm and rational explanation for her choice.","zh":"她為自己的選擇給了冷靜而合理的解釋。"}]},{"word":"rattle","pos":"v. / n.","phonetic":"[ˈrætḷ]","meaning":"發出咯咯聲；使緊張","definition":"to make a series of short, sharp sounds, or to upset someone","collocations":["rattle the windows","rattle someone","a baby's rattle"],"example":"The old bus rattled loudly along the bumpy road.","exampleZh":"那輛舊公車在顛簸的路上發出咯咯聲。","synonyms":["shake","clatter"],"level":4,"theme":"聲音","examples":[{"en":"The old bus rattled loudly along the bumpy road.","zh":"那輛舊公車在顛簸的路上發出咯咯聲。"},{"en":"The strong wind rattled the windows all night long.","zh":"強風整夜把窗戶吹得咯咯作響。"},{"en":"The tough question rattled the young contestant on stage.","zh":"這道難題使台上年輕的參賽者緊張了起來。"}]},{"word":"raven","pos":"n.","phonetic":"[ˈrevən]","meaning":"渡鴉","definition":"a large black bird similar to a crow","collocations":["a black raven","a raven's call"],"example":"A raven landed on the old tower's roof.","exampleZh":"一隻渡鴉停在那座古塔的屋頂上。","synonyms":["crow"],"level":3,"theme":"動物與植物","examples":[{"en":"A raven landed on the old tower's roof.","zh":"一隻渡鴉停在那座古塔的屋頂上。"},{"en":"A black raven perched quietly on the old fence.","zh":"一隻黑色的渡鴉靜靜地棲息在舊圍籬上。"},{"en":"We heard a raven's harsh call from the tall pine tree.","zh":"我們聽見高大的松樹上傳來渡鴉刺耳的叫聲。"}]},{"word":"raw","pos":"adj.","phonetic":"[rɔ]","meaning":"生的；未加工的","definition":"uncooked or unprocessed","collocations":["raw meat","raw materials","raw data"],"example":"Never eat raw chicken; it can make you sick.","exampleZh":"千萬不要吃生雞肉，會讓你生病。","synonyms":["uncooked"],"level":2,"theme":"食物與烹飪","examples":[{"en":"Never eat raw chicken; it can make you sick.","zh":"千萬不要吃生雞肉，會讓你生病。"},{"en":"You should never eat raw chicken, as it can make you ill.","zh":"你絕不該吃生雞肉，因為可能會讓你生病。"},{"en":"The factory turns raw materials into finished products.","zh":"這家工廠把原料變成成品。"}]},{"word":"ray","pos":"n.","phonetic":"[re]","meaning":"光線；射線","definition":"a narrow beam of light or radiation","collocations":["ray of sunlight","X-ray"],"example":"A ray of sunlight came through the window.","exampleZh":"一道陽光穿過窗戶照了進來。","synonyms":["beam"],"level":2,"theme":"科學與數學","examples":[{"en":"A ray of sunlight came through the window.","zh":"一道陽光穿過窗戶照了進來。"},{"en":"A warm ray of sunlight came through the classroom window.","zh":"一道溫暖的陽光從教室窗戶照進來。"},{"en":"The doctor used an X-ray to check the boy's broken arm.","zh":"醫生用X光檢查男孩斷掉的手臂。"}]},{"word":"razor","pos":"n.","phonetic":"[ˈrezɚ]","meaning":"刮鬍刀；剃刀","definition":"a tool with a sharp blade used for shaving hair","collocations":["a razor blade","shave with a razor","a razor-sharp edge"],"example":"He nicked his chin while shaving with an old razor.","exampleZh":"他用舊刮鬍刀刮鬍子時割傷了下巴。","synonyms":[],"level":3,"theme":"居家與生活","examples":[{"en":"He nicked his chin while shaving with an old razor.","zh":"他用舊刮鬍刀刮鬍子時割傷了下巴。"},{"en":"He carefully shaved his beard with a new razor.","zh":"他用一把新刮鬍刀小心地刮鬍子。"},{"en":"Be careful, because the razor blade is extremely sharp.","zh":"小心點，因為刮鬍刀的刀片非常鋒利。"}]},{"word":"reach","pos":"v. / n.","phonetic":"[ritʃ]","meaning":"到達；伸手拿；影響範圍","definition":"to arrive at or stretch out to touch something","collocations":["reach a goal","reach out","within reach"],"example":"We finally reached the top of the mountain.","exampleZh":"我們終於到達了山頂。","synonyms":["arrive at","attain"],"level":2,"theme":"動作與行為","examples":[{"en":"We finally reached the top of the mountain.","zh":"我們終於到達了山頂。"},{"en":"After a long climb, we finally reached the mountain top.","zh":"經過漫長的攀登，我們終於到達山頂。"},{"en":"She reached out to grab the book on the high shelf.","zh":"她伸手去拿高架子上的書。"}]},{"word":"react","pos":"v.","phonetic":"[rɪˈækt]","meaning":"反應；回應","definition":"to act in response to something","collocations":["react quickly","react to news","react negatively"],"example":"She reacted calmly to the bad news.","exampleZh":"她冷靜地應對這個壞消息。","synonyms":["respond"],"level":3,"theme":"動作與行為","examples":[{"en":"She reacted calmly to the bad news.","zh":"她冷靜地應對這個壞消息。"},{"en":"She reacted calmly when she heard the surprising news.","zh":"聽到令人驚訝的消息時，她冷靜地回應。"},{"en":"Some plants react quickly to changes in sunlight.","zh":"有些植物對陽光的變化反應迅速。"}]},{"word":"reaction","pos":"n.","phonetic":"[rɪˈækʃən]","meaning":"反應","definition":"a response to a situation or event","collocations":["a strong reaction","chain reaction","allergic reaction"],"example":"His reaction to the surprise party was priceless.","exampleZh":"他對這場驚喜派對的反應太珍貴了。","synonyms":["response"],"level":3,"theme":"情緒與感受","examples":[{"en":"His reaction to the surprise party was priceless.","zh":"他對這場驚喜派對的反應太珍貴了。"},{"en":"His first reaction to the gift was one of pure joy.","zh":"他對這份禮物的第一反應是純粹的喜悅。"},{"en":"Some people have an allergic reaction to certain foods.","zh":"有些人對某些食物會有過敏反應。"}]},{"word":"reactor","pos":"n.","phonetic":"[rɪˈæktɚ]","meaning":"反應爐","definition":"a device or building used to produce nuclear energy","collocations":["a nuclear reactor","shut down a reactor"],"example":"The nuclear reactor was shut down for safety checks.","exampleZh":"這座核反應爐因安全檢查而暫時關閉。","synonyms":[],"level":5,"theme":"科學與數學","examples":[{"en":"The nuclear reactor was shut down for safety checks.","zh":"這座核反應爐因安全檢查而暫時關閉。"},{"en":"Engineers shut down the nuclear reactor for safety checks.","zh":"工程師關閉了核子反應爐以進行安全檢查。"},{"en":"A nuclear reactor produces a huge amount of energy.","zh":"核子反應爐能產生巨大的能量。"}]},{"word":"read","pos":"v.","phonetic":"[rid]","meaning":"閱讀","definition":"to look at and understand written words","collocations":["read a book","read aloud","read between the lines"],"example":"She likes to read novels before bed.","exampleZh":"她喜歡睡前讀小說。","synonyms":[],"level":1,"theme":"教育與學習","examples":[{"en":"She likes to read novels before bed.","zh":"她喜歡睡前讀小說。"},{"en":"She likes to read adventure novels before falling asleep.","zh":"她喜歡在入睡前閱讀冒險小說。"},{"en":"The teacher asked us to read the poem aloud.","zh":"老師要我們把這首詩大聲朗讀出來。"}]},{"word":"reader","pos":"n.","phonetic":"[ˈridɚ]","meaning":"讀者","definition":"a person who reads","collocations":["a keen reader","dear reader","frequent reader"],"example":"The book has attracted millions of readers worldwide.","exampleZh":"這本書吸引了全球數百萬讀者。","synonyms":[],"level":1,"theme":"教育與學習","examples":[{"en":"The book has attracted millions of readers worldwide.","zh":"這本書吸引了全球數百萬讀者。"},{"en":"The exciting story kept every reader turning the pages.","zh":"這個刺激的故事讓每位讀者不停翻頁。"},{"en":"My brother is a keen reader of history books.","zh":"我哥哥是歷史書籍的熱衷讀者。"}]},{"word":"readily","pos":"adv.","phonetic":"[ˈrɛdəlɪ]","meaning":"欣然地；容易地","definition":"willingly or without difficulty","collocations":["readily available","agree readily","readily admit"],"example":"Fresh vegetables are readily available at the local market.","exampleZh":"新鮮蔬菜在當地市場很容易買到。","synonyms":["willingly","easily"],"level":4,"theme":"抽象概念","examples":[{"en":"Fresh vegetables are readily available at the local market.","zh":"新鮮蔬菜在當地市場很容易買到。"},{"en":"Fresh fruit is readily available at the morning market.","zh":"早市上很容易買到新鮮水果。"},{"en":"She readily agreed to help her classmate with the project.","zh":"她欣然同意幫助同學完成專題。"}]},{"word":"readiness","pos":"n.","phonetic":"[ˈrɛdɪnɪs]","meaning":"準備就緒；願意","definition":"the state of being fully prepared for something","collocations":["a state of readiness","readiness to help"],"example":"The soldiers stood in readiness for the drill.","exampleZh":"士兵們已準備就緒等待演習開始。","synonyms":["preparedness"],"level":5,"theme":"抽象概念","examples":[{"en":"The soldiers stood in readiness for the drill.","zh":"士兵們已準備就緒等待演習開始。"},{"en":"The team stood in readiness before the big match began.","zh":"大賽開始前，這支隊伍已準備就緒。"},{"en":"His readiness to help others made him very popular.","zh":"他樂於助人的態度使他很受歡迎。"}]},{"word":"ready","pos":"adj.","phonetic":"[ˈrɛdɪ]","meaning":"準備好的","definition":"prepared for an action or situation","collocations":["get ready","ready to go","ready-made"],"example":"Are you ready for the exam tomorrow?","exampleZh":"你準備好明天的考試了嗎？","synonyms":["prepared"],"level":1,"theme":"性質與描述","examples":[{"en":"Are you ready for the exam tomorrow?","zh":"你準備好明天的考試了嗎？"},{"en":"Are you ready for the important exam tomorrow morning?","zh":"你準備好迎接明早的重要考試了嗎？"},{"en":"Please get ready quickly; the bus is about to leave.","zh":"請快點準備好，公車就要開了。"}]},{"word":"real","pos":"adj.","phonetic":"[rɪəl]","meaning":"真實的；真正的","definition":"actually existing as a thing or occurring in fact","collocations":["real life","real estate","for real"],"example":"This story is based on real events.","exampleZh":"這個故事是根據真實事件改編的。","synonyms":["true","genuine"],"level":1,"theme":"性質與描述","examples":[{"en":"This story is based on real events.","zh":"這個故事是根據真實事件改編的。"},{"en":"This exciting movie is based on real events.","zh":"這部刺激的電影是根據真實事件改編的。"},{"en":"A real friend stays with you during hard times.","zh":"真正的朋友會在困難時陪伴你。"}]},{"word":"realism","pos":"n.","phonetic":"[ˈrɪəˌlɪzəm]","meaning":"寫實主義；現實主義","definition":"the practice of accepting a situation as it is; a style showing things realistically","collocations":["a sense of realism","realism in art","political realism"],"example":"The painting is admired for its stunning realism.","exampleZh":"這幅畫因其驚人的寫實風格而備受讚賞。","synonyms":[],"level":5,"theme":"藝術與音樂","examples":[{"en":"The painting is admired for its stunning realism.","zh":"這幅畫因其驚人的寫實風格而備受讚賞。"},{"en":"The painting is famous for its striking realism.","zh":"這幅畫以驚人的寫實風格聞名。"},{"en":"The novel describes village life with great realism.","zh":"這部小說以極為寫實的手法描寫鄉村生活。"}]},{"word":"realistic","pos":"adj.","phonetic":"[ˌriəˈlɪstɪk]","meaning":"實際的；逼真的","definition":"having a sensible view of what is possible or true to life","collocations":["realistic goal","realistic expectations","look realistic"],"example":"We need to set realistic goals for the project.","exampleZh":"我們需要為這個計畫設定實際的目標。","synonyms":["practical"],"level":4,"theme":"性質與描述","examples":[{"en":"We need to set realistic goals for the project.","zh":"我們需要為這個計畫設定實際的目標。"},{"en":"We should set realistic goals that we can actually reach.","zh":"我們應該設定真正能達成的實際目標。"},{"en":"The model dinosaur looked so realistic that children were amazed.","zh":"這隻恐龍模型看起來如此逼真，孩子們都驚呆了。"}]},{"word":"reality","pos":"n.","phonetic":"[rɪˈælətɪ]","meaning":"現實；真實","definition":"the state of things as they actually exist","collocations":["face reality","in reality","reality show"],"example":"In reality, the plan was much harder to carry out.","exampleZh":"事實上，這個計畫執行起來困難得多。","synonyms":["truth"],"level":3,"theme":"抽象概念","examples":[{"en":"In reality, the plan was much harder to carry out.","zh":"事實上，這個計畫執行起來困難得多。"},{"en":"In reality, learning a language takes years of practice.","zh":"事實上，學一種語言需要多年的練習。"},{"en":"She had to face the reality of moving to a new city.","zh":"她必須面對搬到新城市的現實。"}]},{"word":"realize","pos":"v.","phonetic":"[ˈriəˌlaɪz]","meaning":"意識到；實現","definition":"to become fully aware of something as a fact","collocations":["realize a mistake","realize a dream","suddenly realize"],"example":"I didn't realize how late it was.","exampleZh":"我沒意識到已經這麼晚了。","synonyms":["recognize","understand"],"level":2,"theme":"抽象概念","examples":[{"en":"I didn't realize how late it was.","zh":"我沒意識到已經這麼晚了。"},{"en":"He suddenly realized that he had left his keys at home.","zh":"他突然意識到把鑰匙忘在家裡了。"},{"en":"With hard work, she finally realized her dream of becoming a pilot.","zh":"靠著努力，她終於實現了成為飛行員的夢想。"}]},{"word":"really","pos":"adv.","phonetic":"[ˈriəlɪ]","meaning":"真正地；實際上","definition":"in actual fact; used to emphasize a statement","collocations":["really like","really important","not really"],"example":"I really appreciate your help.","exampleZh":"我真的很感激你的幫忙。","synonyms":["truly"],"level":1,"theme":"抽象概念","examples":[{"en":"I really appreciate your help.","zh":"我真的很感激你的幫忙。"},{"en":"I really appreciate all the help you gave me.","zh":"我真的很感謝你給我的所有幫助。"},{"en":"This puzzle is really difficult, even for adults.","zh":"這個謎題真的很難，連大人也覺得難。"}]},{"word":"realm","pos":"n.","phonetic":"[rɛlm]","meaning":"領域；王國","definition":"an area of activity or interest; a kingdom","collocations":["the realm of science","beyond the realm of","a distant realm"],"example":"This topic falls outside the realm of biology.","exampleZh":"這個主題超出了生物學的範疇。","synonyms":["domain","kingdom"],"level":5,"theme":"抽象概念","examples":[{"en":"This topic falls outside the realm of biology.","zh":"這個主題超出了生物學的範疇。"},{"en":"This question lies outside the realm of biology.","zh":"這個問題超出了生物學的領域。"},{"en":"In the fairy tale, a kind king ruled a peaceful realm.","zh":"在童話故事裡，一位仁慈的國王統治著一個和平的王國。"}]},{"word":"reap","pos":"v.","phonetic":"[rip]","meaning":"收割；獲得","definition":"to harvest crops, or to gain benefits from an action","collocations":["reap the benefits","reap a harvest","reap rewards"],"example":"Farmers reap the wheat every autumn.","exampleZh":"農夫每年秋天收割小麥。","synonyms":["harvest","gain"],"level":4,"theme":"自然與環境","examples":[{"en":"Farmers reap the wheat every autumn.","zh":"農夫每年秋天收割小麥。"},{"en":"Farmers in the village reap the golden wheat every autumn.","zh":"村裡的農夫每年秋天收割金黃的小麥。"},{"en":"If you study hard now, you will reap the benefits later.","zh":"如果你現在用功讀書，日後就會獲得好處。"}]},{"word":"rear","pos":"n. / adj. / v.","phonetic":"[rɪr]","meaning":"後面；養育","definition":"the back part of something; to raise a child or animal","collocations":["the rear of the car","rear a child","at the rear"],"example":"They entered through the rear door of the building.","exampleZh":"他們從大樓的後門進入。","synonyms":["back","raise"],"level":3,"theme":"時間與空間","examples":[{"en":"They entered through the rear door of the building.","zh":"他們從大樓的後門進入。"},{"en":"They entered the theater through the rear door.","zh":"他們從劇院的後門進入。"},{"en":"It takes patience and love to rear a child well.","zh":"好好養育一個孩子需要耐心和愛。"}]},{"word":"rearrange","pos":"v.","phonetic":"[ˌriəˈrendʒ]","meaning":"重新安排；重新佈置","definition":"to change the order or position of things","collocations":["rearrange furniture","rearrange a schedule","rearrange the words"],"example":"We decided to rearrange the furniture in the living room.","exampleZh":"我們決定重新佈置客廳的家具。","synonyms":["reorganize"],"level":3,"theme":"居家與生活","examples":[{"en":"We decided to rearrange the furniture in the living room.","zh":"我們決定重新佈置客廳的家具。"},{"en":"Let's rearrange the chairs so everyone can see the screen clearly.","zh":"我們把椅子重新排一下，好讓大家都能清楚看到螢幕。"},{"en":"The teacher had to rearrange the schedule after the holiday.","zh":"假期過後，老師必須重新安排課程表。"}]},{"word":"reason","pos":"n. / v.","phonetic":"[ˈrizn̩]","meaning":"理由；原因；推理","definition":"a cause or explanation for something","collocations":["good reason","for this reason","reason with someone"],"example":"There is no reason to worry.","exampleZh":"沒有理由需要擔心。","synonyms":["cause","motive"],"level":2,"theme":"抽象概念","examples":[{"en":"There is no reason to worry.","zh":"沒有理由需要擔心。"},{"en":"There is no good reason to skip breakfast every day.","zh":"沒有好理由每天不吃早餐。"},{"en":"She tried to reason with her friend to avoid a fight.","zh":"她試著和朋友講道理以避免爭吵。"}]},{"word":"reasonable","pos":"adj.","phonetic":"[ˈriznəbl̩]","meaning":"合理的；合情理的","definition":"fair and sensible","collocations":["reasonable price","reasonable request","sound reasonable"],"example":"The price of the shirt seemed reasonable.","exampleZh":"這件襯衫的價格似乎很合理。","synonyms":["fair","sensible"],"level":3,"theme":"性質與描述","examples":[{"en":"The price of the shirt seemed reasonable.","zh":"這件襯衫的價格似乎很合理。"},{"en":"The price of the second-hand bicycle seemed very reasonable.","zh":"這輛二手腳踏車的價格似乎很合理。"},{"en":"It is reasonable to rest after studying for many hours.","zh":"讀書好幾個小時後休息一下是合情理的。"}]},{"word":"reassure","pos":"v.","phonetic":"[ˌriəˈʃʊr]","meaning":"使安心；使放心","definition":"to say or do things to remove someone's doubts or fears","collocations":["reassure someone","reassure the public","feel reassured"],"example":"The doctor reassured her that the surgery would go smoothly.","exampleZh":"醫生向她保證手術會順利進行,讓她安心。","synonyms":["comfort","calm"],"level":4,"theme":"情緒與感受","examples":[{"en":"The doctor reassured her that the surgery would go smoothly.","zh":"醫生向她保證手術會順利進行,讓她安心。"},{"en":"The teacher reassured the nervous students before the test.","zh":"老師在考試前讓緊張的學生安心。"},{"en":"He smiled to reassure his little brother during the storm.","zh":"暴風雨中，他微笑著讓弟弟放心。"}]},{"word":"rebel","pos":"n. / v.","phonetic":"[ˈrɛbḷ]","meaning":"叛徒；反叛","definition":"a person who resists authority; to act or fight against authority","collocations":["rebel against","a teenage rebel","rebel forces"],"example":"As a teenager, he rebelled against his strict parents.","exampleZh":"他青少年時期曾反抗嚴格的父母。","synonyms":["revolt","resist"],"level":4,"theme":"社會與文化","examples":[{"en":"As a teenager, he rebelled against his strict parents.","zh":"他青少年時期曾反抗嚴格的父母。"},{"en":"As a teenager, she began to rebel against strict rules.","zh":"青少年時期，她開始反抗嚴格的規定。"},{"en":"The rebel forces refused to obey the king's orders.","zh":"反叛勢力拒絕服從國王的命令。"}]},{"word":"rebellion","pos":"n.","phonetic":"[rɪˈbɛljən]","meaning":"叛亂；反抗","definition":"an act of organized resistance against authority","collocations":["stage a rebellion","crush a rebellion","teenage rebellion"],"example":"The government quickly crushed the armed rebellion.","exampleZh":"政府迅速鎮壓了這場武裝叛亂。","synonyms":["revolt","uprising"],"level":5,"theme":"政治與法律","examples":[{"en":"The government quickly crushed the armed rebellion.","zh":"政府迅速鎮壓了這場武裝叛亂。"},{"en":"The unfair taxes led to a rebellion among the farmers.","zh":"不公平的稅收引發了農民的反抗。"},{"en":"The old king struggled to crush the growing rebellion.","zh":"老國王努力鎮壓日益壯大的叛亂。"}]},{"word":"rebound","pos":"v. / n.","phonetic":"[rɪˈbaʊnd]","meaning":"反彈；恢復","definition":"to bounce back after hitting something, or to recover after a setback","collocations":["rebound from a loss","the ball rebounded","the economy rebounds"],"example":"The stock market rebounded quickly after the crash.","exampleZh":"股市在崩盤後迅速反彈。","synonyms":["bounce back","recover"],"level":5,"theme":"商業與金錢","examples":[{"en":"The stock market rebounded quickly after the crash.","zh":"股市在崩盤後迅速反彈。"},{"en":"The ball rebounded off the wall and rolled away.","zh":"球從牆上反彈回來然後滾走了。"},{"en":"The economy began to rebound after the difficult year.","zh":"經濟在艱困的一年後開始復甦。"}]},{"word":"rebuild","pos":"v.","phonetic":"[ˌriˈbɪld]","meaning":"重建","definition":"to build something again after it has been damaged or destroyed","collocations":["rebuild a house","rebuild trust","rebuild a city"],"example":"It took years to rebuild the city after the earthquake.","exampleZh":"地震後花了好幾年才把這座城市重建起來。","synonyms":["reconstruct"],"level":3,"theme":"居家與生活","examples":[{"en":"It took years to rebuild the city after the earthquake.","zh":"地震後花了好幾年才把這座城市重建起來。"},{"en":"It took many years to rebuild the town after the flood.","zh":"洪水過後，花了許多年才重建這座城鎮。"},{"en":"They worked hard to rebuild trust after the argument.","zh":"爭吵之後，他們努力重建彼此的信任。"}]},{"word":"recall","pos":"v. / n.","phonetic":"[rɪˈkɔl]","meaning":"回想；召回","definition":"to remember something, or to officially call something back","collocations":["recall a memory","recall a product","total recall"],"example":"I can't quite recall where I put my keys.","exampleZh":"我想不太起來把鑰匙放在哪裡了。","synonyms":["remember","summon"],"level":4,"theme":"教育與學習","examples":[{"en":"I can't quite recall where I put my keys.","zh":"我想不太起來把鑰匙放在哪裡了。"},{"en":"I can't recall exactly where I parked the car.","zh":"我想不起來到底把車停在哪裡了。"},{"en":"The company had to recall the unsafe toys from stores.","zh":"這家公司必須從商店召回不安全的玩具。"}]},{"word":"recede","pos":"v.","phonetic":"[rɪˈsid]","meaning":"退去；漸漸消失","definition":"to gradually move back or become less noticeable","collocations":["the floodwaters recede","memories recede","a receding hairline"],"example":"The floodwaters slowly receded after the storm passed.","exampleZh":"暴風雨過後,洪水漸漸退去。","synonyms":["retreat","withdraw"],"level":6,"theme":"自然與環境","examples":[{"en":"The floodwaters slowly receded after the storm passed.","zh":"暴風雨過後,洪水漸漸退去。"},{"en":"The floodwaters slowly receded after the heavy rain stopped.","zh":"大雨停後，洪水緩緩退去。"},{"en":"As the years passed, the painful memories began to recede.","zh":"隨著歲月流逝，痛苦的記憶開始漸漸消退。"}]},{"word":"receive","pos":"v.","phonetic":"[rɪˈsiv]","meaning":"收到；接受","definition":"to be given, sent, or handed something","collocations":["receive a gift","receive an email","receive training"],"example":"She received a letter from her old friend.","exampleZh":"她收到一封老朋友寄來的信。","synonyms":["get","obtain"],"level":2,"theme":"動作與行為","examples":[{"en":"She received a letter from her old friend.","zh":"她收到一封老朋友寄來的信。"},{"en":"She was excited to receive a letter from her old friend.","zh":"收到老朋友的來信，她很興奮。"},{"en":"New members receive training before they start work.","zh":"新成員在開始工作前會接受訓練。"}]},{"word":"recent","pos":"adj.","phonetic":"[ˈrisn̩t]","meaning":"最近的","definition":"having happened or begun not long ago","collocations":["recent years","recent events","in recent times"],"example":"In recent years, the city has changed a lot.","exampleZh":"近年來，這座城市改變了很多。","synonyms":["latest"],"level":2,"theme":"時間與空間","examples":[{"en":"In recent years, the city has changed a lot.","zh":"近年來，這座城市改變了很多。"},{"en":"In recent years, the city has built many new parks.","zh":"近年來，這座城市興建了許多新公園。"},{"en":"Recent events have changed the way people shop.","zh":"最近的事件改變了人們購物的方式。"}]},{"word":"recently","pos":"adv.","phonetic":"[ˈrisn̩tlɪ]","meaning":"最近","definition":"not long ago; lately","collocations":["recently moved","have recently done","until recently"],"example":"I recently started a new job.","exampleZh":"我最近開始了一份新工作。","synonyms":["lately"],"level":2,"theme":"時間與空間","examples":[{"en":"I recently started a new job.","zh":"我最近開始了一份新工作。"},{"en":"I recently moved to a quieter neighborhood near the park.","zh":"我最近搬到公園附近一個較安靜的社區。"},{"en":"She has recently taken up painting as a hobby.","zh":"她最近開始把繪畫當作嗜好。"}]},{"word":"recess","pos":"n.","phonetic":"[ˈrisɛs]","meaning":"下課時間；休會","definition":"a temporary break from work, school, or a formal meeting","collocations":["during recess","a school recess","go into recess"],"example":"The children played tag during morning recess.","exampleZh":"孩子們在早上下課時間玩鬼抓人。","synonyms":["break"],"level":3,"theme":"教育與學習","examples":[{"en":"The children played tag during morning recess.","zh":"孩子們在早上下課時間玩鬼抓人。"},{"en":"The children played basketball during the morning recess.","zh":"孩子們在早上下課時間打籃球。"},{"en":"The court went into recess for a short lunch break.","zh":"法庭休會，進行短暫的午餐休息。"}]},{"word":"recipe","pos":"n.","phonetic":"[ˈrɛsəpɪ]","meaning":"食譜；秘訣","definition":"a set of instructions for preparing a dish","collocations":["follow a recipe","family recipe","recipe for success"],"example":"She followed the recipe carefully to make the cake.","exampleZh":"她仔細按照食譜做蛋糕。","synonyms":[],"level":3,"theme":"食物與烹飪","examples":[{"en":"She followed the recipe carefully to make the cake.","zh":"她仔細按照食譜做蛋糕。"},{"en":"She followed the recipe carefully to bake a soft cake.","zh":"她仔細照著食譜烤出一個鬆軟的蛋糕。"},{"en":"Hard work and honesty are a good recipe for success.","zh":"努力與誠實是成功的好祕訣。"}]},{"word":"reckless","pos":"adj.","phonetic":"[ˈrɛklɪs]","meaning":"魯莽的；不顧後果的","definition":"acting without thinking carefully about the consequences","collocations":["reckless driving","a reckless decision","act recklessly"],"example":"He was fined for reckless driving on the highway.","exampleZh":"他因在高速公路上魯莽駕駛而被罰款。","synonyms":["careless","rash"],"level":5,"theme":"性質與描述","examples":[{"en":"He was fined for reckless driving on the highway.","zh":"他因在高速公路上魯莽駕駛而被罰款。"},{"en":"He was fined for reckless driving on the busy road.","zh":"他因在繁忙的道路上魯莽駕駛而被罰款。"},{"en":"Making a reckless choice can put others in danger.","zh":"做出不顧後果的選擇可能會使他人陷入危險。"}]},{"word":"recognize","pos":"v.","phonetic":"[ˈrɛkəgˌnaɪz]","meaning":"認出；承認","definition":"to identify someone or something from previous knowledge","collocations":["recognize a face","recognize an achievement","hardly recognize"],"example":"I almost didn't recognize you with short hair.","exampleZh":"你剪短髮後我差點認不出你。","synonyms":["identify","acknowledge"],"level":3,"theme":"抽象概念","examples":[{"en":"I almost didn't recognize you with short hair.","zh":"你剪短髮後我差點認不出你。"},{"en":"I almost didn't recognize you with your new haircut.","zh":"你剪了新髮型，我差點認不出你。"},{"en":"The school will recognize her outstanding achievement with an award.","zh":"學校將以獎項來表彰她傑出的成就。"}]},{"word":"recommend","pos":"v.","phonetic":"[ˌrɛkəˈmɛnd]","meaning":"推薦；建議","definition":"to suggest that something is good or suitable","collocations":["recommend a restaurant","highly recommend","recommend a book"],"example":"Can you recommend a good restaurant nearby?","exampleZh":"你能推薦附近一間不錯的餐廳嗎？","synonyms":["suggest","advise"],"level":3,"theme":"溝通與語言","examples":[{"en":"Can you recommend a good restaurant nearby?","zh":"你能推薦附近一間不錯的餐廳嗎？"},{"en":"Can you recommend a good book for a rainy afternoon?","zh":"你能推薦一本適合下雨午後的好書嗎？"},{"en":"The doctor recommended that he get more sleep.","zh":"醫生建議他多睡一點。"}]},{"word":"record","pos":"n. / v.","phonetic":"[ˈrɛkɚd]","meaning":"紀錄；唱片；記錄","definition":"a piece of evidence about the past, or to set down in writing or sound","collocations":["break a record","keep a record","record a song"],"example":"He broke the world record in swimming.","exampleZh":"他打破了游泳的世界紀錄。","synonyms":["log"],"level":2,"theme":"科技與媒體","examples":[{"en":"He broke the world record in swimming.","zh":"他打破了游泳的世界紀錄。"},{"en":"The young swimmer broke the national record last week.","zh":"這位年輕游泳選手上週打破了全國紀錄。"},{"en":"Please record the results of the experiment in your notebook.","zh":"請把實驗結果記錄在你的筆記本裡。"}]},{"word":"recover","pos":"v.","phonetic":"[rɪˈkʌvɚ]","meaning":"恢復；復原","definition":"to return to a normal state of health or strength","collocations":["recover from illness","fully recover","recover quickly"],"example":"It took him weeks to recover from the flu.","exampleZh":"他花了好幾週才從流感中康復。","synonyms":["heal","recuperate"],"level":3,"theme":"身體與健康","examples":[{"en":"It took him weeks to recover from the flu.","zh":"他花了好幾週才從流感中康復。"},{"en":"After a good night's sleep, she began to recover her energy.","zh":"睡了一夜好覺後，她開始恢復體力。"},{"en":"It may take months to fully recover from a broken leg.","zh":"腿骨折後可能需要好幾個月才能完全復原。"}]},{"word":"reduce","pos":"v.","phonetic":"[rɪˈdjus]","meaning":"減少；降低","definition":"to make something smaller or less in amount","collocations":["reduce costs","reduce stress","reduce speed"],"example":"The company aims to reduce its carbon emissions.","exampleZh":"這家公司致力於減少碳排放。","synonyms":["decrease","lower"],"level":3,"theme":"抽象概念","examples":[{"en":"The company aims to reduce its carbon emissions.","zh":"這家公司致力於減少碳排放。"},{"en":"Turning off the lights can help reduce our electricity costs.","zh":"關燈有助於降低我們的電費。"},{"en":"Deep breathing is a simple way to reduce stress before exams.","zh":"深呼吸是考試前減少壓力的簡單方法。"}]},{"word":"refrigerator","pos":"n.","phonetic":"[rɪˈfrɪdʒəˌretɚ]","meaning":"冰箱","definition":"an appliance used to keep food cold","collocations":["put in the refrigerator","open the refrigerator","empty refrigerator"],"example":"Please put the milk back in the refrigerator.","exampleZh":"請把牛奶放回冰箱。","synonyms":["fridge"],"level":2,"theme":"居家與生活","examples":[{"en":"Please put the milk back in the refrigerator.","zh":"請把牛奶放回冰箱。"},{"en":"Remember to put the leftovers in the refrigerator tonight.","zh":"記得今晚把剩菜放進冰箱。"},{"en":"She opened the refrigerator to look for something cold to drink.","zh":"她打開冰箱，想找點冰涼的東西喝。"}]},{"word":"refuse","pos":"v.","phonetic":"[rɪˈfjuz]","meaning":"拒絕","definition":"to indicate unwillingness to do or accept something","collocations":["refuse an offer","refuse to answer","flatly refuse"],"example":"He refused to give up his seat.","exampleZh":"他拒絕讓出座位。","synonyms":["decline","reject"],"level":3,"theme":"動作與行為","examples":[{"en":"He refused to give up his seat.","zh":"他拒絕讓出座位。"},{"en":"The stubborn child refused to eat his vegetables at dinner.","zh":"那個固執的孩子晚餐時拒絕吃蔬菜。"},{"en":"She flatly refused the offer because the pay was too low.","zh":"因為薪水太低，她斷然拒絕了那份工作。"}]},{"word":"regard","pos":"v. / n.","phonetic":"[rɪˈgɑrd]","meaning":"視為；尊重；關注","definition":"to consider or think of in a particular way","collocations":["regard as","in this regard","with regard to"],"example":"She is regarded as one of the best doctors in town.","exampleZh":"她被視為鎮上最好的醫生之一。","synonyms":["consider","respect"],"level":4,"theme":"抽象概念","examples":[{"en":"She is regarded as one of the best doctors in town.","zh":"她被視為鎮上最好的醫生之一。"},{"en":"Many students regard him as the most inspiring teacher in school.","zh":"許多學生把他視為學校裡最能啟發人的老師。"},{"en":"With regard to your question, I will explain it after class.","zh":"關於你的問題，我會在下課後解釋。"}]},{"word":"region","pos":"n.","phonetic":"[ˈridʒən]","meaning":"地區；區域","definition":"an area, especially part of a country","collocations":["mountain region","this region","regional differences"],"example":"This region is famous for its tea production.","exampleZh":"這個地區以生產茶葉聞名。","synonyms":["area","zone"],"level":3,"theme":"時間與空間","examples":[{"en":"This region is famous for its tea production.","zh":"這個地區以生產茶葉聞名。"},{"en":"The northern region of the island receives heavy rain in winter.","zh":"這座島嶼的北部地區冬天降雨很多。"},{"en":"Regional differences in food make traveling around the country fun.","zh":"各地區飲食的差異讓在國內旅行變得有趣。"}]},{"word":"regret","pos":"v. / n.","phonetic":"[rɪˈgrɛt]","meaning":"後悔；遺憾","definition":"to feel sorry about something one has done or failed to do","collocations":["regret a decision","deeply regret","no regrets"],"example":"He regretted not studying harder for the test.","exampleZh":"他後悔沒有更努力準備考試。","synonyms":["remorse"],"level":4,"theme":"情緒與感受","examples":[{"en":"He regretted not studying harder for the test.","zh":"他後悔沒有更努力準備考試。"},{"en":"She deeply regrets the harsh words she said to her friend.","zh":"她非常後悔對朋友說出的那些刻薄話。"},{"en":"I have no regrets about choosing to study science.","zh":"我對選擇讀理科這件事毫不後悔。"}]},{"word":"regular","pos":"adj.","phonetic":"[ˈrɛgjəlɚ]","meaning":"規律的；定期的；正常的","definition":"occurring at fixed intervals or following a set pattern","collocations":["regular exercise","regular basis","regular customer"],"example":"Regular exercise keeps you healthy.","exampleZh":"規律運動能讓你保持健康。","synonyms":["routine","normal"],"level":2,"theme":"性質與描述","examples":[{"en":"Regular exercise keeps you healthy.","zh":"規律運動能讓你保持健康。"},{"en":"He visits the same café so often that he became a regular customer.","zh":"他常去同一家咖啡廳，因此成了常客。"},{"en":"Getting enough sleep on a regular basis improves your memory.","zh":"規律地獲得充足睡眠能增進你的記憶力。"}]},{"word":"reject","pos":"v.","phonetic":"[rɪˈdʒɛkt]","meaning":"拒絕；駁回","definition":"to refuse to accept, believe, or consider something","collocations":["reject an offer","reject an application","flatly reject"],"example":"The committee rejected his proposal.","exampleZh":"委員會駁回了他的提案。","synonyms":["refuse","decline"],"level":4,"theme":"動作與行為","examples":[{"en":"The committee rejected his proposal.","zh":"委員會駁回了他的提案。"},{"en":"The publisher rejected her manuscript, but she kept writing.","zh":"出版社駁回了她的手稿，但她仍持續寫作。"},{"en":"The school rejected his application because it arrived too late.","zh":"學校駁回了他的申請，因為送件太晚了。"}]},{"word":"relate","pos":"v.","phonetic":"[rɪˈlet]","meaning":"使有關聯；理解","definition":"to show or make a connection between things","collocations":["relate to","relate a story","closely related"],"example":"I can really relate to what you're saying.","exampleZh":"我真的能理解你所說的。","synonyms":["connect"],"level":3,"theme":"抽象概念","examples":[{"en":"I can really relate to what you're saying.","zh":"我真的能理解你所說的。"},{"en":"Teachers should relate new ideas to what students already know.","zh":"老師應該把新概念與學生已知的知識連結起來。"},{"en":"Many teenagers can relate to the struggles shown in the film.","zh":"許多青少年都能理解電影中呈現的掙扎。"}]},{"word":"relationship","pos":"n.","phonetic":"[rɪˈleʃənˌʃɪp]","meaning":"關係","definition":"the way in which two or more people or things are connected","collocations":["build a relationship","close relationship","long-term relationship"],"example":"They have a close relationship with their neighbors.","exampleZh":"他們和鄰居關係很好。","synonyms":["connection"],"level":2,"theme":"人物與家庭","examples":[{"en":"They have a close relationship with their neighbors.","zh":"他們和鄰居關係很好。"},{"en":"It takes time and honesty to build a strong relationship.","zh":"建立穩固的關係需要時間與誠實。"},{"en":"They have kept a long-term relationship since high school.","zh":"他們從高中起就維持著長久的關係。"}]},{"word":"relative","pos":"n. / adj.","phonetic":"[ˈrɛlətɪv]","meaning":"親戚；相對的","definition":"a person connected by blood or marriage, or considered in comparison","collocations":["close relative","relative to","relatively speaking"],"example":"We invited all our relatives to the wedding.","exampleZh":"我們邀請了所有親戚來參加婚禮。","synonyms":["kin"],"level":3,"theme":"人物與家庭","examples":[{"en":"We invited all our relatives to the wedding.","zh":"我們邀請了所有親戚來參加婚禮。"},{"en":"A close relative of mine lives in a small mountain town.","zh":"我的一位近親住在一座小山城。"},{"en":"The test was easy relative to the one we took last week.","zh":"相較於上週的考試，這次考試算容易。"}]},{"word":"relax","pos":"v.","phonetic":"[rɪˈlæks]","meaning":"放鬆","definition":"to become less tense or anxious","collocations":["relax at home","just relax","relax the muscles"],"example":"Just relax and enjoy the weekend.","exampleZh":"放輕鬆，好好享受週末。","synonyms":["unwind"],"level":2,"theme":"情緒與感受","examples":[{"en":"Just relax and enjoy the weekend.","zh":"放輕鬆，好好享受週末。"},{"en":"After the final exam, the students finally relaxed at home.","zh":"期末考結束後，學生們終於在家放鬆了。"},{"en":"Take a deep breath and try to relax your shoulders.","zh":"深吸一口氣，試著放鬆你的肩膀。"}]},{"word":"relaxed","pos":"adj.","phonetic":"[rɪˈlækst]","meaning":"放鬆的；輕鬆的","definition":"free from tension or anxiety","collocations":["feel relaxed","relaxed atmosphere","stay relaxed"],"example":"The music created a relaxed atmosphere.","exampleZh":"這音樂營造出輕鬆的氛圍。","synonyms":["calm"],"level":2,"theme":"情緒與感受","examples":[{"en":"The music created a relaxed atmosphere.","zh":"這音樂營造出輕鬆的氛圍。"},{"en":"The teacher created a relaxed atmosphere in the classroom.","zh":"老師在教室裡營造出輕鬆的氣氛。"},{"en":"She felt relaxed as she walked along the quiet beach.","zh":"沿著寧靜的海灘漫步時，她感到很放鬆。"}]},{"word":"release","pos":"v. / n.","phonetic":"[rɪˈlis]","meaning":"釋放；發行","definition":"to allow to move freely, or to make available to the public","collocations":["release a movie","release a prisoner","new release"],"example":"The band will release a new album next month.","exampleZh":"這個樂團下個月將發行新專輯。","synonyms":["free","publish"],"level":3,"theme":"科技與媒體","examples":[{"en":"The band will release a new album next month.","zh":"這個樂團下個月將發行新專輯。"},{"en":"The studio plans to release the movie during the summer holidays.","zh":"製片公司計畫在暑假期間發行這部電影。"},{"en":"The zookeeper released the healed bird back into the wild.","zh":"動物園管理員把康復的鳥兒放回野外。"}]},{"word":"relevant","pos":"adj.","phonetic":"[ˈrɛləvənt]","meaning":"相關的；切題的","definition":"closely connected or appropriate to what is being discussed","collocations":["relevant information","relevant experience","stay relevant"],"example":"Please provide relevant examples in your essay.","exampleZh":"請在你的文章中提供相關的例子。","synonyms":["pertinent"],"level":5,"theme":"抽象概念","examples":[{"en":"Please provide relevant examples in your essay.","zh":"請在你的文章中提供相關的例子。"},{"en":"Please include only relevant information in your report.","zh":"請在你的報告中只納入相關的資訊。"},{"en":"Her relevant experience made her a strong candidate for the job.","zh":"她相關的經驗使她成為這份工作的有力人選。"}]},{"word":"reliable","pos":"adj.","phonetic":"[rɪˈlaɪəbl̩]","meaning":"可靠的","definition":"consistently good in quality or performance; trustworthy","collocations":["reliable source","reliable friend","highly reliable"],"example":"He is a reliable friend who always keeps his promises.","exampleZh":"他是個可靠的朋友，總是信守承諾。","synonyms":["dependable"],"level":4,"theme":"性質與描述","examples":[{"en":"He is a reliable friend who always keeps his promises.","zh":"他是個可靠的朋友，總是信守承諾。"},{"en":"A good encyclopedia is a reliable source of information.","zh":"一本好的百科全書是可靠的資訊來源。"},{"en":"This old car is surprisingly reliable in cold weather.","zh":"這輛舊車在寒冷天氣裡出乎意料地可靠。"}]},{"word":"religion","pos":"n.","phonetic":"[rɪˈlɪdʒən]","meaning":"宗教","definition":"the belief in and worship of a superhuman controlling power","collocations":["practice a religion","freedom of religion","world religions"],"example":"People of different religions live peacefully in this city.","exampleZh":"不同宗教的人們在這座城市裡和平共處。","synonyms":["faith"],"level":4,"theme":"社會與文化","examples":[{"en":"People of different religions live peacefully in this city.","zh":"不同宗教的人們在這座城市裡和平共處。"},{"en":"In this country, people are free to practice any religion.","zh":"在這個國家，人們可以自由信奉任何宗教。"},{"en":"The course compares the beliefs of several world religions.","zh":"這門課比較了幾種世界宗教的信仰。"}]},{"word":"religious","pos":"adj.","phonetic":"[rɪˈlɪdʒəs]","meaning":"宗教的；虔誠的","definition":"relating to or believing in a religion","collocations":["religious belief","religious festival","deeply religious"],"example":"They celebrate several religious festivals every year.","exampleZh":"他們每年慶祝好幾個宗教節日。","synonyms":["devout"],"level":4,"theme":"社會與文化","examples":[{"en":"They celebrate several religious festivals every year.","zh":"他們每年慶祝好幾個宗教節日。"},{"en":"Her grandmother is a deeply religious woman who prays daily.","zh":"她的祖母是個非常虔誠、每天禱告的女性。"},{"en":"The town holds a colorful religious festival every spring.","zh":"這個小鎮每年春天都會舉辦繽紛的宗教節慶。"}]},{"word":"rely","pos":"v.","phonetic":"[rɪˈlaɪ]","meaning":"依賴；信賴","definition":"to depend on with full trust or confidence","collocations":["rely on","rely heavily","cannot rely"],"example":"You can always rely on her for help.","exampleZh":"你總是可以依賴她的幫助。","synonyms":["depend"],"level":3,"theme":"抽象概念","examples":[{"en":"You can always rely on her for help.","zh":"你總是可以依賴她的幫助。"},{"en":"Farmers rely heavily on rain to water their crops.","zh":"農民非常依賴雨水來灌溉他們的作物。"},{"en":"You cannot rely on luck alone to pass the exam.","zh":"你不能只靠運氣就通過考試。"}]},{"word":"remain","pos":"v.","phonetic":"[rɪˈmen]","meaning":"保持；仍然是；剩下","definition":"to continue to exist or stay in the same state","collocations":["remain calm","remain unchanged","remain silent"],"example":"Despite the chaos, she remained calm.","exampleZh":"儘管一片混亂，她仍保持冷靜。","synonyms":["stay"],"level":3,"theme":"抽象概念","examples":[{"en":"Despite the chaos, she remained calm.","zh":"儘管一片混亂，她仍保持冷靜。"},{"en":"Please remain silent while the others are taking the test.","zh":"其他人考試時請保持安靜。"},{"en":"Only a few cookies remained on the plate after the party.","zh":"派對結束後，盤子上只剩下幾片餅乾。"}]},{"word":"remarkable","pos":"adj.","phonetic":"[rɪˈmɑrkəbl̩]","meaning":"卓越的；非凡的","definition":"worthy of attention; striking or extraordinary","collocations":["remarkable achievement","remarkable ability","truly remarkable"],"example":"She made remarkable progress in just one month.","exampleZh":"她在短短一個月內取得了驚人的進步。","synonyms":["extraordinary"],"level":5,"theme":"性質與描述","examples":[{"en":"She made remarkable progress in just one month.","zh":"她在短短一個月內取得了驚人的進步。"},{"en":"The young pianist has a truly remarkable talent for music.","zh":"這位年輕鋼琴家在音樂上有著非凡的天賦。"},{"en":"Recovering so quickly was a remarkable achievement for the patient.","zh":"如此迅速康復對這位病人來說是了不起的成就。"}]},{"word":"remember","pos":"v.","phonetic":"[rɪˈmɛmbɚ]","meaning":"記得","definition":"to have or keep in one's mind an awareness of something","collocations":["remember a name","remember to do","hard to remember"],"example":"Please remember to lock the door.","exampleZh":"請記得鎖門。","synonyms":["recall"],"level":1,"theme":"抽象概念","examples":[{"en":"Please remember to lock the door.","zh":"請記得鎖門。"},{"en":"I can't remember the name of that street near the park.","zh":"我記不起公園附近那條街的名字。"},{"en":"Remember to bring your umbrella; it might rain later.","zh":"記得帶傘，等一下可能會下雨。"}]},{"word":"remind","pos":"v.","phonetic":"[rɪˈmaɪnd]","meaning":"提醒","definition":"to cause someone to remember something","collocations":["remind someone of","gentle reminder","remind to do"],"example":"This song reminds me of my childhood.","exampleZh":"這首歌讓我想起了童年。","synonyms":["prompt"],"level":2,"theme":"溝通與語言","examples":[{"en":"This song reminds me of my childhood.","zh":"這首歌讓我想起了童年。"},{"en":"Please remind me to call the dentist tomorrow morning.","zh":"請提醒我明天早上打電話給牙醫。"},{"en":"The old photograph reminds her of her school days.","zh":"那張舊照片讓她想起學生時代。"}]},{"word":"remote","pos":"adj. / n.","phonetic":"[rɪˈmot]","meaning":"遙遠的；偏僻的；遙控器","definition":"far away in distance; a device used to operate something from a distance","collocations":["remote area","remote control","remote work"],"example":"They live in a remote village in the mountains.","exampleZh":"他們住在山區的一個偏僻村莊。","synonyms":["distant"],"level":4,"theme":"時間與空間","examples":[{"en":"They live in a remote village in the mountains.","zh":"他們住在山區的一個偏僻村莊。"},{"en":"The scientists set up a station in a remote area of the forest.","zh":"科學家在森林偏遠的地方設立了一個觀測站。"},{"en":"He grabbed the remote control to change the channel.","zh":"他拿起遙控器轉台。"}]},{"word":"remove","pos":"v.","phonetic":"[rɪˈmuv]","meaning":"移除；去除","definition":"to take something away or off","collocations":["remove a stain","remove a barrier","remove clothes"],"example":"Please remove your shoes before entering.","exampleZh":"進門前請脫鞋。","synonyms":["take away","eliminate"],"level":3,"theme":"動作與行為","examples":[{"en":"Please remove your shoes before entering.","zh":"進門前請脫鞋。"},{"en":"This special soap can remove even the toughest stains.","zh":"這種特殊肥皂連最頑固的污漬都能去除。"},{"en":"Workers removed the fallen tree from the road after the storm.","zh":"暴風雨後，工人把倒下的樹從路上移除。"}]},{"word":"rent","pos":"v. / n.","phonetic":"[rɛnt]","meaning":"租；租金","definition":"to pay someone for the use of something, or the payment made","collocations":["rent an apartment","pay rent","for rent"],"example":"They rent a small apartment near the university.","exampleZh":"他們在大學附近租了一間小公寓。","synonyms":["lease"],"level":2,"theme":"居家與生活","examples":[{"en":"They rent a small apartment near the university.","zh":"他們在大學附近租了一間小公寓。"},{"en":"The students rent a small apartment near the campus.","zh":"這些學生在校園附近租了一間小公寓。"},{"en":"The monthly rent for this room is quite reasonable.","zh":"這個房間的月租相當合理。"}]},{"word":"repair","pos":"v. / n.","phonetic":"[rɪˈpɛr]","meaning":"修理；修復","definition":"to fix something that is damaged or not working","collocations":["repair a car","under repair","repair shop"],"example":"The mechanic repaired the car in an hour.","exampleZh":"技師一小時內就修好了這輛車。","synonyms":["fix","mend"],"level":3,"theme":"工作與職業","examples":[{"en":"The mechanic repaired the car in an hour.","zh":"技師一小時內就修好了這輛車。"},{"en":"It took the plumber an hour to repair the leaking pipe.","zh":"水電工花了一小時修理漏水的管子。"},{"en":"The bridge is closed because it is under repair.","zh":"這座橋因正在維修而封閉。"}]},{"word":"repeat","pos":"v.","phonetic":"[rɪˈpit]","meaning":"重複","definition":"to say or do something again","collocations":["repeat a word","repeat after me","repeat mistakes"],"example":"Could you repeat that, please?","exampleZh":"你可以再說一次嗎？","synonyms":["reiterate"],"level":2,"theme":"溝通與語言","examples":[{"en":"Could you repeat that, please?","zh":"你可以再說一次嗎？"},{"en":"The teacher asked the class to repeat the new words after her.","zh":"老師要全班跟著她重複唸這些新單字。"},{"en":"If you don't study, you may repeat the same mistakes.","zh":"如果你不用功，可能會重複犯相同的錯誤。"}]},{"word":"replace","pos":"v.","phonetic":"[rɪˈples]","meaning":"取代；替換","definition":"to put something new in the place of something else","collocations":["replace a battery","replace with","cannot be replaced"],"example":"We need to replace the old printer.","exampleZh":"我們需要更換舊印表機。","synonyms":["substitute"],"level":3,"theme":"動作與行為","examples":[{"en":"We need to replace the old printer.","zh":"我們需要更換舊印表機。"},{"en":"We should replace the batteries in the smoke detector.","zh":"我們應該更換煙霧偵測器裡的電池。"},{"en":"No machine can replace a caring and patient teacher.","zh":"沒有機器能取代一位關懷又有耐心的老師。"}]},{"word":"reply","pos":"v. / n.","phonetic":"[rɪˈplaɪ]","meaning":"回覆；回答","definition":"to say or write something in response","collocations":["reply to a letter","quick reply","in reply"],"example":"She hasn't replied to my message yet.","exampleZh":"她還沒回覆我的訊息。","synonyms":["respond","answer"],"level":2,"theme":"溝通與語言","examples":[{"en":"She hasn't replied to my message yet.","zh":"她還沒回覆我的訊息。"},{"en":"She promised to reply to my email by the end of the day.","zh":"她答應在今天結束前回覆我的電子郵件。"},{"en":"His quick reply surprised everyone in the meeting.","zh":"他迅速的回答讓會議上的每個人都感到驚訝。"}]},{"word":"report","pos":"n. / v.","phonetic":"[rɪˈport]","meaning":"報告；報導","definition":"a written or spoken account of something, or to give such an account","collocations":["news report","weather report","report a crime"],"example":"The reporter wrote a report about the accident.","exampleZh":"記者寫了一篇關於這起事故的報導。","synonyms":["account"],"level":2,"theme":"科技與媒體","examples":[{"en":"The reporter wrote a report about the accident.","zh":"記者寫了一篇關於這起事故的報導。"},{"en":"The students handed in their science reports on time.","zh":"學生們準時交出了他們的科學報告。"},{"en":"You should report the accident to the police immediately.","zh":"你應該立刻向警方報案。"}]},{"word":"represent","pos":"v.","phonetic":"[ˌrɛprɪˈzɛnt]","meaning":"代表","definition":"to act or speak on behalf of someone or something","collocations":["represent a country","represent an idea","fairly represent"],"example":"She will represent our school in the debate contest.","exampleZh":"她將代表我們學校參加辯論比賽。","synonyms":["stand for"],"level":4,"theme":"抽象概念","examples":[{"en":"She will represent our school in the debate contest.","zh":"她將代表我們學校參加辯論比賽。"},{"en":"Two students will represent our class at the science fair.","zh":"兩名學生將代表我們班參加科學展。"},{"en":"The dove is often used to represent peace.","zh":"鴿子常被用來代表和平。"}]},{"word":"republic","pos":"n.","phonetic":"[rɪˈpʌblɪk]","meaning":"共和國","definition":"a state in which power is held by elected representatives","collocations":["a democratic republic","the Republic of China","form a republic"],"example":"Taiwan is officially known as the Republic of China.","exampleZh":"臺灣的正式名稱是中華民國。","synonyms":[],"level":4,"theme":"政治與法律","examples":[{"en":"Taiwan is officially known as the Republic of China.","zh":"臺灣的正式名稱是中華民國。"},{"en":"The country became a republic after the old king stepped down.","zh":"在老國王退位後，這個國家成為了共和國。"},{"en":"In a republic, citizens elect their own leaders.","zh":"在共和國裡，公民選出自己的領袖。"}]},{"word":"require","pos":"v.","phonetic":"[rɪˈkwaɪr]","meaning":"需要；要求","definition":"to need something for a particular purpose","collocations":["require attention","require permission","as required"],"example":"This job requires a lot of patience.","exampleZh":"這份工作需要很大的耐心。","synonyms":["need"],"level":3,"theme":"抽象概念","examples":[{"en":"This job requires a lot of patience.","zh":"這份工作需要很大的耐心。"},{"en":"Learning a new language requires patience and daily practice.","zh":"學習一門新語言需要耐心和每天練習。"},{"en":"Visitors are required to show their tickets at the gate.","zh":"訪客被要求在入口處出示門票。"}]},{"word":"rescue","pos":"v. / n.","phonetic":"[ˈrɛskju]","meaning":"救援；營救","definition":"to save someone from danger or harm","collocations":["rescue team","come to the rescue","rescue operation"],"example":"Firefighters rescued the cat from the tree.","exampleZh":"消防員從樹上救下了那隻貓。","synonyms":["save"],"level":3,"theme":"動作與行為","examples":[{"en":"Firefighters rescued the cat from the tree.","zh":"消防員從樹上救下了那隻貓。"},{"en":"The rescue team searched the mountain for the lost hikers.","zh":"救援隊在山上搜尋失蹤的登山客。"},{"en":"A passing sailor came to the rescue of the drowning boy.","zh":"一名路過的水手前來營救那名溺水的男孩。"}]},{"word":"research","pos":"n. / v.","phonetic":"[rɪˈsɝtʃ]","meaning":"研究","definition":"the systematic investigation into a subject","collocations":["conduct research","research shows","medical research"],"example":"Scientists are conducting research on climate change.","exampleZh":"科學家正在進行氣候變遷的研究。","synonyms":["study"],"level":3,"theme":"科學與數學","examples":[{"en":"Scientists are conducting research on climate change.","zh":"科學家正在進行氣候變遷的研究。"},{"en":"Students must conduct research before writing their essays.","zh":"學生在寫論文之前必須先進行研究。"},{"en":"Recent research shows that reading improves concentration.","zh":"近期研究顯示，閱讀能增進專注力。"}]},{"word":"reserve","pos":"v. / n.","phonetic":"[rɪˈzɝv]","meaning":"預訂；儲備","definition":"to arrange for something to be kept for a particular person","collocations":["reserve a table","natural reserve","in reserve"],"example":"I'd like to reserve a table for four tonight.","exampleZh":"我想預訂今晚四人的座位。","synonyms":["book"],"level":4,"theme":"商業與金錢","examples":[{"en":"I'd like to reserve a table for four tonight.","zh":"我想預訂今晚四人的座位。"},{"en":"I'd like to reserve two seats for tonight's concert.","zh":"我想預訂今晚音樂會的兩個座位。"},{"en":"The park is a nature reserve where hunting is forbidden.","zh":"這座公園是禁止狩獵的自然保護區。"}]},{"word":"resolve","pos":"v.","phonetic":"[rɪˈzɑlv]","meaning":"解決；決心","definition":"to find a solution to a problem or difficulty","collocations":["resolve a conflict","resolve an issue","firmly resolve"],"example":"They finally resolved their differences.","exampleZh":"他們終於解決了彼此的分歧。","synonyms":["settle"],"level":5,"theme":"抽象概念","examples":[{"en":"They finally resolved their differences.","zh":"他們終於解決了彼此的分歧。"},{"en":"The two friends talked calmly to resolve their argument.","zh":"兩位朋友平靜地交談以化解他們的爭執。"},{"en":"She resolved to study harder after failing the quiz.","zh":"小考不及格後，她下定決心要更用功。"}]},{"word":"resource","pos":"n.","phonetic":"[ˈrisɔrs]","meaning":"資源","definition":"a stock or supply of materials or assets","collocations":["natural resources","human resources","limited resources"],"example":"Taiwan lacks natural resources such as oil.","exampleZh":"臺灣缺乏石油等天然資源。","synonyms":["asset"],"level":4,"theme":"商業與金錢","examples":[{"en":"Taiwan lacks natural resources such as oil.","zh":"臺灣缺乏石油等天然資源。"},{"en":"Clean water is a precious natural resource we must protect.","zh":"乾淨的水是我們必須保護的珍貴天然資源。"},{"en":"The library offers many useful resources for students.","zh":"圖書館為學生提供許多有用的資源。"}]},{"word":"respect","pos":"n. / v.","phonetic":"[rɪˈspɛkt]","meaning":"尊重；尊敬","definition":"a feeling of deep admiration for someone or something","collocations":["show respect","mutual respect","respect for elders"],"example":"Students should show respect for their teachers.","exampleZh":"學生應該尊重老師。","synonyms":["admire"],"level":2,"theme":"抽象概念","examples":[{"en":"Students should show respect for their teachers.","zh":"學生應該尊重老師。"},{"en":"We should show respect for people from different cultures.","zh":"我們應該尊重來自不同文化的人。"},{"en":"Mutual respect is the basis of any good friendship.","zh":"相互尊重是任何良好友誼的基礎。"}]},{"word":"respond","pos":"v.","phonetic":"[rɪˈspɑnd]","meaning":"回應；回答","definition":"to say or do something as a reaction to something","collocations":["respond quickly","respond to a question","fail to respond"],"example":"He responded to my email right away.","exampleZh":"他馬上回覆了我的電子郵件。","synonyms":["reply"],"level":3,"theme":"溝通與語言","examples":[{"en":"He responded to my email right away.","zh":"他馬上回覆了我的電子郵件。"},{"en":"The firefighters responded quickly to the emergency call.","zh":"消防員迅速回應了那通緊急電話。"},{"en":"She didn't respond to my question, so I asked again.","zh":"她沒有回答我的問題，所以我又問了一次。"}]},{"word":"response","pos":"n.","phonetic":"[rɪˈspɑns]","meaning":"回應；反應","definition":"a reply or reaction to something","collocations":["in response to","positive response","quick response"],"example":"The company received hundreds of responses to the survey.","exampleZh":"這家公司收到了數百份問卷回應。","synonyms":["reply"],"level":3,"theme":"溝通與語言","examples":[{"en":"The company received hundreds of responses to the survey.","zh":"這家公司收到了數百份問卷回應。"},{"en":"The teacher was pleased with the students' positive response.","zh":"老師對學生們積極的反應感到滿意。"},{"en":"In response to the complaints, the shop changed its policy.","zh":"為回應那些抱怨，商店改變了政策。"}]},{"word":"responsibility","pos":"n.","phonetic":"[rɪˌspɑnsəˈbɪlətɪ]","meaning":"責任","definition":"a duty to deal with or take care of something","collocations":["take responsibility","sense of responsibility","job responsibility"],"example":"Taking care of the dog is my responsibility.","exampleZh":"照顧這隻狗是我的責任。","synonyms":["duty"],"level":3,"theme":"抽象概念","examples":[{"en":"Taking care of the dog is my responsibility.","zh":"照顧這隻狗是我的責任。"},{"en":"Every citizen has a responsibility to protect the environment.","zh":"每位公民都有保護環境的責任。"},{"en":"He took full responsibility for the mistake he made.","zh":"他為自己所犯的錯誤負起全部責任。"}]},{"word":"responsible","pos":"adj.","phonetic":"[rɪˈspɑnsəbl̩]","meaning":"負責任的","definition":"having a duty to deal with something or having control over someone","collocations":["responsible for","socially responsible","act responsible"],"example":"Parents are responsible for their children's safety.","exampleZh":"父母有責任確保孩子的安全。","synonyms":["accountable"],"level":3,"theme":"性質與描述","examples":[{"en":"Parents are responsible for their children's safety.","zh":"父母有責任確保孩子的安全。"},{"en":"The class monitor is responsible for keeping the room tidy.","zh":"班長負責維持教室整潔。"},{"en":"A responsible driver never uses a phone while driving.","zh":"負責任的駕駛開車時絕不使用手機。"}]},{"word":"rest","pos":"n. / v.","phonetic":"[rɛst]","meaning":"休息；剩餘部分","definition":"a period of relaxation, or the remaining part of something","collocations":["take a rest","the rest of","rest assured"],"example":"You should take a rest after such a long trip.","exampleZh":"經過這麼長的旅程，你應該休息一下。","synonyms":["relaxation"],"level":1,"theme":"身體與健康","examples":[{"en":"You should take a rest after such a long trip.","zh":"經過這麼長的旅程，你應該休息一下。"},{"en":"You look tired; you should take a rest for a while.","zh":"你看起來很累，應該休息一下。"},{"en":"I finished half the book and will read the rest tonight.","zh":"我讀完了半本書，其餘的今晚再讀。"}]},{"word":"restaurant","pos":"n.","phonetic":"[ˈrɛstərənt]","meaning":"餐廳","definition":"a place where people pay to sit and eat meals","collocations":["eat at a restaurant","open a restaurant","fancy restaurant"],"example":"We celebrated her birthday at a fancy restaurant.","exampleZh":"我們在一家高級餐廳慶祝她的生日。","synonyms":[],"level":1,"theme":"食物與烹飪","examples":[{"en":"We celebrated her birthday at a fancy restaurant.","zh":"我們在一家高級餐廳慶祝她的生日。"},{"en":"They opened a small Italian restaurant near the train station.","zh":"他們在火車站附近開了一家小型義大利餐廳。"},{"en":"We often eat at a family restaurant on weekends.","zh":"我們週末常在一家家庭餐廳用餐。"}]},{"word":"result","pos":"n. / v.","phonetic":"[rɪˈzʌlt]","meaning":"結果","definition":"a consequence, effect, or outcome of something","collocations":["as a result","test result","result in"],"example":"As a result of hard work, she passed the exam.","exampleZh":"由於努力，她通過了考試。","synonyms":["outcome"],"level":2,"theme":"抽象概念","examples":[{"en":"As a result of hard work, she passed the exam.","zh":"由於努力，她通過了考試。"},{"en":"As a result of the heavy rain, the game was canceled.","zh":"由於下大雨，比賽被取消了。"},{"en":"The students eagerly waited for their exam results.","zh":"學生們急切地等待考試結果。"}]},{"word":"retire","pos":"v.","phonetic":"[rɪˈtaɪr]","meaning":"退休","definition":"to leave one's job and stop working, usually because of age","collocations":["retire from work","early retirement","plan to retire"],"example":"My grandfather retired at the age of sixty-five.","exampleZh":"我祖父在六十五歲時退休。","synonyms":[],"level":3,"theme":"工作與職業","examples":[{"en":"My grandfather retired at the age of sixty-five.","zh":"我祖父在六十五歲時退休。"},{"en":"My aunt plans to retire early and travel around the world.","zh":"我阿姨打算提早退休，去環遊世界。"},{"en":"After forty years of teaching, he finally retired from work.","zh":"教了四十年書後，他終於退休了。"}]},{"word":"return","pos":"v. / n.","phonetic":"[rɪˈtɝn]","meaning":"返回；歸還","definition":"to come or go back to a place, or to give something back","collocations":["return home","return a book","in return"],"example":"He returned the library book two days late.","exampleZh":"他歸還圖書館的書遲了兩天。","synonyms":["come back"],"level":1,"theme":"動作與行為","examples":[{"en":"He returned the library book two days late.","zh":"他歸還圖書館的書遲了兩天。"},{"en":"Please return the borrowed books to the library on time.","zh":"請準時把借的書歸還給圖書館。"},{"en":"They plan to return home before it gets dark.","zh":"他們打算在天黑前返家。"}]},{"word":"reveal","pos":"v.","phonetic":"[rɪˈvil]","meaning":"揭露；顯示","definition":"to make known previously secret or hidden information","collocations":["reveal a secret","reveal the truth","study reveals"],"example":"The magician revealed how the trick was done.","exampleZh":"魔術師揭露了這個把戲是怎麼做的。","synonyms":["disclose"],"level":4,"theme":"溝通與語言","examples":[{"en":"The magician revealed how the trick was done.","zh":"魔術師揭露了這個把戲是怎麼做的。"},{"en":"The survey revealed that most teenagers sleep too little.","zh":"這項調查顯示大多數青少年睡得太少。"},{"en":"She promised not to reveal her friend's secret to anyone.","zh":"她答應不把朋友的秘密透露給任何人。"}]},{"word":"review","pos":"n. / v.","phonetic":"[rɪˈvju]","meaning":"評論；複習；審查","definition":"a formal assessment of something, or to examine again","collocations":["book review","review for a test","under review"],"example":"She wrote a positive review of the new movie.","exampleZh":"她給那部新電影寫了正面的評論。","synonyms":["evaluate"],"level":3,"theme":"教育與學習","examples":[{"en":"She wrote a positive review of the new movie.","zh":"她給那部新電影寫了正面的評論。"},{"en":"I always review my notes the night before a test.","zh":"我總是在考試前一晚複習筆記。"},{"en":"The committee will review the plan before approving it.","zh":"委員會會在批准之前審查這個計畫。"}]},{"word":"revolution","pos":"n.","phonetic":"[ˌrɛvəˈluʃən]","meaning":"革命；大變革","definition":"a forcible overthrow of a government, or a dramatic change","collocations":["industrial revolution","political revolution","technological revolution"],"example":"The Industrial Revolution changed the way people worked.","exampleZh":"工業革命改變了人們的工作方式。","synonyms":["uprising"],"level":5,"theme":"社會與文化","examples":[{"en":"The Industrial Revolution changed the way people worked.","zh":"工業革命改變了人們的工作方式。"},{"en":"The Industrial Revolution transformed how goods were produced.","zh":"工業革命改變了商品的生產方式。"},{"en":"The smartphone caused a revolution in the way we communicate.","zh":"智慧型手機為我們的溝通方式帶來了革命。"}]},{"word":"reward","pos":"n. / v.","phonetic":"[rɪˈwɔrd]","meaning":"獎勵；報酬","definition":"a thing given in recognition of effort or achievement","collocations":["reward effort","offer a reward","great reward"],"example":"Hard work is often its own reward.","exampleZh":"努力工作本身往往就是一種回報。","synonyms":["prize"],"level":3,"theme":"抽象概念","examples":[{"en":"Hard work is often its own reward.","zh":"努力工作本身往往就是一種回報。"},{"en":"The company offered a reward for information about the theft.","zh":"公司懸賞徵求關於竊案的線索。"},{"en":"Good grades were the reward for her months of hard work.","zh":"好成績是她數個月努力的報酬。"}]},{"word":"rhyme","pos":"n. / v.","phonetic":"[raɪm]","meaning":"押韻；韻文","definition":"correspondence of sound between words or the end of lines","collocations":["nursery rhyme","rhyme with","rhyme scheme"],"example":"Children love singing nursery rhymes.","exampleZh":"孩子們喜歡唱兒歌。","synonyms":[],"level":3,"theme":"藝術與音樂","examples":[{"en":"Children love singing nursery rhymes.","zh":"孩子們喜歡唱兒歌。"},{"en":"The poet used simple words that rhyme with each other.","zh":"這位詩人用了彼此押韻的簡單字詞。"},{"en":"In this poem, the word 'night' rhymes with 'light'.","zh":"在這首詩中，「night」與「light」押韻。"}]},{"word":"rhythm","pos":"n.","phonetic":"[ˈrɪðəm]","meaning":"節奏；韻律","definition":"a strong regular repeated pattern of movement or sound","collocations":["dance rhythm","sense of rhythm","natural rhythm"],"example":"She has a great sense of rhythm when she dances.","exampleZh":"她跳舞時很有節奏感。","synonyms":["beat"],"level":4,"theme":"藝術與音樂","examples":[{"en":"She has a great sense of rhythm when she dances.","zh":"她跳舞時很有節奏感。"},{"en":"The dancers moved gracefully to the rhythm of the drums.","zh":"舞者隨著鼓聲的節奏優雅地舞動。"},{"en":"It takes practice to keep a steady rhythm while drumming.","zh":"打鼓時要保持穩定的節奏需要練習。"}]},{"word":"rice","pos":"n.","phonetic":"[raɪs]","meaning":"米飯；稻米","definition":"the small seeds of a cereal plant used as food","collocations":["cook rice","fried rice","rice field"],"example":"Rice is the main food in many Asian countries.","exampleZh":"米飯是許多亞洲國家的主食。","synonyms":[],"level":1,"theme":"食物與烹飪","examples":[{"en":"Rice is the main food in many Asian countries.","zh":"米飯是許多亞洲國家的主食。"},{"en":"My mother cooks a pot of rice every evening for dinner.","zh":"我媽媽每天傍晚煮一鍋飯當晚餐。"},{"en":"Farmers work hard in the rice fields during the summer.","zh":"夏天時農民在稻田裡辛勤工作。"}]},{"word":"rich","pos":"adj.","phonetic":"[rɪtʃ]","meaning":"富有的；豐富的","definition":"having a great deal of money or resources","collocations":["get rich","rich in vitamins","rich culture"],"example":"The soup is rich in flavor and nutrients.","exampleZh":"這道湯風味與營養都很豐富。","synonyms":["wealthy"],"level":1,"theme":"性質與描述","examples":[{"en":"The soup is rich in flavor and nutrients.","zh":"這道湯風味與營養都很豐富。"},{"en":"Green vegetables are rich in vitamins and minerals.","zh":"綠色蔬菜富含維生素和礦物質。"},{"en":"The old town is famous for its rich cultural history.","zh":"這座古鎮以其豐富的文化歷史而聞名。"}]},{"word":"rid","pos":"v.","phonetic":"[rɪd]","meaning":"擺脫；除去","definition":"to make someone or something free of something unwanted","collocations":["get rid of","rid of pests","rid oneself of"],"example":"We need to get rid of these old newspapers.","exampleZh":"我們需要處理掉這些舊報紙。","synonyms":["eliminate"],"level":3,"theme":"動作與行為","examples":[{"en":"We need to get rid of these old newspapers.","zh":"我們需要處理掉這些舊報紙。"},{"en":"We should get rid of these broken toys in the garage.","zh":"我們應該把車庫裡這些壞掉的玩具處理掉。"},{"en":"Exercise can help you get rid of stress and stay healthy.","zh":"運動能幫助你擺脫壓力並保持健康。"}]},{"word":"ride","pos":"v. / n.","phonetic":"[raɪd]","meaning":"騎；搭乘","definition":"to sit on and control the movement of an animal or vehicle","collocations":["ride a bike","give a ride","take a ride"],"example":"He rides his bicycle to school every day.","exampleZh":"他每天騎腳踏車上學。","synonyms":[],"level":1,"theme":"交通與旅行","examples":[{"en":"He rides his bicycle to school every day.","zh":"他每天騎腳踏車上學。"},{"en":"Would you like a ride to the station in my car?","zh":"你想搭我的車到車站嗎？"},{"en":"They rode their bikes along the river all afternoon.","zh":"他們整個下午沿著河邊騎腳踏車。"}]},{"word":"right","pos":"adj. / adv. / n.","phonetic":"[raɪt]","meaning":"正確的；右邊；權利","definition":"correct or true; the direction opposite left; a moral or legal entitlement","collocations":["turn right","human rights","get it right"],"example":"You have the right to express your opinion.","exampleZh":"你有權表達自己的意見。","synonyms":["correct"],"level":1,"theme":"抽象概念","examples":[{"en":"You have the right to express your opinion.","zh":"你有權表達自己的意見。"},{"en":"Turn right at the corner, and the school is on your left.","zh":"在轉角右轉，學校就在你的左邊。"},{"en":"Everyone has the right to a fair and free education.","zh":"每個人都有接受公平且自由教育的權利。"}]},{"word":"ring","pos":"n. / v.","phonetic":"[rɪŋ]","meaning":"戒指；鈴聲；打電話","definition":"a small circular band, or the sound of a bell, or to make such a sound","collocations":["wedding ring","ring a bell","phone rings"],"example":"The phone rang three times before she answered.","exampleZh":"電話響了三聲她才接。","synonyms":[],"level":1,"theme":"服裝與外表","examples":[{"en":"The phone rang three times before she answered.","zh":"電話響了三聲她才接。"},{"en":"The alarm clock rang loudly at six in the morning.","zh":"鬧鐘早上六點大聲響起。"},{"en":"She wore a beautiful silver ring on her finger.","zh":"她的手指上戴著一枚漂亮的銀戒指。"}]},{"word":"ripe","pos":"adj.","phonetic":"[raɪp]","meaning":"成熟的","definition":"fully developed and ready to be harvested or eaten","collocations":["ripe fruit","not yet ripe","ripe banana"],"example":"These mangoes are perfectly ripe and sweet.","exampleZh":"這些芒果剛好熟透又甜。","synonyms":["mature"],"level":3,"theme":"食物與烹飪","examples":[{"en":"These mangoes are perfectly ripe and sweet.","zh":"這些芒果剛好熟透又甜。"},{"en":"The tomatoes in the garden are finally ripe enough to pick.","zh":"花園裡的番茄終於成熟到可以採收了。"},{"en":"Don't eat that banana yet; it is not ripe.","zh":"先別吃那根香蕉，它還沒熟。"}]},{"word":"rise","pos":"v. / n.","phonetic":"[raɪz]","meaning":"上升；起身；增加","definition":"to move upward or increase in level or amount","collocations":["sun rises","rise in price","give rise to"],"example":"Prices have risen sharply this year.","exampleZh":"今年物價急遽上漲。","synonyms":["increase","ascend"],"level":2,"theme":"動作與行為","examples":[{"en":"Prices have risen sharply this year.","zh":"今年物價急遽上漲。"},{"en":"The sun rises earlier in the summer than in the winter.","zh":"夏天太陽比冬天升起得早。"},{"en":"The rapid rise in food prices worried many families.","zh":"食物價格的快速上漲讓許多家庭擔憂。"}]},{"word":"risk","pos":"n. / v.","phonetic":"[rɪsk]","meaning":"風險；冒險","definition":"a situation involving exposure to danger","collocations":["take a risk","at risk","risk one's life"],"example":"Smoking increases the risk of lung cancer.","exampleZh":"吸菸會增加罹患肺癌的風險。","synonyms":["danger"],"level":3,"theme":"抽象概念","examples":[{"en":"Smoking increases the risk of lung cancer.","zh":"吸菸會增加罹患肺癌的風險。"},{"en":"Wearing a seat belt reduces the risk of serious injury.","zh":"繫安全帶能降低受重傷的風險。"},{"en":"The firefighter risked his life to save the trapped child.","zh":"那名消防員冒著生命危險去救受困的孩子。"}]},{"word":"river","pos":"n.","phonetic":"[ˈrɪvɚ]","meaning":"河流","definition":"a large natural stream of water flowing to the sea","collocations":["cross a river","river bank","flow into a river"],"example":"The village is located near a wide river.","exampleZh":"這個村莊位於一條寬闊的河流附近。","synonyms":["stream"],"level":1,"theme":"自然與環境","examples":[{"en":"The village is located near a wide river.","zh":"這個村莊位於一條寬闊的河流附近。"},{"en":"Children love to swim in the clear river during summer.","zh":"孩子們喜歡在夏天到清澈的河裡游泳。"},{"en":"A narrow wooden bridge crosses the river near our house.","zh":"我們家附近有座狹窄的木橋橫跨這條河。"}]},{"word":"road","pos":"n.","phonetic":"[rod]","meaning":"道路；馬路","definition":"a way for traveling between places","collocations":["road trip","cross the road","road sign"],"example":"We took a long road trip across the country.","exampleZh":"我們進行了一趟橫越全國的公路旅行。","synonyms":["street","route"],"level":1,"theme":"交通與旅行","examples":[{"en":"We took a long road trip across the country.","zh":"我們進行了一趟橫越全國的公路旅行。"},{"en":"Look both ways before you cross the busy road.","zh":"過繁忙的馬路前要看看兩邊。"},{"en":"A clear road sign showed the way to the airport.","zh":"一個清楚的路標指出了往機場的路。"}]},{"word":"roam","pos":"v.","phonetic":"[rom]","meaning":"漫遊；閒逛","definition":"to walk or travel without a fixed purpose","collocations":["roam freely","roam the streets","roam around"],"example":"The cattle roam freely across the fields.","exampleZh":"牛群在田野間自由漫遊。","synonyms":["wander","ramble"],"level":4,"theme":"動作與行為","examples":[{"en":"The cattle roam freely across the fields.","zh":"牛群在田野間自由漫遊。"},{"en":"Tourists love to roam the narrow streets of the old town.","zh":"遊客喜歡在古鎮狹窄的街道上閒逛。"},{"en":"Wild deer roam freely in this national park.","zh":"野生鹿群在這座國家公園裡自由漫遊。"}]},{"word":"roar","pos":"v. / n.","phonetic":"[ror]","meaning":"吼叫；轟鳴","definition":"a loud deep sound made by an animal or engine","collocations":["roar with laughter","the lion's roar","engines roar"],"example":"The lion let out a mighty roar.","exampleZh":"那頭獅子發出了一聲巨吼。","synonyms":["bellow","growl"],"level":3,"theme":"動物與植物","examples":[{"en":"The lion let out a mighty roar.","zh":"那頭獅子發出了一聲巨吼。"},{"en":"The crowd roared with excitement when the team scored.","zh":"當球隊得分時，群眾興奮地咆哮。"},{"en":"We heard the engines roar as the race began.","zh":"比賽開始時，我們聽見引擎轟鳴。"}]},{"word":"roast","pos":"v. / n. / adj.","phonetic":"[rost]","meaning":"烤；烘烤","definition":"to cook food using dry heat","collocations":["roast chicken","roast beef","roast in the oven"],"example":"My mother roasted a chicken for dinner.","exampleZh":"我媽媽烤了一隻雞當晚餐。","synonyms":["grill","bake"],"level":3,"theme":"食物與烹飪","examples":[{"en":"My mother roasted a chicken for dinner.","zh":"我媽媽烤了一隻雞當晚餐。"},{"en":"We roasted some sweet potatoes over the campfire last night.","zh":"昨晚我們在營火上烤了一些地瓜。"},{"en":"The smell of roast beef filled the whole kitchen.","zh":"烤牛肉的香味瀰漫了整個廚房。"}]},{"word":"rob","pos":"v.","phonetic":"[rɑb]","meaning":"搶劫；偷竊","definition":"to steal from a person or place","collocations":["rob a bank","rob someone of something"],"example":"Two men tried to rob the bank yesterday.","exampleZh":"昨天兩名男子企圖搶劫銀行。","synonyms":["steal","burgle"],"level":3,"theme":"政治與法律","examples":[{"en":"Two men tried to rob the bank yesterday.","zh":"昨天兩名男子企圖搶劫銀行。"},{"en":"Thieves tried to rob the small shop late at night.","zh":"竊賊試圖在深夜搶劫那家小商店。"},{"en":"He was robbed of his wallet on the crowded bus.","zh":"他在擁擠的公車上被搶走了錢包。"}]},{"word":"robber","pos":"n.","phonetic":"[ˈrɑbɚ]","meaning":"強盜；搶劫犯","definition":"a person who commits robbery","collocations":["catch a robber","armed robber"],"example":"The police caught the robber near the station.","exampleZh":"警方在車站附近抓到了那名搶匪。","synonyms":["thief","burglar"],"level":3,"theme":"政治與法律","examples":[{"en":"The police caught the robber near the station.","zh":"警方在車站附近抓到了那名搶匪。"},{"en":"The brave clerk described the robber to the police.","zh":"勇敢的店員向警方描述了那名搶劫犯。"},{"en":"An armed robber broke into the jewelry store.","zh":"一名持械搶匪闖入了珠寶店。"}]},{"word":"robbery","pos":"n.","phonetic":"[ˈrɑbərɪ]","meaning":"搶劫；盜竊罪","definition":"the crime of stealing from a place or person","collocations":["bank robbery","commit robbery"],"example":"The bank robbery was reported on the news.","exampleZh":"新聞報導了這起銀行搶案。","synonyms":["theft","burglary"],"level":4,"theme":"政治與法律","examples":[{"en":"The bank robbery was reported on the news.","zh":"新聞報導了這起銀行搶案。"},{"en":"The bank robbery shocked everyone in the quiet town.","zh":"這起銀行搶案震驚了寧靜小鎮的每個人。"},{"en":"Police arrested two men for committing the robbery.","zh":"警方逮捕了兩名犯下搶案的男子。"}]},{"word":"robe","pos":"n.","phonetic":"[rob]","meaning":"長袍；睡袍","definition":"a long loose piece of clothing","collocations":["bath robe","wear a robe"],"example":"She wrapped herself in a warm robe after the shower.","exampleZh":"她洗完澡後裹上一件溫暖的浴袍。","synonyms":["gown"],"level":2,"theme":"服裝與外表","examples":[{"en":"She wrapped herself in a warm robe after the shower.","zh":"她洗完澡後裹上一件溫暖的浴袍。"},{"en":"The judge wore a long black robe in the courtroom.","zh":"法官在法庭上穿著一件黑色長袍。"},{"en":"He put on a warm robe before making breakfast.","zh":"他在做早餐前穿上了一件保暖的睡袍。"}]},{"word":"robot","pos":"n.","phonetic":"[ˈrobɑt]","meaning":"機器人","definition":"a machine that can perform tasks automatically","collocations":["build a robot","robot arm"],"example":"The factory uses robots to assemble cars.","exampleZh":"這家工廠使用機器人來組裝汽車。","synonyms":["android"],"level":2,"theme":"科技與媒體","examples":[{"en":"The factory uses robots to assemble cars.","zh":"這家工廠使用機器人來組裝汽車。"},{"en":"Modern factories use robots to build cars quickly.","zh":"現代工廠使用機器人來快速組裝汽車。"},{"en":"The students built a small robot for the science contest.","zh":"學生們為科學競賽製作了一個小機器人。"}]},{"word":"robust","pos":"adj.","phonetic":"[roˈbʌst]","meaning":"強健的；強壯的","definition":"strong and healthy; sturdy","collocations":["robust economy","robust health","robust design"],"example":"The company built a robust economy over the decade.","exampleZh":"這家公司在十年間建立了強健的經濟體系。","synonyms":["sturdy","strong"],"level":5,"theme":"性質與描述","examples":[{"en":"The company built a robust economy over the decade.","zh":"這家公司在十年間建立了強健的經濟體系。"},{"en":"Daily exercise helped him stay robust even in old age.","zh":"每天運動讓他即使年老也保持強健。"},{"en":"The new bridge has a robust design that resists strong winds.","zh":"這座新橋有著能抵抗強風的堅固設計。"}]},{"word":"rock","pos":"n. / v.","phonetic":"[rɑk]","meaning":"岩石；搖動","definition":"a hard mineral material; to move back and forth","collocations":["rock climbing","rock the boat","solid rock"],"example":"They went rock climbing over the weekend.","exampleZh":"他們週末去攀岩。","synonyms":["stone"],"level":1,"theme":"自然與環境","examples":[{"en":"They went rock climbing over the weekend.","zh":"他們週末去攀岩。"},{"en":"The climbers rested on a large flat rock near the peak.","zh":"登山者在接近山頂的一塊大平岩上休息。"},{"en":"She gently rocked the baby until he fell asleep.","zh":"她輕輕搖著寶寶，直到他睡著。"}]},{"word":"rocket","pos":"n. / v.","phonetic":"[ˈrɑkɪt]","meaning":"火箭","definition":"a vehicle propelled into space","collocations":["launch a rocket","rocket science"],"example":"The rocket launched successfully into orbit.","exampleZh":"這枚火箭成功發射進入軌道。","synonyms":["missile"],"level":2,"theme":"科學與數學","examples":[{"en":"The rocket launched successfully into orbit.","zh":"這枚火箭成功發射進入軌道。"},{"en":"The scientists watched the rocket rise into the sky.","zh":"科學家們看著火箭升上天空。"},{"en":"Building a rocket requires knowledge of physics and math.","zh":"製造火箭需要物理和數學的知識。"}]},{"word":"rod","pos":"n.","phonetic":"[rɑd]","meaning":"桿；棒","definition":"a thin straight bar or stick","collocations":["fishing rod","metal rod"],"example":"He bought a new fishing rod for the trip.","exampleZh":"他為了這趟旅行買了一支新釣竿。","synonyms":["pole","stick"],"level":3,"theme":"運動與休閒","examples":[{"en":"He bought a new fishing rod for the trip.","zh":"他為了這趟旅行買了一支新釣竿。"},{"en":"He fixed the curtain with a long metal rod.","zh":"他用一根長金屬桿把窗簾固定好。"},{"en":"The old man sat by the lake holding a fishing rod.","zh":"老人坐在湖邊，手裡拿著釣竿。"}]},{"word":"rogue","pos":"n. / adj.","phonetic":"[rog]","meaning":"惡棍；流氓的","definition":"a dishonest or unprincipled person","collocations":["rogue nation","act like a rogue"],"example":"The novel's hero is a charming rogue.","exampleZh":"這部小說的主角是個迷人的惡棍。","synonyms":["scoundrel"],"level":6,"theme":"人物與家庭","examples":[{"en":"The novel's hero is a charming rogue.","zh":"這部小說的主角是個迷人的惡棍。"},{"en":"In the story, a clever rogue tricks the greedy merchant.","zh":"在故事中，一個聰明的惡棍騙倒了貪心的商人。"},{"en":"The film's charming rogue slowly becomes a real hero.","zh":"電影中迷人的無賴慢慢變成了真正的英雄。"}]},{"word":"role","pos":"n.","phonetic":"[rol]","meaning":"角色；作用","definition":"the function or position someone has","collocations":["play a role","leading role"],"example":"She played the leading role in the school play.","exampleZh":"她在學校話劇中飾演主角。","synonyms":["part","function"],"level":2,"theme":"藝術與音樂","examples":[{"en":"She played the leading role in the school play.","zh":"她在學校話劇中飾演主角。"},{"en":"Vitamins play an important role in keeping us healthy.","zh":"維生素在維持我們的健康上扮演重要的角色。"},{"en":"She was excited to win the leading role in the play.","zh":"她很興奮能在戲劇中得到主角。"}]},{"word":"roll","pos":"v. / n.","phonetic":"[rol]","meaning":"滾動；捲","definition":"to move by turning over and over","collocations":["roll the dice","bread roll","roll over"],"example":"The ball rolled down the hill.","exampleZh":"球滾下了山坡。","synonyms":["turn","revolve"],"level":1,"theme":"動作與行為","examples":[{"en":"The ball rolled down the hill.","zh":"球滾下了山坡。"},{"en":"The pencil rolled off the desk and fell on the floor.","zh":"鉛筆從桌上滾下來，掉在地板上。"},{"en":"He rolled the dough flat before making the pizza.","zh":"他在做披薩前把麵團擀平。"}]},{"word":"roller","pos":"n.","phonetic":"[ˈrolɚ]","meaning":"滾筒；輥軸","definition":"a cylindrical device that rolls","collocations":["roller coaster","paint roller"],"example":"We screamed on the roller coaster.","exampleZh":"我們在雲霄飛車上尖叫。","synonyms":["cylinder"],"level":2,"theme":"運動與休閒","examples":[{"en":"We screamed on the roller coaster.","zh":"我們在雲霄飛車上尖叫。"},{"en":"We used a paint roller to cover the wall quickly.","zh":"我們用油漆滾筒快速地把牆刷好。"},{"en":"The children screamed happily on the fast roller coaster.","zh":"孩子們在飛快的雲霄飛車上開心地尖叫。"}]},{"word":"romance","pos":"n.","phonetic":"[roˈmæns]","meaning":"戀愛；浪漫史","definition":"a love affair or a feeling of excitement connected with love","collocations":["a summer romance","romance novel"],"example":"Their romance began in college.","exampleZh":"他們的戀情始於大學時期。","synonyms":["love affair"],"level":4,"theme":"情緒與感受","examples":[{"en":"Their romance began in college.","zh":"他們的戀情始於大學時期。"},{"en":"The novel tells the sweet romance between two shy students.","zh":"這本小說講述兩個害羞學生之間甜蜜的戀情。"},{"en":"Their summer romance was full of long walks and laughter.","zh":"他們的夏日戀情充滿了漫步與歡笑。"}]},{"word":"romantic","pos":"adj.","phonetic":"[roˈmæntɪk]","meaning":"浪漫的","definition":"relating to love or a beautiful, idealized quality","collocations":["romantic dinner","romantic comedy"],"example":"They had a romantic dinner by the beach.","exampleZh":"他們在海邊享用了一頓浪漫的晚餐。","synonyms":["loving","idealistic"],"level":3,"theme":"情緒與感受","examples":[{"en":"They had a romantic dinner by the beach.","zh":"他們在海邊享用了一頓浪漫的晚餐。"},{"en":"He planned a romantic dinner to celebrate their anniversary.","zh":"他籌劃了一頓浪漫的晚餐來慶祝他們的週年紀念。"},{"en":"They watched a funny romantic comedy on Friday night.","zh":"他們週五晚上看了一部好笑的浪漫喜劇。"}]},{"word":"roof","pos":"n.","phonetic":"[ruf]","meaning":"屋頂","definition":"the covering on top of a building","collocations":["leaking roof","roof of a house"],"example":"A tree branch fell onto the roof.","exampleZh":"一根樹枝掉落到屋頂上。","synonyms":["rooftop"],"level":1,"theme":"居家與生活","examples":[{"en":"A tree branch fell onto the roof.","zh":"一根樹枝掉落到屋頂上。"},{"en":"Heavy snow piled up on the roof of the old barn.","zh":"厚厚的雪堆積在老穀倉的屋頂上。"},{"en":"Workers climbed up to fix the leaking roof after the storm.","zh":"暴風雨後，工人爬上去修理漏水的屋頂。"}]},{"word":"rookie","pos":"n.","phonetic":"[ˈrʊkɪ]","meaning":"新手；菜鳥","definition":"a person new to a job or activity","collocations":["rookie mistake","rookie player"],"example":"The rookie player scored his first goal.","exampleZh":"這位新秀球員攻進了他的第一顆球。","synonyms":["beginner","novice"],"level":5,"theme":"運動與休閒","examples":[{"en":"The rookie player scored his first goal.","zh":"這位新秀球員攻進了他的第一顆球。"},{"en":"As a rookie, he made a few mistakes on his first day.","zh":"身為新手，他第一天犯了幾個錯誤。"},{"en":"The rookie surprised the coach with her amazing speed.","zh":"這位新手以驚人的速度讓教練刮目相看。"}]},{"word":"room","pos":"n.","phonetic":"[rum]","meaning":"房間；空間","definition":"a part of a building enclosed by walls","collocations":["living room","make room for"],"example":"There isn't enough room for everyone.","exampleZh":"空間不夠讓大家都坐下。","synonyms":["space","chamber"],"level":1,"theme":"居家與生活","examples":[{"en":"There isn't enough room for everyone.","zh":"空間不夠讓大家都坐下。"},{"en":"Please move your bag so we can make room for others.","zh":"請移一下你的包包，好讓我們騰出空間給其他人。"},{"en":"Her favorite room in the house is the sunny living room.","zh":"她在家裡最喜歡的房間是陽光充足的客廳。"}]},{"word":"roommate","pos":"n.","phonetic":"[ˈrumˌmet]","meaning":"室友","definition":"a person who shares a room or apartment with another","collocations":["get along with a roommate","find a roommate"],"example":"My roommate and I share the cooking duties.","exampleZh":"我和室友一起分擔煮飯的工作。","synonyms":["flatmate"],"level":2,"theme":"人物與家庭","examples":[{"en":"My roommate and I share the cooking duties.","zh":"我和室友一起分擔煮飯的工作。"},{"en":"My roommate is quiet and always keeps our room clean.","zh":"我的室友很安靜，總是把我們的房間保持乾淨。"},{"en":"She gets along well with her new college roommate.","zh":"她和她的新大學室友相處得很好。"}]},{"word":"roomy","pos":"adj.","phonetic":"[ˈrumɪ]","meaning":"寬敞的","definition":"having plenty of space","collocations":["roomy car","roomy apartment"],"example":"Their new car has a roomy trunk.","exampleZh":"他們的新車有個寬敞的後車廂。","synonyms":["spacious"],"level":5,"theme":"居家與生活","examples":[{"en":"Their new car has a roomy trunk.","zh":"他們的新車有個寬敞的後車廂。"},{"en":"The apartment is small but the kitchen is quite roomy.","zh":"這間公寓不大，但廚房相當寬敞。"},{"en":"I like this backpack because it is light and roomy.","zh":"我喜歡這個背包，因為它既輕又寬敞。"}]},{"word":"roost","pos":"n. / v.","phonetic":"[rust]","meaning":"棲息處；棲息","definition":"a place where birds rest or sleep","collocations":["chicken roost","come home to roost"],"example":"The hens returned to their roost at sunset.","exampleZh":"母雞們在日落時回到棲息處。","synonyms":["perch"],"level":6,"theme":"動物與植物","examples":[{"en":"The hens returned to their roost at sunset.","zh":"母雞們在日落時回到棲息處。"},{"en":"At dusk, the birds fly back to their roost in the trees.","zh":"黃昏時，鳥兒飛回牠們在樹上的棲息處。"},{"en":"The hens settled down to roost as night fell.","zh":"夜幕降臨時，母雞們安頓下來準備棲息。"}]},{"word":"rooster","pos":"n.","phonetic":"[ˈrustɚ]","meaning":"公雞","definition":"an adult male chicken","collocations":["rooster crows","farm rooster"],"example":"The rooster crows every morning at dawn.","exampleZh":"公雞每天黎明時分都會啼叫。","synonyms":["cock"],"level":2,"theme":"動物與植物","examples":[{"en":"The rooster crows every morning at dawn.","zh":"公雞每天黎明時分都會啼叫。"},{"en":"The loud rooster woke the whole farm before sunrise.","zh":"吵鬧的公雞在日出前叫醒了整座農場。"},{"en":"A colorful rooster strutted proudly around the yard.","zh":"一隻色彩鮮豔的公雞在院子裡神氣地踱步。"}]},{"word":"root","pos":"n. / v.","phonetic":"[rut]","meaning":"根；根源","definition":"the part of a plant below the ground; origin","collocations":["root cause","put down roots"],"example":"We need to find the root cause of the problem.","exampleZh":"我們需要找出問題的根本原因。","synonyms":["origin","source"],"level":3,"theme":"自然與環境","examples":[{"en":"We need to find the root cause of the problem.","zh":"我們需要找出問題的根本原因。"},{"en":"The tree's deep roots keep it steady in strong winds.","zh":"這棵樹深深的根讓它在強風中保持穩固。"},{"en":"Poor planning was the root cause of the project's failure.","zh":"計畫不周是這個專案失敗的根本原因。"}]},{"word":"rope","pos":"n.","phonetic":"[rop]","meaning":"繩索","definition":"a strong thick cord","collocations":["jump rope","tie a rope"],"example":"The sailors tied the boat with a thick rope.","exampleZh":"水手們用一條粗繩把船綁住。","synonyms":["cord"],"level":2,"theme":"居家與生活","examples":[{"en":"The sailors tied the boat with a thick rope.","zh":"水手們用一條粗繩把船綁住。"},{"en":"The children used a long rope to play jump rope.","zh":"孩子們用一條長繩玩跳繩。"},{"en":"He tied the tent to a tree with a strong rope.","zh":"他用一條堅固的繩子把帳篷綁在樹上。"}]},{"word":"rose","pos":"n.","phonetic":"[roz]","meaning":"玫瑰","definition":"a fragrant flower with thorny stems","collocations":["red rose","bunch of roses"],"example":"He gave her a bouquet of red roses.","exampleZh":"他送給她一束紅玫瑰。","synonyms":[],"level":1,"theme":"動物與植物","examples":[{"en":"He gave her a bouquet of red roses.","zh":"他送給她一束紅玫瑰。"},{"en":"A single red rose stood in a vase on the table.","zh":"一朵紅玫瑰插在桌上的花瓶裡。"},{"en":"The garden was full of roses in every color.","zh":"花園裡開滿了各種顏色的玫瑰。"}]},{"word":"rot","pos":"v. / n.","phonetic":"[rɑt]","meaning":"腐爛；腐朽","definition":"to decay or decompose","collocations":["tooth rot","rot away"],"example":"The fallen leaves began to rot on the ground.","exampleZh":"落葉開始在地上腐爛。","synonyms":["decay","decompose"],"level":4,"theme":"自然與環境","examples":[{"en":"The fallen leaves began to rot on the ground.","zh":"落葉開始在地上腐爛。"},{"en":"If you leave fruit in the sun, it will quickly rot.","zh":"如果把水果放在陽光下，它會很快腐爛。"},{"en":"The wooden fence began to rot after years of rain.","zh":"經過多年的雨水，木籬笆開始腐朽。"}]},{"word":"rotate","pos":"v.","phonetic":"[ˈrotet]","meaning":"旋轉；輪流","definition":"to turn around a central point","collocations":["rotate crops","rotate the tires"],"example":"The Earth rotates on its axis once a day.","exampleZh":"地球每天繞地軸自轉一圈。","synonyms":["revolve","spin"],"level":4,"theme":"科學與數學","examples":[{"en":"The Earth rotates on its axis once a day.","zh":"地球每天繞地軸自轉一圈。"},{"en":"The Earth rotates slowly, giving us day and night.","zh":"地球緩慢地自轉，帶給我們白天和黑夜。"},{"en":"The team members rotate the cleaning duties every week.","zh":"隊員們每週輪流負責清潔工作。"}]},{"word":"rotten","pos":"adj.","phonetic":"[ˈrɑtn̩]","meaning":"腐爛的；腐敗的","definition":"decayed and no longer fresh","collocations":["rotten egg","rotten wood"],"example":"The rotten egg gave off a terrible smell.","exampleZh":"那顆腐壞的雞蛋散發出可怕的臭味。","synonyms":["decayed","spoiled"],"level":3,"theme":"食物與烹飪","examples":[{"en":"The rotten egg gave off a terrible smell.","zh":"那顆腐壞的雞蛋散發出可怕的臭味。"},{"en":"She threw away the rotten apples at the bottom of the basket.","zh":"她把籃子底部腐爛的蘋果丟掉了。"},{"en":"A rotten smell came from the forgotten lunchbox.","zh":"被遺忘的便當盒散發出腐臭味。"}]},{"word":"rotund","pos":"adj.","phonetic":"[roˈtʌnd]","meaning":"圓胖的","definition":"round and plump","collocations":["rotund figure","rotund man"],"example":"The rotund man laughed heartily at the joke.","exampleZh":"那位圓胖的男子聽了這個笑話開懷大笑。","synonyms":["plump","chubby"],"level":6,"theme":"身體與健康","examples":[{"en":"The rotund man laughed heartily at the joke.","zh":"那位圓胖的男子聽了這個笑話開懷大笑。"},{"en":"The rotund chef smiled as he served the delicious soup.","zh":"圓胖的廚師笑著端上美味的湯。"},{"en":"A rotund little robin hopped across the snowy garden.","zh":"一隻圓胖的小知更鳥在雪白的花園裡跳來跳去。"}]},{"word":"rough","pos":"adj.","phonetic":"[rʌf]","meaning":"粗糙的；粗略的","definition":"having an uneven surface; not gentle","collocations":["rough surface","rough estimate"],"example":"The rough road made the ride uncomfortable.","exampleZh":"崎嶇的道路讓這趟車程很不舒服。","synonyms":["coarse","harsh"],"level":3,"theme":"性質與描述","examples":[{"en":"The rough road made the ride uncomfortable.","zh":"崎嶇的道路讓這趟車程很不舒服。"},{"en":"The cat's tongue felt rough against my hand.","zh":"貓的舌頭在我手上感覺很粗糙。"},{"en":"Can you give me a rough estimate of the total cost?","zh":"你能給我一個總費用的粗略估計嗎？"}]},{"word":"roughly","pos":"adv.","phonetic":"[ˈrʌflɪ]","meaning":"大約地；粗略地","definition":"approximately; in a rough manner","collocations":["roughly estimated","treated roughly"],"example":"The trip takes roughly three hours.","exampleZh":"這趟旅程大約需要三小時。","synonyms":["approximately","about"],"level":3,"theme":"時間與空間","examples":[{"en":"The trip takes roughly three hours.","zh":"這趟旅程大約需要三小時。"},{"en":"The stadium can hold roughly fifty thousand people.","zh":"這座體育場大約可容納五萬人。"},{"en":"Don't handle the puppy so roughly; be gentle with it.","zh":"別這麼粗魯地對待小狗，要溫柔一點。"}]},{"word":"round","pos":"adj. / n. / prep.","phonetic":"[raʊnd]","meaning":"圓的；一輪","definition":"shaped like a circle; a series or stage","collocations":["round table","round of applause"],"example":"They sat around a round table to discuss the plan.","exampleZh":"他們圍坐在一張圓桌旁討論計畫。","synonyms":["circular"],"level":2,"theme":"性質與描述","examples":[{"en":"They sat around a round table to discuss the plan.","zh":"他們圍坐在一張圓桌旁討論計畫。"},{"en":"The players sat in a round circle to discuss the rules.","zh":"球員們圍成一個圓圈討論規則。"},{"en":"Her joke earned a big round of applause from the audience.","zh":"她的笑話贏得了觀眾一陣熱烈的掌聲。"}]},{"word":"roundabout","pos":"adj. / n.","phonetic":"[ˈraʊndəˌbaʊt]","meaning":"迂迴的；圓環","definition":"indirect; a circular road junction","collocations":["roundabout way","traffic roundabout"],"example":"He explained it in a roundabout way.","exampleZh":"他用迂迴的方式解釋了這件事。","synonyms":["indirect"],"level":5,"theme":"交通與旅行","examples":[{"en":"He explained it in a roundabout way.","zh":"他用迂迴的方式解釋了這件事。"},{"en":"He answered my question in a roundabout way.","zh":"他以迂迴的方式回答了我的問題。"},{"en":"Drive carefully when you enter the busy roundabout.","zh":"進入繁忙的圓環時要小心駕駛。"}]},{"word":"route","pos":"n.","phonetic":"[rut]","meaning":"路線；路徑","definition":"a way or course taken to get somewhere","collocations":["bus route","take a different route"],"example":"We took a scenic route through the mountains.","exampleZh":"我們選了一條穿越山區的風景路線。","synonyms":["path","way"],"level":3,"theme":"交通與旅行","examples":[{"en":"We took a scenic route through the mountains.","zh":"我們選了一條穿越山區的風景路線。"},{"en":"The bus route passes right in front of our school.","zh":"這條公車路線正好經過我們學校門口。"},{"en":"We took a different route to avoid the traffic jam.","zh":"我們走了另一條路線以避開塞車。"}]},{"word":"routine","pos":"n. / adj.","phonetic":"[ruˈtin]","meaning":"例行公事；日常慣例","definition":"a regular way of doing things","collocations":["daily routine","routine checkup"],"example":"Exercise is part of my daily routine.","exampleZh":"運動是我日常生活的一部分。","synonyms":["habit","procedure"],"level":3,"theme":"居家與生活","examples":[{"en":"Exercise is part of my daily routine.","zh":"運動是我日常生活的一部分。"},{"en":"Brushing your teeth should be part of your morning routine.","zh":"刷牙應該是你晨間例行事務的一部分。"},{"en":"The doctor said the checkup was just a routine examination.","zh":"醫生說這次檢查只是例行檢查。"}]},{"word":"rove","pos":"v.","phonetic":"[rov]","meaning":"漫遊；流浪","definition":"to move about without a settled destination","collocations":["rove the countryside","rove freely"],"example":"The wolves rove across the vast wilderness.","exampleZh":"狼群在廣闊的荒野中四處遊蕩。","synonyms":["roam","wander"],"level":6,"theme":"動作與行為","examples":[{"en":"The wolves rove across the vast wilderness.","zh":"狼群在廣闊的荒野中四處遊蕩。"},{"en":"As a young man, he loved to rove from town to town.","zh":"年輕時，他喜歡從一個城鎮流浪到另一個城鎮。"},{"en":"The herd of buffalo rove across the open grassland.","zh":"水牛群在開闊的草原上漫遊。"}]},{"word":"row","pos":"n. / v.","phonetic":"[ro]","meaning":"排；划船","definition":"a line of things or people; to propel a boat with oars","collocations":["front row","row a boat"],"example":"We sat in the front row of the theater.","exampleZh":"我們坐在劇院的前排。","synonyms":["line","line up"],"level":2,"theme":"時間與空間","examples":[{"en":"We sat in the front row of the theater.","zh":"我們坐在劇院的前排。"},{"en":"We managed to get seats in the second row of the concert.","zh":"我們設法在音樂會第二排拿到了座位。"},{"en":"They took turns to row the small boat across the pond.","zh":"他們輪流划著小船橫渡池塘。"}]},{"word":"rowdy","pos":"adj.","phonetic":"[ˈraʊdɪ]","meaning":"喧鬧的；粗暴的","definition":"noisy and disorderly","collocations":["rowdy crowd","rowdy behavior"],"example":"Security removed the rowdy fans from the stadium.","exampleZh":"保全人員將喧鬧的球迷請出了體育場。","synonyms":["unruly","noisy"],"level":5,"theme":"性質與描述","examples":[{"en":"Security removed the rowdy fans from the stadium.","zh":"保全人員將喧鬧的球迷請出了體育場。"},{"en":"The teacher calmed down the rowdy students before class.","zh":"老師在上課前讓喧鬧的學生們安靜下來。"},{"en":"A rowdy crowd gathered outside the stadium after the match.","zh":"比賽後，一群喧鬧的人聚集在體育場外。"}]},{"word":"rowing","pos":"n.","phonetic":"[ˈroɪŋ]","meaning":"划船運動","definition":"the sport of propelling a boat with oars","collocations":["rowing team","go rowing"],"example":"The rowing team practices every morning on the river.","exampleZh":"划船隊每天早上都在河上練習。","synonyms":[],"level":4,"theme":"運動與休閒","examples":[{"en":"The rowing team practices every morning on the river.","zh":"划船隊每天早上都在河上練習。"},{"en":"Rowing is a great sport for building strong arms.","zh":"划船是鍛鍊強壯手臂的絕佳運動。"},{"en":"She joined the rowing club to stay fit and make friends.","zh":"她加入划船社以保持健康並結交朋友。"}]},{"word":"royal","pos":"adj.","phonetic":"[ˈrɔɪəl]","meaning":"皇家的；王室的","definition":"relating to a king or queen","collocations":["royal family","royal palace"],"example":"The royal family waved to the crowd.","exampleZh":"皇室成員向群眾揮手致意。","synonyms":["regal"],"level":3,"theme":"政治與法律","examples":[{"en":"The royal family waved to the crowd.","zh":"皇室成員向群眾揮手致意。"},{"en":"Tourists lined up to visit the grand royal palace.","zh":"遊客排隊參觀宏偉的皇家宮殿。"},{"en":"The royal family greeted the cheering crowd warmly.","zh":"王室成員親切地向歡呼的群眾致意。"}]},{"word":"royalty","pos":"n.","phonetic":"[ˈrɔɪəltɪ]","meaning":"王室成員；版稅","definition":"members of a royal family; a payment to an author","collocations":["pay royalty","visiting royalty"],"example":"The author earns royalty from every book sold.","exampleZh":"這位作者每賣出一本書就能獲得版稅。","synonyms":[],"level":5,"theme":"商業與金錢","examples":[{"en":"The author earns royalty from every book sold.","zh":"這位作者每賣出一本書就能獲得版稅。"},{"en":"The famous author earns royalty from every copy sold.","zh":"這位知名作家從賣出的每一本書中賺取版稅。"},{"en":"During the parade, people hoped to catch a glimpse of royalty.","zh":"遊行期間，人們希望能一睹王室成員的風采。"}]},{"word":"rub","pos":"v.","phonetic":"[rʌb]","meaning":"摩擦；擦拭","definition":"to move something back and forth against a surface","collocations":["rub your eyes","rub in cream"],"example":"She rubbed her eyes after waking up.","exampleZh":"她起床後揉了揉眼睛。","synonyms":["massage","scrub"],"level":2,"theme":"動作與行為","examples":[{"en":"She rubbed her eyes after waking up.","zh":"她起床後揉了揉眼睛。"},{"en":"He rubbed his cold hands together to keep warm.","zh":"他把冰冷的雙手互相摩擦以保暖。"},{"en":"Gently rub some cream on the dry skin twice a day.","zh":"每天兩次輕輕在乾燥的皮膚上塗抹一些乳液。"}]},{"word":"rubber","pos":"n. / adj.","phonetic":"[ˈrʌbɚ]","meaning":"橡膠","definition":"an elastic material made from tree sap or synthetic sources","collocations":["rubber band","rubber boots"],"example":"The tires are made of tough rubber.","exampleZh":"這些輪胎是用堅韌的橡膠製成的。","synonyms":[],"level":2,"theme":"科學與數學","examples":[{"en":"The tires are made of tough rubber.","zh":"這些輪胎是用堅韌的橡膠製成的。"},{"en":"She kept the papers together with a small rubber band.","zh":"她用一條小橡皮筋把文件綁在一起。"},{"en":"Wear rubber boots so your feet stay dry in the rain.","zh":"穿上橡膠靴，這樣下雨時你的腳才不會濕。"}]},{"word":"rubbish","pos":"n.","phonetic":"[ˈrʌbɪʃ]","meaning":"垃圾；廢話","definition":"waste material; nonsense","collocations":["rubbish bin","talk rubbish"],"example":"Please throw the rubbish in the bin.","exampleZh":"請把垃圾丟進垃圾桶。","synonyms":["garbage","trash"],"level":3,"theme":"居家與生活","examples":[{"en":"Please throw the rubbish in the bin.","zh":"請把垃圾丟進垃圾桶。"},{"en":"Please put your rubbish in the bin, not on the ground.","zh":"請把你的垃圾丟進垃圾桶，不要丟在地上。"},{"en":"Don't believe him; he is just talking rubbish.","zh":"別相信他，他只是在胡說八道。"}]},{"word":"ruby","pos":"n. / adj.","phonetic":"[ˈrubɪ]","meaning":"紅寶石","definition":"a red precious gemstone","collocations":["ruby ring","ruby red"],"example":"She wore a ring with a bright ruby.","exampleZh":"她戴著一枚鑲有亮紅寶石的戒指。","synonyms":[],"level":4,"theme":"商業與金錢","examples":[{"en":"She wore a ring with a bright ruby.","zh":"她戴著一枚鑲有亮紅寶石的戒指。"},{"en":"The queen's crown was decorated with a large ruby.","zh":"女王的皇冠上鑲著一顆大紅寶石。"},{"en":"Her ruby earrings sparkled under the bright lights.","zh":"她的紅寶石耳環在明亮的燈光下閃閃發光。"}]},{"word":"rudder","pos":"n.","phonetic":"[ˈrʌdɚ]","meaning":"舵","definition":"a flat piece used to steer a boat or aircraft","collocations":["steer with a rudder","broken rudder"],"example":"The sailor adjusted the rudder to change direction.","exampleZh":"這位水手調整了船舵以改變方向。","synonyms":[],"level":5,"theme":"交通與旅行","examples":[{"en":"The sailor adjusted the rudder to change direction.","zh":"這位水手調整了船舵以改變方向。"},{"en":"The captain turned the rudder to steer around the rocks.","zh":"船長轉動舵以繞過那些岩石。"},{"en":"Without a working rudder, the boat drifted off course.","zh":"沒有正常運作的舵，船就偏離了航道。"}]},{"word":"rude","pos":"adj.","phonetic":"[rud]","meaning":"粗魯的；無禮的","definition":"not polite; showing bad manners","collocations":["rude comment","rude behavior"],"example":"It's rude to interrupt someone while they're talking.","exampleZh":"打斷別人說話是很沒禮貌的。","synonyms":["impolite","discourteous"],"level":2,"theme":"性質與描述","examples":[{"en":"It's rude to interrupt someone while they're talking.","zh":"打斷別人說話是很沒禮貌的。"},{"en":"It is rude to talk loudly in a quiet library.","zh":"在安靜的圖書館裡大聲說話是不禮貌的。"},{"en":"He apologized for his rude comment during the meeting.","zh":"他為自己在會議上無禮的話道歉。"}]},{"word":"rudimentary","pos":"adj.","phonetic":"[ˌrudəˈmɛntərɪ]","meaning":"基本的；初步的","definition":"basic or undeveloped","collocations":["rudimentary knowledge","rudimentary skills"],"example":"He only has a rudimentary knowledge of French.","exampleZh":"他只有基礎的法語知識。","synonyms":["basic","elementary"],"level":6,"theme":"教育與學習","examples":[{"en":"He only has a rudimentary knowledge of French.","zh":"他只有基礎的法語知識。"},{"en":"She has only a rudimentary knowledge of computer coding.","zh":"她對電腦程式設計只有初步的認識。"},{"en":"The beginners learned the rudimentary skills of swimming.","zh":"初學者學習了游泳的基本技巧。"}]},{"word":"ruffle","pos":"v.","phonetic":"[ˈrʌfl̩]","meaning":"弄皺；使不安","definition":"to disturb the smoothness of; to upset","collocations":["ruffle feathers","ruffle someone's hair"],"example":"The wind ruffled her hair as she walked.","exampleZh":"風把她走路時的頭髮吹亂了。","synonyms":["disturb","tousle"],"level":6,"theme":"情緒與感受","examples":[{"en":"The wind ruffled her hair as she walked.","zh":"風把她走路時的頭髮吹亂了。"},{"en":"A gentle breeze ruffled the pages of her open book.","zh":"一陣微風吹亂了她攤開書本的書頁。"},{"en":"The rude remark ruffled the calm speaker for a moment.","zh":"那句無禮的話讓冷靜的演講者一時感到不安。"}]},{"word":"rug","pos":"n.","phonetic":"[rʌg]","meaning":"小地毯","definition":"a piece of thick fabric used as a floor covering","collocations":["sweep under the rug","wool rug"],"example":"A colorful rug covered the living room floor.","exampleZh":"一張色彩繽紛的地毯鋪在客廳地板上。","synonyms":["carpet"],"level":2,"theme":"居家與生活","examples":[{"en":"A colorful rug covered the living room floor.","zh":"一張色彩繽紛的地毯鋪在客廳地板上。"},{"en":"A soft wool rug lay in front of the fireplace.","zh":"一塊柔軟的羊毛地毯鋪在壁爐前。"},{"en":"Don't sweep your problems under the rug and ignore them.","zh":"別把你的問題掩蓋起來、視而不見。"}]},{"word":"rugby","pos":"n.","phonetic":"[ˈrʌgbɪ]","meaning":"橄欖球","definition":"a team sport played with an oval ball","collocations":["play rugby","rugby team"],"example":"He joined the school rugby team this year.","exampleZh":"他今年加入了學校的橄欖球隊。","synonyms":[],"level":3,"theme":"運動與休閒","examples":[{"en":"He joined the school rugby team this year.","zh":"他今年加入了學校的橄欖球隊。"},{"en":"They played rugby in the muddy field all afternoon.","zh":"他們整個下午在泥濘的球場上打橄欖球。"},{"en":"Our school rugby team won the championship this year.","zh":"我們學校的橄欖球隊今年贏得了冠軍。"}]},{"word":"rugged","pos":"adj.","phonetic":"[ˈrʌgɪd]","meaning":"崎嶇的；堅固的","definition":"having a rough, uneven surface; sturdy","collocations":["rugged terrain","rugged design"],"example":"The hikers crossed the rugged mountain terrain.","exampleZh":"登山客們穿越了崎嶇的山區地形。","synonyms":["rough","sturdy"],"level":5,"theme":"自然與環境","examples":[{"en":"The hikers crossed the rugged mountain terrain.","zh":"登山客們穿越了崎嶇的山區地形。"},{"en":"The hikers climbed slowly over the rugged mountain path.","zh":"登山者緩慢地攀越崎嶇的山路。"},{"en":"This camera has a rugged body that survives rough trips.","zh":"這台相機有堅固的機身，能承受艱難的旅程。"}]},{"word":"ruin","pos":"v. / n.","phonetic":"[ˈruɪn]","meaning":"毀壞；廢墟","definition":"to destroy or severely damage","collocations":["ruin a plan","ancient ruins"],"example":"The heavy rain ruined our picnic plans.","exampleZh":"大雨毀了我們的野餐計畫。","synonyms":["destroy","wreck"],"level":3,"theme":"動作與行為","examples":[{"en":"The heavy rain ruined our picnic plans.","zh":"大雨毀了我們的野餐計畫。"},{"en":"A sudden storm ruined the outdoor wedding party.","zh":"一場突如其來的暴風雨毀了戶外婚禮派對。"},{"en":"Tourists explored the ancient ruins of the old temple.","zh":"遊客探索著古老寺廟的遺跡。"}]},{"word":"rule","pos":"n. / v.","phonetic":"[rul]","meaning":"規則；統治","definition":"a statement about what to do; to govern","collocations":["break a rule","rule a country"],"example":"Students must follow the school rules.","exampleZh":"學生必須遵守校規。","synonyms":["regulation","govern"],"level":1,"theme":"政治與法律","examples":[{"en":"Students must follow the school rules.","zh":"學生必須遵守校規。"},{"en":"Every player must follow the rules of the game.","zh":"每位球員都必須遵守遊戲規則。"},{"en":"The wise queen ruled the land for over thirty years.","zh":"這位睿智的女王統治這片土地超過三十年。"}]},{"word":"ruler","pos":"n.","phonetic":"[ˈrulɚ]","meaning":"統治者；尺","definition":"a person who governs; a measuring tool","collocations":["absolute ruler","wooden ruler"],"example":"The king was a wise and fair ruler.","exampleZh":"這位國王是個明智又公正的統治者。","synonyms":["leader","monarch"],"level":2,"theme":"政治與法律","examples":[{"en":"The king was a wise and fair ruler.","zh":"這位國王是個明智又公正的統治者。"},{"en":"The ancient ruler built many roads across his kingdom.","zh":"這位古代統治者在他的王國各處修建了許多道路。"},{"en":"Use a ruler to draw a straight line in your notebook.","zh":"用尺在你的筆記本上畫一條直線。"}]},{"word":"rum","pos":"n.","phonetic":"[rʌm]","meaning":"蘭姆酒","definition":"an alcoholic drink made from sugar cane","collocations":["rum and coke","dark rum"],"example":"The recipe calls for a splash of rum.","exampleZh":"這份食譜需要加一點蘭姆酒。","synonyms":[],"level":5,"theme":"食物與烹飪","examples":[{"en":"The recipe calls for a splash of rum.","zh":"這份食譜需要加一點蘭姆酒。"},{"en":"The chef added a little rum to flavor the fruitcake.","zh":"廚師加了一點蘭姆酒為水果蛋糕增添風味。"},{"en":"Sailors of the past often drank rum on long voyages.","zh":"過去的水手在長途航行中常喝蘭姆酒。"}]},{"word":"rumble","pos":"v. / n.","phonetic":"[ˈrʌmbl̩]","meaning":"隆隆作響","definition":"to make a deep heavy continuous sound","collocations":["thunder rumbles","stomach rumbles"],"example":"Thunder rumbled in the distance before the storm.","exampleZh":"暴風雨來臨前遠處傳來隆隆雷聲。","synonyms":["growl","roar"],"level":5,"theme":"天氣與季節","examples":[{"en":"Thunder rumbled in the distance before the storm.","zh":"暴風雨來臨前遠處傳來隆隆雷聲。"},{"en":"His empty stomach rumbled loudly during the quiet class.","zh":"在安靜的課堂上，他空空的肚子大聲咕嚕作響。"},{"en":"The heavy trucks made the old bridge rumble.","zh":"沉重的卡車讓老橋隆隆作響。"}]},{"word":"rumor","pos":"n.","phonetic":"[ˈrumɚ]","meaning":"謠言；傳聞","definition":"unverified information spread among people","collocations":["spread a rumor","hear a rumor"],"example":"There's a rumor that the school will close early.","exampleZh":"有謠言說學校會提早放學。","synonyms":["gossip","hearsay"],"level":4,"theme":"溝通與語言","examples":[{"en":"There's a rumor that the school will close early.","zh":"有謠言說學校會提早放學。"},{"en":"Don't spread a rumor unless you know it is true.","zh":"除非你確定是真的，否則別散播謠言。"},{"en":"I heard a rumor that our teacher is getting married.","zh":"我聽到一個傳聞說我們老師要結婚了。"}]},{"word":"run","pos":"v. / n.","phonetic":"[rʌn]","meaning":"跑；經營","definition":"to move quickly on foot; to manage","collocations":["run a business","go for a run"],"example":"She runs five kilometers every morning.","exampleZh":"她每天早上跑五公里。","synonyms":["sprint","operate"],"level":1,"theme":"運動與休閒","examples":[{"en":"She runs five kilometers every morning.","zh":"她每天早上跑五公里。"},{"en":"My parents run a small bakery in our neighborhood.","zh":"我父母在我們社區經營一家小麵包店。"},{"en":"He goes for a run in the park every morning.","zh":"他每天早上到公園跑步。"}]},{"word":"runaway","pos":"n. / adj.","phonetic":"[ˈrʌnəˌwe]","meaning":"逃跑者；失控的","definition":"a person who has fled; out of control","collocations":["runaway train","runaway success"],"example":"The movie became a runaway success at the box office.","exampleZh":"這部電影在票房上取得了驚人的成功。","synonyms":["fugitive"],"level":5,"theme":"抽象概念","examples":[{"en":"The movie became a runaway success at the box office.","zh":"這部電影在票房上取得了驚人的成功。"},{"en":"The police searched the city for the young runaway.","zh":"警方在城裡搜尋那名年輕的離家出走者。"},{"en":"Her first novel became a runaway success overnight.","zh":"她的第一本小說一夜之間成為爆紅的暢銷書。"}]},{"word":"runner","pos":"n.","phonetic":"[ˈrʌnɚ]","meaning":"跑步者","definition":"a person who runs, especially in a race","collocations":["marathon runner","fast runner"],"example":"The runner crossed the finish line first.","exampleZh":"這位跑者第一個衝過終點線。","synonyms":["sprinter","jogger"],"level":2,"theme":"運動與休閒","examples":[{"en":"The runner crossed the finish line first.","zh":"這位跑者第一個衝過終點線。"},{"en":"The marathon runner trained hard for many months.","zh":"這位馬拉松跑者辛苦訓練了好幾個月。"},{"en":"The fastest runner in our class won the school race.","zh":"我們班跑得最快的人贏得了校內賽跑。"}]},{"word":"runny","pos":"adj.","phonetic":"[ˈrʌnɪ]","meaning":"流鼻涕的；稀的","definition":"liquid or flowing more than usual","collocations":["runny nose","runny egg"],"example":"She had a runny nose because of her cold.","exampleZh":"她因為感冒而流鼻涕。","synonyms":[],"level":3,"theme":"身體與健康","examples":[{"en":"She had a runny nose because of her cold.","zh":"她因為感冒而流鼻涕。"},{"en":"The cold weather left him with a runny nose all week.","zh":"寒冷的天氣讓他整個星期都流鼻涕。"},{"en":"I like my breakfast eggs a little runny in the middle.","zh":"我喜歡我的早餐蛋中間帶點半熟流動的口感。"}]},{"word":"runway","pos":"n.","phonetic":"[ˈrʌnˌwe]","meaning":"跑道","definition":"a strip where aircraft take off and land","collocations":["airport runway","fashion runway"],"example":"The plane sped down the runway before takeoff.","exampleZh":"飛機起飛前在跑道上加速滑行。","synonyms":[],"level":3,"theme":"交通與旅行","examples":[{"en":"The plane sped down the runway before takeoff.","zh":"飛機起飛前在跑道上加速滑行。"},{"en":"The plane raced down the runway and lifted into the air.","zh":"飛機在跑道上疾駛，然後騰空而起。"},{"en":"The pilot waited for permission to land on the runway.","zh":"飛行員等待著在跑道上降落的許可。"}]},{"word":"rural","pos":"adj.","phonetic":"[ˈrʊrəl]","meaning":"鄉村的","definition":"relating to the countryside","collocations":["rural area","rural life"],"example":"They moved to a rural area to enjoy a quiet life.","exampleZh":"他們搬到鄉村地區享受寧靜的生活。","synonyms":["countryside","agricultural"],"level":4,"theme":"居家與生活","examples":[{"en":"They moved to a rural area to enjoy a quiet life.","zh":"他們搬到鄉村地區享受寧靜的生活。"},{"en":"Life in a rural village is slower and much quieter.","zh":"鄉村生活步調較慢，也安靜得多。"},{"en":"Many young people leave rural areas to find city jobs.","zh":"許多年輕人離開鄉村地區到城市找工作。"}]},{"word":"rush","pos":"v. / n.","phonetic":"[rʌʃ]","meaning":"匆忙；衝","definition":"to move or act with urgent speed","collocations":["rush hour","rush to finish"],"example":"Don't rush; we still have plenty of time.","exampleZh":"別急,我們還有充裕的時間。","synonyms":["hurry","hasten"],"level":3,"theme":"動作與行為","examples":[{"en":"Don't rush; we still have plenty of time.","zh":"別急,我們還有充裕的時間。"},{"en":"Don't rush your homework, or you will make careless mistakes.","zh":"別急著趕作業，否則你會犯粗心的錯誤。"},{"en":"Commuters filled the station during the morning rush hour.","zh":"早晨尖峰時段，通勤者擠滿了車站。"}]},{"word":"rust","pos":"n. / v.","phonetic":"[rʌst]","meaning":"生鏽","definition":"a reddish coating formed on iron exposed to moisture","collocations":["rust away","prevent rust"],"example":"The old bicycle was covered in rust.","exampleZh":"那輛舊腳踏車佈滿了鐵鏽。","synonyms":["corrosion"],"level":4,"theme":"科學與數學","examples":[{"en":"The old bicycle was covered in rust.","zh":"那輛舊腳踏車佈滿了鐵鏽。"},{"en":"Paint the metal gate to protect it from rust.","zh":"把金屬大門漆一漆，以防止生鏽。"},{"en":"The garden tools were covered in rust after the rainy season.","zh":"雨季過後，園藝工具都生鏽了。"}]},{"word":"rustic","pos":"adj.","phonetic":"[ˈrʌstɪk]","meaning":"鄉村風格的；質樸的","definition":"simple and typical of the countryside","collocations":["rustic charm","rustic furniture"],"example":"The cabin had a rustic charm that visitors loved.","exampleZh":"那間小木屋有著遊客喜愛的鄉村風情。","synonyms":["rural","simple"],"level":6,"theme":"居家與生活","examples":[{"en":"The cabin had a rustic charm that visitors loved.","zh":"那間小木屋有著遊客喜愛的鄉村風情。"},{"en":"The little café has a warm, rustic charm.","zh":"這家小咖啡館有著溫暖質樸的魅力。"},{"en":"They decorated the room with simple rustic furniture.","zh":"他們用簡單的鄉村風家具佈置這個房間。"}]},{"word":"rusty","pos":"adj.","phonetic":"[ˈrʌstɪ]","meaning":"生鏽的；荒疏的","definition":"covered with rust; out of practice","collocations":["rusty gate","rusty skills"],"example":"My French is a little rusty since I haven't practiced.","exampleZh":"我的法語有點荒疏了,因為我沒有練習。","synonyms":["corroded"],"level":3,"theme":"性質與描述","examples":[{"en":"My French is a little rusty since I haven't practiced.","zh":"我的法語有點荒疏了,因為我沒有練習。"},{"en":"He struggled to open the rusty gate in the backyard.","zh":"他費力地想打開後院那扇生鏽的門。"},{"en":"My swimming skills are a little rusty after the long break.","zh":"長時間沒練，我的游泳技巧有點荒疏了。"}]},{"word":"ruthless","pos":"adj.","phonetic":"[ˈruθlɪs]","meaning":"無情的；殘忍的","definition":"having no pity or compassion","collocations":["ruthless dictator","ruthless competition"],"example":"The company faced ruthless competition in the market.","exampleZh":"這家公司在市場上面臨無情的競爭。","synonyms":["merciless","cruel"],"level":6,"theme":"性質與描述","examples":[{"en":"The company faced ruthless competition in the market.","zh":"這家公司在市場上面臨無情的競爭。"},{"en":"The villain in the story is cold and ruthless.","zh":"故事裡的反派冷酷又無情。"},{"en":"Small shops struggle against ruthless competition from big stores.","zh":"小商店在大商店無情的競爭下艱難求生。"}]},{"word":"rye","pos":"n.","phonetic":"[raɪ]","meaning":"黑麥","definition":"a cereal grass used for bread and whiskey","collocations":["rye bread","rye whiskey"],"example":"She ordered a sandwich made with rye bread.","exampleZh":"她點了一份用黑麥麵包做的三明治。","synonyms":[],"level":5,"theme":"食物與烹飪","examples":[{"en":"She ordered a sandwich made with rye bread.","zh":"她點了一份用黑麥麵包做的三明治。"},{"en":"He prefers dark rye bread over plain white bread.","zh":"比起普通的白麵包，他更喜歡深色的黑麥麵包。"},{"en":"The farmer planted rye in the field this autumn.","zh":"農夫今年秋天在田裡種了黑麥。"}]},{"word":"sad","pos":"adj.","phonetic":"[sæd]","meaning":"難過的；悲傷的","definition":"feeling unhappy","collocations":["sad news","feel sad","sad story"],"example":"She felt sad when her dog died.","exampleZh":"她的狗死掉時她感到很難過。","synonyms":["unhappy","sorrowful"],"level":1,"theme":"情緒與感受","examples":[{"en":"She felt sad when her dog died.","zh":"她的狗死掉時她感到很難過。"},{"en":"She felt sad after saying goodbye to her best friend.","zh":"和最好的朋友道別後，她感到很難過。"},{"en":"The sad news of the accident spread through the town.","zh":"那起意外的悲傷消息傳遍了小鎮。"}]},{"word":"safe","pos":"adj.","phonetic":"[sef]","meaning":"安全的；平安的","definition":"free from danger or harm","collocations":["safe place","safe and sound","keep safe"],"example":"Please drive safe on the icy road.","exampleZh":"請在結冰的路上小心駕駛。","synonyms":["secure"],"level":1,"theme":"性質與描述","examples":[{"en":"Please drive safe on the icy road.","zh":"請在結冰的路上小心駕駛。"},{"en":"Keep your passport in a safe place while traveling.","zh":"旅行時把你的護照放在安全的地方。"},{"en":"The lost hikers returned home safe and sound.","zh":"迷路的登山者平安無事地回到了家。"}]},{"word":"safety","pos":"n.","phonetic":"[ˈsefti]","meaning":"安全","definition":"the state of being safe","collocations":["safety belt","road safety","for safety reasons"],"example":"Wear a helmet for your own safety.","exampleZh":"為了你自己的安全請戴安全帽。","synonyms":["security"],"level":2,"theme":"抽象概念","examples":[{"en":"Wear a helmet for your own safety.","zh":"為了你自己的安全請戴安全帽。"},{"en":"Always fasten your safety belt before the car moves.","zh":"在車子開動前一定要繫好安全帶。"},{"en":"The school held a class on fire safety last week.","zh":"學校上週上了一堂消防安全課。"}]},{"word":"sail","pos":"v. / n.","phonetic":"[sel]","meaning":"航行；風帆","definition":"to travel on water using a boat","collocations":["set sail","sail across","sail a boat"],"example":"The ship sailed across the Pacific Ocean.","exampleZh":"這艘船航行橫越太平洋。","synonyms":["cruise"],"level":3,"theme":"交通與旅行","examples":[{"en":"The ship sailed across the Pacific Ocean.","zh":"這艘船航行橫越太平洋。"},{"en":"The small boat set sail early in the morning.","zh":"那艘小船一大早就啟航了。"},{"en":"They watched the white sails move across the blue sea.","zh":"他們看著白色的帆在藍色海面上移動。"}]},{"word":"sailor","pos":"n.","phonetic":"[ˈselɚ]","meaning":"水手；船員","definition":"a person who works on a ship","collocations":["become a sailor","old sailor","sailor's uniform"],"example":"His father was a sailor in the navy.","exampleZh":"他父親曾是海軍的水手。","synonyms":["seaman"],"level":2,"theme":"工作與職業","examples":[{"en":"His father was a sailor in the navy.","zh":"他父親曾是海軍的水手。"},{"en":"The young sailor learned to tie many kinds of knots.","zh":"這位年輕的水手學會了打各種繩結。"},{"en":"The sailors worked together to steer the ship through the storm.","zh":"船員們齊心協力駕駛船隻穿過暴風雨。"}]},{"word":"salad","pos":"n.","phonetic":"[ˈsæləd]","meaning":"沙拉","definition":"a mixture of raw vegetables","collocations":["fruit salad","green salad","make a salad"],"example":"She ordered a salad for lunch.","exampleZh":"她午餐點了一份沙拉。","synonyms":[],"level":1,"theme":"食物與烹飪","examples":[{"en":"She ordered a salad for lunch.","zh":"她午餐點了一份沙拉。"},{"en":"She made a fresh green salad to go with the pasta.","zh":"她做了一份新鮮的綠色沙拉來搭配義大利麵。"},{"en":"A bowl of fruit salad is a healthy afternoon snack.","zh":"一碗水果沙拉是健康的午後點心。"}]},{"word":"salary","pos":"n.","phonetic":"[ˈsæləri]","meaning":"薪水","definition":"fixed regular payment for work","collocations":["monthly salary","high salary","salary increase"],"example":"He earns a good salary as an engineer.","exampleZh":"他當工程師領著不錯的薪水。","synonyms":["wage","pay"],"level":3,"theme":"商業與金錢","examples":[{"en":"He earns a good salary as an engineer.","zh":"他當工程師領著不錯的薪水。"},{"en":"His monthly salary is enough to support the whole family.","zh":"他的月薪足以養活全家。"},{"en":"The workers hoped for a salary increase next year.","zh":"工人們希望明年能加薪。"}]},{"word":"sale","pos":"n.","phonetic":"[sel]","meaning":"銷售；拍賣","definition":"the act of selling something","collocations":["for sale","on sale","sales figures"],"example":"The house is for sale.","exampleZh":"這棟房子正在出售。","synonyms":[],"level":2,"theme":"商業與金錢","examples":[{"en":"The house is for sale.","zh":"這棟房子正在出售。"},{"en":"The department store is having a big sale this weekend.","zh":"這家百貨公司這個週末有大特賣。"},{"en":"That house with the blue door is now for sale.","zh":"那棟有藍色門的房子現在要出售了。"}]},{"word":"salmon","pos":"n.","phonetic":"[ˈsæmən]","meaning":"鮭魚","definition":"a large edible fish","collocations":["smoked salmon","salmon fillet","grilled salmon"],"example":"We had grilled salmon for dinner.","exampleZh":"我們晚餐吃了烤鮭魚。","synonyms":[],"level":3,"theme":"食物與烹飪","examples":[{"en":"We had grilled salmon for dinner.","zh":"我們晚餐吃了烤鮭魚。"},{"en":"We enjoyed a plate of grilled salmon for dinner.","zh":"我們晚餐享用了一盤烤鮭魚。"},{"en":"Smoked salmon tastes delicious on a slice of toast.","zh":"煙燻鮭魚放在一片吐司上很美味。"}]},{"word":"salt","pos":"n.","phonetic":"[sɔlt]","meaning":"鹽","definition":"a white substance used to season food","collocations":["add salt","salt water","pass the salt"],"example":"Please pass me the salt.","exampleZh":"請把鹽遞給我。","synonyms":[],"level":1,"theme":"食物與烹飪","examples":[{"en":"Please pass me the salt.","zh":"請把鹽遞給我。"},{"en":"Add a pinch of salt to make the soup taste better.","zh":"加一小撮鹽讓湯更好喝。"},{"en":"Too much salt in your diet is bad for your health.","zh":"飲食中鹽分過多對你的健康有害。"}]},{"word":"salty","pos":"adj.","phonetic":"[ˈsɔlti]","meaning":"鹹的","definition":"tasting of salt","collocations":["salty food","too salty","salty snacks"],"example":"The soup is too salty for me.","exampleZh":"這湯對我來說太鹹了。","synonyms":[],"level":2,"theme":"食物與烹飪","examples":[{"en":"The soup is too salty for me.","zh":"這湯對我來說太鹹了。"},{"en":"These potato chips are so salty that I need more water.","zh":"這些洋芋片太鹹了，害我需要喝更多水。"},{"en":"I prefer salty snacks like crackers rather than sweet desserts.","zh":"比起甜點，我更喜歡餅乾之類的鹹味零食。"}]},{"word":"same","pos":"adj.","phonetic":"[sem]","meaning":"相同的","definition":"identical, not different","collocations":["the same time","same as","all the same"],"example":"We were born on the same day.","exampleZh":"我們在同一天出生。","synonyms":["identical"],"level":1,"theme":"性質與描述","examples":[{"en":"We were born on the same day.","zh":"我們在同一天出生。"},{"en":"My best friend and I take the same bus every morning.","zh":"我和我最好的朋友每天早上搭同一班公車。"},{"en":"Her answer was exactly the same as mine on the test.","zh":"考試中她的答案跟我的一模一樣。"}]},{"word":"sample","pos":"n. / v.","phonetic":"[ˈsæmpəl]","meaning":"樣本；試吃","definition":"a small part representing the whole","collocations":["free sample","sample size","take a sample"],"example":"You can try a free sample at the store.","exampleZh":"你可以在店裡試吃免費樣品。","synonyms":["example"],"level":3,"theme":"抽象概念","examples":[{"en":"You can try a free sample at the store.","zh":"你可以在店裡試吃免費樣品。"},{"en":"The teacher collected a water sample from the river for the experiment.","zh":"老師從河裡採集了一份水樣本用於實驗。"},{"en":"Shoppers lined up to sample the new flavor of ice cream.","zh":"顧客們排隊試吃新口味的冰淇淋。"}]},{"word":"sand","pos":"n.","phonetic":"[sænd]","meaning":"沙子","definition":"loose grains found on beaches or deserts","collocations":["grain of sand","sand castle","beach sand"],"example":"The children built castles in the sand.","exampleZh":"孩子們在沙地上堆城堡。","synonyms":[],"level":1,"theme":"自然與環境","examples":[{"en":"The children built castles in the sand.","zh":"孩子們在沙地上堆城堡。"},{"en":"We walked barefoot across the warm sand at the beach.","zh":"我們赤腳走過海灘上溫暖的沙子。"},{"en":"A single grain of sand got stuck inside my shoe.","zh":"一粒沙子卡在我的鞋子裡。"}]},{"word":"sandwich","pos":"n.","phonetic":"[ˈsænwɪtʃ]","meaning":"三明治","definition":"food consisting of fillings between slices of bread","collocations":["ham sandwich","make a sandwich"],"example":"She made a sandwich for lunch.","exampleZh":"她做了一個三明治當午餐。","synonyms":[],"level":1,"theme":"食物與烹飪","examples":[{"en":"She made a sandwich for lunch.","zh":"她做了一個三明治當午餐。"},{"en":"I usually eat a ham sandwich for lunch at school.","zh":"我在學校午餐通常吃火腿三明治。"},{"en":"Could you help me make a sandwich with cheese and tomato?","zh":"你可以幫我做一個夾起司和番茄的三明治嗎？"}]},{"word":"satellite","pos":"n.","phonetic":"[ˈsætḷˌaɪt]","meaning":"衛星","definition":"an object that orbits a planet","collocations":["satellite dish","launch a satellite"],"example":"The satellite orbits the Earth every 90 minutes.","exampleZh":"這顆衛星每90分鐘繞地球一圈。","synonyms":[],"level":4,"theme":"科學與數學","examples":[{"en":"The satellite orbits the Earth every 90 minutes.","zh":"這顆衛星每90分鐘繞地球一圈。"},{"en":"Scientists will launch a new satellite into space next month.","zh":"科學家下個月將發射一顆新衛星到太空。"},{"en":"We installed a satellite dish on the roof for better signals.","zh":"我們在屋頂裝了一個衛星接收器以獲得更好的訊號。"}]},{"word":"satisfaction","pos":"n.","phonetic":"[ˌsætɪsˈfækʃən]","meaning":"滿意","definition":"the feeling of being satisfied","collocations":["job satisfaction","to my satisfaction"],"example":"She smiled with satisfaction.","exampleZh":"她滿意地笑了。","synonyms":["content"],"level":4,"theme":"情緒與感受","examples":[{"en":"She smiled with satisfaction.","zh":"她滿意地笑了。"},{"en":"She finished the marathon with a deep sense of satisfaction.","zh":"她帶著深深的滿足感完成了馬拉松。"},{"en":"Good job satisfaction makes employees want to stay longer.","zh":"良好的工作滿意度讓員工願意待得更久。"}]},{"word":"satisfy","pos":"v.","phonetic":"[ˈsætɪsˌfaɪ]","meaning":"使滿意","definition":"to meet expectations or needs","collocations":["satisfy customers","hard to satisfy"],"example":"The meal satisfied everyone's hunger.","exampleZh":"這頓飯讓每個人都吃飽滿足。","synonyms":["please"],"level":3,"theme":"情緒與感受","examples":[{"en":"The meal satisfied everyone's hunger.","zh":"這頓飯讓每個人都吃飽滿足。"},{"en":"This small snack is not enough to satisfy my hunger.","zh":"這份小點心不足以滿足我的飢餓。"},{"en":"The company works hard to satisfy its loyal customers.","zh":"這家公司努力使忠實顧客滿意。"}]},{"word":"sauce","pos":"n.","phonetic":"[sɔs]","meaning":"醬汁","definition":"a liquid added to food to give flavor","collocations":["tomato sauce","soy sauce"],"example":"Add some soy sauce to the noodles.","exampleZh":"在麵裡加一些醬油。","synonyms":[],"level":2,"theme":"食物與烹飪","examples":[{"en":"Add some soy sauce to the noodles.","zh":"在麵裡加一些醬油。"},{"en":"She poured tomato sauce over the freshly cooked spaghetti.","zh":"她把番茄醬汁淋在剛煮好的義大利麵上。"},{"en":"Dip the dumplings in soy sauce before you eat them.","zh":"吃水餃前先沾一點醬油。"}]},{"word":"saucer","pos":"n.","phonetic":"[ˈsɔsɚ]","meaning":"茶托；茶碟","definition":"a small plate placed under a cup","collocations":["cup and saucer","flying saucer"],"example":"She placed the cup on a saucer.","exampleZh":"她把杯子放在茶碟上。","synonyms":[],"level":2,"theme":"居家與生活","examples":[{"en":"She placed the cup on a saucer.","zh":"她把杯子放在茶碟上。"},{"en":"She carefully placed the teacup on its matching saucer.","zh":"她小心地把茶杯放在配對的茶托上。"},{"en":"A little tea spilled onto the saucer under the cup.","zh":"一點茶灑到了杯子下面的茶碟上。"}]},{"word":"sausage","pos":"n.","phonetic":"[ˈsɔsɪdʒ]","meaning":"香腸","definition":"minced meat stuffed in a casing","collocations":["grill a sausage","sausage roll"],"example":"He grilled sausages for breakfast.","exampleZh":"他早餐烤了香腸。","synonyms":[],"level":2,"theme":"食物與烹飪","examples":[{"en":"He grilled sausages for breakfast.","zh":"他早餐烤了香腸。"},{"en":"We grilled several sausages over the fire during the camping trip.","zh":"露營時我們在火上烤了好幾條香腸。"},{"en":"He ordered a sausage roll and a cup of coffee.","zh":"他點了一個香腸捲和一杯咖啡。"}]},{"word":"save","pos":"v.","phonetic":"[sev]","meaning":"拯救；儲蓄","definition":"to rescue from danger or keep money for later","collocations":["save money","save time","save a life"],"example":"He saved money to buy a new bike.","exampleZh":"他存錢買了一台新腳踏車。","synonyms":["rescue"],"level":1,"theme":"動作與行為","examples":[{"en":"He saved money to buy a new bike.","zh":"他存錢買了一台新腳踏車。"},{"en":"The brave firefighter rushed in to save the trapped child.","zh":"勇敢的消防員衝進去拯救受困的孩子。"},{"en":"I try to save some money every month for college.","zh":"我試著每個月存一些錢念大學。"}]},{"word":"saving","pos":"n.","phonetic":"[ˈsevɪŋ]","meaning":"儲蓄","definition":"money saved for future use","collocations":["savings account","life savings"],"example":"She put her savings in the bank.","exampleZh":"她把積蓄存進銀行。","synonyms":[],"level":3,"theme":"商業與金錢","examples":[{"en":"She put her savings in the bank.","zh":"她把積蓄存進銀行。"},{"en":"He opened a savings account to keep his money safe.","zh":"他開了一個儲蓄帳戶來保管他的錢。"},{"en":"She spent her entire life savings on the new house.","zh":"她把畢生的儲蓄都花在新房子上。"}]},{"word":"saw","pos":"v. / n.","phonetic":"[sɔ]","meaning":"鋸；鋸子","definition":"a tool with a toothed blade for cutting wood","collocations":["saw wood","electric saw"],"example":"He used a saw to cut the log.","exampleZh":"他用鋸子鋸木頭。","synonyms":[],"level":2,"theme":"居家與生活","examples":[{"en":"He used a saw to cut the log.","zh":"他用鋸子鋸木頭。"},{"en":"My father used an electric saw to cut the wooden boards.","zh":"我父親用電鋸切割木板。"},{"en":"You must wear gloves when you saw thick branches.","zh":"鋸粗樹枝時你必須戴手套。"}]},{"word":"say","pos":"v.","phonetic":"[se]","meaning":"說","definition":"to speak words","collocations":["say hello","so to say","say sorry"],"example":"She said hello to everyone.","exampleZh":"她向大家問好。","synonyms":["speak","state"],"level":1,"theme":"溝通與語言","examples":[{"en":"She said hello to everyone.","zh":"她向大家問好。"},{"en":"Remember to say sorry when you hurt someone's feelings.","zh":"當你傷害別人的感受時，記得說對不起。"},{"en":"The teacher asked us to say hello to the new student.","zh":"老師要我們向新同學說哈囉。"}]},{"word":"scale","pos":"n.","phonetic":"[skel]","meaning":"規模；刻度；磅秤","definition":"the size or extent of something, or a device for weighing","collocations":["large scale","on a small scale","bathroom scale"],"example":"The project was carried out on a large scale.","exampleZh":"這項計畫是大規模進行的。","synonyms":["extent"],"level":4,"theme":"抽象概念","examples":[{"en":"The project was carried out on a large scale.","zh":"這項計畫是大規模進行的。"},{"en":"The company expanded its business on a much larger scale.","zh":"這家公司以更大的規模擴展業務。"},{"en":"She stepped on the bathroom scale to check her weight.","zh":"她踏上浴室磅秤量體重。"}]},{"word":"scan","pos":"v.","phonetic":"[skæn]","meaning":"掃描；瀏覽","definition":"to look at quickly or convert into digital data","collocations":["scan a document","scan the room"],"example":"He scanned the newspaper for job ads.","exampleZh":"他瀏覽報紙找工作廣告。","synonyms":["skim"],"level":3,"theme":"科技與媒體","examples":[{"en":"He scanned the newspaper for job ads.","zh":"他瀏覽報紙找工作廣告。"},{"en":"Please scan the document and email it to me.","zh":"請把文件掃描後用電子郵件寄給我。"},{"en":"He quickly scanned the room, looking for a familiar face.","zh":"他快速掃視房間，尋找熟悉的臉孔。"}]},{"word":"scarce","pos":"adj.","phonetic":"[skɛrs]","meaning":"稀少的","definition":"not enough of something; rare","collocations":["scarce resources","become scarce"],"example":"Fresh water is scarce in the desert.","exampleZh":"沙漠中的淡水很稀少。","synonyms":["rare","limited"],"level":5,"theme":"性質與描述","examples":[{"en":"Fresh water is scarce in the desert.","zh":"沙漠中的淡水很稀少。"},{"en":"Clean drinking water becomes scarce during the long dry season.","zh":"在漫長的乾季，乾淨的飲用水變得稀少。"},{"en":"Jobs were scarce in the small town after the factory closed.","zh":"工廠關閉後，這座小鎮的工作機會很稀少。"}]},{"word":"scarf","pos":"n.","phonetic":"[skɑrf]","meaning":"圍巾","definition":"a piece of cloth worn around the neck","collocations":["wool scarf","wear a scarf"],"example":"She wrapped a scarf around her neck.","exampleZh":"她把圍巾繞在脖子上。","synonyms":[],"level":2,"theme":"服裝與外表","examples":[{"en":"She wrapped a scarf around her neck.","zh":"她把圍巾繞在脖子上。"},{"en":"She knitted a warm wool scarf for her grandmother.","zh":"她為祖母織了一條溫暖的羊毛圍巾。"},{"en":"Don't forget to wear a scarf; it's freezing outside.","zh":"別忘了戴圍巾，外面冷得要命。"}]},{"word":"scary","pos":"adj.","phonetic":"[ˈskɛri]","meaning":"嚇人的","definition":"frightening","collocations":["scary movie","scary story"],"example":"The scary movie kept us awake all night.","exampleZh":"那部恐怖片讓我們整晚睡不著。","synonyms":["frightening"],"level":2,"theme":"情緒與感受","examples":[{"en":"The scary movie kept us awake all night.","zh":"那部恐怖片讓我們整晚睡不著。"},{"en":"My little brother refuses to watch scary movies at night.","zh":"我弟弟拒絕在晚上看恐怖電影。"},{"en":"She told us a scary story around the campfire.","zh":"她在營火旁跟我們說了一個嚇人的故事。"}]},{"word":"scatter","pos":"v.","phonetic":"[ˈskætɚ]","meaning":"散落；驅散","definition":"to spread widely over an area","collocations":["scatter seeds","scatter the crowd"],"example":"The wind scattered the leaves across the yard.","exampleZh":"風把樹葉吹散到院子各處。","synonyms":["spread"],"level":4,"theme":"動作與行為","examples":[{"en":"The wind scattered the leaves across the yard.","zh":"風把樹葉吹散到院子各處。"},{"en":"The farmer scattered seeds across the wide open field.","zh":"農夫把種子撒在寬廣的田野上。"},{"en":"Police arrived quickly to scatter the noisy crowd.","zh":"警察迅速趕到驅散吵鬧的人群。"}]},{"word":"scene","pos":"n.","phonetic":"[sin]","meaning":"場景；景象","definition":"a place where an event happens","collocations":["crime scene","behind the scenes"],"example":"Police arrived at the scene quickly.","exampleZh":"警方很快就抵達現場。","synonyms":["setting"],"level":3,"theme":"藝術與音樂","examples":[{"en":"Police arrived at the scene quickly.","zh":"警方很快就抵達現場。"},{"en":"Detectives carefully examined every detail at the crime scene.","zh":"偵探們仔細檢查犯罪現場的每個細節。"},{"en":"Many workers stay busy behind the scenes of the show.","zh":"許多工作人員在節目幕後忙碌著。"}]},{"word":"scenery","pos":"n.","phonetic":"[ˈsinəri]","meaning":"風景","definition":"the natural features of a landscape","collocations":["beautiful scenery","mountain scenery"],"example":"We enjoyed the beautiful scenery along the coast.","exampleZh":"我們欣賞著沿海美麗的風景。","synonyms":["landscape"],"level":4,"theme":"自然與環境","examples":[{"en":"We enjoyed the beautiful scenery along the coast.","zh":"我們欣賞著沿海美麗的風景。"},{"en":"The train ride offered stunning mountain scenery along the way.","zh":"沿途的火車之旅提供了令人驚豔的山景。"},{"en":"Tourists stopped to photograph the beautiful scenery of the valley.","zh":"遊客們停下來拍攝山谷的美麗風景。"}]},{"word":"schedule","pos":"n. / v.","phonetic":"[ˈskɛdʒʊl]","meaning":"時間表；排定","definition":"a plan of times for events","collocations":["busy schedule","ahead of schedule"],"example":"My schedule is full this week.","exampleZh":"我這週的行程排得很滿。","synonyms":["timetable"],"level":3,"theme":"時間與空間","examples":[{"en":"My schedule is full this week.","zh":"我這週的行程排得很滿。"},{"en":"My schedule is so busy that I barely have free time.","zh":"我的行程太滿，幾乎沒有空閒時間。"},{"en":"The train arrived ten minutes ahead of schedule today.","zh":"今天火車提早十分鐘進站。"}]},{"word":"scholar","pos":"n.","phonetic":"[ˈskɑlɚ]","meaning":"學者","definition":"a person who studies a subject deeply and thoroughly","collocations":["famous scholar","scholarly research"],"example":"The scholar spent years researching ancient history.","exampleZh":"這位學者花了數年研究古代歷史。","synonyms":[],"level":5,"theme":"教育與學習","examples":[{"en":"The scholar spent years researching ancient history.","zh":"這位學者花了數年研究古代歷史。"},{"en":"The famous scholar gave a lecture on ancient Chinese poetry.","zh":"這位著名學者做了一場關於中國古詩的演講。"},{"en":"Many scholars gathered to discuss the newly discovered documents.","zh":"許多學者聚集討論新發現的文件。"}]},{"word":"scholarship","pos":"n.","phonetic":"[ˈskɑlɚˌʃɪp]","meaning":"獎學金","definition":"money given to support a student's study","collocations":["win a scholarship","apply for a scholarship"],"example":"She won a scholarship to study abroad.","exampleZh":"她獲得了出國留學的獎學金。","synonyms":[],"level":4,"theme":"教育與學習","examples":[{"en":"She won a scholarship to study abroad.","zh":"她獲得了出國留學的獎學金。"},{"en":"She worked hard to win a scholarship for medical school.","zh":"她努力爭取到就讀醫學院的獎學金。"},{"en":"You should apply for a scholarship to reduce tuition costs.","zh":"你應該申請獎學金以減輕學費負擔。"}]},{"word":"school","pos":"n.","phonetic":"[skul]","meaning":"學校","definition":"a place for teaching and learning","collocations":["go to school","school uniform"],"example":"He goes to school by bus every day.","exampleZh":"他每天搭公車上學。","synonyms":[],"level":1,"theme":"教育與學習","examples":[{"en":"He goes to school by bus every day.","zh":"他每天搭公車上學。"},{"en":"Children in our neighborhood walk to school together every day.","zh":"我們社區的孩子每天一起走路上學。"},{"en":"Our school requires every student to wear a uniform.","zh":"我們學校要求每位學生穿制服。"}]},{"word":"science","pos":"n.","phonetic":"[ˈsaɪəns]","meaning":"科學","definition":"the study of the natural world through observation and experiment","collocations":["science class","computer science"],"example":"She loves studying science and math.","exampleZh":"她喜歡研讀科學和數學。","synonyms":[],"level":2,"theme":"科學與數學","examples":[{"en":"She loves studying science and math.","zh":"她喜歡研讀科學和數學。"},{"en":"Our science class did an exciting experiment about electricity today.","zh":"我們的科學課今天做了一個關於電的有趣實驗。"},{"en":"He plans to study computer science at university next year.","zh":"他打算明年在大學讀資訊科學。"}]},{"word":"scientist","pos":"n.","phonetic":"[ˈsaɪəntɪst]","meaning":"科學家","definition":"a person who studies or works in science","collocations":["become a scientist","famous scientist"],"example":"The scientist discovered a new element.","exampleZh":"這位科學家發現了一種新元素。","synonyms":[],"level":2,"theme":"工作與職業","examples":[{"en":"The scientist discovered a new element.","zh":"這位科學家發現了一種新元素。"},{"en":"The scientist spent years studying how plants absorb sunlight.","zh":"這位科學家花了多年研究植物如何吸收陽光。"},{"en":"She dreams of becoming a scientist who explores outer space.","zh":"她夢想成為一名探索外太空的科學家。"}]},{"word":"scissors","pos":"n.","phonetic":"[ˈsɪzɚz]","meaning":"剪刀","definition":"a tool with two blades used for cutting","collocations":["pair of scissors","use scissors"],"example":"Use the scissors to cut the paper.","exampleZh":"用剪刀剪紙。","synonyms":[],"level":1,"theme":"居家與生活","examples":[{"en":"Use the scissors to cut the paper.","zh":"用剪刀剪紙。"},{"en":"Please pass me the scissors so I can cut this ribbon.","zh":"請把剪刀遞給我，我好剪這條緞帶。"},{"en":"Always keep a pair of scissors in the drawer for emergencies.","zh":"隨時在抽屜裡放一把剪刀以備不時之需。"}]},{"word":"scold","pos":"v.","phonetic":"[skold]","meaning":"責罵","definition":"to criticize someone angrily","collocations":["scold a child","get scolded"],"example":"The teacher scolded him for being late.","exampleZh":"老師因為他遲到而責罵他。","synonyms":["reprimand"],"level":4,"theme":"溝通與語言","examples":[{"en":"The teacher scolded him for being late.","zh":"老師因為他遲到而責罵他。"},{"en":"His mother scolded him for coming home so late.","zh":"他母親因為他這麼晚回家而責罵他。"},{"en":"No one likes to get scolded in front of classmates.","zh":"沒有人喜歡在同學面前被責罵。"}]},{"word":"scope","pos":"n.","phonetic":"[skop]","meaning":"範圍","definition":"the range covered by a subject or activity","collocations":["beyond the scope","wide scope"],"example":"This topic is beyond the scope of our discussion.","exampleZh":"這個議題超出我們討論的範圍。","synonyms":["range"],"level":5,"theme":"抽象概念","examples":[{"en":"This topic is beyond the scope of our discussion.","zh":"這個議題超出我們討論的範圍。"},{"en":"That question lies beyond the scope of today's lesson.","zh":"那個問題超出了今天課程的範圍。"},{"en":"The new project has a very wide scope of research.","zh":"這個新專案有非常廣泛的研究範圍。"}]},{"word":"score","pos":"n. / v.","phonetic":"[skor]","meaning":"得分；分數","definition":"the number of points made in a game or test","collocations":["final score","score a goal"],"example":"He scored the winning goal in the last minute.","exampleZh":"他在最後一分鐘踢進致勝的一球。","synonyms":[],"level":2,"theme":"運動與休閒","examples":[{"en":"He scored the winning goal in the last minute.","zh":"他在最後一分鐘踢進致勝的一球。"},{"en":"The final score of the basketball game was very close.","zh":"這場籃球賽的最終比分非常接近。"},{"en":"She managed to score a goal in the last minute.","zh":"她在最後一分鐘成功進了一球。"}]},{"word":"scout","pos":"n. / v.","phonetic":"[skaʊt]","meaning":"童子軍；偵察","definition":"a person sent to gather information, or to search for talent","collocations":["boy scout","scout for talent"],"example":"The coach scouted for new players.","exampleZh":"教練四處物色新球員。","synonyms":[],"level":4,"theme":"其他","examples":[{"en":"The coach scouted for new players.","zh":"教練四處物色新球員。"},{"en":"As a boy scout, he learned how to build a fire.","zh":"身為童子軍，他學會了如何生火。"},{"en":"The team sent someone to scout for talented young players.","zh":"球隊派人去物色有天賦的年輕球員。"}]},{"word":"scramble","pos":"v.","phonetic":"[ˈskræmbəl]","meaning":"爭搶；攀爬","definition":"to move hurriedly or climb using hands and feet","collocations":["scramble up","scrambled eggs"],"example":"They scrambled to find seats before the show.","exampleZh":"他們趕忙在表演前找座位。","synonyms":["hurry"],"level":5,"theme":"動作與行為","examples":[{"en":"They scrambled to find seats before the show.","zh":"他們趕忙在表演前找座位。"},{"en":"The hikers scrambled up the steep rocky slope carefully.","zh":"登山者小心地爬上陡峭的岩石斜坡。"},{"en":"Fans scrambled to grab tickets before they sold out.","zh":"歌迷們爭搶著在票賣光前買到票。"}]},{"word":"scratch","pos":"v. / n.","phonetic":"[skrætʃ]","meaning":"抓；刮痕","definition":"to rub or mark a surface with something sharp","collocations":["scratch an itch","from scratch"],"example":"The cat scratched the sofa.","exampleZh":"那隻貓抓壞了沙發。","synonyms":[],"level":3,"theme":"動作與行為","examples":[{"en":"The cat scratched the sofa.","zh":"那隻貓抓壞了沙發。"},{"en":"The kitten likes to scratch the back of the chair.","zh":"這隻小貓喜歡抓椅子的背面。"},{"en":"She decided to bake the cake from scratch herself.","zh":"她決定自己從頭開始烤這個蛋糕。"}]},{"word":"scream","pos":"v. / n.","phonetic":"[skrim]","meaning":"尖叫","definition":"to cry out loudly in fear, pain, or excitement","collocations":["scream in fear","let out a scream"],"example":"She screamed when she saw the spider.","exampleZh":"她看到蜘蛛時尖叫了一聲。","synonyms":["shriek","yell"],"level":2,"theme":"情緒與感受","examples":[{"en":"She screamed when she saw the spider.","zh":"她看到蜘蛛時尖叫了一聲。"},{"en":"The children screamed with joy on the roller coaster.","zh":"孩子們在雲霄飛車上開心地尖叫。"},{"en":"He let out a loud scream when the lights went off.","zh":"燈熄滅時他發出一聲大叫。"}]},{"word":"screen","pos":"n.","phonetic":"[skrin]","meaning":"螢幕","definition":"the flat surface of a display device","collocations":["computer screen","on screen"],"example":"Don't stare at the screen too long.","exampleZh":"不要盯著螢幕太久。","synonyms":[],"level":2,"theme":"科技與媒體","examples":[{"en":"Don't stare at the screen too long.","zh":"不要盯著螢幕太久。"},{"en":"Staring at a computer screen for hours hurts your eyes.","zh":"盯著電腦螢幕好幾個小時會傷害你的眼睛。"},{"en":"The words appeared clearly on the giant screen at the front.","zh":"文字清楚地出現在前方的大螢幕上。"}]},{"word":"script","pos":"n.","phonetic":"[skrɪpt]","meaning":"劇本；腳本","definition":"the written text of a play, film, or speech","collocations":["film script","follow the script"],"example":"The actors memorized the entire script.","exampleZh":"演員們把整個劇本都背下來了。","synonyms":[],"level":4,"theme":"藝術與音樂","examples":[{"en":"The actors memorized the entire script.","zh":"演員們把整個劇本都背下來了。"},{"en":"The young actor practiced his lines from the film script.","zh":"這位年輕演員練習電影劇本裡的台詞。"},{"en":"The host followed the script closely during the live show.","zh":"主持人在直播節目中緊跟著腳本。"}]},{"word":"sculpture","pos":"n.","phonetic":"[ˈskʌlptʃɚ]","meaning":"雕塑","definition":"a piece of art made by carving or shaping material","collocations":["stone sculpture","modern sculpture"],"example":"The museum displays ancient sculptures.","exampleZh":"這座博物館展示古代雕塑作品。","synonyms":["statue"],"level":5,"theme":"藝術與音樂","examples":[{"en":"The museum displays ancient sculptures.","zh":"這座博物館展示古代雕塑作品。"},{"en":"The artist carved a beautiful sculpture out of white marble.","zh":"這位藝術家用白色大理石雕刻出一件美麗的雕塑。"},{"en":"We admired the modern sculptures displayed in the park.","zh":"我們欣賞公園裡展示的現代雕塑。"}]},{"word":"sea","pos":"n.","phonetic":"[si]","meaning":"海","definition":"a large body of salt water","collocations":["by the sea","go to sea"],"example":"We spent our vacation by the sea.","exampleZh":"我們在海邊度過了假期。","synonyms":["ocean"],"level":1,"theme":"自然與環境","examples":[{"en":"We spent our vacation by the sea.","zh":"我們在海邊度過了假期。"},{"en":"They love to sail across the calm blue sea.","zh":"他們喜歡航行在平靜的藍色大海上。"},{"en":"Our little cottage stands right by the sea.","zh":"我們的小屋就座落在海邊。"}]},{"word":"seal","pos":"n. / v.","phonetic":"[sil]","meaning":"海豹；密封","definition":"a marine mammal, or to close something tightly","collocations":["seal a letter","seal an envelope"],"example":"The seal swam gracefully in the water.","exampleZh":"海豹優雅地在水中游動。","synonyms":[],"level":3,"theme":"動物與植物","examples":[{"en":"The seal swam gracefully in the water.","zh":"海豹優雅地在水中游動。"},{"en":"A playful seal popped its head out of the water.","zh":"一隻頑皮的海豹從水中探出頭來。"},{"en":"Please seal the envelope before you mail the letter.","zh":"寄信之前請把信封封好。"}]},{"word":"search","pos":"v. / n.","phonetic":"[sɝtʃ]","meaning":"搜尋","definition":"to look for something carefully","collocations":["search for","search engine"],"example":"Police searched the area for clues.","exampleZh":"警方在該地區搜尋線索。","synonyms":["look for"],"level":2,"theme":"動作與行為","examples":[{"en":"Police searched the area for clues.","zh":"警方在該地區搜尋線索。"},{"en":"We searched everywhere for the lost house keys.","zh":"我們到處尋找遺失的家門鑰匙。"},{"en":"You can use a search engine to find the answer.","zh":"你可以用搜尋引擎找到答案。"}]},{"word":"season","pos":"n.","phonetic":"[ˈsizən]","meaning":"季節","definition":"one of the four periods of the year","collocations":["rainy season","in season"],"example":"Summer is my favorite season.","exampleZh":"夏天是我最喜歡的季節。","synonyms":[],"level":1,"theme":"天氣與季節","examples":[{"en":"Summer is my favorite season.","zh":"夏天是我最喜歡的季節。"},{"en":"Mangoes are cheapest when they are in season.","zh":"芒果在盛產季節時最便宜。"},{"en":"The rainy season usually lasts from May to June here.","zh":"這裡的雨季通常從五月持續到六月。"}]},{"word":"seat","pos":"n.","phonetic":"[sit]","meaning":"座位","definition":"a place where one sits","collocations":["take a seat","window seat"],"example":"Please take a seat and wait.","exampleZh":"請坐下等候。","synonyms":[],"level":1,"theme":"居家與生活","examples":[{"en":"Please take a seat and wait.","zh":"請坐下等候。"},{"en":"Please take a seat while the doctor finishes his call.","zh":"醫生講完電話時請先就座。"},{"en":"I prefer a window seat when I travel by plane.","zh":"搭飛機旅行時我比較喜歡靠窗的座位。"}]},{"word":"second","pos":"n. / adj.","phonetic":"[ˈsɛkənd]","meaning":"第二；秒","definition":"next after first, or a unit of time","collocations":["second place","wait a second"],"example":"He finished the race in second place.","exampleZh":"他以第二名完成比賽。","synonyms":[],"level":1,"theme":"時間與空間","examples":[{"en":"He finished the race in second place.","zh":"他以第二名完成比賽。"},{"en":"Wait a second while I find my umbrella.","zh":"等一下，我找一下我的雨傘。"},{"en":"She proudly came in second place in the singing contest.","zh":"她在歌唱比賽中驕傲地獲得第二名。"}]},{"word":"secret","pos":"n. / adj.","phonetic":"[ˈsikrɪt]","meaning":"秘密的","definition":"something kept hidden from others","collocations":["keep a secret","secret code"],"example":"Can you keep a secret?","exampleZh":"你能保守秘密嗎？","synonyms":["private"],"level":2,"theme":"溝通與語言","examples":[{"en":"Can you keep a secret?","zh":"你能保守秘密嗎？"},{"en":"I promise I can keep a secret from everyone.","zh":"我保證我能對所有人保守秘密。"},{"en":"The children used a secret code to send messages.","zh":"孩子們用秘密暗號來傳遞訊息。"}]},{"word":"secretary","pos":"n.","phonetic":"[ˈsɛkrəˌtɛri]","meaning":"秘書","definition":"a person who assists with office and administrative work","collocations":["hire a secretary","personal secretary"],"example":"The secretary scheduled all his meetings.","exampleZh":"秘書安排了他所有的會議。","synonyms":[],"level":3,"theme":"工作與職業","examples":[{"en":"The secretary scheduled all his meetings.","zh":"秘書安排了他所有的會議。"},{"en":"The company decided to hire a new secretary this week.","zh":"公司這週決定聘請一位新秘書。"},{"en":"His personal secretary handles all his phone calls.","zh":"他的私人秘書處理他所有的電話。"}]},{"word":"section","pos":"n.","phonetic":"[ˈsɛkʃən]","meaning":"部分；區段","definition":"a distinct part of something","collocations":["a section of","sports section"],"example":"Please read the first section of the report.","exampleZh":"請閱讀報告的第一部分。","synonyms":["part"],"level":3,"theme":"抽象概念","examples":[{"en":"Please read the first section of the report.","zh":"請閱讀報告的第一部分。"},{"en":"Please read the first section of the chapter tonight.","zh":"今晚請閱讀本章的第一部分。"},{"en":"He always turns to the sports section of the newspaper.","zh":"他總是翻到報紙的體育版。"}]},{"word":"secure","pos":"adj. / v.","phonetic":"[sɪˈkjʊr]","meaning":"安全的；確保","definition":"free from danger, or to obtain firmly","collocations":["secure a job","feel secure"],"example":"He worked hard to secure a stable job.","exampleZh":"他努力工作以確保一份穩定的工作。","synonyms":["safe"],"level":4,"theme":"性質與描述","examples":[{"en":"He worked hard to secure a stable job.","zh":"他努力工作以確保一份穩定的工作。"},{"en":"After graduation, he hoped to secure a stable job.","zh":"畢業後，他希望能找到一份穩定的工作。"},{"en":"The children feel secure when their parents are nearby.","zh":"父母在身邊時孩子們感到安心。"}]},{"word":"security","pos":"n.","phonetic":"[sɪˈkjʊrəti]","meaning":"安全；保全","definition":"protection from danger or threat","collocations":["national security","security guard"],"example":"The airport has tight security.","exampleZh":"機場的安檢非常嚴密。","synonyms":["safety"],"level":3,"theme":"社會與文化","examples":[{"en":"The airport has tight security.","zh":"機場的安檢非常嚴密。"},{"en":"The airport increased its security before the busy holiday.","zh":"機場在繁忙的假期前加強了安全措施。"},{"en":"A security guard checks every visitor at the front gate.","zh":"一名保全人員在大門口檢查每位訪客。"}]},{"word":"seed","pos":"n.","phonetic":"[sid]","meaning":"種子","definition":"the part of a plant from which a new plant grows","collocations":["plant a seed","seed packet"],"example":"She planted a seed in the garden.","exampleZh":"她在花園裡種下一顆種子。","synonyms":[],"level":2,"theme":"動物與植物","examples":[{"en":"She planted a seed in the garden.","zh":"她在花園裡種下一顆種子。"},{"en":"She planted a few sunflower seeds in the backyard.","zh":"她在後院種了幾顆向日葵種子。"},{"en":"Water the seeds daily and they will grow quickly.","zh":"每天給種子澆水，它們就會長得很快。"}]},{"word":"seek","pos":"v.","phonetic":"[sik]","meaning":"尋求","definition":"to try to find or obtain something","collocations":["seek help","seek advice"],"example":"He sought help from his teacher.","exampleZh":"他向老師尋求協助。","synonyms":["search for"],"level":4,"theme":"動作與行為","examples":[{"en":"He sought help from his teacher.","zh":"他向老師尋求協助。"},{"en":"Students should seek help when they don't understand the lesson.","zh":"學生在不懂課程時應該尋求協助。"},{"en":"She decided to seek advice from an experienced teacher.","zh":"她決定向一位經驗豐富的老師尋求建議。"}]},{"word":"seem","pos":"v.","phonetic":"[sim]","meaning":"似乎","definition":"to give the impression of being something","collocations":["seem to be","it seems that"],"example":"She seems happy today.","exampleZh":"她今天似乎很開心。","synonyms":["appear"],"level":1,"theme":"抽象概念","examples":[{"en":"She seems happy today.","zh":"她今天似乎很開心。"},{"en":"The new student seems a little nervous on his first day.","zh":"這位新學生在第一天似乎有點緊張。"},{"en":"It seems that the rain will continue all afternoon.","zh":"看來雨會持續整個下午。"}]},{"word":"seize","pos":"v.","phonetic":"[siz]","meaning":"抓住；奪取","definition":"to take hold of something suddenly and firmly","collocations":["seize an opportunity","seize power"],"example":"He seized the chance to speak.","exampleZh":"他抓住機會發言。","synonyms":["grab"],"level":5,"theme":"動作與行為","examples":[{"en":"He seized the chance to speak.","zh":"他抓住機會發言。"},{"en":"You should seize this rare opportunity to study abroad.","zh":"你應該抓住這個難得的機會出國留學。"},{"en":"The guard seized the thief before he could escape.","zh":"警衛在小偷逃跑前抓住了他。"}]},{"word":"select","pos":"v. / adj.","phonetic":"[sɪˈlɛkt]","meaning":"挑選；精選的","definition":"to choose carefully from a group","collocations":["select a color","select group"],"example":"Please select your favorite dish.","exampleZh":"請選擇你最喜歡的菜。","synonyms":["choose"],"level":3,"theme":"動作與行為","examples":[{"en":"Please select your favorite dish.","zh":"請選擇你最喜歡的菜。"},{"en":"Please select the color you like best for your bedroom.","zh":"請挑選你最喜歡的臥室顏色。"},{"en":"Only a select group of students joined the special program.","zh":"只有一小群精選的學生加入了這個特別計畫。"}]},{"word":"self","pos":"n.","phonetic":"[sɛlf]","meaning":"自我","definition":"a person's own individual nature or identity","collocations":["sense of self","self-control"],"example":"He needs to develop a stronger sense of self.","exampleZh":"他需要培養更強的自我意識。","synonyms":[],"level":3,"theme":"抽象概念","examples":[{"en":"He needs to develop a stronger sense of self.","zh":"他需要培養更強的自我意識。"},{"en":"Learning a new skill can improve your sense of self.","zh":"學習新技能能提升你的自我意識。"},{"en":"Good self-control helps you resist eating too much candy.","zh":"良好的自我控制能幫助你抗拒吃太多糖果。"}]},{"word":"selfish","pos":"adj.","phonetic":"[ˈsɛlfɪʃ]","meaning":"自私的","definition":"caring only about oneself, not others","collocations":["selfish behavior","act selfish"],"example":"It's selfish to ignore others' feelings.","exampleZh":"忽視別人的感受是自私的。","synonyms":[],"level":3,"theme":"性質與描述","examples":[{"en":"It's selfish to ignore others' feelings.","zh":"忽視別人的感受是自私的。"},{"en":"It is selfish to keep all the snacks for yourself.","zh":"把所有零食都留給自己是很自私的。"},{"en":"His selfish behavior upset the whole team.","zh":"他自私的行為讓整個團隊很不高興。"}]},{"word":"sell","pos":"v.","phonetic":"[sɛl]","meaning":"賣","definition":"to exchange goods or services for money","collocations":["sell goods","sell out"],"example":"The shop sells fresh vegetables.","exampleZh":"這家店賣新鮮蔬菜。","synonyms":[],"level":1,"theme":"商業與金錢","examples":[{"en":"The shop sells fresh vegetables.","zh":"這家店賣新鮮蔬菜。"},{"en":"The bakery sells fresh bread early every morning.","zh":"這家麵包店每天一早就賣新鮮的麵包。"},{"en":"The concert tickets sold out within just a few minutes.","zh":"演唱會的票在短短幾分鐘內就賣光了。"}]},{"word":"semester","pos":"n.","phonetic":"[sɪˈmɛstɚ]","meaning":"學期","definition":"half of a school or university year","collocations":["fall semester","this semester"],"example":"She studied hard this semester.","exampleZh":"她這學期讀書很認真。","synonyms":[],"level":3,"theme":"教育與學習","examples":[{"en":"She studied hard this semester.","zh":"她這學期讀書很認真。"},{"en":"I plan to take a photography course next semester.","zh":"我打算下學期修一門攝影課。"},{"en":"The fall semester begins right after the summer holiday.","zh":"秋季學期在暑假結束後隨即開始。"}]},{"word":"senior","pos":"adj. / n.","phonetic":"[ˈsinjɚ]","meaning":"資深的；高年級生","definition":"older or higher in rank, or a final-year student","collocations":["senior citizen","senior year"],"example":"He is a senior at the university.","exampleZh":"他是大學的大四生。","synonyms":[],"level":4,"theme":"教育與學習","examples":[{"en":"He is a senior at the university.","zh":"他是大學的大四生。"},{"en":"As a senior, she gives advice to the younger students.","zh":"身為高年級生，她給學弟妹建議。"},{"en":"Special seats on the bus are reserved for senior citizens.","zh":"公車上的博愛座是保留給年長者的。"}]},{"word":"sense","pos":"n. / v.","phonetic":"[sɛns]","meaning":"感覺；意義","definition":"a feeling or the ability to perceive something","collocations":["make sense","sense of humor"],"example":"It doesn't make sense to me.","exampleZh":"這對我來說沒有道理。","synonyms":["feeling"],"level":2,"theme":"抽象概念","examples":[{"en":"It doesn't make sense to me.","zh":"這對我來說沒有道理。"},{"en":"His explanation finally started to make sense to me.","zh":"他的解釋終於開始讓我覺得有道理。"},{"en":"She has a great sense of humor that makes everyone laugh.","zh":"她很有幽默感，逗得大家哈哈大笑。"}]},{"word":"sensible","pos":"adj.","phonetic":"[ˈsɛnsəbəl]","meaning":"明智的","definition":"showing good judgment or reasoning","collocations":["sensible decision","sensible advice"],"example":"It was a sensible decision to save money.","exampleZh":"存錢是個明智的決定。","synonyms":["reasonable"],"level":4,"theme":"性質與描述","examples":[{"en":"It was a sensible decision to save money.","zh":"存錢是個明智的決定。"},{"en":"Saving part of your allowance is a sensible habit.","zh":"把一部分零用錢存起來是明智的習慣。"},{"en":"She gave me some sensible advice about my studies.","zh":"她給了我一些關於學業的明智建議。"}]},{"word":"sensitive","pos":"adj.","phonetic":"[ˈsɛnsətɪv]","meaning":"敏感的","definition":"easily affected, hurt, or offended","collocations":["sensitive skin","sensitive topic"],"example":"She is sensitive to criticism.","exampleZh":"她對批評很敏感。","synonyms":[],"level":4,"theme":"情緒與感受","examples":[{"en":"She is sensitive to criticism.","zh":"她對批評很敏感。"},{"en":"My skin is very sensitive to strong sunlight.","zh":"我的皮膚對強烈的陽光非常敏感。"},{"en":"Please be careful; this is a very sensitive topic for him.","zh":"請小心，這對他來說是個非常敏感的話題。"}]},{"word":"sentence","pos":"n.","phonetic":"[ˈsɛntəns]","meaning":"句子；判決","definition":"a group of words expressing a complete idea","collocations":["complete sentence","jail sentence"],"example":"Write a sentence using this word.","exampleZh":"用這個字造一個句子。","synonyms":[],"level":1,"theme":"溝通與語言","examples":[{"en":"Write a sentence using this word.","zh":"用這個字造一個句子。"},{"en":"Try to write a complete sentence using this new word.","zh":"試著用這個新單字寫一個完整的句子。"},{"en":"The judge gave the criminal a long jail sentence.","zh":"法官判了這名罪犯很長的刑期。"}]},{"word":"separate","pos":"v. / adj.","phonetic":"[ˈsɛpəˌret]","meaning":"分開的；使分開","definition":"to divide or set apart from each other","collocations":["separate rooms","separate from"],"example":"Please separate the trash from the recycling.","exampleZh":"請把垃圾和回收物分開。","synonyms":["divide"],"level":3,"theme":"動作與行為","examples":[{"en":"Please separate the trash from the recycling.","zh":"請把垃圾和回收物分開。"},{"en":"Please separate the plastic bottles from the paper for recycling.","zh":"請將塑膠瓶和紙分開回收。"},{"en":"The two brothers now live in separate apartments.","zh":"這兩兄弟現在住在不同的公寓裡。"}]},{"word":"series","pos":"n.","phonetic":"[ˈsɪriz]","meaning":"系列","definition":"a number of related things or events","collocations":["TV series","a series of events"],"example":"She is watching a new TV series.","exampleZh":"她正在看一部新的電視影集。","synonyms":[],"level":3,"theme":"科技與媒體","examples":[{"en":"She is watching a new TV series.","zh":"她正在看一部新的電視影集。"},{"en":"She stayed up late watching her favorite TV series.","zh":"她熬夜看她最愛的電視影集。"},{"en":"A series of small mistakes led to the big problem.","zh":"一連串的小錯誤導致了這個大問題。"}]},{"word":"serious","pos":"adj.","phonetic":"[ˈsɪriəs]","meaning":"嚴重的；認真的","definition":"important and needing careful attention","collocations":["serious problem","be serious about"],"example":"This is a serious matter that needs attention.","exampleZh":"這是一件需要關注的嚴重事情。","synonyms":["grave"],"level":2,"theme":"性質與描述","examples":[{"en":"This is a serious matter that needs attention.","zh":"這是一件需要關注的嚴重事情。"},{"en":"Air pollution is a serious problem in many big cities.","zh":"空氣污染在許多大城市是個嚴重的問題。"},{"en":"She is very serious about becoming a professional dancer.","zh":"她對成為職業舞者非常認真。"}]},{"word":"serve","pos":"v.","phonetic":"[sɝv]","meaning":"服務；供應","definition":"to provide help, food, or a service","collocations":["serve customers","serve food"],"example":"The waiter served us quickly.","exampleZh":"服務生很快地為我們服務。","synonyms":[],"level":2,"theme":"工作與職業","examples":[{"en":"The waiter served us quickly.","zh":"服務生很快地為我們服務。"},{"en":"This restaurant serves breakfast until eleven in the morning.","zh":"這家餐廳供應早餐到早上十一點。"},{"en":"The kind volunteers serve meals to homeless people daily.","zh":"善良的志工每天為無家可歸的人供餐。"}]},{"word":"service","pos":"n.","phonetic":"[ˈsɝvɪs]","meaning":"服務","definition":"the act of helping or providing for someone","collocations":["customer service","public service"],"example":"The hotel offers excellent service.","exampleZh":"這間飯店提供優質的服務。","synonyms":[],"level":2,"theme":"工作與職業","examples":[{"en":"The hotel offers excellent service.","zh":"這間飯店提供優質的服務。"},{"en":"The customer service at that store is friendly and fast.","zh":"那家店的客戶服務既友善又快速。"},{"en":"Many young people join public service to help their community.","zh":"許多年輕人加入公共服務來幫助他們的社區。"}]},{"word":"session","pos":"n.","phonetic":"[ˈsɛʃən]","meaning":"會議；時段","definition":"a period of time devoted to an activity","collocations":["training session","in session"],"example":"We had a long training session today.","exampleZh":"我們今天有一場很長的訓練課程。","synonyms":[],"level":4,"theme":"時間與空間","examples":[{"en":"We had a long training session today.","zh":"我們今天有一場很長的訓練課程。"},{"en":"We had an intense training session at the gym today.","zh":"我們今天在健身房進行了一場激烈的訓練。"},{"en":"The parliament is currently in session to discuss the new law.","zh":"議會目前正在開會討論新法律。"}]},{"word":"settle","pos":"v.","phonetic":"[ˈsɛtḷ]","meaning":"定居；解決","definition":"to resolve a matter or move somewhere permanently","collocations":["settle down","settle a dispute"],"example":"They settled in a small town after retiring.","exampleZh":"他們退休後在一個小鎮定居。","synonyms":["resolve"],"level":3,"theme":"動作與行為","examples":[{"en":"They settled in a small town after retiring.","zh":"他們退休後在一個小鎮定居。"},{"en":"After years of travel, they decided to settle down in the countryside.","zh":"旅行多年後，他們決定在鄉下定居下來。"},{"en":"The two neighbors finally settled their long argument peacefully.","zh":"這兩位鄰居終於和平地解決了長久的爭執。"}]},{"word":"settlement","pos":"n.","phonetic":"[ˈsɛtḷmənt]","meaning":"解決；聚落","definition":"an official agreement, or a place where people establish a community","collocations":["reach a settlement","early settlement"],"example":"The two sides reached a settlement.","exampleZh":"雙方達成了協議。","synonyms":[],"level":5,"theme":"社會與文化","examples":[{"en":"The two sides reached a settlement.","zh":"雙方達成了協議。"},{"en":"After long talks, the two companies reached a fair settlement.","zh":"經過長時間協商，兩家公司達成了公平的和解。"},{"en":"Archaeologists discovered an ancient settlement beneath the hill.","zh":"考古學家在山丘下發現了一處古老的聚落。"}]},{"word":"several","pos":"adj.","phonetic":"[ˈsɛvərəl]","meaning":"幾個的","definition":"more than two but not very many","collocations":["several times","several people"],"example":"I have called her several times.","exampleZh":"我打過她好幾次電話。","synonyms":[],"level":2,"theme":"抽象概念","examples":[{"en":"I have called her several times.","zh":"我打過她好幾次電話。"},{"en":"I have visited that museum several times this year.","zh":"我今年已經去那間博物館好幾次了。"},{"en":"Several people were waiting outside the shop before it opened.","zh":"商店開門前，好幾個人在外面等候。"}]},{"word":"severe","pos":"adj.","phonetic":"[sɪˈvɪr]","meaning":"嚴重的；嚴厲的","definition":"very bad, serious, or strict","collocations":["severe weather","severe punishment"],"example":"The area suffered severe flooding.","exampleZh":"這個地區遭受嚴重的水災。","synonyms":["harsh"],"level":4,"theme":"性質與描述","examples":[{"en":"The area suffered severe flooding.","zh":"這個地區遭受嚴重的水災。"},{"en":"The city was hit by severe weather over the weekend.","zh":"這座城市在週末遭受了惡劣天氣的侵襲。"},{"en":"Breaking the rules may bring severe punishment.","zh":"違反規定可能會招致嚴厲的懲罰。"}]},{"word":"shade","pos":"n. / v.","phonetic":"[ʃed]","meaning":"陰涼處；遮光物；使變暗","definition":"an area sheltered from direct sunlight, or to block light from something","collocations":["sit in the shade","a shade of blue","shade one's eyes"],"example":"We rested in the shade of a big tree.","exampleZh":"我們在一棵大樹的陰涼處休息。","synonyms":["shadow"],"level":2,"theme":"自然與環境","examples":[{"en":"We rested in the shade of a big tree.","zh":"我們在一棵大樹的陰涼處休息。"},{"en":"On hot days we like to sit in the shade of the tree.","zh":"炎熱的日子我們喜歡坐在樹蔭下。"},{"en":"She chose a lighter shade of blue for the walls.","zh":"她為牆壁選了較淺的藍色調。"}]},{"word":"shadow","pos":"n. / v.","phonetic":"[ˈʃædo]","meaning":"影子；陰影；跟蹤","definition":"a dark shape made when something blocks light","collocations":["cast a shadow","in the shadow of","shadow someone"],"example":"His shadow grew longer as the sun went down.","exampleZh":"太陽下山時，他的影子變得越來越長。","synonyms":["shade"],"level":2,"theme":"自然與環境","examples":[{"en":"His shadow grew longer as the sun went down.","zh":"太陽下山時，他的影子變得越來越長。"},{"en":"The tall building cast a long shadow over the street.","zh":"這棟高樓在街道上投下長長的影子。"},{"en":"The detective quietly shadowed the suspect through the market.","zh":"偵探悄悄地在市場裡跟蹤嫌疑犯。"}]},{"word":"shake","pos":"v. / n.","phonetic":"[ʃek]","meaning":"搖動；顫抖；握手","definition":"to move quickly up and down or side to side","collocations":["shake hands","shake one's head","a milk shake"],"example":"She shook her head to say no.","exampleZh":"她搖搖頭表示不同意。","synonyms":["tremble","shiver"],"level":1,"theme":"動作與行為","examples":[{"en":"She shook her head to say no.","zh":"她搖搖頭表示不同意。"},{"en":"The two leaders shook hands warmly in front of the cameras.","zh":"兩位領袖在鏡頭前熱情地握手。"},{"en":"Please shake the bottle well before pouring the juice.","zh":"倒果汁前請把瓶子搖勻。"}]},{"word":"shallow","pos":"adj.","phonetic":"[ˈʃælo]","meaning":"淺的；膚淺的","definition":"not deep","collocations":["shallow water","a shallow person","shallow breathing"],"example":"Children can swim safely in the shallow end of the pool.","exampleZh":"孩子們可以安全地在泳池的淺水區游泳。","synonyms":["superficial"],"level":3,"theme":"性質與描述","examples":[{"en":"Children can swim safely in the shallow end of the pool.","zh":"孩子們可以安全地在泳池的淺水區游泳。"},{"en":"The children played happily in the shallow water near the shore.","zh":"孩子們在靠近岸邊的淺水裡開心地玩耍。"},{"en":"Judging people by their looks is a shallow attitude.","zh":"以外貌評斷別人是一種膚淺的態度。"}]},{"word":"shame","pos":"n. / v.","phonetic":"[ʃem]","meaning":"羞恥；遺憾；使蒙羞","definition":"a painful feeling of guilt or embarrassment","collocations":["feel shame","a shame that","bring shame on"],"example":"It's a shame that you can't come to the party.","exampleZh":"你不能來派對真是可惜。","synonyms":["disgrace","embarrassment"],"level":3,"theme":"情緒與感受","examples":[{"en":"It's a shame that you can't come to the party.","zh":"你不能來派對真是可惜。"},{"en":"He felt deep shame after telling such an obvious lie.","zh":"說了這麼明顯的謊之後，他感到深深的羞愧。"},{"en":"It is a real shame that the concert was cancelled.","zh":"演唱會取消真是太可惜了。"}]},{"word":"shampoo","pos":"n. / v.","phonetic":"[ʃæmˈpu]","meaning":"洗髮精；洗頭","definition":"a liquid soap used for washing hair","collocations":["a bottle of shampoo","shampoo your hair"],"example":"She bought a new bottle of shampoo yesterday.","exampleZh":"她昨天買了一瓶新的洗髮精。","synonyms":[],"level":1,"theme":"居家與生活","examples":[{"en":"She bought a new bottle of shampoo yesterday.","zh":"她昨天買了一瓶新的洗髮精。"},{"en":"I need to buy a new bottle of shampoo tomorrow.","zh":"我明天需要買一瓶新的洗髮精。"},{"en":"Remember to shampoo your hair after swimming in the pool.","zh":"在泳池游泳後記得洗頭。"}]},{"word":"shape","pos":"n. / v.","phonetic":"[ʃep]","meaning":"形狀；塑造","definition":"the form or outline of something","collocations":["in good shape","take shape"],"example":"The cloud was in the shape of a heart.","exampleZh":"那朵雲的形狀像顆心。","synonyms":["form"],"level":2,"theme":"性質與描述","examples":[{"en":"The cloud was in the shape of a heart.","zh":"那朵雲的形狀像顆心。"},{"en":"The baker cut the dough into the shape of a star.","zh":"麵包師傅把麵團切成星星的形狀。"},{"en":"Regular exercise keeps my grandfather in good shape.","zh":"規律運動讓我祖父保持良好的身體狀態。"}]},{"word":"share","pos":"v. / n.","phonetic":"[ʃɛr]","meaning":"分享","definition":"to have, use, or divide something together with others","collocations":["share food","share ideas"],"example":"We shared the pizza equally.","exampleZh":"我們平均分享了披薩。","synonyms":[],"level":1,"theme":"動作與行為","examples":[{"en":"We shared the pizza equally.","zh":"我們平均分享了披薩。"},{"en":"The two sisters agreed to share the last piece of cake.","zh":"兩姊妹同意分享最後一塊蛋糕。"},{"en":"In class we often share ideas about the story we read.","zh":"課堂上我們常常分享對所讀故事的想法。"}]},{"word":"shark","pos":"n.","phonetic":"[ʃɑrk]","meaning":"鯊魚","definition":"a large, often dangerous sea fish with sharp teeth","collocations":["a great white shark","shark attack","swim with sharks"],"example":"A shark was spotted near the beach yesterday.","exampleZh":"昨天有人在海灘附近發現一隻鯊魚。","synonyms":[],"level":2,"theme":"動物與植物","examples":[{"en":"A shark was spotted near the beach yesterday.","zh":"昨天有人在海灘附近發現一隻鯊魚。"},{"en":"A great white shark suddenly appeared near the diving boat.","zh":"一條大白鯊突然出現在潛水船附近。"},{"en":"Brave tourists paid to swim with sharks in a large tank.","zh":"勇敢的遊客付費在大水槽裡與鯊魚共游。"}]},{"word":"sharp","pos":"adj.","phonetic":"[ʃɑrp]","meaning":"銳利的；敏銳的","definition":"having a fine cutting edge, or quick to notice things","collocations":["sharp knife","sharp mind"],"example":"Be careful, the knife is very sharp.","exampleZh":"小心，這把刀非常鋒利。","synonyms":["keen"],"level":2,"theme":"性質與描述","examples":[{"en":"Be careful, the knife is very sharp.","zh":"小心，這把刀非常鋒利。"},{"en":"Be careful because the edge of this knife is very sharp.","zh":"小心，這把刀的刀刃非常銳利。"},{"en":"Her sharp mind allows her to solve puzzles quickly.","zh":"她敏銳的頭腦讓她能快速解開謎題。"}]},{"word":"shave","pos":"v. / n.","phonetic":"[ʃev]","meaning":"刮鬍子；剃毛","definition":"to remove hair from the skin with a razor","collocations":["shave one's beard","a close shave","shave legs"],"example":"He shaves his face every morning before work.","exampleZh":"他每天早上上班前都會刮鬍子。","synonyms":[],"level":2,"theme":"服裝與外表","examples":[{"en":"He shaves his face every morning before work.","zh":"他每天早上上班前都會刮鬍子。"},{"en":"He cut himself slightly while trying to shave his beard.","zh":"他刮鬍子時不小心割傷了自己。"},{"en":"The barber gave him a close shave before the wedding.","zh":"婚禮前理髮師幫他刮了個乾淨的鬍子。"}]},{"word":"shed","pos":"n. / v.","phonetic":"[ʃɛd]","meaning":"小屋；棚子；脫落","definition":"a small simple building used for storage, or to lose something naturally","collocations":["a garden shed","shed light on","shed tears"],"example":"He keeps his tools in the shed behind the house.","exampleZh":"他把工具放在房子後面的小屋裡。","synonyms":["hut"],"level":4,"theme":"居家與生活","examples":[{"en":"He keeps his tools in the shed behind the house.","zh":"他把工具放在房子後面的小屋裡。"},{"en":"Dad keeps his gardening tools in the wooden shed outside.","zh":"爸爸把園藝工具放在外面的木造小屋裡。"},{"en":"The report helped shed light on the mysterious problem.","zh":"這份報告幫助闡明了這個神秘的問題。"}]},{"word":"sheep","pos":"n.","phonetic":"[ʃip]","meaning":"綿羊","definition":"a farm animal raised for wool and meat","collocations":["a flock of sheep","count sheep","black sheep"],"example":"The farmer keeps a hundred sheep on his farm.","exampleZh":"這位農夫在他的農場裡養了一百隻綿羊。","synonyms":[],"level":1,"theme":"動物與植物","examples":[{"en":"The farmer keeps a hundred sheep on his farm.","zh":"這位農夫在他的農場裡養了一百隻綿羊。"},{"en":"A large flock of sheep grazed peacefully on the green hill.","zh":"一大群綿羊在青綠的山坡上安靜地吃草。"},{"en":"When I can't sleep, I try counting sheep in my head.","zh":"睡不著的時候，我試著在腦中數綿羊。"}]},{"word":"sheet","pos":"n.","phonetic":"[ʃit]","meaning":"床單；一張(紙)；薄片","definition":"a large piece of cloth used on a bed, or a flat piece of paper","collocations":["a sheet of paper","bed sheet","a sheet of ice"],"example":"She changed the sheets on the bed this morning.","exampleZh":"她今天早上換了床單。","synonyms":[],"level":2,"theme":"居家與生活","examples":[{"en":"She changed the sheets on the bed this morning.","zh":"她今天早上換了床單。"},{"en":"Please hand me a clean sheet of paper for my notes.","zh":"請遞給我一張乾淨的紙做筆記。"},{"en":"A thin sheet of ice covered the pond overnight.","zh":"一夜之間，薄薄的一層冰覆蓋了池塘。"}]},{"word":"shelf","pos":"n.","phonetic":"[ʃɛlf]","meaning":"架子","definition":"a flat surface for storing or displaying objects","collocations":["bookshelf","top shelf"],"example":"She put the books on the shelf.","exampleZh":"她把書放在架子上。","synonyms":[],"level":2,"theme":"居家與生活","examples":[{"en":"She put the books on the shelf.","zh":"她把書放在架子上。"},{"en":"The tallest books are kept on the top shelf.","zh":"最高的書放在最上層的架子上。"},{"en":"She reached up to place the vase on the shelf.","zh":"她伸手把花瓶放到架子上。"}]},{"word":"shell","pos":"n. / v.","phonetic":"[ʃɛl]","meaning":"貝殼；外殼；剝殼","definition":"the hard outer covering of an egg, nut, or sea creature","collocations":["a sea shell","shell an egg","turtle shell"],"example":"She collected colorful shells along the beach.","exampleZh":"她在海灘上撿了許多色彩繽紛的貝殼。","synonyms":[],"level":2,"theme":"自然與環境","examples":[{"en":"She collected colorful shells along the beach.","zh":"她在海灘上撿了許多色彩繽紛的貝殼。"},{"en":"The turtle quickly pulled its head into its hard shell.","zh":"烏龜迅速把頭縮進堅硬的殼裡。"},{"en":"We spent the afternoon collecting sea shells along the beach.","zh":"我們花了一下午沿著海灘撿貝殼。"}]},{"word":"shelter","pos":"n. / v.","phonetic":"[ˈʃɛltɚ]","meaning":"庇護所；避難處；躲避","definition":"a place giving protection from weather or danger","collocations":["take shelter","a homeless shelter","shelter from the rain"],"example":"They took shelter under a bridge during the storm.","exampleZh":"暴風雨期間他們在橋下躲避。","synonyms":["refuge"],"level":3,"theme":"居家與生活","examples":[{"en":"They took shelter under a bridge during the storm.","zh":"暴風雨期間他們在橋下躲避。"},{"en":"The hikers took shelter in a cave when the storm began.","zh":"暴風雨開始時，登山者躲進洞穴避難。"},{"en":"The volunteers built a shelter for the stray dogs.","zh":"志工們為流浪狗蓋了一個庇護所。"}]},{"word":"shepherd","pos":"n. / v.","phonetic":"[ˈʃɛpɚd]","meaning":"牧羊人；引導","definition":"a person who takes care of sheep","collocations":["a young shepherd","shepherd the group","a shepherd's flock"],"example":"The shepherd led his flock across the hills.","exampleZh":"牧羊人帶領著他的羊群穿越山丘。","synonyms":[],"level":4,"theme":"工作與職業","examples":[{"en":"The shepherd led his flock across the hills.","zh":"牧羊人帶領著他的羊群穿越山丘。"},{"en":"The young shepherd watched over his sheep on the hillside.","zh":"年輕的牧羊人在山坡上照看他的羊群。"},{"en":"The teacher shepherded the noisy children onto the bus.","zh":"老師引導吵鬧的孩子們上了巴士。"}]},{"word":"shield","pos":"n. / v.","phonetic":"[ʃild]","meaning":"盾牌；防護罩；保護","definition":"a piece of equipment used for protection, or to protect someone","collocations":["a shield from danger","raise a shield","shield your eyes"],"example":"The soldier used his shield to block the attack.","exampleZh":"這名士兵用盾牌擋住了攻擊。","synonyms":["protect"],"level":4,"theme":"其他","examples":[{"en":"The soldier used his shield to block the attack.","zh":"這名士兵用盾牌擋住了攻擊。"},{"en":"She raised her hand to shield her eyes from the sun.","zh":"她舉起手遮擋陽光保護眼睛。"},{"en":"Good parents try to shield their children from real danger.","zh":"好的父母會試著保護孩子遠離真正的危險。"}]},{"word":"shift","pos":"n. / v.","phonetic":"[ʃɪft]","meaning":"轉變；輪班","definition":"a change in position or a period of work","collocations":["night shift","shift in attitude"],"example":"She works the night shift at the hospital.","exampleZh":"她在醫院上夜班。","synonyms":["change"],"level":3,"theme":"工作與職業","examples":[{"en":"She works the night shift at the hospital.","zh":"她在醫院上夜班。"},{"en":"The nurse is tired after a long night shift.","zh":"護士上完漫長的夜班後很疲累。"},{"en":"There has been a big shift in public attitudes toward recycling.","zh":"大眾對回收的態度有了很大的轉變。"}]},{"word":"shine","pos":"v.","phonetic":"[ʃaɪn]","meaning":"發光；閃耀","definition":"to give off or reflect light","collocations":["the sun shines","shine bright"],"example":"The sun shone brightly all day.","exampleZh":"太陽整天都閃耀著光芒。","synonyms":["glow"],"level":2,"theme":"天氣與季節","examples":[{"en":"The sun shone brightly all day.","zh":"太陽整天都閃耀著光芒。"},{"en":"The stars shine brightly in the clear country sky.","zh":"星星在清朗的鄉間夜空中閃耀。"},{"en":"She polished the silver spoon until it began to shine.","zh":"她把銀湯匙擦到開始發亮。"}]},{"word":"ship","pos":"n. / v.","phonetic":"[ʃɪp]","meaning":"船；運送","definition":"a large vessel that travels on water","collocations":["board a ship","ship goods"],"example":"The ship sailed to Japan.","exampleZh":"這艘船航向日本。","synonyms":["vessel"],"level":1,"theme":"交通與旅行","examples":[{"en":"The ship sailed to Japan.","zh":"這艘船航向日本。"},{"en":"Hundreds of passengers boarded the huge cruise ship.","zh":"數百名乘客登上了巨大的郵輪。"},{"en":"The factory will ship the goods to customers next week.","zh":"工廠下週會把貨物運送給顧客。"}]},{"word":"shirt","pos":"n.","phonetic":"[ʃɝt]","meaning":"襯衫","definition":"a piece of clothing worn on the upper body","collocations":["white shirt","button a shirt"],"example":"He wore a blue shirt to the interview.","exampleZh":"他穿了一件藍色襯衫去面試。","synonyms":[],"level":1,"theme":"服裝與外表","examples":[{"en":"He wore a blue shirt to the interview.","zh":"他穿了一件藍色襯衫去面試。"},{"en":"He ironed his white shirt before the important interview.","zh":"重要面試前他燙了他的白襯衫。"},{"en":"Could you help me button the back of this shirt?","zh":"你可以幫我扣這件襯衫後面的扣子嗎？"}]},{"word":"shiver","pos":"v. / n.","phonetic":"[ˈʃɪvɚ]","meaning":"顫抖；發抖","definition":"to shake slightly because of cold or fear","collocations":["shiver with cold","a shiver of fear","shiver uncontrollably"],"example":"She shivered as the cold wind blew past.","exampleZh":"寒風吹過時她不禁顫抖起來。","synonyms":["tremble","shake"],"level":3,"theme":"情緒與感受","examples":[{"en":"She shivered as the cold wind blew past.","zh":"寒風吹過時她不禁顫抖起來。"},{"en":"The lost puppy shivered with cold in the heavy rain.","zh":"迷路的小狗在大雨中冷得發抖。"},{"en":"A sudden shiver of fear ran down her spine.","zh":"一陣突如其來的恐懼寒意竄過她的背脊。"}]},{"word":"shock","pos":"n. / v.","phonetic":"[ʃɑk]","meaning":"震驚","definition":"a sudden and surprising event or feeling","collocations":["electric shock","in shock"],"example":"The news came as a great shock to us.","exampleZh":"這個消息讓我們大為震驚。","synonyms":["surprise"],"level":3,"theme":"情緒與感受","examples":[{"en":"The news came as a great shock to us.","zh":"這個消息讓我們大為震驚。"},{"en":"The sudden bad news left the whole family in shock.","zh":"突如其來的壞消息讓全家人都陷入震驚。"},{"en":"He got a small electric shock while fixing the lamp.","zh":"他修理檯燈時觸了一下電。"}]},{"word":"shoe","pos":"n.","phonetic":"[ʃu]","meaning":"鞋子","definition":"an outer covering for the foot","collocations":["pair of shoes","tie shoes"],"example":"She bought a new pair of shoes.","exampleZh":"她買了一雙新鞋。","synonyms":[],"level":1,"theme":"服裝與外表","examples":[{"en":"She bought a new pair of shoes.","zh":"她買了一雙新鞋。"},{"en":"These running shoes are comfortable enough for a long walk.","zh":"這雙跑鞋舒服到足以應付長時間走路。"},{"en":"Remember to tie your shoes before you start running.","zh":"開始跑步前記得綁好鞋帶。"}]},{"word":"shoot","pos":"v. / n.","phonetic":"[ʃut]","meaning":"射擊；拍攝；嫩芽","definition":"to fire a weapon, or to take photos or film","collocations":["shoot a movie","shoot an arrow","shoot a goal"],"example":"The photographer will shoot the wedding photos tomorrow.","exampleZh":"攝影師明天會拍攝婚紗照。","synonyms":["fire"],"level":2,"theme":"動作與行為","examples":[{"en":"The photographer will shoot the wedding photos tomorrow.","zh":"攝影師明天會拍攝婚紗照。"},{"en":"The director plans to shoot the final scene at dawn.","zh":"導演計畫在黎明時拍攝最後一幕。"},{"en":"He practiced hard to shoot the arrow at the target.","zh":"他努力練習把箭射向靶心。"}]},{"word":"shop","pos":"n. / v.","phonetic":"[ʃɑp]","meaning":"商店；購物","definition":"a place where goods are sold, or to buy goods","collocations":["go shopping","coffee shop"],"example":"We went shopping downtown.","exampleZh":"我們去市區購物。","synonyms":["store"],"level":1,"theme":"商業與金錢","examples":[{"en":"We went shopping downtown.","zh":"我們去市區購物。"},{"en":"We often meet friends at the coffee shop after class.","zh":"下課後我們常在咖啡店和朋友碰面。"},{"en":"She likes to go shopping for clothes on weekends.","zh":"她喜歡在週末去買衣服。"}]},{"word":"shore","pos":"n.","phonetic":"[ʃor]","meaning":"海岸","definition":"the land along the edge of a sea or lake","collocations":["along the shore","off shore"],"example":"Waves crashed against the shore.","exampleZh":"海浪拍打著海岸。","synonyms":["coast"],"level":3,"theme":"自然與環境","examples":[{"en":"Waves crashed against the shore.","zh":"海浪拍打著海岸。"},{"en":"Gentle waves rolled softly onto the sandy shore.","zh":"溫柔的海浪輕輕拍打在沙岸上。"},{"en":"A small fishing boat waited just off the shore.","zh":"一艘小漁船就停在離岸不遠處。"}]},{"word":"short","pos":"adj.","phonetic":"[ʃɔrt]","meaning":"短的；矮的","definition":"not long in length, time, or height","collocations":["short hair","short trip"],"example":"She has short black hair.","exampleZh":"她有一頭黑色短髮。","synonyms":[],"level":1,"theme":"性質與描述","examples":[{"en":"She has short black hair.","zh":"她有一頭黑色短髮。"},{"en":"We took a short trip to the mountains last weekend.","zh":"上週末我們去山上做了一趟短程旅行。"},{"en":"He decided to get a short haircut for the summer.","zh":"他決定為了夏天剪個短髮。"}]},{"word":"shortage","pos":"n.","phonetic":"[ˈʃɔrtɪdʒ]","meaning":"短缺","definition":"a lack or insufficient amount of something needed","collocations":["water shortage","food shortage"],"example":"The drought caused a water shortage.","exampleZh":"乾旱造成了缺水問題。","synonyms":["lack"],"level":4,"theme":"社會與文化","examples":[{"en":"The drought caused a water shortage.","zh":"乾旱造成了缺水問題。"},{"en":"The long drought caused a serious water shortage in the region.","zh":"長期乾旱造成了該地區嚴重的水資源短缺。"},{"en":"A food shortage forced prices to rise sharply.","zh":"食物短缺迫使物價急遽上漲。"}]},{"word":"shot","pos":"n.","phonetic":"[ʃɑt]","meaning":"射擊；一投；注射","definition":"an act of firing a gun or throwing/kicking a ball","collocations":["take a shot","a shot in the arm","a good shot"],"example":"He took a shot at the basket and scored.","exampleZh":"他投籃並得分了。","synonyms":[],"level":3,"theme":"運動與休閒","examples":[{"en":"He took a shot at the basket and scored.","zh":"他投籃並得分了。"},{"en":"He took a quick shot and scored the winning point.","zh":"他快速一投，得到了致勝的一分。"},{"en":"The nurse gave the child a flu shot in the arm.","zh":"護士在孩子的手臂上打了一針流感疫苗。"}]},{"word":"shoulder","pos":"n. / v.","phonetic":"[ˈʃoldɚ]","meaning":"肩膀；承擔","definition":"the part of the body between the neck and the arm","collocations":["shoulder to shoulder","shoulder the blame","a shoulder bag"],"example":"She carried the bag over her shoulder.","exampleZh":"她把包包背在肩上。","synonyms":[],"level":2,"theme":"身體與健康","examples":[{"en":"She carried the bag over her shoulder.","zh":"她把包包背在肩上。"},{"en":"She gently patted him on the shoulder to comfort him.","zh":"她輕拍他的肩膀安慰他。"},{"en":"As the eldest child, he had to shoulder many responsibilities.","zh":"身為長子，他必須承擔許多責任。"}]},{"word":"shout","pos":"v. / n.","phonetic":"[ʃaʊt]","meaning":"大喊","definition":"to speak or cry out very loudly","collocations":["shout for help","shout at someone"],"example":"He shouted for help when he fell.","exampleZh":"他跌倒時大喊求救。","synonyms":["yell"],"level":2,"theme":"溝通與語言","examples":[{"en":"He shouted for help when he fell.","zh":"他跌倒時大喊求救。"},{"en":"The coach had to shout to be heard over the crowd.","zh":"教練必須大喊才能蓋過人群的聲音被聽見。"},{"en":"Please don't shout at your little sister like that.","zh":"請不要那樣對你妹妹大吼。"}]},{"word":"shovel","pos":"n. / v.","phonetic":"[ˈʃʌvəl]","meaning":"鏟子；鏟(雪、土)","definition":"a tool used for digging or moving material like snow or dirt","collocations":["a snow shovel","shovel snow","dig with a shovel"],"example":"They used a shovel to clear the snow from the driveway.","exampleZh":"他們用鏟子清除車道上的積雪。","synonyms":[],"level":3,"theme":"居家與生活","examples":[{"en":"They used a shovel to clear the snow from the driveway.","zh":"他們用鏟子清除車道上的積雪。"},{"en":"He used a shovel to dig a hole for the tree.","zh":"他用鏟子挖了一個洞來種樹。"},{"en":"Every winter they must shovel snow off the front steps.","zh":"每年冬天他們必須把前階梯上的雪鏟掉。"}]},{"word":"show","pos":"v. / n.","phonetic":"[ʃo]","meaning":"展示；節目","definition":"to display something, or a performance or program","collocations":["TV show","show up"],"example":"She showed me her new phone.","exampleZh":"她給我看她的新手機。","synonyms":["display"],"level":1,"theme":"藝術與音樂","examples":[{"en":"She showed me her new phone.","zh":"她給我看她的新手機。"},{"en":"Let me show you how to solve this math problem.","zh":"讓我示範給你看如何解這道數學題。"},{"en":"He promised to show up early for the group meeting.","zh":"他答應會提早出現在小組會議上。"}]},{"word":"shower","pos":"n.","phonetic":"[ˈʃaʊɚ]","meaning":"淋浴；陣雨","definition":"a wash with a spray of water, or a brief fall of rain","collocations":["take a shower","rain shower"],"example":"He takes a shower every morning.","exampleZh":"他每天早上都會淋浴。","synonyms":[],"level":2,"theme":"居家與生活","examples":[{"en":"He takes a shower every morning.","zh":"他每天早上都會淋浴。"},{"en":"She likes to take a warm shower before going to bed.","zh":"她喜歡睡前洗個溫水澡。"},{"en":"A sudden shower forced us to run for cover.","zh":"一陣突如其來的陣雨迫使我們跑去躲雨。"}]},{"word":"shrimp","pos":"n.","phonetic":"[ʃrɪmp]","meaning":"蝦子","definition":"a small edible shellfish","collocations":["fried shrimp","shrimp cocktail"],"example":"We ordered fried shrimp for dinner.","exampleZh":"我們晚餐點了炸蝦。","synonyms":["prawn"],"level":2,"theme":"食物與烹飪","examples":[{"en":"We ordered fried shrimp for dinner.","zh":"我們晚餐點了炸蝦。"},{"en":"The chef fried the fresh shrimp with garlic and butter.","zh":"廚師用大蒜和奶油煎新鮮的蝦子。"},{"en":"I ordered a shrimp cocktail as a starter.","zh":"我點了一份鮮蝦盅當開胃菜。"}]},{"word":"shrink","pos":"v.","phonetic":"[ʃrɪŋk]","meaning":"縮小","definition":"to become or make smaller","collocations":["shrink in size","shrink the budget"],"example":"My sweater shrank after washing.","exampleZh":"我的毛衣洗過後縮水了。","synonyms":["contract"],"level":4,"theme":"動作與行為","examples":[{"en":"My sweater shrank after washing.","zh":"我的毛衣洗過後縮水了。"},{"en":"Wool sweaters often shrink if you wash them in hot water.","zh":"羊毛毛衣用熱水洗常常會縮水。"},{"en":"The company had to shrink its budget during hard times.","zh":"在艱困時期公司不得不縮減預算。"}]},{"word":"shrug","pos":"v. / n.","phonetic":"[ʃrʌg]","meaning":"聳肩","definition":"to raise the shoulders to show you don't know or care","collocations":["shrug one's shoulders","shrug off","give a shrug"],"example":"She shrugged her shoulders when I asked her opinion.","exampleZh":"我問她的意見時，她聳了聳肩。","synonyms":[],"level":4,"theme":"動作與行為","examples":[{"en":"She shrugged her shoulders when I asked her opinion.","zh":"我問她的意見時，她聳了聳肩。"},{"en":"He just shrugged his shoulders when I asked what happened.","zh":"當我問發生什麼事時，他只是聳聳肩。"},{"en":"She tried to shrug off the rude comment and smile.","zh":"她試著不理會那句無禮的評論並微笑。"}]},{"word":"shut","pos":"v. / adj.","phonetic":"[ʃʌt]","meaning":"關閉；關上的","definition":"to close something, or in a closed position","collocations":["shut the door","shut down","shut up"],"example":"Please shut the window; it's getting cold.","exampleZh":"請把窗戶關上，天氣變冷了。","synonyms":["close"],"level":1,"theme":"動作與行為","examples":[{"en":"Please shut the window; it's getting cold.","zh":"請把窗戶關上，天氣變冷了。"},{"en":"Please shut the door quietly when you leave the room.","zh":"離開房間時請輕輕把門關上。"},{"en":"The old factory was forced to shut down last year.","zh":"那間老工廠去年被迫關閉。"}]},{"word":"shuttle","pos":"n. / v.","phonetic":"[ˈʃʌtl̩]","meaning":"接駁車；穿梭；太空梭","definition":"a vehicle that travels regularly between two places","collocations":["a shuttle bus","space shuttle","shuttle passengers"],"example":"A free shuttle bus runs between the airport and the hotel.","exampleZh":"機場與飯店之間有免費的接駁車。","synonyms":[],"level":4,"theme":"交通與旅行","examples":[{"en":"A free shuttle bus runs between the airport and the hotel.","zh":"機場與飯店之間有免費的接駁車。"},{"en":"A free shuttle bus takes visitors from the station to the museum.","zh":"一輛免費接駁車載訪客從車站到博物館。"},{"en":"The astronauts boarded the space shuttle before launch.","zh":"太空人在發射前登上了太空梭。"}]},{"word":"shy","pos":"adj.","phonetic":"[ʃaɪ]","meaning":"害羞的","definition":"nervous or timid around other people","collocations":["shy smile","too shy"],"example":"The boy is too shy to speak in public.","exampleZh":"這男孩太害羞不敢公開發言。","synonyms":["timid"],"level":2,"theme":"情緒與感受","examples":[{"en":"The boy is too shy to speak in public.","zh":"這男孩太害羞不敢公開發言。"},{"en":"The shy girl blushed when the teacher praised her.","zh":"老師稱讚她時，害羞的女孩臉紅了。"},{"en":"He gave a shy smile and looked down at his shoes.","zh":"他害羞地笑了笑，低頭看著自己的鞋子。"}]},{"word":"sick","pos":"adj.","phonetic":"[sɪk]","meaning":"生病的","definition":"unwell or affected by illness","collocations":["feel sick","sick leave"],"example":"He stayed home because he felt sick.","exampleZh":"他因為身體不舒服而待在家裡。","synonyms":["ill"],"level":1,"theme":"身體與健康","examples":[{"en":"He stayed home because he felt sick.","zh":"他因為身體不舒服而待在家裡。"},{"en":"She took a day of sick leave to see the doctor.","zh":"她請了一天病假去看醫生。"},{"en":"Eating too much candy made the little boy feel sick.","zh":"吃太多糖果讓這小男孩覺得不舒服。"}]},{"word":"side","pos":"n.","phonetic":"[saɪd]","meaning":"邊；一側","definition":"a part of something away from its center","collocations":["side by side","take sides"],"example":"They walked side by side.","exampleZh":"他們並肩走著。","synonyms":[],"level":1,"theme":"時間與空間","examples":[{"en":"They walked side by side.","zh":"他們並肩走著。"},{"en":"The old couple walked slowly side by side in the park.","zh":"這對老夫妻在公園裡並肩慢慢地走。"},{"en":"There is a small garden on the other side of the house.","zh":"房子的另一側有一個小花園。"}]},{"word":"sigh","pos":"v. / n.","phonetic":"[saɪ]","meaning":"嘆息；嘆氣","definition":"to breathe out slowly and loudly, showing tiredness or sadness","collocations":["sigh with relief","let out a sigh","heave a sigh"],"example":"She sighed with relief when the test was over.","exampleZh":"考試結束後她鬆了一口氣。","synonyms":[],"level":3,"theme":"情緒與感受","examples":[{"en":"She sighed with relief when the test was over.","zh":"考試結束後她鬆了一口氣。"},{"en":"He let out a deep sigh after the exhausting day.","zh":"經過疲憊的一天後，他深深地嘆了一口氣。"},{"en":"She sighed with relief when her lost cat came home.","zh":"當她走失的貓回家時，她鬆了一口氣。"}]},{"word":"sight","pos":"n.","phonetic":"[saɪt]","meaning":"視力；景象；視覺","definition":"the ability to see, or something that is seen","collocations":["lose sight of","a beautiful sight","at first sight"],"example":"The mountain view was a breathtaking sight.","exampleZh":"這片山景美得令人屏息。","synonyms":["vision"],"level":2,"theme":"身體與健康","examples":[{"en":"The mountain view was a breathtaking sight.","zh":"這片山景美得令人屏息。"},{"en":"The colorful fireworks were an amazing sight to everyone.","zh":"五彩繽紛的煙火對每個人來說都是驚人的景象。"},{"en":"Don't lose sight of your bags in the crowded station.","zh":"在擁擠的車站別讓你的行李離開你的視線。"}]},{"word":"sightseeing","pos":"n.","phonetic":"[ˈsaɪtˌsiɪŋ]","meaning":"觀光；遊覽","definition":"the activity of visiting interesting places as a tourist","collocations":["go sightseeing","a sightseeing tour","sightseeing spots"],"example":"We spent the whole day sightseeing in the old city.","exampleZh":"我們花了一整天在舊城區觀光。","synonyms":[],"level":3,"theme":"交通與旅行","examples":[{"en":"We spent the whole day sightseeing in the old city.","zh":"我們花了一整天在舊城區觀光。"},{"en":"We spent the whole morning sightseeing around the old temple.","zh":"我們整個上午都在古廟周圍觀光。"},{"en":"The guide showed us the most famous sightseeing spots downtown.","zh":"導遊帶我們看了市中心最著名的觀光景點。"}]},{"word":"sign","pos":"n. / v.","phonetic":"[saɪn]","meaning":"標誌；簽名","definition":"a mark or gesture that conveys meaning, or to write one's name","collocations":["sign a contract","road sign"],"example":"Please sign your name here.","exampleZh":"請在這裡簽名。","synonyms":["symbol"],"level":2,"theme":"溝通與語言","examples":[{"en":"Please sign your name here.","zh":"請在這裡簽名。"},{"en":"The road sign warns drivers about the sharp turn ahead.","zh":"這個路標警告駕駛前方有急轉彎。"},{"en":"You must sign the form before handing it in.","zh":"你必須在交出表格前簽名。"}]},{"word":"signal","pos":"n. / v.","phonetic":"[ˈsɪgnəl]","meaning":"信號","definition":"a sign or gesture used to convey information","collocations":["traffic signal","send a signal"],"example":"The traffic signal turned red.","exampleZh":"交通號誌變成紅燈。","synonyms":[],"level":3,"theme":"科技與媒體","examples":[{"en":"The traffic signal turned red.","zh":"交通號誌變成紅燈。"},{"en":"The traffic signal turned green, so the cars moved forward.","zh":"紅綠燈變綠了，車子便向前行駛。"},{"en":"She waved her arms to send a signal for help.","zh":"她揮舞手臂發出求救信號。"}]},{"word":"signature","pos":"n.","phonetic":"[ˈsɪgnətʃɚ]","meaning":"簽名","definition":"a person's name written in their own handwriting","collocations":["a valid signature","put your signature","a signature dish"],"example":"The contract requires your signature at the end.","exampleZh":"這份合約最後需要你的簽名。","synonyms":[],"level":4,"theme":"商業與金錢","examples":[{"en":"The contract requires your signature at the end.","zh":"這份合約最後需要你的簽名。"},{"en":"The bank needs your signature to open the new account.","zh":"銀行需要你的簽名才能開立新帳戶。"},{"en":"This spicy noodle dish is the restaurant's signature dish.","zh":"這道辣麵是這家餐廳的招牌菜。"}]},{"word":"significant","pos":"adj.","phonetic":"[sɪgˈnɪfɪkənt]","meaning":"重大的；顯著的","definition":"important enough to be noticed or to have an effect","collocations":["significant change","significant impact"],"example":"The discovery had a significant impact on science.","exampleZh":"這項發現對科學有重大的影響。","synonyms":["important"],"level":5,"theme":"抽象概念","examples":[{"en":"The discovery had a significant impact on science.","zh":"這項發現對科學有重大的影響。"},{"en":"Regular exercise brings a significant change to your health.","zh":"規律運動為你的健康帶來顯著的改變。"},{"en":"The new policy had a significant impact on local farmers.","zh":"這項新政策對當地農民造成了重大的影響。"}]},{"word":"silence","pos":"n. / v.","phonetic":"[ˈsaɪləns]","meaning":"沉默；寂靜；使沉默","definition":"complete absence of sound or speech","collocations":["a moment of silence","break the silence","in silence"],"example":"The whole room fell into silence when he entered.","exampleZh":"他進來時整個房間都陷入了沉默。","synonyms":["quiet"],"level":3,"theme":"溝通與語言","examples":[{"en":"The whole room fell into silence when he entered.","zh":"他進來時整個房間都陷入了沉默。"},{"en":"A moment of silence was held to honor the heroes.","zh":"全體默哀片刻以向英雄致敬。"},{"en":"His surprising answer broke the silence in the classroom.","zh":"他出人意料的回答打破了教室裡的沉默。"}]},{"word":"silent","pos":"adj.","phonetic":"[ˈsaɪlənt]","meaning":"安靜的；沉默的","definition":"making no sound; not speaking","collocations":["stay silent","a silent movie","fall silent"],"example":"Please remain silent during the exam.","exampleZh":"考試期間請保持安靜。","synonyms":["quiet"],"level":2,"theme":"溝通與語言","examples":[{"en":"Please remain silent during the exam.","zh":"考試期間請保持安靜。"},{"en":"Everyone must stay silent during the school examination.","zh":"考試期間每個人都必須保持安靜。"},{"en":"The whole crowd fell silent when the singer appeared.","zh":"當歌手出現時，全場觀眾靜了下來。"}]},{"word":"silk","pos":"n.","phonetic":"[sɪlk]","meaning":"絲；絲綢","definition":"a fine, soft cloth made by silkworms","collocations":["a silk dress","pure silk","smooth as silk"],"example":"She wore a beautiful silk scarf to the event.","exampleZh":"她參加活動時戴了一條漂亮的絲巾。","synonyms":[],"level":3,"theme":"服裝與外表","examples":[{"en":"She wore a beautiful silk scarf to the event.","zh":"她參加活動時戴了一條漂亮的絲巾。"},{"en":"She wore a smooth silk dress to the evening party.","zh":"她穿了一件光滑的絲質洋裝去參加晚會。"},{"en":"This scarf feels as soft and smooth as pure silk.","zh":"這條圍巾摸起來像純絲一樣柔軟光滑。"}]},{"word":"silly","pos":"adj.","phonetic":"[ˈsɪli]","meaning":"愚蠢的；傻的","definition":"showing a lack of thought or good sense","collocations":["a silly mistake","feel silly","silly question"],"example":"Don't be silly; of course I'll help you.","exampleZh":"別傻了，我當然會幫你。","synonyms":["foolish"],"level":1,"theme":"性質與描述","examples":[{"en":"Don't be silly; of course I'll help you.","zh":"別傻了，我當然會幫你。"},{"en":"I made a silly mistake by writing the wrong date.","zh":"我犯了一個把日期寫錯的愚蠢錯誤。"},{"en":"Don't be silly; of course we still want you here.","zh":"別傻了，我們當然還是希望你留在這裡。"}]},{"word":"silver","pos":"n. / adj.","phonetic":"[ˈsɪlvɚ]","meaning":"銀；銀色的","definition":"a shiny white precious metal, or its color","collocations":["a silver medal","silver jewelry","silver hair"],"example":"She won a silver medal in the swimming competition.","exampleZh":"她在游泳比賽中獲得銀牌。","synonyms":[],"level":2,"theme":"性質與描述","examples":[{"en":"She won a silver medal in the swimming competition.","zh":"她在游泳比賽中獲得銀牌。"},{"en":"She proudly won a silver medal at the swimming meet.","zh":"她在游泳比賽中驕傲地贏得了銀牌。"},{"en":"My grandmother wears a pretty ring made of silver.","zh":"我祖母戴著一枚漂亮的銀戒指。"}]},{"word":"similar","pos":"adj.","phonetic":"[ˈsɪmələ]","meaning":"相似的；類似的","definition":"like something else but not exactly the same","collocations":["similar to","in a similar way","similar interests"],"example":"Her opinion is similar to mine on this issue.","exampleZh":"她對這個問題的看法和我的很相似。","synonyms":["alike"],"level":2,"theme":"性質與描述","examples":[{"en":"Her opinion is similar to mine on this issue.","zh":"她對這個問題的看法和我的很相似。"},{"en":"My sister and I have very similar taste in music.","zh":"我和我姊姊在音樂品味上非常相似。"},{"en":"These two paintings look surprisingly similar to each other.","zh":"這兩幅畫看起來出奇地相似。"}]},{"word":"simple","pos":"adj.","phonetic":"[ˈsɪmpl̩]","meaning":"簡單的；樸素的","definition":"easy to understand or do; not complicated","collocations":["a simple task","keep it simple","simple life"],"example":"The instructions are very simple to follow.","exampleZh":"這些說明非常簡單易懂。","synonyms":["easy"],"level":1,"theme":"性質與描述","examples":[{"en":"The instructions are very simple to follow.","zh":"這些說明非常簡單易懂。"},{"en":"This recipe is so simple that even a child can follow it.","zh":"這道食譜非常簡單，連小孩都會做。"},{"en":"They prefer a simple life in a quiet country village.","zh":"他們喜歡在寧靜的鄉村過樸素的生活。"}]},{"word":"simplify","pos":"v.","phonetic":"[ˈsɪmpləˌfaɪ]","meaning":"簡化","definition":"to make something easier to understand or do","collocations":["simplify a process","simplify the rules","simplify language"],"example":"The teacher simplified the lesson for younger students.","exampleZh":"老師為年幼的學生簡化了課程內容。","synonyms":[],"level":5,"theme":"教育與學習","examples":[{"en":"The teacher simplified the lesson for younger students.","zh":"老師為年幼的學生簡化了課程內容。"},{"en":"The teacher tried to simplify the difficult math problem for us.","zh":"老師試著為我們簡化這道困難的數學題。"},{"en":"Using clear pictures can simplify a complicated process.","zh":"使用清楚的圖片可以簡化複雜的流程。"}]},{"word":"simultaneous","pos":"adj.","phonetic":"[ˌsaɪməlˈteniəs]","meaning":"同時發生的","definition":"happening or done at exactly the same time","collocations":["simultaneous events","simultaneous translation","occur simultaneously"],"example":"The two events happened almost simultaneously.","exampleZh":"這兩起事件幾乎同時發生。","synonyms":[],"level":6,"theme":"時間與空間","examples":[{"en":"The two events happened almost simultaneously.","zh":"這兩起事件幾乎同時發生。"},{"en":"The concert offered simultaneous translation for foreign guests.","zh":"這場音樂會為外國賓客提供同步翻譯。"},{"en":"The two explosions were almost simultaneous, shaking the whole street.","zh":"兩起爆炸幾乎同時發生，震動了整條街。"}]},{"word":"since","pos":"prep. / conj. / adv.","phonetic":"[sɪns]","meaning":"自從；既然；此後","definition":"from a particular time in the past until now","collocations":["since then","ever since","since childhood"],"example":"I have lived here since I was five years old.","exampleZh":"我從五歲起就住在這裡。","synonyms":[],"level":2,"theme":"時間與空間","examples":[{"en":"I have lived here since I was five years old.","zh":"我從五歲起就住在這裡。"},{"en":"I have been learning the piano since I was seven.","zh":"我從七歲起就一直在學鋼琴。"},{"en":"Since it is raining, let's stay indoors and read.","zh":"既然在下雨，我們就待在室內看書吧。"}]},{"word":"sincere","pos":"adj.","phonetic":"[sɪnˈsɪr]","meaning":"真誠的；誠懇的","definition":"honest and truthful in feelings or beliefs","collocations":["sincere apology","sincere thanks","a sincere person"],"example":"He gave a sincere apology for his mistake.","exampleZh":"他為自己的錯誤真誠地道歉。","synonyms":["honest","genuine"],"level":4,"theme":"性質與描述","examples":[{"en":"He gave a sincere apology for his mistake.","zh":"他為自己的錯誤真誠地道歉。"},{"en":"Please accept my sincere thanks for all your help.","zh":"請接受我對你所有幫助的誠摯感謝。"},{"en":"A sincere person always keeps his promises to friends.","zh":"真誠的人總是對朋友信守承諾。"}]},{"word":"sing","pos":"v.","phonetic":"[sɪŋ]","meaning":"唱歌","definition":"to make musical sounds with the voice","collocations":["sing a song","sing along","sing in a choir"],"example":"She loves to sing in the school choir.","exampleZh":"她喜歡在學校合唱團裡唱歌。","synonyms":[],"level":1,"theme":"藝術與音樂","examples":[{"en":"She loves to sing in the school choir.","zh":"她喜歡在學校合唱團裡唱歌。"},{"en":"The whole family loves to sing along to old songs.","zh":"全家人都喜歡跟著老歌一起唱。"},{"en":"She was invited to sing at her friend's wedding.","zh":"她受邀在朋友的婚禮上唱歌。"}]},{"word":"singer","pos":"n.","phonetic":"[ˈsɪŋɚ]","meaning":"歌手","definition":"a person who sings, especially professionally","collocations":["a famous singer","a lead singer","become a singer"],"example":"She dreams of becoming a famous singer someday.","exampleZh":"她夢想有一天能成為一位知名歌手。","synonyms":["vocalist"],"level":1,"theme":"工作與職業","examples":[{"en":"She dreams of becoming a famous singer someday.","zh":"她夢想有一天能成為一位知名歌手。"},{"en":"The lead singer of the band has a powerful voice.","zh":"這個樂團的主唱有一副強而有力的嗓音。"},{"en":"Many young people dream of becoming a famous singer.","zh":"許多年輕人夢想成為知名歌手。"}]},{"word":"single","pos":"adj. / n.","phonetic":"[ˈsɪŋgl̩]","meaning":"單一的；單身的；單曲","definition":"only one; not married","collocations":["a single room","stay single","every single day"],"example":"He has remained single for several years.","exampleZh":"他已經單身好幾年了。","synonyms":["sole"],"level":2,"theme":"人物與家庭","examples":[{"en":"He has remained single for several years.","zh":"他已經單身好幾年了。"},{"en":"I booked a single room at the hotel for the night.","zh":"我在旅館訂了一間單人房過夜。"},{"en":"He answered every single question correctly on the quiz.","zh":"小考的每一道題目他都答對了。"}]},{"word":"sink","pos":"v. / n.","phonetic":"[sɪŋk]","meaning":"下沉；沉沒；水槽","definition":"to go down below the surface of water; a basin for washing","collocations":["sink to the bottom","kitchen sink","a sinking feeling"],"example":"The ship began to sink after hitting the rocks.","exampleZh":"這艘船撞上礁石後開始下沉。","synonyms":[],"level":2,"theme":"自然與環境","examples":[{"en":"The ship began to sink after hitting the rocks.","zh":"這艘船撞上礁石後開始下沉。"},{"en":"The heavy stone quickly sank to the bottom of the lake.","zh":"沉重的石頭很快沉到湖底。"},{"en":"She washed the dirty dishes in the kitchen sink.","zh":"她在廚房水槽裡洗髒盤子。"}]},{"word":"sip","pos":"v. / n.","phonetic":"[sɪp]","meaning":"啜飲；小口喝","definition":"to drink something slowly, taking small amounts","collocations":["sip coffee","take a sip","sip slowly"],"example":"She sipped her tea while reading the newspaper.","exampleZh":"她一邊啜飲茶一邊看報紙。","synonyms":["drink"],"level":2,"theme":"食物與烹飪","examples":[{"en":"She sipped her tea while reading the newspaper.","zh":"她一邊啜飲茶一邊看報紙。"},{"en":"He slowly sipped his hot coffee while reading a book.","zh":"他一邊看書一邊慢慢啜飲熱咖啡。"},{"en":"She took a small sip of the soup to test its flavor.","zh":"她小口喝了一口湯來試味道。"}]},{"word":"siren","pos":"n.","phonetic":"[ˈsaɪrən]","meaning":"警報器；警笛","definition":"a device that makes a loud warning sound","collocations":["a police siren","sound the siren","an air raid siren"],"example":"We heard a siren as the ambulance rushed past.","exampleZh":"救護車呼嘯而過時我們聽到了警笛聲。","synonyms":["alarm"],"level":4,"theme":"科技與媒體","examples":[{"en":"We heard a siren as the ambulance rushed past.","zh":"救護車呼嘯而過時我們聽到了警笛聲。"},{"en":"We stepped aside when we heard the loud police siren.","zh":"當我們聽到響亮的警笛聲時就靠邊站。"},{"en":"The fire truck raced past with its siren wailing.","zh":"消防車鳴著警笛飛快地駛過。"}]},{"word":"sister","pos":"n.","phonetic":"[ˈsɪstɚ]","meaning":"姊妹","definition":"a girl or woman with the same parents as another person","collocations":["older sister","younger sister","sister city"],"example":"My sister and I share a room.","exampleZh":"我和我姊姊共用一間房間。","synonyms":[],"level":1,"theme":"人物與家庭","examples":[{"en":"My sister and I share a room.","zh":"我和我姊姊共用一間房間。"},{"en":"My older sister helps me with my homework every night.","zh":"我姊姊每天晚上幫我做功課。"},{"en":"Her younger sister just started attending primary school.","zh":"她妹妹剛開始上小學。"}]},{"word":"sit","pos":"v.","phonetic":"[sɪt]","meaning":"坐；位於","definition":"to be in a position where the body is supported on the buttocks","collocations":["sit down","sit still","sit on the fence"],"example":"Please sit down and make yourself comfortable.","exampleZh":"請坐下，不要拘束。","synonyms":[],"level":1,"theme":"動作與行為","examples":[{"en":"Please sit down and make yourself comfortable.","zh":"請坐下，不要拘束。"},{"en":"Please sit still while the photographer takes the picture.","zh":"攝影師拍照時請坐著別動。"},{"en":"The children sat quietly and listened to the story.","zh":"孩子們安靜地坐著聽故事。"}]},{"word":"site","pos":"n.","phonetic":"[saɪt]","meaning":"地點；場所；網站","definition":"a place where something is located or happens","collocations":["a construction site","a website","the site of the battle"],"example":"The company built a new factory on this site.","exampleZh":"這家公司在這個地點蓋了一座新工廠。","synonyms":["location"],"level":3,"theme":"時間與空間","examples":[{"en":"The company built a new factory on this site.","zh":"這家公司在這個地點蓋了一座新工廠。"},{"en":"Workers are busy building a new hospital on this site.","zh":"工人們正忙著在這個地點興建一座新醫院。"},{"en":"You can find more details on the school's official website.","zh":"你可以在學校的官方網站上找到更多細節。"}]},{"word":"situation","pos":"n.","phonetic":"[ˌsɪtʃuˈeʃən]","meaning":"情況；處境","definition":"the set of circumstances that a person is in at a particular time","collocations":["a difficult situation","handle the situation","the current situation"],"example":"We need to find a solution to this difficult situation.","exampleZh":"我們需要找到解決這個困境的方法。","synonyms":["circumstance"],"level":3,"theme":"抽象概念","examples":[{"en":"We need to find a solution to this difficult situation.","zh":"我們需要找到解決這個困境的方法。"},{"en":"The teacher calmly handled the difficult situation in class.","zh":"老師冷靜地處理了課堂上的棘手情況。"},{"en":"We must think carefully before acting in this situation.","zh":"在這種情況下我們必須先仔細思考再行動。"}]},{"word":"size","pos":"n.","phonetic":"[saɪz]","meaning":"尺寸；大小；尺碼","definition":"the measurement or dimensions of something","collocations":["shoe size","the size of","a large size"],"example":"What size shoes do you wear?","exampleZh":"你穿幾號的鞋子？","synonyms":[],"level":1,"theme":"性質與描述","examples":[{"en":"What size shoes do you wear?","zh":"你穿幾號的鞋子？"},{"en":"Do you have these shoes in a larger size?","zh":"這雙鞋你們有大一號的尺碼嗎？"},{"en":"The size of the new stadium truly surprised everyone.","zh":"新體育場的規模真的讓所有人都驚訝。"}]},{"word":"sketch","pos":"n. / v.","phonetic":"[skɛtʃ]","meaning":"素描；草圖；草擬","definition":"a quick, rough drawing, or to draw one","collocations":["sketch a picture","a rough sketch","sketch out a plan"],"example":"The artist sketched the mountains in his notebook.","exampleZh":"畫家在他的筆記本上素描了山景。","synonyms":["draft"],"level":4,"theme":"藝術與音樂","examples":[{"en":"The artist sketched the mountains in his notebook.","zh":"畫家在他的筆記本上素描了山景。"},{"en":"The artist quickly sketched the busy street in her notebook.","zh":"藝術家在她的筆記本上快速畫下繁忙的街道。"},{"en":"Let's sketch out a plan before we start the project.","zh":"在開始這個專案前，我們先草擬一個計畫。"}]},{"word":"ski","pos":"v. / n.","phonetic":"[ski]","meaning":"滑雪","definition":"to move over snow on long narrow boards attached to the feet","collocations":["ski down a slope","go skiing","ski resort"],"example":"They went skiing in the Alps last winter.","exampleZh":"他們去年冬天去阿爾卑斯山滑雪。","synonyms":[],"level":2,"theme":"運動與休閒","examples":[{"en":"They went skiing in the Alps last winter.","zh":"他們去年冬天去阿爾卑斯山滑雪。"},{"en":"We plan to ski down the gentle slope near the resort.","zh":"我們打算沿著度假村附近平緩的斜坡滑雪而下。"},{"en":"My brother learned to ski when he was only six.","zh":"我哥哥六歲時就學會了滑雪。"}]},{"word":"skill","pos":"n.","phonetic":"[skɪl]","meaning":"技巧；技能","definition":"the ability to do something well, gained through training or practice","collocations":["a useful skill","develop skills","communication skills"],"example":"Learning a new language requires patience and skill.","exampleZh":"學習一門新語言需要耐心和技巧。","synonyms":["ability"],"level":2,"theme":"教育與學習","examples":[{"en":"Learning a new language requires patience and skill.","zh":"學習一門新語言需要耐心和技巧。"},{"en":"Good communication skills will help you in almost any job.","zh":"良好的溝通技巧幾乎在任何工作中都能幫助你。"},{"en":"It takes years of practice to develop this useful skill.","zh":"要培養這項實用的技能需要多年的練習。"}]},{"word":"skilled","pos":"adj.","phonetic":"[skɪld]","meaning":"熟練的；有技術的","definition":"having the ability and experience to do something well","collocations":["a skilled worker","highly skilled","skilled labor"],"example":"They need skilled workers to build the new bridge.","exampleZh":"他們需要熟練的工人來建造這座新橋。","synonyms":["expert"],"level":3,"theme":"工作與職業","examples":[{"en":"They need skilled workers to build the new bridge.","zh":"他們需要熟練的工人來建造這座新橋。"},{"en":"The factory hires highly skilled workers to operate the machines.","zh":"這家工廠雇用技術純熟的工人來操作機器。"},{"en":"A skilled teacher can explain difficult ideas in simple ways.","zh":"熟練的老師能用簡單的方式解釋艱深的概念。"}]},{"word":"skillful","pos":"adj.","phonetic":"[ˈskɪlfəl]","meaning":"熟練的；靈巧的","definition":"having or showing great skill","collocations":["a skillful player","skillful hands","skillful at"],"example":"She is a skillful painter with many years of experience.","exampleZh":"她是一位經驗豐富、技巧純熟的畫家。","synonyms":["skilled"],"level":4,"theme":"性質與描述","examples":[{"en":"She is a skillful painter with many years of experience.","zh":"她是一位經驗豐富、技巧純熟的畫家。"},{"en":"The skillful goalkeeper stopped almost every shot during the match.","zh":"這位技術高超的守門員在比賽中幾乎擋下了每一球。"},{"en":"She is very skillful at repairing old clocks by hand.","zh":"她非常擅長用手修理老舊的時鐘。"}]},{"word":"skin","pos":"n.","phonetic":"[skɪn]","meaning":"皮膚；皮革","definition":"the natural outer layer covering a person or animal's body","collocations":["dry skin","skin care","under the skin"],"example":"Use sunscreen to protect your skin from the sun.","exampleZh":"使用防曬乳來保護你的皮膚免受陽光傷害。","synonyms":[],"level":2,"theme":"身體與健康","examples":[{"en":"Use sunscreen to protect your skin from the sun.","zh":"使用防曬乳來保護你的皮膚免受陽光傷害。"},{"en":"Drinking enough water keeps your skin healthy and smooth.","zh":"喝足夠的水能讓你的皮膚保持健康光滑。"},{"en":"Cold winter air can easily make your skin dry.","zh":"寒冷的冬天空氣很容易讓你的皮膚變乾。"}]},{"word":"skip","pos":"v. / n.","phonetic":"[skɪp]","meaning":"跳過；蹦跳；略過","definition":"to move quickly with jumps, or to leave something out","collocations":["skip breakfast","skip a class","skip rope"],"example":"He often skips breakfast because he wakes up late.","exampleZh":"他常常因為晚起而跳過早餐。","synonyms":["hop","omit"],"level":2,"theme":"動作與行為","examples":[{"en":"He often skips breakfast because he wakes up late.","zh":"他常常因為晚起而跳過早餐。"},{"en":"You should never skip breakfast before an important exam.","zh":"在重要考試前你絕不該不吃早餐。"},{"en":"The little girl skipped happily across the grassy field.","zh":"小女孩在草地上開心地蹦蹦跳跳。"}]},{"word":"skirt","pos":"n.","phonetic":"[skɝt]","meaning":"裙子","definition":"a piece of clothing that hangs from the waist","collocations":["a long skirt","a mini skirt","wear a skirt"],"example":"She wore a pretty floral skirt to school.","exampleZh":"她穿了一件漂亮的花裙子去上學。","synonyms":[],"level":1,"theme":"服裝與外表","examples":[{"en":"She wore a pretty floral skirt to school.","zh":"她穿了一件漂亮的花裙子去上學。"},{"en":"She chose a long skirt to wear to the concert.","zh":"她選了一條長裙去參加音樂會。"},{"en":"The dancers all wore matching red skirts on stage.","zh":"舞者們在舞台上都穿著成套的紅色裙子。"}]},{"word":"skull","pos":"n.","phonetic":"[skʌl]","meaning":"頭骨；頭蓋骨","definition":"the bony structure of the head that protects the brain","collocations":["a human skull","skull and crossbones","fracture the skull"],"example":"The museum displayed an ancient human skull.","exampleZh":"博物館展示了一個古代人類的頭骨。","synonyms":[],"level":4,"theme":"身體與健康","examples":[{"en":"The museum displayed an ancient human skull.","zh":"博物館展示了一個古代人類的頭骨。"},{"en":"The helmet protects the skull during a serious fall.","zh":"安全帽在嚴重跌倒時能保護頭骨。"},{"en":"Scientists studied the ancient skull to learn about early humans.","zh":"科學家研究這個古老的頭骨,以了解早期人類。"}]},{"word":"sky","pos":"n.","phonetic":"[skaɪ]","meaning":"天空","definition":"the space above the earth where clouds and the sun appear","collocations":["blue sky","the night sky","sky-high"],"example":"The sky turned orange as the sun set.","exampleZh":"太陽下山時天空變成了橙色。","synonyms":[],"level":1,"theme":"自然與環境","examples":[{"en":"The sky turned orange as the sun set.","zh":"太陽下山時天空變成了橙色。"},{"en":"We lay on the grass and watched the night sky.","zh":"我們躺在草地上,看著夜空。"},{"en":"A clear blue sky made the perfect day for hiking.","zh":"晴朗的藍天使這一天成為健行的最佳日子。"}]},{"word":"slam","pos":"v. / n.","phonetic":"[slæm]","meaning":"猛力關上；重擊","definition":"to shut something forcefully and loudly","collocations":["slam the door","slam on the brakes","slam down"],"example":"He slammed the door in anger and left.","exampleZh":"他生氣地用力甩上門離開了。","synonyms":["bang"],"level":4,"theme":"動作與行為","examples":[{"en":"He slammed the door in anger and left.","zh":"他生氣地用力甩上門離開了。"},{"en":"The driver had to slam on the brakes suddenly.","zh":"駕駛人不得不突然猛踩剎車。"},{"en":"Please don't slam the door when you leave the room.","zh":"離開房間時請不要用力甩門。"}]},{"word":"slang","pos":"n.","phonetic":"[slæŋ]","meaning":"俚語；俗語","definition":"very informal language used mainly in speech","collocations":["use slang","teenage slang","slang words"],"example":"Young people often use slang that adults don't understand.","exampleZh":"年輕人常使用大人聽不懂的俚語。","synonyms":[],"level":4,"theme":"溝通與語言","examples":[{"en":"Young people often use slang that adults don't understand.","zh":"年輕人常使用大人聽不懂的俚語。"},{"en":"Teachers usually ask students not to use slang in essays.","zh":"老師通常會要求學生不要在作文中使用俚語。"},{"en":"Many slang words become popular for only a short time.","zh":"許多俚語只流行一小段時間。"}]},{"word":"slap","pos":"v. / n.","phonetic":"[slæp]","meaning":"掌摑；拍打","definition":"to hit someone or something with the open hand","collocations":["slap someone's face","a slap on the back","slap the table"],"example":"She slapped the mosquito on her arm.","exampleZh":"她拍打了手臂上的蚊子。","synonyms":["smack"],"level":4,"theme":"動作與行為","examples":[{"en":"She slapped the mosquito on her arm.","zh":"她拍打了手臂上的蚊子。"},{"en":"He gave his friend a friendly slap on the back.","zh":"他友善地拍了朋友的背一下。"},{"en":"The waves slapped gently against the side of the boat.","zh":"海浪輕輕地拍打著船身。"}]},{"word":"slave","pos":"n.","phonetic":"[slev]","meaning":"奴隸","definition":"a person who is legally owned by another and forced to work","collocations":["a former slave","slave labor","slave to habit"],"example":"The novel tells the story of a slave seeking freedom.","exampleZh":"這本小說講述一個奴隸尋求自由的故事。","synonyms":[],"level":5,"theme":"社會與文化","examples":[{"en":"The novel tells the story of a slave seeking freedom.","zh":"這本小說講述一個奴隸尋求自由的故事。"},{"en":"The museum explains how former slaves fought for their freedom.","zh":"博物館解說了昔日的奴隸如何為自由而奮鬥。"},{"en":"Don't become a slave to your smartphone every day.","zh":"別讓自己每天都成為智慧型手機的奴隸。"}]},{"word":"sled","pos":"n. / v.","phonetic":"[slɛd]","meaning":"雪橇","definition":"a vehicle used for traveling over snow or ice","collocations":["ride a sled","pull a sled","go sledding"],"example":"The children rode a sled down the snowy hill.","exampleZh":"孩子們坐著雪橇滑下積雪的山坡。","synonyms":[],"level":3,"theme":"運動與休閒","examples":[{"en":"The children rode a sled down the snowy hill.","zh":"孩子們坐著雪橇滑下積雪的山坡。"},{"en":"Two dogs pulled the sled across the frozen lake.","zh":"兩隻狗拉著雪橇越過結冰的湖面。"},{"en":"We went sledding all morning on the snowy hillside.","zh":"我們整個早上都在積雪的山坡上玩雪橇。"}]},{"word":"sleep","pos":"v. / n.","phonetic":"[slip]","meaning":"睡覺；睡眠","definition":"to rest with the eyes closed and the mind unconscious","collocations":["fall asleep","a good night's sleep","sleep late"],"example":"You should get enough sleep every night.","exampleZh":"你每晚應該有充足的睡眠。","synonyms":["rest"],"level":1,"theme":"身體與健康","examples":[{"en":"You should get enough sleep every night.","zh":"你每晚應該有充足的睡眠。"},{"en":"A good night's sleep helps you focus better at school.","zh":"睡個好覺能幫助你在學校更專注。"},{"en":"The baby finally fell asleep after a warm bath.","zh":"寶寶洗完溫水澡後終於睡著了。"}]},{"word":"sleepy","pos":"adj.","phonetic":"[ˈslipi]","meaning":"想睡的；睏倦的","definition":"feeling ready to sleep; tired","collocations":["feel sleepy","a sleepy town","sleepy eyes"],"example":"I felt sleepy after eating a big lunch.","exampleZh":"吃完豐盛的午餐後我覺得很想睡。","synonyms":["tired","drowsy"],"level":2,"theme":"身體與健康","examples":[{"en":"I felt sleepy after eating a big lunch.","zh":"吃完豐盛的午餐後我覺得很想睡。"},{"en":"The warm classroom made all the students feel sleepy.","zh":"溫暖的教室讓所有學生都感到昏昏欲睡。"},{"en":"We spent the weekend in a quiet, sleepy little town.","zh":"我們在一個安靜、沉寂的小鎮度過了週末。"}]},{"word":"sleeve","pos":"n.","phonetic":"[sliv]","meaning":"袖子","definition":"the part of a garment that covers the arm","collocations":["long sleeves","roll up sleeves","short-sleeved shirt"],"example":"He rolled up his sleeves before starting work.","exampleZh":"他開始工作前先捲起袖子。","synonyms":[],"level":3,"theme":"服裝與外表","examples":[{"en":"He rolled up his sleeves before starting work.","zh":"他開始工作前先捲起袖子。"},{"en":"He rolled up his sleeves to wash the dishes.","zh":"他捲起袖子去洗碗。"},{"en":"This shirt has long sleeves, perfect for cool evenings.","zh":"這件襯衫有長袖,很適合涼爽的夜晚。"}]},{"word":"slender","pos":"adj.","phonetic":"[ˈslɛndɚ]","meaning":"苗條的；纖細的","definition":"thin in an attractive or elegant way","collocations":["a slender figure","slender fingers","slender build"],"example":"The dancer had a tall, slender figure.","exampleZh":"這位舞者身材高挑苗條。","synonyms":["slim","thin"],"level":5,"theme":"服裝與外表","examples":[{"en":"The dancer had a tall, slender figure.","zh":"這位舞者身材高挑苗條。"},{"en":"The vase had a slender neck and a wide base.","zh":"這個花瓶有著細長的瓶頸和寬大的底座。"},{"en":"Her slender fingers moved gracefully across the piano keys.","zh":"她纖細的手指優雅地在鋼琴鍵上移動。"}]},{"word":"slice","pos":"n. / v.","phonetic":"[slaɪs]","meaning":"薄片；切片","definition":"a thin flat piece cut from something, or to cut it that way","collocations":["a slice of bread","slice into pieces","a slice of cake"],"example":"Would you like a slice of cake?","exampleZh":"你要來一片蛋糕嗎？","synonyms":["piece"],"level":2,"theme":"食物與烹飪","examples":[{"en":"Would you like a slice of cake?","zh":"你要來一片蛋糕嗎？"},{"en":"He cut the apple into thin slices for the salad.","zh":"他把蘋果切成薄片放進沙拉裡。"},{"en":"Please slice the bread before you make the sandwiches.","zh":"做三明治之前請先把麵包切片。"}]},{"word":"slide","pos":"v. / n.","phonetic":"[slaɪd]","meaning":"滑動；滑梯；投影片","definition":"to move smoothly along a surface, or a playground structure","collocations":["slide down","a water slide","a slide show"],"example":"The kids love to slide down the playground slide.","exampleZh":"孩子們喜歡從遊樂場的滑梯上滑下來。","synonyms":[],"level":2,"theme":"運動與休閒","examples":[{"en":"The kids love to slide down the playground slide.","zh":"孩子們喜歡從遊樂場的滑梯上滑下來。"},{"en":"The teacher showed a slide show about ocean animals.","zh":"老師播放了一場關於海洋動物的投影片。"},{"en":"The children took turns to slide down the water slide.","zh":"孩子們輪流從滑水道上滑下來。"}]},{"word":"slight","pos":"adj.","phonetic":"[slaɪt]","meaning":"輕微的；些微的","definition":"small in degree or amount","collocations":["a slight problem","a slight increase","not the slightest idea"],"example":"There was only a slight difference between the two designs.","exampleZh":"這兩個設計之間只有些微的差異。","synonyms":["minor"],"level":4,"theme":"性質與描述","examples":[{"en":"There was only a slight difference between the two designs.","zh":"這兩個設計之間只有些微的差異。"},{"en":"There was a slight increase in the price of vegetables.","zh":"蔬菜的價格有些微上漲。"},{"en":"I have not the slightest idea where my keys are.","zh":"我一點也不知道我的鑰匙在哪裡。"}]},{"word":"slightly","pos":"adv.","phonetic":"[ˈslaɪtli]","meaning":"稍微地；輕微地","definition":"to a small degree","collocations":["slightly different","slightly higher","slightly late"],"example":"The temperature is slightly higher than yesterday.","exampleZh":"今天的氣溫比昨天稍微高一些。","synonyms":["a little"],"level":4,"theme":"性質與描述","examples":[{"en":"The temperature is slightly higher than yesterday.","zh":"今天的氣溫比昨天稍微高一些。"},{"en":"This shirt is slightly too big for my younger brother.","zh":"這件襯衫對我弟弟來說稍微大了一點。"},{"en":"She arrived slightly late because the bus was delayed.","zh":"因為公車誤點,她稍微遲到了一點。"}]},{"word":"slim","pos":"adj. / v.","phonetic":"[slɪm]","meaning":"苗條的；纖細的；減肥","definition":"thin, often in a way that is attractive","collocations":["a slim chance","slim figure","slim down"],"example":"She has stayed slim by exercising regularly.","exampleZh":"她靠規律運動保持苗條的身材。","synonyms":["slender"],"level":3,"theme":"身體與健康","examples":[{"en":"She has stayed slim by exercising regularly.","zh":"她靠規律運動保持苗條的身材。"},{"en":"There is only a slim chance of rain this afternoon.","zh":"今天下午下雨的機會很小。"},{"en":"He tried to slim down by cycling to work each day.","zh":"他試著每天騎腳踏車上班來減重。"}]},{"word":"slip","pos":"v. / n.","phonetic":"[slɪp]","meaning":"滑倒；溜走；紙條","definition":"to slide accidentally and lose one's balance","collocations":["slip and fall","let it slip","a slip of paper"],"example":"Be careful not to slip on the wet floor.","exampleZh":"小心別在濕滑的地板上滑倒。","synonyms":["slide"],"level":2,"theme":"動作與行為","examples":[{"en":"Be careful not to slip on the wet floor.","zh":"小心別在濕滑的地板上滑倒。"},{"en":"She wrote the address on a small slip of paper.","zh":"她把地址寫在一張小紙條上。"},{"en":"He slipped on the icy steps but was not hurt.","zh":"他在結冰的階梯上滑了一跤,但沒有受傷。"}]},{"word":"slipper","pos":"n.","phonetic":"[ˈslɪpɚ]","meaning":"拖鞋","definition":"a light, soft shoe worn indoors","collocations":["a pair of slippers","house slippers","wear slippers"],"example":"She wore slippers around the house all evening.","exampleZh":"她整個晚上都在家裡穿著拖鞋。","synonyms":[],"level":2,"theme":"服裝與外表","examples":[{"en":"She wore slippers around the house all evening.","zh":"她整個晚上都在家裡穿著拖鞋。"},{"en":"I keep a soft pair of slippers by my bed.","zh":"我在床邊放了一雙柔軟的拖鞋。"},{"en":"Please wear house slippers when you come inside.","zh":"進屋時請穿上室內拖鞋。"}]},{"word":"slippery","pos":"adj.","phonetic":"[ˈslɪpəri]","meaning":"滑的；狡猾的","definition":"smooth and difficult to hold or stand on","collocations":["slippery floor","a slippery slope","slippery when wet"],"example":"Be careful, the road is slippery after the rain.","exampleZh":"下雨後路面很滑，小心一點。","synonyms":[],"level":3,"theme":"性質與描述","examples":[{"en":"Be careful, the road is slippery after the rain.","zh":"下雨後路面很滑，小心一點。"},{"en":"The kitchen floor becomes slippery when it is wet.","zh":"廚房的地板一濕就會變得很滑。"},{"en":"Skipping homework can be a slippery slope to bad grades.","zh":"不做作業可能是通往壞成績的滑坡。"}]},{"word":"slogan","pos":"n.","phonetic":"[ˈslogən]","meaning":"標語；口號","definition":"a short, easily remembered phrase used in advertising or politics","collocations":["an advertising slogan","a political slogan","catchy slogan"],"example":"The company created a catchy slogan for its new product.","exampleZh":"這家公司為新產品創造了一句朗朗上口的標語。","synonyms":[],"level":5,"theme":"商業與金錢","examples":[{"en":"The company created a catchy slogan for its new product.","zh":"這家公司為新產品創造了一句朗朗上口的標語。"},{"en":"The students painted a catchy slogan for the recycling campaign.","zh":"學生們為回收活動畫了一句朗朗上口的標語。"},{"en":"A good advertising slogan is short and easy to remember.","zh":"好的廣告標語簡短又容易記住。"}]},{"word":"slope","pos":"n. / v.","phonetic":"[slop]","meaning":"斜坡；坡度；傾斜","definition":"a surface with one end higher than the other","collocations":["a ski slope","a steep slope","slope downward"],"example":"They skied down the steep slope of the mountain.","exampleZh":"他們從陡峭的山坡滑雪而下。","synonyms":["incline"],"level":4,"theme":"自然與環境","examples":[{"en":"They skied down the steep slope of the mountain.","zh":"他們從陡峭的山坡滑雪而下。"},{"en":"The path followed a gentle slope down to the river.","zh":"這條小路沿著平緩的斜坡向下通往河邊。"},{"en":"Beginners should practice on a slope that is not too steep.","zh":"初學者應該在不太陡的斜坡上練習。"}]},{"word":"slow","pos":"adj. / v.","phonetic":"[slo]","meaning":"慢的；緩慢；使變慢","definition":"not fast; taking a long time","collocations":["slow down","a slow learner","slow traffic"],"example":"Please drive slowly on this narrow road.","exampleZh":"在這條狹窄的道路上請慢慢開車。","synonyms":[],"level":1,"theme":"性質與描述","examples":[{"en":"Please drive slowly on this narrow road.","zh":"在這條狹窄的道路上請慢慢開車。"},{"en":"Please slow down so we can enjoy the beautiful view.","zh":"請放慢速度,好讓我們欣賞美麗的景色。"},{"en":"Heavy rain caused slow traffic all across the city.","zh":"大雨造成全市交通緩慢。"}]},{"word":"slum","pos":"n.","phonetic":"[slʌm]","meaning":"貧民窟","definition":"a poor, crowded area of a city with bad housing conditions","collocations":["city slums","grow up in a slum","slum area"],"example":"He grew up in a slum on the edge of the city.","exampleZh":"他在城市邊緣的貧民窟長大。","synonyms":[],"level":6,"theme":"社會與文化","examples":[{"en":"He grew up in a slum on the edge of the city.","zh":"他在城市邊緣的貧民窟長大。"},{"en":"Volunteers built a small library in the crowded slum.","zh":"志工在擁擠的貧民窟裡蓋了一座小圖書館。"},{"en":"The charity works to improve housing in city slums.","zh":"這個慈善機構致力於改善城市貧民窟的住屋。"}]},{"word":"sly","pos":"adj.","phonetic":"[slaɪ]","meaning":"狡猾的；偷偷摸摸的","definition":"clever in a dishonest or secretive way","collocations":["a sly smile","a sly fox","sly comment"],"example":"He gave a sly smile before revealing his plan.","exampleZh":"他露出狡猾的微笑，才透露他的計畫。","synonyms":["cunning"],"level":5,"theme":"性質與描述","examples":[{"en":"He gave a sly smile before revealing his plan.","zh":"他露出狡猾的微笑，才透露他的計畫。"},{"en":"The sly fox quietly slipped past the sleeping guard dog.","zh":"狡猾的狐狸悄悄地溜過了熟睡的看門狗。"},{"en":"She made a sly comment that made everyone laugh.","zh":"她說了一句狡黠的評論,逗得大家都笑了。"}]},{"word":"small","pos":"adj.","phonetic":"[smɔl]","meaning":"小的；少的","definition":"not large in size or amount","collocations":["a small amount","small talk","a small business"],"example":"They live in a small apartment near the city center.","exampleZh":"他們住在市中心附近一間小公寓。","synonyms":["little"],"level":1,"theme":"性質與描述","examples":[{"en":"They live in a small apartment near the city center.","zh":"他們住在市中心附近一間小公寓。"},{"en":"They started a small business selling homemade cookies online.","zh":"他們開了一間在網路上賣自製餅乾的小生意。"},{"en":"We made small talk while waiting for the bus.","zh":"我們一邊等公車一邊閒聊。"}]},{"word":"smart","pos":"adj.","phonetic":"[smɑrt]","meaning":"聰明的；時髦的","definition":"having or showing intelligence; stylish","collocations":["a smart phone","smart move","dressed smart"],"example":"She is smart enough to solve this problem herself.","exampleZh":"她夠聰明，能自己解決這個問題。","synonyms":["clever","intelligent"],"level":1,"theme":"性質與描述","examples":[{"en":"She is smart enough to solve this problem herself.","zh":"她夠聰明，能自己解決這個問題。"},{"en":"Saving a little money each month is a smart move.","zh":"每個月存一點錢是明智之舉。"},{"en":"He looked very smart in his new suit and tie.","zh":"他穿著新西裝打著領帶,看起來非常體面。"}]},{"word":"smell","pos":"v. / n.","phonetic":"[smɛl]","meaning":"聞；氣味","definition":"to notice or examine an odor, or the odor itself","collocations":["smell good","a strong smell","smell of smoke"],"example":"The kitchen smells like fresh baked bread.","exampleZh":"廚房裡飄著剛烤好麵包的香味。","synonyms":["scent"],"level":1,"theme":"身體與健康","examples":[{"en":"The kitchen smells like fresh baked bread.","zh":"廚房裡飄著剛烤好麵包的香味。"},{"en":"The flowers in the garden smell wonderfully sweet.","zh":"花園裡的花聞起來甜美極了。"},{"en":"I noticed a strong smell of smoke in the hallway.","zh":"我注意到走廊裡有股濃濃的煙味。"}]},{"word":"smile","pos":"v. / n.","phonetic":"[smaɪl]","meaning":"微笑","definition":"to make a happy expression by turning up the corners of the mouth","collocations":["smile at","a warm smile","force a smile"],"example":"She smiled warmly when she saw her old friend.","exampleZh":"她看到老朋友時露出溫暖的微笑。","synonyms":["grin"],"level":1,"theme":"情緒與感受","examples":[{"en":"She smiled warmly when she saw her old friend.","zh":"她看到老朋友時露出溫暖的微笑。"},{"en":"The kind nurse gave the child a warm smile.","zh":"親切的護士對孩子露出溫暖的微笑。"},{"en":"He smiled at the stranger who helped him find the way.","zh":"他對那位幫他指路的陌生人微笑。"}]},{"word":"snack","pos":"n. / v.","phonetic":"[snæk]","meaning":"點心；小吃","definition":"a small amount of food eaten between meals","collocations":["grab a snack","snack bar","healthy snack","snack on chips"],"example":"I usually have a snack before dinner.","exampleZh":"我通常在晚餐前吃點心。","synonyms":["bite","nibble"],"level":1,"theme":"食物與烹飪","examples":[{"en":"I usually have a snack before dinner.","zh":"我通常在晚餐前吃點心。"},{"en":"She likes to snack on fresh fruit while studying.","zh":"她喜歡在讀書時吃新鮮水果當點心。"},{"en":"There is a small snack bar next to the library.","zh":"圖書館旁邊有一間小小的點心吧。"}]},{"word":"snail","pos":"n.","phonetic":"[snel]","meaning":"蝸牛","definition":"a small slow-moving animal with a spiral shell","collocations":["snail's pace","garden snail"],"example":"The snail moved slowly across the leaf.","exampleZh":"蝸牛緩慢地爬過葉子。","synonyms":[],"level":1,"theme":"動物與植物","examples":[{"en":"The snail moved slowly across the leaf.","zh":"蝸牛緩慢地爬過葉子。"},{"en":"After the rain, several snails appeared on the garden wall.","zh":"雨後,幾隻蝸牛出現在花園的牆上。"},{"en":"The old computer loaded pages at a snail's pace.","zh":"這台老舊的電腦以蝸牛般的速度載入網頁。"}]},{"word":"snake","pos":"n.","phonetic":"[snek]","meaning":"蛇","definition":"a long limbless reptile","collocations":["poisonous snake","snake bite","snake charmer"],"example":"A snake slid quietly through the grass.","exampleZh":"一條蛇悄悄地滑過草叢。","synonyms":["serpent"],"level":1,"theme":"動物與植物","examples":[{"en":"A snake slid quietly through the grass.","zh":"一條蛇悄悄地滑過草叢。"},{"en":"The guide warned us about poisonous snakes on the trail.","zh":"嚮導警告我們小路上有毒蛇。"},{"en":"A long green snake rested quietly on the warm rock.","zh":"一條長長的綠蛇靜靜地趴在溫暖的岩石上。"}]},{"word":"snap","pos":"v. / n.","phonetic":"[snæp]","meaning":"突然折斷；猛咬；拍照","definition":"to break suddenly with a sharp sound","collocations":["snap a photo","snap in half","snap at someone"],"example":"The dry branch snapped under his foot.","exampleZh":"乾樹枝在他腳下應聲折斷。","synonyms":["break","crack"],"level":2,"theme":"動作與行為","examples":[{"en":"The dry branch snapped under his foot.","zh":"乾樹枝在他腳下應聲折斷。"},{"en":"He stopped to snap a photo of the sunset.","zh":"他停下來拍了一張日落的照片。"},{"en":"The thin twig snapped in half when I stepped on it.","zh":"我一踩上去,細樹枝就折成兩半。"}]},{"word":"sneak","pos":"v.","phonetic":"[snik]","meaning":"偷偷地做；溜","definition":"to go somewhere secretly and quietly","collocations":["sneak out","sneak a peek","sneak in"],"example":"The children tried to sneak out of the house at midnight.","exampleZh":"孩子們試圖在半夜偷偷溜出屋子。","synonyms":["slip","creep"],"level":3,"theme":"動作與行為","examples":[{"en":"The children tried to sneak out of the house at midnight.","zh":"孩子們試圖在半夜偷偷溜出屋子。"},{"en":"She tried to sneak a peek at her birthday gift.","zh":"她試著偷看一眼她的生日禮物。"},{"en":"The cat sneaked into the kitchen to find some food.","zh":"貓咪偷偷溜進廚房尋找食物。"}]},{"word":"sneeze","pos":"v. / n.","phonetic":"[sniz]","meaning":"打噴嚏","definition":"to force air out through the nose suddenly and uncontrollably","collocations":["sneeze loudly","cover a sneeze"],"example":"The dust made her sneeze several times.","exampleZh":"灰塵讓她連續打了好幾個噴嚏。","synonyms":[],"level":2,"theme":"身體與健康","examples":[{"en":"The dust made her sneeze several times.","zh":"灰塵讓她連續打了好幾個噴嚏。"},{"en":"The pepper made me sneeze loudly at the table.","zh":"胡椒讓我在餐桌上大聲打了噴嚏。"},{"en":"Please cover your mouth whenever you sneeze or cough.","zh":"每當你打噴嚏或咳嗽時,請摀住嘴巴。"}]},{"word":"sniff","pos":"v. / n.","phonetic":"[snɪf]","meaning":"嗅；聞","definition":"to breathe in air through the nose in short breaths, often to smell something","collocations":["sniff the air","sniff out","take a sniff"],"example":"The dog sniffed the ground looking for food.","exampleZh":"那隻狗嗅著地面尋找食物。","synonyms":["smell"],"level":3,"theme":"動物與植物","examples":[{"en":"The dog sniffed the ground looking for food.","zh":"那隻狗嗅著地面尋找食物。"},{"en":"The puppy sniffed the air, hoping to smell dinner.","zh":"小狗嗅著空氣,希望能聞到晚餐的味道。"},{"en":"She took a quick sniff of the fresh coffee.","zh":"她快速地聞了一下新鮮咖啡的味道。"}]},{"word":"snore","pos":"v. / n.","phonetic":"[snɔr]","meaning":"打鼾","definition":"to breathe noisily through the nose while sleeping","collocations":["snore loudly","stop snoring"],"example":"My father snores so loudly that I can hear him next door.","exampleZh":"我爸爸打鼾很大聲,隔壁房間都聽得到。","synonyms":[],"level":3,"theme":"身體與健康","examples":[{"en":"My father snores so loudly that I can hear him next door.","zh":"我爸爸打鼾很大聲,隔壁房間都聽得到。"},{"en":"He was so tired that he began to snore loudly.","zh":"他累到開始大聲打鼾。"},{"en":"The doctor gave her advice on how to stop snoring.","zh":"醫生給了她如何停止打鼾的建議。"}]},{"word":"snow","pos":"n. / v.","phonetic":"[sno]","meaning":"雪；下雪","definition":"soft white flakes of frozen water that fall from the sky","collocations":["heavy snow","snow falls","snow-covered"],"example":"It started to snow early this morning.","exampleZh":"今天一大早就開始下雪了。","synonyms":[],"level":1,"theme":"天氣與季節","examples":[{"en":"It started to snow early this morning.","zh":"今天一大早就開始下雪了。"},{"en":"Heavy snow covered the whole village overnight.","zh":"大雪在一夜之間覆蓋了整個村莊。"},{"en":"The children cheered when it began to snow outside.","zh":"當外面開始下雪時,孩子們歡呼起來。"}]},{"word":"snowy","pos":"adj.","phonetic":"[ˈsnoɪ]","meaning":"下雪的；多雪的","definition":"covered with or characterized by snow","collocations":["snowy weather","snowy mountain","snowy day"],"example":"We had a snowy winter this year.","exampleZh":"今年我們經歷了一個多雪的冬天。","synonyms":[],"level":2,"theme":"天氣與季節","examples":[{"en":"We had a snowy winter this year.","zh":"今年我們經歷了一個多雪的冬天。"},{"en":"We drove carefully along the snowy mountain road.","zh":"我們小心翼翼地沿著積雪的山路開車。"},{"en":"A snowy day is perfect for making a snowman.","zh":"下雪天最適合堆雪人了。"}]},{"word":"sob","pos":"v. / n.","phonetic":"[sɑb]","meaning":"啜泣；抽噎","definition":"to cry while breathing in short, sharp gasps","collocations":["sob quietly","burst into sobs"],"example":"She sobbed uncontrollably after hearing the sad news.","exampleZh":"聽到這個悲傷的消息後她忍不住啜泣。","synonyms":["weep","cry"],"level":4,"theme":"情緒與感受","examples":[{"en":"She sobbed uncontrollably after hearing the sad news.","zh":"聽到這個悲傷的消息後她忍不住啜泣。"},{"en":"The little boy began to sob quietly in the corner.","zh":"小男孩開始在角落裡默默啜泣。"},{"en":"She burst into sobs when she read the touching letter.","zh":"讀到那封感人的信時,她放聲哭泣起來。"}]},{"word":"social","pos":"adj.","phonetic":"[ˈsoʃəl]","meaning":"社會的；社交的","definition":"relating to society or to spending time with other people","collocations":["social media","social skills","social life"],"example":"She has a very active social life.","exampleZh":"她有非常活躍的社交生活。","synonyms":[],"level":2,"theme":"社會與文化","examples":[{"en":"She has a very active social life.","zh":"她有非常活躍的社交生活。"},{"en":"Joining a club is a great way to improve social skills.","zh":"加入社團是增進社交技巧的好方法。"},{"en":"Many teenagers spend too much time on social media.","zh":"許多青少年在社群媒體上花太多時間。"}]},{"word":"socialize","pos":"v.","phonetic":"[ˈsoʃəˌlaɪz]","meaning":"社交；與人交往","definition":"to spend time with others in a friendly way","collocations":["socialize with colleagues","socialize online"],"example":"He likes to socialize with new people at parties.","exampleZh":"他喜歡在派對上與新朋友交際。","synonyms":["mingle"],"level":4,"theme":"社會與文化","examples":[{"en":"He likes to socialize with new people at parties.","zh":"他喜歡在派對上與新朋友交際。"},{"en":"He enjoys taking time to socialize with his classmates.","zh":"他喜歡花時間和同學交際往來。"},{"en":"During the trip, we socialized with travelers from many countries.","zh":"旅途中,我們和來自許多國家的旅客交流往來。"}]},{"word":"society","pos":"n.","phonetic":"[səˈsaɪəti]","meaning":"社會；社團","definition":"people living together in an organized community","collocations":["modern society","member of society"],"example":"Technology has changed modern society greatly.","exampleZh":"科技大大改變了現代社會。","synonyms":[],"level":3,"theme":"社會與文化","examples":[{"en":"Technology has changed modern society greatly.","zh":"科技大大改變了現代社會。"},{"en":"Education plays an important role in modern society.","zh":"教育在現代社會中扮演重要的角色。"},{"en":"As a member of society, we should help those in need.","zh":"身為社會的一員,我們應該幫助有需要的人。"}]},{"word":"sock","pos":"n.","phonetic":"[sɑk]","meaning":"襪子","definition":"a piece of clothing worn on the foot, usually inside a shoe","collocations":["a pair of socks","wool socks"],"example":"He put on a clean pair of socks.","exampleZh":"他穿上一雙乾淨的襪子。","synonyms":[],"level":1,"theme":"服裝與外表","examples":[{"en":"He put on a clean pair of socks.","zh":"他穿上一雙乾淨的襪子。"},{"en":"In winter I like to wear thick wool socks.","zh":"冬天我喜歡穿厚厚的羊毛襪。"},{"en":"He could not find a matching pair of socks.","zh":"他找不到一雙成對的襪子。"}]},{"word":"soda","pos":"n.","phonetic":"[ˈsodə]","meaning":"蘇打水；汽水","definition":"a sweet fizzy drink","collocations":["soda pop","soda water","drink soda"],"example":"She ordered a cold soda with her lunch.","exampleZh":"她點了午餐配一杯冰涼的汽水。","synonyms":[],"level":1,"theme":"食物與烹飪","examples":[{"en":"She ordered a cold soda with her lunch.","zh":"她點了午餐配一杯冰涼的汽水。"},{"en":"Drinking too much soda is not good for your teeth.","zh":"喝太多汽水對你的牙齒不好。"},{"en":"She poured some soda water over a glass of ice.","zh":"她把一些蘇打水倒在一杯冰塊上。"}]},{"word":"sofa","pos":"n.","phonetic":"[ˈsofə]","meaning":"沙發","definition":"a long soft seat with a back and arms for two or more people","collocations":["sit on the sofa","sofa bed"],"example":"The whole family sat on the sofa watching TV.","exampleZh":"全家人坐在沙發上看電視。","synonyms":["couch"],"level":1,"theme":"居家與生活","examples":[{"en":"The whole family sat on the sofa watching TV.","zh":"全家人坐在沙發上看電視。"},{"en":"After a long day, he relaxed on the soft sofa.","zh":"忙了一整天後,他在柔軟的沙發上放鬆休息。"},{"en":"Their living room has a large sofa bed for guests.","zh":"他們的客廳有一張供客人使用的大沙發床。"}]},{"word":"soft","pos":"adj.","phonetic":"[sɔft]","meaning":"柔軟的；溫和的","definition":"not hard or firm to the touch; gentle","collocations":["soft voice","soft pillow","soft skin"],"example":"The kitten's fur felt very soft.","exampleZh":"小貓的毛摸起來非常柔軟。","synonyms":["gentle","tender"],"level":1,"theme":"性質與描述","examples":[{"en":"The kitten's fur felt very soft.","zh":"小貓的毛摸起來非常柔軟。"},{"en":"The teacher spoke in a soft voice to calm the class.","zh":"老師用溫柔的聲音說話,好讓班上安靜下來。"},{"en":"This new pillow is much softer than the old one.","zh":"這個新枕頭比舊的柔軟多了。"}]},{"word":"software","pos":"n.","phonetic":"[ˈsɔftˌwɛr]","meaning":"軟體","definition":"the programs and instructions used by a computer","collocations":["install software","software update"],"example":"The company develops software for schools.","exampleZh":"這家公司為學校開發軟體。","synonyms":[],"level":3,"theme":"科技與媒體","examples":[{"en":"The company develops software for schools.","zh":"這家公司為學校開發軟體。"},{"en":"You should update the software to fix the security problem.","zh":"你應該更新軟體來修復安全問題。"},{"en":"The students learned to install software on their own laptops.","zh":"學生們學會了在自己的筆記型電腦上安裝軟體。"}]},{"word":"soil","pos":"n.","phonetic":"[sɔɪl]","meaning":"土壤","definition":"the top layer of earth in which plants grow","collocations":["fertile soil","soil erosion"],"example":"The farmer checked the soil before planting seeds.","exampleZh":"農夫在播種前檢查了土壤。","synonyms":["earth","dirt"],"level":2,"theme":"自然與環境","examples":[{"en":"The farmer checked the soil before planting seeds.","zh":"農夫在播種前檢查了土壤。"},{"en":"Rich, fertile soil helps vegetables grow quickly.","zh":"肥沃的土壤有助於蔬菜快速生長。"},{"en":"Planting trees can help prevent soil erosion on the hills.","zh":"種樹有助於防止山坡上的土壤流失。"}]},{"word":"solar","pos":"adj.","phonetic":"[ˈsolɚ]","meaning":"太陽的；太陽能的","definition":"relating to the sun or energy obtained from it","collocations":["solar power","solar panel","solar system"],"example":"Many houses now use solar panels for electricity.","exampleZh":"現在很多房子使用太陽能板來發電。","synonyms":[],"level":3,"theme":"科學與數學","examples":[{"en":"Many houses now use solar panels for electricity.","zh":"現在很多房子使用太陽能板來發電。"},{"en":"The school installed solar panels to save on electricity.","zh":"學校裝設了太陽能板以節省電費。"},{"en":"Earth is one of the planets in the solar system.","zh":"地球是太陽系中的行星之一。"}]},{"word":"soldier","pos":"n.","phonetic":"[ˈsoldʒɚ]","meaning":"士兵；軍人","definition":"a member of an army","collocations":["brave soldier","soldiers on duty"],"example":"The soldier fought bravely for his country.","exampleZh":"這名士兵為國家英勇作戰。","synonyms":[],"level":2,"theme":"工作與職業","examples":[{"en":"The soldier fought bravely for his country.","zh":"這名士兵為國家英勇作戰。"},{"en":"The young soldier wrote letters home every week.","zh":"這名年輕的士兵每週都寫信回家。"},{"en":"Many soldiers were on duty during the national holiday.","zh":"許多軍人在國定假日期間執勤。"}]},{"word":"solemn","pos":"adj.","phonetic":"[ˈsɑləm]","meaning":"莊嚴的；嚴肅的","definition":"very serious and formal","collocations":["solemn promise","solemn ceremony"],"example":"The judge made a solemn promise to be fair.","exampleZh":"法官莊嚴地承諾要保持公正。","synonyms":["serious","grave"],"level":5,"theme":"性質與描述","examples":[{"en":"The judge made a solemn promise to be fair.","zh":"法官莊嚴地承諾要保持公正。"},{"en":"Everyone stayed quiet during the solemn ceremony.","zh":"在莊嚴的典禮中,每個人都保持安靜。"},{"en":"He made a solemn promise to take care of the dog.","zh":"他鄭重地承諾要照顧那隻狗。"}]},{"word":"solid","pos":"adj. / n.","phonetic":"[ˈsɑlɪd]","meaning":"固體的；堅固的；固體","definition":"hard or firm; not liquid or gas","collocations":["solid ground","solid evidence","turn into a solid"],"example":"Water becomes solid when it freezes.","exampleZh":"水結凍後會變成固體。","synonyms":["firm","sturdy"],"level":2,"theme":"科學與數學","examples":[{"en":"Water becomes solid when it freezes.","zh":"水結凍後會變成固體。"},{"en":"The builders made sure the house stood on solid ground.","zh":"建築工人確保房子建在堅固的地基上。"},{"en":"The scientists needed solid evidence to support their theory.","zh":"科學家需要確鑿的證據來支持他們的理論。"}]},{"word":"solitary","pos":"adj.","phonetic":"[ˈsɑləˌtɛri]","meaning":"孤獨的；單獨的","definition":"alone; without the company of others","collocations":["solitary life","solitary confinement"],"example":"He led a solitary life in the mountains.","exampleZh":"他在山中過著孤獨的生活。","synonyms":["lonely","alone"],"level":5,"theme":"情緒與感受","examples":[{"en":"He led a solitary life in the mountains.","zh":"他在山中過著孤獨的生活。"},{"en":"The writer preferred a solitary life in the countryside.","zh":"這位作家偏好在鄉間過孤獨的生活。"},{"en":"A single solitary tree stood in the middle of the field.","zh":"一棵孤零零的樹立在田地中央。"}]},{"word":"solo","pos":"adj. / n. / adv.","phonetic":"[ˈsolo]","meaning":"單獨的；獨奏(曲)","definition":"done alone, especially a musical performance","collocations":["solo performance","fly solo","guitar solo"],"example":"She performed a beautiful piano solo.","exampleZh":"她演奏了一段優美的鋼琴獨奏。","synonyms":[],"level":4,"theme":"藝術與音樂","examples":[{"en":"She performed a beautiful piano solo.","zh":"她演奏了一段優美的鋼琴獨奏。"},{"en":"The young musician played a lovely violin solo.","zh":"這位年輕的音樂家演奏了一段動聽的小提琴獨奏。"},{"en":"After months of training, the pilot finally flew solo.","zh":"經過幾個月的訓練,這名飛行員終於單獨飛行。"}]},{"word":"solution","pos":"n.","phonetic":"[səˈluʃən]","meaning":"解決方案；答案","definition":"a way of solving a problem","collocations":["find a solution","practical solution"],"example":"We need to find a solution to this problem quickly.","exampleZh":"我們需要快點找到這個問題的解決方案。","synonyms":["answer","remedy"],"level":3,"theme":"抽象概念","examples":[{"en":"We need to find a solution to this problem quickly.","zh":"我們需要快點找到這個問題的解決方案。"},{"en":"The engineers found a practical solution to the water shortage.","zh":"工程師找到了解決缺水問題的實用方法。"},{"en":"Talking calmly is often the best solution to an argument.","zh":"冷靜地談話往往是解決爭吵的最佳辦法。"}]},{"word":"solve","pos":"v.","phonetic":"[sɑlv]","meaning":"解決；解答","definition":"to find an answer to or a way of dealing with a problem","collocations":["solve a problem","solve a mystery"],"example":"The detective solved the mystery in a week.","exampleZh":"偵探在一週內解開了這個謎團。","synonyms":["resolve"],"level":2,"theme":"動作與行為","examples":[{"en":"The detective solved the mystery in a week.","zh":"偵探在一週內解開了這個謎團。"},{"en":"Working together, they quickly solved the difficult math problem.","zh":"他們合力很快就解開了這道困難的數學題。"},{"en":"The clever detective solved the mystery within a few days.","zh":"聰明的偵探在幾天內就破解了這個謎團。"}]},{"word":"somebody","pos":"pron.","phonetic":"[ˈsʌmˌbɑdi]","meaning":"某人","definition":"some person; an unspecified or unknown person","collocations":["somebody else","somebody important"],"example":"Somebody left their umbrella on the bus.","exampleZh":"有人把雨傘忘在公車上了。","synonyms":["someone"],"level":1,"theme":"溝通與語言","examples":[{"en":"Somebody left their umbrella on the bus.","zh":"有人把雨傘忘在公車上了。"},{"en":"Somebody must have moved my bag while I was away.","zh":"我不在的時候一定有人動了我的包包。"},{"en":"If you need help, ask somebody at the front desk.","zh":"如果你需要幫忙,可以問櫃台的某個人。"}]},{"word":"somehow","pos":"adv.","phonetic":"[ˈsʌmˌhaʊ]","meaning":"不知怎麼地；設法","definition":"in a way that is not known or specified","collocations":["somehow manage","somehow feel"],"example":"We somehow managed to finish the project on time.","exampleZh":"我們不知怎麼地設法準時完成了專案。","synonyms":[],"level":3,"theme":"溝通與語言","examples":[{"en":"We somehow managed to finish the project on time.","zh":"我們不知怎麼地設法準時完成了專案。"},{"en":"We somehow found our way back in the thick fog.","zh":"在濃霧中我們設法找到了回去的路。"},{"en":"Somehow this old song always makes me feel happy.","zh":"不知怎麼地,這首老歌總是讓我感到開心。"}]},{"word":"someone","pos":"pron.","phonetic":"[ˈsʌmˌwʌn]","meaning":"某人","definition":"some person, not known or specified","collocations":["someone special","someone else"],"example":"Someone called while you were out.","exampleZh":"你出去的時候有人打電話來。","synonyms":["somebody"],"level":1,"theme":"溝通與語言","examples":[{"en":"Someone called while you were out.","zh":"你出去的時候有人打電話來。"},{"en":"She hopes to meet someone special at the school dance.","zh":"她希望在學校舞會上遇見某個特別的人。"},{"en":"Someone left a kind note on my desk this morning.","zh":"今天早上有人在我桌上留了一張親切的字條。"}]},{"word":"something","pos":"pron.","phonetic":"[ˈsʌmθɪŋ]","meaning":"某事物","definition":"a thing that is not specified or known","collocations":["something wrong","something new"],"example":"There is something strange about this house.","exampleZh":"這棟房子有些奇怪之處。","synonyms":[],"level":1,"theme":"溝通與語言","examples":[{"en":"There is something strange about this house.","zh":"這棟房子有些奇怪之處。"},{"en":"I want to try something new for lunch today.","zh":"我今天想在午餐嚐試點新東西。"},{"en":"There is clearly something wrong with the old printer.","zh":"這台舊印表機顯然出了什麼問題。"}]},{"word":"sometimes","pos":"adv.","phonetic":"[ˈsʌmˌtaɪmz]","meaning":"有時候","definition":"on some occasions; not always","collocations":["sometimes happens","sometimes feel"],"example":"Sometimes I like to walk to school instead of taking the bus.","exampleZh":"有時候我喜歡走路上學而不是搭公車。","synonyms":["occasionally"],"level":1,"theme":"時間與空間","examples":[{"en":"Sometimes I like to walk to school instead of taking the bus.","zh":"有時候我喜歡走路上學而不是搭公車。"},{"en":"Sometimes the best ideas come when you least expect them.","zh":"有時候最好的點子會在你最意想不到時出現。"},{"en":"He sometimes stays after class to ask the teacher questions.","zh":"他有時會在下課後留下來問老師問題。"}]},{"word":"somewhat","pos":"adv.","phonetic":"[ˈsʌmˌhwʌt]","meaning":"有點；稍微","definition":"to some extent; rather","collocations":["somewhat surprised","somewhat difficult"],"example":"The test was somewhat harder than I expected.","exampleZh":"這次考試比我預期的稍微難一些。","synonyms":["rather","fairly"],"level":4,"theme":"性質與描述","examples":[{"en":"The test was somewhat harder than I expected.","zh":"這次考試比我預期的稍微難一些。"},{"en":"I was somewhat surprised to see how much you had grown.","zh":"看到你長這麼大,我有點驚訝。"},{"en":"The instructions were somewhat difficult to follow at first.","zh":"這些說明一開始有點難以理解。"}]},{"word":"somewhere","pos":"adv.","phonetic":"[ˈsʌmˌhwɛr]","meaning":"某處","definition":"in, at, or to some place not known or specified","collocations":["somewhere nearby","somewhere else"],"example":"I've seen that man somewhere before.","exampleZh":"我以前在某個地方見過那個人。","synonyms":[],"level":2,"theme":"時間與空間","examples":[{"en":"I've seen that man somewhere before.","zh":"我以前在某個地方見過那個人。"},{"en":"Let's find somewhere quiet nearby to finish our homework.","zh":"我們去附近找個安靜的地方把作業寫完吧。"},{"en":"I left my umbrella somewhere in the classroom.","zh":"我把雨傘忘在教室某個地方了。"}]},{"word":"son","pos":"n.","phonetic":"[sʌn]","meaning":"兒子","definition":"a male child in relation to his parents","collocations":["eldest son","son and daughter"],"example":"Their son just started college this year.","exampleZh":"他們的兒子今年剛上大學。","synonyms":[],"level":1,"theme":"人物與家庭","examples":[{"en":"Their son just started college this year.","zh":"他們的兒子今年剛上大學。"},{"en":"Their eldest son helps look after his little sister.","zh":"他們的長子幫忙照顧他的小妹妹。"},{"en":"The proud father watched his son receive the award.","zh":"驕傲的父親看著兒子領獎。"}]},{"word":"song","pos":"n.","phonetic":"[sɔŋ]","meaning":"歌曲","definition":"a piece of music with words that is sung","collocations":["sing a song","favorite song"],"example":"She wrote a song about her hometown.","exampleZh":"她寫了一首關於家鄉的歌。","synonyms":["tune"],"level":1,"theme":"藝術與音樂","examples":[{"en":"She wrote a song about her hometown.","zh":"她寫了一首關於家鄉的歌。"},{"en":"The whole class sang a cheerful song together.","zh":"全班一起唱了一首歡樂的歌曲。"},{"en":"This is my favorite song to listen to while jogging.","zh":"這是我慢跑時最愛聽的歌曲。"}]},{"word":"soon","pos":"adv.","phonetic":"[sun]","meaning":"不久；很快","definition":"in a short time from now","collocations":["as soon as possible","come soon"],"example":"I hope to see you again soon.","exampleZh":"希望能很快再見到你。","synonyms":["shortly"],"level":1,"theme":"時間與空間","examples":[{"en":"I hope to see you again soon.","zh":"希望能很快再見到你。"},{"en":"Please finish your report as soon as possible.","zh":"請盡快完成你的報告。"},{"en":"The bus should arrive quite soon, so let's wait here.","zh":"公車應該很快就到了,我們在這裡等吧。"}]},{"word":"soothe","pos":"v.","phonetic":"[suð]","meaning":"安撫；緩和","definition":"to make someone calm, or to relieve pain","collocations":["soothe a baby","soothe pain"],"example":"The mother sang softly to soothe her crying baby.","exampleZh":"媽媽輕聲唱歌安撫哭泣的寶寶。","synonyms":["calm","comfort"],"level":5,"theme":"情緒與感受","examples":[{"en":"The mother sang softly to soothe her crying baby.","zh":"媽媽輕聲唱歌安撫哭泣的寶寶。"},{"en":"A cup of warm tea can help soothe a sore throat.","zh":"一杯溫熱的茶有助於緩解喉嚨痛。"},{"en":"Soft music often soothes the nerves before an exam.","zh":"輕柔的音樂常能在考試前安撫緊張的情緒。"}]},{"word":"sophisticated","pos":"adj.","phonetic":"[səˈfɪstɪˌketɪd]","meaning":"精密的；老練的；世故的","definition":"highly developed and complex, or experienced in worldly matters","collocations":["sophisticated technology","sophisticated taste"],"example":"The new phone uses sophisticated technology.","exampleZh":"這款新手機採用了精密複雜的科技。","synonyms":["advanced","complex"],"level":6,"theme":"科技與媒體","examples":[{"en":"The new phone uses sophisticated technology.","zh":"這款新手機採用了精密複雜的科技。"},{"en":"The laboratory uses sophisticated equipment to test water quality.","zh":"這間實驗室使用精密的設備來檢測水質。"},{"en":"She has quite a sophisticated taste in classical music.","zh":"她對古典音樂有相當高雅的品味。"}]},{"word":"sore","pos":"adj.","phonetic":"[sɔr]","meaning":"疼痛的；痠痛的","definition":"painful, especially from injury or overuse","collocations":["sore throat","sore muscles"],"example":"My legs are sore after the long run.","exampleZh":"長跑之後我的腿很痠痛。","synonyms":["painful","aching"],"level":3,"theme":"身體與健康","examples":[{"en":"My legs are sore after the long run.","zh":"長跑之後我的腿很痠痛。"},{"en":"He woke up with a sore throat and a slight cough.","zh":"他醒來時喉嚨痛,還有輕微的咳嗽。"},{"en":"My muscles were sore after helping move the furniture.","zh":"幫忙搬家具之後,我的肌肉很痠痛。"}]},{"word":"sorrow","pos":"n.","phonetic":"[ˈsɑro]","meaning":"悲傷；悲痛","definition":"a feeling of deep sadness or regret","collocations":["deep sorrow","express sorrow"],"example":"She felt great sorrow after losing her pet.","exampleZh":"失去寵物後她感到十分悲傷。","synonyms":["sadness","grief"],"level":5,"theme":"情緒與感受","examples":[{"en":"She felt great sorrow after losing her pet.","zh":"失去寵物後她感到十分悲傷。"},{"en":"The sad music filled everyone's heart with deep sorrow.","zh":"這悲傷的音樂讓每個人心中充滿了深深的哀傷。"},{"en":"She tried to hide her sorrow behind a brave smile.","zh":"她試圖用勇敢的微笑掩飾自己的悲傷。"}]},{"word":"sorry","pos":"adj.","phonetic":"[ˈsɑri]","meaning":"抱歉的；遺憾的","definition":"feeling regret, sympathy, or sadness","collocations":["feel sorry","say sorry"],"example":"I'm sorry for being late to the meeting.","exampleZh":"很抱歉開會遲到了。","synonyms":["apologetic"],"level":1,"theme":"情緒與感受","examples":[{"en":"I'm sorry for being late to the meeting.","zh":"很抱歉開會遲到了。"},{"en":"I feel sorry for the stray cat out in the rain.","zh":"我為在雨中的那隻流浪貓感到難過。"},{"en":"He said sorry to his sister for breaking her toy.","zh":"他因為弄壞妹妹的玩具而向她道歉。"}]},{"word":"sort","pos":"n. / v.","phonetic":"[sɔrt]","meaning":"種類；分類","definition":"a type or kind of thing; to arrange into groups","collocations":["sort of","sort out","sort by size"],"example":"Please sort these files by date.","exampleZh":"請依日期將這些檔案分類。","synonyms":["type","kind"],"level":2,"theme":"抽象概念","examples":[{"en":"Please sort these files by date.","zh":"請依日期將這些檔案分類。"},{"en":"Please sort these books by their size on the shelf.","zh":"請把這些書按大小排列在書架上。"},{"en":"We need to sort out this problem before the deadline.","zh":"我們需要在截止日期前解決這個問題。"}]},{"word":"soul","pos":"n.","phonetic":"[sol]","meaning":"靈魂；心靈","definition":"the spiritual or non-physical part of a person","collocations":["heart and soul","lost soul"],"example":"She believes music feeds the soul.","exampleZh":"她相信音樂能滋養心靈。","synonyms":["spirit"],"level":4,"theme":"抽象概念","examples":[{"en":"She believes music feeds the soul.","zh":"她相信音樂能滋養心靈。"},{"en":"He put his heart and soul into learning the guitar.","zh":"他全心全意地投入學習吉他。"},{"en":"Many artists believe that beauty can lift the soul.","zh":"許多藝術家相信美能提升人的心靈。"}]},{"word":"sound","pos":"n. / adj. / v.","phonetic":"[saʊnd]","meaning":"聲音；健全的；聽起來","definition":"something that can be heard; healthy or reasonable","collocations":["loud sound","sound asleep","sound like"],"example":"I heard a strange sound outside the window.","exampleZh":"我聽到窗外傳來奇怪的聲音。","synonyms":["noise"],"level":1,"theme":"抽象概念","examples":[{"en":"I heard a strange sound outside the window.","zh":"我聽到窗外傳來奇怪的聲音。"},{"en":"The gentle sound of rain helped me fall asleep.","zh":"輕柔的雨聲幫助我入睡。"},{"en":"Your plan sounds like a sensible and reasonable idea.","zh":"你的計畫聽起來是個明智又合理的點子。"}]},{"word":"soup","pos":"n.","phonetic":"[sup]","meaning":"湯","definition":"a liquid food made by boiling meat, vegetables, or other ingredients","collocations":["bowl of soup","chicken soup"],"example":"My grandmother makes the best chicken soup.","exampleZh":"我奶奶煮的雞湯最好喝。","synonyms":[],"level":1,"theme":"食物與烹飪","examples":[{"en":"My grandmother makes the best chicken soup.","zh":"我奶奶煮的雞湯最好喝。"},{"en":"A hot bowl of soup is perfect on a cold day.","zh":"在寒冷的日子裡,一碗熱湯再適合不過了。"},{"en":"She added a little salt to the vegetable soup.","zh":"她在蔬菜湯裡加了一點鹽。"}]},{"word":"sour","pos":"adj.","phonetic":"[saʊr]","meaning":"酸的","definition":"having a sharp, acid taste like a lemon","collocations":["sour taste","sour milk","sweet and sour"],"example":"The lemon tasted very sour.","exampleZh":"這顆檸檬嚐起來非常酸。","synonyms":[],"level":1,"theme":"食物與烹飪","examples":[{"en":"The lemon tasted very sour.","zh":"這顆檸檬嚐起來非常酸。"},{"en":"The milk had turned sour after sitting out all day.","zh":"牛奶放了一整天後變酸了。"},{"en":"I ordered a bowl of hot and sour soup.","zh":"我點了一碗酸辣湯。"}]},{"word":"source","pos":"n.","phonetic":"[sɔrs]","meaning":"來源；出處","definition":"the place, person, or thing from which something comes","collocations":["main source","reliable source","energy source"],"example":"The sun is the main source of energy on Earth.","exampleZh":"太陽是地球上主要的能量來源。","synonyms":["origin"],"level":3,"theme":"抽象概念","examples":[{"en":"The sun is the main source of energy on Earth.","zh":"太陽是地球上主要的能量來源。"},{"en":"Always check whether a website is a reliable source.","zh":"永遠要查證一個網站是否為可靠的來源。"},{"en":"Fresh fruit is a good source of vitamins.","zh":"新鮮水果是維他命的良好來源。"}]},{"word":"south","pos":"n. / adj. / adv.","phonetic":"[saʊθ]","meaning":"南方(的)","definition":"the direction that is opposite to north","collocations":["south of","head south"],"example":"Birds fly south for the winter.","exampleZh":"鳥兒會在冬天飛往南方。","synonyms":[],"level":1,"theme":"時間與空間","examples":[{"en":"Birds fly south for the winter.","zh":"鳥兒會在冬天飛往南方。"},{"en":"The town lies just south of the wide river.","zh":"這座小鎮就位於這條寬闊河流的南方。"},{"en":"We decided to head south for our summer vacation.","zh":"我們決定往南去度過暑假。"}]},{"word":"southern","pos":"adj.","phonetic":"[ˈsʌðɚn]","meaning":"南方的","definition":"located in or coming from the south","collocations":["southern coast","southern hemisphere"],"example":"They grew up in a small town in southern Taiwan.","exampleZh":"他們在台灣南部的一個小鎮長大。","synonyms":[],"level":2,"theme":"時間與空間","examples":[{"en":"They grew up in a small town in southern Taiwan.","zh":"他們在台灣南部的一個小鎮長大。"},{"en":"The southern coast is famous for its warm beaches.","zh":"南部海岸以溫暖的海灘聞名。"},{"en":"Many tropical fruits grow well in southern regions.","zh":"許多熱帶水果在南方地區生長得很好。"}]},{"word":"souvenir","pos":"n.","phonetic":"[ˌsuvəˈnɪr]","meaning":"紀念品","definition":"an item kept to remember a place, event, or person","collocations":["buy a souvenir","souvenir shop"],"example":"We bought some souvenirs to remember our trip.","exampleZh":"我們買了一些紀念品來紀念這趟旅行。","synonyms":["keepsake"],"level":4,"theme":"交通與旅行","examples":[{"en":"We bought some souvenirs to remember our trip.","zh":"我們買了一些紀念品來紀念這趟旅行。"},{"en":"She bought a small souvenir shop postcard for her friend.","zh":"她在紀念品店買了一張明信片給朋友。"},{"en":"This shell is a souvenir from our trip to the sea.","zh":"這個貝殼是我們海邊之旅的紀念品。"}]},{"word":"sovereign","pos":"adj. / n.","phonetic":"[ˈsɑvrɪn]","meaning":"主權的；君主","definition":"having supreme power and independence; a king or queen","collocations":["sovereign nation","sovereign power"],"example":"The country became a sovereign nation after the war.","exampleZh":"這個國家在戰後成為一個主權國家。","synonyms":[],"level":6,"theme":"政治與法律","examples":[{"en":"The country became a sovereign nation after the war.","zh":"這個國家在戰後成為一個主權國家。"},{"en":"The island became a sovereign nation with its own laws.","zh":"這座島嶼成為擁有自己法律的主權國家。"},{"en":"A sovereign state has the right to govern itself.","zh":"主權國家有權自我治理。"}]},{"word":"sow","pos":"v.","phonetic":"[so]","meaning":"播種","definition":"to plant seeds in the ground","collocations":["sow seeds","sow crops"],"example":"Farmers sow seeds in early spring.","exampleZh":"農夫在初春播種。","synonyms":["plant"],"level":4,"theme":"自然與環境","examples":[{"en":"Farmers sow seeds in early spring.","zh":"農夫在初春播種。"},{"en":"The farmers sow seeds in the fields every spring.","zh":"農夫每年春天都在田裡播種。"},{"en":"We sowed carrot seeds in neat rows in the garden.","zh":"我們在花園裡整齊地成排播下胡蘿蔔種子。"}]},{"word":"soybean","pos":"n.","phonetic":"[ˈsɔɪˌbin]","meaning":"黃豆；大豆","definition":"a bean used to make food products such as tofu and oil","collocations":["soybean oil","soybean field"],"example":"Soybeans are used to make tofu and soy milk.","exampleZh":"黃豆被用來製作豆腐和豆漿。","synonyms":[],"level":3,"theme":"食物與烹飪","examples":[{"en":"Soybeans are used to make tofu and soy milk.","zh":"黃豆被用來製作豆腐和豆漿。"},{"en":"Soybean oil is commonly used for cooking at home.","zh":"大豆油常被用於家庭烹飪。"},{"en":"The farmer harvested a large soybean field in autumn.","zh":"農夫在秋天收成了一大片黃豆田。"}]},{"word":"space","pos":"n.","phonetic":"[spes]","meaning":"空間；太空","definition":"an empty area; the universe beyond Earth's atmosphere","collocations":["outer space","parking space","space station"],"example":"Scientists are exploring outer space with new technology.","exampleZh":"科學家們正運用新科技探索外太空。","synonyms":["room"],"level":2,"theme":"科學與數學","examples":[{"en":"Scientists are exploring outer space with new technology.","zh":"科學家們正運用新科技探索外太空。"},{"en":"We could not find a parking space near the mall.","zh":"我們在購物中心附近找不到停車位。"},{"en":"Astronauts study the earth from a space station.","zh":"太空人從太空站觀測地球。"}]},{"word":"spacious","pos":"adj.","phonetic":"[ˈspeʃəs]","meaning":"寬敞的","definition":"having a lot of space; large in area","collocations":["spacious room","spacious apartment"],"example":"Their new house has a spacious living room.","exampleZh":"他們的新房子有一間寬敞的客廳。","synonyms":["roomy"],"level":5,"theme":"居家與生活","examples":[{"en":"Their new house has a spacious living room.","zh":"他們的新房子有一間寬敞的客廳。"},{"en":"The new library has a spacious reading room upstairs.","zh":"新圖書館樓上有一間寬敞的閱覽室。"},{"en":"Their apartment feels spacious because of the large windows.","zh":"因為有大窗戶,他們的公寓感覺很寬敞。"}]},{"word":"spade","pos":"n.","phonetic":"[sped]","meaning":"鏟子","definition":"a tool with a flat blade used for digging","collocations":["dig with a spade"],"example":"He used a spade to dig a hole for the tree.","exampleZh":"他用鏟子挖了一個洞來種樹。","synonyms":["shovel"],"level":3,"theme":"居家與生活","examples":[{"en":"He used a spade to dig a hole for the tree.","zh":"他用鏟子挖了一個洞來種樹。"},{"en":"The gardener turned the soil with a heavy spade.","zh":"園丁用一把沉重的鏟子翻土。"},{"en":"He dug a deep hole with a spade for the plant.","zh":"他用鏟子為那株植物挖了一個深洞。"}]},{"word":"span","pos":"n. / v.","phonetic":"[spæn]","meaning":"期間；跨度；跨越","definition":"the length of time or distance that something covers","collocations":["life span","span of time","span a river"],"example":"The bridge spans over two kilometers.","exampleZh":"這座橋橫跨超過兩公里。","synonyms":[],"level":5,"theme":"時間與空間","examples":[{"en":"The bridge spans over two kilometers.","zh":"這座橋橫跨超過兩公里。"},{"en":"The new bridge will span the entire wide valley.","zh":"這座新橋將橫跨整個寬闊的山谷。"},{"en":"Her career as a teacher covers a span of thirty years.","zh":"她的教師生涯橫跨了三十年。"}]},{"word":"spare","pos":"adj. / v.","phonetic":"[spɛr]","meaning":"備用的；騰出(時間)","definition":"kept in reserve for use when needed; to make time or money available","collocations":["spare time","spare tire","spare a moment"],"example":"Do you have any spare time this weekend?","exampleZh":"你這個週末有空閒時間嗎?","synonyms":["extra"],"level":3,"theme":"時間與空間","examples":[{"en":"Do you have any spare time this weekend?","zh":"你這個週末有空閒時間嗎?"},{"en":"Could you spare a moment to help me with this?","zh":"你能抽出片刻幫我處理這個嗎?"},{"en":"He keeps a spare tire in the back of the car.","zh":"他在車子後面放了一個備胎。"}]},{"word":"spark","pos":"n. / v.","phonetic":"[spɑrk]","meaning":"火花；引發","definition":"a small flash of fire or light; to cause something to start","collocations":["spark a fire","spark interest","electric spark"],"example":"The idea sparked a lot of interest among students.","exampleZh":"這個點子引發了學生們很大的興趣。","synonyms":["ignite"],"level":4,"theme":"抽象概念","examples":[{"en":"The idea sparked a lot of interest among students.","zh":"這個點子引發了學生們很大的興趣。"},{"en":"The documentary sparked her interest in marine biology.","zh":"這部紀錄片激發了她對海洋生物學的興趣。"},{"en":"A single spark from the campfire could start a fire.","zh":"營火冒出的一個火花就可能引起火災。"}]},{"word":"sparkle","pos":"v. / n.","phonetic":"[ˈspɑrkl]","meaning":"閃爍；發光","definition":"to shine brightly with small flashes of light","collocations":["sparkle brightly","eyes sparkle"],"example":"The diamond necklace sparkled under the light.","exampleZh":"這條鑽石項鍊在燈光下閃閃發光。","synonyms":["shine","glitter"],"level":4,"theme":"性質與描述","examples":[{"en":"The diamond necklace sparkled under the light.","zh":"這條鑽石項鍊在燈光下閃閃發光。"},{"en":"Her eyes sparkled with joy when she opened the gift.","zh":"她打開禮物時,雙眼因喜悅而閃閃發亮。"},{"en":"The morning dew made the whole lawn sparkle brightly.","zh":"清晨的露水讓整片草坪閃閃發光。"}]},{"word":"sparrow","pos":"n.","phonetic":"[ˈspɛro]","meaning":"麻雀","definition":"a small brown bird commonly found near buildings","collocations":["a flock of sparrows"],"example":"A sparrow landed on the windowsill.","exampleZh":"一隻麻雀停在窗台上。","synonyms":[],"level":3,"theme":"動物與植物","examples":[{"en":"A sparrow landed on the windowsill.","zh":"一隻麻雀停在窗台上。"},{"en":"A small sparrow hopped along the garden path.","zh":"一隻小麻雀沿著花園小徑跳躍前進。"},{"en":"A flock of sparrows gathered around the bread crumbs.","zh":"一群麻雀聚集在麵包屑周圍。"}]},{"word":"speak","pos":"v.","phonetic":"[spik]","meaning":"說話；講","definition":"to say words aloud in order to communicate","collocations":["speak English","speak up","speak to"],"example":"Could you speak more slowly, please?","exampleZh":"可以請你說慢一點嗎?","synonyms":["talk"],"level":1,"theme":"溝通與語言","examples":[{"en":"Could you speak more slowly, please?","zh":"可以請你說慢一點嗎?"},{"en":"You should speak up so everyone can hear you clearly.","zh":"你應該大聲一點,好讓大家都能聽清楚。"},{"en":"She can speak English and French very fluently.","zh":"她能非常流利地說英語和法語。"}]},{"word":"speaker","pos":"n.","phonetic":"[ˈspikɚ]","meaning":"說話者；喇叭；演講者","definition":"a person who speaks; a device that produces sound","collocations":["native speaker","guest speaker","loudspeaker"],"example":"The guest speaker gave an inspiring talk.","exampleZh":"這位特別來賓演講者發表了一場鼓舞人心的演說。","synonyms":[],"level":2,"theme":"溝通與語言","examples":[{"en":"The guest speaker gave an inspiring talk.","zh":"這位特別來賓演講者發表了一場鼓舞人心的演說。"},{"en":"Our teacher invited a guest speaker to the classroom.","zh":"我們的老師邀請了一位客座講者到教室。"},{"en":"He turned up the speaker so we could all hear.","zh":"他把喇叭音量調大,好讓我們都能聽到。"}]},{"word":"spear","pos":"n.","phonetic":"[spɪr]","meaning":"矛；長矛","definition":"a weapon with a long shaft and a pointed tip","collocations":["throw a spear","hunt with a spear"],"example":"Ancient hunters used spears to catch fish.","exampleZh":"古代獵人用長矛捕魚。","synonyms":[],"level":4,"theme":"其他","examples":[{"en":"Ancient hunters used spears to catch fish.","zh":"古代獵人用長矛捕魚。"},{"en":"The museum displays a stone spear from ancient times.","zh":"博物館展出一支來自古代的石矛。"},{"en":"Long ago, hunters used spears to catch large animals.","zh":"很久以前,獵人用長矛捕捉大型動物。"}]},{"word":"special","pos":"adj.","phonetic":"[ˈspɛʃəl]","meaning":"特別的；特殊的","definition":"different from what is usual; not ordinary","collocations":["special occasion","feel special","something special"],"example":"We had a special dinner to celebrate her birthday.","exampleZh":"我們特地準備了一頓特別的晚餐慶祝她的生日。","synonyms":["particular"],"level":1,"theme":"性質與描述","examples":[{"en":"We had a special dinner to celebrate her birthday.","zh":"我們特地準備了一頓特別的晚餐慶祝她的生日。"},{"en":"We saved this cake for a special occasion.","zh":"我們把這個蛋糕留給特別的場合。"},{"en":"Her kind words made me feel truly special.","zh":"她親切的話語讓我感到自己真的很特別。"}]},{"word":"specialist","pos":"n.","phonetic":"[ˈspɛʃəlɪst]","meaning":"專家","definition":"a person with special knowledge or skill in a particular field","collocations":["eye specialist","financial specialist"],"example":"She saw a specialist about her back pain.","exampleZh":"她因為背痛去看了專科醫生。","synonyms":["expert"],"level":4,"theme":"工作與職業","examples":[{"en":"She saw a specialist about her back pain.","zh":"她因為背痛去看了專科醫生。"},{"en":"The doctor sent him to see an eye specialist.","zh":"醫生把他轉介去看眼科專科醫生。"},{"en":"A heart specialist explained the results of the test.","zh":"一位心臟專科醫生解釋了檢查的結果。"}]},{"word":"specialize","pos":"v.","phonetic":"[ˈspɛʃəˌlaɪz]","meaning":"專攻；專門從事","definition":"to focus one's work or study on a particular area","collocations":["specialize in","specialize in medicine"],"example":"This law firm specializes in international business.","exampleZh":"這家律師事務所專門處理國際商務案件。","synonyms":[],"level":4,"theme":"工作與職業","examples":[{"en":"This law firm specializes in international business.","zh":"這家律師事務所專門處理國際商務案件。"},{"en":"This restaurant specializes in fresh seafood dishes.","zh":"這家餐廳專門提供新鮮的海鮮料理。"},{"en":"She hopes to specialize in medicine after graduation.","zh":"她希望畢業後專攻醫學。"}]},{"word":"species","pos":"n.","phonetic":"[ˈspiʃiz]","meaning":"物種","definition":"a group of living organisms that share similar characteristics","collocations":["endangered species","new species"],"example":"Scientists discovered a new species of frog.","exampleZh":"科學家發現了一種新的青蛙物種。","synonyms":[],"level":4,"theme":"自然與環境","examples":[{"en":"Scientists discovered a new species of frog.","zh":"科學家發現了一種新的青蛙物種。"},{"en":"Many species of birds visit this lake in winter.","zh":"許多種類的鳥在冬天造訪這座湖。"},{"en":"We must protect endangered species from disappearing forever.","zh":"我們必須保護瀕危物種,以免牠們永遠消失。"}]},{"word":"specific","pos":"adj.","phonetic":"[spɪˈsɪfɪk]","meaning":"特定的；明確的","definition":"clearly defined or particular","collocations":["specific reason","specific information"],"example":"Please give me a specific date for the meeting.","exampleZh":"請給我一個明確的開會日期。","synonyms":["particular","exact"],"level":3,"theme":"性質與描述","examples":[{"en":"Please give me a specific date for the meeting.","zh":"請給我一個明確的開會日期。"},{"en":"The teacher gave specific instructions for the science project.","zh":"老師為這個科學專題給了明確的指示。"},{"en":"Can you tell me the specific reason for your absence?","zh":"你能告訴我你缺席的確切原因嗎?"}]},{"word":"specimen","pos":"n.","phonetic":"[ˈspɛsəmən]","meaning":"樣本；標本","definition":"a small sample or example used for scientific study","collocations":["blood specimen","collect a specimen"],"example":"The scientist examined the specimen under a microscope.","exampleZh":"科學家用顯微鏡檢查這個樣本。","synonyms":["sample"],"level":5,"theme":"科學與數學","examples":[{"en":"The scientist examined the specimen under a microscope.","zh":"科學家用顯微鏡檢查這個樣本。"},{"en":"The students collected a leaf specimen for their biology class.","zh":"學生們為生物課採集了一片葉子標本。"},{"en":"The nurse carefully labeled the blood specimen.","zh":"護士小心地為血液樣本貼上標籤。"}]},{"word":"spectacle","pos":"n.","phonetic":"[ˈspɛktəkl]","meaning":"奇觀；場面","definition":"an impressive public display or scene","collocations":["amazing spectacle","spectacle of light"],"example":"The fireworks show was quite a spectacle.","exampleZh":"這場煙火秀真是一場壯觀的場面。","synonyms":[],"level":6,"theme":"藝術與音樂","examples":[{"en":"The fireworks show was quite a spectacle.","zh":"這場煙火秀真是一場壯觀的場面。"},{"en":"The colorful parade was a wonderful spectacle to watch.","zh":"這場繽紛的遊行是一場精彩的奇觀。"},{"en":"The dancing fountains created an amazing spectacle at night.","zh":"跳動的噴泉在夜裡創造出驚人的景象。"}]},{"word":"spectacular","pos":"adj.","phonetic":"[spɛkˈtækjəlɚ]","meaning":"壯觀的；驚人的","definition":"very impressive or dramatic to look at","collocations":["spectacular view","spectacular performance"],"example":"The view from the mountain top was spectacular.","exampleZh":"從山頂看到的景色非常壯觀。","synonyms":["amazing","stunning"],"level":5,"theme":"性質與描述","examples":[{"en":"The view from the mountain top was spectacular.","zh":"從山頂看到的景色非常壯觀。"},{"en":"We enjoyed a spectacular view of the city at night.","zh":"我們欣賞了城市夜晚壯觀的景色。"},{"en":"The gymnast gave a spectacular performance at the final.","zh":"這位體操選手在決賽中表現得驚人出色。"}]},{"word":"spectator","pos":"n.","phonetic":"[ˈspɛkˌtetɚ]","meaning":"觀眾","definition":"a person who watches an event, especially a sports match","collocations":["spectator sport","cheering spectators"],"example":"Thousands of spectators watched the final match.","exampleZh":"數千名觀眾觀看了這場決賽。","synonyms":["audience","viewer"],"level":5,"theme":"運動與休閒","examples":[{"en":"Thousands of spectators watched the final match.","zh":"數千名觀眾觀看了這場決賽。"},{"en":"Excited spectators filled every seat in the arena.","zh":"興奮的觀眾坐滿了場館裡的每個座位。"},{"en":"The cheering spectators encouraged the runners to keep going.","zh":"歡呼的觀眾鼓勵跑者繼續前進。"}]},{"word":"speech","pos":"n.","phonetic":"[spitʃ]","meaning":"演講；言語","definition":"a formal talk given to an audience","collocations":["give a speech","freedom of speech"],"example":"The president gave a moving speech at the ceremony.","exampleZh":"總統在典禮上發表了一場感人的演講。","synonyms":[],"level":2,"theme":"溝通與語言","examples":[{"en":"The president gave a moving speech at the ceremony.","zh":"總統在典禮上發表了一場感人的演講。"},{"en":"She practiced her speech many times before the contest.","zh":"她在比賽前把演講練習了許多次。"},{"en":"Freedom of speech is an important right in a democracy.","zh":"言論自由是民主中一項重要的權利。"}]},{"word":"speed","pos":"n. / v.","phonetic":"[spid]","meaning":"速度；加速","definition":"the rate at which something moves or happens","collocations":["high speed","speed limit","speed up"],"example":"The car was traveling at a very high speed.","exampleZh":"這輛車以非常快的速度行駛。","synonyms":[],"level":2,"theme":"交通與旅行","examples":[{"en":"The car was traveling at a very high speed.","zh":"這輛車以非常快的速度行駛。"},{"en":"Drivers must obey the speed limit near the school.","zh":"駕駛人在學校附近必須遵守速限。"},{"en":"The runner increased his speed in the final lap.","zh":"這名跑者在最後一圈加快了速度。"}]},{"word":"spell","pos":"v. / n.","phonetic":"[spɛl]","meaning":"拼字；符咒","definition":"to write or say the letters of a word in the correct order","collocations":["spell a word","cast a spell"],"example":"Can you spell your last name for me?","exampleZh":"你可以幫我拼一下你的姓氏嗎?","synonyms":[],"level":1,"theme":"教育與學習","examples":[{"en":"Can you spell your last name for me?","zh":"你可以幫我拼一下你的姓氏嗎?"},{"en":"Could you please spell your street name for me?","zh":"你可以幫我拼出你的街道名稱嗎?"},{"en":"In the story, a wizard cast a magic spell.","zh":"在故事裡,一位巫師施了一道魔法咒語。"}]},{"word":"spend","pos":"v.","phonetic":"[spɛnd]","meaning":"花費(錢、時間)","definition":"to use money or time on something","collocations":["spend money","spend time"],"example":"We spent the whole afternoon at the museum.","exampleZh":"我們整個下午都待在博物館裡。","synonyms":[],"level":1,"theme":"商業與金錢","examples":[{"en":"We spent the whole afternoon at the museum.","zh":"我們整個下午都待在博物館裡。"},{"en":"We spent the whole weekend hiking in the mountains.","zh":"我們整個週末都在山裡健行。"},{"en":"Try not to spend too much money on snacks.","zh":"盡量不要花太多錢買零食。"}]},{"word":"sphere","pos":"n.","phonetic":"[sfɪr]","meaning":"球體；領域","definition":"a perfectly round solid shape; an area of activity or interest","collocations":["political sphere","perfect sphere"],"example":"The earth is not a perfect sphere.","exampleZh":"地球並不是一個完美的球體。","synonyms":[],"level":5,"theme":"科學與數學","examples":[{"en":"The earth is not a perfect sphere.","zh":"地球並不是一個完美的球體。"},{"en":"The students learned to calculate the volume of a sphere.","zh":"學生們學會計算球體的體積。"},{"en":"She is well respected in the sphere of education.","zh":"她在教育領域備受尊敬。"}]},{"word":"spice","pos":"n.","phonetic":"[spaɪs]","meaning":"香料","definition":"a substance made from plants used to flavor food","collocations":["add spice","spice rack"],"example":"This curry has too much spice for me.","exampleZh":"這道咖哩對我來說香料放太多了。","synonyms":[],"level":3,"theme":"食物與烹飪","examples":[{"en":"This curry has too much spice for me.","zh":"這道咖哩對我來說香料放太多了。"},{"en":"A little spice can make a simple dish more interesting.","zh":"一點香料能讓簡單的菜餚變得更有趣。"},{"en":"She keeps her jars of spice neatly on a rack.","zh":"她把香料罐整齊地放在架子上。"}]},{"word":"spicy","pos":"adj.","phonetic":"[ˈspaɪsi]","meaning":"辛辣的","definition":"flavored with strong spices, especially hot ones","collocations":["spicy food","spicy sauce"],"example":"I love spicy food, especially Sichuan dishes.","exampleZh":"我很愛吃辣的食物,尤其是川菜。","synonyms":["hot"],"level":2,"theme":"食物與烹飪","examples":[{"en":"I love spicy food, especially Sichuan dishes.","zh":"我很愛吃辣的食物,尤其是川菜。"},{"en":"This spicy sauce is too hot for young children.","zh":"這種辣醬對小孩子來說太辣了。"},{"en":"He ordered a bowl of spicy noodles for lunch.","zh":"他午餐點了一碗辣味麵。"}]},{"word":"spider","pos":"n.","phonetic":"[ˈspaɪdɚ]","meaning":"蜘蛛","definition":"a small eight-legged creature that spins webs to catch insects","collocations":["spider web","afraid of spiders"],"example":"A big spider was hanging from the ceiling.","exampleZh":"一隻大蜘蛛從天花板上垂掛下來。","synonyms":[],"level":2,"theme":"動物與植物","examples":[{"en":"A big spider was hanging from the ceiling.","zh":"一隻大蜘蛛從天花板上垂掛下來。"},{"en":"A spider spun a beautiful web between the two branches.","zh":"一隻蜘蛛在兩根樹枝之間織了一張美麗的網。"},{"en":"My little sister is quite afraid of spiders.","zh":"我的小妹妹相當怕蜘蛛。"}]},{"word":"spill","pos":"v. / n.","phonetic":"[spɪl]","meaning":"灑出；溢出","definition":"to accidentally pour liquid out of a container","collocations":["spill water","oil spill"],"example":"Be careful not to spill your coffee on the desk.","exampleZh":"小心別把咖啡灑在桌上。","synonyms":[],"level":3,"theme":"動作與行為","examples":[{"en":"Be careful not to spill your coffee on the desk.","zh":"小心別把咖啡灑在桌上。"},{"en":"Try not to spill the juice on the clean carpet.","zh":"盡量不要把果汁灑在乾淨的地毯上。"},{"en":"The oil spill harmed many animals along the coast.","zh":"這場漏油事件傷害了沿岸許多動物。"}]},{"word":"spin","pos":"v. / n.","phonetic":"[spɪn]","meaning":"旋轉；紡織","definition":"to turn around and around quickly","collocations":["spin around","spin a wheel"],"example":"The dancer began to spin gracefully on stage.","exampleZh":"這位舞者開始在舞台上優雅地旋轉。","synonyms":["turn","rotate"],"level":3,"theme":"動作與行為","examples":[{"en":"The dancer began to spin gracefully on stage.","zh":"這位舞者開始在舞台上優雅地旋轉。"},{"en":"The children love to spin around until they feel dizzy.","zh":"孩子們喜歡一直轉圈圈直到頭暈。"},{"en":"The wheel began to spin faster and faster.","zh":"輪子開始轉得越來越快。"}]},{"word":"spinach","pos":"n.","phonetic":"[ˈspɪnɪtʃ]","meaning":"菠菜","definition":"a green leafy vegetable rich in iron","collocations":["fresh spinach","spinach salad"],"example":"Popeye is famous for eating spinach for strength.","exampleZh":"大力水手以吃菠菜增強力量而聞名。","synonyms":[],"level":3,"theme":"食物與烹飪","examples":[{"en":"Popeye is famous for eating spinach for strength.","zh":"大力水手以吃菠菜增強力量而聞名。"},{"en":"Fresh spinach is full of iron and other nutrients.","zh":"新鮮的菠菜富含鐵質和其他營養。"},{"en":"She made a healthy salad with spinach and tomatoes.","zh":"她用菠菜和番茄做了一份健康的沙拉。"}]},{"word":"spine","pos":"n.","phonetic":"[spaɪn]","meaning":"脊椎；書脊","definition":"the row of connected bones down the middle of the back","collocations":["injure one's spine","spine of a book"],"example":"The accident damaged his spine badly.","exampleZh":"這場意外嚴重傷害了他的脊椎。","synonyms":["backbone"],"level":4,"theme":"身體與健康","examples":[{"en":"The accident damaged his spine badly.","zh":"這場意外嚴重傷害了他的脊椎。"},{"en":"Sitting up straight is good for your spine.","zh":"坐直對你的脊椎有益。"},{"en":"The book's title was printed on the spine.","zh":"書名印在書脊上。"}]},{"word":"spirit","pos":"n.","phonetic":"[ˈspɪrɪt]","meaning":"精神；靈魂","definition":"the non-physical part of a person; a mood or attitude","collocations":["team spirit","in good spirits"],"example":"The whole team showed great spirit during the game.","exampleZh":"整個隊伍在比賽中展現了極佳的團隊精神。","synonyms":["soul"],"level":3,"theme":"抽象概念","examples":[{"en":"The whole team showed great spirit during the game.","zh":"整個隊伍在比賽中展現了極佳的團隊精神。"},{"en":"The players showed great team spirit throughout the season.","zh":"球員們在整個賽季中都展現了極佳的團隊精神。"},{"en":"She was in good spirits after passing her exam.","zh":"通過考試後,她的心情很好。"}]},{"word":"spiritual","pos":"adj.","phonetic":"[ˈspɪrɪtʃuəl]","meaning":"精神上的；心靈的","definition":"relating to the spirit or soul rather than the body","collocations":["spiritual life","spiritual leader"],"example":"Many people find spiritual comfort in music.","exampleZh":"許多人在音樂中找到心靈上的慰藉。","synonyms":[],"level":5,"theme":"抽象概念","examples":[{"en":"Many people find spiritual comfort in music.","zh":"許多人在音樂中找到心靈上的慰藉。"},{"en":"Meditation is part of his daily spiritual life.","zh":"冥想是他每日精神生活的一部分。"},{"en":"The old temple is a place of spiritual peace.","zh":"這座古老的寺廟是一個心靈平靜的地方。"}]},{"word":"spit","pos":"v. / n.","phonetic":"[spɪt]","meaning":"吐(口水)","definition":"to force saliva or another substance out of the mouth","collocations":["spit out","spit on the ground"],"example":"Please don't spit on the sidewalk.","exampleZh":"請不要在人行道上吐口水。","synonyms":[],"level":3,"theme":"動作與行為","examples":[{"en":"Please don't spit on the sidewalk.","zh":"請不要在人行道上吐口水。"},{"en":"It is rude to spit on the ground in public.","zh":"在公共場合隨地吐痰是很沒禮貌的。"},{"en":"The baby spit out the food she did not like.","zh":"寶寶把她不喜歡的食物吐了出來。"}]},{"word":"spite","pos":"n.","phonetic":"[spaɪt]","meaning":"惡意；怨恨","definition":"a desire to hurt, annoy, or offend someone","collocations":["in spite of","out of spite"],"example":"In spite of the rain, they finished the race.","exampleZh":"儘管下雨,他們仍完成了比賽。","synonyms":["malice"],"level":4,"theme":"情緒與感受","examples":[{"en":"In spite of the rain, they finished the race.","zh":"儘管下雨,他們仍完成了比賽。"},{"en":"In spite of the heavy rain, the game continued.","zh":"儘管下著大雨,比賽仍然繼續進行。"},{"en":"He broke the toy out of spite, not by accident.","zh":"他是出於怨恨才弄壞玩具,而不是不小心。"}]},{"word":"splash","pos":"v. / n.","phonetic":"[splæʃ]","meaning":"濺；潑","definition":"to make liquid scatter about in drops","collocations":["splash water","make a splash"],"example":"The children loved to splash water at each other in the pool.","exampleZh":"孩子們喜歡在泳池裡互相潑水。","synonyms":[],"level":3,"theme":"動作與行為","examples":[{"en":"The children loved to splash water at each other in the pool.","zh":"孩子們喜歡在泳池裡互相潑水。"},{"en":"The dog jumped in and made a big splash.","zh":"那隻狗跳了進去,濺起了好大的水花。"},{"en":"Waves splashed against the rocks along the shore.","zh":"海浪拍打著岸邊的岩石,濺起水花。"}]},{"word":"splendid","pos":"adj.","phonetic":"[ˈsplɛndɪd]","meaning":"極好的；壯麗的","definition":"very impressive, beautiful, or excellent","collocations":["splendid view","splendid performance"],"example":"We had a splendid time at the festival.","exampleZh":"我們在這場慶典上玩得非常盡興。","synonyms":["excellent","magnificent"],"level":5,"theme":"性質與描述","examples":[{"en":"We had a splendid time at the festival.","zh":"我們在這場慶典上玩得非常盡興。"},{"en":"We had a splendid time at the summer music festival.","zh":"我們在夏季音樂節度過了極為美好的時光。"},{"en":"The palace garden offered a truly splendid view.","zh":"這座宮殿花園呈現出真正壯麗的景色。"}]},{"word":"split","pos":"v. / n.","phonetic":"[splɪt]","meaning":"分裂；分開","definition":"to divide or break into two or more parts","collocations":["split up","split the bill"],"example":"Let's split the bill evenly among us.","exampleZh":"我們平均分攤帳單吧。","synonyms":["divide"],"level":3,"theme":"動作與行為","examples":[{"en":"Let's split the bill evenly among us.","zh":"我們平均分攤帳單吧。"},{"en":"Let's split the pizza so everyone gets a piece.","zh":"我們把披薩分了吧,好讓每個人都有一塊。"},{"en":"The strong wind split the old tree in two.","zh":"強風把那棵老樹劈成了兩半。"}]},{"word":"spoil","pos":"v.","phonetic":"[spɔɪl]","meaning":"破壞；寵壞；(食物)腐壞","definition":"to damage or ruin something, or to ruin a child by giving too much","collocations":["spoil the fun","spoil a child","food spoils"],"example":"The rain spoiled our picnic plans.","exampleZh":"這場雨破壞了我們的野餐計畫。","synonyms":["ruin"],"level":3,"theme":"動作與行為","examples":[{"en":"The rain spoiled our picnic plans.","zh":"這場雨破壞了我們的野餐計畫。"},{"en":"Don't let one bad review spoil your happy day.","zh":"別讓一則負評破壞了你愉快的一天。"},{"en":"The milk will spoil quickly if you leave it out.","zh":"如果你把牛奶放在外面,它很快就會壞掉。"}]},{"word":"sponge","pos":"n.","phonetic":"[spʌndʒ]","meaning":"海綿","definition":"a soft, light material used for cleaning or absorbing liquid","collocations":["wash with a sponge","sea sponge"],"example":"She wiped the table with a wet sponge.","exampleZh":"她用濕海綿擦拭桌子。","synonyms":[],"level":3,"theme":"居家與生活","examples":[{"en":"She wiped the table with a wet sponge.","zh":"她用濕海綿擦拭桌子。"},{"en":"He cleaned the dirty pan with a soft sponge.","zh":"他用一塊柔軟的海綿清洗骯髒的平底鍋。"},{"en":"A dry sponge quickly soaks up the spilled water.","zh":"乾燥的海綿能快速吸乾灑出的水。"}]},{"word":"sponsor","pos":"n. / v.","phonetic":"[ˈspɑnsɚ]","meaning":"贊助者；贊助","definition":"a person or company that provides money to support an event or activity","collocations":["sponsor an event","corporate sponsor"],"example":"A local company agreed to sponsor the school marathon.","exampleZh":"一家本地公司同意贊助這場校園馬拉松。","synonyms":["support","fund"],"level":4,"theme":"商業與金錢","examples":[{"en":"A local company agreed to sponsor the school marathon.","zh":"一家本地公司同意贊助這場校園馬拉松。"},{"en":"A kind company agreed to sponsor the children's art contest.","zh":"一家好心的公司同意贊助兒童美術比賽。"},{"en":"They are looking for a sponsor to fund the new team.","zh":"他們正在尋找贊助者來資助這支新隊伍。"}]},{"word":"spontaneous","pos":"adj.","phonetic":"[spɑnˈteniəs]","meaning":"自發的；即興的","definition":"done or happening without planning in advance","collocations":["spontaneous decision","spontaneous laughter"],"example":"Their trip to the beach was completely spontaneous.","exampleZh":"他們這趟海邊之旅完全是臨時起意。","synonyms":["impulsive"],"level":6,"theme":"性質與描述","examples":[{"en":"Their trip to the beach was completely spontaneous.","zh":"他們這趟海邊之旅完全是臨時起意。"},{"en":"Her spontaneous decision to join the club surprised everyone.","zh":"她臨時決定加入社團,讓大家都很驚訝。"},{"en":"The funny joke caused spontaneous laughter in the room.","zh":"這個有趣的笑話引起了房間裡自然而然的笑聲。"}]},{"word":"spoon","pos":"n.","phonetic":"[spun]","meaning":"湯匙","definition":"a utensil with a small bowl-shaped end used for eating or serving food","collocations":["soup spoon","teaspoon"],"example":"She stirred her coffee with a small spoon.","exampleZh":"她用一支小湯匙攪拌咖啡。","synonyms":[],"level":1,"theme":"食物與烹飪","examples":[{"en":"She stirred her coffee with a small spoon.","zh":"她用一支小湯匙攪拌咖啡。"},{"en":"He ate the soup slowly with a large spoon.","zh":"他用一支大湯匙慢慢地喝湯。"},{"en":"Add one teaspoon of sugar to the warm milk.","zh":"在溫牛奶裡加入一茶匙的糖。"}]},{"word":"sport","pos":"n.","phonetic":"[spɔrt]","meaning":"運動","definition":"a physical activity done for competition, exercise, or enjoyment","collocations":["play sports","favorite sport"],"example":"Basketball is his favorite sport.","exampleZh":"籃球是他最喜歡的運動。","synonyms":[],"level":1,"theme":"運動與休閒","examples":[{"en":"Basketball is his favorite sport.","zh":"籃球是他最喜歡的運動。"},{"en":"Playing sports after school keeps students healthy and active.","zh":"放學後從事運動能讓學生保持健康和活力。"},{"en":"Swimming is a great sport for the whole family.","zh":"游泳是很適合全家人的一項運動。"}]},{"word":"spot","pos":"n. / v.","phonetic":"[spɑt]","meaning":"地點；斑點；發現","definition":"a particular place; a small mark; to notice or see something","collocations":["parking spot","spot the difference"],"example":"We found a nice spot for a picnic near the river.","exampleZh":"我們在河邊找到了一個適合野餐的好地方。","synonyms":["place","location"],"level":2,"theme":"時間與空間","examples":[{"en":"We found a nice spot for a picnic near the river.","zh":"我們在河邊找到了一個適合野餐的好地方。"},{"en":"Can you spot the difference between these two pictures?","zh":"你能找出這兩張圖片之間的不同嗎?"},{"en":"They found a shady spot to rest under the tree.","zh":"他們在樹下找到一個陰涼的地方休息。"}]},{"word":"spotlight","pos":"n.","phonetic":"[ˈspɑtˌlaɪt]","meaning":"聚光燈；焦點","definition":"a strong beam of light directed at one person or thing; public attention","collocations":["in the spotlight","steal the spotlight"],"example":"The singer stood in the spotlight on stage.","exampleZh":"這位歌手站在舞台的聚光燈下。","synonyms":[],"level":4,"theme":"藝術與音樂","examples":[{"en":"The singer stood in the spotlight on stage.","zh":"這位歌手站在舞台的聚光燈下。"},{"en":"The young actor stepped into the spotlight and bowed.","zh":"這位年輕演員走進聚光燈下並鞠躬。"},{"en":"Her brilliant idea put her in the spotlight at school.","zh":"她絕妙的點子讓她在學校成為眾人的焦點。"}]},{"word":"spouse","pos":"n.","phonetic":"[spaʊs]","meaning":"配偶","definition":"a husband or wife","collocations":["spouse and children","future spouse"],"example":"Employees can bring their spouse to the company party.","exampleZh":"員工可以攜帶配偶參加公司派對。","synonyms":[],"level":5,"theme":"人物與家庭","examples":[{"en":"Employees can bring their spouse to the company party.","zh":"員工可以攜帶配偶參加公司派對。"},{"en":"Each employee may invite one spouse to the dinner.","zh":"每位員工可以邀請一位配偶參加晚宴。"},{"en":"She and her spouse enjoy hiking together on weekends.","zh":"她和她的配偶喜歡在週末一起健行。"}]},{"word":"spray","pos":"v. / n.","phonetic":"[spre]","meaning":"噴灑","definition":"to force a liquid out of a container in very small drops","collocations":["spray water","spray paint"],"example":"She sprayed perfume on her wrist before leaving.","exampleZh":"她出門前在手腕上噴了香水。","synonyms":[],"level":3,"theme":"動作與行為","examples":[{"en":"She sprayed perfume on her wrist before leaving.","zh":"她出門前在手腕上噴了香水。"},{"en":"He used a bottle to spray water on the plants.","zh":"他用一個瓶子在植物上噴水。"},{"en":"She sprayed a little perfume before going to the party.","zh":"去派對前她噴了一點香水。"}]},{"word":"spread","pos":"v. / n.","phonetic":"[sprɛd]","meaning":"散布；塗抹；蔓延","definition":"to open out or extend over a wider area","collocations":["spread butter","spread the news","spread out"],"example":"News of the accident spread quickly through the town.","exampleZh":"意外的消息很快就在鎮上傳開了。","synonyms":["extend","expand"],"level":2,"theme":"動作與行為","examples":[{"en":"News of the accident spread quickly through the town.","zh":"意外的消息很快就在鎮上傳開了。"},{"en":"Please help me spread butter evenly on the toast.","zh":"請幫我把奶油均勻地塗在吐司上。"},{"en":"Good news about the school team spread quickly online.","zh":"關於校隊的好消息在網路上迅速傳開。"}]},{"word":"spring","pos":"n. / v.","phonetic":"[sprɪŋ]","meaning":"春天；彈簧；跳躍","definition":"the season after winter; to jump suddenly","collocations":["spring season","spring up","spring water"],"example":"Flowers bloom everywhere in spring.","exampleZh":"春天時到處都開滿了花。","synonyms":[],"level":1,"theme":"天氣與季節","examples":[{"en":"Flowers bloom everywhere in spring.","zh":"春天時到處都開滿了花。"},{"en":"Colorful flowers bloom in the park every spring.","zh":"每年春天公園裡都會開滿繽紛的花朵。"},{"en":"The cat crouched, ready to spring onto the table.","zh":"貓咪蹲伏著,準備躍上桌子。"}]},{"word":"sprinkle","pos":"v.","phonetic":"[ˈsprɪŋkl]","meaning":"灑；撒","definition":"to scatter small drops or particles of something over a surface","collocations":["sprinkle sugar","sprinkle water"],"example":"Sprinkle some cheese on top of the pizza.","exampleZh":"在披薩上灑一些起司。","synonyms":[],"level":4,"theme":"食物與烹飪","examples":[{"en":"Sprinkle some cheese on top of the pizza.","zh":"在披薩上灑一些起司。"},{"en":"She likes to sprinkle sugar on top of her pancakes.","zh":"她喜歡在鬆餅上撒糖。"},{"en":"Sprinkle a little water on the seeds every morning.","zh":"每天早上在種子上灑一點水。"}]},{"word":"sprout","pos":"v. / n.","phonetic":"[spraʊt]","meaning":"發芽；萌芽","definition":"to begin to grow, especially a new plant shoot","collocations":["sprout leaves","bean sprouts"],"example":"The seeds sprouted after just a few days.","exampleZh":"種子才過幾天就發芽了。","synonyms":[],"level":4,"theme":"自然與環境","examples":[{"en":"The seeds sprouted after just a few days.","zh":"種子才過幾天就發芽了。"},{"en":"The bean seeds began to sprout after a few warm days.","zh":"豆子種子在幾個溫暖的日子後開始發芽。"},{"en":"We added fresh bean sprouts to the vegetable soup.","zh":"我們在蔬菜湯裡加了新鮮的豆芽。"}]},{"word":"spy","pos":"n. / v.","phonetic":"[spaɪ]","meaning":"間諜；偵查","definition":"a person who secretly gathers information about another country or organization","collocations":["spy on someone","secret spy"],"example":"The movie is about a spy working for two countries.","exampleZh":"這部電影講述一名為兩國效力的間諜。","synonyms":["agent"],"level":3,"theme":"政治與法律","examples":[{"en":"The movie is about a spy working for two countries.","zh":"這部電影講述一名為兩國效力的間諜。"},{"en":"The exciting novel is about a clever secret spy.","zh":"這部刺激的小說講述一名聰明的秘密間諜。"},{"en":"It is not polite to spy on your neighbors.","zh":"偷偷監視你的鄰居是不禮貌的。"}]},{"word":"squirrel","pos":"n.","phonetic":"[ˈskwɝəl]","meaning":"松鼠","definition":"a small animal with a long bushy tail that lives in trees","collocations":["squirrel nuts","gray squirrel"],"example":"A squirrel buried nuts under the tree for winter.","exampleZh":"一隻松鼠把堅果埋在樹下以備過冬。","synonyms":[],"level":2,"theme":"動物與植物","examples":[{"en":"A squirrel buried nuts under the tree for winter.","zh":"一隻松鼠把堅果埋在樹下以備過冬。"},{"en":"A gray squirrel ran quickly up the tall oak tree.","zh":"一隻灰松鼠迅速地爬上高大的橡樹。"},{"en":"The squirrel gathered nuts to store for the cold winter.","zh":"松鼠收集堅果,儲存起來過寒冷的冬天。"}]},{"word":"stable","pos":"adj. / n.","phonetic":"[ˈstebl̩]","meaning":"穩定的；馬廄","definition":"not likely to change or fail; firm","collocations":["stable economy","stable condition","financially stable"],"example":"The patient's condition is now stable.","exampleZh":"病人的病情現在穩定了。","synonyms":["steady","firm"],"level":3,"theme":"性質與描述","examples":[{"en":"The patient's condition is now stable.","zh":"病人的病情現在穩定了。"},{"en":"A stable economy helps businesses plan for the future.","zh":"穩定的經濟有助於企業規劃未來。"},{"en":"The farmer led the tired horse back to the stable.","zh":"農夫把疲累的馬牽回馬廄。"}]},{"word":"stadium","pos":"n.","phonetic":"[ˈstedɪəm]","meaning":"體育場；運動場","definition":"a large structure with tiered seats for sports events","collocations":["football stadium","packed stadium","home stadium"],"example":"The stadium was full of cheering fans.","exampleZh":"體育場擠滿了歡呼的球迷。","synonyms":["arena"],"level":2,"theme":"運動與休閒","examples":[{"en":"The stadium was full of cheering fans.","zh":"體育場擠滿了歡呼的球迷。"},{"en":"The football stadium can hold thousands of cheering fans.","zh":"這座足球場能容納數千名歡呼的球迷。"},{"en":"We watched the final game at the packed stadium.","zh":"我們在擠滿人的體育場觀看了決賽。"}]},{"word":"staff","pos":"n.","phonetic":"[stæf]","meaning":"職員；全體員工","definition":"the people who work for an organization","collocations":["teaching staff","staff meeting","hospital staff"],"example":"All staff must attend the meeting.","exampleZh":"所有員工都必須參加會議。","synonyms":["personnel","employees"],"level":3,"theme":"工作與職業","examples":[{"en":"All staff must attend the meeting.","zh":"所有員工都必須參加會議。"},{"en":"The hospital staff worked hard to care for patients.","zh":"醫院的員工努力工作照顧病人。"},{"en":"The teaching staff met to discuss the new schedule.","zh":"教職員開會討論新的課程表。"}]},{"word":"stage","pos":"n. / v.","phonetic":"[stedʒ]","meaning":"舞台；階段；舉行","definition":"a platform for performance; a period in a process","collocations":["on stage","stage a play","early stage"],"example":"She walked onto the stage confidently.","exampleZh":"她自信地走上舞台。","synonyms":["phase"],"level":2,"theme":"藝術與音樂","examples":[{"en":"She walked onto the stage confidently.","zh":"她自信地走上舞台。"},{"en":"The singer walked onto the stage to loud applause.","zh":"歌手在熱烈的掌聲中走上舞台。"},{"en":"The project is still at an early stage of planning.","zh":"這個專案仍處於規劃的早期階段。"}]},{"word":"stain","pos":"n. / v.","phonetic":"[sten]","meaning":"污漬；弄髒","definition":"a mark that is difficult to remove","collocations":["coffee stain","stain remover","stained glass"],"example":"The wine left a stain on the tablecloth.","exampleZh":"紅酒在桌布上留下了污漬。","synonyms":["spot","mark"],"level":4,"theme":"居家與生活","examples":[{"en":"The wine left a stain on the tablecloth.","zh":"紅酒在桌布上留下了污漬。"},{"en":"She used a special cleaner to remove the coffee stain.","zh":"她用一種特殊的清潔劑去除咖啡漬。"},{"en":"The colorful stained glass window brightened the whole hall.","zh":"色彩繽紛的彩繪玻璃窗照亮了整個大廳。"}]},{"word":"stair","pos":"n.","phonetic":"[stɛr]","meaning":"樓梯（一階）","definition":"one of a set of steps leading from one floor to another","collocations":["flight of stairs","go up the stairs","stair railing"],"example":"He tripped on the bottom stair.","exampleZh":"他在樓梯最下面一階絆倒了。","synonyms":["step"],"level":1,"theme":"居家與生活","examples":[{"en":"He tripped on the bottom stair.","zh":"他在樓梯最下面一階絆倒了。"},{"en":"She climbed the wooden stairs slowly, carrying a heavy basket of fruit.","zh":"她提著一籃沉重的水果，緩緩爬上木製樓梯。"},{"en":"A firm stair railing helps elderly people go up the stairs safely.","zh":"穩固的樓梯扶手幫助年長者安全地上樓梯。"}]},{"word":"stake","pos":"n. / v.","phonetic":"[stek]","meaning":"賭注；木樁；以...為賭注","definition":"money risked in a bet; a wooden post","collocations":["at stake","raise the stakes","stake a claim"],"example":"His reputation is at stake.","exampleZh":"他的名聲岌岌可危。","synonyms":["bet","wager"],"level":5,"theme":"商業與金錢","examples":[{"en":"His reputation is at stake.","zh":"他的名聲岌岌可危。"},{"en":"The players raised the stakes as the card game grew more exciting.","zh":"隨著牌局越來越刺激，玩家們提高了賭注。"},{"en":"Farmers drove wooden stakes into the ground to support the young trees.","zh":"農夫把木樁打進地裡，用來支撐幼小的樹苗。"}]},{"word":"stall","pos":"n. / v.","phonetic":"[stɔl]","meaning":"攤位；(引擎)熄火","definition":"a small stand for selling goods; to stop working suddenly","collocations":["market stall","engine stalls","stall for time"],"example":"She bought fresh vegetables from a market stall.","exampleZh":"她在市場攤位買了新鮮蔬菜。","synonyms":["booth"],"level":4,"theme":"商業與金錢","examples":[{"en":"She bought fresh vegetables from a market stall.","zh":"她在市場攤位買了新鮮蔬菜。"},{"en":"The old car's engine stalled twice on the way to school.","zh":"那輛老車的引擎在上學途中熄火了兩次。"},{"en":"He tried to stall for time while waiting for his friend to arrive.","zh":"他試圖拖延時間，等著朋友到來。"}]},{"word":"stamp","pos":"n. / v.","phonetic":"[stæmp]","meaning":"郵票；蓋章；跺腳","definition":"a small piece of paper for postage; to bring the foot down heavily","collocations":["postage stamp","stamp collection","stamp your feet"],"example":"He collects rare stamps from around the world.","exampleZh":"他收集世界各地的稀有郵票。","synonyms":["seal"],"level":2,"theme":"溝通與語言","examples":[{"en":"He collects rare stamps from around the world.","zh":"他收集世界各地的稀有郵票。"},{"en":"She stuck a postage stamp on the envelope and mailed the letter.","zh":"她在信封上貼了一張郵票，然後把信寄出。"},{"en":"The angry child stamped his feet loudly on the kitchen floor.","zh":"那個生氣的孩子在廚房地板上大聲跺腳。"}]},{"word":"stand","pos":"v. / n.","phonetic":"[stænd]","meaning":"站立；忍受；攤位","definition":"to be in an upright position; to tolerate","collocations":["stand up","stand for","take a stand"],"example":"I can't stand the noise anymore.","exampleZh":"我再也無法忍受這噪音了。","synonyms":["tolerate","bear"],"level":1,"theme":"動作與行為","examples":[{"en":"I can't stand the noise anymore.","zh":"我再也無法忍受這噪音了。"},{"en":"Please stand up when the national anthem begins to play.","zh":"當國歌開始演奏時，請起立。"},{"en":"She decided to take a stand against unfair treatment at school.","zh":"她決定挺身反對學校裡的不公平待遇。"}]},{"word":"standard","pos":"n. / adj.","phonetic":"[ˈstændɚd]","meaning":"標準；水準的","definition":"a level of quality used as a basis of comparison; usual","collocations":["living standard","standard procedure","meet the standard"],"example":"The hotel maintains high standards of service.","exampleZh":"這家飯店維持高水準的服務。","synonyms":["criterion","norm"],"level":3,"theme":"抽象概念","examples":[{"en":"The hotel maintains high standards of service.","zh":"這家飯店維持高水準的服務。"},{"en":"The factory follows a standard procedure to check every product.","zh":"工廠遵循標準程序來檢查每一件產品。"},{"en":"A good education can raise a family's living standard over time.","zh":"良好的教育能隨著時間提高一個家庭的生活水準。"}]},{"word":"staple","pos":"n. / adj.","phonetic":"[ˈstepl̩]","meaning":"主食；訂書針；主要的","definition":"a basic and important food item or product","collocations":["staple food","staple diet","staple gun"],"example":"Rice is a staple food in many Asian countries.","exampleZh":"米飯是許多亞洲國家的主食。","synonyms":["basic"],"level":5,"theme":"食物與烹飪","examples":[{"en":"Rice is a staple food in many Asian countries.","zh":"米飯是許多亞洲國家的主食。"},{"en":"Noodles are a staple food for many families across Asia.","zh":"麵條是亞洲許多家庭的主食。"},{"en":"He used a staple gun to attach the poster to the wooden board.","zh":"他用釘槍把海報固定在木板上。"}]},{"word":"star","pos":"n. / v.","phonetic":"[stɑr]","meaning":"星星；明星；主演","definition":"a bright object in the night sky; a famous performer","collocations":["movie star","star in a film","shooting star"],"example":"She dreams of becoming a movie star.","exampleZh":"她夢想成為電影明星。","synonyms":["celebrity"],"level":1,"theme":"藝術與音樂","examples":[{"en":"She dreams of becoming a movie star.","zh":"她夢想成為電影明星。"},{"en":"We lay on the grass and counted the bright stars all night.","zh":"我們躺在草地上，整晚數著明亮的星星。"},{"en":"The talented actress will star in a new film next spring.","zh":"這位有才華的女演員將在明年春天主演一部新電影。"}]},{"word":"stare","pos":"v. / n.","phonetic":"[stɛr]","meaning":"盯著看；凝視","definition":"to look fixedly at something for a long time","collocations":["stare at","blank stare","stare into space"],"example":"He stared at the screen for hours.","exampleZh":"他盯著螢幕看了好幾個小時。","synonyms":["gaze","glare"],"level":2,"theme":"動作與行為","examples":[{"en":"He stared at the screen for hours.","zh":"他盯著螢幕看了好幾個小時。"},{"en":"It is rude to stare at strangers on the crowded bus.","zh":"在擁擠的公車上盯著陌生人看是很不禮貌的。"},{"en":"She sat quietly and stared into space, lost in her thoughts.","zh":"她靜靜地坐著，凝視著遠方，陷入了沉思。"}]},{"word":"start","pos":"v. / n.","phonetic":"[stɑrt]","meaning":"開始；出發","definition":"to begin an action or activity","collocations":["start over","from the start","get started"],"example":"We need to start the project today.","exampleZh":"我們今天必須開始這個專案。","synonyms":["begin","commence"],"level":1,"theme":"動作與行為","examples":[{"en":"We need to start the project today.","zh":"我們今天必須開始這個專案。"},{"en":"Let's get started on our homework before the sun goes down.","zh":"我們在太陽下山前開始做功課吧。"},{"en":"If the plan fails, we can always start over from the beginning.","zh":"如果計畫失敗，我們隨時可以從頭重新開始。"}]},{"word":"starve","pos":"v.","phonetic":"[stɑrv]","meaning":"挨餓；餓死","definition":"to suffer or die from lack of food","collocations":["starve to death","starving children","starve for attention"],"example":"Millions of people starve every year.","exampleZh":"每年有數百萬人挨餓。","synonyms":["famish"],"level":4,"theme":"身體與健康","examples":[{"en":"Millions of people starve every year.","zh":"每年有數百萬人挨餓。"},{"en":"Without rain, the crops died and many animals began to starve.","zh":"沒有雨水，農作物枯死，許多動物開始挨餓。"},{"en":"The lonely puppy seemed to starve for attention and love.","zh":"那隻孤單的小狗似乎渴望得到關注與愛。"}]},{"word":"state","pos":"n. / v.","phonetic":"[stet]","meaning":"州；狀態；陳述","definition":"a condition of something; a country's government; to say clearly","collocations":["state of mind","state a fact","state government"],"example":"Please state your name clearly.","exampleZh":"請清楚說出你的名字。","synonyms":["condition","declare"],"level":2,"theme":"政治與法律","examples":[{"en":"Please state your name clearly.","zh":"請清楚說出你的名字。"},{"en":"The witness calmly stated the facts to the police officer.","zh":"目擊者冷靜地向警察陳述了事實。"},{"en":"After the long trip, she was in a tired state of mind.","zh":"經過漫長的旅程後，她的心理狀態十分疲憊。"}]},{"word":"statement","pos":"n.","phonetic":"[ˈstetmənt]","meaning":"陳述；聲明","definition":"something said or written officially","collocations":["make a statement","official statement","bank statement"],"example":"The company issued a statement about the accident.","exampleZh":"公司針對這起意外發表了聲明。","synonyms":["declaration"],"level":3,"theme":"溝通與語言","examples":[{"en":"The company issued a statement about the accident.","zh":"公司針對這起意外發表了聲明。"},{"en":"The principal made a short statement about the new school rules.","zh":"校長針對新的校規發表了一段簡短的聲明。"},{"en":"I check my bank statement carefully at the end of every month.","zh":"我每個月底都會仔細檢查我的銀行對帳單。"}]},{"word":"station","pos":"n.","phonetic":"[ˈsteʃən]","meaning":"車站；電視台；崗位","definition":"a place where trains or buses stop regularly; a broadcasting company","collocations":["train station","gas station","radio station"],"example":"Meet me at the train station at noon.","exampleZh":"中午在火車站跟我見面。","synonyms":["depot"],"level":1,"theme":"交通與旅行","examples":[{"en":"Meet me at the train station at noon.","zh":"中午在火車站跟我見面。"},{"en":"We stopped at a gas station to fill the tank before the trip.","zh":"出發前我們在加油站停下來把油箱加滿。"},{"en":"The local radio station plays soft music every Sunday morning.","zh":"當地的廣播電台每個星期天早上都播放輕柔的音樂。"}]},{"word":"statistic","pos":"n.","phonetic":"[stəˈtɪstɪk]","meaning":"統計數字","definition":"a fact or piece of data based on numerical information","collocations":["crime statistics","official statistics","according to statistics"],"example":"The statistics show a rise in unemployment.","exampleZh":"統計數字顯示失業率上升。","synonyms":["data","figure"],"level":5,"theme":"科學與數學","examples":[{"en":"The statistics show a rise in unemployment.","zh":"統計數字顯示失業率上升。"},{"en":"According to statistics, more teenagers are exercising than before.","zh":"根據統計數字，比以前有更多青少年在運動。"},{"en":"The report included crime statistics from the past ten years.","zh":"這份報告包含了過去十年的犯罪統計數字。"}]},{"word":"statue","pos":"n.","phonetic":"[ˈstætʃu]","meaning":"雕像","definition":"a carved or cast figure of a person or animal","collocations":["bronze statue","erect a statue","Statue of Liberty"],"example":"There is a statue of the founder in the park.","exampleZh":"公園裡有一座創辦人的雕像。","synonyms":["sculpture"],"level":3,"theme":"藝術與音樂","examples":[{"en":"There is a statue of the founder in the park.","zh":"公園裡有一座創辦人的雕像。"},{"en":"Workers spent a year building the huge bronze statue in the square.","zh":"工人們花了一年時間在廣場上建造那座巨大的銅像。"},{"en":"The city plans to erect a statue to honor the famous poet.","zh":"這座城市計畫豎立一座雕像來紀念那位著名的詩人。"}]},{"word":"status","pos":"n.","phonetic":"[ˈstetəs]","meaning":"地位；身份；狀態","definition":"the relative social or professional position of someone","collocations":["social status","marital status","status symbol"],"example":"His social status changed after he became famous.","exampleZh":"他成名後社會地位改變了。","synonyms":["rank","position"],"level":4,"theme":"社會與文化","examples":[{"en":"His social status changed after he became famous.","zh":"他成名後社會地位改變了。"},{"en":"Owning a luxury car is seen by some as a status symbol.","zh":"擁有一輛豪華轎車被某些人視為地位的象徵。"},{"en":"Please fill in your marital status on the application form.","zh":"請在申請表上填寫您的婚姻狀況。"}]},{"word":"stay","pos":"v. / n.","phonetic":"[ste]","meaning":"停留；保持","definition":"to remain in a place or condition","collocations":["stay calm","stay overnight","stay in touch"],"example":"Please stay calm during the fire drill.","exampleZh":"消防演習時請保持冷靜。","synonyms":["remain"],"level":1,"theme":"動作與行為","examples":[{"en":"Please stay calm during the fire drill.","zh":"消防演習時請保持冷靜。"},{"en":"Try to stay calm even when the exam questions look difficult.","zh":"即使考題看起來很難，也要試著保持冷靜。"},{"en":"We plan to stay overnight at a small hotel near the lake.","zh":"我們打算在湖邊的一間小旅館過夜。"}]},{"word":"steady","pos":"adj. / v.","phonetic":"[ˈstɛdɪ]","meaning":"穩定的；使穩固","definition":"firmly fixed or balanced; not changing","collocations":["steady income","steady pace","hold steady"],"example":"He kept a steady pace throughout the race.","exampleZh":"他在比賽中保持穩定的步伐。","synonyms":["stable","constant"],"level":3,"theme":"性質與描述","examples":[{"en":"He kept a steady pace throughout the race.","zh":"他在比賽中保持穩定的步伐。"},{"en":"A steady income allows the young couple to save money each month.","zh":"穩定的收入讓這對年輕夫妻每個月都能存錢。"},{"en":"He held the ladder steady while his brother climbed to the roof.","zh":"他扶穩梯子，讓弟弟爬上屋頂。"}]},{"word":"steak","pos":"n.","phonetic":"[stek]","meaning":"牛排","definition":"a thick slice of meat, especially beef","collocations":["grilled steak","steak knife","medium-rare steak"],"example":"We ordered steak for dinner.","exampleZh":"我們晚餐點了牛排。","synonyms":[],"level":2,"theme":"食物與烹飪","examples":[{"en":"We ordered steak for dinner.","zh":"我們晚餐點了牛排。"},{"en":"The waiter recommended a medium-rare steak with fresh vegetables.","zh":"服務生推薦了一份三分熟的牛排，搭配新鮮蔬菜。"},{"en":"You will need a sharp steak knife to cut this thick meat.","zh":"你需要一把鋒利的牛排刀來切這塊厚肉。"}]},{"word":"steal","pos":"v.","phonetic":"[stil]","meaning":"偷竊","definition":"to take something without permission","collocations":["steal money","steal the show","steal a glance"],"example":"Someone stole my bicycle last night.","exampleZh":"昨晚有人偷了我的腳踏車。","synonyms":["rob","thieve"],"level":2,"theme":"政治與法律","examples":[{"en":"Someone stole my bicycle last night.","zh":"昨晚有人偷了我的腳踏車。"},{"en":"The clever actor managed to steal the show with his funny lines.","zh":"那位聰明的演員憑著他有趣的台詞搶盡了風頭。"},{"en":"She quietly stole a glance at the boy sitting across the room.","zh":"她悄悄地偷看了一眼坐在房間另一頭的男孩。"}]},{"word":"steam","pos":"n. / v.","phonetic":"[stim]","meaning":"蒸汽；蒸","definition":"the hot vapor produced when water boils","collocations":["steam engine","steamed vegetables","let off steam"],"example":"Steam rose from the hot soup.","exampleZh":"熱湯冒出蒸汽。","synonyms":["vapor"],"level":3,"theme":"科學與數學","examples":[{"en":"Steam rose from the hot soup.","zh":"熱湯冒出蒸汽。"},{"en":"My grandmother often serves steamed vegetables with brown rice.","zh":"我奶奶常端出蒸蔬菜搭配糙米飯。"},{"en":"After a stressful week, he plays basketball to let off steam.","zh":"在忙碌緊張的一週後，他打籃球來發洩情緒。"}]},{"word":"steel","pos":"n.","phonetic":"[stil]","meaning":"鋼鐵","definition":"a strong alloy of iron and carbon","collocations":["stainless steel","steel industry","nerves of steel"],"example":"The bridge is made of steel.","exampleZh":"這座橋是用鋼鐵造的。","synonyms":[],"level":3,"theme":"科學與數學","examples":[{"en":"The bridge is made of steel.","zh":"這座橋是用鋼鐵造的。"},{"en":"The kitchen sink is made of shiny stainless steel.","zh":"廚房的水槽是用閃亮的不鏽鋼製成的。"},{"en":"The brave firefighter showed nerves of steel during the rescue.","zh":"那位勇敢的消防員在救援過程中展現了鋼鐵般的膽識。"}]},{"word":"steep","pos":"adj.","phonetic":"[stip]","meaning":"陡峭的；(價格)過高的","definition":"rising or falling sharply","collocations":["steep hill","steep price","steep decline"],"example":"The path up the mountain is very steep.","exampleZh":"上山的小路非常陡峭。","synonyms":["sheer"],"level":4,"theme":"自然與環境","examples":[{"en":"The path up the mountain is very steep.","zh":"上山的小路非常陡峭。"},{"en":"The hikers were tired after climbing the steep hill for hours.","zh":"健行者爬了好幾個小時的陡坡後感到十分疲累。"},{"en":"The steep price of the new phone surprised many customers.","zh":"那支新手機過高的價格讓許多顧客大吃一驚。"}]},{"word":"steer","pos":"v.","phonetic":"[stɪr]","meaning":"駕駛；引導","definition":"to guide the direction of a vehicle or situation","collocations":["steer a car","steer clear of","steer the conversation"],"example":"He steered the boat carefully around the rocks.","exampleZh":"他小心翼翼地駕船繞過岩石。","synonyms":["guide","direct"],"level":4,"theme":"交通與旅行","examples":[{"en":"He steered the boat carefully around the rocks.","zh":"他小心翼翼地駕船繞過岩石。"},{"en":"The teacher tried to steer the conversation back to the main topic.","zh":"老師試著把話題引導回主要的討論重點。"},{"en":"You should steer clear of that muddy road after heavy rain.","zh":"大雨過後，你應該避開那條泥濘的道路。"}]},{"word":"stem","pos":"n. / v.","phonetic":"[stɛm]","meaning":"莖；起源於","definition":"the main stalk of a plant; to originate from something","collocations":["stem from","flower stem","stem cell"],"example":"The problem stems from poor communication.","exampleZh":"這個問題源自於溝通不良。","synonyms":["stalk","originate"],"level":4,"theme":"動物與植物","examples":[{"en":"The problem stems from poor communication.","zh":"這個問題源自於溝通不良。"},{"en":"Many of his health problems stem from a lack of sleep.","zh":"他許多的健康問題都源自於睡眠不足。"},{"en":"She carefully cut the long stem before placing the rose in water.","zh":"她小心地剪掉長長的花莖，才把玫瑰放進水中。"}]},{"word":"step","pos":"n. / v.","phonetic":"[stɛp]","meaning":"步驟；台階；走","definition":"a movement of the foot; a stage in a process","collocations":["step by step","take a step","first step"],"example":"Follow these steps carefully.","exampleZh":"請仔細遵循這些步驟。","synonyms":["stage","pace"],"level":1,"theme":"動作與行為","examples":[{"en":"Follow these steps carefully.","zh":"請仔細遵循這些步驟。"},{"en":"The teacher explained the experiment step by step for the class.","zh":"老師為全班一步一步地講解這個實驗。"},{"en":"Learning to save money is the first step toward independence.","zh":"學會存錢是邁向獨立的第一步。"}]},{"word":"stereo","pos":"n. / adj.","phonetic":"[ˈstɛrɪo]","meaning":"立體聲音響；立體聲的","definition":"a system for playing recorded sound","collocations":["car stereo","stereo system","in stereo"],"example":"He turned up the stereo to full volume.","exampleZh":"他把音響開到最大聲。","synonyms":[],"level":3,"theme":"科技與媒體","examples":[{"en":"He turned up the stereo to full volume.","zh":"他把音響開到最大聲。"},{"en":"He installed a new car stereo to enjoy music on long drives.","zh":"他裝了一套新的車用音響，好在長途開車時享受音樂。"},{"en":"The song sounds much richer when you play it in stereo.","zh":"用立體聲播放時，這首歌聽起來豐富多了。"}]},{"word":"stern","pos":"adj. / n.","phonetic":"[stɜn]","meaning":"嚴厲的；船尾","definition":"serious and strict in manner","collocations":["stern warning","stern look","stern expression"],"example":"The teacher gave a stern warning to the students.","exampleZh":"老師給學生們一個嚴厲的警告。","synonyms":["strict","harsh"],"level":5,"theme":"情緒與感受","examples":[{"en":"The teacher gave a stern warning to the students.","zh":"老師給學生們一個嚴厲的警告。"},{"en":"The coach gave the players a stern look after their careless mistakes.","zh":"教練在球員們粗心犯錯後，給了他們一個嚴厲的眼神。"},{"en":"Her stern expression told us the meeting would be serious.","zh":"她嚴肅的表情告訴我們，這場會議將會很嚴肅。"}]},{"word":"stick","pos":"n. / v.","phonetic":"[stɪk]","meaning":"棍子；黏；堅持","definition":"a thin piece of wood; to adhere to something","collocations":["stick to","walking stick","stick together"],"example":"Let's stick to the original plan.","exampleZh":"我們就堅持原本的計畫吧。","synonyms":["adhere","cling"],"level":2,"theme":"動作與行為","examples":[{"en":"Let's stick to the original plan.","zh":"我們就堅持原本的計畫吧。"},{"en":"No matter what happens, let's stick together as a team.","zh":"無論發生什麼事，我們都要以團隊的方式團結在一起。"},{"en":"The old man walked slowly with the help of a wooden walking stick.","zh":"那位老人拄著木製拐杖慢慢地走著。"}]},{"word":"sticky","pos":"adj.","phonetic":"[ˈstɪkɪ]","meaning":"黏的","definition":"tending to stick to things it touches","collocations":["sticky note","sticky fingers","sticky rice"],"example":"My hands are sticky from the candy.","exampleZh":"我的手因為糖果而黏黏的。","synonyms":["gluey"],"level":2,"theme":"性質與描述","examples":[{"en":"My hands are sticky from the candy.","zh":"我的手因為糖果而黏黏的。"},{"en":"She left a sticky note on the fridge to remind her family.","zh":"她在冰箱上留了一張便利貼提醒家人。"},{"en":"The children's fingers were sticky after eating the sweet cake.","zh":"孩子們吃完甜蛋糕後，手指都黏黏的。"}]},{"word":"stiff","pos":"adj.","phonetic":"[stɪf]","meaning":"僵硬的；困難的","definition":"not easily bent or moved; difficult","collocations":["stiff neck","stiff competition","feel stiff"],"example":"I woke up with a stiff neck this morning.","exampleZh":"我今早醒來脖子僵硬。","synonyms":["rigid"],"level":3,"theme":"身體與健康","examples":[{"en":"I woke up with a stiff neck this morning.","zh":"我今早醒來脖子僵硬。"},{"en":"My legs felt stiff after sitting on the train for six hours.","zh":"在火車上坐了六個小時後，我的雙腿感到僵硬。"},{"en":"The two teams faced stiff competition in the final match.","zh":"兩支隊伍在決賽中面臨激烈的競爭。"}]},{"word":"still","pos":"adv. / adj.","phonetic":"[stɪl]","meaning":"仍然；靜止的","definition":"continuing up to the present time; not moving","collocations":["stand still","still water","still waiting"],"example":"She is still waiting for the bus.","exampleZh":"她仍在等公車。","synonyms":["motionless"],"level":1,"theme":"性質與描述","examples":[{"en":"She is still waiting for the bus.","zh":"她仍在等公車。"},{"en":"The lake was so still that it looked like a giant mirror.","zh":"湖面如此平靜，看起來就像一面巨大的鏡子。"},{"en":"Please stand still while I take a photo of the whole group.","zh":"我幫大家拍合照時，請站著別動。"}]},{"word":"stimulate","pos":"v.","phonetic":"[ˈstɪmjəˌlet]","meaning":"刺激；激勵","definition":"to encourage development or increased activity","collocations":["stimulate growth","stimulate interest","stimulate the economy"],"example":"The teacher tried to stimulate students' interest in science.","exampleZh":"老師試圖激發學生對科學的興趣。","synonyms":["encourage","motivate"],"level":6,"theme":"教育與學習","examples":[{"en":"The teacher tried to stimulate students' interest in science.","zh":"老師試圖激發學生對科學的興趣。"},{"en":"Colorful picture books can stimulate a young child's imagination.","zh":"色彩繽紛的圖畫書能激發幼兒的想像力。"},{"en":"The government hopes the new policy will stimulate the economy.","zh":"政府希望這項新政策能刺激經濟。"}]},{"word":"sting","pos":"v. / n.","phonetic":"[stɪŋ]","meaning":"刺；螫；刺痛","definition":"to prick painfully with a sharp organ or part","collocations":["bee sting","sting badly","sting operation"],"example":"A bee stung him on the arm.","exampleZh":"一隻蜜蜂螫了他的手臂。","synonyms":["prick"],"level":4,"theme":"動物與植物","examples":[{"en":"A bee stung him on the arm.","zh":"一隻蜜蜂螫了他的手臂。"},{"en":"Be careful near the flowers, or a bee might sting you.","zh":"在花叢附近要小心，否則蜜蜂可能會螫你。"},{"en":"The cold wind made his cheeks sting on the winter morning.","zh":"在那個冬天的早晨，冷風讓他的臉頰感到刺痛。"}]},{"word":"stir","pos":"v. / n.","phonetic":"[stɜr]","meaning":"攪拌；引起(騷動)","definition":"to mix a substance with a spoon; to provoke a reaction","collocations":["stir the soup","stir up trouble","cause a stir"],"example":"Stir the sauce until it thickens.","exampleZh":"攪拌醬汁直到變稠。","synonyms":["mix"],"level":3,"theme":"食物與烹飪","examples":[{"en":"Stir the sauce until it thickens.","zh":"攪拌醬汁直到變稠。"},{"en":"Please stir the soup gently so it does not burn.","zh":"請輕輕攪拌湯，這樣才不會燒焦。"},{"en":"The surprising news caused quite a stir among the students.","zh":"這則令人驚訝的消息在學生之間引起了不小的騷動。"}]},{"word":"stitch","pos":"n. / v.","phonetic":"[stɪtʃ]","meaning":"縫線；一針；縫合","definition":"a single loop made by a needle in sewing","collocations":["a stitch in time","get stitches","stitch up a wound"],"example":"He needed five stitches after the accident.","exampleZh":"他在意外後需要縫五針。","synonyms":["sew"],"level":5,"theme":"身體與健康","examples":[{"en":"He needed five stitches after the accident.","zh":"他在意外後需要縫五針。"},{"en":"The nurse said the deep cut would need several stitches.","zh":"護士說這道深深的傷口需要縫好幾針。"},{"en":"My mother taught me how to stitch a button back onto my shirt.","zh":"我媽媽教我如何把鈕扣縫回襯衫上。"}]},{"word":"stock","pos":"n. / v.","phonetic":"[stɑk]","meaning":"股票；存貨；儲備","definition":"shares in a company; goods available for sale","collocations":["stock market","out of stock","stock up on"],"example":"The store is out of stock on that item.","exampleZh":"這家店那項商品缺貨。","synonyms":["shares","inventory"],"level":4,"theme":"商業與金錢","examples":[{"en":"The store is out of stock on that item.","zh":"這家店那項商品缺貨。"},{"en":"The popular toy sold out and is now out of stock everywhere.","zh":"那款熱門玩具賣光了，現在到處都缺貨。"},{"en":"We should stock up on water before the typhoon arrives.","zh":"在颱風來臨前，我們應該儲備好飲用水。"}]},{"word":"stomach","pos":"n.","phonetic":"[ˈstʌmək]","meaning":"胃；腹部","definition":"the organ in the body that digests food","collocations":["stomach ache","empty stomach","upset stomach"],"example":"I have a stomach ache after eating too fast.","exampleZh":"我吃得太快，胃痛。","synonyms":["belly"],"level":2,"theme":"身體與健康","examples":[{"en":"I have a stomach ache after eating too fast.","zh":"我吃得太快，胃痛。"},{"en":"You should not swim right after eating on a full stomach.","zh":"吃飽後不該馬上游泳。"},{"en":"He got an upset stomach after eating too much greasy food.","zh":"他吃了太多油膩的食物後鬧肚子不舒服。"}]},{"word":"stone","pos":"n.","phonetic":"[ston]","meaning":"石頭","definition":"a hard solid mineral matter","collocations":["stone wall","stepping stone","kidney stone"],"example":"The path was paved with smooth stones.","exampleZh":"這條小路鋪滿了平滑的石頭。","synonyms":["rock"],"level":1,"theme":"自然與環境","examples":[{"en":"The path was paved with smooth stones.","zh":"這條小路鋪滿了平滑的石頭。"},{"en":"The children skipped flat stones across the calm river.","zh":"孩子們在平靜的河面上打水漂。"},{"en":"This new job is just a stepping stone to my dream career.","zh":"這份新工作只是通往我理想事業的踏腳石。"}]},{"word":"stool","pos":"n.","phonetic":"[stul]","meaning":"凳子","definition":"a seat without a back or arms","collocations":["bar stool","wooden stool","sit on a stool"],"example":"He sat on a stool at the counter.","exampleZh":"他坐在櫃檯的凳子上。","synonyms":["seat"],"level":3,"theme":"居家與生活","examples":[{"en":"He sat on a stool at the counter.","zh":"他坐在櫃檯的凳子上。"},{"en":"The little girl needed a wooden stool to reach the sink.","zh":"小女孩需要一張木凳才能構到水槽。"},{"en":"He sat on a bar stool and ordered a cup of hot tea.","zh":"他坐在吧台高腳凳上，點了一杯熱茶。"}]},{"word":"stop","pos":"v. / n.","phonetic":"[stɑp]","meaning":"停止；車站","definition":"to cease moving or doing something","collocations":["stop by","bus stop","stop talking"],"example":"Please stop talking during the movie.","exampleZh":"電影播放時請停止交談。","synonyms":["halt","cease"],"level":1,"theme":"動作與行為","examples":[{"en":"Please stop talking during the movie.","zh":"電影播放時請停止交談。"},{"en":"We can stop by the bakery on our way home from school.","zh":"我們放學回家的路上可以順道去麵包店。"},{"en":"The bus stop is just across the street from the library.","zh":"公車站就在圖書館對面的街上。"}]},{"word":"storage","pos":"n.","phonetic":"[ˈstɔrɪdʒ]","meaning":"儲存；倉庫","definition":"the act or space of keeping goods for future use","collocations":["storage space","in storage","storage unit"],"example":"We rented a storage unit for our furniture.","exampleZh":"我們租了一個倉儲單位放家具。","synonyms":["warehouse"],"level":4,"theme":"居家與生活","examples":[{"en":"We rented a storage unit for our furniture.","zh":"我們租了一個倉儲單位放家具。"},{"en":"This laptop has plenty of storage space for photos and videos.","zh":"這台筆記型電腦有充足的儲存空間可以放照片和影片。"},{"en":"We keep our winter clothes in storage during the hot summer.","zh":"炎熱的夏天期間，我們把冬衣收在倉庫裡。"}]},{"word":"store","pos":"n. / v.","phonetic":"[stɔr]","meaning":"商店；儲存","definition":"a shop; to keep something for future use","collocations":["grocery store","store data","department store"],"example":"She bought some bread at the store.","exampleZh":"她在商店買了一些麵包。","synonyms":["shop"],"level":1,"theme":"商業與金錢","examples":[{"en":"She bought some bread at the store.","zh":"她在商店買了一些麵包。"},{"en":"You can store leftover rice in the fridge for a few days.","zh":"你可以把剩飯儲存在冰箱裡放幾天。"},{"en":"The department store is having a big sale this weekend.","zh":"這家百貨公司這個週末正在舉行大特賣。"}]},{"word":"storm","pos":"n. / v.","phonetic":"[stɔrm]","meaning":"暴風雨","definition":"a violent disturbance of the atmosphere","collocations":["thunderstorm","weather the storm","storm warning"],"example":"A severe storm hit the coast last night.","exampleZh":"昨晚一場猛烈的暴風雨襲擊了海岸。","synonyms":["tempest"],"level":2,"theme":"天氣與季節","examples":[{"en":"A severe storm hit the coast last night.","zh":"昨晚一場猛烈的暴風雨襲擊了海岸。"},{"en":"The weather forecast issued a storm warning for the coastal towns.","zh":"氣象預報對沿海城鎮發布了暴風雨警報。"},{"en":"The small village managed to weather the storm without any damage.","zh":"這個小村莊安然度過了暴風雨，沒有任何損失。"}]},{"word":"story","pos":"n.","phonetic":"[ˈstɔrɪ]","meaning":"故事；樓層","definition":"an account of imaginary or real events","collocations":["tell a story","short story","love story"],"example":"She told her children a bedtime story.","exampleZh":"她給孩子們講了一個睡前故事。","synonyms":["tale"],"level":1,"theme":"藝術與音樂","examples":[{"en":"She told her children a bedtime story.","zh":"她給孩子們講了一個睡前故事。"},{"en":"Our teacher asked us to write a short story about friendship.","zh":"老師要我們寫一篇關於友誼的短篇故事。"},{"en":"They live in a tall building with more than twenty stories.","zh":"他們住在一棟超過二十層樓的高樓裡。"}]},{"word":"stove","pos":"n.","phonetic":"[stov]","meaning":"爐子","definition":"an apparatus for cooking or heating","collocations":["gas stove","on the stove","wood stove"],"example":"She left the pot on the stove too long.","exampleZh":"她把鍋子放在爐子上太久了。","synonyms":["cooker"],"level":2,"theme":"食物與烹飪","examples":[{"en":"She left the pot on the stove too long.","zh":"她把鍋子放在爐子上太久了。"},{"en":"She heated the milk slowly on the gas stove for breakfast.","zh":"她在瓦斯爐上慢慢加熱牛奶當早餐。"},{"en":"Never leave a pot boiling on the stove without watching it.","zh":"絕不要讓鍋子在爐子上煮沸卻沒人看著。"}]},{"word":"straight","pos":"adj. / adv.","phonetic":"[stret]","meaning":"直的；直接地","definition":"extending without a curve or bend","collocations":["straight line","go straight","straight ahead"],"example":"Walk straight down this road.","exampleZh":"沿著這條路直走。","synonyms":["direct"],"level":1,"theme":"性質與描述","examples":[{"en":"Walk straight down this road.","zh":"沿著這條路直走。"},{"en":"Draw a straight line from one corner to the other.","zh":"從一個角畫一條直線到另一個角。"},{"en":"After school, he went straight home to finish his project.","zh":"放學後，他直接回家去完成他的專題。"}]},{"word":"strain","pos":"n. / v.","phonetic":"[stren]","meaning":"壓力；拉傷；使緊張","definition":"mental or physical tension; to injure by overuse","collocations":["under strain","strain a muscle","put a strain on"],"example":"He strained his back lifting the box.","exampleZh":"他搬箱子時拉傷了背部。","synonyms":["stress","tension"],"level":5,"theme":"身體與健康","examples":[{"en":"He strained his back lifting the box.","zh":"他搬箱子時拉傷了背部。"},{"en":"The long working hours put a great strain on her health.","zh":"漫長的工作時間對她的健康造成了很大的負擔。"},{"en":"He strained a muscle while lifting weights at the gym.","zh":"他在健身房舉重時拉傷了一條肌肉。"}]},{"word":"strange","pos":"adj.","phonetic":"[strendʒ]","meaning":"奇怪的","definition":"unusual or unfamiliar","collocations":["strange feeling","strange noise","strange behavior"],"example":"I heard a strange noise outside last night.","exampleZh":"我昨晚聽到外面有奇怪的聲音。","synonyms":["odd","weird"],"level":1,"theme":"性質與描述","examples":[{"en":"I heard a strange noise outside last night.","zh":"我昨晚聽到外面有奇怪的聲音。"},{"en":"I had a strange feeling that someone was following me home.","zh":"我有一種奇怪的感覺，好像有人跟著我回家。"},{"en":"The old house made strange noises whenever the wind blew.","zh":"每當風吹起，那間老房子就會發出奇怪的聲響。"}]},{"word":"stranger","pos":"n.","phonetic":"[ˈstrendʒɚ]","meaning":"陌生人","definition":"a person one does not know","collocations":["talk to strangers","total stranger","stranger danger"],"example":"Don't talk to strangers you don't know.","exampleZh":"不要和不認識的陌生人說話。","synonyms":[],"level":2,"theme":"人物與家庭","examples":[{"en":"Don't talk to strangers you don't know.","zh":"不要和不認識的陌生人說話。"},{"en":"A kind stranger helped the lost tourist find the station.","zh":"一位善良的陌生人幫助迷路的觀光客找到車站。"},{"en":"As a total stranger to the city, she often got lost.","zh":"身為這座城市的完全陌生人，她常常迷路。"}]},{"word":"strap","pos":"n. / v.","phonetic":"[stræp]","meaning":"帶子；用帶子綁","definition":"a strip of leather or fabric used to fasten things","collocations":["shoulder strap","seat strap","strap on"],"example":"The bag has an adjustable shoulder strap.","exampleZh":"這個包包有可調式肩帶。","synonyms":["band"],"level":4,"theme":"服裝與外表","examples":[{"en":"The bag has an adjustable shoulder strap.","zh":"這個包包有可調式肩帶。"},{"en":"Remember to strap on your helmet before riding the bicycle.","zh":"騎腳踏車前，記得繫好你的安全帽帶子。"},{"en":"The heavy bag hurt her shoulder because the strap was too thin.","zh":"那個沉重的包包因為帶子太細而弄痛了她的肩膀。"}]},{"word":"strategy","pos":"n.","phonetic":"[ˈstrætədʒɪ]","meaning":"策略","definition":"a plan of action designed to achieve a goal","collocations":["marketing strategy","develop a strategy","long-term strategy"],"example":"The company changed its marketing strategy.","exampleZh":"這家公司改變了行銷策略。","synonyms":["plan","tactic"],"level":5,"theme":"商業與金錢","examples":[{"en":"The company changed its marketing strategy.","zh":"這家公司改變了行銷策略。"},{"en":"The team developed a clever strategy to win the debate contest.","zh":"隊伍想出了一個巧妙的策略來贏得辯論比賽。"},{"en":"A good long-term strategy is needed to protect the forest.","zh":"保護這片森林需要一個良好的長期策略。"}]},{"word":"straw","pos":"n.","phonetic":"[strɔ]","meaning":"稻草；吸管","definition":"dried stalks of grain; a thin tube for drinking","collocations":["drinking straw","straw hat","last straw"],"example":"She drank the juice through a straw.","exampleZh":"她用吸管喝果汁。","synonyms":[],"level":2,"theme":"食物與烹飪","examples":[{"en":"She drank the juice through a straw.","zh":"她用吸管喝果汁。"},{"en":"The farmer covered the young plants with a thick layer of straw.","zh":"農夫用厚厚的一層稻草蓋住幼苗。"},{"en":"Losing his keys was the last straw after a terrible day.","zh":"在糟糕的一天之後，弄丟鑰匙是壓垮他的最後一根稻草。"}]},{"word":"strawberry","pos":"n.","phonetic":"[ˈstrɔˌbɛrɪ]","meaning":"草莓","definition":"a small red juicy fruit","collocations":["strawberry jam","strawberry cake","fresh strawberries"],"example":"We picked strawberries at the farm.","exampleZh":"我們在農場摘草莓。","synonyms":[],"level":1,"theme":"食物與烹飪","examples":[{"en":"We picked strawberries at the farm.","zh":"我們在農場摘草莓。"},{"en":"She spread sweet strawberry jam on a warm slice of toast.","zh":"她在溫熱的吐司上塗了甜甜的草莓果醬。"},{"en":"Fresh strawberries taste wonderful with a little cream on top.","zh":"新鮮草莓上面加一點鮮奶油，味道好極了。"}]},{"word":"stray","pos":"adj. / v.","phonetic":"[stre]","meaning":"流浪的；迷路","definition":"having no home; to wander away from a path","collocations":["stray dog","stray cat","stray from the path"],"example":"They adopted a stray dog from the street.","exampleZh":"他們收養了一隻街上的流浪狗。","synonyms":["wander"],"level":4,"theme":"動物與植物","examples":[{"en":"They adopted a stray dog from the street.","zh":"他們收養了一隻街上的流浪狗。"},{"en":"A hungry stray cat waited quietly outside the restaurant door.","zh":"一隻飢餓的流浪貓靜靜地在餐廳門外等候。"},{"en":"Please don't stray from the path while walking in the forest.","zh":"在森林中行走時，請不要偏離小徑。"}]},{"word":"stream","pos":"n. / v.","phonetic":"[strim]","meaning":"小溪；串流","definition":"a small river; to flow continuously online","collocations":["mountain stream","stream a video","stream of consciousness"],"example":"Fish swam in the clear mountain stream.","exampleZh":"魚兒在清澈的山間小溪中游動。","synonyms":["brook","creek"],"level":3,"theme":"自然與環境","examples":[{"en":"Fish swam in the clear mountain stream.","zh":"魚兒在清澈的山間小溪中游動。"},{"en":"We stopped by a clear mountain stream to rest and drink water.","zh":"我們在一條清澈的山間小溪旁停下來休息、喝水。"},{"en":"Many students stream educational videos to review their lessons.","zh":"許多學生透過串流觀看教學影片來複習功課。"}]},{"word":"street","pos":"n.","phonetic":"[strit]","meaning":"街道","definition":"a public road in a city or town","collocations":["main street","cross the street","street vendor"],"example":"The street was full of shops and cafes.","exampleZh":"這條街上滿是商店和咖啡館。","synonyms":["road","avenue"],"level":1,"theme":"交通與旅行","examples":[{"en":"The street was full of shops and cafes.","zh":"這條街上滿是商店和咖啡館。"},{"en":"Always look both ways before you cross the busy street.","zh":"過繁忙的街道前，一定要左右看清楚。"},{"en":"A friendly street vendor sold hot snacks near the school gate.","zh":"一位親切的街頭小販在校門口附近賣熱騰騰的小吃。"}]},{"word":"strength","pos":"n.","phonetic":"[strɛŋkθ]","meaning":"力量；優點","definition":"the quality of being physically strong","collocations":["physical strength","strength and weakness","gain strength"],"example":"It took great strength to lift the rock.","exampleZh":"需要很大的力量才能舉起那塊岩石。","synonyms":["power","force"],"level":2,"theme":"身體與健康","examples":[{"en":"It took great strength to lift the rock.","zh":"需要很大的力量才能舉起那塊岩石。"},{"en":"After the illness, she slowly gained back her strength.","zh":"生病之後，她慢慢地恢復了體力。"},{"en":"Every student should know their own strengths and weaknesses.","zh":"每位學生都應該了解自己的優點和缺點。"}]},{"word":"strengthen","pos":"v.","phonetic":"[ˈstrɛŋkθən]","meaning":"加強；增強","definition":"to make or become stronger","collocations":["strengthen ties","strengthen muscles","strengthen the economy"],"example":"Exercise helps strengthen your muscles.","exampleZh":"運動有助於增強肌肉。","synonyms":["reinforce"],"level":4,"theme":"身體與健康","examples":[{"en":"Exercise helps strengthen your muscles.","zh":"運動有助於增強肌肉。"},{"en":"Regular swimming can strengthen the muscles in your arms.","zh":"規律的游泳能增強你手臂的肌肉。"},{"en":"The two towns signed an agreement to strengthen their ties.","zh":"這兩個城鎮簽署了一項協議以加強彼此的關係。"}]},{"word":"stress","pos":"n. / v.","phonetic":"[strɛs]","meaning":"壓力；強調","definition":"mental or emotional tension; to emphasize","collocations":["under stress","stress relief","stress the importance"],"example":"Work stress can affect your health.","exampleZh":"工作壓力會影響你的健康。","synonyms":["pressure","tension"],"level":3,"theme":"情緒與感受","examples":[{"en":"Work stress can affect your health.","zh":"工作壓力會影響你的健康。"},{"en":"The teacher stressed the importance of reading every day.","zh":"老師強調每天閱讀的重要性。"},{"en":"Too much stress before exams can make students feel sick.","zh":"考試前過多的壓力會讓學生覺得不舒服。"}]},{"word":"stretch","pos":"v. / n.","phonetic":"[strɛtʃ]","meaning":"伸展；延伸","definition":"to extend or lengthen the body or a material","collocations":["stretch out","stretch your legs","stretch of road"],"example":"She stretched her arms after sitting all day.","exampleZh":"她坐了一整天後伸展手臂。","synonyms":["extend"],"level":3,"theme":"動作與行為","examples":[{"en":"She stretched her arms after sitting all day.","zh":"她坐了一整天後伸展手臂。"},{"en":"Remember to stretch your legs before you go for a run.","zh":"去跑步前記得先伸展你的雙腿。"},{"en":"A long stretch of road lay ahead of the tired travelers.","zh":"一段漫長的道路橫在疲憊的旅人面前。"}]},{"word":"strict","pos":"adj.","phonetic":"[strɪkt]","meaning":"嚴格的","definition":"demanding that rules be obeyed","collocations":["strict rules","strict teacher","strict diet"],"example":"My parents are strict about homework.","exampleZh":"我爸媽對作業很嚴格。","synonyms":["rigid","stern"],"level":3,"theme":"性質與描述","examples":[{"en":"My parents are strict about homework.","zh":"我爸媽對作業很嚴格。"},{"en":"The new teacher is very strict about arriving to class on time.","zh":"這位新老師對準時上課要求非常嚴格。"},{"en":"The athlete follows a strict diet to stay in good shape.","zh":"這位運動員遵守嚴格的飲食來保持良好的體態。"}]},{"word":"stride","pos":"n. / v.","phonetic":"[straɪd]","meaning":"大步；闊步走","definition":"a long confident step; to walk with long steps","collocations":["make strides","stride forward","take in stride"],"example":"He walked with confident strides across the stage.","exampleZh":"他自信地大步走過舞台。","synonyms":["pace","step"],"level":6,"theme":"動作與行為","examples":[{"en":"He walked with confident strides across the stage.","zh":"他自信地大步走過舞台。"},{"en":"The team has made great strides in improving their teamwork.","zh":"這支隊伍在改善團隊合作方面有了很大的進步。"},{"en":"She strode forward confidently to accept her award on stage.","zh":"她自信地大步向前，在台上領取她的獎項。"}]},{"word":"strike","pos":"v. / n.","phonetic":"[straɪk]","meaning":"打；罷工；打擊","definition":"to hit forcefully; a refusal to work as a form of protest","collocations":["go on strike","strike a balance","lightning strike"],"example":"Workers decided to go on strike for higher wages.","exampleZh":"工人們決定為爭取更高工資而罷工。","synonyms":["hit"],"level":4,"theme":"工作與職業","examples":[{"en":"Workers decided to go on strike for higher wages.","zh":"工人們決定為爭取更高工資而罷工。"},{"en":"It is difficult to strike a balance between study and rest.","zh":"在讀書和休息之間取得平衡是很困難的。"},{"en":"A sudden lightning strike lit up the dark evening sky.","zh":"一道突如其來的閃電照亮了漆黑的夜空。"}]},{"word":"string","pos":"n.","phonetic":"[strɪŋ]","meaning":"繩子；弦","definition":"thin cord; a series of connected items","collocations":["string instrument","guitar string","string of events"],"example":"He tied the box with a piece of string.","exampleZh":"他用一條繩子綁住盒子。","synonyms":["cord","thread"],"level":2,"theme":"藝術與音樂","examples":[{"en":"He tied the box with a piece of string.","zh":"他用一條繩子綁住盒子。"},{"en":"The guitar player replaced a broken string before the concert.","zh":"吉他手在演唱會前換掉了一根斷掉的弦。"},{"en":"A strange string of events led to their surprising victory.","zh":"一連串奇怪的事件促成了他們令人驚訝的勝利。"}]},{"word":"strip","pos":"n. / v.","phonetic":"[strɪp]","meaning":"條狀物；脫去","definition":"a narrow piece of something; to remove a covering","collocations":["strip of paper","strip away","comic strip"],"example":"She cut the paper into thin strips.","exampleZh":"她把紙剪成細條狀。","synonyms":[],"level":4,"theme":"性質與描述","examples":[{"en":"She cut the paper into thin strips.","zh":"她把紙剪成細條狀。"},{"en":"She tore the old wallpaper and stripped the walls bare.","zh":"她撕掉舊壁紙，把牆面剝得光禿禿的。"},{"en":"The children love reading the funny comic strip every Sunday.","zh":"孩子們喜歡每個星期天閱讀那則有趣的連環漫畫。"}]},{"word":"stripe","pos":"n.","phonetic":"[straɪp]","meaning":"條紋","definition":"a long narrow band of color","collocations":["red stripes","striped shirt","tiger stripes"],"example":"The shirt has blue and white stripes.","exampleZh":"這件襯衫有藍白條紋。","synonyms":["band"],"level":3,"theme":"服裝與外表","examples":[{"en":"The shirt has blue and white stripes.","zh":"這件襯衫有藍白條紋。"},{"en":"The referee wore a shirt with black and white stripes.","zh":"裁判穿著一件黑白條紋的衣服。"},{"en":"A tiger's orange coat is covered with dark stripes.","zh":"老虎橙色的毛皮上布滿了深色的條紋。"}]},{"word":"strive","pos":"v.","phonetic":"[straɪv]","meaning":"努力奮鬥","definition":"to make great efforts to achieve something","collocations":["strive for excellence","strive to succeed","strive hard"],"example":"We should strive for excellence in everything we do.","exampleZh":"我們做任何事都應該力求卓越。","synonyms":["struggle","endeavor"],"level":5,"theme":"抽象概念","examples":[{"en":"We should strive for excellence in everything we do.","zh":"我們做任何事都應該力求卓越。"},{"en":"Young athletes strive to succeed through years of hard training.","zh":"年輕的運動員透過多年的刻苦訓練，努力爭取成功。"},{"en":"Our school encourages every student to strive for excellence.","zh":"我們學校鼓勵每位學生追求卓越。"}]},{"word":"stroke","pos":"n. / v.","phonetic":"[strok]","meaning":"中風；筆劃；輕撫","definition":"a sudden loss of brain function; to touch gently","collocations":["heat stroke","stroke of luck","stroke a cat"],"example":"Her grandfather suffered a stroke last year.","exampleZh":"她祖父去年中風了。","synonyms":[],"level":5,"theme":"身體與健康","examples":[{"en":"Her grandfather suffered a stroke last year.","zh":"她祖父去年中風了。"},{"en":"Winning the writing contest was an amazing stroke of luck.","zh":"贏得寫作比賽真是令人驚喜的一次好運。"},{"en":"The gentle girl loves to stroke her cat's soft fur.","zh":"那個溫柔的女孩喜歡輕撫她貓咪柔軟的毛。"}]},{"word":"stroll","pos":"v. / n.","phonetic":"[strol]","meaning":"散步；漫步","definition":"to walk in a leisurely, relaxed way","collocations":["take a stroll","stroll along the beach","evening stroll"],"example":"We strolled along the beach at sunset.","exampleZh":"我們在日落時沿著海灘散步。","synonyms":["walk","wander"],"level":4,"theme":"運動與休閒","examples":[{"en":"We strolled along the beach at sunset.","zh":"我們在日落時沿著海灘散步。"},{"en":"Every evening, the elderly couple takes a stroll in the park.","zh":"每天傍晚，那對年長的夫妻都會在公園裡散步。"},{"en":"We strolled along the quiet street, enjoying the cool breeze.","zh":"我們沿著寧靜的街道漫步，享受著涼爽的微風。"}]},{"word":"strong","pos":"adj.","phonetic":"[strɔŋ]","meaning":"強壯的；濃烈的","definition":"having great physical power or force","collocations":["strong coffee","strong will","strong wind"],"example":"He is strong enough to lift heavy boxes.","exampleZh":"他強壯得足以舉起重箱子。","synonyms":["powerful","tough"],"level":1,"theme":"性質與描述","examples":[{"en":"He is strong enough to lift heavy boxes.","zh":"他強壯得足以舉起重箱子。"},{"en":"A strong wind blew the umbrella right out of her hands.","zh":"一陣強風把雨傘從她手中吹走。"},{"en":"My father drinks a cup of strong coffee every morning.","zh":"我爸爸每天早上都喝一杯濃咖啡。"}]},{"word":"structure","pos":"n. / v.","phonetic":"[ˈstrʌktʃɚ]","meaning":"結構；建築物","definition":"the arrangement of and relations between the parts","collocations":["social structure","sentence structure","building structure"],"example":"The novel has an unusual narrative structure.","exampleZh":"這部小說有不尋常的敘事結構。","synonyms":["framework"],"level":4,"theme":"抽象概念","examples":[{"en":"The novel has an unusual narrative structure.","zh":"這部小說有不尋常的敘事結構。"},{"en":"The teacher explained the basic structure of an English sentence.","zh":"老師講解了英語句子的基本結構。"},{"en":"That ancient stone structure has stood for over a thousand years.","zh":"那座古老的石造建築已經屹立超過一千年了。"}]},{"word":"struggle","pos":"v. / n.","phonetic":"[ˈstrʌgl̩]","meaning":"掙扎；奮鬥","definition":"to try hard to overcome a difficulty","collocations":["struggle with","power struggle","struggle to survive"],"example":"She struggled to finish the marathon.","exampleZh":"她努力掙扎完成馬拉松。","synonyms":["strive","fight"],"level":3,"theme":"抽象概念","examples":[{"en":"She struggled to finish the marathon.","zh":"她努力掙扎完成馬拉松。"},{"en":"Many new students struggle with math during their first year.","zh":"許多新生在第一年都對數學感到吃力。"},{"en":"The poor family had to struggle to survive each winter.","zh":"那個貧窮的家庭每年冬天都得掙扎求生。"}]},{"word":"stubborn","pos":"adj.","phonetic":"[ˈstʌbɚn]","meaning":"頑固的","definition":"refusing to change one's mind or course of action","collocations":["stubborn as a mule","stubborn refusal","stubborn stain"],"example":"He is too stubborn to admit his mistake.","exampleZh":"他太頑固了，不肯承認自己的錯誤。","synonyms":["obstinate"],"level":4,"theme":"情緒與感受","examples":[{"en":"He is too stubborn to admit his mistake.","zh":"他太頑固了，不肯承認自己的錯誤。"},{"en":"He is as stubborn as a mule and never listens to advice.","zh":"他頑固得像頭騾子，從不聽別人的建議。"},{"en":"No matter how hard she scrubbed, the stubborn stain remained.","zh":"無論她多麼用力刷洗，那個頑固的污漬仍然存在。"}]},{"word":"student","pos":"n.","phonetic":"[ˈstjudnt]","meaning":"學生","definition":"a person who is studying at a school or college","collocations":["college student","student loan","exchange student"],"example":"She is a diligent student who studies hard.","exampleZh":"她是個努力讀書的勤奮學生。","synonyms":["pupil","learner"],"level":1,"theme":"教育與學習","examples":[{"en":"She is a diligent student who studies hard.","zh":"她是個努力讀書的勤奮學生。"},{"en":"The exchange student quickly made many friends at our school.","zh":"那位交換學生很快就在我們學校交到許多朋友。"},{"en":"Many college students take out a student loan to pay for school.","zh":"許多大學生借學生貸款來支付學費。"}]},{"word":"studio","pos":"n.","phonetic":"[ˈstjudɪˌo]","meaning":"工作室；攝影棚","definition":"a room where an artist works or media is produced","collocations":["recording studio","art studio","studio apartment"],"example":"The band recorded their album in a studio.","exampleZh":"樂團在錄音室錄製專輯。","synonyms":["workshop"],"level":3,"theme":"藝術與音樂","examples":[{"en":"The band recorded their album in a studio.","zh":"樂團在錄音室錄製專輯。"},{"en":"The young painter rented a bright art studio downtown.","zh":"那位年輕的畫家在市中心租了一間明亮的畫室。"},{"en":"They recorded the whole song in a professional recording studio.","zh":"他們在一間專業的錄音室錄製了整首歌。"}]},{"word":"study","pos":"v. / n.","phonetic":"[ˈstʌdɪ]","meaning":"學習；研究","definition":"to learn about a subject through reading or research","collocations":["study abroad","study hard","case study"],"example":"She plans to study medicine in college.","exampleZh":"她計畫在大學攻讀醫學。","synonyms":["learn","research"],"level":1,"theme":"教育與學習","examples":[{"en":"She plans to study medicine in college.","zh":"她計畫在大學攻讀醫學。"},{"en":"She hopes to study abroad after finishing high school.","zh":"她希望高中畢業後出國留學。"},{"en":"A recent case study showed how exercise improves memory.","zh":"最近一項個案研究顯示運動如何增進記憶力。"}]},{"word":"stuff","pos":"n. / v.","phonetic":"[stʌf]","meaning":"東西；填塞","definition":"things or material of an unspecified kind; to fill tightly","collocations":["kid stuff","stuff a turkey","stuff with"],"example":"Please put your stuff away before dinner.","exampleZh":"晚餐前請把你的東西收好。","synonyms":["things","items"],"level":2,"theme":"其他","examples":[{"en":"Please put your stuff away before dinner.","zh":"晚餐前請把你的東西收好。"},{"en":"He cleared all his stuff off the desk before the exam.","zh":"考試前他把桌上所有的東西都清理乾淨。"},{"en":"My grandmother likes to stuff the turkey with bread and herbs.","zh":"我奶奶喜歡用麵包和香草填塞火雞。"}]},{"word":"stumble","pos":"v.","phonetic":"[ˈstʌmbl̩]","meaning":"絆倒；蹣跚","definition":"to trip and almost fall","collocations":["stumble upon","stumble over","stumble across"],"example":"He stumbled over a rock in the dark.","exampleZh":"他在黑暗中被石頭絆倒。","synonyms":["trip"],"level":5,"theme":"動作與行為","examples":[{"en":"He stumbled over a rock in the dark.","zh":"他在黑暗中被石頭絆倒。"},{"en":"While hiking, we stumbled upon a hidden waterfall in the woods.","zh":"健行時，我們無意間發現了森林裡一座隱密的瀑布。"},{"en":"She stumbled over the loose carpet but did not fall down.","zh":"她被鬆動的地毯絆了一下，但沒有跌倒。"}]},{"word":"stupid","pos":"adj.","phonetic":"[ˈstjupɪd]","meaning":"愚蠢的","definition":"lacking intelligence or good sense","collocations":["stupid mistake","feel stupid","stupid idea"],"example":"It was stupid of me to forget my keys.","exampleZh":"我忘記帶鑰匙真是愚蠢。","synonyms":["foolish","silly"],"level":1,"theme":"性質與描述","examples":[{"en":"It was stupid of me to forget my keys.","zh":"我忘記帶鑰匙真是愚蠢。"},{"en":"Forgetting to save the file was a stupid mistake.","zh":"忘記存檔是個愚蠢的錯誤。"},{"en":"Don't feel stupid for asking questions; curiosity helps you learn.","zh":"別因為發問而覺得自己笨；好奇心能幫助你學習。"}]},{"word":"sturdy","pos":"adj.","phonetic":"[ˈstɜdɪ]","meaning":"堅固的；結實的","definition":"strongly and solidly built","collocations":["sturdy table","sturdy shoes","sturdy build"],"example":"We need a sturdy table for the workshop.","exampleZh":"我們需要一張堅固的桌子做工作坊用。","synonyms":["solid","robust"],"level":5,"theme":"性質與描述","examples":[{"en":"We need a sturdy table for the workshop.","zh":"我們需要一張堅固的桌子做工作坊用。"},{"en":"These sturdy hiking shoes can handle rough mountain trails.","zh":"這雙結實的登山鞋能應付崎嶇的山路。"},{"en":"The carpenter built a sturdy table that will last for years.","zh":"木匠打造了一張堅固的桌子，可以用上好幾年。"}]},{"word":"style","pos":"n. / v.","phonetic":"[staɪl]","meaning":"風格；款式","definition":"a distinctive manner of doing or making something","collocations":["hair style","lifestyle","in style"],"example":"She has her own unique style of writing.","exampleZh":"她有自己獨特的寫作風格。","synonyms":["fashion","manner"],"level":2,"theme":"服裝與外表","examples":[{"en":"She has her own unique style of writing.","zh":"她有自己獨特的寫作風格。"},{"en":"This restaurant serves noodles cooked in a traditional style.","zh":"這家餐廳供應以傳統方式烹煮的麵。"},{"en":"Bright colors and short skirts are back in style this year.","zh":"今年鮮豔的顏色和短裙又開始流行了。"}]},{"word":"subject","pos":"n. / adj. / v.","phonetic":"[ˈsʌbdʒɪkt]","meaning":"科目；主題；使遭受","definition":"a branch of study; a topic being discussed","collocations":["subject matter","favorite subject","subject to change"],"example":"Math is my favorite subject in school.","exampleZh":"數學是我在學校最喜歡的科目。","synonyms":["topic"],"level":2,"theme":"教育與學習","examples":[{"en":"Math is my favorite subject in school.","zh":"數學是我在學校最喜歡的科目。"},{"en":"History is the subject that interests me the most.","zh":"歷史是最讓我感興趣的科目。"},{"en":"The prices on the menu are subject to change without notice.","zh":"菜單上的價格可能隨時變動，恕不另行通知。"}]},{"word":"submarine","pos":"n.","phonetic":"[ˈsʌbməˌrin]","meaning":"潛水艇","definition":"a ship that can operate underwater","collocations":["nuclear submarine","submarine sandwich","submarine warfare"],"example":"The navy launched a new submarine.","exampleZh":"海軍下水了一艘新潛艇。","synonyms":[],"level":4,"theme":"交通與旅行","examples":[{"en":"The navy launched a new submarine.","zh":"海軍下水了一艘新潛艇。"},{"en":"The scientists used a small submarine to explore the deep ocean.","zh":"科學家們用一艘小型潛水艇來探索深海。"},{"en":"For lunch, he ordered a large submarine sandwich with cheese.","zh":"午餐時，他點了一份加了起司的大潛艇堡。"}]},{"word":"submit","pos":"v.","phonetic":"[səbˈmɪt]","meaning":"提交；屈服","definition":"to hand in for consideration; to give in to authority","collocations":["submit an application","submit to","submit a report"],"example":"Please submit your homework by Friday.","exampleZh":"請在星期五前繳交作業。","synonyms":["hand in","yield"],"level":4,"theme":"教育與學習","examples":[{"en":"Please submit your homework by Friday.","zh":"請在星期五前繳交作業。"},{"en":"Students must submit their application before the end of March.","zh":"學生必須在三月底前提交申請。"},{"en":"Please submit the report to your teacher by tomorrow morning.","zh":"請在明天早上前把報告交給你的老師。"}]},{"word":"substance","pos":"n.","phonetic":"[ˈsʌbstəns]","meaning":"物質；實質","definition":"a particular kind of matter with uniform properties","collocations":["chemical substance","illegal substance","substance abuse"],"example":"The bottle contains a dangerous substance.","exampleZh":"這瓶子裝有危險物質。","synonyms":["matter","material"],"level":5,"theme":"科學與數學","examples":[{"en":"The bottle contains a dangerous substance.","zh":"這瓶子裝有危險物質。"},{"en":"Water is a common substance found almost everywhere on Earth.","zh":"水是一種在地球上幾乎隨處可見的常見物質。"},{"en":"The label warns that the cleaner contains a harmful substance.","zh":"標籤警告說這款清潔劑含有一種有害物質。"}]},{"word":"substitute","pos":"n. / v.","phonetic":"[ˈsʌbstəˌtjut]","meaning":"替代品；代替","definition":"a person or thing used instead of another","collocations":["substitute teacher","sugar substitute","substitute for"],"example":"Honey can be used as a substitute for sugar.","exampleZh":"蜂蜜可以用來代替糖。","synonyms":["replacement","alternative"],"level":5,"theme":"抽象概念","examples":[{"en":"Honey can be used as a substitute for sugar.","zh":"蜂蜜可以用來代替糖。"},{"en":"Our regular teacher was sick, so a substitute taught the class.","zh":"我們的正式老師生病了，所以由一位代課老師上課。"},{"en":"You can substitute honey for sugar in this simple recipe.","zh":"在這道簡單的食譜中，你可以用蜂蜜代替糖。"}]},{"word":"subtle","pos":"adj.","phonetic":"[ˈsʌtl̩]","meaning":"微妙的；細微的","definition":"not obvious or immediately noticeable; delicate","collocations":["subtle difference","subtle hint","subtle change"],"example":"There is a subtle difference between the two colors.","exampleZh":"這兩種顏色之間有微妙的差異。","synonyms":["delicate","faint"],"level":6,"theme":"性質與描述","examples":[{"en":"There is a subtle difference between the two colors.","zh":"這兩種顏色之間有微妙的差異。"},{"en":"There is a subtle difference between the twin sisters' voices.","zh":"這對雙胞胎姊妹的聲音之間有著細微的差別。"},{"en":"She gave a subtle hint that she wanted to leave early.","zh":"她給了一個微妙的暗示，表示她想早點離開。"}]},{"word":"suburb","pos":"n.","phonetic":"[ˈsʌbɜb]","meaning":"郊區","definition":"a residential area on the outskirts of a city","collocations":["live in the suburbs","quiet suburb","suburb of Taipei"],"example":"They moved to a suburb outside the city.","exampleZh":"他們搬到城外的郊區居住。","synonyms":["outskirts"],"level":4,"theme":"居家與生活","examples":[{"en":"They moved to a suburb outside the city.","zh":"他們搬到城外的郊區居住。"},{"en":"They enjoy the fresh air of a quiet suburb far from traffic.","zh":"他們享受著遠離車流、寧靜郊區的新鮮空氣。"},{"en":"Many families choose to live in the suburbs to raise children.","zh":"許多家庭選擇住在郊區養育孩子。"}]},{"word":"subway","pos":"n.","phonetic":"[ˈsʌbˌwe]","meaning":"地下鐵","definition":"an underground railway system in a city","collocations":["take the subway","subway station","subway line"],"example":"I take the subway to work every day.","exampleZh":"我每天搭地下鐵上班。","synonyms":["metro"],"level":2,"theme":"交通與旅行","examples":[{"en":"I take the subway to work every day.","zh":"我每天搭地下鐵上班。"},{"en":"The subway station is only a short walk from my apartment.","zh":"地鐵站離我的公寓只有幾分鐘的步行路程。"},{"en":"During rush hour, the subway line is always very crowded.","zh":"在尖峰時段，這條地鐵線總是非常擁擠。"}]},{"word":"succeed","pos":"v.","phonetic":"[səkˈsid]","meaning":"成功；繼承","definition":"to achieve a desired aim or result","collocations":["succeed in","succeed at","succeed the throne"],"example":"She worked hard and finally succeeded.","exampleZh":"她努力工作，終於成功了。","synonyms":["prosper"],"level":3,"theme":"抽象概念","examples":[{"en":"She worked hard and finally succeeded.","zh":"她努力工作，終於成功了。"},{"en":"If you keep practicing, you will surely succeed in the end.","zh":"只要你持續練習，最後一定會成功。"},{"en":"She hopes to succeed in becoming a professional dancer.","zh":"她希望能成功成為一名專業舞者。"}]},{"word":"success","pos":"n.","phonetic":"[səkˈsɛs]","meaning":"成功","definition":"the accomplishment of an aim or purpose","collocations":["key to success","great success","achieve success"],"example":"Hard work is the key to success.","exampleZh":"努力是成功的關鍵。","synonyms":["achievement"],"level":2,"theme":"抽象概念","examples":[{"en":"Hard work is the key to success.","zh":"努力是成功的關鍵。"},{"en":"The school play was a great success, and everyone applauded.","zh":"學校的話劇非常成功，大家都鼓掌叫好。"},{"en":"Patience and effort are the keys to success in any field.","zh":"耐心和努力是任何領域成功的關鍵。"}]},{"word":"successful","pos":"adj.","phonetic":"[səkˈsɛsfəl]","meaning":"成功的","definition":"achieving the desired aim or result","collocations":["successful career","highly successful","successful attempt"],"example":"He became a successful businessman.","exampleZh":"他成為一位成功的商人。","synonyms":["prosperous"],"level":2,"theme":"抽象概念","examples":[{"en":"He became a successful businessman.","zh":"他成為一位成功的商人。"},{"en":"After many tries, they made a successful attempt to fix the robot.","zh":"經過多次嘗試，他們成功地修好了機器人。"},{"en":"She dreams of building a successful career in medicine.","zh":"她夢想在醫學領域建立成功的事業。"}]},{"word":"sudden","pos":"adj.","phonetic":"[ˈsʌdn̩]","meaning":"突然的","definition":"happening quickly and unexpectedly","collocations":["sudden change","all of a sudden","sudden death"],"example":"There was a sudden change in the weather.","exampleZh":"天氣突然發生了變化。","synonyms":["abrupt","unexpected"],"level":2,"theme":"性質與描述","examples":[{"en":"There was a sudden change in the weather.","zh":"天氣突然發生了變化。"},{"en":"All of a sudden, the lights went out during the concert.","zh":"演唱會進行到一半，燈突然全滅了。"},{"en":"A sudden change in the weather forced us to cancel the picnic.","zh":"天氣突然變化，迫使我們取消了野餐。"}]},{"word":"suffer","pos":"v.","phonetic":"[ˈsʌfɚ]","meaning":"受苦；遭受","definition":"to experience pain, illness, or difficulty","collocations":["suffer from","suffer a loss","suffer pain"],"example":"Many patients suffer from chronic pain.","exampleZh":"許多病人長期忍受慢性疼痛。","synonyms":["endure"],"level":3,"theme":"身體與健康","examples":[{"en":"Many patients suffer from chronic pain.","zh":"許多病人長期忍受慢性疼痛。"},{"en":"Many elderly people suffer from pain in their knees.","zh":"許多老年人飽受膝蓋疼痛之苦。"},{"en":"The small shop suffered a great loss during the flood.","zh":"那家小店在水災中遭受了重大損失。"}]},{"word":"sufficient","pos":"adj.","phonetic":"[səˈfɪʃənt]","meaning":"足夠的","definition":"enough for a particular purpose","collocations":["sufficient evidence","sufficient funds","sufficient time"],"example":"We need sufficient evidence to prove the case.","exampleZh":"我們需要足夠的證據來證明這個案子。","synonyms":["enough","adequate"],"level":5,"theme":"性質與描述","examples":[{"en":"We need sufficient evidence to prove the case.","zh":"我們需要足夠的證據來證明這個案子。"},{"en":"Make sure you have sufficient time to review before the test.","zh":"確保你有足夠的時間在考試前複習。"},{"en":"The charity did not have sufficient funds to help everyone.","zh":"這個慈善機構沒有足夠的資金去幫助每一個人。"}]},{"word":"sugar","pos":"n.","phonetic":"[ˈʃʊgɚ]","meaning":"糖","definition":"a sweet crystalline substance used in food","collocations":["sugar cane","blood sugar","sugar free"],"example":"She takes sugar in her coffee.","exampleZh":"她咖啡裡加糖。","synonyms":[],"level":1,"theme":"食物與烹飪","examples":[{"en":"She takes sugar in her coffee.","zh":"她咖啡裡加糖。"},{"en":"The doctor advised him to eat less sugar to stay healthy.","zh":"醫生建議他少吃糖以保持健康。"},{"en":"Eating too many sweets can raise your blood sugar quickly.","zh":"吃太多甜食會使你的血糖迅速升高。"}]},{"word":"suggest","pos":"v.","phonetic":"[səgˈdʒɛst]","meaning":"建議；暗示","definition":"to put forward an idea or plan for consideration","collocations":["suggest an idea","suggest that","strongly suggest"],"example":"I suggest we leave early to avoid traffic.","exampleZh":"我建議我們早點出發以避開塞車。","synonyms":["recommend","propose"],"level":2,"theme":"溝通與語言","examples":[{"en":"I suggest we leave early to avoid traffic.","zh":"我建議我們早點出發以避開塞車。"},{"en":"The guide suggested that we visit the museum in the morning.","zh":"導遊建議我們早上去參觀博物館。"},{"en":"May I suggest an easier way to solve this math problem?","zh":"我可以建議一個解這道數學題更簡單的方法嗎？"}]},{"word":"suit","pos":"n. / v.","phonetic":"[sut]","meaning":"西裝；適合","definition":"a set of matching clothes; to be convenient or suitable","collocations":["business suit","suit yourself","suit your needs"],"example":"He wore a black suit to the interview.","exampleZh":"他穿著黑色西裝去面試。","synonyms":["fit"],"level":2,"theme":"服裝與外表","examples":[{"en":"He wore a black suit to the interview.","zh":"他穿著黑色西裝去面試。"},{"en":"This quiet apartment would suit your needs perfectly.","zh":"這間安靜的公寓會完全符合你的需求。"},{"en":"If you don't want to join us, then suit yourself.","zh":"如果你不想加入我們，那就隨你的便吧。"}]},{"word":"suitable","pos":"adj.","phonetic":"[ˈsutəbl̩]","meaning":"適合的","definition":"right or appropriate for a particular purpose","collocations":["suitable for","suitable candidate","suitable clothing"],"example":"This movie is not suitable for children.","exampleZh":"這部電影不適合兒童觀看。","synonyms":["appropriate","fitting"],"level":3,"theme":"性質與描述","examples":[{"en":"This movie is not suitable for children.","zh":"這部電影不適合兒童觀看。"},{"en":"These shoes are not suitable for climbing steep mountains.","zh":"這雙鞋不適合攀爬陡峭的山。"},{"en":"The committee chose the most suitable candidate for the job.","zh":"委員會挑選了最適合這份工作的人選。"}]},{"word":"suitcase","pos":"n.","phonetic":"[ˈsutˌkes]","meaning":"手提箱；行李箱","definition":"a rectangular case for carrying clothes and belongings","collocations":["pack a suitcase","heavy suitcase","roll a suitcase"],"example":"She packed her suitcase for the trip.","exampleZh":"她為了旅行打包行李箱。","synonyms":["luggage"],"level":1,"theme":"交通與旅行","examples":[{"en":"She packed her suitcase for the trip.","zh":"她為了旅行打包行李箱。"},{"en":"He could barely lift the heavy suitcase onto the train.","zh":"他幾乎抬不動那個沉重的行李箱上火車。"},{"en":"She rolled her small suitcase quickly through the busy airport.","zh":"她拉著小行李箱快速穿過繁忙的機場。"}]},{"word":"summary","pos":"n.","phonetic":"[ˈsʌmərɪ]","meaning":"摘要","definition":"a brief statement of the main points of something","collocations":["brief summary","in summary","summary of events"],"example":"Please write a summary of the article.","exampleZh":"請寫一篇這篇文章的摘要。","synonyms":["overview","outline"],"level":4,"theme":"教育與學習","examples":[{"en":"Please write a summary of the article.","zh":"請寫一篇這篇文章的摘要。"},{"en":"In summary, exercise and sleep are both important for health.","zh":"總而言之，運動和睡眠對健康都很重要。"},{"en":"He wrote a brief summary of the story in his notebook.","zh":"他在筆記本上寫下了這個故事的簡短摘要。"}]},{"word":"summer","pos":"n.","phonetic":"[ˈsʌmɚ]","meaning":"夏天","definition":"the warmest season of the year","collocations":["summer vacation","summer camp","hot summer"],"example":"We go swimming every summer.","exampleZh":"我們每年夏天都去游泳。","synonyms":[],"level":1,"theme":"天氣與季節","examples":[{"en":"We go swimming every summer.","zh":"我們每年夏天都去游泳。"},{"en":"During summer vacation, we often visit our grandparents in the countryside.","zh":"暑假期間，我們常去鄉下探望祖父母。"},{"en":"The hot summer sun made everyone long for a cold drink.","zh":"炎熱的夏日陽光讓每個人都渴望來杯冷飲。"}]},{"word":"summit","pos":"n.","phonetic":"[ˈsʌmɪt]","meaning":"山頂；高峰會","definition":"the top of a mountain; a meeting of top leaders","collocations":["reach the summit","summit meeting","climate summit"],"example":"They finally reached the summit of the mountain.","exampleZh":"他們終於到達山頂。","synonyms":["peak","top"],"level":5,"theme":"自然與環境","examples":[{"en":"They finally reached the summit of the mountain.","zh":"他們終於到達山頂。"},{"en":"After hours of climbing, they finally reached the snowy summit.","zh":"經過數小時的攀登，他們終於抵達了白雪覆蓋的山頂。"},{"en":"World leaders gathered for a summit meeting on climate change.","zh":"各國領袖齊聚一堂，舉行關於氣候變遷的高峰會。"}]},{"word":"sunrise","pos":"n.","phonetic":"[ˈsʌnˌraɪz]","meaning":"日出","definition":"the time when the sun rises in the morning","collocations":["watch the sunrise","before sunrise","a beautiful sunrise"],"example":"We got up early to watch the sunrise over the mountains.","exampleZh":"我們很早起床欣賞山上的日出。","synonyms":["dawn"],"level":2,"theme":"自然與環境","examples":[{"en":"We got up early to watch the sunrise over the mountains.","zh":"我們很早起床欣賞山上的日出。"},{"en":"The fishermen set out before sunrise to catch fresh fish.","zh":"漁夫們在日出前出發去捕撈新鮮的魚。"},{"en":"We watched a beautiful sunrise from the top of the hill.","zh":"我們從山丘頂上欣賞了美麗的日出。"}]},{"word":"sunset","pos":"n.","phonetic":"[ˈsʌnˌsɛt]","meaning":"日落","definition":"the time when the sun goes down in the evening","collocations":["watch the sunset","at sunset","a golden sunset"],"example":"The sky turned orange at sunset.","exampleZh":"日落時天空變成了橘色。","synonyms":["dusk"],"level":2,"theme":"自然與環境","examples":[{"en":"The sky turned orange at sunset.","zh":"日落時天空變成了橘色。"},{"en":"The whole sky glowed with a golden sunset over the sea.","zh":"整片天空因海上金色的日落而閃耀著光芒。"},{"en":"They lit a small campfire on the beach at sunset.","zh":"日落時分，他們在海灘上升起了一小堆營火。"}]},{"word":"sunshine","pos":"n.","phonetic":"[ˈsʌnˌʃaɪn]","meaning":"陽光","definition":"the light and warmth from the sun","collocations":["bright sunshine","enjoy the sunshine","a ray of sunshine"],"example":"The children played happily in the sunshine.","exampleZh":"孩子們在陽光下開心地玩耍。","synonyms":["sunlight"],"level":2,"theme":"天氣與季節","examples":[{"en":"The children played happily in the sunshine.","zh":"孩子們在陽光下開心地玩耍。"},{"en":"After days of rain, everyone enjoyed the warm sunshine outside.","zh":"在連日下雨之後，大家都享受著戶外溫暖的陽光。"},{"en":"Her cheerful smile was like a ray of sunshine to us.","zh":"她開朗的笑容對我們來說就像一道陽光。"}]},{"word":"superb","pos":"adj.","phonetic":"[sʊˈpɝb]","meaning":"極好的；出色的","definition":"excellent or of very high quality","collocations":["a superb performance","superb quality","do a superb job"],"example":"The chef prepared a superb meal for the guests.","exampleZh":"主廚為客人準備了一頓極好的餐點。","synonyms":["excellent","outstanding"],"level":5,"theme":"性質與描述","examples":[{"en":"The chef prepared a superb meal for the guests.","zh":"主廚為客人準備了一頓極好的餐點。"},{"en":"The young pianist gave a superb performance at the school concert.","zh":"那位年輕的鋼琴家在學校音樂會上有著出色的演出。"},{"en":"The team did a superb job cleaning up the whole beach.","zh":"團隊把整片海灘清理得很出色。"}]},{"word":"superior","pos":"adj. / n.","phonetic":"[səˈpɪriɚ]","meaning":"較優越的；上級","definition":"better in quality, or a person of higher rank","collocations":["superior quality","feel superior","report to a superior"],"example":"This brand is known for its superior quality.","exampleZh":"這個品牌以其優越的品質聞名。","synonyms":["better","excellent"],"level":5,"theme":"性質與描述","examples":[{"en":"This brand is known for its superior quality.","zh":"這個品牌以其優越的品質聞名。"},{"en":"This handmade chair is superior in quality to the cheap ones.","zh":"這把手工椅在品質上比那些便宜的椅子優越。"},{"en":"She reported the problem to her superior at the office.","zh":"她把這個問題向辦公室的上司報告。"}]},{"word":"supermarket","pos":"n.","phonetic":"[ˈsupɚˌmɑrkɪt]","meaning":"超級市場","definition":"a large store selling food and household goods","collocations":["go to the supermarket","shop at a supermarket","a local supermarket"],"example":"My mother buys vegetables at the supermarket every week.","exampleZh":"我媽媽每星期都在超市買菜。","synonyms":[],"level":2,"theme":"居家與生活","examples":[{"en":"My mother buys vegetables at the supermarket every week.","zh":"我媽媽每星期都在超市買菜。"},{"en":"I forgot to buy milk when I went to the supermarket.","zh":"我去超市時忘了買牛奶。"},{"en":"The local supermarket is offering fresh fruit at low prices today.","zh":"當地的超市今天以低價供應新鮮水果。"}]},{"word":"superstition","pos":"n.","phonetic":"[ˌsupɚˈstɪʃən]","meaning":"迷信","definition":"a belief not based on reason or science","collocations":["an old superstition","believe in superstition","local superstitions"],"example":"It is a common superstition that black cats bring bad luck.","exampleZh":"黑貓帶來厄運是一個常見的迷信。","synonyms":[],"level":5,"theme":"社會與文化","examples":[{"en":"It is a common superstition that black cats bring bad luck.","zh":"黑貓帶來厄運是一個常見的迷信。"},{"en":"According to an old superstition, breaking a mirror brings bad luck.","zh":"根據一個古老的迷信，打破鏡子會帶來厄運。"},{"en":"Many local superstitions are passed down from grandparents to children.","zh":"許多當地的迷信是由祖父母傳給孩子的。"}]},{"word":"supper","pos":"n.","phonetic":"[ˈsʌpɚ]","meaning":"晚餐；晚飯","definition":"a meal eaten in the evening","collocations":["have supper","cook supper","a light supper"],"example":"We usually have supper together at seven o'clock.","exampleZh":"我們通常七點一起吃晚餐。","synonyms":["dinner"],"level":2,"theme":"食物與烹飪","examples":[{"en":"We usually have supper together at seven o'clock.","zh":"我們通常七點一起吃晚餐。"},{"en":"After the long walk, we enjoyed a light supper at home.","zh":"在長途散步後，我們在家享用了一頓清淡的晚餐。"},{"en":"My mother is cooking supper while we set the table.","zh":"我媽媽正在煮晚餐，而我們則在擺放餐具。"}]},{"word":"supply","pos":"n. / v.","phonetic":"[səˈplaɪ]","meaning":"供應；供給","definition":"to provide something needed, or the amount provided","collocations":["supply water","food supply","supply and demand"],"example":"The factory supplies parts to car companies worldwide.","exampleZh":"這家工廠供應零件給世界各地的汽車公司。","synonyms":["provide"],"level":3,"theme":"商業與金錢","examples":[{"en":"The factory supplies parts to car companies worldwide.","zh":"這家工廠供應零件給世界各地的汽車公司。"},{"en":"The mountain village depends on trucks to supply fresh food.","zh":"這個山村仰賴卡車來供應新鮮食物。"},{"en":"Prices often rise when supply cannot meet the growing demand.","zh":"當供給無法滿足不斷增長的需求時，價格往往會上漲。"}]},{"word":"support","pos":"v. / n.","phonetic":"[səˈport]","meaning":"支持；支撐","definition":"to help or agree with someone, or to hold something up","collocations":["support a decision","financial support","support each other"],"example":"My family always supports my dreams.","exampleZh":"我的家人總是支持我的夢想。","synonyms":["back","help"],"level":2,"theme":"抽象概念","examples":[{"en":"My family always supports my dreams.","zh":"我的家人總是支持我的夢想。"},{"en":"Good friends support each other through difficult times.","zh":"好朋友會在艱難的時刻互相支持。"},{"en":"Strong steel beams support the roof of the huge hall.","zh":"堅固的鋼樑支撐著這座巨大廳堂的屋頂。"}]},{"word":"suppose","pos":"v.","phonetic":"[səˈpoz]","meaning":"猜想；假定","definition":"to think something is likely true","collocations":["suppose that","be supposed to","I suppose so"],"example":"I suppose she will be late because of the traffic.","exampleZh":"我猜她會因為塞車而遲到。","synonyms":["guess","assume"],"level":3,"theme":"溝通與語言","examples":[{"en":"I suppose she will be late because of the traffic.","zh":"我猜她會因為塞車而遲到。"},{"en":"I suppose the train will be late because of the heavy snow.","zh":"我猜火車會因為大雪而誤點。"},{"en":"You are supposed to return the library books by Friday.","zh":"你應該在星期五之前歸還圖書館的書。"}]},{"word":"supreme","pos":"adj.","phonetic":"[səˈprim]","meaning":"至高的；最高的","definition":"highest in rank, power, or quality","collocations":["supreme court","supreme power","the supreme leader"],"example":"The general was given supreme command of the army.","exampleZh":"這位將軍被授予軍隊的最高指揮權。","synonyms":["highest","ultimate"],"level":5,"theme":"政治與法律","examples":[{"en":"The general was given supreme command of the army.","zh":"這位將軍被授予軍隊的最高指揮權。"},{"en":"The case was finally decided by the country's supreme court.","zh":"這個案件最終由該國的最高法院裁決。"},{"en":"The wise old queen held supreme power over the whole land.","zh":"睿智的老女王對整片土地擁有至高無上的權力。"}]},{"word":"surf","pos":"v. / n.","phonetic":"[sɝf]","meaning":"衝浪；瀏覽","definition":"to ride waves on a board, or to browse online","collocations":["surf the waves","surf the Internet","go surfing"],"example":"He loves to surf every summer at the beach.","exampleZh":"他每年夏天都喜歡去海邊衝浪。","synonyms":[],"level":3,"theme":"運動與休閒","examples":[{"en":"He loves to surf every summer at the beach.","zh":"他每年夏天都喜歡去海邊衝浪。"},{"en":"On sunny weekends, they love to surf the waves at the beach.","zh":"在晴朗的週末，他們喜歡在海灘上乘浪衝浪。"},{"en":"He often surfs the Internet to find interesting science articles.","zh":"他常常上網瀏覽，尋找有趣的科學文章。"}]},{"word":"surface","pos":"n.","phonetic":"[ˈsɝfɪs]","meaning":"表面","definition":"the outer or top layer of something","collocations":["the earth's surface","a smooth surface","rise to the surface"],"example":"The lake's surface was completely frozen.","exampleZh":"湖面完全結冰了。","synonyms":[],"level":3,"theme":"自然與環境","examples":[{"en":"The lake's surface was completely frozen.","zh":"湖面完全結冰了。"},{"en":"The table has a smooth surface that is easy to clean.","zh":"這張桌子有著容易清潔的光滑表面。"},{"en":"A few bubbles slowly rose to the surface of the pond.","zh":"幾個氣泡緩緩升到池塘的水面。"}]},{"word":"surgeon","pos":"n.","phonetic":"[ˈsɝdʒən]","meaning":"外科醫生","definition":"a doctor who performs operations","collocations":["a heart surgeon","become a surgeon","a skilled surgeon"],"example":"The surgeon operated on the patient for six hours.","exampleZh":"這位外科醫生為病人動了六個小時的手術。","synonyms":[],"level":4,"theme":"工作與職業","examples":[{"en":"The surgeon operated on the patient for six hours.","zh":"這位外科醫生為病人動了六個小時的手術。"},{"en":"The skilled surgeon carefully repaired the boy's broken arm.","zh":"技術高超的外科醫生細心地修復了男孩斷掉的手臂。"},{"en":"She studied hard for many years to become a heart surgeon.","zh":"她苦讀多年，只為成為一名心臟外科醫生。"}]},{"word":"surgery","pos":"n.","phonetic":"[ˈsɝdʒəri]","meaning":"手術","definition":"medical treatment that involves cutting into the body","collocations":["undergo surgery","perform surgery","need surgery"],"example":"She had surgery on her knee last month.","exampleZh":"她上個月動了膝蓋手術。","synonyms":["operation"],"level":4,"theme":"身體與健康","examples":[{"en":"She had surgery on her knee last month.","zh":"她上個月動了膝蓋手術。"},{"en":"The doctor said he would need surgery to fix his knee.","zh":"醫生說他需要動手術來修復膝蓋。"},{"en":"She felt nervous before undergoing surgery on her shoulder.","zh":"在接受肩膀手術前，她感到很緊張。"}]},{"word":"surname","pos":"n.","phonetic":"[ˈsɝˌnem]","meaning":"姓氏","definition":"a person's family name","collocations":["share a surname","common surname","write your surname"],"example":"Please write your surname before your first name.","exampleZh":"請把姓氏寫在名字之前。","synonyms":["family name"],"level":3,"theme":"人物與家庭","examples":[{"en":"Please write your surname before your first name.","zh":"請把姓氏寫在名字之前。"},{"en":"Many people in this town share the same common surname.","zh":"這個鎮上許多人都有相同的常見姓氏。"},{"en":"The teacher asked each student to write their surname clearly.","zh":"老師要求每位學生把姓氏寫清楚。"}]},{"word":"surplus","pos":"n.","phonetic":"[ˈsɝplʌs]","meaning":"剩餘；盈餘","definition":"an amount left over after needs are met","collocations":["a trade surplus","budget surplus","surplus food"],"example":"The country enjoyed a large trade surplus last year.","exampleZh":"這個國家去年享有龐大的貿易順差。","synonyms":["excess"],"level":5,"theme":"商業與金錢","examples":[{"en":"The country enjoyed a large trade surplus last year.","zh":"這個國家去年享有龐大的貿易順差。"},{"en":"The farm had a surplus of vegetables and gave some away.","zh":"農場有多餘的蔬菜，便分送了一些出去。"},{"en":"A healthy budget surplus allowed the town to build a new library.","zh":"健全的預算盈餘讓小鎮得以興建一座新圖書館。"}]},{"word":"surrender","pos":"v. / n.","phonetic":"[səˈrɛndɚ]","meaning":"投降；放棄","definition":"to stop fighting and admit defeat","collocations":["surrender to the enemy","unconditional surrender","surrender control"],"example":"The soldiers had no choice but to surrender.","exampleZh":"士兵們別無選擇只能投降。","synonyms":["give up"],"level":5,"theme":"政治與法律","examples":[{"en":"The soldiers had no choice but to surrender.","zh":"士兵們別無選擇只能投降。"},{"en":"The tired team refused to surrender until the final whistle.","zh":"疲憊的隊伍直到終場哨聲響起都拒絕放棄。"},{"en":"The trapped soldiers finally chose to surrender to the enemy.","zh":"被困的士兵最終選擇向敵人投降。"}]},{"word":"surround","pos":"v.","phonetic":"[səˈraʊnd]","meaning":"環繞；圍繞","definition":"to be or move all around something","collocations":["surround the building","surrounded by trees","police surrounded the area"],"example":"Tall mountains surround the small village.","exampleZh":"高山環繞著這個小村莊。","synonyms":["encircle"],"level":3,"theme":"自然與環境","examples":[{"en":"Tall mountains surround the small village.","zh":"高山環繞著這個小村莊。"},{"en":"Tall green trees surround the peaceful little cottage.","zh":"高大的綠樹環繞著那間寧靜的小屋。"},{"en":"A wooden fence surrounds the garden to keep the rabbits out.","zh":"一道木籬笆圍繞著花園，防止兔子進入。"}]},{"word":"surroundings","pos":"n.","phonetic":"[səˈraʊndɪŋz]","meaning":"周遭環境","definition":"the conditions and objects around a place","collocations":["peaceful surroundings","familiar surroundings","natural surroundings"],"example":"The hotel is set in beautiful natural surroundings.","exampleZh":"這家飯店坐落在美麗的自然環境中。","synonyms":["environment"],"level":4,"theme":"自然與環境","examples":[{"en":"The hotel is set in beautiful natural surroundings.","zh":"這家飯店坐落在美麗的自然環境中。"},{"en":"The new student slowly got used to his unfamiliar surroundings.","zh":"這位新生慢慢地適應了陌生的周遭環境。"},{"en":"They chose a hotel set in quiet and peaceful surroundings.","zh":"他們選了一間位於安靜祥和環境中的旅館。"}]},{"word":"survey","pos":"n. / v.","phonetic":"[ˈsɝve]","meaning":"調查；問卷","definition":"a study to collect information from people","collocations":["conduct a survey","take a survey","a survey shows that"],"example":"A recent survey shows that most students prefer online classes.","exampleZh":"一項最近的調查顯示大多數學生偏好線上課程。","synonyms":["poll"],"level":4,"theme":"教育與學習","examples":[{"en":"A recent survey shows that most students prefer online classes.","zh":"一項最近的調查顯示大多數學生偏好線上課程。"},{"en":"The class conducted a survey about students' favorite sports.","zh":"全班做了一份關於學生最喜愛運動的調查。"},{"en":"Please take a few minutes to fill out this short survey.","zh":"請花幾分鐘填寫這份簡短的問卷。"}]},{"word":"survival","pos":"n.","phonetic":"[sɚˈvaɪvl̩]","meaning":"生存；倖存","definition":"the state of continuing to live or exist","collocations":["survival skills","fight for survival","survival rate"],"example":"The hikers learned basic survival skills before the trip.","exampleZh":"登山者在旅行前學習了基本的生存技能。","synonyms":[],"level":4,"theme":"抽象概念","examples":[{"en":"The hikers learned basic survival skills before the trip.","zh":"登山者在旅行前學習了基本的生存技能。"},{"en":"Clean water is essential for the survival of every living thing.","zh":"乾淨的水對每一種生物的生存都至關重要。"},{"en":"The campers learned useful survival skills in the wild forest.","zh":"露營者在荒野森林中學會了實用的生存技能。"}]},{"word":"survive","pos":"v.","phonetic":"[sɚˈvaɪv]","meaning":"倖存；存活","definition":"to continue to live after a difficult event","collocations":["survive a disaster","barely survive","survive the winter"],"example":"Only a few passengers survived the crash.","exampleZh":"只有少數乘客在這場空難中倖存。","synonyms":["endure"],"level":3,"theme":"抽象概念","examples":[{"en":"Only a few passengers survived the crash.","zh":"只有少數乘客在這場空難中倖存。"},{"en":"These hardy plants can survive the cold winter without much water.","zh":"這些耐寒的植物不需要太多水就能熬過寒冷的冬天。"},{"en":"Only a few of the tiny turtles survive their first year.","zh":"只有少數小海龜能存活過牠們的第一年。"}]},{"word":"suspect","pos":"v. / n.","phonetic":"[səˈspɛkt]","meaning":"懷疑；嫌疑犯","definition":"to believe something without proof, or a person thought guilty","collocations":["suspect someone","the main suspect","suspect foul play"],"example":"The police suspect that he stole the money.","exampleZh":"警方懷疑他偷了錢。","synonyms":["doubt"],"level":4,"theme":"政治與法律","examples":[{"en":"The police suspect that he stole the money.","zh":"警方懷疑他偷了錢。"},{"en":"The teacher began to suspect that the answers had been copied.","zh":"老師開始懷疑那些答案是抄來的。"},{"en":"The police questioned the main suspect for several hours.","zh":"警方訊問了主要嫌疑犯好幾個小時。"}]},{"word":"suspend","pos":"v.","phonetic":"[səˈspɛnd]","meaning":"暫停；懸掛","definition":"to stop something temporarily, or to hang something","collocations":["suspend a game","suspend a student","suspended from the ceiling"],"example":"The school suspended the student for a week.","exampleZh":"學校讓那名學生停學一週。","synonyms":["postpone"],"level":5,"theme":"教育與學習","examples":[{"en":"The school suspended the student for a week.","zh":"學校讓那名學生停學一週。"},{"en":"The referee had to suspend the game because of the heavy rain.","zh":"裁判因為大雨不得不暫停比賽。"},{"en":"A beautiful lamp was suspended from the ceiling of the hall.","zh":"一盞漂亮的燈懸掛在大廳的天花板上。"}]},{"word":"suspicion","pos":"n.","phonetic":"[səˈspɪʃən]","meaning":"懷疑","definition":"a feeling that something is wrong or someone is guilty","collocations":["arouse suspicion","under suspicion","have a suspicion"],"example":"His strange behavior aroused the teacher's suspicion.","exampleZh":"他古怪的行為引起了老師的懷疑。","synonyms":["doubt"],"level":5,"theme":"抽象概念","examples":[{"en":"His strange behavior aroused the teacher's suspicion.","zh":"他古怪的行為引起了老師的懷疑。"},{"en":"His nervous behavior aroused the guard's suspicion at once.","zh":"他緊張的舉止立刻引起了警衛的懷疑。"},{"en":"She had a strong suspicion that her brother ate the last cookie.","zh":"她強烈懷疑是她弟弟吃了最後一塊餅乾。"}]},{"word":"suspicious","pos":"adj.","phonetic":"[səˈspɪʃəs]","meaning":"可疑的；懷疑的","definition":"causing or feeling a belief that something is wrong","collocations":["look suspicious","a suspicious person","be suspicious of"],"example":"The security guard noticed a suspicious bag near the gate.","exampleZh":"保全人員注意到大門附近有個可疑的包包。","synonyms":["doubtful"],"level":5,"theme":"性質與描述","examples":[{"en":"The security guard noticed a suspicious bag near the gate.","zh":"保全人員注意到大門附近有個可疑的包包。"},{"en":"The clerk became suspicious of the man wearing a heavy coat.","zh":"店員對那個穿著厚外套的男人起了疑心。"},{"en":"A suspicious package was found outside the empty building.","zh":"在那棟空建築外發現了一個可疑的包裹。"}]},{"word":"sustain","pos":"v.","phonetic":"[səˈsten]","meaning":"維持；支撐","definition":"to keep something going or in existence","collocations":["sustain life","sustain economic growth","sustain an injury"],"example":"Farmers work hard to sustain their crops during the drought.","exampleZh":"農夫在乾旱期間努力維持他們的作物。","synonyms":["maintain"],"level":5,"theme":"抽象概念","examples":[{"en":"Farmers work hard to sustain their crops during the drought.","zh":"農夫在乾旱期間努力維持他們的作物。"},{"en":"It is hard to sustain such fast economic growth for long.","zh":"要長期維持如此快速的經濟成長是很困難的。"},{"en":"A balanced diet helps sustain your energy throughout the day.","zh":"均衡的飲食有助於維持你一整天的體力。"}]},{"word":"swallow","pos":"v. / n.","phonetic":"[ˈswɑlo]","meaning":"吞嚥；燕子","definition":"to make food pass down the throat, or a small bird","collocations":["swallow food","swallow pride","a flock of swallows"],"example":"He swallowed the medicine with a glass of water.","exampleZh":"他用一杯水把藥吞下去。","synonyms":[],"level":3,"theme":"身體與健康","examples":[{"en":"He swallowed the medicine with a glass of water.","zh":"他用一杯水把藥吞下去。"},{"en":"The soup was so hot that he could barely swallow it.","zh":"湯太燙了，他幾乎無法吞嚥。"},{"en":"In spring, a flock of swallows returned to build nests.","zh":"春天時，一群燕子回來築巢。"}]},{"word":"swamp","pos":"n.","phonetic":"[swɑmp]","meaning":"沼澤","definition":"an area of very wet, soft land","collocations":["a dark swamp","cross a swamp","swamp creatures"],"example":"Alligators live in the swamps of Florida.","exampleZh":"鱷魚生活在佛羅里達州的沼澤裡。","synonyms":["marsh"],"level":4,"theme":"自然與環境","examples":[{"en":"Alligators live in the swamps of Florida.","zh":"鱷魚生活在佛羅里達州的沼澤裡。"},{"en":"The explorers slowly crossed the dark and muddy swamp.","zh":"探險家們緩緩地穿越那片黑暗又泥濘的沼澤。"},{"en":"Many strange plants and insects live in this wet swamp.","zh":"許多奇特的植物和昆蟲生活在這片潮濕的沼澤裡。"}]},{"word":"swap","pos":"v. / n.","phonetic":"[swɑp]","meaning":"交換","definition":"to exchange one thing for another","collocations":["swap seats","swap ideas","a fair swap"],"example":"Let's swap seats so you can see better.","exampleZh":"我們換一下座位吧,這樣你可以看得更清楚。","synonyms":["exchange"],"level":4,"theme":"動作與行為","examples":[{"en":"Let's swap seats so you can see better.","zh":"我們換一下座位吧,這樣你可以看得更清楚。"},{"en":"The two boys agreed to swap comic books after school.","zh":"兩個男孩同意放學後交換漫畫書。"},{"en":"Would you like to swap seats so you can see the stage?","zh":"你想不想換位子，好讓你能看見舞台？"}]},{"word":"swarm","pos":"n. / v.","phonetic":"[swɔrm]","meaning":"一大群（昆蟲）；蜂擁","definition":"a large group of insects moving together, or to move in a crowd","collocations":["a swarm of bees","swarm into","tourists swarm the beach"],"example":"A swarm of bees flew past the window.","exampleZh":"一群蜜蜂飛過窗戶。","synonyms":["crowd"],"level":5,"theme":"動物與植物","examples":[{"en":"A swarm of bees flew past the window.","zh":"一群蜜蜂飛過窗戶。"},{"en":"A huge swarm of bees suddenly appeared near the garden.","zh":"一大群蜜蜂突然出現在花園附近。"},{"en":"Excited fans swarmed into the stadium before the big game.","zh":"興奮的球迷在大賽前湧入了體育場。"}]},{"word":"swear","pos":"v.","phonetic":"[swɛr]","meaning":"發誓；咒罵","definition":"to make a serious promise, or to use rude language","collocations":["swear an oath","swear to tell the truth","swear at someone"],"example":"He swore to always tell the truth in court.","exampleZh":"他發誓在法庭上永遠說實話。","synonyms":["vow"],"level":4,"theme":"溝通與語言","examples":[{"en":"He swore to always tell the truth in court.","zh":"他發誓在法庭上永遠說實話。"},{"en":"The new members had to swear an oath to protect the club.","zh":"新成員必須宣誓要保護這個社團。"},{"en":"He promised to swear to tell the truth in front of everyone.","zh":"他答應在大家面前發誓說出真相。"}]},{"word":"sweat","pos":"n. / v.","phonetic":"[swɛt]","meaning":"汗水；流汗","definition":"the liquid that comes from skin when hot, or to produce it","collocations":["sweat heavily","break into a sweat","sweat and tears"],"example":"His shirt was soaked with sweat after the race.","exampleZh":"賽跑後他的襯衫被汗水浸濕了。","synonyms":["perspire"],"level":3,"theme":"身體與健康","examples":[{"en":"His shirt was soaked with sweat after the race.","zh":"賽跑後他的襯衫被汗水浸濕了。"},{"en":"The runners were dripping with sweat after the long race.","zh":"跑者們在漫長的比賽後全身大汗淋漓。"},{"en":"He broke into a sweat when the teacher called his name.","zh":"當老師叫到他的名字時，他嚇出一身冷汗。"}]},{"word":"sweater","pos":"n.","phonetic":"[ˈswɛtɚ]","meaning":"毛衣","definition":"a warm knitted piece of clothing worn on the upper body","collocations":["wear a sweater","a wool sweater","knit a sweater"],"example":"She put on a thick sweater because it was cold outside.","exampleZh":"因為外面很冷,她穿上了一件厚毛衣。","synonyms":[],"level":2,"theme":"服裝與外表","examples":[{"en":"She put on a thick sweater because it was cold outside.","zh":"因為外面很冷,她穿上了一件厚毛衣。"},{"en":"My aunt spent the whole winter knitting me a warm sweater.","zh":"我阿姨花了整個冬天為我織一件溫暖的毛衣。"},{"en":"He wore a wool sweater to stay warm in the cold classroom.","zh":"他穿了一件羊毛衣，好在寒冷的教室裡保暖。"}]},{"word":"sweep","pos":"v.","phonetic":"[swip]","meaning":"打掃；掃除","definition":"to clean a surface using a broom","collocations":["sweep the floor","sweep away","sweep the yard"],"example":"She swept the floor before the guests arrived.","exampleZh":"客人到來之前她把地板打掃乾淨了。","synonyms":["clean"],"level":3,"theme":"居家與生活","examples":[{"en":"She swept the floor before the guests arrived.","zh":"客人到來之前她把地板打掃乾淨了。"},{"en":"Every morning, the shopkeeper sweeps the floor before opening.","zh":"每天早上，店主在開店前都會打掃地板。"},{"en":"Please help me sweep the leaves away from the front yard.","zh":"請幫我把前院的落葉掃走。"}]},{"word":"swell","pos":"v.","phonetic":"[swɛl]","meaning":"腫脹；膨脹","definition":"to become larger or rounder than normal","collocations":["swell up","the crowd swelled","an ankle swells"],"example":"Her ankle began to swell after the fall.","exampleZh":"她跌倒後腳踝開始腫起來。","synonyms":["expand"],"level":5,"theme":"身體與健康","examples":[{"en":"Her ankle began to swell after the fall.","zh":"她跌倒後腳踝開始腫起來。"},{"en":"The bee sting made his hand swell up within minutes.","zh":"蜜蜂的螫咬讓他的手在幾分鐘內就腫了起來。"},{"en":"As the concert began, the excited crowd began to swell.","zh":"隨著演唱會開始，興奮的人群開始越聚越多。"}]},{"word":"swift","pos":"adj.","phonetic":"[swɪft]","meaning":"迅速的","definition":"happening or moving very quickly","collocations":["a swift response","swift action","swift movement"],"example":"The government took swift action to control the flood.","exampleZh":"政府迅速採取行動控制洪水。","synonyms":["quick","fast"],"level":5,"theme":"性質與描述","examples":[{"en":"The government took swift action to control the flood.","zh":"政府迅速採取行動控制洪水。"},{"en":"The rescue team gave a swift response to the emergency call.","zh":"救援隊對緊急求救做出了迅速的回應。"},{"en":"With one swift movement, the cat caught the falling toy.","zh":"貓咪以一個迅速的動作接住了掉落的玩具。"}]},{"word":"swing","pos":"v. / n.","phonetic":"[swɪŋ]","meaning":"搖擺；鞦韆","definition":"to move back and forth, or a seat that hangs and swings","collocations":["swing a bat","play on the swing","mood swing"],"example":"The children took turns on the swing in the park.","exampleZh":"孩子們輪流在公園盪鞦韆。","synonyms":[],"level":3,"theme":"運動與休閒","examples":[{"en":"The children took turns on the swing in the park.","zh":"孩子們輪流在公園盪鞦韆。"},{"en":"The little girl laughed as her father pushed the swing higher.","zh":"當爸爸把鞦韆推得更高時，小女孩開心地笑了。"},{"en":"The batter swung the bat hard but missed the fast ball.","zh":"打者用力揮棒，卻沒打中那顆快速球。"}]},{"word":"switch","pos":"n. / v.","phonetic":"[swɪtʃ]","meaning":"開關；轉換","definition":"a device for turning something on or off, or to change","collocations":["turn on the switch","switch jobs","light switch"],"example":"He flipped the switch to turn on the lights.","exampleZh":"他扳動開關把燈打開。","synonyms":["change"],"level":3,"theme":"科技與媒體","examples":[{"en":"He flipped the switch to turn on the lights.","zh":"他扳動開關把燈打開。"},{"en":"Remember to turn off the light switch when you leave the room.","zh":"離開房間時記得關掉電燈開關。"},{"en":"After ten years, she decided to switch jobs and try teaching.","zh":"十年後，她決定換工作，嘗試教書。"}]},{"word":"swollen","pos":"adj.","phonetic":"[ˈswolən]","meaning":"腫脹的","definition":"larger than normal because of swelling","collocations":["a swollen ankle","swollen eyes","swollen river"],"example":"His eyes were swollen from crying all night.","exampleZh":"他的眼睛因為哭了一整晚而腫了起來。","synonyms":[],"level":5,"theme":"身體與健康","examples":[{"en":"His eyes were swollen from crying all night.","zh":"他的眼睛因為哭了一整晚而腫了起來。"},{"en":"After the long hike, her feet were sore and swollen.","zh":"在長途健行後，她的雙腳又痛又腫。"},{"en":"Heavy rain turned the calm river into a swollen brown flood.","zh":"大雨把平靜的河流變成了暴漲的褐色洪水。"}]},{"word":"sword","pos":"n.","phonetic":"[sɔrd]","meaning":"劍","definition":"a weapon with a long blade and a handle","collocations":["draw a sword","a sharp sword","fight with swords"],"example":"The knight carried a sword at his side.","exampleZh":"這位騎士腰間佩帶著一把劍。","synonyms":[],"level":3,"theme":"社會與文化","examples":[{"en":"The knight carried a sword at his side.","zh":"這位騎士腰間佩帶著一把劍。"},{"en":"In the museum, we saw an ancient sword with a golden handle.","zh":"在博物館裡，我們看到了一把有金色握柄的古劍。"},{"en":"The actor learned to fight with a sword for the stage play.","zh":"那位演員為了舞台劇學習用劍打鬥。"}]},{"word":"syllable","pos":"n.","phonetic":"[ˈsɪləbl̩]","meaning":"音節","definition":"a unit of pronunciation forming a word or part of one","collocations":["a two-syllable word","stress a syllable","count syllables"],"example":"The word 'water' has two syllables.","exampleZh":"「water」這個字有兩個音節。","synonyms":[],"level":4,"theme":"教育與學習","examples":[{"en":"The word 'water' has two syllables.","zh":"「water」這個字有兩個音節。"},{"en":"The word 'banana' is made up of three separate syllables.","zh":"「banana」這個字由三個獨立的音節組成。"},{"en":"Our teacher showed us how to stress the first syllable.","zh":"老師示範了如何重讀第一個音節。"}]},{"word":"symbol","pos":"n.","phonetic":"[ˈsɪmbl̩]","meaning":"象徵；符號","definition":"a sign or object that represents something else","collocations":["a symbol of peace","a national symbol","mathematical symbol"],"example":"The dove is a symbol of peace around the world.","exampleZh":"鴿子在世界各地是和平的象徵。","synonyms":["sign"],"level":3,"theme":"社會與文化","examples":[{"en":"The dove is a symbol of peace around the world.","zh":"鴿子在世界各地是和平的象徵。"},{"en":"In many cultures, a red rose is a symbol of love.","zh":"在許多文化中，紅玫瑰是愛情的象徵。"},{"en":"Students must learn each mathematical symbol before the test.","zh":"學生必須在考試前學會每一個數學符號。"}]},{"word":"table","pos":"n.","phonetic":"[ˈtebḷ]","meaning":"餐桌；桌子；表格","definition":"a piece of furniture with a flat top and legs","collocations":["set the table","table manners","coffee table"],"example":"We sat around the table for dinner.","exampleZh":"我們圍坐在餐桌旁吃晚餐。","synonyms":["desk"],"level":1,"theme":"居家與生活","examples":[{"en":"We sat around the table for dinner.","zh":"我們圍坐在餐桌旁吃晚餐。"},{"en":"Please help me set the table before our guests arrive.","zh":"客人到達前，請幫我擺好餐桌。"},{"en":"The teacher drew a table on the board to compare the two animals.","zh":"老師在黑板上畫了一張表格來比較這兩種動物。"}]},{"word":"tablet","pos":"n.","phonetic":"[ˈtæblɪt]","meaning":"平板電腦；藥片；碑板","definition":"a flat electronic device or a small pill","collocations":["a digital tablet","take a tablet","a stone tablet"],"example":"He uses a tablet to read e-books on the train.","exampleZh":"他在火車上用平板電腦看電子書。","synonyms":["pad","pill"],"level":2,"theme":"科技與媒體","examples":[{"en":"He uses a tablet to read e-books on the train.","zh":"他在火車上用平板電腦看電子書。"},{"en":"My brother does his homework on a digital tablet every evening.","zh":"我弟弟每天晚上用平板電腦寫作業。"},{"en":"The doctor told her to take one tablet after each meal.","zh":"醫生要她每餐飯後服用一顆藥片。"}]},{"word":"tackle","pos":"v. / n.","phonetic":"[ˈtækl]","meaning":"處理；應付；擒抱","definition":"to deal with a difficult problem or task","collocations":["tackle a problem","tackle an issue","football tackle"],"example":"The team decided to tackle the issue right away.","exampleZh":"這個團隊決定立刻處理這個問題。","synonyms":["handle","address"],"level":3,"theme":"動作與行為","examples":[{"en":"The team decided to tackle the issue right away.","zh":"這個團隊決定立刻處理這個問題。"},{"en":"We must tackle this problem together before it gets worse.","zh":"我們必須一起處理這個問題，以免它變得更糟。"},{"en":"The player made a clean tackle and stopped the attack.","zh":"那名球員乾淨俐落地擒抱對手，阻止了進攻。"}]},{"word":"tactic","pos":"n.","phonetic":"[ˈtæktɪk]","meaning":"策略；戰術","definition":"a planned way of achieving a goal","collocations":["a clever tactic","business tactics","change tactics"],"example":"The coach explained a new tactic before the match.","exampleZh":"教練在比賽前說明了一項新戰術。","synonyms":["strategy","plan"],"level":4,"theme":"抽象概念","examples":[{"en":"The coach explained a new tactic before the match.","zh":"教練在比賽前說明了一項新戰術。"},{"en":"Changing our tactic halfway through the game surprised the other team.","zh":"比賽中途改變戰術讓對方球隊感到意外。"},{"en":"Studying a little every day is a clever tactic for exams.","zh":"每天讀一點書是應付考試的聰明策略。"}]},{"word":"tag","pos":"n. / v.","phonetic":"[tæg]","meaning":"標籤；標記；玩捉人遊戲","definition":"a small piece of paper or plastic attached to something for identification","collocations":["price tag","name tag","tag along"],"example":"Check the price tag before you buy it.","exampleZh":"買之前先看看價格標籤。","synonyms":["label"],"level":2,"theme":"商業與金錢","examples":[{"en":"Check the price tag before you buy it.","zh":"買之前先看看價格標籤。"},{"en":"She wrote her name on a paper tag and tied it to the bag.","zh":"她在紙標籤上寫下名字，並把它綁在袋子上。"},{"en":"My younger cousin loves to tag along whenever I go out.","zh":"每次我出門，我的小表弟都喜歡跟著一起去。"}]},{"word":"tail","pos":"n.","phonetic":"[tel]","meaning":"尾巴","definition":"the part at the back end of an animal's body","collocations":["wag its tail","tail end","dog's tail"],"example":"The dog wagged its tail happily.","exampleZh":"那隻狗開心地搖著尾巴。","synonyms":[],"level":1,"theme":"動物與植物","examples":[{"en":"The dog wagged its tail happily.","zh":"那隻狗開心地搖著尾巴。"},{"en":"The cat curled its long tail around its warm body.","zh":"那隻貓把長長的尾巴蜷繞在溫暖的身體上。"},{"en":"We arrived at the tail end of the parade.","zh":"我們在遊行的尾聲才趕到。"}]},{"word":"tailor","pos":"n. / v.","phonetic":"[ˈtelɚ]","meaning":"裁縫師；量身打造","definition":"a person who makes clothes, or to adjust something to fit needs","collocations":["visit a tailor","tailor a plan","a tailored suit"],"example":"The tailor made a suit that fit him perfectly.","exampleZh":"裁縫師做了一套完全合身的西裝。","synonyms":["adjust","customize"],"level":4,"theme":"服裝與外表","examples":[{"en":"The tailor made a suit that fit him perfectly.","zh":"裁縫師做了一套完全合身的西裝。"},{"en":"The tailor measured his shoulders before making the jacket.","zh":"裁縫師在製作外套前先量了他的肩寬。"},{"en":"Good teachers tailor their lessons to fit each student's needs.","zh":"好的老師會依每位學生的需求量身打造課程。"}]},{"word":"take","pos":"v.","phonetic":"[tek]","meaning":"拿；帶；花費(時間)","definition":"to move something from one place to another or to need an amount of time","collocations":["take a break","take place","take time"],"example":"It will take an hour to finish the report.","exampleZh":"完成這份報告需要一個小時。","synonyms":["grab","bring"],"level":1,"theme":"動作與行為","examples":[{"en":"It will take an hour to finish the report.","zh":"完成這份報告需要一個小時。"},{"en":"Remember to take an umbrella because it might rain later.","zh":"記得帶把傘，因為待會兒可能會下雨。"},{"en":"Let's take a short break before we start the next chapter.","zh":"在開始下一章之前，我們先休息一下吧。"}]},{"word":"tale","pos":"n.","phonetic":"[tel]","meaning":"故事；傳說","definition":"a story, especially one involving imaginary events","collocations":["fairy tale","tell a tale","folk tale"],"example":"My grandmother told us a fairy tale before bed.","exampleZh":"奶奶在睡前給我們講了一個童話故事。","synonyms":["story"],"level":2,"theme":"藝術與音樂","examples":[{"en":"My grandmother told us a fairy tale before bed.","zh":"奶奶在睡前給我們講了一個童話故事。"},{"en":"The old sailor told us an exciting tale about a storm.","zh":"那位年老的水手向我們講了一個關於暴風雨的精彩故事。"},{"en":"This folk tale has been passed down for many generations.","zh":"這個民間傳說已經流傳了好幾個世代。"}]},{"word":"talent","pos":"n.","phonetic":"[ˈtælənt]","meaning":"天賦；才能","definition":"a natural ability to do something well","collocations":["musical talent","natural talent","talent show"],"example":"She has a real talent for painting.","exampleZh":"她真的很有繪畫天分。","synonyms":["gift","ability"],"level":3,"theme":"教育與學習","examples":[{"en":"She has a real talent for painting.","zh":"她真的很有繪畫天分。"},{"en":"Everyone was amazed by his musical talent at the school concert.","zh":"在學校音樂會上，大家都對他的音樂天賦感到驚豔。"},{"en":"She joined the talent show to sing in front of the class.","zh":"她參加了才藝表演，在全班面前唱歌。"}]},{"word":"talk","pos":"v. / n.","phonetic":"[tɔk]","meaning":"說話；談話","definition":"to speak to someone in order to give information or ideas","collocations":["talk about","small talk","give a talk"],"example":"Let's talk about the plan tomorrow.","exampleZh":"我們明天再談這個計畫吧。","synonyms":["speak","chat"],"level":1,"theme":"溝通與語言","examples":[{"en":"Let's talk about the plan tomorrow.","zh":"我們明天再談這個計畫吧。"},{"en":"We should talk about the group project after class.","zh":"下課後我們應該談談這個小組報告。"},{"en":"The scientist gave an interesting talk about outer space.","zh":"那位科學家做了一場關於外太空的有趣演講。"}]},{"word":"talkative","pos":"adj.","phonetic":"[ˈtɔkətɪv]","meaning":"健談的；話多的","definition":"tending to talk a lot","collocations":["a talkative child","become talkative","a talkative person"],"example":"My little sister is very talkative at family dinners.","exampleZh":"我妹妹在家庭聚餐時話特別多。","synonyms":["chatty","talky"],"level":3,"theme":"性質與描述","examples":[{"en":"My little sister is very talkative at family dinners.","zh":"我妹妹在家庭聚餐時話特別多。"},{"en":"Our new classmate is friendly and quite talkative.","zh":"我們的新同學很友善，而且相當健談。"},{"en":"He becomes talkative whenever the topic is basketball.","zh":"只要話題是籃球，他就變得很愛講話。"}]},{"word":"tall","pos":"adj.","phonetic":"[tɔl]","meaning":"高的","definition":"having a greater than average height","collocations":["tall building","grow tall","tall tree"],"example":"He is the tallest boy in our class.","exampleZh":"他是我們班上最高的男生。","synonyms":["high"],"level":1,"theme":"性質與描述","examples":[{"en":"He is the tallest boy in our class.","zh":"他是我們班上最高的男生。"},{"en":"They planted a tall tree in the corner of the playground.","zh":"他們在操場的角落種了一棵高大的樹。"},{"en":"From here you can see the tall building downtown.","zh":"從這裡你可以看見市中心那棟高樓。"}]},{"word":"tame","pos":"adj. / v.","phonetic":"[tem]","meaning":"溫馴的；馴服","definition":"not wild or dangerous; to make an animal gentle and obedient","collocations":["tame animal","tame a lion"],"example":"The zoo keeper managed to tame the tiger.","exampleZh":"動物園管理員成功馴服了那隻老虎。","synonyms":["gentle","domesticated"],"level":4,"theme":"動物與植物","examples":[{"en":"The zoo keeper managed to tame the tiger.","zh":"動物園管理員成功馴服了那隻老虎。"},{"en":"With patience, the farmer managed to tame the wild horse.","zh":"憑著耐心，那位農夫成功馴服了那匹野馬。"},{"en":"The rabbit is so tame that it eats from my hand.","zh":"這隻兔子很溫馴，甚至會從我手上吃東西。"}]},{"word":"tangible","pos":"adj.","phonetic":"[ˈtændʒəbl]","meaning":"有形的；實質的；明確的","definition":"able to be touched or clearly perceived as real","collocations":["tangible evidence","tangible benefits","a tangible result"],"example":"The new policy brought tangible improvements to the town.","exampleZh":"這項新政策為小鎮帶來了實質的改善。","synonyms":["concrete","real"],"level":5,"theme":"抽象概念","examples":[{"en":"The new policy brought tangible improvements to the town.","zh":"這項新政策為小鎮帶來了實質的改善。"},{"en":"The students wanted tangible evidence before believing the story.","zh":"學生們在相信這個說法之前想要明確的證據。"},{"en":"Regular exercise brings tangible benefits to your health.","zh":"規律運動會為你的健康帶來實質的好處。"}]},{"word":"tangle","pos":"v. / n.","phonetic":"[ˈtæŋɡl]","meaning":"糾結；纏繞；混亂","definition":"to twist together in a confused mass","collocations":["tangled hair","a tangle of wires","get tangled up"],"example":"Her long hair got tangled in the wind.","exampleZh":"她的長髮在風中糾結在一起。","synonyms":["twist","knot"],"level":3,"theme":"性質與描述","examples":[{"en":"Her long hair got tangled in the wind.","zh":"她的長髮在風中糾結在一起。"},{"en":"The kitten played until the ball of yarn was a tangle.","zh":"小貓一直玩，直到那團毛線變得一團糟。"},{"en":"The earphone cords always tangle inside my pocket.","zh":"耳機線總是在我的口袋裡纏成一團。"}]},{"word":"tank","pos":"n.","phonetic":"[tæŋk]","meaning":"坦克；水箱","definition":"a large container for liquid or gas, or a military armored vehicle","collocations":["fish tank","gas tank","army tank"],"example":"The fish tank needs to be cleaned.","exampleZh":"這個魚缸需要清洗了。","synonyms":[],"level":3,"theme":"科技與媒體","examples":[{"en":"The fish tank needs to be cleaned.","zh":"這個魚缸需要清洗了。"},{"en":"We keep three goldfish in the glass tank by the window.","zh":"我們在窗邊的玻璃水缸裡養了三條金魚。"},{"en":"Dad filled the gas tank before the long drive.","zh":"爸爸在長途開車前把油箱加滿了。"}]},{"word":"tap","pos":"v. / n.","phonetic":"[tæp]","meaning":"輕拍；水龍頭","definition":"to hit gently, or a device to control the flow of water","collocations":["tap on the shoulder","turn on the tap","tap water"],"example":"She tapped me on the shoulder to get my attention.","exampleZh":"她輕拍我的肩膀引起我的注意。","synonyms":["knock"],"level":2,"theme":"動作與行為","examples":[{"en":"She tapped me on the shoulder to get my attention.","zh":"她輕拍我的肩膀引起我的注意。"},{"en":"She gently tapped the window to get the bird's attention.","zh":"她輕輕地拍打窗戶，想引起那隻鳥的注意。"},{"en":"Please turn off the tap so we don't waste water.","zh":"請把水龍頭關上，這樣我們才不會浪費水。"}]},{"word":"tape","pos":"n. / v.","phonetic":"[tep]","meaning":"膠帶；錄音帶","definition":"a strip of material used for sticking things together or recording sound","collocations":["sticky tape","tape recorder","duct tape"],"example":"He used tape to fix the broken box.","exampleZh":"他用膠帶修好了破損的箱子。","synonyms":[],"level":2,"theme":"科技與媒體","examples":[{"en":"He used tape to fix the broken box.","zh":"他用膠帶修好了破損的箱子。"},{"en":"He wrapped the gift and sealed it with sticky tape.","zh":"他把禮物包好，並用膠帶封起來。"},{"en":"My grandfather still keeps his old music on a cassette tape.","zh":"我爺爺仍把他的老歌保存在錄音帶裡。"}]},{"word":"target","pos":"n. / v.","phonetic":"[ˈtɑrgɪt]","meaning":"目標；靶子","definition":"a result that you try to achieve, or an object aimed at","collocations":["hit the target","target audience","set a target"],"example":"Our sales target for this month is high.","exampleZh":"我們這個月的銷售目標很高。","synonyms":["goal","aim"],"level":3,"theme":"商業與金錢","examples":[{"en":"Our sales target for this month is high.","zh":"我們這個月的銷售目標很高。"},{"en":"The archer aimed carefully and hit the target every time.","zh":"那位射箭手仔細瞄準，每次都命中靶心。"},{"en":"Our class set a target to read fifty books this year.","zh":"我們班訂下今年閱讀五十本書的目標。"}]},{"word":"tariff","pos":"n.","phonetic":"[ˈtærɪf]","meaning":"關稅；價目表","definition":"a tax charged on goods brought into a country","collocations":["impose a tariff","raise tariffs","trade tariffs"],"example":"The government raised tariffs on imported cars.","exampleZh":"政府提高了進口汽車的關稅。","synonyms":["duty","tax"],"level":5,"theme":"商業與金錢","examples":[{"en":"The government raised tariffs on imported cars.","zh":"政府提高了進口汽車的關稅。"},{"en":"Higher tariffs on foreign fruit made prices go up.","zh":"對進口水果課徵較高的關稅使得價格上漲。"},{"en":"The two countries agreed to lower trade tariffs.","zh":"這兩個國家同意調降貿易關稅。"}]},{"word":"task","pos":"n.","phonetic":"[tæsk]","meaning":"任務；工作","definition":"a piece of work to be done","collocations":["complete a task","daily tasks","difficult task"],"example":"Finishing the project was not an easy task.","exampleZh":"完成這個專案並不是件容易的任務。","synonyms":["job","assignment"],"level":3,"theme":"工作與職業","examples":[{"en":"Finishing the project was not an easy task.","zh":"完成這個專案並不是件容易的任務。"},{"en":"Each member of the team was given a different task.","zh":"團隊中的每個成員都被分配到不同的任務。"},{"en":"Cleaning the whole house in one day was a difficult task.","zh":"要在一天內打掃完整棟房子是件困難的工作。"}]},{"word":"taste","pos":"n. / v.","phonetic":"[test]","meaning":"味道；品嘗","definition":"the flavor of food, or to test the flavor of something","collocations":["taste good","taste bud","a taste of"],"example":"This soup tastes delicious.","exampleZh":"這道湯嘗起來很美味。","synonyms":["flavor"],"level":2,"theme":"食物與烹飪","examples":[{"en":"This soup tastes delicious.","zh":"這道湯嘗起來很美味。"},{"en":"Would you like to taste the sauce before I add salt?","zh":"在我加鹽之前，你要不要先嘗嘗這醬汁？"},{"en":"The fresh mango has a sweet and juicy taste.","zh":"這顆新鮮的芒果嚐起來又甜又多汁。"}]},{"word":"tavern","pos":"n.","phonetic":"[ˈtævɚn]","meaning":"小酒館；客棧","definition":"a place that serves alcoholic drinks and sometimes food","collocations":["a local tavern","stop at a tavern","a village tavern"],"example":"Travelers rested at a small tavern along the road.","exampleZh":"旅人們在路邊一間小酒館休息。","synonyms":["inn","pub"],"level":4,"theme":"交通與旅行","examples":[{"en":"Travelers rested at a small tavern along the road.","zh":"旅人們在路邊一間小酒館休息。"},{"en":"The tired travelers spent the night at a small tavern.","zh":"疲憊的旅人在一間小酒館過了一夜。"},{"en":"An old tavern near the harbor served warm soup to sailors.","zh":"港口附近一間古老的客棧供應熱湯給水手。"}]},{"word":"tax","pos":"n.","phonetic":"[tæks]","meaning":"稅金","definition":"money that must be paid to the government","collocations":["pay tax","income tax","tax return"],"example":"The government raised the income tax rate.","exampleZh":"政府提高了所得稅稅率。","synonyms":[],"level":3,"theme":"商業與金錢","examples":[{"en":"The government raised the income tax rate.","zh":"政府提高了所得稅稅率。"},{"en":"Everyone who earns money must pay income tax.","zh":"每個賺錢的人都必須繳納所得稅。"},{"en":"The shop adds a small tax to the price of each item.","zh":"這家店在每件商品的價格上加了一點稅金。"}]},{"word":"taxi","pos":"n.","phonetic":"[ˈtæksɪ]","meaning":"計程車","definition":"a car that carries passengers for a fare","collocations":["take a taxi","call a taxi","taxi driver"],"example":"We took a taxi to the airport.","exampleZh":"我們搭計程車去機場。","synonyms":["cab"],"level":1,"theme":"交通與旅行","examples":[{"en":"We took a taxi to the airport.","zh":"我們搭計程車去機場。"},{"en":"It was raining hard, so we decided to call a taxi.","zh":"雨下得很大，所以我們決定叫一輛計程車。"},{"en":"The taxi driver knew a faster route to the station.","zh":"那位計程車司機知道一條比較快到車站的路。"}]},{"word":"tea","pos":"n.","phonetic":"[ti]","meaning":"茶","definition":"a hot drink made by pouring boiling water on dried leaves","collocations":["cup of tea","green tea","make tea"],"example":"Would you like a cup of tea?","exampleZh":"你想喝杯茶嗎？","synonyms":[],"level":1,"theme":"食物與烹飪","examples":[{"en":"Would you like a cup of tea?","zh":"你想喝杯茶嗎？"},{"en":"My mother likes to make green tea in the afternoon.","zh":"我媽媽喜歡在下午泡綠茶。"},{"en":"He offered our guests a warm cup of tea.","zh":"他請客人喝了一杯溫熱的茶。"}]},{"word":"teach","pos":"v.","phonetic":"[titʃ]","meaning":"教導；教書","definition":"to give lessons to someone so they learn something","collocations":["teach a class","teach English","teach by example"],"example":"She teaches math at a high school.","exampleZh":"她在高中教數學。","synonyms":["instruct","educate"],"level":1,"theme":"教育與學習","examples":[{"en":"She teaches math at a high school.","zh":"她在高中教數學。"},{"en":"My aunt teaches English to young children on weekends.","zh":"我阿姨週末教小孩子英文。"},{"en":"Good parents often teach their children by example.","zh":"好的父母常常以身作則來教導孩子。"}]},{"word":"team","pos":"n.","phonetic":"[tim]","meaning":"隊伍；團隊","definition":"a group of people who work or play together","collocations":["team up","team spirit","sports team"],"example":"Our team won the championship.","exampleZh":"我們的隊伍贏得了冠軍。","synonyms":["group"],"level":1,"theme":"運動與休閒","examples":[{"en":"Our team won the championship.","zh":"我們的隊伍贏得了冠軍。"},{"en":"The whole team practiced hard for the coming match.","zh":"整支隊伍為即將到來的比賽努力練習。"},{"en":"Let's team up and finish the science project together.","zh":"我們組隊一起完成這個科學專題吧。"}]},{"word":"tear","pos":"n. / v.","phonetic":"[tɪr]","meaning":"眼淚；撕裂","definition":"a drop of liquid from the eye, or to rip something apart","collocations":["burst into tears","tear apart","shed tears"],"example":"She burst into tears when she heard the sad news.","exampleZh":"她聽到這個壞消息時哭了出來。","synonyms":["rip","cry"],"level":2,"theme":"情緒與感受","examples":[{"en":"She burst into tears when she heard the sad news.","zh":"她聽到這個壞消息時哭了出來。"},{"en":"A single tear rolled down her cheek during the movie.","zh":"看電影時，一滴眼淚滑下她的臉頰。"},{"en":"Be careful not to tear the page when you turn it.","zh":"翻頁的時候小心不要把紙撕破了。"}]},{"word":"technical","pos":"adj.","phonetic":"[ˈtɛknɪkḷ]","meaning":"技術性的","definition":"relating to the skills needed for a particular job or subject","collocations":["technical support","technical problem","technical skill"],"example":"The company offers technical support 24 hours a day.","exampleZh":"這家公司提供全天候的技術支援。","synonyms":[],"level":4,"theme":"科技與媒體","examples":[{"en":"The company offers technical support 24 hours a day.","zh":"這家公司提供全天候的技術支援。"},{"en":"I called the technical support line to fix my computer.","zh":"我打電話給技術支援專線來修理我的電腦。"},{"en":"The manual uses too many technical words for beginners.","zh":"這本手冊對初學者來說用了太多技術性的詞彙。"}]},{"word":"technique","pos":"n.","phonetic":"[tɛkˈnik]","meaning":"技巧；技術","definition":"a way of doing something that requires skill","collocations":["painting technique","new technique","master a technique"],"example":"He learned a new technique for solving the problem.","exampleZh":"他學會了一種解決問題的新技巧。","synonyms":["method","skill"],"level":4,"theme":"科技與媒體","examples":[{"en":"He learned a new technique for solving the problem.","zh":"他學會了一種解決問題的新技巧。"},{"en":"The art teacher showed us a new painting technique.","zh":"美術老師教了我們一種新的繪畫技巧。"},{"en":"It takes years of practice to master this technique.","zh":"要精通這項技術需要多年的練習。"}]},{"word":"technology","pos":"n.","phonetic":"[tɛkˈnɑlədʒɪ]","meaning":"科技","definition":"the application of scientific knowledge for practical purposes","collocations":["modern technology","information technology","advanced technology"],"example":"Technology has changed the way we communicate.","exampleZh":"科技改變了我們溝通的方式。","synonyms":[],"level":3,"theme":"科技與媒體","examples":[{"en":"Technology has changed the way we communicate.","zh":"科技改變了我們溝通的方式。"},{"en":"Modern technology allows us to study online from home.","zh":"現代科技讓我們能夠在家線上學習。"},{"en":"Advanced technology has made farming much more efficient.","zh":"先進科技使農耕變得更有效率。"}]},{"word":"tedious","pos":"adj.","phonetic":"[ˈtidiəs]","meaning":"乏味的；冗長的","definition":"too long, slow, or dull; tiresome","collocations":["a tedious task","tedious work","a tedious journey"],"example":"Filling out the forms was a tedious process.","exampleZh":"填寫這些表格是一件乏味的工作。","synonyms":["boring","dull"],"level":5,"theme":"情緒與感受","examples":[{"en":"Filling out the forms was a tedious process.","zh":"填寫這些表格是一件乏味的工作。"},{"en":"Copying the whole chapter by hand was a tedious task.","zh":"用手抄寫整章內容是件乏味的工作。"},{"en":"The long, tedious journey made all the children sleepy.","zh":"這趟漫長又冗長的旅程讓所有孩子都昏昏欲睡。"}]},{"word":"teenage","pos":"adj.","phonetic":"[ˈtinˏedʒ]","meaning":"青少年的","definition":"relating to people aged between 13 and 19","collocations":["teenage years","teenage boy","teenage problems"],"example":"Teenage years can be difficult for many students.","exampleZh":"青少年時期對許多學生來說可能很辛苦。","synonyms":[],"level":2,"theme":"人物與家庭","examples":[{"en":"Teenage years can be difficult for many students.","zh":"青少年時期對許多學生來說可能很辛苦。"},{"en":"During his teenage years, he became interested in photography.","zh":"在青少年時期，他開始對攝影產生興趣。"},{"en":"Many teenage students enjoy playing sports after class.","zh":"許多青少年學生喜歡在課後運動。"}]},{"word":"telegraph","pos":"n. / v.","phonetic":"[ˈtɛləˌɡræf]","meaning":"電報；打電報","definition":"a system for sending messages by electrical signals","collocations":["send a telegraph","by telegraph","telegraph a message"],"example":"News once traveled quickly by telegraph.","exampleZh":"從前消息藉由電報快速傳遞。","synonyms":["wire"],"level":4,"theme":"科技與媒體","examples":[{"en":"News once traveled quickly by telegraph.","zh":"從前消息藉由電報快速傳遞。"},{"en":"Long ago, people sent urgent news by telegraph.","zh":"很久以前，人們透過電報傳送緊急消息。"},{"en":"The operator learned to telegraph a message in code.","zh":"那位報務員學會用密碼打電報傳送訊息。"}]},{"word":"telephone","pos":"n.","phonetic":"[ˈtɛləˏfon]","meaning":"電話","definition":"a device used to talk to someone who is far away","collocations":["answer the telephone","telephone call","telephone number"],"example":"She answered the telephone immediately.","exampleZh":"她立刻接了電話。","synonyms":["phone"],"level":1,"theme":"科技與媒體","examples":[{"en":"She answered the telephone immediately.","zh":"她立刻接了電話。"},{"en":"She picked up the telephone and dialed her friend's number.","zh":"她拿起電話，撥了朋友的號碼。"},{"en":"I received an important telephone call during dinner.","zh":"我在晚餐時接到一通重要的電話。"}]},{"word":"telescope","pos":"n.","phonetic":"[ˈtɛləˏskop]","meaning":"望遠鏡","definition":"an instrument used for viewing distant objects","collocations":["look through a telescope","powerful telescope"],"example":"We used a telescope to observe the stars.","exampleZh":"我們用望遠鏡觀察星星。","synonyms":[],"level":3,"theme":"科學與數學","examples":[{"en":"We used a telescope to observe the stars.","zh":"我們用望遠鏡觀察星星。"},{"en":"Through the telescope, we could see the moon's craters clearly.","zh":"透過望遠鏡，我們能清楚地看見月球上的坑洞。"},{"en":"The science club bought a powerful telescope for stargazing.","zh":"科學社買了一台強力的望遠鏡來觀星。"}]},{"word":"television","pos":"n.","phonetic":"[ˈtɛləˏvɪʒən]","meaning":"電視","definition":"a device for receiving broadcast programs with pictures and sound","collocations":["watch television","turn on the television","television program"],"example":"The children love watching television after school.","exampleZh":"孩子們放學後喜歡看電視。","synonyms":["TV"],"level":1,"theme":"科技與媒體","examples":[{"en":"The children love watching television after school.","zh":"孩子們放學後喜歡看電視。"},{"en":"My grandparents like to watch the news on television.","zh":"我的祖父母喜歡看電視上的新聞。"},{"en":"Please turn off the television and finish your homework.","zh":"請把電視關掉，把功課寫完。"}]},{"word":"tell","pos":"v.","phonetic":"[tɛl]","meaning":"告訴；說","definition":"to give information to someone by speaking or writing","collocations":["tell the truth","tell a story","tell apart"],"example":"Please tell me the truth.","exampleZh":"請告訴我實話。","synonyms":["inform","say"],"level":1,"theme":"溝通與語言","examples":[{"en":"Please tell me the truth.","zh":"請告訴我實話。"},{"en":"Could you tell me the way to the train station?","zh":"你能告訴我去火車站的路怎麼走嗎？"},{"en":"The twins look so alike that I cannot tell them apart.","zh":"這對雙胞胎長得太像，我分辨不出他們。"}]},{"word":"temper","pos":"n.","phonetic":"[ˈtɛmpɚ]","meaning":"脾氣","definition":"a person's tendency to become angry quickly","collocations":["lose one's temper","quick temper","keep one's temper"],"example":"He lost his temper when the train was late.","exampleZh":"火車誤點時他發脾氣了。","synonyms":["mood"],"level":4,"theme":"情緒與感受","examples":[{"en":"He lost his temper when the train was late.","zh":"火車誤點時他發脾氣了。"},{"en":"He tried to keep his temper when the game was unfair.","zh":"當比賽不公平時，他努力控制自己的脾氣。"},{"en":"She has a quick temper and shouts when she is angry.","zh":"她脾氣很急，生氣時就會大吼。"}]},{"word":"temperament","pos":"n.","phonetic":"[ˈtɛmprəmənt]","meaning":"氣質；性情","definition":"a person's or animal's nature, especially as it affects behavior","collocations":["a calm temperament","a fiery temperament","suit one's temperament"],"example":"The dog has a gentle temperament and loves children.","exampleZh":"這隻狗性情溫和,喜歡小孩。","synonyms":["nature","disposition"],"level":5,"theme":"情緒與感受","examples":[{"en":"The dog has a gentle temperament and loves children.","zh":"這隻狗性情溫和,喜歡小孩。"},{"en":"The little puppy has a calm temperament and rarely barks.","zh":"這隻小狗性情溫和，很少吠叫。"},{"en":"His cheerful temperament makes him popular among classmates.","zh":"他開朗的性情使他在同學間很受歡迎。"}]},{"word":"temperature","pos":"n.","phonetic":"[ˈtɛmprətʃɚ]","meaning":"溫度；體溫","definition":"the degree of heat or cold measured on a scale","collocations":["room temperature","high temperature","take one's temperature"],"example":"The temperature dropped suddenly last night.","exampleZh":"昨晚氣溫突然下降。","synonyms":[],"level":2,"theme":"天氣與季節","examples":[{"en":"The temperature dropped suddenly last night.","zh":"昨晚氣溫突然下降。"},{"en":"The nurse checked my temperature before the examination.","zh":"護士在檢查前先量了我的體溫。"},{"en":"Water boils at a very high temperature.","zh":"水在很高的溫度下才會沸騰。"}]},{"word":"template","pos":"n.","phonetic":"[ˈtɛmplɪt]","meaning":"模板；樣板","definition":"a shape or pattern used as a guide to make something","collocations":["a design template","use a template","a resume template"],"example":"She used a template to design her presentation slides.","exampleZh":"她用一個模板來設計她的簡報投影片。","synonyms":["pattern","model"],"level":4,"theme":"科技與媒體","examples":[{"en":"She used a template to design her presentation slides.","zh":"她用一個模板來設計她的簡報投影片。"},{"en":"I downloaded a template to write my report more easily.","zh":"我下載了一個模板，好讓我更輕鬆地撰寫報告。"},{"en":"The teacher gave us a template for the science poster.","zh":"老師給了我們一份科學海報的樣板。"}]},{"word":"temple","pos":"n.","phonetic":"[ˈtɛmpḷ]","meaning":"寺廟；神殿","definition":"a building used for the worship of a god or gods","collocations":["visit a temple","ancient temple","Buddhist temple"],"example":"Tourists often visit the old temple in the city.","exampleZh":"遊客常常參觀這座城市裡的古老寺廟。","synonyms":["shrine"],"level":3,"theme":"社會與文化","examples":[{"en":"Tourists often visit the old temple in the city.","zh":"遊客常常參觀這座城市裡的古老寺廟。"},{"en":"Many people visit the ancient temple during festivals.","zh":"許多人在節慶期間會參訪這座古老的寺廟。"},{"en":"The quiet temple stood peacefully among the tall trees.","zh":"這座寧靜的神殿安詳地矗立在高大的樹木之間。"}]},{"word":"tempo","pos":"n.","phonetic":"[ˈtɛmpo]","meaning":"速度；節奏","definition":"the speed at which a piece of music is played, or the pace of an activity","collocations":["a fast tempo","set the tempo","change the tempo"],"example":"The conductor slowed the tempo during the final movement.","exampleZh":"指揮在最後樂章放慢了節奏。","synonyms":["pace","rhythm"],"level":4,"theme":"藝術與音樂","examples":[{"en":"The conductor slowed the tempo during the final movement.","zh":"指揮在最後樂章放慢了節奏。"},{"en":"The dancers moved faster as the music picked up tempo.","zh":"隨著音樂加快速度，舞者們的動作也變快了。"},{"en":"Please keep a steady tempo while playing the piano.","zh":"彈鋼琴時請保持穩定的節奏。"}]},{"word":"temporary","pos":"adj.","phonetic":"[ˈtɛmpəˏrɛrɪ]","meaning":"暫時的","definition":"lasting for only a limited period of time","collocations":["temporary job","temporary solution","temporary shelter"],"example":"She took a temporary job during the summer.","exampleZh":"她暑假期間做了一份臨時工作。","synonyms":["brief","short-term"],"level":4,"theme":"性質與描述","examples":[{"en":"She took a temporary job during the summer.","zh":"她暑假期間做了一份臨時工作。"},{"en":"The library set up a temporary reading room during repairs.","zh":"圖書館在整修期間設置了一間臨時閱覽室。"},{"en":"This is only a temporary solution until we find a better one.","zh":"在我們找到更好的辦法前，這只是暫時的解決方案。"}]},{"word":"tempt","pos":"v.","phonetic":"[tɛmpt]","meaning":"誘惑","definition":"to attract or entice someone to do something, often unwise","collocations":["tempt someone to","tempted to buy","resist the temptation"],"example":"The smell of cookies tempted him to eat one.","exampleZh":"餅乾的香味誘惑他吃了一個。","synonyms":["entice","lure"],"level":5,"theme":"抽象概念","examples":[{"en":"The smell of cookies tempted him to eat one.","zh":"餅乾的香味誘惑他吃了一個。"},{"en":"The colorful candy in the shop tempted the little boy.","zh":"店裡色彩繽紛的糖果誘惑著那個小男孩。"},{"en":"Don't let your phone tempt you while you are studying.","zh":"讀書時別讓手機誘惑你分心。"}]},{"word":"tenant","pos":"n.","phonetic":"[ˈtɛnənt]","meaning":"房客；承租人","definition":"a person who rents land or property from a landlord","collocations":["a new tenant","evict a tenant","tenant rights"],"example":"The tenant signed a one-year lease for the apartment.","exampleZh":"房客簽了公寓一年的租約。","synonyms":["renter","lodger"],"level":4,"theme":"居家與生活","examples":[{"en":"The tenant signed a one-year lease for the apartment.","zh":"房客簽了公寓一年的租約。"},{"en":"The new tenant moved into the apartment upstairs yesterday.","zh":"新房客昨天搬進了樓上的公寓。"},{"en":"The landlord promised to fix the leak for the tenant.","zh":"房東答應為房客修理漏水的地方。"}]},{"word":"tend","pos":"v.","phonetic":"[tɛnd]","meaning":"傾向於；照料","definition":"to be likely to behave in a particular way, or to take care of something","collocations":["tend to","tend a garden"],"example":"People tend to eat more in winter.","exampleZh":"人們在冬天往往吃得比較多。","synonyms":["incline"],"level":4,"theme":"抽象概念","examples":[{"en":"People tend to eat more in winter.","zh":"人們在冬天往往吃得比較多。"},{"en":"Students tend to feel nervous before an important exam.","zh":"學生在重要考試前往往會感到緊張。"},{"en":"My grandmother loves to tend her small vegetable garden.","zh":"我奶奶喜歡照料她那座小小的菜園。"}]},{"word":"tendency","pos":"n.","phonetic":"[ˈtɛndənsi]","meaning":"傾向；趨勢","definition":"an inclination to behave or think in a certain way","collocations":["a natural tendency","have a tendency to","a growing tendency"],"example":"He has a tendency to arrive late for meetings.","exampleZh":"他開會總是有遲到的傾向。","synonyms":["inclination","trend"],"level":4,"theme":"抽象概念","examples":[{"en":"He has a tendency to arrive late for meetings.","zh":"他開會總是有遲到的傾向。"},{"en":"He has a tendency to forget his umbrella on rainy days.","zh":"他在雨天常常有忘記帶傘的傾向。"},{"en":"There is a growing tendency for students to study abroad.","zh":"學生出國留學的趨勢正在增加。"}]},{"word":"tender","pos":"adj.","phonetic":"[ˈtɛndɚ]","meaning":"溫柔的；嫩的","definition":"gentle and kind, or soft and easy to chew","collocations":["tender meat","tender care","tender heart"],"example":"The steak was cooked until tender.","exampleZh":"這塊牛排煮到軟嫩。","synonyms":["gentle","soft"],"level":4,"theme":"性質與描述","examples":[{"en":"The steak was cooked until tender.","zh":"這塊牛排煮到軟嫩。"},{"en":"The mother gave her baby a tender kiss on the forehead.","zh":"母親在寶寶的額頭上溫柔地親了一下。"},{"en":"After slow cooking, the meat became soft and tender.","zh":"經過慢火烹煮後，肉變得柔軟又鮮嫩。"}]},{"word":"tennis","pos":"n.","phonetic":"[ˈtɛnɪs]","meaning":"網球","definition":"a game played by two or four players with rackets and a ball","collocations":["play tennis","tennis court","tennis racket"],"example":"They play tennis every weekend.","exampleZh":"他們每個週末都打網球。","synonyms":[],"level":1,"theme":"運動與休閒","examples":[{"en":"They play tennis every weekend.","zh":"他們每個週末都打網球。"},{"en":"We booked a tennis court for Saturday afternoon.","zh":"我們預訂了星期六下午的網球場。"},{"en":"She practices with her new tennis racket every day.","zh":"她每天都用她的新網球拍練習。"}]},{"word":"tense","pos":"adj. / n.","phonetic":"[tɛns]","meaning":"緊張的；時態","definition":"feeling or showing nervousness, or a grammatical form of a verb","collocations":["feel tense","tense atmosphere","verb tense"],"example":"The atmosphere was tense before the exam.","exampleZh":"考試前氣氛很緊張。","synonyms":["nervous","anxious"],"level":4,"theme":"情緒與感受","examples":[{"en":"The atmosphere was tense before the exam.","zh":"考試前氣氛很緊張。"},{"en":"Everyone felt tense as the results were announced.","zh":"當結果宣布時，每個人都感到緊張。"},{"en":"Our English teacher explained the past tense clearly.","zh":"我們的英文老師清楚地講解了過去式的時態。"}]},{"word":"tent","pos":"n.","phonetic":"[tɛnt]","meaning":"帳篷","definition":"a portable shelter made of cloth supported by poles","collocations":["pitch a tent","camping tent","sleep in a tent"],"example":"We set up our tent near the lake.","exampleZh":"我們在湖邊搭起帳篷。","synonyms":[],"level":2,"theme":"交通與旅行","examples":[{"en":"We set up our tent near the lake.","zh":"我們在湖邊搭起帳篷。"},{"en":"It started to rain, so we hurried into the tent.","zh":"開始下雨了，所以我們趕緊躲進帳篷裡。"},{"en":"The scouts learned how to pitch a tent quickly.","zh":"童軍們學會如何快速搭起帳篷。"}]},{"word":"tentative","pos":"adj.","phonetic":"[ˈtɛntətɪv]","meaning":"暫定的；試探性的","definition":"not certain or fixed; provisional","collocations":["a tentative plan","a tentative agreement","tentative steps"],"example":"We made a tentative arrangement to meet next Friday.","exampleZh":"我們暫定下週五見面。","synonyms":["provisional","uncertain"],"level":5,"theme":"抽象概念","examples":[{"en":"We made a tentative arrangement to meet next Friday.","zh":"我們暫定下週五見面。"},{"en":"We have a tentative plan to visit the museum on Sunday.","zh":"我們暫定星期天去參觀博物館。"},{"en":"The two sides reached a tentative agreement after the talk.","zh":"雙方在會談後達成了暫定的協議。"}]},{"word":"term","pos":"n.","phonetic":"[tɝm]","meaning":"學期；名詞；條件","definition":"a period of time such as a school semester, or a word/condition","collocations":["school term","technical term","term of contract"],"example":"The new term begins in September.","exampleZh":"新學期九月開始。","synonyms":["semester"],"level":3,"theme":"教育與學習","examples":[{"en":"The new term begins in September.","zh":"新學期九月開始。"},{"en":"Our new school term will start right after the holiday.","zh":"我們的新學期將在假期後立刻開始。"},{"en":"The teacher explained the difficult term in simple words.","zh":"老師用簡單的字詞解釋了那個難懂的名詞。"}]},{"word":"terminal","pos":"adj. / n.","phonetic":"[ˈtɝmənl]","meaning":"終點的；末期的；航空站","definition":"situated at an end, or a building where journeys begin or end","collocations":["airport terminal","terminal illness","bus terminal"],"example":"We waited at the airport terminal for our flight.","exampleZh":"我們在機場航廈等候班機。","synonyms":["final","station"],"level":4,"theme":"交通與旅行","examples":[{"en":"We waited at the airport terminal for our flight.","zh":"我們在機場航廈等候班機。"},{"en":"We rushed to the terminal to catch our early flight.","zh":"我們趕往航空站以搭上清晨的班機。"},{"en":"The bus terminal was crowded during the holiday season.","zh":"假期期間，公車總站擠滿了人。"}]},{"word":"terminate","pos":"v.","phonetic":"[ˈtɝməˌnet]","meaning":"終止；結束","definition":"to bring or come to an end","collocations":["terminate a contract","terminate employment","terminate a program"],"example":"The company decided to terminate the contract early.","exampleZh":"公司決定提前終止合約。","synonyms":["end","stop"],"level":5,"theme":"商業與金錢","examples":[{"en":"The company decided to terminate the contract early.","zh":"公司決定提前終止合約。"},{"en":"The club decided to terminate the meeting because of the storm.","zh":"由於暴風雨，社團決定終止這場會議。"},{"en":"They had to terminate the experiment when the power failed.","zh":"停電時他們不得不終止這項實驗。"}]},{"word":"terrace","pos":"n.","phonetic":"[ˈtɛrəs]","meaning":"露台；梯田","definition":"a flat outdoor area next to a building, or a leveled area on a hillside","collocations":["a roof terrace","rice terraces","sit on the terrace"],"example":"They had breakfast on the terrace overlooking the sea.","exampleZh":"他們在能俯瞰大海的露台上吃早餐。","synonyms":["patio","deck"],"level":4,"theme":"居家與生活","examples":[{"en":"They had breakfast on the terrace overlooking the sea.","zh":"他們在能俯瞰大海的露台上吃早餐。"},{"en":"We enjoyed a cool breeze while sitting on the terrace.","zh":"我們坐在露台上享受著涼爽的微風。"},{"en":"Farmers grow rice on the green terraces along the hillside.","zh":"農夫們在山坡上綠色的梯田裡種植稻米。"}]},{"word":"terrain","pos":"n.","phonetic":"[təˈren]","meaning":"地形；地勢","definition":"a stretch of land, especially with regard to its physical features","collocations":["rough terrain","mountainous terrain","cross difficult terrain"],"example":"The hikers struggled across the rocky terrain.","exampleZh":"登山客艱難地穿越崎嶇的地形。","synonyms":["landscape","ground"],"level":5,"theme":"自然與環境","examples":[{"en":"The hikers struggled across the rocky terrain.","zh":"登山客艱難地穿越崎嶇的地形。"},{"en":"The mountain bike is designed for rough terrain.","zh":"這輛登山車是為崎嶇的地形所設計的。"},{"en":"Soldiers had to march across difficult terrain for hours.","zh":"士兵們必須在艱難的地形上行軍好幾個小時。"}]},{"word":"terrible","pos":"adj.","phonetic":"[ˈtɛrəbḷ]","meaning":"可怕的；糟糕的","definition":"very bad, serious, or unpleasant","collocations":["terrible mistake","terrible weather","feel terrible"],"example":"We had terrible weather during our trip.","exampleZh":"我們旅行時天氣糟透了。","synonyms":["awful","dreadful"],"level":2,"theme":"性質與描述","examples":[{"en":"We had terrible weather during our trip.","zh":"我們旅行時天氣糟透了。"},{"en":"Forgetting my lines on stage was a terrible experience.","zh":"在台上忘詞是一次糟糕的經歷。"},{"en":"The terrible storm knocked down several old trees.","zh":"這場可怕的暴風雨吹倒了好幾棵老樹。"}]},{"word":"terrific","pos":"adj.","phonetic":"[təˈrɪfɪk]","meaning":"極好的","definition":"excellent or very good","collocations":["terrific idea","terrific performance"],"example":"You did a terrific job on the project.","exampleZh":"你這個專案做得非常出色。","synonyms":["excellent","wonderful"],"level":3,"theme":"性質與描述","examples":[{"en":"You did a terrific job on the project.","zh":"你這個專案做得非常出色。"},{"en":"The band gave a terrific performance at the festival.","zh":"那支樂團在慶典上有著極為出色的表演。"},{"en":"What a terrific idea for the school fair!","zh":"這對校園園遊會來說真是個好點子！"}]},{"word":"territory","pos":"n.","phonetic":"[ˈtɛrəˏtorɪ]","meaning":"領土；領域","definition":"an area of land under the control of a country or ruler","collocations":["enemy territory","foreign territory","defend territory"],"example":"The country expanded its territory after the war.","exampleZh":"這個國家在戰後擴張了領土。","synonyms":["land","region"],"level":5,"theme":"政治與法律","examples":[{"en":"The country expanded its territory after the war.","zh":"這個國家在戰後擴張了領土。"},{"en":"The lion roared to defend its territory from strangers.","zh":"那隻獅子吼叫著，以保衛自己的領土不受外來者侵犯。"},{"en":"Exploring a new subject can feel like unfamiliar territory.","zh":"探索一門新學科可能會讓人感覺像是陌生的領域。"}]},{"word":"terror","pos":"n.","phonetic":"[ˈtɛrɚ]","meaning":"恐懼；恐怖","definition":"extreme fear","collocations":["reign of terror","scream in terror","terror attack"],"example":"She screamed in terror when she saw the snake.","exampleZh":"她看到蛇時嚇得尖叫。","synonyms":["fear","horror"],"level":4,"theme":"情緒與感受","examples":[{"en":"She screamed in terror when she saw the snake.","zh":"她看到蛇時嚇得尖叫。"},{"en":"The children ran in terror when the dog started barking.","zh":"當狗開始吠叫時，孩子們驚恐地逃跑。"},{"en":"His face turned pale with terror during the scary movie.","zh":"看恐怖片時，他的臉因恐懼而變得蒼白。"}]},{"word":"test","pos":"n. / v.","phonetic":"[tɛst]","meaning":"測驗；測試","definition":"a set of questions or activities designed to measure ability or knowledge","collocations":["take a test","pass a test","blood test"],"example":"We have a math test tomorrow.","exampleZh":"我們明天有一場數學測驗。","synonyms":["exam","quiz"],"level":1,"theme":"教育與學習","examples":[{"en":"We have a math test tomorrow.","zh":"我們明天有一場數學測驗。"},{"en":"We need to study hard for the history test on Friday.","zh":"我們得為星期五的歷史考試用功讀書。"},{"en":"The doctor ordered a blood test to check his health.","zh":"醫生安排了血液檢驗以檢查他的健康狀況。"}]},{"word":"testify","pos":"v.","phonetic":"[ˈtɛstəˌfaɪ]","meaning":"作證；證明","definition":"to give evidence as a witness, in court or in a public inquiry","collocations":["testify in court","testify against someone","testify to the truth"],"example":"The witness testified that she saw the accident happen.","exampleZh":"目擊者作證說她看到了事故發生的經過。","synonyms":["witness","declare"],"level":5,"theme":"政治與法律","examples":[{"en":"The witness testified that she saw the accident happen.","zh":"目擊者作證說她看到了事故發生的經過。"},{"en":"A brave neighbor agreed to testify in court about the crime.","zh":"一位勇敢的鄰居同意上法庭為這起犯罪作證。"},{"en":"His good grades testify to his hard work all year.","zh":"他優異的成績證明了他整年的努力。"}]},{"word":"testimony","pos":"n.","phonetic":"[ˈtɛstəˌmoni]","meaning":"證詞；證言","definition":"a formal written or spoken statement, especially in a court of law","collocations":["give testimony","expert testimony","written testimony"],"example":"Her testimony helped convince the jury of his innocence.","exampleZh":"她的證詞幫助陪審團相信他的清白。","synonyms":["statement","evidence"],"level":5,"theme":"政治與法律","examples":[{"en":"Her testimony helped convince the jury of his innocence.","zh":"她的證詞幫助陪審團相信他的清白。"},{"en":"The witness gave clear testimony about what she had seen.","zh":"那位證人就她所目睹的事清楚地作了證詞。"},{"en":"The scientist's testimony helped explain the accident.","zh":"那位科學家的證言有助於解釋這起意外。"}]},{"word":"text","pos":"n. / v.","phonetic":"[tɛkst]","meaning":"文本；傳簡訊","definition":"written material, or to send someone a text message","collocations":["text message","send a text","read a text"],"example":"I'll text you when I arrive.","exampleZh":"我到了會傳簡訊給你。","synonyms":["message"],"level":2,"theme":"溝通與語言","examples":[{"en":"I'll text you when I arrive.","zh":"我到了會傳簡訊給你。"},{"en":"She sent me a text to say she would be late.","zh":"她傳了一則簡訊告訴我她會遲到。"},{"en":"We read the whole text carefully before answering the questions.","zh":"在回答問題之前，我們仔細地閱讀了整篇文章。"}]},{"word":"textbook","pos":"n.","phonetic":"[ˈtɛkstˏbʊk]","meaning":"教科書","definition":"a book used for studying a particular subject","collocations":["history textbook","buy a textbook"],"example":"Please open your textbook to page ten.","exampleZh":"請翻開課本第十頁。","synonyms":[],"level":1,"theme":"教育與學習","examples":[{"en":"Please open your textbook to page ten.","zh":"請翻開課本第十頁。"},{"en":"I forgot my science textbook at home this morning.","zh":"今天早上我把自然科教科書忘在家裡了。"},{"en":"The history textbook has many helpful maps and pictures.","zh":"這本歷史教科書有許多實用的地圖和圖片。"}]},{"word":"textile","pos":"n. / adj.","phonetic":"[ˈtɛkstaɪl]","meaning":"紡織品；紡織的","definition":"a type of cloth or woven fabric","collocations":["textile industry","cotton textiles","textile factory"],"example":"The city was once famous for its textile industry.","exampleZh":"這座城市曾以紡織業聞名。","synonyms":["fabric","cloth"],"level":5,"theme":"商業與金錢","examples":[{"en":"The city was once famous for its textile industry.","zh":"這座城市曾以紡織業聞名。"},{"en":"The factory produces cotton textiles for clothing stores.","zh":"這家工廠為服飾店生產棉質紡織品。"},{"en":"Her aunt works in the textile industry designing patterns.","zh":"她阿姨在紡織業工作，負責設計花樣。"}]},{"word":"texture","pos":"n.","phonetic":"[ˈtɛkstʃɚ]","meaning":"質地；紋理","definition":"the feel, appearance, or consistency of a surface or substance","collocations":["smooth texture","rough texture","texture of the fabric"],"example":"The cake has a soft, moist texture.","exampleZh":"這個蛋糕的質地柔軟濕潤。","synonyms":[],"level":5,"theme":"性質與描述","examples":[{"en":"The cake has a soft, moist texture.","zh":"這個蛋糕的質地柔軟濕潤。"},{"en":"I love the smooth texture of this silk scarf.","zh":"我很喜歡這條絲巾光滑的質地。"},{"en":"The rough texture of the bark felt strange under my fingers.","zh":"樹皮粗糙的紋理在我指尖下感覺很奇特。"}]},{"word":"thank","pos":"v.","phonetic":"[θæŋk]","meaning":"感謝","definition":"to express gratitude to someone","collocations":["thank you","thank someone for"],"example":"I want to thank you for your help.","exampleZh":"我想感謝你的幫助。","synonyms":["appreciate"],"level":1,"theme":"溝通與語言","examples":[{"en":"I want to thank you for your help.","zh":"我想感謝你的幫助。"},{"en":"I would like to thank everyone who came to my party.","zh":"我想感謝每一位來參加我派對的人。"},{"en":"She wrote a card to thank her teacher for the guidance.","zh":"她寫了一張卡片，感謝老師的指導。"}]},{"word":"theater","pos":"n.","phonetic":"[ˈθiətɚ]","meaning":"劇院；戲劇","definition":"a building where plays or films are performed or shown","collocations":["go to the theater","movie theater","theater ticket"],"example":"We watched a play at the theater last night.","exampleZh":"我們昨晚在劇院看了一場戲。","synonyms":[],"level":2,"theme":"藝術與音樂","examples":[{"en":"We watched a play at the theater last night.","zh":"我們昨晚在劇院看了一場戲。"},{"en":"They dressed nicely before going to the theater downtown.","zh":"他們穿得漂漂亮亮才去市中心的劇院。"},{"en":"The new movie theater has very comfortable seats.","zh":"這家新的電影院有著非常舒適的座椅。"}]},{"word":"theft","pos":"n.","phonetic":"[θɛft]","meaning":"竊盜；偷竊","definition":"the act of stealing","collocations":["report a theft","identity theft","prevent theft"],"example":"The store installed cameras to prevent theft.","exampleZh":"這家店安裝了攝影機以防止竊盜。","synonyms":["stealing","robbery"],"level":4,"theme":"政治與法律","examples":[{"en":"The store installed cameras to prevent theft.","zh":"這家店安裝了攝影機以防止竊盜。"},{"en":"The manager reported the theft of several laptops to the police.","zh":"經理向警方報案，說有好幾台筆電遭竊。"},{"en":"Locking your bike helps prevent theft on campus.","zh":"把腳踏車鎖好有助於防止校園內的竊盜。"}]},{"word":"theme","pos":"n.","phonetic":"[θim]","meaning":"主題","definition":"the main subject or idea of a piece of work","collocations":["main theme","theme song","theme park"],"example":"The theme of the novel is love and loss.","exampleZh":"這本小說的主題是愛與失去。","synonyms":["subject","topic"],"level":4,"theme":"藝術與音樂","examples":[{"en":"The theme of the novel is love and loss.","zh":"這本小說的主題是愛與失去。"},{"en":"Friendship is the main theme of this children's book.","zh":"友誼是這本童書的主要主題。"},{"en":"We spent the whole day at the new theme park.","zh":"我們在新的主題樂園玩了一整天。"}]},{"word":"theoretical","pos":"adj.","phonetic":"[ˌθiəˈrɛtɪkl]","meaning":"理論的；理論上的","definition":"concerned with theory rather than practice","collocations":["theoretical knowledge","a theoretical approach","purely theoretical"],"example":"The course focuses on theoretical rather than practical skills.","exampleZh":"這門課著重理論而非實務技能。","synonyms":["abstract","conceptual"],"level":6,"theme":"科學與數學","examples":[{"en":"The course focuses on theoretical rather than practical skills.","zh":"這門課著重理論而非實務技能。"},{"en":"The lecture was purely theoretical, with no real examples.","zh":"這場演講純粹是理論性的，沒有實際的例子。"},{"en":"He has plenty of theoretical knowledge but little experience.","zh":"他有豐富的理論知識，卻缺乏實務經驗。"}]},{"word":"theory","pos":"n.","phonetic":"[ˈθiərɪ]","meaning":"理論","definition":"an idea or set of ideas meant to explain something","collocations":["scientific theory","in theory","prove a theory"],"example":"Darwin's theory of evolution changed science.","exampleZh":"達爾文的演化論改變了科學。","synonyms":[],"level":4,"theme":"科學與數學","examples":[{"en":"Darwin's theory of evolution changed science.","zh":"達爾文的演化論改變了科學。"},{"en":"In theory, the plan sounds simple, but it is hard to do.","zh":"理論上，這個計畫聽起來很簡單，但實際上很難做到。"},{"en":"The students discussed a scientific theory about black holes.","zh":"學生們討論了一個關於黑洞的科學理論。"}]},{"word":"therapist","pos":"n.","phonetic":"[ˈθɛrəpɪst]","meaning":"治療師","definition":"a person trained to treat physical or mental problems","collocations":["see a therapist","a physical therapist","a family therapist"],"example":"She visits a therapist every week to manage her stress.","exampleZh":"她每週去看治療師以緩解壓力。","synonyms":["counselor"],"level":5,"theme":"身體與健康","examples":[{"en":"She visits a therapist every week to manage her stress.","zh":"她每週去看治療師以緩解壓力。"},{"en":"The physical therapist helped him walk again after the injury.","zh":"物理治療師幫助他在受傷後重新走路。"},{"en":"She decided to see a therapist to talk about her worries.","zh":"她決定去看治療師，聊聊自己的煩惱。"}]},{"word":"therapy","pos":"n.","phonetic":"[ˈθɛrəpɪ]","meaning":"治療","definition":"treatment intended to relieve or heal a disorder","collocations":["physical therapy","speech therapy","undergo therapy"],"example":"She is undergoing therapy after the accident.","exampleZh":"她在事故後接受治療。","synonyms":["treatment"],"level":5,"theme":"身體與健康","examples":[{"en":"She is undergoing therapy after the accident.","zh":"她在事故後接受治療。"},{"en":"The child needs speech therapy to pronounce words clearly.","zh":"這個孩子需要語言治療才能清楚地發音。"},{"en":"He is undergoing therapy to strengthen his broken leg.","zh":"他正在接受治療，以強化他斷掉的腿。"}]},{"word":"thermal","pos":"adj.","phonetic":"[ˈθɝml]","meaning":"熱的；保暖的","definition":"relating to heat, or designed to keep the body warm","collocations":["thermal energy","thermal underwear","a thermal spring"],"example":"She wore thermal clothing to stay warm during the hike.","exampleZh":"她穿著保暖衣物在健行時保持溫暖。","synonyms":["warm","heat-related"],"level":5,"theme":"科學與數學","examples":[{"en":"She wore thermal clothing to stay warm during the hike.","zh":"她穿著保暖衣物在健行時保持溫暖。"},{"en":"The hot spring uses thermal energy from deep underground.","zh":"這座溫泉利用來自地底深處的熱能。"},{"en":"We packed thermal underwear for the trip to the snowy mountain.","zh":"我們為前往雪山的旅程準備了保暖內衣。"}]},{"word":"thermometer","pos":"n.","phonetic":"[θɚˈmɑmətɚ]","meaning":"溫度計","definition":"an instrument for measuring temperature","collocations":["check the thermometer","a mercury thermometer","read a thermometer"],"example":"The nurse used a thermometer to check the patient's temperature.","exampleZh":"護理師用溫度計量測病人的體溫。","synonyms":[],"level":3,"theme":"科學與數學","examples":[{"en":"The nurse used a thermometer to check the patient's temperature.","zh":"護理師用溫度計量測病人的體溫。"},{"en":"She placed the thermometer under her tongue to check the fever.","zh":"她把溫度計放在舌下量體溫，看看是否發燒。"},{"en":"The thermometer showed that the room was quite warm.","zh":"溫度計顯示房間相當溫暖。"}]},{"word":"thesis","pos":"n.","phonetic":"[ˈθisɪs]","meaning":"論文；論點","definition":"a long piece of academic writing based on original research, or a statement put forward for argument","collocations":["write a thesis","a master's thesis","defend a thesis"],"example":"She spent a year researching her graduate thesis.","exampleZh":"她花了一年時間研究她的碩士論文。","synonyms":["dissertation","argument"],"level":6,"theme":"教育與學習","examples":[{"en":"She spent a year researching her graduate thesis.","zh":"她花了一年時間研究她的碩士論文。"},{"en":"She spent two years writing her master's thesis on ocean life.","zh":"她花了兩年撰寫關於海洋生物的碩士論文。"},{"en":"The main thesis of his essay is that reading builds empathy.","zh":"他文章的主要論點是閱讀能培養同理心。"}]},{"word":"thick","pos":"adj.","phonetic":"[θɪk]","meaning":"厚的；濃的","definition":"having a large distance between opposite surfaces","collocations":["thick book","thick fog","thick soup"],"example":"The fog was so thick we couldn't see the road.","exampleZh":"霧太濃了，我們看不到道路。","synonyms":["dense"],"level":2,"theme":"性質與描述","examples":[{"en":"The fog was so thick we couldn't see the road.","zh":"霧太濃了，我們看不到道路。"},{"en":"He wore a thick coat because the wind was freezing.","zh":"因為風冷得刺骨，他穿了一件厚外套。"},{"en":"She spread a thick layer of jam on her toast.","zh":"她在吐司上塗了一層厚厚的果醬。"}]},{"word":"thief","pos":"n.","phonetic":"[θif]","meaning":"小偷","definition":"a person who steals something from another person","collocations":["catch a thief","thief in the night"],"example":"The thief stole her purse on the bus.","exampleZh":"那個小偷在公車上偷了她的錢包。","synonyms":["robber"],"level":2,"theme":"政治與法律","examples":[{"en":"The thief stole her purse on the bus.","zh":"那個小偷在公車上偷了她的錢包。"},{"en":"The police finally caught the thief who robbed the bank.","zh":"警方終於抓到了那名搶劫銀行的小偷。"},{"en":"A clever dog scared the thief away from the yard.","zh":"一隻聰明的狗把小偷從院子裡嚇跑了。"}]},{"word":"thigh","pos":"n.","phonetic":"[θaɪ]","meaning":"大腿","definition":"the part of the leg between the hip and the knee","collocations":["thigh muscle","chicken thigh"],"example":"He pulled a muscle in his thigh during the race.","exampleZh":"他在賽跑時大腿拉傷了。","synonyms":[],"level":3,"theme":"身體與健康","examples":[{"en":"He pulled a muscle in his thigh during the race.","zh":"他在賽跑時大腿拉傷了。"},{"en":"The runner rubbed his sore thigh after the long race.","zh":"跑者在長跑後揉著他痠痛的大腿。"},{"en":"Grilled chicken thigh is my favorite dish at dinner.","zh":"烤雞腿是我晚餐時最愛的一道菜。"}]},{"word":"thin","pos":"adj.","phonetic":"[θɪn]","meaning":"薄的；瘦的","definition":"having little thickness, or having little body fat","collocations":["thin slice","thin and tall","thin ice"],"example":"She cut the bread into thin slices.","exampleZh":"她把麵包切成薄片。","synonyms":["slim","slender"],"level":1,"theme":"性質與描述","examples":[{"en":"She cut the bread into thin slices.","zh":"她把麵包切成薄片。"},{"en":"The ice on the pond is too thin to walk on.","zh":"池塘上的冰太薄，無法在上面行走。"},{"en":"He is tall and thin, so most clothes fit him loosely.","zh":"他又高又瘦，所以大部分的衣服穿在他身上都很寬鬆。"}]},{"word":"thing","pos":"n.","phonetic":"[θɪŋ]","meaning":"事情；東西","definition":"an object or matter that is not named specifically","collocations":["a good thing","do things","things to do"],"example":"There are many things to do this weekend.","exampleZh":"這個週末有很多事情要做。","synonyms":["object","matter"],"level":1,"theme":"抽象概念","examples":[{"en":"There are many things to do this weekend.","zh":"這個週末有很多事情要做。"},{"en":"Finishing your homework early is a good thing.","zh":"提早完成功課是件好事。"},{"en":"There are so many things to remember before the trip.","zh":"出遊前有好多事情要記得。"}]},{"word":"think","pos":"v.","phonetic":"[θɪŋk]","meaning":"思考；認為","definition":"to use one's mind to consider or believe something","collocations":["think about","think of","think twice"],"example":"I need time to think about your offer.","exampleZh":"我需要時間考慮你的提議。","synonyms":["consider","believe"],"level":1,"theme":"抽象概念","examples":[{"en":"I need time to think about your offer.","zh":"我需要時間考慮你的提議。"},{"en":"Please think carefully before you answer the question.","zh":"回答問題前請仔細思考。"},{"en":"I think we should leave early to avoid the traffic.","zh":"我認為我們應該早點出發以避開交通壅塞。"}]},{"word":"thirsty","pos":"adj.","phonetic":"[ˈθɝstɪ]","meaning":"口渴的","definition":"feeling a need to drink something","collocations":["get thirsty","thirsty for water"],"example":"After the run, I was very thirsty.","exampleZh":"跑步後我非常口渴。","synonyms":[],"level":1,"theme":"身體與健康","examples":[{"en":"After the run, I was very thirsty.","zh":"跑步後我非常口渴。"},{"en":"The hikers grew thirsty under the hot afternoon sun.","zh":"登山客在午後炎熱的陽光下越來越口渴。"},{"en":"Playing basketball all morning made me very thirsty.","zh":"打了一整個早上的籃球讓我非常口渴。"}]},{"word":"thorn","pos":"n.","phonetic":"[θɔrn]","meaning":"刺；荊棘","definition":"a sharp pointed growth on the stem of a plant","collocations":["a rose thorn","prick on a thorn","a thorn bush"],"example":"He pricked his finger on a rose thorn.","exampleZh":"他的手指被玫瑰花刺扎到了。","synonyms":["spike","prickle"],"level":3,"theme":"動物與植物","examples":[{"en":"He pricked his finger on a rose thorn.","zh":"他的手指被玫瑰花刺扎到了。"},{"en":"Be careful of the sharp thorns when you pick the roses.","zh":"摘玫瑰時要小心那些尖銳的刺。"},{"en":"A thorn from the bush tore a hole in his sleeve.","zh":"灌木叢上的一根刺在他的袖子上劃破了一個洞。"}]},{"word":"thorough","pos":"adj.","phonetic":"[ˈθɝo]","meaning":"徹底的；仔細的","definition":"complete in every detail; careful and exact","collocations":["thorough investigation","thorough check","thorough understanding"],"example":"The police conducted a thorough investigation.","exampleZh":"警方進行了徹底的調查。","synonyms":["complete","careful"],"level":5,"theme":"性質與描述","examples":[{"en":"The police conducted a thorough investigation.","zh":"警方進行了徹底的調查。"},{"en":"The mechanic did a thorough check of the whole car.","zh":"技師對整輛車做了徹底的檢查。"},{"en":"A thorough understanding of the topic takes patience.","zh":"對一個主題有透徹的理解需要耐心。"}]},{"word":"though","pos":"conj. / adv.","phonetic":"[ðo]","meaning":"雖然；不過","definition":"despite the fact that; however","collocations":["even though","as though"],"example":"Though it was raining, we went hiking.","exampleZh":"雖然下雨，我們還是去健行了。","synonyms":["although"],"level":2,"theme":"溝通與語言","examples":[{"en":"Though it was raining, we went hiking.","zh":"雖然下雨，我們還是去健行了。"},{"en":"Though the test was hard, most students passed it.","zh":"雖然這次考試很難，大多數學生還是通過了。"},{"en":"She smiled as though nothing had happened.","zh":"她笑得彷彿什麼事都沒發生過。"}]},{"word":"thought","pos":"n.","phonetic":"[θɔt]","meaning":"想法；思考","definition":"an idea or opinion produced by thinking","collocations":["deep in thought","second thought","share a thought"],"example":"She was lost in thought during the meeting.","exampleZh":"她在會議中陷入沉思。","synonyms":["idea"],"level":2,"theme":"抽象概念","examples":[{"en":"She was lost in thought during the meeting.","zh":"她在會議中陷入沉思。"},{"en":"A sudden thought made him change his whole plan.","zh":"一個突如其來的想法讓他改變了整個計畫。"},{"en":"On second thought, I decided not to buy the jacket.","zh":"再仔細想想，我決定不買那件外套了。"}]},{"word":"thoughtful","pos":"adj.","phonetic":"[ˈθɔtfl]","meaning":"體貼的；深思的","definition":"showing careful thought or considerate concern for others","collocations":["a thoughtful gift","a thoughtful person","a thoughtful expression"],"example":"It was very thoughtful of you to remember my birthday.","exampleZh":"你還記得我的生日,真是體貼。","synonyms":["considerate","caring"],"level":3,"theme":"性質與描述","examples":[{"en":"It was very thoughtful of you to remember my birthday.","zh":"你還記得我的生日,真是體貼。"},{"en":"It was thoughtful of her to save me a seat.","zh":"她幫我留了個位子，真是體貼。"},{"en":"He wore a thoughtful expression while solving the puzzle.","zh":"他解謎題時露出深思的表情。"}]},{"word":"thousand","pos":"n.","phonetic":"[ˈθaʊzn̩d]","meaning":"一千","definition":"the number 1000","collocations":["thousands of","a thousand times"],"example":"Thousands of people attended the concert.","exampleZh":"數千人參加了這場演唱會。","synonyms":[],"level":1,"theme":"科學與數學","examples":[{"en":"Thousands of people attended the concert.","zh":"數千人參加了這場演唱會。"},{"en":"Thousands of students took the entrance exam this year.","zh":"今年有數千名學生參加了入學考試。"},{"en":"I have told you a thousand times to close the door.","zh":"我已經告訴你一千次要關門了。"}]},{"word":"thread","pos":"n. / v.","phonetic":"[θrɛd]","meaning":"線；縫線","definition":"a fine strand of cotton or other fiber used in sewing","collocations":["needle and thread","thread a needle"],"example":"She used a needle and thread to fix the button.","exampleZh":"她用針線縫好了鈕扣。","synonyms":[],"level":3,"theme":"服裝與外表","examples":[{"en":"She used a needle and thread to fix the button.","zh":"她用針線縫好了鈕扣。"},{"en":"She carefully pulled a red thread through the needle.","zh":"她小心地把一條紅線穿過針孔。"},{"en":"He needed a strong thread to sew the torn backpack.","zh":"他需要一條堅韌的線來縫補破掉的背包。"}]},{"word":"threat","pos":"n.","phonetic":"[θrɛt]","meaning":"威脅","definition":"a statement of intention to cause harm or damage","collocations":["pose a threat","death threat","under threat"],"example":"Pollution is a serious threat to the environment.","exampleZh":"污染是對環境的嚴重威脅。","synonyms":["danger"],"level":4,"theme":"抽象概念","examples":[{"en":"Pollution is a serious threat to the environment.","zh":"污染是對環境的嚴重威脅。"},{"en":"Heavy pollution poses a serious threat to the river's fish.","zh":"嚴重的汙染對河中的魚構成嚴重的威脅。"},{"en":"The old bridge is under threat of collapsing.","zh":"那座舊橋面臨倒塌的威脅。"}]},{"word":"threaten","pos":"v.","phonetic":"[ˈθrɛtn̩]","meaning":"威脅","definition":"to express an intention to harm someone","collocations":["threaten to","be threatened by"],"example":"He threatened to quit if he didn't get a raise.","exampleZh":"他威脅如果不加薪就要辭職。","synonyms":["warn","intimidate"],"level":4,"theme":"抽象概念","examples":[{"en":"He threatened to quit if he didn't get a raise.","zh":"他威脅如果不加薪就要辭職。"},{"en":"Dark clouds threatened to bring a heavy storm.","zh":"烏雲密布，似乎將帶來一場大暴風雨。"},{"en":"He threatened to tell the teacher about the broken window.","zh":"他威脅說要把打破窗戶的事告訴老師。"}]},{"word":"threshold","pos":"n.","phonetic":"[ˈθrɛʃhold]","meaning":"門檻；起點；界限","definition":"the entrance to a room or building, or the point at which something begins","collocations":["cross the threshold","a pain threshold","on the threshold of"],"example":"She stood on the threshold, hesitant to enter.","exampleZh":"她站在門檻上,猶豫著要不要進去。","synonyms":["doorway","entrance"],"level":5,"theme":"時間與空間","examples":[{"en":"She stood on the threshold, hesitant to enter.","zh":"她站在門檻上,猶豫著要不要進去。"},{"en":"She paused on the threshold before stepping into the dark room.","zh":"她在門檻上停頓了一下，才踏進那間黑暗的房間。"},{"en":"The young athlete is on the threshold of a great career.","zh":"這位年輕運動員正站在輝煌職業生涯的起點上。"}]},{"word":"thrifty","pos":"adj.","phonetic":"[ˈθrɪfti]","meaning":"節儉的","definition":"careful with money; not wasteful","collocations":["a thrifty shopper","thrifty habits","live a thrifty life"],"example":"My grandmother is thrifty and never wastes food.","exampleZh":"我奶奶很節儉,從不浪費食物。","synonyms":["frugal","economical"],"level":5,"theme":"商業與金錢","examples":[{"en":"My grandmother is thrifty and never wastes food.","zh":"我奶奶很節儉,從不浪費食物。"},{"en":"Being thrifty, she saved most of her pocket money.","zh":"由於節儉，她把大部分的零用錢都存了起來。"},{"en":"A thrifty shopper always compares prices before buying.","zh":"節儉的購物者總是在購買前比較價格。"}]},{"word":"thrill","pos":"n. / v.","phonetic":"[θrɪl]","meaning":"興奮；刺激；使興奮","definition":"a sudden feeling of excitement or pleasure","collocations":["a thrill of excitement","thrill seekers","thrilled to hear"],"example":"Riding the roller coaster gave her a real thrill.","exampleZh":"搭雲霄飛車讓她感到非常刺激。","synonyms":["excitement","exhilaration"],"level":4,"theme":"情緒與感受","examples":[{"en":"Riding the roller coaster gave her a real thrill.","zh":"搭雲霄飛車讓她感到非常刺激。"},{"en":"Scoring the winning goal gave the whole team a thrill.","zh":"踢進致勝的一球讓整支球隊感到興奮無比。"},{"en":"She was thrilled to hear that she had won the contest.","zh":"聽到自己贏得比賽，她興奮極了。"}]},{"word":"throat","pos":"n.","phonetic":"[θrot]","meaning":"喉嚨","definition":"the passage at the back of the mouth leading to the stomach and lungs","collocations":["sore throat","clear one's throat"],"example":"I have a sore throat and a cough.","exampleZh":"我喉嚨痛又咳嗽。","synonyms":[],"level":2,"theme":"身體與健康","examples":[{"en":"I have a sore throat and a cough.","zh":"我喉嚨痛又咳嗽。"},{"en":"I have a sore throat, so I can hardly speak today.","zh":"我喉嚨痛，所以今天幾乎說不出話來。"},{"en":"He cleared his throat before starting his speech.","zh":"他在開始演講前清了清喉嚨。"}]},{"word":"throne","pos":"n.","phonetic":"[θron]","meaning":"王座；王位","definition":"the ceremonial chair on which a king or queen sits","collocations":["sit on the throne","take the throne"],"example":"The prince will inherit the throne next year.","exampleZh":"王子明年將繼承王位。","synonyms":[],"level":5,"theme":"政治與法律","examples":[{"en":"The prince will inherit the throne next year.","zh":"王子明年將繼承王位。"},{"en":"The young queen sat proudly on the golden throne.","zh":"年輕的女王驕傲地坐在金色的王座上。"},{"en":"After his father died, the prince took the throne.","zh":"父親過世後，王子繼承了王位。"}]},{"word":"through","pos":"prep.","phonetic":"[θru]","meaning":"穿過；透過","definition":"moving in one side of something and out the other","collocations":["go through","through the window","look through"],"example":"Sunlight streamed through the window.","exampleZh":"陽光透過窗戶照射進來。","synonyms":[],"level":1,"theme":"時間與空間","examples":[{"en":"Sunlight streamed through the window.","zh":"陽光透過窗戶照射進來。"},{"en":"The train went through a long dark tunnel.","zh":"火車穿過一條又長又黑的隧道。"},{"en":"We learned about history through an interesting documentary.","zh":"我們透過一部有趣的紀錄片認識歷史。"}]},{"word":"throughout","pos":"prep.","phonetic":"[θruˈaʊt]","meaning":"遍及；自始至終","definition":"during the whole period of time, or in every part of a place","collocations":["throughout the year","throughout the country"],"example":"The festival is celebrated throughout the country.","exampleZh":"這個節日在全國各地都會慶祝。","synonyms":[],"level":4,"theme":"時間與空間","examples":[{"en":"The festival is celebrated throughout the country.","zh":"這個節日在全國各地都會慶祝。"},{"en":"The little shop stays busy throughout the whole year.","zh":"這家小店一整年都很忙碌。"},{"en":"News of the victory spread throughout the town quickly.","zh":"勝利的消息很快傳遍了整個城鎮。"}]},{"word":"throw","pos":"v.","phonetic":"[θro]","meaning":"投擲；丟","definition":"to send something through the air with force","collocations":["throw a ball","throw away","throw a party"],"example":"He threw the ball to his teammate.","exampleZh":"他把球丟給了隊友。","synonyms":["toss","pitch"],"level":1,"theme":"動作與行為","examples":[{"en":"He threw the ball to his teammate.","zh":"他把球丟給了隊友。"},{"en":"Please don't throw trash on the ground in the park.","zh":"請不要把垃圾丟在公園的地上。"},{"en":"My parents will throw a party for my graduation.","zh":"我的父母將為我的畢業舉辦一場派對。"}]},{"word":"thumb","pos":"n.","phonetic":"[θʌm]","meaning":"拇指","definition":"the short thick finger on the hand set apart from the other four","collocations":["thumbs up","under one's thumb"],"example":"She gave a thumbs up to show approval.","exampleZh":"她豎起大拇指表示贊同。","synonyms":[],"level":2,"theme":"身體與健康","examples":[{"en":"She gave a thumbs up to show approval.","zh":"她豎起大拇指表示贊同。"},{"en":"He hit his thumb with the hammer by accident.","zh":"他不小心用鎚子敲到了自己的拇指。"},{"en":"The coach gave the players a thumbs up after the win.","zh":"教練在獲勝後對球員們比了個讚。"}]},{"word":"thunder","pos":"n. / v.","phonetic":"[ˈθʌndɚ]","meaning":"雷聲；打雷","definition":"the loud noise that follows a flash of lightning","collocations":["thunder and lightning","thunder roars"],"example":"We heard thunder rolling in the distance.","exampleZh":"我們聽到遠處傳來雷聲。","synonyms":[],"level":2,"theme":"天氣與季節","examples":[{"en":"We heard thunder rolling in the distance.","zh":"我們聽到遠處傳來雷聲。"},{"en":"The loud thunder frightened the sleeping baby.","zh":"響亮的雷聲嚇到了熟睡的嬰兒。"},{"en":"Thunder and lightning kept us awake all night.","zh":"打雷和閃電讓我們整晚都睡不著。"}]},{"word":"thus","pos":"adv.","phonetic":"[ðʌs]","meaning":"因此；如此","definition":"as a result of this; in this way","collocations":["thus far","and thus"],"example":"The road was closed, thus causing heavy traffic.","exampleZh":"道路封閉，因此造成嚴重塞車。","synonyms":["therefore"],"level":4,"theme":"溝通與語言","examples":[{"en":"The road was closed, thus causing heavy traffic.","zh":"道路封閉，因此造成嚴重塞車。"},{"en":"He practiced daily, thus becoming the best player on the team.","zh":"他每天練習，因此成為隊上最優秀的球員。"},{"en":"We have finished thus far without any serious problems.","zh":"到目前為止，我們順利地完成了工作，沒有嚴重的問題。"}]},{"word":"tick","pos":"v. / n.","phonetic":"[tɪk]","meaning":"滴答聲；打勾","definition":"the regular sound a clock makes, or a mark to show something is correct","collocations":["tick the box","clock ticks"],"example":"Please tick the correct answer.","exampleZh":"請在正確答案上打勾。","synonyms":[],"level":3,"theme":"時間與空間","examples":[{"en":"Please tick the correct answer.","zh":"請在正確答案上打勾。"},{"en":"Please tick the box next to your favorite hobby.","zh":"請在你最喜歡的嗜好旁邊的框框裡打勾。"},{"en":"The old clock continued to tick quietly on the wall.","zh":"那座老鐘在牆上安靜地滴答作響。"}]},{"word":"ticket","pos":"n.","phonetic":"[ˈtɪkɪt]","meaning":"票；罰單","definition":"a piece of paper showing payment for entry, travel, or a fine","collocations":["buy a ticket","movie ticket","parking ticket"],"example":"I bought two tickets for the concert.","exampleZh":"我買了兩張演唱會的票。","synonyms":[],"level":1,"theme":"交通與旅行","examples":[{"en":"I bought two tickets for the concert.","zh":"我買了兩張演唱會的票。"},{"en":"I bought a ticket for the morning train to the coast.","zh":"我買了一張早班火車前往海邊的車票。"},{"en":"He got a parking ticket for leaving his car on the corner.","zh":"他因為把車停在轉角而收到一張違規停車罰單。"}]},{"word":"tide","pos":"n.","phonetic":"[taɪd]","meaning":"潮汐","definition":"the regular rise and fall of the sea caused by the moon's pull","collocations":["high tide","low tide","tide comes in"],"example":"The tide comes in twice a day.","exampleZh":"潮汐每天漲兩次。","synonyms":[],"level":3,"theme":"自然與環境","examples":[{"en":"The tide comes in twice a day.","zh":"潮汐每天漲兩次。"},{"en":"At high tide, the beach almost disappears under the water.","zh":"漲潮時，海灘幾乎全被水淹沒。"},{"en":"We collected shells when the tide went out.","zh":"退潮時我們撿了貝殼。"}]},{"word":"tidy","pos":"adj. / v.","phonetic":"[ˈtaɪdɪ]","meaning":"整潔的；整理","definition":"neat and in order; to make something neat","collocations":["tidy room","keep tidy","tidy up"],"example":"Please tidy up your room before dinner.","exampleZh":"晚餐前請把房間整理好。","synonyms":["neat","clean"],"level":2,"theme":"居家與生活","examples":[{"en":"Please tidy up your room before dinner.","zh":"晚餐前請把房間整理好。"},{"en":"She keeps her desk tidy so she can find things easily.","zh":"她把書桌保持整潔，這樣才能輕鬆找到東西。"},{"en":"Let's tidy up the classroom before the teacher arrives.","zh":"在老師來之前，我們把教室整理乾淨吧。"}]},{"word":"tie","pos":"v. / n.","phonetic":"[taɪ]","meaning":"綁；領帶；平局","definition":"to fasten with string or rope; a piece of clothing worn around the neck; an equal result","collocations":["tie a knot","wear a tie","end in a tie"],"example":"He wore a blue tie to the interview.","exampleZh":"他穿了藍色領帶去面試。","synonyms":["fasten","bind"],"level":2,"theme":"服裝與外表","examples":[{"en":"He wore a blue tie to the interview.","zh":"他穿了藍色領帶去面試。"},{"en":"Can you help me tie this knot on the package?","zh":"你能幫我把包裹上的這個結綁好嗎？"},{"en":"The exciting match ended in a tie after extra time.","zh":"這場精彩的比賽在延長賽後以平局收場。"}]},{"word":"tight","pos":"adj.","phonetic":"[taɪt]","meaning":"緊的","definition":"fitting closely; not loose","collocations":["tight schedule","tight clothes","hold tight"],"example":"These shoes feel too tight.","exampleZh":"這雙鞋感覺太緊了。","synonyms":[],"level":2,"theme":"性質與描述","examples":[{"en":"These shoes feel too tight.","zh":"這雙鞋感覺太緊了。"},{"en":"We have a tight schedule, so please arrive on time.","zh":"我們的行程很緊湊，所以請準時抵達。"},{"en":"Hold the rope tight so you don't fall.","zh":"把繩子抓緊，這樣你才不會摔下去。"}]},{"word":"tile","pos":"n.","phonetic":"[taɪl]","meaning":"磁磚；瓦片","definition":"a flat piece of material used to cover floors, walls, or roofs","collocations":["floor tile","roof tile","ceramic tile"],"example":"The bathroom floor is covered with white tiles.","exampleZh":"浴室地板鋪滿了白色磁磚。","synonyms":[],"level":3,"theme":"居家與生活","examples":[{"en":"The bathroom floor is covered with white tiles.","zh":"浴室地板鋪滿了白色磁磚。"},{"en":"The workers laid new ceramic tiles on the kitchen floor.","zh":"工人們在廚房地板上鋪了新的陶瓷磁磚。"},{"en":"A broken roof tile let the rain leak into the attic.","zh":"一片破損的屋瓦讓雨水滲進了閣樓。"}]},{"word":"till","pos":"prep. / conj.","phonetic":"[tɪl]","meaning":"直到","definition":"up to a particular time","collocations":["till now","wait till"],"example":"We waited till midnight for the fireworks.","exampleZh":"我們一直等到午夜才看到煙火。","synonyms":["until"],"level":2,"theme":"時間與空間","examples":[{"en":"We waited till midnight for the fireworks.","zh":"我們一直等到午夜才看到煙火。"},{"en":"The library stays open till nine on weekday evenings.","zh":"圖書館在平日晚上開放到九點。"},{"en":"Please wait till the light turns green before crossing.","zh":"請等到燈變綠再過馬路。"}]},{"word":"timber","pos":"n.","phonetic":"[ˈtɪmbɚ]","meaning":"木材","definition":"wood that has been prepared for use in building","collocations":["timber industry","cut timber"],"example":"The house was built with local timber.","exampleZh":"這棟房子是用當地木材建造的。","synonyms":["wood","lumber"],"level":5,"theme":"自然與環境","examples":[{"en":"The house was built with local timber.","zh":"這棟房子是用當地木材建造的。"},{"en":"The old cabin was made entirely of local timber.","zh":"這間老木屋完全是用當地的木材建造的。"},{"en":"Workers loaded the timber onto the truck for the mill.","zh":"工人們把木材裝上卡車運往鋸木廠。"}]},{"word":"time","pos":"n.","phonetic":"[taɪm]","meaning":"時間","definition":"the ongoing and continuous progress of events","collocations":["on time","spend time","in time"],"example":"We arrived just in time for the meeting.","exampleZh":"我們正好準時趕上會議。","synonyms":[],"level":1,"theme":"時間與空間","examples":[{"en":"We arrived just in time for the meeting.","zh":"我們正好準時趕上會議。"},{"en":"We don't have enough time to finish the whole book today.","zh":"我們今天沒有足夠的時間讀完整本書。"},{"en":"She always finishes her homework on time.","zh":"她總是準時完成她的作業。"}]},{"word":"timid","pos":"adj.","phonetic":"[ˈtɪmɪd]","meaning":"膽小的","definition":"lacking courage or confidence; easily frightened","collocations":["timid person","timid smile"],"example":"The timid child hid behind her mother.","exampleZh":"那個膽小的孩子躲在媽媽身後。","synonyms":["shy","fearful"],"level":4,"theme":"情緒與感受","examples":[{"en":"The timid child hid behind her mother.","zh":"那個膽小的孩子躲在媽媽身後。"},{"en":"The timid new student was afraid to raise his hand.","zh":"那位膽小的新同學不敢舉手發言。"},{"en":"She gave a timid smile when the teacher praised her.","zh":"當老師稱讚她時，她露出了羞怯的微笑。"}]},{"word":"tin","pos":"n.","phonetic":"[tɪn]","meaning":"錫；罐頭","definition":"a soft silvery metal, or a metal container for food","collocations":["tin can","tin foil"],"example":"She opened a tin of soup for lunch.","exampleZh":"她打開一罐湯當午餐。","synonyms":["can"],"level":3,"theme":"食物與烹飪","examples":[{"en":"She opened a tin of soup for lunch.","zh":"她打開一罐湯當午餐。"},{"en":"He opened a tin of cookies and shared them with us.","zh":"他打開一罐餅乾，和我們分著吃。"},{"en":"Mom wrapped the leftover fish in tin foil.","zh":"媽媽用錫箔紙把剩下的魚包了起來。"}]},{"word":"tiny","pos":"adj.","phonetic":"[ˈtaɪnɪ]","meaning":"微小的","definition":"extremely small in size","collocations":["tiny amount","tiny house","tiny bit"],"example":"The kitten is tiny and adorable.","exampleZh":"這隻小貓非常小又可愛。","synonyms":["small","little"],"level":1,"theme":"性質與描述","examples":[{"en":"The kitten is tiny and adorable.","zh":"這隻小貓非常小又可愛。"},{"en":"A tiny ant carried a crumb across the kitchen floor.","zh":"一隻小小的螞蟻扛著一塊麵包屑爬過廚房地板。"},{"en":"They live in a tiny house near the busy market.","zh":"他們住在熱鬧市場附近的一間小屋裡。"}]},{"word":"tip","pos":"n. / v.","phonetic":"[tɪp]","meaning":"尖端；小費；建議","definition":"the pointed end of something; money given for service; a piece of advice","collocations":["give a tip","tip of the iceberg","useful tips"],"example":"He gave the waiter a generous tip.","exampleZh":"他給了服務生一筆豐厚的小費。","synonyms":["gratuity","advice"],"level":2,"theme":"商業與金錢","examples":[{"en":"He gave the waiter a generous tip.","zh":"他給了服務生一筆豐厚的小費。"},{"en":"The teacher shared a useful tip for memorizing new words.","zh":"老師分享了一個記憶新單字的實用訣竅。"},{"en":"He balanced the pen on the tip of his finger.","zh":"他把筆平衡在他的指尖上。"}]},{"word":"tire","pos":"v. / n.","phonetic":"[taɪr]","meaning":"使疲倦；輪胎","definition":"to make someone weary, or a rubber ring fitted around a wheel","collocations":["tire easily","flat tire","tire out"],"example":"The long hike tired us out.","exampleZh":"這場長途健行讓我們累壞了。","synonyms":["exhaust"],"level":2,"theme":"身體與健康","examples":[{"en":"The long hike tired us out.","zh":"這場長途健行讓我們累壞了。"},{"en":"Climbing the steep hill began to tire the young hikers.","zh":"爬那座陡峭的山丘開始讓年輕的登山客感到疲累。"},{"en":"Dad changed the flat tire on the side of the road.","zh":"爸爸在路邊換了那個沒氣的輪胎。"}]},{"word":"tired","pos":"adj.","phonetic":"[taɪrd]","meaning":"疲倦的","definition":"feeling in need of rest or sleep","collocations":["feel tired","tired of","get tired"],"example":"I feel very tired after work.","exampleZh":"下班後我感覺非常疲倦。","synonyms":["exhausted","sleepy"],"level":1,"theme":"身體與健康","examples":[{"en":"I feel very tired after work.","zh":"下班後我感覺非常疲倦。"},{"en":"After the long trip, the children were too tired to eat.","zh":"經過漫長的旅程，孩子們累得吃不下飯。"},{"en":"I am tired of hearing the same excuse every day.","zh":"我對每天聽到同樣的藉口感到厭煩。"}]},{"word":"tissue","pos":"n.","phonetic":"[ˈtɪʃu]","meaning":"面紙；組織(生物)","definition":"soft paper used for wiping, or a group of similar cells in a body","collocations":["tissue paper","blow one's nose with a tissue"],"example":"She wiped her tears with a tissue.","exampleZh":"她用面紙擦掉眼淚。","synonyms":[],"level":3,"theme":"身體與健康","examples":[{"en":"She wiped her tears with a tissue.","zh":"她用面紙擦掉眼淚。"},{"en":"She handed him a tissue when he started to sneeze.","zh":"當他開始打噴嚏時，她遞給他一張面紙。"},{"en":"The nurse studied the plant tissue under the microscope.","zh":"護士在顯微鏡下研究那植物的組織。"}]},{"word":"title","pos":"n.","phonetic":"[ˈtaɪtḷ]","meaning":"標題；頭銜","definition":"the name of a book, film, or a word showing a person's rank","collocations":["book title","win the title","job title"],"example":"What is the title of this novel?","exampleZh":"這本小說的書名是什麼？","synonyms":["name","heading"],"level":2,"theme":"藝術與音樂","examples":[{"en":"What is the title of this novel?","zh":"這本小說的書名是什麼？"},{"en":"I cannot remember the title of that famous song.","zh":"我想不起那首著名歌曲的名稱。"},{"en":"Our team hopes to win the title in this year's contest.","zh":"我們隊伍希望在今年的比賽中奪得冠軍頭銜。"}]},{"word":"toast","pos":"n. / v.","phonetic":"[tost]","meaning":"吐司；敬酒","definition":"sliced bread browned by heat, or to raise a glass in someone's honor","collocations":["butter the toast","propose a toast"],"example":"I had toast and eggs for breakfast.","exampleZh":"我早餐吃了吐司和蛋。","synonyms":[],"level":2,"theme":"食物與烹飪","examples":[{"en":"I had toast and eggs for breakfast.","zh":"我早餐吃了吐司和蛋。"},{"en":"She spread butter on the warm toast for breakfast.","zh":"她在溫熱的吐司上塗奶油當早餐。"},{"en":"The guests raised their glasses to propose a toast.","zh":"賓客們舉起酒杯敬酒。"}]},{"word":"tobacco","pos":"n.","phonetic":"[təˈbæko]","meaning":"菸草","definition":"a plant whose dried leaves are used to make cigarettes","collocations":["tobacco leaf","tobacco industry"],"example":"Tobacco use can cause serious health problems.","exampleZh":"使用菸草可能導致嚴重的健康問題。","synonyms":[],"level":4,"theme":"身體與健康","examples":[{"en":"Tobacco use can cause serious health problems.","zh":"使用菸草可能導致嚴重的健康問題。"},{"en":"Doctors warn that tobacco can harm the lungs.","zh":"醫生警告菸草會傷害肺部。"},{"en":"The store is not allowed to sell tobacco to teenagers.","zh":"這家商店不得將菸草賣給青少年。"}]},{"word":"today","pos":"adv. / n.","phonetic":"[təˈde]","meaning":"今天","definition":"on or during this present day","collocations":["today's news","until today"],"example":"What day is it today?","exampleZh":"今天是星期幾？","synonyms":[],"level":1,"theme":"時間與空間","examples":[{"en":"What day is it today?","zh":"今天是星期幾？"},{"en":"We have a special science class scheduled for today.","zh":"我們今天安排了一堂特別的自然課。"},{"en":"Today's weather is perfect for a walk in the park.","zh":"今天的天氣非常適合去公園散步。"}]},{"word":"toe","pos":"n.","phonetic":"[to]","meaning":"腳趾","definition":"one of the five digits at the end of the foot","collocations":["stub one's toe","big toe"],"example":"She stubbed her toe on the table leg.","exampleZh":"她的腳趾撞到了桌腳。","synonyms":[],"level":1,"theme":"身體與健康","examples":[{"en":"She stubbed her toe on the table leg.","zh":"她的腳趾撞到了桌腳。"},{"en":"She wiggled her toes in the warm sand at the beach.","zh":"她在海灘溫暖的沙子裡扭動著腳趾。"},{"en":"He hurt his big toe while playing soccer.","zh":"他踢足球時弄傷了大腳趾。"}]},{"word":"together","pos":"adv.","phonetic":"[təˈgɛðɚ]","meaning":"一起","definition":"with or near each other; jointly","collocations":["work together","get together","live together"],"example":"We studied together for the exam.","exampleZh":"我們一起讀書準備考試。","synonyms":["jointly"],"level":1,"theme":"人物與家庭","examples":[{"en":"We studied together for the exam.","zh":"我們一起讀書準備考試。"},{"en":"The whole family cooked dinner together on the weekend.","zh":"週末時全家人一起煮晚餐。"},{"en":"If we work together, we can finish the poster faster.","zh":"如果我們合作，就能更快完成海報。"}]},{"word":"toilet","pos":"n.","phonetic":"[ˈtɔɪlɪt]","meaning":"廁所；馬桶","definition":"a bathroom fixture used for urination and defecation","collocations":["use the toilet","flush the toilet","public toilet"],"example":"Where is the nearest public toilet?","exampleZh":"最近的公共廁所在哪裡？","synonyms":["restroom"],"level":1,"theme":"居家與生活","examples":[{"en":"Where is the nearest public toilet?","zh":"最近的公共廁所在哪裡？"},{"en":"Please remember to flush the toilet after using it.","zh":"用完廁所後請記得沖水。"},{"en":"There is a clean public toilet near the park entrance.","zh":"公園入口附近有一間乾淨的公共廁所。"}]},{"word":"tolerance","pos":"n.","phonetic":"[ˈtɑlərəns]","meaning":"容忍；耐受度","definition":"the ability or willingness to tolerate something","collocations":["religious tolerance","zero tolerance","build tolerance"],"example":"The society values tolerance and diversity.","exampleZh":"這個社會重視容忍與多元。","synonyms":["patience"],"level":4,"theme":"抽象概念","examples":[{"en":"The society values tolerance and diversity.","zh":"這個社會重視容忍與多元。"},{"en":"Our school teaches respect and tolerance for all cultures.","zh":"我們學校教導對所有文化的尊重與包容。"},{"en":"The team has zero tolerance for cheating during games.","zh":"這支隊伍對比賽中作弊採取零容忍。"}]},{"word":"tolerant","pos":"adj.","phonetic":"[ˈtɑlərənt]","meaning":"寬容的；容忍的","definition":"showing willingness to allow the existence of opinions or behavior one disagrees with","collocations":["tolerant of","tolerant attitude","become tolerant"],"example":"Good teachers are tolerant of students' mistakes.","exampleZh":"好老師會包容學生的錯誤。","synonyms":["open-minded"],"level":4,"theme":"性質與描述","examples":[{"en":"Good teachers are tolerant of students' mistakes.","zh":"好老師會包容學生的錯誤。"},{"en":"A tolerant leader listens to different opinions calmly.","zh":"一位寬容的領導者會冷靜地傾聽不同的意見。"},{"en":"She is very tolerant of her little brother's noise.","zh":"她對弟弟製造的吵鬧聲非常包容。"}]},{"word":"tolerate","pos":"v.","phonetic":"[ˈtɑləˏret]","meaning":"容忍","definition":"to accept or endure something unpleasant without complaint","collocations":["tolerate noise","cannot tolerate","tolerate differences"],"example":"I cannot tolerate such rude behavior.","exampleZh":"我無法容忍這種無禮的行為。","synonyms":["endure","bear"],"level":5,"theme":"抽象概念","examples":[{"en":"I cannot tolerate such rude behavior.","zh":"我無法容忍這種無禮的行為。"},{"en":"I cannot tolerate people who litter in the park.","zh":"我無法容忍在公園亂丟垃圾的人。"},{"en":"These plants can tolerate very dry weather.","zh":"這些植物能夠耐受非常乾燥的天氣。"}]},{"word":"tomato","pos":"n.","phonetic":"[təˈmeto]","meaning":"番茄","definition":"a soft red fruit eaten as a vegetable","collocations":["tomato sauce","ripe tomato","tomato soup"],"example":"She added fresh tomatoes to the salad.","exampleZh":"她在沙拉裡加了新鮮番茄。","synonyms":[],"level":1,"theme":"食物與烹飪","examples":[{"en":"She added fresh tomatoes to the salad.","zh":"她在沙拉裡加了新鮮番茄。"},{"en":"He picked a ripe tomato from the garden for the salad.","zh":"他從菜園裡摘了一顆熟番茄做沙拉。"},{"en":"My favorite pizza is covered with tomato sauce and cheese.","zh":"我最愛的披薩上鋪滿了番茄醬和起司。"}]},{"word":"tomb","pos":"n.","phonetic":"[tum]","meaning":"墳墓","definition":"a place, usually underground, where a dead body is buried","collocations":["ancient tomb","visit a tomb"],"example":"Archaeologists discovered an ancient tomb in the desert.","exampleZh":"考古學家在沙漠中發現了一座古墓。","synonyms":["grave"],"level":4,"theme":"社會與文化","examples":[{"en":"Archaeologists discovered an ancient tomb in the desert.","zh":"考古學家在沙漠中發現了一座古墓。"},{"en":"The ancient tomb was decorated with beautiful stone carvings.","zh":"這座古墓上裝飾著美麗的石雕。"},{"en":"Visitors spoke quietly as they walked past the tomb.","zh":"參觀者走過墳墓時輕聲細語。"}]},{"word":"tomorrow","pos":"n. / adv.","phonetic":"[təˈmɑro]","meaning":"明天；未來","definition":"the day after today","collocations":["tomorrow morning","see you tomorrow","tomorrow's weather"],"example":"We will meet again tomorrow.","exampleZh":"我們明天再見面。","synonyms":[],"level":1,"theme":"時間與空間","examples":[{"en":"We will meet again tomorrow.","zh":"我們明天再見面。"},{"en":"We should leave early tomorrow morning to catch the bus.","zh":"我們明天早上應該早點出發去趕公車。"},{"en":"Let's check tomorrow's weather before planning the picnic.","zh":"在計劃野餐前，我們先看看明天的天氣吧。"}]},{"word":"ton","pos":"n.","phonetic":"[tʌn]","meaning":"噸；大量","definition":"a unit of weight equal to 2,000 pounds","collocations":["a ton of","weigh a ton","tons of money"],"example":"The truck can carry two tons of goods.","exampleZh":"這輛卡車可以載運兩噸貨物。","synonyms":[],"level":3,"theme":"科學與數學","examples":[{"en":"The truck can carry two tons of goods.","zh":"這輛卡車可以載運兩噸貨物。"},{"en":"The elephant looks as if it weighs a ton.","zh":"那頭大象看起來好像有一噸重。"},{"en":"She has tons of homework to finish this weekend.","zh":"她這個週末有一大堆作業要完成。"}]},{"word":"tone","pos":"n.","phonetic":"[ton]","meaning":"語氣；音調","definition":"the quality of a sound or the way a person speaks, showing feeling","collocations":["tone of voice","polite tone","change one's tone"],"example":"She spoke in a calm tone.","exampleZh":"她用平靜的語氣說話。","synonyms":[],"level":4,"theme":"溝通與語言","examples":[{"en":"She spoke in a calm tone.","zh":"她用平靜的語氣說話。"},{"en":"His gentle tone of voice made the child feel safe.","zh":"他溫柔的語氣讓孩子感到安心。"},{"en":"She changed her tone when the teacher walked in.","zh":"當老師走進來時，她改變了語氣。"}]},{"word":"tongue","pos":"n.","phonetic":"[tʌŋ]","meaning":"舌頭；語言","definition":"the organ in the mouth used for tasting and speaking","collocations":["mother tongue","bite one's tongue","stick out one's tongue"],"example":"English is not her mother tongue.","exampleZh":"英語不是她的母語。","synonyms":["language"],"level":2,"theme":"身體與健康","examples":[{"en":"English is not her mother tongue.","zh":"英語不是她的母語。"},{"en":"He burned his tongue on the hot bowl of soup.","zh":"他被那碗熱湯燙到了舌頭。"},{"en":"Chinese is her mother tongue, but she also speaks English.","zh":"中文是她的母語，但她也會說英文。"}]},{"word":"tonight","pos":"adv. / n.","phonetic":"[təˈnaɪt]","meaning":"今晚","definition":"on the night of the present day","collocations":["tonight's dinner","see you tonight"],"example":"We are going to a movie tonight.","exampleZh":"我們今晚要去看電影。","synonyms":[],"level":1,"theme":"時間與空間","examples":[{"en":"We are going to a movie tonight.","zh":"我們今晚要去看電影。"},{"en":"We plan to watch the meteor shower tonight.","zh":"我們打算今晚觀賞流星雨。"},{"en":"Tonight's dinner will be my grandmother's famous noodles.","zh":"今晚的晚餐將是我奶奶著名的麵。"}]},{"word":"too","pos":"adv.","phonetic":"[tu]","meaning":"也；太","definition":"in addition; to an excessive extent","collocations":["me too","too much","too many"],"example":"I would like to come too.","exampleZh":"我也想一起去。","synonyms":["also"],"level":1,"theme":"抽象概念","examples":[{"en":"I would like to come too.","zh":"我也想一起去。"},{"en":"This coffee is too hot for me to drink right now.","zh":"這杯咖啡太燙了，我現在沒辦法喝。"},{"en":"My sister wants to join the trip, and I do too.","zh":"我姊姊想參加這趟旅行，我也想。"}]},{"word":"tool","pos":"n.","phonetic":"[tul]","meaning":"工具","definition":"a device used to carry out a particular task","collocations":["use a tool","tool box","power tool"],"example":"A hammer is a useful tool for this job.","exampleZh":"鎚子是做這項工作的實用工具。","synonyms":["instrument"],"level":1,"theme":"科技與媒體","examples":[{"en":"A hammer is a useful tool for this job.","zh":"鎚子是做這項工作的實用工具。"},{"en":"A dictionary is a helpful tool for learning new words.","zh":"字典是學習新單字的實用工具。"},{"en":"He keeps every tool neatly inside a wooden tool box.","zh":"他把每樣工具整齊地收在一個木製工具箱裡。"}]},{"word":"tooth","pos":"n.","phonetic":"[tuθ]","meaning":"牙齒","definition":"one of the hard white structures in the mouth used for biting","collocations":["brush one's teeth","tooth decay","lose a tooth"],"example":"He brushes his teeth twice a day.","exampleZh":"他每天刷兩次牙。","synonyms":[],"level":1,"theme":"身體與健康","examples":[{"en":"He brushes his teeth twice a day.","zh":"他每天刷兩次牙。"},{"en":"The dentist warned him about tooth decay from too much candy.","zh":"牙醫警告他吃太多糖果會造成蛀牙。"},{"en":"My little sister lost her first baby tooth today.","zh":"我妹妹今天掉了她的第一顆乳牙。"}]},{"word":"top","pos":"n. / adj.","phonetic":"[tɑp]","meaning":"頂端；最高的","definition":"the highest point or part of something","collocations":["on top of","top student","reach the top"],"example":"We finally reached the top of the mountain.","exampleZh":"我們終於到達山頂。","synonyms":["peak","summit"],"level":1,"theme":"時間與空間","examples":[{"en":"We finally reached the top of the mountain.","zh":"我們終於到達山頂。"},{"en":"She placed the trophy on top of the bookshelf.","zh":"她把獎盃放在書架的頂端。"},{"en":"He worked hard to become the top student in class.","zh":"他努力用功，成為班上頂尖的學生。"}]},{"word":"topic","pos":"n.","phonetic":"[ˈtɑpɪk]","meaning":"主題；話題","definition":"a subject discussed in a conversation, essay, or lecture","collocations":["discuss a topic","hot topic","choose a topic"],"example":"The topic of today's lecture is climate change.","exampleZh":"今天演講的主題是氣候變遷。","synonyms":["subject"],"level":3,"theme":"教育與學習","examples":[{"en":"The topic of today's lecture is climate change.","zh":"今天演講的主題是氣候變遷。"},{"en":"Each group chose a different topic for the presentation.","zh":"每一組都為報告選擇了不同的主題。"},{"en":"Climate change is a hot topic among young people today.","zh":"氣候變遷是當今年輕人之間熱門的話題。"}]},{"word":"torch","pos":"n.","phonetic":"[tɔrtʃ]","meaning":"火把；手電筒","definition":"a portable light source, or a stick with burning material at one end","collocations":["light a torch","Olympic torch","hand torch"],"example":"The runner carried the Olympic torch through the city.","exampleZh":"跑者帶著奧運聖火穿越城市。","synonyms":["flashlight"],"level":4,"theme":"科技與媒體","examples":[{"en":"The runner carried the Olympic torch through the city.","zh":"跑者帶著奧運聖火穿越城市。"},{"en":"He used a torch to find his way through the dark cave.","zh":"他用手電筒在黑暗的洞穴中找路。"},{"en":"The athletes cheered as the Olympic torch passed by.","zh":"當奧運火炬經過時，運動員們歡呼喝采。"}]},{"word":"tornado","pos":"n.","phonetic":"[tɔrˈnedo]","meaning":"龍捲風","definition":"a violently rotating column of air in contact with the ground","collocations":["tornado warning","a tornado hit","tornado alley"],"example":"A tornado destroyed several houses in the town.","exampleZh":"一場龍捲風摧毀了鎮上好幾間房子。","synonyms":["twister"],"level":4,"theme":"天氣與季節","examples":[{"en":"A tornado destroyed several houses in the town.","zh":"一場龍捲風摧毀了鎮上好幾間房子。"},{"en":"The weather service issued a tornado warning for our county this afternoon.","zh":"氣象單位今天下午對我們的郡發布了龍捲風警報。"},{"en":"Many farms in tornado alley are damaged by storms every spring.","zh":"龍捲風走廊上的許多農場每年春天都被暴風雨破壞。"}]},{"word":"tortoise","pos":"n.","phonetic":"[ˈtɔrtəs]","meaning":"陸龜","definition":"a slow-moving land reptile with a hard shell","collocations":["slow as a tortoise","pet tortoise"],"example":"The tortoise moved slowly across the yard.","exampleZh":"那隻陸龜緩慢地爬過院子。","synonyms":["turtle"],"level":3,"theme":"動物與植物","examples":[{"en":"The tortoise moved slowly across the yard.","zh":"那隻陸龜緩慢地爬過院子。"},{"en":"My grandfather keeps a pet tortoise that is over fifty years old.","zh":"我爺爺養了一隻超過五十歲的寵物陸龜。"},{"en":"He finished the marathon slow as a tortoise but never gave up.","zh":"他跑馬拉松慢得像陸龜一樣，但從未放棄。"}]},{"word":"torture","pos":"n. / v.","phonetic":"[ˈtɔrtʃɚ]","meaning":"折磨；拷打","definition":"to cause someone severe physical or mental pain","collocations":["torture a prisoner","mental torture"],"example":"The prisoners were tortured for information.","exampleZh":"囚犯們被拷打以取得情報。","synonyms":["torment"],"level":5,"theme":"政治與法律","examples":[{"en":"The prisoners were tortured for information.","zh":"囚犯們被拷打以取得情報。"},{"en":"Waiting for the exam results was a kind of mental torture for her.","zh":"等待考試成績對她來說是一種精神上的折磨。"},{"en":"International law forbids soldiers from torturing prisoners during a war.","zh":"國際法禁止士兵在戰爭期間拷打囚犯。"}]},{"word":"toss","pos":"v. / n.","phonetic":"[tɔs]","meaning":"投擲；輕拋","definition":"to throw something lightly or carelessly","collocations":["toss a coin","toss and turn","toss a salad"],"example":"He tossed the ball to his friend.","exampleZh":"他把球拋給他的朋友。","synonyms":["throw"],"level":3,"theme":"動作與行為","examples":[{"en":"He tossed the ball to his friend.","zh":"他把球拋給他的朋友。"},{"en":"Let's toss a coin to decide who goes first in the game.","zh":"我們擲硬幣來決定遊戲中誰先開始吧。"},{"en":"She tossed the salad with olive oil and a little lemon juice.","zh":"她用橄欖油和一點檸檬汁拌了沙拉。"}]},{"word":"total","pos":"adj. / n.","phonetic":"[ˈtotḷ]","meaning":"總共的；總數","definition":"complete, or the whole amount of something","collocations":["total amount","in total","total cost"],"example":"The total cost of the trip was quite high.","exampleZh":"這趟旅行的總花費相當高。","synonyms":["whole","entire"],"level":2,"theme":"商業與金錢","examples":[{"en":"The total cost of the trip was quite high.","zh":"這趟旅行的總花費相當高。"},{"en":"There were three hundred guests at the wedding in total.","zh":"婚禮上總共有三百位賓客。"},{"en":"Please add up the total amount before you print the receipt.","zh":"請在列印收據前把總金額加起來。"}]},{"word":"touch","pos":"v. / n.","phonetic":"[tʌtʃ]","meaning":"觸摸；接觸","definition":"to put one's hand or fingers on something","collocations":["touch screen","keep in touch","touch base"],"example":"Please don't touch the wet paint.","exampleZh":"請不要碰觸未乾的油漆。","synonyms":["feel"],"level":1,"theme":"動作與行為","examples":[{"en":"Please don't touch the wet paint.","zh":"請不要碰觸未乾的油漆。"},{"en":"Remember to keep in touch with your friends after you move abroad.","zh":"記得在你搬到國外後和朋友們保持聯絡。"},{"en":"This new phone has a large touch screen that responds very quickly.","zh":"這支新手機有一個反應非常快的大觸控螢幕。"}]},{"word":"tough","pos":"adj.","phonetic":"[tʌf]","meaning":"堅韌的；困難的","definition":"strong and difficult to break, or difficult to deal with","collocations":["tough decision","tough meat","tough time"],"example":"It was a tough decision to make.","exampleZh":"這是一個困難的決定。","synonyms":["hard","difficult"],"level":3,"theme":"性質與描述","examples":[{"en":"It was a tough decision to make.","zh":"這是一個困難的決定。"},{"en":"The steak was so tough that I could hardly chew it.","zh":"這塊牛排太韌了，我幾乎咬不動。"},{"en":"She went through a tough time after losing her part-time job.","zh":"她在失去兼職工作後經歷了一段艱難的時期。"}]},{"word":"tour","pos":"n. / v.","phonetic":"[tʊr]","meaning":"旅行；巡迴","definition":"a journey for pleasure in which several places are visited","collocations":["guided tour","world tour","tour guide"],"example":"We took a guided tour of the museum.","exampleZh":"我們參加了博物館的導覽行程。","synonyms":["trip"],"level":2,"theme":"交通與旅行","examples":[{"en":"We took a guided tour of the museum.","zh":"我們參加了博物館的導覽行程。"},{"en":"The famous band began a world tour to promote their new album.","zh":"那支著名樂團展開世界巡迴演出來宣傳他們的新專輯。"},{"en":"Our tour guide explained the history of every temple we visited.","zh":"我們的導遊解說了我們參觀的每一座寺廟的歷史。"}]},{"word":"tourist","pos":"n.","phonetic":"[ˈtʊrɪst]","meaning":"觀光客；遊客","definition":"a person who travels for pleasure","collocations":["tourist attraction","foreign tourist","tourist season"],"example":"The city is full of tourists in summer.","exampleZh":"夏天這座城市擠滿了觀光客。","synonyms":["traveler","visitor"],"level":2,"theme":"交通與旅行","examples":[{"en":"The city is full of tourists in summer.","zh":"夏天這座城市擠滿了觀光客。"},{"en":"The night market is a popular tourist attraction in this city.","zh":"這個夜市是這座城市裡受歡迎的觀光景點。"},{"en":"During the tourist season, hotel prices near the beach rise sharply.","zh":"在觀光旺季，海灘附近的旅館價格會大幅上漲。"}]},{"word":"toward","pos":"prep.","phonetic":"[tɔrd]","meaning":"朝向；對於","definition":"in the direction of","collocations":["move toward","attitude toward","walk toward"],"example":"She walked toward the exit.","exampleZh":"她朝出口走去。","synonyms":["towards"],"level":2,"theme":"時間與空間","examples":[{"en":"She walked toward the exit.","zh":"她朝出口走去。"},{"en":"His attitude toward homework changed after he failed the midterm.","zh":"他對作業的態度在期中考不及格後有了改變。"},{"en":"The crowd slowly moved toward the stage as the concert began.","zh":"隨著演唱會開始，人群慢慢地朝舞台移動。"}]},{"word":"towel","pos":"n.","phonetic":"[ˈtaʊəl]","meaning":"毛巾","definition":"a piece of thick absorbent cloth used for drying oneself","collocations":["bath towel","paper towel","throw in the towel"],"example":"He dried his hair with a towel.","exampleZh":"他用毛巾擦乾頭髮。","synonyms":[],"level":1,"theme":"居家與生活","examples":[{"en":"He dried his hair with a towel.","zh":"他用毛巾擦乾頭髮。"},{"en":"She wrapped herself in a warm bath towel after the shower.","zh":"淋浴後她用一條溫暖的浴巾把自己裹起來。"},{"en":"Don't throw in the towel just because the first attempt failed.","zh":"別只因為第一次嘗試失敗就認輸放棄。"}]},{"word":"tower","pos":"n.","phonetic":"[ˈtaʊɚ]","meaning":"塔；高樓","definition":"a tall, narrow building or structure","collocations":["clock tower","control tower","tower block"],"example":"The clock tower stands in the city center.","exampleZh":"這座鐘塔矗立在市中心。","synonyms":[],"level":2,"theme":"居家與生活","examples":[{"en":"The clock tower stands in the city center.","zh":"這座鐘塔矗立在市中心。"},{"en":"From the top of the tower, we could see the whole city.","zh":"從塔頂，我們可以看見整座城市。"},{"en":"The pilot waited for instructions from the airport control tower.","zh":"飛行員等待機場塔台的指示。"}]},{"word":"town","pos":"n.","phonetic":"[taʊn]","meaning":"城鎮","definition":"a populated area smaller than a city","collocations":["small town","town hall","go into town"],"example":"They live in a small town near the coast.","exampleZh":"他們住在海邊的一個小鎮。","synonyms":[],"level":1,"theme":"居家與生活","examples":[{"en":"They live in a small town near the coast.","zh":"他們住在海邊的一個小鎮。"},{"en":"We drove into town to buy groceries for the weekend.","zh":"我們開車進城為週末買雜貨。"},{"en":"The mayor gave a speech at the town hall last night.","zh":"市長昨晚在市政廳發表了演說。"}]},{"word":"toxic","pos":"adj.","phonetic":"[ˈtɑksɪk]","meaning":"有毒的","definition":"poisonous; harmful to living organisms","collocations":["toxic waste","toxic chemical","toxic relationship"],"example":"The factory released toxic gas into the air.","exampleZh":"這間工廠排放有毒氣體到空氣中。","synonyms":["poisonous"],"level":5,"theme":"科學與數學","examples":[{"en":"The factory released toxic gas into the air.","zh":"這間工廠排放有毒氣體到空氣中。"},{"en":"The river was polluted by toxic waste from a nearby factory.","zh":"這條河被附近工廠排出的有毒廢棄物污染了。"},{"en":"She finally left the toxic relationship that made her miserable.","zh":"她終於離開了那段讓她痛苦不堪的有毒關係。"}]},{"word":"toy","pos":"n.","phonetic":"[tɔɪ]","meaning":"玩具","definition":"an object for a child to play with","collocations":["toy store","toy car","play with toys"],"example":"The children were playing with their toys.","exampleZh":"孩子們正在玩他們的玩具。","synonyms":[],"level":1,"theme":"居家與生活","examples":[{"en":"The children were playing with their toys.","zh":"孩子們正在玩他們的玩具。"},{"en":"The little boy pushed his new toy car across the floor.","zh":"那個小男孩把他的新玩具車推過地板。"},{"en":"They spent an hour choosing gifts at the toy store.","zh":"他們花了一小時在玩具店挑選禮物。"}]},{"word":"trace","pos":"v. / n.","phonetic":"[tres]","meaning":"追蹤；痕跡","definition":"to find or discover by investigation; a mark left by something","collocations":["trace back","without a trace","trace an email"],"example":"Police traced the call to an apartment downtown.","exampleZh":"警方追蹤這通電話到市區的一間公寓。","synonyms":["track"],"level":4,"theme":"科學與數學","examples":[{"en":"Police traced the call to an apartment downtown.","zh":"警方追蹤這通電話到市區的一間公寓。"},{"en":"The thief disappeared without a trace after the robbery.","zh":"那名小偷在搶劫後消失得無影無蹤。"},{"en":"Scientists traced the disease back to a single contaminated well.","zh":"科學家把這場疾病追溯到一口受污染的水井。"}]},{"word":"track","pos":"n. / v.","phonetic":"[træk]","meaning":"軌道；追蹤","definition":"a rough path or road; to follow the course of something","collocations":["track record","keep track of","railroad track"],"example":"We need to keep track of our expenses.","exampleZh":"我們需要追蹤我們的開銷。","synonyms":["path","trail"],"level":2,"theme":"交通與旅行","examples":[{"en":"We need to keep track of our expenses.","zh":"我們需要追蹤我們的開銷。"},{"en":"The company has an excellent track record of protecting its customers.","zh":"這家公司在保護顧客方面有著優異的紀錄。"},{"en":"Please do not walk across the railroad track when the light flashes.","zh":"燈號閃爍時請勿穿越鐵軌。"}]},{"word":"trade","pos":"n. / v.","phonetic":"[tred]","meaning":"貿易；交易","definition":"the action of buying and selling goods and services","collocations":["free trade","trade agreement","trade with"],"example":"The two countries signed a new trade agreement.","exampleZh":"這兩國簽署了一項新的貿易協定。","synonyms":["commerce"],"level":3,"theme":"商業與金錢","examples":[{"en":"The two countries signed a new trade agreement.","zh":"這兩國簽署了一項新的貿易協定。"},{"en":"Many small nations depend heavily on free trade with their neighbors.","zh":"許多小國嚴重依賴與鄰國的自由貿易。"},{"en":"The boy traded his lunch for his friend's chocolate bar.","zh":"那男孩用他的午餐換了朋友的巧克力棒。"}]},{"word":"tradition","pos":"n.","phonetic":"[trəˈdɪʃən]","meaning":"傳統","definition":"a custom or belief passed down through generations","collocations":["family tradition","break tradition","follow tradition"],"example":"It is a family tradition to gather for dinner every Sunday.","exampleZh":"每週日聚餐是我們家的傳統。","synonyms":["custom"],"level":3,"theme":"社會與文化","examples":[{"en":"It is a family tradition to gather for dinner every Sunday.","zh":"每週日聚餐是我們家的傳統。"},{"en":"Lighting lanterns during the festival is a long-standing tradition here.","zh":"在節慶期間點燈籠是這裡由來已久的傳統。"},{"en":"They decided to break tradition and hold the ceremony outdoors.","zh":"他們決定打破傳統，在戶外舉行典禮。"}]},{"word":"traditional","pos":"adj.","phonetic":"[trəˈdɪʃənl̩]","meaning":"傳統的","definition":"existing in or as part of a tradition; long-established","collocations":["traditional culture","traditional clothing","traditional festival"],"example":"They celebrated the festival in traditional costumes.","exampleZh":"他們穿著傳統服飾慶祝節日。","synonyms":["conventional"],"level":3,"theme":"社會與文化","examples":[{"en":"They celebrated the festival in traditional costumes.","zh":"他們穿著傳統服飾慶祝節日。"},{"en":"The museum displays traditional clothing worn by farmers a century ago.","zh":"這座博物館展示了一世紀前農民穿的傳統服飾。"},{"en":"Many young people are losing interest in traditional culture.","zh":"許多年輕人對傳統文化正逐漸失去興趣。"}]},{"word":"traffic","pos":"n.","phonetic":"[ˈtræfɪk]","meaning":"交通；交通量","definition":"the movement of vehicles or people on roads","collocations":["traffic jam","heavy traffic","traffic light"],"example":"We were stuck in traffic for two hours.","exampleZh":"我們塞在車陣中兩個小時。","synonyms":[],"level":2,"theme":"交通與旅行","examples":[{"en":"We were stuck in traffic for two hours.","zh":"我們塞在車陣中兩個小時。"},{"en":"We were late because of a serious traffic jam on the highway.","zh":"我們遲到是因為高速公路上嚴重的交通堵塞。"},{"en":"Always stop when the traffic light turns red.","zh":"交通號誌變紅燈時一定要停下來。"}]},{"word":"tragedy","pos":"n.","phonetic":"[ˈtrædʒədi]","meaning":"悲劇","definition":"an event causing great suffering or destruction; a serious play with an unhappy ending","collocations":["a tragedy occurred","personal tragedy","Greek tragedy"],"example":"The earthquake was a terrible tragedy for the whole nation.","exampleZh":"這場地震對全國來說是一場可怕的悲劇。","synonyms":["disaster"],"level":5,"theme":"藝術與音樂","examples":[{"en":"The earthquake was a terrible tragedy for the whole nation.","zh":"這場地震對全國來說是一場可怕的悲劇。"},{"en":"The sinking of the ferry was a tragedy that shocked the whole world.","zh":"那艘渡輪的沉沒是一場震驚全世界的悲劇。"},{"en":"Despite his personal tragedy, he continued to help others in need.","zh":"儘管經歷了個人的悲劇，他仍持續幫助有需要的人。"}]},{"word":"tragic","pos":"adj.","phonetic":"[ˈtrædʒɪk]","meaning":"悲劇的；悲慘的","definition":"causing or characterized by extreme distress or sorrow","collocations":["tragic accident","tragic ending","tragic hero"],"example":"The movie tells a tragic love story.","exampleZh":"這部電影講述一個悲劇性的愛情故事。","synonyms":["sorrowful"],"level":5,"theme":"藝術與音樂","examples":[{"en":"The movie tells a tragic love story.","zh":"這部電影講述一個悲劇性的愛情故事。"},{"en":"A tragic accident on the mountain claimed three climbers' lives.","zh":"山上一場悲慘的意外奪走了三名登山者的性命。"},{"en":"The novel has a tragic ending that made many readers cry.","zh":"這本小說有個悲傷的結局，讓許多讀者落淚。"}]},{"word":"trail","pos":"n. / v.","phonetic":"[trel]","meaning":"小徑；蹤跡","definition":"a path or track; to follow a track or scent","collocations":["hiking trail","leave a trail","trail behind"],"example":"We followed the trail through the forest.","exampleZh":"我們沿著小徑穿過森林。","synonyms":["path"],"level":3,"theme":"自然與環境","examples":[{"en":"We followed the trail through the forest.","zh":"我們沿著小徑穿過森林。"},{"en":"This hiking trail leads to a beautiful waterfall in the mountains.","zh":"這條登山步道通往山中一座美麗的瀑布。"},{"en":"The injured deer left a trail of blood through the snow.","zh":"那隻受傷的鹿在雪地上留下一道血跡。"}]},{"word":"train","pos":"n. / v.","phonetic":"[tren]","meaning":"火車；訓練","definition":"a series of connected railway carriages; to teach a skill","collocations":["catch a train","train hard","train employees"],"example":"She trains every morning before school.","exampleZh":"她每天上學前都會訓練。","synonyms":["coach"],"level":1,"theme":"交通與旅行","examples":[{"en":"She trains every morning before school.","zh":"她每天上學前都會訓練。"},{"en":"We ran fast to catch the last train home.","zh":"我們飛快地跑去趕最後一班回家的火車。"},{"en":"The company trains its new employees for two weeks before they start.","zh":"這家公司在新員工正式上工前會訓練他們兩週。"}]},{"word":"trainer","pos":"n.","phonetic":"[ˈtrenɚ]","meaning":"教練；訓練員","definition":"a person who trains people or animals","collocations":["personal trainer","dog trainer","fitness trainer"],"example":"Her personal trainer helped her lose weight.","exampleZh":"她的私人教練幫助她減重。","synonyms":["coach"],"level":2,"theme":"運動與休閒","examples":[{"en":"Her personal trainer helped her lose weight.","zh":"她的私人教練幫助她減重。"},{"en":"The dog trainer taught our puppy to sit and stay.","zh":"那位馴狗師教會了我們的小狗坐下和待在原地。"},{"en":"A good fitness trainer designs exercises that match your goals.","zh":"一位好的健身教練會設計符合你目標的運動。"}]},{"word":"training","pos":"n.","phonetic":"[ˈtreniŋ]","meaning":"訓練；培訓","definition":"the action of teaching a person a particular skill","collocations":["job training","training program","military training"],"example":"New employees must complete safety training.","exampleZh":"新進員工必須完成安全訓練。","synonyms":["coaching"],"level":2,"theme":"工作與職業","examples":[{"en":"New employees must complete safety training.","zh":"新進員工必須完成安全訓練。"},{"en":"The new nurses attended a six-month training program at the hospital.","zh":"新進護理師在醫院參加了為期六個月的培訓計畫。"},{"en":"Proper training helps workers avoid accidents on the factory floor.","zh":"適當的訓練能幫助工人避免在工廠裡發生意外。"}]},{"word":"trait","pos":"n.","phonetic":"[tret]","meaning":"特質；特徵","definition":"a distinguishing quality or characteristic","collocations":["personality trait","genetic trait","common trait"],"example":"Honesty is one of his best traits.","exampleZh":"誠實是他最好的特質之一。","synonyms":["characteristic"],"level":5,"theme":"性質與描述","examples":[{"en":"Honesty is one of his best traits.","zh":"誠實是他最好的特質之一。"},{"en":"Patience is an important personality trait for a good teacher.","zh":"耐心是一位好老師重要的人格特質。"},{"en":"Curiosity is a common trait among successful scientists.","zh":"好奇心是成功科學家們共有的特質。"}]},{"word":"tram","pos":"n.","phonetic":"[træm]","meaning":"路面電車","definition":"a passenger vehicle powered by electricity, running on rails in a street","collocations":["take a tram","tram stop","tram line"],"example":"We took a tram to the old town.","exampleZh":"我們搭電車前往舊城區。","synonyms":[],"level":3,"theme":"交通與旅行","examples":[{"en":"We took a tram to the old town.","zh":"我們搭電車前往舊城區。"},{"en":"We waited at the tram stop for about ten minutes.","zh":"我們在路面電車站等了大約十分鐘。"},{"en":"The new tram line connects the station to the university.","zh":"新的路面電車線將車站與大學連接起來。"}]},{"word":"tranquil","pos":"adj.","phonetic":"[ˈtræŋkwɪl]","meaning":"寧靜的；平靜的","definition":"free from disturbance; calm","collocations":["tranquil lake","tranquil life","tranquil atmosphere"],"example":"The village was quiet and tranquil at night.","exampleZh":"這座村莊在夜晚安靜又寧靜。","synonyms":["peaceful","calm"],"level":6,"theme":"性質與描述","examples":[{"en":"The village was quiet and tranquil at night.","zh":"這座村莊在夜晚安靜又寧靜。"},{"en":"The tranquil lake reflected the mountains like a giant mirror.","zh":"那平靜的湖面像一面巨大的鏡子映照著群山。"},{"en":"After retiring, they enjoyed a tranquil life in the countryside.","zh":"退休後，他們在鄉間過著寧靜的生活。"}]},{"word":"transfer","pos":"v. / n.","phonetic":"[trænsˈfɝ]","meaning":"轉移；轉學；轉乘","definition":"to move from one place, position, or situation to another","collocations":["transfer money","transfer schools","train transfer"],"example":"He transferred to a new school last year.","exampleZh":"他去年轉學到一所新學校。","synonyms":["move","shift"],"level":3,"theme":"教育與學習","examples":[{"en":"He transferred to a new school last year.","zh":"他去年轉學到一所新學校。"},{"en":"You can transfer money to my account through this mobile app.","zh":"你可以透過這個手機應用程式把錢轉到我的帳戶。"},{"en":"We had to transfer to another train at the central station.","zh":"我們必須在中央車站轉乘另一班火車。"}]},{"word":"transform","pos":"v.","phonetic":"[trænsˈfɔrm]","meaning":"轉變；使變形","definition":"to make a marked change in the form or nature of something","collocations":["transform into","completely transform","transform a room"],"example":"The internet has transformed the way we communicate.","exampleZh":"網路已經改變了我們溝通的方式。","synonyms":["change"],"level":4,"theme":"科技與媒體","examples":[{"en":"The internet has transformed the way we communicate.","zh":"網路已經改變了我們溝通的方式。"},{"en":"A fresh coat of paint can completely transform an old room.","zh":"一層新油漆就能徹底改變一個舊房間的面貌。"},{"en":"The caterpillar will eventually transform into a beautiful butterfly.","zh":"這隻毛毛蟲最終會蛻變成一隻美麗的蝴蝶。"}]},{"word":"transition","pos":"n.","phonetic":"[trænˈzɪʃən]","meaning":"轉變；過渡","definition":"the process of changing from one state to another","collocations":["transition period","smooth transition","transition into adulthood"],"example":"The transition from school to work can be difficult.","exampleZh":"從學校到職場的轉變可能很困難。","synonyms":["change"],"level":5,"theme":"抽象概念","examples":[{"en":"The transition from school to work can be difficult.","zh":"從學校到職場的轉變可能很困難。"},{"en":"The company planned a smooth transition to the new computer system.","zh":"這家公司為轉換到新的電腦系統規劃了順利的過渡。"},{"en":"Moving to a new city marked his transition into adulthood.","zh":"搬到一個新城市標誌著他步入成年的過渡。"}]},{"word":"translate","pos":"v.","phonetic":"[trænsˈlet]","meaning":"翻譯","definition":"to express the meaning of text or speech in another language","collocations":["translate into","translate a document","translate for someone"],"example":"Can you translate this letter into English?","exampleZh":"你能把這封信翻譯成英文嗎？","synonyms":["interpret"],"level":3,"theme":"溝通與語言","examples":[{"en":"Can you translate this letter into English?","zh":"你能把這封信翻譯成英文嗎？"},{"en":"She translated the poem into English for her foreign classmates.","zh":"她為外國同學把這首詩翻譯成英文。"},{"en":"Could you translate for me when we meet the Japanese guests?","zh":"我們見到日本客人時你能為我翻譯嗎？"}]},{"word":"translation","pos":"n.","phonetic":"[trænsˈleʃən]","meaning":"翻譯；譯文","definition":"the process of translating words or text into another language","collocations":["English translation","machine translation","literal translation"],"example":"She works as a translation editor for a publisher.","exampleZh":"她在出版社擔任翻譯編輯。","synonyms":[],"level":3,"theme":"溝通與語言","examples":[{"en":"She works as a translation editor for a publisher.","zh":"她在出版社擔任翻譯編輯。"},{"en":"The English translation of this novel keeps the original's beautiful style.","zh":"這本小說的英文譯本保留了原著優美的風格。"},{"en":"Machine translation is fast, but it often makes small mistakes.","zh":"機器翻譯速度很快，但常常會出現小錯誤。"}]},{"word":"transmit","pos":"v.","phonetic":"[trænsˈmɪt]","meaning":"傳送；傳播","definition":"to cause something to pass from one person, place, or thing to another","collocations":["transmit a signal","transmit disease","transmit data"],"example":"The virus can be transmitted through contact.","exampleZh":"這種病毒可以透過接觸傳播。","synonyms":["send"],"level":5,"theme":"科技與媒體","examples":[{"en":"The virus can be transmitted through contact.","zh":"這種病毒可以透過接觸傳播。"},{"en":"The tower transmits a strong signal to the whole valley.","zh":"這座塔向整個山谷傳送強力的訊號。"},{"en":"Mosquitoes can transmit dangerous diseases to humans.","zh":"蚊子能將危險的疾病傳播給人類。"}]},{"word":"transparent","pos":"adj.","phonetic":"[trænsˈpɛrənt]","meaning":"透明的；坦誠的","definition":"allowing light to pass through so objects can be seen clearly; open and honest","collocations":["transparent glass","transparent process","completely transparent"],"example":"The company promised a more transparent decision-making process.","exampleZh":"該公司承諾決策過程會更加透明。","synonyms":["clear"],"level":5,"theme":"性質與描述","examples":[{"en":"The company promised a more transparent decision-making process.","zh":"該公司承諾決策過程會更加透明。"},{"en":"The fish tank is made of thick transparent glass.","zh":"這個魚缸是用厚厚的透明玻璃製成的。"},{"en":"Voters want a completely transparent process for counting the ballots.","zh":"選民希望有一個完全透明的計票過程。"}]},{"word":"transport","pos":"v. / n.","phonetic":"[trænsˈpɔrt]","meaning":"運輸；運送","definition":"to take or carry goods or people from one place to another","collocations":["public transport","transport goods","means of transport"],"example":"The goods were transported by ship.","exampleZh":"這些貨物是由船運送的。","synonyms":["carry"],"level":3,"theme":"交通與旅行","examples":[{"en":"The goods were transported by ship.","zh":"這些貨物是由船運送的。"},{"en":"Huge trucks transport fresh vegetables from the farms to the city.","zh":"大卡車將新鮮蔬菜從農場運送到城市。"},{"en":"In this town, the bicycle is a common means of transport.","zh":"在這個城鎮，腳踏車是常見的交通工具。"}]},{"word":"transportation","pos":"n.","phonetic":"[ˌtrænspɚˈteʃən]","meaning":"運輸；交通工具","definition":"the means of transporting or conveying goods or people","collocations":["public transportation","means of transportation","transportation system"],"example":"The city has an efficient public transportation system.","exampleZh":"這座城市擁有高效率的大眾運輸系統。","synonyms":[],"level":3,"theme":"交通與旅行","examples":[{"en":"The city has an efficient public transportation system.","zh":"這座城市擁有高效率的大眾運輸系統。"},{"en":"Taking public transportation is cheaper than driving your own car.","zh":"搭乘大眾運輸比開自己的車便宜。"},{"en":"The island's transportation system relies mainly on ferries and buses.","zh":"這座島的交通系統主要依賴渡輪和公車。"}]},{"word":"trap","pos":"n. / v.","phonetic":"[træp]","meaning":"陷阱；圈套","definition":"a device or scheme used to catch a person or animal unawares","collocations":["set a trap","fall into a trap","mouse trap"],"example":"The hunter set a trap to catch the fox.","exampleZh":"獵人設下陷阱來抓狐狸。","synonyms":["snare"],"level":3,"theme":"動作與行為","examples":[{"en":"The hunter set a trap to catch the fox.","zh":"獵人設下陷阱來抓狐狸。"},{"en":"We set a mouse trap in the kitchen to catch the pest.","zh":"我們在廚房設了一個捕鼠器來抓那隻害蟲。"},{"en":"The clever fox never fell into the hunter's trap.","zh":"那隻聰明的狐狸從未落入獵人的陷阱。"}]},{"word":"trash","pos":"n.","phonetic":"[træʃ]","meaning":"垃圾","definition":"unwanted material that is thrown away","collocations":["take out the trash","trash can","trash bag"],"example":"Please take out the trash before you leave.","exampleZh":"離開前請把垃圾拿出去倒。","synonyms":["garbage","rubbish"],"level":2,"theme":"居家與生活","examples":[{"en":"Please take out the trash before you leave.","zh":"離開前請把垃圾拿出去倒。"},{"en":"He threw the empty bottle into the trash can outside.","zh":"他把空瓶子丟進了外面的垃圾桶。"},{"en":"Remember to tie the trash bag before you leave it outside.","zh":"記得在把垃圾袋放到外面之前把它綁好。"}]},{"word":"travel","pos":"v. / n.","phonetic":"[ˈtrævl̩]","meaning":"旅行；行進","definition":"to make a journey, typically of some length","collocations":["travel abroad","travel agency","world travel"],"example":"They love to travel around the world.","exampleZh":"他們喜歡環遊世界旅行。","synonyms":["journey"],"level":1,"theme":"交通與旅行","examples":[{"en":"They love to travel around the world.","zh":"他們喜歡環遊世界旅行。"},{"en":"She dreams of traveling abroad after she graduates from college.","zh":"她夢想在大學畢業後出國旅行。"},{"en":"Light travels much faster than sound.","zh":"光行進的速度比聲音快得多。"}]},{"word":"traveler","pos":"n.","phonetic":"[ˈtrævlɚ]","meaning":"旅行者","definition":"a person who travels","collocations":["frequent traveler","world traveler","traveler's check"],"example":"The traveler stayed at a small hostel.","exampleZh":"這位旅行者住在一家小型青年旅館。","synonyms":["tourist"],"level":2,"theme":"交通與旅行","examples":[{"en":"The traveler stayed at a small hostel.","zh":"這位旅行者住在一家小型青年旅館。"},{"en":"As a frequent traveler, he always packs his suitcase in ten minutes.","zh":"身為經常旅行的人，他總是在十分鐘內把行李箱打包好。"},{"en":"The experienced traveler gave us useful tips about the trip.","zh":"那位經驗豐富的旅行者給了我們關於旅程的實用建議。"}]},{"word":"tray","pos":"n.","phonetic":"[tre]","meaning":"托盤","definition":"a flat container with a raised edge, used for carrying items","collocations":["serving tray","food tray","tray of drinks"],"example":"The waiter carried a tray full of drinks.","exampleZh":"服務生端著一盤滿滿的飲料。","synonyms":[],"level":2,"theme":"居家與生活","examples":[{"en":"The waiter carried a tray full of drinks.","zh":"服務生端著一盤滿滿的飲料。"},{"en":"She carefully carried a tray of drinks to the guests.","zh":"她小心翼翼地端著一盤飲料給客人。"},{"en":"Please put your food tray in the return area after eating.","zh":"用餐後請將你的餐盤放到回收區。"}]},{"word":"treasure","pos":"n. / v.","phonetic":"[ˈtrɛʒɚ]","meaning":"寶藏；珍惜","definition":"a quantity of precious metals or gems; to value greatly","collocations":["buried treasure","treasure hunt","treasure a memory"],"example":"They found buried treasure on the island.","exampleZh":"他們在島上發現了埋藏的寶藏。","synonyms":["cherish"],"level":3,"theme":"抽象概念","examples":[{"en":"They found buried treasure on the island.","zh":"他們在島上發現了埋藏的寶藏。"},{"en":"The old man treasures the letters his wife wrote to him.","zh":"那位老人珍惜著妻子寫給他的信。"},{"en":"The children organized a treasure hunt in the backyard.","zh":"孩子們在後院辦了一場尋寶遊戲。"}]},{"word":"treat","pos":"v. / n.","phonetic":"[trit]","meaning":"對待；治療；款待","definition":"to behave toward someone in a certain way; to give medical care","collocations":["treat kindly","treat a disease","a special treat"],"example":"The doctor treated the patient's injury.","exampleZh":"醫生治療了病人的傷口。","synonyms":["handle"],"level":2,"theme":"身體與健康","examples":[{"en":"The doctor treated the patient's injury.","zh":"醫生治療了病人的傷口。"},{"en":"You should treat others kindly if you want their respect.","zh":"如果你想得到別人的尊重，就該親切地對待他們。"},{"en":"Ice cream on a hot day is always a special treat.","zh":"炎熱天裡的冰淇淋總是一種特別的享受。"}]},{"word":"treatment","pos":"n.","phonetic":"[ˈtritmənt]","meaning":"治療；待遇","definition":"medical care given to a patient; the manner of dealing with someone","collocations":["medical treatment","receive treatment","fair treatment"],"example":"He is receiving treatment for his illness.","exampleZh":"他正在接受疾病治療。","synonyms":["therapy"],"level":3,"theme":"身體與健康","examples":[{"en":"He is receiving treatment for his illness.","zh":"他正在接受疾病治療。"},{"en":"The injured worker received medical treatment at the local clinic.","zh":"那名受傷的工人在當地診所接受了治療。"},{"en":"All employees deserve fair treatment regardless of their background.","zh":"無論背景如何，所有員工都應得到公平的待遇。"}]},{"word":"treaty","pos":"n.","phonetic":"[ˈtriti]","meaning":"條約","definition":"a formally concluded agreement between states","collocations":["sign a treaty","peace treaty","international treaty"],"example":"The two nations signed a peace treaty.","exampleZh":"這兩國簽署了一項和平條約。","synonyms":["agreement"],"level":5,"theme":"政治與法律","examples":[{"en":"The two nations signed a peace treaty.","zh":"這兩國簽署了一項和平條約。"},{"en":"The two countries finally signed a treaty to end the conflict.","zh":"兩國終於簽署了一項條約來結束衝突。"},{"en":"An international treaty was created to protect the world's oceans.","zh":"一項國際條約被制定來保護世界的海洋。"}]},{"word":"tree","pos":"n.","phonetic":"[tri]","meaning":"樹","definition":"a woody perennial plant with a trunk and branches","collocations":["climb a tree","family tree","plant a tree"],"example":"A tall tree grows in front of our house.","exampleZh":"我們家門前長著一棵高大的樹。","synonyms":[],"level":1,"theme":"自然與環境","examples":[{"en":"A tall tree grows in front of our house.","zh":"我們家門前長著一棵高大的樹。"},{"en":"Every spring, our class plants a tree in the schoolyard.","zh":"每年春天，我們班都會在校園裡種一棵樹。"},{"en":"She drew her family tree for the history assignment.","zh":"她為歷史作業畫了自己的家族樹。"}]},{"word":"tremble","pos":"v.","phonetic":"[ˈtrɛmbl̩]","meaning":"顫抖","definition":"to shake involuntarily, typically from fear or excitement","collocations":["tremble with fear","hands tremble","tremble slightly"],"example":"Her hands trembled as she opened the letter.","exampleZh":"她打開那封信時雙手顫抖著。","synonyms":["shake"],"level":4,"theme":"情緒與感受","examples":[{"en":"Her hands trembled as she opened the letter.","zh":"她打開那封信時雙手顫抖著。"},{"en":"The little girl trembled with fear during the thunderstorm.","zh":"小女孩在雷雨中嚇得發抖。"},{"en":"His voice trembled slightly as he gave his first public speech.","zh":"他發表第一次公開演說時，聲音微微顫抖。"}]},{"word":"tremendous","pos":"adj.","phonetic":"[trɪˈmɛndəs]","meaning":"巨大的；驚人的","definition":"very great in amount, scale, or intensity","collocations":["tremendous success","tremendous amount","tremendous effort"],"example":"The project was a tremendous success.","exampleZh":"這項計畫獲得了巨大的成功。","synonyms":["huge","enormous"],"level":4,"theme":"性質與描述","examples":[{"en":"The project was a tremendous success.","zh":"這項計畫獲得了巨大的成功。"},{"en":"The charity concert was a tremendous success and raised much money.","zh":"那場慈善演唱會非常成功，募得了大量的錢。"},{"en":"It took tremendous effort to finish the project on time.","zh":"準時完成這個專案花費了巨大的努力。"}]},{"word":"trend","pos":"n.","phonetic":"[trɛnd]","meaning":"趨勢；潮流","definition":"a general direction in which something is developing or changing","collocations":["latest trend","fashion trend","upward trend"],"example":"There is a growing trend toward online shopping.","exampleZh":"線上購物的趨勢正逐漸增長。","synonyms":["tendency"],"level":3,"theme":"社會與文化","examples":[{"en":"There is a growing trend toward online shopping.","zh":"線上購物的趨勢正逐漸增長。"},{"en":"Wearing loose clothes is the latest trend among teenagers.","zh":"穿寬鬆的衣服是青少年之間最新的潮流。"},{"en":"Sales have shown a steady upward trend over the past year.","zh":"過去一年來，銷售額呈現穩定上升的趨勢。"}]},{"word":"trial","pos":"n.","phonetic":"[ˈtraɪəl]","meaning":"審判；試驗","definition":"a formal examination of evidence in court; a test of performance","collocations":["stand trial","trial period","clinical trial"],"example":"The suspect will stand trial next month.","exampleZh":"這名嫌犯下個月將出庭受審。","synonyms":["test"],"level":4,"theme":"政治與法律","examples":[{"en":"The suspect will stand trial next month.","zh":"這名嫌犯下個月將出庭受審。"},{"en":"The new medicine is being tested in a clinical trial.","zh":"這種新藥正在臨床試驗中接受測試。"},{"en":"You can use the software free during the thirty-day trial period.","zh":"在三十天的試用期內你可以免費使用這個軟體。"}]},{"word":"triangle","pos":"n.","phonetic":"[ˈtraɪˌæŋɡl̩]","meaning":"三角形","definition":"a shape with three straight sides and three angles","collocations":["draw a triangle","right triangle","triangle shape"],"example":"Draw a triangle with three equal sides.","exampleZh":"畫出一個三邊相等的三角形。","synonyms":[],"level":2,"theme":"科學與數學","examples":[{"en":"Draw a triangle with three equal sides.","zh":"畫出一個三邊相等的三角形。"},{"en":"The teacher asked us to measure the angles of the triangle.","zh":"老師要我們量出這個三角形的角度。"},{"en":"A slice of this cake has a perfect triangle shape.","zh":"這塊蛋糕的一片呈現完美的三角形。"}]},{"word":"tribe","pos":"n.","phonetic":"[traɪb]","meaning":"部落","definition":"a social group made up of families with a common ancestor or culture","collocations":["ancient tribe","tribe of people","tribal leader"],"example":"The tribe has lived in the forest for centuries.","exampleZh":"這個部落已在森林中生活了好幾世紀。","synonyms":["clan"],"level":4,"theme":"社會與文化","examples":[{"en":"The tribe has lived in the forest for centuries.","zh":"這個部落已在森林中生活了好幾世紀。"},{"en":"The ancient tribe used stone tools to hunt wild animals.","zh":"這個古老的部落用石器來獵捕野生動物。"},{"en":"Each tribe in the region has its own language and customs.","zh":"這個地區的每個部落都有自己的語言和習俗。"}]},{"word":"trick","pos":"n. / v.","phonetic":"[trɪk]","meaning":"詭計；把戲","definition":"a cunning act to deceive; a skillful act performed for entertainment","collocations":["play a trick","magic trick","trick someone into"],"example":"The magician performed an amazing trick.","exampleZh":"這位魔術師表演了一個驚人的把戲。","synonyms":["deceive"],"level":2,"theme":"娛樂與活動","examples":[{"en":"The magician performed an amazing trick.","zh":"這位魔術師表演了一個驚人的把戲。"},{"en":"The boys played a trick on their teacher on April Fools' Day.","zh":"男孩們在愚人節那天對老師惡作劇。"},{"en":"The salesman tricked the old lady into buying a useless product.","zh":"那名推銷員騙老太太買了一件沒用的產品。"}]},{"word":"tricky","pos":"adj.","phonetic":"[ˈtrɪki]","meaning":"棘手的；狡猾的","definition":"difficult to do or deal with; deceptive","collocations":["tricky question","tricky situation","a tricky task"],"example":"This math problem is quite tricky.","exampleZh":"這道數學題相當棘手。","synonyms":["difficult"],"level":3,"theme":"性質與描述","examples":[{"en":"This math problem is quite tricky.","zh":"這道數學題相當棘手。"},{"en":"The interviewer asked a few tricky questions to test our thinking.","zh":"面試官問了幾個棘手的問題來測試我們的思考。"},{"en":"Repairing the old clock turned out to be a tricky task.","zh":"修理這個老時鐘結果是一件棘手的工作。"}]},{"word":"trigger","pos":"v. / n.","phonetic":"[ˈtrɪɡɚ]","meaning":"觸發；扳機","definition":"to cause something to happen or start","collocations":["trigger a reaction","pull the trigger","trigger an alarm"],"example":"Stress can trigger headaches.","exampleZh":"壓力可能引發頭痛。","synonyms":["cause"],"level":5,"theme":"抽象概念","examples":[{"en":"Stress can trigger headaches.","zh":"壓力可能引發頭痛。"},{"en":"The smoke from the toast triggered the fire alarm.","zh":"烤麵包冒出的煙觸發了火災警報。"},{"en":"Certain foods can trigger an allergic reaction in some people.","zh":"某些食物會在部分人身上引發過敏反應。"}]},{"word":"trim","pos":"v.","phonetic":"[trɪm]","meaning":"修剪","definition":"to make something neat by cutting away irregular parts","collocations":["trim hair","trim the hedge","trim the budget"],"example":"He trimmed the hedges in the garden.","exampleZh":"他修剪了花園裡的樹籬。","synonyms":["cut"],"level":4,"theme":"動作與行為","examples":[{"en":"He trimmed the hedges in the garden.","zh":"他修剪了花園裡的樹籬。"},{"en":"The barber trimmed his hair neatly before the graduation ceremony.","zh":"理髮師在畢業典禮前把他的頭髮修剪得整整齊齊。"},{"en":"The manager decided to trim the budget for next year.","zh":"經理決定削減明年的預算。"}]},{"word":"trip","pos":"n. / v.","phonetic":"[trɪp]","meaning":"旅行；絆倒","definition":"a journey or excursion; to stumble and almost fall","collocations":["go on a trip","business trip","trip over"],"example":"We are planning a trip to Japan next summer.","exampleZh":"我們正計劃明年夏天去日本旅行。","synonyms":["journey"],"level":1,"theme":"交通與旅行","examples":[{"en":"We are planning a trip to Japan next summer.","zh":"我們正計劃明年夏天去日本旅行。"},{"en":"Be careful not to trip over the cable on the floor.","zh":"小心別被地板上的電線絆倒。"},{"en":"My father often goes on a business trip to Southeast Asia.","zh":"我爸爸經常到東南亞出差。"}]},{"word":"triple","pos":"adj. / v.","phonetic":"[ˈtrɪpl̩]","meaning":"三倍的；使增加三倍","definition":"consisting of three parts; to become three times as much","collocations":["triple the amount","triple jump","a triple threat"],"example":"The company's profits tripled last year.","exampleZh":"這家公司的利潤去年成長了三倍。","synonyms":[],"level":4,"theme":"科學與數學","examples":[{"en":"The company's profits tripled last year.","zh":"這家公司的利潤去年成長了三倍。"},{"en":"The recipe serves four, so triple the amount for twelve guests.","zh":"這道食譜供四人份，所以要招待十二位客人就把份量增為三倍。"},{"en":"The athlete broke the school record in the triple jump.","zh":"那名運動員打破了三級跳的校紀錄。"}]},{"word":"triumph","pos":"n. / v.","phonetic":"[ˈtraɪəmf]","meaning":"勝利；凱旋","definition":"a great victory or achievement","collocations":["triumph over","moment of triumph","celebrate a triumph"],"example":"The team celebrated their triumph over their rivals.","exampleZh":"這支隊伍慶祝他們戰勝對手的勝利。","synonyms":["victory"],"level":5,"theme":"運動與休閒","examples":[{"en":"The team celebrated their triumph over their rivals.","zh":"這支隊伍慶祝他們戰勝對手的勝利。"},{"en":"Winning the science fair was a great triumph for the small school.","zh":"贏得科展對這所小學校來說是一大勝利。"},{"en":"She finally triumphed over her fear of speaking in public.","zh":"她終於戰勝了在公開場合說話的恐懼。"}]},{"word":"trivial","pos":"adj.","phonetic":"[ˈtrɪvɪəl]","meaning":"瑣碎的；不重要的","definition":"of little value or importance","collocations":["trivial matter","trivial detail","seem trivial"],"example":"Don't worry about such trivial matters.","exampleZh":"別為這些瑣事煩惱。","synonyms":["minor","unimportant"],"level":6,"theme":"性質與描述","examples":[{"en":"Don't worry about such trivial matters.","zh":"別為這些瑣事煩惱。"},{"en":"They argued for hours over a completely trivial matter.","zh":"他們為了一件完全微不足道的小事爭論了好幾個小時。"},{"en":"Don't waste your energy on such trivial details.","zh":"別把你的精力浪費在這種瑣碎的細節上。"}]},{"word":"troop","pos":"n.","phonetic":"[trup]","meaning":"部隊；軍隊","definition":"a group of soldiers, especially as part of a large force","collocations":["send troops","withdraw troops","troop movement"],"example":"The government decided to send more troops abroad.","exampleZh":"政府決定派遣更多部隊到海外。","synonyms":["soldiers"],"level":5,"theme":"政治與法律","examples":[{"en":"The government decided to send more troops abroad.","zh":"政府決定派遣更多部隊到海外。"},{"en":"The general ordered the troops to withdraw from the border.","zh":"將軍下令部隊從邊境撤退。"},{"en":"Fresh troops were sent to help with the rescue after the flood.","zh":"洪水過後，新的部隊被派去協助救援。"}]},{"word":"tropical","pos":"adj.","phonetic":"[ˈtrɑpɪkl̩]","meaning":"熱帶的","definition":"relating to or situated in the tropics","collocations":["tropical climate","tropical fruit","tropical rainforest"],"example":"Mangoes are a popular tropical fruit.","exampleZh":"芒果是一種很受歡迎的熱帶水果。","synonyms":[],"level":3,"theme":"天氣與季節","examples":[{"en":"Mangoes are a popular tropical fruit.","zh":"芒果是一種很受歡迎的熱帶水果。"},{"en":"The tropical rainforest is home to thousands of rare species.","zh":"這片熱帶雨林是數千種稀有物種的家園。"},{"en":"In a tropical climate, it stays warm and humid all year.","zh":"在熱帶氣候中，全年都保持溫暖潮濕。"}]},{"word":"trouble","pos":"n. / v.","phonetic":"[ˈtrʌbl̩]","meaning":"麻煩；困擾","definition":"difficulty or problems; to cause distress","collocations":["get into trouble","have trouble with","trouble someone"],"example":"He got into trouble for skipping class.","exampleZh":"他因為蹺課而惹上麻煩。","synonyms":["problem"],"level":2,"theme":"抽象概念","examples":[{"en":"He got into trouble for skipping class.","zh":"他因為蹺課而惹上麻煩。"},{"en":"I have trouble understanding this chapter of the physics book.","zh":"我很難理解物理課本的這一章。"},{"en":"Sorry to trouble you, but could you help me carry this box?","zh":"抱歉打擾你，但你能幫我搬這個箱子嗎？"}]},{"word":"troublesome","pos":"adj.","phonetic":"[ˈtrʌbl̩səm]","meaning":"麻煩的；令人煩惱的","definition":"causing difficulty or annoyance","collocations":["troublesome child","troublesome problem","troublesome neighbor"],"example":"The leaking roof has been quite troublesome.","exampleZh":"這個漏水的屋頂一直很麻煩。","synonyms":["annoying"],"level":5,"theme":"性質與描述","examples":[{"en":"The leaking roof has been quite troublesome.","zh":"這個漏水的屋頂一直很麻煩。"},{"en":"The noisy machine has been a troublesome problem for weeks.","zh":"那台吵鬧的機器已經是個惱人的問題好幾週了。"},{"en":"Their troublesome neighbor plays loud music late at night.","zh":"他們那個麻煩的鄰居深夜還放很大聲的音樂。"}]},{"word":"trousers","pos":"n.","phonetic":"[ˈtraʊzɚz]","meaning":"長褲","definition":"a garment covering the body from the waist to the ankles, with a separate part for each leg","collocations":["a pair of trousers","wear trousers","black trousers"],"example":"He wore a pair of gray trousers to the interview.","exampleZh":"他穿了一條灰色長褲去面試。","synonyms":["pants"],"level":2,"theme":"服裝與外表","examples":[{"en":"He wore a pair of gray trousers to the interview.","zh":"他穿了一條灰色長褲去面試。"},{"en":"She bought a new pair of trousers for the job interview.","zh":"她為工作面試買了一條新長褲。"},{"en":"These black trousers are too long and need to be shortened.","zh":"這條黑色長褲太長了，需要改短。"}]},{"word":"truck","pos":"n.","phonetic":"[trʌk]","meaning":"卡車","definition":"a large motor vehicle used for transporting goods","collocations":["delivery truck","truck driver","load a truck"],"example":"The truck delivered furniture to the new house.","exampleZh":"這輛卡車把家具送到新房子。","synonyms":[],"level":1,"theme":"交通與旅行","examples":[{"en":"The truck delivered furniture to the new house.","zh":"這輛卡車把家具送到新房子。"},{"en":"The workers loaded the truck with heavy boxes of fruit.","zh":"工人們把一箱箱沉重的水果裝上卡車。"},{"en":"A delivery truck blocked the narrow street this morning.","zh":"今天早上一輛送貨卡車擋住了這條狹窄的街道。"}]},{"word":"true","pos":"adj.","phonetic":"[tru]","meaning":"真實的；真正的","definition":"in accordance with fact or reality","collocations":["true story","come true","true love"],"example":"It is true that hard work pays off.","exampleZh":"努力就會有收穫是真的。","synonyms":["real"],"level":1,"theme":"性質與描述","examples":[{"en":"It is true that hard work pays off.","zh":"努力就會有收穫是真的。"},{"en":"This movie is based on a true story about a brave doctor.","zh":"這部電影是根據一個勇敢醫生的真實故事改編的。"},{"en":"If you keep working hard, your dream will come true.","zh":"如果你持續努力，你的夢想就會實現。"}]},{"word":"truly","pos":"adv.","phonetic":"[ˈtruli]","meaning":"真正地；確實地","definition":"in a true, accurate, or sincere manner","collocations":["truly grateful","truly amazing","yours truly"],"example":"I am truly grateful for your help.","exampleZh":"我真心感激你的幫助。","synonyms":["genuinely"],"level":2,"theme":"抽象概念","examples":[{"en":"I am truly grateful for your help.","zh":"我真心感激你的幫助。"},{"en":"The view from the mountaintop was truly amazing at sunrise.","zh":"日出時從山頂看到的景色確實令人驚嘆。"},{"en":"She was truly happy to see her old friends again.","zh":"再次見到老朋友，她真的很開心。"}]},{"word":"trumpet","pos":"n.","phonetic":"[ˈtrʌmpɪt]","meaning":"小號","definition":"a brass musical instrument with a flared bell","collocations":["play the trumpet","trumpet player","blow a trumpet"],"example":"He learned to play the trumpet in the school band.","exampleZh":"他在校樂團學會了吹小號。","synonyms":[],"level":3,"theme":"藝術與音樂","examples":[{"en":"He learned to play the trumpet in the school band.","zh":"他在校樂團學會了吹小號。"},{"en":"The young trumpet player performed a solo at the concert.","zh":"那位年輕的小號手在音樂會上演奏了獨奏。"},{"en":"He practices the trumpet for an hour every evening.","zh":"他每天晚上練習小號一個小時。"}]},{"word":"trunk","pos":"n.","phonetic":"[trʌŋk]","meaning":"樹幹；後車廂；象鼻","definition":"the main stem of a tree; the rear storage compartment of a car; an elephant's nose","collocations":["tree trunk","car trunk","elephant's trunk"],"example":"He put the suitcase in the trunk of the car.","exampleZh":"他把行李箱放進汽車的後車廂。","synonyms":[],"level":3,"theme":"自然與環境","examples":[{"en":"He put the suitcase in the trunk of the car.","zh":"他把行李箱放進汽車的後車廂。"},{"en":"The elephant used its trunk to spray water over its back.","zh":"那隻大象用鼻子把水噴到自己的背上。"},{"en":"The old tree trunk was so wide that three people could hug it.","zh":"那棵老樹的樹幹寬得需要三個人才能環抱。"}]},{"word":"trust","pos":"v. / n.","phonetic":"[trʌst]","meaning":"信任","definition":"firm belief in the reliability of someone or something","collocations":["trust someone","build trust","break trust"],"example":"I trust you to make the right decision.","exampleZh":"我相信你會做出正確的決定。","synonyms":["believe","faith"],"level":2,"theme":"人物與家庭","examples":[{"en":"I trust you to make the right decision.","zh":"我相信你會做出正確的決定。"},{"en":"It takes years to build trust but only seconds to break it.","zh":"建立信任需要好幾年，破壞它卻只需幾秒。"},{"en":"The students trust their teacher to treat everyone fairly.","zh":"學生們信任他們的老師會公平對待每個人。"}]},{"word":"truth","pos":"n.","phonetic":"[truθ]","meaning":"真相；事實","definition":"the quality or state of being true; fact","collocations":["tell the truth","the whole truth","truth be told"],"example":"You should always tell the truth.","exampleZh":"你應該永遠說實話。","synonyms":["fact"],"level":1,"theme":"抽象概念","examples":[{"en":"You should always tell the truth.","zh":"你應該永遠說實話。"},{"en":"The reporter worked hard to discover the truth behind the scandal.","zh":"那名記者努力查明醜聞背後的真相。"},{"en":"Truth be told, I have never enjoyed watching horror movies.","zh":"老實說，我從來就不喜歡看恐怖片。"}]},{"word":"try","pos":"v. / n.","phonetic":"[traɪ]","meaning":"嘗試；試圖","definition":"to make an attempt or effort to do something","collocations":["try hard","try one's best","give it a try"],"example":"She tried her best to solve the problem.","exampleZh":"她盡了最大努力來解決這個問題。","synonyms":["attempt"],"level":1,"theme":"動作與行為","examples":[{"en":"She tried her best to solve the problem.","zh":"她盡了最大努力來解決這個問題。"},{"en":"Even if it looks difficult, you should give it a try.","zh":"即使看起來很難，你也應該試一試。"},{"en":"He tried hard to remember where he had left his keys.","zh":"他努力回想他把鑰匙放在哪裡了。"}]},{"word":"tube","pos":"n.","phonetic":"[tub]","meaning":"管子；試管","definition":"a long hollow cylinder for holding or transporting something","collocations":["test tube","tube of toothpaste","inner tube"],"example":"She squeezed the tube of toothpaste.","exampleZh":"她擠了牙膏管。","synonyms":["pipe"],"level":2,"theme":"科學與數學","examples":[{"en":"She squeezed the tube of toothpaste.","zh":"她擠了牙膏管。"},{"en":"The scientist poured the blue liquid into a clean test tube.","zh":"科學家把藍色液體倒進一支乾淨的試管裡。"},{"en":"There is only a little left in the tube of toothpaste.","zh":"這條牙膏管裡只剩下一點點了。"}]},{"word":"tug","pos":"v. / n.","phonetic":"[tʌɡ]","meaning":"用力拉","definition":"to pull something hard or suddenly","collocations":["tug at","tug of war","give a tug"],"example":"The child tugged at his mother's sleeve.","exampleZh":"這孩子用力拉扯他媽媽的袖子。","synonyms":["pull"],"level":4,"theme":"動作與行為","examples":[{"en":"The child tugged at his mother's sleeve.","zh":"這孩子用力拉扯他媽媽的袖子。"},{"en":"The two teams competed fiercely in the tug of war.","zh":"兩隊在拔河比賽中激烈競爭。"},{"en":"The puppy tugged at the rope, trying to pull it away.","zh":"小狗用力拉扯繩子，想把它拖走。"}]},{"word":"tuition","pos":"n.","phonetic":"[tuˈɪʃən]","meaning":"學費；教學","definition":"the fee charged for instruction, especially at a school or college","collocations":["pay tuition","tuition fee","tuition increase"],"example":"College tuition has risen sharply this year.","exampleZh":"今年大學學費大幅上漲。","synonyms":[],"level":5,"theme":"教育與學習","examples":[{"en":"College tuition has risen sharply this year.","zh":"今年大學學費大幅上漲。"},{"en":"Her parents work extra hours to pay her college tuition.","zh":"她的父母加班工作來支付她的大學學費。"},{"en":"Many students protested against the sudden tuition increase.","zh":"許多學生抗議學費突然調漲。"}]},{"word":"tulip","pos":"n.","phonetic":"[ˈtulɪp]","meaning":"鬱金香","definition":"a spring-flowering bulbous plant with brightly colored flowers","collocations":["tulip field","red tulip","tulip garden"],"example":"The tulip fields in Holland attract many tourists.","exampleZh":"荷蘭的鬱金香花田吸引了許多觀光客。","synonyms":[],"level":3,"theme":"動物與植物","examples":[{"en":"The tulip fields in Holland attract many tourists.","zh":"荷蘭的鬱金香花田吸引了許多觀光客。"},{"en":"She planted red tulips along the path to the front door.","zh":"她沿著通往前門的小徑種了紅色的鬱金香。"},{"en":"In spring, the tulip garden is full of bright colors.","zh":"春天時，這座鬱金香花園滿是鮮豔的色彩。"}]},{"word":"tune","pos":"n. / v.","phonetic":"[tun]","meaning":"曲調；調音","definition":"a melody; to adjust an instrument to the correct pitch","collocations":["hum a tune","tune a guitar","catchy tune"],"example":"She hummed a familiar tune while cooking.","exampleZh":"她一邊煮飯一邊哼著熟悉的曲調。","synonyms":["melody"],"level":3,"theme":"藝術與音樂","examples":[{"en":"She hummed a familiar tune while cooking.","zh":"她一邊煮飯一邊哼著熟悉的曲調。"},{"en":"The song has such a catchy tune that everyone remembers it.","zh":"這首歌的曲調很好記，每個人都記得住。"},{"en":"He carefully tuned his guitar before the performance began.","zh":"演出開始前，他仔細地為吉他調音。"}]},{"word":"tunnel","pos":"n.","phonetic":"[ˈtʌnl̩]","meaning":"隧道","definition":"an underground passage, especially one built through a hill or under a road","collocations":["dig a tunnel","tunnel entrance","drive through a tunnel"],"example":"The train passed through a long tunnel.","exampleZh":"火車穿過了一條長長的隧道。","synonyms":[],"level":3,"theme":"交通與旅行","examples":[{"en":"The train passed through a long tunnel.","zh":"火車穿過了一條長長的隧道。"},{"en":"It took ten years to dig the tunnel through the mountain.","zh":"挖穿這座山的隧道花了十年。"},{"en":"We drove through a long tunnel to reach the other valley.","zh":"我們開車穿過一條長隧道到達另一個山谷。"}]},{"word":"turkey","pos":"n.","phonetic":"[ˈtɝki]","meaning":"火雞","definition":"a large bird often eaten at holiday meals","collocations":["roast turkey","turkey sandwich","carve the turkey"],"example":"We always eat roast turkey at Thanksgiving.","exampleZh":"我們感恩節總是吃烤火雞。","synonyms":[],"level":2,"theme":"食物與烹飪","examples":[{"en":"We always eat roast turkey at Thanksgiving.","zh":"我們感恩節總是吃烤火雞。"},{"en":"Grandfather carved the turkey while the family waited hungrily.","zh":"爺爺切著火雞，全家人餓著肚子等待。"},{"en":"I made a turkey sandwich with the leftovers from last night.","zh":"我用昨晚剩下的食材做了一個火雞三明治。"}]},{"word":"turn","pos":"v. / n.","phonetic":"[tɝn]","meaning":"轉動；輪流","definition":"to move in a circular direction; a chance to do something in a sequence","collocations":["turn around","take turns","turn off"],"example":"Please take turns using the computer.","exampleZh":"請輪流使用電腦。","synonyms":["rotate"],"level":1,"theme":"動作與行為","examples":[{"en":"Please take turns using the computer.","zh":"請輪流使用電腦。"},{"en":"Please turn off the lights before you leave the classroom.","zh":"離開教室前請關燈。"},{"en":"The children took turns riding the new bicycle.","zh":"孩子們輪流騎那輛新腳踏車。"}]},{"word":"turtle","pos":"n.","phonetic":"[ˈtɝtl̩]","meaning":"烏龜","definition":"a reptile with a hard shell that protects its body","collocations":["pet turtle","sea turtle","turtle shell"],"example":"We saw a sea turtle swimming near the reef.","exampleZh":"我們看見一隻海龜在珊瑚礁附近游泳。","synonyms":[],"level":1,"theme":"動物與植物","examples":[{"en":"We saw a sea turtle swimming near the reef.","zh":"我們看見一隻海龜在珊瑚礁附近游泳。"},{"en":"The tiny turtle hid inside its shell when we came close.","zh":"我們靠近時，那隻小烏龜縮進了牠的殼裡。"},{"en":"Volunteers help baby sea turtles reach the ocean safely.","zh":"志工幫助小海龜安全地回到海裡。"}]},{"word":"tutor","pos":"n. / v.","phonetic":"[ˈtutɚ]","meaning":"家教；輔導老師","definition":"a private teacher who teaches a single student or a small group","collocations":["private tutor","hire a tutor","tutor a student"],"example":"He hired a math tutor to help his son.","exampleZh":"他請了一位數學家教來輔導兒子。","synonyms":["instructor"],"level":3,"theme":"教育與學習","examples":[{"en":"He hired a math tutor to help his son.","zh":"他請了一位數學家教來輔導兒子。"},{"en":"She works as a private tutor to earn money for college.","zh":"她當家教賺錢來付大學的費用。"},{"en":"My older brother tutors me in chemistry every weekend.","zh":"我哥哥每個週末輔導我化學。"}]},{"word":"twelve","pos":"n. / adj.","phonetic":"[twɛlv]","meaning":"十二","definition":"the number equivalent to the product of three and four","collocations":["twelve months","twelve o'clock","twelve years old"],"example":"There are twelve months in a year.","exampleZh":"一年有十二個月。","synonyms":[],"level":1,"theme":"科學與數學","examples":[{"en":"There are twelve months in a year.","zh":"一年有十二個月。"},{"en":"The store closes at twelve o'clock every night.","zh":"這家店每晚十二點打烊。"},{"en":"My cousin started learning the violin when she was twelve years old.","zh":"我表妹十二歲時開始學小提琴。"}]},{"word":"twenty","pos":"n. / adj.","phonetic":"[ˈtwɛnti]","meaning":"二十","definition":"the number equivalent to two times ten","collocations":["twenty years","twenty percent","twenty minutes"],"example":"She turned twenty last week.","exampleZh":"她上週滿二十歲。","synonyms":[],"level":1,"theme":"科學與數學","examples":[{"en":"She turned twenty last week.","zh":"她上週滿二十歲。"},{"en":"The bus will arrive in about twenty minutes.","zh":"公車大約二十分鐘後會到。"},{"en":"The store is offering twenty percent off all winter coats.","zh":"這家店所有冬季大衣都減價百分之二十。"}]},{"word":"twice","pos":"adv.","phonetic":"[twaɪs]","meaning":"兩次；兩倍","definition":"two times","collocations":["twice a week","twice as much","think twice"],"example":"I go to the gym twice a week.","exampleZh":"我一週上健身房兩次。","synonyms":[],"level":1,"theme":"時間與空間","examples":[{"en":"I go to the gym twice a week.","zh":"我一週上健身房兩次。"},{"en":"You should think twice before spending all your savings.","zh":"在花光所有積蓄之前，你應該三思。"},{"en":"This bag can hold twice as much as my old one.","zh":"這個包包能裝的東西是我舊包包的兩倍。"}]},{"word":"twin","pos":"n. / adj.","phonetic":"[twɪn]","meaning":"雙胞胎；成對的","definition":"one of two children born to the same mother at the same time","collocations":["twin brother","identical twins","twin beds"],"example":"My sister and I are twins.","exampleZh":"我和我姊姊是雙胞胎。","synonyms":[],"level":2,"theme":"人物與家庭","examples":[{"en":"My sister and I are twins.","zh":"我和我姊姊是雙胞胎。"},{"en":"The hotel room had two comfortable twin beds by the window.","zh":"這間旅館房間在窗邊有兩張舒適的單人床。"},{"en":"The identical twins look so alike that even teachers confuse them.","zh":"這對同卵雙胞胎長得太像了，連老師都會認錯。"}]},{"word":"twinkle","pos":"v. / n.","phonetic":"[ˈtwɪŋkl̩]","meaning":"閃爍","definition":"to shine with a flickering or sparkling light","collocations":["stars twinkle","twinkle in one's eye","twinkling lights"],"example":"The stars twinkled brightly in the night sky.","exampleZh":"星星在夜空中閃爍著明亮的光芒。","synonyms":["sparkle","glitter"],"level":4,"theme":"自然與環境","examples":[{"en":"The stars twinkled brightly in the night sky.","zh":"星星在夜空中閃爍著明亮的光芒。"},{"en":"The city lights twinkled below us as the plane took off.","zh":"飛機起飛時，城市的燈光在我們下方閃爍。"},{"en":"There was a mischievous twinkle in the boy's eyes.","zh":"那男孩的眼中閃著調皮的光芒。"}]},{"word":"twist","pos":"v. / n.","phonetic":"[twɪst]","meaning":"扭轉；扭曲","definition":"to form into a bent, curling, or distorted shape","collocations":["twist one's ankle","plot twist","twist the cap"],"example":"She twisted her ankle while running.","exampleZh":"她跑步時扭傷了腳踝。","synonyms":["bend"],"level":3,"theme":"動作與行為","examples":[{"en":"She twisted her ankle while running.","zh":"她跑步時扭傷了腳踝。"},{"en":"The story has a surprising plot twist near the end.","zh":"這個故事在接近結尾時有個令人驚訝的轉折。"},{"en":"He twisted the cap tightly so the bottle would not leak.","zh":"他把瓶蓋轉緊，這樣瓶子就不會漏。"}]},{"word":"two","pos":"n. / adj.","phonetic":"[tu]","meaning":"二；兩個","definition":"the number equivalent to one plus one","collocations":["two of us","in two ways","two hundred"],"example":"I have two brothers.","exampleZh":"我有兩個兄弟。","synonyms":[],"level":1,"theme":"科學與數學","examples":[{"en":"I have two brothers.","zh":"我有兩個兄弟。"},{"en":"The two of us walked to school together every morning.","zh":"我們兩個每天早上一起走路上學。"},{"en":"There are two hundred pages left in this thick novel.","zh":"這本厚小說還剩下兩百頁。"}]},{"word":"type","pos":"n. / v.","phonetic":"[taɪp]","meaning":"類型；打字","definition":"a category of things having common characteristics; to write using a keyboard","collocations":["type of","type a letter","different types"],"example":"Please type your name on the form.","exampleZh":"請在表格上打上你的名字。","synonyms":["kind"],"level":1,"theme":"科技與媒體","examples":[{"en":"Please type your name on the form.","zh":"請在表格上打上你的名字。"},{"en":"The library has many different types of books for children.","zh":"這座圖書館有許多不同類型的兒童書籍。"},{"en":"She learned to type quickly without looking at the keyboard.","zh":"她學會了不看鍵盤就能快速打字。"}]},{"word":"typhoon","pos":"n.","phonetic":"[taɪˈfun]","meaning":"颱風","definition":"a violent tropical storm in the region of the Indian or western Pacific Ocean","collocations":["typhoon warning","typhoon season","a strong typhoon"],"example":"The typhoon caused severe flooding in the south.","exampleZh":"這場颱風在南部造成嚴重淹水。","synonyms":["hurricane"],"level":3,"theme":"天氣與季節","examples":[{"en":"The typhoon caused severe flooding in the south.","zh":"這場颱風在南部造成嚴重淹水。"},{"en":"Schools were closed because of the typhoon warning.","zh":"因為颱風警報，學校停課了。"},{"en":"During typhoon season, we always keep flashlights and water ready.","zh":"在颱風季節，我們總是備妥手電筒和水。"}]},{"word":"typical","pos":"adj.","phonetic":"[ˈtɪpɪkl̩]","meaning":"典型的；平常的","definition":"having the distinctive qualities of a particular type of person or thing","collocations":["typical example","a typical day","typical behavior"],"example":"That's typical of him to be late.","exampleZh":"他遲到真是他的典型作風。","synonyms":["standard"],"level":3,"theme":"性質與描述","examples":[{"en":"That's typical of him to be late.","zh":"他遲到真是他的典型作風。"},{"en":"On a typical day, she wakes up at six and jogs.","zh":"在平常的一天，她六點起床然後慢跑。"},{"en":"This painting is a typical example of the artist's early style.","zh":"這幅畫是這位藝術家早期風格的典型例子。"}]},{"word":"ugly","pos":"adj.","phonetic":"[ˈʌglɪ]","meaning":"醜陋的；難看的","definition":"unpleasant to look at","collocations":["ugly duckling","an ugly scar","ugly weather"],"example":"The old building looked ugly and abandoned.","exampleZh":"那棟老建築看起來又醜又荒廢。","synonyms":["hideous","unattractive"],"level":1,"theme":"性質與描述","examples":[{"en":"The old building looked ugly and abandoned.","zh":"那棟老建築看起來又醜又荒廢。"},{"en":"The accident left an ugly scar on his left arm.","zh":"那場意外在他的左臂上留下了一道難看的疤痕。"},{"en":"Nobody wanted to buy the house because of its ugly color.","zh":"因為那難看的顏色，沒有人想買那棟房子。"}]},{"word":"ultimate","pos":"adj.","phonetic":"[ˈʌltəmɪt]","meaning":"最終的；根本的","definition":"being the final or best of its kind","collocations":["ultimate goal","the ultimate decision","ultimate success"],"example":"Winning the championship is our ultimate goal.","exampleZh":"贏得冠軍是我們最終的目標。","synonyms":["final","supreme"],"level":4,"theme":"抽象概念","examples":[{"en":"Winning the championship is our ultimate goal.","zh":"贏得冠軍是我們最終的目標。"},{"en":"Her ultimate goal is to become a doctor and help the poor.","zh":"她的最終目標是成為醫生並幫助窮人。"},{"en":"The ultimate decision about the trip belongs to our parents.","zh":"關於這趟旅行的最終決定權在我們的父母手上。"}]},{"word":"ultimately","pos":"adv.","phonetic":"[ˈʌltəmɪtlɪ]","meaning":"最終；最後","definition":"in the end; finally","collocations":["ultimately fail","ultimately succeed","ultimately decide"],"example":"Ultimately, the choice is yours to make.","exampleZh":"最終，這個選擇由你來做。","synonyms":["eventually","finally"],"level":4,"theme":"時間與空間","examples":[{"en":"Ultimately, the choice is yours to make.","zh":"最終，這個選擇由你來做。"},{"en":"After many failures, the team ultimately succeeded in their experiment.","zh":"經過多次失敗，這個團隊最終在實驗中成功了。"},{"en":"Ultimately, it is your effort that decides your future.","zh":"最終，決定你未來的是你自己的努力。"}]},{"word":"umbrella","pos":"n.","phonetic":"[ʌmˈbrɛlə]","meaning":"雨傘","definition":"a device used for protection from rain","collocations":["open an umbrella","carry an umbrella","under an umbrella"],"example":"She forgot her umbrella and got soaked in the rain.","exampleZh":"她忘了帶傘，結果被雨淋濕了。","synonyms":[],"level":1,"theme":"居家與生活","examples":[{"en":"She forgot her umbrella and got soaked in the rain.","zh":"她忘了帶傘，結果被雨淋濕了。"},{"en":"Please open your umbrella; it has started to rain heavily.","zh":"請撐開你的傘，已經開始下大雨了。"},{"en":"We stood together under one umbrella at the bus stop.","zh":"我們在公車站一起躲在一把傘下。"}]},{"word":"unable","pos":"adj.","phonetic":"[ʌnˈebl̩]","meaning":"不能的；無法的","definition":"not having the ability or means to do something","collocations":["unable to attend","unable to move","unable to sleep"],"example":"He was unable to finish the race due to an injury.","exampleZh":"他因受傷無法完成比賽。","synonyms":["incapable"],"level":2,"theme":"抽象概念","examples":[{"en":"He was unable to finish the race due to an injury.","zh":"他因受傷無法完成比賽。"},{"en":"I was unable to sleep because of the noise next door.","zh":"因為隔壁的噪音，我無法入睡。"},{"en":"She was unable to attend the meeting due to a bad cold.","zh":"她因為重感冒無法出席會議。"}]},{"word":"unaware","pos":"adj.","phonetic":"[ʌnəˈwɛr]","meaning":"未察覺的；不知道的","definition":"not knowing about a situation or fact","collocations":["unaware of the danger","completely unaware","remain unaware"],"example":"She was unaware that her phone had been stolen.","exampleZh":"她沒有察覺自己的手機已被偷走。","synonyms":["ignorant","oblivious"],"level":4,"theme":"抽象概念","examples":[{"en":"She was unaware that her phone had been stolen.","zh":"她沒有察覺自己的手機已被偷走。"},{"en":"The hikers were completely unaware of the approaching storm.","zh":"那些登山客完全沒察覺暴風雨即將來臨。"},{"en":"He walked on, unaware that his wallet had fallen out.","zh":"他繼續往前走，沒發覺自己的錢包掉了出來。"}]},{"word":"uncertain","pos":"adj.","phonetic":"[ʌnˈsɝtn̩]","meaning":"不確定的；猶豫的","definition":"not known or definite; not sure","collocations":["uncertain future","feel uncertain","remain uncertain"],"example":"The future of the company remains uncertain.","exampleZh":"這家公司的未來仍不確定。","synonyms":["unsure","doubtful"],"level":3,"theme":"抽象概念","examples":[{"en":"The future of the company remains uncertain.","zh":"這家公司的未來仍不確定。"},{"en":"Many graduates feel uncertain about their future careers.","zh":"許多畢業生對自己未來的職涯感到不確定。"},{"en":"The result of the election remains uncertain tonight.","zh":"今晚選舉的結果仍不明朗。"}]},{"word":"uncle","pos":"n.","phonetic":"[ˈʌŋkl̩]","meaning":"叔叔；伯父；舅舅；姑丈；姨丈","definition":"the brother of one's father or mother, or the husband of one's aunt","collocations":["my uncle","uncle's house","visit an uncle"],"example":"My uncle taught me how to fish when I was young.","exampleZh":"我叔叔在我小時候教我如何釣魚。","synonyms":[],"level":1,"theme":"人物與家庭","examples":[{"en":"My uncle taught me how to fish when I was young.","zh":"我叔叔在我小時候教我如何釣魚。"},{"en":"We visited my uncle's house in the countryside last weekend.","zh":"上週末我們去了鄉下叔叔的家。"},{"en":"My uncle runs a small bakery near the train station.","zh":"我舅舅在火車站附近經營一家小麵包店。"}]},{"word":"uncomfortable","pos":"adj.","phonetic":"[ʌnˈkʌmfɚtəbl̩]","meaning":"不舒服的；不自在的","definition":"causing or feeling discomfort","collocations":["feel uncomfortable","an uncomfortable chair","uncomfortable silence"],"example":"The chair was too small and uncomfortable to sit on.","exampleZh":"那張椅子太小，坐起來不舒服。","synonyms":["uneasy"],"level":2,"theme":"身體與健康","examples":[{"en":"The chair was too small and uncomfortable to sit on.","zh":"那張椅子太小，坐起來不舒服。"},{"en":"There was an uncomfortable silence after his rude comment.","zh":"在他無禮的評論後，出現了一陣令人不自在的沉默。"},{"en":"The thick sweater made her feel hot and uncomfortable.","zh":"那件厚毛衣讓她覺得又熱又不舒服。"}]},{"word":"unconscious","pos":"adj.","phonetic":"[ʌnˈkɑnʃəs]","meaning":"失去知覺的；無意識的","definition":"not awake and aware of one's surroundings","collocations":["knock someone unconscious","remain unconscious","unconscious mind"],"example":"The driver was found unconscious after the accident.","exampleZh":"車禍後，這名駕駛被發現失去了知覺。","synonyms":["senseless"],"level":5,"theme":"身體與健康","examples":[{"en":"The driver was found unconscious after the accident.","zh":"車禍後，這名駕駛被發現失去了知覺。"},{"en":"The boxer was knocked unconscious in the final round.","zh":"那名拳擊手在最後一回合被擊昏了。"},{"en":"She remained unconscious for several hours after the surgery.","zh":"手術後她昏迷了好幾個小時。"}]},{"word":"under","pos":"prep.","phonetic":"[ˈʌndɚ]","meaning":"在……之下；少於","definition":"in or to a position below or lower than something","collocations":["under the table","under pressure","under control"],"example":"The cat is sleeping under the bed.","exampleZh":"貓正在床底下睡覺。","synonyms":["below"],"level":1,"theme":"時間與空間","examples":[{"en":"The cat is sleeping under the bed.","zh":"貓正在床底下睡覺。"},{"en":"The firefighters soon brought the flames under control.","zh":"消防員很快就把火勢控制住了。"},{"en":"He performs well even when he is under great pressure.","zh":"即使承受著巨大的壓力，他也表現得很好。"}]},{"word":"underground","pos":"adj. / adv.","phonetic":"[ˈʌndɚˌgraʊnd]","meaning":"地下的；祕密的","definition":"below the surface of the ground; hidden or secret","collocations":["underground tunnel","go underground","underground water"],"example":"Workers built a long underground tunnel for the subway.","exampleZh":"工人們為地鐵建造了一條長長的地下隧道。","synonyms":["subterranean"],"level":3,"theme":"交通與旅行","examples":[{"en":"Workers built a long underground tunnel for the subway.","zh":"工人們為地鐵建造了一條長長的地下隧道。"},{"en":"The old mine has a maze of underground tunnels.","zh":"這座舊礦坑有著如迷宮般的地下隧道。"},{"en":"The rebels went underground to avoid being arrested.","zh":"反抗者轉入地下活動以避免被逮捕。"}]},{"word":"underline","pos":"v. / n.","phonetic":"[ˈʌndɚˌlaɪn]","meaning":"在……下劃線；強調","definition":"to draw a line under a word or emphasize something","collocations":["underline a word","underline the importance","double underline"],"example":"Please underline the key words in each paragraph.","exampleZh":"請在每段的關鍵字下畫線。","synonyms":["emphasize"],"level":3,"theme":"教育與學習","examples":[{"en":"Please underline the key words in each paragraph.","zh":"請在每段的關鍵字下畫線。"},{"en":"The teacher told us to underline every verb in the sentence.","zh":"老師要我們在句子中的每個動詞下面劃線。"},{"en":"The tragic accident underlines the importance of wearing seat belts.","zh":"這場悲慘的意外凸顯了繫安全帶的重要性。"}]},{"word":"understand","pos":"v.","phonetic":"[ˌʌndɚˈstænd]","meaning":"了解；懂得","definition":"to grasp the meaning of something","collocations":["understand a concept","fully understand","hard to understand"],"example":"I don't fully understand the instructions.","exampleZh":"我不太懂這些指示。","synonyms":["comprehend"],"level":1,"theme":"教育與學習","examples":[{"en":"I don't fully understand the instructions.","zh":"我不太懂這些指示。"},{"en":"It took me a while to fully understand the new concept.","zh":"我花了一段時間才完全理解這個新概念。"},{"en":"Her handwriting is so messy that it is hard to understand.","zh":"她的字跡太潦草了，很難看懂。"}]},{"word":"understanding","pos":"n. / adj.","phonetic":"[ˌʌndɚˈstændɪŋ]","meaning":"理解；諒解；體諒的","definition":"the ability to understand something, or being sympathetic","collocations":["mutual understanding","reach an understanding","an understanding friend"],"example":"They finally reached a mutual understanding.","exampleZh":"他們終於達成了共識。","synonyms":["comprehension"],"level":3,"theme":"溝通與語言","examples":[{"en":"They finally reached a mutual understanding.","zh":"他們終於達成了共識。"},{"en":"A good teacher shows deep understanding of each student's needs.","zh":"一位好老師會對每個學生的需求展現深刻的理解。"},{"en":"My understanding boss let me leave early to see the doctor.","zh":"我那體貼的老闆讓我提早離開去看醫生。"}]},{"word":"undertake","pos":"v.","phonetic":"[ˌʌndɚˈtek]","meaning":"承擔；著手做","definition":"to commit to and start a task","collocations":["undertake a project","undertake a task","undertake responsibility"],"example":"The team will undertake a new research project.","exampleZh":"這個團隊將著手進行一項新的研究計畫。","synonyms":["carry out"],"level":5,"theme":"工作與職業","examples":[{"en":"The team will undertake a new research project.","zh":"這個團隊將著手進行一項新的研究計畫。"},{"en":"The young engineer agreed to undertake the challenging project alone.","zh":"那位年輕工程師同意獨自承擔這項艱鉅的計畫。"},{"en":"She undertook the responsibility of caring for her sick grandmother.","zh":"她承擔起照顧生病祖母的責任。"}]},{"word":"underwear","pos":"n.","phonetic":"[ˈʌndɚˌwɛr]","meaning":"內衣褲","definition":"clothing worn under other clothes, next to the skin","collocations":["a pair of underwear","change underwear","thermal underwear"],"example":"He packed extra underwear for the trip.","exampleZh":"他為這趟旅行多帶了幾件內衣褲。","synonyms":[],"level":2,"theme":"服裝與外表","examples":[{"en":"He packed extra underwear for the trip.","zh":"他為這趟旅行多帶了幾件內衣褲。"},{"en":"In winter, he wears thermal underwear to stay warm outside.","zh":"冬天時，他穿保暖內衣以在戶外保持溫暖。"},{"en":"Remember to pack enough clean underwear for the long trip.","zh":"記得為這趟長途旅行帶足夠的乾淨內衣褲。"}]},{"word":"undo","pos":"v.","phonetic":"[ʌnˈdu]","meaning":"解開；取消；撤銷","definition":"to reverse or untie something","collocations":["undo a button","undo the damage","undo an action"],"example":"She tried to undo the knot in her shoelace.","exampleZh":"她試著解開鞋帶上的結。","synonyms":["reverse","untie"],"level":3,"theme":"動作與行為","examples":[{"en":"She tried to undo the knot in her shoelace.","zh":"她試著解開鞋帶上的結。"},{"en":"If you make a mistake, just press this key to undo it.","zh":"如果你出錯了，只要按這個鍵就能撤銷。"},{"en":"Nothing can undo the damage caused by years of pollution.","zh":"沒有什麼能挽回多年污染所造成的傷害。"}]},{"word":"unemployed","pos":"adj.","phonetic":"[ˌʌnɪmˈplɔɪd]","meaning":"失業的","definition":"without a paid job but able to work","collocations":["unemployed workers","become unemployed","long-term unemployed"],"example":"He has been unemployed for six months.","exampleZh":"他已經失業六個月了。","synonyms":["jobless"],"level":4,"theme":"工作與職業","examples":[{"en":"He has been unemployed for six months.","zh":"他已經失業六個月了。"},{"en":"The factory closed, leaving hundreds of workers unemployed.","zh":"工廠關閉了，讓數百名工人失業。"},{"en":"The government offers free courses to help the unemployed find jobs.","zh":"政府提供免費課程來幫助失業者找工作。"}]},{"word":"unemployment","pos":"n.","phonetic":"[ˌʌnɪmˈplɔɪmənt]","meaning":"失業；失業率","definition":"the state of being without a job","collocations":["unemployment rate","rising unemployment","unemployment benefits"],"example":"The unemployment rate dropped last month.","exampleZh":"失業率上個月下降了。","synonyms":[],"level":4,"theme":"商業與金錢","examples":[{"en":"The unemployment rate dropped last month.","zh":"失業率上個月下降了。"},{"en":"Rising unemployment has become a serious problem in the region.","zh":"不斷上升的失業率已成為這個地區的嚴重問題。"},{"en":"He applied for unemployment benefits after losing his job.","zh":"失去工作後，他申請了失業補助。"}]},{"word":"unequal","pos":"adj.","phonetic":"[ʌnˈikwəl]","meaning":"不平等的；不相等的","definition":"not equal in amount, size, or status","collocations":["unequal distribution","unequal treatment","unequal rights"],"example":"The unequal distribution of wealth causes social problems.","exampleZh":"財富分配不均引發了社會問題。","synonyms":["uneven"],"level":5,"theme":"社會與文化","examples":[{"en":"The unequal distribution of wealth causes social problems.","zh":"財富分配不均引發了社會問題。"},{"en":"Workers protested against the unequal treatment in the company.","zh":"工人們抗議公司裡的不平等待遇。"},{"en":"The two boxes contain unequal amounts of sugar.","zh":"這兩個盒子裝著不相等分量的糖。"}]},{"word":"uneven","pos":"adj.","phonetic":"[ʌnˈivən]","meaning":"不平坦的；不均勻的","definition":"not level or smooth; not consistent","collocations":["uneven surface","uneven ground","uneven quality"],"example":"Be careful walking on the uneven road.","exampleZh":"走在那條不平坦的路上要小心。","synonyms":["irregular"],"level":4,"theme":"性質與描述","examples":[{"en":"Be careful walking on the uneven road.","zh":"走在那條不平坦的路上要小心。"},{"en":"It is hard to ride a bicycle on such uneven ground.","zh":"在這麼不平坦的地面上騎腳踏車很困難。"},{"en":"The handmade cups have an uneven but charming shape.","zh":"這些手工杯子的形狀不均勻，卻很有魅力。"}]},{"word":"unexpected","pos":"adj.","phonetic":"[ˌʌnɪkˈspɛktɪd]","meaning":"意外的；預料之外的","definition":"not expected or anticipated","collocations":["an unexpected visit","unexpected result","unexpected news"],"example":"We had an unexpected visit from our old friend.","exampleZh":"我們的老朋友意外來訪。","synonyms":["surprising"],"level":3,"theme":"情緒與感受","examples":[{"en":"We had an unexpected visit from our old friend.","zh":"我們的老朋友意外來訪。"},{"en":"The experiment produced an unexpected but exciting result.","zh":"這個實驗產生了一個意外但令人興奮的結果。"},{"en":"Her sudden resignation was unexpected news to everyone.","zh":"她突然的辭職對每個人來說都是意外的消息。"}]},{"word":"unfair","pos":"adj.","phonetic":"[ʌnˈfɛr]","meaning":"不公平的","definition":"not fair or just","collocations":["unfair treatment","unfair advantage","seem unfair"],"example":"It's unfair to blame him for everyone's mistakes.","exampleZh":"把大家的錯都怪在他身上是不公平的。","synonyms":["unjust"],"level":3,"theme":"社會與文化","examples":[{"en":"It's unfair to blame him for everyone's mistakes.","zh":"把大家的錯都怪在他身上是不公平的。"},{"en":"The students complained that the new rule was unfair.","zh":"學生們抱怨這條新規定不公平。"},{"en":"Using a hidden dictionary gave him an unfair advantage in the test.","zh":"使用藏起來的字典讓他在考試中占了不公平的便宜。"}]},{"word":"unfamiliar","pos":"adj.","phonetic":"[ˌʌnfəˈmɪljɚ]","meaning":"不熟悉的；陌生的","definition":"not known or recognized","collocations":["unfamiliar place","unfamiliar face","unfamiliar with"],"example":"I felt lost in the unfamiliar city.","exampleZh":"我在這座陌生的城市感到迷失。","synonyms":["strange"],"level":4,"theme":"性質與描述","examples":[{"en":"I felt lost in the unfamiliar city.","zh":"我在這座陌生的城市感到迷失。"},{"en":"She felt nervous walking alone through an unfamiliar neighborhood.","zh":"獨自走過一個陌生的社區，她感到緊張。"},{"en":"I am still unfamiliar with the software my new job uses.","zh":"我對新工作使用的軟體還不熟悉。"}]},{"word":"unfold","pos":"v.","phonetic":"[ʌnˈfold]","meaning":"展開；逐漸展現","definition":"to open out from a folded position; to develop gradually","collocations":["unfold a map","events unfold","unfold slowly"],"example":"She unfolded the map to find the shortest route.","exampleZh":"她展開地圖尋找最短的路線。","synonyms":["reveal"],"level":5,"theme":"動作與行為","examples":[{"en":"She unfolded the map to find the shortest route.","zh":"她展開地圖尋找最短的路線。"},{"en":"The exciting story unfolds slowly over the first few chapters.","zh":"這個精彩的故事在最初幾章中慢慢展開。"},{"en":"He unfolded the letter and began to read it aloud.","zh":"他攤開信，開始大聲朗讀。"}]},{"word":"unfortunate","pos":"adj.","phonetic":"[ʌnˈfɔrtʃənɪt]","meaning":"不幸的；令人遺憾的","definition":"having bad luck; regrettable","collocations":["unfortunate event","an unfortunate accident","unfortunate situation"],"example":"It was an unfortunate accident that no one could predict.","exampleZh":"那是一場沒人能預料到的不幸事故。","synonyms":["unlucky"],"level":4,"theme":"抽象概念","examples":[{"en":"It was an unfortunate accident that no one could predict.","zh":"那是一場沒人能預料到的不幸事故。"},{"en":"It was an unfortunate situation that nobody had planned for.","zh":"那是一個沒有人事先料想到的不幸情況。"},{"en":"Losing the championship by one point was truly unfortunate.","zh":"以一分之差輸掉冠軍實在令人遺憾。"}]},{"word":"unfortunately","pos":"adv.","phonetic":"[ʌnˈfɔrtʃənɪtlɪ]","meaning":"不幸地；可惜地","definition":"unluckily; regrettably","collocations":["unfortunately for us","but unfortunately","unfortunately not"],"example":"Unfortunately, the flight was canceled due to the storm.","exampleZh":"不幸的是，班機因暴風雨被取消了。","synonyms":["sadly"],"level":3,"theme":"抽象概念","examples":[{"en":"Unfortunately, the flight was canceled due to the storm.","zh":"不幸的是，班機因暴風雨被取消了。"},{"en":"We planned a picnic, but unfortunately it rained all day.","zh":"我們計畫了野餐，但可惜整天都在下雨。"},{"en":"Unfortunately, the last two tickets had already been sold.","zh":"不幸的是，最後兩張票已經賣完了。"}]},{"word":"unhappy","pos":"adj.","phonetic":"[ʌnˈhæpɪ]","meaning":"不快樂的；不滿意的","definition":"not happy; sad or dissatisfied","collocations":["feel unhappy","unhappy childhood","unhappy with"],"example":"She looked unhappy after hearing the news.","exampleZh":"聽到這個消息後，她看起來很不開心。","synonyms":["sad","miserable"],"level":1,"theme":"情緒與感受","examples":[{"en":"She looked unhappy after hearing the news.","zh":"聽到這個消息後，她看起來很不開心。"},{"en":"Customers were unhappy with the slow service at the restaurant.","zh":"顧客對這家餐廳緩慢的服務感到不滿意。"},{"en":"He felt unhappy after arguing with his best friend.","zh":"和最好的朋友吵架後，他感到不快樂。"}]},{"word":"uniform","pos":"n. / adj.","phonetic":"[ˈjunəˌfɔrm]","meaning":"制服；一致的","definition":"a distinctive set of clothes for members of a group; consistent","collocations":["school uniform","wear a uniform","uniform standard"],"example":"Students must wear their school uniform every day.","exampleZh":"學生每天都必須穿校服。","synonyms":["consistent"],"level":2,"theme":"服裝與外表","examples":[{"en":"Students must wear their school uniform every day.","zh":"學生每天都必須穿校服。"},{"en":"All the nurses in this hospital wear a blue uniform.","zh":"這家醫院所有的護理師都穿藍色制服。"},{"en":"The factory keeps a uniform standard for every product it makes.","zh":"這家工廠對它生產的每件產品都維持一致的標準。"}]},{"word":"union","pos":"n.","phonetic":"[ˈjunjən]","meaning":"聯盟；工會；結合","definition":"an act of joining or a group joined together, such as a labor union","collocations":["labor union","form a union","trade union"],"example":"Workers formed a union to protect their rights.","exampleZh":"工人們組成工會來保障自己的權益。","synonyms":["alliance"],"level":4,"theme":"社會與文化","examples":[{"en":"Workers formed a union to protect their rights.","zh":"工人們組成工會來保障自己的權益。"},{"en":"The workers joined the labor union to demand safer conditions.","zh":"工人們加入工會以要求更安全的工作環境。"},{"en":"The marriage was a happy union of two loving families.","zh":"這場婚姻是兩個充滿愛的家庭的幸福結合。"}]},{"word":"unique","pos":"adj.","phonetic":"[juˈnik]","meaning":"獨特的；獨一無二的","definition":"being the only one of its kind","collocations":["unique style","unique opportunity","truly unique"],"example":"Each snowflake has a unique pattern.","exampleZh":"每片雪花都有獨特的圖案。","synonyms":["distinctive"],"level":4,"theme":"性質與描述","examples":[{"en":"Each snowflake has a unique pattern.","zh":"每片雪花都有獨特的圖案。"},{"en":"The artist paints in a unique style that no one can copy.","zh":"這位藝術家以一種無人能模仿的獨特風格作畫。"},{"en":"Studying abroad is a unique opportunity to learn about other cultures.","zh":"出國留學是了解其他文化的難得機會。"}]},{"word":"unit","pos":"n.","phonetic":"[ˈjunɪt]","meaning":"單位；單元","definition":"a single, standard, or complete part of something larger","collocations":["a unit of measurement","study unit","housing unit"],"example":"This lesson is the first unit of the textbook.","exampleZh":"這一課是課本的第一單元。","synonyms":[],"level":2,"theme":"教育與學習","examples":[{"en":"This lesson is the first unit of the textbook.","zh":"這一課是課本的第一單元。"},{"en":"The meter is a common unit of measurement for length.","zh":"公尺是測量長度常用的單位。"},{"en":"We will finish the final unit of the textbook this week.","zh":"我們這週會完成課本的最後一個單元。"}]},{"word":"unite","pos":"v.","phonetic":"[juˈnaɪt]","meaning":"聯合；團結","definition":"to join together for a common purpose","collocations":["unite people","unite against","unite forces"],"example":"The two countries united to fight the common enemy.","exampleZh":"這兩個國家聯合起來對抗共同的敵人。","synonyms":["join","combine"],"level":4,"theme":"社會與文化","examples":[{"en":"The two countries united to fight the common enemy.","zh":"這兩個國家聯合起來對抗共同的敵人。"},{"en":"A common goal can unite people from very different backgrounds.","zh":"共同的目標能把來自不同背景的人們團結起來。"},{"en":"The villagers united to rebuild their homes after the flood.","zh":"村民們團結一致，在洪水過後重建他們的家園。"}]},{"word":"united","pos":"adj.","phonetic":"[juˈnaɪtɪd]","meaning":"聯合的；團結一致的","definition":"joined together by a common purpose","collocations":["a united team","stand united","united front"],"example":"The team remained united even after losing the game.","exampleZh":"即使輸了比賽，這支隊伍依然團結一致。","synonyms":["unified"],"level":3,"theme":"社會與文化","examples":[{"en":"The team remained united even after losing the game.","zh":"即使輸了比賽，這支隊伍依然團結一致。"},{"en":"A united team can overcome even the strongest opponents.","zh":"一支團結的隊伍即使面對最強的對手也能克服。"},{"en":"The workers stood united in their demand for fair pay.","zh":"工人們團結一致地要求合理的薪資。"}]},{"word":"universal","pos":"adj.","phonetic":"[ˌjunəˈvɝsl̩]","meaning":"普遍的；宇宙的；通用的","definition":"applicable to all cases or affecting everyone","collocations":["universal truth","universal language","universal access"],"example":"Music is often called a universal language.","exampleZh":"音樂常被稱為一種通用的語言。","synonyms":["global"],"level":5,"theme":"抽象概念","examples":[{"en":"Music is often called a universal language.","zh":"音樂常被稱為一種通用的語言。"},{"en":"Kindness is a universal value understood in every culture.","zh":"善良是每個文化都能理解的普世價值。"},{"en":"The charity works for universal access to clean drinking water.","zh":"這個慈善機構致力於讓所有人都能取得乾淨的飲用水。"}]},{"word":"universe","pos":"n.","phonetic":"[ˈjunəˌvɝs]","meaning":"宇宙","definition":"all existing matter and space considered as a whole","collocations":["the whole universe","explore the universe","origin of the universe"],"example":"Scientists still don't know how the universe began.","exampleZh":"科學家仍不知道宇宙是如何開始的。","synonyms":["cosmos"],"level":3,"theme":"科學與數學","examples":[{"en":"Scientists still don't know how the universe began.","zh":"科學家仍不知道宇宙是如何開始的。"},{"en":"Scientists build powerful telescopes to explore the distant universe.","zh":"科學家建造強大的望遠鏡來探索遙遠的宇宙。"},{"en":"To her, family means more than anything else in the universe.","zh":"對她而言，家人比宇宙中任何事物都重要。"}]},{"word":"university","pos":"n.","phonetic":"[ˌjunəˈvɝsətɪ]","meaning":"大學","definition":"an institution of higher education","collocations":["attend university","university degree","apply to university"],"example":"She is studying law at a famous university.","exampleZh":"她在一所知名大學攻讀法律。","synonyms":[],"level":1,"theme":"教育與學習","examples":[{"en":"She is studying law at a famous university.","zh":"她在一所知名大學攻讀法律。"},{"en":"He plans to apply to a university that offers marine biology.","zh":"他打算申請一所有海洋生物學的大學。"},{"en":"A university degree can open many doors in your career.","zh":"大學學位能為你的職涯打開許多扇門。"}]},{"word":"unkind","pos":"adj.","phonetic":"[ʌnˈkaɪnd]","meaning":"不友善的；刻薄的","definition":"not kind; unfriendly or unpleasant","collocations":["unkind words","unkind remark","unkind to someone"],"example":"It was unkind of him to laugh at her mistake.","exampleZh":"他嘲笑她的錯誤，這樣做很不友善。","synonyms":["cruel","unfriendly"],"level":2,"theme":"情緒與感受","examples":[{"en":"It was unkind of him to laugh at her mistake.","zh":"他嘲笑她的錯誤，這樣做很不友善。"},{"en":"His unkind words hurt her feelings deeply.","zh":"他刻薄的話深深傷了她的感情。"},{"en":"It is unkind to make fun of people who are different.","zh":"取笑與眾不同的人是很不友善的。"}]},{"word":"unknown","pos":"adj. / n.","phonetic":"[ʌnˈnon]","meaning":"未知的；不出名的","definition":"not known or familiar","collocations":["unknown artist","unknown reason","venture into the unknown"],"example":"The cause of the fire remains unknown.","exampleZh":"火災的原因仍然不明。","synonyms":["unfamiliar"],"level":2,"theme":"抽象概念","examples":[{"en":"The cause of the fire remains unknown.","zh":"火災的原因仍然不明。"},{"en":"For some unknown reason, the machine suddenly stopped working.","zh":"因為某種未知的原因，這台機器突然停止運作。"},{"en":"Brave explorers often venture into the unknown to make discoveries.","zh":"勇敢的探險家經常闖入未知的領域以求發現。"}]},{"word":"unless","pos":"conj.","phonetic":"[ənˈlɛs]","meaning":"除非","definition":"except on the condition that","collocations":["unless otherwise noted","unless you agree","unless it rains"],"example":"We won't go hiking unless the weather improves.","exampleZh":"除非天氣好轉，否則我們不會去健行。","synonyms":["except if"],"level":2,"theme":"溝通與語言","examples":[{"en":"We won't go hiking unless the weather improves.","zh":"除非天氣好轉，否則我們不會去健行。"},{"en":"We will hold the sports day outdoors unless it rains.","zh":"除非下雨，否則我們會在戶外舉行運動會。"},{"en":"You cannot enter the lab unless you wear safety glasses.","zh":"除非你戴上護目鏡，否則不能進入實驗室。"}]},{"word":"unlike","pos":"prep. / adj.","phonetic":"[ʌnˈlaɪk]","meaning":"不像；與……不同","definition":"different from; not like","collocations":["unlike his brother","unlike before","quite unlike"],"example":"Unlike her sister, she loves spicy food.","exampleZh":"和她姊姊不同，她喜歡辣的食物。","synonyms":["different from"],"level":2,"theme":"性質與描述","examples":[{"en":"Unlike her sister, she loves spicy food.","zh":"和她姊姊不同，她喜歡辣的食物。"},{"en":"Unlike most cats, this one actually enjoys swimming in water.","zh":"不像大多數的貓，這隻貓其實喜歡在水裡游泳。"},{"en":"Unlike his quiet brother, he loves talking to strangers.","zh":"不像他文靜的哥哥，他喜歡和陌生人交談。"}]},{"word":"unlikely","pos":"adj.","phonetic":"[ʌnˈlaɪklɪ]","meaning":"不太可能的","definition":"not likely to happen or be true","collocations":["unlikely event","highly unlikely","unlikely to succeed"],"example":"It is unlikely to rain this afternoon.","exampleZh":"今天下午不太可能會下雨。","synonyms":["improbable"],"level":4,"theme":"抽象概念","examples":[{"en":"It is unlikely to rain this afternoon.","zh":"今天下午不太可能會下雨。"},{"en":"It is highly unlikely that he will change his mind now.","zh":"他現在極不可能改變主意。"},{"en":"Without more practice, the team is unlikely to win the contest.","zh":"沒有更多練習，這支隊伍不太可能贏得比賽。"}]},{"word":"unload","pos":"v.","phonetic":"[ʌnˈlod]","meaning":"卸貨；卸下","definition":"to remove goods from a vehicle or container","collocations":["unload cargo","unload a truck","unload luggage"],"example":"The workers unloaded the boxes from the truck.","exampleZh":"工人們把箱子從卡車上卸下來。","synonyms":["unpack"],"level":3,"theme":"交通與旅行","examples":[{"en":"The workers unloaded the boxes from the truck.","zh":"工人們把箱子從卡車上卸下來。"},{"en":"It took two hours to unload all the cargo from the ship.","zh":"從船上卸下所有貨物花了兩個小時。"},{"en":"The driver helped us unload our luggage at the hotel.","zh":"司機幫我們在旅館卸下行李。"}]},{"word":"unlock","pos":"v.","phonetic":"[ʌnˈlɑk]","meaning":"開鎖；解開","definition":"to open something using a key or code","collocations":["unlock a door","unlock your phone","unlock potential"],"example":"She used her key to unlock the front door.","exampleZh":"她用鑰匙打開前門的鎖。","synonyms":["open"],"level":2,"theme":"動作與行為","examples":[{"en":"She used her key to unlock the front door.","zh":"她用鑰匙打開前門的鎖。"},{"en":"A good coach can unlock the hidden potential in young players.","zh":"一位好的教練能激發年輕球員身上隱藏的潛能。"},{"en":"She forgot the code and could not unlock her phone.","zh":"她忘了密碼，無法解鎖她的手機。"}]},{"word":"unlucky","pos":"adj.","phonetic":"[ʌnˈlʌkɪ]","meaning":"不幸運的；倒楣的","definition":"having or bringing bad luck","collocations":["unlucky number","unlucky day","feel unlucky"],"example":"Thirteen is considered an unlucky number in some cultures.","exampleZh":"在某些文化中，十三被認為是不吉利的數字。","synonyms":["unfortunate"],"level":2,"theme":"抽象概念","examples":[{"en":"Thirteen is considered an unlucky number in some cultures.","zh":"在某些文化中，十三被認為是不吉利的數字。"},{"en":"It was an unlucky day; he missed the bus and lost his wallet.","zh":"那真是倒楣的一天，他錯過了公車還弄丟了錢包。"},{"en":"Some people avoid the number four because they think it is unlucky.","zh":"有些人避開數字四，因為他們認為那不吉利。"}]},{"word":"unnecessary","pos":"adj.","phonetic":"[ʌnˈnɛsəˌsɛrɪ]","meaning":"不必要的","definition":"not needed; more than is required","collocations":["unnecessary risk","unnecessary expense","cause unnecessary trouble"],"example":"Try to avoid unnecessary expenses this month.","exampleZh":"這個月試著避免不必要的開銷。","synonyms":["needless"],"level":4,"theme":"抽象概念","examples":[{"en":"Try to avoid unnecessary expenses this month.","zh":"這個月試著避免不必要的開銷。"},{"en":"Driving too fast takes an unnecessary risk with everyone's safety.","zh":"開太快是拿大家的安全冒不必要的險。"},{"en":"We cut several unnecessary expenses to save more money.","zh":"我們刪減了幾項不必要的開支以存更多的錢。"}]},{"word":"unpleasant","pos":"adj.","phonetic":"[ʌnˈplɛzn̩t]","meaning":"令人不愉快的","definition":"causing discomfort or dislike","collocations":["unpleasant smell","unpleasant experience","unpleasant surprise"],"example":"There was an unpleasant smell coming from the kitchen.","exampleZh":"廚房傳來一股令人不快的氣味。","synonyms":["disagreeable"],"level":3,"theme":"情緒與感受","examples":[{"en":"There was an unpleasant smell coming from the kitchen.","zh":"廚房傳來一股令人不快的氣味。"},{"en":"Being caught in the crowded train was an unpleasant experience.","zh":"被困在擁擠的火車裡是個不愉快的經驗。"},{"en":"An unpleasant smell came from the forgotten lunch box.","zh":"那個被遺忘的便當盒發出一股難聞的氣味。"}]},{"word":"unpopular","pos":"adj.","phonetic":"[ʌnˈpɑpjəlɚ]","meaning":"不受歡迎的","definition":"not liked by many people","collocations":["unpopular decision","unpopular opinion","become unpopular"],"example":"The new policy proved to be very unpopular.","exampleZh":"這項新政策證實非常不受歡迎。","synonyms":["disliked"],"level":4,"theme":"社會與文化","examples":[{"en":"The new policy proved to be very unpopular.","zh":"這項新政策證實非常不受歡迎。"},{"en":"The principal made the unpopular decision to shorten summer vacation.","zh":"校長做了縮短暑假這個不受歡迎的決定。"},{"en":"He is not afraid to share an unpopular opinion in class.","zh":"他不害怕在課堂上發表不受歡迎的意見。"}]},{"word":"until","pos":"prep. / conj.","phonetic":"[ənˈtɪl]","meaning":"直到……為止","definition":"up to the point in time or the event mentioned","collocations":["until now","wait until","until further notice"],"example":"We waited until the rain stopped.","exampleZh":"我們一直等到雨停了。","synonyms":["till"],"level":1,"theme":"時間與空間","examples":[{"en":"We waited until the rain stopped.","zh":"我們一直等到雨停了。"},{"en":"The library will remain closed until further notice.","zh":"圖書館將暫停開放，直到另行通知為止。"},{"en":"Please wait here until the doctor calls your name.","zh":"請在這裡等候，直到醫生叫到你的名字。"}]},{"word":"unusual","pos":"adj.","phonetic":"[ʌnˈjuʒʊəl]","meaning":"不尋常的；罕見的","definition":"not common or ordinary","collocations":["unusual weather","unusual behavior","rather unusual"],"example":"It's unusual for him to be late for school.","exampleZh":"他上學遲到是很不尋常的事。","synonyms":["uncommon"],"level":2,"theme":"性質與描述","examples":[{"en":"It's unusual for him to be late for school.","zh":"他上學遲到是很不尋常的事。"},{"en":"We had unusual weather this winter, with almost no rain.","zh":"今年冬天天氣很反常，幾乎沒有下雨。"},{"en":"The cat's unusual behavior worried its owner.","zh":"那隻貓不尋常的行為讓主人擔心。"}]},{"word":"unwilling","pos":"adj.","phonetic":"[ʌnˈwɪlɪŋ]","meaning":"不情願的","definition":"not willing to do something","collocations":["unwilling to help","unwilling participant","seem unwilling"],"example":"He seemed unwilling to share his opinion.","exampleZh":"他似乎不太願意分享自己的意見。","synonyms":["reluctant"],"level":4,"theme":"情緒與感受","examples":[{"en":"He seemed unwilling to share his opinion.","zh":"他似乎不太願意分享自己的意見。"},{"en":"The tired child was unwilling to go to bed early.","zh":"那個疲倦的孩子不情願早早上床睡覺。"},{"en":"He seemed unwilling to answer any questions about the accident.","zh":"他似乎不願意回答任何關於那場意外的問題。"}]},{"word":"unwrap","pos":"v.","phonetic":"[ʌnˈræp]","meaning":"打開包裝；拆開","definition":"to remove the covering from something","collocations":["unwrap a gift","unwrap a present","unwrap candy"],"example":"The children rushed to unwrap their presents.","exampleZh":"孩子們爭先恐後地拆開禮物。","synonyms":["open"],"level":2,"theme":"動作與行為","examples":[{"en":"The children rushed to unwrap their presents.","zh":"孩子們爭先恐後地拆開禮物。"},{"en":"She slowly unwrapped the gift, trying not to tear the paper.","zh":"她慢慢地拆開禮物，盡量不撕破包裝紙。"},{"en":"The toddler unwrapped the candy and popped it into his mouth.","zh":"那個小孩剝開糖果，把它塞進嘴裡。"}]},{"word":"up","pos":"adv. / prep. / adj.","phonetic":"[ʌp]","meaning":"向上；起床；升高","definition":"toward a higher place or position","collocations":["stand up","get up","go up"],"example":"Please stand up when the teacher enters the room.","exampleZh":"老師進教室時請起立。","synonyms":[],"level":1,"theme":"動作與行為","examples":[{"en":"Please stand up when the teacher enters the room.","zh":"老師進教室時請起立。"},{"en":"He gets up early every morning to jog around the park.","zh":"他每天早上早起繞著公園慢跑。"},{"en":"The price of vegetables went up sharply after the storm.","zh":"暴風雨過後，蔬菜的價格急劇上升。"}]},{"word":"update","pos":"v. / n.","phonetic":"[ˌʌpˈdet]","meaning":"更新；最新消息","definition":"to make something more modern or add the latest information","collocations":["update software","give an update","regularly update"],"example":"Please update your app to the latest version.","exampleZh":"請將你的應用程式更新到最新版本。","synonyms":["renew"],"level":3,"theme":"科技與媒體","examples":[{"en":"Please update your app to the latest version.","zh":"請將你的應用程式更新到最新版本。"},{"en":"The teacher promised to update us on the exam results by Friday.","zh":"老師答應在星期五前告訴我們考試成績的最新消息。"},{"en":"We should regularly update the club website with new photos.","zh":"我們應該定期用新照片更新社團網站。"}]},{"word":"upgrade","pos":"v. / n.","phonetic":"[ʌpˈgred]","meaning":"升級；提升","definition":"to improve the quality or value of something","collocations":["upgrade a computer","free upgrade","upgrade the system"],"example":"We decided to upgrade our computer system.","exampleZh":"我們決定升級我們的電腦系統。","synonyms":["improve"],"level":4,"theme":"科技與媒體","examples":[{"en":"We decided to upgrade our computer system.","zh":"我們決定升級我們的電腦系統。"},{"en":"My parents plan to upgrade my old laptop before the new semester.","zh":"我父母打算在新學期開始前把我的舊筆電升級。"},{"en":"The airline offered her a free upgrade to business class.","zh":"航空公司提供她免費升等到商務艙。"}]},{"word":"uphold","pos":"v.","phonetic":"[ʌpˈhold]","meaning":"支持；維護；堅持","definition":"to support or maintain something, especially a law or decision","collocations":["uphold the law","uphold justice","uphold a decision"],"example":"The court decided to uphold the original ruling.","exampleZh":"法院決定維持原判決。","synonyms":["maintain"],"level":6,"theme":"政治與法律","examples":[{"en":"The court decided to uphold the original ruling.","zh":"法院決定維持原判決。"},{"en":"A good judge must always uphold the law fairly.","zh":"一位好的法官必須始終公正地維護法律。"},{"en":"The school works hard to uphold justice among its students.","zh":"這所學校努力在學生之間維護正義。"}]},{"word":"upload","pos":"v. / n.","phonetic":"[ʌpˈlod]","meaning":"上傳","definition":"to transfer data to a larger computer system or the internet","collocations":["upload a video","upload photos","upload to the cloud"],"example":"She uploaded the photos to her social media account.","exampleZh":"她把照片上傳到自己的社群媒體帳號。","synonyms":[],"level":3,"theme":"科技與媒體","examples":[{"en":"She uploaded the photos to her social media account.","zh":"她把照片上傳到自己的社群媒體帳號。"},{"en":"Please upload your homework to the cloud before midnight.","zh":"請在午夜前把你的作業上傳到雲端。"},{"en":"It took an hour to upload the long video to the website.","zh":"把這段長影片上傳到網站花了一個小時。"}]},{"word":"upon","pos":"prep.","phonetic":"[əˈpɑn]","meaning":"在……之上；一……就","definition":"on; used similarly to 'on' but more formal","collocations":["upon arrival","once upon a time","depend upon"],"example":"Once upon a time, there lived a kind old man.","exampleZh":"從前，有一位善良的老人。","synonyms":["on"],"level":3,"theme":"時間與空間","examples":[{"en":"Once upon a time, there lived a kind old man.","zh":"從前，有一位善良的老人。"},{"en":"Upon arrival at the airport, we searched for our tour guide.","zh":"一抵達機場，我們就開始尋找我們的導遊。"},{"en":"The success of the project depends upon everyone's cooperation.","zh":"這個計畫的成功取決於每個人的合作。"}]},{"word":"upper","pos":"adj.","phonetic":"[ˈʌpɚ]","meaning":"上面的；較高的","definition":"situated above another part","collocations":["upper floor","upper class","upper body"],"example":"Our office is on the upper floor of the building.","exampleZh":"我們的辦公室在這棟大樓的較高樓層。","synonyms":["higher"],"level":2,"theme":"時間與空間","examples":[{"en":"Our office is on the upper floor of the building.","zh":"我們的辦公室在這棟大樓的較高樓層。"},{"en":"He injured his upper arm while playing basketball yesterday.","zh":"他昨天打籃球時傷到了上臂。"},{"en":"The library is located on the upper floor of the building.","zh":"圖書館位於這棟建築物的樓上。"}]},{"word":"upright","pos":"adj. / adv.","phonetic":"[ˈʌpˌraɪt]","meaning":"直立的；正直的","definition":"vertical or in a standing position; honest","collocations":["stand upright","upright position","upright citizen"],"example":"Please keep your seat upright during landing.","exampleZh":"降落時請將座椅豎直。","synonyms":["vertical","honest"],"level":5,"theme":"性質與描述","examples":[{"en":"Please keep your seat upright during landing.","zh":"降落時請將座椅豎直。"},{"en":"Please sit upright in your chair while writing the test.","zh":"寫測驗時請在椅子上坐直。"},{"en":"Everyone respected him as an honest and upright citizen.","zh":"大家都尊敬他是個誠實正直的公民。"}]},{"word":"upset","pos":"adj. / v.","phonetic":"[ʌpˈsɛt]","meaning":"心煩的；使不安；打翻","definition":"unhappy or worried; to make someone unhappy","collocations":["upset stomach","get upset","upset the balance"],"example":"She was upset after losing her favorite necklace.","exampleZh":"她弄丟了心愛的項鍊，感到很難過。","synonyms":["disturbed"],"level":3,"theme":"情緒與感受","examples":[{"en":"She was upset after losing her favorite necklace.","zh":"她弄丟了心愛的項鍊，感到很難過。"},{"en":"Eating too much greasy food gave me an upset stomach.","zh":"吃太多油膩的食物讓我腸胃不適。"},{"en":"Don't get upset over such a small mistake.","zh":"別為了這麼小的錯誤而心煩。"}]},{"word":"upside","pos":"n.","phonetic":"[ˈʌpˌsaɪd]","meaning":"優點；正面；好處","definition":"the positive aspect of a situation","collocations":["the upside of","see the upside","a hidden upside"],"example":"The upside of working from home is having more free time.","exampleZh":"在家工作的好處是有更多的自由時間。","synonyms":["advantage"],"level":4,"theme":"抽象概念","examples":[{"en":"The upside of working from home is having more free time.","zh":"在家工作的好處是有更多的自由時間。"},{"en":"The upside of losing the game is that we learned a lot.","zh":"輸掉比賽的好處是我們學到了很多。"},{"en":"Try to see the upside even when things go wrong.","zh":"即使事情出錯，也要試著看見正面的一面。"}]},{"word":"upstairs","pos":"adv. / adj. / n.","phonetic":"[ˈʌpˈstɛrz]","meaning":"樓上","definition":"on or to a higher floor of a building","collocations":["go upstairs","upstairs room","live upstairs"],"example":"My bedroom is upstairs on the second floor.","exampleZh":"我的臥室在樓上二樓。","synonyms":[],"level":1,"theme":"居家與生活","examples":[{"en":"My bedroom is upstairs on the second floor.","zh":"我的臥室在樓上二樓。"},{"en":"I heard footsteps upstairs late last night.","zh":"昨晚很晚時我聽見樓上有腳步聲。"},{"en":"She ran upstairs to grab her forgotten umbrella.","zh":"她跑上樓去拿她忘記的雨傘。"}]},{"word":"upward","pos":"adv. / adj.","phonetic":"[ˈʌpwɚd]","meaning":"向上地；向上的","definition":"moving or pointing toward a higher position","collocations":["upward trend","move upward","upward spiral"],"example":"Sales showed an upward trend this quarter.","exampleZh":"這一季的銷售呈現上升的趨勢。","synonyms":["rising"],"level":4,"theme":"時間與空間","examples":[{"en":"Sales showed an upward trend this quarter.","zh":"這一季的銷售呈現上升的趨勢。"},{"en":"The balloon drifted slowly upward into the clear sky.","zh":"氣球緩緩地向上飄進晴朗的天空。"},{"en":"The number of online shoppers continues its upward trend.","zh":"網路購物者的數量持續呈現向上的趨勢。"}]},{"word":"urban","pos":"adj.","phonetic":"[ˈɝbən]","meaning":"都市的；城市的","definition":"relating to a city or densely populated area","collocations":["urban area","urban life","urban development"],"example":"Urban areas are growing rapidly around the world.","exampleZh":"世界各地的都市地區都在迅速發展。","synonyms":["metropolitan"],"level":5,"theme":"社會與文化","examples":[{"en":"Urban areas are growing rapidly around the world.","zh":"世界各地的都市地區都在迅速發展。"},{"en":"Many young people move to urban areas to find jobs.","zh":"許多年輕人搬到都市地區找工作。"},{"en":"Urban life can be exciting but also very stressful.","zh":"都市生活可能令人興奮，但也非常有壓力。"}]},{"word":"urge","pos":"v. / n.","phonetic":"[ɝdʒ]","meaning":"敦促；力勸；衝動","definition":"to strongly encourage someone to do something; a strong desire","collocations":["urge someone to","feel an urge","urge caution"],"example":"The doctor urged him to quit smoking.","exampleZh":"醫生力勸他戒菸。","synonyms":["encourage","push"],"level":4,"theme":"溝通與語言","examples":[{"en":"The doctor urged him to quit smoking.","zh":"醫生力勸他戒菸。"},{"en":"Teachers often urge students to read more books.","zh":"老師常常力勸學生多讀書。"},{"en":"I felt a sudden urge to call my grandmother.","zh":"我突然有股衝動想打電話給我的祖母。"}]},{"word":"urgent","pos":"adj.","phonetic":"[ˈɝdʒənt]","meaning":"緊急的；急迫的","definition":"requiring immediate action or attention","collocations":["urgent matter","urgent message","urgent care"],"example":"This is an urgent matter that needs your attention.","exampleZh":"這是一件需要你立刻處理的緊急事務。","synonyms":["pressing"],"level":3,"theme":"抽象概念","examples":[{"en":"This is an urgent matter that needs your attention.","zh":"這是一件需要你立刻處理的緊急事務。"},{"en":"She received an urgent message asking her to come home.","zh":"她收到一則緊急訊息，要她回家。"},{"en":"The injured hiker was rushed to urgent care.","zh":"受傷的登山客被緊急送去急診照護。"}]},{"word":"usage","pos":"n.","phonetic":"[ˈjusɪdʒ]","meaning":"使用；用法","definition":"the way in which something is used","collocations":["language usage","water usage","common usage"],"example":"This dictionary explains the correct usage of each word.","exampleZh":"這本字典解釋了每個單字的正確用法。","synonyms":["use"],"level":5,"theme":"溝通與語言","examples":[{"en":"This dictionary explains the correct usage of each word.","zh":"這本字典解釋了每個單字的正確用法。"},{"en":"The city is trying to reduce water usage this summer.","zh":"這座城市正試圖在今年夏天減少用水量。"},{"en":"Correct grammar usage is important in formal writing.","zh":"正確的文法用法在正式寫作中很重要。"}]},{"word":"use","pos":"v. / n.","phonetic":"[juz]","meaning":"使用；利用","definition":"to take, employ, or apply something for a purpose","collocations":["use a tool","make use of","for personal use"],"example":"You can use my computer if you need to.","exampleZh":"如果你需要，可以用我的電腦。","synonyms":["utilize"],"level":1,"theme":"動作與行為","examples":[{"en":"You can use my computer if you need to.","zh":"如果你需要，可以用我的電腦。"},{"en":"Farmers use modern tools to harvest their crops faster.","zh":"農夫使用現代工具更快地收割作物。"},{"en":"This room is reserved for personal use only.","zh":"這個房間僅供個人使用。"}]},{"word":"used","pos":"adj.","phonetic":"[juzd]","meaning":"習慣於；二手的","definition":"accustomed to something; previously owned","collocations":["used to","used car","get used to"],"example":"I'm not used to waking up so early.","exampleZh":"我還不習慣這麼早起床。","synonyms":["accustomed"],"level":1,"theme":"抽象概念","examples":[{"en":"I'm not used to waking up so early.","zh":"我還不習慣這麼早起床。"},{"en":"My brother bought a used car at a fair price.","zh":"我哥哥以合理的價格買了一輛二手車。"},{"en":"It took me weeks to get used to the new school.","zh":"我花了好幾週才習慣這所新學校。"}]},{"word":"useful","pos":"adj.","phonetic":"[ˈjusfl̩]","meaning":"有用的","definition":"able to be used effectively","collocations":["useful information","useful tool","find useful"],"example":"This app provides very useful information for travelers.","exampleZh":"這個應用程式為旅客提供了非常實用的資訊。","synonyms":["helpful"],"level":1,"theme":"性質與描述","examples":[{"en":"This app provides very useful information for travelers.","zh":"這個應用程式為旅客提供了非常實用的資訊。"},{"en":"The teacher shared some useful tips for the exam.","zh":"老師分享了一些對考試有用的訣竅。"},{"en":"I found this website extremely useful for my research.","zh":"我發現這個網站對我的研究極為有用。"}]},{"word":"useless","pos":"adj.","phonetic":"[ˈjuslɪs]","meaning":"無用的；沒有效果的","definition":"not effective or serving a purpose","collocations":["useless information","feel useless","completely useless"],"example":"Without electricity, the machine is useless.","exampleZh":"沒有電力，這台機器就沒有用了。","synonyms":["worthless"],"level":2,"theme":"性質與描述","examples":[{"en":"Without electricity, the machine is useless.","zh":"沒有電力，這台機器就沒有用了。"},{"en":"A broken umbrella is completely useless in a storm.","zh":"一把壞掉的雨傘在暴風雨中完全沒用。"},{"en":"He felt useless because he couldn't help his friends.","zh":"他覺得自己沒用，因為他幫不上朋友的忙。"}]},{"word":"user","pos":"n.","phonetic":"[ˈjuzɚ]","meaning":"使用者","definition":"a person who uses something, such as a product or service","collocations":["internet user","user-friendly","daily user"],"example":"This software is designed to be simple for new users.","exampleZh":"這個軟體設計得對新使用者來說很簡單。","synonyms":[],"level":2,"theme":"科技與媒體","examples":[{"en":"This software is designed to be simple for new users.","zh":"這個軟體設計得對新使用者來說很簡單。"},{"en":"Every internet user should protect their personal password.","zh":"每位網路使用者都應該保護自己的個人密碼。"},{"en":"The app is popular because it is so user-friendly.","zh":"這個應用程式很受歡迎，因為它非常容易使用。"}]},{"word":"usual","pos":"adj.","phonetic":"[ˈjuʒʊəl]","meaning":"通常的；平常的","definition":"habitually or commonly occurring","collocations":["as usual","usual routine","the usual place"],"example":"He arrived late, as usual.","exampleZh":"他和往常一樣遲到了。","synonyms":["normal","typical"],"level":2,"theme":"抽象概念","examples":[{"en":"He arrived late, as usual.","zh":"他和往常一樣遲到了。"},{"en":"We met at the usual place near the bus stop.","zh":"我們在公車站附近老地方碰面。"},{"en":"She followed her usual routine before going to bed.","zh":"睡覺前她照著平常的習慣做事。"}]},{"word":"usually","pos":"adv.","phonetic":"[ˈjuʒʊəlɪ]","meaning":"通常;一般而言","definition":"under normal conditions; generally","collocations":["usually go","usually happens","not usually"],"example":"I usually get up at seven o'clock.","exampleZh":"我通常七點起床。","synonyms":["generally"],"level":1,"theme":"時間與空間","examples":[{"en":"I usually get up at seven o'clock.","zh":"我通常七點起床。"},{"en":"My family usually eats dinner together at seven.","zh":"我的家人通常在七點一起吃晚餐。"},{"en":"It does not usually snow in this part of the country.","zh":"這個國家的這個地區通常不會下雪。"}]},{"word":"utility","pos":"n.","phonetic":"[juˈtɪlətɪ]","meaning":"實用性；公用事業","definition":"the state of being useful, or public services like water and electricity","collocations":["utility bill","public utility","utility company"],"example":"The utility bill increased sharply this winter.","exampleZh":"這個冬天，公用事業費用大幅上升。","synonyms":["usefulness"],"level":6,"theme":"商業與金錢","examples":[{"en":"The utility bill increased sharply this winter.","zh":"這個冬天，公用事業費用大幅上升。"},{"en":"The utility company will fix the broken power line today.","zh":"公用事業公司今天會修好斷掉的電線。"},{"en":"We pay our utility bill at the convenience store.","zh":"我們在便利商店繳公用事業帳單。"}]},{"word":"utilize","pos":"v.","phonetic":"[ˈjutlˌaɪz]","meaning":"利用；使用","definition":"to make practical and effective use of something","collocations":["utilize resources","utilize technology","fully utilize"],"example":"The company plans to utilize renewable energy sources.","exampleZh":"這家公司計劃利用再生能源。","synonyms":["use","employ"],"level":6,"theme":"動作與行為","examples":[{"en":"The company plans to utilize renewable energy sources.","zh":"這家公司計劃利用再生能源。"},{"en":"Good students know how to fully utilize their study time.","zh":"好的學生懂得如何充分利用他們的讀書時間。"},{"en":"The factory plans to utilize new technology to save energy.","zh":"這間工廠打算利用新科技來節省能源。"}]},{"word":"utmost","pos":"adj. / n.","phonetic":"[ˈʌtˌmost]","meaning":"最大限度的；極度的","definition":"the greatest or most extreme degree of something","collocations":["utmost importance","do one's utmost","utmost care"],"example":"Safety is of the utmost importance during the trip.","exampleZh":"在旅途中，安全是最重要的事。","synonyms":["greatest"],"level":6,"theme":"抽象概念","examples":[{"en":"Safety is of the utmost importance during the trip.","zh":"在旅途中，安全是最重要的事。"},{"en":"Please handle these glass cups with the utmost care.","zh":"請以最大的小心處理這些玻璃杯。"},{"en":"She did her utmost to finish the project on time.","zh":"她盡了最大的努力準時完成這個計畫。"}]},{"word":"utter","pos":"v. / adj.","phonetic":"[ˈʌtɚ]","meaning":"說出；發出；完全的","definition":"to say something aloud; complete and total","collocations":["utter a word","utter nonsense","utter silence"],"example":"He didn't utter a single word during the meeting.","exampleZh":"他在會議中一句話都沒說。","synonyms":["say","complete"],"level":6,"theme":"溝通與語言","examples":[{"en":"He didn't utter a single word during the meeting.","zh":"他在會議中一句話都沒說。"},{"en":"He was so nervous that he could not utter a word.","zh":"他緊張到說不出一個字。"},{"en":"The empty theater was filled with utter silence.","zh":"空蕩的劇院裡充滿了徹底的寂靜。"}]},{"word":"vacant","pos":"adj.","phonetic":"[ˈvekənt]","meaning":"空的；未被占用的；茫然的","definition":"not occupied or filled; showing no interest or intelligence","collocations":["vacant seat","vacant position","vacant stare"],"example":"There was a vacant seat next to the window.","exampleZh":"窗邊有一個空位。","synonyms":["empty","unoccupied"],"level":3,"theme":"性質與描述","examples":[{"en":"There was a vacant seat next to the window.","zh":"窗邊有一個空位。"},{"en":"There is a vacant position for a part-time waiter.","zh":"這裡有一個兼職服務生的空缺職位。"},{"en":"She gave me a vacant stare, as if lost in thought.","zh":"她茫然地盯著我，彷彿陷入沉思。"}]},{"word":"vacation","pos":"n.","phonetic":"[veˈkeʃən]","meaning":"假期；休假","definition":"a period of time devoted to rest or travel away from work or school","collocations":["summer vacation","go on vacation","take a vacation"],"example":"We are planning a family vacation to the beach.","exampleZh":"我們正在計畫一趟家庭海灘假期。","synonyms":["holiday","break"],"level":1,"theme":"交通與旅行","examples":[{"en":"We are planning a family vacation to the beach.","zh":"我們正在計畫一趟家庭海灘假期。"},{"en":"They decided to take a vacation in the mountains this year.","zh":"他們今年決定到山上度假。"},{"en":"During summer vacation, I plan to learn how to swim.","zh":"暑假期間，我打算學游泳。"}]},{"word":"vaccine","pos":"n.","phonetic":"[vækˈsin]","meaning":"疫苗","definition":"a substance used to stimulate immunity against a disease","collocations":["flu vaccine","vaccine shot","develop a vaccine"],"example":"Children need to get several vaccines before school starts.","exampleZh":"兒童在開學前需要接種幾種疫苗。","synonyms":["inoculation"],"level":4,"theme":"身體與健康","examples":[{"en":"Children need to get several vaccines before school starts.","zh":"兒童在開學前需要接種幾種疫苗。"},{"en":"Scientists worked day and night to develop a new vaccine.","zh":"科學家日以繼夜地研發一種新疫苗。"},{"en":"I get a flu vaccine every autumn to stay healthy.","zh":"我每年秋天都打流感疫苗以保持健康。"}]},{"word":"vacuum","pos":"n. / v.","phonetic":"[ˈvækjuəm]","meaning":"真空；吸塵器；用吸塵器清潔","definition":"a space with no matter in it; a device that cleans by suction","collocations":["vacuum cleaner","vacuum the floor","create a vacuum"],"example":"She vacuumed the living room before the guests arrived.","exampleZh":"她在客人到來前用吸塵器清潔了客廳。","synonyms":["void"],"level":3,"theme":"居家與生活","examples":[{"en":"She vacuumed the living room before the guests arrived.","zh":"她在客人到來前用吸塵器清潔了客廳。"},{"en":"I need to vacuum the carpet before my friends arrive.","zh":"朋友來之前我需要用吸塵器清理地毯。"},{"en":"A thermos keeps drinks hot by using a vacuum layer.","zh":"保溫瓶利用真空層讓飲料保持熱度。"}]},{"word":"vague","pos":"adj.","phonetic":"[veg]","meaning":"模糊的；含糊的","definition":"not clearly expressed or defined","collocations":["vague answer","vague idea","vague memory"],"example":"His explanation was too vague to be helpful.","exampleZh":"他的解釋太模糊了，沒什麼幫助。","synonyms":["unclear","ambiguous"],"level":4,"theme":"性質與描述","examples":[{"en":"His explanation was too vague to be helpful.","zh":"他的解釋太模糊了，沒什麼幫助。"},{"en":"I only have a vague idea of how the machine works.","zh":"我對這台機器如何運作只有模糊的概念。"},{"en":"Her vague answer left everyone feeling confused.","zh":"她含糊的回答讓大家都覺得困惑。"}]},{"word":"vain","pos":"adj.","phonetic":"[ven]","meaning":"徒勞的；自負的","definition":"having too much pride in one's appearance; producing no result","collocations":["in vain","vain attempt","vain person"],"example":"They tried in vain to fix the broken engine.","exampleZh":"他們徒勞地試圖修好那台故障的引擎。","synonyms":["useless","conceited"],"level":4,"theme":"性質與描述","examples":[{"en":"They tried in vain to fix the broken engine.","zh":"他們徒勞地試圖修好那台故障的引擎。"},{"en":"The firefighters searched in vain for the missing cat.","zh":"消防員徒勞地尋找那隻失蹤的貓。"},{"en":"He is so vain that he checks his hair constantly.","zh":"他非常自負，不停地檢查自己的頭髮。"}]},{"word":"valentine","pos":"n.","phonetic":"[ˈvæləntaɪn]","meaning":"情人節卡片（禮物）；情人","definition":"a card or gift sent to someone as a sign of love, especially on Valentine's Day","collocations":["send a valentine","be someone's valentine","a valentine card"],"example":"He gave her a handmade valentine card.","exampleZh":"他送給她一張手工情人節卡片。","synonyms":["sweetheart"],"level":2,"theme":"人物與家庭","examples":[{"en":"He gave her a handmade valentine card.","zh":"他送給她一張手工情人節卡片。"},{"en":"She spent the evening making a valentine for her best friend.","zh":"她花了一整晚為她最好的朋友做情人節卡片。"},{"en":"He nervously asked the girl to be his valentine.","zh":"他緊張地問那個女孩願不願意當他的情人。"}]},{"word":"valid","pos":"adj.","phonetic":"[ˈvælɪd]","meaning":"有效的；合理的","definition":"legally or officially acceptable; based on truth or reason","collocations":["valid ticket","valid reason","valid argument"],"example":"Your passport must be valid for at least six months.","exampleZh":"你的護照有效期至少要六個月。","synonyms":["legitimate","reasonable"],"level":4,"theme":"抽象概念","examples":[{"en":"Your passport must be valid for at least six months.","zh":"你的護照有效期至少要六個月。"},{"en":"You need a valid ticket to enter the concert hall.","zh":"你需要一張有效的門票才能進入音樂廳。"},{"en":"She gave a valid reason for missing the class.","zh":"她為缺課提出了一個合理的理由。"}]},{"word":"valley","pos":"n.","phonetic":"[ˈvælɪ]","meaning":"山谷；溪谷","definition":"a low area of land between hills or mountains, often with a river flowing through it","collocations":["mountain valley","river valley","fertile valley"],"example":"The village lies in a quiet valley surrounded by mountains.","exampleZh":"這個村莊坐落在群山環繞的寧靜山谷中。","synonyms":["dale"],"level":2,"theme":"自然與環境","examples":[{"en":"The village lies in a quiet valley surrounded by mountains.","zh":"這個村莊坐落在群山環繞的寧靜山谷中。"},{"en":"A clear river winds through the green valley.","zh":"一條清澈的河流蜿蜒穿過綠色的山谷。"},{"en":"Farmers grow rice in the fertile valley below.","zh":"農夫在下方肥沃的溪谷種植稻米。"}]},{"word":"valuable","pos":"adj.","phonetic":"[ˈvæljəbḷ]","meaning":"珍貴的；有價值的","definition":"worth a lot of money or of great importance or usefulness","collocations":["valuable advice","valuable time","valuable resource"],"example":"She gave me some valuable advice about my career.","exampleZh":"她給了我一些關於職涯的寶貴建議。","synonyms":["precious","useful"],"level":2,"theme":"性質與描述","examples":[{"en":"She gave me some valuable advice about my career.","zh":"她給了我一些關於職涯的寶貴建議。"},{"en":"Time is a valuable resource that we should not waste.","zh":"時間是我們不該浪費的寶貴資源。"},{"en":"The old painting turned out to be extremely valuable.","zh":"這幅舊畫結果證明極為珍貴。"}]},{"word":"value","pos":"n. / v.","phonetic":"[ˈvælju]","meaning":"價值；重視","definition":"the importance or worth of something; to consider something important","collocations":["market value","value of life","value one's friendship"],"example":"We really value your feedback on our service.","exampleZh":"我們非常重視你對我們服務的意見。","synonyms":["worth","cherish"],"level":2,"theme":"商業與金錢","examples":[{"en":"We really value your feedback on our service.","zh":"我們非常重視你對我們服務的意見。"},{"en":"The market value of the house has risen sharply.","zh":"這棟房子的市場價值大幅上升。"},{"en":"I truly value your friendship more than anything.","zh":"我真的比任何事物都更重視你的友誼。"}]},{"word":"van","pos":"n.","phonetic":"[væn]","meaning":"廂型車；貨車","definition":"a medium-sized road vehicle used for transporting goods or people","collocations":["delivery van","drive a van","load the van"],"example":"The company uses a van to deliver packages.","exampleZh":"這家公司用廂型車送貨。","synonyms":["truck"],"level":1,"theme":"交通與旅行","examples":[{"en":"The company uses a van to deliver packages.","zh":"這家公司用廂型車送貨。"},{"en":"The workers loaded the van with boxes of fresh fruit.","zh":"工人把一箱箱新鮮水果裝上廂型車。"},{"en":"My uncle drives a delivery van for a living.","zh":"我叔叔以開送貨車維生。"}]},{"word":"vanish","pos":"v.","phonetic":"[ˈvænɪʃ]","meaning":"消失；不見","definition":"to disappear suddenly and completely","collocations":["vanish into thin air","vanish without a trace","suddenly vanish"],"example":"The magician made the coin vanish before our eyes.","exampleZh":"魔術師讓那枚硬幣在我們眼前消失了。","synonyms":["disappear"],"level":3,"theme":"動作與行為","examples":[{"en":"The magician made the coin vanish before our eyes.","zh":"魔術師讓那枚硬幣在我們眼前消失了。"},{"en":"The morning fog began to vanish as the sun rose.","zh":"隨著太陽升起，晨霧開始消失。"},{"en":"The thief seemed to vanish without a trace.","zh":"那名小偷似乎消失得無影無蹤。"}]},{"word":"vanity","pos":"n.","phonetic":"[ˈvænətɪ]","meaning":"虛榮心；自負","definition":"excessive pride in one's appearance or achievements","collocations":["personal vanity","out of vanity","a matter of vanity"],"example":"His vanity made him spend hours in front of the mirror.","exampleZh":"他的虛榮心讓他花好幾個小時照鏡子。","synonyms":["conceit","pride"],"level":5,"theme":"情緒與感受","examples":[{"en":"His vanity made him spend hours in front of the mirror.","zh":"他的虛榮心讓他花好幾個小時照鏡子。"},{"en":"Out of vanity, she refused to wear her glasses.","zh":"出於虛榮心，她拒絕戴眼鏡。"},{"en":"His vanity often made it hard for others to work with him.","zh":"他的自負常常讓別人難以和他共事。"}]},{"word":"variety","pos":"n.","phonetic":"[vəˈraɪətɪ]","meaning":"多樣性；種類","definition":"a number of different types of things or a lack of uniformity","collocations":["a variety of","variety show","add variety"],"example":"The restaurant offers a variety of dishes from around the world.","exampleZh":"這家餐廳提供來自世界各地的多種料理。","synonyms":["diversity","assortment"],"level":3,"theme":"抽象概念","examples":[{"en":"The restaurant offers a variety of dishes from around the world.","zh":"這家餐廳提供來自世界各地的多種料理。"},{"en":"The bookstore sells a wide variety of magazines.","zh":"這家書店販售各式各樣的雜誌。"},{"en":"Adding variety to your meals keeps eating interesting.","zh":"為你的餐點增添多樣性能讓飲食保持有趣。"}]},{"word":"various","pos":"adj.","phonetic":"[ˈvɛrɪəs]","meaning":"各式各樣的；多種的","definition":"more than one; of several different kinds","collocations":["various reasons","various ways","various countries"],"example":"Students learn various subjects in junior high school.","exampleZh":"國中生學習各種不同的科目。","synonyms":["diverse","several"],"level":3,"theme":"性質與描述","examples":[{"en":"Students learn various subjects in junior high school.","zh":"國中生學習各種不同的科目。"},{"en":"People choose to exercise for various reasons.","zh":"人們基於各種不同的理由選擇運動。"},{"en":"The museum displays artifacts from various countries.","zh":"這座博物館展示來自各個國家的文物。"}]},{"word":"vary","pos":"v.","phonetic":"[ˈvɛrɪ]","meaning":"改變；不同","definition":"to differ or change according to circumstances","collocations":["vary in size","vary from person to person","prices vary"],"example":"Prices vary depending on the season.","exampleZh":"價格會依季節而有所不同。","synonyms":["differ","fluctuate"],"level":3,"theme":"動作與行為","examples":[{"en":"Prices vary depending on the season.","zh":"價格會依季節而有所不同。"},{"en":"The apples vary in size, from small to very large.","zh":"這些蘋果大小不一，從小的到非常大的都有。"},{"en":"Opinions about the new rule vary from person to person.","zh":"對於這項新規定的看法因人而異。"}]},{"word":"vase","pos":"n.","phonetic":"[ves]","meaning":"花瓶","definition":"a container used for holding cut flowers or as an ornament","collocations":["flower vase","glass vase","put flowers in a vase"],"example":"She placed the fresh roses in a crystal vase.","exampleZh":"她把新鮮的玫瑰放進水晶花瓶裡。","synonyms":[],"level":2,"theme":"居家與生活","examples":[{"en":"She placed the fresh roses in a crystal vase.","zh":"她把新鮮的玫瑰放進水晶花瓶裡。"},{"en":"A blue glass vase stood on the wooden table.","zh":"一個藍色的玻璃花瓶立在木桌上。"},{"en":"She carefully arranged the tulips in a tall vase.","zh":"她小心地把鬱金香插進一個高花瓶裡。"}]},{"word":"vast","pos":"adj.","phonetic":"[væst]","meaning":"廣大的；巨大的","definition":"extremely large in area, size, or amount","collocations":["vast area","vast amount","vast desert"],"example":"The Sahara is a vast desert covering much of North Africa.","exampleZh":"撒哈拉沙漠是一片覆蓋北非大部分地區的廣闊沙漠。","synonyms":["huge","immense"],"level":4,"theme":"性質與描述","examples":[{"en":"The Sahara is a vast desert covering much of North Africa.","zh":"撒哈拉沙漠是一片覆蓋北非大部分地區的廣闊沙漠。"},{"en":"The explorers crossed a vast area of frozen land.","zh":"探險家們穿越了一大片結冰的土地。"},{"en":"A vast amount of information is available online today.","zh":"如今網路上有大量的資訊可供取用。"}]},{"word":"vegetable","pos":"n.","phonetic":"[ˈvɛdʒətəbḷ]","meaning":"蔬菜","definition":"a plant or part of a plant used as food, typically eaten with the main part of a meal","collocations":["fresh vegetables","vegetable soup","grow vegetables"],"example":"My mother grows vegetables in the backyard garden.","exampleZh":"我媽媽在後院菜園種蔬菜。","synonyms":[],"level":1,"theme":"食物與烹飪","examples":[{"en":"My mother grows vegetables in the backyard garden.","zh":"我媽媽在後院菜園種蔬菜。"},{"en":"Fresh vegetables are an important part of a healthy diet.","zh":"新鮮蔬菜是健康飲食的重要部分。"},{"en":"He made a warm vegetable soup for the cold evening.","zh":"他為寒冷的夜晚煮了一鍋溫暖的蔬菜湯。"}]},{"word":"vegetarian","pos":"n. / adj.","phonetic":"[ˌvɛdʒəˈtɛrɪən]","meaning":"素食者；素食的","definition":"a person who does not eat meat or fish; relating to such a diet","collocations":["vegetarian diet","strict vegetarian","vegetarian restaurant"],"example":"She has been a vegetarian for over ten years.","exampleZh":"她已經吃素超過十年了。","synonyms":[],"level":3,"theme":"食物與烹飪","examples":[{"en":"She has been a vegetarian for over ten years.","zh":"她已經吃素超過十年了。"},{"en":"My cousin follows a strict vegetarian diet for health reasons.","zh":"我表哥基於健康理由遵循嚴格的素食飲食。"},{"en":"We found a lovely vegetarian restaurant near the park.","zh":"我們在公園附近找到一家很棒的素食餐廳。"}]},{"word":"vehicle","pos":"n.","phonetic":"[ˈviɪkḷ]","meaning":"車輛；交通工具","definition":"a machine, typically with wheels or engine, used for transporting people or goods","collocations":["motor vehicle","drive a vehicle","electric vehicle"],"example":"The parking lot was full of vehicles of all sizes.","exampleZh":"停車場裡停滿了各種大小的車輛。","synonyms":["car","automobile"],"level":3,"theme":"交通與旅行","examples":[{"en":"The parking lot was full of vehicles of all sizes.","zh":"停車場裡停滿了各種大小的車輛。"},{"en":"Every motor vehicle must stop at the red light.","zh":"每輛機動車輛都必須在紅燈前停下。"},{"en":"Electric vehicles are becoming more common in cities.","zh":"電動車在城市裡變得越來越普遍。"}]},{"word":"veil","pos":"n. / v.","phonetic":"[vel]","meaning":"面紗；遮蓋物；遮掩","definition":"a piece of fine fabric worn to cover the face; to cover or conceal something","collocations":["bridal veil","wear a veil","veil of secrecy"],"example":"The bride wore a delicate white veil.","exampleZh":"新娘戴著一片精緻的白色面紗。","synonyms":["cover"],"level":5,"theme":"服裝與外表","examples":[{"en":"The bride wore a delicate white veil.","zh":"新娘戴著一片精緻的白色面紗。"},{"en":"A thin veil of mist covered the quiet lake.","zh":"一層薄薄的霧氣籠罩著寧靜的湖面。"},{"en":"They kept their plans behind a veil of secrecy.","zh":"他們把計畫藏在一層祕密的面紗之後。"}]},{"word":"vein","pos":"n.","phonetic":"[ven]","meaning":"靜脈；紋理","definition":"a blood vessel that carries blood toward the heart; a line or streak in something","collocations":["varicose vein","vein of a leaf","veins in the arm"],"example":"The nurse found a vein in his arm to draw blood.","exampleZh":"護士在他的手臂上找到一條靜脈來抽血。","synonyms":[],"level":4,"theme":"身體與健康","examples":[{"en":"The nurse found a vein in his arm to draw blood.","zh":"護士在他的手臂上找到一條靜脈來抽血。"},{"en":"You can see the blue veins on the back of your hand.","zh":"你可以看見手背上的藍色靜脈。"},{"en":"The delicate vein of the leaf looked like a tiny map.","zh":"那片葉子細緻的紋理看起來像一張小地圖。"}]},{"word":"velvet","pos":"n. / adj.","phonetic":"[ˈvɛlvɪt]","meaning":"天鵝絨；絲絨的","definition":"a soft fabric with a thick, short pile on one side","collocations":["velvet dress","smooth as velvet","velvet curtain"],"example":"The theater curtains were made of dark red velvet.","exampleZh":"劇院的窗簾是用深紅色的天鵝絨製成的。","synonyms":[],"level":5,"theme":"服裝與外表","examples":[{"en":"The theater curtains were made of dark red velvet.","zh":"劇院的窗簾是用深紅色的天鵝絨製成的。"},{"en":"The queen wore a gown made of deep blue velvet.","zh":"女王穿著一件深藍色天鵝絨製成的禮服。"},{"en":"The kitten's fur felt as smooth as velvet.","zh":"小貓的毛摸起來像天鵝絨般柔滑。"}]},{"word":"vendor","pos":"n.","phonetic":"[ˈvɛndɚ]","meaning":"小販；賣主","definition":"a person or company that sells goods, especially in the street or from a stall","collocations":["street vendor","food vendor","vendor stall"],"example":"A street vendor was selling roasted chestnuts on the corner.","exampleZh":"一位街頭小販在街角賣烤栗子。","synonyms":["seller"],"level":5,"theme":"商業與金錢","examples":[{"en":"A street vendor was selling roasted chestnuts on the corner.","zh":"一位街頭小販在街角賣烤栗子。"},{"en":"A food vendor sold hot dumplings outside the station.","zh":"一名食物小販在車站外賣熱騰騰的水餃。"},{"en":"The street vendor arranged fresh flowers at her stall.","zh":"街頭小販在她的攤位上擺放新鮮的花朵。"}]},{"word":"venture","pos":"n. / v.","phonetic":"[ˈvɛntʃɚ]","meaning":"冒險事業；投機；冒險做","definition":"a risky or daring undertaking, especially in business; to dare to do something","collocations":["business venture","venture capital","venture out"],"example":"Starting his own restaurant was a risky business venture.","exampleZh":"開自己的餐廳是一項冒險的商業投資。","synonyms":["enterprise","dare"],"level":5,"theme":"商業與金錢","examples":[{"en":"Starting his own restaurant was a risky business venture.","zh":"開自己的餐廳是一項冒險的商業投資。"},{"en":"Opening a bakery was their first business venture together.","zh":"開一家麵包店是他們第一次共同的冒險事業。"},{"en":"The children did not dare to venture into the dark cave.","zh":"孩子們不敢冒險走進那個黑暗的洞穴。"}]},{"word":"venue","pos":"n.","phonetic":"[ˈvɛnju]","meaning":"場地；地點","definition":"the place where an event or meeting is held","collocations":["concert venue","wedding venue","change the venue"],"example":"The organizers found a perfect venue for the conference.","exampleZh":"主辦單位找到了一個完美的會議場地。","synonyms":["location","site"],"level":5,"theme":"時間與空間","examples":[{"en":"The organizers found a perfect venue for the conference.","zh":"主辦單位找到了一個完美的會議場地。"},{"en":"The concert venue can hold over ten thousand people.","zh":"這個演唱會場地可以容納超過一萬人。"},{"en":"Because of the rain, they had to change the venue.","zh":"由於下雨，他們不得不更換場地。"}]},{"word":"verb","pos":"n.","phonetic":"[vɝb]","meaning":"動詞","definition":"a word used to describe an action, state, or occurrence","collocations":["irregular verb","action verb","verb tense"],"example":"In this sentence, 'run' is the main verb.","exampleZh":"在這個句子中，「run」是主要動詞。","synonyms":[],"level":2,"theme":"教育與學習","examples":[{"en":"In this sentence, 'run' is the main verb.","zh":"在這個句子中，「run」是主要動詞。"},{"en":"An action verb tells us what the subject is doing.","zh":"動作動詞告訴我們主詞正在做什麼。"},{"en":"Learning irregular verb forms takes plenty of practice.","zh":"學習不規則動詞的形式需要大量的練習。"}]},{"word":"verbal","pos":"adj.","phonetic":"[ˈvɝbḷ]","meaning":"口頭的；言語的","definition":"relating to or in the form of words, especially spoken rather than written","collocations":["verbal agreement","verbal communication","verbal warning"],"example":"They reached a verbal agreement before signing the contract.","exampleZh":"他們在簽合約之前先達成了口頭協議。","synonyms":["oral","spoken"],"level":4,"theme":"溝通與語言","examples":[{"en":"They reached a verbal agreement before signing the contract.","zh":"他們在簽合約之前先達成了口頭協議。"},{"en":"The manager gave the worker a verbal warning first.","zh":"經理先給了那名員工一次口頭警告。"},{"en":"Good verbal communication helps avoid misunderstandings.","zh":"良好的口語溝通有助於避免誤會。"}]},{"word":"verify","pos":"v.","phonetic":"[ˈvɛrəˌfaɪ]","meaning":"證實；核實","definition":"to make sure or demonstrate that something is true, accurate, or justified","collocations":["verify information","verify identity","verify a claim"],"example":"Please verify your email address to complete registration.","exampleZh":"請驗證你的電子郵件地址以完成註冊。","synonyms":["confirm","check"],"level":4,"theme":"溝通與語言","examples":[{"en":"Please verify your email address to complete registration.","zh":"請驗證你的電子郵件地址以完成註冊。"},{"en":"The bank needs to verify your identity before the transfer.","zh":"銀行在轉帳前需要核實你的身分。"},{"en":"Reporters must verify information before publishing a story.","zh":"記者在發表報導前必須查證資訊。"}]},{"word":"verse","pos":"n.","phonetic":"[vɝs]","meaning":"詩句；韻文","definition":"writing arranged with a metrical rhythm, typically having a rhyme","collocations":["a verse of poetry","free verse","Bible verse"],"example":"He recited a verse from his favorite poem.","exampleZh":"他朗誦了他最喜歡的詩中的一段。","synonyms":["poetry","stanza"],"level":4,"theme":"藝術與音樂","examples":[{"en":"He recited a verse from his favorite poem.","zh":"他朗誦了他最喜歡的詩中的一段。"},{"en":"The student memorized a short verse of poetry for class.","zh":"這名學生為了課堂背了一小段詩句。"},{"en":"He wrote the whole song in free verse.","zh":"他用自由詩體寫了整首歌。"}]},{"word":"version","pos":"n.","phonetic":"[ˈvɝʒən]","meaning":"版本；說法","definition":"a particular form of something differing from other forms of the same type","collocations":["latest version","different version","movie version"],"example":"This is the updated version of the software.","exampleZh":"這是這款軟體的更新版本。","synonyms":["variant","edition"],"level":3,"theme":"科技與媒體","examples":[{"en":"This is the updated version of the software.","zh":"這是這款軟體的更新版本。"},{"en":"I prefer the movie version to the original book.","zh":"比起原著書籍，我更喜歡電影版本。"},{"en":"Everyone told a slightly different version of the story.","zh":"每個人講的故事版本都略有不同。"}]},{"word":"versus","pos":"prep.","phonetic":"[ˈvɝsəs]","meaning":"對；相對於","definition":"against, in contrast with, or as opposed to","collocations":["team A versus team B","cost versus benefit","risk versus reward"],"example":"Tomorrow's game is Taiwan versus Japan.","exampleZh":"明天的比賽是台灣對日本。","synonyms":["against"],"level":4,"theme":"其他","examples":[{"en":"Tomorrow's game is Taiwan versus Japan.","zh":"明天的比賽是台灣對日本。"},{"en":"The final match is our school versus the champions.","zh":"決賽是我們學校對上冠軍隊。"},{"en":"We discussed the cost versus the benefit of the trip.","zh":"我們討論了這趟旅行的成本相對於效益。"}]},{"word":"vertical","pos":"adj.","phonetic":"[ˈvɝtɪkḷ]","meaning":"垂直的；直立的","definition":"placed or extending straight up or down; at right angles to the horizon","collocations":["vertical line","vertical position","vertical drop"],"example":"The rock climber faced a steep vertical cliff.","exampleZh":"攀岩者面對著一面陡峭的垂直懸崖。","synonyms":["upright"],"level":4,"theme":"性質與描述","examples":[{"en":"The rock climber faced a steep vertical cliff.","zh":"攀岩者面對著一面陡峭的垂直懸崖。"},{"en":"Draw a straight vertical line down the center of the page.","zh":"在頁面中央畫一條筆直的垂直線。"},{"en":"The elevator moved in a smooth vertical motion.","zh":"電梯以平穩的垂直動作移動。"}]},{"word":"very","pos":"adv. / adj.","phonetic":"[ˈvɛrɪ]","meaning":"非常；正是","definition":"used to emphasize a quality or state; exact, precise","collocations":["very good","very much","the very same"],"example":"The soup was very hot when it arrived.","exampleZh":"湯送來的時候非常燙。","synonyms":["extremely"],"level":1,"theme":"其他","examples":[{"en":"The soup was very hot when it arrived.","zh":"湯送來的時候非常燙。"},{"en":"The math test was very difficult for most students.","zh":"這次數學考試對大多數學生來說非常困難。"},{"en":"This is the very book I have been looking for.","zh":"這正是我一直在找的那本書。"}]},{"word":"vessel","pos":"n.","phonetic":"[ˈvɛsḷ]","meaning":"船隻；容器；血管","definition":"a ship or large boat; a container for liquid; a tube carrying blood","collocations":["fishing vessel","blood vessel","cargo vessel"],"example":"A large cargo vessel entered the harbor at dawn.","exampleZh":"一艘大型貨船在黎明時分駛入港口。","synonyms":["ship","container"],"level":5,"theme":"交通與旅行","examples":[{"en":"A large cargo vessel entered the harbor at dawn.","zh":"一艘大型貨船在黎明時分駛入港口。"},{"en":"A small fishing vessel rocked gently in the harbor.","zh":"一艘小漁船在港口裡輕輕搖晃。"},{"en":"Exercise helps keep your blood vessels healthy.","zh":"運動有助於保持你的血管健康。"}]},{"word":"veteran","pos":"n. / adj.","phonetic":"[ˈvɛtərən]","meaning":"退伍軍人；老手","definition":"a person who has had long experience in a particular field, especially a former soldier","collocations":["war veteran","veteran teacher","veteran player"],"example":"The war veteran shared stories of his service.","exampleZh":"這位退伍軍人分享了他從軍時的故事。","synonyms":["expert"],"level":5,"theme":"工作與職業","examples":[{"en":"The war veteran shared stories of his service.","zh":"這位退伍軍人分享了他從軍時的故事。"},{"en":"The veteran teacher has taught history for thirty years.","zh":"這位資深老教師教了三十年的歷史。"},{"en":"As a veteran player, he stayed calm under pressure.","zh":"身為老將，他在壓力下保持冷靜。"}]},{"word":"veto","pos":"n. / v.","phonetic":"[ˈvito]","meaning":"否決權；否決","definition":"a constitutional right to reject a decision or proposal made by a lawmaking body","collocations":["veto power","veto a bill","exercise a veto"],"example":"The president decided to veto the new law.","exampleZh":"總統決定否決這項新法律。","synonyms":["reject","block"],"level":6,"theme":"政治與法律","examples":[{"en":"The president decided to veto the new law.","zh":"總統決定否決這項新法律。"},{"en":"The committee has the power to veto any new proposal.","zh":"委員會有權否決任何新的提案。"},{"en":"Her father used his veto and refused the late-night plan.","zh":"她父親行使否決權，拒絕了那個深夜計畫。"}]},{"word":"via","pos":"prep.","phonetic":"[ˈvaɪə]","meaning":"經由；透過","definition":"traveling through a place on the way to a destination; by means of","collocations":["via email","via train","travel via"],"example":"We flew to London via Dubai.","exampleZh":"我們經由杜拜飛往倫敦。","synonyms":["through","by means of"],"level":4,"theme":"交通與旅行","examples":[{"en":"We flew to London via Dubai.","zh":"我們經由杜拜飛往倫敦。"},{"en":"She sent the report to her teacher via email.","zh":"她透過電子郵件把報告寄給老師。"},{"en":"We traveled to the coast via a scenic mountain road.","zh":"我們經由一條風景優美的山路前往海岸。"}]},{"word":"vibrate","pos":"v.","phonetic":"[ˈvaɪbret]","meaning":"震動；顫動","definition":"to move back and forth or side to side rapidly and continually","collocations":["vibrate rapidly","phone vibrates","vibrate gently"],"example":"My phone vibrated in my pocket during the meeting.","exampleZh":"開會時我口袋裡的手機震動了。","synonyms":["shake","quiver"],"level":4,"theme":"科學與數學","examples":[{"en":"My phone vibrated in my pocket during the meeting.","zh":"開會時我口袋裡的手機震動了。"},{"en":"The whole floor seemed to vibrate as the train passed.","zh":"火車經過時整個地板似乎都在震動。"},{"en":"I set my phone to vibrate during the exam.","zh":"考試時我把手機設成震動。"}]},{"word":"vice","pos":"n. / adj.","phonetic":"[vaɪs]","meaning":"惡習；副的","definition":"immoral or wicked behavior; serving as a deputy to the person named","collocations":["vice president","smoking is a vice","vice versa"],"example":"He was appointed vice president of the company.","exampleZh":"他被任命為公司的副總裁。","synonyms":["sin","deputy"],"level":5,"theme":"工作與職業","examples":[{"en":"He was appointed vice president of the company.","zh":"他被任命為公司的副總裁。"},{"en":"The vice president will speak at tomorrow's ceremony.","zh":"副總裁將在明天的典禮上致詞。"},{"en":"He believes that laziness is his worst vice.","zh":"他認為懶惰是他最糟糕的惡習。"}]},{"word":"vicinity","pos":"n.","phonetic":"[vɪˈsɪnətɪ]","meaning":"附近；周圍","definition":"the area near or surrounding a particular place","collocations":["in the vicinity of","immediate vicinity","in close vicinity"],"example":"There are several restaurants in the vicinity of the station.","exampleZh":"車站附近有幾家餐廳。","synonyms":["neighborhood","surroundings"],"level":6,"theme":"時間與空間","examples":[{"en":"There are several restaurants in the vicinity of the station.","zh":"車站附近有幾家餐廳。"},{"en":"There are no gas stations in the immediate vicinity.","zh":"這附近沒有任何加油站。"},{"en":"Many old temples stand in the vicinity of the village.","zh":"許多古老的廟宇座落在這座村莊附近。"}]},{"word":"victim","pos":"n.","phonetic":"[ˈvɪktɪm]","meaning":"受害者；犧牲者","definition":"a person harmed, injured, or killed as a result of a crime, accident, or other event","collocations":["crime victim","victim of abuse","help the victim"],"example":"The charity provides support for victims of natural disasters.","exampleZh":"這個慈善機構為天災受害者提供援助。","synonyms":["sufferer"],"level":4,"theme":"社會與文化","examples":[{"en":"The charity provides support for victims of natural disasters.","zh":"這個慈善機構為天災受害者提供援助。"},{"en":"Volunteers rushed to help the victims of the earthquake.","zh":"志工們趕去幫助地震的受害者。"},{"en":"The police officer comforted the frightened crime victim.","zh":"警察安慰那名受驚的犯罪受害者。"}]},{"word":"victory","pos":"n.","phonetic":"[ˈvɪktərɪ]","meaning":"勝利","definition":"an act of defeating an enemy or opponent in a battle, game, or competition","collocations":["win a victory","victory parade","claim victory"],"example":"The team celebrated their victory with a big party.","exampleZh":"球隊以盛大派對慶祝他們的勝利。","synonyms":["triumph","win"],"level":3,"theme":"運動與休閒","examples":[{"en":"The team celebrated their victory with a big party.","zh":"球隊以盛大派對慶祝他們的勝利。"},{"en":"The soldiers marched proudly in the victory parade.","zh":"士兵們在勝利遊行中驕傲地行進。"},{"en":"Our team finally won a great victory after years of effort.","zh":"經過多年努力，我們隊伍終於贏得一場偉大的勝利。"}]},{"word":"video","pos":"n. / adj.","phonetic":"[ˈvɪdɪˌo]","meaning":"影片；視訊的","definition":"a recording of moving visual images, typically with sound","collocations":["watch a video","video game","upload a video"],"example":"She uploaded a funny video of her cat.","exampleZh":"她上傳了一段她貓咪的搞笑影片。","synonyms":["clip","recording"],"level":1,"theme":"科技與媒體","examples":[{"en":"She uploaded a funny video of her cat.","zh":"她上傳了一段她貓咪的搞笑影片。"},{"en":"My little brother spends too much time on video games.","zh":"我弟弟花太多時間在電玩遊戲上。"},{"en":"The teacher showed a short video about ocean animals.","zh":"老師播放了一段關於海洋動物的短片。"}]},{"word":"view","pos":"n. / v.","phonetic":"[vju]","meaning":"景色；看法；觀看","definition":"the ability to see something from a particular place; an opinion; to look at or consider","collocations":["scenic view","point of view","view the situation"],"example":"The hotel room offers a beautiful view of the sea.","exampleZh":"這間飯店房間可以欣賞美麗的海景。","synonyms":["sight","opinion"],"level":2,"theme":"自然與環境","examples":[{"en":"The hotel room offers a beautiful view of the sea.","zh":"這間飯店房間可以欣賞美麗的海景。"},{"en":"From the top of the hill, we enjoyed a scenic view.","zh":"從山頂上，我們欣賞到優美的景色。"},{"en":"Everyone should respect another person's point of view.","zh":"每個人都應該尊重他人的觀點。"}]},{"word":"viewpoint","pos":"n.","phonetic":"[ˈvjuˌpɔɪnt]","meaning":"觀點；看法","definition":"a way of thinking about or looking at something; a person's opinion","collocations":["from my viewpoint","different viewpoint","express a viewpoint"],"example":"From my viewpoint, the plan needs more time.","exampleZh":"依我的觀點，這個計畫需要更多時間。","synonyms":["perspective","opinion"],"level":4,"theme":"抽象概念","examples":[{"en":"From my viewpoint, the plan needs more time.","zh":"依我的觀點，這個計畫需要更多時間。"},{"en":"Reading widely helps you understand different viewpoints.","zh":"廣泛閱讀能幫助你了解不同的觀點。"},{"en":"She bravely expressed her viewpoint during the debate.","zh":"她在辯論中勇敢地表達了自己的看法。"}]},{"word":"vigorous","pos":"adj.","phonetic":"[ˈvɪgərəs]","meaning":"精力充沛的；劇烈的","definition":"strong, healthy, and full of energy; involving physical strength and effort","collocations":["vigorous exercise","vigorous debate","vigorous growth"],"example":"Doctors recommend vigorous exercise for at least thirty minutes a day.","exampleZh":"醫生建議每天至少進行三十分鐘的劇烈運動。","synonyms":["energetic","robust"],"level":5,"theme":"運動與休閒","examples":[{"en":"Doctors recommend vigorous exercise for at least thirty minutes a day.","zh":"醫生建議每天至少進行三十分鐘的劇烈運動。"},{"en":"After a vigorous workout, he felt tired but happy.","zh":"經過一場劇烈的運動後，他感到疲累但快樂。"},{"en":"The new plan started a vigorous debate in class.","zh":"這項新計畫在班上引發了一場激烈的辯論。"}]},{"word":"villa","pos":"n.","phonetic":"[ˈvɪlə]","meaning":"別墅","definition":"a large, luxurious country house, especially one used for vacations","collocations":["seaside villa","rent a villa","luxury villa"],"example":"They rented a villa by the sea for the summer.","exampleZh":"他們夏天租了一棟海邊別墅。","synonyms":["mansion"],"level":4,"theme":"居家與生活","examples":[{"en":"They rented a villa by the sea for the summer.","zh":"他們夏天租了一棟海邊別墅。"},{"en":"The famous singer owns a luxury villa in the countryside.","zh":"這位知名歌手在鄉間擁有一棟豪華別墅。"},{"en":"We hope to rent a seaside villa for our holiday.","zh":"我們希望為假期租一棟海邊的別墅。"}]},{"word":"village","pos":"n.","phonetic":"[ˈvɪlɪdʒ]","meaning":"村莊；鄉村","definition":"a small community or group of houses in a rural area, smaller than a town","collocations":["small village","village life","fishing village"],"example":"He grew up in a small fishing village.","exampleZh":"他在一個小漁村長大。","synonyms":["hamlet"],"level":2,"theme":"居家與生活","examples":[{"en":"He grew up in a small fishing village.","zh":"他在一個小漁村長大。"},{"en":"Life in the small mountain village is peaceful and slow.","zh":"這座小山村的生活寧靜而緩慢。"},{"en":"Every year the fishing village holds a colorful festival.","zh":"這座漁村每年都舉辦一場繽紛的慶典。"}]},{"word":"villain","pos":"n.","phonetic":"[ˈvɪlən]","meaning":"反派；壞蛋","definition":"a character whose evil actions or motives are important to the plot; a wicked person","collocations":["movie villain","play the villain","evil villain"],"example":"The villain in the movie tries to destroy the city.","exampleZh":"電影裡的反派試圖摧毀這座城市。","synonyms":["antagonist"],"level":4,"theme":"藝術與音樂","examples":[{"en":"The villain in the movie tries to destroy the city.","zh":"電影裡的反派試圖摧毀這座城市。"},{"en":"The clever villain nearly escaped from the police.","zh":"那個狡猾的反派差點從警方手中逃脫。"},{"en":"He was chosen to play the villain in the school play.","zh":"他被選中在校園話劇中飾演壞蛋。"}]},{"word":"vine","pos":"n.","phonetic":"[vaɪn]","meaning":"藤蔓；葡萄樹","definition":"a plant with a long stem that climbs or trails, especially one that produces grapes","collocations":["grape vine","climbing vine","vine leaves"],"example":"Grapes hung heavily from the vine.","exampleZh":"葡萄沉甸甸地掛在藤蔓上。","synonyms":[],"level":4,"theme":"動物與植物","examples":[{"en":"Grapes hung heavily from the vine.","zh":"葡萄沉甸甸地掛在藤蔓上。"},{"en":"A climbing vine covered the entire garden wall.","zh":"一株攀爬的藤蔓覆蓋了整面花園牆。"},{"en":"They picked ripe grapes from the vine at harvest time.","zh":"收成時他們從葡萄樹上摘下成熟的葡萄。"}]},{"word":"vinegar","pos":"n.","phonetic":"[ˈvɪnɪgɚ]","meaning":"醋","definition":"a sour liquid used for flavoring or preserving food, made from fermented alcohol","collocations":["rice vinegar","salt and vinegar","a splash of vinegar"],"example":"Add a spoonful of vinegar to the salad dressing.","exampleZh":"在沙拉醬裡加一匙醋。","synonyms":[],"level":3,"theme":"食物與烹飪","examples":[{"en":"Add a spoonful of vinegar to the salad dressing.","zh":"在沙拉醬裡加一匙醋。"},{"en":"A splash of rice vinegar makes the dish taste fresh.","zh":"加一點米醋讓這道菜嚐起來清爽。"},{"en":"She likes salt and vinegar chips as an afternoon snack.","zh":"她喜歡把鹽醋洋芋片當作下午的點心。"}]},{"word":"violate","pos":"v.","phonetic":"[ˈvaɪəˌlet]","meaning":"違反；侵犯","definition":"to break or fail to comply with a rule, law, or agreement","collocations":["violate a law","violate rights","violate privacy"],"example":"The company was fined for violating environmental regulations.","exampleZh":"該公司因違反環保法規而被罰款。","synonyms":["break","infringe"],"level":5,"theme":"政治與法律","examples":[{"en":"The company was fined for violating environmental regulations.","zh":"該公司因違反環保法規而被罰款。"},{"en":"Drivers who violate traffic laws may lose their license.","zh":"違反交通法規的駕駛人可能會被吊銷駕照。"},{"en":"Reading someone's diary can violate their privacy.","zh":"偷看別人的日記可能會侵犯他們的隱私。"}]},{"word":"violence","pos":"n.","phonetic":"[ˈvaɪələns]","meaning":"暴力","definition":"behavior involving physical force intended to hurt, damage, or kill","collocations":["domestic violence","act of violence","school violence"],"example":"The film was criticized for its excessive violence.","exampleZh":"這部電影因過度暴力而受到批評。","synonyms":["brutality"],"level":4,"theme":"社會與文化","examples":[{"en":"The film was criticized for its excessive violence.","zh":"這部電影因過度暴力而受到批評。"},{"en":"The peaceful protest ended without any violence.","zh":"這場和平抗議在沒有任何暴力的情況下結束。"},{"en":"Schools teach students to solve problems without violence.","zh":"學校教導學生不用暴力來解決問題。"}]},{"word":"violent","pos":"adj.","phonetic":"[ˈvaɪələnt]","meaning":"暴力的；猛烈的","definition":"using or involving physical force intended to hurt, damage, or kill someone or something","collocations":["violent crime","violent storm","become violent"],"example":"The area suffered a violent storm last night.","exampleZh":"這個地區昨晚遭受了一場猛烈的暴風雨。","synonyms":["fierce","brutal"],"level":4,"theme":"性質與描述","examples":[{"en":"The area suffered a violent storm last night.","zh":"這個地區昨晚遭受了一場猛烈的暴風雨。"},{"en":"A violent storm knocked down several trees last night.","zh":"昨晚一場猛烈的暴風雨吹倒了好幾棵樹。"},{"en":"The gentle dog had never shown any violent behavior.","zh":"這隻溫馴的狗從未表現出任何暴力行為。"}]},{"word":"violet","pos":"n. / adj.","phonetic":"[ˈvaɪəlɪt]","meaning":"紫羅蘭；紫色的","definition":"a small plant with purple or blue flowers; a bluish-purple color","collocations":["violet flower","violet color","shrinking violet"],"example":"The garden was full of violet flowers in spring.","exampleZh":"春天時花園裡開滿了紫羅蘭。","synonyms":["purple"],"level":3,"theme":"動物與植物","examples":[{"en":"The garden was full of violet flowers in spring.","zh":"春天時花園裡開滿了紫羅蘭。"},{"en":"Tiny violet flowers bloomed along the garden path.","zh":"小小的紫羅蘭沿著花園小徑綻放。"},{"en":"She painted the evening sky in shades of violet.","zh":"她把傍晚的天空畫成一片紫色的色調。"}]},{"word":"violin","pos":"n.","phonetic":"[ˌvaɪəˈlɪn]","meaning":"小提琴","definition":"a stringed musical instrument played with a bow","collocations":["play the violin","violin lesson","violin string"],"example":"She has practiced the violin every day since she was five.","exampleZh":"她從五歲起每天都練習拉小提琴。","synonyms":[],"level":2,"theme":"藝術與音樂","examples":[{"en":"She has practiced the violin every day since she was five.","zh":"她從五歲起每天都練習拉小提琴。"},{"en":"He tuned each violin string before the performance.","zh":"表演前他把小提琴的每根弦都調好音。"},{"en":"My sister takes a violin lesson every Thursday.","zh":"我姊姊每個星期四上一堂小提琴課。"}]},{"word":"virtual","pos":"adj.","phonetic":"[ˈvɝtʃuəl]","meaning":"虛擬的；實質上的","definition":"almost or nearly as described but not completely or in name; not physically existing but made to appear so by software","collocations":["virtual reality","virtual world","virtual meeting"],"example":"The company held a virtual meeting instead of an in-person one.","exampleZh":"公司舉行了視訊會議而非實體會議。","synonyms":["simulated"],"level":5,"theme":"科技與媒體","examples":[{"en":"The company held a virtual meeting instead of an in-person one.","zh":"公司舉行了視訊會議而非實體會議。"},{"en":"Students explored the museum through a virtual tour.","zh":"學生們透過虛擬導覽參觀了博物館。"},{"en":"With the new headset, the virtual world looks real.","zh":"戴上新的頭戴裝置，虛擬世界看起來很真實。"}]},{"word":"virtue","pos":"n.","phonetic":"[ˈvɝtʃu]","meaning":"美德；優點","definition":"behavior showing high moral standards; a good or useful quality","collocations":["patience is a virtue","virtue and vice","by virtue of"],"example":"Patience is considered a great virtue.","exampleZh":"耐心被視為一種偉大的美德。","synonyms":["merit","goodness"],"level":6,"theme":"抽象概念","examples":[{"en":"Patience is considered a great virtue.","zh":"耐心被視為一種偉大的美德。"},{"en":"Honesty is a virtue that everyone should value.","zh":"誠實是每個人都應該重視的美德。"},{"en":"She got the job by virtue of her hard work.","zh":"她憑藉自己的努力得到了這份工作。"}]},{"word":"virus","pos":"n.","phonetic":"[ˈvaɪrəs]","meaning":"病毒","definition":"an infective agent that causes disease; a piece of malicious computer code","collocations":["computer virus","catch a virus","spread a virus"],"example":"The doctor confirmed that he had caught a virus.","exampleZh":"醫生證實他感染了一種病毒。","synonyms":[],"level":4,"theme":"身體與健康","examples":[{"en":"The doctor confirmed that he had caught a virus.","zh":"醫生證實他感染了一種病毒。"},{"en":"A computer virus destroyed all of his important files.","zh":"一種電腦病毒摧毀了他所有重要的檔案。"},{"en":"Washing your hands often helps stop the virus from spreading.","zh":"經常洗手有助於阻止病毒散播。"}]},{"word":"visa","pos":"n.","phonetic":"[ˈvizə]","meaning":"簽證","definition":"an official document or stamp permitting entry into a country","collocations":["apply for a visa","student visa","visa application"],"example":"You need a valid visa to enter the country.","exampleZh":"你需要有效簽證才能入境這個國家。","synonyms":[],"level":4,"theme":"交通與旅行","examples":[{"en":"You need a valid visa to enter the country.","zh":"你需要有效簽證才能入境這個國家。"},{"en":"He applied for a student visa before studying abroad.","zh":"出國留學前他申請了學生簽證。"},{"en":"The visa application took nearly three weeks to process.","zh":"這份簽證申請花了將近三週才處理完成。"}]},{"word":"visible","pos":"adj.","phonetic":"[ˈvɪzəbḷ]","meaning":"看得見的；明顯的","definition":"able to be seen; noticeable or apparent","collocations":["clearly visible","visible from a distance","become visible"],"example":"The mountains were clearly visible from our hotel window.","exampleZh":"從我們飯店窗戶可以清楚看到那些山。","synonyms":["apparent","noticeable"],"level":3,"theme":"性質與描述","examples":[{"en":"The mountains were clearly visible from our hotel window.","zh":"從我們飯店窗戶可以清楚看到那些山。"},{"en":"The bright stars were clearly visible in the dark sky.","zh":"明亮的星星在黑暗的天空中清晰可見。"},{"en":"The ship slowly became visible through the thick fog.","zh":"那艘船在濃霧中緩緩變得看得見。"}]},{"word":"vision","pos":"n.","phonetic":"[ˈvɪʒən]","meaning":"視力；願景；想像力","definition":"the ability to see; an idea or image of the future; the ability to think or plan with imagination","collocations":["poor vision","have a vision","future vision"],"example":"The company leader has a clear vision for the future.","exampleZh":"這家公司的領導者對未來有清楚的願景。","synonyms":["eyesight","foresight"],"level":4,"theme":"抽象概念","examples":[{"en":"The company leader has a clear vision for the future.","zh":"這家公司的領導者對未來有清楚的願景。"},{"en":"Wearing glasses greatly improved her poor vision.","zh":"戴眼鏡大大改善了她不好的視力。"},{"en":"The young mayor has a bold vision for the city.","zh":"這位年輕市長對這座城市有著大膽的願景。"}]},{"word":"visit","pos":"v. / n.","phonetic":"[ˈvɪzɪt]","meaning":"拜訪；參觀","definition":"to go to see a person or place; an occasion of going to see someone or something","collocations":["visit a museum","pay a visit","visit relatives"],"example":"We plan to visit our grandparents this weekend.","exampleZh":"我們計畫這個週末去拜訪祖父母。","synonyms":["call on"],"level":1,"theme":"交通與旅行","examples":[{"en":"We plan to visit our grandparents this weekend.","zh":"我們計畫這個週末去拜訪祖父母。"},{"en":"We plan to visit the science museum on Saturday.","zh":"我們打算星期六去參觀科學博物館。"},{"en":"My aunt paid us a short visit during the holidays.","zh":"我阿姨在假期期間短暫來拜訪了我們。"}]},{"word":"visitor","pos":"n.","phonetic":"[ˈvɪzɪtɚ]","meaning":"訪客；遊客","definition":"a person who visits a place or another person","collocations":["welcome visitors","visitor center","frequent visitor"],"example":"The museum welcomes thousands of visitors every year.","exampleZh":"這間博物館每年都迎接數千名遊客。","synonyms":["guest","tourist"],"level":2,"theme":"交通與旅行","examples":[{"en":"The museum welcomes thousands of visitors every year.","zh":"這間博物館每年都迎接數千名遊客。"},{"en":"The visitor center offers free maps to all tourists.","zh":"遊客中心提供免費地圖給所有觀光客。"},{"en":"She is a frequent visitor to the local library.","zh":"她是當地圖書館的常客。"}]},{"word":"visual","pos":"adj.","phonetic":"[ˈvɪʒuəl]","meaning":"視覺的","definition":"relating to seeing or sight","collocations":["visual aid","visual arts","visual effect"],"example":"The teacher used visual aids to explain the lesson.","exampleZh":"老師用視覺輔助教材來解釋這堂課。","synonyms":[],"level":3,"theme":"科技與媒體","examples":[{"en":"The teacher used visual aids to explain the lesson.","zh":"老師用視覺輔助教材來解釋這堂課。"},{"en":"Charts are helpful visual aids for explaining data.","zh":"圖表是解釋資料時很有幫助的視覺輔助工具。"},{"en":"The movie is famous for its stunning visual effects.","zh":"這部電影以其驚人的視覺效果而聞名。"}]},{"word":"vital","pos":"adj.","phonetic":"[ˈvaɪtḷ]","meaning":"至關重要的；充滿活力的","definition":"absolutely necessary or important; full of energy","collocations":["vital role","vital importance","vital signs"],"example":"Sleep plays a vital role in maintaining good health.","exampleZh":"睡眠在維持良好健康方面扮演著至關重要的角色。","synonyms":["essential","crucial"],"level":4,"theme":"抽象概念","examples":[{"en":"Sleep plays a vital role in maintaining good health.","zh":"睡眠在維持良好健康方面扮演著至關重要的角色。"},{"en":"Clean water is vital for the survival of every village.","zh":"乾淨的水對每個村莊的生存至關重要。"},{"en":"The nurse carefully checked the patient's vital signs.","zh":"護士仔細檢查了病人的生命徵象。"}]},{"word":"vitamin","pos":"n.","phonetic":"[ˈvaɪtəmɪn]","meaning":"維生素","definition":"a naturally occurring organic substance essential for normal growth and nutrition","collocations":["vitamin C","take vitamins","vitamin deficiency"],"example":"Oranges are rich in vitamin C.","exampleZh":"柳橙富含維生素C。","synonyms":[],"level":2,"theme":"身體與健康","examples":[{"en":"Oranges are rich in vitamin C.","zh":"柳橙富含維生素C。"},{"en":"Doctors advise us to take vitamins in a balanced diet.","zh":"醫生建議我們在均衡飲食中攝取維生素。"},{"en":"A vitamin deficiency can make you feel weak and tired.","zh":"維生素不足會讓你感到虛弱疲倦。"}]},{"word":"vivid","pos":"adj.","phonetic":"[ˈvɪvɪd]","meaning":"生動的；鮮明的","definition":"producing powerful feelings or clear images in the mind; bright and strong in color","collocations":["vivid memory","vivid description","vivid colors"],"example":"She has a vivid memory of her first day at school.","exampleZh":"她對第一天上學有著鮮明的記憶。","synonyms":["lively","bright"],"level":4,"theme":"性質與描述","examples":[{"en":"She has a vivid memory of her first day at school.","zh":"她對第一天上學有著鮮明的記憶。"},{"en":"The writer painted a vivid description of the busy market.","zh":"這位作家生動地描寫了熱鬧的市場。"},{"en":"The garden was full of vivid colors in early summer.","zh":"初夏時花園裡充滿了鮮明的色彩。"}]},{"word":"vocabulary","pos":"n.","phonetic":"[voˈkæbjəˌlɛrɪ]","meaning":"詞彙","definition":"the body of words used in a particular language or by a particular person","collocations":["build vocabulary","English vocabulary","limited vocabulary"],"example":"Reading widely helps you build a richer vocabulary.","exampleZh":"廣泛閱讀有助於累積更豐富的詞彙。","synonyms":["lexicon"],"level":2,"theme":"教育與學習","examples":[{"en":"Reading widely helps you build a richer vocabulary.","zh":"廣泛閱讀有助於累積更豐富的詞彙。"},{"en":"He tries to learn ten new vocabulary words every day.","zh":"他試著每天學十個新的詞彙。"},{"en":"A limited vocabulary can make writing essays difficult.","zh":"有限的詞彙量會讓寫作文變得困難。"}]},{"word":"vocal","pos":"adj. / n.","phonetic":"[ˈvokḷ]","meaning":"聲音的；直言不諱的；歌唱部分","definition":"relating to the human voice; expressing opinions loudly and freely","collocations":["vocal cords","vocal music","become vocal about"],"example":"She was very vocal about her opposition to the plan.","exampleZh":"她對這項計畫的反對意見表達得非常直接。","synonyms":["outspoken"],"level":5,"theme":"藝術與音樂","examples":[{"en":"She was very vocal about her opposition to the plan.","zh":"她對這項計畫的反對意見表達得非常直接。"},{"en":"The singer warmed up her vocal cords before the show.","zh":"歌手在表演前先暖好她的聲帶。"},{"en":"Parents became vocal about the school's new lunch menu.","zh":"家長們對學校的新午餐菜單直言不諱。"}]},{"word":"vocation","pos":"n.","phonetic":"[voˈkeʃən]","meaning":"職業；天職","definition":"a strong feeling of suitability for a particular career or occupation","collocations":["sense of vocation","choose a vocation","true vocation"],"example":"Teaching became her true vocation in life.","exampleZh":"教書成為她一生真正的天職。","synonyms":["calling","profession"],"level":6,"theme":"工作與職業","examples":[{"en":"Teaching became her true vocation in life.","zh":"教書成為她一生真正的天職。"},{"en":"For him, medicine was more than a job; it was a vocation.","zh":"對他來說，醫學不只是一份工作，而是一種天職。"},{"en":"She discovered her true vocation while helping the poor.","zh":"她在幫助窮人的過程中發現了自己真正的天職。"}]},{"word":"voice","pos":"n. / v.","phonetic":"[vɔɪs]","meaning":"聲音；表達","definition":"the sound produced by a person's vocal organs; to express in words","collocations":["raise one's voice","voice an opinion","lose one's voice"],"example":"He voiced his concerns about the new policy.","exampleZh":"他表達了對新政策的擔憂。","synonyms":["speak","express"],"level":1,"theme":"溝通與語言","examples":[{"en":"He voiced his concerns about the new policy.","zh":"他表達了對新政策的擔憂。"},{"en":"The shy student finally found the courage to voice her opinion.","zh":"這位害羞的學生終於鼓起勇氣表達自己的意見。"},{"en":"He shouted so loudly that he lost his voice.","zh":"他喊得太大聲，結果失聲了。"}]},{"word":"volcano","pos":"n.","phonetic":"[vɑlˈkeno]","meaning":"火山","definition":"a mountain with a vent through which lava, ash, and gases erupt","collocations":["active volcano","volcano erupts","dormant volcano"],"example":"The volcano erupted, sending ash into the sky.","exampleZh":"這座火山爆發，將火山灰噴向天空。","synonyms":[],"level":3,"theme":"自然與環境","examples":[{"en":"The volcano erupted, sending ash into the sky.","zh":"這座火山爆發，將火山灰噴向天空。"},{"en":"The dormant volcano has not erupted for centuries.","zh":"這座休眠火山已經好幾個世紀沒有噴發了。"},{"en":"Scientists study the active volcano from a safe distance.","zh":"科學家從安全距離研究這座活火山。"}]},{"word":"volleyball","pos":"n.","phonetic":"[ˈvɑlɪˌbɔl]","meaning":"排球","definition":"a team sport in which players hit a ball over a net without letting it touch the ground","collocations":["play volleyball","volleyball team","beach volleyball"],"example":"They played beach volleyball every summer.","exampleZh":"他們每年夏天都會打沙灘排球。","synonyms":[],"level":1,"theme":"運動與休閒","examples":[{"en":"They played beach volleyball every summer.","zh":"他們每年夏天都會打沙灘排球。"},{"en":"Our volleyball team practices hard every afternoon.","zh":"我們的排球隊每天下午都努力練習。"},{"en":"They spent the whole weekend playing beach volleyball.","zh":"他們整個週末都在打沙灘排球。"}]},{"word":"volume","pos":"n.","phonetic":"[ˈvɑljəm]","meaning":"音量；體積；冊","definition":"the amount of space occupied by a substance; the loudness of sound; a book, especially one of a series","collocations":["turn up the volume","volume of water","first volume"],"example":"Could you turn down the volume on the TV?","exampleZh":"你可以把電視音量調小一點嗎？","synonyms":["loudness"],"level":3,"theme":"科技與媒體","examples":[{"en":"Could you turn down the volume on the TV?","zh":"你可以把電視音量調小一點嗎？"},{"en":"Please turn up the volume so everyone can hear.","zh":"請把音量調大，讓大家都能聽見。"},{"en":"This is only the first volume of a long series.","zh":"這只是一套長篇系列的第一冊。"}]},{"word":"voluntary","pos":"adj.","phonetic":"[ˈvɑlənˌtɛrɪ]","meaning":"自願的；志願的","definition":"done, given, or acting of one's own free will, without being forced or paid","collocations":["voluntary work","voluntary basis","voluntary donation"],"example":"Attendance at the meeting is voluntary, not required.","exampleZh":"參加這場會議是自願的，並非強制性的。","synonyms":["optional","willing"],"level":5,"theme":"社會與文化","examples":[{"en":"Attendance at the meeting is voluntary, not required.","zh":"參加這場會議是自願的，並非強制性的。"},{"en":"The students did voluntary work at the local shelter.","zh":"學生們在當地收容所從事志願工作。"},{"en":"All donations to the fund are completely voluntary.","zh":"對這個基金的所有捐款都是完全自願的。"}]},{"word":"volunteer","pos":"n. / v.","phonetic":"[ˌvɑlənˈtɪr]","meaning":"志工；自願做","definition":"a person who freely offers to do something; to offer to do something without being forced","collocations":["volunteer work","volunteer for a project","become a volunteer"],"example":"She volunteers at the animal shelter every weekend.","exampleZh":"她每個週末都在動物收容所當志工。","synonyms":["helper"],"level":3,"theme":"社會與文化","examples":[{"en":"She volunteers at the animal shelter every weekend.","zh":"她每個週末都在動物收容所當志工。"},{"en":"Many people volunteer to clean the beach every spring.","zh":"許多人每年春天自願去清理海灘。"},{"en":"She became a volunteer at the children's hospital.","zh":"她成了兒童醫院的一名志工。"}]},{"word":"wage","pos":"n. / v.","phonetic":"[wedʒ]","meaning":"工資；薪水；發動（戰爭）","definition":"a fixed regular payment for work, or to carry on a conflict","collocations":["minimum wage","wage a war","hourly wage"],"example":"The factory workers demanded a higher minimum wage.","exampleZh":"工廠工人要求提高最低工資。","synonyms":["pay","salary"],"level":3,"theme":"商業與金錢","examples":[{"en":"The factory workers demanded a higher minimum wage.","zh":"工廠工人要求提高最低工資。"},{"en":"Part-time workers often earn an hourly wage.","zh":"兼職工作者通常賺取時薪。"},{"en":"The government raised the minimum wage this year.","zh":"政府今年提高了最低工資。"}]},{"word":"wait","pos":"v. / n.","phonetic":"[wet]","meaning":"等待；等候","definition":"to stay in a place until someone arrives or something happens","collocations":["wait for someone","wait in line","wait a moment"],"example":"Please wait for me outside the classroom.","exampleZh":"請在教室外面等我。","synonyms":["await","stay"],"level":1,"theme":"動作與行為","examples":[{"en":"Please wait for me outside the classroom.","zh":"請在教室外面等我。"},{"en":"We had to wait in line for over an hour.","zh":"我們不得不排隊等了超過一個小時。"},{"en":"Could you wait a moment while I find my keys?","zh":"我找鑰匙時你可以稍等一下嗎？"}]},{"word":"wake","pos":"v.","phonetic":"[wek]","meaning":"醒來；喚醒","definition":"to stop sleeping, or to make someone stop sleeping","collocations":["wake up early","wake someone up","wake from a dream"],"example":"I usually wake up at six in the morning.","exampleZh":"我通常在早上六點醒來。","synonyms":["awaken","rouse"],"level":1,"theme":"動作與行為","examples":[{"en":"I usually wake up at six in the morning.","zh":"我通常在早上六點醒來。"},{"en":"My mother wakes me up every morning at six.","zh":"我媽媽每天早上六點叫我起床。"},{"en":"He woke suddenly from a strange dream.","zh":"他從一個奇怪的夢中突然醒來。"}]},{"word":"walk","pos":"v. / n.","phonetic":"[wɔk]","meaning":"走路；散步","definition":"to move on foot at a normal speed","collocations":["take a walk","walk the dog","walk to school"],"example":"We walk to school together every day.","exampleZh":"我們每天一起走路上學。","synonyms":["stroll","march"],"level":1,"theme":"動作與行為","examples":[{"en":"We walk to school together every day.","zh":"我們每天一起走路上學。"},{"en":"Let's take a walk in the park after dinner.","zh":"晚餐後我們去公園散步吧。"},{"en":"She walks the dog around the block every evening.","zh":"她每天傍晚帶狗繞街區散步。"}]},{"word":"wall","pos":"n.","phonetic":"[wɔl]","meaning":"牆壁；圍牆","definition":"a vertical structure that divides or encloses an area","collocations":["a stone wall","hang on the wall","climb over a wall"],"example":"There is a beautiful painting on the wall.","exampleZh":"牆上掛著一幅美麗的畫。","synonyms":["barrier","partition"],"level":1,"theme":"居家與生活","examples":[{"en":"There is a beautiful painting on the wall.","zh":"牆上掛著一幅美麗的畫。"},{"en":"The children helped paint the classroom wall bright yellow.","zh":"孩子們幫忙把教室的牆壁漆成亮黃色。"},{"en":"An old stone wall surrounds the quiet garden.","zh":"一道古老的石牆環繞著這座寧靜的花園。"}]},{"word":"wallet","pos":"n.","phonetic":"[ˈwɑlɪt]","meaning":"皮夾；錢包","definition":"a small flat case for carrying money and cards","collocations":["lose a wallet","a leather wallet","an empty wallet"],"example":"He lost his wallet on the bus yesterday.","exampleZh":"他昨天在公車上弄丟了皮夾。","synonyms":["purse"],"level":2,"theme":"居家與生活","examples":[{"en":"He lost his wallet on the bus yesterday.","zh":"他昨天在公車上弄丟了皮夾。"},{"en":"He pulled a leather wallet out of his back pocket.","zh":"他從後口袋裡拿出一個皮夾。"},{"en":"After the trip, she returned home with an empty wallet.","zh":"旅行結束後，她帶著空空的錢包回家。"}]},{"word":"wander","pos":"v.","phonetic":"[ˈwɑndɚ]","meaning":"閒逛；漫遊；徘徊","definition":"to walk slowly around an area without a fixed direction or purpose","collocations":["wander around","wander through the streets","let one's mind wander"],"example":"They wandered around the old town for hours.","exampleZh":"他們在舊城區閒逛了好幾個小時。","synonyms":["roam","stroll"],"level":4,"theme":"動作與行為","examples":[{"en":"They wandered around the old town for hours.","zh":"他們在舊城區閒逛了好幾個小時。"},{"en":"We love to wander through the narrow old streets.","zh":"我們喜歡在狹窄的舊街道間漫步。"},{"en":"During boring lessons, my mind tends to wander.","zh":"上無聊的課時，我的思緒容易飄走。"}]},{"word":"want","pos":"v. / n.","phonetic":"[wɑnt]","meaning":"想要；需要","definition":"to have a desire for something","collocations":["want to do something","in want of","want something badly"],"example":"She wants to travel around the world someday.","exampleZh":"她想要有一天環遊世界。","synonyms":["desire","wish"],"level":1,"theme":"抽象概念","examples":[{"en":"She wants to travel around the world someday.","zh":"她想要有一天環遊世界。"},{"en":"The hungry child wanted a warm bowl of noodles.","zh":"那個飢餓的孩子想要一碗溫熱的麵。"},{"en":"He wants to become a pilot when he grows up.","zh":"他長大後想成為一名飛行員。"}]},{"word":"war","pos":"n.","phonetic":"[wɔr]","meaning":"戰爭","definition":"armed fighting between countries or groups","collocations":["go to war","civil war","the outbreak of war"],"example":"The two countries have been at war for years.","exampleZh":"這兩個國家已經打仗多年了。","synonyms":["conflict","combat"],"level":2,"theme":"政治與法律","examples":[{"en":"The two countries have been at war for years.","zh":"這兩個國家已經打仗多年了。"},{"en":"Many families were separated during the long war.","zh":"許多家庭在這場漫長的戰爭中被拆散。"},{"en":"The two nations finally ended their civil war.","zh":"這兩個國家終於結束了他們的內戰。"}]},{"word":"wardrobe","pos":"n.","phonetic":"[ˋwɔrd͵rob]","meaning":"衣櫃；全部衣物","definition":"a large cupboard for clothes, or a person's collection of clothes","collocations":["a wooden wardrobe","summer wardrobe","update one's wardrobe"],"example":"She keeps all her dresses in a large wardrobe.","exampleZh":"她把所有的洋裝都放在一個大衣櫃裡。","synonyms":["closet"],"level":3,"theme":"服裝與外表","examples":[{"en":"She keeps all her dresses in a large wardrobe.","zh":"她把所有的洋裝都放在一個大衣櫃裡。"},{"en":"She hung her new coat inside the wooden wardrobe.","zh":"她把新外套掛進木製衣櫃裡。"},{"en":"He decided to update his wardrobe for the new job.","zh":"他決定為新工作更新自己的全部衣物。"}]},{"word":"warehouse","pos":"n.","phonetic":"[ˋwɛr͵haʊs]","meaning":"倉庫","definition":"a large building for storing goods","collocations":["a storage warehouse","warehouse workers","ship from the warehouse"],"example":"The company stores its products in a huge warehouse.","exampleZh":"這家公司把產品存放在一個巨大的倉庫裡。","synonyms":["storehouse"],"level":3,"theme":"商業與金錢","examples":[{"en":"The company stores its products in a huge warehouse.","zh":"這家公司把產品存放在一個巨大的倉庫裡。"},{"en":"Workers unloaded the trucks at the busy warehouse.","zh":"工人在繁忙的倉庫裡卸下卡車上的貨物。"},{"en":"The store ships all its orders from a central warehouse.","zh":"這家店從一個中央倉庫寄出所有訂單。"}]},{"word":"warfare","pos":"n.","phonetic":"[ˋwɔr͵fɛr]","meaning":"戰爭；作戰","definition":"the activity of fighting a war","collocations":["modern warfare","chemical warfare","engage in warfare"],"example":"Modern warfare relies heavily on advanced technology.","exampleZh":"現代戰爭高度依賴先進科技。","synonyms":["combat","war"],"level":5,"theme":"政治與法律","examples":[{"en":"Modern warfare relies heavily on advanced technology.","zh":"現代戰爭高度依賴先進科技。"},{"en":"Modern warfare relies on drones and computers.","zh":"現代戰爭仰賴無人機和電腦。"},{"en":"The history book describes ancient methods of warfare.","zh":"這本歷史書描述了古代的作戰方式。"}]},{"word":"warm","pos":"adj. / v.","phonetic":"[wɔrm]","meaning":"溫暖的；暖和的","definition":"having a comfortably high temperature","collocations":["warm weather","warm up","a warm welcome"],"example":"It's warm enough to go swimming today.","exampleZh":"今天天氣暖和到可以去游泳了。","synonyms":["mild","cozy"],"level":1,"theme":"天氣與季節","examples":[{"en":"It's warm enough to go swimming today.","zh":"今天天氣暖和到可以去游泳了。"},{"en":"The players need to warm up before the match begins.","zh":"球員在比賽開始前需要暖身。"},{"en":"The villagers gave the travelers a warm welcome.","zh":"村民們給了旅人們熱情的歡迎。"}]},{"word":"warmth","pos":"n.","phonetic":"[wɔrmθ]","meaning":"溫暖；熱情","definition":"the quality of having a comfortable heat, or friendliness","collocations":["the warmth of the sun","greet with warmth","feel warmth"],"example":"The fireplace gave the room a pleasant warmth.","exampleZh":"壁爐讓房間有種舒適的溫暖。","synonyms":["heat"],"level":3,"theme":"天氣與季節","examples":[{"en":"The fireplace gave the room a pleasant warmth.","zh":"壁爐讓房間有種舒適的溫暖。"},{"en":"We enjoyed the warmth of the sun on the beach.","zh":"我們在海灘上享受陽光的溫暖。"},{"en":"She greeted her old friend with great warmth.","zh":"她以極大的熱情迎接她的老朋友。"}]},{"word":"warn","pos":"v.","phonetic":"[wɔrn]","meaning":"警告；提醒","definition":"to tell someone about a possible danger or problem in advance","collocations":["warn someone about","warn against","warn someone not to do something"],"example":"The teacher warned the students about the exam's difficulty.","exampleZh":"老師警告學生們這次考試的難度。","synonyms":["caution","alert"],"level":3,"theme":"溝通與語言","examples":[{"en":"The teacher warned the students about the exam's difficulty.","zh":"老師警告學生們這次考試的難度。"},{"en":"The lifeguard warned the swimmers about the strong waves.","zh":"救生員警告泳客們注意強勁的海浪。"},{"en":"My mother warned me not to touch the hot stove.","zh":"我媽媽警告我不要碰熱爐子。"}]},{"word":"warning","pos":"n.","phonetic":"[ˈwɔrnɪŋ]","meaning":"警告；警報","definition":"a statement or sign telling people of a possible danger","collocations":["a warning sign","typhoon warning","give a warning"],"example":"The government issued a typhoon warning yesterday.","exampleZh":"政府昨天發布了颱風警報。","synonyms":["alert","notice"],"level":3,"theme":"自然與環境","examples":[{"en":"The government issued a typhoon warning yesterday.","zh":"政府昨天發布了颱風警報。"},{"en":"A red warning sign stood at the edge of the cliff.","zh":"一個紅色的警告標誌立在懸崖邊。"},{"en":"The referee gave the player a final warning.","zh":"裁判給了那名球員最後一次警告。"}]},{"word":"warrior","pos":"n.","phonetic":"[ˋwɔrɪɚ]","meaning":"戰士；勇士","definition":"a brave or experienced soldier or fighter","collocations":["a fierce warrior","ancient warriors","warrior spirit"],"example":"The ancient warrior fought bravely to protect his village.","exampleZh":"這位古代戰士英勇奮戰保護他的村莊。","synonyms":["fighter","soldier"],"level":4,"theme":"社會與文化","examples":[{"en":"The ancient warrior fought bravely to protect his village.","zh":"這位古代戰士英勇奮戰保護他的村莊。"},{"en":"Legends tell of a brave warrior who saved the kingdom.","zh":"傳說講述一位拯救王國的勇敢戰士。"},{"en":"The young man trained for years to become a warrior.","zh":"這名年輕人訓練多年才成為一名戰士。"}]},{"word":"wary","pos":"adj.","phonetic":"[ˋwɛrɪ]","meaning":"謹慎的；小心的","definition":"feeling or showing caution about possible dangers","collocations":["be wary of strangers","a wary look","grow wary"],"example":"Children should be wary of talking to strangers online.","exampleZh":"孩子們應該對在網路上與陌生人交談保持警惕。","synonyms":["cautious","careful"],"level":5,"theme":"情緒與感受","examples":[{"en":"Children should be wary of talking to strangers online.","zh":"孩子們應該對在網路上與陌生人交談保持警惕。"},{"en":"Travelers should be wary of strangers offering free rides.","zh":"旅行者應該對提供免費搭乘的陌生人保持警惕。"},{"en":"After being cheated once, she grew wary of online deals.","zh":"被騙過一次後，她對網路交易變得謹慎。"}]},{"word":"wash","pos":"v.","phonetic":"[wɑʃ]","meaning":"洗滌；洗","definition":"to clean something with water","collocations":["wash the dishes","wash one's hands","wash clothes"],"example":"Remember to wash your hands before eating.","exampleZh":"吃飯前記得要洗手。","synonyms":["clean","rinse"],"level":1,"theme":"居家與生活","examples":[{"en":"Remember to wash your hands before eating.","zh":"吃飯前記得要洗手。"},{"en":"It is my turn to wash the dishes tonight.","zh":"今晚輪到我洗碗。"},{"en":"She washed her muddy clothes after the hike.","zh":"健行後她清洗了沾滿泥巴的衣服。"}]},{"word":"waste","pos":"v. / n.","phonetic":"[west]","meaning":"浪費；廢棄物","definition":"to use something carelessly without a good result, or unwanted material","collocations":["waste time","waste money","food waste"],"example":"Don't waste your money on things you don't need.","exampleZh":"不要把錢浪費在你不需要的東西上。","synonyms":["squander","misuse"],"level":2,"theme":"商業與金錢","examples":[{"en":"Don't waste your money on things you don't need.","zh":"不要把錢浪費在你不需要的東西上。"},{"en":"We should not waste food when so many people are hungry.","zh":"當這麼多人挨餓時，我們不該浪費食物。"},{"en":"The city built a new plant to recycle household waste.","zh":"這座城市建了一座新工廠來回收家庭廢棄物。"}]},{"word":"watch","pos":"v. / n.","phonetic":"[wɑtʃ]","meaning":"觀看；手錶","definition":"to look at something for a period of time, or a small device for telling time","collocations":["watch TV","watch out for","wear a watch"],"example":"He wears a new watch on his left wrist.","exampleZh":"他左手戴著一支新手錶。","synonyms":["observe","view"],"level":1,"theme":"科技與媒體","examples":[{"en":"He wears a new watch on his left wrist.","zh":"他左手戴著一支新手錶。"},{"en":"Please watch out for cars when crossing the street.","zh":"過馬路時請小心來車。"},{"en":"My grandfather gave me a silver watch for my birthday.","zh":"我爺爺送了我一支銀色手錶當生日禮物。"}]},{"word":"water","pos":"n. / v.","phonetic":"[ˈwɔtɚ]","meaning":"水；澆水","definition":"the clear liquid that falls as rain and is essential for life","collocations":["drink water","water the plants","fresh water"],"example":"She waters the flowers in the garden every evening.","exampleZh":"她每天傍晚都會幫花園裡的花澆水。","synonyms":[],"level":1,"theme":"自然與環境","examples":[{"en":"She waters the flowers in the garden every evening.","zh":"她每天傍晚都會幫花園裡的花澆水。"},{"en":"Remember to drink enough water on a hot day.","zh":"炎熱的日子記得喝足夠的水。"},{"en":"He waters the vegetable garden early every morning.","zh":"他每天一早就為菜園澆水。"}]},{"word":"waterfall","pos":"n.","phonetic":"[ˈwɔtɚˌfɔl]","meaning":"瀑布","definition":"a place where a river falls from a high point to a low point","collocations":["a beautiful waterfall","visit a waterfall","the roar of a waterfall"],"example":"Tourists love taking pictures at the waterfall.","exampleZh":"遊客們喜歡在瀑布前拍照。","synonyms":[],"level":2,"theme":"自然與環境","examples":[{"en":"Tourists love taking pictures at the waterfall.","zh":"遊客們喜歡在瀑布前拍照。"},{"en":"We could hear the roar of the waterfall from far away.","zh":"我們從很遠的地方就能聽見瀑布的轟鳴聲。"},{"en":"They hiked for hours to visit a beautiful waterfall.","zh":"他們健行了好幾個小時去參觀一座美麗的瀑布。"}]},{"word":"waterproof","pos":"adj. / v.","phonetic":"[ˋwɔtɚ͵pruf]","meaning":"防水的；使防水","definition":"not letting water pass through","collocations":["a waterproof jacket","waterproof material","waterproof the tent"],"example":"Make sure your hiking boots are waterproof before the trip.","exampleZh":"出發前確定你的登山鞋是防水的。","synonyms":["watertight"],"level":3,"theme":"服裝與外表","examples":[{"en":"Make sure your hiking boots are waterproof before the trip.","zh":"出發前確定你的登山鞋是防水的。"},{"en":"She bought a waterproof jacket for the rainy season.","zh":"她為雨季買了一件防水外套。"},{"en":"You should waterproof the tent before the camping trip.","zh":"露營前你應該把帳篷做防水處理。"}]},{"word":"wave","pos":"n. / v.","phonetic":"[wev]","meaning":"波浪；揮手","definition":"a moving ridge of water, or to move a hand as a greeting","collocations":["ride a wave","wave goodbye","a heat wave"],"example":"The children waved goodbye to their grandparents.","exampleZh":"孩子們向祖父母揮手道別。","synonyms":["billow","gesture"],"level":2,"theme":"自然與環境","examples":[{"en":"The children waved goodbye to their grandparents.","zh":"孩子們向祖父母揮手道別。"},{"en":"The surfer skillfully rode the huge ocean wave.","zh":"衝浪者熟練地駕馭那道巨大的海浪。"},{"en":"She waved to her friends from across the street.","zh":"她從街道對面向朋友們揮手。"}]},{"word":"wax","pos":"n. / v.","phonetic":"[wæks]","meaning":"蠟；替……打蠟","definition":"a soft sticky substance that melts easily, or to polish with it","collocations":["candle wax","wax the car","ear wax"],"example":"The candles were made of pure beeswax.","exampleZh":"這些蠟燭是用純蜂蠟做的。","synonyms":[],"level":3,"theme":"居家與生活","examples":[{"en":"The candles were made of pure beeswax.","zh":"這些蠟燭是用純蜂蠟做的。"},{"en":"Melted candle wax dripped onto the wooden table.","zh":"融化的蠟燭油滴到了木桌上。"},{"en":"My father likes to wax the car every weekend.","zh":"我爸爸喜歡每個週末幫車子打蠟。"}]},{"word":"way","pos":"n.","phonetic":"[we]","meaning":"方法；道路；方式","definition":"a method of doing something, or a road or path","collocations":["find a way","by the way","on the way home"],"example":"There must be a better way to solve this problem.","exampleZh":"一定有更好的方法可以解決這個問題。","synonyms":["method","path"],"level":1,"theme":"抽象概念","examples":[{"en":"There must be a better way to solve this problem.","zh":"一定有更好的方法可以解決這個問題。"},{"en":"Can you tell me the way to the train station?","zh":"你能告訴我去火車站的路嗎？"},{"en":"By the way, did you finish your science project?","zh":"順帶一提，你完成你的科學作業了嗎？"}]},{"word":"weak","pos":"adj.","phonetic":"[wik]","meaning":"虛弱的；薄弱的","definition":"lacking physical strength or power","collocations":["a weak signal","feel weak","a weak argument"],"example":"He felt too weak to get out of bed.","exampleZh":"他覺得虛弱到無法下床。","synonyms":["feeble","fragile"],"level":2,"theme":"身體與健康","examples":[{"en":"He felt too weak to get out of bed.","zh":"他覺得虛弱到無法下床。"},{"en":"The phone signal was too weak inside the tunnel.","zh":"隧道裡的手機訊號太弱了。"},{"en":"His argument was weak and easy to disprove.","zh":"他的論點薄弱，很容易被駁倒。"}]},{"word":"wealth","pos":"n.","phonetic":"[wɛlθ]","meaning":"財富；財產","definition":"a large amount of money or valuable possessions","collocations":["great wealth","national wealth","a wealth of information"],"example":"The businessman built his wealth through hard work.","exampleZh":"這位商人靠努力工作累積了財富。","synonyms":["fortune","riches"],"level":3,"theme":"商業與金錢","examples":[{"en":"The businessman built his wealth through hard work.","zh":"這位商人靠努力工作累積了財富。"},{"en":"True happiness does not always come from wealth.","zh":"真正的快樂並不總是來自財富。"},{"en":"The library holds a wealth of information about history.","zh":"這座圖書館藏有大量關於歷史的資訊。"}]},{"word":"wealthy","pos":"adj.","phonetic":"[ˈwɛlθɪ]","meaning":"富有的；富裕的","definition":"having a lot of money or valuable possessions","collocations":["a wealthy family","become wealthy","wealthy nations"],"example":"She comes from a wealthy family in Taipei.","exampleZh":"她來自台北一個富裕的家庭。","synonyms":["rich","affluent"],"level":3,"theme":"商業與金錢","examples":[{"en":"She comes from a wealthy family in Taipei.","zh":"她來自台北一個富裕的家庭。"},{"en":"The wealthy businessman donated money to build a school.","zh":"這位富有的商人捐錢蓋了一所學校。"},{"en":"Through years of saving, they slowly became wealthy.","zh":"透過多年的存錢，他們慢慢變得富有。"}]},{"word":"weapon","pos":"n.","phonetic":"[ˈwɛpən]","meaning":"武器","definition":"an object used to cause physical harm or damage","collocations":["a dangerous weapon","carry a weapon","nuclear weapons"],"example":"The police found a weapon hidden in the car.","exampleZh":"警方在車裡發現了一件被藏起來的武器。","synonyms":["arm","firearm"],"level":3,"theme":"政治與法律","examples":[{"en":"The police found a weapon hidden in the car.","zh":"警方在車裡發現了一件被藏起來的武器。"},{"en":"The museum displays ancient weapons behind thick glass.","zh":"博物館在厚玻璃後展示古代的武器。"},{"en":"Knowledge can be a powerful weapon against ignorance.","zh":"知識可以是對抗無知的強大武器。"}]},{"word":"wear","pos":"v.","phonetic":"[wɛr]","meaning":"穿；戴","definition":"to have clothing, jewelry, or an accessory on one's body","collocations":["wear a uniform","wear glasses","wear out"],"example":"Students must wear their uniforms to school.","exampleZh":"學生上學必須穿制服。","synonyms":["put on","dress in"],"level":1,"theme":"服裝與外表","examples":[{"en":"Students must wear their uniforms to school.","zh":"學生上學必須穿制服。"},{"en":"You should wear a helmet when riding a bicycle.","zh":"騎腳踏車時你應該戴安全帽。"},{"en":"These old shoes have finally started to wear out.","zh":"這雙舊鞋終於開始磨損了。"}]},{"word":"weary","pos":"adj. / v.","phonetic":"[ˋwɪrɪ]","meaning":"疲倦的；厭倦的","definition":"extremely tired, especially after a lot of effort","collocations":["weary travelers","grow weary of","a weary sigh"],"example":"After the long journey, the weary travelers finally reached home.","exampleZh":"經過漫長的旅程,疲憊的旅客們終於到家了。","synonyms":["tired","exhausted"],"level":4,"theme":"身體與健康","examples":[{"en":"After the long journey, the weary travelers finally reached home.","zh":"經過漫長的旅程,疲憊的旅客們終於到家了。"},{"en":"The weary farmer rested under a shady tree at noon.","zh":"疲倦的農夫中午在一棵陰涼的樹下休息。"},{"en":"She grew weary of hearing the same excuses again.","zh":"她厭倦了再次聽到同樣的藉口。"}]},{"word":"weather","pos":"n.","phonetic":"[ˈwɛðɚ]","meaning":"天氣","definition":"the condition of the atmosphere at a particular time and place","collocations":["bad weather","weather forecast","in this weather"],"example":"The weather forecast says it will rain tomorrow.","exampleZh":"天氣預報說明天會下雨。","synonyms":["climate"],"level":1,"theme":"天氣與季節","examples":[{"en":"The weather forecast says it will rain tomorrow.","zh":"天氣預報說明天會下雨。"},{"en":"We checked the weather forecast before planning the picnic.","zh":"計畫野餐前我們查了天氣預報。"},{"en":"You should not go sailing in this stormy weather.","zh":"在這種暴風雨的天氣裡你不該去航海。"}]},{"word":"weave","pos":"v.","phonetic":"[wiv]","meaning":"編織；織造","definition":"to make cloth or a basket by crossing threads or strips over and under each other","collocations":["weave a basket","weave cloth","weave a story"],"example":"The old woman weaves beautiful baskets from bamboo.","exampleZh":"這位老婦人用竹子編織出美麗的籃子。","synonyms":["knit","braid"],"level":4,"theme":"藝術與音樂","examples":[{"en":"The old woman weaves beautiful baskets from bamboo.","zh":"這位老婦人用竹子編織出美麗的籃子。"},{"en":"Skilled artists weave colorful cloth on wooden looms.","zh":"技藝純熟的工匠在木製織布機上織出彩色的布。"},{"en":"The author knows how to weave a fascinating story.","zh":"這位作家懂得如何編織一個引人入勝的故事。"}]},{"word":"web","pos":"n.","phonetic":"[wɛb]","meaning":"蜘蛛網；網狀物；網路","definition":"a network of thin threads made by a spider, or an interconnected system","collocations":["spider web","the World Wide Web","weave a web"],"example":"A spider spun its web across the corner of the window.","exampleZh":"一隻蜘蛛在窗角織了一張網。","synonyms":["network"],"level":2,"theme":"科技與媒體","examples":[{"en":"A spider spun its web across the corner of the window.","zh":"一隻蜘蛛在窗角織了一張網。"},{"en":"Dewdrops sparkled on the spider web this morning.","zh":"今天早上露珠在蜘蛛網上閃閃發光。"},{"en":"You can find almost anything on the World Wide Web.","zh":"你幾乎可以在全球資訊網上找到任何東西。"}]},{"word":"website","pos":"n.","phonetic":"[ˈwɛbˌsaɪt]","meaning":"網站","definition":"a set of related pages on the internet, usually with a single address","collocations":["visit a website","create a website","an official website"],"example":"You can find more details on the school's website.","exampleZh":"你可以在學校網站上找到更多細節。","synonyms":["site"],"level":2,"theme":"科技與媒體","examples":[{"en":"You can find more details on the school's website.","zh":"你可以在學校網站上找到更多細節。"},{"en":"They hired a designer to create a new website.","zh":"他們聘請了一位設計師來建立新網站。"},{"en":"Check the official website for the latest schedule.","zh":"查看官方網站以獲得最新的時程表。"}]},{"word":"wedding","pos":"n.","phonetic":"[ˈwɛdɪŋ]","meaning":"婚禮","definition":"a ceremony at which two people get married","collocations":["attend a wedding","a wedding dress","a wedding ceremony"],"example":"We were all invited to their wedding next month.","exampleZh":"我們都被邀請參加他們下個月的婚禮。","synonyms":["marriage ceremony"],"level":2,"theme":"人物與家庭","examples":[{"en":"We were all invited to their wedding next month.","zh":"我們都被邀請參加他們下個月的婚禮。"},{"en":"The bride looked lovely in her white wedding dress.","zh":"新娘穿著白色婚紗看起來很美。"},{"en":"They held their wedding ceremony in a quiet garden.","zh":"他們在一座寧靜的花園裡舉行婚禮。"}]},{"word":"wedge","pos":"n. / v.","phonetic":"[wɛdʒ]","meaning":"楔子；把……楔入","definition":"a piece of wood or metal that is thick at one end and thin at the other, used to fix things in place","collocations":["a wedge of cheese","drive a wedge","wedge the door open"],"example":"He used a wooden wedge to keep the door open.","exampleZh":"他用一個木楔子把門撐開。","synonyms":[],"level":4,"theme":"居家與生活","examples":[{"en":"He used a wooden wedge to keep the door open.","zh":"他用一個木楔子把門撐開。"},{"en":"She cut a thick wedge of cheese for the sandwich.","zh":"她切了一塊厚厚的楔形起司做三明治。"},{"en":"The argument drove a wedge between the two brothers.","zh":"那場爭吵在兩兄弟之間造成了裂痕。"}]},{"word":"weed","pos":"n. / v.","phonetic":"[wid]","meaning":"雜草；除草","definition":"a wild plant growing where it is not wanted, or to remove such plants","collocations":["pull weeds","weed the garden","grow like weeds"],"example":"My father spends every weekend weeding the garden.","exampleZh":"我爸爸每個週末都在花園裡除草。","synonyms":[],"level":3,"theme":"動物與植物","examples":[{"en":"My father spends every weekend weeding the garden.","zh":"我爸爸每個週末都在花園裡除草。"},{"en":"We pulled weeds from the flower bed all afternoon.","zh":"我們整個下午都在花圃裡拔雜草。"},{"en":"The wild plants grow like weeds beside the road.","zh":"這些野生植物像雜草一樣長在路邊。"}]},{"word":"week","pos":"n.","phonetic":"[wik]","meaning":"星期；週","definition":"a period of seven days","collocations":["next week","twice a week","the school week"],"example":"I have a piano lesson twice a week.","exampleZh":"我一週上兩次鋼琴課。","synonyms":[],"level":1,"theme":"時間與空間","examples":[{"en":"I have a piano lesson twice a week.","zh":"我一週上兩次鋼琴課。"},{"en":"I visit the swimming pool twice a week.","zh":"我一週去游泳池兩次。"},{"en":"We are moving to a new house next week.","zh":"我們下星期要搬到一間新房子。"}]},{"word":"weekday","pos":"n.","phonetic":"[ˈwikˌde]","meaning":"平日；工作日","definition":"any day except Saturday and Sunday","collocations":["on weekdays","a busy weekday","weekday classes"],"example":"The library is open until nine on weekdays.","exampleZh":"圖書館平日開放到晚上九點。","synonyms":[],"level":2,"theme":"時間與空間","examples":[{"en":"The library is open until nine on weekdays.","zh":"圖書館平日開放到晚上九點。"},{"en":"The museum is much quieter on a weekday than on weekends.","zh":"博物館在平日比週末安靜得多。"},{"en":"She attends weekday classes and works on Saturdays.","zh":"她上平日的課，並在星期六工作。"}]},{"word":"weekend","pos":"n.","phonetic":"[ˈwikˌɛnd]","meaning":"週末","definition":"Saturday and Sunday, the days when many people do not work","collocations":["on the weekend","a long weekend","weekend plans"],"example":"We are going hiking this weekend.","exampleZh":"我們這個週末要去健行。","synonyms":[],"level":1,"theme":"時間與空間","examples":[{"en":"We are going hiking this weekend.","zh":"我們這個週末要去健行。"},{"en":"We are looking forward to a relaxing long weekend.","zh":"我們很期待一個放鬆的連假週末。"},{"en":"What are your plans for the weekend?","zh":"你這個週末有什麼計畫？"}]},{"word":"weep","pos":"v.","phonetic":"[wip]","meaning":"哭泣；流淚","definition":"to cry, especially because of strong emotion","collocations":["weep for joy","weep with sorrow","weep silently"],"example":"She wept quietly at the sad movie.","exampleZh":"她在這部悲傷的電影中靜靜地哭泣。","synonyms":["cry","sob"],"level":4,"theme":"情緒與感受","examples":[{"en":"She wept quietly at the sad movie.","zh":"她在這部悲傷的電影中靜靜地哭泣。"},{"en":"The whole family wept with joy at the good news.","zh":"聽到這個好消息，全家人喜極而泣。"},{"en":"She sat alone and wept silently over the letter.","zh":"她獨自坐著，對著那封信默默地哭泣。"}]},{"word":"weigh","pos":"v.","phonetic":"[we]","meaning":"秤重；權衡","definition":"to measure how heavy someone or something is","collocations":["weigh yourself","weigh the options","weigh 50 kilograms"],"example":"The baby weighs about four kilograms.","exampleZh":"這個嬰兒大約重四公斤。","synonyms":["measure"],"level":3,"theme":"科學與數學","examples":[{"en":"The baby weighs about four kilograms.","zh":"這個嬰兒大約重四公斤。"},{"en":"You should weigh the options carefully before choosing a college.","zh":"在選擇大學之前，你應該仔細權衡各種選項。"},{"en":"The nurse asked me to weigh myself on the scale.","zh":"護士要我站上磅秤量體重。"}]},{"word":"weight","pos":"n.","phonetic":"[wet]","meaning":"重量；體重","definition":"how heavy a person or thing is","collocations":["lose weight","gain weight","the weight of a bag"],"example":"He has been trying to lose weight since last year.","exampleZh":"他從去年開始就一直努力減重。","synonyms":[],"level":2,"theme":"身體與健康","examples":[{"en":"He has been trying to lose weight since last year.","zh":"他從去年開始就一直努力減重。"},{"en":"The weight of the backpack made her shoulders ache all day.","zh":"背包的重量讓她的肩膀痛了一整天。"},{"en":"My uncle wants to gain weight before the swimming competition.","zh":"我叔叔想在游泳比賽前增加體重。"}]},{"word":"weird","pos":"adj.","phonetic":"[wɪrd]","meaning":"奇怪的；怪異的","definition":"strange or unusual in a way that is surprising or slightly frightening","collocations":["a weird dream","weird behavior","sound weird"],"example":"That's a weird noise coming from the basement.","exampleZh":"地下室傳來一陣奇怪的聲音。","synonyms":["strange","odd"],"level":3,"theme":"性質與描述","examples":[{"en":"That's a weird noise coming from the basement.","zh":"地下室傳來一陣奇怪的聲音。"},{"en":"I had a really weird dream about flying over the ocean last night.","zh":"昨晚我做了一個非常奇怪的夢，夢見自己飛越海洋。"},{"en":"His sudden change in behavior seemed weird to all his friends.","zh":"他行為的突然改變讓所有朋友都覺得奇怪。"}]},{"word":"welcome","pos":"v. / adj. / n.","phonetic":"[ˈwɛlkəm]","meaning":"歡迎","definition":"to greet someone in a friendly and polite way","collocations":["welcome guests","a warm welcome","you're welcome"],"example":"They welcomed us with a big smile at the door.","exampleZh":"他們在門口以燦爛的笑容歡迎我們。","synonyms":["greet"],"level":1,"theme":"溝通與語言","examples":[{"en":"They welcomed us with a big smile at the door.","zh":"他們在門口以燦爛的笑容歡迎我們。"},{"en":"The hotel staff gave every guest a warm welcome at the entrance.","zh":"旅館員工在入口處熱情歡迎每一位客人。"},{"en":"New students are always welcome to join our reading club.","zh":"我們的讀書會隨時歡迎新同學加入。"}]},{"word":"welfare","pos":"n.","phonetic":"[ˈwɛlˌfɛr]","meaning":"福利；福祉","definition":"the health, happiness, and safety of a person or group","collocations":["social welfare","public welfare","child welfare"],"example":"The government spends a lot on social welfare programs.","exampleZh":"政府在社會福利計畫上花費了大量經費。","synonyms":["well-being"],"level":5,"theme":"社會與文化","examples":[{"en":"The government spends a lot on social welfare programs.","zh":"政府在社會福利計畫上花費了大量經費。"},{"en":"Teachers care deeply about the welfare of every child in class.","zh":"老師非常關心班上每個孩子的福祉。"},{"en":"The new law aims to improve public welfare in rural areas.","zh":"新法律的目的是改善鄉村地區的公共福利。"}]},{"word":"well-known","pos":"adj.","phonetic":"[ˈwɛlˈnon]","meaning":"著名的；知名的","definition":"known about by a lot of people","collocations":["a well-known writer","well-known for","a well-known brand"],"example":"She is a well-known singer in Taiwan.","exampleZh":"她是台灣一位知名的歌手。","synonyms":["famous","renowned"],"level":3,"theme":"性質與描述","examples":[{"en":"She is a well-known singer in Taiwan.","zh":"她是台灣一位知名的歌手。"},{"en":"This small town is well-known for its delicious pineapple cakes.","zh":"這個小鎮以美味的鳳梨酥而聞名。"},{"en":"The museum displays paintings by several well-known artists.","zh":"這座博物館展出好幾位著名畫家的畫作。"}]},{"word":"west","pos":"n. / adj. / adv.","phonetic":"[wɛst]","meaning":"西方；西邊","definition":"the direction in which the sun sets","collocations":["face west","the west coast","travel west"],"example":"The sun sets in the west every evening.","exampleZh":"太陽每天傍晚都在西方落下。","synonyms":[],"level":1,"theme":"時間與空間","examples":[{"en":"The sun sets in the west every evening.","zh":"太陽每天傍晚都在西方落下。"},{"en":"Our classroom windows face west, so afternoons get very warm.","zh":"我們教室的窗戶朝西，所以下午變得很熱。"},{"en":"They plan to travel west until they reach the ocean.","zh":"他們打算一路往西走，直到抵達海邊。"}]},{"word":"western","pos":"adj.","phonetic":"[ˈwɛstɚn]","meaning":"西方的；西部的","definition":"relating to the west, especially Western countries or culture","collocations":["western culture","western countries","western food"],"example":"Many young people are interested in western culture.","exampleZh":"許多年輕人對西方文化很感興趣。","synonyms":[],"level":2,"theme":"社會與文化","examples":[{"en":"Many young people are interested in western culture.","zh":"許多年輕人對西方文化很感興趣。"},{"en":"The restaurant serves both Taiwanese dishes and western food.","zh":"這家餐廳同時供應台灣菜和西式料理。"},{"en":"Many western countries celebrate this holiday in December.","zh":"許多西方國家在十二月慶祝這個節日。"}]},{"word":"wet","pos":"adj. / v.","phonetic":"[wɛt]","meaning":"潮濕的；濕的","definition":"covered in or soaked with liquid","collocations":["wet clothes","wet weather","get wet"],"example":"Don't go outside; your clothes will get wet in the rain.","exampleZh":"別出去了,你的衣服在雨中會弄濕的。","synonyms":["damp","moist"],"level":1,"theme":"天氣與季節","examples":[{"en":"Don't go outside; your clothes will get wet in the rain.","zh":"別出去了,你的衣服在雨中會弄濕的。"},{"en":"Please hang the wet clothes on the balcony to dry them.","zh":"請把濕衣服掛在陽台上晾乾。"},{"en":"The dog shook itself and made the whole floor wet.","zh":"那隻狗甩了甩身體，把整個地板都弄濕了。"}]},{"word":"whale","pos":"n.","phonetic":"[hwel]","meaning":"鯨魚","definition":"a very large sea mammal that breathes air","collocations":["a blue whale","watch whales","a whale of a time"],"example":"We saw several whales during our boat trip.","exampleZh":"我們在乘船旅行時看到了好幾隻鯨魚。","synonyms":[],"level":2,"theme":"動物與植物","examples":[{"en":"We saw several whales during our boat trip.","zh":"我們在乘船旅行時看到了好幾隻鯨魚。"},{"en":"The blue whale is the largest animal ever to live on Earth.","zh":"藍鯨是地球上有史以來最大的動物。"},{"en":"Tourists come to this coast every summer to watch whales.","zh":"每年夏天遊客都來到這片海岸賞鯨。"}]},{"word":"wharf","pos":"n.","phonetic":"[hwɔrf]","meaning":"碼頭","definition":"a structure built on the shore where ships load and unload","collocations":["a busy wharf","along the wharf","docked at the wharf"],"example":"Fishermen were unloading their catch at the wharf.","exampleZh":"漁夫們正在碼頭卸下他們捕獲的漁獲。","synonyms":["dock","pier"],"level":5,"theme":"交通與旅行","examples":[{"en":"Fishermen were unloading their catch at the wharf.","zh":"漁夫們正在碼頭卸下他們捕獲的漁獲。"},{"en":"Several fishing boats were docked at the old wharf this morning.","zh":"今天早上有幾艘漁船停靠在舊碼頭邊。"},{"en":"We walked along the wharf and watched the sun set.","zh":"我們沿著碼頭散步，看著太陽西下。"}]},{"word":"wheat","pos":"n.","phonetic":"[hwit]","meaning":"小麥","definition":"a grain used to make flour and bread","collocations":["a field of wheat","whole wheat bread","grow wheat"],"example":"This bread is made from whole wheat flour.","exampleZh":"這種麵包是用全麥麵粉做成的。","synonyms":[],"level":3,"theme":"食物與烹飪","examples":[{"en":"This bread is made from whole wheat flour.","zh":"這種麵包是用全麥麵粉做成的。"},{"en":"Golden fields of wheat stretched as far as we could see.","zh":"金黃色的麥田一望無際。"},{"en":"My mother prefers whole wheat bread because it is healthier.","zh":"我媽媽偏好全麥麵包，因為它比較健康。"}]},{"word":"wheel","pos":"n.","phonetic":"[hwil]","meaning":"輪子；方向盤","definition":"a round object that turns and allows a vehicle to move","collocations":["a steering wheel","the front wheel","behind the wheel"],"example":"One of the bike's wheels is broken.","exampleZh":"腳踏車的其中一個輪子壞了。","synonyms":[],"level":2,"theme":"交通與旅行","examples":[{"en":"One of the bike's wheels is broken.","zh":"腳踏車的其中一個輪子壞了。"},{"en":"He kept both hands on the steering wheel while driving in the storm.","zh":"在暴風雨中開車時，他雙手都握著方向盤。"},{"en":"The front wheel of my bike needs more air.","zh":"我腳踏車的前輪需要打更多氣。"}]},{"word":"whimper","pos":"v. / n.","phonetic":"[ˋhwɪmpɚ]","meaning":"啜泣；發出哀鳴聲","definition":"to make a series of soft, weak crying sounds","collocations":["whimper in pain","a soft whimper","the puppy whimpered"],"example":"The frightened puppy whimpered under the table.","exampleZh":"受驚的小狗在桌子底下發出哀鳴。","synonyms":["whine","sob"],"level":6,"theme":"情緒與感受","examples":[{"en":"The frightened puppy whimpered under the table.","zh":"受驚的小狗在桌子底下發出哀鳴。"},{"en":"The lost child began to whimper softly in the crowded station.","zh":"那個走失的孩子在擁擠的車站裡開始低聲啜泣。"},{"en":"With a soft whimper, the injured dog crawled toward its owner.","zh":"受傷的狗發出一聲微弱的哀鳴，朝主人爬去。"}]},{"word":"whip","pos":"n. / v.","phonetic":"[hwɪp]","meaning":"鞭子；鞭打；快速攪拌","definition":"a long piece of leather used for hitting, or to strike with one; to beat quickly","collocations":["crack the whip","whip cream","whip someone into shape"],"example":"The chef whipped the cream until it became fluffy.","exampleZh":"廚師把奶油攪打到蓬鬆為止。","synonyms":["lash"],"level":4,"theme":"食物與烹飪","examples":[{"en":"The chef whipped the cream until it became fluffy.","zh":"廚師把奶油攪打到蓬鬆為止。"},{"en":"Whip the egg whites until they form stiff peaks.","zh":"把蛋白攪打到出現堅挺的尖角為止。"},{"en":"The rider cracked the whip and the horses ran faster.","zh":"騎士甩響鞭子，馬兒跑得更快了。"}]},{"word":"whirl","pos":"v. / n.","phonetic":"[hwɝl]","meaning":"旋轉；急轉","definition":"to move or turn around quickly","collocations":["whirl around","a whirl of activity","leaves whirl in the wind"],"example":"The dancers whirled around the stage in perfect rhythm.","exampleZh":"舞者們以完美的節奏在舞台上旋轉。","synonyms":["spin","twirl"],"level":5,"theme":"動作與行為","examples":[{"en":"The dancers whirled around the stage in perfect rhythm.","zh":"舞者們以完美的節奏在舞台上旋轉。"},{"en":"Dry leaves whirled in the wind along the empty street.","zh":"枯葉在風中沿著空蕩的街道旋轉飛舞。"},{"en":"She whirled around when she heard someone call her name.","zh":"當她聽到有人叫她的名字時，猛然轉過身來。"}]},{"word":"whisper","pos":"v. / n.","phonetic":"[ˈhwɪspɚ]","meaning":"低聲說；耳語","definition":"to speak very softly using breath rather than the voice","collocations":["whisper a secret","whisper in someone's ear","speak in a whisper"],"example":"She whispered the answer so no one else could hear.","exampleZh":"她低聲說出答案,以免其他人聽到。","synonyms":["murmur"],"level":3,"theme":"溝通與語言","examples":[{"en":"She whispered the answer so no one else could hear.","zh":"她低聲說出答案,以免其他人聽到。"},{"en":"He leaned over to whisper a secret in his friend's ear.","zh":"他傾身在朋友耳邊低聲說了一個祕密。"},{"en":"The children spoke in a whisper so they wouldn't wake the baby.","zh":"孩子們低聲說話，以免吵醒嬰兒。"}]},{"word":"whistle","pos":"v. / n.","phonetic":"[ˈhwɪsl̩]","meaning":"吹口哨；哨子","definition":"to make a high, clear sound by forcing air through pursed lips","collocations":["blow a whistle","whistle a tune","the referee's whistle"],"example":"The referee blew the whistle to end the game.","exampleZh":"裁判吹哨結束了比賽。","synonyms":[],"level":3,"theme":"運動與休閒","examples":[{"en":"The referee blew the whistle to end the game.","zh":"裁判吹哨結束了比賽。"},{"en":"The old man whistled a cheerful tune as he walked home.","zh":"老人一邊走回家，一邊吹著愉快的曲調。"},{"en":"The lifeguard blew his whistle when he saw the swimmer in danger.","zh":"救生員看到泳客有危險時，吹響了他的哨子。"}]},{"word":"white","pos":"adj. / n.","phonetic":"[hwaɪt]","meaning":"白色的；白色","definition":"having the color of snow or milk","collocations":["white paper","a white shirt","turn white"],"example":"He was wearing a white shirt and black pants.","exampleZh":"他穿著一件白襯衫和一條黑褲子。","synonyms":[],"level":1,"theme":"性質與描述","examples":[{"en":"He was wearing a white shirt and black pants.","zh":"他穿著一件白襯衫和一條黑褲子。"},{"en":"Her face turned white when she heard the frightening news.","zh":"聽到那個嚇人的消息時，她的臉變得慘白。"},{"en":"He wrote the plan on a clean sheet of white paper.","zh":"他把計畫寫在一張乾淨的白紙上。"}]},{"word":"whole","pos":"adj. / n.","phonetic":"[hol]","meaning":"整個的；全部的","definition":"complete, with nothing missing or left out","collocations":["the whole world","a whole day","as a whole"],"example":"We spent the whole day cleaning the house.","exampleZh":"我們花了一整天的時間打掃房子。","synonyms":["entire","complete"],"level":2,"theme":"抽象概念","examples":[{"en":"We spent the whole day cleaning the house.","zh":"我們花了一整天的時間打掃房子。"},{"en":"The whole class worked together to decorate the classroom.","zh":"全班同學一起合作布置教室。"},{"en":"Looking at the project as a whole, the results were impressive.","zh":"從整體來看，這個計畫的成果令人印象深刻。"}]},{"word":"wicked","pos":"adj.","phonetic":"[ˈwɪkɪd]","meaning":"邪惡的；缺德的","definition":"morally very bad; evil","collocations":["a wicked witch","a wicked plan","wicked behavior"],"example":"In the story, the wicked witch cast a curse on the prince.","exampleZh":"在故事中,邪惡的女巫對王子下了詛咒。","synonyms":["evil","sinful"],"level":4,"theme":"性質與描述","examples":[{"en":"In the story, the wicked witch cast a curse on the prince.","zh":"在故事中,邪惡的女巫對王子下了詛咒。"},{"en":"The villain came up with a wicked plan to steal the treasure.","zh":"那個反派想出一個邪惡的計畫來偷取寶藏。"},{"en":"No one could believe such wicked behavior from a trusted man.","zh":"沒有人能相信一個受人信任的人會有如此缺德的行為。"}]},{"word":"wide","pos":"adj. / adv.","phonetic":"[waɪd]","meaning":"寬的；廣泛的","definition":"measuring a large distance from one side to the other","collocations":["a wide road","wide open","a wide range of"],"example":"The new highway is much wider than the old one.","exampleZh":"這條新高速公路比舊的寬多了。","synonyms":["broad"],"level":2,"theme":"性質與描述","examples":[{"en":"The new highway is much wider than the old one.","zh":"這條新高速公路比舊的寬多了。"},{"en":"The library offers a wide range of books for young readers.","zh":"圖書館為年輕讀者提供各式各樣的書籍。"},{"en":"She left the door wide open so the cat could come in.","zh":"她把門敞開，好讓貓進來。"}]},{"word":"widespread","pos":"adj.","phonetic":"[ˈwaɪdˈsprɛd]","meaning":"普遍的；廣泛分布的","definition":"existing or happening over a large area or among many people","collocations":["widespread use","widespread damage","become widespread"],"example":"Smartphones have become widespread among teenagers.","exampleZh":"智慧型手機在青少年之間已變得非常普遍。","synonyms":["extensive","common"],"level":5,"theme":"社會與文化","examples":[{"en":"Smartphones have become widespread among teenagers.","zh":"智慧型手機在青少年之間已變得非常普遍。"},{"en":"The typhoon caused widespread damage across the whole island.","zh":"颱風在整個島嶼造成了大範圍的破壞。"},{"en":"The use of electric scooters has become widespread in cities.","zh":"電動滑板車的使用在城市中已變得普遍。"}]},{"word":"widow","pos":"n.","phonetic":"[ˈwɪdo]","meaning":"寡婦","definition":"a woman whose husband has died and who has not remarried","collocations":["a young widow","become a widow","a war widow"],"example":"The widow lived alone in the old house.","exampleZh":"這位寡婦獨自住在那間老房子裡。","synonyms":[],"level":5,"theme":"人物與家庭","examples":[{"en":"The widow lived alone in the old house.","zh":"這位寡婦獨自住在那間老房子裡。"},{"en":"After the accident, the young widow raised three children alone.","zh":"那場意外之後，年輕的寡婦獨自撫養三個孩子。"},{"en":"The kind widow next door often shares vegetables from her garden.","zh":"隔壁善良的寡婦常常分享她菜園裡的蔬菜。"}]},{"word":"width","pos":"n.","phonetic":"[wɪdθ]","meaning":"寬度","definition":"the distance from one side of something to the other","collocations":["the width of a road","measure the width","in width"],"example":"Please measure the width of the table.","exampleZh":"請測量一下這張桌子的寬度。","synonyms":[],"level":4,"theme":"科學與數學","examples":[{"en":"Please measure the width of the table.","zh":"請測量一下這張桌子的寬度。"},{"en":"Please measure the width of the window before buying curtains.","zh":"買窗簾之前，請先量一量窗戶的寬度。"},{"en":"The river is about ten meters in width at this point.","zh":"這條河在這一段大約有十公尺寬。"}]},{"word":"wife","pos":"n.","phonetic":"[waɪf]","meaning":"妻子","definition":"the woman a man is married to","collocations":["a loving wife","husband and wife","become a wife"],"example":"His wife works as a doctor at the hospital.","exampleZh":"他的妻子在醫院擔任醫生。","synonyms":["spouse"],"level":1,"theme":"人物與家庭","examples":[{"en":"His wife works as a doctor at the hospital.","zh":"他的妻子在醫院擔任醫生。"},{"en":"His wife teaches music at a local elementary school.","zh":"他的妻子在當地一所小學教音樂。"},{"en":"The husband and wife opened a small bakery together.","zh":"這對夫妻一起開了一間小麵包店。"}]},{"word":"wild","pos":"adj.","phonetic":"[waɪld]","meaning":"野生的；狂野的","definition":"living or growing in a natural state, not tamed or cultivated","collocations":["wild animals","a wild guess","grow wild"],"example":"Wild animals should not be kept as pets.","exampleZh":"野生動物不應該被當作寵物飼養。","synonyms":["untamed","feral"],"level":2,"theme":"動物與植物","examples":[{"en":"Wild animals should not be kept as pets.","zh":"野生動物不應該被當作寵物飼養。"},{"en":"Beautiful flowers grow wild along the mountain path in spring.","zh":"春天時，美麗的花朵沿著山徑野生綻放。"},{"en":"I don't know the answer, so let me make a wild guess.","zh":"我不知道答案，所以讓我隨便猜猜看。"}]},{"word":"wildlife","pos":"n.","phonetic":"[ˈwaɪldˌlaɪf]","meaning":"野生動物；野生生物","definition":"animals and plants living in their natural environment","collocations":["protect wildlife","wildlife conservation","local wildlife"],"example":"The national park protects a wide variety of wildlife.","exampleZh":"這座國家公園保護了各種各樣的野生動物。","synonyms":[],"level":3,"theme":"自然與環境","examples":[{"en":"The national park protects a wide variety of wildlife.","zh":"這座國家公園保護了各種各樣的野生動物。"},{"en":"Volunteers work hard to protect the wildlife in this forest.","zh":"志工們努力保護這座森林裡的野生動物。"},{"en":"The documentary taught us a lot about local wildlife.","zh":"這部紀錄片讓我們對當地的野生動物有很多認識。"}]},{"word":"willing","pos":"adj.","phonetic":"[ˈwɪlɪŋ]","meaning":"願意的；樂意的","definition":"ready or happy to do something without being forced","collocations":["be willing to","a willing helper","willing to try"],"example":"He is always willing to help his classmates.","exampleZh":"他總是樂意幫助同學。","synonyms":["ready","eager"],"level":3,"theme":"情緒與感受","examples":[{"en":"He is always willing to help his classmates.","zh":"他總是樂意幫助同學。"},{"en":"She is always willing to try new things without fear.","zh":"她總是願意毫無畏懼地嘗試新事物。"},{"en":"Are you willing to share your notes with the new student?","zh":"你願意把筆記分享給那位新同學嗎？"}]},{"word":"win","pos":"v. / n.","phonetic":"[wɪn]","meaning":"贏；獲勝","definition":"to achieve success or first place in a competition","collocations":["win a game","win a prize","win the race"],"example":"Our team won the basketball game last night.","exampleZh":"我們的隊伍昨晚贏得了籃球比賽。","synonyms":["triumph","succeed"],"level":1,"theme":"運動與休閒","examples":[{"en":"Our team won the basketball game last night.","zh":"我們的隊伍昨晚贏得了籃球比賽。"},{"en":"If we practice hard, we can win the singing contest.","zh":"如果我們努力練習，就能贏得歌唱比賽。"},{"en":"She ran so fast that she won the race easily.","zh":"她跑得非常快，輕鬆贏得了那場賽跑。"}]},{"word":"wince","pos":"v. / n.","phonetic":"[wɪns]","meaning":"畏縮；因痛而皺眉","definition":"to make a slight movement of the face as a reaction to pain or embarrassment","collocations":["wince in pain","wince at the memory","a visible wince"],"example":"She winced as the nurse cleaned her wound.","exampleZh":"護士清理她的傷口時她痛得皺起眉頭。","synonyms":["flinch"],"level":6,"theme":"身體與健康","examples":[{"en":"She winced as the nurse cleaned her wound.","zh":"護士清理她的傷口時她痛得皺起眉頭。"},{"en":"He winced in pain when the doctor touched his swollen ankle.","zh":"當醫生碰到他腫脹的腳踝時，他痛得皺起眉頭。"},{"en":"She still winces at the memory of that embarrassing moment.","zh":"一想起那個尷尬的時刻，她仍然會不由得縮一下。"}]},{"word":"wind","pos":"n. / v.","phonetic":"[wɪnd]","meaning":"風；蜿蜒前進","definition":"a natural movement of air, or to twist and turn","collocations":["a strong wind","wind blows","wind through the mountains"],"example":"A cold wind blew across the field this morning.","exampleZh":"今天早上田野上吹過一陣冷風。","synonyms":["breeze"],"level":1,"theme":"天氣與季節","examples":[{"en":"A cold wind blew across the field this morning.","zh":"今天早上田野上吹過一陣冷風。"},{"en":"A strong wind knocked several branches off the old tree.","zh":"一陣強風把老樹上的好幾根樹枝吹了下來。"},{"en":"The narrow road winds through the mountains toward the village.","zh":"那條狹窄的道路蜿蜒穿過群山通向村莊。"}]},{"word":"wink","pos":"v. / n.","phonetic":"[wɪŋk]","meaning":"眨眼示意；眨眼","definition":"to close and open one eye quickly as a signal","collocations":["wink at someone","a knowing wink","not sleep a wink"],"example":"He gave her a friendly wink before leaving the room.","exampleZh":"他離開房間前對她友善地眨了眨眼。","synonyms":["blink"],"level":3,"theme":"溝通與語言","examples":[{"en":"He gave her a friendly wink before leaving the room.","zh":"他離開房間前對她友善地眨了眨眼。"},{"en":"The teacher gave me a knowing wink to show she understood.","zh":"老師對我心照不宣地眨了眨眼，表示她明白了。"},{"en":"I was so nervous that I didn't sleep a wink last night.","zh":"我太緊張了，昨晚一夜都沒睡。"}]},{"word":"wipe","pos":"v. / n.","phonetic":"[waɪp]","meaning":"擦拭；抹去","definition":"to clean or dry something by rubbing it","collocations":["wipe the table","wipe away tears","wipe out"],"example":"She wiped the table clean after breakfast.","exampleZh":"早餐後她把桌子擦乾淨了。","synonyms":["clean","rub"],"level":2,"theme":"居家與生活","examples":[{"en":"She wiped the table clean after breakfast.","zh":"早餐後她把桌子擦乾淨了。"},{"en":"She gently wiped away the child's tears with a soft tissue.","zh":"她用柔軟的面紙輕輕擦去孩子的眼淚。"},{"en":"Please wipe the whiteboard before the next class begins.","zh":"請在下一堂課開始前把白板擦乾淨。"}]},{"word":"wire","pos":"n. / v.","phonetic":"[waɪr]","meaning":"電線；金屬絲；接線","definition":"a thin piece of metal used to carry electricity or for fastening things","collocations":["electric wire","barbed wire","wire the house"],"example":"The electrician replaced the old wire behind the wall.","exampleZh":"電工更換了牆後的舊電線。","synonyms":["cable"],"level":3,"theme":"科技與媒體","examples":[{"en":"The electrician replaced the old wire behind the wall.","zh":"電工更換了牆後的舊電線。"},{"en":"A fence of barbed wire surrounded the empty factory.","zh":"一圈帶刺鐵絲網圍繞著那座空蕩的工廠。"},{"en":"Never touch a bare electric wire with wet hands.","zh":"絕對不要用濕手觸摸裸露的電線。"}]},{"word":"wisdom","pos":"n.","phonetic":"[ˋwɪzdəm]","meaning":"智慧；才智","definition":"the quality of having experience, knowledge, and good judgment","collocations":["words of wisdom","common wisdom","the wisdom of age"],"example":"Grandma always shares her wisdom with the younger generation.","exampleZh":"奶奶總是把她的智慧分享給年輕一代。","synonyms":["intelligence"],"level":4,"theme":"抽象概念","examples":[{"en":"Grandma always shares her wisdom with the younger generation.","zh":"奶奶總是把她的智慧分享給年輕一代。"},{"en":"My teacher shared a few words of wisdom before the exam.","zh":"考試前，老師分享了幾句充滿智慧的話。"},{"en":"With the wisdom of age, my grandfather stays calm in any crisis.","zh":"憑著歲月積累的智慧，我祖父在任何危機中都保持鎮定。"}]},{"word":"wise","pos":"adj.","phonetic":"[waɪz]","meaning":"明智的；有智慧的","definition":"having or showing good judgment based on knowledge and experience","collocations":["a wise decision","a wise man","it would be wise to"],"example":"It would be wise to save some money for emergencies.","exampleZh":"為緊急情況存一些錢是明智的。","synonyms":["sensible","smart"],"level":3,"theme":"性質與描述","examples":[{"en":"It would be wise to save some money for emergencies.","zh":"為緊急情況存一些錢是明智的。"},{"en":"Choosing to study a little every day was a wise decision.","zh":"選擇每天讀一點書是個明智的決定。"},{"en":"It would be wise to check the weather before hiking.","zh":"健行前先查看天氣會是明智之舉。"}]},{"word":"wish","pos":"v. / n.","phonetic":"[wɪʃ]","meaning":"希望；願望","definition":"to want something to happen or be true, or a desire for something","collocations":["make a wish","best wishes","wish for peace"],"example":"She closed her eyes and made a wish before blowing out the candles.","exampleZh":"她閉上眼睛,在吹熄蠟燭前許了一個願望。","synonyms":["desire","hope"],"level":2,"theme":"情緒與感受","examples":[{"en":"She closed her eyes and made a wish before blowing out the candles.","zh":"她閉上眼睛,在吹熄蠟燭前許了一個願望。"},{"en":"Everyone stood up and wished the couple a happy life.","zh":"大家都站起來祝福這對新人生活幸福。"},{"en":"People around the world wish for lasting peace.","zh":"世界各地的人們都渴望持久的和平。"}]},{"word":"wit","pos":"n.","phonetic":"[wɪt]","meaning":"機智；才智；風趣","definition":"the ability to say or write clever, amusing things","collocations":["quick wit","a man of wit","keep one's wits about"],"example":"His quick wit made everyone at the party laugh.","exampleZh":"他機智的談吐讓派對上的每個人都大笑。","synonyms":["humor","cleverness"],"level":5,"theme":"抽象概念","examples":[{"en":"His quick wit made everyone at the party laugh.","zh":"他機智的談吐讓派對上的每個人都大笑。"},{"en":"Her quick wit helped her answer every tricky question.","zh":"她的機智反應幫助她回答了每個刁鑽的問題。"},{"en":"You must keep your wits about you when crossing a busy street.","zh":"過繁忙的馬路時，你必須保持警覺。"}]},{"word":"withdraw","pos":"v.","phonetic":"[wɪðˋdrɔ]","meaning":"撤回；提款；退出","definition":"to remove or take away, or to leave a place or activity","collocations":["withdraw money","withdraw from the race","withdraw troops"],"example":"He went to the bank to withdraw some cash.","exampleZh":"他去銀行提了一些現金。","synonyms":["retreat","remove"],"level":4,"theme":"商業與金錢","examples":[{"en":"He went to the bank to withdraw some cash.","zh":"他去銀行提了一些現金。"},{"en":"Because of an injury, she had to withdraw from the marathon.","zh":"由於受傷，她不得不退出馬拉松比賽。"},{"en":"I need to withdraw some money before the shops close.","zh":"我需要在商店關門前提一些錢。"}]},{"word":"withdrawal","pos":"n.","phonetic":"[wɪðˋdrɔəl]","meaning":"撤回；提款；退出","definition":"the act of withdrawing something or someone","collocations":["cash withdrawal","troop withdrawal","withdrawal symptoms"],"example":"The bank charges a small fee for each cash withdrawal.","exampleZh":"銀行對每次提款收取一小筆手續費。","synonyms":["removal"],"level":5,"theme":"商業與金錢","examples":[{"en":"The bank charges a small fee for each cash withdrawal.","zh":"銀行對每次提款收取一小筆手續費。"},{"en":"There is a daily limit on cash withdrawals from this machine.","zh":"這台機器每天提領現金有金額上限。"},{"en":"His sudden withdrawal from the team surprised everyone.","zh":"他突然退出隊伍，讓大家都很驚訝。"}]},{"word":"wither","pos":"v.","phonetic":"[ˋwɪðɚ]","meaning":"枯萎；凋謝","definition":"to become dry and shrivel, especially of a plant","collocations":["flowers wither","wither away","wither in the heat"],"example":"Without water, the plants soon began to wither.","exampleZh":"沒有水的滋潤,植物很快就開始枯萎了。","synonyms":["shrivel","fade"],"level":6,"theme":"自然與環境","examples":[{"en":"Without water, the plants soon began to wither.","zh":"沒有水的滋潤,植物很快就開始枯萎了。"},{"en":"The roses began to wither after a week without water.","zh":"玫瑰在缺水一週後開始枯萎。"},{"en":"Under the burning sun, the young crops withered quickly.","zh":"在烈日下，幼小的農作物很快就枯萎了。"}]},{"word":"witness","pos":"n. / v.","phonetic":"[ˋwɪtnɪs]","meaning":"目擊者；證人；目擊","definition":"a person who sees an event happen, or to see something happen","collocations":["an eyewitness","witness a crime","call a witness"],"example":"Several people witnessed the accident on the highway.","exampleZh":"好幾個人目擊了高速公路上的事故。","synonyms":["observer","spectator"],"level":4,"theme":"政治與法律","examples":[{"en":"Several people witnessed the accident on the highway.","zh":"好幾個人目擊了高速公路上的事故。"},{"en":"The police asked the witness to describe what she had seen.","zh":"警方要求目擊者描述她所看到的一切。"},{"en":"We were lucky to witness a beautiful meteor shower last night.","zh":"昨晚我們很幸運目睹了一場美麗的流星雨。"}]},{"word":"wizard","pos":"n.","phonetic":"[ˋwɪzɚd]","meaning":"巫師；奇才","definition":"a man who has magical powers, or someone very skilled at something","collocations":["a powerful wizard","a computer wizard","wizard of finance"],"example":"In the story, the old wizard casts a powerful spell.","exampleZh":"在這個故事裡,老巫師施展了一個強大的咒語。","synonyms":["magician","sorcerer"],"level":4,"theme":"藝術與音樂","examples":[{"en":"In the story, the old wizard casts a powerful spell.","zh":"在這個故事裡,老巫師施展了一個強大的咒語。"},{"en":"In the fairy tale, a powerful wizard guarded the magic castle.","zh":"在童話故事裡，一位強大的巫師守護著魔法城堡。"},{"en":"My brother is a real computer wizard who fixes any problem.","zh":"我哥哥是個真正的電腦奇才，什麼問題都能解決。"}]},{"word":"wobble","pos":"v. / n.","phonetic":"[ˋwɑb!]","meaning":"搖晃；不穩地擺動","definition":"to move unsteadily from side to side","collocations":["the table wobbles","wobble on high heels","a slight wobble"],"example":"The old chair wobbles whenever someone sits on it.","exampleZh":"每當有人坐上去,那張舊椅子就會搖晃。","synonyms":["shake","totter"],"level":5,"theme":"動作與行為","examples":[{"en":"The old chair wobbles whenever someone sits on it.","zh":"每當有人坐上去,那張舊椅子就會搖晃。"},{"en":"The tower of blocks wobbled and then crashed to the floor.","zh":"那疊積木搖晃了一下，接著就倒在地上。"},{"en":"She wobbled on her high heels as she crossed the stage.","zh":"她穿著高跟鞋走過舞台時搖搖晃晃的。"}]},{"word":"woe","pos":"n.","phonetic":"[wo]","meaning":"悲哀；不幸","definition":"great sorrow or distress","collocations":["tale of woe","woe is me","woes of life"],"example":"She told us about all her woes.","exampleZh":"她向我們訴說了她所有的不幸。","synonyms":["sorrow","misery"],"level":6,"theme":"情緒與感受","examples":[{"en":"She told us about all her woes.","zh":"她向我們訴說了她所有的不幸。"},{"en":"The old sailor told us a long tale of woe at sea.","zh":"老水手向我們訴說了一段在海上的悲慘遭遇。"},{"en":"Despite all the woes of life, she never lost her smile.","zh":"儘管生活充滿種種不幸，她從未失去笑容。"}]},{"word":"wolf","pos":"n.","phonetic":"[wʊlf]","meaning":"狼","definition":"a wild animal that looks like a large dog and lives in packs","collocations":["pack of wolves","cry wolf","lone wolf"],"example":"A wolf howled in the distance.","exampleZh":"遠處傳來狼的嚎叫聲。","synonyms":[],"level":2,"theme":"動物與植物","examples":[{"en":"A wolf howled in the distance.","zh":"遠處傳來狼的嚎叫聲。"},{"en":"A hungry pack of wolves hunted together in the snowy forest.","zh":"一群飢餓的狼在雪林中一起獵食。"},{"en":"If you always cry wolf, no one will believe you in real danger.","zh":"如果你老是謊報消息，真正有危險時就沒人會相信你。"}]},{"word":"woman","pos":"n.","phonetic":"[ˈwʊmən]","meaning":"女人；婦女","definition":"an adult female human being","collocations":["young woman","working woman","woman of the year"],"example":"The woman standing by the door is my aunt.","exampleZh":"站在門邊的那位女士是我阿姨。","synonyms":[],"level":1,"theme":"人物與家庭","examples":[{"en":"The woman standing by the door is my aunt.","zh":"站在門邊的那位女士是我阿姨。"},{"en":"The young woman volunteered to teach children how to read.","zh":"那位年輕女子自願教孩子們識字。"},{"en":"As a busy working woman, she still finds time to exercise.","zh":"身為忙碌的職業婦女，她仍然抽得出時間運動。"}]},{"word":"wonder","pos":"v. / n.","phonetic":"[ˈwʌndɚ]","meaning":"想知道；感到驚奇；奇蹟","definition":"to want to know something; a feeling of surprise or admiration","collocations":["wonder if","wonder about","no wonder","wonders of nature"],"example":"I wonder why she didn't come to the party.","exampleZh":"我想知道她為什麼沒來派對。","synonyms":["ponder","marvel"],"level":2,"theme":"情緒與感受","examples":[{"en":"I wonder why she didn't come to the party.","zh":"我想知道她為什麼沒來派對。"},{"en":"I wonder whether it will rain during our field trip tomorrow.","zh":"我在想明天校外教學時會不會下雨。"},{"en":"The tourists gazed in wonder at the huge waterfall.","zh":"遊客們驚奇地凝望著那座巨大的瀑布。"}]},{"word":"wonderful","pos":"adj.","phonetic":"[ˈwʌndɚfəl]","meaning":"極好的；令人驚奇的","definition":"extremely good or pleasant","collocations":["wonderful news","wonderful time","wonderful world"],"example":"We had a wonderful vacation in Japan.","exampleZh":"我們在日本度過了一個美好的假期。","synonyms":["marvelous","fantastic"],"level":1,"theme":"性質與描述","examples":[{"en":"We had a wonderful vacation in Japan.","zh":"我們在日本度過了一個美好的假期。"},{"en":"We received wonderful news that grandpa is finally healthy again.","zh":"我們收到一個好消息，爺爺終於恢復健康了。"},{"en":"The children had a wonderful time at the summer camp.","zh":"孩子們在夏令營度過了一段美好的時光。"}]},{"word":"wood","pos":"n.","phonetic":"[wʊd]","meaning":"木頭；樹林","definition":"the hard material that forms the trunk and branches of a tree","collocations":["piece of wood","made of wood","walk in the woods"],"example":"The table is made of wood.","exampleZh":"這張桌子是木頭做的。","synonyms":["timber"],"level":1,"theme":"自然與環境","examples":[{"en":"The table is made of wood.","zh":"這張桌子是木頭做的。"},{"en":"We took a quiet walk in the woods behind our school.","zh":"我們在學校後面的樹林裡靜靜地散步。"},{"en":"He carved a small boat out of a piece of wood.","zh":"他用一塊木頭雕出一艘小船。"}]},{"word":"wooden","pos":"adj.","phonetic":"[ˈwʊdn̩]","meaning":"木製的","definition":"made of wood","collocations":["wooden chair","wooden floor","wooden box"],"example":"They live in a small wooden house.","exampleZh":"他們住在一間小木屋裡。","synonyms":[],"level":2,"theme":"居家與生活","examples":[{"en":"They live in a small wooden house.","zh":"他們住在一間小木屋裡。"},{"en":"Grandma keeps her old letters in a small wooden box.","zh":"奶奶把她的舊信件放在一個小木盒裡。"},{"en":"The wooden floor creaked as he walked across the room.","zh":"他走過房間時，木地板發出嘎吱聲。"}]},{"word":"wool","pos":"n.","phonetic":"[wʊl]","meaning":"羊毛；毛線","definition":"the soft thick hair of sheep, used to make cloth","collocations":["pure wool","wool sweater","ball of wool"],"example":"This sweater is made of pure wool.","exampleZh":"這件毛衣是純羊毛製成的。","synonyms":[],"level":2,"theme":"服裝與外表","examples":[{"en":"This sweater is made of pure wool.","zh":"這件毛衣是純羊毛製成的。"},{"en":"My aunt knitted me a warm wool sweater for winter.","zh":"我阿姨為我織了一件溫暖的羊毛衣過冬。"},{"en":"The kitten played happily with a ball of wool.","zh":"小貓開心地玩著一團毛線。"}]},{"word":"word","pos":"n.","phonetic":"[wɝd]","meaning":"字；詞；話","definition":"a single unit of language that has meaning","collocations":["keep one's word","in other words","word for word"],"example":"Can you tell me the meaning of this word?","exampleZh":"你能告訴我這個字的意思嗎？","synonyms":["term"],"level":1,"theme":"溝通與語言","examples":[{"en":"Can you tell me the meaning of this word?","zh":"你能告訴我這個字的意思嗎？"},{"en":"He always keeps his word, so we can trust him.","zh":"他總是信守承諾，所以我們可以信任他。"},{"en":"She repeated the poem word for word without a single mistake.","zh":"她一字不差地背出那首詩，沒有出任何錯。"}]},{"word":"work","pos":"n. / v.","phonetic":"[wɝk]","meaning":"工作；作品；工作，運轉","definition":"to do a job or activity involving effort; a task or job","collocations":["go to work","work hard","work of art"],"example":"She works at a hospital as a nurse.","exampleZh":"她在醫院當護士工作。","synonyms":["labor","job"],"level":1,"theme":"工作與職業","examples":[{"en":"She works at a hospital as a nurse.","zh":"她在醫院當護士工作。"},{"en":"This painting is truly a beautiful work of art.","zh":"這幅畫真是一件美麗的藝術品。"},{"en":"My father takes the train to work every morning.","zh":"我爸爸每天早上搭火車去上班。"}]},{"word":"worker","pos":"n.","phonetic":"[ˈwɝkɚ]","meaning":"工人；工作者","definition":"a person who works, especially with their hands or in a particular job","collocations":["factory worker","social worker","hard worker"],"example":"The factory workers went on strike.","exampleZh":"工廠工人們罷工了。","synonyms":["employee"],"level":2,"theme":"工作與職業","examples":[{"en":"The factory workers went on strike.","zh":"工廠工人們罷工了。"},{"en":"The social worker visits the elderly couple every week.","zh":"社工每週都會去探訪那對年長的夫妻。"},{"en":"She is such a hard worker that she rarely takes a break.","zh":"她是個非常勤奮的工作者，很少休息。"}]},{"word":"workforce","pos":"n.","phonetic":"[ˈwɝkˌfɔrs]","meaning":"勞動力；全體員工","definition":"all the people who work in a particular company, industry, or country","collocations":["skilled workforce","global workforce","join the workforce"],"example":"Women make up half of the workforce today.","exampleZh":"婦女如今占了勞動力的一半。","synonyms":["labor force"],"level":5,"theme":"商業與金錢","examples":[{"en":"Women make up half of the workforce today.","zh":"婦女如今占了勞動力的一半。"},{"en":"The company needs a skilled workforce to build its new products.","zh":"公司需要一支技術熟練的勞動力來製造新產品。"},{"en":"After graduation, many students are eager to join the workforce.","zh":"畢業後，許多學生都渴望投入職場。"}]},{"word":"workload","pos":"n.","phonetic":"[ˋwɝk͵lod]","meaning":"工作量；工作負荷","definition":"the amount of work that a person or machine has to do","collocations":["a heavy workload","reduce the workload","manage one's workload"],"example":"Teachers often complain about their heavy workload.","exampleZh":"老師們常常抱怨他們沉重的工作量。","synonyms":[],"level":4,"theme":"工作與職業","examples":[{"en":"Teachers often complain about their heavy workload.","zh":"老師們常常抱怨他們沉重的工作量。"},{"en":"The manager promised to reduce our workload before the holidays.","zh":"經理答應在假期前減輕我們的工作量。"},{"en":"Learning to manage your workload is an important life skill.","zh":"學會管理自己的工作量是一項重要的人生技能。"}]},{"word":"workout","pos":"n.","phonetic":"[ˈwɝkˌaʊt]","meaning":"健身運動","definition":"a session of physical exercise","collocations":["daily workout","workout routine","gym workout"],"example":"He does a workout every morning before school.","exampleZh":"他每天早上上學前都會健身。","synonyms":["exercise"],"level":3,"theme":"運動與休閒","examples":[{"en":"He does a workout every morning before school.","zh":"他每天早上上學前都會健身。"},{"en":"She never skips her daily workout, even on rainy days.","zh":"即使在下雨天，她也從不略過每天的健身運動。"},{"en":"A good workout routine keeps both body and mind healthy.","zh":"良好的運動習慣能讓身心都保持健康。"}]},{"word":"workplace","pos":"n.","phonetic":"[ˈwɝkˌples]","meaning":"工作場所","definition":"the place where a person works","collocations":["safe workplace","workplace environment","in the workplace"],"example":"The company improved safety in the workplace.","exampleZh":"公司改善了工作場所的安全。","synonyms":[],"level":3,"theme":"工作與職業","examples":[{"en":"The company improved safety in the workplace.","zh":"公司改善了工作場所的安全。"},{"en":"Every employee has the right to a safe workplace.","zh":"每位員工都有權享有安全的工作場所。"},{"en":"Good communication makes the workplace more pleasant for everyone.","zh":"良好的溝通讓工作場所對每個人都更愉快。"}]},{"word":"workshop","pos":"n.","phonetic":"[ˈwɝkˌʃɑp]","meaning":"工作坊；研討會","definition":"a session for discussion or practical work; a room for manual or industrial work","collocations":["attend a workshop","writing workshop","repair workshop"],"example":"I signed up for a photography workshop.","exampleZh":"我報名參加了一個攝影工作坊。","synonyms":["seminar"],"level":3,"theme":"教育與學習","examples":[{"en":"I signed up for a photography workshop.","zh":"我報名參加了一個攝影工作坊。"},{"en":"I attended a cooking workshop and learned to make dumplings.","zh":"我參加了一場烹飪工作坊，學會了包水餃。"},{"en":"The writing workshop helped her improve her storytelling skills.","zh":"那場寫作工作坊幫助她提升了說故事的技巧。"}]},{"word":"world","pos":"n.","phonetic":"[wɝld]","meaning":"世界","definition":"the earth with all its countries and people","collocations":["around the world","real world","world war"],"example":"Traveling around the world is her dream.","exampleZh":"環遊世界是她的夢想。","synonyms":["globe","earth"],"level":1,"theme":"自然與環境","examples":[{"en":"Traveling around the world is her dream.","zh":"環遊世界是她的夢想。"},{"en":"Reading books lets us explore places all around the world.","zh":"閱讀書籍讓我們能探索世界各地的地方。"},{"en":"After graduation, she was excited to enter the real world.","zh":"畢業後，她很興奮能踏入真實的社會。"}]},{"word":"worldwide","pos":"adj. / adv.","phonetic":"[ˌwɝldˈwaɪd]","meaning":"全世界的；遍及全球地","definition":"extending or applying throughout the world","collocations":["worldwide fame","sold worldwide","worldwide web"],"example":"The disease spread worldwide within months.","exampleZh":"這種疾病在幾個月內傳遍全球。","synonyms":["global"],"level":4,"theme":"社會與文化","examples":[{"en":"The disease spread worldwide within months.","zh":"這種疾病在幾個月內傳遍全球。"},{"en":"The singer gained worldwide fame after her first album.","zh":"那位歌手在首張專輯後獲得了全球的名聲。"},{"en":"This popular toy is now sold worldwide in many stores.","zh":"這款熱門玩具如今在許多商店裡銷售遍及全球。"}]},{"word":"worm","pos":"n.","phonetic":"[wɝm]","meaning":"蟲；蠕蟲","definition":"a small long creature with a soft body and no legs","collocations":["earthworm","worm hole","catch worms"],"example":"The early bird catches the worm.","exampleZh":"早起的鳥兒有蟲吃。","synonyms":[],"level":2,"theme":"動物與植物","examples":[{"en":"The early bird catches the worm.","zh":"早起的鳥兒有蟲吃。"},{"en":"After the rain, many earthworms appeared on the wet path.","zh":"雨後，濕漉漉的小路上出現了許多蚯蚓。"},{"en":"The little bird pulled a worm out of the soft ground.","zh":"小鳥從鬆軟的泥土中拉出一條蟲。"}]},{"word":"worried","pos":"adj.","phonetic":"[ˈwɝid]","meaning":"擔心的；憂慮的","definition":"feeling anxious or troubled about something","collocations":["worried look","worried about","get worried"],"example":"She looked worried about her son's health.","exampleZh":"她看起來很擔心她兒子的健康。","synonyms":["anxious","concerned"],"level":2,"theme":"情緒與感受","examples":[{"en":"She looked worried about her son's health.","zh":"她看起來很擔心她兒子的健康。"},{"en":"She gave me a worried look when I arrived home late.","zh":"當我很晚回到家時，她給了我一個擔憂的眼神。"},{"en":"My parents were worried about my health during the exam week.","zh":"在考試那週，我父母很擔心我的健康。"}]},{"word":"worry","pos":"v. / n.","phonetic":"[ˈwɝi]","meaning":"擔心；煩惱","definition":"to feel or cause anxiety about something","collocations":["worry about","don't worry","worry over"],"example":"Don't worry about the exam; you'll do fine.","exampleZh":"別擔心考試，你會考得不錯的。","synonyms":["fret","be anxious"],"level":2,"theme":"情緒與感受","examples":[{"en":"Don't worry about the exam; you'll do fine.","zh":"別擔心考試，你會考得不錯的。"},{"en":"There's no need to worry about small mistakes while learning.","zh":"學習時不需要為小錯誤而煩惱。"},{"en":"He tends to worry too much about what others think.","zh":"他往往太過在意別人的想法。"}]},{"word":"worrying","pos":"adj.","phonetic":"[ˈwɝiɪŋ]","meaning":"令人擔憂的","definition":"causing anxiety or concern","collocations":["worrying trend","worrying news","worrying situation"],"example":"The rising crime rate is worrying.","exampleZh":"不斷上升的犯罪率令人擔憂。","synonyms":["troubling"],"level":4,"theme":"情緒與感受","examples":[{"en":"The rising crime rate is worrying.","zh":"不斷上升的犯罪率令人擔憂。"},{"en":"The falling number of birds in the park is a worrying trend.","zh":"公園裡鳥類數量減少是個令人擔憂的趨勢。"},{"en":"We received some worrying news about the coming storm.","zh":"我們收到一些關於即將來襲風暴的令人擔憂的消息。"}]},{"word":"worse","pos":"adj. / adv.","phonetic":"[wɝs]","meaning":"更差的；更糟地","definition":"comparative form of bad or badly","collocations":["get worse","worse than","worse off"],"example":"The traffic got worse during rush hour.","exampleZh":"尖峰時間的交通變得更糟了。","synonyms":[],"level":2,"theme":"性質與描述","examples":[{"en":"The traffic got worse during rush hour.","zh":"尖峰時間的交通變得更糟了。"},{"en":"If you ignore the cough, it may get much worse.","zh":"如果你不理會這咳嗽，情況可能會變得更糟。"},{"en":"Today's traffic was even worse than yesterday's.","zh":"今天的交通比昨天還要糟糕。"}]},{"word":"worship","pos":"v. / n.","phonetic":"[ˈwɝʃɪp]","meaning":"崇拜；敬拜","definition":"to show great respect and love for a god or sacred thing","collocations":["worship god","place of worship","ancestor worship"],"example":"People gather here to worship every Sunday.","exampleZh":"人們每個星期天聚集在這裡做禮拜。","synonyms":["adore","revere"],"level":5,"theme":"社會與文化","examples":[{"en":"People gather here to worship every Sunday.","zh":"人們每個星期天聚集在這裡做禮拜。"},{"en":"This ancient temple is an important place of worship.","zh":"這座古老的寺廟是一個重要的敬拜場所。"},{"en":"Many families still practice ancestor worship during festivals.","zh":"許多家庭在節日時仍然進行祭祖。"}]},{"word":"worst","pos":"adj. / adv.","phonetic":"[wɝst]","meaning":"最差的；最糟地","definition":"superlative form of bad or badly","collocations":["worst case","at worst","the worst part"],"example":"That was the worst movie I've ever seen.","exampleZh":"那是我看過最爛的電影。","synonyms":[],"level":2,"theme":"性質與描述","examples":[{"en":"That was the worst movie I've ever seen.","zh":"那是我看過最爛的電影。"},{"en":"The worst part of the trip was losing my passport.","zh":"這趟旅行最糟糕的部分是弄丟了護照。"},{"en":"In the worst case, we may have to cancel the picnic.","zh":"最壞的情況下，我們可能得取消野餐。"}]},{"word":"worth","pos":"adj. / n.","phonetic":"[wɝθ]","meaning":"值得...的；價值","definition":"having a value of; the value or usefulness of something","collocations":["worth it","worth doing","net worth"],"example":"This museum is definitely worth visiting.","exampleZh":"這座博物館絕對值得參觀。","synonyms":["value"],"level":3,"theme":"抽象概念","examples":[{"en":"This museum is definitely worth visiting.","zh":"這座博物館絕對值得參觀。"},{"en":"The long climb was tiring, but the view was worth it.","zh":"這段長長的攀爬很累，但那景色很值得。"},{"en":"Helping others is always worth doing, no matter how small.","zh":"幫助別人永遠值得去做，不論多麼微小。"}]},{"word":"worthwhile","pos":"adj.","phonetic":"[ˌwɝθˈwaɪl]","meaning":"值得做的","definition":"important, valuable, or worth the time and effort spent","collocations":["worthwhile experience","worthwhile investment","feel worthwhile"],"example":"Learning a new language is always worthwhile.","exampleZh":"學習一種新語言總是值得的。","synonyms":["valuable"],"level":5,"theme":"抽象概念","examples":[{"en":"Learning a new language is always worthwhile.","zh":"學習一種新語言總是值得的。"},{"en":"Volunteering at the shelter was a truly worthwhile experience.","zh":"在收容所當志工是一次非常值得的經歷。"},{"en":"Buying good running shoes is a worthwhile investment for athletes.","zh":"對運動員來說，買一雙好的跑鞋是值得的投資。"}]},{"word":"worthy","pos":"adj.","phonetic":"[ˈwɝði]","meaning":"值得的；有價值的","definition":"deserving effort, attention, or respect","collocations":["worthy cause","worthy of praise","worthy opponent"],"example":"This is a worthy cause that deserves our support.","exampleZh":"這是個值得我們支持的正當理由。","synonyms":["deserving"],"level":5,"theme":"性質與描述","examples":[{"en":"This is a worthy cause that deserves our support.","zh":"這是個值得我們支持的正當理由。"},{"en":"Her hard work on the project is worthy of praise.","zh":"她在這個計畫上的努力值得讚揚。"},{"en":"The chess champion finally met a worthy opponent.","zh":"那位西洋棋冠軍終於遇到了一位勢均力敵的對手。"}]},{"word":"would","pos":"aux.v.","phonetic":"[wʊd]","meaning":"會；願意（表過去或假設語氣）","definition":"used to express a hypothetical situation, past habit, or polite request","collocations":["would like","would rather","would have"],"example":"I would help you if I had time.","exampleZh":"如果我有時間，我會幫你。","synonyms":[],"level":1,"theme":"溝通與語言","examples":[{"en":"I would help you if I had time.","zh":"如果我有時間，我會幫你。"},{"en":"I would like a glass of cold water, please.","zh":"我想要一杯冰水，麻煩你。"},{"en":"She would rather stay home than go out in the rain.","zh":"她寧願待在家裡，也不願在雨中出門。"}]},{"word":"wound","pos":"n. / v.","phonetic":"[wund]","meaning":"傷口；使受傷","definition":"an injury to the body, especially one where the skin is cut or broken","collocations":["open wound","wound healing","wound someone"],"example":"The soldier's wound healed slowly.","exampleZh":"那名士兵的傷口癒合得很慢。","synonyms":["injury"],"level":4,"theme":"身體與健康","examples":[{"en":"The soldier's wound healed slowly.","zh":"那名士兵的傷口癒合得很慢。"},{"en":"The nurse carefully cleaned the open wound on his knee.","zh":"護士小心地清理他膝蓋上的開放性傷口。"},{"en":"Harsh words can wound a person as deeply as actions.","zh":"刻薄的話語可能像行為一樣深深傷害一個人。"}]},{"word":"wow","pos":"int. / v.","phonetic":"[waʊ]","meaning":"哇；使驚嘆","definition":"used to express amazement or admiration","collocations":["wow factor","wow the audience"],"example":"Wow, this view is amazing!","exampleZh":"哇，這風景太美了！","synonyms":[],"level":1,"theme":"情緒與感受","examples":[{"en":"Wow, this view is amazing!","zh":"哇，這風景太美了！"},{"en":"The magician's final trick truly wowed the whole audience.","zh":"魔術師最後的把戲真的讓全場觀眾驚嘆不已。"},{"en":"Wow, I can't believe you finished the whole book in one day!","zh":"哇，我真不敢相信你一天就把整本書看完了！"}]},{"word":"wrap","pos":"v. / n.","phonetic":"[ræp]","meaning":"包；包裹","definition":"to cover something by folding paper or cloth around it","collocations":["wrap a gift","wrap up","plastic wrap"],"example":"She wrapped the present in colorful paper.","exampleZh":"她用彩色紙包裝禮物。","synonyms":["cover","package"],"level":2,"theme":"動作與行為","examples":[{"en":"She wrapped the present in colorful paper.","zh":"她用彩色紙包裝禮物。"},{"en":"She carefully wrapped the birthday gift in shiny blue paper.","zh":"她小心地用閃亮的藍色紙把生日禮物包起來。"},{"en":"Cover the leftover food with plastic wrap before storing it.","zh":"把剩菜用保鮮膜蓋好再收起來。"}]},{"word":"wrapper","pos":"n.","phonetic":"[ˈræpɚ]","meaning":"包裝紙","definition":"a piece of paper or plastic used to cover or enclose something","collocations":["candy wrapper","plastic wrapper","throw away a wrapper"],"example":"He threw the candy wrapper into the trash can.","exampleZh":"他把糖果包裝紙丟進垃圾桶。","synonyms":[],"level":3,"theme":"居家與生活","examples":[{"en":"He threw the candy wrapper into the trash can.","zh":"他把糖果包裝紙丟進垃圾桶。"},{"en":"Please throw the candy wrapper into the bin, not on the floor.","zh":"請把糖果包裝紙丟進垃圾桶，不要丟在地上。"},{"en":"The plastic wrapper on the new book was hard to remove.","zh":"新書上的塑膠包裝很難撕開。"}]},{"word":"wreath","pos":"n.","phonetic":"[riθ]","meaning":"花圈；花環","definition":"an arrangement of flowers or leaves twisted into a circular shape","collocations":["Christmas wreath","lay a wreath","flower wreath"],"example":"They laid a wreath at the memorial.","exampleZh":"他們在紀念碑前獻上花圈。","synonyms":["garland"],"level":6,"theme":"社會與文化","examples":[{"en":"They laid a wreath at the memorial.","zh":"他們在紀念碑前獻上花圈。"},{"en":"They hung a green Christmas wreath on the front door.","zh":"他們在前門掛上一個綠色的聖誕花圈。"},{"en":"The mayor laid a wreath at the soldiers' memorial.","zh":"市長在士兵紀念碑前獻上一個花圈。"}]},{"word":"wreck","pos":"v. / n.","phonetic":"[rɛk]","meaning":"破壞；殘骸","definition":"to destroy or badly damage something; the remains of something destroyed","collocations":["shipwreck","wreck a car","nervous wreck"],"example":"The storm wrecked several boats along the coast.","exampleZh":"暴風雨摧毀了海岸邊的幾艘船。","synonyms":["destroy","ruin"],"level":4,"theme":"自然與環境","examples":[{"en":"The storm wrecked several boats along the coast.","zh":"暴風雨摧毀了海岸邊的幾艘船。"},{"en":"The careless driver wrecked his car against a stone wall.","zh":"那個粗心的駕駛把車撞毀在石牆上。"},{"en":"Before the interview, she was a complete nervous wreck.","zh":"面試前，她整個人緊張得快崩潰了。"}]},{"word":"wreckage","pos":"n.","phonetic":"[ˈrɛkɪdʒ]","meaning":"殘骸","definition":"the remains of something that has been badly damaged or destroyed","collocations":["plane wreckage","among the wreckage","clear the wreckage"],"example":"Rescuers searched through the wreckage for survivors.","exampleZh":"救難人員在殘骸中搜尋生還者。","synonyms":["debris","ruins"],"level":5,"theme":"交通與旅行","examples":[{"en":"Rescuers searched through the wreckage for survivors.","zh":"救難人員在殘骸中搜尋生還者。"},{"en":"Rescue workers searched the wreckage for anyone still alive.","zh":"救援人員在殘骸中搜尋任何倖存的人。"},{"en":"It took several days to clear the wreckage from the road.","zh":"花了好幾天才把道路上的殘骸清理乾淨。"}]},{"word":"wrestle","pos":"v.","phonetic":"[ˈrɛsl̩]","meaning":"摔角；搏鬥","definition":"to fight by holding someone and trying to throw them to the ground","collocations":["wrestle with","wrestle an opponent","wrestle a problem"],"example":"The two boys wrestled playfully on the grass.","exampleZh":"兩個男孩在草地上嬉鬧摔角。","synonyms":["grapple","struggle"],"level":4,"theme":"運動與休閒","examples":[{"en":"The two boys wrestled playfully on the grass.","zh":"兩個男孩在草地上嬉鬧摔角。"},{"en":"The young athlete trained hard to wrestle his opponent to the ground.","zh":"那位年輕運動員努力訓練，要把對手摔倒在地。"},{"en":"For weeks she wrestled with the difficult decision.","zh":"好幾個星期以來，她一直為這個艱難的決定而苦惱。"}]},{"word":"wrestling","pos":"n.","phonetic":"[ˈrɛslɪŋ]","meaning":"摔角運動","definition":"the sport in which two people fight by holding and throwing each other","collocations":["professional wrestling","wrestling match","wrestling team"],"example":"He joined the school wrestling team.","exampleZh":"他加入了學校的摔角隊。","synonyms":[],"level":4,"theme":"運動與休閒","examples":[{"en":"He joined the school wrestling team.","zh":"他加入了學校的摔角隊。"},{"en":"The two schools held an exciting wrestling match on Saturday.","zh":"兩所學校在星期六舉行了一場精彩的摔角比賽。"},{"en":"He trains every day to stay on the wrestling team.","zh":"他每天訓練，以保住摔角隊的位置。"}]},{"word":"wretched","pos":"adj.","phonetic":"[ˈrɛtʃɪd]","meaning":"可憐的；悲慘的","definition":"very unhappy, unfortunate, or of very poor quality","collocations":["feel wretched","wretched conditions","wretched life"],"example":"The refugees lived in wretched conditions.","exampleZh":"難民們生活在悲慘的環境中。","synonyms":["miserable","pitiful"],"level":6,"theme":"情緒與感受","examples":[{"en":"The refugees lived in wretched conditions.","zh":"難民們生活在悲慘的環境中。"},{"en":"The stray cats lived in wretched conditions under the bridge.","zh":"那些流浪貓在橋下過著悲慘的生活。"},{"en":"She felt wretched after arguing with her best friend.","zh":"和最好的朋友吵架後，她覺得很難受。"}]},{"word":"wring","pos":"v.","phonetic":"[rɪŋ]","meaning":"擰；絞","definition":"to twist and squeeze something tightly to remove liquid","collocations":["wring out","wring one's hands","wring water from"],"example":"She wrung the wet towel before hanging it up.","exampleZh":"她把濕毛巾擰乾後才掛起來。","synonyms":["squeeze","twist"],"level":5,"theme":"動作與行為","examples":[{"en":"She wrung the wet towel before hanging it up.","zh":"她把濕毛巾擰乾後才掛起來。"},{"en":"He wrung out the wet cloth before wiping the desk.","zh":"他把濕布擰乾後才擦桌子。"},{"en":"She wrung her hands nervously while waiting for the results.","zh":"等待結果時，她緊張地扭著雙手。"}]},{"word":"wrinkle","pos":"n. / v.","phonetic":"[ˈrɪŋkl̩]","meaning":"皺紋；使起皺","definition":"a small fold or line, especially one that appears on skin or fabric","collocations":["iron out wrinkles","wrinkle-free","deep wrinkles"],"example":"Her grandmother's face was covered with wrinkles.","exampleZh":"她祖母的臉上滿是皺紋。","synonyms":["crease","fold"],"level":4,"theme":"身體與健康","examples":[{"en":"Her grandmother's face was covered with wrinkles.","zh":"她祖母的臉上滿是皺紋。"},{"en":"Please iron out the wrinkles in this shirt before the ceremony.","zh":"請在典禮前把這件襯衫上的皺褶燙平。"},{"en":"Years of laughter had left kind wrinkles around his eyes.","zh":"多年的歡笑在他眼角留下了慈祥的皺紋。"}]},{"word":"wrist","pos":"n.","phonetic":"[rɪst]","meaning":"手腕","definition":"the joint connecting the hand with the arm","collocations":["sprain one's wrist","wrist watch","wrist band"],"example":"She hurt her wrist while playing tennis.","exampleZh":"她打網球時扭傷了手腕。","synonyms":[],"level":3,"theme":"身體與健康","examples":[{"en":"She hurt her wrist while playing tennis.","zh":"她打網球時扭傷了手腕。"},{"en":"He sprained his wrist when he fell off the skateboard.","zh":"他從滑板上摔下來時扭傷了手腕。"},{"en":"She glanced at the watch on her wrist and hurried off.","zh":"她瞥了一眼手腕上的錶，便匆匆離開了。"}]},{"word":"wristband","pos":"n.","phonetic":"[ˈrɪstˌbænd]","meaning":"腕帶；手環","definition":"a band worn around the wrist","collocations":["rubber wristband","sports wristband","wear a wristband"],"example":"Every visitor must wear a wristband to enter the concert.","exampleZh":"每位訪客都必須戴上腕帶才能進入演唱會。","synonyms":[],"level":4,"theme":"服裝與外表","examples":[{"en":"Every visitor must wear a wristband to enter the concert.","zh":"每位訪客都必須戴上腕帶才能進入演唱會。"},{"en":"Runners wear a colorful wristband to show they joined the race.","zh":"跑者戴著彩色手環，表示他們參加了這場比賽。"},{"en":"The rubber wristband reminds her to drink more water.","zh":"那個橡膠手環提醒她要多喝水。"}]},{"word":"write","pos":"v.","phonetic":"[raɪt]","meaning":"寫；書寫","definition":"to make letters, words, or numbers on a surface, especially with a pen","collocations":["write a letter","write down","write about"],"example":"He writes a diary entry every night.","exampleZh":"他每晚都寫日記。","synonyms":["compose"],"level":1,"theme":"溝通與語言","examples":[{"en":"He writes a diary entry every night.","zh":"他每晚都寫日記。"},{"en":"Remember to write down your homework in your notebook.","zh":"記得把作業寫在你的筆記本上。"},{"en":"She loves to write about her travels in a small journal.","zh":"她喜歡在一本小日記裡書寫她的旅行。"}]},{"word":"writer","pos":"n.","phonetic":"[ˈraɪtɚ]","meaning":"作家；作者","definition":"a person who writes books, articles, or other material","collocations":["famous writer","freelance writer","become a writer"],"example":"She dreams of becoming a famous writer.","exampleZh":"她夢想成為一位知名作家。","synonyms":["author"],"level":2,"theme":"藝術與音樂","examples":[{"en":"She dreams of becoming a famous writer.","zh":"她夢想成為一位知名作家。"},{"en":"As a freelance writer, he works from cafes all over town.","zh":"身為自由作家，他在城裡各處的咖啡館工作。"},{"en":"The famous writer signed copies of her new novel for fans.","zh":"那位著名作家為粉絲在她的新小說上簽名。"}]},{"word":"writhe","pos":"v.","phonetic":"[raɪð]","meaning":"扭動；翻滾","definition":"to twist the body about, usually because of pain","collocations":["writhe in pain","writhe on the ground","writhe with agony"],"example":"He writhed in pain after twisting his ankle.","exampleZh":"他扭傷腳踝後痛苦地扭動身體。","synonyms":["squirm","twist"],"level":6,"theme":"身體與健康","examples":[{"en":"He writhed in pain after twisting his ankle.","zh":"他扭傷腳踝後痛苦地扭動身體。"},{"en":"The player writhed on the ground after twisting his knee.","zh":"那名球員扭傷膝蓋後在地上痛苦地翻滾。"},{"en":"The snake writhed quickly as it slid into the tall grass.","zh":"那條蛇快速扭動著身子，滑進高草叢中。"}]},{"word":"writing","pos":"n.","phonetic":"[ˈraɪtɪŋ]","meaning":"寫作；文字","definition":"the activity or skill of writing; something that has been written","collocations":["creative writing","in writing","writing skills"],"example":"Good writing skills are important for students.","exampleZh":"良好的寫作技巧對學生來說很重要。","synonyms":[],"level":2,"theme":"教育與學習","examples":[{"en":"Good writing skills are important for students.","zh":"良好的寫作技巧對學生來說很重要。"},{"en":"The teacher praised her creative writing in front of the class.","zh":"老師在全班面前稱讚她的創意寫作。"},{"en":"Please put your request in writing so we have a record.","zh":"請以書面提出你的要求，好讓我們有紀錄。"}]},{"word":"wrong","pos":"adj. / adv. / n.","phonetic":"[rɔŋ]","meaning":"錯誤的；錯誤地；錯誤","definition":"not correct or not what is required; incorrectly","collocations":["go wrong","wrong answer","right and wrong"],"example":"I think you took the wrong turn.","exampleZh":"我覺得你轉錯彎了。","synonyms":["incorrect","mistaken"],"level":1,"theme":"性質與描述","examples":[{"en":"I think you took the wrong turn.","zh":"我覺得你轉錯彎了。"},{"en":"Something went wrong with the printer just before the deadline.","zh":"就在截止期限前，印表機出了問題。"},{"en":"Parents help children learn the difference between right and wrong.","zh":"父母幫助孩子學會分辨對與錯。"}]},{"word":"wrongdoing","pos":"n.","phonetic":"[ˈrɔŋˌduɪŋ]","meaning":"不法行為；壞事","definition":"illegal or dishonest behavior","collocations":["admit wrongdoing","evidence of wrongdoing","deny wrongdoing"],"example":"The company denied any wrongdoing in the scandal.","exampleZh":"該公司否認在這起醜聞中有任何不法行為。","synonyms":["misconduct"],"level":6,"theme":"政治與法律","examples":[{"en":"The company denied any wrongdoing in the scandal.","zh":"該公司否認在這起醜聞中有任何不法行為。"},{"en":"The investigation found no evidence of any wrongdoing.","zh":"調查並未發現任何不法行為的證據。"},{"en":"He finally admitted his wrongdoing and apologized to everyone.","zh":"他終於承認自己的錯誤，並向大家道歉。"}]},{"word":"wrought","pos":"adj.","phonetic":"[rɔt]","meaning":"精製的；鍛造的","definition":"shaped or formed, especially by hammering metal","collocations":["wrought iron","well wrought","hand-wrought"],"example":"The gate was made of black wrought iron.","exampleZh":"那扇門是用黑色鍛鐵製成的。","synonyms":["forged"],"level":6,"theme":"藝術與音樂","examples":[{"en":"The gate was made of black wrought iron.","zh":"那扇門是用黑色鍛鐵製成的。"},{"en":"The garden was surrounded by an elegant wrought iron fence.","zh":"花園四周圍著一圈雅緻的鍛鐵欄杆。"},{"en":"The museum displayed a beautifully wrought silver cup.","zh":"博物館展出一只精美鍛造的銀杯。"}]},{"word":"x-ray","pos":"n. / v.","phonetic":"[ˈɛksˌre]","meaning":"X光；X光照片；用X光檢查","definition":"a type of electromagnetic radiation used to see inside the body or objects, or a photograph made using it","collocations":["take an x-ray","x-ray machine","x-ray a patient","chest x-ray"],"example":"The doctor took an x-ray of my broken arm.","exampleZh":"醫生為我斷掉的手臂照了X光。","synonyms":["radiograph"],"level":2,"theme":"身體與健康","examples":[{"en":"The doctor took an x-ray of my broken arm.","zh":"醫生為我斷掉的手臂照了X光。"},{"en":"The dentist took an x-ray to check my sore tooth.","zh":"牙醫照了一張X光片來檢查我疼痛的牙齒。"},{"en":"At the airport, every bag passes through an x-ray machine.","zh":"在機場，每件行李都要通過X光機檢查。"}]},{"word":"xenon","pos":"n.","phonetic":"[ˈzinɑn]","meaning":"氙（一種化學元素）","definition":"a colorless, odorless chemical element that is a heavy noble gas, used in lamps and lasers","collocations":["xenon gas","xenon lamp","xenon headlight"],"example":"Xenon is used in some car headlights because it produces a bright white light.","exampleZh":"氙氣被用在某些汽車頭燈上,因為它能發出明亮的白光。","synonyms":[],"level":5,"theme":"科學與數學","examples":[{"en":"Xenon is used in some car headlights because it produces a bright white light.","zh":"氙氣被用在某些汽車頭燈上,因為它能發出明亮的白光。"},{"en":"The new stadium uses bright xenon lamps to light the field.","zh":"新體育場使用明亮的氙氣燈來照亮球場。"},{"en":"Xenon is a rare gas found in very small amounts in the air.","zh":"氙是一種稀有氣體，在空氣中含量極少。"}]},{"word":"xenophobia","pos":"n.","phonetic":"[ˌzɛnəˈfobɪə]","meaning":"仇外；排外心理","definition":"a strong dislike or fear of people from other countries","collocations":["rising xenophobia","fight xenophobia","signs of xenophobia"],"example":"The government launched a campaign to fight xenophobia and promote tolerance.","exampleZh":"政府發起了一項運動來對抗仇外心理並推廣包容。","synonyms":["prejudice"],"level":6,"theme":"社會與文化","examples":[{"en":"The government launched a campaign to fight xenophobia and promote tolerance.","zh":"政府發起了一項運動來對抗仇外心理並推廣包容。"},{"en":"The teacher explained how education can help reduce xenophobia.","zh":"老師說明教育如何有助於減少仇外心理。"},{"en":"Rising xenophobia in the city worried many local leaders.","zh":"城市中日益升高的排外情緒讓許多地方領袖感到憂心。"}]},{"word":"xenophobic","pos":"adj.","phonetic":"[ˌzɛnəˈfobɪk]","meaning":"仇外的；排外的","definition":"showing a strong dislike or fear of people from other countries","collocations":["xenophobic attitude","xenophobic remarks","become xenophobic"],"example":"Some people criticized the politician's xenophobic comments about immigrants.","exampleZh":"有些人批評那位政治人物針對移民的排外言論。","synonyms":["prejudiced","intolerant"],"level":6,"theme":"社會與文化","examples":[{"en":"Some people criticized the politician's xenophobic comments about immigrants.","zh":"有些人批評那位政治人物針對移民的排外言論。"},{"en":"His xenophobic remarks upset many of his classmates.","zh":"他仇外的言論讓許多同學感到不快。"},{"en":"A kind community should never allow xenophobic attitudes to grow.","zh":"一個友善的社群絕不應讓排外的態度滋長。"}]},{"word":"xerophyte","pos":"n.","phonetic":"[ˈzɪrəˌfaɪt]","meaning":"旱生植物；耐旱植物","definition":"a plant that has adapted to survive in an environment with very little water, such as a desert","collocations":["desert xerophyte","xerophyte adaptation","typical xerophyte"],"example":"A cactus is a classic example of a xerophyte that thrives in dry deserts.","exampleZh":"仙人掌是能在乾燥沙漠中茁壯生長的典型旱生植物。","synonyms":[],"level":6,"theme":"動物與植物","examples":[{"en":"A cactus is a classic example of a xerophyte that thrives in dry deserts.","zh":"仙人掌是能在乾燥沙漠中茁壯生長的典型旱生植物。"},{"en":"A cactus is a xerophyte that can survive with very little water.","zh":"仙人掌是一種只需極少水分就能存活的旱生植物。"},{"en":"The thick leaves of this xerophyte help it store water.","zh":"這種旱生植物厚厚的葉子能幫助它儲存水分。"}]},{"word":"xerox","pos":"n. / v.","phonetic":"[ˈzɪrɑks]","meaning":"影印機；影印本；影印","definition":"to make a photocopy of a document, or a copy made this way","collocations":["xerox a document","xerox copy","make a xerox"],"example":"Could you xerox this report for me before the meeting?","exampleZh":"你可以在開會前幫我影印這份報告嗎?","synonyms":["photocopy","copy"],"level":3,"theme":"科技與媒體","examples":[{"en":"Could you xerox this report for me before the meeting?","zh":"你可以在開會前幫我影印這份報告嗎?"},{"en":"Could you xerox these notes for the rest of the group?","zh":"你可以把這些筆記影印給組裡其他人嗎？"},{"en":"She made a xerox of her report before handing it in.","zh":"她在交出報告前先影印了一份。"}]},{"word":"xylem","pos":"n.","phonetic":"[ˈzaɪləm]","meaning":"木質部（植物輸導組織）","definition":"the tissue in plants that carries water and nutrients from the roots up to the leaves","collocations":["xylem tissue","xylem vessels","xylem and phloem"],"example":"Water travels from the roots to the leaves through the xylem.","exampleZh":"水分透過木質部從根部輸送到葉子。","synonyms":[],"level":6,"theme":"科學與數學","examples":[{"en":"Water travels from the roots to the leaves through the xylem.","zh":"水分透過木質部從根部輸送到葉子。"},{"en":"The xylem carries water from the roots up to the leaves.","zh":"木質部把水分從根部往上輸送到葉子。"},{"en":"In biology class, we studied xylem and phloem in plants.","zh":"在生物課上，我們研究了植物的木質部與韌皮部。"}]},{"word":"xylophone","pos":"n.","phonetic":"[ˈzaɪləˌfon]","meaning":"木琴","definition":"a musical instrument made of a row of wooden bars that are hit with small hammers","collocations":["play the xylophone","xylophone mallet","wooden xylophone"],"example":"The little girl learned to play a simple tune on the xylophone.","exampleZh":"那個小女孩學會在木琴上彈奏一首簡單的曲子。","synonyms":[],"level":2,"theme":"藝術與音樂","examples":[{"en":"The little girl learned to play a simple tune on the xylophone.","zh":"那個小女孩學會在木琴上彈奏一首簡單的曲子。"},{"en":"The music teacher showed us how to play the xylophone.","zh":"音樂老師教我們如何演奏木琴。"},{"en":"He tapped the wooden xylophone gently with two small mallets.","zh":"他用兩根小槌子輕輕敲擊木琴。"}]},{"word":"yacht","pos":"n.","phonetic":"[jɑt]","meaning":"遊艇；帆船","definition":"a boat with sails or an engine used for racing or pleasure trips","collocations":["sail a yacht","luxury yacht","yacht club"],"example":"They spent the weekend sailing a yacht along the coast.","exampleZh":"他們週末沿著海岸駕駛遊艇出遊。","synonyms":["sailboat"],"level":4,"theme":"交通與旅行","examples":[{"en":"They spent the weekend sailing a yacht along the coast.","zh":"他們週末沿著海岸駕駛遊艇出遊。"},{"en":"They dreamed of sailing a yacht across the calm blue sea.","zh":"他們夢想著駕著帆船橫渡平靜的藍色海洋。"},{"en":"A luxury yacht was anchored just outside the small harbor.","zh":"一艘豪華遊艇停泊在小港口外。"}]},{"word":"yard","pos":"n.","phonetic":"[jɑrd]","meaning":"庭院；院子；碼（長度單位）","definition":"an area of ground next to a house, often with grass, or a unit of length equal to three feet","collocations":["back yard","front yard","clean the yard"],"example":"The children were playing in the back yard.","exampleZh":"孩子們在後院玩耍。","synonyms":["garden","lawn"],"level":2,"theme":"居家與生活","examples":[{"en":"The children were playing in the back yard.","zh":"孩子們在後院玩耍。"},{"en":"The children built a small tent in the back yard.","zh":"孩子們在後院搭了一個小帳篷。"},{"en":"Every weekend, my father cleans the yard and waters the plants.","zh":"每個週末，我爸爸都會打掃庭院並澆花。"}]},{"word":"yardstick","pos":"n.","phonetic":"[ˈjɑrdˌstɪk]","meaning":"衡量標準；準則","definition":"a standard used to judge or measure the quality or value of something","collocations":["a useful yardstick","yardstick for success","common yardstick"],"example":"Test scores are often used as a yardstick for a student's ability.","exampleZh":"考試成績常被用來當作評量學生能力的標準。","synonyms":["standard","benchmark"],"level":5,"theme":"抽象概念","examples":[{"en":"Test scores are often used as a yardstick for a student's ability.","zh":"考試成績常被用來當作評量學生能力的標準。"},{"en":"Money should not be the only yardstick for success.","zh":"金錢不應該是衡量成功的唯一標準。"},{"en":"Kindness is a useful yardstick for judging a person's character.","zh":"善良是評斷一個人品格的有用標準。"}]},{"word":"yarn","pos":"n.","phonetic":"[jɑrn]","meaning":"紗線；毛線","definition":"a long thread of cotton, wool, or other fiber used for knitting or weaving","collocations":["a ball of yarn","knit with yarn","colorful yarn"],"example":"My grandmother taught me how to knit a scarf with wool yarn.","exampleZh":"我奶奶教我用毛線織圍巾。","synonyms":["thread"],"level":3,"theme":"居家與生活","examples":[{"en":"My grandmother taught me how to knit a scarf with wool yarn.","zh":"我奶奶教我用毛線織圍巾。"},{"en":"She bought several balls of colorful yarn to knit a scarf.","zh":"她買了好幾團彩色毛線來織圍巾。"},{"en":"The craft class taught us to weave a mat with yarn.","zh":"手工藝課教我們用紗線編織一張墊子。"}]},{"word":"yawn","pos":"v. / n.","phonetic":"[jɔn]","meaning":"打呵欠","definition":"to open the mouth wide and breathe in deeply because one is tired or bored","collocations":["yawn loudly","stifle a yawn","yawn with boredom"],"example":"She yawned several times during the boring lecture.","exampleZh":"她在無聊的講座中打了好幾次呵欠。","synonyms":[],"level":3,"theme":"身體與健康","examples":[{"en":"She yawned several times during the boring lecture.","zh":"她在無聊的講座中打了好幾次呵欠。"},{"en":"He tried to stifle a yawn during the long meeting.","zh":"在冗長的會議中，他努力忍住呵欠。"},{"en":"The students yawned with boredom as the film went on.","zh":"隨著影片繼續播放，學生們無聊得直打呵欠。"}]},{"word":"year","pos":"n.","phonetic":"[jɪr]","meaning":"年；年度","definition":"the time it takes the earth to go around the sun once, about 365 days","collocations":["this year","last year","a year ago","school year"],"example":"We moved to Taipei three years ago.","exampleZh":"我們三年前搬到了台北。","synonyms":[],"level":1,"theme":"時間與空間","examples":[{"en":"We moved to Taipei three years ago.","zh":"我們三年前搬到了台北。"},{"en":"Our school holds a sports day at the end of each year.","zh":"我們學校每年年底都會舉辦運動會。"},{"en":"A year ago, she could barely speak a word of English.","zh":"一年前，她幾乎一句英文都不會說。"}]},{"word":"yearbook","pos":"n.","phonetic":"[ˈjɪrˌbʊk]","meaning":"畢業紀念冊；年鑑","definition":"a book published every year, especially one recording the events of a school year","collocations":["sign the yearbook","school yearbook","yearbook photo"],"example":"All the students signed each other's yearbooks before graduation.","exampleZh":"畢業前，所有學生互相在彼此的畢業紀念冊上簽名。","synonyms":[],"level":3,"theme":"教育與學習","examples":[{"en":"All the students signed each other's yearbooks before graduation.","zh":"畢業前，所有學生互相在彼此的畢業紀念冊上簽名。"},{"en":"Everyone laughed at their funny yearbook photos from last term.","zh":"大家看到上學期搞笑的紀念冊照片都笑了。"},{"en":"She asked her favorite teacher to sign her yearbook.","zh":"她請她最喜歡的老師在她的紀念冊上簽名。"}]},{"word":"yearly","pos":"adj. / adv.","phonetic":"[ˈjɪrli]","meaning":"每年的；每年地","definition":"happening or done once every year","collocations":["a yearly event","yearly income","meet yearly"],"example":"The company holds a yearly meeting for all employees.","exampleZh":"這家公司每年為全體員工舉辦一次會議。","synonyms":["annual"],"level":3,"theme":"時間與空間","examples":[{"en":"The company holds a yearly meeting for all employees.","zh":"這家公司每年為全體員工舉辦一次會議。"},{"en":"The flower festival is a yearly event that draws many visitors.","zh":"花卉節是一年一度吸引許多遊客的活動。"},{"en":"The old friends meet yearly to share news about their lives.","zh":"這些老朋友每年見一次面，分享彼此生活的近況。"}]},{"word":"yearn","pos":"v.","phonetic":"[jɝn]","meaning":"渴望；嚮往","definition":"to have a strong desire or feeling of wanting something","collocations":["yearn for freedom","yearn to travel","yearn for home"],"example":"After years abroad, he yearned to return to his hometown.","exampleZh":"在國外多年後，他渴望回到家鄉。","synonyms":["long for","crave"],"level":5,"theme":"情緒與感受","examples":[{"en":"After years abroad, he yearned to return to his hometown.","zh":"在國外多年後，他渴望回到家鄉。"},{"en":"Living in the city, she yearned for the quiet countryside.","zh":"住在城市裡，她渴望寧靜的鄉間。"},{"en":"The sailors yearned for home after months at sea.","zh":"在海上待了好幾個月後，水手們渴望回家。"}]},{"word":"yeast","pos":"n.","phonetic":"[jist]","meaning":"酵母","definition":"a type of fungus used to make bread rise and to produce alcohol","collocations":["baking yeast","add yeast","yeast infection"],"example":"You need to add yeast to the dough to make it rise.","exampleZh":"你需要在麵團裡加酵母讓它發起來。","synonyms":[],"level":4,"theme":"食物與烹飪","examples":[{"en":"You need to add yeast to the dough to make it rise.","zh":"你需要在麵團裡加酵母讓它發起來。"},{"en":"You must add yeast to the dough so the bread will rise.","zh":"你必須在麵團裡加入酵母，麵包才會發起來。"},{"en":"Without enough yeast, the loaf stayed flat and hard.","zh":"沒有足夠的酵母，那條麵包又扁又硬。"}]},{"word":"yell","pos":"v. / n.","phonetic":"[jɛl]","meaning":"大叫；吼叫","definition":"to shout something loudly, especially because of anger, fear, or pain","collocations":["yell at someone","yell for help","give a yell"],"example":"The coach yelled at the players to run faster.","exampleZh":"教練對球員大吼要他們跑快一點。","synonyms":["shout","scream"],"level":2,"theme":"溝通與語言","examples":[{"en":"The coach yelled at the players to run faster.","zh":"教練對球員大吼要他們跑快一點。"},{"en":"The swimmer began to yell for help when the current grew strong.","zh":"當水流變強時，那名泳客開始大聲呼救。"},{"en":"Please don't yell at your little brother over such a small thing.","zh":"請不要為了這麼小的事對你弟弟大吼。"}]},{"word":"yellow","pos":"adj. / n.","phonetic":"[ˈjɛlo]","meaning":"黃色的；黃色","definition":"having the color of the sun or of gold","collocations":["a yellow shirt","turn yellow","yellow light"],"example":"The leaves turn yellow in autumn.","exampleZh":"秋天樹葉會變黃。","synonyms":[],"level":1,"theme":"性質與描述","examples":[{"en":"The leaves turn yellow in autumn.","zh":"秋天樹葉會變黃。"},{"en":"Drivers should slow down when they see the yellow light.","zh":"駕駛看到黃燈時應該減速。"},{"en":"The banana skins slowly turned yellow on the kitchen table.","zh":"香蕉皮在廚房桌上慢慢變黃了。"}]},{"word":"yellowish","pos":"adj.","phonetic":"[ˈjɛloɪʃ]","meaning":"微黃的；淡黃色的","definition":"somewhat yellow in color","collocations":["a yellowish tint","yellowish light","turn yellowish"],"example":"The old photograph had turned a yellowish color over time.","exampleZh":"這張老照片經過時間變成了泛黃的顏色。","synonyms":[],"level":4,"theme":"性質與描述","examples":[{"en":"The old photograph had turned a yellowish color over time.","zh":"這張老照片經過時間變成了泛黃的顏色。"},{"en":"The evening sky had a soft yellowish tint before sunset.","zh":"日落前，傍晚的天空帶著柔和的淡黃色調。"},{"en":"The pages of the old book had turned yellowish with age.","zh":"這本舊書的書頁隨著時間泛黃了。"}]},{"word":"yes","pos":"adv. / int.","phonetic":"[jɛs]","meaning":"是；對；好的","definition":"used to give an affirmative response or agreement","collocations":["say yes","yes or no","answer yes"],"example":"She said yes to his proposal.","exampleZh":"她答應了他的求婚。","synonyms":["yeah","okay"],"level":1,"theme":"溝通與語言","examples":[{"en":"She said yes to his proposal.","zh":"她答應了他的求婚。"},{"en":"Just answer yes or no; you don't need to explain.","zh":"只要回答是或不是，你不需要解釋。"},{"en":"When he asked her to dance, she happily said yes.","zh":"當他邀她跳舞時，她開心地答應了。"}]},{"word":"yesterday","pos":"n. / adv.","phonetic":"[ˈjɛstɚˌde]","meaning":"昨天","definition":"on the day before today","collocations":["yesterday morning","since yesterday","as of yesterday"],"example":"It rained heavily yesterday afternoon.","exampleZh":"昨天下午下了很大的雨。","synonyms":[],"level":1,"theme":"時間與空間","examples":[{"en":"It rained heavily yesterday afternoon.","zh":"昨天下午下了很大的雨。"},{"en":"I finished reading the whole novel yesterday morning.","zh":"我昨天早上把整本小說看完了。"},{"en":"She has been feeling sick since yesterday afternoon.","zh":"她從昨天下午開始就一直覺得不舒服。"}]},{"word":"yet","pos":"adv. / conj.","phonetic":"[jɛt]","meaning":"尚未；然而；但是","definition":"up until now, or despite that","collocations":["not yet","yet again","small yet powerful"],"example":"He hasn't finished his homework yet.","exampleZh":"他還沒完成作業。","synonyms":["still","however"],"level":2,"theme":"溝通與語言","examples":[{"en":"He hasn't finished his homework yet.","zh":"他還沒完成作業。"},{"en":"The new phone is small yet powerful enough for everything.","zh":"這支新手機雖然小，卻強大到足以應付一切。"},{"en":"I have not decided yet which club I want to join.","zh":"我還沒決定要加入哪個社團。"}]},{"word":"yield","pos":"v. / n.","phonetic":"[jild]","meaning":"屈服；讓步；產量；收益","definition":"to produce or provide something, or to give way to pressure or demand","collocations":["yield to pressure","crop yield","high yield","yield results"],"example":"The new farming method increased the rice yield significantly.","exampleZh":"新的耕作方法大幅提高了稻米的產量。","synonyms":["produce","surrender"],"level":4,"theme":"商業與金錢","examples":[{"en":"The new farming method increased the rice yield significantly.","zh":"新的耕作方法大幅提高了稻米的產量。"},{"en":"Good soil and enough rain gave the farmers a high crop yield.","zh":"良好的土壤和充足的雨水讓農民獲得了高產量。"},{"en":"She refused to yield to pressure and kept her honest opinion.","zh":"她拒絕屈服於壓力，堅持自己誠實的看法。"}]},{"word":"yoga","pos":"n.","phonetic":"[ˈjogə]","meaning":"瑜伽","definition":"a system of exercises for mental and physical health involving controlled breathing and stretching","collocations":["practice yoga","yoga class","yoga mat"],"example":"She practices yoga every morning to relax her body and mind.","exampleZh":"她每天早上練瑜伽來放鬆身心。","synonyms":[],"level":3,"theme":"運動與休閒","examples":[{"en":"She practices yoga every morning to relax her body and mind.","zh":"她每天早上練瑜伽來放鬆身心。"},{"en":"She rolled out her yoga mat and began her morning stretches.","zh":"她攤開瑜伽墊，開始做晨間伸展。"},{"en":"Joining a yoga class helped him feel calmer and more focused.","zh":"參加瑜伽課讓他感覺更平靜、更專注。"}]},{"word":"yogurt","pos":"n.","phonetic":"[ˈjogɚt]","meaning":"優格；優酪乳","definition":"a thick liquid food made from milk that has been treated with certain bacteria","collocations":["a cup of yogurt","plain yogurt","yogurt with fruit"],"example":"I usually have yogurt with fruit for breakfast.","exampleZh":"我早餐通常會吃優格配水果。","synonyms":[],"level":2,"theme":"食物與烹飪","examples":[{"en":"I usually have yogurt with fruit for breakfast.","zh":"我早餐通常會吃優格配水果。"},{"en":"She mixed plain yogurt with honey for a healthy snack.","zh":"她把原味優格和蜂蜜混在一起，做成健康的點心。"},{"en":"A cup of yogurt with fruit is my favorite breakfast.","zh":"一杯加水果的優格是我最喜歡的早餐。"}]},{"word":"yolk","pos":"n.","phonetic":"[jok]","meaning":"蛋黃","definition":"the yellow part in the middle of an egg","collocations":["egg yolk","separate the yolk","runny yolk"],"example":"She whisked the egg yolks with sugar for the cake.","exampleZh":"她把蛋黃和糖攪拌均勻來做蛋糕。","synonyms":[],"level":4,"theme":"食物與烹飪","examples":[{"en":"She whisked the egg yolks with sugar for the cake.","zh":"她把蛋黃和糖攪拌均勻來做蛋糕。"},{"en":"Carefully separate the yolk from the white before you start.","zh":"開始前，先小心地把蛋黃和蛋白分開。"},{"en":"He likes his fried eggs with a soft, runny yolk.","zh":"他喜歡蛋黃軟嫩流動的煎蛋。"}]},{"word":"yonder","pos":"adv. / adj.","phonetic":"[ˈjɑndɚ]","meaning":"那邊的；在那邊","definition":"situated at some distance in the direction indicated; over there","collocations":["over yonder","yonder hill","the house yonder"],"example":"The old church stands on the hill yonder.","exampleZh":"那座古老的教堂就矗立在那邊的山丘上。","synonyms":["there"],"level":6,"theme":"時間與空間","examples":[{"en":"The old church stands on the hill yonder.","zh":"那座古老的教堂就矗立在那邊的山丘上。"},{"en":"You can see our farm on the green hill over yonder.","zh":"你可以看到我們的農場就在那邊的綠色山丘上。"},{"en":"The travelers rested near the small stream yonder.","zh":"旅人們在那邊的小溪旁休息。"}]},{"word":"you","pos":"pron.","phonetic":"[ju]","meaning":"你；你們","definition":"used to refer to the person or people being spoken to","collocations":["thank you","you and I","you guys"],"example":"Can you help me with this box?","exampleZh":"你可以幫我拿這個箱子嗎？","synonyms":[],"level":1,"theme":"溝通與語言","examples":[{"en":"Can you help me with this box?","zh":"你可以幫我拿這個箱子嗎？"},{"en":"Thank you so much for helping me carry these heavy bags.","zh":"非常謝謝你幫我提這些沉重的袋子。"},{"en":"You and I should study together for the science test.","zh":"你和我應該一起準備自然科考試。"}]},{"word":"young","pos":"adj.","phonetic":"[jʌŋ]","meaning":"年輕的；幼小的","definition":"having lived or existed for only a short time","collocations":["young people","when I was young","look young"],"example":"My grandmother was very active when she was young.","exampleZh":"我奶奶年輕時非常活躍。","synonyms":["youthful","juvenile"],"level":1,"theme":"性質與描述","examples":[{"en":"My grandmother was very active when she was young.","zh":"我奶奶年輕時非常活躍。"},{"en":"Many young people enjoy taking photos and sharing them online.","zh":"許多年輕人喜歡拍照並在網路上分享。"},{"en":"When I was young, my family lived near a quiet beach.","zh":"我小時候，我家住在一個寧靜的海灘附近。"}]},{"word":"youngster","pos":"n.","phonetic":"[ˈjʌŋstɚ]","meaning":"年輕人；小孩","definition":"a young person or child","collocations":["a group of youngsters","local youngsters","teach youngsters"],"example":"The park was full of youngsters playing basketball.","exampleZh":"公園裡到處都是打籃球的年輕人。","synonyms":["kid","youth"],"level":3,"theme":"人物與家庭","examples":[{"en":"The park was full of youngsters playing basketball.","zh":"公園裡到處都是打籃球的年輕人。"},{"en":"A group of youngsters helped clean up the beach on Sunday.","zh":"一群年輕人在星期天幫忙清理海灘。"},{"en":"The coach loves teaching youngsters how to play baseball.","zh":"教練喜歡教小孩子打棒球。"}]},{"word":"your","pos":"pron.","phonetic":"[jʊr]","meaning":"你的；你們的","definition":"belonging to or associated with the person being addressed","collocations":["your name","your family","your turn"],"example":"Is this your umbrella?","exampleZh":"這是你的雨傘嗎？","synonyms":[],"level":1,"theme":"溝通與語言","examples":[{"en":"Is this your umbrella?","zh":"這是你的雨傘嗎？"},{"en":"Please write your name clearly at the top of the paper.","zh":"請在紙的最上方清楚地寫下你的名字。"},{"en":"It's your turn to feed the fish this evening.","zh":"今晚輪到你餵魚了。"}]},{"word":"yours","pos":"pron.","phonetic":"[jʊrz]","meaning":"你的（東西）；你們的（東西）","definition":"the one or ones belonging to the person being addressed","collocations":["this book is yours","a friend of yours","yours sincerely"],"example":"This pen is yours, not mine.","exampleZh":"這支筆是你的，不是我的。","synonyms":[],"level":2,"theme":"溝通與語言","examples":[{"en":"This pen is yours, not mine.","zh":"這支筆是你的，不是我的。"},{"en":"Is this blue umbrella yours or your sister's?","zh":"這把藍色的雨傘是你的，還是你姐姐的？"},{"en":"A friend of yours called while you were out.","zh":"你外出的時候，你的一位朋友打過電話來。"}]},{"word":"yourself","pos":"pron.","phonetic":"[jʊrˈsɛlf]","meaning":"你自己","definition":"used to refer back to the person being addressed as the subject of the sentence","collocations":["take care of yourself","by yourself","enjoy yourself"],"example":"Please introduce yourself to the class.","exampleZh":"請向全班自我介紹。","synonyms":[],"level":2,"theme":"溝通與語言","examples":[{"en":"Please introduce yourself to the class.","zh":"請向全班自我介紹。"},{"en":"Please take good care of yourself during the cold winter.","zh":"在寒冷的冬天，請好好照顧自己。"},{"en":"Did you fix the bike all by yourself?","zh":"這台腳踏車是你自己一個人修好的嗎？"}]},{"word":"youth","pos":"n.","phonetic":"[juθ]","meaning":"青春；年輕時期；青年","definition":"the period of life when a person is young, or young people in general","collocations":["in his youth","youth culture","the youth of today"],"example":"In her youth, she traveled all over the world.","exampleZh":"她年輕時環遊了世界。","synonyms":["adolescence"],"level":3,"theme":"人物與家庭","examples":[{"en":"In her youth, she traveled all over the world.","zh":"她年輕時環遊了世界。"},{"en":"In his youth, my grandfather worked on a fishing boat.","zh":"我祖父年輕時在漁船上工作。"},{"en":"The youth of today face many new challenges and opportunities.","zh":"當今的年輕人面對許多新的挑戰與機會。"}]},{"word":"youthful","pos":"adj.","phonetic":"[ˈjuθfəl]","meaning":"年輕的；青春洋溢的","definition":"having the qualities or appearance of being young","collocations":["youthful energy","youthful appearance","youthful spirit"],"example":"Despite her age, she has a youthful energy that inspires everyone.","exampleZh":"儘管年紀不小，她仍有著充滿活力的青春氣息，激勵著大家。","synonyms":["young","vigorous"],"level":4,"theme":"性質與描述","examples":[{"en":"Despite her age, she has a youthful energy that inspires everyone.","zh":"儘管年紀不小，她仍有著充滿活力的青春氣息，激勵著大家。"},{"en":"The teacher's youthful energy made every lesson exciting.","zh":"老師青春洋溢的活力讓每堂課都很精彩。"},{"en":"Despite being sixty, she still has a youthful appearance.","zh":"儘管已經六十歲，她看起來依然年輕。"}]},{"word":"yummy","pos":"adj.","phonetic":"[ˈjʌmi]","meaning":"美味的；好吃的","definition":"very pleasant to taste; delicious","collocations":["yummy food","smell yummy","look yummy"],"example":"The cookies smell so yummy!","exampleZh":"這些餅乾聞起來好香喔！","synonyms":["delicious","tasty"],"level":2,"theme":"食物與烹飪","examples":[{"en":"The cookies smell so yummy!","zh":"這些餅乾聞起來好香喔！"},{"en":"The freshly baked bread smelled so yummy that we couldn't wait.","zh":"剛出爐的麵包聞起來太香了，我們都等不及了。"},{"en":"Grandma cooked a table of yummy food for the reunion.","zh":"奶奶為團圓煮了一桌美味的菜餚。"}]},{"word":"zany","pos":"adj.","phonetic":"[ˈzeni]","meaning":"滑稽的；古怪逗趣的","definition":"amusingly unconventional and often ridiculous","collocations":["zany humor","a zany character","zany ideas"],"example":"The comedian is famous for his zany sense of humor.","exampleZh":"這位喜劇演員以他古怪逗趣的幽默感聞名。","synonyms":["quirky","wacky"],"level":6,"theme":"性質與描述","examples":[{"en":"The comedian is famous for his zany sense of humor.","zh":"這位喜劇演員以他古怪逗趣的幽默感聞名。"},{"en":"The cartoon is full of zany characters that make children laugh.","zh":"這部卡通充滿逗趣的角色，逗得孩子們哈哈大笑。"},{"en":"His zany ideas often turn an ordinary day into an adventure.","zh":"他古怪逗趣的點子常把平凡的一天變成一場冒險。"}]},{"word":"zeal","pos":"n.","phonetic":"[zil]","meaning":"熱忱；熱心","definition":"great energy or enthusiasm shown in support of a person, cause, or goal","collocations":["religious zeal","with great zeal","zeal for reform"],"example":"She pursued her new business idea with great zeal.","exampleZh":"她以極大的熱忱推動她的新事業構想。","synonyms":["enthusiasm","passion"],"level":6,"theme":"情緒與感受","examples":[{"en":"She pursued her new business idea with great zeal.","zh":"她以極大的熱忱推動她的新事業構想。"},{"en":"The volunteers cleaned the park with great zeal all morning.","zh":"志工們整個上午都充滿熱忱地清掃公園。"},{"en":"Her zeal for learning inspired everyone in the classroom.","zh":"她對學習的熱忱激勵了教室裡的每個人。"}]},{"word":"zealous","pos":"adj.","phonetic":"[ˈzɛləs]","meaning":"熱心的；狂熱的","definition":"showing great energy and enthusiasm to support something or achieve something","collocations":["a zealous supporter","zealous about","zealous efforts"],"example":"He is a zealous supporter of environmental protection.","exampleZh":"他是環境保護的熱心支持者。","synonyms":["enthusiastic","eager"],"level":6,"theme":"情緒與感受","examples":[{"en":"He is a zealous supporter of environmental protection.","zh":"他是環境保護的熱心支持者。"},{"en":"He is a zealous supporter of recycling in our neighborhood.","zh":"他是我們社區裡熱心支持回收的人。"},{"en":"The team's zealous efforts finally paid off with a victory.","zh":"這支隊伍的熱切努力最終以勝利獲得回報。"}]},{"word":"zebra","pos":"n.","phonetic":"[ˈzibrə]","meaning":"斑馬","definition":"an African wild animal like a horse with black and white stripes","collocations":["a herd of zebras","zebra crossing","zebra stripes"],"example":"A group of zebras ran across the grassland.","exampleZh":"一群斑馬奔跑過草原。","synonyms":[],"level":1,"theme":"動物與植物","examples":[{"en":"A group of zebras ran across the grassland.","zh":"一群斑馬奔跑過草原。"},{"en":"Always look both ways before you use the zebra crossing.","zh":"使用斑馬線前一定要看看左右兩邊。"},{"en":"Each zebra has its own unique pattern of black stripes.","zh":"每一匹斑馬都有屬於自己獨特的黑色條紋。"}]},{"word":"zenith","pos":"n.","phonetic":"[ˈzinɪθ]","meaning":"頂點；顛峰","definition":"the time when someone or something is most powerful, successful, or impressive","collocations":["reach its zenith","the zenith of one's career","at its zenith"],"example":"The singer's career reached its zenith in the late 1990s.","exampleZh":"這位歌手的事業在1990年代末達到顛峰。","synonyms":["peak","summit"],"level":6,"theme":"抽象概念","examples":[{"en":"The singer's career reached its zenith in the late 1990s.","zh":"這位歌手的事業在1990年代末達到顛峰。"},{"en":"The athlete reached the zenith of his career at the games.","zh":"那位運動員在這場運動會上達到了他職業生涯的顛峰。"},{"en":"At the zenith of summer, the fields were full of flowers.","zh":"在盛夏的頂點，田野裡開滿了花。"}]},{"word":"zephyr","pos":"n.","phonetic":"[ˈzɛfɚ]","meaning":"微風；和風","definition":"a soft gentle wind or breeze","collocations":["a gentle zephyr","a cool zephyr","a summer zephyr"],"example":"A cool zephyr drifted across the meadow in the evening.","exampleZh":"傍晚時分，一陣涼爽的微風吹過草地。","synonyms":["breeze"],"level":6,"theme":"天氣與季節","examples":[{"en":"A cool zephyr drifted across the meadow in the evening.","zh":"傍晚時分，一陣涼爽的微風吹過草地。"},{"en":"A gentle zephyr carried the smell of flowers into the room.","zh":"一陣輕柔的微風把花香帶進了房間。"},{"en":"We sat by the lake, enjoying the cool evening zephyr.","zh":"我們坐在湖邊，享受傍晚涼爽的微風。"}]},{"word":"zero","pos":"n. / adj.","phonetic":"[ˈzɪro]","meaning":"零；零度；零的","definition":"the number 0; nothing at all","collocations":["below zero","zero degrees","zero chance"],"example":"The temperature dropped to zero degrees last night.","exampleZh":"昨晚氣溫降到零度。","synonyms":["nil","nothing"],"level":1,"theme":"科學與數學","examples":[{"en":"The temperature dropped to zero degrees last night.","zh":"昨晚氣溫降到零度。"},{"en":"In the mountains, the temperature often drops below zero at night.","zh":"在山上，夜晚氣溫常常降到零度以下。"},{"en":"There is almost zero chance of rain this afternoon.","zh":"今天下午幾乎不可能下雨。"}]},{"word":"zest","pos":"n.","phonetic":"[zɛst]","meaning":"熱情；興致；(柑橘類)果皮","definition":"great enthusiasm and energy; also the outer skin of citrus fruit used for flavoring","collocations":["zest for life","lemon zest","with zest"],"example":"Even at eighty, my grandmother still has a great zest for life.","exampleZh":"即使已經八十歲，我祖母仍然對生活充滿熱情。","synonyms":["enthusiasm","relish"],"level":5,"theme":"情緒與感受","examples":[{"en":"Even at eighty, my grandmother still has a great zest for life.","zh":"即使已經八十歲，我祖母仍然對生活充滿熱情。"},{"en":"She adds a little lemon zest to make the cake smell fresh.","zh":"她加了一點檸檬皮屑，讓蛋糕聞起來清新。"},{"en":"His zest for life makes every trip an unforgettable memory.","zh":"他對生活的熱情讓每一趟旅行都成為難忘的回憶。"}]},{"word":"zigzag","pos":"n. / v. / adj.","phonetic":"[ˈzɪgˌzæg]","meaning":"之字形；曲折前進的","definition":"a line or path that turns sharply from side to side","collocations":["a zigzag pattern","zigzag across the road","a zigzag path"],"example":"The mountain trail zigzagged all the way up to the peak.","exampleZh":"那條山路以之字形一路蜿蜒到山頂。","synonyms":[],"level":4,"theme":"性質與描述","examples":[{"en":"The mountain trail zigzagged all the way up to the peak.","zh":"那條山路以之字形一路蜿蜒到山頂。"},{"en":"A narrow zigzag path led all the way down the steep hill.","zh":"一條狹窄的之字形小徑一路通向陡峭的山下。"},{"en":"The rabbit ran in a zigzag to escape the chasing dog.","zh":"兔子以之字形奔跑，躲避追趕的狗。"}]},{"word":"zinc","pos":"n.","phonetic":"[zɪŋk]","meaning":"鋅","definition":"a bluish-white metal used to coat other metals and make alloys","collocations":["zinc supplement","zinc coating","rich in zinc"],"example":"Oysters are known to be rich in zinc.","exampleZh":"牡蠣以富含鋅聞名。","synonyms":[],"level":5,"theme":"科學與數學","examples":[{"en":"Oysters are known to be rich in zinc.","zh":"牡蠣以富含鋅聞名。"},{"en":"Doctors say foods rich in zinc can help wounds heal faster.","zh":"醫生說富含鋅的食物有助於傷口更快癒合。"},{"en":"A thin zinc coating protects the metal roof from rust.","zh":"一層薄薄的鍍鋅能保護金屬屋頂不生鏽。"}]},{"word":"zip","pos":"n. / v.","phonetic":"[zɪp]","meaning":"拉鍊；用拉鍊拉上；快速移動","definition":"a fastener with two rows of teeth pulled together by a sliding tab; to move very fast","collocations":["zip up a jacket","zip past","a broken zip"],"example":"Please zip up your coat; it's cold outside.","exampleZh":"請把你的外套拉鍊拉上，外面很冷。","synonyms":["fastener"],"level":2,"theme":"服裝與外表","examples":[{"en":"Please zip up your coat; it's cold outside.","zh":"請把你的外套拉鍊拉上，外面很冷。"},{"en":"Please zip up your jacket before we go out into the cold.","zh":"在我們出門進入寒冷的天氣前，請把外套拉鍊拉好。"},{"en":"A red sports car zipped past us on the highway.","zh":"一輛紅色跑車在高速公路上從我們身旁飛馳而過。"}]},{"word":"zipper","pos":"n.","phonetic":"[ˈzɪpɚ]","meaning":"拉鍊","definition":"a device used to fasten clothes, bags, etc., with two rows of metal or plastic teeth","collocations":["a stuck zipper","pull up the zipper","a zipper pocket"],"example":"The zipper on my backpack got stuck this morning.","exampleZh":"今天早上我背包的拉鍊卡住了。","synonyms":["zip"],"level":2,"theme":"服裝與外表","examples":[{"en":"The zipper on my backpack got stuck this morning.","zh":"今天早上我背包的拉鍊卡住了。"},{"en":"She keeps her coins in a small zipper pocket inside her bag.","zh":"她把硬幣放在包包內側的小拉鍊口袋裡。"},{"en":"The zipper on my jacket got stuck halfway up.","zh":"我外套的拉鍊拉到一半卡住了。"}]},{"word":"zodiac","pos":"n.","phonetic":"[ˈzodɪˌæk]","meaning":"黃道十二宮；十二生肖","definition":"a diagram or chart showing the twelve signs used in astrology","collocations":["the zodiac sign","Chinese zodiac","zodiac chart"],"example":"In the Chinese zodiac, this year is the Year of the Dragon.","exampleZh":"在中國生肖裡，今年是龍年。","synonyms":[],"level":5,"theme":"社會與文化","examples":[{"en":"In the Chinese zodiac, this year is the Year of the Dragon.","zh":"在中國生肖裡，今年是龍年。"},{"en":"Many people enjoy reading about their zodiac sign in magazines.","zh":"許多人喜歡在雜誌上閱讀關於自己星座的內容。"},{"en":"The rat is the first animal in the Chinese zodiac.","zh":"鼠是十二生肖中的第一個動物。"}]},{"word":"zombie","pos":"n.","phonetic":"[ˈzɑmbi]","meaning":"殭屍；行屍走肉般的人","definition":"a dead body that has supposedly been brought back to life, especially in horror stories","collocations":["a zombie movie","look like a zombie","zombie apocalypse"],"example":"The kids dressed up as zombies for the Halloween party.","exampleZh":"孩子們為了萬聖節派對打扮成殭屍。","synonyms":[],"level":4,"theme":"藝術與音樂","examples":[{"en":"The kids dressed up as zombies for the Halloween party.","zh":"孩子們為了萬聖節派對打扮成殭屍。"},{"en":"After staying up all night, he looked like a zombie in class.","zh":"熬了一整夜後，他在課堂上看起來像行屍走肉。"},{"en":"We watched a scary zombie movie together on Halloween night.","zh":"萬聖節晚上，我們一起看了一部恐怖的殭屍電影。"}]},{"word":"zone","pos":"n.","phonetic":"[zon]","meaning":"地區；地帶；區域","definition":"an area with a particular feature, purpose, or use","collocations":["a war zone","a time zone","a no-parking zone"],"example":"This part of the city is a quiet residential zone.","exampleZh":"這座城市的這個部分是安靜的住宅區。","synonyms":["area","region"],"level":3,"theme":"時間與空間","examples":[{"en":"This part of the city is a quiet residential zone.","zh":"這座城市的這個部分是安靜的住宅區。"},{"en":"You cannot leave your car in a no-parking zone.","zh":"你不可以把車子停在禁止停車區。"},{"en":"Taiwan and New York are in completely different time zones.","zh":"台灣和紐約位於完全不同的時區。"}]},{"word":"zoo","pos":"n.","phonetic":"[zu]","meaning":"動物園","definition":"a place where wild animals are kept for people to look at","collocations":["go to the zoo","visit the zoo","a zoo animal"],"example":"My little brother loves feeding the goats at the zoo.","exampleZh":"我弟弟很喜歡在動物園裡餵山羊。","synonyms":[],"level":1,"theme":"動物與植物","examples":[{"en":"My little brother loves feeding the goats at the zoo.","zh":"我弟弟很喜歡在動物園裡餵山羊。"},{"en":"We plan to visit the zoo to see the new baby elephant.","zh":"我們打算去動物園看剛出生的小象。"},{"en":"The children were excited to feed the giraffes at the zoo.","zh":"孩子們很興奮能在動物園餵長頸鹿。"}]},{"word":"zoology","pos":"n.","phonetic":"[zoˈɑlədʒi]","meaning":"動物學","definition":"the scientific study of animals and their behavior","collocations":["study zoology","a zoology major","zoology department"],"example":"She decided to major in zoology at university.","exampleZh":"她決定在大學主修動物學。","synonyms":[],"level":5,"theme":"科學與數學","examples":[{"en":"She decided to major in zoology at university.","zh":"她決定在大學主修動物學。"},{"en":"As a zoology major, she spends weekends observing birds.","zh":"身為動物學主修的學生，她週末都在觀察鳥類。"},{"en":"The professor teaches zoology and studies rare frogs.","zh":"這位教授教授動物學，並研究稀有的青蛙。"}]},{"word":"zoom","pos":"v.","phonetic":"[zum]","meaning":"急速移動；(鏡頭)拉近","definition":"to move very quickly, or to make a camera lens bring an object closer","collocations":["zoom in","zoom past","zoom off"],"example":"The sports car zoomed past us on the highway.","exampleZh":"那輛跑車在高速公路上從我們身邊呼嘯而過。","synonyms":["speed","dash"],"level":2,"theme":"動作與行為","examples":[{"en":"The sports car zoomed past us on the highway.","zh":"那輛跑車在高速公路上從我們身邊呼嘯而過。"},{"en":"The motorcycle zoomed off the moment the traffic light turned green.","zh":"綠燈一亮，那台機車就急速地衝了出去。"},{"en":"Please zoom in on the map so we can read the tiny street names.","zh":"請把地圖鏡頭拉近，這樣我們才能看清楚那些小小的街名。"}]},{"word":"zucchini","pos":"n.","phonetic":"[zuˈkini]","meaning":"櫛瓜","definition":"a long, dark green vegetable similar to a cucumber","collocations":["grilled zucchini","zucchini bread","slice zucchini"],"example":"She added sliced zucchini to the vegetable soup.","exampleZh":"她把切片的櫛瓜加進蔬菜湯裡。","synonyms":["courgette"],"level":4,"theme":"食物與烹飪","examples":[{"en":"She added sliced zucchini to the vegetable soup.","zh":"她把切片的櫛瓜加進蔬菜湯裡。"},{"en":"My grandmother often bakes zucchini bread for us on weekends.","zh":"我奶奶週末時常常為我們烤櫛瓜麵包。"},{"en":"We grilled zucchini and mushrooms together for a healthy summer dinner.","zh":"我們把櫛瓜和蘑菇一起烤，做成一頓健康的夏日晚餐。"}]},{"word":"zygote","pos":"n.","phonetic":"[ˈzaɪgot]","meaning":"受精卵；合子","definition":"a cell formed when a male and a female reproductive cell join together","collocations":["a fertilized zygote","zygote formation","develop from a zygote"],"example":"The zygote begins to divide rapidly after fertilization.","exampleZh":"受精卵在受精後開始快速分裂。","synonyms":[],"level":6,"theme":"科學與數學","examples":[{"en":"The zygote begins to divide rapidly after fertilization.","zh":"受精卵在受精後開始快速分裂。"},{"en":"A human life begins when a fertilized zygote starts to divide.","zh":"當一個受精卵開始分裂時，人類的生命就此展開。"},{"en":"In biology class, we learned how a zygote develops into an embryo.","zh":"在生物課上，我們學到合子如何發育成胚胎。"}]}];
